window.BIBLE["Jeremiah"] = {"1":{"chapter":"1","title":"JEREMIAH'S CALL — BEFORE I FORMED THEE","verses":{"1":{"text":"The words of Jeremiah the son of Hilkiah, of the priests that were in Anathoth in the land of Benjamin:","ref":"Jeremiah 1:1","synthesized":"These are the words of Jeremiah son of Hilkiah, one of the priests in Anathoth in the territory of Benjamin.","sources":{"KJV":{"text":"The words of Jeremiah the son of Hilkiah, of the priests that were in Anathoth in the land of Benjamin:"},"BSB":{"text":"These are the words of Jeremiah son of Hilkiah, one of the priests in Anathoth in the territory of Benjamin."},"TANAKH":{"text":"THE WORDS of Jeremiah the son of Hilkiah, of the priests that were in Anathoth in the land of Benjamin,"},"HEBREW":{"text":"דִּבְרֵ֥י יִרְמְיָ֖הוּ בֶּן־חִלְקִיָּ֑הוּ מִן־הַכֹּֽהֲנִים֙ אֲשֶׁ֣ר בַּעֲנָת֔וֹת בְּאֶ֖רֶץ בִּנְיָמִֽן׃"}},"definableWords":["son","one","Benjamin"],"peopleInVerse":["Jeremiah"],"kingdomLens":"'Before I formed thee in the belly I knew thee; and before thou camest forth out of the womb I sanctified thee' (Jer 1:5). God's knowledge of every person predates conception. Jeremiah pleaded he was too young; God answered, 'Say not, I am a child: for thou shalt go to all that I shall send thee.' The youngest prophet preached the hardest message: judgment was coming. He was right.","cultural":{"title":"Jeremiah's Call","detail":"Jeremiah ministered 40+ years through the reigns of five kings — saw Jerusalem fall to Babylon in 586 BC. He was beaten, imprisoned, lowered into a cistern, finally dragged to Egypt against his will. The 'weeping prophet' who never gave up.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"To whom the word of the LORD came in the days of Josiah the son of Amon king of Judah, in the thirteenth year of his reign.","ref":"Jeremiah 1:2","synthesized":"The word of the LORD came to Jeremiah in the thirteenth year of the reign of Josiah son of Amon king of Judah,","sources":{"KJV":{"text":"To whom the word of the LORD came in the days of Josiah the son of Amon king of Judah, in the thirteenth year of his reign."},"BSB":{"text":"The word of the LORD came to Jeremiah in the thirteenth year of the reign of Josiah son of Amon king of Judah,"},"TANAKH":{"text":"to whom the word of HaShem came in the days of Josiah the son of Amon, king of Judah, in the thirteenth year of his reign."},"HEBREW":{"text":"אֲשֶׁ֨ר הָיָ֤ה דְבַר־יְהוָה֙ אֵלָ֔יו בִּימֵ֛י יֹאשִׁיָּ֥הוּ בֶן־אָמ֖וֹן מֶ֣לֶךְ יְהוּדָ֑ה בִּשְׁלֹשׁ־עֶשְׂרֵ֥ה שָׁנָ֖ה לְמָלְכֽוֹ׃"}},"definableWords":["word","LORD","year","reign","son","king","Judah"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingdom_of_god","kingship"]},"3":{"text":"It came also in the days of Jehoiakim the son of Josiah king of Judah, unto the end of the eleventh year of Zedekiah the son of Josiah king of Judah, unto the carrying away of Jerusalem captive in the fifth month.","ref":"Jeremiah 1:3","synthesized":"and through the days of Jehoiakim son of Josiah king of Judah, until the fifth month of the eleventh year of Zedekiah son of Josiah king of Judah, when the people of Jerusalem went into exile.","sources":{"KJV":{"text":"It came also in the days of Jehoiakim the son of Josiah king of Judah, unto the end of the eleventh year of Zedekiah the son of Josiah king of Judah, unto the carrying away of Jerusalem captive in the fifth month."},"BSB":{"text":"and through the days of Jehoiakim son of Josiah king of Judah, until the fifth month of the eleventh year of Zedekiah son of Josiah king of Judah, when the people of Jerusalem went into exile."},"TANAKH":{"text":"It came also in the days of Jehoiakim the son of Josiah, king of Judah, unto the end of the eleventh year of Zedekiah the son of Josiah, king of Judah, unto the carrying away of Jerusalem captive in the fifth month."},"HEBREW":{"text":"וַיְהִ֗י בִּימֵ֨י יְהוֹיָקִ֤ים בֶּן־יֹאשִׁיָּ֙הוּ֙ מֶ֣לֶךְ יְהוּדָ֔ה עַד־תֹּם֙ עַשְׁתֵּ֣י עֶשְׂרֵ֣ה שָׁנָ֔ה לְצִדְקִיָּ֥הוּ בֶן־יֹאשִׁיָּ֖הוּ מֶ֣לֶךְ יְהוּדָ֑ה עַד־גְּל֥וֹת יְרוּשָׁלַ֖͏ִם בַּחֹ֥דֶשׁ הַחֲמִישִֽׁי׃"}},"definableWords":["days","son","king","Judah","year","Son","King","people","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["exile_return","kingship"]},"4":{"text":"Then the word of the LORD came unto me, saying,","ref":"Jeremiah 1:4","synthesized":"The word of the LORD came to me, saying:","sources":{"KJV":{"text":"Then the word of the LORD came unto me, saying,"},"BSB":{"text":"The word of the LORD came to me, saying:"},"TANAKH":{"text":"And the word of HaShem came unto me, saying:"},"HEBREW":{"text":"וַיְהִ֥י דְבַר־יְהוָ֖ה אֵלַ֥י לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"5":{"text":"Before I formed thee in the belly I knew thee; and before thou camest forth out of the womb I sanctified thee, and I ordained thee a prophet unto the nations.","ref":"Jeremiah 1:5","synthesized":"“Before I formed you in the womb I knew you, and before you were born I set you apart and appointed you as a prophet to the nations.”","sources":{"KJV":{"text":"Before I formed thee in the belly I knew thee; and before thou camest forth out of the womb I sanctified thee, and I ordained thee a prophet unto the nations."},"BSB":{"text":"“Before I formed you in the womb I knew you, and before you were born I set you apart and appointed you as a prophet to the nations.”"},"TANAKH":{"text":"Before I formed thee in the belly I knew thee, and before thou camest forth out of the womb I sanctified thee; I have appointed thee a prophet unto the nations."},"HEBREW":{"text":"בְּטֶ֨רֶם אצורך אֶצָּרְךָ֤ בַבֶּ֙טֶן֙ יְדַעְתִּ֔יךָ וּבְטֶ֛רֶם תֵּצֵ֥א מֵרֶ֖חֶם הִקְדַּשְׁתִּ֑יךָ נָבִ֥יא לַגּוֹיִ֖ם נְתַתִּֽיךָ׃"}},"definableWords":["formed","prophet","nations"],"peopleInVerse":[],"themesInVerse":["creation"]},"6":{"text":"Then said I, Ah, Lord GOD! behold, I cannot speak: for I am a child.","ref":"Jeremiah 1:6","synthesized":"“Ah, Lord GOD,” I said, “I surely do not know how to speak, for I am only a child!”","sources":{"KJV":{"text":"Then said I, Ah, Lord GOD! behold, I cannot speak: for I am a child."},"BSB":{"text":"“Ah, Lord GOD,” I said, “I surely do not know how to speak, for I am only a child!”"},"TANAKH":{"text":"Then said I: 'Ah, L-rd GOD! behold, I cannot speak; for I am a child.'"},"HEBREW":{"text":"וָאֹמַ֗ר אֲהָהּ֙ אֲדֹנָ֣י יְהֹוִ֔ה הִנֵּ֥ה לֹא־יָדַ֖עְתִּי דַּבֵּ֑ר כִּי־נַ֖עַר אָנֹֽכִי׃"}},"definableWords":["Lord","God"],"peopleInVerse":[]},"7":{"text":"But the LORD said unto me, Say not, I am a child: for thou shalt go to all that I shall send thee, and whatsoever I command thee thou shalt speak.","ref":"Jeremiah 1:7","synthesized":"But the LORD told me:  “Do not say, ‘I am only a child.’ For to everyone I send you, you must go, and all that I command you, you must speak.","sources":{"KJV":{"text":"But the LORD said unto me, Say not, I am a child: for thou shalt go to all that I shall send thee, and whatsoever I command thee thou shalt speak."},"BSB":{"text":"But the LORD told me:  “Do not say, ‘I am only a child.’ For to everyone I send you, you must go, and all that I command you, you must speak."},"TANAKH":{"text":"But HaShem said unto me: say not: I am a child; for to whomsoever I shall send thee thou shalt go, and whatsoever I shall command thee thou shalt speak."},"HEBREW":{"text":"וַיֹּ֤אמֶר יְהוָה֙ אֵלַ֔י אַל־תֹּאמַ֖ר נַ֣עַר אָנֹ֑כִי כִּ֠י עַֽל־כָּל־אֲשֶׁ֤ר אֽ͏ֶשְׁלָחֲךָ֙ תֵּלֵ֔ךְ וְאֵ֛ת כָּל־אֲשֶׁ֥ר אֲצַוְּךָ֖ תְּדַבֵּֽר׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"8":{"text":"Be not afraid of their faces: for I am with thee to deliver thee, saith the LORD.","ref":"Jeremiah 1:8","synthesized":"Do not be afraid of them, for I am with you to deliver you,” declares the LORD.","sources":{"KJV":{"text":"Be not afraid of their faces: for I am with thee to deliver thee, saith the LORD."},"BSB":{"text":"Do not be afraid of them, for I am with you to deliver you,” declares the LORD."},"TANAKH":{"text":"Be not afraid of them; for I am with thee to deliver thee, saith HaShem."},"HEBREW":{"text":"אַל־תִּירָ֖א מִפְּנֵיהֶ֑ם כִּֽי־אִתְּךָ֥ אֲנִ֛י לְהַצִּלֶ֖ךָ נְאֻם־יְהוָֽה׃"}},"definableWords":["deliver","LORD"],"peopleInVerse":[],"themesInVerse":["redemption","salvation"]},"9":{"text":"Then the LORD put forth his hand, and touched my mouth. And the LORD said unto me, Behold, I have put my words in thy mouth.","ref":"Jeremiah 1:9","synthesized":"Then the LORD reached out His hand, touched my mouth, and said to me:  “Behold, I have put My words in your mouth.","sources":{"KJV":{"text":"Then the LORD put forth his hand, and touched my mouth. And the LORD said unto me, Behold, I have put my words in thy mouth."},"BSB":{"text":"Then the LORD reached out His hand, touched my mouth, and said to me:  “Behold, I have put My words in your mouth."},"TANAKH":{"text":"Then HaShem put forth His hand, and touched my mouth; and HaShem said unto me: Behold, I have put My words in thy mouth;"},"HEBREW":{"text":"וַיִּשְׁלַ֤ח יְהוָה֙ אֶת־יָד֔וֹ וַיַּגַּ֖ע עַל־פִּ֑י וַיֹּ֤אמֶר יְהוָה֙ אֵלַ֔י הִנֵּ֛ה נָתַ֥תִּי דְבָרַ֖י בְּפִֽיךָ׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"10":{"text":"See, I have this day set thee over the nations and over the kingdoms, to root out, and to pull down, and to destroy, and to throw down, to build, and to plant.","ref":"Jeremiah 1:10","synthesized":"See, I have appointed you today over nations and kingdoms to uproot and tear down, to destroy and overthrow, to build and plant.”","sources":{"KJV":{"text":"See, I have this day set thee over the nations and over the kingdoms, to root out, and to pull down, and to destroy, and to throw down, to build, and to plant."},"BSB":{"text":"See, I have appointed you today over nations and kingdoms to uproot and tear down, to destroy and overthrow, to build and plant.”"},"TANAKH":{"text":"See, I have this day set thee over the nations and over the kingdoms, to root out and to pull down, and to destroy and to overthrow; to build, and to plant."},"HEBREW":{"text":"רְאֵ֞ה הִפְקַדְתִּ֣יךָ ׀ הַיּ֣וֹם הַזֶּ֗ה עַל־הַגּוֹיִם֙ וְעַל־הַמַּמְלָכ֔וֹת לִנְת֥וֹשׁ וְלִנְת֖וֹץ וּלְהַאֲבִ֣יד וְלַהֲר֑וֹס לִבְנ֖וֹת וְלִנְטֽוֹעַ׃"}},"definableWords":["see","nations"],"peopleInVerse":[]},"11":{"text":"Moreover the word of the LORD came unto me, saying, Jeremiah, what seest thou? And I said, I see a rod of an almond tree.","ref":"Jeremiah 1:11","synthesized":"And the word of the LORD came to me, asking, “Jeremiah, what do you see?”  “I see a branch of an almond tree,” I replied.","sources":{"KJV":{"text":"Moreover the word of the LORD came unto me, saying, Jeremiah, what seest thou? And I said, I see a rod of an almond tree."},"BSB":{"text":"And the word of the LORD came to me, asking, “Jeremiah, what do you see?”  “I see a branch of an almond tree,” I replied."},"TANAKH":{"text":"Moreover the word of HaShem came unto me, saying: 'Jeremiah, what seest thou?' And I said: 'I see a rod of an almond-tree.'"},"HEBREW":{"text":"וַיְהִ֤י דְבַר־יְהוָה֙ אֵלַ֣י לֵאמֹ֔ר מָה־אַתָּ֥ה רֹאֶ֖ה יִרְמְיָ֑הוּ וָאֹמַ֕ר מַקֵּ֥ל שָׁקֵ֖ד אֲנִ֥י רֹאֶֽה׃"}},"definableWords":["word","LORD","see","tree"],"peopleInVerse":["Jeremiah"],"themesInVerse":["messiah"]},"12":{"text":"Then said the LORD unto me, Thou hast well seen: for I will hasten my word to perform it.","ref":"Jeremiah 1:12","synthesized":"“You have observed correctly,” said the LORD, “for I am watching over My word to accomplish it.”","sources":{"KJV":{"text":"Then said the LORD unto me, Thou hast well seen: for I will hasten my word to perform it."},"BSB":{"text":"“You have observed correctly,” said the LORD, “for I am watching over My word to accomplish it.”"},"TANAKH":{"text":"Then said HaShem unto me: 'Thou hast well seen; for I watch over My word to perform it.'"},"HEBREW":{"text":"וַיֹּ֧אמֶר יְהוָ֛ה אֵלַ֖י הֵיטַ֣בְתָּ לִרְא֑וֹת כִּֽי־שֹׁקֵ֥ד אֲנִ֛י עַל־דְּבָרִ֖י לַעֲשֹׂתֽוֹ׃"}},"definableWords":["LORD","word"],"peopleInVerse":[]},"13":{"text":"And the word of the LORD came unto me the second time, saying, What seest thou? And I said, I see a seething pot; and the face thereof is toward the north.","ref":"Jeremiah 1:13","synthesized":"Again the word of the LORD came to me, asking, “What do you see?”  “I see a boiling pot,” I replied, “and it is tilting toward us from the north.”","sources":{"KJV":{"text":"And the word of the LORD came unto me the second time, saying, What seest thou? And I said, I see a seething pot; and the face thereof is toward the north."},"BSB":{"text":"Again the word of the LORD came to me, asking, “What do you see?”  “I see a boiling pot,” I replied, “and it is tilting toward us from the north.”"},"TANAKH":{"text":"And the word of HaShem came unto me the second time, saying: 'What seest thou?' And I said: 'I see a seething pot; and the face thereof is from the north.'"},"HEBREW":{"text":"וַיְהִ֨י דְבַר־יְהוָ֤ה ׀ אֵלַי֙ שֵׁנִ֣ית לֵאמֹ֔ר מָ֥ה אַתָּ֖ה רֹאֶ֑ה וָאֹמַ֗ר סִ֤יר נָפ֙וּחַ֙ אֲנִ֣י רֹאֶ֔ה וּפָנָ֖יו מִפְּנֵ֥י צָפֽוֹנָה׃"}},"definableWords":["word","LORD","see"],"peopleInVerse":[]},"14":{"text":"Then the LORD said unto me, Out of the north an evil shall break forth upon all the inhabitants of the land.","ref":"Jeremiah 1:14","synthesized":"Then the LORD said to me, “Disaster from the north will be poured out on all who live in the land.","sources":{"KJV":{"text":"Then the LORD said unto me, Out of the north an evil shall break forth upon all the inhabitants of the land."},"BSB":{"text":"Then the LORD said to me, “Disaster from the north will be poured out on all who live in the land."},"TANAKH":{"text":"Then HaShem said unto me: 'Out of the north the evil shall break forth upon all the inhabitants of the land."},"HEBREW":{"text":"וַיֹּ֥אמֶר יְהוָ֖ה אֵלָ֑י מִצָּפוֹן֙ תִּפָּתַ֣ח הָרָעָ֔ה עַ֥ל כָּל־יֹשְׁבֵ֖י הָאָֽרֶץ׃"}},"definableWords":["LORD","live","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"15":{"text":"For, lo, I will call all the families of the kingdoms of the north, saith the LORD; and they shall come, and they shall set every one his throne at the entering of the gates of Jerusalem, and against all the walls thereof round about, and against all the cities of Judah.","ref":"Jeremiah 1:15","synthesized":"For I am about to summon all the clans and kingdoms of the north,” declares the LORD.  “Their kings will come and set up their thrones at the entrance of the gates of Jerusalem. They will attack all her surrounding walls and all the other cities of Judah.","sources":{"KJV":{"text":"For, lo, I will call all the families of the kingdoms of the north, saith the LORD; and they shall come, and they shall set every one his throne at the entering of the gates of Jerusalem, and against all the walls thereof round about, and against all the cities of Judah."},"BSB":{"text":"For I am about to summon all the clans and kingdoms of the north,” declares the LORD.  “Their kings will come and set up their thrones at the entrance of the gates of Jerusalem. They will attack all her surrounding walls and all the other cities of Judah."},"TANAKH":{"text":"For, lo, I will call all the families of the kingdoms of the north, saith HaShem; and they shall come, and they shall set every one his throne at the entrance of the gates of Jerusalem, and against all the walls thereof round about, and against all the cities of Judah."},"HEBREW":{"text":"כִּ֣י ׀ הִנְנִ֣י קֹרֵ֗א לְכָֽל־מִשְׁפְּח֛וֹת מַמְלְכ֥וֹת צָפ֖וֹנָה נְאֻם־יְהוָ֑ה וּבָ֡אוּ וְֽנָתְנוּ֩ אִ֨ישׁ כִּסְא֜וֹ פֶּ֣תַח ׀ שַׁעֲרֵ֣י יְרוּשָׁלִַ֗ם וְעַ֤ל כָּל־חוֹמֹתֶ֙יהָ֙ סָבִ֔יב וְעַ֖ל כָּל־עָרֵ֥י יְהוּדָֽה׃"}},"definableWords":["LORD","kings","Jerusalem","Judah"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"16":{"text":"And I will utter my judgments against them touching all their wickedness, who have forsaken me, and have burned incense unto other gods, and worshipped the works of their own hands.","ref":"Jeremiah 1:16","synthesized":"I will pronounce My judgments against them for all their wickedness, because they have forsaken Me to burn incense to other gods and to worship the works of their own hands.","sources":{"KJV":{"text":"And I will utter my judgments against them touching all their wickedness, who have forsaken me, and have burned incense unto other gods, and worshipped the works of their own hands."},"BSB":{"text":"I will pronounce My judgments against them for all their wickedness, because they have forsaken Me to burn incense to other gods and to worship the works of their own hands."},"TANAKH":{"text":"And I will utter My judgments against them touching all their wickedness; in that they have forsaken me, and have offered unto other gods, and worshipped the work of their own hands."},"HEBREW":{"text":"וְדִבַּרְתִּ֤י מִשְׁפָּטַי֙ אוֹתָ֔ם עַ֖ל כָּל־רָעָתָ֑ם אֲשֶׁ֣ר עֲזָב֗וּנִי וַֽיְקַטְּרוּ֙ לֵאלֹהִ֣ים אֲחֵרִ֔ים וַיִּֽשְׁתַּחֲו֖וּ לְמַעֲשֵׂ֥י יְדֵיהֶֽם׃"}},"definableWords":["incense","worship","works"],"peopleInVerse":[],"themesInVerse":["worship"]},"17":{"text":"Thou therefore gird up thy loins, and arise, and speak unto them all that I command thee: be not dismayed at their faces, lest I confound thee before them.","ref":"Jeremiah 1:17","synthesized":"Get yourself ready. Stand up and tell them everything that I command you. Do not be intimidated by them, or I will terrify you before them.","sources":{"KJV":{"text":"Thou therefore gird up thy loins, and arise, and speak unto them all that I command thee: be not dismayed at their faces, lest I confound thee before them."},"BSB":{"text":"Get yourself ready. Stand up and tell them everything that I command you. Do not be intimidated by them, or I will terrify you before them."},"TANAKH":{"text":"Thou therefore gird up thy loins, and arise, and speak unto them all that I command thee; be not dismayed at them, lest I dismay thee before them."},"HEBREW":{"text":"וְאַתָּה֙ תֶּאְזֹ֣ר מָתְנֶ֔יךָ וְקַמְתָּ֙ וְדִבַּרְתָּ֣ אֲלֵיהֶ֔ם אֵ֛ת כָּל־אֲשֶׁ֥ר אָנֹכִ֖י אֲצַוֶּ֑ךָּ אַל־תֵּחַת֙ מִפְּנֵיהֶ֔ם פֶּֽן־אֲחִתְּךָ֖ לִפְנֵיהֶֽם׃"}},"definableWords":["stand","or"],"peopleInVerse":[]},"18":{"text":"For, behold, I have made thee this day a defenced city, and an iron pillar, and brasen walls against the whole land, against the kings of Judah, against the princes thereof, against the priests thereof, and against the people of the land.","ref":"Jeremiah 1:18","synthesized":"Now behold, this day I have made you like a fortified city, an iron pillar, and bronze walls against the whole land—against the kings of Judah, its officials, its priests, and the people of the land.","sources":{"KJV":{"text":"For, behold, I have made thee this day a defenced city, and an iron pillar, and brasen walls against the whole land, against the kings of Judah, against the princes thereof, against the priests thereof, and against the people of the land."},"BSB":{"text":"Now behold, this day I have made you like a fortified city, an iron pillar, and bronze walls against the whole land—against the kings of Judah, its officials, its priests, and the people of the land."},"TANAKH":{"text":"For, behold, I have made thee this day a fortified city, and an iron pillar, and brazen walls, against the whole land, against the kings of Judah, against the princes thereof, against the priests thereof, and against the people of the land."},"HEBREW":{"text":"וַאֲנִ֞י הִנֵּ֧ה נְתַתִּ֣יךָ הַיּ֗וֹם לְעִ֨יר מִבְצָ֜ר וּלְעַמּ֥וּד בַּרְזֶ֛ל וּלְחֹמ֥וֹת נְחֹ֖שֶׁת עַל־כָּל־הָאָ֑רֶץ לְמַלְכֵ֤י יְהוּדָה֙ לְשָׂרֶ֔יהָ לְכֹהֲנֶ֖יהָ וּלְעַ֥ם הָאָֽרֶץ׃"}},"definableWords":["day","made","land","kings","Judah","people"],"peopleInVerse":[],"themesInVerse":["creation","land_promise"]},"19":{"text":"And they shall fight against thee; but they shall not prevail against thee; for I am with thee, saith the LORD, to deliver thee.","ref":"Jeremiah 1:19","synthesized":"They will fight against you but will never overcome you, since I am with you to deliver you,” declares the LORD.","sources":{"KJV":{"text":"And they shall fight against thee; but they shall not prevail against thee; for I am with thee, saith the LORD, to deliver thee."},"BSB":{"text":"They will fight against you but will never overcome you, since I am with you to deliver you,” declares the LORD."},"TANAKH":{"text":"And they shall fight against thee; but they shall not prevail against thee; For I am with thee, saith HaShem, to deliver thee.'"},"HEBREW":{"text":"וְנִלְחֲמ֥וּ אֵלֶ֖יךָ וְלֹא־י֣וּכְלוּ לָ֑ךְ כִּֽי־אִתְּךָ֥ אֲנִ֛י נְאֻם־יְהוָ֖ה לְהַצִּילֶֽךָ׃"}},"definableWords":["fight","overcome","deliver","LORD"],"peopleInVerse":[],"themesInVerse":["redemption","salvation","spiritual_warfare"]}}},"2":{"chapter":"2","title":"ISRAEL HAS FORSAKEN THE FOUNTAIN","verses":{"1":{"text":"Moreover the word of the LORD came to me, saying,","ref":"Jeremiah 2:1","synthesized":"Now the word of the LORD came to me, saying,","sources":{"KJV":{"text":"Moreover the word of the LORD came to me, saying,"},"BSB":{"text":"Now the word of the LORD came to me, saying,"},"TANAKH":{"text":"And the word of HaShem came to me, saying:"},"HEBREW":{"text":"וַיְהִ֥י דְבַר־יְהוָ֖ה אֵלַ֥י לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"2":{"text":"Go and cry in the ears of Jerusalem, saying, Thus saith the LORD; I remember thee, the kindness of thy youth, the love of thine espousals, when thou wentest after me in the wilderness, in a land that was not sown.","ref":"Jeremiah 2:2","synthesized":"“Go and proclaim in the hearing of Jerusalem that this is what the LORD says:  ‘I remember the devotion of your youth, your love as a bride, how you followed Me in the wilderness, in a land not sown.","sources":{"KJV":{"text":"Go and cry in the ears of Jerusalem, saying, Thus saith the LORD; I remember thee, the kindness of thy youth, the love of thine espousals, when thou wentest after me in the wilderness, in a land that was not sown."},"BSB":{"text":"“Go and proclaim in the hearing of Jerusalem that this is what the LORD says:  ‘I remember the devotion of your youth, your love as a bride, how you followed Me in the wilderness, in a land not sown."},"TANAKH":{"text":"Go, and cry in the ears of Jerusalem, saying: Thus saith HaShem: I remember for thee the affection of thy youth, the love of thine espousals; how thou wentest after Me in the wilderness, in a land that was not sown."},"HEBREW":{"text":"הָלֹ֡ךְ וְקָֽרָאתָ֩ בְאָזְנֵ֨י יְרוּשָׁלִַ֜ם לֵאמֹ֗ר כֹּ֚ה אָמַ֣ר יְהוָ֔ה זָכַ֤רְתִּי לָךְ֙ חֶ֣סֶד נְעוּרַ֔יִךְ אַהֲבַ֖ת כְּלוּלֹתָ֑יִךְ לֶכְתֵּ֤ךְ אַחֲרַי֙ בַּמִּדְבָּ֔ר בְּאֶ֖רֶץ לֹ֥א זְרוּעָֽה׃"}},"definableWords":["Jerusalem","LORD","remember","love","land"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["land_promise","love","marriage_bride"]},"3":{"text":"Israel was holiness unto the LORD, and the firstfruits of his increase: all that devour him shall offend; evil shall come upon them, saith the LORD.","ref":"Jeremiah 2:3","synthesized":"Israel was holy to the LORD, the firstfruits of His harvest. All who devoured her found themselves guilty; disaster came upon them,’” declares the LORD.","sources":{"KJV":{"text":"Israel was holiness unto the LORD, and the firstfruits of his increase: all that devour him shall offend; evil shall come upon them, saith the LORD."},"BSB":{"text":"Israel was holy to the LORD, the firstfruits of His harvest. All who devoured her found themselves guilty; disaster came upon them,’” declares the LORD."},"TANAKH":{"text":"Israel is HaShem'S hallowed portion, His first-fruits of the increase; all that devour him shall be held guilty, evil shall come upon them, saith HaShem."},"HEBREW":{"text":"קֹ֤דֶשׁ יִשְׂרָאֵל֙ לַיהוָ֔ה רֵאשִׁ֖ית תְּבוּאָתֹ֑ה כָּל־אֹכְלָ֣יו יֶאְשָׁ֔מוּ רָעָ֛ה תָּבֹ֥א אֲלֵיהֶ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["Israel","holy","LORD","Lord"],"peopleInVerse":[]},"4":{"text":"Hear ye the word of the LORD, O house of Jacob, and all the families of the house of Israel:","ref":"Jeremiah 2:4","synthesized":"Hear the word of the LORD, O house of Jacob, and all you families of the house of Israel.","sources":{"KJV":{"text":"Hear ye the word of the LORD, O house of Jacob, and all the families of the house of Israel:"},"BSB":{"text":"Hear the word of the LORD, O house of Jacob, and all you families of the house of Israel."},"TANAKH":{"text":"Hear ye the word of HaShem, O house of Jacob, and all the families of the house of Israel;"},"HEBREW":{"text":"שִׁמְע֥וּ דְבַר־יְהוָ֖ה בֵּ֣ית יַעֲקֹ֑ב וְכָֽל־מִשְׁפְּח֖וֹת בֵּ֥ית יִשְׂרָאֵֽל׃"}},"definableWords":["hear","word","LORD","house","Jacob","families","Israel"],"peopleInVerse":["Jacob"]},"5":{"text":"Thus saith the LORD, What iniquity have your fathers found in me, that they are gone far from me, and have walked after vanity, and are become vain?","ref":"Jeremiah 2:5","synthesized":"This is what the LORD says:  “What fault did your fathers find in Me that they strayed so far from Me, and followed worthless idols, and became worthless themselves?","sources":{"KJV":{"text":"Thus saith the LORD, What iniquity have your fathers found in me, that they are gone far from me, and have walked after vanity, and are become vain?"},"BSB":{"text":"This is what the LORD says:  “What fault did your fathers find in Me that they strayed so far from Me, and followed worthless idols, and became worthless themselves?"},"TANAKH":{"text":"Thus saith HaShem: what unrighteousness have your fathers found in Me, that they are gone far from Me, and have walked after things of nought, and are become nought?"},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה מַה־מָּצְא֨וּ אֲבוֹתֵיכֶ֥ם בִּי֙ עָ֔וֶל כִּ֥י רָחֲק֖וּ מֵעָלָ֑י וַיֵּֽלְכ֛וּ אַחֲרֵ֥י הַהֶ֖בֶל וַיֶּהְבָּֽלוּ׃"}},"definableWords":["LORD","fathers"],"peopleInVerse":[]},"6":{"text":"Neither said they, Where is the LORD that brought us up out of the land of Egypt, that led us through the wilderness, through a land of deserts and of pits, through a land of drought, and of the shadow of death, through a land that no man passed through, and where no man dwelt?","ref":"Jeremiah 2:6","synthesized":"They did not ask, ‘Where is the LORD who brought us up from the land of Egypt, who led us through the wilderness, through a land of deserts and pits, a land of drought and darkness, a land where no one travels and no one lives?’","sources":{"KJV":{"text":"Neither said they, Where is the LORD that brought us up out of the land of Egypt, that led us through the wilderness, through a land of deserts and of pits, through a land of drought, and of the shadow of death, through a land that no man passed through, and where no man dwelt?"},"BSB":{"text":"They did not ask, ‘Where is the LORD who brought us up from the land of Egypt, who led us through the wilderness, through a land of deserts and pits, a land of drought and darkness, a land where no one travels and no one lives?’"},"TANAKH":{"text":"Neither said they: 'Where is HaShem that brought us up out of the land of Egypt; that led us through the wilderness, through a land of deserts and of pits, through a land of drought and of the shadow of death, through a land that no man passed through, and where no man dwelt?'"},"HEBREW":{"text":"וְלֹ֣א אָמְר֔וּ אַיֵּ֣ה יְהוָ֔ה הַמַּעֲלֶ֥ה אֹתָ֖נוּ מֵאֶ֣רֶץ מִצְרָ֑יִם הַמּוֹלִ֨יךְ אֹתָ֜נוּ בַּמִּדְבָּ֗ר בְּאֶ֨רֶץ עֲרָבָ֤ה וְשׁוּחָה֙ בְּאֶ֙רֶץ֙ צִיָּ֣ה וְצַלְמָ֔וֶת בְּאֶ֗רֶץ לֹֽא־עָ֤בַר בָּהּ֙ אִ֔ישׁ וְלֹֽא־יָשַׁ֥ב אָדָ֖ם שָֽׁם׃"}},"definableWords":["LORD","land","Egypt","darkness","one"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise","light_darkness"]},"7":{"text":"And I brought you into a plentiful country, to eat the fruit thereof and the goodness thereof; but when ye entered, ye defiled my land, and made mine heritage an abomination.","ref":"Jeremiah 2:7","synthesized":"I brought you into a fertile land to eat its fruit and bounty, but you came and defiled My land, and made My inheritance detestable.","sources":{"KJV":{"text":"And I brought you into a plentiful country, to eat the fruit thereof and the goodness thereof; but when ye entered, ye defiled my land, and made mine heritage an abomination."},"BSB":{"text":"I brought you into a fertile land to eat its fruit and bounty, but you came and defiled My land, and made My inheritance detestable."},"TANAKH":{"text":"And I brought you into a land of fruitful fields, to eat the fruit thereof and the good thereof; but when ye entered, ye defiled My land, and made My heritage an abomination."},"HEBREW":{"text":"וָאָבִ֤יא אֶתְכֶם֙ אֶל־אֶ֣רֶץ הַכַּרְמֶ֔ל לֶאֱכֹ֥ל פִּרְיָ֖הּ וְטוּבָ֑הּ וַתָּבֹ֙אוּ֙ וַתְּטַמְּא֣וּ אֶת־אַרְצִ֔י וְנַחֲלָתִ֥י שַׂמְתֶּ֖ם לְתוֹעֵבָֽה׃"}},"definableWords":["land","made"],"peopleInVerse":[],"themesInVerse":["creation","land_promise","vine_branches"]},"8":{"text":"The priests said not, Where is the LORD? and they that handle the law knew me not: the pastors also transgressed against me, and the prophets prophesied by Baal, and walked after things that do not profit.","ref":"Jeremiah 2:8","synthesized":"The priests did not ask, ‘Where is the LORD?’ The experts in the law no longer knew Me, and the leaders rebelled against Me. The prophets prophesied by Baal and followed useless idols.","sources":{"KJV":{"text":"The priests said not, Where is the LORD? and they that handle the law knew me not: the pastors also transgressed against me, and the prophets prophesied by Baal, and walked after things that do not profit."},"BSB":{"text":"The priests did not ask, ‘Where is the LORD?’ The experts in the law no longer knew Me, and the leaders rebelled against Me. The prophets prophesied by Baal and followed useless idols."},"TANAKH":{"text":"The priests said not: 'Where is HaShem?' And they that handle the law knew Me not, and the rulers transgressed against Me; the prophets also prophesied by Baal, and walked after things that do not profit."},"HEBREW":{"text":"הַכֹּהֲנִ֗ים לֹ֤א אָֽמְרוּ֙ אַיֵּ֣ה יְהוָ֔ה וְתֹפְשֵׂ֤י הַתּוֹרָה֙ לֹ֣א יְדָע֔וּנִי וְהָרֹעִ֖ים פָּ֣שְׁעוּ בִ֑י וְהַנְּבִיאִים֙ נִבְּא֣וּ בַבַּ֔עַל וְאַחֲרֵ֥י לֹֽא־יוֹעִ֖לוּ הָלָֽכוּ׃"}},"definableWords":["LORD","law"],"peopleInVerse":[]},"9":{"text":"Wherefore I will yet plead with you, saith the LORD, and with your children’s children will I plead.","ref":"Jeremiah 2:9","synthesized":"Therefore, I will contend with you again, declares the LORD, and I will bring a case against your children’s children.","sources":{"KJV":{"text":"Wherefore I will yet plead with you, saith the LORD, and with your children’s children will I plead."},"BSB":{"text":"Therefore, I will contend with you again, declares the LORD, and I will bring a case against your children’s children."},"TANAKH":{"text":"Wherefore I will yet plead with you, saith HaShem, and with your children's children will I plead."},"HEBREW":{"text":"לָכֵ֗ן עֹ֛ד אָרִ֥יב אִתְּכֶ֖ם נְאֻם־יְהוָ֑ה וְאֶת־בְּנֵ֥י בְנֵיכֶ֖ם אָרִֽיב׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"10":{"text":"For pass over the isles of Chittim, and see; and send unto Kedar, and consider diligently, and see if there be such a thing.","ref":"Jeremiah 2:10","synthesized":"Cross over to the coasts of Cyprus and take a look; send to Kedar and consider carefully; see if there has ever been anything like this:","sources":{"KJV":{"text":"For pass over the isles of Chittim, and see; and send unto Kedar, and consider diligently, and see if there be such a thing."},"BSB":{"text":"Cross over to the coasts of Cyprus and take a look; send to Kedar and consider carefully; see if there has ever been anything like this:"},"TANAKH":{"text":"For pass over to the isles of the Kittites, and see, and send unto Kedar, and consider diligently, and see if there hath been such a thing."},"HEBREW":{"text":"כִּ֣י עִבְר֞וּ אִיֵּ֤י כִתִּיִּים֙ וּרְא֔וּ וְקֵדָ֛ר שִׁלְח֥וּ וְהִֽתְבּוֹנְנ֖וּ מְאֹ֑ד וּרְא֕וּ הֵ֥ן הָיְתָ֖ה כָּזֹֽאת׃"}},"definableWords":["see"],"peopleInVerse":[]},"11":{"text":"Hath a nation changed their gods, which are yet no gods? but my people have changed their glory for that which doth not profit.","ref":"Jeremiah 2:11","synthesized":"Has a nation ever changed its gods, though they are no gods at all? Yet My people have exchanged their Glory for useless idols.","sources":{"KJV":{"text":"Hath a nation changed their gods, which are yet no gods? but my people have changed their glory for that which doth not profit."},"BSB":{"text":"Has a nation ever changed its gods, though they are no gods at all? Yet My people have exchanged their Glory for useless idols."},"TANAKH":{"text":"Hath a nation changed its gods, which yet are no gods? But My people hath changed its glory for that which doth not profit."},"HEBREW":{"text":"הַהֵימִ֥יר גּוֹי֙ אֱלֹהִ֔ים וְהֵ֖מָּה לֹ֣א אֱלֹהִ֑ים וְעַמִּ֛י הֵמִ֥יר כְּבוֹד֖וֹ בְּל֥וֹא יוֹעִֽיל׃"}},"definableWords":["nation","people","glory"],"peopleInVerse":[],"themesInVerse":["worship"]},"12":{"text":"Be astonished, O ye heavens, at this, and be horribly afraid, be ye very desolate, saith the LORD.","ref":"Jeremiah 2:12","synthesized":"Be stunned by this, O heavens; be shocked and utterly appalled,” declares the LORD.","sources":{"KJV":{"text":"Be astonished, O ye heavens, at this, and be horribly afraid, be ye very desolate, saith the LORD."},"BSB":{"text":"Be stunned by this, O heavens; be shocked and utterly appalled,” declares the LORD."},"TANAKH":{"text":"Be astonished, O ye heavens, at this, and be horribly afraid, be ye exceeding amazed, saith HaShem."},"HEBREW":{"text":"שֹׁ֥מּוּ שָׁמַ֖יִם עַל־זֹ֑את וְשַׂעֲר֛וּ חָרְב֥וּ מְאֹ֖ד נְאֻם־יְהוָֽה׃"}},"definableWords":["heavens","LORD"],"peopleInVerse":[]},"13":{"text":"For my people have committed two evils; they have forsaken me the fountain of living waters, and hewed them out cisterns, broken cisterns, that can hold no water.","ref":"Jeremiah 2:13","synthesized":"“For My people have committed two evils:   They have forsaken Me, the fountain of living water, and they have dug their own cisterns— broken cisterns that cannot hold water.","sources":{"KJV":{"text":"For my people have committed two evils; they have forsaken me the fountain of living waters, and hewed them out cisterns, broken cisterns, that can hold no water."},"BSB":{"text":"“For My people have committed two evils:   They have forsaken Me, the fountain of living water, and they have dug their own cisterns— broken cisterns that cannot hold water."},"TANAKH":{"text":"For My people have committed two evils: they have forsaken Me, the fountain of living waters, and hewed them out cisterns, broken cisterns, that can hold no water."},"HEBREW":{"text":"כִּֽי־שְׁתַּ֥יִם רָע֖וֹת עָשָׂ֣ה עַמִּ֑י אֹתִ֨י עָזְב֜וּ מְק֣וֹר ׀ מַ֣יִם חַיִּ֗ים לַחְצֹ֤ב לָהֶם֙ בֹּאר֔וֹת בֹּארֹת֙ נִשְׁבָּרִ֔ים אֲשֶׁ֥ר לֹא־יָכִ֖לוּ הַמָּֽיִם׃"}},"definableWords":["people","living","water"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"14":{"text":"Is Israel a servant? is he a homeborn slave? why is he spoiled?","ref":"Jeremiah 2:14","synthesized":"Is Israel a slave? Was he born into slavery? Why then has he become prey?","sources":{"KJV":{"text":"Is Israel a servant? is he a homeborn slave? why is he spoiled?"},"BSB":{"text":"Is Israel a slave? Was he born into slavery? Why then has he become prey?"},"TANAKH":{"text":"Is Israel a servant? Is he a home-born slave? Why is he become a prey?"},"HEBREW":{"text":"הַעֶ֙בֶד֙ יִשְׂרָאֵ֔ל אִם־יְלִ֥יד בַּ֖יִת ה֑וּא מַדּ֖וּעַ הָיָ֥ה לָבַֽז׃"}},"definableWords":["Israel"],"peopleInVerse":[]},"15":{"text":"The young lions roared upon him, and yelled, and they made his land waste: his cities are burned without inhabitant.","ref":"Jeremiah 2:15","synthesized":"The young lions have roared at him; they have growled with a loud voice. They have laid waste his land; his cities lie in ruins, without inhabitant.","sources":{"KJV":{"text":"The young lions roared upon him, and yelled, and they made his land waste: his cities are burned without inhabitant."},"BSB":{"text":"The young lions have roared at him; they have growled with a loud voice. They have laid waste his land; his cities lie in ruins, without inhabitant."},"TANAKH":{"text":"The young lions have roared upon him, and let their voice resound; and they have made his land desolate, his cities are laid waste, without inhabitant."},"HEBREW":{"text":"עָלָיו֙ יִשְׁאֲג֣וּ כְפִרִ֔ים נָתְנ֖וּ קוֹלָ֑ם וַיָּשִׁ֤יתוּ אַרְצוֹ֙ לְשַׁמָּ֔ה עָרָ֥יו נצתה נִצְּת֖וּ מִבְּלִ֥י יֹשֵֽׁב׃"}},"definableWords":["voice","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"16":{"text":"Also the children of Noph and Tahapanes have broken the crown of thy head.","ref":"Jeremiah 2:16","synthesized":"The men of Memphis and Tahpanhes have shaved the crown of your head.","sources":{"KJV":{"text":"Also the children of Noph and Tahapanes have broken the crown of thy head."},"BSB":{"text":"The men of Memphis and Tahpanhes have shaved the crown of your head."},"TANAKH":{"text":"The children also of Noph and Tahpanhes feed upon the crown of thy head."},"HEBREW":{"text":"גַּם־בְּנֵי־נֹ֖ף ותחפנס וְתַחְפַּנְחֵ֑ס יִרְע֖וּךְ קָדְקֹֽד׃"}},"definableWords":["men","crown"],"peopleInVerse":[]},"17":{"text":"Hast thou not procured this unto thyself, in that thou hast forsaken the LORD thy God, when he led thee by the way?","ref":"Jeremiah 2:17","synthesized":"Have you not brought this on yourself by forsaking the LORD your God when He led you in the way?","sources":{"KJV":{"text":"Hast thou not procured this unto thyself, in that thou hast forsaken the LORD thy God, when he led thee by the way?"},"BSB":{"text":"Have you not brought this on yourself by forsaking the LORD your God when He led you in the way?"},"TANAKH":{"text":"Is it not this that doth cause it unto thee, that thou hast forsaken HaShem thy G-d, when He led thee by the way?"},"HEBREW":{"text":"הֲלוֹא־זֹ֖את תַּעֲשֶׂה־לָּ֑ךְ עָזְבֵךְ֙ אֶת־יְהוָ֣ה אֱלֹהַ֔יִךְ בְּעֵ֖ת מוֹלִיכֵ֥ךְ בַּדָּֽרֶךְ׃"}},"definableWords":["LORD","God","way"],"peopleInVerse":[]},"18":{"text":"And now what hast thou to do in the way of Egypt, to drink the waters of Sihor? or what hast thou to do in the way of Assyria, to drink the waters of the river?","ref":"Jeremiah 2:18","synthesized":"Now what will you gain on your way to Egypt to drink the waters of the Nile? What will you gain on your way to Assyria to drink the waters of the Euphrates?","sources":{"KJV":{"text":"And now what hast thou to do in the way of Egypt, to drink the waters of Sihor? or what hast thou to do in the way of Assyria, to drink the waters of the river?"},"BSB":{"text":"Now what will you gain on your way to Egypt to drink the waters of the Nile? What will you gain on your way to Assyria to drink the waters of the Euphrates?"},"TANAKH":{"text":"And now what hast thou to do in the way to Egypt, to drink the waters of Shihor? Or what hast thou to do in the way to Assyria, to drink the waters of the River?"},"HEBREW":{"text":"וְעַתָּ֗ה מַה־לָּךְ֙ לְדֶ֣רֶךְ מִצְרַ֔יִם לִשְׁתּ֖וֹת מֵ֣י שִׁח֑וֹר וּמַה־לָּךְ֙ לְדֶ֣רֶךְ אַשּׁ֔וּר לִשְׁתּ֖וֹת מֵ֥י נָהָֽר׃"}},"definableWords":["way","Egypt","waters"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern"]},"19":{"text":"Thine own wickedness shall correct thee, and thy backslidings shall reprove thee: know therefore and see that it is an evil thing and bitter, that thou hast forsaken the LORD thy God, and that my fear is not in thee, saith the Lord GOD of hosts.","ref":"Jeremiah 2:19","synthesized":"Your own evil will discipline you; your own apostasies will reprimand you. Consider and realize how evil and bitter it is for you to forsake the LORD your God and to have no fear of Me,” declares the Lord GOD of Hosts.","sources":{"KJV":{"text":"Thine own wickedness shall correct thee, and thy backslidings shall reprove thee: know therefore and see that it is an evil thing and bitter, that thou hast forsaken the LORD thy God, and that my fear is not in thee, saith the Lord GOD of hosts."},"BSB":{"text":"Your own evil will discipline you; your own apostasies will reprimand you. Consider and realize how evil and bitter it is for you to forsake the LORD your God and to have no fear of Me,” declares the Lord GOD of Hosts."},"TANAKH":{"text":"Thine own wickedness shall correct thee, and thy backslidings shall reprove thee: know therefore and see that it is an evil and a bitter thing, that thou hast forsaken HaShem thy G-d, neither is My fear in thee, saith the L-rd GOD of hosts."},"HEBREW":{"text":"תְּיַסְּרֵ֣ךְ רָעָתֵ֗ךְ וּמְשֻֽׁבוֹתַ֙יִךְ֙ תּוֹכִחֻ֔ךְ וּדְעִ֤י וּרְאִי֙ כִּי־רַ֣ע וָמָ֔ר עָזְבֵ֖ךְ אֶת־יְהוָ֣ה אֱלֹהָ֑יִךְ וְלֹ֤א פַחְדָּתִי֙ אֵלַ֔יִךְ נְאֻם־אֲדֹנָ֥י יְהוִ֖ה צְבָאֽוֹת׃"}},"definableWords":["evil","LORD","God","fear","Lord"],"peopleInVerse":[],"themesInVerse":["fear_of_lord"]},"20":{"text":"For of old time I have broken thy yoke, and burst thy bands; and thou saidst, I will not transgress; when upon every high hill and under every green tree thou wanderest, playing the harlot.","ref":"Jeremiah 2:20","synthesized":"“For long ago you broke your yoke and tore off your chains, saying, ‘I will not serve!’ Indeed, on every high hill and under every green tree you lay down as a prostitute.","sources":{"KJV":{"text":"For of old time I have broken thy yoke, and burst thy bands; and thou saidst, I will not transgress; when upon every high hill and under every green tree thou wanderest, playing the harlot."},"BSB":{"text":"“For long ago you broke your yoke and tore off your chains, saying, ‘I will not serve!’ Indeed, on every high hill and under every green tree you lay down as a prostitute."},"TANAKH":{"text":"For of old time I have broken thy yoke, and burst thy bands, and thou saidst: 'I will not transgress'; upon every high hill and under every leafy tree thou didst recline, playing the harlot."},"HEBREW":{"text":"כִּ֣י מֵעוֹלָ֞ם שָׁבַ֣רְתִּי עֻלֵּ֗ךְ נִתַּ֙קְתִּי֙ מוֹסְרֹתַ֔יִךְ וַתֹּאמְרִ֖י לֹ֣א אעבד אֶעֱב֑וֹר כִּ֣י עַֽל־כָּל־גִּבְעָ֞ה גְּבֹהָ֗ה וְתַ֙חַת֙ כָּל־עֵ֣ץ רַעֲנָ֔ן אַ֖תְּ צֹעָ֥ה זֹנָֽה׃"}},"definableWords":["tree"],"peopleInVerse":[]},"21":{"text":"Yet I had planted thee a noble vine, wholly a right seed: how then art thou turned into the degenerate plant of a strange vine unto me?","ref":"Jeremiah 2:21","synthesized":"I had planted you like a choice vine from the very best seed. How could you turn yourself before Me into a rotten, wild vine?","sources":{"KJV":{"text":"Yet I had planted thee a noble vine, wholly a right seed: how then art thou turned into the degenerate plant of a strange vine unto me?"},"BSB":{"text":"I had planted you like a choice vine from the very best seed. How could you turn yourself before Me into a rotten, wild vine?"},"TANAKH":{"text":"Yet I had planted thee a noble vine, wholly a right seed; how then art thou turned into the degenerate plant of a strange vine unto Me?"},"HEBREW":{"text":"וְאָֽנֹכִי֙ נְטַעְתִּ֣יךְ שֹׂרֵ֔ק כֻּלֹּ֖ה זֶ֣רַע אֱמֶ֑ת וְאֵיךְ֙ נֶהְפַּ֣כְתְּ לִ֔י סוּרֵ֖י הַגֶּ֥פֶן נָכְרִיָּֽה׃"}},"definableWords":["seed"],"peopleInVerse":[],"themesInVerse":["messiah","vine_branches"]},"22":{"text":"For though thou wash thee with nitre, and take thee much soap, yet thine iniquity is marked before me, saith the Lord GOD.","ref":"Jeremiah 2:22","synthesized":"Although you wash with lye and use an abundance of soap, the stain of your guilt is still before Me,” declares the Lord GOD.","sources":{"KJV":{"text":"For though thou wash thee with nitre, and take thee much soap, yet thine iniquity is marked before me, saith the Lord GOD."},"BSB":{"text":"Although you wash with lye and use an abundance of soap, the stain of your guilt is still before Me,” declares the Lord GOD."},"TANAKH":{"text":"For though thou wash thee with nitre, and take thee much soap, yet thine iniquity is marked before Me, saith the L-rd GOD."},"HEBREW":{"text":"כִּ֤י אִם־תְּכַבְּסִי֙ בַּנֶּ֔תֶר וְתַרְבִּי־לָ֖ךְ בֹּרִ֑ית נִכְתָּ֤ם עֲוֺנֵךְ֙ לְפָנַ֔י נְאֻ֖ם אֲדֹנָ֥י יְהוִֽה׃"}},"definableWords":["Lord","God"],"peopleInVerse":[]},"23":{"text":"How canst thou say, I am not polluted, I have not gone after Baalim? see thy way in the valley, know what thou hast done: thou art a swift dromedary traversing her ways;","ref":"Jeremiah 2:23","synthesized":"“How can you say, ‘I am not defiled; I have not run after the Baals’? Look at your behavior in the valley; acknowledge what you have done. You are a swift young she-camel galloping here and there,","sources":{"KJV":{"text":"How canst thou say, I am not polluted, I have not gone after Baalim? see thy way in the valley, know what thou hast done: thou art a swift dromedary traversing her ways;"},"BSB":{"text":"“How can you say, ‘I am not defiled; I have not run after the Baals’? Look at your behavior in the valley; acknowledge what you have done. You are a swift young she-camel galloping here and there,"},"TANAKH":{"text":"How canst thou say: 'I am not defiled, I have not gone after the Baalim'? See thy way in the Valley, know what thou hast done; thou art a swift young camel traversing her ways;"},"HEBREW":{"text":"אֵ֣יךְ תֹּאמְרִ֞י לֹ֣א נִטְמֵ֗אתִי אַחֲרֵ֤י הַבְּעָלִים֙ לֹ֣א הָלַ֔כְתִּי רְאִ֤י דַרְכֵּךְ֙ בַּגַּ֔יְא דְּעִ֖י מֶ֣ה עָשִׂ֑ית בִּכְרָ֥ה קַלָּ֖ה מְשָׂרֶ֥כֶת דְּרָכֶֽיהָ׃"}},"definableWords":["run"],"peopleInVerse":[]},"24":{"text":"A wild ass used to the wilderness, that snuffeth up the wind at her pleasure; in her occasion who can turn her away? all they that seek her will not weary themselves; in her month they shall find her.","ref":"Jeremiah 2:24","synthesized":"a wild donkey at home in the wilderness, sniffing the wind in the heat of her desire. Who can restrain her passion? All who seek her need not weary themselves; in mating season they will find her.","sources":{"KJV":{"text":"A wild ass used to the wilderness, that snuffeth up the wind at her pleasure; in her occasion who can turn her away? all they that seek her will not weary themselves; in her month they shall find her."},"BSB":{"text":"a wild donkey at home in the wilderness, sniffing the wind in the heat of her desire. Who can restrain her passion? All who seek her need not weary themselves; in mating season they will find her."},"TANAKH":{"text":"A wild ass used to the wilderness, that snuffeth up the wind in her desire; her lust, who can hinder it? All they that seek her will not weary themselves; in her month they shall find her."},"HEBREW":{"text":"פֶּ֣רֶה ׀ לִמֻּ֣ד מִדְבָּ֗ר בְּאַוַּ֤ת נפשו נַפְשָׁהּ֙ שָׁאֲפָ֣ה ר֔וּחַ תַּאֲנָתָ֖הּ מִ֣י יְשִׁיבֶ֑נָּה כָּל־מְבַקְשֶׁ֙יהָ֙ לֹ֣א יִיעָ֔פוּ בְּחָדְשָׁ֖הּ יִמְצָאֽוּנְהָ׃"}},"definableWords":["seek"],"peopleInVerse":[]},"25":{"text":"Withhold thy foot from being unshod, and thy throat from thirst: but thou saidst, There is no hope: no; for I have loved strangers, and after them will I go.","ref":"Jeremiah 2:25","synthesized":"You should have kept your feet from going bare and your throat from being thirsty. But you said, ‘It is hopeless! For I love foreign gods, and I must go after them.’","sources":{"KJV":{"text":"Withhold thy foot from being unshod, and thy throat from thirst: but thou saidst, There is no hope: no; for I have loved strangers, and after them will I go."},"BSB":{"text":"You should have kept your feet from going bare and your throat from being thirsty. But you said, ‘It is hopeless! For I love foreign gods, and I must go after them.’"},"TANAKH":{"text":"Withhold thy foot from being unshod, and thy throat from thirst; but thou saidst: 'There is no hope; no, for I have loved strangers, and after them will I go.'"},"HEBREW":{"text":"מִנְעִ֤י רַגְלֵךְ֙ מִיָּחֵ֔ף וגורנך וּגְרוֹנֵ֖ךְ מִצִּמְאָ֑ה וַתֹּאמְרִ֣י נוֹאָ֔שׁ ל֕וֹא כִּֽי־אָהַ֥בְתִּי זָרִ֖ים וְאַחֲרֵיהֶ֥ם אֵלֵֽךְ׃"}},"definableWords":["love"],"peopleInVerse":[],"themesInVerse":["love"]},"26":{"text":"As the thief is ashamed when he is found, so is the house of Israel ashamed; they, their kings, their princes, and their priests, and their prophets,","ref":"Jeremiah 2:26","synthesized":"As the thief is ashamed when he is caught, so the house of Israel is disgraced. They, their kings, their officials, their priests, and their prophets","sources":{"KJV":{"text":"As the thief is ashamed when he is found, so is the house of Israel ashamed; they, their kings, their princes, and their priests, and their prophets,"},"BSB":{"text":"As the thief is ashamed when he is caught, so the house of Israel is disgraced. They, their kings, their officials, their priests, and their prophets"},"TANAKH":{"text":"As the thief is ashamed when he is found, so is the house of Israel ashamed; they, their kings, their princes, and their priests, and their prophets;"},"HEBREW":{"text":"כְּבֹ֤שֶׁת גַּנָּב֙ כִּ֣י יִמָּצֵ֔א כֵּ֥ן הֹבִ֖ישׁוּ בֵּ֣ית יִשְׂרָאֵ֑ל הֵ֤מָּה מַלְכֵיהֶם֙ שָֽׂרֵיהֶ֔ם וְכֹהֲנֵיהֶ֖ם וּנְבִיאֵיהֶֽם׃"}},"definableWords":["house","Israel","kings"],"peopleInVerse":[]},"27":{"text":"Saying to a stock, Thou art my father; and to a stone, Thou hast brought me forth: for they have turned their back unto me, and not their face: but in the time of their trouble they will say, Arise, and save us.","ref":"Jeremiah 2:27","synthesized":"say to a tree, ‘You are my father,’ and to a stone, ‘You gave me birth.’ For they have turned their backs to Me and not their faces, yet in the time of trouble they beg, ‘Rise up and save us!’","sources":{"KJV":{"text":"Saying to a stock, Thou art my father; and to a stone, Thou hast brought me forth: for they have turned their back unto me, and not their face: but in the time of their trouble they will say, Arise, and save us."},"BSB":{"text":"say to a tree, ‘You are my father,’ and to a stone, ‘You gave me birth.’ For they have turned their backs to Me and not their faces, yet in the time of trouble they beg, ‘Rise up and save us!’"},"TANAKH":{"text":"Who say to a stock: 'Thou art my father', and to a stone: 'Thou hast brought us forth', for they have turned their back unto Me, and not their face; but in the time of their trouble they will say: 'Arise, and save us.'"},"HEBREW":{"text":"אֹמְרִ֨ים לָעֵ֜ץ אָ֣בִי אַ֗תָּה וְלָאֶ֙בֶן֙ אַ֣תְּ ילדתני יְלִדְתָּ֔נוּ כִּֽי־פָנ֥וּ אֵלַ֛י עֹ֖רֶף וְלֹ֣א פָנִ֑ים וּבְעֵ֤ת רָֽעָתָם֙ יֹֽאמְר֔וּ ק֖וּמָה וְהוֹשִׁיעֵֽנוּ׃"}},"definableWords":["tree","father","stone"],"peopleInVerse":[],"themesInVerse":["resurrection","salvation"]},"28":{"text":"But where are thy gods that thou hast made thee? let them arise, if they can save thee in the time of thy trouble: for according to the number of thy cities are thy gods, O Judah.","ref":"Jeremiah 2:28","synthesized":"But where are the gods you made for yourselves? Let them rise up in your time of trouble and save you if they can; for your gods are as numerous as your cities, O Judah.","sources":{"KJV":{"text":"But where are thy gods that thou hast made thee? let them arise, if they can save thee in the time of thy trouble: for according to the number of thy cities are thy gods, O Judah."},"BSB":{"text":"But where are the gods you made for yourselves? Let them rise up in your time of trouble and save you if they can; for your gods are as numerous as your cities, O Judah."},"TANAKH":{"text":"But where are thy gods that thou hast made thee? Let them arise, if they can save thee in the time of thy trouble; for according to the number of thy cities are thy gods, O Judah."},"HEBREW":{"text":"וְאַיֵּ֤ה אֱלֹהֶ֙יךָ֙ אֲשֶׁ֣ר עָשִׂ֣יתָ לָּ֔ךְ יָק֕וּמוּ אִם־יוֹשִׁיע֖וּךָ בְּעֵ֣ת רָעָתֶ֑ךָ כִּ֚י מִסְפַּ֣ר עָרֶ֔יךָ הָי֥וּ אֱלֹהֶ֖יךָ יְהוּדָֽה׃"}},"definableWords":["made","Judah"],"peopleInVerse":[],"themesInVerse":["creation","resurrection","salvation"]},"29":{"text":"Wherefore will ye plead with me? ye all have transgressed against me, saith the LORD.","ref":"Jeremiah 2:29","synthesized":"Why do you bring a case against Me? You have all rebelled against Me,” declares the LORD.","sources":{"KJV":{"text":"Wherefore will ye plead with me? ye all have transgressed against me, saith the LORD."},"BSB":{"text":"Why do you bring a case against Me? You have all rebelled against Me,” declares the LORD."},"TANAKH":{"text":"Wherefore will ye contend with Me? Ye all have transgressed against Me, saith HaShem."},"HEBREW":{"text":"לָ֥מָּה תָרִ֖יבוּ אֵלָ֑י כֻּלְּכֶ֛ם פְּשַׁעְתֶּ֥ם בִּ֖י נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"30":{"text":"In vain have I smitten your children; they received no correction: your own sword hath devoured your prophets, like a destroying lion.","ref":"Jeremiah 2:30","synthesized":"“I have struck your sons in vain; they accepted no discipline. Your own sword has devoured your prophets like a voracious lion.”","sources":{"KJV":{"text":"In vain have I smitten your children; they received no correction: your own sword hath devoured your prophets, like a destroying lion."},"BSB":{"text":"“I have struck your sons in vain; they accepted no discipline. Your own sword has devoured your prophets like a voracious lion.”"},"TANAKH":{"text":"In vain have I smitten your children--they received no correction; your sword hath devoured your prophets, like a destroying lion."},"HEBREW":{"text":"לַשָּׁוְא֙ הִכֵּ֣יתִי אֶת־בְּנֵיכֶ֔ם מוּסָ֖ר לֹ֣א לָקָ֑חוּ אָכְלָ֧ה חַרְבְּכֶ֛ם נְבִֽיאֵיכֶ֖ם כְּאַרְיֵ֥ה מַשְׁחִֽית׃"}},"definableWords":["sons","lion"],"peopleInVerse":[]},"31":{"text":"O generation, see ye the word of the LORD. Have I been a wilderness unto Israel? a land of darkness? wherefore say my people, We are lords; we will come no more unto thee?","ref":"Jeremiah 2:31","synthesized":"You people of this generation, consider the word of the LORD:  “Have I been a wilderness to Israel or a land of dense darkness? Why do My people say, ‘We are free to roam; we will come to You no more’?","sources":{"KJV":{"text":"O generation, see ye the word of the LORD. Have I been a wilderness unto Israel? a land of darkness? wherefore say my people, We are lords; we will come no more unto thee?"},"BSB":{"text":"You people of this generation, consider the word of the LORD:  “Have I been a wilderness to Israel or a land of dense darkness? Why do My people say, ‘We are free to roam; we will come to You no more’?"},"TANAKH":{"text":"O generation, see ye the word of HaShem: have I been a wilderness unto Israel? or a land of thick darkness? Wherefore say My people: 'We roam at large; we will come no more unto Thee'?"},"HEBREW":{"text":"הַדּ֗וֹר אַתֶּם֙ רְא֣וּ דְבַר־יְהוָ֔ה הֲמִדְבָּ֤ר הָיִ֙יתִי֙ לְיִשְׂרָאֵ֔ל אִ֛ם אֶ֥רֶץ מַאְפֵּ֖לְיָ֑ה מַדּ֜וּעַ אָמְר֤וּ עַמִּי֙ רַ֔דְנוּ לֽוֹא־נָב֥וֹא ע֖וֹד אֵלֶֽיךָ׃"}},"definableWords":["people","word","LORD","Israel","or","land","darkness"],"peopleInVerse":[],"themesInVerse":["land_promise","light_darkness"]},"32":{"text":"Can a maid forget her ornaments, or a bride her attire? yet my people have forgotten me days without number.","ref":"Jeremiah 2:32","synthesized":"Does a maiden forget her jewelry or a bride her wedding sash? Yet My people have forgotten Me for days without number.","sources":{"KJV":{"text":"Can a maid forget her ornaments, or a bride her attire? yet my people have forgotten me days without number."},"BSB":{"text":"Does a maiden forget her jewelry or a bride her wedding sash? Yet My people have forgotten Me for days without number."},"TANAKH":{"text":"Can a maid forget her ornaments, or a bride her attire? Yet My people have forgotten Me days without number."},"HEBREW":{"text":"הֲתִשְׁכַּ֤ח בְּתוּלָה֙ עֶדְיָ֔הּ כַּלָּ֖ה קִשֻּׁרֶ֑יהָ וְעַמִּ֣י שְׁכֵח֔וּנִי יָמִ֖ים אֵ֥ין מִסְפָּֽר׃"}},"definableWords":["or","people","days"],"peopleInVerse":[],"themesInVerse":["marriage_bride"]},"33":{"text":"Why trimmest thou thy way to seek love? therefore hast thou also taught the wicked ones thy ways.","ref":"Jeremiah 2:33","synthesized":"How skillfully you pursue love! Even the most immoral of women could learn from your ways.","sources":{"KJV":{"text":"Why trimmest thou thy way to seek love? therefore hast thou also taught the wicked ones thy ways."},"BSB":{"text":"How skillfully you pursue love! Even the most immoral of women could learn from your ways."},"TANAKH":{"text":"How trimmest thou thy way to seek love! Therefore--even the wicked women hast thou taught thy ways;"},"HEBREW":{"text":"מַה־תֵּיטִ֥בִי דַּרְכֵּ֖ךְ לְבַקֵּ֣שׁ אַהֲבָ֑ה לָכֵן֙ גַּ֣ם אֶת־הָרָע֔וֹת למדתי לִמַּ֖דְתְּ אֶת־דְּרָכָֽיִךְ׃"}},"definableWords":["love","women"],"peopleInVerse":[],"themesInVerse":["love"]},"34":{"text":"Also in thy skirts is found the blood of the souls of the poor innocents: I have not found it by secret search, but upon all these.","ref":"Jeremiah 2:34","synthesized":"Moreover, your skirts are stained with the blood of the innocent poor, though you did not find them breaking in.   But in spite of all these things","sources":{"KJV":{"text":"Also in thy skirts is found the blood of the souls of the poor innocents: I have not found it by secret search, but upon all these."},"BSB":{"text":"Moreover, your skirts are stained with the blood of the innocent poor, though you did not find them breaking in.   But in spite of all these things"},"TANAKH":{"text":"Also in thy skirts is found the blood of the souls of the innocent poor; thou didst not find them breaking in; yet for all these things"},"HEBREW":{"text":"גַּ֤ם בִּכְנָפַ֙יִךְ֙ נִמְצְא֔וּ דַּ֛ם נַפְשׁ֥וֹת אֶבְיוֹנִ֖ים נְקִיִּ֑ים לֹֽא־בַמַּחְתֶּ֥רֶת מְצָאתִ֖ים כִּ֥י עַל־כָּל־אֵֽלֶּה׃"}},"definableWords":["blood"],"peopleInVerse":[],"themesInVerse":["passover","sacrifice"]},"35":{"text":"Yet thou sayest, Because I am innocent, surely his anger shall turn from me. Behold, I will plead with thee, because thou sayest, I have not sinned.","ref":"Jeremiah 2:35","synthesized":"you say, ‘I am innocent. Surely His anger will turn from me.’ Behold, I will judge you, because you say, ‘I have not sinned.’","sources":{"KJV":{"text":"Yet thou sayest, Because I am innocent, surely his anger shall turn from me. Behold, I will plead with thee, because thou sayest, I have not sinned."},"BSB":{"text":"you say, ‘I am innocent. Surely His anger will turn from me.’ Behold, I will judge you, because you say, ‘I have not sinned.’"},"TANAKH":{"text":"Thou saidst: 'I am innocent; surely His anger is turned away from me' --behold, I will enter into judgment with thee, because thou sayest: 'I have not sinned.'"},"HEBREW":{"text":"וַתֹּֽאמְרִי֙ כִּ֣י נִקֵּ֔יתִי אַ֛ךְ שָׁ֥ב אַפּ֖וֹ מִמֶּ֑נִּי הִנְנִי֙ נִשְׁפָּ֣ט אוֹתָ֔ךְ עַל־אָמְרֵ֖ךְ לֹ֥א חָטָֽאתִי׃"}},"definableWords":["anger"],"peopleInVerse":[],"themesInVerse":["judgment"]},"36":{"text":"Why gaddest thou about so much to change thy way? thou also shalt be ashamed of Egypt, as thou wast ashamed of Assyria.","ref":"Jeremiah 2:36","synthesized":"How unstable you are, constantly changing your ways! You will be disappointed by Egypt just as you were by Assyria.","sources":{"KJV":{"text":"Why gaddest thou about so much to change thy way? thou also shalt be ashamed of Egypt, as thou wast ashamed of Assyria."},"BSB":{"text":"How unstable you are, constantly changing your ways! You will be disappointed by Egypt just as you were by Assyria."},"TANAKH":{"text":"How greatly dost thou cheapen thyself to change thy way? Thou shalt be ashamed of Egypt also, as thou wast ashamed of Asshur."},"HEBREW":{"text":"מַה־תֵּזְלִ֥י מְאֹ֖ד לְשַׁנּ֣וֹת אֶת־דַּרְכֵּ֑ךְ גַּ֤ם מִמִּצְרַ֙יִם֙ תֵּב֔וֹשִׁי כַּאֲשֶׁר־בֹּ֖שְׁתְּ מֵאַשּֽׁוּר׃"}},"definableWords":["Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern"]},"37":{"text":"Yea, thou shalt go forth from him, and thine hands upon thine head: for the LORD hath rejected thy confidences, and thou shalt not prosper in them.","ref":"Jeremiah 2:37","synthesized":"Moreover, you will leave that place with your hands on your head, for the LORD has rejected those you trust; you will not prosper by their help.”","sources":{"KJV":{"text":"Yea, thou shalt go forth from him, and thine hands upon thine head: for the LORD hath rejected thy confidences, and thou shalt not prosper in them."},"BSB":{"text":"Moreover, you will leave that place with your hands on your head, for the LORD has rejected those you trust; you will not prosper by their help.”"},"TANAKH":{"text":"From him also shalt thou go forth, with thy hands upon thy head; for HaShem hath rejected them in whom thou didst trust, and thou shalt not prosper in them."},"HEBREW":{"text":"גַּ֣ם מֵאֵ֥ת זֶה֙ תֵּֽצְאִ֔י וְיָדַ֖יִךְ עַל־רֹאשֵׁ֑ךְ כִּֽי־מָאַ֤ס יְהֹוָה֙ בְּמִבְטַחַ֔יִךְ וְלֹ֥א תַצְלִ֖יחִי לָהֶֽם׃"}},"definableWords":["LORD","trust"],"peopleInVerse":[],"themesInVerse":["faith"]}}},"3":{"chapter":"3","title":"BACKSLIDING ISRAEL — RETURN","verses":{"1":{"text":"They say, If a man put away his wife, and she go from him, and become another man’s, shall he return unto her again? shall not that land be greatly polluted? but thou hast played the harlot with many lovers; yet return again to me, saith the LORD.","ref":"Jeremiah 3:1","synthesized":"“If a man divorces his wife and she leaves him to marry another, can he ever return to her? Would not such a land be completely defiled? But you have played the harlot with many lovers— and you would return to Me?” declares the LORD.","sources":{"KJV":{"text":"They say, If a man put away his wife, and she go from him, and become another man’s, shall he return unto her again? shall not that land be greatly polluted? but thou hast played the harlot with many lovers; yet return again to me, saith the LORD."},"BSB":{"text":"“If a man divorces his wife and she leaves him to marry another, can he ever return to her? Would not such a land be completely defiled? But you have played the harlot with many lovers— and you would return to Me?” declares the LORD."},"TANAKH":{"text":"...saying: If a man put away his wife, and she go from him, and become another man's, may he return unto her again? Will not that land be greatly polluted? But thou hast played the harlot with many lovers; and wouldest thou yet return to Me? saith HaShem."},"HEBREW":{"text":"לֵאמֹ֡ר הֵ֣ן יְשַׁלַּ֣ח אִ֣ישׁ אֶת־אִשְׁתּוֹ֩ וְהָלְכָ֨ה מֵאִתּ֜וֹ וְהָיְתָ֣ה לְאִישׁ־אַחֵ֗ר הֲיָשׁ֤וּב אֵלֶ֙יהָ֙ ע֔וֹד הֲל֛וֹא חָנ֥וֹף תֶּחֱנַ֖ף הָאָ֣רֶץ הַהִ֑יא וְאַ֗תְּ זָנִית֙ רֵעִ֣ים רַבִּ֔ים וְשׁ֥וֹב אֵלַ֖י נְאֻם־יְהֹוָֽה׃"}},"definableWords":["man","wife","land","LORD"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise","second_coming"]},"2":{"text":"Lift up thine eyes unto the high places, and see where thou hast not been lien with. In the ways hast thou sat for them, as the Arabian in the wilderness; and thou hast polluted the land with thy whoredoms and with thy wickedness.","ref":"Jeremiah 3:2","synthesized":"“Lift up your eyes to the barren heights and see. Is there any place where you have not been violated? You sat beside the highways waiting for your lovers, like a nomad in the desert. You have defiled the land with your prostitution and wickedness.","sources":{"KJV":{"text":"Lift up thine eyes unto the high places, and see where thou hast not been lien with. In the ways hast thou sat for them, as the Arabian in the wilderness; and thou hast polluted the land with thy whoredoms and with thy wickedness."},"BSB":{"text":"“Lift up your eyes to the barren heights and see. Is there any place where you have not been violated? You sat beside the highways waiting for your lovers, like a nomad in the desert. You have defiled the land with your prostitution and wickedness."},"TANAKH":{"text":"Lift up thine eyes unto the high hills, and see: where hast thou not been lain with? By the ways hast thou sat for them, as an Arabian in the wilderness; and thou hast polluted the land with thy harlotries and with thy wickedness."},"HEBREW":{"text":"שְׂאִֽי־עֵינַ֨יִךְ עַל־שְׁפָיִ֜ם וּרְאִ֗י אֵיפֹה֙ לֹ֣א שגלת שֻׁכַּ֔בְתְּ עַל־דְּרָכִים֙ יָשַׁ֣בְתְּ לָהֶ֔ם כַּעֲרָבִ֖י בַּמִּדְבָּ֑ר וַתַּחֲנִ֣יפִי אֶ֔רֶץ בִּזְנוּתַ֖יִךְ וּבְרָעָתֵֽךְ׃"}},"definableWords":["see","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"3":{"text":"Therefore the showers have been withholden, and there hath been no latter rain; and thou hadst a whore’s forehead, thou refusedst to be ashamed.","ref":"Jeremiah 3:3","synthesized":"Therefore the showers have been withheld, and no spring rains have fallen. Yet you have the brazen look of a prostitute; you refuse to be ashamed.","sources":{"KJV":{"text":"Therefore the showers have been withholden, and there hath been no latter rain; and thou hadst a whore’s forehead, thou refusedst to be ashamed."},"BSB":{"text":"Therefore the showers have been withheld, and no spring rains have fallen. Yet you have the brazen look of a prostitute; you refuse to be ashamed."},"TANAKH":{"text":"Therefore the showers have been withheld, and there hath been no latter rain; yet thou hadst a harlot's forehead, thou refusedst to be ashamed."},"HEBREW":{"text":"וַיִּמָּנְע֣וּ רְבִבִ֔ים וּמַלְק֖וֹשׁ ל֣וֹא הָיָ֑ה וּמֵ֨צַח אִשָּׁ֤ה זוֹנָה֙ הָ֣יָה לָ֔ךְ מֵאַ֖נְתְּ הִכָּלֵֽם׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"4":{"text":"Wilt thou not from this time cry unto me, My father, thou art the guide of my youth?","ref":"Jeremiah 3:4","synthesized":"Have you not just called to Me, ‘My Father, You are my friend from youth.","sources":{"KJV":{"text":"Wilt thou not from this time cry unto me, My father, thou art the guide of my youth?"},"BSB":{"text":"Have you not just called to Me, ‘My Father, You are my friend from youth."},"TANAKH":{"text":"Didst thou not just now cry unto Me: 'My father, Thou art the friend of my youth."},"HEBREW":{"text":"הֲל֣וֹא מֵעַ֔תָּה קראתי קָרָ֥את לִ֖י אָבִ֑י אַלּ֥וּף נְעֻרַ֖י אָֽתָּה׃"}},"definableWords":["Father"],"peopleInVerse":[]},"5":{"text":"Will he reserve his anger for ever? will he keep it to the end? Behold, thou hast spoken and done evil things as thou couldest.","ref":"Jeremiah 3:5","synthesized":"Will He be angry forever? Will He be indignant to the end?’ This you have spoken, but you keep doing all the evil you can.”","sources":{"KJV":{"text":"Will he reserve his anger for ever? will he keep it to the end? Behold, thou hast spoken and done evil things as thou couldest."},"BSB":{"text":"Will He be angry forever? Will He be indignant to the end?’ This you have spoken, but you keep doing all the evil you can.”"},"TANAKH":{"text":"Will He bear grudge for ever? Will He keep it to the end?' Behold, thou hast spoken, but hast done evil things, and hast had thy way."},"HEBREW":{"text":"הֲיִנְטֹ֣ר לְעוֹלָ֔ם אִם־יִשְׁמֹ֖ר לָנֶ֑צַח הִנֵּ֥ה דברתי דִבַּ֛רְתְּ וַתַּעֲשִׂ֥י הָרָע֖וֹת וַתּוּכָֽל׃"}},"definableWords":["keep","evil"],"peopleInVerse":[]},"6":{"text":"The LORD said also unto me in the days of Josiah the king, Hast thou seen that which backsliding Israel hath done? she is gone up upon every high mountain and under every green tree, and there hath played the harlot.","ref":"Jeremiah 3:6","synthesized":"Now in the days of King Josiah, the LORD said to me, “Have you seen what faithless Israel has done? She has gone up on every high hill and under every green tree to prostitute herself there.","sources":{"KJV":{"text":"The LORD said also unto me in the days of Josiah the king, Hast thou seen that which backsliding Israel hath done? she is gone up upon every high mountain and under every green tree, and there hath played the harlot."},"BSB":{"text":"Now in the days of King Josiah, the LORD said to me, “Have you seen what faithless Israel has done? She has gone up on every high hill and under every green tree to prostitute herself there."},"TANAKH":{"text":"And HaShem said unto me in the days of Josiah the king: 'Hast thou seen that which backsliding Israel did? she went up upon every high mountain and under every leafy tree, and there played the harlot."},"HEBREW":{"text":"וַיֹּ֨אמֶר יְהוָ֜ה אֵלַ֗י בִּימֵי֙ יֹאשִׁיָּ֣הוּ הַמֶּ֔לֶךְ הֲ‍ֽרָאִ֔יתָ אֲשֶׁ֥ר עָשְׂתָ֖ה מְשֻׁבָ֣ה יִשְׂרָאֵ֑ל הֹלְכָ֨ה הִ֜יא עַל־כָּל־הַ֣ר גָּבֹ֗הַּ וְאֶל־תַּ֛חַת כָּל־עֵ֥ץ רַעֲנָ֖ן וַתִּזְנִי־שָֽׁם׃"}},"definableWords":["days","King","LORD","Israel","tree"],"peopleInVerse":[],"themesInVerse":["kingship"]},"7":{"text":"And I said after she had done all these things, Turn thou unto me. But she returned not. And her treacherous sister Judah saw it.","ref":"Jeremiah 3:7","synthesized":"I thought that after she had done all these things, she would return to Me. But she did not return, and her unfaithful sister Judah saw it.","sources":{"KJV":{"text":"And I said after she had done all these things, Turn thou unto me. But she returned not. And her treacherous sister Judah saw it."},"BSB":{"text":"I thought that after she had done all these things, she would return to Me. But she did not return, and her unfaithful sister Judah saw it."},"TANAKH":{"text":"And I said: After she hath done all these things, she will return unto me; but she returned not. And her treacherous sister Judah saw it."},"HEBREW":{"text":"וָאֹמַ֗ר אַחֲרֵ֨י עֲשׂוֹתָ֧הּ אֶת־כָּל־אֵ֛לֶּה אֵלַ֥י תָּשׁ֖וּב וְלֹא־שָׁ֑בָה ותראה וַתֵּ֛רֶא בָּגוֹדָ֥ה אֲחוֹתָ֖הּ יְהוּדָֽה׃"}},"definableWords":["sister","Judah","saw"],"peopleInVerse":[],"themesInVerse":["exile_return","second_coming"]},"8":{"text":"And I saw, when for all the causes whereby backsliding Israel committed adultery I had put her away, and given her a bill of divorce; yet her treacherous sister Judah feared not, but went and played the harlot also.","ref":"Jeremiah 3:8","synthesized":"She saw that because faithless Israel had committed adultery, I gave her a certificate of divorce and sent her away. Yet that unfaithful sister Judah had no fear and prostituted herself as well.","sources":{"KJV":{"text":"And I saw, when for all the causes whereby backsliding Israel committed adultery I had put her away, and given her a bill of divorce; yet her treacherous sister Judah feared not, but went and played the harlot also."},"BSB":{"text":"She saw that because faithless Israel had committed adultery, I gave her a certificate of divorce and sent her away. Yet that unfaithful sister Judah had no fear and prostituted herself as well."},"TANAKH":{"text":"And I saw, when, forasmuch as backsliding Israel had committed adultery, I had put her away and given her a bill of divorcement, that yet treacherous Judah her sister feared not; but she also went and played the harlot;"},"HEBREW":{"text":"וָאֵ֗רֶא כִּ֤י עַל־כָּל־אֹדוֹת֙ אֲשֶׁ֤ר נִֽאֲפָה֙ מְשֻׁבָ֣ה יִשְׂרָאֵ֔ל שִׁלַּחְתִּ֕יהָ וָאֶתֵּ֛ן אֶת־סֵ֥פֶר כְּרִיתֻתֶ֖יהָ אֵלֶ֑יהָ וְלֹ֨א יָֽרְאָ֜ה בֹּֽגֵדָ֤ה יְהוּדָה֙ אֲחוֹתָ֔הּ וַתֵּ֖לֶךְ וַתִּ֥זֶן גַּם־הִֽיא׃"}},"definableWords":["saw","Israel","sister","Judah","fear"],"peopleInVerse":[],"themesInVerse":["bread_water_life","fear_of_lord"]},"9":{"text":"And it came to pass through the lightness of her whoredom, that she defiled the land, and committed adultery with stones and with stocks.","ref":"Jeremiah 3:9","synthesized":"Indifferent to her own infidelity, Israel had defiled the land and committed adultery with stones and trees.","sources":{"KJV":{"text":"And it came to pass through the lightness of her whoredom, that she defiled the land, and committed adultery with stones and with stocks."},"BSB":{"text":"Indifferent to her own infidelity, Israel had defiled the land and committed adultery with stones and trees."},"TANAKH":{"text":"and it came to pass through the lightness of her harlotry, that the land was polluted, and she committed adultery with stones and with stocks;"},"HEBREW":{"text":"וְהָיָה֙ מִקֹּ֣ל זְנוּתָ֔הּ וַתֶּחֱנַ֖ף אֶת־הָאָ֑רֶץ וַתִּנְאַ֥ף אֶת־הָאֶ֖בֶן וְאֶת־הָעֵֽץ׃"}},"definableWords":["Israel","land","trees"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"10":{"text":"And yet for all this her treacherous sister Judah hath not turned unto me with her whole heart, but feignedly, saith the LORD.","ref":"Jeremiah 3:10","synthesized":"Yet in spite of all this, her unfaithful sister Judah did not return to Me with all her heart, but only in pretense,” declares the LORD.","sources":{"KJV":{"text":"And yet for all this her treacherous sister Judah hath not turned unto me with her whole heart, but feignedly, saith the LORD."},"BSB":{"text":"Yet in spite of all this, her unfaithful sister Judah did not return to Me with all her heart, but only in pretense,” declares the LORD."},"TANAKH":{"text":"and yet for all this her treacherous sister Judah hath not returned unto Me with her whole heart, but feignedly, saith HaShem--"},"HEBREW":{"text":"וְגַם־בְּכָל־זֹ֗את לֹא־שָׁ֨בָה אֵלַ֜י בָּגוֹדָ֧ה אֲחוֹתָ֛הּ יְהוּדָ֖ה בְּכָל־לִבָּ֑הּ כִּ֥י אִם־בְּשֶׁ֖קֶר נְאֻם־יְהוָֽה׃"}},"definableWords":["sister","Judah","heart","LORD"],"peopleInVerse":[],"themesInVerse":["exile_return","second_coming"]},"11":{"text":"And the LORD said unto me, The backsliding Israel hath justified herself more than treacherous Judah.","ref":"Jeremiah 3:11","synthesized":"And the LORD said to me, “Faithless Israel has shown herself more righteous than unfaithful Judah.","sources":{"KJV":{"text":"And the LORD said unto me, The backsliding Israel hath justified herself more than treacherous Judah."},"BSB":{"text":"And the LORD said to me, “Faithless Israel has shown herself more righteous than unfaithful Judah."},"TANAKH":{"text":"even HaShem said unto me--backsliding Israel hath proved herself more righteous than treacherous Judah."},"HEBREW":{"text":"וַיֹּ֤אמֶר יְהוָה֙ אֵלַ֔י צִדְּקָ֥ה נַפְשָׁ֖הּ מְשֻׁבָ֣ה יִשְׂרָאֵ֑ל מִבֹּגֵדָ֖ה יְהוּדָֽה׃"}},"definableWords":["LORD","Israel","righteous","Judah"],"peopleInVerse":[]},"12":{"text":"Go and proclaim these words toward the north, and say, Return, thou backsliding Israel, saith the LORD; and I will not cause mine anger to fall upon you: for I am merciful, saith the LORD, and I will not keep anger for ever.","ref":"Jeremiah 3:12","synthesized":"Go, proclaim this message toward the north:  ‘Return, O faithless Israel,’ declares the LORD. ‘I will no longer look on you with anger, for I am merciful,’ declares the LORD. ‘I will not be angry forever.","sources":{"KJV":{"text":"Go and proclaim these words toward the north, and say, Return, thou backsliding Israel, saith the LORD; and I will not cause mine anger to fall upon you: for I am merciful, saith the LORD, and I will not keep anger for ever."},"BSB":{"text":"Go, proclaim this message toward the north:  ‘Return, O faithless Israel,’ declares the LORD. ‘I will no longer look on you with anger, for I am merciful,’ declares the LORD. ‘I will not be angry forever."},"TANAKH":{"text":"Go, and proclaim these words toward the north, and say: return, thou backsliding Israel, saith HaShem; I will not frown upon you; for I am merciful, saith HaShem, I will not bear grudge for ever."},"HEBREW":{"text":"הָלֹ֡ךְ וְקֽ͏ָרָאתָ֩ אֶת־הַדְּבָרִ֨ים הָאֵ֜לֶּה צָפ֗וֹנָה וְ֠אָמַרְתָּ שׁ֣וּבָה מְשֻׁבָ֤ה יִשְׂרָאֵל֙ נְאֻם־יְהוָ֔ה לֽוֹא־אַפִּ֥יל פָּנַ֖י בָּכֶ֑ם כִּֽי־חָסִ֤יד אֲנִי֙ נְאֻם־יְהוָ֔ה לֹ֥א אֶטּ֖וֹר לְעוֹלָֽם׃"}},"definableWords":["Israel","LORD","anger","Lord"],"peopleInVerse":[],"themesInVerse":["exile_return","second_coming"]},"13":{"text":"Only acknowledge thine iniquity, that thou hast transgressed against the LORD thy God, and hast scattered thy ways to the strangers under every green tree, and ye have not obeyed my voice, saith the LORD.","ref":"Jeremiah 3:13","synthesized":"Only acknowledge your guilt, that you have rebelled against the LORD your God. You have scattered your favors to foreign gods under every green tree and have not obeyed My voice,’” declares the LORD.","sources":{"KJV":{"text":"Only acknowledge thine iniquity, that thou hast transgressed against the LORD thy God, and hast scattered thy ways to the strangers under every green tree, and ye have not obeyed my voice, saith the LORD."},"BSB":{"text":"Only acknowledge your guilt, that you have rebelled against the LORD your God. You have scattered your favors to foreign gods under every green tree and have not obeyed My voice,’” declares the LORD."},"TANAKH":{"text":"Only acknowledge thine iniquity, that thou hast transgressed against HaShem thy G-d, and hast scattered thy ways to the strangers under every leafy tree, and ye have not hearkened to My voice, saith HaShem."},"HEBREW":{"text":"אַ֚ךְ דְּעִ֣י עֲוֺנֵ֔ךְ כִּ֛י בַּיהוָ֥ה אֱלֹהַ֖יִךְ פָּשָׁ֑עַתְּ וַתְּפַזְּרִ֨י אֶת־דְּרָכַ֜יִךְ לַזָּרִ֗ים תַּ֚חַת כָּל־עֵ֣ץ רַעֲנָ֔ן וּבְקוֹלִ֥י לֹא־שְׁמַעְתֶּ֖ם נְאֻם־יְהֹוָֽה׃"}},"definableWords":["LORD","God","tree","voice","Lord"],"peopleInVerse":[]},"14":{"text":"Turn, O backsliding children, saith the LORD; for I am married unto you: and I will take you one of a city, and two of a family, and I will bring you to Zion:","ref":"Jeremiah 3:14","synthesized":"“Return, O faithless children,” declares the LORD, “for I am your master, and I will take you—one from a city and two from a family—and bring you to Zion.","sources":{"KJV":{"text":"Turn, O backsliding children, saith the LORD; for I am married unto you: and I will take you one of a city, and two of a family, and I will bring you to Zion:"},"BSB":{"text":"“Return, O faithless children,” declares the LORD, “for I am your master, and I will take you—one from a city and two from a family—and bring you to Zion."},"TANAKH":{"text":"Return, O backsliding children, saith HaShem; for I am a lord unto you, and I will take you one of a city, and two of a family, and I will bring you to Zion;"},"HEBREW":{"text":"שׁ֣וּבוּ בָנִ֤ים שׁוֹבָבִים֙ נְאֻם־יְהוָ֔ה כִּ֥י אָנֹכִ֖י בָּעַ֣לְתִּי בָכֶ֑ם וְלָקַחְתִּ֨י אֶתְכֶ֜ם אֶחָ֣ד מֵעִ֗יר וּשְׁנַ֙יִם֙ מִמִּשְׁפָּחָ֔ה וְהֵבֵאתִ֥י אֶתְכֶ֖ם צִיּֽוֹן׃"}},"definableWords":["LORD","one","family","Zion"],"peopleInVerse":[],"placesInVerse":["Mount Zion"],"themesInVerse":["exile_return","second_coming"]},"15":{"text":"And I will give you pastors according to mine heart, which shall feed you with knowledge and understanding.","ref":"Jeremiah 3:15","synthesized":"Then I will give you shepherds after My own heart, who will feed you with knowledge and understanding.”","sources":{"KJV":{"text":"And I will give you pastors according to mine heart, which shall feed you with knowledge and understanding."},"BSB":{"text":"Then I will give you shepherds after My own heart, who will feed you with knowledge and understanding.”"},"TANAKH":{"text":"and I will give you shepherds according to My heart, who shall feed you with knowledge and understanding."},"HEBREW":{"text":"וְנָתַתִּ֥י לָכֶ֛ם רֹעִ֖ים כְּלִבִּ֑י וְרָע֥וּ אֶתְכֶ֖ם דֵּעָ֥ה וְהַשְׂכֵּֽיל׃"}},"definableWords":["heart","knowledge"],"peopleInVerse":[],"themesInVerse":["wisdom"]},"16":{"text":"And it shall come to pass, when ye be multiplied and increased in the land, in those days, saith the LORD, they shall say no more, The ark of the covenant of the LORD: neither shall it come to mind: neither shall they remember it; neither shall they visit it; neither shall that be done any more.","ref":"Jeremiah 3:16","synthesized":"“In those days, when you multiply and increase in the land,” declares the LORD, “they will no longer discuss the ark of the covenant of the LORD. It will never come to mind, and no one will remember it or miss it, nor will another one be made.","sources":{"KJV":{"text":"And it shall come to pass, when ye be multiplied and increased in the land, in those days, saith the LORD, they shall say no more, The ark of the covenant of the LORD: neither shall it come to mind: neither shall they remember it; neither shall they visit it; neither shall that be done any more."},"BSB":{"text":"“In those days, when you multiply and increase in the land,” declares the LORD, “they will no longer discuss the ark of the covenant of the LORD. It will never come to mind, and no one will remember it or miss it, nor will another one be made."},"TANAKH":{"text":"And it shall come to pass, when ye are multiplied and increased in the land, in those days, saith HaShem, they shall say no more: The ark of the covenant of HaShem; neither shall it come to mind; neither shall they make mention of it; neither shall they miss it; neither shall it be made any more."},"HEBREW":{"text":"וְהָיָ֡ה כִּ֣י תִרְבּוּ֩ וּפְרִיתֶ֨ם בָּאָ֜רֶץ בַּיָּמִ֤ים הָהֵ֙מָּה֙ נְאֻם־יְהוָ֔ה לֹא־יֹ֣אמְרוּ ע֗וֹד אֲרוֹן֙ בְּרִית־יְהוָ֔ה וְלֹ֥א יַעֲלֶ֖ה עַל־לֵ֑ב וְלֹ֤א יִזְכְּרוּ־בוֹ֙ וְלֹ֣א יִפְקֹ֔דוּ וְלֹ֥א יֵעָשֶׂ֖ה עֽוֹד׃"}},"definableWords":["days","multiply","land","LORD","ark","covenant","Lord","mind","one","remember","or","made"],"peopleInVerse":[],"themesInVerse":["covenant","creation","land_promise"]},"17":{"text":"At that time they shall call Jerusalem the throne of the LORD; and all the nations shall be gathered unto it, to the name of the LORD, to Jerusalem: neither shall they walk any more after the imagination of their evil heart.","ref":"Jeremiah 3:17","synthesized":"At that time Jerusalem will be called The Throne of the LORD, and all the nations will be gathered in Jerusalem to honor the name of the LORD. They will no longer follow the stubbornness of their evil hearts.","sources":{"KJV":{"text":"At that time they shall call Jerusalem the throne of the LORD; and all the nations shall be gathered unto it, to the name of the LORD, to Jerusalem: neither shall they walk any more after the imagination of their evil heart."},"BSB":{"text":"At that time Jerusalem will be called The Throne of the LORD, and all the nations will be gathered in Jerusalem to honor the name of the LORD. They will no longer follow the stubbornness of their evil hearts."},"TANAKH":{"text":"At that time they shall call Jerusalem The throne of HaShem; and all the nations shall be gathered unto it, to the name of HaShem, to Jerusalem; neither shall they walk any more after the stubbornness of their evil heart."},"HEBREW":{"text":"בָּעֵ֣ת הַהִ֗יא יִקְרְא֤וּ לִירוּשָׁלִַ֙ם֙ כִּסֵּ֣א יְהוָ֔ה וְנִקְוּ֨וּ אֵלֶ֧יהָ כָֽל־הַגּוֹיִ֛ם לְשֵׁ֥ם יְהוָ֖ה לִירוּשָׁלָ֑͏ִם וְלֹא־יֵלְכ֣וּ ע֔וֹד אַחֲרֵ֕י שְׁרִר֖וּת לִבָּ֥ם הָרָֽע׃"}},"definableWords":["Jerusalem","throne","LORD","nations","name","Lord","evil"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["kingdom_of_god","kingship","worship"]},"18":{"text":"In those days the house of Judah shall walk with the house of Israel, and they shall come together out of the land of the north to the land that I have given for an inheritance unto your fathers.","ref":"Jeremiah 3:18","synthesized":"In those days the house of Judah will walk with the house of Israel, and they will come together from the land of the north to the land that I gave to your fathers as an inheritance.","sources":{"KJV":{"text":"In those days the house of Judah shall walk with the house of Israel, and they shall come together out of the land of the north to the land that I have given for an inheritance unto your fathers."},"BSB":{"text":"In those days the house of Judah will walk with the house of Israel, and they will come together from the land of the north to the land that I gave to your fathers as an inheritance."},"TANAKH":{"text":"In those days the house of Judah shall walk with the house of Israel, and they shall come together out of the land of the north to the land that I have given for an inheritance unto your fathers.'"},"HEBREW":{"text":"בַּיָּמִ֣ים הָהֵ֔מָּה יֵלְכ֥וּ בֵית־יְהוּדָ֖ה עַל־בֵּ֣ית יִשְׂרָאֵ֑ל וְיָבֹ֤אוּ יַחְדָּו֙ מֵאֶ֣רֶץ צָפ֔וֹן עַל־הָאָ֕רֶץ אֲשֶׁ֥ר הִנְחַ֖לְתִּי אֶת־אֲבוֹתֵיכֶֽם׃"}},"definableWords":["days","house","Judah","walk","Israel","land","fathers"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"19":{"text":"But I said, How shall I put thee among the children, and give thee a pleasant land, a goodly heritage of the hosts of nations? and I said, Thou shalt call me, My father; and shalt not turn away from me.","ref":"Jeremiah 3:19","synthesized":"Then I said, ‘How I long to make you My sons and give you a desirable land, the most beautiful inheritance of all the nations!’ I thought you would call Me ‘Father’ and never turn away from following Me.","sources":{"KJV":{"text":"But I said, How shall I put thee among the children, and give thee a pleasant land, a goodly heritage of the hosts of nations? and I said, Thou shalt call me, My father; and shalt not turn away from me."},"BSB":{"text":"Then I said, ‘How I long to make you My sons and give you a desirable land, the most beautiful inheritance of all the nations!’ I thought you would call Me ‘Father’ and never turn away from following Me."},"TANAKH":{"text":"But I said: 'How would I put thee among the sons, and give thee a pleasant land, the goodliest heritage of the nations!' And I said: 'Thou shalt call Me, My father; and shalt not turn away from following Me.'"},"HEBREW":{"text":"וְאָנֹכִ֣י אָמַ֗רְתִּי אֵ֚יךְ אֲשִׁיתֵ֣ךְ בַּבָּנִ֔ים וְאֶתֶּן־לָךְ֙ אֶ֣רֶץ חֶמְדָּ֔ה נַחֲלַ֥ת צְבִ֖י צִבְא֣וֹת גּוֹיִ֑ם וָאֹמַ֗ר אָבִי֙ תקראו־תִּקְרְאִי־לִ֔י וּמֵאַחֲרַ֖י לֹ֥א תשובו תָשֽׁוּבִי׃"}},"definableWords":["make","sons","land","nations","Father"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"20":{"text":"Surely as a wife treacherously departeth from her husband, so have ye dealt treacherously with me, O house of Israel, saith the LORD.","ref":"Jeremiah 3:20","synthesized":"But as a woman may betray her husband, so you have betrayed Me, O house of Israel,” declares the LORD.","sources":{"KJV":{"text":"Surely as a wife treacherously departeth from her husband, so have ye dealt treacherously with me, O house of Israel, saith the LORD."},"BSB":{"text":"But as a woman may betray her husband, so you have betrayed Me, O house of Israel,” declares the LORD."},"TANAKH":{"text":"Surely as a wife treacherously departeth from her husband, so have ye dealt treacherously with Me, O house of Israel, saith HaShem."},"HEBREW":{"text":"אָכֵ֛ן בָּגְדָ֥ה אִשָּׁ֖ה מֵרֵעָ֑הּ כֵּ֣ן בְּגַדְתֶּ֥ם בִּ֛י בֵּ֥ית יִשְׂרָאֵ֖ל נְאֻם־יְהוָֽה׃"}},"definableWords":["woman","husband","house","Israel","LORD"],"peopleInVerse":[],"themesInVerse":["marriage_bride"]},"21":{"text":"A voice was heard upon the high places, weeping and supplications of the children of Israel: for they have perverted their way, and they have forgotten the LORD their God.","ref":"Jeremiah 3:21","synthesized":"A voice is heard on the barren heights, the children of Israel weeping and begging for mercy, because they have perverted their ways and forgotten the LORD their God.","sources":{"KJV":{"text":"A voice was heard upon the high places, weeping and supplications of the children of Israel: for they have perverted their way, and they have forgotten the LORD their God."},"BSB":{"text":"A voice is heard on the barren heights, the children of Israel weeping and begging for mercy, because they have perverted their ways and forgotten the LORD their God."},"TANAKH":{"text":"Hark! upon the high hills is heard the suppliant weeping of the children of Israel; for that they have perverted their way, they have forgotten HaShem their G-d."},"HEBREW":{"text":"ק֚וֹל עַל־שְׁפָיִ֣ים נִשְׁמָ֔ע בְּכִ֥י תַחֲנוּנֵ֖י בְּנֵ֣י יִשְׂרָאֵ֑ל כִּ֤י הֶעֱוּוּ֙ אֶת־דַּרְכָּ֔ם שָׁכְח֖וּ אֶת־יְהֹוָ֥ה אֱלֹהֵיהֶֽם׃"}},"definableWords":["voice","Israel","mercy","LORD","God"],"peopleInVerse":[],"themesInVerse":["grace"]},"22":{"text":"Return, ye backsliding children, and I will heal your backslidings. Behold, we come unto thee; for thou art the LORD our God.","ref":"Jeremiah 3:22","synthesized":"“Return, O faithless children, and I will heal your faithlessness.”   “Here we are. We come to You, for You are the LORD our God.","sources":{"KJV":{"text":"Return, ye backsliding children, and I will heal your backslidings. Behold, we come unto thee; for thou art the LORD our God."},"BSB":{"text":"“Return, O faithless children, and I will heal your faithlessness.”   “Here we are. We come to You, for You are the LORD our God."},"TANAKH":{"text":"Return, ye backsliding children, I will heal your backslidings.-- 'Here we are, we are come unto Thee; for Thou art HaShem our G-d."},"HEBREW":{"text":"שׁ֚וּבוּ בָּנִ֣ים שׁוֹבָבִ֔ים אֶרְפָּ֖ה מְשׁוּבֹֽתֵיכֶ֑ם הִנְנוּ֙ אָתָ֣נוּ לָ֔ךְ כִּ֥י אַתָּ֖ה יְהֹוָ֥ה אֱלֹהֵֽינוּ׃"}},"definableWords":["heal","LORD","God"],"peopleInVerse":[],"themesInVerse":["exile_return","second_coming"]},"23":{"text":"Truly in vain is salvation hoped for from the hills, and from the multitude of mountains: truly in the LORD our God is the salvation of Israel.","ref":"Jeremiah 3:23","synthesized":"Surely deception comes from the hills, and commotion from the mountains. Surely the salvation of Israel is in the LORD our God.","sources":{"KJV":{"text":"Truly in vain is salvation hoped for from the hills, and from the multitude of mountains: truly in the LORD our God is the salvation of Israel."},"BSB":{"text":"Surely deception comes from the hills, and commotion from the mountains. Surely the salvation of Israel is in the LORD our God."},"TANAKH":{"text":"Truly vain have proved the hills, the uproar on the mountains; truly in HaShem our G-d is the salvation of Israel."},"HEBREW":{"text":"אָכֵ֥ן לַשֶּׁ֛קֶר מִגְּבָע֖וֹת הָמ֣וֹן הָרִ֑ים אָכֵן֙ בַּיהֹוָ֣ה אֱלֹהֵ֔ינוּ תְּשׁוּעַ֖ת יִשְׂרָאֵֽל׃"}},"definableWords":["salvation","Israel","LORD","God"],"peopleInVerse":[],"themesInVerse":["salvation"]},"24":{"text":"For shame hath devoured the labour of our fathers from our youth; their flocks and their herds, their sons and their daughters.","ref":"Jeremiah 3:24","synthesized":"From our youth, that shameful god has consumed what our fathers have worked for— their flocks and herds, their sons and daughters.","sources":{"KJV":{"text":"For shame hath devoured the labour of our fathers from our youth; their flocks and their herds, their sons and their daughters."},"BSB":{"text":"From our youth, that shameful god has consumed what our fathers have worked for— their flocks and herds, their sons and daughters."},"TANAKH":{"text":"But the shameful thing hath devoured the labour of our fathers from our youth; their flocks and their herds, their sons and their daughters."},"HEBREW":{"text":"וְהַבֹּ֗שֶׁת אָֽכְלָ֛ה אֶת־יְגִ֥יעַ אֲבוֹתֵ֖ינוּ מִנְּעוּרֵ֑ינוּ אֶת־צֹאנָם֙ וְאֶת־בְּקָרָ֔ם אֶת־בְּנֵיהֶ֖ם וְאֶת־בְּנוֹתֵיהֶֽם׃"}},"definableWords":["God","fathers","sons","daughters"],"peopleInVerse":[]},"25":{"text":"We lie down in our shame, and our confusion covereth us: for we have sinned against the LORD our God, we and our fathers, from our youth even unto this day, and have not obeyed the voice of the LORD our God.","ref":"Jeremiah 3:25","synthesized":"Let us lie down in our shame; let our disgrace cover us. We have sinned against the LORD our God, both we and our fathers; from our youth even to this day we have not obeyed the voice of the LORD our God.”","sources":{"KJV":{"text":"We lie down in our shame, and our confusion covereth us: for we have sinned against the LORD our God, we and our fathers, from our youth even unto this day, and have not obeyed the voice of the LORD our God."},"BSB":{"text":"Let us lie down in our shame; let our disgrace cover us. We have sinned against the LORD our God, both we and our fathers; from our youth even to this day we have not obeyed the voice of the LORD our God.”"},"TANAKH":{"text":"Let us lie down in our shame, and let our confusion cover us; for we have sinned against HaShem our G-d, we and our fathers, from our youth even unto this day; and we have not hearkened to the voice of HaShem our G-d.'"},"HEBREW":{"text":"נִשְׁכְּבָ֣ה בְּבָשְׁתֵּ֗נוּ וּֽתְכַסֵּנוּ֮ כְּלִמָּתֵנוּ֒ כִּי֩ לַיהוָ֨ה אֱלֹהֵ֜ינוּ חָטָ֗אנוּ אֲנַ֙חְנוּ֙ וַאֲבוֹתֵ֔ינוּ מִנְּעוּרֵ֖ינוּ וְעַד־הַיּ֣וֹם הַזֶּ֑ה וְלֹ֣א שָׁמַ֔עְנוּ בְּק֖וֹל יְהֹוָ֥ה אֱלֹהֵֽינוּ׃"}},"definableWords":["LORD","God","fathers","day","voice","Lord"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"TURN UNTO ME","verses":{"1":{"text":"If thou wilt return, O Israel, saith the LORD, return unto me: and if thou wilt put away thine abominations out of my sight, then shalt thou not remove.","ref":"Jeremiah 4:1","synthesized":"“If you will return, O Israel, return to Me,” declares the LORD. “If you will remove your detestable idols from My sight and no longer waver,","sources":{"KJV":{"text":"If thou wilt return, O Israel, saith the LORD, return unto me: and if thou wilt put away thine abominations out of my sight, then shalt thou not remove."},"BSB":{"text":"“If you will return, O Israel, return to Me,” declares the LORD. “If you will remove your detestable idols from My sight and no longer waver,"},"TANAKH":{"text":"If thou wilt return, O Israel, saith HaShem, yea, return unto Me; and if thou wilt put away thy detestable things out of My sight, and wilt not waver;"},"HEBREW":{"text":"אִם־תָּשׁ֨וּב יִשְׂרָאֵ֧ל ׀ נְאֻם־יְהוָ֛ה אֵלַ֖י תָּשׁ֑וּב וְאִם־תָּסִ֧יר שִׁקּוּצֶ֛יךָ מִפָּנַ֖י וְלֹ֥א תָנֽוּד׃"}},"definableWords":["Israel","LORD"],"peopleInVerse":[],"themesInVerse":["exile_return","second_coming"]},"2":{"text":"And thou shalt swear, The LORD liveth, in truth, in judgment, and in righteousness; and the nations shall bless themselves in him, and in him shall they glory.","ref":"Jeremiah 4:2","synthesized":"and if you can swear, ‘As surely as the LORD lives,’ in truth, in justice, and in righteousness, then the nations will be blessed by Him, and in Him they will glory.”","sources":{"KJV":{"text":"And thou shalt swear, The LORD liveth, in truth, in judgment, and in righteousness; and the nations shall bless themselves in him, and in him shall they glory."},"BSB":{"text":"and if you can swear, ‘As surely as the LORD lives,’ in truth, in justice, and in righteousness, then the nations will be blessed by Him, and in Him they will glory.”"},"TANAKH":{"text":"And wilt swear: 'As HaShem liveth' in truth, in justice, and in righteousness; then shall the nations bless themselves by Him, and in Him shall they glory."},"HEBREW":{"text":"וְנִשְׁבַּ֙עְתָּ֙ חַי־יְהוָ֔ה בֶּאֱמֶ֖ת בְּמִשְׁפָּ֣ט וּבִצְדָקָ֑ה וְהִתְבָּ֥רְכוּ ב֛וֹ גּוֹיִ֖ם וּב֥וֹ יִתְהַלָּֽלוּ׃"}},"definableWords":["LORD","truth","justice","righteousness","nations","blessed","glory"],"peopleInVerse":[],"themesInVerse":["covenant","worship"]},"3":{"text":"For thus saith the LORD to the men of Judah and Jerusalem, Break up your fallow ground, and sow not among thorns.","ref":"Jeremiah 4:3","synthesized":"For this is what the LORD says to the men of Judah and Jerusalem:  “Break up your unplowed ground, and do not sow among the thorns.","sources":{"KJV":{"text":"For thus saith the LORD to the men of Judah and Jerusalem, Break up your fallow ground, and sow not among thorns."},"BSB":{"text":"For this is what the LORD says to the men of Judah and Jerusalem:  “Break up your unplowed ground, and do not sow among the thorns."},"TANAKH":{"text":"For thus saith HaShem to the men of Judah and to Jerusalem: break up for you a fallow ground, and sow not among thorns."},"HEBREW":{"text":"כִּי־כֹ֣ה ׀ אָמַ֣ר יְהֹוָ֗ה לְאִ֤ישׁ יְהוּדָה֙ וְלִיר֣וּשָׁלִַ֔ם נִ֥ירוּ לָכֶ֖ם נִ֑יר וְאַֽל־תִּזְרְע֖וּ אֶל־קוֹצִֽים׃"}},"definableWords":["LORD","men","Judah","Jerusalem","ground"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"4":{"text":"Circumcise yourselves to the LORD, and take away the foreskins of your heart, ye men of Judah and inhabitants of Jerusalem: lest my fury come forth like fire, and burn that none can quench it, because of the evil of your doings.","ref":"Jeremiah 4:4","synthesized":"Circumcise yourselves to the LORD, and remove the foreskins of your hearts, O men of Judah and people of Jerusalem. Otherwise, My wrath will break out like fire and burn with no one to extinguish it, because of your evil deeds.”","sources":{"KJV":{"text":"Circumcise yourselves to the LORD, and take away the foreskins of your heart, ye men of Judah and inhabitants of Jerusalem: lest my fury come forth like fire, and burn that none can quench it, because of the evil of your doings."},"BSB":{"text":"Circumcise yourselves to the LORD, and remove the foreskins of your hearts, O men of Judah and people of Jerusalem. Otherwise, My wrath will break out like fire and burn with no one to extinguish it, because of your evil deeds.”"},"TANAKH":{"text":"Circumcise yourselves to HaShem, and take away the foreskins of your heart, ye men of Judah and inhabitants of Jerusalem; lest My fury go forth like fire, and burn that none can quench it, because of the evil of your doings."},"HEBREW":{"text":"הִמֹּ֣לוּ לַיהֹוָ֗ה וְהָסִ֙רוּ֙ עָרְל֣וֹת לְבַבְכֶ֔ם אִ֥ישׁ יְהוּדָ֖ה וְיֹשְׁבֵ֣י יְרוּשָׁלָ֑͏ִם פֶּן־תֵּצֵ֨א כָאֵ֜שׁ חֲמָתִ֗י וּבָעֲרָה֙ וְאֵ֣ין מְכַבֶּ֔ה מִפְּנֵ֖י רֹ֥עַ מַעַלְלֵיכֶֽם׃"}},"definableWords":["LORD","men","Judah","people","Jerusalem","wrath","one","evil"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["judgment"]},"5":{"text":"Declare ye in Judah, and publish in Jerusalem; and say, Blow ye the trumpet in the land: cry, gather together, and say, Assemble yourselves, and let us go into the defenced cities.","ref":"Jeremiah 4:5","synthesized":"Announce in Judah, proclaim in Jerusalem, and say:  “Blow the ram’s horn throughout the land. Cry aloud and say, ‘Assemble yourselves and let us flee to the fortified cities.’","sources":{"KJV":{"text":"Declare ye in Judah, and publish in Jerusalem; and say, Blow ye the trumpet in the land: cry, gather together, and say, Assemble yourselves, and let us go into the defenced cities."},"BSB":{"text":"Announce in Judah, proclaim in Jerusalem, and say:  “Blow the ram’s horn throughout the land. Cry aloud and say, ‘Assemble yourselves and let us flee to the fortified cities.’"},"TANAKH":{"text":"Declare ye in Judah, and publish in Jerusalem, and say: 'Blow ye the horn in the land'; cry aloud and say: 'Assemble yourselves, and let us go into the fortified cities.'"},"HEBREW":{"text":"הַגִּ֣ידוּ בִֽיהוּדָ֗ה וּבִירוּשָׁלִַ֙ם֙ הַשְׁמִ֔יעוּ וְאִמְר֕וּ ותקעו תִּקְע֥וּ שׁוֹפָ֖ר בָּאָ֑רֶץ קִרְא֤וּ מַלְאוּ֙ וְאִמְר֔וּ הֵאָסְפ֥וּ וְנָב֖וֹאָה אֶל־עָרֵ֥י הַמִּבְצָֽר׃"}},"definableWords":["Judah","Jerusalem","land"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["land_promise"]},"6":{"text":"Set up the standard toward Zion: retire, stay not: for I will bring evil from the north, and a great destruction.","ref":"Jeremiah 4:6","synthesized":"Raise a signal flag toward Zion. Seek refuge! Do not delay! For I am bringing disaster from the north, and terrible destruction.","sources":{"KJV":{"text":"Set up the standard toward Zion: retire, stay not: for I will bring evil from the north, and a great destruction."},"BSB":{"text":"Raise a signal flag toward Zion. Seek refuge! Do not delay! For I am bringing disaster from the north, and terrible destruction."},"TANAKH":{"text":"Set up a standard toward Zion; put yourselves under covert, stay not; for I will bring evil from the north, and a great destruction."},"HEBREW":{"text":"שְׂאוּ־נֵ֣ס צִיּ֔וֹנָה הָעִ֖יזוּ אַֽל־תַּעֲמֹ֑דוּ כִּ֣י רָעָ֗ה אָנֹכִ֛י מֵבִ֥יא מִצָּפ֖וֹן וְשֶׁ֥בֶר גָּדֽוֹל׃"}},"definableWords":["Zion","seek"],"peopleInVerse":[],"placesInVerse":["Mount Zion"]},"7":{"text":"The lion is come up from his thicket, and the destroyer of the Gentiles is on his way; he is gone forth from his place to make thy land desolate; and thy cities shall be laid waste, without an inhabitant.","ref":"Jeremiah 4:7","synthesized":"A lion has gone up from his thicket, and a destroyer of nations has set out. He has left his lair to lay waste your land. Your cities will be reduced to ruins and lie uninhabited.","sources":{"KJV":{"text":"The lion is come up from his thicket, and the destroyer of the Gentiles is on his way; he is gone forth from his place to make thy land desolate; and thy cities shall be laid waste, without an inhabitant."},"BSB":{"text":"A lion has gone up from his thicket, and a destroyer of nations has set out. He has left his lair to lay waste your land. Your cities will be reduced to ruins and lie uninhabited."},"TANAKH":{"text":"A lion is gone up from his thicket, and a destroyer of nations is set out, gone forth from his place; to make thy land desolate, that thy cities be laid waste, without inhabitant."},"HEBREW":{"text":"עָלָ֤ה אַרְיֵה֙ מִֽסֻּבְּכ֔וֹ וּמַשְׁחִ֣ית גּוֹיִ֔ם נָסַ֖ע יָצָ֣א מִמְּקֹמ֑וֹ לָשׂ֤וּם אַרְצֵךְ֙ לְשַׁמָּ֔ה עָרַ֥יִךְ תִּצֶּ֖ינָה מֵאֵ֥ין יוֹשֵֽׁב׃"}},"definableWords":["lion","nations","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"8":{"text":"For this gird you with sackcloth, lament and howl: for the fierce anger of the LORD is not turned back from us.","ref":"Jeremiah 4:8","synthesized":"So put on sackcloth, mourn and wail, for the fierce anger of the LORD has not turned away from us.”","sources":{"KJV":{"text":"For this gird you with sackcloth, lament and howl: for the fierce anger of the LORD is not turned back from us."},"BSB":{"text":"So put on sackcloth, mourn and wail, for the fierce anger of the LORD has not turned away from us.”"},"TANAKH":{"text":"For this gird you with sackcloth, lament and wail; for the fierce anger of HaShem is not turned back from us."},"HEBREW":{"text":"עַל־זֹ֛את חִגְר֥וּ שַׂקִּ֖ים סִפְד֣וּ וְהֵילִ֑ילוּ כִּ֥י לֹא־שָׁ֛ב חֲר֥וֹן אַף־יְהֹוָ֖ה מִמֶּֽנּוּ׃"}},"definableWords":["anger","LORD"],"peopleInVerse":[]},"9":{"text":"And it shall come to pass at that day, saith the LORD, that the heart of the king shall perish, and the heart of the princes; and the priests shall be astonished, and the prophets shall wonder.","ref":"Jeremiah 4:9","synthesized":"“In that day,” declares the LORD, “the king and officials will lose their courage. The priests will tremble in fear, and the prophets will be astounded.”","sources":{"KJV":{"text":"And it shall come to pass at that day, saith the LORD, that the heart of the king shall perish, and the heart of the princes; and the priests shall be astonished, and the prophets shall wonder."},"BSB":{"text":"“In that day,” declares the LORD, “the king and officials will lose their courage. The priests will tremble in fear, and the prophets will be astounded.”"},"TANAKH":{"text":"And it shall come to pass at that day, saith HaShem, that the heart of the king shall fail, and the heart of the princes; and the priests shall be astonished, and the prophets shall wonder."},"HEBREW":{"text":"וְהָיָ֤ה בַיּוֹם־הַהוּא֙ נְאֻם־יְהוָ֔ה יֹאבַ֥ד לֵב־הַמֶּ֖לֶךְ וְלֵ֣ב הַשָּׂרִ֑ים וְנָשַׁ֙מּוּ֙ הַכֹּ֣הֲנִ֔ים וְהַנְּבִיאִ֖ים יִתְמָֽהוּ׃"}},"definableWords":["day","LORD","king","fear"],"peopleInVerse":[],"themesInVerse":["fear_of_lord","kingship"]},"10":{"text":"Then said I, Ah, Lord GOD! surely thou hast greatly deceived this people and Jerusalem, saying, Ye shall have peace; whereas the sword reacheth unto the soul.","ref":"Jeremiah 4:10","synthesized":"Then I said, “Ah, Lord GOD, how completely You have deceived this people and Jerusalem by saying, ‘You will have peace,’ while a sword is at our throats.”","sources":{"KJV":{"text":"Then said I, Ah, Lord GOD! surely thou hast greatly deceived this people and Jerusalem, saying, Ye shall have peace; whereas the sword reacheth unto the soul."},"BSB":{"text":"Then I said, “Ah, Lord GOD, how completely You have deceived this people and Jerusalem by saying, ‘You will have peace,’ while a sword is at our throats.”"},"TANAKH":{"text":"Then said I: 'Ah, L-rd GOD! surely Thou hast greatly deceived this people and Jerusalem, saying: Ye shall have peace; whereas the sword reacheth unto the soul.'"},"HEBREW":{"text":"וָאֹמַ֞ר אֲהָ֣הּ ׀ אֲדֹנָ֣י יְהוִ֗ה אָכֵן֩ הַשֵּׁ֨א הִשֵּׁ֜אתָ לָעָ֤ם הַזֶּה֙ וְלִירוּשָׁלַ֣͏ִם לֵאמֹ֔ר שָׁל֖וֹם יִהְיֶ֣ה לָכֶ֑ם וְנָגְעָ֥ה חֶ֖רֶב עַד־הַנָּֽפֶשׁ׃"}},"definableWords":["Lord","God","people","Jerusalem","peace"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["peace"]},"11":{"text":"At that time shall it be said to this people and to Jerusalem, A dry wind of the high places in the wilderness toward the daughter of my people, not to fan, nor to cleanse,","ref":"Jeremiah 4:11","synthesized":"At that time it will be said to this people and to Jerusalem, “A searing wind from the barren heights in the desert blows toward the daughter of My people, but not to winnow or to sift;","sources":{"KJV":{"text":"At that time shall it be said to this people and to Jerusalem, A dry wind of the high places in the wilderness toward the daughter of my people, not to fan, nor to cleanse,"},"BSB":{"text":"At that time it will be said to this people and to Jerusalem, “A searing wind from the barren heights in the desert blows toward the daughter of My people, but not to winnow or to sift;"},"TANAKH":{"text":"At that time shall it be said of this people and of Jerusalem; a hot wind of the high hills in the wilderness toward the daughter of My people, not to fan, nor to cleanse;"},"HEBREW":{"text":"בָּעֵ֣ת הַהִ֗יא יֵאָמֵ֤ר לָֽעָם־הַזֶּה֙ וְלִיר֣וּשָׁלִַ֔ם ר֣וּחַ צַ֤ח שְׁפָיִים֙ בַּמִּדְבָּ֔ר דֶּ֖רֶךְ בַּת־עַמִּ֑י ל֥וֹא לִזְר֖וֹת וְל֥וֹא לְהָבַֽר׃"}},"definableWords":["people","Jerusalem","daughter","or"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"12":{"text":"Even a full wind from those places shall come unto me: now also will I give sentence against them.","ref":"Jeremiah 4:12","synthesized":"a wind too strong for that comes from Me. Now I also pronounce judgments against them.”","sources":{"KJV":{"text":"Even a full wind from those places shall come unto me: now also will I give sentence against them."},"BSB":{"text":"a wind too strong for that comes from Me. Now I also pronounce judgments against them.”"},"TANAKH":{"text":"A wind too strong for this shall come for Me; now will I also utter judgments against them."},"HEBREW":{"text":"ר֧וּחַ מָלֵ֛א מֵאֵ֖לֶּה יָ֣בוֹא לִ֑י עַתָּ֕ה גַּם־אֲנִ֛י אֲדַבֵּ֥ר מִשְׁפָּטִ֖ים אוֹתָֽם׃"}},"definableWords":["strong"],"peopleInVerse":[]},"13":{"text":"Behold, he shall come up as clouds, and his chariots shall be as a whirlwind: his horses are swifter than eagles. Woe unto us! for we are spoiled.","ref":"Jeremiah 4:13","synthesized":"Behold, he advances like the clouds, his chariots like the whirlwind. His horses are swifter than eagles. Woe to us, for we are ruined!","sources":{"KJV":{"text":"Behold, he shall come up as clouds, and his chariots shall be as a whirlwind: his horses are swifter than eagles. Woe unto us! for we are spoiled."},"BSB":{"text":"Behold, he advances like the clouds, his chariots like the whirlwind. His horses are swifter than eagles. Woe to us, for we are ruined!"},"TANAKH":{"text":"Behold, he cometh up as clouds, and his chariots are as the whirlwind; his horses are swifter than eagles.--' Woe unto us! for we are undone.'--"},"HEBREW":{"text":"הִנֵּ֣ה ׀ כַּעֲנָנִ֣ים יַעֲלֶ֗ה וְכַסּוּפָה֙ מַרְכְּבוֹתָ֔יו קַלּ֥וּ מִנְּשָׁרִ֖ים סוּסָ֑יו א֥וֹי לָ֖נוּ כִּ֥י שֻׁדָּֽדְנוּ׃"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"O Jerusalem, wash thine heart from wickedness, that thou mayest be saved. How long shall thy vain thoughts lodge within thee?","ref":"Jeremiah 4:14","synthesized":"Wash the evil from your heart, O Jerusalem, so that you may be saved. How long will you harbor wicked thoughts within you?","sources":{"KJV":{"text":"O Jerusalem, wash thine heart from wickedness, that thou mayest be saved. How long shall thy vain thoughts lodge within thee?"},"BSB":{"text":"Wash the evil from your heart, O Jerusalem, so that you may be saved. How long will you harbor wicked thoughts within you?"},"TANAKH":{"text":"O Jerusalem, wash thy heart from wickedness, that thou mayest be saved. How long shall thy baleful thoughts lodge within thee?"},"HEBREW":{"text":"כַּבְּסִ֨י מֵרָעָ֤ה לִבֵּךְ֙ יְר֣וּשָׁלִַ֔ם לְמַ֖עַן תִּוָּשֵׁ֑עִי עַד־מָתַ֛י תָּלִ֥ין בְּקִרְבֵּ֖ךְ מַחְשְׁב֥וֹת אוֹנֵֽךְ׃"}},"definableWords":["evil","heart","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"15":{"text":"For a voice declareth from Dan, and publisheth affliction from mount Ephraim.","ref":"Jeremiah 4:15","synthesized":"For a voice resounds from Dan, proclaiming disaster from the hills of Ephraim.","sources":{"KJV":{"text":"For a voice declareth from Dan, and publisheth affliction from mount Ephraim."},"BSB":{"text":"For a voice resounds from Dan, proclaiming disaster from the hills of Ephraim."},"TANAKH":{"text":"For hark! one declareth from Dan, and announceth calamity from the hills of Ephraim:"},"HEBREW":{"text":"כִּ֛י ק֥וֹל מַגִּ֖יד מִדָּ֑ן וּמַשְׁמִ֥יעַ אָ֖וֶן מֵהַ֥ר אֶפְרָֽיִם׃"}},"definableWords":["voice"],"peopleInVerse":[]},"16":{"text":"Make ye mention to the nations; behold, publish against Jerusalem, that watchers come from a far country, and give out their voice against the cities of Judah.","ref":"Jeremiah 4:16","synthesized":"Warn the nations now! Proclaim to Jerusalem: “A besieging army comes from a distant land; they raise their voices against the cities of Judah.","sources":{"KJV":{"text":"Make ye mention to the nations; behold, publish against Jerusalem, that watchers come from a far country, and give out their voice against the cities of Judah."},"BSB":{"text":"Warn the nations now! Proclaim to Jerusalem: “A besieging army comes from a distant land; they raise their voices against the cities of Judah."},"TANAKH":{"text":"'Make ye mention to the nations: behold--publish concerning Jerusalem--watchers come from a far country, and give out their voice against the cities of Judah.'"},"HEBREW":{"text":"הַזְכִּ֣ירוּ לַגּוֹיִ֗ם הִנֵּה֙ הַשְׁמִ֣יעוּ עַל־יְרוּשָׁלִַ֔ם נֹצְרִ֥ים בָּאִ֖ים מֵאֶ֣רֶץ הַמֶּרְחָ֑ק וַֽיִּתְּנ֛וּ עַל־עָרֵ֥י יְהוּדָ֖ה קוֹלָֽם׃"}},"definableWords":["nations","Jerusalem","land","Judah"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["land_promise"]},"17":{"text":"As keepers of a field, are they against her round about; because she hath been rebellious against me, saith the LORD.","ref":"Jeremiah 4:17","synthesized":"They surround her like men guarding a field, because she has rebelled against Me,” declares the LORD.","sources":{"KJV":{"text":"As keepers of a field, are they against her round about; because she hath been rebellious against me, saith the LORD."},"BSB":{"text":"They surround her like men guarding a field, because she has rebelled against Me,” declares the LORD."},"TANAKH":{"text":"As keepers of a field are they against her round about; because she hath been rebellious against Me, saith HaShem."},"HEBREW":{"text":"כְּשֹׁמְרֵ֣י שָׂדַ֔י הָי֥וּ עָלֶ֖יהָ מִסָּבִ֑יב כִּי־אֹתִ֥י מָרָ֖תָה נְאֻם־יְהוָֽה׃"}},"definableWords":["men","field","LORD"],"peopleInVerse":[]},"18":{"text":"Thy way and thy doings have procured these things unto thee; this is thy wickedness, because it is bitter, because it reacheth unto thine heart.","ref":"Jeremiah 4:18","synthesized":"“Your ways and deeds have brought this upon you. This is your punishment; how bitter it is, because it pierces to the heart!”","sources":{"KJV":{"text":"Thy way and thy doings have procured these things unto thee; this is thy wickedness, because it is bitter, because it reacheth unto thine heart."},"BSB":{"text":"“Your ways and deeds have brought this upon you. This is your punishment; how bitter it is, because it pierces to the heart!”"},"TANAKH":{"text":"Thy way and thy doings have procured these things unto thee; this is thy wickedness; yea, it is bitter, yea, it reacheth unto thy heart."},"HEBREW":{"text":"דַּרְכֵּךְ֙ וּמַ֣עֲלָלַ֔יִךְ עָשׂ֥וֹ אֵ֖לֶּה לָ֑ךְ זֹ֤את רָעָתֵךְ֙ כִּ֣י מָ֔ר כִּ֥י נָגַ֖ע עַד־לִבֵּֽךְ׃"}},"definableWords":["heart"],"peopleInVerse":[]},"19":{"text":"My bowels, my bowels! I am pained at my very heart; my heart maketh a noise in me; I cannot hold my peace, because thou hast heard, O my soul, the sound of the trumpet, the alarm of war.","ref":"Jeremiah 4:19","synthesized":"My anguish, my anguish! I writhe in pain! Oh, the pain in my chest! My heart pounds within me; I cannot be silent. For I have heard the sound of the horn, the alarm of battle.","sources":{"KJV":{"text":"My bowels, my bowels! I am pained at my very heart; my heart maketh a noise in me; I cannot hold my peace, because thou hast heard, O my soul, the sound of the trumpet, the alarm of war."},"BSB":{"text":"My anguish, my anguish! I writhe in pain! Oh, the pain in my chest! My heart pounds within me; I cannot be silent. For I have heard the sound of the horn, the alarm of battle."},"TANAKH":{"text":"My bowels, my bowels! I writhe in pain! The chambers of my heart! My heart moaneth within me! I cannot hold my peace! because thou hast heard, O my soul, the sound of the horn, the alarm of war."},"HEBREW":{"text":"מֵעַ֣י ׀ מֵעַ֨י ׀ אחולה אוֹחִ֜ילָה קִיר֥וֹת לִבִּ֛י הֹֽמֶה־לִּ֥י לִבִּ֖י לֹ֣א אַחֲרִ֑ישׁ כִּ֣י ק֤וֹל שׁוֹפָר֙ שמעתי שָׁמַ֣עַתְּ נַפְשִׁ֔י תְּרוּעַ֖ת מִלְחָמָֽה׃"}},"definableWords":["heart"],"peopleInVerse":[],"themesInVerse":["spiritual_warfare","suffering"]},"20":{"text":"Destruction upon destruction is cried; for the whole land is spoiled: suddenly are my tents spoiled, and my curtains in a moment.","ref":"Jeremiah 4:20","synthesized":"Disaster after disaster is proclaimed, for the whole land is laid waste. My tents are destroyed in an instant, my curtains in a moment.","sources":{"KJV":{"text":"Destruction upon destruction is cried; for the whole land is spoiled: suddenly are my tents spoiled, and my curtains in a moment."},"BSB":{"text":"Disaster after disaster is proclaimed, for the whole land is laid waste. My tents are destroyed in an instant, my curtains in a moment."},"TANAKH":{"text":"Destruction followeth upon destruction, for the whole land is spoiled; suddenly are my tents spoiled, my curtains in a moment."},"HEBREW":{"text":"שֶׁ֤בֶר עַל־שֶׁ֙בֶר֙ נִקְרָ֔א כִּ֥י שֻׁדְּדָ֖ה כָּל־הָאָ֑רֶץ פִּתְאֹם֙ שֻׁדְּד֣וּ אֹהָלַ֔י רֶ֖גַע יְרִיעֹתָֽי׃"}},"definableWords":["land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"21":{"text":"How long shall I see the standard, and hear the sound of the trumpet?","ref":"Jeremiah 4:21","synthesized":"How long must I see the signal flag and hear the sound of the horn?","sources":{"KJV":{"text":"How long shall I see the standard, and hear the sound of the trumpet?"},"BSB":{"text":"How long must I see the signal flag and hear the sound of the horn?"},"TANAKH":{"text":"How long shall I see the standard, shall I hear the sound of the horn?"},"HEBREW":{"text":"עַד־מָתַ֖י אֶרְאֶה־נֵּ֑ס אֶשְׁמְעָ֖ה ק֥וֹל שׁוֹפָֽר׃"}},"definableWords":["see","hear"],"peopleInVerse":[]},"22":{"text":"For my people is foolish, they have not known me; they are sottish children, and they have none understanding: they are wise to do evil, but to do good they have no knowledge.","ref":"Jeremiah 4:22","synthesized":"“For My people are fools; they have not known Me. They are foolish children, without understanding. They are skilled in doing evil, but they know not how to do good.”","sources":{"KJV":{"text":"For my people is foolish, they have not known me; they are sottish children, and they have none understanding: they are wise to do evil, but to do good they have no knowledge."},"BSB":{"text":"“For My people are fools; they have not known Me. They are foolish children, without understanding. They are skilled in doing evil, but they know not how to do good.”"},"TANAKH":{"text":"For My people is foolish, they know Me not; they are sottish children, and they have no understanding; they are wise to do evil, but to do good they have no knowledge."},"HEBREW":{"text":"כִּ֣י ׀ אֱוִ֣יל עַמִּ֗י אוֹתִי֙ לֹ֣א יָדָ֔עוּ בָּנִ֤ים סְכָלִים֙ הֵ֔מָּה וְלֹ֥א נְבוֹנִ֖ים הֵ֑מָּה חֲכָמִ֥ים הֵ֙מָּה֙ לְהָרַ֔ע וּלְהֵיטִ֖יב לֹ֥א יָדָֽעוּ׃"}},"definableWords":["people","evil","good"],"peopleInVerse":[],"themesInVerse":["wisdom"]},"23":{"text":"I beheld the earth, and, lo, it was without form, and void; and the heavens, and they had no light.","ref":"Jeremiah 4:23","synthesized":"I looked at the earth, and it was formless and void; I looked to the heavens, and they had no light.","sources":{"KJV":{"text":"I beheld the earth, and, lo, it was without form, and void; and the heavens, and they had no light."},"BSB":{"text":"I looked at the earth, and it was formless and void; I looked to the heavens, and they had no light."},"TANAKH":{"text":"I beheld the earth, and, lo, it was waste and void; and the heavens, and they had no light."},"HEBREW":{"text":"רָאִ֙יתִי֙ אֶת־הָאָ֔רֶץ וְהִנֵּה־תֹ֖הוּ וָבֹ֑הוּ וְאֶל־הַשָּׁמַ֖יִם וְאֵ֥ין אוֹרָֽם׃"}},"definableWords":["earth","heavens","light"],"peopleInVerse":[],"themesInVerse":["light_darkness"]},"24":{"text":"I beheld the mountains, and, lo, they trembled, and all the hills moved lightly.","ref":"Jeremiah 4:24","synthesized":"I looked at the mountains, and behold, they were quaking; all the hills were swaying.","sources":{"KJV":{"text":"I beheld the mountains, and, lo, they trembled, and all the hills moved lightly."},"BSB":{"text":"I looked at the mountains, and behold, they were quaking; all the hills were swaying."},"TANAKH":{"text":"I beheld the mountains, and, lo, they trembled, and all the hills moved to and fro."},"HEBREW":{"text":"רָאִ֙יתִי֙ הֶֽהָרִ֔ים וְהִנֵּ֖ה רֹעֲשִׁ֑ים וְכָל־הַגְּבָע֖וֹת הִתְקַלְקָֽלוּ׃"}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"I beheld, and, lo, there was no man, and all the birds of the heavens were fled.","ref":"Jeremiah 4:25","synthesized":"I looked, and no man was left; all the birds of the air had fled.","sources":{"KJV":{"text":"I beheld, and, lo, there was no man, and all the birds of the heavens were fled."},"BSB":{"text":"I looked, and no man was left; all the birds of the air had fled."},"TANAKH":{"text":"I beheld, and, lo, there was no man, and all the birds of the heavens were fled."},"HEBREW":{"text":"רָאִ֕יתִי וְהִנֵּ֖ה אֵ֣ין הָאָדָ֑ם וְכָל־ע֥וֹף הַשָּׁמַ֖יִם נָדָֽדוּ׃"}},"definableWords":["man","birds"],"peopleInVerse":[]},"26":{"text":"I beheld, and, lo, the fruitful place was a wilderness, and all the cities thereof were broken down at the presence of the LORD, and by his fierce anger.","ref":"Jeremiah 4:26","synthesized":"I looked, and the fruitful land was a desert. All its cities were torn down before the LORD, before His fierce anger.","sources":{"KJV":{"text":"I beheld, and, lo, the fruitful place was a wilderness, and all the cities thereof were broken down at the presence of the LORD, and by his fierce anger."},"BSB":{"text":"I looked, and the fruitful land was a desert. All its cities were torn down before the LORD, before His fierce anger."},"TANAKH":{"text":"I beheld, and, lo, the fruitful field was a wilderness, and all the cities thereof were broken down at the presence of HaShem, and before His fierce anger."},"HEBREW":{"text":"רָאִ֕יתִי וְהִנֵּ֥ה הַכַּרְמֶ֖ל הַמִּדְבָּ֑ר וְכָל־עָרָ֗יו נִתְּצוּ֙ מִפְּנֵ֣י יְהוָ֔ה מִפְּנֵ֖י חֲר֥וֹן אַפּֽוֹ׃"}},"definableWords":["fruitful","land","LORD","anger"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"27":{"text":"For thus hath the LORD said, The whole land shall be desolate; yet will I not make a full end.","ref":"Jeremiah 4:27","synthesized":"For this is what the LORD says:  “The whole land will be desolate, but I will not finish its destruction.","sources":{"KJV":{"text":"For thus hath the LORD said, The whole land shall be desolate; yet will I not make a full end."},"BSB":{"text":"For this is what the LORD says:  “The whole land will be desolate, but I will not finish its destruction."},"TANAKH":{"text":"For thus saith HaShem: The whole land shall be desolate; yet will I not make a full end."},"HEBREW":{"text":"כִּי־כֹה֙ אָמַ֣ר יְהוָ֔ה שְׁמָמָ֥ה תִהְיֶ֖ה כָּל־הָאָ֑רֶץ וְכָלָ֖ה לֹ֥א אֶעֱשֶֽׂה׃"}},"definableWords":["LORD","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"28":{"text":"For this shall the earth mourn, and the heavens above be black: because I have spoken it, I have purposed it, and will not repent, neither will I turn back from it.","ref":"Jeremiah 4:28","synthesized":"Therefore the earth will mourn and the heavens above will grow dark. I have spoken, I have planned, and I will not relent or turn back.”","sources":{"KJV":{"text":"For this shall the earth mourn, and the heavens above be black: because I have spoken it, I have purposed it, and will not repent, neither will I turn back from it."},"BSB":{"text":"Therefore the earth will mourn and the heavens above will grow dark. I have spoken, I have planned, and I will not relent or turn back.”"},"TANAKH":{"text":"For this shall the earth mourn, and the heavens above be black; because I have spoken it, I have purposed it, and I have not repented, neither will I turn back from it."},"HEBREW":{"text":"עַל־זֹאת֙ תֶּאֱבַ֣ל הָאָ֔רֶץ וְקָדְר֥וּ הַשָּׁמַ֖יִם מִמָּ֑עַל עַ֤ל כִּי־דִבַּ֙רְתִּי֙ זַמֹּ֔תִי וְלֹ֥א נִחַ֖מְתִּי וְלֹא־אָשׁ֥וּב מִמֶּֽנָּה׃"}},"definableWords":["earth","heavens","or"],"peopleInVerse":[]},"29":{"text":"The whole city shall flee for the noise of the horsemen and bowmen; they shall go into thickets, and climb up upon the rocks: every city shall be forsaken, and not a man dwell therein.","ref":"Jeremiah 4:29","synthesized":"Every city flees at the sound of the horseman and archer. They enter the thickets and climb among the rocks. Every city is abandoned; no inhabitant is left.","sources":{"KJV":{"text":"The whole city shall flee for the noise of the horsemen and bowmen; they shall go into thickets, and climb up upon the rocks: every city shall be forsaken, and not a man dwell therein."},"BSB":{"text":"Every city flees at the sound of the horseman and archer. They enter the thickets and climb among the rocks. Every city is abandoned; no inhabitant is left."},"TANAKH":{"text":"For the noise of the horsemen and bowmen the whole city fleeth; they go into the thickets, and climb up upon the rocks; every city is forsaken, and not a man dwelleth therein."},"HEBREW":{"text":"מִקּ֨וֹל פָּרָ֜שׁ וְרֹ֣מֵה קֶ֗שֶׁת בֹּרַ֙חַת֙ כָּל־הָעִ֔יר בָּ֚אוּ בֶּעָבִ֔ים וּבַכֵּפִ֖ים עָל֑וּ כָּל־הָעִ֣יר עֲזוּבָ֔ה וְאֵין־יוֹשֵׁ֥ב בָּהֵ֖ן אִֽישׁ׃"}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"And when thou art spoiled, what wilt thou do? Though thou clothest thyself with crimson, though thou deckest thee with ornaments of gold, though thou rentest thy face with painting, in vain shalt thou make thyself fair; thy lovers will despise thee, they will seek thy life.","ref":"Jeremiah 4:30","synthesized":"And you, O devastated one, what will you do, though you dress yourself in scarlet, though you adorn yourself with gold jewelry, though you enlarge your eyes with paint? You adorn yourself in vain; your lovers despise you; they want to take your life.","sources":{"KJV":{"text":"And when thou art spoiled, what wilt thou do? Though thou clothest thyself with crimson, though thou deckest thee with ornaments of gold, though thou rentest thy face with painting, in vain shalt thou make thyself fair; thy lovers will despise thee, they will seek thy life."},"BSB":{"text":"And you, O devastated one, what will you do, though you dress yourself in scarlet, though you adorn yourself with gold jewelry, though you enlarge your eyes with paint? You adorn yourself in vain; your lovers despise you; they want to take your life."},"TANAKH":{"text":"And thou, that art spoiled, what doest thou, that thou clothest thyself with scarlet, that thou deckest thee with ornaments of gold, that thou enlargest thine eyes with paint? In vain dost thou make thyself fair; thy lovers despise thee, they seek thy life."},"HEBREW":{"text":"ואתי וְאַ֨תְּ שָׁד֜וּד מַֽה־תַּעֲשִׂ֗י כִּֽי־תִלְבְּשִׁ֨י שָׁנִ֜י כִּי־תַעְדִּ֣י עֲדִי־זָהָ֗ב כִּֽי־תִקְרְעִ֤י בַפּוּךְ֙ עֵינַ֔יִךְ לַשָּׁ֖וְא תִּתְיַפִּ֑י מָאֲסוּ־בָ֥ךְ עֹגְבִ֖ים נַפְשֵׁ֥ךְ יְבַקֵּֽשׁוּ׃"}},"definableWords":["one","life"],"peopleInVerse":[]},"31":{"text":"For I have heard a voice as of a woman in travail, and the anguish as of her that bringeth forth her first child, the voice of the daughter of Zion, that bewaileth herself, that spreadeth her hands, saying, Woe is me now! for my soul is wearied because of murderers.","ref":"Jeremiah 4:31","synthesized":"For I hear a cry like a woman in labor, a cry of anguish like one bearing her first child— the cry of the Daughter of Zion gasping for breath, stretching out her hands to say, “Woe is me, for my soul faints before the murderers!”","sources":{"KJV":{"text":"For I have heard a voice as of a woman in travail, and the anguish as of her that bringeth forth her first child, the voice of the daughter of Zion, that bewaileth herself, that spreadeth her hands, saying, Woe is me now! for my soul is wearied because of murderers."},"BSB":{"text":"For I hear a cry like a woman in labor, a cry of anguish like one bearing her first child— the cry of the Daughter of Zion gasping for breath, stretching out her hands to say, “Woe is me, for my soul faints before the murderers!”"},"TANAKH":{"text":"For I have heard a voice as of a woman in travail, the anguish as of her that bringeth forth her first child, the voice of the daughter of Zion, that gaspeth for breath, that spreadeth her hands: 'Woe is me, now! for my soul fainteth before the murderers.'"},"HEBREW":{"text":"כִּי֩ ק֨וֹל כְּחוֹלָ֜ה שָׁמַ֗עְתִּי צָרָה֙ כְּמַבְכִּירָ֔ה ק֧וֹל בַּת־צִיּ֛וֹן תִּתְיַפֵּ֖חַ תְּפָרֵ֣שׂ כַּפֶּ֑יהָ אֽוֹי־נָ֣א לִ֔י כִּֽי־עָיְפָ֥ה נַפְשִׁ֖י לְהֹרְגִֽים׃"}},"definableWords":["hear","woman","one","daughter","Zion","breath","soul"],"peopleInVerse":[],"placesInVerse":["Mount Zion"]}}},"5":{"chapter":"5","title":"RUN THROUGH JERUSALEM, FIND A JUST MAN","verses":{"1":{"text":"Run ye to and fro through the streets of Jerusalem, and see now, and know, and seek in the broad places thereof, if ye can find a man, if there be any that executeth judgment, that seeketh the truth; and I will pardon it.","ref":"Jeremiah 5:1","synthesized":"“Go up and down the streets of Jerusalem. Look now and take note; search her squares. If you can find a single person, anyone who acts justly, anyone who seeks the truth, then I will forgive the city.","sources":{"KJV":{"text":"Run ye to and fro through the streets of Jerusalem, and see now, and know, and seek in the broad places thereof, if ye can find a man, if there be any that executeth judgment, that seeketh the truth; and I will pardon it."},"BSB":{"text":"“Go up and down the streets of Jerusalem. Look now and take note; search her squares. If you can find a single person, anyone who acts justly, anyone who seeks the truth, then I will forgive the city."},"TANAKH":{"text":"Run ye to and fro through the streets of Jerusalem, and see now, and know, and seek in the broad places thereof, if ye can find a man, if there be any that doeth justly, that seeketh truth; and I will pardon her."},"HEBREW":{"text":"שׁוֹטְט֞וּ בְּחוּצ֣וֹת יְרוּשָׁלִַ֗ם וּרְאוּ־נָ֤א וּדְעוּ֙ וּבַקְשׁ֣וּ בִרְחוֹבוֹתֶ֔יהָ אִם־תִּמְצְא֣וּ אִ֔ישׁ אִם־יֵ֛שׁ עֹשֶׂ֥ה מִשְׁפָּ֖ט מְבַקֵּ֣שׁ אֱמוּנָ֑ה וְאֶסְלַ֖ח לָֽהּ׃"}},"definableWords":["Jerusalem","truth","forgive"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"2":{"text":"And though they say, The LORD liveth; surely they swear falsely.","ref":"Jeremiah 5:2","synthesized":"Although they say, ‘As surely as the LORD lives,’ they are swearing falsely.”","sources":{"KJV":{"text":"And though they say, The LORD liveth; surely they swear falsely."},"BSB":{"text":"Although they say, ‘As surely as the LORD lives,’ they are swearing falsely.”"},"TANAKH":{"text":"And though they say: 'As HaShem liveth', surely they swear falsely."},"HEBREW":{"text":"וְאִ֥ם חַי־יְהֹוָ֖ה יֹאמֵ֑רוּ לָכֵ֥ן לַשֶּׁ֖קֶר יִשָּׁבֵֽעוּ׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"3":{"text":"O LORD, are not thine eyes upon the truth? thou hast stricken them, but they have not grieved; thou hast consumed them, but they have refused to receive correction: they have made their faces harder than a rock; they have refused to return.","ref":"Jeremiah 5:3","synthesized":"O LORD, do not Your eyes look for truth? You struck them, but they felt no pain. You finished them off, but they refused to accept discipline. They have made their faces harder than stone and refused to repent.","sources":{"KJV":{"text":"O LORD, are not thine eyes upon the truth? thou hast stricken them, but they have not grieved; thou hast consumed them, but they have refused to receive correction: they have made their faces harder than a rock; they have refused to return."},"BSB":{"text":"O LORD, do not Your eyes look for truth? You struck them, but they felt no pain. You finished them off, but they refused to accept discipline. They have made their faces harder than stone and refused to repent."},"TANAKH":{"text":"O HaShem, are not Thine eyes upon truth? Thou hast stricken them, but they were not affected; Thou hast consumed them, but they have refused to receive correction; they have made their faces harder than a rock; they have refused to return."},"HEBREW":{"text":"יְהֹוָ֗ה עֵינֶיךָ֮ הֲל֣וֹא לֶאֱמוּנָה֒ הִכִּ֤יתָה אֹתָם֙ וְֽלֹא־חָ֔לוּ כִּלִּיתָ֕ם מֵאֲנ֖וּ קַ֣חַת מוּסָ֑ר חִזְּק֤וּ פְנֵיהֶם֙ מִסֶּ֔לַע מֵאֲנ֖וּ לָשֽׁוּב׃"}},"definableWords":["LORD","truth","made","stone"],"peopleInVerse":[],"themesInVerse":["creation","suffering"]},"4":{"text":"Therefore I said, Surely these are poor; they are foolish: for they know not the way of the LORD, nor the judgment of their God.","ref":"Jeremiah 5:4","synthesized":"Then I said, “They are only the poor; they have played the fool, for they do not know the way of the LORD, the justice of their God.","sources":{"KJV":{"text":"Therefore I said, Surely these are poor; they are foolish: for they know not the way of the LORD, nor the judgment of their God."},"BSB":{"text":"Then I said, “They are only the poor; they have played the fool, for they do not know the way of the LORD, the justice of their God."},"TANAKH":{"text":"And I said: 'Surely these are poor, they are foolish, for they know not the way of HaShem, nor the ordinance of their G-d;"},"HEBREW":{"text":"וַאֲנִ֣י אָמַ֔רְתִּי אַךְ־דַּלִּ֖ים הֵ֑ם נוֹאֲל֕וּ כִּ֣י לֹ֤א יָדְעוּ֙ דֶּ֣רֶךְ יְהוָ֔ה מִשְׁפַּ֖ט אֱלֹהֵיהֶֽם׃"}},"definableWords":["fool","way","LORD","justice","God"],"peopleInVerse":[]},"5":{"text":"I will get me unto the great men, and will speak unto them; for they have known the way of the LORD, and the judgment of their God: but these have altogether broken the yoke, and burst the bonds.","ref":"Jeremiah 5:5","synthesized":"I will go to the powerful and speak to them. Surely they know the way of the LORD, the justice of their God.”   But they too, with one accord, had broken the yoke and torn off the chains.","sources":{"KJV":{"text":"I will get me unto the great men, and will speak unto them; for they have known the way of the LORD, and the judgment of their God: but these have altogether broken the yoke, and burst the bonds."},"BSB":{"text":"I will go to the powerful and speak to them. Surely they know the way of the LORD, the justice of their God.”   But they too, with one accord, had broken the yoke and torn off the chains."},"TANAKH":{"text":"I will get me unto the great men, and will speak unto them; for they know the way of HaShem, and the ordinance of their G-d.' But these had altogether broken the yoke, and burst the bands."},"HEBREW":{"text":"אֵֽלֲכָה־לִּ֤י אֶל־הַגְּדֹלִים֙ וַאֲדַבְּרָ֣ה אוֹתָ֔ם כִּ֣י הֵ֗מָּה יָדְעוּ֙ דֶּ֣רֶךְ יְהוָ֔ה מִשְׁפַּ֖ט אֱלֹהֵיהֶ֑ם אַ֣ךְ הֵ֤מָּה יַחְדָּו֙ שָׁ֣בְרוּ עֹ֔ל נִתְּק֖וּ מוֹסֵרֽוֹת׃"}},"definableWords":["way","LORD","justice","God","one"],"peopleInVerse":[]},"6":{"text":"Wherefore a lion out of the forest shall slay them, and a wolf of the evenings shall spoil them, a leopard shall watch over their cities: every one that goeth out thence shall be torn in pieces: because their transgressions are many, and their backslidings are increased.","ref":"Jeremiah 5:6","synthesized":"Therefore a lion from the forest will strike them down, a wolf from the desert will ravage them. A leopard will lie in wait near their cities, and everyone who ventures out will be torn to pieces. For their rebellious acts are many, and their unfaithful deeds are numerous.","sources":{"KJV":{"text":"Wherefore a lion out of the forest shall slay them, and a wolf of the evenings shall spoil them, a leopard shall watch over their cities: every one that goeth out thence shall be torn in pieces: because their transgressions are many, and their backslidings are increased."},"BSB":{"text":"Therefore a lion from the forest will strike them down, a wolf from the desert will ravage them. A leopard will lie in wait near their cities, and everyone who ventures out will be torn to pieces. For their rebellious acts are many, and their unfaithful deeds are numerous."},"TANAKH":{"text":"Wherefore a lion out of the forest doth slay them, a wolf of the deserts doth spoil them, a leopard watcheth over their cities, every one that goeth out thence is torn in pieces; because their transgressions are many, their backslidings are increased."},"HEBREW":{"text":"עַל־כֵּן֩ הִכָּ֨ם אַרְיֵ֜ה מִיַּ֗עַר זְאֵ֤ב עֲרָבוֹת֙ יְשָׁדְדֵ֔ם נָמֵ֤ר שֹׁקֵד֙ עַל־עָ֣רֵיהֶ֔ם כָּל־הַיּוֹצֵ֥א מֵהֵ֖נָּה יִטָּרֵ֑ף כִּ֤י רַבּוּ֙ פִּשְׁעֵיהֶ֔ם עָצְמ֖וּ משבותיהם מְשׁוּבוֹתֵיהֶֽם׃"}},"definableWords":["lion","wait"],"peopleInVerse":[],"themesInVerse":["hope"]},"7":{"text":"How shall I pardon thee for this? thy children have forsaken me, and sworn by them that are no gods: when I had fed them to the full, they then committed adultery, and assembled themselves by troops in the harlots’ houses.","ref":"Jeremiah 5:7","synthesized":"“Why should I forgive you? Your children have forsaken Me and sworn by gods that are not gods. I satisfied their needs, yet they committed adultery and assembled at the houses of prostitutes.","sources":{"KJV":{"text":"How shall I pardon thee for this? thy children have forsaken me, and sworn by them that are no gods: when I had fed them to the full, they then committed adultery, and assembled themselves by troops in the harlots’ houses."},"BSB":{"text":"“Why should I forgive you? Your children have forsaken Me and sworn by gods that are not gods. I satisfied their needs, yet they committed adultery and assembled at the houses of prostitutes."},"TANAKH":{"text":"Wherefore should I pardon thee? The children have forsaken Me, and sworn by no-gods; and when I had fed them to the full, they committed adultery, and assembled themselves in troops at the harlots' houses."},"HEBREW":{"text":"אֵ֤י לָזֹאת֙ אסלוח־אֶֽסְלַֽח־לָ֔ךְ בָּנַ֣יִךְ עֲזָב֔וּנִי וַיִּשָּׁבְע֖וּ בְּלֹ֣א אֱלֹהִ֑ים וָאַשְׂבִּ֤עַ אוֹתָם֙ וַיִּנְאָ֔פוּ וּבֵ֥ית זוֹנָ֖ה יִתְגֹּדָֽדוּ׃"}},"definableWords":["forgive"],"peopleInVerse":[]},"8":{"text":"They were as fed horses in the morning: every one neighed after his neighbour’s wife.","ref":"Jeremiah 5:8","synthesized":"They are well-fed, lusty stallions, each neighing after his neighbor’s wife.","sources":{"KJV":{"text":"They were as fed horses in the morning: every one neighed after his neighbour’s wife."},"BSB":{"text":"They are well-fed, lusty stallions, each neighing after his neighbor’s wife."},"TANAKH":{"text":"They are become as well-fed horses, lusty stallions; every one neigheth after his neighbour's wife."},"HEBREW":{"text":"סוּסִ֥ים מְיֻזָּנִ֖ים מַשְׁכִּ֣ים הָי֑וּ אִ֛ישׁ אֶל־אֵ֥שֶׁת רֵעֵ֖הוּ יִצְהָֽלוּ׃"}},"definableWords":["wife"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"9":{"text":"Shall I not visit for these things? saith the LORD: and shall not my soul be avenged on such a nation as this?","ref":"Jeremiah 5:9","synthesized":"Should I not punish them for these things?” declares the LORD. “Should I not avenge Myself on such a nation as this?","sources":{"KJV":{"text":"Shall I not visit for these things? saith the LORD: and shall not my soul be avenged on such a nation as this?"},"BSB":{"text":"Should I not punish them for these things?” declares the LORD. “Should I not avenge Myself on such a nation as this?"},"TANAKH":{"text":"Shall I not punish for these things? saith HaShem; and shall not My soul be avenged on such a nation as this?"},"HEBREW":{"text":"הַֽעַל־אֵ֥לֶּה לוֹא־אֶפְקֹ֖ד נְאֻם־יְהֹוָ֑ה וְאִם֙ בְּג֣וֹי אֲשֶׁר־כָּזֶ֔ה לֹ֥א תִתְנַקֵּ֖ם נַפְשִֽׁי׃"}},"definableWords":["LORD","nation"],"peopleInVerse":[]},"10":{"text":"Go ye up upon her walls, and destroy; but make not a full end: take away her battlements; for they are not the LORD’s.","ref":"Jeremiah 5:10","synthesized":"Go up through her vineyards and ravage them, but do not finish them off. Strip off her branches, for they do not belong to the LORD.","sources":{"KJV":{"text":"Go ye up upon her walls, and destroy; but make not a full end: take away her battlements; for they are not the LORD’s."},"BSB":{"text":"Go up through her vineyards and ravage them, but do not finish them off. Strip off her branches, for they do not belong to the LORD."},"TANAKH":{"text":"Go ye up into her rows, and destroy, but make not a full end; take away her shoots; for they are not HaShem'S."},"HEBREW":{"text":"עֲל֤וּ בְשָׁרוֹתֶ֙יהָ֙ וְשַׁחֵ֔תוּ וְכָלָ֖ה אַֽל־תַּעֲשׂ֑וּ הָסִ֙ירוּ֙ נְטִ֣ישׁוֹתֶ֔יהָ כִּ֛י ל֥וֹא לַיהוָ֖ה הֵֽמָּה׃"}},"definableWords":["LORD"],"peopleInVerse":[],"themesInVerse":["vine_branches"]},"11":{"text":"For the house of Israel and the house of Judah have dealt very treacherously against me, saith the LORD.","ref":"Jeremiah 5:11","synthesized":"For the house of Israel and the house of Judah have been utterly unfaithful to Me,” declares the LORD.","sources":{"KJV":{"text":"For the house of Israel and the house of Judah have dealt very treacherously against me, saith the LORD."},"BSB":{"text":"For the house of Israel and the house of Judah have been utterly unfaithful to Me,” declares the LORD."},"TANAKH":{"text":"For the house of Israel and the house of Judah have dealt very treacherously against Me, saith HaShem."},"HEBREW":{"text":"כִּי֩ בָג֨וֹד בָּגְד֜וּ בִּ֗י בֵּ֧ית יִשְׂרָאֵ֛ל וּבֵ֥ית יְהוּדָ֖ה נְאֻם־יְהוָֽה׃"}},"definableWords":["house","Israel","Judah","LORD"],"peopleInVerse":[]},"12":{"text":"They have belied the LORD, and said, It is not he; neither shall evil come upon us; neither shall we see sword nor famine:","ref":"Jeremiah 5:12","synthesized":"They have lied about the LORD and said:  “He will not do anything; harm will not come to us; we will not see sword or famine.","sources":{"KJV":{"text":"They have belied the LORD, and said, It is not he; neither shall evil come upon us; neither shall we see sword nor famine:"},"BSB":{"text":"They have lied about the LORD and said:  “He will not do anything; harm will not come to us; we will not see sword or famine."},"TANAKH":{"text":"They have belied HaShem, and said: 'It is not He, neither shall evil come upon us; neither shall we see sword nor famine;"},"HEBREW":{"text":"כִּֽחֲשׁוּ֙ בַּיהוָ֔ה וַיֹּאמְר֖וּ לֹא־ה֑וּא וְלֹא־תָב֤וֹא עָלֵ֙ינוּ֙ רָעָ֔ה וְחֶ֥רֶב וְרָעָ֖ב ל֥וֹא נִרְאֶֽה׃"}},"definableWords":["LORD","see","or"],"peopleInVerse":[]},"13":{"text":"And the prophets shall become wind, and the word is not in them: thus shall it be done unto them.","ref":"Jeremiah 5:13","synthesized":"The prophets are but wind, for the word is not in them. So let their own predictions befall them.”","sources":{"KJV":{"text":"And the prophets shall become wind, and the word is not in them: thus shall it be done unto them."},"BSB":{"text":"The prophets are but wind, for the word is not in them. So let their own predictions befall them.”"},"TANAKH":{"text":"And the prophets shall become wind, and the word is not in them; thus be it done unto them.'"},"HEBREW":{"text":"וְהַנְּבִיאִים֙ יִֽהְי֣וּ לְר֔וּחַ וְהַדִּבֵּ֖ר אֵ֣ין בָּהֶ֑ם כֹּ֥ה יֵעָשֶׂ֖ה לָהֶֽם׃"}},"definableWords":["word"],"peopleInVerse":[]},"14":{"text":"Wherefore thus saith the LORD God of hosts, Because ye speak this word, behold, I will make my words in thy mouth fire, and this people wood, and it shall devour them.","ref":"Jeremiah 5:14","synthesized":"Therefore this is what the LORD God of Hosts says:  “Because you have spoken this word, I will make My words a fire in your mouth and this people the wood it consumes.","sources":{"KJV":{"text":"Wherefore thus saith the LORD God of hosts, Because ye speak this word, behold, I will make my words in thy mouth fire, and this people wood, and it shall devour them."},"BSB":{"text":"Therefore this is what the LORD God of Hosts says:  “Because you have spoken this word, I will make My words a fire in your mouth and this people the wood it consumes."},"TANAKH":{"text":"Wherefore thus saith HaShem, the G-d of hosts: Because ye speak this word, behold, I will make My words in thy mouth fire, and this people wood, and it shall devour them."},"HEBREW":{"text":"לָכֵ֗ן כֹּֽה־אָמַ֤ר יְהוָה֙ אֱלֹהֵ֣י צְבָא֔וֹת יַ֚עַן דַּבֶּרְכֶ֔ם אֶת־הַדָּבָ֖ר הַזֶּ֑ה הִנְנִ֣י נֹתֵן֩ דְּבָרַ֨י בְּפִ֜יךָ לְאֵ֗שׁ וְהָעָ֥ם הַזֶּ֛ה עֵצִ֖ים וַאֲכָלָֽתַם׃"}},"definableWords":["LORD","God","word","make","people"],"peopleInVerse":[]},"15":{"text":"Lo, I will bring a nation upon you from far, O house of Israel, saith the LORD: it is a mighty nation, it is an ancient nation, a nation whose language thou knowest not, neither understandest what they say.","ref":"Jeremiah 5:15","synthesized":"Behold, I am bringing a distant nation against you, O house of Israel,” declares the LORD. “It is an established nation, an ancient nation, a nation whose language you do not know and whose speech you do not understand.","sources":{"KJV":{"text":"Lo, I will bring a nation upon you from far, O house of Israel, saith the LORD: it is a mighty nation, it is an ancient nation, a nation whose language thou knowest not, neither understandest what they say."},"BSB":{"text":"Behold, I am bringing a distant nation against you, O house of Israel,” declares the LORD. “It is an established nation, an ancient nation, a nation whose language you do not know and whose speech you do not understand."},"TANAKH":{"text":"Lo, I will bring a nation upon you from far, O house of Israel, saith HaShem; it is an enduring nation, it is an ancient nation, a nation whose language thou knowest not, neither understandest what they say."},"HEBREW":{"text":"הִנְנִ֣י מֵבִיא֩ עֲלֵיכֶ֨ם גּ֧וֹי מִמֶּרְחָ֛ק בֵּ֥ית יִשְׂרָאֵ֖ל נְאֻם־יְהֹוָ֑ה גּ֣וֹי ׀ אֵיתָ֣ן ה֗וּא גּ֤וֹי מֵעוֹלָם֙ ה֔וּא גּ֚וֹי לֹא־תֵדַ֣ע לְשֹׁנ֔וֹ וְלֹ֥א תִשְׁמַ֖ע מַה־יְדַבֵּֽר׃"}},"definableWords":["nation","house","Israel","LORD"],"peopleInVerse":[]},"16":{"text":"Their quiver is as an open sepulchre, they are all mighty men.","ref":"Jeremiah 5:16","synthesized":"Their quivers are like open graves; they are all mighty men.","sources":{"KJV":{"text":"Their quiver is as an open sepulchre, they are all mighty men."},"BSB":{"text":"Their quivers are like open graves; they are all mighty men."},"TANAKH":{"text":"Their quiver is an open sepulchre, they are all mighty men."},"HEBREW":{"text":"אַשְׁפָּת֖וֹ כְּקֶ֣בֶר פָּת֑וּחַ כֻּלָּ֖ם גִּבּוֹרִֽים׃"}},"definableWords":["mighty","men"],"peopleInVerse":[]},"17":{"text":"And they shall eat up thine harvest, and thy bread, which thy sons and thy daughters should eat: they shall eat up thy flocks and thine herds: they shall eat up thy vines and thy fig trees: they shall impoverish thy fenced cities, wherein thou trustedst, with the sword.","ref":"Jeremiah 5:17","synthesized":"They will devour your harvest and food; they will consume your sons and daughters; they will eat up your flocks and herds; they will feed on your vines and fig trees. With the sword they will destroy the fortified cities in which you trust.”","sources":{"KJV":{"text":"And they shall eat up thine harvest, and thy bread, which thy sons and thy daughters should eat: they shall eat up thy flocks and thine herds: they shall eat up thy vines and thy fig trees: they shall impoverish thy fenced cities, wherein thou trustedst, with the sword."},"BSB":{"text":"They will devour your harvest and food; they will consume your sons and daughters; they will eat up your flocks and herds; they will feed on your vines and fig trees. With the sword they will destroy the fortified cities in which you trust.”"},"TANAKH":{"text":"And they shall eat up thy harvest, and thy bread, they shall eat up thy sons and thy daughters, they shall eat up thy flocks and thy herds, they shall eat up thy vines and thy fig-trees; they shall batter thy fortified cities, wherein thou trusteth, with the sword."},"HEBREW":{"text":"וְאָכַ֨ל קְצִֽירְךָ֜ וְלַחְמֶ֗ךָ יֹאכְלוּ֙ בָּנֶ֣יךָ וּבְנוֹתֶ֔יךָ יֹאכַ֤ל צֹאנְךָ֙ וּבְקָרֶ֔ךָ יֹאכַ֥ל גַּפְנְךָ֖ וּתְאֵנָתֶ֑ךָ יְרֹשֵׁ֞שׁ עָרֵ֣י מִבְצָרֶ֗יךָ אֲשֶׁ֥ר אַתָּ֛ה בּוֹטֵ֥חַ בָּהֵ֖נָּה בֶּחָֽרֶב׃"}},"definableWords":["sons","daughters","trees","trust"],"peopleInVerse":[],"themesInVerse":["faith"]},"18":{"text":"Nevertheless in those days, saith the LORD, I will not make a full end with you.","ref":"Jeremiah 5:18","synthesized":"“Yet even in those days,” declares the LORD, “I will not make a full end of you.","sources":{"KJV":{"text":"Nevertheless in those days, saith the LORD, I will not make a full end with you."},"BSB":{"text":"“Yet even in those days,” declares the LORD, “I will not make a full end of you."},"TANAKH":{"text":"But even in those days, saith HaShem, I will not make a full end with you."},"HEBREW":{"text":"וְגַ֛ם בַּיָּמִ֥ים הָהֵ֖מָּה נְאֻם־יְהֹוָ֑ה לֹֽא־אֶעֱשֶׂ֥ה אִתְּכֶ֖ם כָּלָֽה׃"}},"definableWords":["days","LORD","make"],"peopleInVerse":[]},"19":{"text":"And it shall come to pass, when ye shall say, Wherefore doeth the LORD our God all these things unto us? then shalt thou answer them, Like as ye have forsaken me, and served strange gods in your land, so shall ye serve strangers in a land that is not yours.","ref":"Jeremiah 5:19","synthesized":"And when the people ask, ‘For what offense has the LORD our God done all these things to us?’ You are to tell them, ‘Just as you have forsaken Me and served foreign gods in your land, so will you serve foreigners in a land that is not your own.’”","sources":{"KJV":{"text":"And it shall come to pass, when ye shall say, Wherefore doeth the LORD our God all these things unto us? then shalt thou answer them, Like as ye have forsaken me, and served strange gods in your land, so shall ye serve strangers in a land that is not yours."},"BSB":{"text":"And when the people ask, ‘For what offense has the LORD our God done all these things to us?’ You are to tell them, ‘Just as you have forsaken Me and served foreign gods in your land, so will you serve foreigners in a land that is not your own.’”"},"TANAKH":{"text":"And it shall come to pass, when ye shall say: 'Wherefore hath HaShem our G-d done all these things unto us?' then shalt Thou say unto them: 'Like as ye have forsaken Me, and served strange gods in your land, so shall ye serve strangers in a land that is not yours.'"},"HEBREW":{"text":"וְהָיָה֙ כִּ֣י תֹאמְר֔וּ תַּ֣חַת מֶ֗ה עָשָׂ֨ה יְהֹוָ֧ה אֱלֹהֵ֛ינוּ לָ֖נוּ אֶת־כָּל־אֵ֑לֶּה וְאָמַרְתָּ֣ אֲלֵיהֶ֗ם כַּאֲשֶׁ֨ר עֲזַבְתֶּ֤ם אוֹתִי֙ וַתַּעַבְד֞וּ אֱלֹהֵ֤י נֵכָר֙ בְּאַרְצְכֶ֔ם כֵּ֚ן תַּעַבְד֣וּ זָרִ֔ים בְּאֶ֖רֶץ לֹ֥א לָכֶֽם׃"}},"definableWords":["people","LORD","God","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"20":{"text":"Declare this in the house of Jacob, and publish it in Judah, saying,","ref":"Jeremiah 5:20","synthesized":"Declare this in the house of Jacob and proclaim it in Judah:","sources":{"KJV":{"text":"Declare this in the house of Jacob, and publish it in Judah, saying,"},"BSB":{"text":"Declare this in the house of Jacob and proclaim it in Judah:"},"TANAKH":{"text":"Declare ye this in the house of Jacob, and announce it in Judah, saying:"},"HEBREW":{"text":"הַגִּ֥ידוּ זֹ֖את בְּבֵ֣ית יַעֲקֹ֑ב וְהַשְׁמִיע֥וּהָ בִיהוּדָ֖ה לֵאמֹֽר׃"}},"definableWords":["house","Jacob","Judah"],"peopleInVerse":["Jacob"]},"21":{"text":"Hear now this, O foolish people, and without understanding; which have eyes, and see not; which have ears, and hear not:","ref":"Jeremiah 5:21","synthesized":"“Hear this, O foolish and senseless people, who have eyes but do not see, who have ears but do not hear.","sources":{"KJV":{"text":"Hear now this, O foolish people, and without understanding; which have eyes, and see not; which have ears, and hear not:"},"BSB":{"text":"“Hear this, O foolish and senseless people, who have eyes but do not see, who have ears but do not hear."},"TANAKH":{"text":"Hear now this, O foolish people, and without understanding, that have eyes, and see not, that have ears, and hear not:"},"HEBREW":{"text":"שִׁמְעוּ־נָ֣א זֹ֔את עַ֥ם סָכָ֖ל וְאֵ֣ין לֵ֑ב עֵינַ֤יִם לָהֶם֙ וְלֹ֣א יִרְא֔וּ אָזְנַ֥יִם לָהֶ֖ם וְלֹ֥א יִשְׁמָֽעוּ׃"}},"definableWords":["hear","people","see"],"peopleInVerse":[]},"22":{"text":"Fear ye not me? saith the LORD: will ye not tremble at my presence, which have placed the sand for the bound of the sea by a perpetual decree, that it cannot pass it: and though the waves thereof toss themselves, yet can they not prevail; though they roar, yet can they not pass over it?","ref":"Jeremiah 5:22","synthesized":"Do you not fear Me?” declares the LORD. “Do you not tremble before Me, the One who set the sand as the boundary for the sea, an enduring barrier it cannot cross? The waves surge, but they cannot prevail. They roar but cannot cross it.","sources":{"KJV":{"text":"Fear ye not me? saith the LORD: will ye not tremble at my presence, which have placed the sand for the bound of the sea by a perpetual decree, that it cannot pass it: and though the waves thereof toss themselves, yet can they not prevail; though they roar, yet can they not pass over it?"},"BSB":{"text":"Do you not fear Me?” declares the LORD. “Do you not tremble before Me, the One who set the sand as the boundary for the sea, an enduring barrier it cannot cross? The waves surge, but they cannot prevail. They roar but cannot cross it."},"TANAKH":{"text":"Fear ye not Me? saith HaShem; will ye not tremble at My presence? who have placed the sand for the bound of the sea, an everlasting ordinance, which it cannot pass; and though the waves thereof toss themselves, yet can they not prevail; though they roar, yet can they not pass over it."},"HEBREW":{"text":"הַאוֹתִ֨י לֹא־תִירָ֜אוּ נְאֻם־יְהֹוָ֗ה אִ֤ם מִפָּנַי֙ לֹ֣א תָחִ֔ילוּ אֲשֶׁר־שַׂ֤מְתִּי חוֹל֙ גְּב֣וּל לַיָּ֔ם חָק־עוֹלָ֖ם וְלֹ֣א יַעַבְרֶ֑נְהוּ וַיִּֽתְגָּעֲשׁוּ֙ וְלֹ֣א יוּכָ֔לוּ וְהָמ֥וּ גַלָּ֖יו וְלֹ֥א יַעַבְרֻֽנְהוּ׃"}},"definableWords":["fear","LORD","one","sea"],"peopleInVerse":[],"themesInVerse":["fear_of_lord"]},"23":{"text":"But this people hath a revolting and a rebellious heart; they are revolted and gone.","ref":"Jeremiah 5:23","synthesized":"But these people have stubborn and rebellious hearts. They have turned aside and gone away.","sources":{"KJV":{"text":"But this people hath a revolting and a rebellious heart; they are revolted and gone."},"BSB":{"text":"But these people have stubborn and rebellious hearts. They have turned aside and gone away."},"TANAKH":{"text":"But this people hath a revolting and a rebellious heart; they are revolted, and gone."},"HEBREW":{"text":"וְלָעָ֤ם הַזֶּה֙ הָיָ֔ה לֵ֖ב סוֹרֵ֣ר וּמוֹרֶ֑ה סָ֖רוּ וַיֵּלֵֽכוּ׃"}},"definableWords":["people"],"peopleInVerse":[]},"24":{"text":"Neither say they in their heart, Let us now fear the LORD our God, that giveth rain, both the former and the latter, in his season: he reserveth unto us the appointed weeks of the harvest.","ref":"Jeremiah 5:24","synthesized":"They have not said in their hearts, ‘Let us fear the LORD our God, who gives the rains, both autumn and spring, in season, who keeps for us the appointed weeks of harvest.’","sources":{"KJV":{"text":"Neither say they in their heart, Let us now fear the LORD our God, that giveth rain, both the former and the latter, in his season: he reserveth unto us the appointed weeks of the harvest."},"BSB":{"text":"They have not said in their hearts, ‘Let us fear the LORD our God, who gives the rains, both autumn and spring, in season, who keeps for us the appointed weeks of harvest.’"},"TANAKH":{"text":"Neither say they in their heart: 'Let us now fear HaShem our G-d, that giveth the former rain, and the latter in due season; that keepeth for us the appointed weeks of the harvest.'"},"HEBREW":{"text":"וְלֹֽא־אָמְר֣וּ בִלְבָבָ֗ם נִ֤ירָא נָא֙ אֶת־יְהוָ֣ה אֱלֹהֵ֔ינוּ הַנֹּתֵ֗ן גֶּ֛שֶׁם וירה יוֹרֶ֥ה וּמַלְק֖וֹשׁ בְּעִתּ֑וֹ שְׁבֻע֛וֹת חֻקּ֥וֹת קָצִ֖יר יִשְׁמָר־לָֽנוּ׃"}},"definableWords":["fear","LORD","God"],"peopleInVerse":[],"themesInVerse":["bread_water_life","fear_of_lord"]},"25":{"text":"Your iniquities have turned away these things, and your sins have withholden good things from you.","ref":"Jeremiah 5:25","synthesized":"Your iniquities have diverted these from you; your sins have deprived you of My bounty.","sources":{"KJV":{"text":"Your iniquities have turned away these things, and your sins have withholden good things from you."},"BSB":{"text":"Your iniquities have diverted these from you; your sins have deprived you of My bounty."},"TANAKH":{"text":"Your iniquities have turned away these things, and your sins have withholden good from you."},"HEBREW":{"text":"עֲוֺנוֹתֵיכֶ֖ם הִטּוּ־אֵ֑לֶּה וְחַטֹּ֣אותֵיכֶ֔ם מָנְע֥וּ הַטּ֖וֹב מִכֶּֽם׃"}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"For among my people are found wicked men: they lay wait, as he that setteth snares; they set a trap, they catch men.","ref":"Jeremiah 5:26","synthesized":"For among My people are wicked men; they watch like fowlers lying in wait; they set a trap to catch men.","sources":{"KJV":{"text":"For among my people are found wicked men: they lay wait, as he that setteth snares; they set a trap, they catch men."},"BSB":{"text":"For among My people are wicked men; they watch like fowlers lying in wait; they set a trap to catch men."},"TANAKH":{"text":"For among My people are found wicked men; they pry, as fowlers lie in wait; they set a trap, they catch men."},"HEBREW":{"text":"כִּי־נִמְצְא֥וּ בְעַמִּ֖י רְשָׁעִ֑ים יָשׁוּר֙ כְּשַׁ֣ךְ יְקוּשִׁ֔ים הִצִּ֥יבוּ מַשְׁחִ֖ית אֲנָשִׁ֥ים יִלְכֹּֽדוּ׃"}},"definableWords":["people","men","wait"],"peopleInVerse":[],"themesInVerse":["hope"]},"27":{"text":"As a cage is full of birds, so are their houses full of deceit: therefore they are become great, and waxen rich.","ref":"Jeremiah 5:27","synthesized":"Like cages full of birds, so their houses are full of deceit. Therefore they have become powerful and rich.","sources":{"KJV":{"text":"As a cage is full of birds, so are their houses full of deceit: therefore they are become great, and waxen rich."},"BSB":{"text":"Like cages full of birds, so their houses are full of deceit. Therefore they have become powerful and rich."},"TANAKH":{"text":"As a cage is full of birds, so are their houses full of deceit; therefore they are become great, and waxen rich;"},"HEBREW":{"text":"כִּכְלוּב֙ מָ֣לֵא ע֔וֹף כֵּ֥ן בָּתֵּיהֶ֖ם מְלֵאִ֣ים מִרְמָ֑ה עַל־כֵּ֥ן גָּדְל֖וּ וַֽיַּעֲשִֽׁירוּ׃"}},"definableWords":["birds"],"peopleInVerse":[]},"28":{"text":"They are waxen fat, they shine: yea, they overpass the deeds of the wicked: they judge not the cause, the cause of the fatherless, yet they prosper; and the right of the needy do they not judge.","ref":"Jeremiah 5:28","synthesized":"They have grown fat and sleek, and have excelled in the deeds of the wicked. They have not taken up the cause of the fatherless, that they might prosper; nor have they defended the rights of the needy.","sources":{"KJV":{"text":"They are waxen fat, they shine: yea, they overpass the deeds of the wicked: they judge not the cause, the cause of the fatherless, yet they prosper; and the right of the needy do they not judge."},"BSB":{"text":"They have grown fat and sleek, and have excelled in the deeds of the wicked. They have not taken up the cause of the fatherless, that they might prosper; nor have they defended the rights of the needy."},"TANAKH":{"text":"They are waxen fat, they are become sleek; yea, they overpass in deeds of wickedness; they plead not the cause, the cause of the fatherless, that they might make it to prosper; and the right of the needy do they not judge."},"HEBREW":{"text":"שָׁמְנ֣וּ עָשְׁת֗וּ גַּ֚ם עָֽבְר֣וּ דִבְרֵי־רָ֔ע דִּ֣ין לֹא־דָ֔נוּ דִּ֥ין יָת֖וֹם וְיַצְלִ֑יחוּ וּמִשְׁפַּ֥ט אֶבְיוֹנִ֖ים לֹ֥א שָׁפָֽטוּ׃"}},"definableWords":[],"peopleInVerse":[]},"29":{"text":"Shall I not visit for these things? saith the LORD: shall not my soul be avenged on such a nation as this?","ref":"Jeremiah 5:29","synthesized":"Should I not punish them for these things?” declares the LORD. “Should I not avenge Myself on such a nation as this?","sources":{"KJV":{"text":"Shall I not visit for these things? saith the LORD: shall not my soul be avenged on such a nation as this?"},"BSB":{"text":"Should I not punish them for these things?” declares the LORD. “Should I not avenge Myself on such a nation as this?"},"TANAKH":{"text":"Shall I not punish for these things? saith HaShem; shall not My soul be avenged on such a nation as this?"},"HEBREW":{"text":"הַֽעַל־אֵ֥לֶּה לֹֽא־אֶפְקֹ֖ד נְאֻם־יְהֹוָ֑ה אִ֚ם בְּג֣וֹי אֲשֶׁר־כָּזֶ֔ה לֹ֥א תִתְנַקֵּ֖ם נַפְשִֽׁי׃"}},"definableWords":["LORD","nation"],"peopleInVerse":[]},"30":{"text":"A wonderful and horrible thing is committed in the land;","ref":"Jeremiah 5:30","synthesized":"A horrible and shocking thing has happened in the land.","sources":{"KJV":{"text":"A wonderful and horrible thing is committed in the land;"},"BSB":{"text":"A horrible and shocking thing has happened in the land."},"TANAKH":{"text":"An appalling and horrible thing is come to pass in the land:"},"HEBREW":{"text":"שַׁמָּה֙ וְשַׁ֣עֲרוּרָ֔ה נִהְיְתָ֖ה בָּאָֽרֶץ׃"}},"definableWords":["land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"31":{"text":"The prophets prophesy falsely, and the priests bear rule by their means; and my people love to have it so: and what will ye do in the end thereof?","ref":"Jeremiah 5:31","synthesized":"The prophets prophesy falsely, and the priests rule by their own authority. My people love it so, but what will you do in the end?","sources":{"KJV":{"text":"The prophets prophesy falsely, and the priests bear rule by their means; and my people love to have it so: and what will ye do in the end thereof?"},"BSB":{"text":"The prophets prophesy falsely, and the priests rule by their own authority. My people love it so, but what will you do in the end?"},"TANAKH":{"text":"The prophets prophesy in the service of falsehood, and the priests bear rule at their beck; and My people love to have it so; what then will ye do in the end thereof?"},"HEBREW":{"text":"הַנְּבִיאִ֞ים נִבְּא֣וּ־בַשֶּׁ֗קֶר וְהַכֹּהֲנִים֙ יִרְדּ֣וּ עַל־יְדֵיהֶ֔ם וְעַמִּ֖י אָ֣הֲבוּ כֵ֑ן וּמַֽה־תַּעֲשׂ֖וּ לְאַחֲרִיתָֽהּ׃"}},"definableWords":["rule","people","love"],"peopleInVerse":[],"themesInVerse":["kingdom_of_god","love"]}}},"6":{"chapter":"6","title":"STAND IN THE WAYS AND SEE — ASK FOR THE OLD PATHS","verses":{"1":{"text":"O ye children of Benjamin, gather yourselves to flee out of the midst of Jerusalem, and blow the trumpet in Tekoa, and set up a sign of fire in Bethhaccerem: for evil appeareth out of the north, and great destruction.","ref":"Jeremiah 6:1","synthesized":"“Run for cover, O sons of Benjamin; flee from Jerusalem! Sound the ram’s horn in Tekoa; send up a signal over Beth-haccherem, for disaster looms from the north, even great destruction.","sources":{"KJV":{"text":"O ye children of Benjamin, gather yourselves to flee out of the midst of Jerusalem, and blow the trumpet in Tekoa, and set up a sign of fire in Bethhaccerem: for evil appeareth out of the north, and great destruction."},"BSB":{"text":"“Run for cover, O sons of Benjamin; flee from Jerusalem! Sound the ram’s horn in Tekoa; send up a signal over Beth-haccherem, for disaster looms from the north, even great destruction."},"TANAKH":{"text":"Put yourselves under covert, ye children of Benjamin, away from the midst of Jerusalem, and blow the horn in Tekoa, and set up a signal on Beth-cherem; for evil looketh forth from the north, and a great destruction."},"HEBREW":{"text":"הָעִ֣זוּ ׀ בְּנֵ֣י בִניָמִ֗ן מִקֶּ֙רֶב֙ יְר֣וּשָׁלִַ֔ם וּבִתְק֙וֹעַ֙ תִּקְע֣וּ שׁוֹפָ֔ר וְעַל־בֵּ֥ית הַכֶּ֖רֶם שְׂא֣וּ מַשְׂאֵ֑ת כִּ֥י רָעָ֛ה נִשְׁקְפָ֥ה מִצָּפ֖וֹן וְשֶׁ֥בֶר גָּדֽוֹל׃"}},"definableWords":["run","sons","Benjamin","Jerusalem","great"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"2":{"text":"I have likened the daughter of Zion to a comely and delicate woman.","ref":"Jeremiah 6:2","synthesized":"Though she is beautiful and delicate, I will destroy the Daughter of Zion.","sources":{"KJV":{"text":"I have likened the daughter of Zion to a comely and delicate woman."},"BSB":{"text":"Though she is beautiful and delicate, I will destroy the Daughter of Zion."},"TANAKH":{"text":"The comely and delicate one, the daughter of Zion, will I cut off."},"HEBREW":{"text":"הַנָּוָה֙ וְהַמְּעֻנָּגָ֔ה דָּמִ֖יתִי בַּת־צִיּֽוֹן׃"}},"definableWords":["daughter","Zion"],"peopleInVerse":[],"placesInVerse":["Mount Zion"]},"3":{"text":"The shepherds with their flocks shall come unto her; they shall pitch their tents against her round about; they shall feed every one in his place.","ref":"Jeremiah 6:3","synthesized":"Shepherds and their flocks will come against her; they will pitch their tents all around her, each tending his own portion:","sources":{"KJV":{"text":"The shepherds with their flocks shall come unto her; they shall pitch their tents against her round about; they shall feed every one in his place."},"BSB":{"text":"Shepherds and their flocks will come against her; they will pitch their tents all around her, each tending his own portion:"},"TANAKH":{"text":"Shepherds with their flocks come unto her; they pitch their tents against her round about; they feed bare every one what is nigh at hand."},"HEBREW":{"text":"אֵלֶ֛יהָ יָבֹ֥אוּ רֹעִ֖ים וְעֶדְרֵיהֶ֑ם תָּקְע֨וּ עָלֶ֤יהָ אֹהָלִים֙ סָבִ֔יב רָע֖וּ אִ֥ישׁ אֶת־יָדֽוֹ׃"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Prepare ye war against her; arise, and let us go up at noon. Woe unto us! for the day goeth away, for the shadows of the evening are stretched out.","ref":"Jeremiah 6:4","synthesized":"‘Prepare for battle against her; rise up, let us attack at noon. Woe to us, for the daylight is fading; the evening shadows grow long.","sources":{"KJV":{"text":"Prepare ye war against her; arise, and let us go up at noon. Woe unto us! for the day goeth away, for the shadows of the evening are stretched out."},"BSB":{"text":"‘Prepare for battle against her; rise up, let us attack at noon. Woe to us, for the daylight is fading; the evening shadows grow long."},"TANAKH":{"text":"'Prepare ye war against her; arise, and let us go up at noon!' 'Woe unto us! for the day declineth, for the shadows of the evening are stretched out!'"},"HEBREW":{"text":"קַדְּשׁ֤וּ עָלֶ֙יהָ֙ מִלְחָמָ֔ה ק֖וּמוּ וְנַעֲלֶ֣ה בַֽצָּהֳרָ֑יִם א֥וֹי לָ֙נוּ֙ כִּי־פָנָ֣ה הַיּ֔וֹם כִּ֥י יִנָּט֖וּ צִלְלֵי־עָֽרֶב׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["resurrection","spiritual_warfare"]},"5":{"text":"Arise, and let us go by night, and let us destroy her palaces.","ref":"Jeremiah 6:5","synthesized":"Rise up, let us attack by night and destroy her fortresses!’”","sources":{"KJV":{"text":"Arise, and let us go by night, and let us destroy her palaces."},"BSB":{"text":"Rise up, let us attack by night and destroy her fortresses!’”"},"TANAKH":{"text":"'Arise, and let us go up by night, and let us destroy her palaces.'"},"HEBREW":{"text":"ק֚וּמוּ וְנַעֲלֶ֣ה בַלָּ֔יְלָה וְנַשְׁחִ֖יתָה אַרְמְנוֹתֶֽיהָ׃"}},"definableWords":["night"],"peopleInVerse":[],"themesInVerse":["resurrection"]},"6":{"text":"For thus hath the LORD of hosts said, Hew ye down trees, and cast a mount against Jerusalem: this is the city to be visited; she is wholly oppression in the midst of her.","ref":"Jeremiah 6:6","synthesized":"For this is what the LORD of Hosts says:  “Cut down the trees and raise a siege ramp against Jerusalem. This city must be punished; there is nothing but oppression in her midst.","sources":{"KJV":{"text":"For thus hath the LORD of hosts said, Hew ye down trees, and cast a mount against Jerusalem: this is the city to be visited; she is wholly oppression in the midst of her."},"BSB":{"text":"For this is what the LORD of Hosts says:  “Cut down the trees and raise a siege ramp against Jerusalem. This city must be punished; there is nothing but oppression in her midst."},"TANAKH":{"text":"For thus hath HaShem of hosts said: hew ye down her trees, and cast up a mound against Jerusalem; this is the city to be punished; everywhere there is oppression in the midst of her."},"HEBREW":{"text":"כִּ֣י כֹ֤ה אָמַר֙ יְהוָ֣ה צְבָא֔וֹת כִּרְת֣וּ עֵצָ֔ה וְשִׁפְכ֥וּ עַל־יְרוּשָׁלַ֖͏ִם סֹלְלָ֑ה הִ֚יא הָעִ֣יר הָפְקַ֔ד כֻּלָּ֖הּ עֹ֥שֶׁק בְּקִרְבָּֽהּ׃"}},"definableWords":["LORD","trees","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"7":{"text":"As a fountain casteth out her waters, so she casteth out her wickedness: violence and spoil is heard in her; before me continually is grief and wounds.","ref":"Jeremiah 6:7","synthesized":"As a well gushes its water, so she pours out her evil. Violence and destruction resound in her; sickness and wounds are ever before Me.","sources":{"KJV":{"text":"As a fountain casteth out her waters, so she casteth out her wickedness: violence and spoil is heard in her; before me continually is grief and wounds."},"BSB":{"text":"As a well gushes its water, so she pours out her evil. Violence and destruction resound in her; sickness and wounds are ever before Me."},"TANAKH":{"text":"As a cistern welleth with her waters, so she welleth with her wickedness; violence and spoil is heard in her; before Me continually is sickness and wounds."},"HEBREW":{"text":"כְּהָקִ֥יר בור בַּ֙יִר֙ מֵימֶ֔יהָ כֵּ֖ן הֵקֵ֣רָה רָעָתָ֑הּ חָמָ֣ס וָ֠שֹׁד יִשָּׁ֨מַע בָּ֧הּ עַל־פָּנַ֛י תָּמִ֖יד חֳלִ֥י וּמַכָּֽה׃"}},"definableWords":["water","evil"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"8":{"text":"Be thou instructed, O Jerusalem, lest my soul depart from thee; lest I make thee desolate, a land not inhabited.","ref":"Jeremiah 6:8","synthesized":"Be forewarned, O Jerusalem, or I will turn away from you; I will make you a desolation, a land without inhabitant.”","sources":{"KJV":{"text":"Be thou instructed, O Jerusalem, lest my soul depart from thee; lest I make thee desolate, a land not inhabited."},"BSB":{"text":"Be forewarned, O Jerusalem, or I will turn away from you; I will make you a desolation, a land without inhabitant.”"},"TANAKH":{"text":"Be thou corrected, O Jerusalem, lest My soul be alienated from thee, lest I make thee desolate, a land not inhabited."},"HEBREW":{"text":"הִוָּסְרִי֙ יְר֣וּשָׁלִַ֔ם פֶּן־תֵּקַ֥ע נַפְשִׁ֖י מִמֵּ֑ךְ פֶּן־אֲשִׂימֵ֣ךְ שְׁמָמָ֔ה אֶ֖רֶץ ל֥וֹא נוֹשָֽׁבָה׃"}},"definableWords":["Jerusalem","or","make","land"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["land_promise"]},"9":{"text":"Thus saith the LORD of hosts, They shall throughly glean the remnant of Israel as a vine: turn back thine hand as a grapegatherer into the baskets.","ref":"Jeremiah 6:9","synthesized":"This is what the LORD of Hosts says:  “Glean the remnant of Israel as thoroughly as a vine. Pass your hand once more like a grape gatherer over the branches.”","sources":{"KJV":{"text":"Thus saith the LORD of hosts, They shall throughly glean the remnant of Israel as a vine: turn back thine hand as a grapegatherer into the baskets."},"BSB":{"text":"This is what the LORD of Hosts says:  “Glean the remnant of Israel as thoroughly as a vine. Pass your hand once more like a grape gatherer over the branches.”"},"TANAKH":{"text":"Thus saith HaShem of hosts: They shall thoroughly glean as a vine the remnant of Israel; turn again thy hand as a grape-gatherer upon the shoots."},"HEBREW":{"text":"כֹּ֤ה אָמַר֙ יְהֹוָ֣ה צְבָא֔וֹת עוֹלֵ֛ל יְעוֹלְל֥וּ כַגֶּ֖פֶן שְׁאֵרִ֣ית יִשְׂרָאֵ֑ל הָשֵׁב֙ יָדְךָ֔ כְּבוֹצֵ֖ר עַל־סַלְסִלּֽוֹת׃"}},"definableWords":["LORD","remnant","Israel"],"peopleInVerse":[],"themesInVerse":["exile_return","vine_branches"]},"10":{"text":"To whom shall I speak, and give warning, that they may hear? behold, their ear is uncircumcised, and they cannot hearken: behold, the word of the LORD is unto them a reproach; they have no delight in it.","ref":"Jeremiah 6:10","synthesized":"To whom can I give this warning? Who will listen to me? Look, their ears are closed, so they cannot hear. See, the word of the LORD has become offensive to them; they find no pleasure in it.","sources":{"KJV":{"text":"To whom shall I speak, and give warning, that they may hear? behold, their ear is uncircumcised, and they cannot hearken: behold, the word of the LORD is unto them a reproach; they have no delight in it."},"BSB":{"text":"To whom can I give this warning? Who will listen to me? Look, their ears are closed, so they cannot hear. See, the word of the LORD has become offensive to them; they find no pleasure in it."},"TANAKH":{"text":"To whom shall I speak and give warning, that they may hear? Behold, their ear is dull, and they cannot attend; behold, the word of HaShem is become unto them a reproach, they have no delight in it."},"HEBREW":{"text":"עַל־מִ֨י אֲדַבְּרָ֤ה וְאָעִ֙ידָה֙ וְיִשְׁמָ֔עוּ הִנֵּה֙ עֲרֵלָ֣ה אָזְנָ֔ם וְלֹ֥א יוּכְל֖וּ לְהַקְשִׁ֑יב הִנֵּ֣ה דְבַר־יְהוָ֗ה הָיָ֥ה לָהֶ֛ם לְחֶרְפָּ֖ה לֹ֥א יַחְפְּצוּ־בֽוֹ׃"}},"definableWords":["hear","see","word","LORD"],"peopleInVerse":[]},"11":{"text":"Therefore I am full of the fury of the LORD; I am weary with holding in: I will pour it out upon the children abroad, and upon the assembly of young men together: for even the husband with the wife shall be taken, the aged with him that is full of days.","ref":"Jeremiah 6:11","synthesized":"But I am full of the LORD’s wrath; I am tired of holding it back.   “Pour it out on the children in the street, and on the young men gathered together. For both husband and wife will be captured, the old and the very old alike.","sources":{"KJV":{"text":"Therefore I am full of the fury of the LORD; I am weary with holding in: I will pour it out upon the children abroad, and upon the assembly of young men together: for even the husband with the wife shall be taken, the aged with him that is full of days."},"BSB":{"text":"But I am full of the LORD’s wrath; I am tired of holding it back.   “Pour it out on the children in the street, and on the young men gathered together. For both husband and wife will be captured, the old and the very old alike."},"TANAKH":{"text":"Therefore I am full of the fury of HaShem, I am weary with holding in: pour it out upon the babes in the street, and upon the assembly of young men together; for even the husband with the wife shall be taken, the aged with him that is full of days."},"HEBREW":{"text":"וְאֵת֩ חֲמַ֨ת יְהוָ֤ה ׀ מָלֵ֙אתִי֙ נִלְאֵ֣יתִי הָכִ֔יל שְׁפֹ֤ךְ עַל־עוֹלָל֙ בַּח֔וּץ וְעַ֛ל ס֥וֹד בַּחוּרִ֖ים יַחְדָּ֑ו כִּֽי־גַם־אִ֤ישׁ עִם־אִשָּׁה֙ יִלָּכֵ֔דוּ זָקֵ֖ן עִם־מְלֵ֥א יָמִֽים׃"}},"definableWords":["LORD","wrath","men","husband","wife"],"peopleInVerse":[],"themesInVerse":["judgment","marriage_bride"]},"12":{"text":"And their houses shall be turned unto others, with their fields and wives together: for I will stretch out my hand upon the inhabitants of the land, saith the LORD.","ref":"Jeremiah 6:12","synthesized":"Their houses will be turned over to others, their fields and wives as well, for I will stretch out My hand against the inhabitants of the land,” declares the LORD.","sources":{"KJV":{"text":"And their houses shall be turned unto others, with their fields and wives together: for I will stretch out my hand upon the inhabitants of the land, saith the LORD."},"BSB":{"text":"Their houses will be turned over to others, their fields and wives as well, for I will stretch out My hand against the inhabitants of the land,” declares the LORD."},"TANAKH":{"text":"And their houses shall be turned unto others, their fields and their wives together; for I will stretch out My hand upon the inhabitants of the land, saith HaShem."},"HEBREW":{"text":"וְנָסַ֤בּוּ בָֽתֵּיהֶם֙ לַאֲחֵרִ֔ים שָׂד֥וֹת וְנָשִׁ֖ים יַחְדָּ֑ו כִּֽי־אַטֶּ֧ה אֶת־יָדִ֛י עַל־יֹשְׁבֵ֥י הָאָ֖רֶץ נְאֻם־יְהוָֽה׃"}},"definableWords":["land","LORD"],"peopleInVerse":[],"themesInVerse":["bread_water_life","land_promise"]},"13":{"text":"For from the least of them even unto the greatest of them every one is given to covetousness; and from the prophet even unto the priest every one dealeth falsely.","ref":"Jeremiah 6:13","synthesized":"“For from the least of them to the greatest, all are greedy for gain; from prophet to priest, all practice deceit.","sources":{"KJV":{"text":"For from the least of them even unto the greatest of them every one is given to covetousness; and from the prophet even unto the priest every one dealeth falsely."},"BSB":{"text":"“For from the least of them to the greatest, all are greedy for gain; from prophet to priest, all practice deceit."},"TANAKH":{"text":"For from the least of them even unto the greatest of them every one is greedy for gain; and from the prophet even unto the priest every one dealeth falsely."},"HEBREW":{"text":"כִּ֤י מִקְּטַנָּם֙ וְעַד־גְּדוֹלָ֔ם כֻּלּ֖וֹ בּוֹצֵ֣עַ בָּ֑צַע וּמִנָּבִיא֙ וְעַד־כֹּהֵ֔ן כֻּלּ֖וֹ עֹ֥שֶׂה שָּֽׁקֶר׃"}},"definableWords":["prophet","priest"],"peopleInVerse":[],"themesInVerse":["kingdom_priesthood"]},"14":{"text":"They have healed also the hurt of the daughter of my people slightly, saying, Peace, peace; when there is no peace.","ref":"Jeremiah 6:14","synthesized":"They dress the wound of My people with very little care, saying, ‘Peace, peace,’ when there is no peace at all.","sources":{"KJV":{"text":"They have healed also the hurt of the daughter of my people slightly, saying, Peace, peace; when there is no peace."},"BSB":{"text":"They dress the wound of My people with very little care, saying, ‘Peace, peace,’ when there is no peace at all."},"TANAKH":{"text":"They have healed also the hurt of My people lightly, saying: 'Peace, peace', when there is no peace."},"HEBREW":{"text":"וַֽיְרַפְּא֞וּ אֶת־שֶׁ֤בֶר עַמִּי֙ עַל־נְקַלָּ֔ה לֵאמֹ֖ר שָׁל֣וֹם ׀ שָׁל֑וֹם וְאֵ֖ין שָׁלֽוֹם׃"}},"definableWords":["people","peace"],"peopleInVerse":[],"themesInVerse":["peace"]},"15":{"text":"Were they ashamed when they had committed abomination? nay, they were not at all ashamed, neither could they blush: therefore they shall fall among them that fall: at the time that I visit them they shall be cast down, saith the LORD.","ref":"Jeremiah 6:15","synthesized":"Are they ashamed of the abomination they have committed? No, they have no shame at all; they do not even know how to blush. So they will fall among the fallen; when I punish them, they will collapse,” says the LORD.","sources":{"KJV":{"text":"Were they ashamed when they had committed abomination? nay, they were not at all ashamed, neither could they blush: therefore they shall fall among them that fall: at the time that I visit them they shall be cast down, saith the LORD."},"BSB":{"text":"Are they ashamed of the abomination they have committed? No, they have no shame at all; they do not even know how to blush. So they will fall among the fallen; when I punish them, they will collapse,” says the LORD."},"TANAKH":{"text":"They shall be put to shame because they have committed abomination; yea, they are not at all ashamed, neither know they how to blush; therefore they shall fall among them that fall, at the time that I punish them they shall stumble, saith HaShem."},"HEBREW":{"text":"הֹבִ֕ישׁוּ כִּ֥י תוֹעֵבָ֖ה עָשׂ֑וּ גַּם־בּ֣וֹשׁ לֹֽא־יֵב֗וֹשׁוּ גַּם־הַכְלִים֙ לֹ֣א יָדָ֔עוּ לָכֵ֞ן יִפְּל֧וּ בַנֹּפְלִ֛ים בְּעֵת־פְּקַדְתִּ֥ים יִכָּשְׁל֖וּ אָמַ֥ר יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"16":{"text":"Thus saith the LORD, Stand ye in the ways, and see, and ask for the old paths, where is the good way, and walk therein, and ye shall find rest for your souls. But they said, We will not walk therein.","ref":"Jeremiah 6:16","synthesized":"This is what the LORD says:  “Stand at the crossroads and look. Ask for the ancient paths: ‘Where is the good way?’ Then walk in it, and you will find rest for your souls. But they said, ‘We will not walk in it!’","sources":{"KJV":{"text":"Thus saith the LORD, Stand ye in the ways, and see, and ask for the old paths, where is the good way, and walk therein, and ye shall find rest for your souls. But they said, We will not walk therein."},"BSB":{"text":"This is what the LORD says:  “Stand at the crossroads and look. Ask for the ancient paths: ‘Where is the good way?’ Then walk in it, and you will find rest for your souls. But they said, ‘We will not walk in it!’"},"TANAKH":{"text":"Thus saith HaShem: stand ye in the ways and see, and ask for the old paths, where is the good way, and walk therein, and ye shall find rest for your souls. But they said: 'We will not walk therein.'"},"HEBREW":{"text":"כֹּ֣ה אָמַ֣ר יְהוָ֡ה עִמְדוּ֩ עַל־דְּרָכִ֨ים וּרְא֜וּ וְשַׁאֲל֣וּ ׀ לִנְתִב֣וֹת עוֹלָ֗ם אֵי־זֶ֨ה דֶ֤רֶךְ הַטּוֹב֙ וּלְכוּ־בָ֔הּ וּמִצְא֥וּ מַרְגּ֖וֹעַ לְנַפְשְׁכֶ֑ם וַיֹּאמְר֖וּ לֹ֥א נֵלֵֽךְ׃"}},"definableWords":["LORD","stand","good","way","walk","rest"],"peopleInVerse":[],"themesInVerse":["peace","sabbath_rest"]},"17":{"text":"Also I set watchmen over you, saying, Hearken to the sound of the trumpet. But they said, We will not hearken.","ref":"Jeremiah 6:17","synthesized":"I appointed watchmen over you and said, ‘Listen for the sound of the ram’s horn.’ But they answered, ‘We will not listen!’","sources":{"KJV":{"text":"Also I set watchmen over you, saying, Hearken to the sound of the trumpet. But they said, We will not hearken."},"BSB":{"text":"I appointed watchmen over you and said, ‘Listen for the sound of the ram’s horn.’ But they answered, ‘We will not listen!’"},"TANAKH":{"text":"And I set watchmen over you: 'Attend to the sound of the horn', but they said: 'We will not attend.'"},"HEBREW":{"text":"וַהֲקִמֹתִ֤י עֲלֵיכֶם֙ צֹפִ֔ים הַקְשִׁ֖יבוּ לְק֣וֹל שׁוֹפָ֑ר וַיֹּאמְר֖וּ לֹ֥א נַקְשִֽׁיב׃"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"Therefore hear, ye nations, and know, O congregation, what is among them.","ref":"Jeremiah 6:18","synthesized":"Therefore hear, O nations, and learn, O congregations, what will happen to them.","sources":{"KJV":{"text":"Therefore hear, ye nations, and know, O congregation, what is among them."},"BSB":{"text":"Therefore hear, O nations, and learn, O congregations, what will happen to them."},"TANAKH":{"text":"Therefore hear, ye nations, and know, O congregation, what is against them."},"HEBREW":{"text":"לָכֵ֖ן שִׁמְע֣וּ הַגּוֹיִ֑ם וּדְעִ֥י עֵדָ֖ה אֶת־אֲשֶׁר־בָּֽם׃"}},"definableWords":["hear","nations"],"peopleInVerse":[]},"19":{"text":"Hear, O earth: behold, I will bring evil upon this people, even the fruit of their thoughts, because they have not hearkened unto my words, nor to my law, but rejected it.","ref":"Jeremiah 6:19","synthesized":"Hear, O earth! I am bringing disaster on this people, the fruit of their own schemes, because they have paid no attention to My word and have rejected My instruction.","sources":{"KJV":{"text":"Hear, O earth: behold, I will bring evil upon this people, even the fruit of their thoughts, because they have not hearkened unto my words, nor to my law, but rejected it."},"BSB":{"text":"Hear, O earth! I am bringing disaster on this people, the fruit of their own schemes, because they have paid no attention to My word and have rejected My instruction."},"TANAKH":{"text":"Hear, O earth: behold, I will bring evil upon this people, even the fruit of their thoughts, because they have not attended unto My words, and as for My teaching, they have rejected it."},"HEBREW":{"text":"שִׁמְעִ֣י הָאָ֔רֶץ הִנֵּ֨ה אָנֹכִ֜י מֵבִ֥יא רָעָ֛ה אֶל־הָעָ֥ם הַזֶּ֖ה פְּרִ֣י מַחְשְׁבוֹתָ֑ם כִּ֤י עַל־דְּבָרַי֙ לֹ֣א הִקְשִׁ֔יבוּ וְתוֹרָתִ֖י וַיִּמְאֲסוּ־בָֽהּ׃"}},"definableWords":["hear","earth","people","word"],"peopleInVerse":[],"themesInVerse":["vine_branches"]},"20":{"text":"To what purpose cometh there to me incense from Sheba, and the sweet cane from a far country? your burnt offerings are not acceptable, nor your sacrifices sweet unto me.","ref":"Jeremiah 6:20","synthesized":"What use to Me is frankincense from Sheba or sweet cane from a distant land? Your burnt offerings are not acceptable; your sacrifices do not please Me.”","sources":{"KJV":{"text":"To what purpose cometh there to me incense from Sheba, and the sweet cane from a far country? your burnt offerings are not acceptable, nor your sacrifices sweet unto me."},"BSB":{"text":"What use to Me is frankincense from Sheba or sweet cane from a distant land? Your burnt offerings are not acceptable; your sacrifices do not please Me.”"},"TANAKH":{"text":"To what purpose is to Me the frankincense that cometh from Sheba, and the sweet cane, from a far country? Your burnt-offerings are not acceptable, nor your sacrifices pleasing unto Me."},"HEBREW":{"text":"לָמָּה־זֶּ֨ה לִ֤י לְבוֹנָה֙ מִשְּׁבָ֣א תָב֔וֹא וְקָנֶ֥ה הַטּ֖וֹב מֵאֶ֣רֶץ מֶרְחָ֑ק עֹלֽוֹתֵיכֶם֙ לֹ֣א לְרָצ֔וֹן וְזִבְחֵיכֶ֖ם לֹא־עָ֥רְבוּ לִֽי׃"}},"definableWords":["or","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"21":{"text":"Therefore thus saith the LORD, Behold, I will lay stumblingblocks before this people, and the fathers and the sons together shall fall upon them; the neighbour and his friend shall perish.","ref":"Jeremiah 6:21","synthesized":"Therefore this is what the LORD says:  “I will lay stumbling blocks before this people; fathers and sons alike will be staggered; friends and neighbors will perish.”","sources":{"KJV":{"text":"Therefore thus saith the LORD, Behold, I will lay stumblingblocks before this people, and the fathers and the sons together shall fall upon them; the neighbour and his friend shall perish."},"BSB":{"text":"Therefore this is what the LORD says:  “I will lay stumbling blocks before this people; fathers and sons alike will be staggered; friends and neighbors will perish.”"},"TANAKH":{"text":"Therefore thus saith HaShem: Behold, I will lay stumblingblocks before this people, and the fathers and the sons together shall stumble against them, the neighbour and his friend, and they shall perish."},"HEBREW":{"text":"לָכֵ֗ן כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִנְנִ֥י נֹתֵ֛ן אֶל־הָעָ֥ם הַזֶּ֖ה מִכְשֹׁלִ֑ים וְכָ֣שְׁלוּ בָ֠ם אָב֨וֹת וּבָנִ֥ים יַחְדָּ֛ו שָׁכֵ֥ן וְרֵע֖וֹ יאבדו וְאָבָֽדוּ׃"}},"definableWords":["LORD","people","fathers","sons"],"peopleInVerse":[]},"22":{"text":"Thus saith the LORD, Behold, a people cometh from the north country, and a great nation shall be raised from the sides of the earth.","ref":"Jeremiah 6:22","synthesized":"This is what the LORD says:  “Behold, an army is coming from the land of the north; a great nation is stirred up from the ends of the earth.","sources":{"KJV":{"text":"Thus saith the LORD, Behold, a people cometh from the north country, and a great nation shall be raised from the sides of the earth."},"BSB":{"text":"This is what the LORD says:  “Behold, an army is coming from the land of the north; a great nation is stirred up from the ends of the earth."},"TANAKH":{"text":"Thus saith HaShem: Behold, a people cometh from the north country, and a great nation shall be roused from the uttermost parts of the earth."},"HEBREW":{"text":"כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִנֵּ֛ה עַ֥ם בָּ֖א מֵאֶ֣רֶץ צָפ֑וֹן וְג֣וֹי גָּד֔וֹל יֵע֖וֹר מִיַּרְכְּתֵי־אָֽרֶץ׃"}},"definableWords":["LORD","land","great","nation","earth"],"peopleInVerse":[],"themesInVerse":["land_promise","second_coming"]},"23":{"text":"They shall lay hold on bow and spear; they are cruel, and have no mercy; their voice roareth like the sea; and they ride upon horses, set in array as men for war against thee, O daughter of Zion.","ref":"Jeremiah 6:23","synthesized":"They grasp the bow and spear; they are cruel and merciless. Their voice roars like the sea, and they ride upon horses, lined up like men in formation against you, O Daughter of Zion.”","sources":{"KJV":{"text":"They shall lay hold on bow and spear; they are cruel, and have no mercy; their voice roareth like the sea; and they ride upon horses, set in array as men for war against thee, O daughter of Zion."},"BSB":{"text":"They grasp the bow and spear; they are cruel and merciless. Their voice roars like the sea, and they ride upon horses, lined up like men in formation against you, O Daughter of Zion.”"},"TANAKH":{"text":"They lay hold on bow and spear, they are cruel, and have no compassion; their voice is like the roaring sea, and they ride upon horses; set in array, as a man for war, against thee, O daughter of Zion."},"HEBREW":{"text":"קֶ֣שֶׁת וְכִיד֞וֹן יַחֲזִ֗יקוּ אַכְזָרִ֥י הוּא֙ וְלֹ֣א יְרַחֵ֔מוּ קוֹלָם֙ כַּיָּ֣ם יֶהֱמֶ֔ה וְעַל־סוּסִ֖ים יִרְכָּ֑בוּ עָר֗וּךְ כְּאִישׁ֙ לַמִּלְחָמָ֔ה עָלַ֖יִךְ בַּת־צִיּֽוֹן׃"}},"definableWords":["voice","sea","men","daughter","Zion"],"peopleInVerse":[],"placesInVerse":["Mount Zion"],"themesInVerse":["worship"]},"24":{"text":"We have heard the fame thereof: our hands wax feeble: anguish hath taken hold of us, and pain, as of a woman in travail.","ref":"Jeremiah 6:24","synthesized":"We have heard the report; our hands hang limp. Anguish has gripped us, pain like that of a woman in labor.","sources":{"KJV":{"text":"We have heard the fame thereof: our hands wax feeble: anguish hath taken hold of us, and pain, as of a woman in travail."},"BSB":{"text":"We have heard the report; our hands hang limp. Anguish has gripped us, pain like that of a woman in labor."},"TANAKH":{"text":"'We have heard the fame thereof, our hands wax feeble, anguish hath taken hold of us, and pain, as of a woman in travail.'"},"HEBREW":{"text":"שָׁמַ֥עְנוּ אֶת־שָׁמְע֖וֹ רָפ֣וּ יָדֵ֑ינוּ צָרָה֙ הֶחֱזִיקַ֔תְנוּ חִ֖יל כַּיּוֹלֵדָֽה׃"}},"definableWords":["woman"],"peopleInVerse":[],"themesInVerse":["suffering"]},"25":{"text":"Go not forth into the field, nor walk by the way; for the sword of the enemy and fear is on every side.","ref":"Jeremiah 6:25","synthesized":"Do not go out to the fields; do not walk the road. For the enemy has a sword; terror is on every side.","sources":{"KJV":{"text":"Go not forth into the field, nor walk by the way; for the sword of the enemy and fear is on every side."},"BSB":{"text":"Do not go out to the fields; do not walk the road. For the enemy has a sword; terror is on every side."},"TANAKH":{"text":"Go not forth into the field, nor walk by the way; for there is the sword of the enemy, and terror on every side."},"HEBREW":{"text":"אַל־תצאי תֵּֽצְאוּ֙ הַשָּׂדֶ֔ה וּבַדֶּ֖רֶךְ אַל־תלכי תֵּלֵ֑כוּ כִּ֚י חֶ֣רֶב לְאֹיֵ֔ב מָג֖וֹר מִסָּבִֽיב׃"}},"definableWords":["walk"],"peopleInVerse":[]},"26":{"text":"O daughter of my people, gird thee with sackcloth, and wallow thyself in ashes: make thee mourning, as for an only son, most bitter lamentation: for the spoiler shall suddenly come upon us.","ref":"Jeremiah 6:26","synthesized":"O daughter of my people, dress yourselves in sackcloth and roll in ashes. Mourn with bitter wailing, as you would for an only son, for suddenly the destroyer will come upon us.","sources":{"KJV":{"text":"O daughter of my people, gird thee with sackcloth, and wallow thyself in ashes: make thee mourning, as for an only son, most bitter lamentation: for the spoiler shall suddenly come upon us."},"BSB":{"text":"O daughter of my people, dress yourselves in sackcloth and roll in ashes. Mourn with bitter wailing, as you would for an only son, for suddenly the destroyer will come upon us."},"TANAKH":{"text":"O daughter of my people, gird thee with sackcloth, and wallow thyself in ashes; make thee mourning, as for an only son, most bitter lamentation; for the spoiler shall suddenly come upon us."},"HEBREW":{"text":"בַּת־עַמִּ֤י חִגְרִי־שָׂק֙ וְהִתְפַּלְּשִׁ֣י בָאֵ֔פֶר אֵ֤בֶל יָחִיד֙ עֲשִׂ֣י לָ֔ךְ מִסְפַּ֖ד תַּמְרוּרִ֑ים כִּ֣י פִתְאֹ֔ם יָבֹ֥א הַשֹּׁדֵ֖ד עָלֵֽינוּ׃"}},"definableWords":["daughter","people","son"],"peopleInVerse":[]},"27":{"text":"I have set thee for a tower and a fortress among my people, that thou mayest know and try their way.","ref":"Jeremiah 6:27","synthesized":"“I have appointed you to examine My people like ore, so you may know and try their ways.","sources":{"KJV":{"text":"I have set thee for a tower and a fortress among my people, that thou mayest know and try their way."},"BSB":{"text":"“I have appointed you to examine My people like ore, so you may know and try their ways."},"TANAKH":{"text":"I have made thee a tower and a fortress among My people; that thou mayest know and try their way."},"HEBREW":{"text":"בָּח֛וֹן נְתַתִּ֥יךָ בְעַמִּ֖י מִבְצָ֑ר וְתֵדַ֕ע וּבָחַנְתָּ֖ אֶת־דַּרְכָּֽם׃"}},"definableWords":["people"],"peopleInVerse":[]},"28":{"text":"They are all grievous revolters, walking with slanders: they are brass and iron; they are all corrupters.","ref":"Jeremiah 6:28","synthesized":"All are hardened rebels, walking around as slanderers. They are bronze and iron; all of them are corrupt.","sources":{"KJV":{"text":"They are all grievous revolters, walking with slanders: they are brass and iron; they are all corrupters."},"BSB":{"text":"All are hardened rebels, walking around as slanderers. They are bronze and iron; all of them are corrupt."},"TANAKH":{"text":"They are all grievous revolters, going about with slanders; they are brass and iron; they all of them deal corruptly."},"HEBREW":{"text":"כֻּלָּם֙ סָרֵ֣י סֽוֹרְרִ֔ים הֹלְכֵ֥י רָכִ֖יל נְחֹ֣שֶׁת וּבַרְזֶ֑ל כֻּלָּ֥ם מַשְׁחִיתִ֖ים הֵֽמָּה׃"}},"definableWords":[],"peopleInVerse":[]},"29":{"text":"The bellows are burned, the lead is consumed of the fire; the founder melteth in vain: for the wicked are not plucked away.","ref":"Jeremiah 6:29","synthesized":"The bellows blow fiercely, blasting away the lead with fire. The refining proceeds in vain, for the wicked are not purged.","sources":{"KJV":{"text":"The bellows are burned, the lead is consumed of the fire; the founder melteth in vain: for the wicked are not plucked away."},"BSB":{"text":"The bellows blow fiercely, blasting away the lead with fire. The refining proceeds in vain, for the wicked are not purged."},"TANAKH":{"text":"The bellows blow fiercely, the lead is consumed of the fire; in vain doth the founder refine, for the wicked are not separated."},"HEBREW":{"text":"נָחַ֣ר מַפֻּ֔חַ מאשתם מֵאֵ֖שׁ תַּ֣ם עֹפָ֑רֶת לַשָּׁוְא֙ צָרַ֣ף צָר֔וֹף וְרָעִ֖ים לֹ֥א נִתָּֽקוּ׃"}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"Reprobate silver shall men call them, because the LORD hath rejected them.","ref":"Jeremiah 6:30","synthesized":"They are called rejected silver, because the LORD has rejected them.”","sources":{"KJV":{"text":"Reprobate silver shall men call them, because the LORD hath rejected them."},"BSB":{"text":"They are called rejected silver, because the LORD has rejected them.”"},"TANAKH":{"text":"Refuse silver shall men call them, because HaShem hath rejected them."},"HEBREW":{"text":"כֶּ֣סֶף נִמְאָ֔ס קָרְא֖וּ לָהֶ֑ם כִּֽי־מָאַ֥ס יְהוָ֖ה בָּהֶֽם׃"}},"definableWords":["LORD"],"peopleInVerse":[]}}},"7":{"chapter":"7","title":"THE TEMPLE SERMON","verses":{"1":{"text":"The word that came to Jeremiah from the LORD, saying,","ref":"Jeremiah 7:1","synthesized":"This is the word that came to Jeremiah from the LORD, saying,","sources":{"KJV":{"text":"The word that came to Jeremiah from the LORD, saying,"},"BSB":{"text":"This is the word that came to Jeremiah from the LORD, saying,"},"TANAKH":{"text":"The word that came to Jeremiah from HaShem, saying:"},"HEBREW":{"text":"הַדָּבָר֙ אֲשֶׁ֣ר הָיָ֣ה אֶֽל־יִרְמְיָ֔הוּ מֵאֵ֥ת יְהוָ֖ה לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"2":{"text":"Stand in the gate of the LORD’s house, and proclaim there this word, and say, Hear the word of the LORD, all ye of Judah, that enter in at these gates to worship the LORD.","ref":"Jeremiah 7:2","synthesized":"“Stand in the gate of the house of the LORD and proclaim this message: Hear the word of the LORD, all you people of Judah who enter through these gates to worship the LORD.","sources":{"KJV":{"text":"Stand in the gate of the LORD’s house, and proclaim there this word, and say, Hear the word of the LORD, all ye of Judah, that enter in at these gates to worship the LORD."},"BSB":{"text":"“Stand in the gate of the house of the LORD and proclaim this message: Hear the word of the LORD, all you people of Judah who enter through these gates to worship the LORD."},"TANAKH":{"text":"Stand in the gate of HaShem'S house, and proclaim there this word, and say: Hear the word of HaShem, all ye of Judah, that enter in at these gates to worship HaShem."},"HEBREW":{"text":"עֲמֹ֗ד בְּשַׁ֙עַר֙ בֵּ֣ית יְהוָ֔ה וְקָרָ֣אתָ שָּׁ֔ם אֶת־הַדָּבָ֖ר הַזֶּ֑ה וְאָמַרְתָּ֞ שִׁמְע֣וּ דְבַר־יְהוָ֗ה כָּל־יְהוּדָה֙ הַבָּאִים֙ בַּשְּׁעָרִ֣ים הָאֵ֔לֶּה לְהִֽשְׁתַּחֲוֺ֖ת לַיהוָֽה׃"}},"definableWords":["stand","house","LORD","hear","word","Lord","people","Judah","worship"],"peopleInVerse":[],"themesInVerse":["worship"]},"3":{"text":"Thus saith the LORD of hosts, the God of Israel, Amend your ways and your doings, and I will cause you to dwell in this place.","ref":"Jeremiah 7:3","synthesized":"Thus says the LORD of Hosts, the God of Israel: Correct your ways and deeds, and I will let you live in this place.","sources":{"KJV":{"text":"Thus saith the LORD of hosts, the God of Israel, Amend your ways and your doings, and I will cause you to dwell in this place."},"BSB":{"text":"Thus says the LORD of Hosts, the God of Israel: Correct your ways and deeds, and I will let you live in this place."},"TANAKH":{"text":"Thus saith HaShem of hosts, the G-d of Israel: Amend your ways and your doings, and I will cause you to dwell in this place."},"HEBREW":{"text":"כֹּֽה־אָמַ֞ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל הֵיטִ֥יבוּ דַרְכֵיכֶ֖ם וּמַֽעַלְלֵיכֶ֑ם וַאֲשַׁכְּנָ֣ה אֶתְכֶ֔ם בַּמָּק֥וֹם הַזֶּֽה׃"}},"definableWords":["LORD","God","Israel","live"],"peopleInVerse":[]},"4":{"text":"Trust ye not in lying words, saying, The temple of the LORD, The temple of the LORD, The temple of the LORD, are these.","ref":"Jeremiah 7:4","synthesized":"Do not trust in deceptive words, chanting:  ‘This is the temple of the LORD, the temple of the LORD, the temple of the LORD.’","sources":{"KJV":{"text":"Trust ye not in lying words, saying, The temple of the LORD, The temple of the LORD, The temple of the LORD, are these."},"BSB":{"text":"Do not trust in deceptive words, chanting:  ‘This is the temple of the LORD, the temple of the LORD, the temple of the LORD.’"},"TANAKH":{"text":"Trust ye not in lying words, saying: 'The temple of HaShem, the temple of HaShem, the temple of HaShem, are these.'"},"HEBREW":{"text":"אַל־תִּבְטְח֣וּ לָכֶ֔ם אֶל־דִּבְרֵ֥י הַשֶּׁ֖קֶר לֵאמֹ֑ר הֵיכַ֤ל יְהוָה֙ הֵיכַ֣ל יְהוָ֔ה הֵיכַ֥ל יְהוָ֖ה הֵֽמָּה׃"}},"definableWords":["trust","temple","LORD","Lord"],"peopleInVerse":[],"themesInVerse":["faith","temple"]},"5":{"text":"For if ye throughly amend your ways and your doings; if ye throughly execute judgment between a man and his neighbour;","ref":"Jeremiah 7:5","synthesized":"For if you really correct your ways and deeds, if you act justly toward one another,","sources":{"KJV":{"text":"For if ye throughly amend your ways and your doings; if ye throughly execute judgment between a man and his neighbour;"},"BSB":{"text":"For if you really correct your ways and deeds, if you act justly toward one another,"},"TANAKH":{"text":"Nay, but if ye thoroughly amend your ways and your doings; if ye thoroughly execute justice between a man and his neighbour;"},"HEBREW":{"text":"כִּ֤י אִם־הֵיטֵיב֙ תֵּיטִ֔יבוּ אֶת־דַּרְכֵיכֶ֖ם וְאֶת־מַֽעַלְלֵיכֶ֑ם אִם־עָשׂ֤וֹ תַֽעֲשׂוּ֙ מִשְׁפָּ֔ט בֵּ֥ין אִ֖ישׁ וּבֵ֥ין רֵעֵֽהוּ׃"}},"definableWords":["one"],"peopleInVerse":[]},"6":{"text":"If ye oppress not the stranger, the fatherless, and the widow, and shed not innocent blood in this place, neither walk after other gods to your hurt:","ref":"Jeremiah 7:6","synthesized":"if you no longer oppress the foreigner and the fatherless and the widow, and if you no longer shed innocent blood in this place or follow other gods to your own harm,","sources":{"KJV":{"text":"If ye oppress not the stranger, the fatherless, and the widow, and shed not innocent blood in this place, neither walk after other gods to your hurt:"},"BSB":{"text":"if you no longer oppress the foreigner and the fatherless and the widow, and if you no longer shed innocent blood in this place or follow other gods to your own harm,"},"TANAKH":{"text":"if ye oppress not the stranger, the fatherless, and the widow, and shed not innocent blood in this place, neither walk after other gods to your hurt;"},"HEBREW":{"text":"גֵּ֣ר יָת֤וֹם וְאַלְמָנָה֙ לֹ֣א תַֽעֲשֹׁ֔קוּ וְדָ֣ם נָקִ֔י אַֽל־תִּשְׁפְּכ֖וּ בַּמָּק֣וֹם הַזֶּ֑ה וְאַחֲרֵ֨י אֱלֹהִ֧ים אֲחֵרִ֛ים לֹ֥א תֵלְכ֖וּ לְרַ֥ע לָכֶֽם׃"}},"definableWords":["widow","blood","or"],"peopleInVerse":[],"themesInVerse":["passover","sacrifice"]},"7":{"text":"Then will I cause you to dwell in this place, in the land that I gave to your fathers, for ever and ever.","ref":"Jeremiah 7:7","synthesized":"then I will let you live in this place, in the land that I gave to your fathers forever and ever.","sources":{"KJV":{"text":"Then will I cause you to dwell in this place, in the land that I gave to your fathers, for ever and ever."},"BSB":{"text":"then I will let you live in this place, in the land that I gave to your fathers forever and ever."},"TANAKH":{"text":"then will I cause you to dwell in this place, in the land that I gave to your fathers, for ever and ever."},"HEBREW":{"text":"וְשִׁכַּנְתִּ֤י אֶתְכֶם֙ בַּמָּק֣וֹם הַזֶּ֔ה בָּאָ֕רֶץ אֲשֶׁ֥ר נָתַ֖תִּי לַאֲבֽוֹתֵיכֶ֑ם לְמִן־עוֹלָ֖ם וְעַד־עוֹלָֽם׃"}},"definableWords":["live","land","fathers"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"8":{"text":"Behold, ye trust in lying words, that cannot profit.","ref":"Jeremiah 7:8","synthesized":"But look, you keep trusting in deceptive words to no avail.","sources":{"KJV":{"text":"Behold, ye trust in lying words, that cannot profit."},"BSB":{"text":"But look, you keep trusting in deceptive words to no avail."},"TANAKH":{"text":"Behold, ye trust in lying words, that cannot profit."},"HEBREW":{"text":"הִנֵּ֤ה אַתֶּם֙ בֹּטְחִ֣ים לָכֶ֔ם עַל־דִּבְרֵ֖י הַשָּׁ֑קֶר לְבִלְתִּ֖י הוֹעִֽיל׃"}},"definableWords":["keep"],"peopleInVerse":[]},"9":{"text":"Will ye steal, murder, and commit adultery, and swear falsely, and burn incense unto Baal, and walk after other gods whom ye know not;","ref":"Jeremiah 7:9","synthesized":"Will you steal and murder, commit adultery and perjury, burn incense to Baal, and follow other gods that you have not known,","sources":{"KJV":{"text":"Will ye steal, murder, and commit adultery, and swear falsely, and burn incense unto Baal, and walk after other gods whom ye know not;"},"BSB":{"text":"Will you steal and murder, commit adultery and perjury, burn incense to Baal, and follow other gods that you have not known,"},"TANAKH":{"text":"Will ye steal, murder, and commit adultery, and swear falsely, and offer unto Baal, and walk after other gods whom ye have not known,"},"HEBREW":{"text":"הֲגָנֹ֤ב ׀ רָצֹ֙חַ֙ וְֽנָאֹ֔ף וְהִשָּׁבֵ֥עַ לַשֶּׁ֖קֶר וְקַטֵּ֣ר לַבָּ֑עַל וְהָלֹ֗ךְ אַחֲרֵ֛י אֱלֹהִ֥ים אֲחֵרִ֖ים אֲשֶׁ֥ר לֹֽא־יְדַעְתֶּֽם׃"}},"definableWords":["incense"],"peopleInVerse":[]},"10":{"text":"And come and stand before me in this house, which is called by my name, and say, We are delivered to do all these abominations?","ref":"Jeremiah 7:10","synthesized":"and then come and stand before Me in this house, which bears My Name, and say, ‘We are delivered, so we can continue with all these abominations’?","sources":{"KJV":{"text":"And come and stand before me in this house, which is called by my name, and say, We are delivered to do all these abominations?"},"BSB":{"text":"and then come and stand before Me in this house, which bears My Name, and say, ‘We are delivered, so we can continue with all these abominations’?"},"TANAKH":{"text":"and come and stand before Me in this house, whereupon My name is called, and say: 'We are delivered', that ye may do all these abominations?"},"HEBREW":{"text":"וּבָאתֶ֞ם וַעֲמַדְתֶּ֣ם לְפָנַ֗י בַּבַּ֤יִת הַזֶּה֙ אֲשֶׁ֣ר נִקְרָא־שְׁמִ֣י עָלָ֔יו וַאֲמַרְתֶּ֖ם נִצַּ֑לְנוּ לְמַ֣עַן עֲשׂ֔וֹת אֵ֥ת כָּל־הַתּוֹעֵב֖וֹת הָאֵֽלֶּה׃"}},"definableWords":["stand","house","name"],"peopleInVerse":[]},"11":{"text":"Is this house, which is called by my name, become a den of robbers in your eyes? Behold, even I have seen it, saith the LORD.","ref":"Jeremiah 7:11","synthesized":"Has this house, which bears My Name, become a den of robbers in your sight? Yes, I too have seen it, declares the LORD.","sources":{"KJV":{"text":"Is this house, which is called by my name, become a den of robbers in your eyes? Behold, even I have seen it, saith the LORD."},"BSB":{"text":"Has this house, which bears My Name, become a den of robbers in your sight? Yes, I too have seen it, declares the LORD."},"TANAKH":{"text":"Is this house, whereupon My name is called, become a den of robbers in your eyes? Behold, I, even I, have seen it, saith HaShem."},"HEBREW":{"text":"הַמְעָרַ֣ת פָּרִצִ֗ים הָיָ֨ה הַבַּ֧יִת הַזֶּ֛ה אֲשֶׁר־נִקְרָֽא־שְׁמִ֥י עָלָ֖יו בְּעֵינֵיכֶ֑ם גַּ֧ם אָנֹכִ֛י הִנֵּ֥ה רָאִ֖יתִי נְאֻם־יְהוָֽה׃"}},"definableWords":["house","name","LORD"],"peopleInVerse":[]},"12":{"text":"But go ye now unto my place which was in Shiloh, where I set my name at the first, and see what I did to it for the wickedness of my people Israel.","ref":"Jeremiah 7:12","synthesized":"But go now to the place in Shiloh where I first made a dwelling for My Name, and see what I did to it because of the wickedness of My people Israel.","sources":{"KJV":{"text":"But go ye now unto my place which was in Shiloh, where I set my name at the first, and see what I did to it for the wickedness of my people Israel."},"BSB":{"text":"But go now to the place in Shiloh where I first made a dwelling for My Name, and see what I did to it because of the wickedness of My people Israel."},"TANAKH":{"text":"For go ye now unto My place which was in Shiloh, where I caused My name to dwell at the first, and see what I did to it for the wickedness of My people Israel."},"HEBREW":{"text":"כִּ֣י לְכוּ־נָ֗א אֶל־מְקוֹמִי֙ אֲשֶׁ֣ר בְּשִׁיל֔וֹ אֲשֶׁ֨ר שִׁכַּ֧נְתִּֽי שְׁמִ֛י שָׁ֖ם בָּרִֽאשׁוֹנָ֑ה וּרְאוּ֙ אֵ֣ת אֲשֶׁר־עָשִׂ֣יתִי ל֔וֹ מִפְּנֵ֕י רָעַ֖ת עַמִּ֥י יִשְׂרָאֵֽל׃"}},"definableWords":["made","name","see","people","Israel"],"peopleInVerse":[],"placesInVerse":["Shiloh"],"themesInVerse":["creation","temple"]},"13":{"text":"And now, because ye have done all these works, saith the LORD, and I spake unto you, rising up early and speaking, but ye heard not; and I called you, but ye answered not;","ref":"Jeremiah 7:13","synthesized":"And now, because you have done all these things, declares the LORD, and because I have spoken to you again and again but you would not listen, and I have called to you but you would not answer,","sources":{"KJV":{"text":"And now, because ye have done all these works, saith the LORD, and I spake unto you, rising up early and speaking, but ye heard not; and I called you, but ye answered not;"},"BSB":{"text":"And now, because you have done all these things, declares the LORD, and because I have spoken to you again and again but you would not listen, and I have called to you but you would not answer,"},"TANAKH":{"text":"And now, because ye have done all these works, saith HaShem, and I spoke unto you, speaking betimes and often, but ye heard not, and I called you, but ye answered not;"},"HEBREW":{"text":"וְעַתָּ֗ה יַ֧עַן עֲשׂוֹתְכֶ֛ם אֶת־כָּל־הַמּֽ͏ַעֲשִׂ֥ים הָאֵ֖לֶּה נְאֻם־יְהוָ֑ה וָאֲדַבֵּ֨ר אֲלֵיכֶ֜ם הַשְׁכֵּ֤ם וְדַבֵּר֙ וְלֹ֣א שְׁמַעְתֶּ֔ם וָאֶקְרָ֥א אֶתְכֶ֖ם וְלֹ֥א עֲנִיתֶֽם׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"14":{"text":"Therefore will I do unto this house, which is called by my name, wherein ye trust, and unto the place which I gave to you and to your fathers, as I have done to Shiloh.","ref":"Jeremiah 7:14","synthesized":"therefore what I did to Shiloh I will now do to the house that bears My Name, the house in which you trust, the place that I gave to you and your fathers.","sources":{"KJV":{"text":"Therefore will I do unto this house, which is called by my name, wherein ye trust, and unto the place which I gave to you and to your fathers, as I have done to Shiloh."},"BSB":{"text":"therefore what I did to Shiloh I will now do to the house that bears My Name, the house in which you trust, the place that I gave to you and your fathers."},"TANAKH":{"text":"therefore will I do unto the house, whereupon My name is called, wherein ye trust, and unto the place which I gave to you and to your fathers, as I have done to Shiloh."},"HEBREW":{"text":"וְעָשִׂ֜יתִי לַבַּ֣יִת ׀ אֲשֶׁ֧ר נִֽקְרָא־שְׁמִ֣י עָלָ֗יו אֲשֶׁ֤ר אַתֶּם֙ בֹּטְחִ֣ים בּ֔וֹ וְלַ֨מָּק֔וֹם אֲשֶׁר־נָתַ֥תִּי לָכֶ֖ם וְלַאֲבֽוֹתֵיכֶ֑ם כַּאֲשֶׁ֥ר עָשִׂ֖יתִי לְשִׁלֽוֹ׃"}},"definableWords":["house","name","trust","fathers"],"peopleInVerse":[],"placesInVerse":["Shiloh"],"themesInVerse":["faith"]},"15":{"text":"And I will cast you out of my sight, as I have cast out all your brethren, even the whole seed of Ephraim.","ref":"Jeremiah 7:15","synthesized":"And I will cast you out of My presence, just as I have cast out all your brothers, all the descendants of Ephraim.","sources":{"KJV":{"text":"And I will cast you out of my sight, as I have cast out all your brethren, even the whole seed of Ephraim."},"BSB":{"text":"And I will cast you out of My presence, just as I have cast out all your brothers, all the descendants of Ephraim."},"TANAKH":{"text":"And I will cast you out of My sight, as I have cast out all your brethren, even the whole seed of Ephraim."},"HEBREW":{"text":"וְהִשְׁלַכְתִּ֥י אֶתְכֶ֖ם מֵעַ֣ל פָּנָ֑י כַּאֲשֶׁ֤ר הִשְׁלַ֙כְתִּי֙ אֶת־כָּל־אֲחֵיכֶ֔ם אֵ֖ת כָּל־זֶ֥רַע אֶפְרָֽיִם׃"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Therefore pray not thou for this people, neither lift up cry nor prayer for them, neither make intercession to me: for I will not hear thee.","ref":"Jeremiah 7:16","synthesized":"As for you, do not pray for these people, do not offer a plea or petition on their behalf, and do not beg Me, for I will not listen to you.","sources":{"KJV":{"text":"Therefore pray not thou for this people, neither lift up cry nor prayer for them, neither make intercession to me: for I will not hear thee."},"BSB":{"text":"As for you, do not pray for these people, do not offer a plea or petition on their behalf, and do not beg Me, for I will not listen to you."},"TANAKH":{"text":"Therefore pray not thou for this people, neither lift up cry nor prayer for them, neither make intercession to Me; for I will not hear thee."},"HEBREW":{"text":"וְאַתָּ֞ה אַל־תִּתְפַּלֵּ֣ל ׀ בְּעַד־הָעָ֣ם הַזֶּ֗ה וְאַל־תִּשָּׂ֧א בַעֲדָ֛ם רִנָּ֥ה וּתְפִלָּ֖ה וְאַל־תִּפְגַּע־בִּ֑י כִּי־אֵינֶ֥נִּי שֹׁמֵ֖עַ אֹתָֽךְ׃"}},"definableWords":["people","or"],"peopleInVerse":[],"themesInVerse":["prayer"]},"17":{"text":"Seest thou not what they do in the cities of Judah and in the streets of Jerusalem?","ref":"Jeremiah 7:17","synthesized":"Do you not see what they are doing in the cities of Judah and in the streets of Jerusalem?","sources":{"KJV":{"text":"Seest thou not what they do in the cities of Judah and in the streets of Jerusalem?"},"BSB":{"text":"Do you not see what they are doing in the cities of Judah and in the streets of Jerusalem?"},"TANAKH":{"text":"Seest thou not what they do in the cities of Judah and in the streets of Jerusalem?"},"HEBREW":{"text":"הַֽאֵינְךָ֣ רֹאֶ֔ה מָ֛ה הֵ֥מָּה עֹשִׂ֖ים בְּעָרֵ֣י יְהוּדָ֑ה וּבְחֻצ֖וֹת יְרוּשָׁלָֽ͏ִם׃"}},"definableWords":["see","Judah","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"18":{"text":"The children gather wood, and the fathers kindle the fire, and the women knead their dough, to make cakes to the queen of heaven, and to pour out drink offerings unto other gods, that they may provoke me to anger.","ref":"Jeremiah 7:18","synthesized":"The sons gather wood, the fathers light the fire, and the women knead the dough to make cakes for the Queen of Heaven; they pour out drink offerings to other gods to provoke Me to anger.","sources":{"KJV":{"text":"The children gather wood, and the fathers kindle the fire, and the women knead their dough, to make cakes to the queen of heaven, and to pour out drink offerings unto other gods, that they may provoke me to anger."},"BSB":{"text":"The sons gather wood, the fathers light the fire, and the women knead the dough to make cakes for the Queen of Heaven; they pour out drink offerings to other gods to provoke Me to anger."},"TANAKH":{"text":"The children gather wood, and the fathers kindle the fire, and the women knead the dough, to make cakes to the queen of heaven, and to pour out drink-offerings unto other gods, that they may provoke Me."},"HEBREW":{"text":"הַבָּנִ֞ים מְלַקְּטִ֣ים עֵצִ֗ים וְהָֽאָבוֹת֙ מְבַעֲרִ֣ים אֶת־הָאֵ֔שׁ וְהַנָּשִׁ֖ים לָשׁ֣וֹת בָּצֵ֑ק לַעֲשׂ֨וֹת כַּוָּנִ֜ים לִמְלֶ֣כֶת הַשָּׁמַ֗יִם וְהַסֵּ֤ךְ נְסָכִים֙ לֵאלֹהִ֣ים אֲחֵרִ֔ים לְמַ֖עַן הַכְעִסֵֽנִי׃"}},"definableWords":["sons","fathers","light","women","make","heaven","anger"],"peopleInVerse":[],"themesInVerse":["light_darkness"]},"19":{"text":"Do they provoke me to anger? saith the LORD: do they not provoke themselves to the confusion of their own faces?","ref":"Jeremiah 7:19","synthesized":"But am I the One they are provoking? declares the LORD. Is it not themselves they spite, to their own shame?","sources":{"KJV":{"text":"Do they provoke me to anger? saith the LORD: do they not provoke themselves to the confusion of their own faces?"},"BSB":{"text":"But am I the One they are provoking? declares the LORD. Is it not themselves they spite, to their own shame?"},"TANAKH":{"text":"Do they provoke Me? saith HaShem; do they not provoke themselves, to the confusion of their own faces?"},"HEBREW":{"text":"הַאֹתִ֛י הֵ֥ם מַכְעִסִ֖ים נְאֻם־יְהוָ֑ה הֲל֣וֹא אֹתָ֔ם לְמַ֖עַן בֹּ֥שֶׁת פְּנֵיהֶֽם׃"}},"definableWords":["one","LORD"],"peopleInVerse":[]},"20":{"text":"Therefore thus saith the Lord GOD; Behold, mine anger and my fury shall be poured out upon this place, upon man, and upon beast, and upon the trees of the field, and upon the fruit of the ground; and it shall burn, and shall not be quenched.","ref":"Jeremiah 7:20","synthesized":"Therefore this is what the Lord GOD says: Behold, My anger and My fury will be poured out on this place, on man and beast, on the trees of the field and the produce of the land, and it will burn and not be extinguished.","sources":{"KJV":{"text":"Therefore thus saith the Lord GOD; Behold, mine anger and my fury shall be poured out upon this place, upon man, and upon beast, and upon the trees of the field, and upon the fruit of the ground; and it shall burn, and shall not be quenched."},"BSB":{"text":"Therefore this is what the Lord GOD says: Behold, My anger and My fury will be poured out on this place, on man and beast, on the trees of the field and the produce of the land, and it will burn and not be extinguished."},"TANAKH":{"text":"Therefore thus saith the L-rd GOD: Behold, Mine anger and My fury shall be poured out upon this place, upon man, and upon beast, and upon the trees of the field, and upon the fruit of the land; and it shall burn, and shall not be quenched."},"HEBREW":{"text":"לָכֵ֞ן כֹּה־אָמַ֣ר ׀ אֲדֹנָ֣י יְהֹוִ֗ה הִנֵּ֨ה אַפִּ֤י וַֽחֲמָתִי֙ נִתֶּ֙כֶת֙ אֶל־הַמָּק֣וֹם הַזֶּ֔ה עַל־הָֽאָדָם֙ וְעַל־הַבְּהֵמָ֔ה וְעַל־עֵ֥ץ הַשָּׂדֶ֖ה וְעַל־פְּרִ֣י הָֽאֲדָמָ֑ה וּבָעֲרָ֖ה וְלֹ֥א תִכְבֶּֽה׃"}},"definableWords":["Lord","God","anger","man","trees","field","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"21":{"text":"Thus saith the LORD of hosts, the God of Israel; Put your burnt offerings unto your sacrifices, and eat flesh.","ref":"Jeremiah 7:21","synthesized":"This is what the LORD of Hosts, the God of Israel, says: Add your burnt offerings to your other sacrifices and eat the meat yourselves!","sources":{"KJV":{"text":"Thus saith the LORD of hosts, the God of Israel; Put your burnt offerings unto your sacrifices, and eat flesh."},"BSB":{"text":"This is what the LORD of Hosts, the God of Israel, says: Add your burnt offerings to your other sacrifices and eat the meat yourselves!"},"TANAKH":{"text":"Thus saith HaShem of hosts, the G-d of Israel: Add your burnt-offerings unto your sacrifices, and eat ye flesh."},"HEBREW":{"text":"כֹּ֥ה אָמַ֛ר יְהוָ֥ה צְבָא֖וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֑ל עֹלוֹתֵיכֶ֛ם סְפ֥וּ עַל־זִבְחֵיכֶ֖ם וְאִכְל֥וּ בָשָֽׂר׃"}},"definableWords":["LORD","God","Israel"],"peopleInVerse":[]},"22":{"text":"For I spake not unto your fathers, nor commanded them in the day that I brought them out of the land of Egypt, concerning burnt offerings or sacrifices:","ref":"Jeremiah 7:22","synthesized":"For when I brought your fathers out of the land of Egypt, I did not merely command them about burnt offerings and sacrifices,","sources":{"KJV":{"text":"For I spake not unto your fathers, nor commanded them in the day that I brought them out of the land of Egypt, concerning burnt offerings or sacrifices:"},"BSB":{"text":"For when I brought your fathers out of the land of Egypt, I did not merely command them about burnt offerings and sacrifices,"},"TANAKH":{"text":"For I spoke not unto your fathers, nor commanded them in the day that I brought them out of the land of Egypt, concerning burnt-offerings or sacrifices;"},"HEBREW":{"text":"כִּ֠י לֹֽא־דִבַּ֤רְתִּי אֶת־אֲבֽוֹתֵיכֶם֙ וְלֹ֣א צִוִּיתִ֔ים בְּי֛וֹם הוציא הוֹצִיאִ֥י אוֹתָ֖ם מֵאֶ֣רֶץ מִצְרָ֑יִם עַל־דִּבְרֵ֥י עוֹלָ֖ה וָזָֽבַח׃"}},"definableWords":["fathers","land","Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"23":{"text":"But this thing commanded I them, saying, Obey my voice, and I will be your God, and ye shall be my people: and walk ye in all the ways that I have commanded you, that it may be well unto you.","ref":"Jeremiah 7:23","synthesized":"but this is what I commanded them: Obey Me, and I will be your God, and you will be My people. You must walk in all the ways I have commanded you, so that it may go well with you.","sources":{"KJV":{"text":"But this thing commanded I them, saying, Obey my voice, and I will be your God, and ye shall be my people: and walk ye in all the ways that I have commanded you, that it may be well unto you."},"BSB":{"text":"but this is what I commanded them: Obey Me, and I will be your God, and you will be My people. You must walk in all the ways I have commanded you, so that it may go well with you."},"TANAKH":{"text":"but this thing I commanded them, saying: 'Hearken unto My voice, and I will be your G-d, and ye shall be My people; and walk ye in all the way that I command you, that it may be well with you.'"},"HEBREW":{"text":"כִּ֣י אִֽם־אֶת־הַדָּבָ֣ר הַ֠זֶּה צִוִּ֨יתִי אוֹתָ֤ם לֵאמֹר֙ שִׁמְע֣וּ בְקוֹלִ֔י וְהָיִ֤יתִי לָכֶם֙ לֵֽאלֹהִ֔ים וְאַתֶּ֖ם תִּֽהְיוּ־לִ֣י לְעָ֑ם וַהֲלַכְתֶּ֗ם בְּכָל־הַדֶּ֙רֶךְ֙ אֲשֶׁ֣ר אֲצַוֶּ֣ה אֶתְכֶ֔ם לְמַ֖עַן יִיטַ֥ב לָכֶֽם׃"}},"definableWords":["God","people","walk"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"24":{"text":"But they hearkened not, nor inclined their ear, but walked in the counsels and in the imagination of their evil heart, and went backward, and not forward.","ref":"Jeremiah 7:24","synthesized":"Yet they did not listen or incline their ear, but they followed the stubborn inclinations of their own evil hearts. They went backward and not forward.","sources":{"KJV":{"text":"But they hearkened not, nor inclined their ear, but walked in the counsels and in the imagination of their evil heart, and went backward, and not forward."},"BSB":{"text":"Yet they did not listen or incline their ear, but they followed the stubborn inclinations of their own evil hearts. They went backward and not forward."},"TANAKH":{"text":"But they hearkened not, nor inclined their ear, but walked in their own counsels, even in the stubbornness of their evil heart, and went backward and not forward,"},"HEBREW":{"text":"וְלֹ֤א שָֽׁמְעוּ֙ וְלֹֽא־הִטּ֣וּ אֶת־אָזְנָ֔ם וַיֵּֽלְכוּ֙ בְּמֹ֣עֵצ֔וֹת בִּשְׁרִר֖וּת לִבָּ֣ם הָרָ֑ע וַיִּהְי֥וּ לְאָח֖וֹר וְלֹ֥א לְפָנִֽים׃"}},"definableWords":["or","evil"],"peopleInVerse":[]},"25":{"text":"Since the day that your fathers came forth out of the land of Egypt unto this day I have even sent unto you all my servants the prophets, daily rising up early and sending them:","ref":"Jeremiah 7:25","synthesized":"From the day your fathers came out of the land of Egypt until this day, I have sent you all My servants the prophets again and again.","sources":{"KJV":{"text":"Since the day that your fathers came forth out of the land of Egypt unto this day I have even sent unto you all my servants the prophets, daily rising up early and sending them:"},"BSB":{"text":"From the day your fathers came out of the land of Egypt until this day, I have sent you all My servants the prophets again and again."},"TANAKH":{"text":"even since the day that your fathers came forth out of the land of Egypt unto this day; and though I have sent unto you all My servants the prophets, sending them daily betimes and often,"},"HEBREW":{"text":"לְמִן־הַיּ֗וֹם אֲשֶׁ֨ר יָצְא֤וּ אֲבֽוֹתֵיכֶם֙ מֵאֶ֣רֶץ מִצְרַ֔יִם עַ֖ד הַיּ֣וֹם הַזֶּ֑ה וָאֶשְׁלַ֤ח אֲלֵיכֶם֙ אֶת־כָּל־עֲבָדַ֣י הַנְּבִיאִ֔ים י֖וֹם הַשְׁכֵּ֥ם וְשָׁלֹֽחַ׃"}},"definableWords":["day","fathers","land","Egypt","servants"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"26":{"text":"Yet they hearkened not unto me, nor inclined their ear, but hardened their neck: they did worse than their fathers.","ref":"Jeremiah 7:26","synthesized":"Yet they would not listen to Me or incline their ear, but they stiffened their necks and did more evil than their fathers.","sources":{"KJV":{"text":"Yet they hearkened not unto me, nor inclined their ear, but hardened their neck: they did worse than their fathers."},"BSB":{"text":"Yet they would not listen to Me or incline their ear, but they stiffened their necks and did more evil than their fathers."},"TANAKH":{"text":"yet they hearkened not unto Me, nor inclined their ear, but made their neck stiff; they did worse than their fathers."},"HEBREW":{"text":"וְל֤וֹא שָׁמְעוּ֙ אֵלַ֔י וְלֹ֥א הִטּ֖וּ אֶת־אָזְנָ֑ם וַיַּקְשׁוּ֙ אֶת־עָרְפָּ֔ם הֵרֵ֖עוּ מֵאֲבוֹתָֽם׃"}},"definableWords":["or","evil","fathers"],"peopleInVerse":[]},"27":{"text":"Therefore thou shalt speak all these words unto them; but they will not hearken to thee: thou shalt also call unto them; but they will not answer thee.","ref":"Jeremiah 7:27","synthesized":"When you tell them all these things, they will not listen to you. When you call to them, they will not answer.","sources":{"KJV":{"text":"Therefore thou shalt speak all these words unto them; but they will not hearken to thee: thou shalt also call unto them; but they will not answer thee."},"BSB":{"text":"When you tell them all these things, they will not listen to you. When you call to them, they will not answer."},"TANAKH":{"text":"And thou shalt speak all these words unto them, but they will not hearken to thee; thou shalt also call unto them, but they will not answer thee."},"HEBREW":{"text":"וְדִבַּרְתָּ֤ אֲלֵיהֶם֙ אֶת־כָּל־הַדְּבָרִ֣ים הָאֵ֔לֶּה וְלֹ֥א יִשְׁמְע֖וּ אֵלֶ֑יךָ וְקָרָ֥אתָ אֲלֵיהֶ֖ם וְלֹ֥א יַעֲנֽוּכָה׃"}},"definableWords":[],"peopleInVerse":[]},"28":{"text":"But thou shalt say unto them, This is a nation that obeyeth not the voice of the LORD their God, nor receiveth correction: truth is perished, and is cut off from their mouth.","ref":"Jeremiah 7:28","synthesized":"Therefore you must say to them, ‘This is the nation that would not listen to the voice of the LORD their God and would not receive correction. Truth has perished; it has disappeared from their lips.","sources":{"KJV":{"text":"But thou shalt say unto them, This is a nation that obeyeth not the voice of the LORD their God, nor receiveth correction: truth is perished, and is cut off from their mouth."},"BSB":{"text":"Therefore you must say to them, ‘This is the nation that would not listen to the voice of the LORD their God and would not receive correction. Truth has perished; it has disappeared from their lips."},"TANAKH":{"text":"Therefore thou shalt say unto them: This is the nation that hath not hearkened to the voice of HaShem their G-d, nor received correction; faithfulness is perished, and is cut off from their mouth."},"HEBREW":{"text":"וְאָמַרְתָּ֣ אֲלֵיהֶ֗ם זֶ֤ה הַגּוֹי֙ אֲשֶׁ֣ר לֽוֹא־שָׁמְע֗וּ בְּקוֹל֙ יְהוָ֣ה אֱלֹהָ֔יו וְלֹ֥א לָקְח֖וּ מוּסָ֑ר אָֽבְדָה֙ הָֽאֱמוּנָ֔ה וְנִכְרְתָ֖ה מִפִּיהֶֽם׃"}},"definableWords":["nation","voice","LORD","God","truth"],"peopleInVerse":[]},"29":{"text":"Cut off thine hair, O Jerusalem, and cast it away, and take up a lamentation on high places; for the LORD hath rejected and forsaken the generation of his wrath.","ref":"Jeremiah 7:29","synthesized":"Cut off your hair and throw it away. Raise up a lamentation on the barren heights, for the LORD has rejected and forsaken the generation of His wrath.’","sources":{"KJV":{"text":"Cut off thine hair, O Jerusalem, and cast it away, and take up a lamentation on high places; for the LORD hath rejected and forsaken the generation of his wrath."},"BSB":{"text":"Cut off your hair and throw it away. Raise up a lamentation on the barren heights, for the LORD has rejected and forsaken the generation of His wrath.’"},"TANAKH":{"text":"Cut off thy hair, and cast it away, and take up a lamentation on the high hills; for HaShem hath rejected and forsaken the generation of His wrath."},"HEBREW":{"text":"גָּזִּ֤י נִזְרֵךְ֙ וְֽהַשְׁלִ֔יכִי וּשְׂאִ֥י עַל־שְׁפָיִ֖ם קִינָ֑ה כִּ֚י מָאַ֣ס יְהוָ֔ה וַיִּטֹּ֖שׁ אֶת־דּ֥וֹר עֶבְרָתֽוֹ׃"}},"definableWords":["LORD","wrath"],"peopleInVerse":[],"themesInVerse":["judgment"]},"30":{"text":"For the children of Judah have done evil in my sight, saith the LORD: they have set their abominations in the house which is called by my name, to pollute it.","ref":"Jeremiah 7:30","synthesized":"For the people of Judah have done evil in My sight, declares the LORD. They have set up their abominations in the house that bears My Name, and so have defiled it.","sources":{"KJV":{"text":"For the children of Judah have done evil in my sight, saith the LORD: they have set their abominations in the house which is called by my name, to pollute it."},"BSB":{"text":"For the people of Judah have done evil in My sight, declares the LORD. They have set up their abominations in the house that bears My Name, and so have defiled it."},"TANAKH":{"text":"For the children of Judah have done that which is evil in My sight, saith HaShem; they have set their detestable things in the house whereon My name is called, to defile it."},"HEBREW":{"text":"כִּֽי־עָשׂ֨וּ בְנֵי־יְהוּדָ֥ה הָרַ֛ע בְּעֵינַ֖י נְאֻום־יְהוָ֑ה שָׂ֣מוּ שִׁקּֽוּצֵיהֶ֗ם בַּבַּ֛יִת אֲשֶׁר־נִקְרָא־שְׁמִ֥י עָלָ֖יו לְטַמְּאֽוֹ׃"}},"definableWords":["people","Judah","evil","LORD","house","name"],"peopleInVerse":[]},"31":{"text":"And they have built the high places of Tophet, which is in the valley of the son of Hinnom, to burn their sons and their daughters in the fire; which I commanded them not, neither came it into my heart.","ref":"Jeremiah 7:31","synthesized":"They have built the high places of Topheth in the Valley of Hinnom so they could burn their sons and daughters in the fire—something I never commanded, nor did it even enter My mind.","sources":{"KJV":{"text":"And they have built the high places of Tophet, which is in the valley of the son of Hinnom, to burn their sons and their daughters in the fire; which I commanded them not, neither came it into my heart."},"BSB":{"text":"They have built the high places of Topheth in the Valley of Hinnom so they could burn their sons and daughters in the fire—something I never commanded, nor did it even enter My mind."},"TANAKH":{"text":"And they have built the high places of Topheth, which is in the valley of the son of Hinnom, to burn their sons and their daughters in the fire; which I commanded not, neither came it into My mind."},"HEBREW":{"text":"וּבָנ֞וּ בָּמ֣וֹת הַתֹּ֗פֶת אֲשֶׁר֙ בְּגֵ֣יא בֶן־הִנֹּ֔ם לִשְׂרֹ֛ף אֶת־בְּנֵיהֶ֥ם וְאֶת־בְּנֹתֵיהֶ֖ם בָּאֵ֑שׁ אֲשֶׁר֙ לֹ֣א צִוִּ֔יתִי וְלֹ֥א עָלְתָ֖ה עַל־לִבִּֽי׃"}},"definableWords":["sons","daughters","mind"],"peopleInVerse":[]},"32":{"text":"Therefore, behold, the days come, saith the LORD, that it shall no more be called Tophet, nor the valley of the son of Hinnom, but the valley of slaughter: for they shall bury in Tophet, till there be no place.","ref":"Jeremiah 7:32","synthesized":"So behold, the days are coming, declares the LORD, when this place will no longer be called Topheth and the Valley of Hinnom, but the Valley of Slaughter. For they will bury the dead in Topheth until there is no more room.","sources":{"KJV":{"text":"Therefore, behold, the days come, saith the LORD, that it shall no more be called Tophet, nor the valley of the son of Hinnom, but the valley of slaughter: for they shall bury in Tophet, till there be no place."},"BSB":{"text":"So behold, the days are coming, declares the LORD, when this place will no longer be called Topheth and the Valley of Hinnom, but the Valley of Slaughter. For they will bury the dead in Topheth until there is no more room."},"TANAKH":{"text":"Therefore, behold, the days come, saith HaShem, that it shall no more be called Topheth, nor The valley of the son of Hinnom, but The valley of slaughter; for they shall bury in Topheth, for lack of room."},"HEBREW":{"text":"לָכֵ֞ן הִנֵּֽה־יָמִ֤ים בָּאִים֙ נְאֻם־יְהוָ֔ה וְלֹא־יֵאָמֵ֨ר ע֤וֹד הַתֹּ֙פֶת֙ וְגֵ֣יא בֶן־הִנֹּ֔ם כִּ֖י אִם־גֵּ֣יא הַהֲרֵגָ֑ה וְקָבְר֥וּ בְתֹ֖פֶת מֵאֵ֥ין מָקֽוֹם׃"}},"definableWords":["days","LORD"],"peopleInVerse":[],"themesInVerse":["second_coming"]},"33":{"text":"And the carcases of this people shall be meat for the fowls of the heaven, and for the beasts of the earth; and none shall fray them away.","ref":"Jeremiah 7:33","synthesized":"The corpses of this people will become food for the birds of the air and the beasts of the earth, and there will be no one to scare them away.","sources":{"KJV":{"text":"And the carcases of this people shall be meat for the fowls of the heaven, and for the beasts of the earth; and none shall fray them away."},"BSB":{"text":"The corpses of this people will become food for the birds of the air and the beasts of the earth, and there will be no one to scare them away."},"TANAKH":{"text":"And the carcasses of this people shall be food for the fowls of the heaven, and for the beasts of the earth; and none shall frighten them away."},"HEBREW":{"text":"וְֽהָ֨יְתָ֜ה נִבְלַ֨ת הָעָ֤ם הַזֶּה֙ לְמַֽאֲכָ֔ל לְע֥וֹף הַשָּׁמַ֖יִם וּלְבֶהֱמַ֣ת הָאָ֑רֶץ וְאֵ֖ין מַחֲרִֽיד׃"}},"definableWords":["people","birds","earth","one"],"peopleInVerse":[]},"34":{"text":"Then will I cause to cease from the cities of Judah, and from the streets of Jerusalem, the voice of mirth, and the voice of gladness, the voice of the bridegroom, and the voice of the bride: for the land shall be desolate.","ref":"Jeremiah 7:34","synthesized":"I will remove from the cities of Judah and the streets of Jerusalem the sounds of joy and gladness and the voices of the bride and bridegroom, for the land will become a wasteland.”","sources":{"KJV":{"text":"Then will I cause to cease from the cities of Judah, and from the streets of Jerusalem, the voice of mirth, and the voice of gladness, the voice of the bridegroom, and the voice of the bride: for the land shall be desolate."},"BSB":{"text":"I will remove from the cities of Judah and the streets of Jerusalem the sounds of joy and gladness and the voices of the bride and bridegroom, for the land will become a wasteland.”"},"TANAKH":{"text":"Then will I cause to cease from the cities of Judah, and from the streets of Jerusalem, the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride; for the land shall be desolate."},"HEBREW":{"text":"וְהִשְׁבַּתִּ֣י ׀ מֵעָרֵ֣י יְהוּדָ֗ה וּמֵֽחֻצוֹת֙ יְר֣וּשָׁלִַ֔ם ק֤וֹל שָׂשׂוֹן֙ וְק֣וֹל שִׂמְחָ֔ה ק֥וֹל חָתָ֖ן וְק֣וֹל כַּלָּ֑ה כִּ֥י לְחָרְבָּ֖ה תִּהְיֶ֥ה הָאָֽרֶץ׃"}},"definableWords":["Judah","Jerusalem","joy","land"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["joy","land_promise","marriage_bride"]}}},"8":{"chapter":"8","title":"IS THERE NO BALM IN GILEAD?","verses":{"1":{"text":"At that time, saith the LORD, they shall bring out the bones of the kings of Judah, and the bones of his princes, and the bones of the priests, and the bones of the prophets, and the bones of the inhabitants of Jerusalem, out of their graves:","ref":"Jeremiah 8:1","synthesized":"“At that time,” declares the LORD, “the bones of the kings of Judah, the bones of the officials, the bones of the priests, the bones of the prophets, and the bones of the people of Jerusalem will be removed from their graves.","sources":{"KJV":{"text":"At that time, saith the LORD, they shall bring out the bones of the kings of Judah, and the bones of his princes, and the bones of the priests, and the bones of the prophets, and the bones of the inhabitants of Jerusalem, out of their graves:"},"BSB":{"text":"“At that time,” declares the LORD, “the bones of the kings of Judah, the bones of the officials, the bones of the priests, the bones of the prophets, and the bones of the people of Jerusalem will be removed from their graves."},"TANAKH":{"text":"At that time, saith HaShem, they shall bring out the bones of the kings of Judah, and the bones of his princes, and the bones of the priests, and the bones of the prophets, and the bones of the inhabitants of Jerusalem, out of their graves;"},"HEBREW":{"text":"בָּעֵ֣ת הַהִ֣יא נְאֻם־יְהוָ֡ה ויציאו יוֹצִ֣יאוּ אֶת־עַצְמ֣וֹת מַלְכֵֽי־יְהוּדָ֣ה וְאֶת־עַצְמוֹת־שָׂרָיו֩ וְאֶת־עַצְמ֨וֹת הַכֹּהֲנִ֜ים וְאֵ֣ת ׀ עַצְמ֣וֹת הַנְּבִיאִ֗ים וְאֵ֛ת עַצְמ֥וֹת יוֹשְׁבֵֽי־יְרוּשָׁלָ֖͏ִם מִקִּבְרֵיהֶֽם׃"}},"definableWords":["LORD","bones","kings","Judah","people","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"2":{"text":"And they shall spread them before the sun, and the moon, and all the host of heaven, whom they have loved, and whom they have served, and after whom they have walked, and whom they have sought, and whom they have worshipped: they shall not be gathered, nor be buried; they shall be for dung upon the face of the earth.","ref":"Jeremiah 8:2","synthesized":"They will be exposed to the sun and moon, and to all the host of heaven which they have loved, served, followed, consulted, and worshiped. Their bones will not be gathered up or buried, but will become like dung lying on the ground.","sources":{"KJV":{"text":"And they shall spread them before the sun, and the moon, and all the host of heaven, whom they have loved, and whom they have served, and after whom they have walked, and whom they have sought, and whom they have worshipped: they shall not be gathered, nor be buried; they shall be for dung upon the face of the earth."},"BSB":{"text":"They will be exposed to the sun and moon, and to all the host of heaven which they have loved, served, followed, consulted, and worshiped. Their bones will not be gathered up or buried, but will become like dung lying on the ground."},"TANAKH":{"text":"and they shall spread them before the sun, and the moon, and all the host of heaven, whom they have loved, and whom they have served, and after whom they have walked, and whom they have sought, and whom they have worshipped; they shall not be gathered, nor be buried, they shall be for dung upon the face of the earth."},"HEBREW":{"text":"וּשְׁטָחוּם֩ לַשֶּׁ֨מֶשׁ וְלַיָּרֵ֜חַ וּלְכֹ֣ל ׀ צְבָ֣א הַשָּׁמַ֗יִם אֲשֶׁ֨ר אֲהֵב֜וּם וַאֲשֶׁ֤ר עֲבָדוּם֙ וַֽאֲשֶׁר֙ הָלְכ֣וּ אַֽחֲרֵיהֶ֔ם וַאֲשֶׁ֣ר דְּרָשׁ֔וּם וַאֲשֶׁ֥ר הִֽשְׁתַּחֲו֖וּ לָהֶ֑ם לֹ֤א יֵאָֽסְפוּ֙ וְלֹ֣א יִקָּבֵ֔רוּ לְדֹ֛מֶן עַל־פְּנֵ֥י הָאֲדָמָ֖ה יִֽהְיֽוּ׃"}},"definableWords":["heaven","bones","or","ground"],"peopleInVerse":[]},"3":{"text":"And death shall be chosen rather than life by all the residue of them that remain of this evil family, which remain in all the places whither I have driven them, saith the LORD of hosts.","ref":"Jeremiah 8:3","synthesized":"And wherever I have banished them, the remnant of this evil family will choose death over life,” declares the LORD of Hosts.","sources":{"KJV":{"text":"And death shall be chosen rather than life by all the residue of them that remain of this evil family, which remain in all the places whither I have driven them, saith the LORD of hosts."},"BSB":{"text":"And wherever I have banished them, the remnant of this evil family will choose death over life,” declares the LORD of Hosts."},"TANAKH":{"text":"And death shall be chosen rather than life by all the residue that remain of this evil family, that remain in all the places whither I have driven them, saith HaShem of hosts."},"HEBREW":{"text":"וְנִבְחַ֥ר מָ֙וֶת֙ מֵֽחַיִּ֔ים לְכֹ֗ל הַשְּׁאֵרִית֙ הַנִּשְׁאָרִ֔ים מִן־הַמִּשְׁפָּחָ֥ה הָֽרָעָ֖ה הַזֹּ֑את בְּכָל־הַמְּקֹמ֤וֹת הַנִּשְׁאָרִים֙ אֲשֶׁ֣ר הִדַּחְתִּ֣ים שָׁ֔ם נְאֻ֖ם יְהוָ֥ה צְבָאֽוֹת׃"}},"definableWords":["remnant","evil","family","death","life","LORD"],"peopleInVerse":[],"themesInVerse":["exile_return"]},"4":{"text":"Moreover thou shalt say unto them, Thus saith the LORD; Shall they fall, and not arise? shall he turn away, and not return?","ref":"Jeremiah 8:4","synthesized":"So you are to tell them this is what the LORD says:  “Do men fall and not get up again? Does one turn away and not return?","sources":{"KJV":{"text":"Moreover thou shalt say unto them, Thus saith the LORD; Shall they fall, and not arise? shall he turn away, and not return?"},"BSB":{"text":"So you are to tell them this is what the LORD says:  “Do men fall and not get up again? Does one turn away and not return?"},"TANAKH":{"text":"Moreover thou shalt say unto them: Thus saith HaShem: do men fall, and not rise up again? Doth one turn away, and not return?"},"HEBREW":{"text":"וְאָמַרְתָּ֣ אֲלֵיהֶ֗ם כֹּ֚ה אָמַ֣ר יְהוָ֔ה הֲיִפְּל֖וּ וְלֹ֣א יָק֑וּמוּ אִם־יָשׁ֖וּב וְלֹ֥א יָשֽׁוּב׃"}},"definableWords":["LORD","men","one"],"peopleInVerse":[],"themesInVerse":["exile_return","fall_sin","second_coming"]},"5":{"text":"Why then is this people of Jerusalem slidden back by a perpetual backsliding? they hold fast deceit, they refuse to return.","ref":"Jeremiah 8:5","synthesized":"Why then have these people turned away? Why does Jerusalem always turn away? They cling to deceit; they refuse to return.","sources":{"KJV":{"text":"Why then is this people of Jerusalem slidden back by a perpetual backsliding? they hold fast deceit, they refuse to return."},"BSB":{"text":"Why then have these people turned away? Why does Jerusalem always turn away? They cling to deceit; they refuse to return."},"TANAKH":{"text":"Why then is this people of Jerusalem slidden back by a perpetual backsliding? They hold fast deceit, they refuse to return."},"HEBREW":{"text":"מַדּ֨וּעַ שׁוֹבְבָ֜ה הָעָ֥ם הַזֶּ֛ה יְרוּשָׁלַ֖͏ִם מְשֻׁבָ֣ה נִצַּ֑חַת הֶחֱזִ֙יקוּ֙ בַּתַּרְמִ֔ית מֵאֲנ֖וּ לָשֽׁוּב׃"}},"definableWords":["people","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["exile_return","second_coming"]},"6":{"text":"I hearkened and heard, but they spake not aright: no man repented him of his wickedness, saying, What have I done? every one turned to his course, as the horse rusheth into the battle.","ref":"Jeremiah 8:6","synthesized":"I have listened and heard; they do not speak what is right. No one repents of his wickedness, asking, ‘What have I done?’ Everyone has pursued his own course like a horse charging into battle.","sources":{"KJV":{"text":"I hearkened and heard, but they spake not aright: no man repented him of his wickedness, saying, What have I done? every one turned to his course, as the horse rusheth into the battle."},"BSB":{"text":"I have listened and heard; they do not speak what is right. No one repents of his wickedness, asking, ‘What have I done?’ Everyone has pursued his own course like a horse charging into battle."},"TANAKH":{"text":"I attended and listened, but they spoke not aright; no man repenteth him of his wickedness, saying: 'What have I done?' Every one turneth away in his course, as a horse that rusheth headlong in the battle."},"HEBREW":{"text":"הִקְשַׁ֤בְתִּי וָֽאֶשְׁמָע֙ לוֹא־כֵ֣ן יְדַבֵּ֔רוּ אֵ֣ין אִ֗ישׁ נִחָם֙ עַל־רָ֣עָת֔וֹ לֵאמֹ֖ר מֶ֣ה עָשִׂ֑יתִי כֻּלֹּ֗ה שָׁ֚ב במרצותם בִּמְר֣וּצָתָ֔ם כְּס֥וּס שׁוֹטֵ֖ף בַּמִּלְחָמָֽה׃"}},"definableWords":["one"],"peopleInVerse":[],"themesInVerse":["spiritual_warfare"]},"7":{"text":"Yea, the stork in the heaven knoweth her appointed times; and the turtle and the crane and the swallow observe the time of their coming; but my people know not the judgment of the LORD.","ref":"Jeremiah 8:7","synthesized":"Even the stork in the sky knows her appointed seasons. The turtledove, the swift, and the thrush keep their time of migration, but My people do not know the requirements of the LORD.","sources":{"KJV":{"text":"Yea, the stork in the heaven knoweth her appointed times; and the turtle and the crane and the swallow observe the time of their coming; but my people know not the judgment of the LORD."},"BSB":{"text":"Even the stork in the sky knows her appointed seasons. The turtledove, the swift, and the thrush keep their time of migration, but My people do not know the requirements of the LORD."},"TANAKH":{"text":"Yea, the stork in the heaven knoweth her appointed times; and the turtle and the swallow and the crane observe the time of their coming; but My people know not the ordinance of HaShem."},"HEBREW":{"text":"גַּם־חֲסִידָ֣ה בַשָּׁמַ֗יִם יָֽדְעָה֙ מֽוֹעֲדֶ֔יהָ וְתֹ֤ר וסוס וְסִיס֙ וְעָג֔וּר שָׁמְר֖וּ אֶת־עֵ֣ת בֹּאָ֑נָה וְעַמִּ֕י לֹ֣א יָֽדְע֔וּ אֵ֖ת מִשְׁפַּ֥ט יְהוָֽה׃"}},"definableWords":["keep","people","LORD"],"peopleInVerse":[]},"8":{"text":"How do ye say, We are wise, and the law of the LORD is with us? Lo, certainly in vain made he it; the pen of the scribes is in vain.","ref":"Jeremiah 8:8","synthesized":"How can you say, ‘We are wise, and the Law of the LORD is with us,’ when in fact the lying pen of the scribes has produced a deception?","sources":{"KJV":{"text":"How do ye say, We are wise, and the law of the LORD is with us? Lo, certainly in vain made he it; the pen of the scribes is in vain."},"BSB":{"text":"How can you say, ‘We are wise, and the Law of the LORD is with us,’ when in fact the lying pen of the scribes has produced a deception?"},"TANAKH":{"text":"How do ye say: 'We are wise, and the Law of HaShem is with us'? Lo, certainly in vain hath wrought the vain pen of the scribes."},"HEBREW":{"text":"אֵיכָ֤ה תֹֽאמְרוּ֙ חֲכָמִ֣ים אֲנַ֔חְנוּ וְתוֹרַ֥ת יְהוָ֖ה אִתָּ֑נוּ אָכֵן֙ הִנֵּ֣ה לַשֶּׁ֣קֶר עָשָׂ֔ה עֵ֖ט שֶׁ֥קֶר סֹפְרִֽים׃"}},"definableWords":["law","LORD"],"peopleInVerse":[],"themesInVerse":["wisdom"]},"9":{"text":"The wise men are ashamed, they are dismayed and taken: lo, they have rejected the word of the LORD; and what wisdom is in them?","ref":"Jeremiah 8:9","synthesized":"The wise will be put to shame; they will be dismayed and trapped. Since they have rejected the word of the LORD, what wisdom do they really have?","sources":{"KJV":{"text":"The wise men are ashamed, they are dismayed and taken: lo, they have rejected the word of the LORD; and what wisdom is in them?"},"BSB":{"text":"The wise will be put to shame; they will be dismayed and trapped. Since they have rejected the word of the LORD, what wisdom do they really have?"},"TANAKH":{"text":"The wise men are ashamed, they are dismayed and taken; lo, they have rejected the word of HaShem; and what wisdom is in them?"},"HEBREW":{"text":"הֹבִ֣ישׁוּ חֲכָמִ֔ים חַ֖תּוּ וַיִּלָּכֵ֑דוּ הִנֵּ֤ה בִדְבַר־יְהוָה֙ מָאָ֔סוּ וְחָכְמַֽת־מֶ֖ה לָהֶֽם׃"}},"definableWords":["word","LORD","wisdom"],"peopleInVerse":[],"themesInVerse":["wisdom"]},"10":{"text":"Therefore will I give their wives unto others, and their fields to them that shall inherit them: for every one from the least even unto the greatest is given to covetousness, from the prophet even unto the priest every one dealeth falsely.","ref":"Jeremiah 8:10","synthesized":"Therefore I will give their wives to other men and their fields to new owners. For from the least of them to the greatest, all are greedy for gain; from prophet to priest, all practice deceit.","sources":{"KJV":{"text":"Therefore will I give their wives unto others, and their fields to them that shall inherit them: for every one from the least even unto the greatest is given to covetousness, from the prophet even unto the priest every one dealeth falsely."},"BSB":{"text":"Therefore I will give their wives to other men and their fields to new owners. For from the least of them to the greatest, all are greedy for gain; from prophet to priest, all practice deceit."},"TANAKH":{"text":"Therefore will I give their wives unto others, and their fields to them that shall possess them; for from the least even unto the greatest every one is greedy for gain, from the prophet even unto the priest every one dealeth falsely."},"HEBREW":{"text":"לָכֵן֩ אֶתֵּ֨ן אֶת־נְשֵׁיהֶ֜ם לַאֲחֵרִ֗ים שְׂדֽוֹתֵיהֶם֙ לְי֣וֹרְשִׁ֔ים כִּ֤י מִקָּטֹן֙ וְעַד־גָּד֔וֹל כֻּלֹּ֖ה בֹּצֵ֣עַ בָּ֑צַע מִנָּבִיא֙ וְעַד־כֹּהֵ֔ן כֻּלֹּ֖ה עֹ֥שֶׂה שָּֽׁקֶר׃"}},"definableWords":["men","prophet","priest"],"peopleInVerse":[],"themesInVerse":["kingdom_priesthood"]},"11":{"text":"For they have healed the hurt of the daughter of my people slightly, saying, Peace, peace; when there is no peace.","ref":"Jeremiah 8:11","synthesized":"They dress the wound of the daughter of My people with very little care, saying, ‘Peace, peace,’ when there is no peace at all.","sources":{"KJV":{"text":"For they have healed the hurt of the daughter of my people slightly, saying, Peace, peace; when there is no peace."},"BSB":{"text":"They dress the wound of the daughter of My people with very little care, saying, ‘Peace, peace,’ when there is no peace at all."},"TANAKH":{"text":"And they have healed the hurt of the daughter of My people lightly, saying: 'Peace, peace', when there is no peace."},"HEBREW":{"text":"וַיְרַפּ֞וּ אֶת־שֶׁ֤בֶר בַּת־עַמִּי֙ עַל־נְקַלָּ֔ה לֵאמֹ֖ר שָׁל֣וֹם ׀ שָׁל֑וֹם וְאֵ֖ין שָׁלֽוֹם׃"}},"definableWords":["daughter","people","peace"],"peopleInVerse":[],"themesInVerse":["peace"]},"12":{"text":"Were they ashamed when they had committed abomination? nay, they were not at all ashamed, neither could they blush: therefore shall they fall among them that fall: in the time of their visitation they shall be cast down, saith the LORD.","ref":"Jeremiah 8:12","synthesized":"Are they ashamed of the abomination they have committed? No, they have no shame at all; they do not even know how to blush. So they will fall among the fallen; when I punish them, they will collapse, says the LORD.","sources":{"KJV":{"text":"Were they ashamed when they had committed abomination? nay, they were not at all ashamed, neither could they blush: therefore shall they fall among them that fall: in the time of their visitation they shall be cast down, saith the LORD."},"BSB":{"text":"Are they ashamed of the abomination they have committed? No, they have no shame at all; they do not even know how to blush. So they will fall among the fallen; when I punish them, they will collapse, says the LORD."},"TANAKH":{"text":"They shall be put to shame because they have committed abomination; yea, they are not at all ashamed, neither know they how to blush; therefore shall they fall among them that fall, in the time of their visitation they shall stumble, saith HaShem."},"HEBREW":{"text":"הֹבִ֕שׁוּ כִּ֥י תוֹעֵבָ֖ה עָשׂ֑וּ גַּם־בּ֣וֹשׁ לֹֽא־יֵבֹ֗שׁוּ וְהִכָּלֵם֙ לֹ֣א יָדָ֔עוּ לָכֵ֞ן יִפְּל֣וּ בַנֹּפְלִ֗ים בְּעֵ֧ת פְּקֻדָּתָ֛ם יִכָּשְׁל֖וּ אָמַ֥ר יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"13":{"text":"I will surely consume them, saith the LORD: there shall be no grapes on the vine, nor figs on the fig tree, and the leaf shall fade; and the things that I have given them shall pass away from them.","ref":"Jeremiah 8:13","synthesized":"I will take away their harvest, declares the LORD. There will be no grapes on the vine, nor figs on the tree, and even the leaf will wither. Whatever I have given them will be lost to them.”","sources":{"KJV":{"text":"I will surely consume them, saith the LORD: there shall be no grapes on the vine, nor figs on the fig tree, and the leaf shall fade; and the things that I have given them shall pass away from them."},"BSB":{"text":"I will take away their harvest, declares the LORD. There will be no grapes on the vine, nor figs on the tree, and even the leaf will wither. Whatever I have given them will be lost to them.”"},"TANAKH":{"text":"I will utterly consume them, saith HaShem; there are no grapes on the vine, nor figs on the fig-tree, and the leaf is faded; and I gave them that which they transgress."},"HEBREW":{"text":"אָסֹ֥ף אֲסִיפֵ֖ם נְאֻם־יְהֹוָ֑ה אֵין֩ עֲנָבִ֨ים בַּגֶּ֜פֶן וְאֵ֧ין תְּאֵנִ֣ים בַּתְּאֵנָ֗ה וְהֶֽעָלֶה֙ נָבֵ֔ל וָאֶתֵּ֥ן לָהֶ֖ם יַעַבְרֽוּם׃"}},"definableWords":["LORD","tree"],"peopleInVerse":[],"themesInVerse":["vine_branches"]},"14":{"text":"Why do we sit still? assemble yourselves, and let us enter into the defenced cities, and let us be silent there: for the LORD our God hath put us to silence, and given us water of gall to drink, because we have sinned against the LORD.","ref":"Jeremiah 8:14","synthesized":"Why are we just sitting here? Gather together, let us flee to the fortified cities and perish there, for the LORD our God has doomed us. He has given us poisoned water to drink, because we have sinned against the LORD.","sources":{"KJV":{"text":"Why do we sit still? assemble yourselves, and let us enter into the defenced cities, and let us be silent there: for the LORD our God hath put us to silence, and given us water of gall to drink, because we have sinned against the LORD."},"BSB":{"text":"Why are we just sitting here? Gather together, let us flee to the fortified cities and perish there, for the LORD our God has doomed us. He has given us poisoned water to drink, because we have sinned against the LORD."},"TANAKH":{"text":"'Why do we sit still? Assemble yourselves, and let us enter into the fortified cities, and let us be cut off there; for HaShem our G-d hath cut us off, and given us water of gall to drink, because we have sinned against HaShem."},"HEBREW":{"text":"עַל־מָה֙ אֲנַ֣חְנוּ יֹֽשְׁבִ֔ים הֵֽאָסְפ֗וּ וְנָב֛וֹא אֶל־עָרֵ֥י הַמִּבְצָ֖ר וְנִדְּמָה־שָּׁ֑ם כִּי֩ יְהוָ֨ה אֱלֹהֵ֤ינוּ הֲדִמָּ֙נוּ֙ וַיַּשְׁקֵ֣נוּ מֵי־רֹ֔אשׁ כִּ֥י חָטָ֖אנוּ לַיהוָֽה׃"}},"definableWords":["LORD","God","water","Lord"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"15":{"text":"We looked for peace, but no good came; and for a time of health, and behold trouble!","ref":"Jeremiah 8:15","synthesized":"We hoped for peace, but no good has come, for a time of healing, but there was only terror.","sources":{"KJV":{"text":"We looked for peace, but no good came; and for a time of health, and behold trouble!"},"BSB":{"text":"We hoped for peace, but no good has come, for a time of healing, but there was only terror."},"TANAKH":{"text":"We looked for peace, but no good came; and for a time of healing, and behold terror!'"},"HEBREW":{"text":"קַוֵּ֥ה לְשָׁל֖וֹם וְאֵ֣ין ט֑וֹב לְעֵ֥ת מַרְפֵּ֖ה וְהִנֵּ֥ה בְעָתָֽה׃"}},"definableWords":["peace","good"],"peopleInVerse":[],"themesInVerse":["peace"]},"16":{"text":"The snorting of his horses was heard from Dan: the whole land trembled at the sound of the neighing of his strong ones; for they are come, and have devoured the land, and all that is in it; the city, and those that dwell therein.","ref":"Jeremiah 8:16","synthesized":"The snorting of enemy horses is heard from Dan. At the sound of the neighing of mighty steeds, the whole land quakes. They come to devour the land and everything in it, the city and all who dwell in it.","sources":{"KJV":{"text":"The snorting of his horses was heard from Dan: the whole land trembled at the sound of the neighing of his strong ones; for they are come, and have devoured the land, and all that is in it; the city, and those that dwell therein."},"BSB":{"text":"The snorting of enemy horses is heard from Dan. At the sound of the neighing of mighty steeds, the whole land quakes. They come to devour the land and everything in it, the city and all who dwell in it."},"TANAKH":{"text":"The snorting of his horses is heard from Dan; at the sound of the neighing of his strong ones the whole land trembleth; for they are come, and have devoured the land and all that is in it, the city and those that dwell therein."},"HEBREW":{"text":"מִדָּ֤ן נִשְׁמַע֙ נַחְרַ֣ת סוּסָ֗יו מִקּוֹל֙ מִצְהֲל֣וֹת אַבִּירָ֔יו רָעֲשָׁ֖ה כָּל־הָאָ֑רֶץ וַיָּב֗וֹאוּ וַיֹּֽאכְלוּ֙ אֶ֣רֶץ וּמְלוֹאָ֔הּ עִ֖יר וְיֹ֥שְׁבֵי בָֽהּ׃"}},"definableWords":["mighty","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"17":{"text":"For, behold, I will send serpents, cockatrices, among you, which will not be charmed, and they shall bite you, saith the LORD.","ref":"Jeremiah 8:17","synthesized":"“For behold, I will send snakes among you, vipers that cannot be charmed, and they will bite you,” declares the LORD.","sources":{"KJV":{"text":"For, behold, I will send serpents, cockatrices, among you, which will not be charmed, and they shall bite you, saith the LORD."},"BSB":{"text":"“For behold, I will send snakes among you, vipers that cannot be charmed, and they will bite you,” declares the LORD."},"TANAKH":{"text":"For, behold, I will send serpents, basilisks, among you, which will not be charmed; and they shall bite you, saith HaShem."},"HEBREW":{"text":"כִּי֩ הִנְנִ֨י מְשַׁלֵּ֜חַ בָּכֶ֗ם נְחָשִׁים֙ צִפְעֹנִ֔ים אֲשֶׁ֥ר אֵין־לָהֶ֖ם לָ֑חַשׁ וְנִשְּׁכ֥וּ אֶתְכֶ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"18":{"text":"When I would comfort myself against sorrow, my heart is faint in me.","ref":"Jeremiah 8:18","synthesized":"My sorrow is beyond healing; my heart is faint within me.","sources":{"KJV":{"text":"When I would comfort myself against sorrow, my heart is faint in me."},"BSB":{"text":"My sorrow is beyond healing; my heart is faint within me."},"TANAKH":{"text":"Though I would take comfort against sorrow, my heart is faint within me."},"HEBREW":{"text":"מַבְלִ֥יגִיתִ֖י עֲלֵ֣י יָג֑וֹן עָלַ֖י לִבִּ֥י דַוָּֽי׃"}},"definableWords":["heart"],"peopleInVerse":[]},"19":{"text":"Behold the voice of the cry of the daughter of my people because of them that dwell in a far country: Is not the LORD in Zion? is not her king in her? Why have they provoked me to anger with their graven images, and with strange vanities?","ref":"Jeremiah 8:19","synthesized":"Listen to the cry of the daughter of my people from a land far away:   “Is the LORD no longer in Zion? Is her King no longer there?”   “Why have they provoked Me to anger with their carved images, with their worthless foreign idols?”","sources":{"KJV":{"text":"Behold the voice of the cry of the daughter of my people because of them that dwell in a far country: Is not the LORD in Zion? is not her king in her? Why have they provoked me to anger with their graven images, and with strange vanities?"},"BSB":{"text":"Listen to the cry of the daughter of my people from a land far away:   “Is the LORD no longer in Zion? Is her King no longer there?”   “Why have they provoked Me to anger with their carved images, with their worthless foreign idols?”"},"TANAKH":{"text":"Behold the voice of the cry of the daughter of my people from a land far off: 'Is not HaShem in Zion? Is not her King in her?'-- 'Why have they provoked Me with their graven images, and with strange vanities?'--"},"HEBREW":{"text":"הִנֵּה־ק֞וֹל שַֽׁוְעַ֣ת בַּת־עַמִּ֗י מֵאֶ֙רֶץ֙ מַרְחַקִּ֔ים הַֽיהוָה֙ אֵ֣ין בְּצִיּ֔וֹן אִם־מַלְכָּ֖הּ אֵ֣ין בָּ֑הּ מַדּ֗וּעַ הִכְעִס֛וּנִי בִּפְסִלֵיהֶ֖ם בְּהַבְלֵ֥י נֵכָֽר׃"}},"definableWords":["daughter","people","land","LORD","Zion","King","anger"],"peopleInVerse":[],"placesInVerse":["Mount Zion"],"themesInVerse":["kingship","land_promise"]},"20":{"text":"The harvest is past, the summer is ended, and we are not saved.","ref":"Jeremiah 8:20","synthesized":"“The harvest has passed, the summer has ended, but we have not been saved.”","sources":{"KJV":{"text":"The harvest is past, the summer is ended, and we are not saved."},"BSB":{"text":"“The harvest has passed, the summer has ended, but we have not been saved.”"},"TANAKH":{"text":"'The harvest is past, the summer is ended, and we are not saved.'"},"HEBREW":{"text":"עָבַ֥ר קָצִ֖יר כָּ֣לָה קָ֑יִץ וַאֲנַ֖חְנוּ ל֥וֹא נוֹשָֽׁעְנוּ׃"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"For the hurt of the daughter of my people am I hurt; I am black; astonishment hath taken hold on me.","ref":"Jeremiah 8:21","synthesized":"For the brokenness of the daughter of my people I am crushed. I mourn; horror has gripped me.","sources":{"KJV":{"text":"For the hurt of the daughter of my people am I hurt; I am black; astonishment hath taken hold on me."},"BSB":{"text":"For the brokenness of the daughter of my people I am crushed. I mourn; horror has gripped me."},"TANAKH":{"text":"For the hurt of the daughter of my people am I seized with anguish; I am black, appalment hath taken hold on me."},"HEBREW":{"text":"עַל־שֶׁ֥בֶר בַּת־עַמִּ֖י הָשְׁבָּ֑רְתִּי קָדַ֕רְתִּי שַׁמָּ֖ה הֶחֱזִקָֽתְנִי׃"}},"definableWords":["daughter","people"],"peopleInVerse":[]},"22":{"text":"Is there no balm in Gilead; is there no physician there? why then is not the health of the daughter of my people recovered?","ref":"Jeremiah 8:22","synthesized":"Is there no balm in Gilead? Is no physician there? Why then has the health of the daughter of my people not been restored?","sources":{"KJV":{"text":"Is there no balm in Gilead; is there no physician there? why then is not the health of the daughter of my people recovered?"},"BSB":{"text":"Is there no balm in Gilead? Is no physician there? Why then has the health of the daughter of my people not been restored?"},"TANAKH":{"text":"Is there no balm in Gilead? Is there no physician there? Why then is not the health of the daughter of my people recovered?"},"HEBREW":{"text":"הַצֳרִי֙ אֵ֣ין בְּגִלְעָ֔ד אִם־רֹפֵ֖א אֵ֣ין שָׁ֑ם כִּ֗י מַדּ֙וּעַ֙ לֹ֣א עָֽלְתָ֔ה אֲרֻכַ֖ת בַּת־עַמִּֽי׃"}},"definableWords":["daughter","people"],"peopleInVerse":[]}}},"9":{"chapter":"9","title":"LET HIM THAT GLORIETH GLORY IN THIS","verses":{"1":{"text":"Oh that my head were waters, and mine eyes a fountain of tears, that I might weep day and night for the slain of the daughter of my people!","ref":"Jeremiah 9:1","synthesized":"Oh, that my head were a spring of water, and my eyes a fountain of tears! I would weep day and night over the slain daughter of my people.","sources":{"KJV":{"text":"Oh that my head were waters, and mine eyes a fountain of tears, that I might weep day and night for the slain of the daughter of my people!"},"BSB":{"text":"Oh, that my head were a spring of water, and my eyes a fountain of tears! I would weep day and night over the slain daughter of my people."},"TANAKH":{"text":"Oh that I were in the wilderness, in a lodging-place of wayfaring men, that I might leave my people, and go from them! For they are all adulterers, an assembly of treacherous men."},"HEBREW":{"text":"מִֽי־יִתְּנֵ֣נִי בַמִּדְבָּ֗ר מְלוֹן֙ אֹֽרְחִ֔ים וְאֶֽעֶזְבָה֙ אֶת־עַמִּ֔י וְאֵלְכָ֖ה מֵֽאִתָּ֑ם כִּ֤י כֻלָּם֙ מְנָ֣אֲפִ֔ים עֲצֶ֖רֶת בֹּגְדִֽים׃"}},"definableWords":["water","day","night","daughter","people"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"2":{"text":"Oh that I had in the wilderness a lodging place of wayfaring men; that I might leave my people, and go from them! for they be all adulterers, an assembly of treacherous men.","ref":"Jeremiah 9:2","synthesized":"If only I had a traveler’s lodge in the wilderness, I would abandon my people and depart from them, for they are all adulterers, a crowd of faithless people.","sources":{"KJV":{"text":"Oh that I had in the wilderness a lodging place of wayfaring men; that I might leave my people, and go from them! for they be all adulterers, an assembly of treacherous men."},"BSB":{"text":"If only I had a traveler’s lodge in the wilderness, I would abandon my people and depart from them, for they are all adulterers, a crowd of faithless people."},"TANAKH":{"text":"And they bend their tongue, their bow of falsehood; and they are grown mighty in the land, but not for truth; for they proceed from evil to evil, and Me they know not, saith HaShem."},"HEBREW":{"text":"וַֽיַּדְרְכ֤וּ אֶת־לְשׁוֹנָם֙ קַשְׁתָּ֣ם שֶׁ֔קֶר וְלֹ֥א לֶאֱמוּנָ֖ה גָּבְר֣וּ בָאָ֑רֶץ כִּי֩ מֵרָעָ֨ה אֶל־רָעָ֧ה ׀ יָצָ֛אוּ וְאֹתִ֥י לֹֽא־יָדָ֖עוּ נְאֻם־יְהוָֽה׃"}},"definableWords":["people"],"peopleInVerse":[]},"3":{"text":"And they bend their tongues like their bow for lies: but they are not valiant for the truth upon the earth; for they proceed from evil to evil, and they know not me, saith the LORD.","ref":"Jeremiah 9:3","synthesized":"“They bend their tongues like bows; lies prevail over truth in the land. For they proceed from evil to evil, and they do not take Me into account,” declares the LORD.","sources":{"KJV":{"text":"And they bend their tongues like their bow for lies: but they are not valiant for the truth upon the earth; for they proceed from evil to evil, and they know not me, saith the LORD."},"BSB":{"text":"“They bend their tongues like bows; lies prevail over truth in the land. For they proceed from evil to evil, and they do not take Me into account,” declares the LORD."},"TANAKH":{"text":"Take ye heed every one of his neighbour, and trust ye not in any brother; for every brother acteth subtly, and every neighbour goeth about with slanders."},"HEBREW":{"text":"אִ֤ישׁ מֵרֵעֵ֙הוּ֙ הִשָּׁמֵ֔רוּ וְעַל־כָּל־אָ֖ח אַל־תִּבְטָ֑חוּ כִּ֤י כָל־אָח֙ עָק֣וֹב יַעְקֹ֔ב וְכָל־רֵ֖עַ רָכִ֥יל יַהֲלֹֽךְ׃"}},"definableWords":["truth","land","evil","LORD"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"4":{"text":"Take ye heed every one of his neighbour, and trust ye not in any brother: for every brother will utterly supplant, and every neighbour will walk with slanders.","ref":"Jeremiah 9:4","synthesized":"“Let everyone guard against his neighbor; do not trust any brother, for every brother deals craftily, and every friend spreads slander.","sources":{"KJV":{"text":"Take ye heed every one of his neighbour, and trust ye not in any brother: for every brother will utterly supplant, and every neighbour will walk with slanders."},"BSB":{"text":"“Let everyone guard against his neighbor; do not trust any brother, for every brother deals craftily, and every friend spreads slander."},"TANAKH":{"text":"And they deceive every one his neighbour, and truth they speak not; they have taught their tongue to speak lies, they weary themselves to commit iniquity."},"HEBREW":{"text":"וְאִ֤ישׁ בְּרֵעֵ֙הוּ֙ יְהָתֵ֔לּוּ וֶאֱמֶ֖ת לֹ֣א יְדַבֵּ֑רוּ לִמְּד֧וּ לְשׁוֹנָ֛ם דַּבֶּר־שֶׁ֖קֶר הַעֲוֵ֥ה נִלְאֽוּ׃"}},"definableWords":["trust","brother"],"peopleInVerse":[],"themesInVerse":["faith"]},"5":{"text":"And they will deceive every one his neighbour, and will not speak the truth: they have taught their tongue to speak lies, and weary themselves to commit iniquity.","ref":"Jeremiah 9:5","synthesized":"Each one betrays his friend; no one tells the truth. They have taught their tongues to lie; they wear themselves out committing iniquity.","sources":{"KJV":{"text":"And they will deceive every one his neighbour, and will not speak the truth: they have taught their tongue to speak lies, and weary themselves to commit iniquity."},"BSB":{"text":"Each one betrays his friend; no one tells the truth. They have taught their tongues to lie; they wear themselves out committing iniquity."},"TANAKH":{"text":"Thy habitation is in the midst of deceit; through deceit they refuse to know Me, saith HaShem."},"HEBREW":{"text":"שִׁבְתְּךָ֖ בְּת֣וֹךְ מִרְמָ֑ה בְּמִרְמָ֛ה מֵאֲנ֥וּ דַֽעַת־אוֹתִ֖י נְאֻם־יְהוָֽה׃"}},"definableWords":["one","truth","iniquity"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"6":{"text":"Thine habitation is in the midst of deceit; through deceit they refuse to know me, saith the LORD.","ref":"Jeremiah 9:6","synthesized":"You dwell in the midst of deception; in their deceit they refuse to know Me,” declares the LORD.","sources":{"KJV":{"text":"Thine habitation is in the midst of deceit; through deceit they refuse to know me, saith the LORD."},"BSB":{"text":"You dwell in the midst of deception; in their deceit they refuse to know Me,” declares the LORD."},"TANAKH":{"text":"Therefore thus saith HaShem of hosts: behold, I will smelt them, and try them; for how else should I do, because of the daughter of My people?"},"HEBREW":{"text":"לָכֵ֗ן כֹּ֤ה אָמַר֙ יְהוָ֣ה צְבָא֔וֹת הִנְנִ֥י צוֹרְפָ֖ם וּבְחַנְתִּ֑ים כִּֽי־אֵ֣יךְ אֶעֱשֶׂ֔ה מִפְּנֵ֖י בַּת־עַמִּֽי׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"7":{"text":"Therefore thus saith the LORD of hosts, Behold, I will melt them, and try them; for how shall I do for the daughter of my people?","ref":"Jeremiah 9:7","synthesized":"Therefore this is what the LORD of Hosts says:  “Behold, I will refine them and test them, for what else can I do because of the daughter of My people?","sources":{"KJV":{"text":"Therefore thus saith the LORD of hosts, Behold, I will melt them, and try them; for how shall I do for the daughter of my people?"},"BSB":{"text":"Therefore this is what the LORD of Hosts says:  “Behold, I will refine them and test them, for what else can I do because of the daughter of My people?"},"TANAKH":{"text":"Their tongue is a sharpened arrow, it speaketh deceit; one speaketh peaceably to his neighbour with his mouth, but in his heart he layeth wait for him."},"HEBREW":{"text":"חֵ֥ץ שוחט שָׁח֛וּט לְשׁוֹנָ֖ם מִרְמָ֣ה דִבֵּ֑ר בְּפִ֗יו שָׁל֤וֹם אֶת־רֵעֵ֙הוּ֙ יְדַבֵּ֔ר וּבְקִרְבּ֖וֹ יָשִׂ֥ים אָרְבּֽוֹ׃"}},"definableWords":["LORD","daughter","people"],"peopleInVerse":[]},"8":{"text":"Their tongue is as an arrow shot out; it speaketh deceit: one speaketh peaceably to his neighbour with his mouth, but in heart he layeth his wait.","ref":"Jeremiah 9:8","synthesized":"Their tongues are deadly arrows; they speak deception. With his mouth a man speaks peace to his neighbor, but in his heart he sets a trap for him.","sources":{"KJV":{"text":"Their tongue is as an arrow shot out; it speaketh deceit: one speaketh peaceably to his neighbour with his mouth, but in heart he layeth his wait."},"BSB":{"text":"Their tongues are deadly arrows; they speak deception. With his mouth a man speaks peace to his neighbor, but in his heart he sets a trap for him."},"TANAKH":{"text":"Shall I not punish them for these things? saith HaShem; shall not My soul be avenged on such a nation as this?"},"HEBREW":{"text":"הַעַל־אֵ֥לֶּה לֹֽא־אֶפְקָד־בָּ֖ם נְאֻם־יְהוָ֑ה אִ֚ם בְּג֣וֹי אֲשֶׁר־כָּזֶ֔ה לֹ֥א תִתְנַקֵּ֖ם נַפְשִֽׁי׃"}},"definableWords":["man","peace","heart"],"peopleInVerse":[],"themesInVerse":["peace"]},"9":{"text":"Shall I not visit them for these things? saith the LORD: shall not my soul be avenged on such a nation as this?","ref":"Jeremiah 9:9","synthesized":"Should I not punish them for these things? declares the LORD. Should I not avenge Myself on such a nation as this?”","sources":{"KJV":{"text":"Shall I not visit them for these things? saith the LORD: shall not my soul be avenged on such a nation as this?"},"BSB":{"text":"Should I not punish them for these things? declares the LORD. Should I not avenge Myself on such a nation as this?”"},"TANAKH":{"text":"For the mountains will I take up a weeping and wailing, and for the pastures of the wilderness a lamentation, because they are burned up, so that none passeth through. And they hear not the voice of the cattle; both the fowl of the heavens and the beast are fled, and gone."},"HEBREW":{"text":"עַל־הֶ֨הָרִ֜ים אֶשָּׂ֧א בְכִ֣י וָנֶ֗הִי וְעַל־נְא֤וֹת מִדְבָּר֙ קִינָ֔ה כִּ֤י נִצְּתוּ֙ מִבְּלִי־אִ֣ישׁ עֹבֵ֔ר וְלֹ֥א שָׁמְע֖וּ ק֣וֹל מִקְנֶ֑ה מֵע֤וֹף הַשָּׁמַ֙יִם֙ וְעַד־בְּהֵמָ֔ה נָדְד֖וּ הָלָֽכוּ׃"}},"definableWords":["LORD","nation"],"peopleInVerse":[]},"10":{"text":"For the mountains will I take up a weeping and wailing, and for the habitations of the wilderness a lamentation, because they are burned up, so that none can pass through them; neither can men hear the voice of the cattle; both the fowl of the heavens and the beast are fled; they are gone.","ref":"Jeremiah 9:10","synthesized":"I will take up a weeping and wailing for the mountains, a dirge over the wilderness pasture, for they have been scorched so no one passes through, and the lowing of cattle is not heard. Both the birds of the air and the beasts have fled; they have gone away.","sources":{"KJV":{"text":"For the mountains will I take up a weeping and wailing, and for the habitations of the wilderness a lamentation, because they are burned up, so that none can pass through them; neither can men hear the voice of the cattle; both the fowl of the heavens and the beast are fled; they are gone."},"BSB":{"text":"I will take up a weeping and wailing for the mountains, a dirge over the wilderness pasture, for they have been scorched so no one passes through, and the lowing of cattle is not heard. Both the birds of the air and the beasts have fled; they have gone away."},"TANAKH":{"text":"And I will make Jerusalem heaps, a lair of jackals; and I will make the cities of Judah a desolation, without an inhabitant."},"HEBREW":{"text":"וְנָתַתִּ֧י אֶת־יְרוּשָׁלַ֛͏ִם לְגַלִּ֖ים מְע֣וֹן תַּנִּ֑ים וְאֶת־עָרֵ֧י יְהוּדָ֛ה אֶתֵּ֥ן שְׁמָמָ֖ה מִבְּלִ֖י יוֹשֵֽׁב׃"}},"definableWords":["one","cattle","birds"],"peopleInVerse":[]},"11":{"text":"And I will make Jerusalem heaps, and a den of dragons; and I will make the cities of Judah desolate, without an inhabitant.","ref":"Jeremiah 9:11","synthesized":"“And I will make Jerusalem a heap of rubble, a haunt for jackals; and I will make the cities of Judah a desolation, without inhabitant.”","sources":{"KJV":{"text":"And I will make Jerusalem heaps, and a den of dragons; and I will make the cities of Judah desolate, without an inhabitant."},"BSB":{"text":"“And I will make Jerusalem a heap of rubble, a haunt for jackals; and I will make the cities of Judah a desolation, without inhabitant.”"},"TANAKH":{"text":"Who is the wise man, that he may understand this? And who is he to whom the mouth of HaShem hath spoken, that he may declare it? Wherefore is the land perished and laid waste like a wilderness, so that none passeth through?"},"HEBREW":{"text":"מִֽי־הָאִ֤ישׁ הֶֽחָכָם֙ וְיָבֵ֣ן אֶת־זֹ֔את וַאֲשֶׁ֨ר דִּבֶּ֧ר פִּֽי־יְהוָ֛ה אֵלָ֖יו וְיַגִּדָ֑הּ עַל־מָה֙ אָבְדָ֣ה הָאָ֔רֶץ נִצְּתָ֥ה כַמִּדְבָּ֖ר מִבְּלִ֖י עֹבֵֽר׃"}},"definableWords":["make","Jerusalem","Judah"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"12":{"text":"Who is the wise man, that may understand this? and who is he to whom the mouth of the LORD hath spoken, that he may declare it, for what the land perisheth and is burned up like a wilderness, that none passeth through?","ref":"Jeremiah 9:12","synthesized":"Who is the man wise enough to understand this? To whom has the mouth of the LORD spoken, that he may explain it? Why is the land destroyed and scorched like a desert, so no one can pass through it?","sources":{"KJV":{"text":"Who is the wise man, that may understand this? and who is he to whom the mouth of the LORD hath spoken, that he may declare it, for what the land perisheth and is burned up like a wilderness, that none passeth through?"},"BSB":{"text":"Who is the man wise enough to understand this? To whom has the mouth of the LORD spoken, that he may explain it? Why is the land destroyed and scorched like a desert, so no one can pass through it?"},"TANAKH":{"text":"And HaShem saith: Because they have forsaken My law which I set before them, and have not hearkened to My voice, neither walked therein;"},"HEBREW":{"text":"וַיֹּ֣אמֶר יְהוָ֔ה עַל־עָזְבָם֙ אֶת־תּ֣וֹרָתִ֔י אֲשֶׁ֥ר נָתַ֖תִּי לִפְנֵיהֶ֑ם וְלֹא־שָׁמְע֥וּ בְקוֹלִ֖י וְלֹא־הָ֥לְכוּ בָֽהּ׃"}},"definableWords":["man","LORD","land","one"],"peopleInVerse":[],"themesInVerse":["land_promise","wisdom"]},"13":{"text":"And the LORD saith, Because they have forsaken my law which I set before them, and have not obeyed my voice, neither walked therein;","ref":"Jeremiah 9:13","synthesized":"And the LORD answered, “It is because they have forsaken My law, which I set before them; they have not walked in it or obeyed My voice.","sources":{"KJV":{"text":"And the LORD saith, Because they have forsaken my law which I set before them, and have not obeyed my voice, neither walked therein;"},"BSB":{"text":"And the LORD answered, “It is because they have forsaken My law, which I set before them; they have not walked in it or obeyed My voice."},"TANAKH":{"text":"But have walked after the stubbornness of their own heart, and after the Baalim, which their fathers taught them."},"HEBREW":{"text":"וַיֵּ֣לְכ֔וּ אַחֲרֵ֖י שְׁרִר֣וּת לִבָּ֑ם וְאַחֲרֵי֙ הַבְּעָלִ֔ים אֲשֶׁ֥ר לִמְּד֖וּם אֲבוֹתָֽם׃"}},"definableWords":["LORD","law","walked","or","voice"],"peopleInVerse":[]},"14":{"text":"But have walked after the imagination of their own heart, and after Baalim, which their fathers taught them:","ref":"Jeremiah 9:14","synthesized":"Instead, they have followed the stubbornness of their hearts and gone after the Baals, as their fathers taught them.”","sources":{"KJV":{"text":"But have walked after the imagination of their own heart, and after Baalim, which their fathers taught them:"},"BSB":{"text":"Instead, they have followed the stubbornness of their hearts and gone after the Baals, as their fathers taught them.”"},"TANAKH":{"text":"Therefore thus saith HaShem of hosts, the G-d of Israel: Behold, I will feed them, even this people, with wormwood, and give them water of gall to drink."},"HEBREW":{"text":"לָכֵ֗ן כֹּֽה־אָמַ֞ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל הִנְנִ֧י מַאֲכִילָ֛ם אֶת־הָעָ֥ם הַזֶּ֖ה לַֽעֲנָ֑ה וְהִשְׁקִיתִ֖ים מֵי־רֹֽאשׁ׃"}},"definableWords":["fathers"],"peopleInVerse":[]},"15":{"text":"Therefore thus saith the LORD of hosts, the God of Israel; Behold, I will feed them, even this people, with wormwood, and give them water of gall to drink.","ref":"Jeremiah 9:15","synthesized":"Therefore this is what the LORD of Hosts, the God of Israel, says: “Behold, I will feed this people wormwood and give them poisoned water to drink.","sources":{"KJV":{"text":"Therefore thus saith the LORD of hosts, the God of Israel; Behold, I will feed them, even this people, with wormwood, and give them water of gall to drink."},"BSB":{"text":"Therefore this is what the LORD of Hosts, the God of Israel, says: “Behold, I will feed this people wormwood and give them poisoned water to drink."},"TANAKH":{"text":"I will scatter them also among the nations, whom neither they nor their fathers have known; and I will send the sword after them, till I have consumed them."},"HEBREW":{"text":"וַהֲפִֽצוֹתִים֙ בַּגּוֹיִ֔ם אֲשֶׁר֙ לֹ֣א יָֽדְע֔וּ הֵ֖מָּה וַֽאֲבוֹתָ֑ם וְשִׁלַּחְתִּ֤י אַֽחֲרֵיהֶם֙ אֶת־הַחֶ֔רֶב עַ֥ד כַּלּוֹתִ֖י אוֹתָֽם׃"}},"definableWords":["LORD","God","Israel","people","water"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"16":{"text":"I will scatter them also among the heathen, whom neither they nor their fathers have known: and I will send a sword after them, till I have consumed them.","ref":"Jeremiah 9:16","synthesized":"I will scatter them among the nations that neither they nor their fathers have known, and I will send a sword after them until I have finished them off.”","sources":{"KJV":{"text":"I will scatter them also among the heathen, whom neither they nor their fathers have known: and I will send a sword after them, till I have consumed them."},"BSB":{"text":"I will scatter them among the nations that neither they nor their fathers have known, and I will send a sword after them until I have finished them off.”"},"TANAKH":{"text":"Thus saith HaShem of hosts: Consider ye, and call for the mourning women, that they may come; and send for the wise women, that they may come;"},"HEBREW":{"text":"כֹּ֤ה אָמַר֙ יְהוָ֣ה צְבָא֔וֹת הִתְבּֽוֹנְנ֛וּ וְקִרְא֥וּ לַמְקוֹנְנ֖וֹת וּתְבוֹאֶ֑ינָה וְאֶל־הַחֲכָמ֥וֹת שִׁלְח֖וּ וְתָבֽוֹאנָה׃"}},"definableWords":["nations","fathers"],"peopleInVerse":[]},"17":{"text":"Thus saith the LORD of hosts, Consider ye, and call for the mourning women, that they may come; and send for cunning women, that they may come:","ref":"Jeremiah 9:17","synthesized":"This is what the LORD of Hosts says:  “Take note, and summon the wailing women; send for the most skillful among them.","sources":{"KJV":{"text":"Thus saith the LORD of hosts, Consider ye, and call for the mourning women, that they may come; and send for cunning women, that they may come:"},"BSB":{"text":"This is what the LORD of Hosts says:  “Take note, and summon the wailing women; send for the most skillful among them."},"TANAKH":{"text":"And let them make haste, and take up a wailing for us, that our eyes may run down with tears, and our eyelids gush out with waters."},"HEBREW":{"text":"וּתְמַהֵ֕רְנָה וְתִשֶּׂ֥נָה עָלֵ֖ינוּ נֶ֑הִי וְתֵרַ֤דְנָה עֵינֵ֙ינוּ֙ דִּמְעָ֔ה וְעַפְעַפֵּ֖ינוּ יִזְּלוּ־מָֽיִם׃"}},"definableWords":["LORD","women"],"peopleInVerse":[]},"18":{"text":"And let them make haste, and take up a wailing for us, that our eyes may run down with tears, and our eyelids gush out with waters.","ref":"Jeremiah 9:18","synthesized":"Let them come quickly and take up a lament over us, that our eyes may overflow with tears, and our eyelids may gush with water.","sources":{"KJV":{"text":"And let them make haste, and take up a wailing for us, that our eyes may run down with tears, and our eyelids gush out with waters."},"BSB":{"text":"Let them come quickly and take up a lament over us, that our eyes may overflow with tears, and our eyelids may gush with water."},"TANAKH":{"text":"For a voice of wailing is heard out of Zion: 'How are we undone! We are greatly confounded, because we have forsaken the land, because our dwellings have cast us out.'"},"HEBREW":{"text":"כִּ֣י ק֥וֹל נְהִ֛י נִשְׁמַ֥ע מִצִיּ֖וֹן אֵ֣יךְ שֻׁדָּ֑דְנוּ בֹּ֤שְׁנֽוּ מְאֹד֙ כִּֽי־עָזַ֣בְנוּ אָ֔רֶץ כִּ֥י הִשְׁלִ֖יכוּ מִשְׁכְּנוֹתֵֽינוּ׃"}},"definableWords":["water"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"19":{"text":"For a voice of wailing is heard out of Zion, How are we spoiled! we are greatly confounded, because we have forsaken the land, because our dwellings have cast us out.","ref":"Jeremiah 9:19","synthesized":"For the sound of wailing is heard from Zion: ‘How devastated we are! How great is our shame! For we have abandoned the land because our dwellings have been torn down.’”","sources":{"KJV":{"text":"For a voice of wailing is heard out of Zion, How are we spoiled! we are greatly confounded, because we have forsaken the land, because our dwellings have cast us out."},"BSB":{"text":"For the sound of wailing is heard from Zion: ‘How devastated we are! How great is our shame! For we have abandoned the land because our dwellings have been torn down.’”"},"TANAKH":{"text":"Yea, hear the word of HaShem, O ye women, and let your ear receive the word of His mouth, and teach your daughters wailing, and every one her neighbour lamentation:"},"HEBREW":{"text":"כִּֽי־שְׁמַ֤עְנָה נָשִׁים֙ דְּבַר־יְהוָ֔ה וְתִקַּ֥ח אָזְנְכֶ֖ם דְּבַר־פִּ֑יו וְלַמֵּ֤דְנָה בְנֽוֹתֵיכֶם֙ נֶ֔הִי וְאִשָּׁ֥ה רְעוּתָ֖הּ קִינָֽה׃"}},"definableWords":["Zion","great","land"],"peopleInVerse":[],"placesInVerse":["Mount Zion"],"themesInVerse":["land_promise"]},"20":{"text":"Yet hear the word of the LORD, O ye women, and let your ear receive the word of his mouth, and teach your daughters wailing, and every one her neighbour lamentation.","ref":"Jeremiah 9:20","synthesized":"Now, O women, hear the word of the LORD. Open your ears to the word of His mouth. Teach your daughters to wail, and one another to lament.","sources":{"KJV":{"text":"Yet hear the word of the LORD, O ye women, and let your ear receive the word of his mouth, and teach your daughters wailing, and every one her neighbour lamentation."},"BSB":{"text":"Now, O women, hear the word of the LORD. Open your ears to the word of His mouth. Teach your daughters to wail, and one another to lament."},"TANAKH":{"text":"'For death is come up into our windows, it is entered into our palaces, to cut off the children from the street, and the young men from the broad places.--"},"HEBREW":{"text":"כִּֽי־עָ֤לָה מָ֙וֶת֙ בְּחַלּוֹנֵ֔ינוּ בָּ֖א בְּאַרְמְנוֹתֵ֑ינוּ לְהַכְרִ֤ית עוֹלָל֙ מִח֔וּץ בַּחוּרִ֖ים מֵרְחֹבֽוֹת׃"}},"definableWords":["women","hear","word","LORD","daughters","one"],"peopleInVerse":[]},"21":{"text":"For death is come up into our windows, and is entered into our palaces, to cut off the children from without, and the young men from the streets.","ref":"Jeremiah 9:21","synthesized":"For death has climbed in through our windows; it has entered our fortresses to cut off the children from the streets, the young men from the town squares.","sources":{"KJV":{"text":"For death is come up into our windows, and is entered into our palaces, to cut off the children from without, and the young men from the streets."},"BSB":{"text":"For death has climbed in through our windows; it has entered our fortresses to cut off the children from the streets, the young men from the town squares."},"TANAKH":{"text":"Speak: Thus saith HaShem--And the carcasses of men fall as dung upon the open field, and as the handful after the harvestman, which none gathereth.'"},"HEBREW":{"text":"דַּבֵּ֗ר כֹּ֚ה נְאֻם־יְהוָ֔ה וְנָֽפְלָה֙ נִבְלַ֣ת הָֽאָדָ֔ם כְּדֹ֖מֶן עַל־פְּנֵ֣י הַשָּׂדֶ֑ה וּכְעָמִ֛יר מֵאַחֲרֵ֥י הַקֹּצֵ֖ר וְאֵ֥ין מְאַסֵּֽף׃"}},"definableWords":["death","men"],"peopleInVerse":[]},"22":{"text":"Speak, Thus saith the LORD, Even the carcases of men shall fall as dung upon the open field, and as the handful after the harvestman, and none shall gather them.","ref":"Jeremiah 9:22","synthesized":"Declare that this is what the LORD says:  “The corpses of men will fall like dung upon the open field, like newly cut grain behind the reaper, with no one to gather it.”","sources":{"KJV":{"text":"Speak, Thus saith the LORD, Even the carcases of men shall fall as dung upon the open field, and as the handful after the harvestman, and none shall gather them."},"BSB":{"text":"Declare that this is what the LORD says:  “The corpses of men will fall like dung upon the open field, like newly cut grain behind the reaper, with no one to gather it.”"},"TANAKH":{"text":"Thus saith HaShem: Let not the wise man glory in his wisdom, neither let the mighty man glory in his might, let not the rich man glory in his riches;"},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה אַל־יִתְהַלֵּ֤ל חָכָם֙ בְּחָכְמָת֔וֹ וְאַל־יִתְהַלֵּ֥ל הַגִּבּ֖וֹר בִּגְבֽוּרָת֑וֹ אַל־יִתְהַלֵּ֥ל עָשִׁ֖יר בְּעָשְׁרֽוֹ׃"}},"definableWords":["LORD","men","field","one"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"23":{"text":"Thus saith the LORD, Let not the wise man glory in his wisdom, neither let the mighty man glory in his might, let not the rich man glory in his riches:","ref":"Jeremiah 9:23","synthesized":"This is what the LORD says:  “Let not the wise man boast in his wisdom, nor the strong man in his strength, nor the wealthy man in his riches.","sources":{"KJV":{"text":"Thus saith the LORD, Let not the wise man glory in his wisdom, neither let the mighty man glory in his might, let not the rich man glory in his riches:"},"BSB":{"text":"This is what the LORD says:  “Let not the wise man boast in his wisdom, nor the strong man in his strength, nor the wealthy man in his riches."},"TANAKH":{"text":"But let him that glorieth glory in this, that he understandeth, and knoweth Me, that I am HaShem who exercise mercy, justice, and righteousness, in the earth; for in these things I delight, saith HaShem."},"HEBREW":{"text":"כִּ֣י אִם־בְּזֹ֞את יִתְהַלֵּ֣ל הַמִּתְהַלֵּ֗ל הַשְׂכֵּל֮ וְיָדֹ֣עַ אוֹתִי֒ כִּ֚י אֲנִ֣י יְהוָ֔ה עֹ֥שֶׂה חֶ֛סֶד מִשְׁפָּ֥ט וּצְדָקָ֖ה בָּאָ֑רֶץ כִּֽי־בְאֵ֥לֶּה חָפַ֖צְתִּי נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD","man","wisdom","strong"],"peopleInVerse":[],"themesInVerse":["wisdom"]},"24":{"text":"But let him that glorieth glory in this, that he understandeth and knoweth me, that I am the LORD which exercise lovingkindness, judgment, and righteousness, in the earth: for in these things I delight, saith the LORD.","ref":"Jeremiah 9:24","synthesized":"But let him who boasts boast in this, that he understands and knows Me, that I am the LORD, who exercises loving devotion, justice and righteousness on the earth— for I delight in these things,” declares the LORD.","sources":{"KJV":{"text":"But let him that glorieth glory in this, that he understandeth and knoweth me, that I am the LORD which exercise lovingkindness, judgment, and righteousness, in the earth: for in these things I delight, saith the LORD."},"BSB":{"text":"But let him who boasts boast in this, that he understands and knows Me, that I am the LORD, who exercises loving devotion, justice and righteousness on the earth— for I delight in these things,” declares the LORD."},"TANAKH":{"text":"Behold, the days come, saith HaShem, that I will punish all them that are circumcised in their uncircumcision:"},"HEBREW":{"text":"הִנֵּ֛ה יָמִ֥ים בָּאִ֖ים נְאֻם־יְהוָ֑ה וּפָ֣קַדְתִּ֔י עַל־כָּל־מ֖וּל בְּעָרְלָֽה׃"}},"definableWords":["LORD","justice","righteousness","earth","Lord"],"peopleInVerse":[],"themesInVerse":["joy"]},"25":{"text":"Behold, the days come, saith the LORD, that I will punish all them which are circumcised with the uncircumcised;","ref":"Jeremiah 9:25","synthesized":"“Behold, the days are coming,” declares the LORD, “when I will punish all who are circumcised yet uncircumcised:","sources":{"KJV":{"text":"Behold, the days come, saith the LORD, that I will punish all them which are circumcised with the uncircumcised;"},"BSB":{"text":"“Behold, the days are coming,” declares the LORD, “when I will punish all who are circumcised yet uncircumcised:"},"TANAKH":{"text":"Egypt, and Judah, and Edom, and the children of Ammon, and Moab, and all that have the corners of their hair polled, that dwell in the wilderness; for all the nations are uncircumcised, but all the house of Israel are uncircumcised in the heart."},"HEBREW":{"text":"עַל־מִצְרַ֣יִם וְעַל־יְהוּדָ֗ה וְעַל־אֱד֞וֹם וְעַל־בְּנֵ֤י עַמּוֹן֙ וְעַל־מוֹאָ֔ב וְעַל֙ כָּל־קְצוּצֵ֣י פֵאָ֔ה הַיֹּשְׁבִ֖ים בַּמִּדְבָּ֑ר כִּ֤י כָל־הַגּוֹיִם֙ עֲרֵלִ֔ים וְכָל־בֵּ֥ית יִשְׂרָאֵ֖ל עַרְלֵי־לֵֽב׃"}},"definableWords":["days","LORD","circumcised"],"peopleInVerse":[],"themesInVerse":["second_coming"]},"26":{"text":"Egypt, and Judah, and Edom, and the children of Ammon, and Moab, and all that are in the utmost corners, that dwell in the wilderness: for all these nations are uncircumcised, and all the house of Israel are uncircumcised in the heart.","ref":"Jeremiah 9:26","synthesized":"Egypt, Judah, Edom, Ammon, Moab, and all the inhabitants of the desert who clip the hair of their temples. For all these nations are uncircumcised, and the whole house of Israel is uncircumcised in heart.”","sources":{"KJV":{"text":"Egypt, and Judah, and Edom, and the children of Ammon, and Moab, and all that are in the utmost corners, that dwell in the wilderness: for all these nations are uncircumcised, and all the house of Israel are uncircumcised in the heart."},"BSB":{"text":"Egypt, Judah, Edom, Ammon, Moab, and all the inhabitants of the desert who clip the hair of their temples. For all these nations are uncircumcised, and the whole house of Israel is uncircumcised in heart.”"}},"definableWords":["Egypt","Judah","Edom","nations","house","Israel","heart"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern"]}}},"10":{"chapter":"10","title":"LEARN NOT THE WAY OF THE HEATHEN","verses":{"1":{"text":"Hear ye the word which the LORD speaketh unto you, O house of Israel:","ref":"Jeremiah 10:1","synthesized":"Hear the word that the LORD speaks to you, O house of Israel.","sources":{"KJV":{"text":"Hear ye the word which the LORD speaketh unto you, O house of Israel:"},"BSB":{"text":"Hear the word that the LORD speaks to you, O house of Israel."},"TANAKH":{"text":"Hear ye the word which HaShem speaketh unto you, O house of Israel;"},"HEBREW":{"text":"שִׁמְע֣וּ אֶת־הַדָּבָ֗ר אֲשֶׁ֨ר דִּבֶּ֧ר יְהוָ֛ה עֲלֵיכֶ֖ם בֵּ֥ית יִשְׂרָאֵֽל׃"}},"definableWords":["hear","word","LORD","house","Israel"],"peopleInVerse":[]},"2":{"text":"Thus saith the LORD, Learn not the way of the heathen, and be not dismayed at the signs of heaven; for the heathen are dismayed at them.","ref":"Jeremiah 10:2","synthesized":"This is what the LORD says:  “Do not learn the ways of the nations or be terrified by the signs in the heavens, though the nations themselves are terrified by them.","sources":{"KJV":{"text":"Thus saith the LORD, Learn not the way of the heathen, and be not dismayed at the signs of heaven; for the heathen are dismayed at them."},"BSB":{"text":"This is what the LORD says:  “Do not learn the ways of the nations or be terrified by the signs in the heavens, though the nations themselves are terrified by them."},"TANAKH":{"text":"thus saith HaShem: Learn not the way of the nations, and be not dismayed at the signs of heaven; for the nations are dismayed at them."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה אֶל־דֶּ֤רֶךְ הַגּוֹיִם֙ אַל־תִּלְמָ֔דוּ וּמֵאֹת֥וֹת הַשָּׁמַ֖יִם אַל־תֵּחָ֑תּוּ כִּֽי־יֵחַ֥תּוּ הַגּוֹיִ֖ם מֵהֵֽמָּה׃"}},"definableWords":["LORD","nations","or","heavens"],"peopleInVerse":[]},"3":{"text":"For the customs of the people are vain: for one cutteth a tree out of the forest, the work of the hands of the workman, with the axe.","ref":"Jeremiah 10:3","synthesized":"For the customs of the peoples are worthless; they cut down a tree from the forest; it is shaped with a chisel by the hands of a craftsman.","sources":{"KJV":{"text":"For the customs of the people are vain: for one cutteth a tree out of the forest, the work of the hands of the workman, with the axe."},"BSB":{"text":"For the customs of the peoples are worthless; they cut down a tree from the forest; it is shaped with a chisel by the hands of a craftsman."},"TANAKH":{"text":"For the customs of the peoples are vanity; for it is but a tree which one cutteth out of the forest, the work of the hands of the workman with the axe."},"HEBREW":{"text":"כִּֽי־חֻקּ֥וֹת הָֽעַמִּ֖ים הֶ֣בֶל ה֑וּא כִּֽי־עֵץ֙ מִיַּ֣עַר כְּרָת֔וֹ מַעֲשֵׂ֥ה יְדֵ֥י־חָרָ֖שׁ בַּֽמַּעֲצָֽד׃"}},"definableWords":["tree"],"peopleInVerse":[]},"4":{"text":"They deck it with silver and with gold; they fasten it with nails and with hammers, that it move not.","ref":"Jeremiah 10:4","synthesized":"They adorn it with silver and gold and fasten it with hammer and nails, so that it will not totter.","sources":{"KJV":{"text":"They deck it with silver and with gold; they fasten it with nails and with hammers, that it move not."},"BSB":{"text":"They adorn it with silver and gold and fasten it with hammer and nails, so that it will not totter."},"TANAKH":{"text":"They deck it with silver and with gold, they fasten it with nails and with hammers, that it move not."},"HEBREW":{"text":"בְּכֶ֥סֶף וּבְזָהָ֖ב יְיַפֵּ֑הוּ בְּמַסְמְר֧וֹת וּבְמַקָּב֛וֹת יְחַזְּק֖וּם וְל֥וֹא יָפִֽיק׃"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"They are upright as the palm tree, but speak not: they must needs be borne, because they cannot go. Be not afraid of them; for they cannot do evil, neither also is it in them to do good.","ref":"Jeremiah 10:5","synthesized":"Like scarecrows in a cucumber patch, their idols cannot speak. They must be carried because they cannot walk. Do not fear them, for they can do no harm, and neither can they do any good.”","sources":{"KJV":{"text":"They are upright as the palm tree, but speak not: they must needs be borne, because they cannot go. Be not afraid of them; for they cannot do evil, neither also is it in them to do good."},"BSB":{"text":"Like scarecrows in a cucumber patch, their idols cannot speak. They must be carried because they cannot walk. Do not fear them, for they can do no harm, and neither can they do any good.”"},"TANAKH":{"text":"They are like a pillar in a garden of cucumbers, and speak not; they must needs be borne, because they cannot go. Be not afraid of them, for they cannot do evil, neither is it in them to do good."},"HEBREW":{"text":"כְּתֹ֨מֶר מִקְשָׁ֥ה הֵ֙מָּה֙ וְלֹ֣א יְדַבֵּ֔רוּ נָשׂ֥וֹא יִנָּשׂ֖וּא כִּ֣י לֹ֣א יִצְעָ֑דוּ אַל־תִּֽירְא֤וּ מֵהֶם֙ כִּי־לֹ֣א יָרֵ֔עוּ וְגַם־הֵיטֵ֖יב אֵ֥ין אוֹתָֽם׃"}},"definableWords":["walk","fear","good"],"peopleInVerse":[],"themesInVerse":["fear_of_lord"]},"6":{"text":"Forasmuch as there is none like unto thee, O LORD; thou art great, and thy name is great in might.","ref":"Jeremiah 10:6","synthesized":"There is none like You, O LORD. You are great, and Your name is mighty in power.","sources":{"KJV":{"text":"Forasmuch as there is none like unto thee, O LORD; thou art great, and thy name is great in might."},"BSB":{"text":"There is none like You, O LORD. You are great, and Your name is mighty in power."},"TANAKH":{"text":"There is none like unto Thee, O HaShem; Thou art great, and Thy name is great in might."},"HEBREW":{"text":"מֵאֵ֥ין כָּמ֖וֹךָ יְהוָ֑ה גָּד֥וֹל אַתָּ֛ה וְגָד֥וֹל שִׁמְךָ֖ בִּגְבוּרָֽה׃"}},"definableWords":["LORD","great","name","mighty"],"peopleInVerse":[]},"7":{"text":"Who would not fear thee, O King of nations? for to thee doth it appertain: forasmuch as among all the wise men of the nations, and in all their kingdoms, there is none like unto thee.","ref":"Jeremiah 10:7","synthesized":"Who would not fear You, O King of nations? This is Your due. For among all the wise men of the nations, and in all their kingdoms, there is none like You.","sources":{"KJV":{"text":"Who would not fear thee, O King of nations? for to thee doth it appertain: forasmuch as among all the wise men of the nations, and in all their kingdoms, there is none like unto thee."},"BSB":{"text":"Who would not fear You, O King of nations? This is Your due. For among all the wise men of the nations, and in all their kingdoms, there is none like You."},"TANAKH":{"text":"Who would not fear Thee, O king of the nations? For it befitteth Thee; forasmuch as among all the wise men of the nations, and in all their royalty, there is none like unto Thee."},"HEBREW":{"text":"מִ֣י לֹ֤א יִֽרָאֲךָ֙ מֶ֣לֶךְ הַגּוֹיִ֔ם כִּ֥י לְךָ֖ יָאָ֑תָה כִּ֣י בְכָל־חַכְמֵ֧י הַגּוֹיִ֛ם וּבְכָל־מַלְכוּתָ֖ם מֵאֵ֥ין כָּמֽוֹךָ׃"}},"definableWords":["fear","King","nations","men"],"peopleInVerse":[],"themesInVerse":["fear_of_lord","kingship","wisdom"]},"8":{"text":"But they are altogether brutish and foolish: the stock is a doctrine of vanities.","ref":"Jeremiah 10:8","synthesized":"But they are altogether senseless and foolish, instructed by worthless idols made of wood!","sources":{"KJV":{"text":"But they are altogether brutish and foolish: the stock is a doctrine of vanities."},"BSB":{"text":"But they are altogether senseless and foolish, instructed by worthless idols made of wood!"},"TANAKH":{"text":"But they are altogether brutish and foolish: the vanities by which they are instructed are but a stock;"},"HEBREW":{"text":"וּבְאַחַ֖ת יִבְעֲר֣וּ וְיִכְסָ֑לוּ מוּסַ֥ר הֲבָלִ֖ים עֵ֥ץ הֽוּא׃"}},"definableWords":["made"],"peopleInVerse":[],"themesInVerse":["creation"]},"9":{"text":"Silver spread into plates is brought from Tarshish, and gold from Uphaz, the work of the workman, and of the hands of the founder: blue and purple is their clothing: they are all the work of cunning men.","ref":"Jeremiah 10:9","synthesized":"Hammered silver is brought from Tarshish, and gold from Uphaz— the work of a craftsman from the hands of a goldsmith. Their clothes are blue and purple, all fashioned by skilled workers.","sources":{"KJV":{"text":"Silver spread into plates is brought from Tarshish, and gold from Uphaz, the work of the workman, and of the hands of the founder: blue and purple is their clothing: they are all the work of cunning men."},"BSB":{"text":"Hammered silver is brought from Tarshish, and gold from Uphaz— the work of a craftsman from the hands of a goldsmith. Their clothes are blue and purple, all fashioned by skilled workers."},"TANAKH":{"text":"Silver beaten into plates which is brought from Tarshish, and gold from Uphaz, the work of the craftsman and of the hands of the goldsmith; blue and purple is their clothing; they are all the work of skilful men."},"HEBREW":{"text":"כֶּ֣סֶף מְרֻקָּ֞ע מִתַּרְשִׁ֣ישׁ יוּבָ֗א וְזָהָב֙ מֵֽאוּפָ֔ז מַעֲשֵׂ֥ה חָרָ֖שׁ וִידֵ֣י צוֹרֵ֑ף תְּכֵ֤לֶת וְאַרְגָּמָן֙ לְבוּשָׁ֔ם מַעֲשֵׂ֥ה חֲכָמִ֖ים כֻּלָּֽם׃"}},"definableWords":["work"],"peopleInVerse":[]},"10":{"text":"But the LORD is the true God, he is the living God, and an everlasting king: at his wrath the earth shall tremble, and the nations shall not be able to abide his indignation.","ref":"Jeremiah 10:10","synthesized":"But the LORD is the true God; He is the living God and eternal King. The earth quakes at His wrath, and the nations cannot endure His indignation.","sources":{"KJV":{"text":"But the LORD is the true God, he is the living God, and an everlasting king: at his wrath the earth shall tremble, and the nations shall not be able to abide his indignation."},"BSB":{"text":"But the LORD is the true God; He is the living God and eternal King. The earth quakes at His wrath, and the nations cannot endure His indignation."},"TANAKH":{"text":"But HaShem G-d is the true G-d, He is the living G-d, and the everlasting King; at His wrath the earth trembleth, and the nations are not able to abide His indignation."},"HEBREW":{"text":"וַֽיהוָ֤ה אֱלֹהִים֙ אֱמֶ֔ת הֽוּא־אֱלֹהִ֥ים חַיִּ֖ים וּמֶ֣לֶךְ עוֹלָ֑ם מִקִּצְפּוֹ֙ תִּרְעַ֣שׁ הָאָ֔רֶץ וְלֹֽא־יָכִ֥לוּ גוֹיִ֖ם זַעְמֽוֹ׃"}},"definableWords":["LORD","God","living","eternal","King","earth","wrath","nations"],"peopleInVerse":[],"themesInVerse":["judgment","kingship"]},"11":{"text":"Thus shall ye say unto them, The gods that have not made the heavens and the earth, even they shall perish from the earth, and from under these heavens.","ref":"Jeremiah 10:11","synthesized":"Thus you are to tell them: “These gods, who have made neither the heavens nor the earth, will perish from this earth and from under these heavens.”","sources":{"KJV":{"text":"Thus shall ye say unto them, The gods that have not made the heavens and the earth, even they shall perish from the earth, and from under these heavens."},"BSB":{"text":"Thus you are to tell them: “These gods, who have made neither the heavens nor the earth, will perish from this earth and from under these heavens.”"},"TANAKH":{"text":"Thus shall ye say unto them: 'The gods that have not made the heavens and the earth, these shall perish from the earth, and from under the heavens.'"},"HEBREW":{"text":"כִּדְנָה֙ תֵּאמְר֣וּן לְה֔וֹם אֱלָ֣הַיָּ֔א דִּֽי־שְׁמַיָּ֥א וְאַרְקָ֖א לָ֣א עֲבַ֑דוּ יֵאבַ֧דוּ מֵֽאַרְעָ֛א וּמִן־תְּח֥וֹת שְׁמַיָּ֖א אֵֽלֶּה׃"}},"definableWords":["made","heavens","earth"],"peopleInVerse":[],"themesInVerse":["creation"]},"12":{"text":"He hath made the earth by his power, he hath established the world by his wisdom, and hath stretched out the heavens by his discretion.","ref":"Jeremiah 10:12","synthesized":"The LORD made the earth by His power; He established the world by His wisdom and stretched out the heavens by His understanding.","sources":{"KJV":{"text":"He hath made the earth by his power, he hath established the world by his wisdom, and hath stretched out the heavens by his discretion."},"BSB":{"text":"The LORD made the earth by His power; He established the world by His wisdom and stretched out the heavens by His understanding."},"TANAKH":{"text":"He that hath made the earth by His power, that hath established the world by His wisdom, and hath stretched out the heavens by His understanding;"},"HEBREW":{"text":"עֹשֵׂ֥ה אֶ֙רֶץ֙ בְּכֹח֔וֹ מֵכִ֥ין תֵּבֵ֖ל בְּחָכְמָת֑וֹ וּבִתְבוּנָת֖וֹ נָטָ֥ה שָׁמָֽיִם׃"}},"definableWords":["LORD","made","earth","wisdom","heavens"],"peopleInVerse":[],"themesInVerse":["creation","wisdom"]},"13":{"text":"When he uttereth his voice, there is a multitude of waters in the heavens, and he causeth the vapours to ascend from the ends of the earth; he maketh lightnings with rain, and bringeth forth the wind out of his treasures.","ref":"Jeremiah 10:13","synthesized":"When He thunders, the waters in the heavens roar; He causes the clouds to rise from the ends of the earth. He generates the lightning with the rain and brings forth the wind from His storehouses.","sources":{"KJV":{"text":"When he uttereth his voice, there is a multitude of waters in the heavens, and he causeth the vapours to ascend from the ends of the earth; he maketh lightnings with rain, and bringeth forth the wind out of his treasures."},"BSB":{"text":"When He thunders, the waters in the heavens roar; He causes the clouds to rise from the ends of the earth. He generates the lightning with the rain and brings forth the wind from His storehouses."},"TANAKH":{"text":"At the sound of His giving a multitude of waters in the heavens, when He causeth the vapours to ascend from the ends of the earth; when He maketh lightnings with the rain, and bringeth forth the wind out of His treasuries;"},"HEBREW":{"text":"לְק֨וֹל תִּתּ֜וֹ הֲמ֥וֹן מַ֙יִם֙ בַּשָּׁמַ֔יִם וַיַּעֲלֶ֥ה נְשִׂאִ֖ים מִקְצֵ֣ה ארץ הָאָ֑רֶץ בְּרָקִ֤ים לַמָּטָר֙ עָשָׂ֔ה וַיּ֥וֹצֵא ר֖וּחַ מֵאֹצְרֹתָֽיו׃"}},"definableWords":["waters","heavens","earth"],"peopleInVerse":[],"themesInVerse":["resurrection"]},"14":{"text":"Every man is brutish in his knowledge: every founder is confounded by the graven image: for his molten image is falsehood, and there is no breath in them.","ref":"Jeremiah 10:14","synthesized":"Every man is senseless and devoid of knowledge; every goldsmith is put to shame by his idols. For his molten images are a fraud, and there is no breath in them.","sources":{"KJV":{"text":"Every man is brutish in his knowledge: every founder is confounded by the graven image: for his molten image is falsehood, and there is no breath in them."},"BSB":{"text":"Every man is senseless and devoid of knowledge; every goldsmith is put to shame by his idols. For his molten images are a fraud, and there is no breath in them."},"TANAKH":{"text":"Every man is proved to be brutish, without knowledge, every goldsmith is put to shame by the graven image, his molten image is falsehood, and there is no breath in them."},"HEBREW":{"text":"נִבְעַ֤ר כָּל־אָדָם֙ מִדַּ֔עַת הֹבִ֥ישׁ כָּל־צוֹרֵ֖ף מִפָּ֑סֶל כִּ֛י שֶׁ֥קֶר נִסְכּ֖וֹ וְלֹא־ר֥וּחַ בָּֽם׃"}},"definableWords":["man","knowledge","breath"],"peopleInVerse":[]},"15":{"text":"They are vanity, and the work of errors: in the time of their visitation they shall perish.","ref":"Jeremiah 10:15","synthesized":"They are worthless, a work to be mocked. In the time of their punishment they will perish.","sources":{"KJV":{"text":"They are vanity, and the work of errors: in the time of their visitation they shall perish."},"BSB":{"text":"They are worthless, a work to be mocked. In the time of their punishment they will perish."},"TANAKH":{"text":"They are vanity, a work of delusion; in the time of their visitation they shall perish."},"HEBREW":{"text":"הֶ֣בֶל הֵ֔מָּה מַעֲשֵׂ֖ה תַּעְתֻּעִ֑ים בְּעֵ֥ת פְּקֻדָּתָ֖ם יֹאבֵֽדוּ׃"}},"definableWords":["work"],"peopleInVerse":[]},"16":{"text":"The portion of Jacob is not like them: for he is the former of all things; and Israel is the rod of his inheritance: The LORD of hosts is his name.","ref":"Jeremiah 10:16","synthesized":"The Portion of Jacob is not like these, for He is the Maker of all things, and Israel is the tribe of His inheritance— the LORD of Hosts is His name.","sources":{"KJV":{"text":"The portion of Jacob is not like them: for he is the former of all things; and Israel is the rod of his inheritance: The LORD of hosts is his name."},"BSB":{"text":"The Portion of Jacob is not like these, for He is the Maker of all things, and Israel is the tribe of His inheritance— the LORD of Hosts is His name."},"TANAKH":{"text":"Not like these is the portion of Jacob; for He is the former of all things, and Israel is the tribe of His inheritance; HaShem of hosts is His name."},"HEBREW":{"text":"לֹֽא־כְאֵ֜לֶּה חֵ֣לֶק יַעֲקֹ֗ב כִּֽי־יוֹצֵ֤ר הַכֹּל֙ ה֔וּא וְיִ֨שְׂרָאֵ֔ל שֵׁ֖בֶט נַֽחֲלָת֑וֹ יְהוָ֥ה צְבָא֖וֹת שְׁמֽוֹ׃"}},"definableWords":["Jacob","Israel","tribe","LORD","name"],"peopleInVerse":["Jacob"],"themesInVerse":["land_promise"]},"17":{"text":"Gather up thy wares out of the land, O inhabitant of the fortress.","ref":"Jeremiah 10:17","synthesized":"Gather up your belongings from this land, you who live under siege.","sources":{"KJV":{"text":"Gather up thy wares out of the land, O inhabitant of the fortress."},"BSB":{"text":"Gather up your belongings from this land, you who live under siege."},"TANAKH":{"text":"Gather up thy wares from the ground, O thou that abidest in the siege."},"HEBREW":{"text":"אִסְפִּ֥י מֵאֶ֖רֶץ כִּנְעָתֵ֑ךְ ישבתי יֹשֶׁ֖בֶת בַּמָּצֽוֹר׃"}},"definableWords":["land","live"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"18":{"text":"For thus saith the LORD, Behold, I will sling out the inhabitants of the land at this once, and will distress them, that they may find it so.","ref":"Jeremiah 10:18","synthesized":"For this is what the LORD says:  “Behold, at this time I will sling out the inhabitants of the land and bring distress upon them so that they may be captured.”","sources":{"KJV":{"text":"For thus saith the LORD, Behold, I will sling out the inhabitants of the land at this once, and will distress them, that they may find it so."},"BSB":{"text":"For this is what the LORD says:  “Behold, at this time I will sling out the inhabitants of the land and bring distress upon them so that they may be captured.”"},"TANAKH":{"text":"For thus saith HaShem: Behold, I will sling out the inhabitants of the land at this time, and will distress them, that they may feel it."},"HEBREW":{"text":"כִּֽי־כֹה֙ אָמַ֣ר יְהוָ֔ה הִנְנִ֥י קוֹלֵ֛עַ אֶת־יוֹשְׁבֵ֥י הָאָ֖רֶץ בַּפַּ֣עַם הַזֹּ֑את וַהֲצֵר֥וֹתִי לָהֶ֖ם לְמַ֥עַן יִמְצָֽאוּ׃"}},"definableWords":["LORD","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"19":{"text":"Woe is me for my hurt! my wound is grievous: but I said, Truly this is a grief, and I must bear it.","ref":"Jeremiah 10:19","synthesized":"Woe to me because of my brokenness; my wound is grievous! But I said, “This is truly my sickness, and I must bear it.”","sources":{"KJV":{"text":"Woe is me for my hurt! my wound is grievous: but I said, Truly this is a grief, and I must bear it."},"BSB":{"text":"Woe to me because of my brokenness; my wound is grievous! But I said, “This is truly my sickness, and I must bear it.”"},"TANAKH":{"text":"Woe is me for my hurt! My wound is grievous; but I said: 'This is but a sickness, and I must bear it.'"},"HEBREW":{"text":"א֥וֹי לִי֙ עַל־שִׁבְרִ֔י נַחְלָ֖ה מַכָּתִ֑י וַאֲנִ֣י אָמַ֔רְתִּי אַ֛ךְ זֶ֥ה חֳלִ֖י וְאֶשָּׂאֶֽנּוּ׃"}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"My tabernacle is spoiled, and all my cords are broken: my children are gone forth of me, and they are not: there is none to stretch forth my tent any more, and to set up my curtains.","ref":"Jeremiah 10:20","synthesized":"My tent is destroyed, and all its ropes are snapped. My sons have departed from me and are no more. I have no one left to pitch my tent or set up my curtains.","sources":{"KJV":{"text":"My tabernacle is spoiled, and all my cords are broken: my children are gone forth of me, and they are not: there is none to stretch forth my tent any more, and to set up my curtains."},"BSB":{"text":"My tent is destroyed, and all its ropes are snapped. My sons have departed from me and are no more. I have no one left to pitch my tent or set up my curtains."},"TANAKH":{"text":"My tent is spoiled, and all my cords are broken; my children are gone forth of me, and they are not; there is none to stretch forth my tent any more, and to set up my curtains."},"HEBREW":{"text":"אָהֳלִ֣י שֻׁדָּ֔ד וְכָל־מֵיתָרַ֖י נִתָּ֑קוּ בָּנַ֤י יְצָאֻ֙נִי֙ וְאֵינָ֔ם אֵין־נֹטֶ֥ה עוֹד֙ אָהֳלִ֔י וּמֵקִ֖ים יְרִיעוֹתָֽי׃"}},"definableWords":["sons","one","or"],"peopleInVerse":[]},"21":{"text":"For the pastors are become brutish, and have not sought the LORD: therefore they shall not prosper, and all their flocks shall be scattered.","ref":"Jeremiah 10:21","synthesized":"For the shepherds have become senseless; they do not seek the LORD. Therefore they have not prospered, and all their flock is scattered.","sources":{"KJV":{"text":"For the pastors are become brutish, and have not sought the LORD: therefore they shall not prosper, and all their flocks shall be scattered."},"BSB":{"text":"For the shepherds have become senseless; they do not seek the LORD. Therefore they have not prospered, and all their flock is scattered."},"TANAKH":{"text":"For the shepherds are become brutish, and have not inquired of HaShem; therefore they have not prospered, and all their flocks are scattered."},"HEBREW":{"text":"כִּ֤י נִבְעֲרוּ֙ הָֽרֹעִ֔ים וְאֶת־יְהוָ֖ה לֹ֣א דָרָ֑שׁוּ עַל־כֵּן֙ לֹ֣א הִשְׂכִּ֔ילוּ וְכָל־מַרְעִיתָ֖ם נָפֽוֹצָה׃"}},"definableWords":["seek","LORD"],"peopleInVerse":[],"themesInVerse":["shepherd_sheep"]},"22":{"text":"Behold, the noise of the bruit is come, and a great commotion out of the north country, to make the cities of Judah desolate, and a den of dragons.","ref":"Jeremiah 10:22","synthesized":"Listen! The sound of a report is coming— a great commotion from the land to the north. The cities of Judah will be made a desolation, a haunt for jackals.","sources":{"KJV":{"text":"Behold, the noise of the bruit is come, and a great commotion out of the north country, to make the cities of Judah desolate, and a den of dragons."},"BSB":{"text":"Listen! The sound of a report is coming— a great commotion from the land to the north. The cities of Judah will be made a desolation, a haunt for jackals."},"TANAKH":{"text":"Hark! a report, behold, it cometh, and a great commotion out of the north country, to make the cities of Judah desolate, a dwelling-place of jackals."},"HEBREW":{"text":"ק֤וֹל שְׁמוּעָה֙ הִנֵּ֣ה בָאָ֔ה וְרַ֥עַשׁ גָּד֖וֹל מֵאֶ֣רֶץ צָפ֑וֹן לָשׂ֞וּם אֶת־עָרֵ֧י יְהוּדָ֛ה שְׁמָמָ֖ה מְע֥וֹן תַּנִּֽים׃"}},"definableWords":["great","land","Judah","made"],"peopleInVerse":[],"themesInVerse":["creation","land_promise","second_coming"]},"23":{"text":"O LORD, I know that the way of man is not in himself: it is not in man that walketh to direct his steps.","ref":"Jeremiah 10:23","synthesized":"I know, O LORD, that a man’s way is not his own; no one who walks directs his own steps.","sources":{"KJV":{"text":"O LORD, I know that the way of man is not in himself: it is not in man that walketh to direct his steps."},"BSB":{"text":"I know, O LORD, that a man’s way is not his own; no one who walks directs his own steps."},"TANAKH":{"text":"O HaShem, I know that man's way is not his own; it is not in man to direct his steps as he walketh."},"HEBREW":{"text":"יָדַ֣עְתִּי יְהוָ֔ה כִּ֛י לֹ֥א לָאָדָ֖ם דַּרְכּ֑וֹ לֹֽא־לְאִ֣ישׁ הֹלֵ֔ךְ וְהָכִ֖ין אֶֽת־צַעֲדֽוֹ׃"}},"definableWords":["LORD","man","way","one"],"peopleInVerse":[]},"24":{"text":"O LORD, correct me, but with judgment; not in thine anger, lest thou bring me to nothing.","ref":"Jeremiah 10:24","synthesized":"Correct me, O LORD, but only with justice— not in Your anger, or You will bring me to nothing.","sources":{"KJV":{"text":"O LORD, correct me, but with judgment; not in thine anger, lest thou bring me to nothing."},"BSB":{"text":"Correct me, O LORD, but only with justice— not in Your anger, or You will bring me to nothing."},"TANAKH":{"text":"O HaShem, correct me, but in measure; not in Thine anger, lest Thou diminish me."},"HEBREW":{"text":"יַסְּרֵ֥נִי יְהוָ֖ה אַךְ־בְּמִשְׁפָּ֑ט אַל־בְּאַפְּךָ֖ פֶּן־תַּמְעִטֵֽנִי׃"}},"definableWords":["LORD","justice","anger","or"],"peopleInVerse":[]},"25":{"text":"Pour out thy fury upon the heathen that know thee not, and upon the families that call not on thy name: for they have eaten up Jacob, and devoured him, and consumed him, and have made his habitation desolate.","ref":"Jeremiah 10:25","synthesized":"Pour out Your wrath on the nations that do not acknowledge You, and on the families that do not call on Your name. For they have devoured Jacob; they have consumed him and finished him off; they have devastated his homeland.","sources":{"KJV":{"text":"Pour out thy fury upon the heathen that know thee not, and upon the families that call not on thy name: for they have eaten up Jacob, and devoured him, and consumed him, and have made his habitation desolate."},"BSB":{"text":"Pour out Your wrath on the nations that do not acknowledge You, and on the families that do not call on Your name. For they have devoured Jacob; they have consumed him and finished him off; they have devastated his homeland."},"TANAKH":{"text":"Pour out Thy wrath upon the nations that know Thee not, and upon the families that call not on Thy name; for they have devoured Jacob, yea, they have devoured him and consumed him, and have laid waste his habitation."},"HEBREW":{"text":"שְׁפֹ֣ךְ חֲמָתְךָ֗ עַל־הַגּוֹיִם֙ אֲשֶׁ֣ר לֹֽא־יְדָע֔וּךָ וְעַל֙ מִשְׁפָּח֔וֹת אֲשֶׁ֥ר בְּשִׁמְךָ֖ לֹ֣א קָרָ֑אוּ כִּֽי־אָכְל֣וּ אֶֽת־יַעֲקֹ֗ב וַאֲכָלֻ֙הוּ֙ וַיְכַלֻּ֔הוּ וְאֶת־נָוֵ֖הוּ הֵשַֽׁמּוּ׃"}},"definableWords":["wrath","nations","families","name","Jacob"],"peopleInVerse":["Jacob"],"themesInVerse":["judgment"]}}},"11":{"chapter":"11","title":"THE BROKEN COVENANT","verses":{"1":{"text":"The word that came to Jeremiah from the LORD, saying,","ref":"Jeremiah 11:1","synthesized":"This is the word that came to Jeremiah from the LORD:","sources":{"KJV":{"text":"The word that came to Jeremiah from the LORD, saying,"},"BSB":{"text":"This is the word that came to Jeremiah from the LORD:"},"TANAKH":{"text":"The word that came to Jeremiah from HaShem, saying:"},"HEBREW":{"text":"הַדָּבָר֙ אֲשֶׁ֣ר הָיָ֣ה אֶֽל־יִרְמְיָ֔הוּ מֵאֵ֥ת יְהוָ֖ה לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"2":{"text":"Hear ye the words of this covenant, and speak unto the men of Judah, and to the inhabitants of Jerusalem;","ref":"Jeremiah 11:2","synthesized":"“Listen to the words of this covenant and tell them to the men of Judah and the residents of Jerusalem.","sources":{"KJV":{"text":"Hear ye the words of this covenant, and speak unto the men of Judah, and to the inhabitants of Jerusalem;"},"BSB":{"text":"“Listen to the words of this covenant and tell them to the men of Judah and the residents of Jerusalem."},"TANAKH":{"text":"'Hear ye the words of this covenant, and speak unto the men of Judah, and to the inhabitants of Jerusalem;"},"HEBREW":{"text":"שִׁמְע֕וּ אֶת־דִּבְרֵ֖י הַבְּרִ֣ית הַזֹּ֑את וְדִבַּרְתָּם֙ אֶל־אִ֣ישׁ יְהוּדָ֔ה וְעַל־יֹשְׁבֵ֖י יְרוּשָׁלָֽ͏ִם׃"}},"definableWords":["covenant","men","Judah","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["covenant"]},"3":{"text":"And say thou unto them, Thus saith the LORD God of Israel; Cursed be the man that obeyeth not the words of this covenant,","ref":"Jeremiah 11:3","synthesized":"You must tell them that this is what the LORD, the God of Israel, says: Cursed is the man who does not obey the words of this covenant,","sources":{"KJV":{"text":"And say thou unto them, Thus saith the LORD God of Israel; Cursed be the man that obeyeth not the words of this covenant,"},"BSB":{"text":"You must tell them that this is what the LORD, the God of Israel, says: Cursed is the man who does not obey the words of this covenant,"},"TANAKH":{"text":"and say thou unto them: Thus saith HaShem, the G-d of Israel: Cursed be the man that heareth not the words of this covenant,"},"HEBREW":{"text":"וְאָמַרְתָּ֣ אֲלֵיהֶ֔ם כֹּֽה־אָמַ֥ר יְהוָ֖ה אֱלֹהֵ֣י יִשְׂרָאֵ֑ל אָר֣וּר הָאִ֔ישׁ אֲשֶׁר֙ לֹ֣א יִשְׁמַ֔ע אֶת־דִּבְרֵ֖י הַבְּרִ֥ית הַזֹּֽאת׃"}},"definableWords":["LORD","God","Israel","cursed","man","covenant"],"peopleInVerse":[],"themesInVerse":["covenant"]},"4":{"text":"Which I commanded your fathers in the day that I brought them forth out of the land of Egypt, from the iron furnace, saying, Obey my voice, and do them, according to all which I command you: so shall ye be my people, and I will be your God:","ref":"Jeremiah 11:4","synthesized":"which I commanded your forefathers when I brought them out of the land of Egypt, out of the iron furnace, saying, ‘Obey Me, and do everything I command you, and you will be My people, and I will be your God.’","sources":{"KJV":{"text":"Which I commanded your fathers in the day that I brought them forth out of the land of Egypt, from the iron furnace, saying, Obey my voice, and do them, according to all which I command you: so shall ye be my people, and I will be your God:"},"BSB":{"text":"which I commanded your forefathers when I brought them out of the land of Egypt, out of the iron furnace, saying, ‘Obey Me, and do everything I command you, and you will be My people, and I will be your God.’"},"TANAKH":{"text":"which I commanded your fathers in the day that I brought them forth out of the land of Egypt, out of the iron furnace, saying: Hearken to My voice, and do them, according to all which I command you; so shall ye be My people, and I will be your G-d;"},"HEBREW":{"text":"אֲשֶׁ֣ר צִוִּ֣יתִי אֶת־אֲבֽוֹתֵיכֶ֡ם בְּי֣וֹם הוֹצִיאִֽי־אוֹתָ֣ם מֵאֶֽרֶץ־מִצְרַיִם֩ מִכּ֨וּר הַבַּרְזֶ֜ל לֵאמֹ֗ר שִׁמְע֤וּ בְקוֹלִי֙ וַעֲשִׂיתֶ֣ם אוֹתָ֔ם כְּכֹ֥ל אֲשֶׁר־אֲצַוֶּ֖ה אֶתְכֶ֑ם וִהְיִ֤יתֶם לִי֙ לְעָ֔ם וְאָ֣נֹכִ֔י אֶהְיֶ֥ה לָכֶ֖ם לֵאלֹהִֽים׃"}},"definableWords":["land","Egypt","people","God"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"5":{"text":"That I may perform the oath which I have sworn unto your fathers, to give them a land flowing with milk and honey, as it is this day. Then answered I, and said, So be it, O LORD.","ref":"Jeremiah 11:5","synthesized":"This was in order to establish the oath I swore to your forefathers, to give them a land flowing with milk and honey, as it is to this day.”  “Amen, LORD,” I answered.","sources":{"KJV":{"text":"That I may perform the oath which I have sworn unto your fathers, to give them a land flowing with milk and honey, as it is this day. Then answered I, and said, So be it, O LORD."},"BSB":{"text":"This was in order to establish the oath I swore to your forefathers, to give them a land flowing with milk and honey, as it is to this day.”  “Amen, LORD,” I answered."},"TANAKH":{"text":"that I may establish the oath which I swore unto your fathers, to give them a land flowing with milk and honey, as at this day.' Then answered I, and said: 'Amen, O HaShem.'"},"HEBREW":{"text":"לְמַעַן֩ הָקִ֨ים אֶת־הַשְּׁבוּעָ֜ה אֲשֶׁר־נִשְׁבַּ֣עְתִּי לַאֲבֽוֹתֵיכֶ֗ם לָתֵ֤ת לָהֶם֙ אֶ֣רֶץ זָבַ֥ת חָלָ֛ב וּדְבַ֖שׁ כַּיּ֣וֹם הַזֶּ֑ה וָאַ֥עַן וָאֹמַ֖ר אָמֵ֥ן ׀ יְהוָֽה׃"}},"definableWords":["land","day","LORD"],"peopleInVerse":[],"themesInVerse":["covenant","land_promise"]},"6":{"text":"Then the LORD said unto me, Proclaim all these words in the cities of Judah, and in the streets of Jerusalem, saying, Hear ye the words of this covenant, and do them.","ref":"Jeremiah 11:6","synthesized":"Then the LORD said to me, “Proclaim all these words in the cities of Judah and in the streets of Jerusalem, saying: Hear the words of this covenant and carry them out.","sources":{"KJV":{"text":"Then the LORD said unto me, Proclaim all these words in the cities of Judah, and in the streets of Jerusalem, saying, Hear ye the words of this covenant, and do them."},"BSB":{"text":"Then the LORD said to me, “Proclaim all these words in the cities of Judah and in the streets of Jerusalem, saying: Hear the words of this covenant and carry them out."},"TANAKH":{"text":"And HaShem said unto me: 'Proclaim all these words in the cities of Judah, and in the streets of Jerusalem, saying: Hear ye the words of this covenant, and do them."},"HEBREW":{"text":"וַיֹּ֤אמֶר יְהוָה֙ אֵלַ֔י קְרָ֨א אֶת־כָּל־הַדְּבָרִ֤ים הָאֵ֙לֶּה֙ בְּעָרֵ֣י יְהוּדָ֔ה וּבְחֻצ֥וֹת יְרוּשָׁלַ֖͏ִם לֵאמֹ֑ר שִׁמְע֗וּ אֶת־דִּבְרֵי֙ הַבְּרִ֣ית הַזֹּ֔את וַעֲשִׂיתֶ֖ם אוֹתָֽם׃"}},"definableWords":["LORD","Judah","Jerusalem","hear","covenant"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["covenant"]},"7":{"text":"For I earnestly protested unto your fathers in the day that I brought them up out of the land of Egypt, even unto this day, rising early and protesting, saying, Obey my voice.","ref":"Jeremiah 11:7","synthesized":"For from the time I brought your fathers out of the land of Egypt until today, I strongly warned them again and again, saying, ‘Obey My voice.’","sources":{"KJV":{"text":"For I earnestly protested unto your fathers in the day that I brought them up out of the land of Egypt, even unto this day, rising early and protesting, saying, Obey my voice."},"BSB":{"text":"For from the time I brought your fathers out of the land of Egypt until today, I strongly warned them again and again, saying, ‘Obey My voice.’"},"TANAKH":{"text":"For I earnestly forewarned your fathers in the day that I brought them up out of the land of Egypt, even unto this day, forewarning betimes and often, saying: Hearken to My voice."},"HEBREW":{"text":"כִּי֩ הָעֵ֨ד הַעִדֹ֜תִי בַּאֲבֽוֹתֵיכֶ֗ם בְּיוֹם֩ הַעֲלוֹתִ֨י אוֹתָ֜ם מֵאֶ֤רֶץ מִצְרַ֙יִם֙ וְעַד־הַיּ֣וֹם הַזֶּ֔ה הַשְׁכֵּ֥ם וְהָעֵ֖ד לֵאמֹ֑ר שִׁמְע֖וּ בְּקוֹלִֽי׃"}},"definableWords":["fathers","land","Egypt","voice"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"8":{"text":"Yet they obeyed not, nor inclined their ear, but walked every one in the imagination of their evil heart: therefore I will bring upon them all the words of this covenant, which I commanded them to do: but they did them not.","ref":"Jeremiah 11:8","synthesized":"Yet they would not obey or incline their ears, but each one followed the stubbornness of his evil heart. So I brought on them all the curses of this covenant I had commanded them to follow but they did not keep.”","sources":{"KJV":{"text":"Yet they obeyed not, nor inclined their ear, but walked every one in the imagination of their evil heart: therefore I will bring upon them all the words of this covenant, which I commanded them to do: but they did them not."},"BSB":{"text":"Yet they would not obey or incline their ears, but each one followed the stubbornness of his evil heart. So I brought on them all the curses of this covenant I had commanded them to follow but they did not keep.”"},"TANAKH":{"text":"Yet they hearkened not, nor inclined their ear, but walked every one in the stubbornness of their evil heart; therefore I brought upon them all the words of this covenant, which I commanded them to do, but they did them not.'"},"HEBREW":{"text":"וְלֹ֤א שָֽׁמְעוּ֙ וְלֹֽא־הִטּ֣וּ אֶת־אָזְנָ֔ם וַיֵּ֣לְכ֔וּ אִ֕ישׁ בִּשְׁרִיר֖וּת לִבָּ֣ם הָרָ֑ע וָאָבִ֨יא עֲלֵיהֶ֜ם אֶֽת־כָּל־דִּבְרֵ֧י הַבְּרִית־הַזֹּ֛את אֲשֶׁר־צִוִּ֥יתִי לַעֲשׂ֖וֹת וְלֹ֥א עָשֽׂוּ׃"}},"definableWords":["or","one","evil","heart","covenant","keep"],"peopleInVerse":[],"themesInVerse":["covenant"]},"9":{"text":"And the LORD said unto me, A conspiracy is found among the men of Judah, and among the inhabitants of Jerusalem.","ref":"Jeremiah 11:9","synthesized":"And the LORD told me, “There is a conspiracy among the men of Judah and the residents of Jerusalem.","sources":{"KJV":{"text":"And the LORD said unto me, A conspiracy is found among the men of Judah, and among the inhabitants of Jerusalem."},"BSB":{"text":"And the LORD told me, “There is a conspiracy among the men of Judah and the residents of Jerusalem."},"TANAKH":{"text":"And HaShem said unto me: 'A conspiracy is found among the men of Judah, and among the inhabitants of Jerusalem."},"HEBREW":{"text":"וַיֹּ֥אמֶר יְהוָ֖ה אֵלָ֑י נִֽמְצָא־קֶ֙שֶׁר֙ בְּאִ֣ישׁ יְהוּדָ֔ה וּבְיֹשְׁבֵ֖י יְרוּשָׁלָֽ͏ִם׃"}},"definableWords":["LORD","men","Judah","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"10":{"text":"They are turned back to the iniquities of their forefathers, which refused to hear my words; and they went after other gods to serve them: the house of Israel and the house of Judah have broken my covenant which I made with their fathers.","ref":"Jeremiah 11:10","synthesized":"They have returned to the sins of their forefathers who refused to obey My words. They have followed other gods to serve them. The house of Israel and the house of Judah have broken the covenant I made with their fathers.","sources":{"KJV":{"text":"They are turned back to the iniquities of their forefathers, which refused to hear my words; and they went after other gods to serve them: the house of Israel and the house of Judah have broken my covenant which I made with their fathers."},"BSB":{"text":"They have returned to the sins of their forefathers who refused to obey My words. They have followed other gods to serve them. The house of Israel and the house of Judah have broken the covenant I made with their fathers."},"TANAKH":{"text":"They are turned back to the iniquities of their forefathers, who refused to hear My words; and they are gone after other gods to serve them; the house of Israel and the house of Judah have broken My covenant which I made with their fathers."},"HEBREW":{"text":"שָׁ֩בוּ֩ עַל־עֲוֺנֹ֨ת אֲבוֹתָ֜ם הָרִֽאשֹׁנִ֗ים אֲשֶׁ֤ר מֵֽאֲנוּ֙ לִשְׁמ֣וֹעַ אֶת־דְּבָרַ֔י וְהֵ֣מָּה הָלְכ֗וּ אַחֲרֵ֛י אֱלֹהִ֥ים אֲחֵרִ֖ים לְעָבְדָ֑ם הֵפֵ֤רוּ בֵֽית־יִשְׂרָאֵל֙ וּבֵ֣ית יְהוּדָ֔ה אֶת־בְּרִיתִ֕י אֲשֶׁ֥ר כָּרַ֖תִּי אֶת־אֲבוֹתָֽם׃"}},"definableWords":["house","Israel","Judah","covenant","made","fathers"],"peopleInVerse":[],"themesInVerse":["covenant","creation"]},"11":{"text":"Therefore thus saith the LORD, Behold, I will bring evil upon them, which they shall not be able to escape; and though they shall cry unto me, I will not hearken unto them.","ref":"Jeremiah 11:11","synthesized":"Therefore this is what the LORD says: ‘I am about to bring upon them a disaster that they cannot escape. They will cry out to Me, but I will not listen to them.","sources":{"KJV":{"text":"Therefore thus saith the LORD, Behold, I will bring evil upon them, which they shall not be able to escape; and though they shall cry unto me, I will not hearken unto them."},"BSB":{"text":"Therefore this is what the LORD says: ‘I am about to bring upon them a disaster that they cannot escape. They will cry out to Me, but I will not listen to them."},"TANAKH":{"text":"Therefore thus saith HaShem: Behold, I will bring evil upon them, which they shall not be able to escape; and though they shall cry unto Me, I will not hearken unto them."},"HEBREW":{"text":"לָכֵ֗ן כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִנְנִ֨י מֵבִ֤יא אֲלֵיהֶם֙ רָעָ֔ה אֲשֶׁ֥ר לֹֽא־יוּכְל֖וּ לָצֵ֣את מִמֶּ֑נָּה וְזָעֲק֣וּ אֵלַ֔י וְלֹ֥א אֶשְׁמַ֖ע אֲלֵיהֶֽם׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"12":{"text":"Then shall the cities of Judah and inhabitants of Jerusalem go, and cry unto the gods unto whom they offer incense: but they shall not save them at all in the time of their trouble.","ref":"Jeremiah 11:12","synthesized":"Then the cities of Judah and the residents of Jerusalem will go and cry out to the gods to which they have been burning incense, but these gods certainly will not save them in their time of disaster.","sources":{"KJV":{"text":"Then shall the cities of Judah and inhabitants of Jerusalem go, and cry unto the gods unto whom they offer incense: but they shall not save them at all in the time of their trouble."},"BSB":{"text":"Then the cities of Judah and the residents of Jerusalem will go and cry out to the gods to which they have been burning incense, but these gods certainly will not save them in their time of disaster."},"TANAKH":{"text":"Then shall the cities of Judah and the inhabitants of Jerusalem go and cry unto the gods unto whom they offer; but they shall not save them at all in the time of their trouble."},"HEBREW":{"text":"וְהָֽלְכ֞וּ עָרֵ֣י יְהוּדָ֗ה וְיֹשְׁבֵי֙ יְר֣וּשָׁלִַ֔ם וְזָֽעֲקוּ֙ אֶל־הָ֣אֱלֹהִ֔ים אֲשֶׁ֛ר הֵ֥ם מְקַטְּרִ֖ים לָהֶ֑ם וְהוֹשֵׁ֛עַ לֹֽא־יוֹשִׁ֥יעוּ לָהֶ֖ם בְּעֵ֥ת רָעָתָֽם׃"}},"definableWords":["Judah","Jerusalem","incense"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["salvation"]},"13":{"text":"For according to the number of thy cities were thy gods, O Judah; and according to the number of the streets of Jerusalem have ye set up altars to that shameful thing, even altars to burn incense unto Baal.","ref":"Jeremiah 11:13","synthesized":"Your gods are indeed as numerous as your cities, O Judah; the altars of shame you have set up—the altars to burn incense to Baal—are as many as the streets of Jerusalem.’","sources":{"KJV":{"text":"For according to the number of thy cities were thy gods, O Judah; and according to the number of the streets of Jerusalem have ye set up altars to that shameful thing, even altars to burn incense unto Baal."},"BSB":{"text":"Your gods are indeed as numerous as your cities, O Judah; the altars of shame you have set up—the altars to burn incense to Baal—are as many as the streets of Jerusalem.’"},"TANAKH":{"text":"For according to the number of thy cities are thy gods, O Judah; and according to the number of the streets of Jerusalem have ye set up altars to the shameful thing, even altars to offer unto Baal."},"HEBREW":{"text":"כִּ֚י מִסְפַּ֣ר עָרֶ֔יךָ הָי֥וּ אֱלֹהֶ֖יךָ יְהוּדָ֑ה וּמִסְפַּ֞ר חֻצ֣וֹת יְרוּשָׁלִַ֗ם שַׂמְתֶּ֤ם מִזְבְּחוֹת֙ לַבֹּ֔שֶׁת מִזְבְּח֖וֹת לְקַטֵּ֥ר לַבָּֽעַל׃"}},"definableWords":["Judah","incense","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"14":{"text":"Therefore pray not thou for this people, neither lift up a cry or prayer for them: for I will not hear them in the time that they cry unto me for their trouble.","ref":"Jeremiah 11:14","synthesized":"As for you, do not pray for these people. Do not raise up a cry or a prayer on their behalf, for I will not be listening when they call out to Me in their time of disaster.","sources":{"KJV":{"text":"Therefore pray not thou for this people, neither lift up a cry or prayer for them: for I will not hear them in the time that they cry unto me for their trouble."},"BSB":{"text":"As for you, do not pray for these people. Do not raise up a cry or a prayer on their behalf, for I will not be listening when they call out to Me in their time of disaster."},"TANAKH":{"text":"Therefore pray not thou for this people, neither lift up cry nor prayer for them; for I will not hear them in the time that they cry unto Me for their trouble.'"},"HEBREW":{"text":"וְאַתָּ֗ה אַל־תִּתְפַּלֵּל֙ בְּעַד־הָעָ֣ם הַזֶּ֔ה וְאַל־תִּשָּׂ֥א בַעֲדָ֖ם רִנָּ֣ה וּתְפִלָּ֑ה כִּ֣י אֵינֶ֣נִּי שֹׁמֵ֗עַ בְּעֵ֛ת קָרְאָ֥ם אֵלַ֖י בְּעַ֥ד רָעָתָֽם׃"}},"definableWords":["people","or","prayer"],"peopleInVerse":[],"themesInVerse":["prayer"]},"15":{"text":"What hath my beloved to do in mine house, seeing she hath wrought lewdness with many, and the holy flesh is passed from thee? when thou doest evil, then thou rejoicest.","ref":"Jeremiah 11:15","synthesized":"What right has My beloved in My house, having carried out so many evil schemes? Can consecrated meat avert your doom, so that you can rejoice?","sources":{"KJV":{"text":"What hath my beloved to do in mine house, seeing she hath wrought lewdness with many, and the holy flesh is passed from thee? when thou doest evil, then thou rejoicest."},"BSB":{"text":"What right has My beloved in My house, having carried out so many evil schemes? Can consecrated meat avert your doom, so that you can rejoice?"},"TANAKH":{"text":"What hath My beloved to do in My house, seeing she hath wrought lewdness with many, and the hallowed flesh is passed from thee? When thou doest evil, then thou rejoicest."},"HEBREW":{"text":"מֶ֣ה לִֽידִידִ֞י בְּבֵיתִ֗י עֲשׂוֹתָ֤הּ הַֽמְזִמָּ֙תָה֙ הָֽרַבִּ֔ים וּבְשַׂר־קֹ֖דֶשׁ יַעַבְר֣וּ מֵֽעָלָ֑יִךְ כִּ֥י רָעָתֵ֖כִי אָ֥ז תַּעֲלֹֽזִי׃"}},"definableWords":["house","evil"],"peopleInVerse":[],"themesInVerse":["joy","love"]},"16":{"text":"The LORD called thy name, A green olive tree, fair, and of goodly fruit: with the noise of a great tumult he hath kindled fire upon it, and the branches of it are broken.","ref":"Jeremiah 11:16","synthesized":"The LORD once called you a flourishing olive tree, beautiful with well-formed fruit. But with a mighty roar He will set it on fire, and its branches will be consumed.","sources":{"KJV":{"text":"The LORD called thy name, A green olive tree, fair, and of goodly fruit: with the noise of a great tumult he hath kindled fire upon it, and the branches of it are broken."},"BSB":{"text":"The LORD once called you a flourishing olive tree, beautiful with well-formed fruit. But with a mighty roar He will set it on fire, and its branches will be consumed."},"TANAKH":{"text":"HaShem called thy name a leafy olive-tree, fair with goodly fruit; with the noise of a great tumult He hath kindled fire upon it, and the branches of it are broken."},"HEBREW":{"text":"זַ֤יִת רַֽעֲנָן֙ יְפֵ֣ה פְרִי־תֹ֔אַר קָרָ֥א יְהוָ֖ה שְׁמֵ֑ךְ לְק֣וֹל ׀ הֲמוּלָּ֣ה גְדֹלָ֗ה הִצִּ֥ית אֵשׁ֙ עָלֶ֔יהָ וְרָע֖וּ דָּלִיּוֹתָֽיו׃"}},"definableWords":["LORD","tree","formed","mighty"],"peopleInVerse":[],"themesInVerse":["bread_water_life","creation","vine_branches"]},"17":{"text":"For the LORD of hosts, that planted thee, hath pronounced evil against thee, for the evil of the house of Israel and of the house of Judah, which they have done against themselves to provoke me to anger in offering incense unto Baal.","ref":"Jeremiah 11:17","synthesized":"The LORD of Hosts, who planted you, has decreed disaster against you on account of the evil that the house of Israel and the house of Judah have brought upon themselves, provoking Me to anger by burning incense to Baal.”","sources":{"KJV":{"text":"For the LORD of hosts, that planted thee, hath pronounced evil against thee, for the evil of the house of Israel and of the house of Judah, which they have done against themselves to provoke me to anger in offering incense unto Baal."},"BSB":{"text":"The LORD of Hosts, who planted you, has decreed disaster against you on account of the evil that the house of Israel and the house of Judah have brought upon themselves, provoking Me to anger by burning incense to Baal.”"},"TANAKH":{"text":"For HaShem of hosts, that planted thee, hath pronounced evil against thee, because of the evil of the house of Israel and of the house of Judah, which they have wrought for themselves in provoking Me by offering unto Baal."},"HEBREW":{"text":"וַיהוָ֤ה צְבָאוֹת֙ הַנּוֹטֵ֣עַ אוֹתָ֔ךְ דִּבֶּ֥ר עָלַ֖יִךְ רָעָ֑ה בִּ֠גְלַל רָעַ֨ת בֵּֽית־יִשְׂרָאֵ֜ל וּבֵ֣ית יְהוּדָ֗ה אֲשֶׁ֨ר עָשׂ֥וּ לָהֶ֛ם לְהַכְעִסֵ֖נִי לְקַטֵּ֥ר לַבָּֽעַל׃"}},"definableWords":["LORD","evil","house","Israel","Judah","anger","incense"],"peopleInVerse":[]},"18":{"text":"And the LORD hath given me knowledge of it, and I know it: then thou shewedst me their doings.","ref":"Jeremiah 11:18","synthesized":"And the LORD informed me, so I knew. Then You showed me their deeds.","sources":{"KJV":{"text":"And the LORD hath given me knowledge of it, and I know it: then thou shewedst me their doings."},"BSB":{"text":"And the LORD informed me, so I knew. Then You showed me their deeds."},"TANAKH":{"text":"And HaShem gave me knowledge of it, and I knew it; then Thou showedst me their doings."},"HEBREW":{"text":"וַֽיהוָ֥ה הֽוֹדִיעַ֖נִי וָֽאֵדָ֑עָה אָ֖ז הִרְאִיתַ֥נִי מַעַלְלֵיהֶֽם׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"19":{"text":"But I was like a lamb or an ox that is brought to the slaughter; and I knew not that they had devised devices against me, saying, Let us destroy the tree with the fruit thereof, and let us cut him off from the land of the living, that his name may be no more remembered.","ref":"Jeremiah 11:19","synthesized":"For I was like a gentle lamb led to slaughter; I did not know that they had plotted against me: “Let us destroy the tree with its fruit; let us cut him off from the land of the living, that his name may be remembered no more.”","sources":{"KJV":{"text":"But I was like a lamb or an ox that is brought to the slaughter; and I knew not that they had devised devices against me, saying, Let us destroy the tree with the fruit thereof, and let us cut him off from the land of the living, that his name may be no more remembered."},"BSB":{"text":"For I was like a gentle lamb led to slaughter; I did not know that they had plotted against me: “Let us destroy the tree with its fruit; let us cut him off from the land of the living, that his name may be remembered no more.”"},"TANAKH":{"text":"But I was like a docile lamb that is led to the slaughter; and I knew not that they had devised devices against me: 'Let us destroy the tree with the fruit thereof, and let us cut him off from the land of the living, that his name may be no more remembered.'"},"HEBREW":{"text":"וַאֲנִ֕י כְּכֶ֥בֶשׂ אַלּ֖וּף יוּבַ֣ל לִטְב֑וֹחַ וְלֹֽא־יָדַ֜עְתִּי כִּֽי־עָלַ֣י ׀ חָשְׁב֣וּ מַחֲשָׁב֗וֹת נַשְׁחִ֨יתָה עֵ֤ץ בְּלַחְמוֹ֙ וְנִכְרְתֶ֙נּוּ֙ מֵאֶ֣רֶץ חַיִּ֔ים וּשְׁמ֖וֹ לֹֽא־יִזָּכֵ֥ר עֽוֹד׃"}},"definableWords":["Lamb","tree","land","living","name","remembered"],"peopleInVerse":[],"themesInVerse":["land_promise","passover","sacrifice","vine_branches"]},"20":{"text":"But, O LORD of hosts, that judgest righteously, that triest the reins and the heart, let me see thy vengeance on them: for unto thee have I revealed my cause.","ref":"Jeremiah 11:20","synthesized":"O LORD of Hosts, who judges righteously, who examines the heart and mind, let me see Your vengeance upon them, for to You I have committed my cause.","sources":{"KJV":{"text":"But, O LORD of hosts, that judgest righteously, that triest the reins and the heart, let me see thy vengeance on them: for unto thee have I revealed my cause."},"BSB":{"text":"O LORD of Hosts, who judges righteously, who examines the heart and mind, let me see Your vengeance upon them, for to You I have committed my cause."},"TANAKH":{"text":"But, O HaShem of hosts, that judgest righteously, that triest the reins and the heart, let me see Thy vengeance on them; for unto Thee have I revealed my cause."},"HEBREW":{"text":"וַֽיהוָ֤ה צְבָאוֹת֙ שֹׁפֵ֣ט צֶ֔דֶק בֹּחֵ֥ן כְּלָי֖וֹת וָלֵ֑ב אֶרְאֶ֤ה נִקְמָֽתְךָ֙ מֵהֶ֔ם כִּ֥י אֵלֶ֖יךָ גִּלִּ֥יתִי אֶת־רִיבִֽי׃"}},"definableWords":["LORD","heart","mind","see"],"peopleInVerse":[]},"21":{"text":"Therefore thus saith the LORD of the men of Anathoth, that seek thy life, saying, Prophesy not in the name of the LORD, that thou die not by our hand:","ref":"Jeremiah 11:21","synthesized":"Therefore this is what the LORD says concerning the people of Anathoth who are seeking your life and saying, “You must not prophesy in the name of the LORD, or you will die by our hand.”","sources":{"KJV":{"text":"Therefore thus saith the LORD of the men of Anathoth, that seek thy life, saying, Prophesy not in the name of the LORD, that thou die not by our hand:"},"BSB":{"text":"Therefore this is what the LORD says concerning the people of Anathoth who are seeking your life and saying, “You must not prophesy in the name of the LORD, or you will die by our hand.”"},"TANAKH":{"text":"Therefore thus saith HaShem concerning the men of Anathoth, that seek thy life, saying: 'Thou shalt not prophesy in the name of HaShem, that thou die not by our hand';"},"HEBREW":{"text":"לָכֵ֗ן כֹּֽה־אָמַ֤ר יְהוָה֙ עַל־אַנְשֵׁ֣י עֲנָת֔וֹת הַֽמְבַקְשִׁ֥ים אֶֽת־נַפְשְׁךָ֖ לֵאמֹ֑ר לֹ֤א תִנָּבֵא֙ בְּשֵׁ֣ם יְהוָ֔ה וְלֹ֥א תָמ֖וּת בְּיָדֵֽנוּ׃"}},"definableWords":["LORD","people","life","name","Lord","or","die"],"peopleInVerse":[]},"22":{"text":"Therefore thus saith the LORD of hosts, Behold, I will punish them: the young men shall die by the sword; their sons and their daughters shall die by famine:","ref":"Jeremiah 11:22","synthesized":"So this is what the LORD of Hosts says: “I will punish them. Their young men will die by the sword, their sons and daughters by famine.","sources":{"KJV":{"text":"Therefore thus saith the LORD of hosts, Behold, I will punish them: the young men shall die by the sword; their sons and their daughters shall die by famine:"},"BSB":{"text":"So this is what the LORD of Hosts says: “I will punish them. Their young men will die by the sword, their sons and daughters by famine."},"TANAKH":{"text":"therefore thus saith HaShem of hosts: Behold, I will punish them; the young men shall die by the sword, their sons and their daughters shall die by famine;"},"HEBREW":{"text":"לָכֵ֗ן כֹּ֤ה אָמַר֙ יְהוָ֣ה צְבָא֔וֹת הִנְנִ֥י פֹקֵ֖ד עֲלֵיהֶ֑ם הַבַּֽחוּרִים֙ יָמֻ֣תוּ בַחֶ֔רֶב בְּנֵיהֶם֙ וּבְנ֣וֹתֵיהֶ֔ם יָמֻ֖תוּ בָּרָעָֽב׃"}},"definableWords":["LORD","men","die","sons","daughters"],"peopleInVerse":[]},"23":{"text":"And there shall be no remnant of them: for I will bring evil upon the men of Anathoth, even the year of their visitation.","ref":"Jeremiah 11:23","synthesized":"There will be no remnant, for I will bring disaster on the people of Anathoth in the year of their punishment.”","sources":{"KJV":{"text":"And there shall be no remnant of them: for I will bring evil upon the men of Anathoth, even the year of their visitation."},"BSB":{"text":"There will be no remnant, for I will bring disaster on the people of Anathoth in the year of their punishment.”"},"TANAKH":{"text":"And there shall be no remnant unto them; for I will bring evil upon the men of Anathoth, even the year of their visitation."},"HEBREW":{"text":"וּשְׁאֵרִ֕ית לֹ֥א תִֽהְיֶ֖ה לָהֶ֑ם כִּֽי־אָבִ֥יא רָעָ֛ה אֶל־אַנְשֵׁ֥י עֲנָת֖וֹת שְׁנַ֥ת פְּקֻדָּתָֽם׃"}},"definableWords":["remnant","people","year"],"peopleInVerse":[],"themesInVerse":["exile_return"]}}},"12":{"chapter":"12","title":"WHEREFORE DOTH THE WAY OF THE WICKED PROSPER?","verses":{"1":{"text":"Righteous art thou, O LORD, when I plead with thee: yet let me talk with thee of thy judgments: Wherefore doth the way of the wicked prosper? wherefore are all they happy that deal very treacherously?","ref":"Jeremiah 12:1","synthesized":"Righteous are You, O LORD, when I plead before You. Yet about Your judgments I wish to contend with You:   Why does the way of the wicked prosper? Why do all the faithless live at ease?","sources":{"KJV":{"text":"Righteous art thou, O LORD, when I plead with thee: yet let me talk with thee of thy judgments: Wherefore doth the way of the wicked prosper? wherefore are all they happy that deal very treacherously?"},"BSB":{"text":"Righteous are You, O LORD, when I plead before You. Yet about Your judgments I wish to contend with You:   Why does the way of the wicked prosper? Why do all the faithless live at ease?"},"TANAKH":{"text":"Right wouldest Thou be, O HaShem, were I to contend with Thee, yet will I reason with Thee: Wherefore doth the way of the wicked prosper? Wherefore are all they secure that deal very treacherously?"},"HEBREW":{"text":"צַדִּ֤יק אַתָּה֙ יְהוָ֔ה כִּ֥י אָרִ֖יב אֵלֶ֑יךָ אַ֤ךְ מִשְׁפָּטִים֙ אֲדַבֵּ֣ר אוֹתָ֔ךְ מַדּ֗וּעַ דֶּ֤רֶךְ רְשָׁעִים֙ צָלֵ֔חָה שָׁל֖וּ כָּל־בֹּ֥גְדֵי בָֽגֶד׃"}},"definableWords":["righteous","LORD","way","live"],"peopleInVerse":[]},"2":{"text":"Thou hast planted them, yea, they have taken root: they grow, yea, they bring forth fruit: thou art near in their mouth, and far from their reins.","ref":"Jeremiah 12:2","synthesized":"You planted them, and they have taken root. They have grown and produced fruit. You are ever on their lips, but far from their hearts.","sources":{"KJV":{"text":"Thou hast planted them, yea, they have taken root: they grow, yea, they bring forth fruit: thou art near in their mouth, and far from their reins."},"BSB":{"text":"You planted them, and they have taken root. They have grown and produced fruit. You are ever on their lips, but far from their hearts."},"TANAKH":{"text":"Thou hast planted them, yea, they have taken root; they grow, yea, they bring forth fruit; Thou art near in their mouth, and far from their reins."},"HEBREW":{"text":"נְטַעְתָּם֙ גַּם־שֹׁרָ֔שׁוּ יֵלְכ֖וּ גַּם־עָ֣שׂוּ פֶ֑רִי קָר֤וֹב אַתָּה֙ בְּפִיהֶ֔ם וְרָח֖וֹק מִכִּלְיוֹתֵיהֶֽם׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["vine_branches"]},"3":{"text":"But thou, O LORD, knowest me: thou hast seen me, and tried mine heart toward thee: pull them out like sheep for the slaughter, and prepare them for the day of slaughter.","ref":"Jeremiah 12:3","synthesized":"But You know me, O LORD; You see me and test my heart toward You. Drag away the wicked like sheep to the slaughter and set them apart for the day of carnage.","sources":{"KJV":{"text":"But thou, O LORD, knowest me: thou hast seen me, and tried mine heart toward thee: pull them out like sheep for the slaughter, and prepare them for the day of slaughter."},"BSB":{"text":"But You know me, O LORD; You see me and test my heart toward You. Drag away the wicked like sheep to the slaughter and set them apart for the day of carnage."},"TANAKH":{"text":"But Thou, O HaShem, knowest me, Thou seest me, and triest my heart toward Thee; pull them out like sheep for the slaughter, and prepare them for the day of slaughter."},"HEBREW":{"text":"וְאַתָּ֤ה יְהוָה֙ יְדַעְתָּ֔נִי תִּרְאֵ֕נִי וּבָחַנְתָּ֥ לִבִּ֖י אִתָּ֑ךְ הַתִּקֵם֙ כְּצֹ֣אן לְטִבְחָ֔ה וְהַקְדִּשֵׁ֖ם לְי֥וֹם הֲרֵגָֽה׃"}},"definableWords":["LORD","see","heart","day"],"peopleInVerse":[],"themesInVerse":["shepherd_sheep"]},"4":{"text":"How long shall the land mourn, and the herbs of every field wither, for the wickedness of them that dwell therein? the beasts are consumed, and the birds; because they said, He shall not see our last end.","ref":"Jeremiah 12:4","synthesized":"How long will the land mourn and the grass of every field be withered? Because of the evil of its residents, the animals and birds have been swept away, for the people have said, “He cannot see what our end will be.”","sources":{"KJV":{"text":"How long shall the land mourn, and the herbs of every field wither, for the wickedness of them that dwell therein? the beasts are consumed, and the birds; because they said, He shall not see our last end."},"BSB":{"text":"How long will the land mourn and the grass of every field be withered? Because of the evil of its residents, the animals and birds have been swept away, for the people have said, “He cannot see what our end will be.”"},"TANAKH":{"text":"How long shall the land mourn, and the herbs of the whole field wither? For the wickedness of them that dwell therein, the beasts are consumed, and the birds; because they said: 'He seeth not our end.'"},"HEBREW":{"text":"עַד־מָתַי֙ תֶּאֱבַ֣ל הָאָ֔רֶץ וְעֵ֥שֶׂב כָּל־הַשָּׂדֶ֖ה יִיבָ֑שׁ מֵרָעַ֣ת יֹֽשְׁבֵי־בָ֗הּ סָפְתָ֤ה בְהֵמוֹת֙ וָע֔וֹף כִּ֣י אָמְר֔וּ לֹ֥א יִרְאֶ֖ה אֶת־אַחֲרִיתֵֽנוּ׃"}},"definableWords":["land","field","evil","birds","people","see"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"5":{"text":"If thou hast run with the footmen, and they have wearied thee, then how canst thou contend with horses? and if in the land of peace, wherein thou trustedst, they wearied thee, then how wilt thou do in the swelling of Jordan?","ref":"Jeremiah 12:5","synthesized":"“If you have raced with men on foot and they have worn you out, how can you compete with horses? If you stumble in a peaceful land, how will you do in the thickets of the Jordan?","sources":{"KJV":{"text":"If thou hast run with the footmen, and they have wearied thee, then how canst thou contend with horses? and if in the land of peace, wherein thou trustedst, they wearied thee, then how wilt thou do in the swelling of Jordan?"},"BSB":{"text":"“If you have raced with men on foot and they have worn you out, how can you compete with horses? If you stumble in a peaceful land, how will you do in the thickets of the Jordan?"},"TANAKH":{"text":"'If thou hast run with the footmen, and they have wearied thee, then how canst thou contend with horses? And though in a land of peace thou art secure, yet how wilt thou do in the thickets of the Jordan?"},"HEBREW":{"text":"כִּ֣י אֶת־רַגְלִ֥ים ׀ רַ֙צְתָּה֙ וַיַּלְא֔וּךָ וְאֵ֥יךְ תְּתַֽחֲרֶ֖ה אֶת־הַסּוּסִ֑ים וּבְאֶ֤רֶץ שָׁלוֹם֙ אַתָּ֣ה בוֹטֵ֔חַ וְאֵ֥יךְ תַּעֲשֶׂ֖ה בִּגְא֥וֹן הַיַּרְדֵּֽן׃"}},"definableWords":["men","land"],"peopleInVerse":[],"placesInVerse":["Jordan River"],"themesInVerse":["land_promise"]},"6":{"text":"For even thy brethren, and the house of thy father, even they have dealt treacherously with thee; yea, they have called a multitude after thee: believe them not, though they speak fair words unto thee.","ref":"Jeremiah 12:6","synthesized":"Even your brothers— your own father’s household— even they have betrayed you; even they have cried aloud against you. Do not trust them, though they speak well of you.","sources":{"KJV":{"text":"For even thy brethren, and the house of thy father, even they have dealt treacherously with thee; yea, they have called a multitude after thee: believe them not, though they speak fair words unto thee."},"BSB":{"text":"Even your brothers— your own father’s household— even they have betrayed you; even they have cried aloud against you. Do not trust them, though they speak well of you."},"TANAKH":{"text":"For even thy brethren, and the house of thy father, even they have dealt treacherously with thee, even they have cried aloud after thee; believe them not, though they speak fair words unto thee.'"},"HEBREW":{"text":"כִּ֧י גַם־אַחֶ֣יךָ וּבֵית־אָבִ֗יךָ גַּם־הֵ֙מָּה֙ בָּ֣גְדוּ בָ֔ךְ גַּם־הֵ֛מָּה קָרְא֥וּ אַחֲרֶ֖יךָ מָלֵ֑א אַל־תַּאֲמֵ֣ן בָּ֔ם כִּֽי־יְדַבְּר֥וּ אֵלֶ֖יךָ טוֹבֽוֹת׃"}},"definableWords":["father","trust"],"peopleInVerse":[],"themesInVerse":["bread_water_life","faith"]},"7":{"text":"I have forsaken mine house, I have left mine heritage; I have given the dearly beloved of my soul into the hand of her enemies.","ref":"Jeremiah 12:7","synthesized":"I have forsaken My house; I have abandoned My inheritance. I have given the love of My life into the hands of her enemies.","sources":{"KJV":{"text":"I have forsaken mine house, I have left mine heritage; I have given the dearly beloved of my soul into the hand of her enemies."},"BSB":{"text":"I have forsaken My house; I have abandoned My inheritance. I have given the love of My life into the hands of her enemies."},"TANAKH":{"text":"I have forsaken My house, I have cast off My heritage; I have given the dearly beloved of My soul into the hand of her enemies."},"HEBREW":{"text":"עָזַ֙בְתִּי֙ אֶת־בֵּיתִ֔י נָטַ֖שְׁתִּי אֶת־נַחֲלָתִ֑י נָתַ֛תִּי אֶת־יְדִד֥וּת נַפְשִׁ֖י בְּכַ֥ף אֹיְבֶֽיהָ׃"}},"definableWords":["house","love","life"],"peopleInVerse":[],"themesInVerse":["land_promise","love"]},"8":{"text":"Mine heritage is unto me as a lion in the forest; it crieth out against me: therefore have I hated it.","ref":"Jeremiah 12:8","synthesized":"My inheritance has become to Me like a lion in the forest. She has roared against Me; therefore I hate her.","sources":{"KJV":{"text":"Mine heritage is unto me as a lion in the forest; it crieth out against me: therefore have I hated it."},"BSB":{"text":"My inheritance has become to Me like a lion in the forest. She has roared against Me; therefore I hate her."},"TANAKH":{"text":"My heritage is become unto Me as a lion in the forest; she hath uttered her voice against Me; therefore have I hated her."},"HEBREW":{"text":"הָיְתָה־לִּ֥י נַחֲלָתִ֖י כְּאַרְיֵ֣ה בַיָּ֑עַר נָתְנָ֥ה עָלַ֛י בְּקוֹלָ֖הּ עַל־כֵּ֥ן שְׂנֵאתִֽיהָ׃"}},"definableWords":["lion"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"9":{"text":"Mine heritage is unto me as a speckled bird, the birds round about are against her; come ye, assemble all the beasts of the field, come to devour.","ref":"Jeremiah 12:9","synthesized":"Is not My inheritance to Me like a speckled bird of prey with other birds of prey circling against her? Go, gather all the beasts of the field; bring them to devour her.","sources":{"KJV":{"text":"Mine heritage is unto me as a speckled bird, the birds round about are against her; come ye, assemble all the beasts of the field, come to devour."},"BSB":{"text":"Is not My inheritance to Me like a speckled bird of prey with other birds of prey circling against her? Go, gather all the beasts of the field; bring them to devour her."},"TANAKH":{"text":"Is My heritage unto Me as a speckled bird of prey? Are the birds of prey against her round about? Come ye, assemble all the beasts of the field, bring them to devour."},"HEBREW":{"text":"הַעַ֨יִט צָב֤וּעַ נַחֲלָתִי֙ לִ֔י הַעַ֖יִט סָבִ֣יב עָלֶ֑יהָ לְכ֗וּ אִסְפ֛וּ כָּל־חַיַּ֥ת הַשָּׂדֶ֖ה הֵתָ֥יוּ לְאָכְלָֽה׃"}},"definableWords":["bird","birds","field"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"10":{"text":"Many pastors have destroyed my vineyard, they have trodden my portion under foot, they have made my pleasant portion a desolate wilderness.","ref":"Jeremiah 12:10","synthesized":"Many shepherds have destroyed My vineyard; they have trampled My plot of ground. They have turned My pleasant field into a desolate wasteland.","sources":{"KJV":{"text":"Many pastors have destroyed my vineyard, they have trodden my portion under foot, they have made my pleasant portion a desolate wilderness."},"BSB":{"text":"Many shepherds have destroyed My vineyard; they have trampled My plot of ground. They have turned My pleasant field into a desolate wasteland."},"TANAKH":{"text":"Many shepherds have destroyed My vineyard, they have trodden My portion under foot, they have made My pleasant portion a desolate wilderness."},"HEBREW":{"text":"רֹעִ֤ים רַבִּים֙ שִֽׁחֲת֣וּ כַרְמִ֔י בֹּסְס֖וּ אֶת־חֶלְקָתִ֑י נָֽתְנ֛וּ אֶת־חֶלְקַ֥ת חֶמְדָּתִ֖י לְמִדְבַּ֥ר שְׁמָמָֽה׃"}},"definableWords":["ground","field"],"peopleInVerse":[],"themesInVerse":["vine_branches"]},"11":{"text":"They have made it desolate, and being desolate it mourneth unto me; the whole land is made desolate, because no man layeth it to heart.","ref":"Jeremiah 12:11","synthesized":"They have made it a desolation; desolate before Me, it mourns. All the land is laid waste, but no man takes it to heart.","sources":{"KJV":{"text":"They have made it desolate, and being desolate it mourneth unto me; the whole land is made desolate, because no man layeth it to heart."},"BSB":{"text":"They have made it a desolation; desolate before Me, it mourns. All the land is laid waste, but no man takes it to heart."},"TANAKH":{"text":"They have made it a desolation, it mourneth unto Me, being desolate; the whole land is made desolate, because no man layeth it to heart."},"HEBREW":{"text":"שָׂמָהּ֙ לִשְׁמָמָ֔ה אָבְלָ֥ה עָלַ֖י שְׁמֵמָ֑ה נָשַׁ֙מָּה֙ כָּל־הָאָ֔רֶץ כִּ֛י אֵ֥ין אִ֖ישׁ שָׂ֥ם עַל־לֵֽב׃"}},"definableWords":["made","land","man","heart"],"peopleInVerse":[],"themesInVerse":["creation","land_promise"]},"12":{"text":"The spoilers are come upon all high places through the wilderness: for the sword of the LORD shall devour from the one end of the land even to the other end of the land: no flesh shall have peace.","ref":"Jeremiah 12:12","synthesized":"Over all the barren heights in the wilderness the destroyers have come, for the sword of the LORD devours from one end of the earth to the other. No flesh has peace.","sources":{"KJV":{"text":"The spoilers are come upon all high places through the wilderness: for the sword of the LORD shall devour from the one end of the land even to the other end of the land: no flesh shall have peace."},"BSB":{"text":"Over all the barren heights in the wilderness the destroyers have come, for the sword of the LORD devours from one end of the earth to the other. No flesh has peace."},"TANAKH":{"text":"Upon all the high hills in the wilderness spoilers are come; for the sword of HaShem devoureth from the one end of the land even to the other end of the land, no flesh hath peace."},"HEBREW":{"text":"עַֽל־כָּל־שְׁפָיִ֣ם בַּמִּדְבָּ֗ר בָּ֚אוּ שֹֽׁדְדִ֔ים כִּ֣י חֶ֤רֶב לַֽיהוָה֙ אֹֽכְלָ֔ה מִקְצֵה־אֶ֖רֶץ וְעַד־קְצֵ֣ה הָאָ֑רֶץ אֵ֥ין שָׁל֖וֹם לְכָל־בָּשָֽׂר׃"}},"definableWords":["LORD","one","earth","flesh","peace"],"peopleInVerse":[],"themesInVerse":["peace"]},"13":{"text":"They have sown wheat, but shall reap thorns: they have put themselves to pain, but shall not profit: and they shall be ashamed of your revenues because of the fierce anger of the LORD.","ref":"Jeremiah 12:13","synthesized":"They have sown wheat but harvested thorns. They have exhausted themselves to no avail. Bear the shame of your harvest because of the fierce anger of the LORD.”","sources":{"KJV":{"text":"They have sown wheat, but shall reap thorns: they have put themselves to pain, but shall not profit: and they shall be ashamed of your revenues because of the fierce anger of the LORD."},"BSB":{"text":"They have sown wheat but harvested thorns. They have exhausted themselves to no avail. Bear the shame of your harvest because of the fierce anger of the LORD.”"},"TANAKH":{"text":"They have sown wheat, and have reaped thorns; they have put themselves to pain, they profit not; be ye then ashamed of your increase, because of the fierce anger of HaShem."},"HEBREW":{"text":"זָרְע֤וּ חִטִּים֙ וְקֹצִ֣ים קָצָ֔רוּ נֶחְל֖וּ לֹ֣א יוֹעִ֑לוּ וּבֹ֙שׁוּ֙ מִתְּבוּאֹ֣תֵיכֶ֔ם מֵחֲר֖וֹן אַף־יְהוָֽה׃"}},"definableWords":["anger","LORD"],"peopleInVerse":[]},"14":{"text":"Thus saith the LORD against all mine evil neighbours, that touch the inheritance which I have caused my people Israel to inherit; Behold, I will pluck them out of their land, and pluck out the house of Judah from among them.","ref":"Jeremiah 12:14","synthesized":"This is what the LORD says: “As for all My evil neighbors who attack the inheritance that I bequeathed to My people Israel, I am about to uproot them from their land, and I will uproot the house of Judah from among them.","sources":{"KJV":{"text":"Thus saith the LORD against all mine evil neighbours, that touch the inheritance which I have caused my people Israel to inherit; Behold, I will pluck them out of their land, and pluck out the house of Judah from among them."},"BSB":{"text":"This is what the LORD says: “As for all My evil neighbors who attack the inheritance that I bequeathed to My people Israel, I am about to uproot them from their land, and I will uproot the house of Judah from among them."},"TANAKH":{"text":"Thus saith HaShem: As for all Mine evil neighbours, that touch the inheritance which I have caused My people Israel to inherit, behold, I will pluck them up from off their land, and will pluck up the house of Judah from among them."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה עַל־כָּל־שְׁכֵנַי֙ הָֽרָעִ֔ים הַנֹּֽגְעִים֙ בַּֽנַּחֲלָ֔ה אֲשֶׁר־הִנְחַ֥לְתִּי אֶת־עַמִּ֖י אֶת־יִשְׂרָאֵ֑ל הִנְנִ֤י נֹֽתְשָׁם֙ מֵעַ֣ל אַדְמָתָ֔ם וְאֶת־בֵּ֥ית יְהוּדָ֖ה אֶתּ֥וֹשׁ מִתּוֹכָֽם׃"}},"definableWords":["LORD","evil","people","Israel","land","house","Judah"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"15":{"text":"And it shall come to pass, after that I have plucked them out I will return, and have compassion on them, and will bring them again, every man to his heritage, and every man to his land.","ref":"Jeremiah 12:15","synthesized":"But after I have uprooted them, I will once again have compassion on them and return each one to his inheritance and to his land.","sources":{"KJV":{"text":"And it shall come to pass, after that I have plucked them out I will return, and have compassion on them, and will bring them again, every man to his heritage, and every man to his land."},"BSB":{"text":"But after I have uprooted them, I will once again have compassion on them and return each one to his inheritance and to his land."},"TANAKH":{"text":"And it shall come to pass, after that I have plucked them up, I will again have compassion on them; and I will bring them back, every man to his heritage, and every man to his land."},"HEBREW":{"text":"וְהָיָ֗ה אַֽחֲרֵי֙ נָתְשִׁ֣י אוֹתָ֔ם אָשׁ֖וּב וְרִֽחַמְתִּ֑ים וַהֲשִׁבֹתִ֛ים אִ֥ישׁ לְנַחֲלָת֖וֹ וְאִ֥ישׁ לְאַרְצֽוֹ׃"}},"definableWords":["one","land"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise","second_coming"]},"16":{"text":"And it shall come to pass, if they will diligently learn the ways of my people, to swear by my name, The LORD liveth; as they taught my people to swear by Baal; then shall they be built in the midst of my people.","ref":"Jeremiah 12:16","synthesized":"And if they will diligently learn the ways of My people and swear by My name, saying, ‘As surely as the LORD lives’—just as they once taught My people to swear by Baal—then they will be established among My people.","sources":{"KJV":{"text":"And it shall come to pass, if they will diligently learn the ways of my people, to swear by my name, The LORD liveth; as they taught my people to swear by Baal; then shall they be built in the midst of my people."},"BSB":{"text":"And if they will diligently learn the ways of My people and swear by My name, saying, ‘As surely as the LORD lives’—just as they once taught My people to swear by Baal—then they will be established among My people."},"TANAKH":{"text":"And it shall come to pass, if they will diligently learn the ways of My people to swear by My name: 'As HaShem liveth,' even as they taught My people to swear by Baal; then shall they be built up in the midst of My people."},"HEBREW":{"text":"וְהָיָ֡ה אִם־לָמֹ֣ד יִלְמְדוּ֩ אֶת־דַּֽרְכֵ֨י עַמִּ֜י לְהִשָּׁבֵ֤עַ בִּשְׁמִי֙ חַי־יְהוָ֔ה כַּאֲשֶׁ֤ר לִמְּדוּ֙ אֶת־עַמִּ֔י לְהִשָּׁבֵ֖עַ בַּבָּ֑עַל וְנִבְנ֖וּ בְּת֥וֹךְ עַמִּֽי׃"}},"definableWords":["people","name","LORD"],"peopleInVerse":[],"themesInVerse":["covenant"]},"17":{"text":"But if they will not obey, I will utterly pluck up and destroy that nation, saith the LORD.","ref":"Jeremiah 12:17","synthesized":"But if they will not obey, then I will uproot that nation; I will uproot it and destroy it, declares the LORD.”","sources":{"KJV":{"text":"But if they will not obey, I will utterly pluck up and destroy that nation, saith the LORD."},"BSB":{"text":"But if they will not obey, then I will uproot that nation; I will uproot it and destroy it, declares the LORD.”"},"TANAKH":{"text":"But if they will not hearken, then will I pluck up that nation, plucking up and destroying it, saith HaShem."},"HEBREW":{"text":"וְאִ֖ם לֹ֣א יִשְׁמָ֑עוּ וְנָ֨תַשְׁתִּ֜י אֶת־הַגּ֥וֹי הַה֛וּא נָת֥וֹשׁ וְאַבֵּ֖ד נְאֻם־יְהוָֽה׃"}},"definableWords":["nation","LORD"],"peopleInVerse":[]}}},"13":{"chapter":"13","title":"THE LINEN GIRDLE","verses":{"1":{"text":"Thus saith the LORD unto me, Go and get thee a linen girdle, and put it upon thy loins, and put it not in water.","ref":"Jeremiah 13:1","synthesized":"This is what the LORD said to me: “Go and buy yourself a linen loincloth and put it around your waist, but do not let it touch water.”","sources":{"KJV":{"text":"Thus saith the LORD unto me, Go and get thee a linen girdle, and put it upon thy loins, and put it not in water."},"BSB":{"text":"This is what the LORD said to me: “Go and buy yourself a linen loincloth and put it around your waist, but do not let it touch water.”"},"TANAKH":{"text":"Thus said HaShem unto me: 'Go, and get thee a linen girdle, and put it upon thy loins, and put it not in water.'"},"HEBREW":{"text":"כֹּֽה־אָמַ֨ר יְהוָ֜ה אֵלַ֗י הָל֞וֹךְ וְקָנִ֤יתָ לְּךָ֙ אֵז֣וֹר פִּשְׁתִּ֔ים וְשַׂמְתּ֖וֹ עַל־מָתְנֶ֑יךָ וּבַמַּ֖יִם לֹ֥א תְבִאֵֽהוּ׃"}},"definableWords":["LORD","water"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"2":{"text":"So I got a girdle according to the word of the LORD, and put it on my loins.","ref":"Jeremiah 13:2","synthesized":"So I bought a loincloth as the LORD had instructed me, and I put it around my waist.","sources":{"KJV":{"text":"So I got a girdle according to the word of the LORD, and put it on my loins."},"BSB":{"text":"So I bought a loincloth as the LORD had instructed me, and I put it around my waist."},"TANAKH":{"text":"So I got a girdle according to the word of HaShem, and put it upon my loins."},"HEBREW":{"text":"וָאֶקְנֶ֥ה אֶת־הָאֵז֖וֹר כִּדְבַ֣ר יְהוָ֑ה וָאָשִׂ֖ם עַל־מָתְנָֽי׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"3":{"text":"And the word of the LORD came unto me the second time, saying,","ref":"Jeremiah 13:3","synthesized":"Then the word of the LORD came to me a second time:","sources":{"KJV":{"text":"And the word of the LORD came unto me the second time, saying,"},"BSB":{"text":"Then the word of the LORD came to me a second time:"},"TANAKH":{"text":"And the word of HaShem came unto me the second time, saying:"},"HEBREW":{"text":"וַיְהִ֧י דְבַר־יְהוָ֛ה אֵלַ֖י שֵׁנִ֥ית לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"4":{"text":"Take the girdle that thou hast got, which is upon thy loins, and arise, go to Euphrates, and hide it there in a hole of the rock.","ref":"Jeremiah 13:4","synthesized":"“Take the loincloth that you bought and are wearing, and go at once to Perath and hide it there in a crevice of the rocks.”","sources":{"KJV":{"text":"Take the girdle that thou hast got, which is upon thy loins, and arise, go to Euphrates, and hide it there in a hole of the rock."},"BSB":{"text":"“Take the loincloth that you bought and are wearing, and go at once to Perath and hide it there in a crevice of the rocks.”"},"TANAKH":{"text":"'Take the girdle that thou hast gotten, which is upon thy loins, and arise, go to Perath, and hide it there in a cleft of the rock.'"},"HEBREW":{"text":"קַ֧ח אֶת־הָאֵז֛וֹר אֲשֶׁ֥ר קָנִ֖יתָ אֲשֶׁ֣ר עַל־מָתְנֶ֑יךָ וְקוּם֙ לֵ֣ךְ פְּרָ֔תָה וְטָמְנֵ֥הוּ שָׁ֖ם בִּנְקִ֥יק הַסָּֽלַע׃"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"So I went, and hid it by Euphrates, as the LORD commanded me.","ref":"Jeremiah 13:5","synthesized":"So I went and hid it at Perath, as the LORD had commanded me.","sources":{"KJV":{"text":"So I went, and hid it by Euphrates, as the LORD commanded me."},"BSB":{"text":"So I went and hid it at Perath, as the LORD had commanded me."},"TANAKH":{"text":"So I went, and hid it in Perath, as HaShem commanded me."},"HEBREW":{"text":"וָאֵלֵ֕ךְ וָאֶטְמְנֵ֖הוּ בִּפְרָ֑ת כַּאֲשֶׁ֛ר צִוָּ֥ה יְהוָ֖ה אוֹתִֽי׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"6":{"text":"And it came to pass after many days, that the LORD said unto me, Arise, go to Euphrates, and take the girdle from thence, which I commanded thee to hide there.","ref":"Jeremiah 13:6","synthesized":"Many days later the LORD said to me, “Arise, go to Perath, and get the loincloth that I commanded you to hide there.”","sources":{"KJV":{"text":"And it came to pass after many days, that the LORD said unto me, Arise, go to Euphrates, and take the girdle from thence, which I commanded thee to hide there."},"BSB":{"text":"Many days later the LORD said to me, “Arise, go to Perath, and get the loincloth that I commanded you to hide there.”"},"TANAKH":{"text":"And it came to pass after many days, that HaShem said unto me: 'Arise, go to Perath, and take the girdle from thence, which I commanded thee to hide there.'"},"HEBREW":{"text":"וַיְהִ֕י מִקֵּ֖ץ יָמִ֣ים רַבִּ֑ים וַיֹּ֨אמֶר יְהוָ֜ה אֵלַ֗י ק֚וּם לֵ֣ךְ פְּרָ֔תָה וְקַ֤ח מִשָּׁם֙ אֶת־הָ֣אֵז֔וֹר אֲשֶׁ֥ר צִוִּיתִ֖יךָ לְטָמְנוֹ־שָֽׁם׃"}},"definableWords":["days","LORD"],"peopleInVerse":[]},"7":{"text":"Then I went to Euphrates, and digged, and took the girdle from the place where I had hid it: and, behold, the girdle was marred, it was profitable for nothing.","ref":"Jeremiah 13:7","synthesized":"So I went to Perath and dug up the loincloth, and I took it from the place where I had hidden it. But now it was ruined—of no use at all.","sources":{"KJV":{"text":"Then I went to Euphrates, and digged, and took the girdle from the place where I had hid it: and, behold, the girdle was marred, it was profitable for nothing."},"BSB":{"text":"So I went to Perath and dug up the loincloth, and I took it from the place where I had hidden it. But now it was ruined—of no use at all."},"TANAKH":{"text":"Then I went to Perath, and digged, and took the girdle from the place where I had hid it; and, behold, the girdle was marred, it was profitable for nothing."},"HEBREW":{"text":"וָאֵלֵ֣ךְ פְּרָ֔תָה וָאֶחְפֹּ֗ר וָֽאֶקַּח֙ אֶת־הָ֣אֵז֔וֹר מִן־הַמָּק֖וֹם אֲשֶׁר־טְמַנְתִּ֣יו שָׁ֑מָּה וְהִנֵּה֙ נִשְׁחַ֣ת הָאֵז֔וֹר לֹ֥א יִצְלַ֖ח לַכֹּֽל׃"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Then the word of the LORD came unto me, saying,","ref":"Jeremiah 13:8","synthesized":"Then the word of the LORD came to me:","sources":{"KJV":{"text":"Then the word of the LORD came unto me, saying,"},"BSB":{"text":"Then the word of the LORD came to me:"},"TANAKH":{"text":"Then the word of HaShem came unto me, saying:"},"HEBREW":{"text":"וַיְהִ֥י דְבַר־יְהוָ֖ה אֵלַ֥י לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"9":{"text":"Thus saith the LORD, After this manner will I mar the pride of Judah, and the great pride of Jerusalem.","ref":"Jeremiah 13:9","synthesized":"“This is what the LORD says: In the same way I will ruin the pride of Judah and the great pride of Jerusalem.","sources":{"KJV":{"text":"Thus saith the LORD, After this manner will I mar the pride of Judah, and the great pride of Jerusalem."},"BSB":{"text":"“This is what the LORD says: In the same way I will ruin the pride of Judah and the great pride of Jerusalem."},"TANAKH":{"text":"Thus saith HaShem: After this manner will I mar the pride of Judah, and the great pride of Jerusalem,"},"HEBREW":{"text":"כֹּ֖ה אָמַ֣ר יְהוָ֑ה כָּ֠כָה אַשְׁחִ֞ית אֶת־גְּא֧וֹן יְהוּדָ֛ה וְאֶת־גְּא֥וֹן יְרוּשָׁלַ֖͏ִם הָרָֽב׃"}},"definableWords":["LORD","way","Judah","great","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"10":{"text":"This evil people, which refuse to hear my words, which walk in the imagination of their heart, and walk after other gods, to serve them, and to worship them, shall even be as this girdle, which is good for nothing.","ref":"Jeremiah 13:10","synthesized":"These evil people, who refuse to listen to My words, who follow the stubbornness of their own hearts, and who go after other gods to serve and worship them, they will be like this loincloth—of no use at all.","sources":{"KJV":{"text":"This evil people, which refuse to hear my words, which walk in the imagination of their heart, and walk after other gods, to serve them, and to worship them, shall even be as this girdle, which is good for nothing."},"BSB":{"text":"These evil people, who refuse to listen to My words, who follow the stubbornness of their own hearts, and who go after other gods to serve and worship them, they will be like this loincloth—of no use at all."},"TANAKH":{"text":"even this evil people, that refuse to hear My words, that walk in the stubbornness of their heart, and are gone after other gods to serve them, and to worship them, that it be as this girdle, which is profitable for nothing."},"HEBREW":{"text":"הָעָם֩ הַזֶּ֨ה הָרָ֜ע הַֽמֵּאֲנִ֣ים ׀ לִשְׁמ֣וֹעַ אֶת־דְּבָרַ֗י הַהֹֽלְכִים֙ בִּשְׁרִר֣וּת לִבָּ֔ם וַיֵּלְכ֗וּ אַֽחֲרֵי֙ אֱלֹהִ֣ים אֲחֵרִ֔ים לְעָבְדָ֖ם וּלְהִשְׁתַּחֲוֺ֣ת לָהֶ֑ם וִיהִי֙ כָּאֵז֣וֹר הַזֶּ֔ה אֲשֶׁ֥ר לֹא־יִצְלַ֖ח לַכֹּֽל׃"}},"definableWords":["evil","people","worship"],"peopleInVerse":[],"themesInVerse":["worship"]},"11":{"text":"For as the girdle cleaveth to the loins of a man, so have I caused to cleave unto me the whole house of Israel and the whole house of Judah, saith the LORD; that they might be unto me for a people, and for a name, and for a praise, and for a glory: but they would not hear.","ref":"Jeremiah 13:11","synthesized":"For just as a loincloth clings to a man’s waist, so I have made the whole house of Israel and the whole house of Judah cling to Me, declares the LORD, so that they might be My people for My renown and praise and glory. But they did not listen.","sources":{"KJV":{"text":"For as the girdle cleaveth to the loins of a man, so have I caused to cleave unto me the whole house of Israel and the whole house of Judah, saith the LORD; that they might be unto me for a people, and for a name, and for a praise, and for a glory: but they would not hear."},"BSB":{"text":"For just as a loincloth clings to a man’s waist, so I have made the whole house of Israel and the whole house of Judah cling to Me, declares the LORD, so that they might be My people for My renown and praise and glory. But they did not listen."},"TANAKH":{"text":"For as the girdle cleaveth to the loins of a man, so have I caused to cleave unto Me the whole house of Israel and the whole house of Judah, saith HaShem, that they might be unto Me for a people, and for a name, and for a praise, and for a glory; but they would not hearken."},"HEBREW":{"text":"כִּ֡י כַּאֲשֶׁר֩ יִדְבַּ֨ק הָאֵז֜וֹר אֶל־מָתְנֵי־אִ֗ישׁ כֵּ֣ן הִדְבַּ֣קְתִּי אֵ֠לַי אֶת־כָּל־בֵּ֨ית יִשְׂרָאֵ֜ל וְאֶת־כָּל־בֵּ֤ית יְהוּדָה֙ נְאֻם־יְהוָ֔ה לִֽהְי֥וֹת לִי֙ לְעָ֔ם וּלְשֵׁ֥ם וְלִתְהִלָּ֖ה וּלְתִפְאָ֑רֶת וְלֹ֖א שָׁמֵֽעוּ׃"}},"definableWords":["man","made","house","Israel","Judah","LORD","people","praise","glory"],"peopleInVerse":[],"themesInVerse":["creation","worship"]},"12":{"text":"Therefore thou shalt speak unto them this word; Thus saith the LORD God of Israel, Every bottle shall be filled with wine: and they shall say unto thee, Do we not certainly know that every bottle shall be filled with wine?","ref":"Jeremiah 13:12","synthesized":"Therefore you are to tell them that this is what the LORD, the God of Israel, says: ‘Every wineskin shall be filled with wine.’  And when they reply, ‘Don’t we surely know that every wineskin should be filled with wine?’","sources":{"KJV":{"text":"Therefore thou shalt speak unto them this word; Thus saith the LORD God of Israel, Every bottle shall be filled with wine: and they shall say unto thee, Do we not certainly know that every bottle shall be filled with wine?"},"BSB":{"text":"Therefore you are to tell them that this is what the LORD, the God of Israel, says: ‘Every wineskin shall be filled with wine.’  And when they reply, ‘Don’t we surely know that every wineskin should be filled with wine?’"},"TANAKH":{"text":"Moreover thou shalt speak unto them this word: Thus saith HaShem, the G-d of Israel: 'Every bottle is filled with wine'; and when they shall say unto thee: 'Do we not know that every bottle is filled with wine?'"},"HEBREW":{"text":"וְאָמַרְתָּ֨ אֲלֵיהֶ֜ם אֶת־הַדָּבָ֣ר הַזֶּ֗ה כֹּֽה־אָמַ֤ר יְהוָה֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל כָּל־נֵ֖בֶל יִמָּ֣לֵא יָ֑יִן וְאָמְר֣וּ אֵלֶ֔יךָ הֲיָדֹ֙עַ֙ לֹ֣א נֵדַ֔ע כִּ֥י כָל־נֵ֖בֶל יִמָּ֥לֵא יָֽיִן׃"}},"definableWords":["LORD","God","Israel"],"peopleInVerse":[]},"13":{"text":"Then shalt thou say unto them, Thus saith the LORD, Behold, I will fill all the inhabitants of this land, even the kings that sit upon David’s throne, and the priests, and the prophets, and all the inhabitants of Jerusalem, with drunkenness.","ref":"Jeremiah 13:13","synthesized":"then you are to tell them that this is what the LORD says: ‘I am going to fill with drunkenness all who live in this land—the kings who sit on David’s throne, the priests, the prophets, and all the people of Jerusalem.","sources":{"KJV":{"text":"Then shalt thou say unto them, Thus saith the LORD, Behold, I will fill all the inhabitants of this land, even the kings that sit upon David’s throne, and the priests, and the prophets, and all the inhabitants of Jerusalem, with drunkenness."},"BSB":{"text":"then you are to tell them that this is what the LORD says: ‘I am going to fill with drunkenness all who live in this land—the kings who sit on David’s throne, the priests, the prophets, and all the people of Jerusalem."},"TANAKH":{"text":"Then shalt thou say unto them: Thus saith HaShem: Behold, I will fill all the inhabitants of this land, even the kings that sit upon David's throne, and the priests, and the prophets, and all the inhabitants of Jerusalem, with drunkenness."},"HEBREW":{"text":"וְאָמַרְתָּ֨ אֲלֵיהֶ֜ם כֹּֽה־אָמַ֣ר יְהוָ֗ה הִנְנִ֣י מְמַלֵּ֣א אֶת־כָּל־יֹשְׁבֵ֣י הָאָ֪רֶץ הַזֹּ֟את וְאֶת־הַמְּלָכִ֣ים הַיֹּשְׁבִים֩ לְדָוִ֨ד עַל־כִּסְא֜וֹ וְאֶת־הַכֹּהֲנִ֣ים וְאֶת־הַנְּבִיאִ֗ים וְאֵ֛ת כָּל־יֹשְׁבֵ֥י יְרוּשָׁלָ֖͏ִם שִׁכָּרֽוֹן׃"}},"definableWords":["LORD","fill","live","land","kings","throne","people","Jerusalem"],"peopleInVerse":["David"],"placesInVerse":["Jerusalem"],"themesInVerse":["kingdom_of_god","kingship","land_promise"]},"14":{"text":"And I will dash them one against another, even the fathers and the sons together, saith the LORD: I will not pity, nor spare, nor have mercy, but destroy them.","ref":"Jeremiah 13:14","synthesized":"I will smash them against one another, fathers and sons alike, declares the LORD. I will allow no mercy or pity or compassion to keep Me from destroying them.’”","sources":{"KJV":{"text":"And I will dash them one against another, even the fathers and the sons together, saith the LORD: I will not pity, nor spare, nor have mercy, but destroy them."},"BSB":{"text":"I will smash them against one another, fathers and sons alike, declares the LORD. I will allow no mercy or pity or compassion to keep Me from destroying them.’”"},"TANAKH":{"text":"And I will dash them one against another, even the fathers and the sons together, saith HaShem; I will not pity, nor spare, nor have compassion, that I should not destroy them."},"HEBREW":{"text":"וְנִפַּצְתִּים֩ אִ֨ישׁ אֶל־אָחִ֜יו וְהָאָב֧וֹת וְהַבָּנִ֛ים יַחְדָּ֖ו נְאֻם־יְהוָ֑ה לֹֽא־אֶחְמ֧וֹל וְלֹֽא־אָח֛וּס וְלֹ֥א אֲרַחֵ֖ם מֵהַשְׁחִיתָֽם׃"}},"definableWords":["one","fathers","sons","LORD","mercy","or","keep"],"peopleInVerse":[],"themesInVerse":["grace"]},"15":{"text":"Hear ye, and give ear; be not proud: for the LORD hath spoken.","ref":"Jeremiah 13:15","synthesized":"Listen and give heed. Do not be arrogant, for the LORD has spoken.","sources":{"KJV":{"text":"Hear ye, and give ear; be not proud: for the LORD hath spoken."},"BSB":{"text":"Listen and give heed. Do not be arrogant, for the LORD has spoken."},"TANAKH":{"text":"Hear ye, and give ear, be not proud; for HaShem hath spoken."},"HEBREW":{"text":"שִׁמְע֥וּ וְהַאֲזִ֖ינוּ אַל־תִּגְבָּ֑הוּ כִּ֥י יְהוָ֖ה דִּבֵּֽר׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"16":{"text":"Give glory to the LORD your God, before he cause darkness, and before your feet stumble upon the dark mountains, and, while ye look for light, he turn it into the shadow of death, and make it gross darkness.","ref":"Jeremiah 13:16","synthesized":"Give glory to the LORD your God before He brings darkness, before your feet stumble on the dusky mountains. You wait for light, but He turns it into deep gloom and thick darkness.","sources":{"KJV":{"text":"Give glory to the LORD your God, before he cause darkness, and before your feet stumble upon the dark mountains, and, while ye look for light, he turn it into the shadow of death, and make it gross darkness."},"BSB":{"text":"Give glory to the LORD your God before He brings darkness, before your feet stumble on the dusky mountains. You wait for light, but He turns it into deep gloom and thick darkness."},"TANAKH":{"text":"Give glory to HaShem your G-d, before it grow dark, and before your feet stumble upon the mountains of twilight, and, while ye look for light, He turn it into the shadow of death, and make it gross darkness."},"HEBREW":{"text":"תְּנוּ֩ לַיהוָ֨ה אֱלֹהֵיכֶ֤ם כָּבוֹד֙ בְּטֶ֣רֶם יַחְשִׁ֔ךְ וּבְטֶ֛רֶם יִֽתְנַגְּפ֥וּ רַגְלֵיכֶ֖ם עַל־הָ֣רֵי נָ֑שֶׁף וְקִוִּיתֶ֤ם לְאוֹר֙ וְשָׂמָ֣הּ לְצַלְמָ֔וֶת ישית וְשִׁ֖ית לַעֲרָפֶֽל׃"}},"definableWords":["glory","LORD","God","darkness","wait","light","deep"],"peopleInVerse":[],"themesInVerse":["hope","light_darkness","worship"]},"17":{"text":"But if ye will not hear it, my soul shall weep in secret places for your pride; and mine eye shall weep sore, and run down with tears, because the LORD’s flock is carried away captive.","ref":"Jeremiah 13:17","synthesized":"But if you do not listen, I will weep in secret because of your pride. My eyes will overflow with tears, because the LORD’s flock has been taken captive.","sources":{"KJV":{"text":"But if ye will not hear it, my soul shall weep in secret places for your pride; and mine eye shall weep sore, and run down with tears, because the LORD’s flock is carried away captive."},"BSB":{"text":"But if you do not listen, I will weep in secret because of your pride. My eyes will overflow with tears, because the LORD’s flock has been taken captive."},"TANAKH":{"text":"But if ye will not hear it, my soul shall weep in secret for your pride; and mine eyes shall weep sore, and run down with tears, because HaShem'S flock is carried away captive."},"HEBREW":{"text":"וְאִם֙ לֹ֣א תִשְׁמָע֔וּהָ בְּמִסְתָּרִ֥ים תִּבְכֶּֽה־נַפְשִׁ֖י מִפְּנֵ֣י גֵוָ֑ה וְדָמֹ֨עַ תִּדְמַ֜ע וְתֵרַ֤ד עֵינִי֙ דִּמְעָ֔ה כִּ֥י נִשְׁבָּ֖ה עֵ֥דֶר יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[],"themesInVerse":["shepherd_sheep"]},"18":{"text":"Say unto the king and to the queen, Humble yourselves, sit down: for your principalities shall come down, even the crown of your glory.","ref":"Jeremiah 13:18","synthesized":"Say to the king and to the queen mother: “Take a lowly seat, for your glorious crowns have fallen from your heads.”","sources":{"KJV":{"text":"Say unto the king and to the queen, Humble yourselves, sit down: for your principalities shall come down, even the crown of your glory."},"BSB":{"text":"Say to the king and to the queen mother: “Take a lowly seat, for your glorious crowns have fallen from your heads.”"},"TANAKH":{"text":"Say thou unto the king and to the queen-mother: 'Sit ye down low; for your headtires are come down, even your beautiful crown.'"},"HEBREW":{"text":"אֱמֹ֥ר לַמֶּ֛לֶךְ וְלַגְּבִירָ֖ה הַשְׁפִּ֣ילוּ שֵׁ֑בוּ כִּ֤י יָרַד֙ מַרְאֲשׁ֣וֹתֵיכֶ֔ם עֲטֶ֖רֶת תִּֽפְאַרְתְּכֶֽם׃"}},"definableWords":["king","mother"],"peopleInVerse":[],"themesInVerse":["humility","kingship"]},"19":{"text":"The cities of the south shall be shut up, and none shall open them: Judah shall be carried away captive all of it, it shall be wholly carried away captive.","ref":"Jeremiah 13:19","synthesized":"The cities of the Negev have been shut tight, and no one can open them. All Judah has been carried into exile, wholly taken captive.","sources":{"KJV":{"text":"The cities of the south shall be shut up, and none shall open them: Judah shall be carried away captive all of it, it shall be wholly carried away captive."},"BSB":{"text":"The cities of the Negev have been shut tight, and no one can open them. All Judah has been carried into exile, wholly taken captive."},"TANAKH":{"text":"The cities of the South are shut up, and there is none to open them; Judah is carried away captive all of it; it is wholly carried away captive."},"HEBREW":{"text":"עָרֵ֥י הַנֶּ֛גֶב סֻגְּר֖וּ וְאֵ֣ין פֹּתֵ֑חַ הָגְלָ֧ת יְהוּדָ֛ה כֻּלָּ֖הּ הָגְלָ֥ת שְׁלוֹמִֽים׃"}},"definableWords":["one","Judah"],"peopleInVerse":[],"placesInVerse":["Negev"],"themesInVerse":["exile_return"]},"20":{"text":"Lift up your eyes, and behold them that come from the north: where is the flock that was given thee, thy beautiful flock?","ref":"Jeremiah 13:20","synthesized":"Lift up your eyes and see those coming from the north. Where is the flock entrusted to you, the sheep that were your pride?","sources":{"KJV":{"text":"Lift up your eyes, and behold them that come from the north: where is the flock that was given thee, thy beautiful flock?"},"BSB":{"text":"Lift up your eyes and see those coming from the north. Where is the flock entrusted to you, the sheep that were your pride?"},"TANAKH":{"text":"Lift up your eyes, and behold them that come from the north; where is the flock that was given thee, thy beautiful flock?"},"HEBREW":{"text":"שאי שְׂא֤וּ עֵֽינֵיכֶם֙ וראי וּרְא֔וּ הַבָּאִ֖ים מִצָּפ֑וֹן אַיֵּ֗ה הָעֵ֙דֶר֙ נִתַּן־לָ֔ךְ צֹ֖אן תִּפְאַרְתֵּֽךְ׃"}},"definableWords":["see"],"peopleInVerse":[],"themesInVerse":["second_coming","shepherd_sheep"]},"21":{"text":"What wilt thou say when he shall punish thee? for thou hast taught them to be captains, and as chief over thee: shall not sorrows take thee, as a woman in travail?","ref":"Jeremiah 13:21","synthesized":"What will you say when He sets over you close allies whom you yourself trained? Will not pangs of anguish grip you, as they do a woman in labor?","sources":{"KJV":{"text":"What wilt thou say when he shall punish thee? for thou hast taught them to be captains, and as chief over thee: shall not sorrows take thee, as a woman in travail?"},"BSB":{"text":"What will you say when He sets over you close allies whom you yourself trained? Will not pangs of anguish grip you, as they do a woman in labor?"},"TANAKH":{"text":"What wilt thou say, when He shall set the friends over thee as head, whom thou thyself hast trained against thee? Shall not pangs take hold of thee, as of a woman in travail?"},"HEBREW":{"text":"מַה־תֹּֽאמְרִי֙ כִּֽי־יִפְקֹ֣ד עָלַ֔יִךְ וְ֠אַתְּ לִמַּ֨דְתְּ אֹתָ֥ם עָלַ֛יִךְ אַלֻּפִ֖ים לְרֹ֑אשׁ הֲל֤וֹא חֲבָלִים֙ יֹאחֱז֔וּךְ כְּמ֖וֹ אֵ֥שֶׁת לֵדָֽה׃"}},"definableWords":["woman"],"peopleInVerse":[]},"22":{"text":"And if thou say in thine heart, Wherefore come these things upon me? For the greatness of thine iniquity are thy skirts discovered, and thy heels made bare.","ref":"Jeremiah 13:22","synthesized":"And if you ask yourself, “Why has this happened to me?” It is because of the magnitude of your iniquity that your skirts have been stripped off and your body has been exposed.","sources":{"KJV":{"text":"And if thou say in thine heart, Wherefore come these things upon me? For the greatness of thine iniquity are thy skirts discovered, and thy heels made bare."},"BSB":{"text":"And if you ask yourself, “Why has this happened to me?” It is because of the magnitude of your iniquity that your skirts have been stripped off and your body has been exposed."},"TANAKH":{"text":"And if thou say in thy heart: 'Wherefore are these things befallen me?' --for the greatness of thine iniquity are thy skirts uncovered, and thy heels suffer violence."},"HEBREW":{"text":"וְכִ֤י תֹאמְרִי֙ בִּלְבָבֵ֔ךְ מַדּ֖וּעַ קְרָאֻ֣נִי אֵ֑לֶּה בְּרֹ֧ב עֲוֺנֵ֛ךְ נִגְל֥וּ שׁוּלַ֖יִךְ נֶחְמְס֥וּ עֲקֵבָֽיִךְ׃"}},"definableWords":["iniquity"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"23":{"text":"Can the Ethiopian change his skin, or the leopard his spots? then may ye also do good, that are accustomed to do evil.","ref":"Jeremiah 13:23","synthesized":"Can the Ethiopian change his skin, or the leopard his spots? Neither are you able to do good— you who are accustomed to doing evil.","sources":{"KJV":{"text":"Can the Ethiopian change his skin, or the leopard his spots? then may ye also do good, that are accustomed to do evil."},"BSB":{"text":"Can the Ethiopian change his skin, or the leopard his spots? Neither are you able to do good— you who are accustomed to doing evil."},"TANAKH":{"text":"Can the Ethiopian change his skin, or the leopard his spots? Then may ye also do good, that are accustomed to do evil."},"HEBREW":{"text":"הֲיַהֲפֹ֤ךְ כּוּשִׁי֙ עוֹר֔וֹ וְנָמֵ֖ר חֲבַרְבֻּרֹתָ֑יו גַּם־אַתֶּם֙ תּוּכְל֣וּ לְהֵיטִ֔יב לִמֻּדֵ֖י הָרֵֽעַ׃"}},"definableWords":["or","good","evil"],"peopleInVerse":[]},"24":{"text":"Therefore will I scatter them as the stubble that passeth away by the wind of the wilderness.","ref":"Jeremiah 13:24","synthesized":"“I will scatter you like chaff driven by the desert wind.","sources":{"KJV":{"text":"Therefore will I scatter them as the stubble that passeth away by the wind of the wilderness."},"BSB":{"text":"“I will scatter you like chaff driven by the desert wind."},"TANAKH":{"text":"Therefore will I scatter them, as the stubble that passeth away by the wind of the wilderness."},"HEBREW":{"text":"וַאֲפִיצֵ֖ם כְּקַשׁ־עוֹבֵ֑ר לְר֖וּחַ מִדְבָּֽר׃"}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"This is thy lot, the portion of thy measures from me, saith the LORD; because thou hast forgotten me, and trusted in falsehood.","ref":"Jeremiah 13:25","synthesized":"This is your lot, the portion I have measured to you,” declares the LORD, “because you have forgotten Me and trusted in falsehood.","sources":{"KJV":{"text":"This is thy lot, the portion of thy measures from me, saith the LORD; because thou hast forgotten me, and trusted in falsehood."},"BSB":{"text":"This is your lot, the portion I have measured to you,” declares the LORD, “because you have forgotten Me and trusted in falsehood."},"TANAKH":{"text":"This is thy lot, the portion measured unto thee from Me, saith HaShem; because thou hast forgotten Me, and trusted in falsehood."},"HEBREW":{"text":"זֶ֣ה גוֹרָלֵ֧ךְ מְנָת־מִדַּ֛יִךְ מֵֽאִתִּ֖י נְאֻם־יְהוָ֑ה אֲשֶׁר֙ שָׁכַ֣חַתְּ אוֹתִ֔י וַֽתִּבְטְחִ֖י בַּשָּֽׁקֶר׃"}},"definableWords":["Lot","LORD"],"peopleInVerse":[]},"26":{"text":"Therefore will I discover thy skirts upon thy face, that thy shame may appear.","ref":"Jeremiah 13:26","synthesized":"So I will pull your skirts up over your face, that your shame may be seen.","sources":{"KJV":{"text":"Therefore will I discover thy skirts upon thy face, that thy shame may appear."},"BSB":{"text":"So I will pull your skirts up over your face, that your shame may be seen."},"TANAKH":{"text":"Therefore will I also uncover thy skirts upon thy face, and thy shame shall appear."},"HEBREW":{"text":"וְגַם־אֲנִ֛י חָשַׂ֥פְתִּי שׁוּלַ֖יִךְ עַל־פָּנָ֑יִךְ וְנִרְאָ֖ה קְלוֹנֵֽךְ׃"}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"I have seen thine adulteries, and thy neighings, the lewdness of thy whoredom, and thine abominations on the hills in the fields. Woe unto thee, O Jerusalem! wilt thou not be made clean? when shall it once be?","ref":"Jeremiah 13:27","synthesized":"Your adulteries and lustful neighings, your shameless prostitution on the hills and in the fields— I have seen your detestable acts. Woe to you, O Jerusalem! How long will you remain unclean?”","sources":{"KJV":{"text":"I have seen thine adulteries, and thy neighings, the lewdness of thy whoredom, and thine abominations on the hills in the fields. Woe unto thee, O Jerusalem! wilt thou not be made clean? when shall it once be?"},"BSB":{"text":"Your adulteries and lustful neighings, your shameless prostitution on the hills and in the fields— I have seen your detestable acts. Woe to you, O Jerusalem! How long will you remain unclean?”"},"TANAKH":{"text":"Thine adulteries, and thy neighings, the lewdness of thy harlotry, on the hills in the field have I seen thy detestable acts. Woe unto thee, O Jerusalem! thou wilt not be made clean! When shall it ever be?"},"HEBREW":{"text":"נִֽאֻפַ֤יִךְ וּמִצְהֲלוֹתַ֙יִךְ֙ זִמַּ֣ת זְנוּתֵ֔ךְ עַל־גְּבָעוֹת֙ בַּשָּׂדֶ֔ה רָאִ֖יתִי שִׁקּוּצָ֑יִךְ א֥וֹי לָךְ֙ יְר֣וּשָׁלִַ֔ם לֹ֣א תִטְהֲרִ֔י אַחֲרֵ֥י מָתַ֖י עֹֽד׃"}},"definableWords":["Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]}}},"14":{"chapter":"14","title":"THE DROUGHT","verses":{"1":{"text":"The word of the LORD that came to Jeremiah concerning the dearth.","ref":"Jeremiah 14:1","synthesized":"This is the word of the LORD that came to Jeremiah concerning the drought:","sources":{"KJV":{"text":"The word of the LORD that came to Jeremiah concerning the dearth."},"BSB":{"text":"This is the word of the LORD that came to Jeremiah concerning the drought:"},"TANAKH":{"text":"The word of HaShem that came to Jeremiah concerning the droughts."},"HEBREW":{"text":"אֲשֶׁ֨ר הָיָ֤ה דְבַר־יְהוָה֙ אֶֽל־יִרְמְיָ֔הוּ עַל־דִּבְרֵ֖י הַבַּצָּרֽוֹת׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"2":{"text":"Judah mourneth, and the gates thereof languish; they are black unto the ground; and the cry of Jerusalem is gone up.","ref":"Jeremiah 14:2","synthesized":"“Judah mourns and her gates languish. Her people wail for the land, and a cry goes up from Jerusalem.","sources":{"KJV":{"text":"Judah mourneth, and the gates thereof languish; they are black unto the ground; and the cry of Jerusalem is gone up."},"BSB":{"text":"“Judah mourns and her gates languish. Her people wail for the land, and a cry goes up from Jerusalem."},"TANAKH":{"text":"Judah mourneth, and the gates thereof languish, they bow down in black unto the ground; and the cry of Jerusalem is gone up."},"HEBREW":{"text":"אָבְלָ֣ה יְהוּדָ֔ה וּשְׁעָרֶ֥יהָ אֻמְלְל֖וּ קָדְר֣וּ לָאָ֑רֶץ וְצִוְחַ֥ת יְרוּשָׁלַ֖͏ִם עָלָֽתָה׃"}},"definableWords":["Judah","people","land","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["land_promise"]},"3":{"text":"And their nobles have sent their little ones to the waters: they came to the pits, and found no water; they returned with their vessels empty; they were ashamed and confounded, and covered their heads.","ref":"Jeremiah 14:3","synthesized":"The nobles send their servants for water; they go to the cisterns, but find no water; their jars return empty. They are ashamed and humiliated; they cover their heads.","sources":{"KJV":{"text":"And their nobles have sent their little ones to the waters: they came to the pits, and found no water; they returned with their vessels empty; they were ashamed and confounded, and covered their heads."},"BSB":{"text":"The nobles send their servants for water; they go to the cisterns, but find no water; their jars return empty. They are ashamed and humiliated; they cover their heads."},"TANAKH":{"text":"And their nobles send their lads for water: they come to the pits, and find no water; their vessels return empty; they are ashamed and confounded, and cover their heads."},"HEBREW":{"text":"וְאַדִּ֣רֵיהֶ֔ם שָׁלְח֥וּ צעוריהם צְעִירֵיהֶ֖ם לַמָּ֑יִם בָּ֣אוּ עַל־גֵּבִ֞ים לֹא־מָ֣צְאוּ מַ֗יִם שָׁ֤בוּ כְלֵיהֶם֙ רֵיקָ֔ם בֹּ֥שׁוּ וְהָכְלְמ֖וּ וְחָפ֥וּ רֹאשָֽׁם׃"}},"definableWords":["servants","water"],"peopleInVerse":[],"themesInVerse":["bread_water_life","exile_return","second_coming"]},"4":{"text":"Because the ground is chapt, for there was no rain in the earth, the plowmen were ashamed, they covered their heads.","ref":"Jeremiah 14:4","synthesized":"The ground is cracked because no rain has fallen on the land. The farmers are ashamed; they cover their heads.","sources":{"KJV":{"text":"Because the ground is chapt, for there was no rain in the earth, the plowmen were ashamed, they covered their heads."},"BSB":{"text":"The ground is cracked because no rain has fallen on the land. The farmers are ashamed; they cover their heads."},"TANAKH":{"text":"Because of the ground which is cracked, for there hath been no rain in the land, the plowmen are ashamed, they cover their heads."},"HEBREW":{"text":"בַּעֲב֤וּר הָאֲדָמָה֙ חַ֔תָּה כִּ֛י לֹא־הָיָ֥ה גֶ֖שֶׁם בָּאָ֑רֶץ בֹּ֥שׁוּ אִכָּרִ֖ים חָפ֥וּ רֹאשָֽׁם׃"}},"definableWords":["ground","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"5":{"text":"Yea, the hind also calved in the field, and forsook it, because there was no grass.","ref":"Jeremiah 14:5","synthesized":"Even the doe in the field deserts her newborn fawn because there is no grass.","sources":{"KJV":{"text":"Yea, the hind also calved in the field, and forsook it, because there was no grass."},"BSB":{"text":"Even the doe in the field deserts her newborn fawn because there is no grass."},"TANAKH":{"text":"Yea, the hind also in the field calveth, and forsaketh her young, because there is no grass,"},"HEBREW":{"text":"כִּ֤י גַם־אַיֶּ֙לֶת֙ בַּשָּׂדֶ֔ה יָלְדָ֖ה וְעָז֑וֹב כִּ֥י לֹֽא־הָיָ֖ה דֶּֽשֶׁא׃"}},"definableWords":["field"],"peopleInVerse":[]},"6":{"text":"And the wild asses did stand in the high places, they snuffed up the wind like dragons; their eyes did fail, because there was no grass.","ref":"Jeremiah 14:6","synthesized":"Wild donkeys stand on barren heights; they pant for air like jackals; their eyes fail for lack of pasture.”","sources":{"KJV":{"text":"And the wild asses did stand in the high places, they snuffed up the wind like dragons; their eyes did fail, because there was no grass."},"BSB":{"text":"Wild donkeys stand on barren heights; they pant for air like jackals; their eyes fail for lack of pasture.”"},"TANAKH":{"text":"And the wild asses stand on the high hills, they gasp for air like jackals; their eyes fail, because there is no herbage."},"HEBREW":{"text":"וּפְרָאִים֙ עָמְד֣וּ עַל־שְׁפָיִ֔ם שָׁאֲפ֥וּ ר֖וּחַ כַּתַּנִּ֑ים כָּל֥וּ עֵינֵיהֶ֖ם כִּי־אֵ֥ין עֵֽשֶׂב׃"}},"definableWords":["stand"],"peopleInVerse":[]},"7":{"text":"O LORD, though our iniquities testify against us, do thou it for thy name’s sake: for our backslidings are many; we have sinned against thee.","ref":"Jeremiah 14:7","synthesized":"Although our iniquities testify against us, O LORD, act for the sake of Your name. Indeed, our rebellions are many; we have sinned against You.","sources":{"KJV":{"text":"O LORD, though our iniquities testify against us, do thou it for thy name’s sake: for our backslidings are many; we have sinned against thee."},"BSB":{"text":"Although our iniquities testify against us, O LORD, act for the sake of Your name. Indeed, our rebellions are many; we have sinned against You."},"TANAKH":{"text":"Though our iniquities testify against us, O HaShem, work Thou for Thy name's sake; for our backslidings are many, we have sinned against Thee."},"HEBREW":{"text":"אִם־עֲוֺנֵ֙ינוּ֙ עָ֣נוּ בָ֔נוּ יְהוָ֕ה עֲשֵׂ֖ה לְמַ֣עַן שְׁמֶ֑ךָ כִּֽי־רַבּ֥וּ מְשׁוּבֹתֵ֖ינוּ לְךָ֥ חָטָֽאנוּ׃"}},"definableWords":["LORD","name"],"peopleInVerse":[]},"8":{"text":"O the hope of Israel, the saviour thereof in time of trouble, why shouldest thou be as a stranger in the land, and as a wayfaring man that turneth aside to tarry for a night?","ref":"Jeremiah 14:8","synthesized":"O Hope of Israel, its Savior in times of distress, why are You like a stranger in the land, like a traveler who stays but a night?","sources":{"KJV":{"text":"O the hope of Israel, the saviour thereof in time of trouble, why shouldest thou be as a stranger in the land, and as a wayfaring man that turneth aside to tarry for a night?"},"BSB":{"text":"O Hope of Israel, its Savior in times of distress, why are You like a stranger in the land, like a traveler who stays but a night?"},"TANAKH":{"text":"O Thou hope of Israel, the Saviour thereof in time of trouble, why shouldest Thou be as a stranger in the land, and as a wayfaring man that turneth aside to tarry for a night?"},"HEBREW":{"text":"מִקְוֵה֙ יִשְׂרָאֵ֔ל מֽוֹשִׁיע֖וֹ בְּעֵ֣ת צָרָ֑ה לָ֤מָּה תִֽהְיֶה֙ כְּגֵ֣ר בָּאָ֔רֶץ וּכְאֹרֵ֖חַ נָטָ֥ה לָלֽוּן׃"}},"definableWords":["hope","Israel","stranger","land","night"],"peopleInVerse":[],"themesInVerse":["hope","land_promise"]},"9":{"text":"Why shouldest thou be as a man astonied, as a mighty man that cannot save? yet thou, O LORD, art in the midst of us, and we are called by thy name; leave us not.","ref":"Jeremiah 14:9","synthesized":"Why are You like a man taken by surprise, like a warrior powerless to save? Yet You are among us, O LORD, and we are called by Your name.   Do not forsake us!","sources":{"KJV":{"text":"Why shouldest thou be as a man astonied, as a mighty man that cannot save? yet thou, O LORD, art in the midst of us, and we are called by thy name; leave us not."},"BSB":{"text":"Why are You like a man taken by surprise, like a warrior powerless to save? Yet You are among us, O LORD, and we are called by Your name.   Do not forsake us!"},"TANAKH":{"text":"Why shouldest thou be as a man overcome, as a mighty man that cannot save? Yet Thou, O HaShem, art in the midst of us, and Thy name is called upon us; leave us not."},"HEBREW":{"text":"לָ֤מָּה תִֽהְיֶה֙ כְּאִ֣ישׁ נִדְהָ֔ם כְּגִבּ֖וֹר לֹא־יוּכַ֣ל לְהוֹשִׁ֑יעַ וְאַתָּ֧ה בְקִרְבֵּ֣נוּ יְהוָ֗ה וְשִׁמְךָ֛ עָלֵ֥ינוּ נִקְרָ֖א אַל־תַּנִּחֵֽנוּ׃"}},"definableWords":["man","LORD","name"],"peopleInVerse":[],"themesInVerse":["salvation"]},"10":{"text":"Thus saith the LORD unto this people, Thus have they loved to wander, they have not refrained their feet, therefore the LORD doth not accept them; he will now remember their iniquity, and visit their sins.","ref":"Jeremiah 14:10","synthesized":"This is what the LORD says about this people:  “Truly they love to wander; they have not restrained their feet. So the LORD does not accept them; He will now remember their guilt and call their sins to account.”","sources":{"KJV":{"text":"Thus saith the LORD unto this people, Thus have they loved to wander, they have not refrained their feet, therefore the LORD doth not accept them; he will now remember their iniquity, and visit their sins."},"BSB":{"text":"This is what the LORD says about this people:  “Truly they love to wander; they have not restrained their feet. So the LORD does not accept them; He will now remember their guilt and call their sins to account.”"},"TANAKH":{"text":"Thus saith HaShem unto this people: Even so have they loved to wander, they have not refrained their feet; therefore HaShem doth not accept them, now will He remember their iniquity, and punish their sins."},"HEBREW":{"text":"כֹּֽה־אָמַ֨ר יְהוָ֜ה לָעָ֣ם הַזֶּ֗ה כֵּ֤ן אָֽהֲבוּ֙ לָנ֔וּעַ רַגְלֵיהֶ֖ם לֹ֣א חָשָׂ֑כוּ וַיהוָה֙ לֹ֣א רָצָ֔ם עַתָּה֙ יִזְכֹּ֣ר עֲוֺנָ֔ם וְיִפְקֹ֖ד חַטֹּאתָֽם׃"}},"definableWords":["LORD","people","love","Lord","remember"],"peopleInVerse":[],"themesInVerse":["love"]},"11":{"text":"Then said the LORD unto me, Pray not for this people for their good.","ref":"Jeremiah 14:11","synthesized":"Then the LORD said to me, “Do not pray for the well-being of this people.","sources":{"KJV":{"text":"Then said the LORD unto me, Pray not for this people for their good."},"BSB":{"text":"Then the LORD said to me, “Do not pray for the well-being of this people."},"TANAKH":{"text":"And HaShem said unto me: 'Pray not for this people for their good."},"HEBREW":{"text":"וַיֹּ֥אמֶר יְהוָ֖ה אֵלָ֑י אַל־תִּתְפַּלֵּ֛ל בְּעַד־הָעָ֥ם הַזֶּ֖ה לְטוֹבָֽה׃"}},"definableWords":["LORD","people"],"peopleInVerse":[],"themesInVerse":["bread_water_life","prayer"]},"12":{"text":"When they fast, I will not hear their cry; and when they offer burnt offering and an oblation, I will not accept them: but I will consume them by the sword, and by the famine, and by the pestilence.","ref":"Jeremiah 14:12","synthesized":"Although they may fast, I will not listen to their cry; although they may offer burnt offerings and grain offerings, I will not accept them. Instead, I will finish them off by sword and famine and plague.”","sources":{"KJV":{"text":"When they fast, I will not hear their cry; and when they offer burnt offering and an oblation, I will not accept them: but I will consume them by the sword, and by the famine, and by the pestilence."},"BSB":{"text":"Although they may fast, I will not listen to their cry; although they may offer burnt offerings and grain offerings, I will not accept them. Instead, I will finish them off by sword and famine and plague.”"},"TANAKH":{"text":"When they fast, I will not hear their cry; and when they offer burnt-offering and meal-offering, I will not accept them; but I will consume them by the sword, and by the famine, and by the pestilence.'"},"HEBREW":{"text":"כִּ֣י יָצֻ֗מוּ אֵינֶ֤נִּי שֹׁמֵ֙עַ֙ אֶל־רִנָּתָ֔ם וְכִ֧י יַעֲל֛וּ עֹלָ֥ה וּמִנְחָ֖ה אֵינֶ֣נִּי רֹצָ֑ם כִּ֗י בַּחֶ֙רֶב֙ וּבָרָעָ֣ב וּבַדֶּ֔בֶר אָנֹכִ֖י מְכַלֶּ֥ה אוֹתָֽם׃"}},"definableWords":["fast"],"peopleInVerse":[]},"13":{"text":"Then said I, Ah, Lord GOD! behold, the prophets say unto them, Ye shall not see the sword, neither shall ye have famine; but I will give you assured peace in this place.","ref":"Jeremiah 14:13","synthesized":"“Ah, Lord GOD!” I replied, “Look, the prophets are telling them, ‘You will not see the sword or suffer famine, but I will give you lasting peace in this place.’”","sources":{"KJV":{"text":"Then said I, Ah, Lord GOD! behold, the prophets say unto them, Ye shall not see the sword, neither shall ye have famine; but I will give you assured peace in this place."},"BSB":{"text":"“Ah, Lord GOD!” I replied, “Look, the prophets are telling them, ‘You will not see the sword or suffer famine, but I will give you lasting peace in this place.’”"},"TANAKH":{"text":"Then said I: 'Ah, L-rd GOD! behold, the prophets say unto them: Ye shall not see the sword, neither shall ye have famine; but I will give you assured peace in this place.'"},"HEBREW":{"text":"וָאֹמַ֞ר אֲהָ֣הּ ׀ אֲדֹנָ֣י יְהוִ֗ה הִנֵּ֨ה הַנְּבִאִ֜ים אֹמְרִ֤ים לָהֶם֙ לֹֽא־תִרְא֣וּ חֶ֔רֶב וְרָעָ֖ב לֹֽא־יִהְיֶ֣ה לָכֶ֑ם כִּֽי־שְׁל֤וֹם אֱמֶת֙ אֶתֵּ֣ן לָכֶ֔ם בַּמָּק֖וֹם הַזֶּֽה׃"}},"definableWords":["Lord","God","see","or","peace"],"peopleInVerse":[],"themesInVerse":["peace","suffering"]},"14":{"text":"Then the LORD said unto me, The prophets prophesy lies in my name: I sent them not, neither have I commanded them, neither spake unto them: they prophesy unto you a false vision and divination, and a thing of nought, and the deceit of their heart.","ref":"Jeremiah 14:14","synthesized":"“The prophets are prophesying lies in My name,” replied the LORD. “I did not send them or appoint them or speak to them. They are prophesying to you a false vision, a worthless divination, the futility and delusion of their own minds.","sources":{"KJV":{"text":"Then the LORD said unto me, The prophets prophesy lies in my name: I sent them not, neither have I commanded them, neither spake unto them: they prophesy unto you a false vision and divination, and a thing of nought, and the deceit of their heart."},"BSB":{"text":"“The prophets are prophesying lies in My name,” replied the LORD. “I did not send them or appoint them or speak to them. They are prophesying to you a false vision, a worthless divination, the futility and delusion of their own minds."},"TANAKH":{"text":"Then HaShem said unto me: 'The prophets prophesy lies in My name; I sent them not, neither have I commanded them, neither spoke I unto them; they prophesy unto you a lying vision, and divination, and a thing of nought, and the deceit of their own heart."},"HEBREW":{"text":"וַיֹּ֨אמֶר יְהוָ֜ה אֵלַ֗י שֶׁ֚קֶר הַנְּבִאִים֙ נִבְּאִ֣ים בִּשְׁמִ֔י לֹ֤א שְׁלַחְתִּים֙ וְלֹ֣א צִוִּיתִ֔ים וְלֹ֥א דִבַּ֖רְתִּי אֲלֵיהֶ֑ם חֲז֨וֹן שֶׁ֜קֶר וְקֶ֤סֶם ואלול וֶֽאֱלִיל֙ ותרמות וְתַרְמִ֣ית לִבָּ֔ם הֵ֖מָּה מִֽתְנַבְּאִ֥ים לָכֶֽם׃"}},"definableWords":["name","LORD","or"],"peopleInVerse":[]},"15":{"text":"Therefore thus saith the LORD concerning the prophets that prophesy in my name, and I sent them not, yet they say, Sword and famine shall not be in this land; By sword and famine shall those prophets be consumed.","ref":"Jeremiah 14:15","synthesized":"Therefore this is what the LORD says about the prophets who prophesy in My name: I did not send them, yet they say, ‘No sword or famine will touch this land.’  By sword and famine these very prophets will meet their end!","sources":{"KJV":{"text":"Therefore thus saith the LORD concerning the prophets that prophesy in my name, and I sent them not, yet they say, Sword and famine shall not be in this land; By sword and famine shall those prophets be consumed."},"BSB":{"text":"Therefore this is what the LORD says about the prophets who prophesy in My name: I did not send them, yet they say, ‘No sword or famine will touch this land.’  By sword and famine these very prophets will meet their end!"},"TANAKH":{"text":"Therefore thus saith HaShem: As for the prophets that prophesy in My name, and I sent them not, yet they say: Sword and famine shall not be in this land, by sword and famine shall those prophets be consumed;"},"HEBREW":{"text":"לָכֵ֞ן כֹּֽה־אָמַ֣ר יְהוָ֗ה עַֽל־הַנְּבִאִ֞ים הַנִּבְּאִ֣ים בִּשְׁמִי֮ וַאֲנִ֣י לֹֽא־שְׁלַחְתִּים֒ וְהֵ֙מָּה֙ אֹֽמְרִ֔ים חֶ֣רֶב וְרָעָ֔ב לֹ֥א יִהְיֶ֖ה בָּאָ֣רֶץ הַזֹּ֑את בַּחֶ֤רֶב וּבָֽרָעָב֙ יִתַּ֔מּוּ הַנְּבִאִ֖ים הָהֵֽמָּה׃"}},"definableWords":["LORD","name","or","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"16":{"text":"And the people to whom they prophesy shall be cast out in the streets of Jerusalem because of the famine and the sword; and they shall have none to bury them, them, their wives, nor their sons, nor their daughters: for I will pour their wickedness upon them.","ref":"Jeremiah 14:16","synthesized":"And the people to whom they prophesy will be thrown into the streets of Jerusalem because of famine and sword. There will be no one to bury them or their wives, their sons or their daughters. I will pour out their own evil upon them.","sources":{"KJV":{"text":"And the people to whom they prophesy shall be cast out in the streets of Jerusalem because of the famine and the sword; and they shall have none to bury them, them, their wives, nor their sons, nor their daughters: for I will pour their wickedness upon them."},"BSB":{"text":"And the people to whom they prophesy will be thrown into the streets of Jerusalem because of famine and sword. There will be no one to bury them or their wives, their sons or their daughters. I will pour out their own evil upon them."},"TANAKH":{"text":"and the people to whom they prophesy shall be cast out in the streets of Jerusalem because of the famine and the sword; and they shall have none to bury them, them, their wives, nor their sons, nor their daughters; for I will pour their evil upon them.'"},"HEBREW":{"text":"וְהָעָ֣ם אֲשֶׁר־הֵ֣מָּה נִבְּאִ֣ים לָהֶ֡ם יִֽהְי֣וּ מֻשְׁלָכִים֩ בְּחֻצ֨וֹת יְרוּשָׁלִַ֜ם מִפְּנֵ֣י ׀ הָרָעָ֣ב וְהַחֶ֗רֶב וְאֵ֤ין מְקַבֵּר֙ לָהֵ֔מָּה הֵ֣מָּה נְשֵׁיהֶ֔ם וּבְנֵיהֶ֖ם וּבְנֹֽתֵיהֶ֑ם וְשָׁפַכְתִּ֥י עֲלֵיהֶ֖ם אֶת־רָעָתָֽם׃"}},"definableWords":["people","Jerusalem","one","or","sons","daughters","evil"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"17":{"text":"Therefore thou shalt say this word unto them; Let mine eyes run down with tears night and day, and let them not cease: for the virgin daughter of my people is broken with a great breach, with a very grievous blow.","ref":"Jeremiah 14:17","synthesized":"You are to speak this word to them:  ‘My eyes overflow with tears; day and night they do not cease, for the virgin daughter of my people has been shattered by a crushing blow, a severely grievous wound.","sources":{"KJV":{"text":"Therefore thou shalt say this word unto them; Let mine eyes run down with tears night and day, and let them not cease: for the virgin daughter of my people is broken with a great breach, with a very grievous blow."},"BSB":{"text":"You are to speak this word to them:  ‘My eyes overflow with tears; day and night they do not cease, for the virgin daughter of my people has been shattered by a crushing blow, a severely grievous wound."},"TANAKH":{"text":"And thou shalt say this word unto them: Let mine eyes run down with tears night and day, and let them not cease; for the virgin daughter of my people is broken with a great breach, with a very grievous blow."},"HEBREW":{"text":"וְאָמַרְתָּ֤ אֲלֵיהֶם֙ אֶת־הַדָּבָ֣ר הַזֶּ֔ה תֵּרַ֨דְנָה עֵינַ֥י דִּמְעָ֛ה לַ֥יְלָה וְיוֹמָ֖ם וְאַל־תִּדְמֶ֑ינָה כִּי֩ שֶׁ֨בֶר גָּד֜וֹל נִשְׁבְּרָ֗ה בְּתוּלַת֙ בַּת־עַמִּ֔י מַכָּ֖ה נַחְלָ֥ה מְאֹֽד׃"}},"definableWords":["word","day","night","daughter","people"],"peopleInVerse":[]},"18":{"text":"If I go forth into the field, then behold the slain with the sword! and if I enter into the city, then behold them that are sick with famine! yea, both the prophet and the priest go about into a land that they know not.","ref":"Jeremiah 14:18","synthesized":"If I go out to the country, I see those slain by the sword; if I enter the city, I see those ravaged by famine! For both prophet and priest travel to a land they do not know.’”","sources":{"KJV":{"text":"If I go forth into the field, then behold the slain with the sword! and if I enter into the city, then behold them that are sick with famine! yea, both the prophet and the priest go about into a land that they know not."},"BSB":{"text":"If I go out to the country, I see those slain by the sword; if I enter the city, I see those ravaged by famine! For both prophet and priest travel to a land they do not know.’”"},"TANAKH":{"text":"If I go forth into the field, then behold the slain with the sword! And if I enter into the city, then behold them that are sick with famine! For both the prophet and the priest are gone about to a land, and knew it not."},"HEBREW":{"text":"אִם־יָצָ֣אתִי הַשָּׂדֶ֗ה וְהִנֵּה֙ חַלְלֵי־חֶ֔רֶב וְאִם֙ בָּ֣אתִי הָעִ֔יר וְהִנֵּ֖ה תַּחֲלוּאֵ֣י רָעָ֑ב כִּֽי־גַם־נָבִ֧יא גַם־כֹּהֵ֛ן סָחֲר֥וּ אֶל־אֶ֖רֶץ וְלֹ֥א יָדָֽעוּ׃"}},"definableWords":["see","prophet","priest","land"],"peopleInVerse":[],"themesInVerse":["kingdom_priesthood","land_promise"]},"19":{"text":"Hast thou utterly rejected Judah? hath thy soul lothed Zion? why hast thou smitten us, and there is no healing for us? we looked for peace, and there is no good; and for the time of healing, and behold trouble!","ref":"Jeremiah 14:19","synthesized":"Have You rejected Judah completely? Do You despise Zion? Why have You stricken us so that we are beyond healing? We hoped for peace, but no good has come, and for the time of healing, but there was only terror.","sources":{"KJV":{"text":"Hast thou utterly rejected Judah? hath thy soul lothed Zion? why hast thou smitten us, and there is no healing for us? we looked for peace, and there is no good; and for the time of healing, and behold trouble!"},"BSB":{"text":"Have You rejected Judah completely? Do You despise Zion? Why have You stricken us so that we are beyond healing? We hoped for peace, but no good has come, and for the time of healing, but there was only terror."},"TANAKH":{"text":"Hast Thou utterly rejected Judah? Hath Thy soul loathed Zion? Why hast Thou smitten us, and there is no healing for us? We looked for peace, but no good came; and for a time of healing, and behold terror!"},"HEBREW":{"text":"הֲמָאֹ֨ס מָאַ֜סְתָּ אֶת־יְהוּדָ֗ה אִם־בְּצִיּוֹן֙ גָּעֲלָ֣ה נַפְשֶׁ֔ךָ מַדּ֙וּעַ֙ הִכִּיתָ֔נוּ וְאֵ֥ין לָ֖נוּ מַרְפֵּ֑א קַוֵּ֤ה לְשָׁלוֹם֙ וְאֵ֣ין ט֔וֹב וּלְעֵ֥ת מַרְפֵּ֖א וְהִנֵּ֥ה בְעָתָֽה׃"}},"definableWords":["Judah","Zion","peace","good"],"peopleInVerse":[],"placesInVerse":["Mount Zion"],"themesInVerse":["peace"]},"20":{"text":"We acknowledge, O LORD, our wickedness, and the iniquity of our fathers: for we have sinned against thee.","ref":"Jeremiah 14:20","synthesized":"We acknowledge our wickedness, O LORD, the guilt of our fathers; indeed, we have sinned against You.","sources":{"KJV":{"text":"We acknowledge, O LORD, our wickedness, and the iniquity of our fathers: for we have sinned against thee."},"BSB":{"text":"We acknowledge our wickedness, O LORD, the guilt of our fathers; indeed, we have sinned against You."},"TANAKH":{"text":"We acknowledge, O HaShem, our wickedness, even the iniquity of our fathers; for we have sinned against Thee."},"HEBREW":{"text":"יָדַ֧עְנוּ יְהוָ֛ה רִשְׁעֵ֖נוּ עֲוֺ֣ן אֲבוֹתֵ֑ינוּ כִּ֥י חָטָ֖אנוּ לָֽךְ׃"}},"definableWords":["LORD","fathers"],"peopleInVerse":[]},"21":{"text":"Do not abhor us, for thy name’s sake, do not disgrace the throne of thy glory: remember, break not thy covenant with us.","ref":"Jeremiah 14:21","synthesized":"For the sake of Your name do not despise us; do not disgrace Your glorious throne. Remember Your covenant with us; do not break it.","sources":{"KJV":{"text":"Do not abhor us, for thy name’s sake, do not disgrace the throne of thy glory: remember, break not thy covenant with us."},"BSB":{"text":"For the sake of Your name do not despise us; do not disgrace Your glorious throne. Remember Your covenant with us; do not break it."},"TANAKH":{"text":"Do not contemn us, for Thy name's sake, do not dishonour the throne of Thy glory; remember, break not Thy covenant with us."},"HEBREW":{"text":"אַל־תִּנְאַץ֙ לְמַ֣עַן שִׁמְךָ֔ אַל־תְּנַבֵּ֖ל כִּסֵּ֣א כְבוֹדֶ֑ךָ זְכֹ֕ר אַל־תָּפֵ֥ר בְּרִֽיתְךָ֖ אִתָּֽנוּ׃"}},"definableWords":["name","throne","remember","covenant"],"peopleInVerse":[],"themesInVerse":["covenant","kingdom_of_god","kingship"]},"22":{"text":"Are there any among the vanities of the Gentiles that can cause rain? or can the heavens give showers? art not thou he, O LORD our God? therefore we will wait upon thee: for thou hast made all these things.","ref":"Jeremiah 14:22","synthesized":"Can the worthless idols of the nations bring rain? Do the skies alone send showers? Is this not by You, O LORD our God? So we put our hope in You, for You have done all these things.","sources":{"KJV":{"text":"Are there any among the vanities of the Gentiles that can cause rain? or can the heavens give showers? art not thou he, O LORD our God? therefore we will wait upon thee: for thou hast made all these things."},"BSB":{"text":"Can the worthless idols of the nations bring rain? Do the skies alone send showers? Is this not by You, O LORD our God? So we put our hope in You, for You have done all these things."},"TANAKH":{"text":"Are there any among the vanities of the nations that can cause rain? or can the heavens give showers? Art not Thou He, O HaShem our G-d, and do we not wait for Thee? For Thou hast made all these things."},"HEBREW":{"text":"הֲיֵ֨שׁ בְּהַבְלֵ֤י הַגּוֹיִם֙ מַגְשִׁמִ֔ים וְאִם־הַשָּׁמַ֖יִם יִתְּנ֣וּ רְבִבִ֑ים הֲלֹ֨א אַתָּה־ה֜וּא יְהוָ֤ה אֱלֹהֵ֙ינוּ֙ וּ֨נְקַוֶּה־לָּ֔ךְ כִּֽי־אַתָּ֥ה עָשִׂ֖יתָ אֶת־כָּל־אֵֽלֶּה׃"}},"definableWords":["nations","LORD","God","hope"],"peopleInVerse":[],"themesInVerse":["hope"]}}},"15":{"chapter":"15","title":"WHITHER SHALL WE GO?","verses":{"1":{"text":"Then said the LORD unto me, Though Moses and Samuel stood before me, yet my mind could not be toward this people: cast them out of my sight, and let them go forth.","ref":"Jeremiah 15:1","synthesized":"Then the LORD said to me: “Even if Moses and Samuel should stand before Me, My heart would not go out to this people. Send them from My presence, and let them go.","sources":{"KJV":{"text":"Then said the LORD unto me, Though Moses and Samuel stood before me, yet my mind could not be toward this people: cast them out of my sight, and let them go forth."},"BSB":{"text":"Then the LORD said to me: “Even if Moses and Samuel should stand before Me, My heart would not go out to this people. Send them from My presence, and let them go."},"TANAKH":{"text":"Then said HaShem unto me: 'Though Moses and Samuel stood before Me, yet My mind could not be toward this people; cast them out of My sight, and let them go forth."},"HEBREW":{"text":"וַיֹּ֤אמֶר יְהוָה֙ אֵלַ֔י אִם־יַעֲמֹ֨ד מֹשֶׁ֤ה וּשְׁמוּאֵל֙ לְפָנַ֔י אֵ֥ין נַפְשִׁ֖י אֶל־הָעָ֣ם הַזֶּ֑ה שַׁלַּ֥ח מֵֽעַל־פָּנַ֖י וְיֵצֵֽאוּ׃"}},"definableWords":["LORD","stand","heart","people"],"peopleInVerse":["Moses","Samuel"]},"2":{"text":"And it shall come to pass, if they say unto thee, Whither shall we go forth? then thou shalt tell them, Thus saith the LORD; Such as are for death, to death; and such as are for the sword, to the sword; and such as are for the famine, to the famine; and such as are for the captivity, to the captivity.","ref":"Jeremiah 15:2","synthesized":"If they ask you, ‘Where shall we go?’ you are to tell them that this is what the LORD says:  ‘Those destined for death, to death; those destined for the sword, to the sword; those destined for famine, to famine; and those destined for captivity, to captivity.’","sources":{"KJV":{"text":"And it shall come to pass, if they say unto thee, Whither shall we go forth? then thou shalt tell them, Thus saith the LORD; Such as are for death, to death; and such as are for the sword, to the sword; and such as are for the famine, to the famine; and such as are for the captivity, to the captivity."},"BSB":{"text":"If they ask you, ‘Where shall we go?’ you are to tell them that this is what the LORD says:  ‘Those destined for death, to death; those destined for the sword, to the sword; those destined for famine, to famine; and those destined for captivity, to captivity.’"},"TANAKH":{"text":"And it shall come to pass, when they say unto thee: Whither shall we go forth? then thou shall tell them: Thus saith HaShem: Such as are for death, to death; and such as are for the sword, to the sword; and such as are for the famine, to the famine; and such as are for captivity, to captivity."},"HEBREW":{"text":"וְהָיָ֛ה כִּֽי־יֹאמְר֥וּ אֵלֶ֖יךָ אָ֣נָה נֵצֵ֑א וְאָמַרְתָּ֨ אֲלֵיהֶ֜ם כֹּֽה־אָמַ֣ר יְהוָ֗ה אֲשֶׁ֨ר לַמָּ֤וֶת לַמָּ֙וֶת֙ וַאֲשֶׁ֤ר לַחֶ֙רֶב֙ לַחֶ֔רֶב וַאֲשֶׁ֤ר לָֽרָעָב֙ לָֽרָעָ֔ב וַאֲשֶׁ֥ר לַשְּׁבִ֖י לַשֶּֽׁבִי׃"}},"definableWords":["LORD","death"],"peopleInVerse":[],"themesInVerse":["exile_return"]},"3":{"text":"And I will appoint over them four kinds, saith the LORD: the sword to slay, and the dogs to tear, and the fowls of the heaven, and the beasts of the earth, to devour and destroy.","ref":"Jeremiah 15:3","synthesized":"I will appoint over them four kinds of destroyers, declares the LORD: the sword to kill, the dogs to drag away, and the birds of the air and beasts of the earth to devour and destroy.","sources":{"KJV":{"text":"And I will appoint over them four kinds, saith the LORD: the sword to slay, and the dogs to tear, and the fowls of the heaven, and the beasts of the earth, to devour and destroy."},"BSB":{"text":"I will appoint over them four kinds of destroyers, declares the LORD: the sword to kill, the dogs to drag away, and the birds of the air and beasts of the earth to devour and destroy."},"TANAKH":{"text":"And I will appoint over them four kinds, saith HaShem: the sword to slay, and the dogs to drag, and the fowls of the heaven, and the beasts of the earth, to devour and to destroy."},"HEBREW":{"text":"וּפָקַדְתִּ֨י עֲלֵיהֶ֜ם אַרְבַּ֤ע מִשְׁפָּחוֹת֙ נְאֻם־יְהוָ֔ה אֶת־הַחֶ֣רֶב לַֽהֲרֹ֔ג וְאֶת־הַכְּלָבִ֖ים לִסְחֹ֑ב וְאֶת־ע֧וֹף הַשָּׁמַ֛יִם וְאֶת־בֶּהֱמַ֥ת הָאָ֖רֶץ לֶאֱכֹ֥ל וּלְהַשְׁחִֽית׃"}},"definableWords":["LORD","birds","earth"],"peopleInVerse":[]},"4":{"text":"And I will cause them to be removed into all kingdoms of the earth, because of Manasseh the son of Hezekiah king of Judah, for that which he did in Jerusalem.","ref":"Jeremiah 15:4","synthesized":"I will make them a horror to all the kingdoms of the earth because of what Manasseh son of Hezekiah king of Judah did in Jerusalem.","sources":{"KJV":{"text":"And I will cause them to be removed into all kingdoms of the earth, because of Manasseh the son of Hezekiah king of Judah, for that which he did in Jerusalem."},"BSB":{"text":"I will make them a horror to all the kingdoms of the earth because of what Manasseh son of Hezekiah king of Judah did in Jerusalem."},"TANAKH":{"text":"And I will cause them to be a horror among all the kingdoms of the earth, because of Manasseh the son of Hezekiah king of Judah, for that which he did in Jerusalem."},"HEBREW":{"text":"וּנְתַתִּ֣ים לזועה לְזַֽעֲוָ֔ה לְכֹ֖ל מַמְלְכ֣וֹת הָאָ֑רֶץ בִּ֠גְלַל מְנַשֶּׁ֤ה בֶן־יְחִזְקִיָּ֙הוּ֙ מֶ֣לֶךְ יְהוּדָ֔ה עַ֥ל אֲשֶׁר־עָשָׂ֖ה בִּירוּשָׁלָֽ͏ִם׃"}},"definableWords":["make","earth","son","king","Judah","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["kingship"]},"5":{"text":"For who shall have pity upon thee, O Jerusalem? or who shall bemoan thee? or who shall go aside to ask how thou doest?","ref":"Jeremiah 15:5","synthesized":"Who will have pity on you, O Jerusalem? Who will mourn for you? Who will turn aside to ask about your welfare?","sources":{"KJV":{"text":"For who shall have pity upon thee, O Jerusalem? or who shall bemoan thee? or who shall go aside to ask how thou doest?"},"BSB":{"text":"Who will have pity on you, O Jerusalem? Who will mourn for you? Who will turn aside to ask about your welfare?"},"TANAKH":{"text":"For who shall have pity upon thee, O Jerusalem? Or who shall bemoan thee? Or who shall turn aside to ask of thy welfare?"},"HEBREW":{"text":"כִּ֠י מִֽי־יַחְמֹ֤ל עָלַ֙יִךְ֙ יְר֣וּשָׁלִַ֔ם וּמִ֖י יָנ֣וּד לָ֑ךְ וּמִ֣י יָס֔וּר לִשְׁאֹ֥ל לְשָׁלֹ֖ם לָֽךְ׃"}},"definableWords":["Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"6":{"text":"Thou hast forsaken me, saith the LORD, thou art gone backward: therefore will I stretch out my hand against thee, and destroy thee; I am weary with repenting.","ref":"Jeremiah 15:6","synthesized":"You have forsaken Me, declares the LORD. You have turned your back. So I will stretch out My hand against you and I will destroy you; I am weary of showing compassion.","sources":{"KJV":{"text":"Thou hast forsaken me, saith the LORD, thou art gone backward: therefore will I stretch out my hand against thee, and destroy thee; I am weary with repenting."},"BSB":{"text":"You have forsaken Me, declares the LORD. You have turned your back. So I will stretch out My hand against you and I will destroy you; I am weary of showing compassion."},"TANAKH":{"text":"Thou hast cast Me off, saith HaShem, thou art gone backward; therefore do I stretch out My hand against thee, and destroy thee; I am weary with repenting."},"HEBREW":{"text":"אַ֣תְּ נָטַ֥שְׁתְּ אֹתִ֛י נְאֻם־יְהוָ֖ה אָח֣וֹר תֵּלֵ֑כִי וָאַ֨ט אֶת־יָדִ֤י עָלַ֙יִךְ֙ וָֽאַשְׁחִיתֵ֔ךְ נִלְאֵ֖יתִי הִנָּחֵֽם׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"7":{"text":"And I will fan them with a fan in the gates of the land; I will bereave them of children, I will destroy my people, since they return not from their ways.","ref":"Jeremiah 15:7","synthesized":"I will scatter them with a winnowing fork at the gates of the land. I will bereave and destroy My people who have not turned from their ways.","sources":{"KJV":{"text":"And I will fan them with a fan in the gates of the land; I will bereave them of children, I will destroy my people, since they return not from their ways."},"BSB":{"text":"I will scatter them with a winnowing fork at the gates of the land. I will bereave and destroy My people who have not turned from their ways."},"TANAKH":{"text":"And I fan them with a fan in the gates of the land; I bereave them of children, I destroy My people, since they return not from their ways."},"HEBREW":{"text":"וָאֶזְרֵ֥ם בְּמִזְרֶ֖ה בְּשַׁעֲרֵ֣י הָאָ֑רֶץ שִׁכַּ֤לְתִּי אִבַּ֙דְתִּי֙ אֶת־עַמִּ֔י מִדַּרְכֵיהֶ֖ם לוֹא־שָֽׁבוּ׃"}},"definableWords":["land","people"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"8":{"text":"Their widows are increased to me above the sand of the seas: I have brought upon them against the mother of the young men a spoiler at noonday: I have caused him to fall upon it suddenly, and terrors upon the city.","ref":"Jeremiah 15:8","synthesized":"I will make their widows more numerous than the sand of the sea. I will bring a destroyer at noon against the mothers of young men. I will suddenly bring upon them anguish and dismay.","sources":{"KJV":{"text":"Their widows are increased to me above the sand of the seas: I have brought upon them against the mother of the young men a spoiler at noonday: I have caused him to fall upon it suddenly, and terrors upon the city."},"BSB":{"text":"I will make their widows more numerous than the sand of the sea. I will bring a destroyer at noon against the mothers of young men. I will suddenly bring upon them anguish and dismay."},"TANAKH":{"text":"Their widows are increased to Me above the sand of the seas; I bring upon them, against the mother, a chosen one, even a spoiler at noonday; I cause anguish and terrors to fall upon her suddenly."},"HEBREW":{"text":"עָֽצְמוּ־לִ֤י אַלְמְנֹתָו֙ מֵח֣וֹל יַמִּ֔ים הֵבֵ֨אתִי לָהֶ֥ם עַל־אֵ֛ם בָּח֖וּר שֹׁדֵ֣ד בַּֽצָּהֳרָ֑יִם הִפַּ֤לְתִּי עָלֶ֙יהָ֙ פִּתְאֹ֔ם עִ֖יר וּבֶהָלֽוֹת׃"}},"definableWords":["make","sea","men"],"peopleInVerse":[]},"9":{"text":"She that hath borne seven languisheth: she hath given up the ghost; her sun is gone down while it was yet day: she hath been ashamed and confounded: and the residue of them will I deliver to the sword before their enemies, saith the LORD.","ref":"Jeremiah 15:9","synthesized":"The mother of seven will grow faint; she will breathe her last breath. Her sun will set while it is still day; she will be disgraced and humiliated. And the rest I will put to the sword in the presence of their enemies,” declares the LORD.","sources":{"KJV":{"text":"She that hath borne seven languisheth: she hath given up the ghost; her sun is gone down while it was yet day: she hath been ashamed and confounded: and the residue of them will I deliver to the sword before their enemies, saith the LORD."},"BSB":{"text":"The mother of seven will grow faint; she will breathe her last breath. Her sun will set while it is still day; she will be disgraced and humiliated. And the rest I will put to the sword in the presence of their enemies,” declares the LORD."},"TANAKH":{"text":"She that hath borne seven languisheth; her spirit droopeth; her sun is gone down while it was yet day, she is ashamed and confounded; and the residue of them will I deliver to the sword before their enemies, saith HaShem.'"},"HEBREW":{"text":"אֻמְלְלָ֞ה יֹלֶ֣דֶת הַשִּׁבְעָ֗ה נָפְחָ֥ה נַפְשָׁ֛הּ באה בָּ֥א שִׁמְשָׁ֛הּ בְּעֹ֥ד יוֹמָ֖ם בּ֣וֹשָׁה וְחָפֵ֑רָה וּשְׁאֵֽרִיתָ֗ם לַחֶ֧רֶב אֶתֵּ֛ן לִפְנֵ֥י אֹיְבֵיהֶ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["mother","breath","day","rest","LORD"],"peopleInVerse":[],"themesInVerse":["peace","sabbath_rest"]},"10":{"text":"Woe is me, my mother, that thou hast borne me a man of strife and a man of contention to the whole earth! I have neither lent on usury, nor men have lent to me on usury; yet every one of them doth curse me.","ref":"Jeremiah 15:10","synthesized":"Woe to me, my mother, that you have borne me, a man of strife and conflict in all the land. I have neither lent nor borrowed, yet everyone curses me.","sources":{"KJV":{"text":"Woe is me, my mother, that thou hast borne me a man of strife and a man of contention to the whole earth! I have neither lent on usury, nor men have lent to me on usury; yet every one of them doth curse me."},"BSB":{"text":"Woe to me, my mother, that you have borne me, a man of strife and conflict in all the land. I have neither lent nor borrowed, yet everyone curses me."},"TANAKH":{"text":"Woe is me, my mother, that thou hast borne me a man of strife and a man of contention to the whole earth! I have not lent, neither have men lent to me; yet every one of them doth curse me."},"HEBREW":{"text":"אֽוֹי־לִ֣י אִמִּ֔י כִּ֣י יְלִדְתִּ֗נִי אִ֥ישׁ רִ֛יב וְאִ֥ישׁ מָד֖וֹן לְכָל־הָאָ֑רֶץ לֹֽא־נָשִׁ֥יתִי וְלֹא־נָֽשׁוּ־בִ֖י כֻּלֹּ֥ה מְקַלְלַֽונִי׃"}},"definableWords":["mother","man","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"11":{"text":"The LORD said, Verily it shall be well with thy remnant; verily I will cause the enemy to entreat thee well in the time of evil and in the time of affliction.","ref":"Jeremiah 15:11","synthesized":"The LORD said:  “Surely I will deliver you for a good purpose; surely I will intercede with your enemy in your time of trouble, in your time of distress.","sources":{"KJV":{"text":"The LORD said, Verily it shall be well with thy remnant; verily I will cause the enemy to entreat thee well in the time of evil and in the time of affliction."},"BSB":{"text":"The LORD said:  “Surely I will deliver you for a good purpose; surely I will intercede with your enemy in your time of trouble, in your time of distress."},"TANAKH":{"text":"HaShem said: 'Verily I will release thee for good; verily I will cause the enemy to make supplication unto thee in the time of evil and in the time of affliction."},"HEBREW":{"text":"אָמַ֣ר יְהוָ֔ה אִם־לֹ֥א שרותך שֵֽׁרִיתִ֖יךָ לְט֑וֹב אִם־ל֣וֹא ׀ הִפְגַּ֣עְתִּֽי בְךָ֗ בְּעֵ֥ת־רָעָ֛ה וּבְעֵ֥ת צָרָ֖ה אֶת־הָאֹיֵֽב׃"}},"definableWords":["LORD","deliver","good"],"peopleInVerse":[],"themesInVerse":["prayer","redemption","salvation"]},"12":{"text":"Shall iron break the northern iron and the steel?","ref":"Jeremiah 15:12","synthesized":"Can anyone smash iron— iron from the north—or bronze?","sources":{"KJV":{"text":"Shall iron break the northern iron and the steel?"},"BSB":{"text":"Can anyone smash iron— iron from the north—or bronze?"},"TANAKH":{"text":"Can iron break iron from the north and brass?"},"HEBREW":{"text":"הֲיָרֹ֨עַ בַּרְזֶ֧ל ׀ בַּרְזֶ֛ל מִצָּפ֖וֹן וּנְחֹֽשֶׁת׃"}},"definableWords":["or"],"peopleInVerse":[]},"13":{"text":"Thy substance and thy treasures will I give to the spoil without price, and that for all thy sins, even in all thy borders.","ref":"Jeremiah 15:13","synthesized":"Your wealth and your treasures I will give up as plunder, without charge for all your sins within all your borders.","sources":{"KJV":{"text":"Thy substance and thy treasures will I give to the spoil without price, and that for all thy sins, even in all thy borders."},"BSB":{"text":"Your wealth and your treasures I will give up as plunder, without charge for all your sins within all your borders."},"TANAKH":{"text":"Thy substance and thy treasures will I give for a spoil without price, and that for all thy sins, even in all thy borders."},"HEBREW":{"text":"חֵילְךָ֧ וְאוֹצְרוֹתֶ֛יךָ לָבַ֥ז אֶתֵּ֖ן לֹ֣א בִמְחִ֑יר וּבְכָל־חַטֹּאותֶ֖יךָ וּבְכָל־גְּבוּלֶֽיךָ׃"}},"definableWords":["charge"],"peopleInVerse":[]},"14":{"text":"And I will make thee to pass with thine enemies into a land which thou knowest not: for a fire is kindled in mine anger, which shall burn upon you.","ref":"Jeremiah 15:14","synthesized":"Then I will enslave you to your enemies in a land you do not know, for My anger will kindle a fire that will burn against you.”","sources":{"KJV":{"text":"And I will make thee to pass with thine enemies into a land which thou knowest not: for a fire is kindled in mine anger, which shall burn upon you."},"BSB":{"text":"Then I will enslave you to your enemies in a land you do not know, for My anger will kindle a fire that will burn against you.”"},"TANAKH":{"text":"And I will make thee to pass with thine enemies into a land which thou knowest not; for a fire is kindled in My nostril, which shall burn upon you.'"},"HEBREW":{"text":"וְהַֽעֲבַרְתִּי֙ אֶת־אֹ֣יְבֶ֔יךָ בְּאֶ֖רֶץ לֹ֣א יָדָ֑עְתָּ כִּֽי־אֵ֛שׁ קָדְחָ֥ה בְאַפִּ֖י עֲלֵיכֶ֥ם תּוּקָֽד׃"}},"definableWords":["land","anger"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"15":{"text":"O LORD, thou knowest: remember me, and visit me, and revenge me of my persecutors; take me not away in thy longsuffering: know that for thy sake I have suffered rebuke.","ref":"Jeremiah 15:15","synthesized":"You understand, O LORD; remember me and attend to me. Avenge me against my persecutors. In Your patience, do not take me away. Know that I endure reproach for Your honor.","sources":{"KJV":{"text":"O LORD, thou knowest: remember me, and visit me, and revenge me of my persecutors; take me not away in thy longsuffering: know that for thy sake I have suffered rebuke."},"BSB":{"text":"You understand, O LORD; remember me and attend to me. Avenge me against my persecutors. In Your patience, do not take me away. Know that I endure reproach for Your honor."},"TANAKH":{"text":"Thou, O HaShem, knowest; remember me, and think of me, and avenge me of my persecutors; take me not away because of Thy long-suffering; know that for Thy sake I have suffered taunts."},"HEBREW":{"text":"אַתָּ֧ה יָדַ֣עְתָּ יְהוָ֗ה זָכְרֵ֤נִי וּפָקְדֵ֙נִי֙ וְהִנָּ֤קֶם לִי֙ מֵרֹ֣דְפַ֔י אַל־לְאֶ֥רֶךְ אַפְּךָ֖ תִּקָּחֵ֑נִי דַּ֕ע שְׂאֵתִ֥י עָלֶ֖יךָ חֶרְפָּֽה׃"}},"definableWords":["LORD","remember","patience"],"peopleInVerse":[],"themesInVerse":["worship"]},"16":{"text":"Thy words were found, and I did eat them; and thy word was unto me the joy and rejoicing of mine heart: for I am called by thy name, O LORD God of hosts.","ref":"Jeremiah 15:16","synthesized":"Your words were found, and I ate them. Your words became my joy and my heart’s delight. For I bear Your name, O LORD God of Hosts.","sources":{"KJV":{"text":"Thy words were found, and I did eat them; and thy word was unto me the joy and rejoicing of mine heart: for I am called by thy name, O LORD God of hosts."},"BSB":{"text":"Your words were found, and I ate them. Your words became my joy and my heart’s delight. For I bear Your name, O LORD God of Hosts."},"TANAKH":{"text":"Thy words were found, and I did eat them; and Thy words were unto me a joy and the rejoicing of my heart; because Thy name was called on me, O HaShem G-d of hosts."},"HEBREW":{"text":"נִמְצְא֤וּ דְבָרֶ֙יךָ֙ וָאֹ֣כְלֵ֔ם וַיְהִ֤י דבריך דְבָֽרְךָ֙ לִ֔י לְשָׂשׂ֖וֹן וּלְשִׂמְחַ֣ת לְבָבִ֑י כִּֽי־נִקְרָ֤א שִׁמְךָ֙ עָלַ֔י יְהוָ֖ה אֱלֹהֵ֥י צְבָאֽוֹת׃"}},"definableWords":["joy","heart","name","LORD","God"],"peopleInVerse":[],"themesInVerse":["joy"]},"17":{"text":"I sat not in the assembly of the mockers, nor rejoiced; I sat alone because of thy hand: for thou hast filled me with indignation.","ref":"Jeremiah 15:17","synthesized":"I never sat with the band of revelers, nor did I celebrate with them. Because Your hand was on me, I sat alone, for You have filled me with indignation.","sources":{"KJV":{"text":"I sat not in the assembly of the mockers, nor rejoiced; I sat alone because of thy hand: for thou hast filled me with indignation."},"BSB":{"text":"I never sat with the band of revelers, nor did I celebrate with them. Because Your hand was on me, I sat alone, for You have filled me with indignation."},"TANAKH":{"text":"I sat not in the assembly of them that make merry, nor rejoiced; I sat alone because of Thy hand; for Thou hast filled me with indignation."},"HEBREW":{"text":"לֹֽא־יָשַׁ֥בְתִּי בְסוֹד־מְשַׂחֲקִ֖ים וָֽאֶעְלֹ֑ז מִפְּנֵ֤י יָֽדְךָ֙ בָּדָ֣ד יָשַׁ֔בְתִּי כִּֽי־זַ֖עַם מִלֵּאתָֽנִי׃"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"Why is my pain perpetual, and my wound incurable, which refuseth to be healed? wilt thou be altogether unto me as a liar, and as waters that fail?","ref":"Jeremiah 15:18","synthesized":"Why is my pain unending, and my wound incurable, refusing to be healed? You have indeed become like a mirage to me— water that is not there.","sources":{"KJV":{"text":"Why is my pain perpetual, and my wound incurable, which refuseth to be healed? wilt thou be altogether unto me as a liar, and as waters that fail?"},"BSB":{"text":"Why is my pain unending, and my wound incurable, refusing to be healed? You have indeed become like a mirage to me— water that is not there."},"TANAKH":{"text":"Why is my pain perpetual, and my wound incurable, so that it refuseth to be healed? Wilt Thou indeed be unto me as a deceitful brook, as waters that fail?"},"HEBREW":{"text":"לָ֣מָּה הָיָ֤ה כְאֵבִי֙ נֶ֔צַח וּמַכָּתִ֖י אֲנוּשָׁ֑ה מֵֽאֲנָה֙ הֵֽרָפֵ֔א הָי֨וֹ תִֽהְיֶ֥ה לִי֙ כְּמ֣וֹ אַכְזָ֔ב מַ֖יִם לֹ֥א נֶאֱמָֽנוּ׃"}},"definableWords":["water"],"peopleInVerse":[],"themesInVerse":["bread_water_life","suffering"]},"19":{"text":"Therefore thus saith the LORD, If thou return, then will I bring thee again, and thou shalt stand before me: and if thou take forth the precious from the vile, thou shalt be as my mouth: let them return unto thee; but return not thou unto them.","ref":"Jeremiah 15:19","synthesized":"Therefore this is what the LORD says:  “If you return, I will restore you; you will stand in My presence. And if you speak words that are noble instead of worthless, you will be My spokesman. It is they who must turn to you, but you must not turn to them.","sources":{"KJV":{"text":"Therefore thus saith the LORD, If thou return, then will I bring thee again, and thou shalt stand before me: and if thou take forth the precious from the vile, thou shalt be as my mouth: let them return unto thee; but return not thou unto them."},"BSB":{"text":"Therefore this is what the LORD says:  “If you return, I will restore you; you will stand in My presence. And if you speak words that are noble instead of worthless, you will be My spokesman. It is they who must turn to you, but you must not turn to them."},"TANAKH":{"text":"Therefore thus saith HaShem: if thou return, and I bring thee back, thou shalt stand before Me; and if thou bring forth the precious out of the vile, thou shalt be as My mouth; let them return unto thee, but thou shalt not return unto them."},"HEBREW":{"text":"לָכֵ֞ן כֹּֽה־אָמַ֣ר יְהוָ֗ה אִם־תָּשׁ֤וּב וַאֲשִֽׁיבְךָ֙ לְפָנַ֣י תַּֽעֲמֹ֔ד וְאִם־תּוֹצִ֥יא יָקָ֛ר מִזּוֹלֵ֖ל כְּפִ֣י תִֽהְיֶ֑ה יָשֻׁ֤בוּ הֵ֙מָּה֙ אֵלֶ֔יךָ וְאַתָּ֖ה לֹֽא־תָשׁ֥וּב אֲלֵיהֶֽם׃"}},"definableWords":["LORD","stand"],"peopleInVerse":[],"themesInVerse":["exile_return","second_coming"]},"20":{"text":"And I will make thee unto this people a fenced brasen wall: and they shall fight against thee, but they shall not prevail against thee: for I am with thee to save thee and to deliver thee, saith the LORD.","ref":"Jeremiah 15:20","synthesized":"Then I will make you a wall to this people, a fortified wall of bronze; they will fight against you but will not overcome you, for I am with you to save and deliver you, declares the LORD.","sources":{"KJV":{"text":"And I will make thee unto this people a fenced brasen wall: and they shall fight against thee, but they shall not prevail against thee: for I am with thee to save thee and to deliver thee, saith the LORD."},"BSB":{"text":"Then I will make you a wall to this people, a fortified wall of bronze; they will fight against you but will not overcome you, for I am with you to save and deliver you, declares the LORD."},"TANAKH":{"text":"And I will make thee unto this people a fortified brazen wall; and they shall fight against thee, but they shall not prevail against thee; for I am with thee to save thee and to deliver thee, saith HaShem."},"HEBREW":{"text":"וּנְתַתִּ֜יךָ לָעָ֣ם הַזֶּ֗ה לְחוֹמַ֤ת נְחֹ֙שֶׁת֙ בְּצוּרָ֔ה וְנִלְחֲמ֥וּ אֵלֶ֖יךָ וְלֹא־י֣וּכְלוּ לָ֑ךְ כִּֽי־אִתְּךָ֥ אֲנִ֛י לְהוֹשִֽׁיעֲךָ֥ וּלְהַצִּילֶ֖ךָ נְאֻם־יְהוָֽה׃"}},"definableWords":["make","people","fight","overcome","deliver","LORD"],"peopleInVerse":[],"themesInVerse":["redemption","salvation","spiritual_warfare"]},"21":{"text":"And I will deliver thee out of the hand of the wicked, and I will redeem thee out of the hand of the terrible.","ref":"Jeremiah 15:21","synthesized":"I will deliver you from the hand of the wicked and redeem you from the grasp of the ruthless.”","sources":{"KJV":{"text":"And I will deliver thee out of the hand of the wicked, and I will redeem thee out of the hand of the terrible."},"BSB":{"text":"I will deliver you from the hand of the wicked and redeem you from the grasp of the ruthless.”"},"TANAKH":{"text":"And I will deliver thee out of the hand of the wicked, and I will redeem thee out of the hand of the terrible."},"HEBREW":{"text":"וְהִצַּלְתִּ֖יךָ מִיַּ֣ד רָעִ֑ים וּפְדִתִ֖יךָ מִכַּ֥ף עָרִצִֽים׃"}},"definableWords":["deliver"],"peopleInVerse":[],"themesInVerse":["redemption","salvation"]}}},"16":{"chapter":"16","title":"THE PROPHET FORBIDDEN TO MARRY","verses":{"1":{"text":"The word of the LORD came also unto me, saying,","ref":"Jeremiah 16:1","synthesized":"Then the word of the LORD came to me, saying,","sources":{"KJV":{"text":"The word of the LORD came also unto me, saying,"},"BSB":{"text":"Then the word of the LORD came to me, saying,"},"TANAKH":{"text":"The word of HaShem came also unto me, saying:"},"HEBREW":{"text":"וַיְהִ֥י דְבַר־יְהוָ֖ה אֵלַ֥י לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"2":{"text":"Thou shalt not take thee a wife, neither shalt thou have sons or daughters in this place.","ref":"Jeremiah 16:2","synthesized":"“You must not marry or have sons or daughters in this place.”","sources":{"KJV":{"text":"Thou shalt not take thee a wife, neither shalt thou have sons or daughters in this place."},"BSB":{"text":"“You must not marry or have sons or daughters in this place.”"},"TANAKH":{"text":"Thou shalt not take thee a wife, neither shalt thou have sons or daughters in this place."},"HEBREW":{"text":"לֹֽא־תִקַּ֥ח לְךָ֖ אִשָּׁ֑ה וְלֹֽא־יִהְי֤וּ לְךָ֙ בָּנִ֣ים וּבָנ֔וֹת בַּמָּק֖וֹם הַזֶּֽה׃"}},"definableWords":["or","sons","daughters"],"peopleInVerse":[]},"3":{"text":"For thus saith the LORD concerning the sons and concerning the daughters that are born in this place, and concerning their mothers that bare them, and concerning their fathers that begat them in this land;","ref":"Jeremiah 16:3","synthesized":"For this is what the LORD says concerning the sons and daughters born in this place, and the mothers who bore them, and the fathers who fathered them in this land:","sources":{"KJV":{"text":"For thus saith the LORD concerning the sons and concerning the daughters that are born in this place, and concerning their mothers that bare them, and concerning their fathers that begat them in this land;"},"BSB":{"text":"For this is what the LORD says concerning the sons and daughters born in this place, and the mothers who bore them, and the fathers who fathered them in this land:"},"TANAKH":{"text":"For thus saith HaShem concerning the sons and concerning the daughters that are born in this place, and concerning their mothers that bore them, and concerning their fathers that begot them in this land:"},"HEBREW":{"text":"כִּי־כֹ֣ה ׀ אָמַ֣ר יְהוָ֗ה עַל־הַבָּנִים֙ וְעַל־הַבָּנ֔וֹת הַיִּלּוֹדִ֖ים בַּמָּק֣וֹם הַזֶּ֑ה וְעַֽל־אִמֹּתָ֞ם הַיֹּלְד֣וֹת אוֹתָ֗ם וְעַל־אֲבוֹתָ֛ם הַמּוֹלִדִ֥ים אוֹתָ֖ם בָּאָ֥רֶץ הַזֹּֽאת׃"}},"definableWords":["LORD","sons","daughters","fathers","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"4":{"text":"They shall die of grievous deaths; they shall not be lamented; neither shall they be buried; but they shall be as dung upon the face of the earth: and they shall be consumed by the sword, and by famine; and their carcases shall be meat for the fowls of heaven, and for the beasts of the earth.","ref":"Jeremiah 16:4","synthesized":"“They will die from deadly diseases. They will not be mourned or buried, but will lie like dung on the ground. They will be finished off by sword and famine, and their corpses will become food for the birds of the air and beasts of the earth.”","sources":{"KJV":{"text":"They shall die of grievous deaths; they shall not be lamented; neither shall they be buried; but they shall be as dung upon the face of the earth: and they shall be consumed by the sword, and by famine; and their carcases shall be meat for the fowls of heaven, and for the beasts of the earth."},"BSB":{"text":"“They will die from deadly diseases. They will not be mourned or buried, but will lie like dung on the ground. They will be finished off by sword and famine, and their corpses will become food for the birds of the air and beasts of the earth.”"},"TANAKH":{"text":"They shall die of grievous deaths; they shall not be lamented, neither shall they be buried, they shall be as dung upon the face of the ground; and they shall be consumed by the sword, and by famine; and their carcasses shall be meat for the fowls of heaven, and for the beasts of the earth."},"HEBREW":{"text":"מְמוֹתֵ֨י תַחֲלֻאִ֜ים יָמֻ֗תוּ לֹ֤א יִסָּֽפְדוּ֙ וְלֹ֣א יִקָּבֵ֔רוּ לְדֹ֛מֶן עַל־פְּנֵ֥י הָאֲדָמָ֖ה יִֽהְי֑וּ וּבַחֶ֤רֶב וּבָֽרָעָב֙ יִכְל֔וּ וְהָיְתָ֤ה נִבְלָתָם֙ לְמַאֲכָ֔ל לְע֥וֹף הַשָּׁמַ֖יִם וּלְבֶהֱמַ֥ת הָאָֽרֶץ׃"}},"definableWords":["die","or","ground","birds","earth"],"peopleInVerse":[]},"5":{"text":"For thus saith the LORD, Enter not into the house of mourning, neither go to lament nor bemoan them: for I have taken away my peace from this people, saith the LORD, even lovingkindness and mercies.","ref":"Jeremiah 16:5","synthesized":"Indeed, this is what the LORD says: “Do not enter a house where there is a funeral meal. Do not go to mourn or show sympathy, for I have removed from this people My peace, My loving devotion, and My compassion,” declares the LORD.","sources":{"KJV":{"text":"For thus saith the LORD, Enter not into the house of mourning, neither go to lament nor bemoan them: for I have taken away my peace from this people, saith the LORD, even lovingkindness and mercies."},"BSB":{"text":"Indeed, this is what the LORD says: “Do not enter a house where there is a funeral meal. Do not go to mourn or show sympathy, for I have removed from this people My peace, My loving devotion, and My compassion,” declares the LORD."},"TANAKH":{"text":"For thus saith HaShem: Enter not into the house of mourning, neither go to lament, neither bemoan them; for I have taken away My peace from this people, saith HaShem, even mercy and compassion."},"HEBREW":{"text":"כִּֽי־כֹ֣ה ׀ אָמַ֣ר יְהוָ֗ה אַל־תָּבוֹא֙ בֵּ֣ית מַרְזֵ֔חַ וְאַל־תֵּלֵ֣ךְ לִסְפּ֔וֹד וְאַל־תָּנֹ֖ד לָהֶ֑ם כִּֽי־אָסַ֨פְתִּי אֶת־שְׁלוֹמִ֜י מֵאֵ֨ת הָעָ֤ם־הַזֶּה֙ נְאֻם־יְהוָ֔ה אֶת־הַחֶ֖סֶד וְאֶת־הָֽרַחֲמִֽים׃"}},"definableWords":["LORD","house","or","people","peace","Lord"],"peopleInVerse":[],"themesInVerse":["peace"]},"6":{"text":"Both the great and the small shall die in this land: they shall not be buried, neither shall men lament for them, nor cut themselves, nor make themselves bald for them:","ref":"Jeremiah 16:6","synthesized":"“Both great and small will die in this land. They will not be buried or mourned, nor will anyone cut himself or shave his head for them.","sources":{"KJV":{"text":"Both the great and the small shall die in this land: they shall not be buried, neither shall men lament for them, nor cut themselves, nor make themselves bald for them:"},"BSB":{"text":"“Both great and small will die in this land. They will not be buried or mourned, nor will anyone cut himself or shave his head for them."},"TANAKH":{"text":"Both the great and the small shall die in this land; they shall not be buried; neither shall men lament for them, nor cut themselves, nor make themselves bald for them;"},"HEBREW":{"text":"וּמֵ֨תוּ גְדֹלִ֧ים וּקְטַנִּ֛ים בָּאָ֥רֶץ הַזֹּ֖את לֹ֣א יִקָּבֵ֑רוּ וְלֹֽא־יִסְפְּד֣וּ לָהֶ֔ם וְלֹ֣א יִתְגֹּדַ֔ד וְלֹ֥א יִקָּרֵ֖חַ לָהֶֽם׃"}},"definableWords":["great","die","land","or"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"7":{"text":"Neither shall men tear themselves for them in mourning, to comfort them for the dead; neither shall men give them the cup of consolation to drink for their father or for their mother.","ref":"Jeremiah 16:7","synthesized":"No food will be offered to comfort those who mourn the dead; not even a cup of consolation will be given for the loss of a father or mother.","sources":{"KJV":{"text":"Neither shall men tear themselves for them in mourning, to comfort them for the dead; neither shall men give them the cup of consolation to drink for their father or for their mother."},"BSB":{"text":"No food will be offered to comfort those who mourn the dead; not even a cup of consolation will be given for the loss of a father or mother."},"TANAKH":{"text":"neither shall men break bread for them in mourning, to comfort them for the dead; neither shall men give them the cup of consolation to drink for their father or for their mother."},"HEBREW":{"text":"וְלֹֽא־יִפְרְס֥וּ לָהֶ֛ם עַל־אֵ֖בֶל לְנַחֲמ֣וֹ עַל־מֵ֑ת וְלֹֽא־יַשְׁק֤וּ אוֹתָם֙ כּ֣וֹס תַּנְחוּמִ֔ים עַל־אָבִ֖יו וְעַל־אִמּֽוֹ׃"}},"definableWords":["father","or","mother"],"peopleInVerse":[]},"8":{"text":"Thou shalt not also go into the house of feasting, to sit with them to eat and to drink.","ref":"Jeremiah 16:8","synthesized":"You must not enter a house where there is feasting and sit down with them to eat and drink.","sources":{"KJV":{"text":"Thou shalt not also go into the house of feasting, to sit with them to eat and to drink."},"BSB":{"text":"You must not enter a house where there is feasting and sit down with them to eat and drink."},"TANAKH":{"text":"And thou shalt not go into the house of feasting to sit with them, to eat and to drink."},"HEBREW":{"text":"וּבֵית־מִשְׁתֶּ֥ה לֹא־תָב֖וֹא לָשֶׁ֣בֶת אוֹתָ֑ם לֶאֱכֹ֖ל וְלִשְׁתּֽוֹת׃"}},"definableWords":["house"],"peopleInVerse":[]},"9":{"text":"For thus saith the LORD of hosts, the God of Israel; Behold, I will cause to cease out of this place in your eyes, and in your days, the voice of mirth, and the voice of gladness, the voice of the bridegroom, and the voice of the bride.","ref":"Jeremiah 16:9","synthesized":"For this is what the LORD of Hosts, the God of Israel, says: I am going to remove from this place, before your very eyes and in your days, the sounds of joy and gladness, the voices of the bride and bridegroom.","sources":{"KJV":{"text":"For thus saith the LORD of hosts, the God of Israel; Behold, I will cause to cease out of this place in your eyes, and in your days, the voice of mirth, and the voice of gladness, the voice of the bridegroom, and the voice of the bride."},"BSB":{"text":"For this is what the LORD of Hosts, the God of Israel, says: I am going to remove from this place, before your very eyes and in your days, the sounds of joy and gladness, the voices of the bride and bridegroom."},"TANAKH":{"text":"For thus saith HaShem of hosts, the G-d of Israel: Behold, I will cause to cease out of this place, before your eyes and in your days, the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride."},"HEBREW":{"text":"כִּי֩ כֹ֨ה אָמַ֜ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל הִנְנִ֨י מַשְׁבִּ֜ית מִן־הַמָּק֥וֹם הַזֶּ֛ה לְעֵינֵיכֶ֖ם וּבִֽימֵיכֶ֑ם ק֤וֹל שָׂשׂוֹן֙ וְק֣וֹל שִׂמְחָ֔ה ק֥וֹל חָתָ֖ן וְק֥וֹל כַּלָּֽה׃"}},"definableWords":["LORD","God","Israel","days","joy"],"peopleInVerse":[],"themesInVerse":["joy","marriage_bride"]},"10":{"text":"And it shall come to pass, when thou shalt shew this people all these words, and they shall say unto thee, Wherefore hath the LORD pronounced all this great evil against us? or what is our iniquity? or what is our sin that we have committed against the LORD our God?","ref":"Jeremiah 16:10","synthesized":"When you tell these people all these things, they will ask you, ‘Why has the LORD pronounced all this great disaster against us? What is our guilt? What is the sin that we have committed against the LORD our God?’","sources":{"KJV":{"text":"And it shall come to pass, when thou shalt shew this people all these words, and they shall say unto thee, Wherefore hath the LORD pronounced all this great evil against us? or what is our iniquity? or what is our sin that we have committed against the LORD our God?"},"BSB":{"text":"When you tell these people all these things, they will ask you, ‘Why has the LORD pronounced all this great disaster against us? What is our guilt? What is the sin that we have committed against the LORD our God?’"},"TANAKH":{"text":"And it shall come to pass, when thou shalt tell this people all these words, and they shall say unto thee: 'Wherefore hath HaShem pronounced all this great evil against us? or what is our iniquity? or what is our sin that we have committed against HaShem our G-d?'"},"HEBREW":{"text":"וְהָיָ֗ה כִּ֤י תַגִּיד֙ לָעָ֣ם הַזֶּ֔ה אֵ֥ת כָּל־הַדְּבָרִ֖ים הָאֵ֑לֶּה וְאָמְר֣וּ אֵלֶ֗יךָ עַל־מֶה֩ דִבֶּ֨ר יְהוָ֤ה עָלֵ֙ינוּ֙ אֵ֣ת כָּל־הָרָעָ֤ה הַגְּדוֹלָה֙ הַזֹּ֔את וּמֶ֤ה עֲוֺנֵ֙נוּ֙ וּמֶ֣ה חַטָּאתֵ֔נוּ אֲשֶׁ֥ר חָטָ֖אנוּ לַֽיהוָ֥ה אֱלֹהֵֽינוּ׃"}},"definableWords":["people","LORD","great","sin","Lord","God"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"11":{"text":"Then shalt thou say unto them, Because your fathers have forsaken me, saith the LORD, and have walked after other gods, and have served them, and have worshipped them, and have forsaken me, and have not kept my law;","ref":"Jeremiah 16:11","synthesized":"Then you are to answer them: ‘It is because your fathers have forsaken Me, declares the LORD, and followed other gods, and served and worshiped them. They abandoned Me and did not keep My instruction.","sources":{"KJV":{"text":"Then shalt thou say unto them, Because your fathers have forsaken me, saith the LORD, and have walked after other gods, and have served them, and have worshipped them, and have forsaken me, and have not kept my law;"},"BSB":{"text":"Then you are to answer them: ‘It is because your fathers have forsaken Me, declares the LORD, and followed other gods, and served and worshiped them. They abandoned Me and did not keep My instruction."},"TANAKH":{"text":"then shalt thou say unto them: 'Because your fathers have forsaken Me, saith HaShem, and have walked after other gods, and have served them, and have worshipped them, and have forsaken Me, and have not kept My law;"},"HEBREW":{"text":"וְאָמַרְתָּ֣ אֲלֵיהֶ֗ם עַל֩ אֲשֶׁר־עָזְב֨וּ אֲבוֹתֵיכֶ֤ם אוֹתִי֙ נְאֻם־יְהוָ֔ה וַיֵּלְכ֗וּ אַֽחֲרֵי֙ אֱלֹהִ֣ים אֲחֵרִ֔ים וַיַּעַבְד֖וּם וַיִּשְׁתַּחֲו֣וּ לָהֶ֑ם וְאֹתִ֣י עָזָ֔בוּ וְאֶת־תּוֹרָתִ֖י לֹ֥א שָׁמָֽרוּ׃"}},"definableWords":["fathers","LORD","keep"],"peopleInVerse":[]},"12":{"text":"And ye have done worse than your fathers; for, behold, ye walk every one after the imagination of his evil heart, that they may not hearken unto me:","ref":"Jeremiah 16:12","synthesized":"And you have done more evil than your fathers. See how each of you follows the stubbornness of his evil heart instead of obeying Me.","sources":{"KJV":{"text":"And ye have done worse than your fathers; for, behold, ye walk every one after the imagination of his evil heart, that they may not hearken unto me:"},"BSB":{"text":"And you have done more evil than your fathers. See how each of you follows the stubbornness of his evil heart instead of obeying Me."},"TANAKH":{"text":"and ye have done worse than your fathers; for, behold, ye walk every one after the stubbornness of his evil heart, so that ye hearken not unto Me;"},"HEBREW":{"text":"וְאַתֶּ֛ם הֲרֵעֹתֶ֥ם לַעֲשׂ֖וֹת מֵאֲבֽוֹתֵיכֶ֑ם וְהִנְּכֶ֣ם הֹלְכִ֗ים אִ֚ישׁ אַֽחֲרֵי֙ שְׁרִר֣וּת לִבּֽוֹ־הָרָ֔ע לְבִלְתִּ֖י שְׁמֹ֥עַ אֵלָֽי׃"}},"definableWords":["evil","fathers","see","heart"],"peopleInVerse":[]},"13":{"text":"Therefore will I cast you out of this land into a land that ye know not, neither ye nor your fathers; and there shall ye serve other gods day and night; where I will not shew you favour.","ref":"Jeremiah 16:13","synthesized":"So I will cast you out of this land into a land that neither you nor your fathers have known. There you will serve other gods day and night, for I will show you no favor.’","sources":{"KJV":{"text":"Therefore will I cast you out of this land into a land that ye know not, neither ye nor your fathers; and there shall ye serve other gods day and night; where I will not shew you favour."},"BSB":{"text":"So I will cast you out of this land into a land that neither you nor your fathers have known. There you will serve other gods day and night, for I will show you no favor.’"},"TANAKH":{"text":"therefore will I cast you out of this land into a land that ye have not known, neither ye nor your fathers; and there shall ye serve other gods day and night; forasmuch as I will show you no favour.'"},"HEBREW":{"text":"וְהֵטַלְתִּ֣י אֶתְכֶ֗ם מֵעַל֙ הָאָ֣רֶץ הַזֹּ֔את עַל־הָאָ֕רֶץ אֲשֶׁר֙ לֹ֣א יְדַעְתֶּ֔ם אַתֶּ֖ם וַאֲבֽוֹתֵיכֶ֑ם וַעֲבַדְתֶּם־שָׁ֞ם אֶת־אֱלֹהִ֤ים אֲחֵרִים֙ יוֹמָ֣ם וָלַ֔יְלָה אֲשֶׁ֛ר לֹֽא־אֶתֵּ֥ן לָכֶ֖ם חֲנִינָֽה׃"}},"definableWords":["land","fathers","day","night"],"peopleInVerse":[],"themesInVerse":["grace","land_promise"]},"14":{"text":"Therefore, behold, the days come, saith the LORD, that it shall no more be said, The LORD liveth, that brought up the children of Israel out of the land of Egypt;","ref":"Jeremiah 16:14","synthesized":"Yet behold, the days are coming, declares the LORD, when they will no longer say, ‘As surely as the LORD lives, who brought the Israelites up out of the land of Egypt.’","sources":{"KJV":{"text":"Therefore, behold, the days come, saith the LORD, that it shall no more be said, The LORD liveth, that brought up the children of Israel out of the land of Egypt;"},"BSB":{"text":"Yet behold, the days are coming, declares the LORD, when they will no longer say, ‘As surely as the LORD lives, who brought the Israelites up out of the land of Egypt.’"},"TANAKH":{"text":"Therefore, behold, the days come, saith HaShem, that it shall no more be said: 'As HaShem liveth, that brought up the children of Israel out of the land of Egypt,'"},"HEBREW":{"text":"לָכֵ֛ן הִנֵּֽה־יָמִ֥ים בָּאִ֖ים נְאֻם־יְהוָ֑ה וְלֹֽא־יֵאָמֵ֥ר עוֹד֙ חַי־יְהוָ֔ה אֲשֶׁ֧ר הֶעֱלָ֛ה אֶת־בְּנֵ֥י יִשְׂרָאֵ֖ל מֵאֶ֥רֶץ מִצְרָֽיִם׃"}},"definableWords":["days","LORD","Lord","Israelites","land","Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise","second_coming"]},"15":{"text":"But, The LORD liveth, that brought up the children of Israel from the land of the north, and from all the lands whither he had driven them: and I will bring them again into their land that I gave unto their fathers.","ref":"Jeremiah 16:15","synthesized":"Instead they will say, ‘As surely as the LORD lives, who brought the Israelites up out of the land of the north and all the other lands to which He had banished them.’ For I will return them to their land that I gave to their forefathers.","sources":{"KJV":{"text":"But, The LORD liveth, that brought up the children of Israel from the land of the north, and from all the lands whither he had driven them: and I will bring them again into their land that I gave unto their fathers."},"BSB":{"text":"Instead they will say, ‘As surely as the LORD lives, who brought the Israelites up out of the land of the north and all the other lands to which He had banished them.’ For I will return them to their land that I gave to their forefathers."},"TANAKH":{"text":"but: 'As HaShem liveth, that brought up the children of Israel from the land of the north, and from all the countries whither He had driven them'; and I will bring them back into their land that I gave unto their fathers."},"HEBREW":{"text":"כִּ֣י אִם־חַי־יְהוָ֗ה אֲשֶׁ֨ר הֶעֱלָ֜ה אֶת־בְּנֵ֤י יִשְׂרָאֵל֙ מֵאֶ֣רֶץ צָפ֔וֹן וּמִכֹּל֙ הָֽאֲרָצ֔וֹת אֲשֶׁ֥ר הִדִּיחָ֖ם שָׁ֑מָּה וַהֲשִֽׁבֹתִים֙ עַל־אַדְמָתָ֔ם אֲשֶׁ֥ר נָתַ֖תִּי לַאֲבוֹתָֽם׃"}},"definableWords":["LORD","Israelites","land"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise","second_coming"]},"16":{"text":"Behold, I will send for many fishers, saith the LORD, and they shall fish them; and after will I send for many hunters, and they shall hunt them from every mountain, and from every hill, and out of the holes of the rocks.","ref":"Jeremiah 16:16","synthesized":"But for now I will send for many fishermen, declares the LORD, and they will catch them. After that I will send for many hunters, and they will hunt them down on every mountain and hill, even from the clefts of the rocks.","sources":{"KJV":{"text":"Behold, I will send for many fishers, saith the LORD, and they shall fish them; and after will I send for many hunters, and they shall hunt them from every mountain, and from every hill, and out of the holes of the rocks."},"BSB":{"text":"But for now I will send for many fishermen, declares the LORD, and they will catch them. After that I will send for many hunters, and they will hunt them down on every mountain and hill, even from the clefts of the rocks."},"TANAKH":{"text":"Behold, I will send for many fishers, saith HaShem, and they shall fish them; and afterward I will send for many hunters, and they shall hunt them from every mountain, and from every hill, and out of the clefts of the rocks."},"HEBREW":{"text":"הִנְנִ֨י שֹׁלֵ֜חַ לדוגים לְדַיָּגִ֥ים רַבִּ֛ים נְאֻם־יְהוָ֖ה וְדִיג֑וּם וְאַֽחֲרֵי־כֵ֗ן אֶשְׁלַח֙ לְרַבִּ֣ים צַיָּדִ֔ים וְצָד֞וּם מֵעַ֤ל כָּל־הַר֙ וּמֵעַ֣ל כָּל־גִּבְעָ֔ה וּמִנְּקִיקֵ֖י הַסְּלָעִֽים׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"17":{"text":"For mine eyes are upon all their ways: they are not hid from my face, neither is their iniquity hid from mine eyes.","ref":"Jeremiah 16:17","synthesized":"For My eyes are on all their ways. They are not hidden from My face, and their guilt is not concealed from My eyes.","sources":{"KJV":{"text":"For mine eyes are upon all their ways: they are not hid from my face, neither is their iniquity hid from mine eyes."},"BSB":{"text":"For My eyes are on all their ways. They are not hidden from My face, and their guilt is not concealed from My eyes."},"TANAKH":{"text":"For Mine eyes are upon all their ways, they are not hid from My face; neither is their iniquity concealed from Mine eyes."},"HEBREW":{"text":"כִּ֤י עֵינַי֙ עַל־כָּל־דַּרְכֵיהֶ֔ם לֹ֥א נִסְתְּר֖וּ מִלְּפָנָ֑י וְלֹֽא־נִצְפַּ֥ן עֲוֺנָ֖ם מִנֶּ֥גֶד עֵינָֽי׃"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"And first I will recompense their iniquity and their sin double; because they have defiled my land, they have filled mine inheritance with the carcases of their detestable and abominable things.","ref":"Jeremiah 16:18","synthesized":"And I will first repay them double their iniquity and their sin, because they have defiled My land with the carcasses of their detestable idols, and they have filled My inheritance with their abominations.”","sources":{"KJV":{"text":"And first I will recompense their iniquity and their sin double; because they have defiled my land, they have filled mine inheritance with the carcases of their detestable and abominable things."},"BSB":{"text":"And I will first repay them double their iniquity and their sin, because they have defiled My land with the carcasses of their detestable idols, and they have filled My inheritance with their abominations.”"},"TANAKH":{"text":"And first I will recompense their iniquity and their sin double; because they have profaned My land; they have filled Mine inheritance with the carcasses of their detestable things and their abominations."},"HEBREW":{"text":"וְשִׁלַּמְתִּ֣י רִֽאשׁוֹנָ֗ה מִשְׁנֵ֤ה עֲוֺנָם֙ וְחַטָּאתָ֔ם עַ֖ל חַלְּלָ֣ם אֶת־אַרְצִ֑י בְּנִבְלַ֤ת שִׁקּֽוּצֵיהֶם֙ וְתוֹעֲב֣וֹתֵיהֶ֔ם מָלְא֖וּ אֶת־נַחֲלָתִֽי׃"}},"definableWords":["iniquity","sin","land"],"peopleInVerse":[],"themesInVerse":["fall_sin","land_promise"]},"19":{"text":"O LORD, my strength, and my fortress, and my refuge in the day of affliction, the Gentiles shall come unto thee from the ends of the earth, and shall say, Surely our fathers have inherited lies, vanity, and things wherein there is no profit.","ref":"Jeremiah 16:19","synthesized":"O LORD, my strength and my fortress, my refuge in the day of distress, the nations will come to You from the ends of the earth, and they will say, “Our fathers inherited nothing but lies, worthless idols of no benefit at all.","sources":{"KJV":{"text":"O LORD, my strength, and my fortress, and my refuge in the day of affliction, the Gentiles shall come unto thee from the ends of the earth, and shall say, Surely our fathers have inherited lies, vanity, and things wherein there is no profit."},"BSB":{"text":"O LORD, my strength and my fortress, my refuge in the day of distress, the nations will come to You from the ends of the earth, and they will say, “Our fathers inherited nothing but lies, worthless idols of no benefit at all."},"TANAKH":{"text":"O HaShem, my strength, and my stronghold, and my refuge, in the day of affliction, unto Thee shall the nations come from the ends of the earth, and shall say: 'Our fathers have inherited nought but lies, vanity and things wherein there is no profit.'"},"HEBREW":{"text":"יְהוָ֞ה עֻזִּ֧י וּמָעֻזִּ֛י וּמְנוּסִ֖י בְּי֣וֹם צָרָ֑ה אֵלֶ֗יךָ גּוֹיִ֤ם יָבֹ֙אוּ֙ מֵֽאַפְסֵי־אָ֔רֶץ וְיֹאמְר֗וּ אַךְ־שֶׁ֙קֶר֙ נָחֲל֣וּ אֲבוֹתֵ֔ינוּ הֶ֖בֶל וְאֵֽין־בָּ֥ם מוֹעִֽיל׃"}},"definableWords":["LORD","day","nations","earth","fathers"],"peopleInVerse":[]},"20":{"text":"Shall a man make gods unto himself, and they are no gods?","ref":"Jeremiah 16:20","synthesized":"Can man make gods for himself? Such are not gods!”","sources":{"KJV":{"text":"Shall a man make gods unto himself, and they are no gods?"},"BSB":{"text":"Can man make gods for himself? Such are not gods!”"},"TANAKH":{"text":"Shall a man make unto himself gods, and they are no gods?"},"HEBREW":{"text":"הֲיַעֲשֶׂה־לּ֥וֹ אָדָ֖ם אֱלֹהִ֑ים וְהֵ֖מָּה לֹ֥א אֱלֹהִֽים׃"}},"definableWords":["man","make"],"peopleInVerse":[]},"21":{"text":"Therefore, behold, I will this once cause them to know, I will cause them to know mine hand and my might; and they shall know that my name is The LORD.","ref":"Jeremiah 16:21","synthesized":"“Therefore behold, I will inform them, and this time I will make them know My power and My might; then they will know that My name is the LORD.","sources":{"KJV":{"text":"Therefore, behold, I will this once cause them to know, I will cause them to know mine hand and my might; and they shall know that my name is The LORD."},"BSB":{"text":"“Therefore behold, I will inform them, and this time I will make them know My power and My might; then they will know that My name is the LORD."},"TANAKH":{"text":"Therefore, behold, I will cause them to know, this once will I cause them to know My hand and My might; and they shall know that My name is HaShem."},"HEBREW":{"text":"לָכֵן֙ הִנְנִ֣י מֽוֹדִיעָ֔ם בַּפַּ֣עַם הַזֹּ֔את אוֹדִיעֵ֥ם אֶת־יָדִ֖י וְאֶת־גְּבֽוּרָתִ֑י וְיָדְע֖וּ כִּֽי־שְׁמִ֥י יְהוָֽה׃"}},"definableWords":["make","name","LORD"],"peopleInVerse":[]}}},"17":{"chapter":"17","title":"BLESSED IS THE MAN THAT TRUSTETH","verses":{"1":{"text":"The sin of Judah is written with a pen of iron, and with the point of a diamond: it is graven upon the table of their heart, and upon the horns of your altars;","ref":"Jeremiah 17:1","synthesized":"“The sin of Judah is written with an iron stylus, engraved with a diamond point on the tablets of their hearts and on the horns of their altars.","sources":{"KJV":{"text":"The sin of Judah is written with a pen of iron, and with the point of a diamond: it is graven upon the table of their heart, and upon the horns of your altars;"},"BSB":{"text":"“The sin of Judah is written with an iron stylus, engraved with a diamond point on the tablets of their hearts and on the horns of their altars."},"TANAKH":{"text":"The sin of Judah is written with a pen of iron, and with the point of a diamond; it is graven upon the tablet of their heart, and upon the horns of your altars."},"HEBREW":{"text":"חַטַּ֣את יְהוּדָ֗ה כְּתוּבָ֛ה בְּעֵ֥ט בַּרְזֶ֖ל בְּצִפֹּ֣רֶן שָׁמִ֑יר חֲרוּשָׁה֙ עַל־ל֣וּחַ לִבָּ֔ם וּלְקַרְנ֖וֹת מִזְבְּחוֹתֵיכֶֽם׃"}},"definableWords":["sin","Judah"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"2":{"text":"Whilst their children remember their altars and their groves by the green trees upon the high hills.","ref":"Jeremiah 17:2","synthesized":"Even their children remember their altars and Asherah poles by the green trees and on the high hills.","sources":{"KJV":{"text":"Whilst their children remember their altars and their groves by the green trees upon the high hills."},"BSB":{"text":"Even their children remember their altars and Asherah poles by the green trees and on the high hills."},"TANAKH":{"text":"Like the symbols of their sons are their altars, and their Asherim are by the leafy trees, upon the high hills."},"HEBREW":{"text":"כִּזְכֹּ֤ר בְּנֵיהֶם֙ מִזְבְּחוֹתָ֔ם וַאֲשֵׁרֵיהֶ֖ם עַל־עֵ֣ץ רַֽעֲנָ֑ן עַ֖ל גְּבָע֥וֹת הַגְּבֹהֽוֹת׃"}},"definableWords":["remember","trees"],"peopleInVerse":[]},"3":{"text":"O my mountain in the field, I will give thy substance and all thy treasures to the spoil, and thy high places for sin, throughout all thy borders.","ref":"Jeremiah 17:3","synthesized":"O My mountain in the countryside, I will give over your wealth and all your treasures as plunder, because of the sin of your high places, within all your borders.","sources":{"KJV":{"text":"O my mountain in the field, I will give thy substance and all thy treasures to the spoil, and thy high places for sin, throughout all thy borders."},"BSB":{"text":"O My mountain in the countryside, I will give over your wealth and all your treasures as plunder, because of the sin of your high places, within all your borders."},"TANAKH":{"text":"O thou that sittest upon the mountain in the field, I will give thy substance and all thy treasures for a spoil, and thy high places, because of sin, throughout all thy borders."},"HEBREW":{"text":"הֲרָרִי֙ בַּשָּׂדֶ֔ה חֵילְךָ֥ כָל־אוֹצְרוֹתֶ֖יךָ לָבַ֣ז אֶתֵּ֑ן בָּמֹתֶ֕יךָ בְּחַטָּ֖את בְּכָל־גְּבוּלֶֽיךָ׃"}},"definableWords":["sin"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"4":{"text":"And thou, even thyself, shalt discontinue from thine heritage that I gave thee; and I will cause thee to serve thine enemies in the land which thou knowest not: for ye have kindled a fire in mine anger, which shall burn for ever.","ref":"Jeremiah 17:4","synthesized":"And you yourself will relinquish the inheritance that I gave you. I will enslave you to your enemies in a land that you do not know, for you have kindled My anger; it will burn forever.”","sources":{"KJV":{"text":"And thou, even thyself, shalt discontinue from thine heritage that I gave thee; and I will cause thee to serve thine enemies in the land which thou knowest not: for ye have kindled a fire in mine anger, which shall burn for ever."},"BSB":{"text":"And you yourself will relinquish the inheritance that I gave you. I will enslave you to your enemies in a land that you do not know, for you have kindled My anger; it will burn forever.”"},"TANAKH":{"text":"And thou, even of thyself, shalt discontinue from thy heritage that I gave thee; and I will cause thee to serve thine enemies in the land which thou knowest not; for ye have kindled a fire in My nostril, which shall burn for ever."},"HEBREW":{"text":"וְשָׁמַטְתָּ֗ה וּבְךָ֙ מִנַּחֲלָֽתְךָ֙ אֲשֶׁ֣ר נָתַ֣תִּי לָ֔ךְ וְהַעֲבַדְתִּ֙יךָ֙ אֶת־אֹ֣יְבֶ֔יךָ בָּאָ֖רֶץ אֲשֶׁ֣ר לֹֽא־יָדָ֑עְתָּ כִּֽי־אֵ֛שׁ קְדַחְתֶּ֥ם בְּאַפִּ֖י עַד־עוֹלָ֥ם תּוּקָֽד׃"}},"definableWords":["land","anger"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"5":{"text":"Thus saith the LORD; Cursed be the man that trusteth in man, and maketh flesh his arm, and whose heart departeth from the LORD.","ref":"Jeremiah 17:5","synthesized":"This is what the LORD says:  “Cursed is the man who trusts in mankind, who makes the flesh his strength and turns his heart from the LORD.","sources":{"KJV":{"text":"Thus saith the LORD; Cursed be the man that trusteth in man, and maketh flesh his arm, and whose heart departeth from the LORD."},"BSB":{"text":"This is what the LORD says:  “Cursed is the man who trusts in mankind, who makes the flesh his strength and turns his heart from the LORD."},"TANAKH":{"text":"Thus saith HaShem: Cursed is the man that trusteth in man, and maketh flesh his arm, and whose heart departeth from HaShem."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה אָר֤וּר הַגֶּ֙בֶר֙ אֲשֶׁ֣ר יִבְטַ֣ח בָּֽאָדָ֔ם וְשָׂ֥ם בָּשָׂ֖ר זְרֹע֑וֹ וּמִן־יְהוָ֖ה יָס֥וּר לִבּֽוֹ׃"}},"definableWords":["LORD","cursed","man","flesh","heart","Lord"],"peopleInVerse":[]},"6":{"text":"For he shall be like the heath in the desert, and shall not see when good cometh; but shall inhabit the parched places in the wilderness, in a salt land and not inhabited.","ref":"Jeremiah 17:6","synthesized":"He will be like a shrub in the desert; he will not see when prosperity comes. He will dwell in the parched places of the desert, in a salt land where no one lives.","sources":{"KJV":{"text":"For he shall be like the heath in the desert, and shall not see when good cometh; but shall inhabit the parched places in the wilderness, in a salt land and not inhabited."},"BSB":{"text":"He will be like a shrub in the desert; he will not see when prosperity comes. He will dwell in the parched places of the desert, in a salt land where no one lives."},"TANAKH":{"text":"For he shall be like a tamarisk in the desert, and shall not see when good cometh; but shall inhabit the parched places in the wilderness, a salt land and not inhabited."},"HEBREW":{"text":"וְהָיָה֙ כְּעַרְעָ֣ר בָּֽעֲרָבָ֔ה וְלֹ֥א יִרְאֶ֖ה כִּי־יָב֣וֹא ט֑וֹב וְשָׁכַ֤ן חֲרֵרִים֙ בַּמִּדְבָּ֔ר אֶ֥רֶץ מְלֵחָ֖ה וְלֹ֥א תֵשֵֽׁב׃"}},"definableWords":["see","land","one"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"7":{"text":"Blessed is the man that trusteth in the LORD, and whose hope the LORD is.","ref":"Jeremiah 17:7","synthesized":"But blessed is the man who trusts in the LORD, whose confidence is in Him.","sources":{"KJV":{"text":"Blessed is the man that trusteth in the LORD, and whose hope the LORD is."},"BSB":{"text":"But blessed is the man who trusts in the LORD, whose confidence is in Him."},"TANAKH":{"text":"Blessed is the man that trusteth in HaShem, and whose trust HaShem is."},"HEBREW":{"text":"בָּר֣וּךְ הַגֶּ֔בֶר אֲשֶׁ֥ר יִבְטַ֖ח בַּֽיהוָ֑ה וְהָיָ֥ה יְהוָ֖ה מִבְטַחֽוֹ׃"}},"definableWords":["blessed","man","LORD"],"peopleInVerse":[]},"8":{"text":"For he shall be as a tree planted by the waters, and that spreadeth out her roots by the river, and shall not see when heat cometh, but her leaf shall be green; and shall not be careful in the year of drought, neither shall cease from yielding fruit.","ref":"Jeremiah 17:8","synthesized":"He is like a tree planted by the waters that sends out its roots toward the stream. It does not fear when the heat comes, and its leaves are always green. It does not worry in a year of drought, nor does it cease to produce fruit.","sources":{"KJV":{"text":"For he shall be as a tree planted by the waters, and that spreadeth out her roots by the river, and shall not see when heat cometh, but her leaf shall be green; and shall not be careful in the year of drought, neither shall cease from yielding fruit."},"BSB":{"text":"He is like a tree planted by the waters that sends out its roots toward the stream. It does not fear when the heat comes, and its leaves are always green. It does not worry in a year of drought, nor does it cease to produce fruit."},"TANAKH":{"text":"For he shall be as a tree planted by the waters, and that spreadeth out its roots by the river, and shall not see when heat cometh, but its foliage shall be luxuriant; and shall not be anxious in the year of drought, neither shall cease from yielding fruit."},"HEBREW":{"text":"וְהָיָ֞ה כְּעֵ֣ץ ׀ שָׁת֣וּל עַל־מַ֗יִם וְעַל־יוּבַל֙ יְשַׁלַּ֣ח שָֽׁרָשָׁ֔יו וְלֹ֤א ירא יִרְאֶה֙ כִּֽי־יָבֹ֣א חֹ֔ם וְהָיָ֥ה עָלֵ֖הוּ רַֽעֲנָ֑ן וּבִשְׁנַ֤ת בַּצֹּ֙רֶת֙ לֹ֣א יִדְאָ֔ג וְלֹ֥א יָמִ֖ישׁ מֵעֲשׂ֥וֹת פֶּֽרִי׃"}},"definableWords":["tree","waters","fear","year"],"peopleInVerse":[],"themesInVerse":["fear_of_lord","vine_branches"]},"9":{"text":"The heart is deceitful above all things, and desperately wicked: who can know it?","ref":"Jeremiah 17:9","synthesized":"The heart is deceitful above all things and beyond cure. Who can understand it?","sources":{"KJV":{"text":"The heart is deceitful above all things, and desperately wicked: who can know it?"},"BSB":{"text":"The heart is deceitful above all things and beyond cure. Who can understand it?"},"TANAKH":{"text":"The heart is deceitful above all things, and it is exceeding weak--who can know it?"},"HEBREW":{"text":"עָקֹ֥ב הַלֵּ֛ב מִכֹּ֖ל וְאָנֻ֣שׁ ה֑וּא מִ֖י יֵדָעֶֽנּוּ׃"}},"definableWords":["heart"],"peopleInVerse":[]},"10":{"text":"I the LORD search the heart, I try the reins, even to give every man according to his ways, and according to the fruit of his doings.","ref":"Jeremiah 17:10","synthesized":"I, the LORD, search the heart; I examine the mind to reward a man according to his way, by what his deeds deserve.","sources":{"KJV":{"text":"I the LORD search the heart, I try the reins, even to give every man according to his ways, and according to the fruit of his doings."},"BSB":{"text":"I, the LORD, search the heart; I examine the mind to reward a man according to his way, by what his deeds deserve."},"TANAKH":{"text":"I HaShem search the heart, I try the reins, even to give every man according to his ways, according to the fruit of his doings."},"HEBREW":{"text":"אֲנִ֧י יְהוָ֛ה חֹקֵ֥ר לֵ֖ב בֹּחֵ֣ן כְּלָי֑וֹת וְלָתֵ֤ת לְאִישׁ֙ כדרכו כִּדְרָכָ֔יו כִּפְרִ֖י מַעֲלָלָֽיו׃"}},"definableWords":["LORD","heart","mind","man","way"],"peopleInVerse":[]},"11":{"text":"As the partridge sitteth on eggs, and hatcheth them not; so he that getteth riches, and not by right, shall leave them in the midst of his days, and at his end shall be a fool.","ref":"Jeremiah 17:11","synthesized":"Like a partridge hatching eggs it did not lay is the man who makes a fortune unjustly. In the middle of his days his riches will desert him, and in the end he will be the fool.”","sources":{"KJV":{"text":"As the partridge sitteth on eggs, and hatcheth them not; so he that getteth riches, and not by right, shall leave them in the midst of his days, and at his end shall be a fool."},"BSB":{"text":"Like a partridge hatching eggs it did not lay is the man who makes a fortune unjustly. In the middle of his days his riches will desert him, and in the end he will be the fool.”"},"TANAKH":{"text":"As the partridge that broodeth over young which she hath not brought forth, so is he that getteth riches, and not by right; in the midst of his days he shall leave them, and at his end he shall be a fool."},"HEBREW":{"text":"קֹרֵ֤א דָגַר֙ וְלֹ֣א יָלָ֔ד עֹ֥שֶׂה עֹ֖שֶׁר וְלֹ֣א בְמִשְׁפָּ֑ט בַּחֲצִ֤י ימו יָמָיו֙ יַעַזְבֶ֔נּוּ וּבְאַחֲרִית֖וֹ יִהְיֶ֥ה נָבָֽל׃"}},"definableWords":["man","days","fool"],"peopleInVerse":[]},"12":{"text":"A glorious high throne from the beginning is the place of our sanctuary.","ref":"Jeremiah 17:12","synthesized":"A glorious throne, exalted from the beginning, is the place of our sanctuary.","sources":{"KJV":{"text":"A glorious high throne from the beginning is the place of our sanctuary."},"BSB":{"text":"A glorious throne, exalted from the beginning, is the place of our sanctuary."},"TANAKH":{"text":"Thou throne of glory, on high from the beginning, thou place of our sanctuary,"},"HEBREW":{"text":"כִּסֵּ֣א כָב֔וֹד מָר֖וֹם מֵֽרִאשׁ֑וֹן מְק֖וֹם מִקְדָּשֵֽׁנוּ׃"}},"definableWords":["throne","beginning"],"peopleInVerse":[],"themesInVerse":["creation","kingdom_of_god","kingship","temple"]},"13":{"text":"O LORD, the hope of Israel, all that forsake thee shall be ashamed, and they that depart from me shall be written in the earth, because they have forsaken the LORD, the fountain of living waters.","ref":"Jeremiah 17:13","synthesized":"O LORD, the hope of Israel, all who abandon You will be put to shame. All who turn away will be written in the dust, for they have abandoned the LORD, the fountain of living water.","sources":{"KJV":{"text":"O LORD, the hope of Israel, all that forsake thee shall be ashamed, and they that depart from me shall be written in the earth, because they have forsaken the LORD, the fountain of living waters."},"BSB":{"text":"O LORD, the hope of Israel, all who abandon You will be put to shame. All who turn away will be written in the dust, for they have abandoned the LORD, the fountain of living water."},"TANAKH":{"text":"Thou hope of Israel, HaShem! All that forsake Thee shall be ashamed; they that depart from Thee shall be written in the earth, because they have forsaken HaShem, the fountain of living waters."},"HEBREW":{"text":"מִקְוֵ֤ה יִשְׂרָאֵל֙ יְהוָ֔ה כָּל־עֹזְבֶ֖יךָ יֵבֹ֑שׁוּ יסורי וְסוּרַי֙ בָּאָ֣רֶץ יִכָּתֵ֔בוּ כִּ֥י עָזְב֛וּ מְק֥וֹר מַֽיִם־חַיִּ֖ים אֶת־יְהוָֽה׃"}},"definableWords":["LORD","hope","Israel","Lord","living","water"],"peopleInVerse":[],"themesInVerse":["bread_water_life","hope"]},"14":{"text":"Heal me, O LORD, and I shall be healed; save me, and I shall be saved: for thou art my praise.","ref":"Jeremiah 17:14","synthesized":"Heal me, O LORD, and I will be healed; save me, and I will be saved, for You are my praise.","sources":{"KJV":{"text":"Heal me, O LORD, and I shall be healed; save me, and I shall be saved: for thou art my praise."},"BSB":{"text":"Heal me, O LORD, and I will be healed; save me, and I will be saved, for You are my praise."},"TANAKH":{"text":"Heal me, O HaShem, and I shall be healed; save me, and I shall be saved; for Thou art my praise."},"HEBREW":{"text":"רְפָאֵ֤נִי יְהוָה֙ וְאֵ֣רָפֵ֔א הוֹשִׁיעֵ֖נִי וְאִוָּשֵׁ֑עָה כִּ֥י תְהִלָּתִ֖י אָֽתָּה׃"}},"definableWords":["heal","LORD","praise"],"peopleInVerse":[],"themesInVerse":["salvation","worship"]},"15":{"text":"Behold, they say unto me, Where is the word of the LORD? let it come now.","ref":"Jeremiah 17:15","synthesized":"Behold, they keep saying to me, “Where is the word of the LORD? Let it come now!”","sources":{"KJV":{"text":"Behold, they say unto me, Where is the word of the LORD? let it come now."},"BSB":{"text":"Behold, they keep saying to me, “Where is the word of the LORD? Let it come now!”"},"TANAKH":{"text":"Behold, they say unto me: 'Where is the word of HaShem? let it come now.'"},"HEBREW":{"text":"הִנֵּה־הֵ֕מָּה אֹמְרִ֖ים אֵלָ֑י אַיֵּ֥ה דְבַר־יְהוָ֖ה יָ֥בוֹא נָֽא׃"}},"definableWords":["keep","word","LORD"],"peopleInVerse":[]},"16":{"text":"As for me, I have not hastened from being a pastor to follow thee: neither have I desired the woeful day; thou knowest: that which came out of my lips was right before thee.","ref":"Jeremiah 17:16","synthesized":"But I have not run away from being Your shepherd; I have not desired the day of despair. You know that the utterance of my lips was spoken in Your presence.","sources":{"KJV":{"text":"As for me, I have not hastened from being a pastor to follow thee: neither have I desired the woeful day; thou knowest: that which came out of my lips was right before thee."},"BSB":{"text":"But I have not run away from being Your shepherd; I have not desired the day of despair. You know that the utterance of my lips was spoken in Your presence."},"TANAKH":{"text":"As for me, I have not hastened from being a shepherd after Thee; neither have I desired the woeful day; Thou knowest it; that which came out of my lips was manifest before Thee."},"HEBREW":{"text":"וַאֲנִ֞י לֹא־אַ֣צְתִּי ׀ מֵרֹעֶ֣ה אַחֲרֶ֗יךָ וְי֥וֹם אָנ֛וּשׁ לֹ֥א הִתְאַוֵּ֖יתִי אַתָּ֣ה יָדָ֑עְתָּ מוֹצָ֣א שְׂפָתַ֔י נֹ֥כַח פָּנֶ֖יךָ הָיָֽה׃"}},"definableWords":["run","shepherd","day"],"peopleInVerse":[],"themesInVerse":["shepherd_sheep"]},"17":{"text":"Be not a terror unto me: thou art my hope in the day of evil.","ref":"Jeremiah 17:17","synthesized":"Do not become a terror to me; You are my refuge in the day of disaster.","sources":{"KJV":{"text":"Be not a terror unto me: thou art my hope in the day of evil."},"BSB":{"text":"Do not become a terror to me; You are my refuge in the day of disaster."},"TANAKH":{"text":"Be not a ruin unto me; thou art my refuge in the day of evil."},"HEBREW":{"text":"אַל־תִּֽהְיֵה־לִ֖י לִמְחִתָּ֑ה מֽ͏ַחֲסִי־אַ֖תָּה בְּי֥וֹם רָעָֽה׃"}},"definableWords":["day"],"peopleInVerse":[]},"18":{"text":"Let them be confounded that persecute me, but let not me be confounded: let them be dismayed, but let not me be dismayed: bring upon them the day of evil, and destroy them with double destruction.","ref":"Jeremiah 17:18","synthesized":"Let my persecutors be put to shame, but do not let me be put to shame. Let them be terrified, but do not let me be terrified. Bring upon them the day of disaster and shatter them with double destruction.","sources":{"KJV":{"text":"Let them be confounded that persecute me, but let not me be confounded: let them be dismayed, but let not me be dismayed: bring upon them the day of evil, and destroy them with double destruction."},"BSB":{"text":"Let my persecutors be put to shame, but do not let me be put to shame. Let them be terrified, but do not let me be terrified. Bring upon them the day of disaster and shatter them with double destruction."},"TANAKH":{"text":"Let them be ashamed that persecute me, but let not me be ashamed; let them be dismayed, but let not me be dismayed; bring upon them the day of evil, and destroy them with double destruction."},"HEBREW":{"text":"יֵבֹ֤שׁוּ רֹדְפַי֙ וְאַל־אֵבֹ֣שָׁה אָ֔נִי יֵחַ֣תּוּ הֵ֔מָּה וְאַל־אֵחַ֖תָּה אָ֑נִי הָבִ֤יא עֲלֵיהֶם֙ י֣וֹם רָעָ֔ה וּמִשְׁנֶ֥ה שִׁבָּר֖וֹן שָׁבְרֵֽם׃"}},"definableWords":["day"],"peopleInVerse":[]},"19":{"text":"Thus said the LORD unto me; Go and stand in the gate of the children of the people, whereby the kings of Judah come in, and by the which they go out, and in all the gates of Jerusalem;","ref":"Jeremiah 17:19","synthesized":"This is what the LORD said to me: “Go and stand at the gate of the people, through which the kings of Judah go in and out; and stand at all the other gates of Jerusalem.","sources":{"KJV":{"text":"Thus said the LORD unto me; Go and stand in the gate of the children of the people, whereby the kings of Judah come in, and by the which they go out, and in all the gates of Jerusalem;"},"BSB":{"text":"This is what the LORD said to me: “Go and stand at the gate of the people, through which the kings of Judah go in and out; and stand at all the other gates of Jerusalem."},"TANAKH":{"text":"Thus said HaShem unto me: Go, and stand in the gate of the children of the people, whereby the kings of Judah come in, and by which they go out, and in all the gates of Jerusalem;"},"HEBREW":{"text":"כֹּה־אָמַ֨ר יְהוָ֜ה אֵלַ֗י הָלֹ֤ךְ וְעָֽמַדְתָּ֙ בְּשַׁ֣עַר בְּנֵֽי־עם הָעָ֔ם אֲשֶׁ֨ר יָבֹ֤אוּ בוֹ֙ מַלְכֵ֣י יְהוּדָ֔ה וַאֲשֶׁ֖ר יֵ֣צְאוּ ב֑וֹ וּבְכֹ֖ל שַׁעֲרֵ֥י יְרוּשָׁלָֽ͏ִם׃"}},"definableWords":["LORD","stand","people","kings","Judah","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"20":{"text":"And say unto them, Hear ye the word of the LORD, ye kings of Judah, and all Judah, and all the inhabitants of Jerusalem, that enter in by these gates:","ref":"Jeremiah 17:20","synthesized":"Say to them, ‘Hear the word of the LORD, O kings of Judah, all people of Judah and Jerusalem who enter through these gates.","sources":{"KJV":{"text":"And say unto them, Hear ye the word of the LORD, ye kings of Judah, and all Judah, and all the inhabitants of Jerusalem, that enter in by these gates:"},"BSB":{"text":"Say to them, ‘Hear the word of the LORD, O kings of Judah, all people of Judah and Jerusalem who enter through these gates."},"TANAKH":{"text":"and say unto them: Hear ye the word of HaShem, ye kings of Judah, and all Judah, and all the inhabitants of Jerusalem, that enter in by these gates;"},"HEBREW":{"text":"וְאָמַרְתָּ֣ אֲ֠לֵיהֶם שִׁמְע֨וּ דְבַר־יְהוָ֜ה מַלְכֵ֤י יְהוּדָה֙ וְכָל־יְהוּדָ֔ה וְכֹ֖ל יֹשְׁבֵ֣י יְרוּשָׁלָ֑͏ִם הַבָּאִ֖ים בַּשְּׁעָרִ֥ים הָאֵֽלֶּה׃"}},"definableWords":["hear","word","LORD","kings","Judah","people","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"21":{"text":"Thus saith the LORD; Take heed to yourselves, and bear no burden on the sabbath day, nor bring it in by the gates of Jerusalem;","ref":"Jeremiah 17:21","synthesized":"This is what the LORD says: Take heed for yourselves; do not carry a load or bring it through the gates of Jerusalem on the Sabbath day.","sources":{"KJV":{"text":"Thus saith the LORD; Take heed to yourselves, and bear no burden on the sabbath day, nor bring it in by the gates of Jerusalem;"},"BSB":{"text":"This is what the LORD says: Take heed for yourselves; do not carry a load or bring it through the gates of Jerusalem on the Sabbath day."},"TANAKH":{"text":"thus saith HaShem: Take heed for the sake of your souls, and bear no burden on the sabbath day, nor bring it in by the gates of Jerusalem;"},"HEBREW":{"text":"כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִשָּׁמְר֖וּ בְּנַפְשֽׁוֹתֵיכֶ֑ם וְאַל־תִּשְׂא֤וּ מַשָּׂא֙ בְּי֣וֹם הַשַּׁבָּ֔ת וַהֲבֵאתֶ֖ם בְּשַׁעֲרֵ֥י יְרוּשָׁלָֽ͏ִם׃"}},"definableWords":["LORD","or","Jerusalem","Sabbath","day"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["sabbath_rest"]},"22":{"text":"Neither carry forth a burden out of your houses on the sabbath day, neither do ye any work, but hallow ye the sabbath day, as I commanded your fathers.","ref":"Jeremiah 17:22","synthesized":"You must not carry a load out of your houses or do any work on the Sabbath day, but you must keep the Sabbath day holy, just as I commanded your forefathers.","sources":{"KJV":{"text":"Neither carry forth a burden out of your houses on the sabbath day, neither do ye any work, but hallow ye the sabbath day, as I commanded your fathers."},"BSB":{"text":"You must not carry a load out of your houses or do any work on the Sabbath day, but you must keep the Sabbath day holy, just as I commanded your forefathers."},"TANAKH":{"text":"neither carry forth a burden out of your houses on the sabbath day, neither do ye any work; but hallow ye the sabbath day, as I commanded your fathers;"},"HEBREW":{"text":"וְלֹא־תוֹצִ֨יאוּ מַשָּׂ֤א מִבָּֽתֵּיכֶם֙ בְּי֣וֹם הַשַּׁבָּ֔ת וְכָל־מְלָאכָ֖ה לֹ֣א תַֽעֲשׂ֑וּ וְקִדַּשְׁתֶּם֙ אֶת־י֣וֹם הַשַּׁבָּ֔ת כַּאֲשֶׁ֥ר צִוִּ֖יתִי אֶת־אֲבוֹתֵיכֶֽם׃"}},"definableWords":["or","work","Sabbath","day","keep","sabbath","holy"],"peopleInVerse":[],"themesInVerse":["sabbath_rest"]},"23":{"text":"But they obeyed not, neither inclined their ear, but made their neck stiff, that they might not hear, nor receive instruction.","ref":"Jeremiah 17:23","synthesized":"Yet they would not listen or incline their ear, but they stiffened their necks and would not listen or receive My discipline.","sources":{"KJV":{"text":"But they obeyed not, neither inclined their ear, but made their neck stiff, that they might not hear, nor receive instruction."},"BSB":{"text":"Yet they would not listen or incline their ear, but they stiffened their necks and would not listen or receive My discipline."},"TANAKH":{"text":"but they hearkened not, neither inclined their ear, but made their neck stiff, that they might not hear, nor receive instruction."},"HEBREW":{"text":"וְלֹ֣א שָֽׁמְע֔וּ וְלֹ֥א הִטּ֖וּ אֶת־אָזְנָ֑ם וַיַּקְשׁוּ֙ אֶת־עָרְפָּ֔ם לְבִלְתִּ֣י שומע שְׁמ֔וֹעַ וּלְבִלְתִּ֖י קַ֥חַת מוּסָֽר׃"}},"definableWords":["or"],"peopleInVerse":[]},"24":{"text":"And it shall come to pass, if ye diligently hearken unto me, saith the LORD, to bring in no burden through the gates of this city on the sabbath day, but hallow the sabbath day, to do no work therein;","ref":"Jeremiah 17:24","synthesized":"If, however, you listen carefully to Me, says the LORD, and bring no load through the gates of this city on the Sabbath day, and keep the Sabbath day holy, and do no work on it,","sources":{"KJV":{"text":"And it shall come to pass, if ye diligently hearken unto me, saith the LORD, to bring in no burden through the gates of this city on the sabbath day, but hallow the sabbath day, to do no work therein;"},"BSB":{"text":"If, however, you listen carefully to Me, says the LORD, and bring no load through the gates of this city on the Sabbath day, and keep the Sabbath day holy, and do no work on it,"},"TANAKH":{"text":"And it shall come to pass, if ye diligently hearken unto Me, saith HaShem, to bring in no burden through the gates of this city on the sabbath day, but to hallow the sabbath day, to do no work therein;"},"HEBREW":{"text":"וְ֠הָיָה אִם־שָׁמֹ֨עַ תִּשְׁמְע֤וּן אֵלַי֙ נְאֻם־יְהוָ֔ה לְבִלְתִּ֣י ׀ הָבִ֣יא מַשָּׂ֗א בְּשַׁעֲרֵ֛י הָעִ֥יר הַזֹּ֖את בְּי֣וֹם הַשַּׁבָּ֑ת וּלְקַדֵּשׁ֙ אֶת־י֣וֹם הַשַּׁבָּ֔ת לְבִלְתִּ֥י עֲשֽׂוֹת־בה בּ֖וֹ כָּל־מְלָאכָֽה׃"}},"definableWords":["LORD","Sabbath","day","keep","sabbath","holy","work"],"peopleInVerse":[],"themesInVerse":["sabbath_rest"]},"25":{"text":"Then shall there enter into the gates of this city kings and princes sitting upon the throne of David, riding in chariots and on horses, they, and their princes, the men of Judah, and the inhabitants of Jerusalem: and this city shall remain for ever.","ref":"Jeremiah 17:25","synthesized":"then kings and princes will enter through the gates of this city. They will sit on the throne of David, riding in chariots and on horses with their officials, along with the men of Judah and the residents of Jerusalem, and this city will be inhabited forever.","sources":{"KJV":{"text":"Then shall there enter into the gates of this city kings and princes sitting upon the throne of David, riding in chariots and on horses, they, and their princes, the men of Judah, and the inhabitants of Jerusalem: and this city shall remain for ever."},"BSB":{"text":"then kings and princes will enter through the gates of this city. They will sit on the throne of David, riding in chariots and on horses with their officials, along with the men of Judah and the residents of Jerusalem, and this city will be inhabited forever."},"TANAKH":{"text":"then shall there enter in by the gates of this city kings and princes sitting upon the throne of David, riding in chariots and on horses, they, and their princes, the men of Judah, and the inhabitants of Jerusalem; and this city shall be inhabited for ever."},"HEBREW":{"text":"וּבָ֣אוּ בְשַׁעֲרֵ֣י הָעִ֣יר הַזֹּ֡את מְלָכִ֣ים ׀ וְשָׂרִ֡ים יֹשְׁבִים֩ עַל־כִּסֵּ֨א דָוִ֜ד רֹכְבִ֣ים ׀ בָּרֶ֣כֶב וּבַסּוּסִ֗ים הֵ֚מָּה וְשָׂ֣רֵיהֶ֔ם אִ֥ישׁ יְהוּדָ֖ה וְיֹשְׁבֵ֣י יְרוּשָׁלָ֑͏ִם וְיָשְׁבָ֥ה הָֽעִיר־הַזֹּ֖את לְעוֹלָֽם׃"}},"definableWords":["kings","throne","men","Judah","Jerusalem"],"peopleInVerse":["David"],"placesInVerse":["Jerusalem"],"themesInVerse":["kingdom_of_god","kingship"]},"26":{"text":"And they shall come from the cities of Judah, and from the places about Jerusalem, and from the land of Benjamin, and from the plain, and from the mountains, and from the south, bringing burnt offerings, and sacrifices, and meat offerings, and incense, and bringing sacrifices of praise, unto the house of the LORD.","ref":"Jeremiah 17:26","synthesized":"And people will come from the cities of Judah and the places around Jerusalem, from the land of Benjamin, and from the foothills, the hill country, and the Negev, bringing burnt offerings and sacrifices, grain offerings and frankincense, and thank offerings to the house of the LORD.","sources":{"KJV":{"text":"And they shall come from the cities of Judah, and from the places about Jerusalem, and from the land of Benjamin, and from the plain, and from the mountains, and from the south, bringing burnt offerings, and sacrifices, and meat offerings, and incense, and bringing sacrifices of praise, unto the house of the LORD."},"BSB":{"text":"And people will come from the cities of Judah and the places around Jerusalem, from the land of Benjamin, and from the foothills, the hill country, and the Negev, bringing burnt offerings and sacrifices, grain offerings and frankincense, and thank offerings to the house of the LORD."},"TANAKH":{"text":"And they shall come from the cities of Judah, and from the places round about Jerusalem, and from the land of Benjamin, and from the Lowland, and from the mountains, and from the South, bringing burnt-offerings, and sacrifices, and meal-offerings, and frankincense, and bringing sacrifices of thanksgiving, unto the house of HaShem."},"HEBREW":{"text":"וּבָ֣אוּ מֵעָרֵֽי־יְ֠הוּדָה וּמִסְּבִיב֨וֹת יְרוּשָׁלִַ֜ם וּמֵאֶ֣רֶץ בִּנְיָמִ֗ן וּמִן־הַשְּׁפֵלָ֤ה וּמִן־הָהָר֙ וּמִן־הַנֶּ֔גֶב מְבִאִ֛ים עוֹלָ֥ה וְזֶ֖בַח וּמִנְחָ֣ה וּלְבוֹנָ֑ה וּמְבִאֵ֥י תוֹדָ֖ה בֵּ֥ית יְהוָֽה׃"}},"definableWords":["people","Judah","Jerusalem","land","Benjamin","house","LORD"],"peopleInVerse":[],"placesInVerse":["Jerusalem","Negev"],"themesInVerse":["land_promise"]},"27":{"text":"But if ye will not hearken unto me to hallow the sabbath day, and not to bear a burden, even entering in at the gates of Jerusalem on the sabbath day; then will I kindle a fire in the gates thereof, and it shall devour the palaces of Jerusalem, and it shall not be quenched.","ref":"Jeremiah 17:27","synthesized":"But if you do not listen to Me to keep the Sabbath day holy by not carrying a load while entering the gates of Jerusalem on the Sabbath day, then I will kindle an unquenchable fire in its gates to consume the citadels of Jerusalem.’”","sources":{"KJV":{"text":"But if ye will not hearken unto me to hallow the sabbath day, and not to bear a burden, even entering in at the gates of Jerusalem on the sabbath day; then will I kindle a fire in the gates thereof, and it shall devour the palaces of Jerusalem, and it shall not be quenched."},"BSB":{"text":"But if you do not listen to Me to keep the Sabbath day holy by not carrying a load while entering the gates of Jerusalem on the Sabbath day, then I will kindle an unquenchable fire in its gates to consume the citadels of Jerusalem.’”"},"TANAKH":{"text":"But if ye will not hearken unto Me to hallow the sabbath day, and not to bear a burden and enter in at the gates of Jerusalem on the sabbath day; then will I kindle a fire in the gates thereof, and it shall devour the palaces of Jerusalem, and it shall not be quenched."},"HEBREW":{"text":"וְאִם־לֹ֨א תִשְׁמְע֜וּ אֵלַ֗י לְקַדֵּשׁ֙ אֶת־י֣וֹם הַשַּׁבָּ֔ת וּלְבִלְתִּ֣י ׀ שְׂאֵ֣ת מַשָּׂ֗א וּבֹ֛א בְּשַׁעֲרֵ֥י יְרוּשָׁלַ֖͏ִם בְּי֣וֹם הַשַּׁבָּ֑ת וְהִצַּ֧תִּי אֵ֣שׁ בִּשְׁעָרֶ֗יהָ וְאָֽכְלָ֛ה אַרְמְנ֥וֹת יְרוּשָׁלַ֖͏ִם וְלֹ֥א תִכְבֶּֽה׃"}},"definableWords":["keep","Sabbath","day","holy","Jerusalem","sabbath"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["sabbath_rest"]}}},"18":{"chapter":"18","title":"THE POTTER AND THE CLAY","verses":{"1":{"text":"The word which came to Jeremiah from the LORD, saying,","ref":"Jeremiah 18:1","synthesized":"This is the word that came to Jeremiah from the LORD:","sources":{"KJV":{"text":"The word which came to Jeremiah from the LORD, saying,"},"BSB":{"text":"This is the word that came to Jeremiah from the LORD:"},"TANAKH":{"text":"The word which came to Jeremiah from HaShem, saying:"},"HEBREW":{"text":"הַדָּבָר֙ אֲשֶׁ֣ר הָיָ֣ה אֶֽל־יִרְמְיָ֔הוּ מֵאֵ֥ת יְהוָ֖ה לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"2":{"text":"Arise, and go down to the potter’s house, and there I will cause thee to hear my words.","ref":"Jeremiah 18:2","synthesized":"“Go down at once to the potter’s house, and there I will reveal My message to you.”","sources":{"KJV":{"text":"Arise, and go down to the potter’s house, and there I will cause thee to hear my words."},"BSB":{"text":"“Go down at once to the potter’s house, and there I will reveal My message to you.”"},"TANAKH":{"text":"'Arise, and go down to the potter's house, and there I will cause thee to hear My words.'"},"HEBREW":{"text":"ק֥וּם וְיָרַדְתָּ֖ בֵּ֣ית הַיּוֹצֵ֑ר וְשָׁ֖מָּה אַשְׁמִֽיעֲךָ֥ אֶת־דְּבָרָֽי׃"}},"definableWords":["house"],"peopleInVerse":[]},"3":{"text":"Then I went down to the potter’s house, and, behold, he wrought a work on the wheels.","ref":"Jeremiah 18:3","synthesized":"So I went down to the potter’s house and saw him working at the wheel.","sources":{"KJV":{"text":"Then I went down to the potter’s house, and, behold, he wrought a work on the wheels."},"BSB":{"text":"So I went down to the potter’s house and saw him working at the wheel."},"TANAKH":{"text":"Then I went down to the potter's house, and, behold, he was at his work on the wheels."},"HEBREW":{"text":"וָאֵרֵ֖ד בֵּ֣ית הַיּוֹצֵ֑ר והנהו וְהִנֵּה־ה֛וּא עֹשֶׂ֥ה מְלָאכָ֖ה עַל־הָאָבְנָֽיִם׃"}},"definableWords":["house","saw"],"peopleInVerse":[]},"4":{"text":"And the vessel that he made of clay was marred in the hand of the potter: so he made it again another vessel, as seemed good to the potter to make it.","ref":"Jeremiah 18:4","synthesized":"But the vessel that he was shaping from the clay became flawed in his hand; so he formed it into another vessel, as it seemed best for him to do.","sources":{"KJV":{"text":"And the vessel that he made of clay was marred in the hand of the potter: so he made it again another vessel, as seemed good to the potter to make it."},"BSB":{"text":"But the vessel that he was shaping from the clay became flawed in his hand; so he formed it into another vessel, as it seemed best for him to do."},"TANAKH":{"text":"And whensoever the vessel that he made of the clay was marred in the hand of the potter, he made it again another vessel, as seemed good to the potter to make it."},"HEBREW":{"text":"וְנִשְׁחַ֣ת הַכְּלִ֗י אֲשֶׁ֨ר ה֥וּא עֹשֶׂ֛ה בַּחֹ֖מֶר בְּיַ֣ד הַיּוֹצֵ֑ר וְשָׁ֗ב וַֽיַּעֲשֵׂ֙הוּ֙ כְּלִ֣י אַחֵ֔ר כַּאֲשֶׁ֥ר יָשַׁ֛ר בְּעֵינֵ֥י הַיּוֹצֵ֖ר לַעֲשֽׂוֹת׃"}},"definableWords":["formed"],"peopleInVerse":[],"themesInVerse":["creation"]},"5":{"text":"Then the word of the LORD came to me, saying,","ref":"Jeremiah 18:5","synthesized":"Then the word of the LORD came to me, saying,","sources":{"KJV":{"text":"Then the word of the LORD came to me, saying,"},"BSB":{"text":"Then the word of the LORD came to me, saying,"},"TANAKH":{"text":"Then the word of HaShem came to me, saying:"},"HEBREW":{"text":"וַיְהִ֥י דְבַר־יְהוָ֖ה אֵלַ֥י לֵאמֽוֹר׃"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"6":{"text":"O house of Israel, cannot I do with you as this potter? saith the LORD. Behold, as the clay is in the potter’s hand, so are ye in mine hand, O house of Israel.","ref":"Jeremiah 18:6","synthesized":"“O house of Israel, declares the LORD, can I not treat you as this potter treats his clay? Just like clay in the potter’s hand, so are you in My hand, O house of Israel.","sources":{"KJV":{"text":"O house of Israel, cannot I do with you as this potter? saith the LORD. Behold, as the clay is in the potter’s hand, so are ye in mine hand, O house of Israel."},"BSB":{"text":"“O house of Israel, declares the LORD, can I not treat you as this potter treats his clay? Just like clay in the potter’s hand, so are you in My hand, O house of Israel."},"TANAKH":{"text":"'O house of Israel, cannot I do with you as this potter? saith HaShem. Behold, as the clay in the potter's hand, so are ye in My hand, O house of Israel."},"HEBREW":{"text":"הֲכַיּוֹצֵ֨ר הַזֶּ֜ה לֹא־אוּכַ֨ל לַעֲשׂ֥וֹת לָכֶ֛ם בֵּ֥ית יִשְׂרָאֵ֖ל נְאֻם־יְהוָ֑ה הִנֵּ֤ה כַחֹ֙מֶר֙ בְּיַ֣ד הַיּוֹצֵ֔ר כֵּן־אַתֶּ֥ם בְּיָדִ֖י בֵּ֥ית יִשְׂרָאֵֽל׃"}},"definableWords":["house","Israel","LORD"],"peopleInVerse":[]},"7":{"text":"At what instant I shall speak concerning a nation, and concerning a kingdom, to pluck up, and to pull down, and to destroy it;","ref":"Jeremiah 18:7","synthesized":"At any time I might announce that a nation or kingdom will be uprooted, torn down, and destroyed.","sources":{"KJV":{"text":"At what instant I shall speak concerning a nation, and concerning a kingdom, to pluck up, and to pull down, and to destroy it;"},"BSB":{"text":"At any time I might announce that a nation or kingdom will be uprooted, torn down, and destroyed."},"TANAKH":{"text":"At one instant I may speak concerning a nation, and concerning a kingdom, to pluck up and to break down and to destroy it;"},"HEBREW":{"text":"רֶ֣גַע אֲדַבֵּ֔ר עַל־גּ֖וֹי וְעַל־מַמְלָכָ֑ה לִנְת֥וֹשׁ וְלִנְת֖וֹץ וּֽלְהַאֲבִֽיד׃"}},"definableWords":["nation","or","kingdom"],"peopleInVerse":[],"themesInVerse":["kingdom_of_god","kingship"]},"8":{"text":"If that nation, against whom I have pronounced, turn from their evil, I will repent of the evil that I thought to do unto them.","ref":"Jeremiah 18:8","synthesized":"But if that nation I warned turns from its evil, then I will relent of the disaster I had planned to bring.","sources":{"KJV":{"text":"If that nation, against whom I have pronounced, turn from their evil, I will repent of the evil that I thought to do unto them."},"BSB":{"text":"But if that nation I warned turns from its evil, then I will relent of the disaster I had planned to bring."},"TANAKH":{"text":"but if that nation turn from their evil, because of which I have spoken against it, I repent of the evil that I thought to do unto it."},"HEBREW":{"text":"וְשָׁב֙ הַגּ֣וֹי הַה֔וּא מֵרָ֣עָת֔וֹ אֲשֶׁ֥ר דִּבַּ֖רְתִּי עָלָ֑יו וְנִֽחַמְתִּי֙ עַל־הָ֣רָעָ֔ה אֲשֶׁ֥ר חָשַׁ֖בְתִּי לַעֲשׂ֥וֹת לֽוֹ׃"}},"definableWords":["nation","evil"],"peopleInVerse":[]},"9":{"text":"And at what instant I shall speak concerning a nation, and concerning a kingdom, to build and to plant it;","ref":"Jeremiah 18:9","synthesized":"And if at another time I announce that I will build up and establish a nation or kingdom,","sources":{"KJV":{"text":"And at what instant I shall speak concerning a nation, and concerning a kingdom, to build and to plant it;"},"BSB":{"text":"And if at another time I announce that I will build up and establish a nation or kingdom,"},"TANAKH":{"text":"And at one instant I may speak concerning a nation, and concerning a kingdom, to build and to plant it;"},"HEBREW":{"text":"וְרֶ֣גַע אֲדַבֵּ֔ר עַל־גּ֖וֹי וְעַל־מַמְלָכָ֑ה לִבְנֹ֖ת וְלִנְטֹֽעַ׃"}},"definableWords":["nation","or","kingdom"],"peopleInVerse":[],"themesInVerse":["kingdom_of_god","kingship"]},"10":{"text":"If it do evil in my sight, that it obey not my voice, then I will repent of the good, wherewith I said I would benefit them.","ref":"Jeremiah 18:10","synthesized":"and if it does evil in My sight and does not listen to My voice, then I will relent of the good I had intended for it.","sources":{"KJV":{"text":"If it do evil in my sight, that it obey not my voice, then I will repent of the good, wherewith I said I would benefit them."},"BSB":{"text":"and if it does evil in My sight and does not listen to My voice, then I will relent of the good I had intended for it."},"TANAKH":{"text":"but if it do evil in My sight, that it hearken not to My voice, then I repent of the good, wherewith I said I would benefit it."},"HEBREW":{"text":"וְעָשָׂ֤ה הרעה הָרַע֙ בְּעֵינַ֔י לְבִלְתִּ֖י שְׁמֹ֣עַ בְּקוֹלִ֑י וְנִֽחַמְתִּי֙ עַל־הַטּוֹבָ֔ה אֲשֶׁ֥ר אָמַ֖רְתִּי לְהֵיטִ֥יב אוֹתֽוֹ׃"}},"definableWords":["evil","voice","good"],"peopleInVerse":[]},"11":{"text":"Now therefore go to, speak to the men of Judah, and to the inhabitants of Jerusalem, saying, Thus saith the LORD; Behold, I frame evil against you, and devise a device against you: return ye now every one from his evil way, and make your ways and your doings good.","ref":"Jeremiah 18:11","synthesized":"Now therefore, tell the men of Judah and the residents of Jerusalem that this is what the LORD says: ‘Behold, I am planning a disaster for you and devising a plan against you. Turn now, each of you, from your evil ways, and correct your ways and deeds.’","sources":{"KJV":{"text":"Now therefore go to, speak to the men of Judah, and to the inhabitants of Jerusalem, saying, Thus saith the LORD; Behold, I frame evil against you, and devise a device against you: return ye now every one from his evil way, and make your ways and your doings good."},"BSB":{"text":"Now therefore, tell the men of Judah and the residents of Jerusalem that this is what the LORD says: ‘Behold, I am planning a disaster for you and devising a plan against you. Turn now, each of you, from your evil ways, and correct your ways and deeds.’"},"TANAKH":{"text":"Now therefore do thou speak to the men of Judah, and to the inhabitants of Jerusalem, saying: Thus saith HaShem: Behold, I frame evil against you, and devise a device against you; return ye now every one from his evil way, and amend your ways and your doings."},"HEBREW":{"text":"וְעַתָּ֡ה אֱמָר־נָ֣א אֶל־אִישׁ־יְהוּדָה֩ וְעַל־יוֹשְׁבֵ֨י יְרוּשָׁלִַ֜ם לֵאמֹ֗ר כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִנֵּ֨ה אָנֹכִ֜י יוֹצֵ֤ר עֲלֵיכֶם֙ רָעָ֔ה וְחֹשֵׁ֥ב עֲלֵיכֶ֖ם מַֽחֲשָׁבָ֑ה שׁ֣וּבוּ נָ֗א אִ֚ישׁ מִדַּרְכּ֣וֹ הָֽרָעָ֔ה וְהֵיטִ֥יבוּ דַרְכֵיכֶ֖ם וּמַעַלְלֵיכֶֽם׃"}},"definableWords":["men","Judah","Jerusalem","LORD","evil"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"12":{"text":"And they said, There is no hope: but we will walk after our own devices, and we will every one do the imagination of his evil heart.","ref":"Jeremiah 18:12","synthesized":"But they will reply, ‘It is hopeless. We will follow our own plans, and each of us will act according to the stubbornness of his evil heart.’”","sources":{"KJV":{"text":"And they said, There is no hope: but we will walk after our own devices, and we will every one do the imagination of his evil heart."},"BSB":{"text":"But they will reply, ‘It is hopeless. We will follow our own plans, and each of us will act according to the stubbornness of his evil heart.’”"},"TANAKH":{"text":"But they say: There is no hope; but we will walk after our own devices, and we will do every one after the stubbornness of his evil heart.'"},"HEBREW":{"text":"וְאָמְר֖וּ נוֹאָ֑שׁ כִּֽי־אַחֲרֵ֤י מַחְשְׁבוֹתֵ֙ינוּ֙ נֵלֵ֔ךְ וְאִ֛ישׁ שְׁרִר֥וּת לִבּֽוֹ־הָרָ֖ע נַעֲשֶֽׂה׃"}},"definableWords":["evil","heart"],"peopleInVerse":[]},"13":{"text":"Therefore thus saith the LORD; Ask ye now among the heathen, who hath heard such things: the virgin of Israel hath done a very horrible thing.","ref":"Jeremiah 18:13","synthesized":"Therefore this is what the LORD says:  “Inquire among the nations: Who has ever heard things like these? Virgin Israel has done a most terrible thing.","sources":{"KJV":{"text":"Therefore thus saith the LORD; Ask ye now among the heathen, who hath heard such things: the virgin of Israel hath done a very horrible thing."},"BSB":{"text":"Therefore this is what the LORD says:  “Inquire among the nations: Who has ever heard things like these? Virgin Israel has done a most terrible thing."},"TANAKH":{"text":"Therefore thus saith HaShem: Ask ye now among the nations, who hath heard such things; the virgin of Israel hath done a very horrible thing."},"HEBREW":{"text":"לָכֵ֗ן כֹּ֚ה אָמַ֣ר יְהוָ֔ה שַֽׁאֲלוּ־נָא֙ בַּגּוֹיִ֔ם מִ֥י שָׁמַ֖ע כָּאֵ֑לֶּה שַֽׁעֲרֻרִת֙ עָשְׂתָ֣ה מְאֹ֔ד בְּתוּלַ֖ת יִשְׂרָאֵֽל׃"}},"definableWords":["LORD","nations","Israel"],"peopleInVerse":[]},"14":{"text":"Will a man leave the snow of Lebanon which cometh from the rock of the field? or shall the cold flowing waters that come from another place be forsaken?","ref":"Jeremiah 18:14","synthesized":"Does the snow of Lebanon ever leave its rocky slopes? Or do its cool waters flowing from a distance ever run dry?","sources":{"KJV":{"text":"Will a man leave the snow of Lebanon which cometh from the rock of the field? or shall the cold flowing waters that come from another place be forsaken?"},"BSB":{"text":"Does the snow of Lebanon ever leave its rocky slopes? Or do its cool waters flowing from a distance ever run dry?"},"TANAKH":{"text":"Doth the snow of Lebanon fail from the rock of the field? or are the strange cold flowing waters plucked up?"},"HEBREW":{"text":"הֲיַעֲזֹ֥ב מִצּ֛וּר שָׂדַ֖י שֶׁ֣לֶג לְבָנ֑וֹן אִם־יִנָּתְשׁ֗וּ מַ֛יִם זָרִ֥ים קָרִ֖ים נוֹזְלִֽים׃"}},"definableWords":["or","waters","run"],"peopleInVerse":[]},"15":{"text":"Because my people hath forgotten me, they have burned incense to vanity, and they have caused them to stumble in their ways from the ancient paths, to walk in paths, in a way not cast up;","ref":"Jeremiah 18:15","synthesized":"Yet My people have forgotten Me. They burn incense to worthless idols that make them stumble in their ways, leaving the ancient roads to walk on rutted bypaths instead of on the highway.","sources":{"KJV":{"text":"Because my people hath forgotten me, they have burned incense to vanity, and they have caused them to stumble in their ways from the ancient paths, to walk in paths, in a way not cast up;"},"BSB":{"text":"Yet My people have forgotten Me. They burn incense to worthless idols that make them stumble in their ways, leaving the ancient roads to walk on rutted bypaths instead of on the highway."},"TANAKH":{"text":"For My people hath forgotten Me, they offer unto vanity; and they have been made to stumble in their ways, in the ancient paths, to walk in bypaths, in a way not cast up;"},"HEBREW":{"text":"כִּֽי־שְׁכֵחֻ֥נִי עַמִּ֖י לַשָּׁ֣וְא יְקַטֵּ֑רוּ וַיַּכְשִׁל֤וּם בְּדַרְכֵיהֶם֙ שְׁבִילֵ֣י עוֹלָ֔ם לָלֶ֣כֶת נְתִיב֔וֹת דֶּ֖רֶךְ לֹ֥א סְלוּלָֽה׃"}},"definableWords":["people","incense","make","walk"],"peopleInVerse":[]},"16":{"text":"To make their land desolate, and a perpetual hissing; every one that passeth thereby shall be astonished, and wag his head.","ref":"Jeremiah 18:16","synthesized":"They have made their land a desolation, a perpetual object of scorn; all who pass by will be appalled and shake their heads.","sources":{"KJV":{"text":"To make their land desolate, and a perpetual hissing; every one that passeth thereby shall be astonished, and wag his head."},"BSB":{"text":"They have made their land a desolation, a perpetual object of scorn; all who pass by will be appalled and shake their heads."},"TANAKH":{"text":"To make their land an astonishment, and a perpetual hissing; every one that passeth thereby shall be astonished, and shake his head."},"HEBREW":{"text":"לָשׂ֥וּם אַרְצָ֛ם לְשַׁמָּ֖ה שרוקת שְׁרִיק֣וֹת עוֹלָ֑ם כֹּ֚ל עוֹבֵ֣ר עָלֶ֔יהָ יִשֹּׁ֖ם וְיָנִ֥יד בְּרֹאשֽׁוֹ׃"}},"definableWords":["made","land"],"peopleInVerse":[],"themesInVerse":["creation","land_promise"]},"17":{"text":"I will scatter them as with an east wind before the enemy; I will shew them the back, and not the face, in the day of their calamity.","ref":"Jeremiah 18:17","synthesized":"I will scatter them before the enemy like the east wind. I will show them My back and not My face in the day of their calamity.”","sources":{"KJV":{"text":"I will scatter them as with an east wind before the enemy; I will shew them the back, and not the face, in the day of their calamity."},"BSB":{"text":"I will scatter them before the enemy like the east wind. I will show them My back and not My face in the day of their calamity.”"},"TANAKH":{"text":"I will scatter them as with an east wind before the enemy; I will look upon their back, and not their face, in the day of their calamity."},"HEBREW":{"text":"כְּרֽוּחַ־קָדִ֥ים אֲפִיצֵ֖ם לִפְנֵ֣י אוֹיֵ֑ב עֹ֧רֶף וְלֹֽא־פָנִ֛ים אֶרְאֵ֖ם בְּי֥וֹם אֵידָֽם׃"}},"definableWords":["day"],"peopleInVerse":[]},"18":{"text":"Then said they, Come, and let us devise devices against Jeremiah; for the law shall not perish from the priest, nor counsel from the wise, nor the word from the prophet. Come, and let us smite him with the tongue, and let us not give heed to any of his words.","ref":"Jeremiah 18:18","synthesized":"Then some said, “Come, let us make plans against Jeremiah, for the law will never be lost to the priest, nor counsel to the wise, nor an oracle to the prophet. Come, let us denounce him and pay no heed to any of his words.”","sources":{"KJV":{"text":"Then said they, Come, and let us devise devices against Jeremiah; for the law shall not perish from the priest, nor counsel from the wise, nor the word from the prophet. Come, and let us smite him with the tongue, and let us not give heed to any of his words."},"BSB":{"text":"Then some said, “Come, let us make plans against Jeremiah, for the law will never be lost to the priest, nor counsel to the wise, nor an oracle to the prophet. Come, let us denounce him and pay no heed to any of his words.”"},"TANAKH":{"text":"Then said they: 'Come, and let us devise devices against Jeremiah; for instruction shall not perish from the priest, nor counsel from the wise, nor the word from the prophet. Come, and let us smite him with the tongue, and let us not give heed to any of his words.'"},"HEBREW":{"text":"וַיֹּאמְר֗וּ לְכ֨וּ וְנַחְשְׁבָ֣ה עַֽל־יִרְמְיָהוּ֮ מַחֲשָׁבוֹת֒ כִּי֩ לֹא־תֹאבַ֨ד תּוֹרָ֜ה מִכֹּהֵ֗ן וְעֵצָה֙ מֵֽחָכָ֔ם וְדָבָ֖ר מִנָּבִ֑יא לְכוּ֙ וְנַכֵּ֣הוּ בַלָּשׁ֔וֹן וְאַל־נַקְשִׁ֖יבָה אֶל־כָּל־דְּבָרָֽיו׃"}},"definableWords":["make","law","priest","prophet"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingdom_priesthood","wisdom"]},"19":{"text":"Give heed to me, O LORD, and hearken to the voice of them that contend with me.","ref":"Jeremiah 18:19","synthesized":"Attend to me, O LORD. Hear what my accusers are saying!","sources":{"KJV":{"text":"Give heed to me, O LORD, and hearken to the voice of them that contend with me."},"BSB":{"text":"Attend to me, O LORD. Hear what my accusers are saying!"},"TANAKH":{"text":"Give heed to me, O HaShem, and hearken to the voice of them that contend with me."},"HEBREW":{"text":"הַקְשִׁ֥יבָה יְהוָ֖ה אֵלָ֑י וּשְׁמַ֖ע לְק֥וֹל יְרִיבָֽי׃"}},"definableWords":["LORD","hear"],"peopleInVerse":[]},"20":{"text":"Shall evil be recompensed for good? for they have digged a pit for my soul. Remember that I stood before thee to speak good for them, and to turn away thy wrath from them.","ref":"Jeremiah 18:20","synthesized":"Should good be repaid with evil? Yet they have dug a pit for me. Remember how I stood before You to speak good on their behalf, to turn Your wrath from them.","sources":{"KJV":{"text":"Shall evil be recompensed for good? for they have digged a pit for my soul. Remember that I stood before thee to speak good for them, and to turn away thy wrath from them."},"BSB":{"text":"Should good be repaid with evil? Yet they have dug a pit for me. Remember how I stood before You to speak good on their behalf, to turn Your wrath from them."},"TANAKH":{"text":"Shall evil be recompensed for good? for they have digged a pit for my soul. Remember how I stood before Thee to speak good for them, to turn away Thy wrath from them."},"HEBREW":{"text":"הַיְשֻׁלַּ֤ם תַּֽחַת־טוֹבָה֙ רָעָ֔ה כִּֽי־כָר֥וּ שׁוּחָ֖ה לְנַפְשִׁ֑י זְכֹ֣ר ׀ עָמְדִ֣י לְפָנֶ֗יךָ לְדַבֵּ֤ר עֲלֵיהֶם֙ טוֹבָ֔ה לְהָשִׁ֥יב אֶת־חֲמָתְךָ֖ מֵהֶֽם׃"}},"definableWords":["good","evil","remember","wrath"],"peopleInVerse":[],"themesInVerse":["judgment"]},"21":{"text":"Therefore deliver up their children to the famine, and pour out their blood by the force of the sword; and let their wives be bereaved of their children, and be widows; and let their men be put to death; let their young men be slain by the sword in battle.","ref":"Jeremiah 18:21","synthesized":"Therefore, hand their children over to famine; pour out the power of the sword upon them. Let their wives become childless and widowed; let their husbands be slain by disease, their young men struck down by the sword in battle.","sources":{"KJV":{"text":"Therefore deliver up their children to the famine, and pour out their blood by the force of the sword; and let their wives be bereaved of their children, and be widows; and let their men be put to death; let their young men be slain by the sword in battle."},"BSB":{"text":"Therefore, hand their children over to famine; pour out the power of the sword upon them. Let their wives become childless and widowed; let their husbands be slain by disease, their young men struck down by the sword in battle."},"TANAKH":{"text":"Therefore deliver up their children to the famine, and hurl them to the power of the sword; and let their wives be bereaved of their children, and widows; and let their men be slain of death, and their young men smitten of the sword in battle."},"HEBREW":{"text":"לָכֵן֩ תֵּ֨ן אֶת־בְּנֵיהֶ֜ם לָרָעָ֗ב וְהַגִּרֵם֮ עַל־יְדֵי־חֶרֶב֒ וְתִֽהְיֶ֨נָה נְשֵׁיהֶ֤ם שַׁכֻּלוֹת֙ וְאַלְמָנ֔וֹת וְאַ֨נְשֵׁיהֶ֔ם יִֽהְי֖וּ הֲרֻ֣גֵי מָ֑וֶת בַּח֣וּרֵיהֶ֔ם מֻכֵּי־חֶ֖רֶב בַּמִּלְחָמָֽה׃"}},"definableWords":["men"],"peopleInVerse":[],"themesInVerse":["spiritual_warfare"]},"22":{"text":"Let a cry be heard from their houses, when thou shalt bring a troop suddenly upon them: for they have digged a pit to take me, and hid snares for my feet.","ref":"Jeremiah 18:22","synthesized":"Let a cry be heard from their houses when You suddenly bring raiders against them, for they have dug a pit to capture me and have hidden snares for my feet.","sources":{"KJV":{"text":"Let a cry be heard from their houses, when thou shalt bring a troop suddenly upon them: for they have digged a pit to take me, and hid snares for my feet."},"BSB":{"text":"Let a cry be heard from their houses when You suddenly bring raiders against them, for they have dug a pit to capture me and have hidden snares for my feet."},"TANAKH":{"text":"Let a cry be heard from their houses, when thou shalt bring a troop suddenly upon them; for they have digged a pit to take me, and hid snares for my feet."},"HEBREW":{"text":"תִּשָּׁמַ֤ע זְעָקָה֙ מִבָּ֣תֵּיהֶ֔ם כִּֽי־תָבִ֧יא עֲלֵיהֶ֛ם גְּד֖וּד פִּתְאֹ֑ם כִּֽי־כָר֤וּ שיחה שׁוּחָה֙ לְלָכְדֵ֔נִי וּפַחִ֖ים טָמְנ֥וּ לְרַגְלָֽי׃"}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Yet, LORD, thou knowest all their counsel against me to slay me: forgive not their iniquity, neither blot out their sin from thy sight, but let them be overthrown before thee; deal thus with them in the time of thine anger.","ref":"Jeremiah 18:23","synthesized":"But You, O LORD, know all their deadly plots against me. Do not wipe out their guilt or blot out their sin from Your sight. Let them be overthrown before You; deal with them in the time of Your anger.","sources":{"KJV":{"text":"Yet, LORD, thou knowest all their counsel against me to slay me: forgive not their iniquity, neither blot out their sin from thy sight, but let them be overthrown before thee; deal thus with them in the time of thine anger."},"BSB":{"text":"But You, O LORD, know all their deadly plots against me. Do not wipe out their guilt or blot out their sin from Your sight. Let them be overthrown before You; deal with them in the time of Your anger."},"TANAKH":{"text":"Yet, HaShem, Thou knowest all their counsel against me to slay me; forgive not their iniquity, neither blot out their sin from Thy sight; but let them be made to stumble before Thee; deal Thou with them in the time of Thine anger."},"HEBREW":{"text":"וְאַתָּ֣ה יְ֠הוָה יָדַ֜עְתָּ אֶֽת־כָּל־עֲצָתָ֤ם עָלַי֙ לַמָּ֔וֶת אַל־תְּכַפֵּר֙ עַל־עֲוֺנָ֔ם וְחַטָּאתָ֖ם מִלְּפָנֶ֣יךָ אַל־תֶּ֑מְחִי והיו וְיִהְי֤וּ מֻכְשָׁלִים֙ לְפָנֶ֔יךָ בְּעֵ֥ת אַפְּךָ֖ עֲשֵׂ֥ה בָהֶֽם׃"}},"definableWords":["LORD","or","sin","anger"],"peopleInVerse":[],"themesInVerse":["fall_sin"]}}},"19":{"chapter":"19","title":"THE BROKEN POTTER'S VESSEL","verses":{"1":{"text":"Thus saith the LORD, Go and get a potter’s earthen bottle, and take of the ancients of the people, and of the ancients of the priests;","ref":"Jeremiah 19:1","synthesized":"This is what the LORD says: “Go and buy a clay jar from a potter. Take some of the elders of the people and leaders of the priests,","sources":{"KJV":{"text":"Thus saith the LORD, Go and get a potter’s earthen bottle, and take of the ancients of the people, and of the ancients of the priests;"},"BSB":{"text":"This is what the LORD says: “Go and buy a clay jar from a potter. Take some of the elders of the people and leaders of the priests,"},"TANAKH":{"text":"Thus said HaShem: Go, and get a potter's earthen bottle, and take of the elders of the people, and of the elders of the priests;"},"HEBREW":{"text":"כֹּ֚ה אָמַ֣ר יְהוָ֔ה הָל֛וֹךְ וְקָנִ֥יתָ בַקְבֻּ֖ק יוֹצֵ֣ר חָ֑רֶשׂ וּמִזִּקְנֵ֣י הָעָ֔ם וּמִזִּקְנֵ֖י הַכֹּהֲנִֽים׃"}},"definableWords":["LORD","people"],"peopleInVerse":[]},"2":{"text":"And go forth unto the valley of the son of Hinnom, which is by the entry of the east gate, and proclaim there the words that I shall tell thee,","ref":"Jeremiah 19:2","synthesized":"and go out to the Valley of Ben-hinnom near the entrance of the Potsherd Gate.  Proclaim there the words I speak to you,","sources":{"KJV":{"text":"And go forth unto the valley of the son of Hinnom, which is by the entry of the east gate, and proclaim there the words that I shall tell thee,"},"BSB":{"text":"and go out to the Valley of Ben-hinnom near the entrance of the Potsherd Gate.  Proclaim there the words I speak to you,"},"TANAKH":{"text":"and go forth unto the valley of the son of Hinnom, which is by the entry of the gate Harsith, and proclaim there the words that I shall tell thee;"},"HEBREW":{"text":"וְיָצָ֙אתָ֙ אֶל־גֵּ֣יא בֶן־הִנֹּ֔ם אֲשֶׁ֕ר פֶּ֖תַח שַׁ֣עַר החרסות הַֽחַרְסִ֑ית וְקָרָ֣אתָ שָּׁ֔ם אֶת־הַדְּבָרִ֖ים אֲשֶׁר־אֲדַבֵּ֥ר אֵלֶֽיךָ׃"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"And say, Hear ye the word of the LORD, O kings of Judah, and inhabitants of Jerusalem; Thus saith the LORD of hosts, the God of Israel; Behold, I will bring evil upon this place, the which whosoever heareth, his ears shall tingle.","ref":"Jeremiah 19:3","synthesized":"saying, ‘Hear the word of the LORD, O kings of Judah and residents of Jerusalem. This is what the LORD of Hosts, the God of Israel, says: I am going to bring such disaster on this place that the ears of all who hear of it will ring,","sources":{"KJV":{"text":"And say, Hear ye the word of the LORD, O kings of Judah, and inhabitants of Jerusalem; Thus saith the LORD of hosts, the God of Israel; Behold, I will bring evil upon this place, the which whosoever heareth, his ears shall tingle."},"BSB":{"text":"saying, ‘Hear the word of the LORD, O kings of Judah and residents of Jerusalem. This is what the LORD of Hosts, the God of Israel, says: I am going to bring such disaster on this place that the ears of all who hear of it will ring,"},"TANAKH":{"text":"and say: Hear ye the word of HaShem, O kings of Judah, and inhabitants of Jerusalem; thus saith HaShem of hosts, the G-d of Israel: Behold, I will bring evil upon this place, which whosoever heareth, his ears shall tingle;"},"HEBREW":{"text":"וְאָֽמַרְתָּ֙ שִׁמְע֣וּ דְבַר־יְהוָ֔ה מַלְכֵ֣י יְהוּדָ֔ה וְיֹשְׁבֵ֖י יְרֽוּשָׁלָ֑͏ִם כֹּֽה־אָמַר֩ יְהוָ֨ה צְבָא֜וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֗ל הִנְנִ֨י מֵבִ֤יא רָעָה֙ עַל־הַמָּק֣וֹם הַזֶּ֔ה אֲשֶׁ֥ר כָּל־שֹׁמְעָ֖הּ תִּצַּ֥לְנָה אָזְנָֽיו׃"}},"definableWords":["hear","word","LORD","kings","Judah","Jerusalem","Lord","God","Israel"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"4":{"text":"Because they have forsaken me, and have estranged this place, and have burned incense in it unto other gods, whom neither they nor their fathers have known, nor the kings of Judah, and have filled this place with the blood of innocents;","ref":"Jeremiah 19:4","synthesized":"because they have abandoned Me and made this a foreign place. They have burned incense in this place to other gods that neither they nor their fathers nor the kings of Judah have ever known. They have filled this place with the blood of the innocent.","sources":{"KJV":{"text":"Because they have forsaken me, and have estranged this place, and have burned incense in it unto other gods, whom neither they nor their fathers have known, nor the kings of Judah, and have filled this place with the blood of innocents;"},"BSB":{"text":"because they have abandoned Me and made this a foreign place. They have burned incense in this place to other gods that neither they nor their fathers nor the kings of Judah have ever known. They have filled this place with the blood of the innocent."},"TANAKH":{"text":"because they have forsaken Me, and have estranged this place, and have offered in it unto other gods, whom neither they nor their fathers have known, nor the kings of Judah; and have filled this place with the blood of innocents;"},"HEBREW":{"text":"יַ֣עַן ׀ אֲשֶׁ֣ר עֲזָבֻ֗נִי וַֽיְנַכְּר֞וּ אֶת־הַמָּק֤וֹם הַזֶּה֙ וַיְקַטְּרוּ־בוֹ֙ לֵאלֹהִ֣ים אֲחֵרִ֔ים אֲשֶׁ֧ר לֹֽא־יְדָע֛וּם הֵ֥מָּה וַאֲבֽוֹתֵיהֶ֖ם וּמַלְכֵ֣י יְהוּדָ֑ה וּמָֽלְא֛וּ אֶת־הַמָּק֥וֹם הַזֶּ֖ה דַּ֥ם נְקִיִּֽם׃"}},"definableWords":["made","incense","fathers","kings","Judah","blood"],"peopleInVerse":[],"themesInVerse":["creation","passover","sacrifice"]},"5":{"text":"They have built also the high places of Baal, to burn their sons with fire for burnt offerings unto Baal, which I commanded not, nor spake it, neither came it into my mind:","ref":"Jeremiah 19:5","synthesized":"They have built high places to Baal on which to burn their children in the fire as offerings to Baal—something I never commanded or mentioned, nor did it even enter My mind.","sources":{"KJV":{"text":"They have built also the high places of Baal, to burn their sons with fire for burnt offerings unto Baal, which I commanded not, nor spake it, neither came it into my mind:"},"BSB":{"text":"They have built high places to Baal on which to burn their children in the fire as offerings to Baal—something I never commanded or mentioned, nor did it even enter My mind."},"TANAKH":{"text":"and have built the high places of Baal, to burn their sons in the fire for burnt-offerings unto Baal; which I commanded not, nor spoke it, neither came it into My mind."},"HEBREW":{"text":"וּבָנ֞וּ אֶת־בָּמ֣וֹת הַבַּ֗עַל לִשְׂרֹ֧ף אֶת־בְּנֵיהֶ֛ם בָּאֵ֖שׁ עֹל֣וֹת לַבָּ֑עַל אֲשֶׁ֤ר לֹֽא־צִוִּ֙יתִי֙ וְלֹ֣א דִבַּ֔רְתִּי וְלֹ֥א עָלְתָ֖ה עַל־לִבִּֽי׃"}},"definableWords":["or","mind"],"peopleInVerse":[]},"6":{"text":"Therefore, behold, the days come, saith the LORD, that this place shall no more be called Tophet, nor The valley of the son of Hinnom, but The valley of slaughter.","ref":"Jeremiah 19:6","synthesized":"So behold, the days are coming, declares the LORD, when this place will no longer be called Topheth or the Valley of Ben-hinnom, but the Valley of Slaughter.","sources":{"KJV":{"text":"Therefore, behold, the days come, saith the LORD, that this place shall no more be called Tophet, nor The valley of the son of Hinnom, but The valley of slaughter."},"BSB":{"text":"So behold, the days are coming, declares the LORD, when this place will no longer be called Topheth or the Valley of Ben-hinnom, but the Valley of Slaughter."},"TANAKH":{"text":"Therefore, behold, the days come, saith HaShem, that this place shall no more be called Topheth, nor The valley of the son of Hinnom, but The valley of slaughter;"},"HEBREW":{"text":"לָכֵ֞ן הִנֵּֽה־יָמִ֤ים בָּאִים֙ נְאֻם־יְהוָ֔ה וְלֹא־יִקָּרֵא֩ לַמָּק֨וֹם הַזֶּ֥ה ע֛וֹד הַתֹּ֖פֶת וְגֵ֣יא בֶן־הִנֹּ֑ם כִּ֖י אִם־גֵּ֥יא הַהֲרֵגָֽה׃"}},"definableWords":["days","LORD","or"],"peopleInVerse":[],"themesInVerse":["second_coming"]},"7":{"text":"And I will make void the counsel of Judah and Jerusalem in this place; and I will cause them to fall by the sword before their enemies, and by the hands of them that seek their lives: and their carcases will I give to be meat for the fowls of the heaven, and for the beasts of the earth.","ref":"Jeremiah 19:7","synthesized":"And in this place I will ruin the plans of Judah and Jerusalem. I will make them fall by the sword before their enemies, by the hands of those who seek their lives, and I will give their carcasses as food to the birds of the air and the beasts of the earth.","sources":{"KJV":{"text":"And I will make void the counsel of Judah and Jerusalem in this place; and I will cause them to fall by the sword before their enemies, and by the hands of them that seek their lives: and their carcases will I give to be meat for the fowls of the heaven, and for the beasts of the earth."},"BSB":{"text":"And in this place I will ruin the plans of Judah and Jerusalem. I will make them fall by the sword before their enemies, by the hands of those who seek their lives, and I will give their carcasses as food to the birds of the air and the beasts of the earth."},"TANAKH":{"text":"and I will make void the counsel of Judah and Jerusalem in this place; and I will cause them to fall by the sword before their enemies, and by the hand of them that seek their life; and their carcasses will I give to be food for the fowls of the heaven, and for the beasts of the earth;"},"HEBREW":{"text":"וּ֠בַקֹּתִי אֶת־עֲצַ֨ת יְהוּדָ֤ה וִירוּשָׁלִַ֙ם֙ בַּמָּק֣וֹם הַזֶּ֔ה וְהִפַּלְתִּ֤ים בַּחֶ֙רֶב֙ לִפְנֵ֣י אֹֽיְבֵיהֶ֔ם וּבְיַ֖ד מְבַקְשֵׁ֣י נַפְשָׁ֑ם וְנָתַתִּ֤י אֶת־נִבְלָתָם֙ לְמַֽאֲכָ֔ל לְע֥וֹף הַשָּׁמַ֖יִם וּלְבֶהֱמַ֥ת הָאָֽרֶץ׃"}},"definableWords":["Judah","Jerusalem","make","seek","birds","earth"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["fall_sin"]},"8":{"text":"And I will make this city desolate, and an hissing; every one that passeth thereby shall be astonished and hiss because of all the plagues thereof.","ref":"Jeremiah 19:8","synthesized":"I will make this city a desolation and an object of scorn. All who pass by will be appalled and will scoff at all her wounds.","sources":{"KJV":{"text":"And I will make this city desolate, and an hissing; every one that passeth thereby shall be astonished and hiss because of all the plagues thereof."},"BSB":{"text":"I will make this city a desolation and an object of scorn. All who pass by will be appalled and will scoff at all her wounds."},"TANAKH":{"text":"and I will make this city an astonishment, and a hissing; every one that passeth thereby shall be astonished and hiss because of all the plagues thereof;"},"HEBREW":{"text":"וְשַׂמְתִּי֙ אֶת־הָעִ֣יר הַזֹּ֔את לְשַׁמָּ֖ה וְלִשְׁרֵקָ֑ה כֹּ֚ל עֹבֵ֣ר עָלֶ֔יהָ יִשֹּׁ֥ם וְיִשְׁרֹ֖ק עַל־כָּל־מַכֹּתֶֽהָ׃"}},"definableWords":["make"],"peopleInVerse":[]},"9":{"text":"And I will cause them to eat the flesh of their sons and the flesh of their daughters, and they shall eat every one the flesh of his friend in the siege and straitness, wherewith their enemies, and they that seek their lives, shall straiten them.","ref":"Jeremiah 19:9","synthesized":"I will make them eat the flesh of their sons and daughters, and they will eat one another’s flesh in the siege and distress inflicted on them by their enemies who seek their lives.’","sources":{"KJV":{"text":"And I will cause them to eat the flesh of their sons and the flesh of their daughters, and they shall eat every one the flesh of his friend in the siege and straitness, wherewith their enemies, and they that seek their lives, shall straiten them."},"BSB":{"text":"I will make them eat the flesh of their sons and daughters, and they will eat one another’s flesh in the siege and distress inflicted on them by their enemies who seek their lives.’"},"TANAKH":{"text":"and I will cause them to eat the flesh of their sons and the flesh of their daughters, and they shall eat every one the flesh of his friend, in the siege and in the straitness, wherewith their enemies, and they that seek their life, shall straiten them."},"HEBREW":{"text":"וְהַֽאֲכַלְתִּ֞ים אֶת־בְּשַׂ֣ר בְּנֵיהֶ֗ם וְאֵת֙ בְּשַׂ֣ר בְּנֹתֵיהֶ֔ם וְאִ֥ישׁ בְּשַׂר־רֵעֵ֖הוּ יֹאכֵ֑לוּ בְּמָצוֹר֙ וּבְמָצ֔וֹק אֲשֶׁ֨ר יָצִ֧יקוּ לָהֶ֛ם אֹיְבֵיהֶ֖ם וּמְבַקְשֵׁ֥י נַפְשָֽׁם׃"}},"definableWords":["make","flesh","sons","daughters","one","seek"],"peopleInVerse":[]},"10":{"text":"Then shalt thou break the bottle in the sight of the men that go with thee,","ref":"Jeremiah 19:10","synthesized":"Then you are to shatter the jar in the presence of the men who accompany you,","sources":{"KJV":{"text":"Then shalt thou break the bottle in the sight of the men that go with thee,"},"BSB":{"text":"Then you are to shatter the jar in the presence of the men who accompany you,"},"TANAKH":{"text":"Then shalt thou break the bottle in the sight of the men that go with thee,"},"HEBREW":{"text":"וְשָׁבַרְתָּ֖ הַבַּקְבֻּ֑ק לְעֵינֵי֙ הָֽאֲנָשִׁ֔ים הַהֹלְכִ֖ים אוֹתָֽךְ׃"}},"definableWords":["men"],"peopleInVerse":[]},"11":{"text":"And shalt say unto them, Thus saith the LORD of hosts; Even so will I break this people and this city, as one breaketh a potter’s vessel, that cannot be made whole again: and they shall bury them in Tophet, till there be no place to bury.","ref":"Jeremiah 19:11","synthesized":"and you are to proclaim to them that this is what the LORD of Hosts says: I will shatter this nation and this city, like one shatters a potter’s jar that can never again be repaired. They will bury the dead in Topheth until there is no more room to bury them.","sources":{"KJV":{"text":"And shalt say unto them, Thus saith the LORD of hosts; Even so will I break this people and this city, as one breaketh a potter’s vessel, that cannot be made whole again: and they shall bury them in Tophet, till there be no place to bury."},"BSB":{"text":"and you are to proclaim to them that this is what the LORD of Hosts says: I will shatter this nation and this city, like one shatters a potter’s jar that can never again be repaired. They will bury the dead in Topheth until there is no more room to bury them."},"TANAKH":{"text":"and shalt say unto them: Thus saith HaShem of hosts: Even so will I break this people and this city, as one breaketh a potter's vessel, that cannot be made whole again; and they shall bury in Topheth, for want of room to bury."},"HEBREW":{"text":"וְאָמַרְתָּ֨ אֲלֵיהֶ֜ם כֹּה־אָמַ֣ר ׀ יְהוָ֣ה צְבָא֗וֹת כָּ֣כָה אֶשְׁבֹּ֞ר אֶת־הָעָ֤ם הַזֶּה֙ וְאֶת־הָעִ֣יר הַזֹּ֔את כַּאֲשֶׁ֤ר יִשְׁבֹּר֙ אֶת־כְּלִ֣י הַיּוֹצֵ֔ר אֲשֶׁ֛ר לֹֽא־יוּכַ֥ל לְהֵרָפֵ֖ה ע֑וֹד וּבְתֹ֣פֶת יִקְבְּר֔וּ מֵאֵ֥ין מָק֖וֹם לִקְבּֽוֹר׃"}},"definableWords":["LORD","nation","one"],"peopleInVerse":[]},"12":{"text":"Thus will I do unto this place, saith the LORD, and to the inhabitants thereof, and even make this city as Tophet:","ref":"Jeremiah 19:12","synthesized":"This is what I will do to this place and to its residents, declares the LORD. I will make this city like Topheth.","sources":{"KJV":{"text":"Thus will I do unto this place, saith the LORD, and to the inhabitants thereof, and even make this city as Tophet:"},"BSB":{"text":"This is what I will do to this place and to its residents, declares the LORD. I will make this city like Topheth."},"TANAKH":{"text":"Thus will I do unto this place, saith HaShem, and to the inhabitants thereof, even making this city as Topheth;"},"HEBREW":{"text":"כֵּֽן־אֶעֱשֶׂ֞ה לַמָּק֥וֹם הַזֶּ֛ה נְאֻם־יְהוָ֖ה וּלְיֽוֹשְׁבָ֑יו וְלָתֵ֛ת אֶת־הָעִ֥יר הַזֹּ֖את כְּתֹֽפֶת׃"}},"definableWords":["LORD","make"],"peopleInVerse":[]},"13":{"text":"And the houses of Jerusalem, and the houses of the kings of Judah, shall be defiled as the place of Tophet, because of all the houses upon whose roofs they have burned incense unto all the host of heaven, and have poured out drink offerings unto other gods.","ref":"Jeremiah 19:13","synthesized":"The houses of Jerusalem and the houses of the kings of Judah will be defiled like that place, Topheth—all the houses on whose rooftops they burned incense to all the host of heaven and poured out drink offerings to other gods.”","sources":{"KJV":{"text":"And the houses of Jerusalem, and the houses of the kings of Judah, shall be defiled as the place of Tophet, because of all the houses upon whose roofs they have burned incense unto all the host of heaven, and have poured out drink offerings unto other gods."},"BSB":{"text":"The houses of Jerusalem and the houses of the kings of Judah will be defiled like that place, Topheth—all the houses on whose rooftops they burned incense to all the host of heaven and poured out drink offerings to other gods.”"},"TANAKH":{"text":"and the houses of Jerusalem, and the houses of the kings of Judah, which are defiled, shall be as the place of Topheth, even all the houses upon whose roofs they have offered unto all the host of heaven, and have poured out drink-offerings unto other gods."},"HEBREW":{"text":"וְהָי֞וּ בָּתֵּ֣י יְרוּשָׁלִַ֗ם וּבָתֵּי֙ מַלְכֵ֣י יְהוּדָ֔ה כִּמְק֥וֹם הַתֹּ֖פֶת הַטְּמֵאִ֑ים לְכֹ֣ל הַבָּתִּ֗ים אֲשֶׁ֨ר קִטְּר֜וּ עַל־גַּגֹּֽתֵיהֶם֙ לְכֹל֙ צְבָ֣א הַשָּׁמַ֔יִם וְהַסֵּ֥ךְ נְסָכִ֖ים לֵאלֹהִ֥ים אֲחֵרִֽים׃"}},"definableWords":["Jerusalem","kings","Judah","incense","heaven"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"14":{"text":"Then came Jeremiah from Tophet, whither the LORD had sent him to prophesy; and he stood in the court of the LORD’s house; and said to all the people,","ref":"Jeremiah 19:14","synthesized":"Then Jeremiah returned from Topheth, where the LORD had sent him to prophesy, and he stood in the courtyard of the house of the LORD and proclaimed to all the people,","sources":{"KJV":{"text":"Then came Jeremiah from Tophet, whither the LORD had sent him to prophesy; and he stood in the court of the LORD’s house; and said to all the people,"},"BSB":{"text":"Then Jeremiah returned from Topheth, where the LORD had sent him to prophesy, and he stood in the courtyard of the house of the LORD and proclaimed to all the people,"},"TANAKH":{"text":"Then came Jeremiah from Topheth, whither HaShem had sent him to prophesy; and he stood in the court of HaShem'S house, and said to all the people:"},"HEBREW":{"text":"וַיָּבֹ֤א יִרְמְיָ֙הוּ֙ מֵֽהַתֹּ֔פֶת אֲשֶׁ֨ר שְׁלָח֧וֹ יְהוָ֛ה שָׁ֖ם לְהִנָּבֵ֑א וַֽיַּעֲמֹד֙ בַּחֲצַ֣ר בֵּית־יְהוָ֔ה וַיֹּ֖אמֶר אֶל־כָּל־הָעָֽם׃"}},"definableWords":["LORD","house","Lord","people"],"peopleInVerse":["Jeremiah"]},"15":{"text":"Thus saith the LORD of hosts, the God of Israel; Behold, I will bring upon this city and upon all her towns all the evil that I have pronounced against it, because they have hardened their necks, that they might not hear my words.","ref":"Jeremiah 19:15","synthesized":"“This is what the LORD of Hosts, the God of Israel, says: ‘Behold, I am about to bring on this city and on all the villages around it every disaster I have pronounced against them, because they have stiffened their necks so as not to heed My words.’”","sources":{"KJV":{"text":"Thus saith the LORD of hosts, the God of Israel; Behold, I will bring upon this city and upon all her towns all the evil that I have pronounced against it, because they have hardened their necks, that they might not hear my words."},"BSB":{"text":"“This is what the LORD of Hosts, the God of Israel, says: ‘Behold, I am about to bring on this city and on all the villages around it every disaster I have pronounced against them, because they have stiffened their necks so as not to heed My words.’”"},"TANAKH":{"text":"'Thus saith HaShem of hosts, the G-d of Israel: Behold, I will bring upon this city and upon all her towns all the evil that I have pronounced against it; because they have made their neck stiff, that they might not hear My words.'"},"HEBREW":{"text":"כֹּֽה־אָמַ֞ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל הִנְנִ֨י מבי מֵבִ֜יא אֶל־הָעִ֤יר הַזֹּאת֙ וְעַל־כָּל־עָרֶ֔יהָ אֵ֚ת כָּל־הָ֣רָעָ֔ה אֲשֶׁ֥ר דִּבַּ֖רְתִּי עָלֶ֑יהָ כִּ֤י הִקְשׁוּ֙ אֶת־עָרְפָּ֔ם לְבִלְתִּ֖י שְׁמ֥וֹעַ אֶת־דְּבָרָֽי׃"}},"definableWords":["LORD","God","Israel"],"peopleInVerse":[]}}},"20":{"chapter":"20","title":"PASHUR PUTS JEREMIAH IN STOCKS","verses":{"1":{"text":"Now Pashur the son of Immer the priest, who was also chief governor in the house of the LORD, heard that Jeremiah prophesied these things.","ref":"Jeremiah 20:1","synthesized":"When Pashhur the priest, the son of Immer and the chief official in the house of the LORD, heard Jeremiah prophesying these things,","sources":{"KJV":{"text":"Now Pashur the son of Immer the priest, who was also chief governor in the house of the LORD, heard that Jeremiah prophesied these things."},"BSB":{"text":"When Pashhur the priest, the son of Immer and the chief official in the house of the LORD, heard Jeremiah prophesying these things,"},"TANAKH":{"text":"Now Pashhur the son of Immer the priest, who was chief officer in the house of HaShem, heard Jeremiah prophesying these things."},"HEBREW":{"text":"וַיִּשְׁמַ֤ע פַּשְׁחוּר֙ בֶּן־אִמֵּ֣ר הַכֹּהֵ֔ן וְהֽוּא־פָקִ֥יד נָגִ֖יד בְּבֵ֣ית יְהוָ֑ה אֶֽת־יִרְמְיָ֔הוּ נִבָּ֖א אֶת־הַדְּבָרִ֥ים הָאֵֽלֶּה׃"}},"definableWords":["priest","son","house","LORD"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingdom_priesthood"]},"2":{"text":"Then Pashur smote Jeremiah the prophet, and put him in the stocks that were in the high gate of Benjamin, which was by the house of the LORD.","ref":"Jeremiah 20:2","synthesized":"he had Jeremiah the prophet beaten and put in the stocks at the Upper Gate of Benjamin, which was by the house of the LORD.","sources":{"KJV":{"text":"Then Pashur smote Jeremiah the prophet, and put him in the stocks that were in the high gate of Benjamin, which was by the house of the LORD."},"BSB":{"text":"he had Jeremiah the prophet beaten and put in the stocks at the Upper Gate of Benjamin, which was by the house of the LORD."},"TANAKH":{"text":"Then Pashhur smote Jeremiah the prophet, and put him in the stocks that were in the upper gate of Benjamin, which was in the house of HaShem."},"HEBREW":{"text":"וַיַּכֶּ֣ה פַשְׁח֔וּר אֵ֖ת יִרְמְיָ֣הוּ הַנָּבִ֑יא וַיִּתֵּ֨ן אֹת֜וֹ עַל־הַמַּהְפֶּ֗כֶת אֲשֶׁ֨ר בְּשַׁ֤עַר בִּנְיָמִן֙ הָֽעֶלְי֔וֹן אֲשֶׁ֖ר בְּבֵ֥ית יְהוָֽה׃"}},"definableWords":["prophet","Benjamin","house","LORD"],"peopleInVerse":["Jeremiah"]},"3":{"text":"And it came to pass on the morrow, that Pashur brought forth Jeremiah out of the stocks. Then said Jeremiah unto him, The LORD hath not called thy name Pashur, but Magormissabib.","ref":"Jeremiah 20:3","synthesized":"The next day, when Pashhur released Jeremiah from the stocks, Jeremiah said to him, “The LORD does not call you Pashhur, but Magor-missabib.","sources":{"KJV":{"text":"And it came to pass on the morrow, that Pashur brought forth Jeremiah out of the stocks. Then said Jeremiah unto him, The LORD hath not called thy name Pashur, but Magormissabib."},"BSB":{"text":"The next day, when Pashhur released Jeremiah from the stocks, Jeremiah said to him, “The LORD does not call you Pashhur, but Magor-missabib."},"TANAKH":{"text":"And it came to pass on the morrow, that Pashhur brought forth Jeremiah out of the stocks. Then said Jeremiah unto him: 'The HaShem hath not called thy name Pashhur, but Magormissabib."},"HEBREW":{"text":"וַֽיְהִי֙ מִֽמָּחֳרָ֔ת וַיֹּצֵ֥א פַשְׁח֛וּר אֶֽת־יִרְמְיָ֖הוּ מִן־הַמַּהְפָּ֑כֶת וַיֹּ֨אמֶר אֵלָ֜יו יִרְמְיָ֗הוּ לֹ֤א פַשְׁחוּר֙ קָרָ֤א יְהוָה֙ שְׁמֶ֔ךָ כִּ֖י אִם־מָג֥וֹר מִסָּבִֽיב׃"}},"definableWords":["day","LORD"],"peopleInVerse":["Jeremiah"]},"4":{"text":"For thus saith the LORD, Behold, I will make thee a terror to thyself, and to all thy friends: and they shall fall by the sword of their enemies, and thine eyes shall behold it: and I will give all Judah into the hand of the king of Babylon, and he shall carry them captive into Babylon, and shall slay them with the sword.","ref":"Jeremiah 20:4","synthesized":"For this is what the LORD says: ‘I will make you a terror to yourself and to all your friends. They will fall by the sword of their enemies before your very eyes. And I will hand Judah over to the king of Babylon, and he will carry them away to Babylon and put them to the sword.","sources":{"KJV":{"text":"For thus saith the LORD, Behold, I will make thee a terror to thyself, and to all thy friends: and they shall fall by the sword of their enemies, and thine eyes shall behold it: and I will give all Judah into the hand of the king of Babylon, and he shall carry them captive into Babylon, and shall slay them with the sword."},"BSB":{"text":"For this is what the LORD says: ‘I will make you a terror to yourself and to all your friends. They will fall by the sword of their enemies before your very eyes. And I will hand Judah over to the king of Babylon, and he will carry them away to Babylon and put them to the sword."},"TANAKH":{"text":"For thus saith HaShem: Behold, I will make thee a terror to thyself, and to all thy friends; and they shall fall by the sword of their enemies, and thine eyes shall behold it; and I will give all Judah into the hand of the king of Babylon, and he shall carry them captive to Babylon, and shall slay them with the sword."},"HEBREW":{"text":"כִּ֣י כֹ֣ה אָמַ֣ר יְהוָ֡ה הִנְנִי֩ נֹתֶנְךָ֨ לְמָג֜וֹר לְךָ֣ וּלְכָל־אֹהֲבֶ֗יךָ וְנָֽפְל֛וּ בְּחֶ֥רֶב אֹיְבֵיהֶ֖ם וְעֵינֶ֣יךָ רֹא֑וֹת וְאֶת־כָּל־יְהוּדָ֗ה אֶתֵּן֙ בְּיַ֣ד מֶֽלֶךְ־בָּבֶ֔ל וְהִגְלָ֥ם בָּבֶ֖לָה וְהִכָּ֥ם בֶּחָֽרֶב׃"}},"definableWords":["LORD","make","Judah","king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["fall_sin","kingship"]},"5":{"text":"Moreover I will deliver all the strength of this city, and all the labours thereof, and all the precious things thereof, and all the treasures of the kings of Judah will I give into the hand of their enemies, which shall spoil them, and take them, and carry them to Babylon.","ref":"Jeremiah 20:5","synthesized":"I will give away all the wealth of this city—all its products and valuables, and all the treasures of the kings of Judah—to their enemies. They will plunder them, seize them, and carry them off to Babylon.","sources":{"KJV":{"text":"Moreover I will deliver all the strength of this city, and all the labours thereof, and all the precious things thereof, and all the treasures of the kings of Judah will I give into the hand of their enemies, which shall spoil them, and take them, and carry them to Babylon."},"BSB":{"text":"I will give away all the wealth of this city—all its products and valuables, and all the treasures of the kings of Judah—to their enemies. They will plunder them, seize them, and carry them off to Babylon."},"TANAKH":{"text":"Moreover I will give all the store of this city, and all the gains thereof, and all the wealth thereof, yea, all the treasures of the kings of Judah will I give into the hand of their enemies, who shall spoil them, and take them, and carry them to Babylon."},"HEBREW":{"text":"וְנָתַתִּ֗י אֶת־כָּל־חֹ֙סֶן֙ הָעִ֣יר הַזֹּ֔את וְאֶת־כָּל־יְגִיעָ֖הּ וְאֶת־כָּל־יְקָרָ֑הּ וְאֵ֨ת כָּל־אוֹצְר֜וֹת מַלְכֵ֣י יְהוּדָ֗ה אֶתֵּן֙ בְּיַ֣ד אֹֽיְבֵיהֶ֔ם וּבְזָזוּם֙ וּלְקָח֔וּם וֶהֱבִיא֖וּם בָּבֶֽלָה׃"}},"definableWords":["kings","Judah","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"6":{"text":"And thou, Pashur, and all that dwell in thine house shall go into captivity: and thou shalt come to Babylon, and there thou shalt die, and shalt be buried there, thou, and all thy friends, to whom thou hast prophesied lies.","ref":"Jeremiah 20:6","synthesized":"And you, Pashhur, and all who live in your house, will go into captivity. You will go to Babylon, and there you will die and be buried—you and all your friends to whom you have prophesied these lies.’”","sources":{"KJV":{"text":"And thou, Pashur, and all that dwell in thine house shall go into captivity: and thou shalt come to Babylon, and there thou shalt die, and shalt be buried there, thou, and all thy friends, to whom thou hast prophesied lies."},"BSB":{"text":"And you, Pashhur, and all who live in your house, will go into captivity. You will go to Babylon, and there you will die and be buried—you and all your friends to whom you have prophesied these lies.’”"},"TANAKH":{"text":"And thou, Pashhur, and all that dwell in thy house shall go into captivity; and thou shalt come to Babylon, and there thou shalt die, and there shalt thou be buried, thou, and all thy friends, to whom thou hast prophesied falsely.'"},"HEBREW":{"text":"וְאַתָּ֣ה פַשְׁח֗וּר וְכֹל֙ יֹשְׁבֵ֣י בֵיתֶ֔ךָ תֵּלְכ֖וּ בַּשֶּׁ֑בִי וּבָבֶ֣ל תָּב֗וֹא וְשָׁ֤ם תָּמוּת֙ וְשָׁ֣ם תִּקָּבֵ֔ר אַתָּה֙ וְכָל־אֹ֣הֲבֶ֔יךָ אֲשֶׁר־נִבֵּ֥אתָ לָהֶ֖ם בַּשָּֽׁקֶר׃"}},"definableWords":["live","house","Babylon","die"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["exile_return"]},"7":{"text":"O LORD, thou hast deceived me, and I was deceived: thou art stronger than I, and hast prevailed: I am in derision daily, every one mocketh me.","ref":"Jeremiah 20:7","synthesized":"You have deceived me, O LORD, and I was deceived. You have overcome me and prevailed. I am a laughingstock all day long; everyone mocks me.","sources":{"KJV":{"text":"O LORD, thou hast deceived me, and I was deceived: thou art stronger than I, and hast prevailed: I am in derision daily, every one mocketh me."},"BSB":{"text":"You have deceived me, O LORD, and I was deceived. You have overcome me and prevailed. I am a laughingstock all day long; everyone mocks me."},"TANAKH":{"text":"O HaShem, Thou hast enticed me, and I was enticed, Thou hast overcome me, and hast prevailed; I am become a laughing-stock all the day, every one mocketh me."},"HEBREW":{"text":"פִּתִּיתַ֤נִי יְהוָה֙ וֽ͏ָאֶפָּ֔ת חֲזַקְתַּ֖נִי וַתּוּכָ֑ל הָיִ֤יתִי לִשְׂחוֹק֙ כָּל־הַיּ֔וֹם כֻּלֹּ֖ה לֹעֵ֥ג לִֽי׃"}},"definableWords":["LORD","overcome","day"],"peopleInVerse":[]},"8":{"text":"For since I spake, I cried out, I cried violence and spoil; because the word of the LORD was made a reproach unto me, and a derision, daily.","ref":"Jeremiah 20:8","synthesized":"For whenever I speak, I cry out; I proclaim violence and destruction. For the word of the LORD has become to me a reproach and derision all day long.","sources":{"KJV":{"text":"For since I spake, I cried out, I cried violence and spoil; because the word of the LORD was made a reproach unto me, and a derision, daily."},"BSB":{"text":"For whenever I speak, I cry out; I proclaim violence and destruction. For the word of the LORD has become to me a reproach and derision all day long."},"TANAKH":{"text":"For as often as I speak, I cry out, I cry: 'Violence and spoil'; because the word of HaShem is made a reproach unto me, and a derision, all the day."},"HEBREW":{"text":"כִּֽי־מִדֵּ֤י אֲדַבֵּר֙ אֶזְעָ֔ק חָמָ֥ס וָשֹׁ֖ד אֶקְרָ֑א כִּֽי־הָיָ֨ה דְבַר־יְהוָ֥ה לִ֛י לְחֶרְפָּ֥ה וּלְקֶ֖לֶס כָּל־הַיּֽוֹם׃"}},"definableWords":["word","LORD","day"],"peopleInVerse":[]},"9":{"text":"Then I said, I will not make mention of him, nor speak any more in his name. But his word was in mine heart as a burning fire shut up in my bones, and I was weary with forbearing, and I could not stay.","ref":"Jeremiah 20:9","synthesized":"If I say, “I will not mention Him or speak any more in His name,” His message becomes a fire burning in my heart, shut up in my bones, and I become weary of holding it in, and I cannot prevail.","sources":{"KJV":{"text":"Then I said, I will not make mention of him, nor speak any more in his name. But his word was in mine heart as a burning fire shut up in my bones, and I was weary with forbearing, and I could not stay."},"BSB":{"text":"If I say, “I will not mention Him or speak any more in His name,” His message becomes a fire burning in my heart, shut up in my bones, and I become weary of holding it in, and I cannot prevail."},"TANAKH":{"text":"And if I say: 'I will not make mention of Him, nor speak any more in His name', then there is in my heart as it were a burning fire shut up in my bones, and I weary myself to hold it in, but cannot."},"HEBREW":{"text":"וְאָמַרְתִּ֣י לֹֽא־אֶזְכְּרֶ֗נּוּ וְלֹֽא־אֲדַבֵּ֥ר עוֹד֙ בִּשְׁמ֔וֹ וְהָיָ֤ה בְלִבִּי֙ כְּאֵ֣שׁ בֹּעֶ֔רֶת עָצֻ֖ר בְּעַצְמֹתָ֑י וְנִלְאֵ֥יתִי כַּֽלְכֵ֖ל וְלֹ֥א אוּכָֽל׃"}},"definableWords":["or","name","heart","bones"],"peopleInVerse":[]},"10":{"text":"For I heard the defaming of many, fear on every side. Report, say they, and we will report it. All my familiars watched for my halting, saying, Peradventure he will be enticed, and we shall prevail against him, and we shall take our revenge on him.","ref":"Jeremiah 20:10","synthesized":"For I have heard the whispering of many: “Terror is on every side! Report him; let us report him!” All my trusted friends watch for my fall: “Perhaps he will be deceived so that we may prevail against him and take our vengeance upon him.”","sources":{"KJV":{"text":"For I heard the defaming of many, fear on every side. Report, say they, and we will report it. All my familiars watched for my halting, saying, Peradventure he will be enticed, and we shall prevail against him, and we shall take our revenge on him."},"BSB":{"text":"For I have heard the whispering of many: “Terror is on every side! Report him; let us report him!” All my trusted friends watch for my fall: “Perhaps he will be deceived so that we may prevail against him and take our vengeance upon him.”"},"TANAKH":{"text":"For I have heard the whispering of many, terror on every side: 'Denounce, and we will denounce him'; even of all my familiar friends, them that watch for my halting: 'Peradventure he will be enticed, and we shall prevail against him, and we shall take our revenge on him.'"},"HEBREW":{"text":"כִּ֣י שָׁמַ֜עְתִּי דִּבַּ֣ת רַבִּים֮ מָג֣וֹר מִסָּבִיב֒ הַגִּ֙ידוּ֙ וְנַגִּידֶ֔נּוּ כֹּ֚ל אֱנ֣וֹשׁ שְׁלוֹמִ֔י שֹׁמְרֵ֖י צַלְעִ֑י אוּלַ֤י יְפֻתֶּה֙ וְנ֣וּכְלָה ל֔וֹ וְנִקְחָ֥ה נִקְמָתֵ֖נוּ מִמֶּֽנּוּ׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"11":{"text":"But the LORD is with me as a mighty terrible one: therefore my persecutors shall stumble, and they shall not prevail: they shall be greatly ashamed; for they shall not prosper: their everlasting confusion shall never be forgotten.","ref":"Jeremiah 20:11","synthesized":"But the LORD is with me like a fearsome warrior. Therefore, my persecutors will stumble and will not prevail. Since they have not succeeded, they will be utterly put to shame, with an everlasting disgrace that will never be forgotten.","sources":{"KJV":{"text":"But the LORD is with me as a mighty terrible one: therefore my persecutors shall stumble, and they shall not prevail: they shall be greatly ashamed; for they shall not prosper: their everlasting confusion shall never be forgotten."},"BSB":{"text":"But the LORD is with me like a fearsome warrior. Therefore, my persecutors will stumble and will not prevail. Since they have not succeeded, they will be utterly put to shame, with an everlasting disgrace that will never be forgotten."},"TANAKH":{"text":"But HaShem is with me as a mighty warrior; therefore my persecutors shall stumble, and they shall not prevail; they shall be greatly ashamed, because they have not prospered, even with an everlasting confusion which shall never be forgotten."},"HEBREW":{"text":"וַֽיהוָ֤ה אוֹתִי֙ כְּגִבּ֣וֹר עָרִ֔יץ עַל־כֵּ֛ן רֹדְפַ֥י יִכָּשְׁל֖וּ וְלֹ֣א יֻכָ֑לוּ בֹּ֤שׁוּ מְאֹד֙ כִּֽי־לֹ֣א הִשְׂכִּ֔ילוּ כְּלִמַּ֥ת עוֹלָ֖ם לֹ֥א תִשָּׁכֵֽחַ׃"}},"definableWords":["LORD","everlasting"],"peopleInVerse":[]},"12":{"text":"But, O LORD of hosts, that triest the righteous, and seest the reins and the heart, let me see thy vengeance on them: for unto thee have I opened my cause.","ref":"Jeremiah 20:12","synthesized":"O LORD of Hosts, who examines the righteous, who sees the heart and mind, let me see Your vengeance upon them, for to You I have committed my cause.","sources":{"KJV":{"text":"But, O LORD of hosts, that triest the righteous, and seest the reins and the heart, let me see thy vengeance on them: for unto thee have I opened my cause."},"BSB":{"text":"O LORD of Hosts, who examines the righteous, who sees the heart and mind, let me see Your vengeance upon them, for to You I have committed my cause."},"TANAKH":{"text":"But, O HaShem of hosts, that triest the righteous, that seest the reins and the heart, let me see Thy vengeance on them; for unto Thee have I revealed my cause."},"HEBREW":{"text":"וַיהוָ֤ה צְבָאוֹת֙ בֹּחֵ֣ן צַדִּ֔יק רֹאֶ֥ה כְלָי֖וֹת וָלֵ֑ב אֶרְאֶ֤ה נִקְמָֽתְךָ֙ מֵהֶ֔ם כִּ֥י אֵלֶ֖יךָ גִּלִּ֥יתִי אֶת־רִיבִֽי׃"}},"definableWords":["LORD","righteous","heart","mind","see"],"peopleInVerse":[]},"13":{"text":"Sing unto the LORD, praise ye the LORD: for he hath delivered the soul of the poor from the hand of evildoers.","ref":"Jeremiah 20:13","synthesized":"Sing to the LORD! Praise the LORD! For He rescues the life of the needy from the hands of evildoers.","sources":{"KJV":{"text":"Sing unto the LORD, praise ye the LORD: for he hath delivered the soul of the poor from the hand of evildoers."},"BSB":{"text":"Sing to the LORD! Praise the LORD! For He rescues the life of the needy from the hands of evildoers."},"TANAKH":{"text":"Sing unto HaShem, praise ye HaShem; for He hath delivered the soul of the needy from the hand of evil-doers."},"HEBREW":{"text":"שִׁ֚ירוּ לַֽיהוָ֔ה הַֽלְל֖וּ אֶת־יְהוָ֑ה כִּ֥י הִצִּ֛יל אֶת־נֶ֥פֶשׁ אֶבְי֖וֹן מִיַּ֥ד מְרֵעִֽים׃"}},"definableWords":["LORD","praise","Lord","life"],"peopleInVerse":[],"themesInVerse":["worship"]},"14":{"text":"Cursed be the day wherein I was born: let not the day wherein my mother bare me be blessed.","ref":"Jeremiah 20:14","synthesized":"Cursed be the day I was born! May the day my mother bore me never be blessed.","sources":{"KJV":{"text":"Cursed be the day wherein I was born: let not the day wherein my mother bare me be blessed."},"BSB":{"text":"Cursed be the day I was born! May the day my mother bore me never be blessed."},"TANAKH":{"text":"Cursed be the day wherein I was born; the day wherein my mother bore me, let it not be blessed."},"HEBREW":{"text":"אָר֣וּר הַיּ֔וֹם אֲשֶׁ֥ר יֻלַּ֖דְתִּי בּ֑וֹ י֛וֹם אֲשֶׁר־יְלָדַ֥תְנִי אִמִּ֖י אַל־יְהִ֥י בָרֽוּךְ׃"}},"definableWords":["cursed","day","mother","blessed"],"peopleInVerse":[]},"15":{"text":"Cursed be the man who brought tidings to my father, saying, A man child is born unto thee; making him very glad.","ref":"Jeremiah 20:15","synthesized":"Cursed be the man who brought my father the news, saying, “A son is born to you,” bringing him great joy.","sources":{"KJV":{"text":"Cursed be the man who brought tidings to my father, saying, A man child is born unto thee; making him very glad."},"BSB":{"text":"Cursed be the man who brought my father the news, saying, “A son is born to you,” bringing him great joy."},"TANAKH":{"text":"Cursed be the man who brought tidings to my father, saying: 'A man-child is born unto thee'; making him very glad."},"HEBREW":{"text":"אָר֣וּר הָאִ֗ישׁ אֲשֶׁ֨ר בִּשַּׂ֤ר אֶת־אָבִי֙ לֵאמֹ֔ר יֻֽלַּד־לְךָ֖ בֵּ֣ן זָכָ֑ר שַׂמֵּ֖חַ שִׂמֳּחָֽהוּ׃"}},"definableWords":["cursed","man","father","son","great","joy"],"peopleInVerse":[],"themesInVerse":["joy"]},"16":{"text":"And let that man be as the cities which the LORD overthrew, and repented not: and let him hear the cry in the morning, and the shouting at noontide;","ref":"Jeremiah 20:16","synthesized":"May that man be like the cities that the LORD overthrew without compassion. May he hear an outcry in the morning and a battle cry at noon,","sources":{"KJV":{"text":"And let that man be as the cities which the LORD overthrew, and repented not: and let him hear the cry in the morning, and the shouting at noontide;"},"BSB":{"text":"May that man be like the cities that the LORD overthrew without compassion. May he hear an outcry in the morning and a battle cry at noon,"},"TANAKH":{"text":"And let that man be as the cities which HaShem overthrew, and repented not; and let him hear a cry in the morning, and an alarm at noontide;"},"HEBREW":{"text":"וְהָיָה֙ הָאִ֣ישׁ הַה֔וּא כֶּֽעָרִ֛ים אֲשֶׁר־הָפַ֥ךְ יְהוָ֖ה וְלֹ֣א נִחָ֑ם וְשָׁמַ֤ע זְעָקָה֙ בַּבֹּ֔קֶר וּתְרוּעָ֖ה בְּעֵ֥ת צָהֳרָֽיִם׃"}},"definableWords":["man","LORD","hear"],"peopleInVerse":[],"themesInVerse":["spiritual_warfare"]},"17":{"text":"Because he slew me not from the womb; or that my mother might have been my grave, and her womb to be always great with me.","ref":"Jeremiah 20:17","synthesized":"because he did not kill me in the womb so that my mother might have been my grave, and her womb forever enlarged.","sources":{"KJV":{"text":"Because he slew me not from the womb; or that my mother might have been my grave, and her womb to be always great with me."},"BSB":{"text":"because he did not kill me in the womb so that my mother might have been my grave, and her womb forever enlarged."},"TANAKH":{"text":"Because He slew me not from the womb; and so my mother would have been my grave, and her womb always great."},"HEBREW":{"text":"אֲשֶׁ֥ר לֹא־מוֹתְתַ֖נִי מֵרָ֑חֶם וַתְּהִי־לִ֤י אִמִּי֙ קִבְרִ֔י וְרַחְמָ֖הֿ הֲרַ֥ת עוֹלָֽם׃"}},"definableWords":["mother"],"peopleInVerse":[]},"18":{"text":"Wherefore came I forth out of the womb to see labour and sorrow, that my days should be consumed with shame?","ref":"Jeremiah 20:18","synthesized":"Why did I come out of the womb to see only trouble and sorrow, and to end my days in shame?","sources":{"KJV":{"text":"Wherefore came I forth out of the womb to see labour and sorrow, that my days should be consumed with shame?"},"BSB":{"text":"Why did I come out of the womb to see only trouble and sorrow, and to end my days in shame?"},"TANAKH":{"text":"Wherefore came I forth out of the womb to see labour and sorrow, that my days should be consumed in shame?"},"HEBREW":{"text":"לָ֤מָּה זֶּה֙ מֵרֶ֣חֶם יָצָ֔אתִי לִרְא֥וֹת עָמָ֖ל וְיָג֑וֹן וַיִּכְל֥וּ בְּבֹ֖שֶׁת יָמָֽי׃"}},"definableWords":["see","days"],"peopleInVerse":[]}}},"21":{"chapter":"21","title":"ZEDEKIAH'S INQUIRY","verses":{"1":{"text":"The word which came unto Jeremiah from the LORD, when king Zedekiah sent unto him Pashur the son of Melchiah, and Zephaniah the son of Maaseiah the priest, saying,","ref":"Jeremiah 21:1","synthesized":"This is the word that came to Jeremiah from the LORD when King Zedekiah sent to him Pashhur son of Malchijah and the priest Zephaniah son of Maaseiah. They said,","sources":{"KJV":{"text":"The word which came unto Jeremiah from the LORD, when king Zedekiah sent unto him Pashur the son of Melchiah, and Zephaniah the son of Maaseiah the priest, saying,"},"BSB":{"text":"This is the word that came to Jeremiah from the LORD when King Zedekiah sent to him Pashhur son of Malchijah and the priest Zephaniah son of Maaseiah. They said,"},"TANAKH":{"text":"The word which came unto Jeremiah from HaShem, when king Zedekiah sent unto him Pashhur the son of Malchiah, and Zephaniah the son of Maaseiah the priest, saying:"},"HEBREW":{"text":"הַדָּבָ֛ר אֲשֶׁר־הָיָ֥ה אֶֽל־יִרְמְיָ֖הוּ מֵאֵ֣ת יְהוָ֑ה בִּשְׁלֹ֨חַ אֵלָ֜יו הַמֶּ֣לֶךְ צִדְקִיָּ֗הוּ אֶת־פַּשְׁחוּר֙ בֶּן־מַלְכִּיָּ֔ה וְאֶת־צְפַנְיָ֧ה בֶן־מַעֲשֵׂיָ֛ה הַכֹּהֵ֖ן לֵאמֹֽר׃"}},"definableWords":["word","LORD","King","son","priest","Son"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingdom_priesthood","kingship"]},"2":{"text":"Enquire, I pray thee, of the LORD for us; for Nebuchadrezzar king of Babylon maketh war against us; if so be that the LORD will deal with us according to all his wondrous works, that he may go up from us.","ref":"Jeremiah 21:2","synthesized":"“Please inquire of the LORD on our behalf, since Nebuchadnezzar king of Babylon is waging war against us. Perhaps the LORD will perform for us something like all His past wonders, so that Nebuchadnezzar will withdraw from us.”","sources":{"KJV":{"text":"Enquire, I pray thee, of the LORD for us; for Nebuchadrezzar king of Babylon maketh war against us; if so be that the LORD will deal with us according to all his wondrous works, that he may go up from us."},"BSB":{"text":"“Please inquire of the LORD on our behalf, since Nebuchadnezzar king of Babylon is waging war against us. Perhaps the LORD will perform for us something like all His past wonders, so that Nebuchadnezzar will withdraw from us.”"},"TANAKH":{"text":"'Inquire, I pray thee, of HaShem for us; for Nebuchadrezzar king of Babylon maketh war against us; peradventure HaShem will deal with us according to all His wondrous works, that he may go up from us.'"},"HEBREW":{"text":"דְּרָשׁ־נָ֤א בַעֲדֵ֙נוּ֙ אֶת־יְהוָ֔ה כִּ֛י נְבוּכַדְרֶאצַּ֥ר מֶֽלֶךְ־בָּבֶ֖ל נִלְחָ֣ם עָלֵ֑ינוּ אוּלַי֩ יַעֲשֶׂ֨ה יְהוָ֤ה אוֹתָ֙נוּ֙ כְּכָל־נִפְלְאֹתָ֔יו וְיַעֲלֶ֖ה מֵעָלֵֽינוּ׃"}},"definableWords":["LORD","king","Babylon","Lord"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"3":{"text":"Then said Jeremiah unto them, Thus shall ye say to Zedekiah:","ref":"Jeremiah 21:3","synthesized":"But Jeremiah answered, “You are to tell Zedekiah that","sources":{"KJV":{"text":"Then said Jeremiah unto them, Thus shall ye say to Zedekiah:"},"BSB":{"text":"But Jeremiah answered, “You are to tell Zedekiah that"},"TANAKH":{"text":"Then said Jeremiah unto them: Thus shall ye say to Zedekiah:"},"HEBREW":{"text":"וַיֹּ֥אמֶר יִרְמְיָ֖הוּ אֲלֵיהֶ֑ם כֹּ֥ה תֹאמְרֻ֖ן אֶל־צִדְקִיָּֽהוּ׃"}},"definableWords":[],"peopleInVerse":["Jeremiah"]},"4":{"text":"Thus saith the LORD God of Israel; Behold, I will turn back the weapons of war that are in your hands, wherewith ye fight against the king of Babylon, and against the Chaldeans, which besiege you without the walls, and I will assemble them into the midst of this city.","ref":"Jeremiah 21:4","synthesized":"this is what the LORD, the God of Israel, says: ‘I will turn against you the weapons of war in your hands, with which you are fighting the king of Babylon and the Chaldeans who besiege you outside the wall, and I will assemble their forces in the center of this city.","sources":{"KJV":{"text":"Thus saith the LORD God of Israel; Behold, I will turn back the weapons of war that are in your hands, wherewith ye fight against the king of Babylon, and against the Chaldeans, which besiege you without the walls, and I will assemble them into the midst of this city."},"BSB":{"text":"this is what the LORD, the God of Israel, says: ‘I will turn against you the weapons of war in your hands, with which you are fighting the king of Babylon and the Chaldeans who besiege you outside the wall, and I will assemble their forces in the center of this city."},"TANAKH":{"text":"Thus saith HaShem, the G-d of Israel: Behold, I will turn back the weapons of war that are in your hands, wherewith ye fight against the king of Babylon, and against the Chaldeans, that besiege you without the walls, and I will gather them into the midst of this city."},"HEBREW":{"text":"כֹּֽה־אָמַ֨ר יְהוָ֜ה אֱלֹהֵ֣י יִשְׂרָאֵ֗ל הִנְנִ֣י מֵסֵב֮ אֶת־כְּלֵ֣י הַמִּלְחָמָה֮ אֲשֶׁ֣ר בְּיֶדְכֶם֒ אֲשֶׁ֨ר אַתֶּ֜ם נִלְחָמִ֣ים בָּ֗ם אֶת־מֶ֤לֶךְ בָּבֶל֙ וְאֶת־הַכַּשְׂדִּ֔ים הַצָּרִ֣ים עֲלֵיכֶ֔ם מִח֖וּץ לַֽחוֹמָ֑ה וְאָסַפְתִּ֣י אוֹתָ֔ם אֶל־תּ֖וֹךְ הָעִ֥יר הַזֹּֽאת׃"}},"definableWords":["LORD","God","Israel","king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"5":{"text":"And I myself will fight against you with an outstretched hand and with a strong arm, even in anger, and in fury, and in great wrath.","ref":"Jeremiah 21:5","synthesized":"And I Myself will fight against you with an outstretched hand and a mighty arm, with anger, fury, and great wrath.","sources":{"KJV":{"text":"And I myself will fight against you with an outstretched hand and with a strong arm, even in anger, and in fury, and in great wrath."},"BSB":{"text":"And I Myself will fight against you with an outstretched hand and a mighty arm, with anger, fury, and great wrath."},"TANAKH":{"text":"And I myself will fight against you with an outstretched hand and with a strong arm, even in anger, and in fury, and in great wrath."},"HEBREW":{"text":"וְנִלְחַמְתִּ֤י אֲנִי֙ אִתְּכֶ֔ם בְּיָ֥ד נְטוּיָ֖ה וּבִזְר֣וֹעַ חֲזָקָ֑ה וּבְאַ֥ף וּבְחֵמָ֖ה וּבְקֶ֥צֶף גָּדֽוֹל׃"}},"definableWords":["fight","mighty","anger","great","wrath"],"peopleInVerse":[],"themesInVerse":["judgment","spiritual_warfare"]},"6":{"text":"And I will smite the inhabitants of this city, both man and beast: they shall die of a great pestilence.","ref":"Jeremiah 21:6","synthesized":"I will strike down the residents of this city, both man and beast. They will die in a terrible plague.’","sources":{"KJV":{"text":"And I will smite the inhabitants of this city, both man and beast: they shall die of a great pestilence."},"BSB":{"text":"I will strike down the residents of this city, both man and beast. They will die in a terrible plague.’"},"TANAKH":{"text":"And I will smite the inhabitants of this city, both man and beast; they shall die of a great pestilence."},"HEBREW":{"text":"וְהִכֵּיתִ֗י אֶת־יֽוֹשְׁבֵי֙ הָעִ֣יר הַזֹּ֔את וְאֶת־הָאָדָ֖ם וְאֶת־הַבְּהֵמָ֑ה בְּדֶ֥בֶר גָּד֖וֹל יָמֻֽתוּ׃"}},"definableWords":["man","die"],"peopleInVerse":[]},"7":{"text":"And afterward, saith the LORD, I will deliver Zedekiah king of Judah, and his servants, and the people, and such as are left in this city from the pestilence, from the sword, and from the famine, into the hand of Nebuchadrezzar king of Babylon, and into the hand of their enemies, and into the hand of those that seek their life: and he shall smite them with the edge of the sword; he shall not spare them, neither have pity, nor have mercy.","ref":"Jeremiah 21:7","synthesized":"‘After that,’ declares the LORD, ‘I will hand over Zedekiah king of Judah, his officers, and the people in this city who survive the plague and sword and famine, to Nebuchadnezzar king of Babylon and to their enemies who seek their lives. He will put them to the sword; he will not spare them or show pity or compassion.’","sources":{"KJV":{"text":"And afterward, saith the LORD, I will deliver Zedekiah king of Judah, and his servants, and the people, and such as are left in this city from the pestilence, from the sword, and from the famine, into the hand of Nebuchadrezzar king of Babylon, and into the hand of their enemies, and into the hand of those that seek their life: and he shall smite them with the edge of the sword; he shall not spare them, neither have pity, nor have mercy."},"BSB":{"text":"‘After that,’ declares the LORD, ‘I will hand over Zedekiah king of Judah, his officers, and the people in this city who survive the plague and sword and famine, to Nebuchadnezzar king of Babylon and to their enemies who seek their lives. He will put them to the sword; he will not spare them or show pity or compassion.’"},"TANAKH":{"text":"And afterward, saith HaShem, I will deliver Zedekiah king of Judah, and his servants, and the people, and such as are left in this city from the pestilence, from the sword, and from the famine, into the hand of Nebuchadrezzar king of Babylon, and into the hand of their enemies, and into the hand of those that seek their life; and he shall smite them with the edge of the sword; he shall not spare them, neither have pity, nor have compassion."},"HEBREW":{"text":"וְאַחֲרֵי־כֵ֣ן נְאֻם־יְהוָ֡ה אֶתֵּ֣ן אֶת־צִדְקִיָּ֣הוּ מֶֽלֶךְ־יְהוּדָ֣ה וְאֶת־עֲבָדָ֣יו ׀ וְאֶת־הָעָ֡ם וְאֶת־הַנִּשְׁאָרִים֩ בָּעִ֨יר הַזֹּ֜את מִן־הַדֶּ֣בֶר ׀ מִן־הַחֶ֣רֶב וּמִן־הָרָעָ֗ב בְּיַד֙ נְבוּכַדְרֶאצַּ֣ר מֶֽלֶךְ־בָּבֶ֔ל וּבְיַד֙ אֹֽיְבֵיהֶ֔ם וּבְיַ֖ד מְבַקְשֵׁ֣י נַפְשָׁ֑ם וְהִכָּ֣ם לְפִי־חֶ֔רֶב לֹֽא־יָח֣וּס עֲלֵיהֶ֔ם וְלֹ֥א יַחְמֹ֖ל וְלֹ֥א יְרַחֵֽם׃"}},"definableWords":["LORD","king","Judah","people","King","Babylon","seek","or"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"8":{"text":"And unto this people thou shalt say, Thus saith the LORD; Behold, I set before you the way of life, and the way of death.","ref":"Jeremiah 21:8","synthesized":"Furthermore, you are to tell this people that this is what the LORD says: ‘Behold, I set before you the way of life and the way of death.","sources":{"KJV":{"text":"And unto this people thou shalt say, Thus saith the LORD; Behold, I set before you the way of life, and the way of death."},"BSB":{"text":"Furthermore, you are to tell this people that this is what the LORD says: ‘Behold, I set before you the way of life and the way of death."},"TANAKH":{"text":"And unto this people thou shalt say: Thus saith HaShem: Behold, I set before you the way of life and the way of death."},"HEBREW":{"text":"וְאֶל־הָעָ֤ם הַזֶּה֙ תֹּאמַ֔ר כֹּ֖ה אָמַ֣ר יְהוָ֑ה הִנְנִ֤י נֹתֵן֙ לִפְנֵיכֶ֔ם אֶת־דֶּ֥רֶךְ הַחַיִּ֖ים וְאֶת־דֶּ֥רֶךְ הַמָּֽוֶת׃"}},"definableWords":["people","LORD","way","life","death"],"peopleInVerse":[]},"9":{"text":"He that abideth in this city shall die by the sword, and by the famine, and by the pestilence: but he that goeth out, and falleth to the Chaldeans that besiege you, he shall live, and his life shall be unto him for a prey.","ref":"Jeremiah 21:9","synthesized":"Whoever stays in this city will die by sword and famine and plague, but whoever goes out and surrenders to the Chaldeans who besiege you will live; he will retain his life like a spoil of war.","sources":{"KJV":{"text":"He that abideth in this city shall die by the sword, and by the famine, and by the pestilence: but he that goeth out, and falleth to the Chaldeans that besiege you, he shall live, and his life shall be unto him for a prey."},"BSB":{"text":"Whoever stays in this city will die by sword and famine and plague, but whoever goes out and surrenders to the Chaldeans who besiege you will live; he will retain his life like a spoil of war."},"TANAKH":{"text":"He that abideth in this city shall die by the sword, and by the famine, and by the pestilence; but he that goeth out, and falleth away to the Chaldeans that besiege you, he shall live, and his life shall be unto him for a prey."},"HEBREW":{"text":"הַיֹּשֵׁב֙ בָּעִ֣יר הַזֹּ֔את יָמ֕וּת בַּחֶ֖רֶב וּבָרָעָ֣ב וּבַדָּ֑בֶר וְהַיּוֹצֵא֩ וְנָפַ֨ל עַל־הַכַּשְׂדִּ֜ים הַצָּרִ֤ים עֲלֵיכֶם֙ יחיה וְחָיָ֔ה וְהָֽיְתָה־לּ֥וֹ נַפְשׁ֖וֹ לְשָׁלָֽל׃"}},"definableWords":["die","live","life"],"peopleInVerse":[]},"10":{"text":"For I have set my face against this city for evil, and not for good, saith the LORD: it shall be given into the hand of the king of Babylon, and he shall burn it with fire.","ref":"Jeremiah 21:10","synthesized":"For I have set My face against this city to bring disaster and not good, declares the LORD. It will be delivered into the hand of the king of Babylon, who will destroy it with fire.’","sources":{"KJV":{"text":"For I have set my face against this city for evil, and not for good, saith the LORD: it shall be given into the hand of the king of Babylon, and he shall burn it with fire."},"BSB":{"text":"For I have set My face against this city to bring disaster and not good, declares the LORD. It will be delivered into the hand of the king of Babylon, who will destroy it with fire.’"},"TANAKH":{"text":"For I have set My face against this city for evil, and not for good, saith HaShem; it shall be given into the hand of the king of Babylon, and he shall burn it with fire."},"HEBREW":{"text":"כִּ֣י שַׂ֣מְתִּי פָ֠נַי בָּעִ֨יר הַזֹּ֧את לְרָעָ֛ה וְלֹ֥א לְטוֹבָ֖ה נְאֻם־יְהוָ֑ה בְּיַד־מֶ֤לֶךְ בָּבֶל֙ תִּנָּתֵ֔ן וּשְׂרָפָ֖הּ בָּאֵֽשׁ׃"}},"definableWords":["good","LORD","king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"11":{"text":"And touching the house of the king of Judah, say, Hear ye the word of the LORD;","ref":"Jeremiah 21:11","synthesized":"Moreover, tell the house of the king of Judah to hear the word of the LORD.","sources":{"KJV":{"text":"And touching the house of the king of Judah, say, Hear ye the word of the LORD;"},"BSB":{"text":"Moreover, tell the house of the king of Judah to hear the word of the LORD."},"TANAKH":{"text":"And unto the house of the king of Judah: Hear ye the word of HaShem;"},"HEBREW":{"text":"וּלְבֵית֙ מֶ֣לֶךְ יְהוּדָ֔ה שִׁמְע֖וּ דְּבַר־יְהוָֽה׃"}},"definableWords":["house","king","Judah","hear","word","LORD"],"peopleInVerse":[],"themesInVerse":["kingship"]},"12":{"text":"O house of David, thus saith the LORD; Execute judgment in the morning, and deliver him that is spoiled out of the hand of the oppressor, lest my fury go out like fire, and burn that none can quench it, because of the evil of your doings.","ref":"Jeremiah 21:12","synthesized":"O house of David, this is what the LORD says:  ‘Administer justice every morning, and rescue the victim of robbery from the hand of his oppressor, or My wrath will go forth like fire and burn with no one to extinguish it because of their evil deeds.","sources":{"KJV":{"text":"O house of David, thus saith the LORD; Execute judgment in the morning, and deliver him that is spoiled out of the hand of the oppressor, lest my fury go out like fire, and burn that none can quench it, because of the evil of your doings."},"BSB":{"text":"O house of David, this is what the LORD says:  ‘Administer justice every morning, and rescue the victim of robbery from the hand of his oppressor, or My wrath will go forth like fire and burn with no one to extinguish it because of their evil deeds."},"TANAKH":{"text":"O house of David, thus saith HaShem: Execute justice in the morning, and deliver the spoiled out of the hand of the oppressor, lest My fury go forth like fire, and burn that none can quench it, because of the evil of your doings."},"HEBREW":{"text":"בֵּ֣ית דָּוִ֗ד כֹּ֚ה אָמַ֣ר יְהוָ֔ה דִּ֤ינוּ לַבֹּ֙קֶר֙ מִשְׁפָּ֔ט וְהַצִּ֥ילוּ גָז֖וּל מִיַּ֣ד עוֹשֵׁ֑ק פֶּן־תֵּצֵ֨א כָאֵ֜שׁ חֲמָתִ֗י וּבָעֲרָה֙ וְאֵ֣ין מְכַבֶּ֔ה מִפְּנֵ֖י רֹ֥עַ מעלליהם מַעַלְלֵיכֶֽם׃"}},"definableWords":["house","LORD","justice","or","wrath","one","evil"],"peopleInVerse":["David"],"themesInVerse":["judgment","salvation"]},"13":{"text":"Behold, I am against thee, O inhabitant of the valley, and rock of the plain, saith the LORD; which say, Who shall come down against us? or who shall enter into our habitations?","ref":"Jeremiah 21:13","synthesized":"Behold, I am against you who dwell above the valley, atop the rocky plateau— declares the LORD— you who say, “Who can come against us? Who can enter our dwellings?”","sources":{"KJV":{"text":"Behold, I am against thee, O inhabitant of the valley, and rock of the plain, saith the LORD; which say, Who shall come down against us? or who shall enter into our habitations?"},"BSB":{"text":"Behold, I am against you who dwell above the valley, atop the rocky plateau— declares the LORD— you who say, “Who can come against us? Who can enter our dwellings?”"},"TANAKH":{"text":"Behold, I am against thee, O inhabitant of the valley, and rock of the plain, saith HaShem; ye that say: 'Who shall come down against us? or who shall enter into our habitations?'"},"HEBREW":{"text":"הִנְנִ֨י אֵלַ֜יִךְ יֹשֶׁ֧בֶת הָעֵ֛מֶק צ֥וּר הַמִּישֹׁ֖ר נְאֻם־יְהוָ֑ה הָאֹֽמְרִים֙ מִֽי־יֵחַ֣ת עָלֵ֔ינוּ וּמִ֥י יָב֖וֹא בִּמְעוֹנוֹתֵֽינוּ׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"14":{"text":"But I will punish you according to the fruit of your doings, saith the LORD: and I will kindle a fire in the forest thereof, and it shall devour all things round about it.","ref":"Jeremiah 21:14","synthesized":"I will punish you as your deeds deserve, declares the LORD. I will kindle a fire in your forest that will consume everything around you.’”","sources":{"KJV":{"text":"But I will punish you according to the fruit of your doings, saith the LORD: and I will kindle a fire in the forest thereof, and it shall devour all things round about it."},"BSB":{"text":"I will punish you as your deeds deserve, declares the LORD. I will kindle a fire in your forest that will consume everything around you.’”"},"TANAKH":{"text":"And I will punish you according to the fruit of your doings, saith HaShem; and I will kindle a fire in her forest, and it shall devour all that is round about her."},"HEBREW":{"text":"וּפָקַדְתִּ֧י עֲלֵיכֶ֛ם כִּפְרִ֥י מַעַלְלֵיכֶ֖ם נְאֻם־יְהוָ֑ה וְהִצַּ֤תִּי אֵשׁ֙ בְּיַעְרָ֔הּ וְאָכְלָ֖ה כָּל־סְבִיבֶֽיהָ׃"}},"definableWords":["LORD"],"peopleInVerse":[]}}},"22":{"chapter":"22","title":"WOE TO THE KINGS OF JUDAH","verses":{"1":{"text":"Thus saith the LORD; Go down to the house of the king of Judah, and speak there this word,","ref":"Jeremiah 22:1","synthesized":"This is what the LORD says: “Go down to the palace of the king of Judah and proclaim this message there,","sources":{"KJV":{"text":"Thus saith the LORD; Go down to the house of the king of Judah, and speak there this word,"},"BSB":{"text":"This is what the LORD says: “Go down to the palace of the king of Judah and proclaim this message there,"},"TANAKH":{"text":"Thus said HaShem: Go down to the house of the king of Judah, and speak there this word,"},"HEBREW":{"text":"כֹּ֚ה אָמַ֣ר יְהוָ֔ה רֵ֖ד בֵּֽית־מֶ֣לֶךְ יְהוּדָ֑ה וְדִבַּרְתָּ֣ שָׁ֔ם אֶת־הַדָּבָ֖ר הַזֶּֽה׃"}},"definableWords":["LORD","king","Judah"],"peopleInVerse":[],"themesInVerse":["kingship"]},"2":{"text":"And say, Hear the word of the LORD, O king of Judah, that sittest upon the throne of David, thou, and thy servants, and thy people that enter in by these gates:","ref":"Jeremiah 22:2","synthesized":"saying, ‘Hear the word of the LORD, O king of Judah, who sits on the throne of David—you and your officials and your people who enter these gates.","sources":{"KJV":{"text":"And say, Hear the word of the LORD, O king of Judah, that sittest upon the throne of David, thou, and thy servants, and thy people that enter in by these gates:"},"BSB":{"text":"saying, ‘Hear the word of the LORD, O king of Judah, who sits on the throne of David—you and your officials and your people who enter these gates."},"TANAKH":{"text":"and say: Hear the word of HaShem, O king of Judah, that sittest upon the throne of David, thou, and thy servants, and thy people that enter in by these gates."},"HEBREW":{"text":"וְאָֽמַרְתָּ֙ שְׁמַ֣ע דְּבַר־יְהוָ֔ה מֶ֣לֶךְ יְהוּדָ֔ה הַיֹּשֵׁ֖ב עַל־כִּסֵּ֣א דָוִ֑ד אַתָּ֤ה וַעֲבָדֶ֙יךָ֙ וְעַמְּךָ֔ הַבָּאִ֖ים בַּשְּׁעָרִ֥ים הָאֵֽלֶּה׃"}},"definableWords":["hear","word","LORD","king","Judah","throne","people"],"peopleInVerse":["David"],"themesInVerse":["kingdom_of_god","kingship"]},"3":{"text":"Thus saith the LORD; Execute ye judgment and righteousness, and deliver the spoiled out of the hand of the oppressor: and do no wrong, do no violence to the stranger, the fatherless, nor the widow, neither shed innocent blood in this place.","ref":"Jeremiah 22:3","synthesized":"This is what the LORD says: Administer justice and righteousness. Rescue the victim of robbery from the hand of his oppressor. Do no wrong or violence to the foreigner, the fatherless, or the widow. Do not shed innocent blood in this place.","sources":{"KJV":{"text":"Thus saith the LORD; Execute ye judgment and righteousness, and deliver the spoiled out of the hand of the oppressor: and do no wrong, do no violence to the stranger, the fatherless, nor the widow, neither shed innocent blood in this place."},"BSB":{"text":"This is what the LORD says: Administer justice and righteousness. Rescue the victim of robbery from the hand of his oppressor. Do no wrong or violence to the foreigner, the fatherless, or the widow. Do not shed innocent blood in this place."},"TANAKH":{"text":"Thus saith HaShem: Execute ye justice and righteousness, and deliver the spoiled out of the hand of the oppressor; and do no wrong, do no violence, to the stranger, the fatherless, nor the widow, neither shed innocent blood in this place."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה עֲשׂ֤וּ מִשְׁפָּט֙ וּצְדָקָ֔ה וְהַצִּ֥ילוּ גָז֖וּל מִיַּ֣ד עָשׁ֑וֹק וְגֵר֩ יָת֨וֹם וְאַלְמָנָ֤ה אַל־תֹּנוּ֙ אַל־תַּחְמֹ֔סוּ וְדָ֣ם נָקִ֔י אַֽל־תִּשְׁפְּכ֖וּ בַּמָּק֥וֹם הַזֶּֽה׃"}},"definableWords":["LORD","justice","righteousness","or","widow","blood"],"peopleInVerse":[],"themesInVerse":["passover","sacrifice","salvation"]},"4":{"text":"For if ye do this thing indeed, then shall there enter in by the gates of this house kings sitting upon the throne of David, riding in chariots and on horses, he, and his servants, and his people.","ref":"Jeremiah 22:4","synthesized":"For if you will indeed carry out these commands, then kings who sit on David’s throne will enter through the gates of this palace riding on chariots and horses—they and their officials and their people.","sources":{"KJV":{"text":"For if ye do this thing indeed, then shall there enter in by the gates of this house kings sitting upon the throne of David, riding in chariots and on horses, he, and his servants, and his people."},"BSB":{"text":"For if you will indeed carry out these commands, then kings who sit on David’s throne will enter through the gates of this palace riding on chariots and horses—they and their officials and their people."},"TANAKH":{"text":"For if ye do this thing indeed, then shall there enter in by the gates of this house kings sitting upon the throne of David, riding in chariots and on horses, he, and his servants, and his people."},"HEBREW":{"text":"כִּ֤י אִם־עָשׂוֹ֙ תַּֽעֲשׂ֔וּ אֶת־הַדָּבָ֖ר הַזֶּ֑ה וּבָ֣אוּ בְשַׁעֲרֵ֣י הַבַּ֣יִת הַזֶּ֡ה מְלָכִים֩ יֹשְׁבִ֨ים לְדָוִ֜ד עַל־כִּסְא֗וֹ רֹֽכְבִים֙ בָּרֶ֣כֶב וּבַסּוּסִ֔ים ה֥וּא ועבדו וַעֲבָדָ֖יו וְעַמּֽוֹ׃"}},"definableWords":["kings","throne","people"],"peopleInVerse":["David"],"themesInVerse":["kingdom_of_god","kingship"]},"5":{"text":"But if ye will not hear these words, I swear by myself, saith the LORD, that this house shall become a desolation.","ref":"Jeremiah 22:5","synthesized":"But if you do not obey these words, then I swear by Myself, declares the LORD, that this house will become a pile of rubble.’”","sources":{"KJV":{"text":"But if ye will not hear these words, I swear by myself, saith the LORD, that this house shall become a desolation."},"BSB":{"text":"But if you do not obey these words, then I swear by Myself, declares the LORD, that this house will become a pile of rubble.’”"},"TANAKH":{"text":"But if ye will not hear these words, I swear by Myself, saith HaShem, that this house shall become a desolation."},"HEBREW":{"text":"וְאִם֙ לֹ֣א תִשְׁמְע֔וּ אֶת־הַדְּבָרִ֖ים הָאֵ֑לֶּה בִּ֤י נִשְׁבַּ֙עְתִּי֙ נְאֻם־יְהוָ֔ה כִּי־לְחָרְבָּ֥ה יִֽהְיֶ֖ה הַבַּ֥יִת הַזֶּֽה׃"}},"definableWords":["LORD","house"],"peopleInVerse":[],"themesInVerse":["covenant"]},"6":{"text":"For thus saith the LORD unto the king’s house of Judah; Thou art Gilead unto me, and the head of Lebanon: yet surely I will make thee a wilderness, and cities which are not inhabited.","ref":"Jeremiah 22:6","synthesized":"For this is what the LORD says concerning the house of the king of Judah:  “You are like Gilead to Me, like the summit of Lebanon; but I will surely turn you into a desert, like cities that are uninhabited.","sources":{"KJV":{"text":"For thus saith the LORD unto the king’s house of Judah; Thou art Gilead unto me, and the head of Lebanon: yet surely I will make thee a wilderness, and cities which are not inhabited."},"BSB":{"text":"For this is what the LORD says concerning the house of the king of Judah:  “You are like Gilead to Me, like the summit of Lebanon; but I will surely turn you into a desert, like cities that are uninhabited."},"TANAKH":{"text":"For thus saith HaShem concerning the house of the king of Judah: Thou art Gilead unto Me, the head of Lebanon; yet surely I will make thee a wilderness, cities which are not inhabited."},"HEBREW":{"text":"כִּֽי־כֹ֣ה ׀ אָמַ֣ר יְהוָ֗ה עַל־בֵּית֙ מֶ֣לֶךְ יְהוּדָ֔ה גִּלְעָ֥ד אַתָּ֛ה לִ֖י רֹ֣אשׁ הַלְּבָנ֑וֹן אִם־לֹ֤א אֲשִֽׁיתְךָ֙ מִדְבָּ֔ר עָרִ֖ים לֹ֥א נושבה נוֹשָֽׁבוּ׃"}},"definableWords":["LORD","house","king","Judah"],"peopleInVerse":[],"themesInVerse":["kingship"]},"7":{"text":"And I will prepare destroyers against thee, every one with his weapons: and they shall cut down thy choice cedars, and cast them into the fire.","ref":"Jeremiah 22:7","synthesized":"I will appoint destroyers against you, each man with his weapons, and they will cut down the choicest of your cedars and throw them into the fire.","sources":{"KJV":{"text":"And I will prepare destroyers against thee, every one with his weapons: and they shall cut down thy choice cedars, and cast them into the fire."},"BSB":{"text":"I will appoint destroyers against you, each man with his weapons, and they will cut down the choicest of your cedars and throw them into the fire."},"TANAKH":{"text":"And I will prepare destroyers against thee, every one with his weapons; and they shall cut down thy choice cedars, and cast them into the fire."},"HEBREW":{"text":"וְקִדַּשְׁתִּ֥י עָלֶ֛יךָ מַשְׁחִתִ֖ים אִ֣ישׁ וְכֵלָ֑יו וְכָֽרְתוּ֙ מִבְחַ֣ר אֲרָזֶ֔יךָ וְהִפִּ֖ילוּ עַל־הָאֵֽשׁ׃"}},"definableWords":["man"],"peopleInVerse":[]},"8":{"text":"And many nations shall pass by this city, and they shall say every man to his neighbour, Wherefore hath the LORD done thus unto this great city?","ref":"Jeremiah 22:8","synthesized":"And many nations will pass by this city and ask one another, ‘Why has the LORD done such a thing to this great city?’","sources":{"KJV":{"text":"And many nations shall pass by this city, and they shall say every man to his neighbour, Wherefore hath the LORD done thus unto this great city?"},"BSB":{"text":"And many nations will pass by this city and ask one another, ‘Why has the LORD done such a thing to this great city?’"},"TANAKH":{"text":"And many nations shall pass by this city, and they shall say every man to his neighbour: 'Wherefore hath HaShem done thus unto this great city?'"},"HEBREW":{"text":"וְעָֽבְרוּ֙ גּוֹיִ֣ם רַבִּ֔ים עַ֖ל הָעִ֣יר הַזֹּ֑את וְאָֽמְרוּ֙ אִ֣ישׁ אֶל־רֵעֵ֔הוּ עַל־מֶ֨ה עָשָׂ֤ה יְהוָה֙ כָּ֔כָה לָעִ֥יר הַגְּדוֹלָ֖ה הַזֹּֽאת׃"}},"definableWords":["nations","one","LORD","great"],"peopleInVerse":[]},"9":{"text":"Then they shall answer, Because they have forsaken the covenant of the LORD their God, and worshipped other gods, and served them.","ref":"Jeremiah 22:9","synthesized":"Then people will reply, ‘Because they have forsaken the covenant of the LORD their God and have worshiped and served other gods.’”","sources":{"KJV":{"text":"Then they shall answer, Because they have forsaken the covenant of the LORD their God, and worshipped other gods, and served them."},"BSB":{"text":"Then people will reply, ‘Because they have forsaken the covenant of the LORD their God and have worshiped and served other gods.’”"},"TANAKH":{"text":"Then they shall answer: 'Because they forsook the covenant of HaShem their G-d, and worshipped other gods, and served them.'"},"HEBREW":{"text":"וְאָ֣מְר֔וּ עַ֚ל אֲשֶׁ֣ר עָֽזְב֔וּ אֶת־בְּרִ֥ית יְהוָ֖ה אֱלֹֽהֵיהֶ֑ם וַיִּֽשְׁתַּחֲו֛וּ לֵאלֹהִ֥ים אֲחֵרִ֖ים וַיַּעַבְדֽוּם׃"}},"definableWords":["people","covenant","LORD","God"],"peopleInVerse":[],"themesInVerse":["covenant"]},"10":{"text":"Weep ye not for the dead, neither bemoan him: but weep sore for him that goeth away: for he shall return no more, nor see his native country.","ref":"Jeremiah 22:10","synthesized":"Do not weep for the dead king; do not mourn his loss. Weep bitterly for the one who is exiled, for he will never return to see his native land.","sources":{"KJV":{"text":"Weep ye not for the dead, neither bemoan him: but weep sore for him that goeth away: for he shall return no more, nor see his native country."},"BSB":{"text":"Do not weep for the dead king; do not mourn his loss. Weep bitterly for the one who is exiled, for he will never return to see his native land."},"TANAKH":{"text":"Weep ye not for the dead, neither bemoan him; but weep sore for him that goeth away, for he shall return no more, nor see his native country."},"HEBREW":{"text":"אַל־תִּבְכּ֣וּ לְמֵ֔ת וְאַל־תָּנֻ֖דוּ ל֑וֹ בְּכ֤וּ בָכוֹ֙ לַֽהֹלֵ֔ךְ כִּ֣י לֹ֤א יָשׁוּב֙ ע֔וֹד וְרָאָ֖ה אֶת־אֶ֥רֶץ מוֹלַדְתּֽוֹ׃"}},"definableWords":["king","one","see","land"],"peopleInVerse":[],"themesInVerse":["exile_return","kingship","land_promise","second_coming"]},"11":{"text":"For thus saith the LORD touching Shallum the son of Josiah king of Judah, which reigned instead of Josiah his father, which went forth out of this place; He shall not return thither any more:","ref":"Jeremiah 22:11","synthesized":"For this is what the LORD says concerning Shallum son of Josiah, king of Judah, who succeeded his father Josiah but has gone forth from this place: “He will never return,","sources":{"KJV":{"text":"For thus saith the LORD touching Shallum the son of Josiah king of Judah, which reigned instead of Josiah his father, which went forth out of this place; He shall not return thither any more:"},"BSB":{"text":"For this is what the LORD says concerning Shallum son of Josiah, king of Judah, who succeeded his father Josiah but has gone forth from this place: “He will never return,"},"TANAKH":{"text":"For thus saith HaShem touching Shallum the son of Josiah, king of Judah, who reigned instead of Josiah his father, and who went forth out of this place: He shall not return thither any more;"},"HEBREW":{"text":"כִּ֣י כֹ֣ה אָֽמַר־יְ֠הוָה אֶל־שַׁלֻּ֨ם בֶּן־יֹאשִׁיָּ֜הוּ מֶ֣לֶךְ יְהוּדָ֗ה הַמֹּלֵךְ֙ תַּ֚חַת יֹאשִׁיָּ֣הוּ אָבִ֔יו אֲשֶׁ֥ר יָצָ֖א מִן־הַמָּק֣וֹם הַזֶּ֑ה לֹֽא־יָשׁ֥וּב שָׁ֖ם עֽוֹד׃"}},"definableWords":["LORD","son","king","Judah","father"],"peopleInVerse":[],"themesInVerse":["exile_return","kingship","second_coming"]},"12":{"text":"But he shall die in the place whither they have led him captive, and shall see this land no more.","ref":"Jeremiah 22:12","synthesized":"but he will die in the place to which he was exiled; he will never see this land again.”","sources":{"KJV":{"text":"But he shall die in the place whither they have led him captive, and shall see this land no more."},"BSB":{"text":"but he will die in the place to which he was exiled; he will never see this land again.”"},"TANAKH":{"text":"but in the place whither they have led him captive, there shall he die, and he shall see this land no more."},"HEBREW":{"text":"כִּ֗י בִּמְק֛וֹם אֲשֶׁר־הִגְל֥וּ אֹת֖וֹ שָׁ֣ם יָמ֑וּת וְאֶת־הָאָ֥רֶץ הַזֹּ֖את לֹֽא־יִרְאֶ֥ה עֽוֹד׃"}},"definableWords":["die","see","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"13":{"text":"Woe unto him that buildeth his house by unrighteousness, and his chambers by wrong; that useth his neighbour’s service without wages, and giveth him not for his work;","ref":"Jeremiah 22:13","synthesized":"“Woe to him who builds his palace by unrighteousness, and his upper rooms without justice, who makes his countrymen serve without pay, and fails to pay their wages,","sources":{"KJV":{"text":"Woe unto him that buildeth his house by unrighteousness, and his chambers by wrong; that useth his neighbour’s service without wages, and giveth him not for his work;"},"BSB":{"text":"“Woe to him who builds his palace by unrighteousness, and his upper rooms without justice, who makes his countrymen serve without pay, and fails to pay their wages,"},"TANAKH":{"text":"Woe unto him that buildeth his house by unrighteousness, and his chambers by injustice; that useth his neighbour's service without wages, and giveth him not his hire;"},"HEBREW":{"text":"ה֣וֹי בֹּנֶ֤ה בֵיתוֹ֙ בְּֽלֹא־צֶ֔דֶק וַעֲלִיּוֹתָ֖יו בְּלֹ֣א מִשְׁפָּ֑ט בְּרֵעֵ֙הוּ֙ יַעֲבֹ֣ד חִנָּ֔ם וּפֹעֲל֖וֹ לֹ֥א יִתֶּן־לֽוֹ׃"}},"definableWords":["justice"],"peopleInVerse":[]},"14":{"text":"That saith, I will build me a wide house and large chambers, and cutteth him out windows; and it is cieled with cedar, and painted with vermilion.","ref":"Jeremiah 22:14","synthesized":"who says, ‘I will build myself a great palace, with spacious upper rooms.’ So he cuts windows in it, panels it with cedar, and paints it with vermilion.","sources":{"KJV":{"text":"That saith, I will build me a wide house and large chambers, and cutteth him out windows; and it is cieled with cedar, and painted with vermilion."},"BSB":{"text":"who says, ‘I will build myself a great palace, with spacious upper rooms.’ So he cuts windows in it, panels it with cedar, and paints it with vermilion."},"TANAKH":{"text":"That saith: 'I will build me a wide house and spacious chambers', and cutteth him out windows, and it is ceiled with cedar, and painted with vermilion."},"HEBREW":{"text":"הָאֹמֵ֗ר אֶבְנֶה־לִּי֙ בֵּ֣ית מִדּ֔וֹת וַעֲלִיּ֖וֹת מְרֻוָּחִ֑ים וְקָ֤רַֽע לוֹ֙ חַלּוֹנָ֔י וְסָפ֣וּן בָּאָ֔רֶז וּמָשׁ֖וֹחַ בַּשָּׁשַֽׁר׃"}},"definableWords":["great"],"peopleInVerse":[]},"15":{"text":"Shalt thou reign, because thou closest thyself in cedar? did not thy father eat and drink, and do judgment and justice, and then it was well with him?","ref":"Jeremiah 22:15","synthesized":"Does it make you a king to excel in cedar? Did not your father have food and drink? He administered justice and righteousness, and so it went well with him.","sources":{"KJV":{"text":"Shalt thou reign, because thou closest thyself in cedar? did not thy father eat and drink, and do judgment and justice, and then it was well with him?"},"BSB":{"text":"Does it make you a king to excel in cedar? Did not your father have food and drink? He administered justice and righteousness, and so it went well with him."},"TANAKH":{"text":"Shalt thou reign, because thou strivest to excel in cedar? Did not thy father eat and drink, and do justice and righteousness? Then it was well with him."},"HEBREW":{"text":"הֲתִֽמְלֹ֔ךְ כִּ֥י אַתָּ֖ה מְתַחֲרֶ֣ה בָאָ֑רֶז אָבִ֜יךָ הֲל֧וֹא אָכַ֣ל וְשָׁתָ֗ה וְעָשָׂ֤ה מִשְׁפָּט֙ וּצְדָקָ֔ה אָ֖ז ט֥וֹב לֽוֹ׃"}},"definableWords":["make","king","father","justice","righteousness"],"peopleInVerse":[],"themesInVerse":["bread_water_life","kingship"]},"16":{"text":"He judged the cause of the poor and needy; then it was well with him: was not this to know me? saith the LORD.","ref":"Jeremiah 22:16","synthesized":"He took up the cause of the poor and needy, and so it went well with him. Is this not what it means to know Me?” declares the LORD.","sources":{"KJV":{"text":"He judged the cause of the poor and needy; then it was well with him: was not this to know me? saith the LORD."},"BSB":{"text":"He took up the cause of the poor and needy, and so it went well with him. Is this not what it means to know Me?” declares the LORD."},"TANAKH":{"text":"He judged the cause of the poor and needy; then it was well. Is not this to know Me? saith HaShem."},"HEBREW":{"text":"דָּ֛ן דִּין־עָנִ֥י וְאֶבְי֖וֹן אָ֣ז ט֑וֹב הֲלוֹא־הִ֛יא הַדַּ֥עַת אֹתִ֖י נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"17":{"text":"But thine eyes and thine heart are not but for thy covetousness, and for to shed innocent blood, and for oppression, and for violence, to do it.","ref":"Jeremiah 22:17","synthesized":"“But your eyes and heart are set on nothing except your own dishonest gain, on shedding innocent blood, on practicing extortion and oppression.”","sources":{"KJV":{"text":"But thine eyes and thine heart are not but for thy covetousness, and for to shed innocent blood, and for oppression, and for violence, to do it."},"BSB":{"text":"“But your eyes and heart are set on nothing except your own dishonest gain, on shedding innocent blood, on practicing extortion and oppression.”"},"TANAKH":{"text":"But thine eyes and thy heart are not but for thy covetousness, and for shedding innocent blood, and for oppression, and for violence, to do it."},"HEBREW":{"text":"כִּ֣י אֵ֤ין עֵינֶ֙יךָ֙ וְלִבְּךָ֔ כִּ֖י אִם־עַל־בִּצְעֶ֑ךָ וְעַ֤ל דַּֽם־הַנָּקִי֙ לִשְׁפּ֔וֹךְ וְעַל־הָעֹ֥שֶׁק וְעַל־הַמְּרוּצָ֖ה לַעֲשֽׂוֹת׃"}},"definableWords":["heart","blood"],"peopleInVerse":[],"themesInVerse":["passover","sacrifice"]},"18":{"text":"Therefore thus saith the LORD concerning Jehoiakim the son of Josiah king of Judah; They shall not lament for him, saying, Ah my brother! or, Ah sister! they shall not lament for him, saying, Ah lord! or, Ah his glory!","ref":"Jeremiah 22:18","synthesized":"Therefore this is what the LORD says concerning Jehoiakim son of Josiah king of Judah:  “They will not mourn for him: ‘Alas, my brother! Alas, my sister!’ They will not mourn for him: ‘Alas, my master! Alas, his splendor!’","sources":{"KJV":{"text":"Therefore thus saith the LORD concerning Jehoiakim the son of Josiah king of Judah; They shall not lament for him, saying, Ah my brother! or, Ah sister! they shall not lament for him, saying, Ah lord! or, Ah his glory!"},"BSB":{"text":"Therefore this is what the LORD says concerning Jehoiakim son of Josiah king of Judah:  “They will not mourn for him: ‘Alas, my brother! Alas, my sister!’ They will not mourn for him: ‘Alas, my master! Alas, his splendor!’"},"TANAKH":{"text":"Therefore thus saith HaShem concerning Jehoiakim the son of Josiah, king of Judah: They shall not lament for him: 'Ah my brother!' or: 'Ah sister!' They shall not lament for him: 'Ah lord!' or: 'Ah his glory!'"},"HEBREW":{"text":"לָכֵ֞ן כֹּֽה־אָמַ֣ר יְהוָ֗ה אֶל־יְהוֹיָקִ֤ים בֶּן־יֹאשִׁיָּ֙הוּ֙ מֶ֣לֶךְ יְהוּדָ֔ה לֹא־יִסְפְּד֣וּ ל֔וֹ ה֥וֹי אָחִ֖י וְה֣וֹי אָח֑וֹת לֹא־יִסְפְּד֣וּ ל֔וֹ ה֥וֹי אָד֖וֹן וְה֥וֹי הֹדֹֽה׃"}},"definableWords":["LORD","son","king","Judah","brother","sister"],"peopleInVerse":[],"themesInVerse":["kingship"]},"19":{"text":"He shall be buried with the burial of an ass, drawn and cast forth beyond the gates of Jerusalem.","ref":"Jeremiah 22:19","synthesized":"He will be buried like a donkey, dragged away and thrown outside the gates of Jerusalem.","sources":{"KJV":{"text":"He shall be buried with the burial of an ass, drawn and cast forth beyond the gates of Jerusalem."},"BSB":{"text":"He will be buried like a donkey, dragged away and thrown outside the gates of Jerusalem."},"TANAKH":{"text":"He shall be buried with the burial of an ass, drawn and cast forth beyond the gates of Jerusalem."},"HEBREW":{"text":"קְבוּרַ֥ת חֲמ֖וֹר יִקָּבֵ֑ר סָח֣וֹב וְהַשְׁלֵ֔ךְ מֵהָ֖לְאָה לְשַׁעֲרֵ֥י יְרוּשָׁלָֽ͏ִם׃"}},"definableWords":["Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"20":{"text":"Go up to Lebanon, and cry; and lift up thy voice in Bashan, and cry from the passages: for all thy lovers are destroyed.","ref":"Jeremiah 22:20","synthesized":"Go up to Lebanon and cry out; raise your voice in Bashan; cry out from Abarim, for all your lovers have been crushed.","sources":{"KJV":{"text":"Go up to Lebanon, and cry; and lift up thy voice in Bashan, and cry from the passages: for all thy lovers are destroyed."},"BSB":{"text":"Go up to Lebanon and cry out; raise your voice in Bashan; cry out from Abarim, for all your lovers have been crushed."},"TANAKH":{"text":"Go up to Lebanon, and cry, and lift up thy voice in Bashan; and cry from Abarim, for all thy lovers are destroyed."},"HEBREW":{"text":"עֲלִ֤י הַלְּבָנוֹן֙ וּֽצְעָ֔קִי וּבַבָּשָׁ֖ן תְּנִ֣י קוֹלֵ֑ךְ וְצַֽעֲקִי֙ מֵֽעֲבָרִ֔ים כִּ֥י נִשְׁבְּר֖וּ כָּל־מְאַהֲבָֽיִךְ׃"}},"definableWords":["voice"],"peopleInVerse":[]},"21":{"text":"I spake unto thee in thy prosperity; but thou saidst, I will not hear. This hath been thy manner from thy youth, that thou obeyedst not my voice.","ref":"Jeremiah 22:21","synthesized":"I warned you when you were secure. You said, ‘I will not listen.’ This has been your way from youth, that you have not obeyed My voice.","sources":{"KJV":{"text":"I spake unto thee in thy prosperity; but thou saidst, I will not hear. This hath been thy manner from thy youth, that thou obeyedst not my voice."},"BSB":{"text":"I warned you when you were secure. You said, ‘I will not listen.’ This has been your way from youth, that you have not obeyed My voice."},"TANAKH":{"text":"I spoke unto thee in thy prosperity, but thou saidst: 'I will not hear.' This hath been thy manner from thy youth, that thou hearkenedst not to My voice."},"HEBREW":{"text":"דִּבַּ֤רְתִּי אֵלַ֙יִךְ֙ בְּשַׁלְוֺתַ֔יִךְ אָמַ֖רְתְּ לֹ֣א אֶשְׁמָ֑ע זֶ֤ה דַרְכֵּךְ֙ מִנְּעוּרַ֔יִךְ כִּ֥י לֹֽא־שָׁמַ֖עַתְּ בְּקוֹלִֽי׃"}},"definableWords":["way","voice"],"peopleInVerse":[]},"22":{"text":"The wind shall eat up all thy pastors, and thy lovers shall go into captivity: surely then shalt thou be ashamed and confounded for all thy wickedness.","ref":"Jeremiah 22:22","synthesized":"The wind will drive away all your shepherds, and your lovers will go into captivity. Then you will be ashamed and humiliated because of all your wickedness.","sources":{"KJV":{"text":"The wind shall eat up all thy pastors, and thy lovers shall go into captivity: surely then shalt thou be ashamed and confounded for all thy wickedness."},"BSB":{"text":"The wind will drive away all your shepherds, and your lovers will go into captivity. Then you will be ashamed and humiliated because of all your wickedness."},"TANAKH":{"text":"The wind shall feed upon all thy shepherds, and thy lovers shall go into captivity; surely then shalt thou be ashamed and confounded for all thy wickedness."},"HEBREW":{"text":"כָּל־רֹעַ֙יִךְ֙ תִּרְעֶה־ר֔וּחַ וּֽמְאַהֲבַ֖יִךְ בַּשְּׁבִ֣י יֵלֵ֑כוּ כִּ֣י אָ֤ז תֵּבֹ֙שִׁי֙ וְנִכְלַ֔מְתְּ מִכֹּ֖ל רָעָתֵֽךְ׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["exile_return"]},"23":{"text":"O inhabitant of Lebanon, that makest thy nest in the cedars, how gracious shalt thou be when pangs come upon thee, the pain as of a woman in travail!","ref":"Jeremiah 22:23","synthesized":"O inhabitant of Lebanon, nestled in the cedars, how you will groan when pangs of anguish come upon you, agony like a woman in labor.”","sources":{"KJV":{"text":"O inhabitant of Lebanon, that makest thy nest in the cedars, how gracious shalt thou be when pangs come upon thee, the pain as of a woman in travail!"},"BSB":{"text":"O inhabitant of Lebanon, nestled in the cedars, how you will groan when pangs of anguish come upon you, agony like a woman in labor.”"},"TANAKH":{"text":"O inhabitant of Lebanon, that art nestled in the cedars, how gracious shalt thou be when pangs come upon thee, the pain as of a woman in travail!"},"HEBREW":{"text":"ישבתי יֹשַׁבְתְּ֙ בַּלְּבָנ֔וֹן מקננתי מְקֻנַּ֖נְתְּ בָּֽאֲרָזִ֑ים מַה־נֵּחַנְתְּ֙ בְּבֹא־לָ֣ךְ חֲבָלִ֔ים חִ֖יל כַּיֹּלֵדָֽה׃"}},"definableWords":["woman"],"peopleInVerse":[]},"24":{"text":"As I live, saith the LORD, though Coniah the son of Jehoiakim king of Judah were the signet upon my right hand, yet would I pluck thee thence;","ref":"Jeremiah 22:24","synthesized":"“As surely as I live,” declares the LORD, “even if you, Coniah son of Jehoiakim king of Judah, were a signet ring on My right hand, I would pull you off.","sources":{"KJV":{"text":"As I live, saith the LORD, though Coniah the son of Jehoiakim king of Judah were the signet upon my right hand, yet would I pluck thee thence;"},"BSB":{"text":"“As surely as I live,” declares the LORD, “even if you, Coniah son of Jehoiakim king of Judah, were a signet ring on My right hand, I would pull you off."},"TANAKH":{"text":"As I live, saith HaShem, though Coniah the son of Jehoiakim king of Judah were the signet upon My right hand, yet would I pluck thee thence;"},"HEBREW":{"text":"חַי־אָנִי֮ נְאֻם־יְהוָה֒ כִּ֣י אִם־יִהְיֶ֞ה כָּנְיָ֤הוּ בֶן־יְהֽוֹיָקִים֙ מֶ֣לֶךְ יְהוּדָ֔ה חוֹתָ֖ם עַל־יַ֣ד יְמִינִ֑י כִּ֥י מִשָּׁ֖ם אֶתְּקֶֽנְךָּ׃"}},"definableWords":["live","LORD","son","king","Judah"],"peopleInVerse":[],"themesInVerse":["kingship"]},"25":{"text":"And I will give thee into the hand of them that seek thy life, and into the hand of them whose face thou fearest, even into the hand of Nebuchadrezzar king of Babylon, and into the hand of the Chaldeans.","ref":"Jeremiah 22:25","synthesized":"In fact, I will hand you over to those you dread, who want to take your life—to Nebuchadnezzar king of Babylon and to the Chaldeans.","sources":{"KJV":{"text":"And I will give thee into the hand of them that seek thy life, and into the hand of them whose face thou fearest, even into the hand of Nebuchadrezzar king of Babylon, and into the hand of the Chaldeans."},"BSB":{"text":"In fact, I will hand you over to those you dread, who want to take your life—to Nebuchadnezzar king of Babylon and to the Chaldeans."},"TANAKH":{"text":"and I will give thee into the hand of them that seek thy life, and into the hand of them of whom thou art afraid, even into the hand of Nebuchadrezzar king of Babylon, and into the hand of the Chaldeans."},"HEBREW":{"text":"וּנְתַתִּ֗יךָ בְּיַד֙ מְבַקְשֵׁ֣י נַפְשֶׁ֔ךָ וּבְיַ֛ד אֲשֶׁר־אַתָּ֥ה יָג֖וֹר מִפְּנֵיהֶ֑ם וּבְיַ֛ד נְבוּכַדְרֶאצַּ֥ר מֶֽלֶךְ־בָּבֶ֖ל וּבְיַ֥ד הַכַּשְׂדִּֽים׃"}},"definableWords":["life","king","Babylon"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"26":{"text":"And I will cast thee out, and thy mother that bare thee, into another country, where ye were not born; and there shall ye die.","ref":"Jeremiah 22:26","synthesized":"I will hurl you and the mother who gave you birth into another land, where neither of you were born—and there you both will die.","sources":{"KJV":{"text":"And I will cast thee out, and thy mother that bare thee, into another country, where ye were not born; and there shall ye die."},"BSB":{"text":"I will hurl you and the mother who gave you birth into another land, where neither of you were born—and there you both will die."},"TANAKH":{"text":"And I will cast thee out, and thy mother that bore thee, into another country, where ye were not born; and there shall ye die."},"HEBREW":{"text":"וְהֵֽטַלְתִּ֣י אֹתְךָ֗ וְאֶֽת־אִמְּךָ֙ אֲשֶׁ֣ר יְלָדַ֔תְךָ עַ֚ל הָאָ֣רֶץ אַחֶ֔רֶת אֲשֶׁ֥ר לֹֽא־יֻלַּדְתֶּ֖ם שָׁ֑ם וְשָׁ֖ם תָּמֽוּתוּ׃"}},"definableWords":["mother","land","die"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"27":{"text":"But to the land whereunto they desire to return, thither shall they not return.","ref":"Jeremiah 22:27","synthesized":"You will never return to the land for which you long.”","sources":{"KJV":{"text":"But to the land whereunto they desire to return, thither shall they not return."},"BSB":{"text":"You will never return to the land for which you long.”"},"TANAKH":{"text":"But to the land whereunto they long to return, thither shall they not return."},"HEBREW":{"text":"וְעַל־הָאָ֗רֶץ אֲשֶׁר־הֵ֛ם מְנַשְּׂאִ֥ים אֶת־נַפְשָׁ֖ם לָשׁ֣וּב שָׁ֑ם שָׁ֖מָּה לֹ֥א יָשֽׁוּבוּ׃"}},"definableWords":["land"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise","second_coming"]},"28":{"text":"Is this man Coniah a despised broken idol? is he a vessel wherein is no pleasure? wherefore are they cast out, he and his seed, and are cast into a land which they know not?","ref":"Jeremiah 22:28","synthesized":"Is this man Coniah a despised and shattered pot, a jar that no one wants? Why are he and his descendants hurled out and cast into a land they do not know?","sources":{"KJV":{"text":"Is this man Coniah a despised broken idol? is he a vessel wherein is no pleasure? wherefore are they cast out, he and his seed, and are cast into a land which they know not?"},"BSB":{"text":"Is this man Coniah a despised and shattered pot, a jar that no one wants? Why are he and his descendants hurled out and cast into a land they do not know?"},"TANAKH":{"text":"Is this man Coniah a despised, broken image? Is he a vessel wherein is no pleasure? Wherefore are they cast out, he and his seed, and are cast into the land which they know not?"},"HEBREW":{"text":"הַעֶ֨צֶב נִבְזֶ֜ה נָפ֗וּץ הָאִ֤ישׁ הַזֶּה֙ כָּנְיָ֔הוּ אִ֨ם־כְּלִ֔י אֵ֥ין חֵ֖פֶץ בּ֑וֹ מַדּ֤וּעַ הֽוּטֲלוּ֙ ה֣וּא וְזַרְע֔וֹ וְהֻ֨שְׁלְכ֔וּ עַל־הָאָ֖רֶץ אֲשֶׁ֥ר לֹא־יָדָֽעוּ׃"}},"definableWords":["man","one","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"29":{"text":"O earth, earth, earth, hear the word of the LORD.","ref":"Jeremiah 22:29","synthesized":"O land, land, land, hear the word of the LORD!","sources":{"KJV":{"text":"O earth, earth, earth, hear the word of the LORD."},"BSB":{"text":"O land, land, land, hear the word of the LORD!"},"TANAKH":{"text":"O land, land, land, hear the word of HaShem."},"HEBREW":{"text":"אֶ֥רֶץ אֶ֖רֶץ אָ֑רֶץ שִׁמְעִ֖י דְּבַר־יְהוָֽה׃"}},"definableWords":["land","hear","word","LORD"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"30":{"text":"Thus saith the LORD, Write ye this man childless, a man that shall not prosper in his days: for no man of his seed shall prosper, sitting upon the throne of David, and ruling any more in Judah.","ref":"Jeremiah 22:30","synthesized":"This is what the LORD says:  “Enroll this man as childless, a man who will not prosper in his lifetime. None of his descendants will prosper to sit on the throne of David or to rule again in Judah.”","sources":{"KJV":{"text":"Thus saith the LORD, Write ye this man childless, a man that shall not prosper in his days: for no man of his seed shall prosper, sitting upon the throne of David, and ruling any more in Judah."},"BSB":{"text":"This is what the LORD says:  “Enroll this man as childless, a man who will not prosper in his lifetime. None of his descendants will prosper to sit on the throne of David or to rule again in Judah.”"},"TANAKH":{"text":"Thus saith HaShem: Write ye this man childless, a man that shall not prosper in his days; for no man of his seed shall prosper, sitting upon the throne of David, and ruling any more in Judah."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה כִּתְב֞וּ אֶת־הָאִ֤ישׁ הַזֶּה֙ עֲרִירִ֔י גֶּ֖בֶר לֹא־יִצְלַ֣ח בְּיָמָ֑יו כִּי֩ לֹ֨א יִצְלַ֜ח מִזַּרְע֗וֹ אִ֚ישׁ יֹשֵׁב֙ עַל־כִּסֵּ֣א דָוִ֔ד וּמֹשֵׁ֥ל ע֖וֹד בִּיהוּדָֽה׃"}},"definableWords":["LORD","man","throne","or","rule","Judah"],"peopleInVerse":["David"],"themesInVerse":["kingdom_of_god","kingship"]}}},"23":{"chapter":"23","title":"THE RIGHTEOUS BRANCH","verses":{"1":{"text":"Woe be unto the pastors that destroy and scatter the sheep of my pasture! saith the LORD.","ref":"Jeremiah 23:1","synthesized":"“Woe to the shepherds who destroy and scatter the sheep of My pasture!” declares the LORD.","sources":{"KJV":{"text":"Woe be unto the pastors that destroy and scatter the sheep of my pasture! saith the LORD."},"BSB":{"text":"“Woe to the shepherds who destroy and scatter the sheep of My pasture!” declares the LORD."},"TANAKH":{"text":"Woe unto the shepherds that destroy and scatter the sheep of My pasture! saith HaShem."},"HEBREW":{"text":"ה֣וֹי רֹעִ֗ים מְאַבְּדִ֧ים וּמְפִצִ֛ים אֶת־צֹ֥אן מַרְעִיתִ֖י נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[],"themesInVerse":["shepherd_sheep"]},"2":{"text":"Therefore thus saith the LORD God of Israel against the pastors that feed my people; Ye have scattered my flock, and driven them away, and have not visited them: behold, I will visit upon you the evil of your doings, saith the LORD.","ref":"Jeremiah 23:2","synthesized":"Therefore this is what the LORD, the God of Israel, says about the shepherds who tend My people: “You have scattered My flock and driven them away, and have not attended to them. Behold, I will attend to you for the evil of your deeds, declares the LORD.","sources":{"KJV":{"text":"Therefore thus saith the LORD God of Israel against the pastors that feed my people; Ye have scattered my flock, and driven them away, and have not visited them: behold, I will visit upon you the evil of your doings, saith the LORD."},"BSB":{"text":"Therefore this is what the LORD, the God of Israel, says about the shepherds who tend My people: “You have scattered My flock and driven them away, and have not attended to them. Behold, I will attend to you for the evil of your deeds, declares the LORD."},"TANAKH":{"text":"Therefore thus saith HaShem, the G-d of Israel, against the shepherds that feed My people: Ye have scattered My flock, and driven them away, and have not taken care of them; behold, I will visit upon you the evil of your doings, saith HaShem."},"HEBREW":{"text":"לָ֠כֵן כֹּֽה־אָמַ֨ר יְהוָ֜ה אֱלֹהֵ֣י יִשְׂרָאֵ֗ל עַֽל־הָרֹעִים֮ הָרֹעִ֣ים אֶת־עַמִּי֒ אַתֶּ֞ם הֲפִצֹתֶ֤ם אֶת־צֹאנִי֙ וַתַּדִּח֔וּם וְלֹ֥א פְקַדְתֶּ֖ם אֹתָ֑ם הִנְנִ֨י פֹקֵ֧ד עֲלֵיכֶ֛ם אֶת־רֹ֥עַ מַעַלְלֵיכֶ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD","God","Israel","people","evil","Lord"],"peopleInVerse":[],"themesInVerse":["shepherd_sheep"]},"3":{"text":"And I will gather the remnant of my flock out of all countries whither I have driven them, and will bring them again to their folds; and they shall be fruitful and increase.","ref":"Jeremiah 23:3","synthesized":"Then I Myself will gather the remnant of My flock from all the lands to which I have banished them, and I will return them to their pasture, where they will be fruitful and multiply.","sources":{"KJV":{"text":"And I will gather the remnant of my flock out of all countries whither I have driven them, and will bring them again to their folds; and they shall be fruitful and increase."},"BSB":{"text":"Then I Myself will gather the remnant of My flock from all the lands to which I have banished them, and I will return them to their pasture, where they will be fruitful and multiply."},"TANAKH":{"text":"And I will gather the remnant of My flock out of all the countries whither I have driven them, and will bring them back to their folds; and they shall be fruitful and multiply."},"HEBREW":{"text":"וַאֲנִ֗י אֲקַבֵּץ֙ אֶת־שְׁאֵרִ֣ית צֹאנִ֔י מִכֹּל֙ הָאֲרָצ֔וֹת אֲשֶׁר־הִדַּ֥חְתִּי אֹתָ֖ם שָׁ֑ם וַהֲשִׁבֹתִ֥י אֶתְהֶ֛ן עַל־נְוֵהֶ֖ן וּפָר֥וּ וְרָבֽוּ׃"}},"definableWords":["remnant","fruitful","multiply"],"peopleInVerse":[],"themesInVerse":["exile_return","second_coming","shepherd_sheep"]},"4":{"text":"And I will set up shepherds over them which shall feed them: and they shall fear no more, nor be dismayed, neither shall they be lacking, saith the LORD.","ref":"Jeremiah 23:4","synthesized":"I will raise up shepherds over them who will tend them, and they will no longer be afraid or dismayed, nor will any go missing, declares the LORD.","sources":{"KJV":{"text":"And I will set up shepherds over them which shall feed them: and they shall fear no more, nor be dismayed, neither shall they be lacking, saith the LORD."},"BSB":{"text":"I will raise up shepherds over them who will tend them, and they will no longer be afraid or dismayed, nor will any go missing, declares the LORD."},"TANAKH":{"text":"And I will set up shepherds over them, who shall feed them; and they shall fear no more, nor be dismayed, neither shall any be lacking, saith HaShem."},"HEBREW":{"text":"וַהֲקִמֹתִ֧י עֲלֵיהֶ֛ם רֹעִ֖ים וְרָע֑וּם וְלֹא־יִֽירְא֨וּ ע֧וֹד וְלֹא־יֵחַ֛תּוּ וְלֹ֥א יִפָּקֵ֖דוּ נְאֻם־יְהוָֽה׃"}},"definableWords":["or","LORD"],"peopleInVerse":[]},"5":{"text":"Behold, the days come, saith the LORD, that I will raise unto David a righteous Branch, and a King shall reign and prosper, and shall execute judgment and justice in the earth.","ref":"Jeremiah 23:5","synthesized":"Behold, the days are coming, declares the LORD, when I will raise up for David a righteous Branch, and He will reign wisely as King and will administer justice and righteousness in the land.","sources":{"KJV":{"text":"Behold, the days come, saith the LORD, that I will raise unto David a righteous Branch, and a King shall reign and prosper, and shall execute judgment and justice in the earth."},"BSB":{"text":"Behold, the days are coming, declares the LORD, when I will raise up for David a righteous Branch, and He will reign wisely as King and will administer justice and righteousness in the land."},"TANAKH":{"text":"Behold, the days come, saith HaShem, that I will raise unto David a righteous shoot, and he shall reign as king and prosper, and shall execute justice and righteousness in the land."},"HEBREW":{"text":"הִנֵּ֨ה יָמִ֤ים בָּאִים֙ נְאֻם־יְהוָ֔ה וַהֲקִמֹתִ֥י לְדָוִ֖ד צֶ֣מַח צַדִּ֑יק וּמָ֤לַךְ מֶ֙לֶךְ֙ וְהִשְׂכִּ֔יל וְעָשָׂ֛ה מִשְׁפָּ֥ט וּצְדָקָ֖ה בָּאָֽרֶץ׃"}},"definableWords":["days","LORD","righteous","reign","King","justice","righteousness","land"],"peopleInVerse":["David"],"themesInVerse":["kingdom_of_god","kingship","land_promise","messiah","second_coming"]},"6":{"text":"In his days Judah shall be saved, and Israel shall dwell safely: and this is his name whereby he shall be called, THE LORD OUR RIGHTEOUSNESS.","ref":"Jeremiah 23:6","synthesized":"In His days Judah will be saved, and Israel will dwell securely. And this is His name by which He will be called: The LORD Our Righteousness.","sources":{"KJV":{"text":"In his days Judah shall be saved, and Israel shall dwell safely: and this is his name whereby he shall be called, THE LORD OUR RIGHTEOUSNESS."},"BSB":{"text":"In His days Judah will be saved, and Israel will dwell securely. And this is His name by which He will be called: The LORD Our Righteousness."},"TANAKH":{"text":"In his days Judah shall be saved, and Israel shall dwell safely; and this is his name whereby he shall be called, HaShem is our righteousness."},"HEBREW":{"text":"בְּיָמָיו֙ תִּוָּשַׁ֣ע יְהוּדָ֔ה וְיִשְׂרָאֵ֖ל יִשְׁכֹּ֣ן לָבֶ֑טַח וְזֶה־שְּׁמ֥וֹ אֲ‍ֽשֶׁר־יִקְרְא֖וֹ יְהוָ֥ה ׀ צִדְקֵֽנוּ׃"}},"definableWords":["days","Judah","Israel","name","LORD","righteousness"],"peopleInVerse":[]},"7":{"text":"Therefore, behold, the days come, saith the LORD, that they shall no more say, The LORD liveth, which brought up the children of Israel out of the land of Egypt;","ref":"Jeremiah 23:7","synthesized":"So behold, the days are coming, declares the LORD, when they will no longer say, ‘As surely as the LORD lives, who brought the Israelites up out of the land of Egypt.’","sources":{"KJV":{"text":"Therefore, behold, the days come, saith the LORD, that they shall no more say, The LORD liveth, which brought up the children of Israel out of the land of Egypt;"},"BSB":{"text":"So behold, the days are coming, declares the LORD, when they will no longer say, ‘As surely as the LORD lives, who brought the Israelites up out of the land of Egypt.’"},"TANAKH":{"text":"Therefore, behold, the days come, saith HaShem, that they shall no more say: 'As HaShem liveth, that brought up the children of Israel out of the land of Egypt';"},"HEBREW":{"text":"לָכֵ֛ן הִנֵּֽה־יָמִ֥ים בָּאִ֖ים נְאֻם־יְהוָ֑ה וְלֹא־יֹ֤אמְרוּ עוֹד֙ חַי־יְהוָ֔ה אֲשֶׁ֧ר הֶעֱלָ֛ה אֶת־בְּנֵ֥י יִשְׂרָאֵ֖ל מֵאֶ֥רֶץ מִצְרָֽיִם׃"}},"definableWords":["days","LORD","Lord","Israelites","land","Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise","second_coming"]},"8":{"text":"But, The LORD liveth, which brought up and which led the seed of the house of Israel out of the north country, and from all countries whither I had driven them; and they shall dwell in their own land.","ref":"Jeremiah 23:8","synthesized":"Instead they will say, ‘As surely as the LORD lives, who brought and led the descendants of the house of Israel up out of the land of the north and all the other lands to which He had banished them.’ Then they will dwell once more in their own land.”","sources":{"KJV":{"text":"But, The LORD liveth, which brought up and which led the seed of the house of Israel out of the north country, and from all countries whither I had driven them; and they shall dwell in their own land."},"BSB":{"text":"Instead they will say, ‘As surely as the LORD lives, who brought and led the descendants of the house of Israel up out of the land of the north and all the other lands to which He had banished them.’ Then they will dwell once more in their own land.”"},"TANAKH":{"text":"but: 'As HaShem liveth, that brought up and that led the seed of the house of Israel out of the north country, and from all the countries whither I had driven them'; and they shall dwell in their own land."},"HEBREW":{"text":"כִּ֣י אִם־חַי־יְהוָ֗ה אֲשֶׁ֣ר הֶעֱלָה֩ וַאֲשֶׁ֨ר הֵבִ֜יא אֶת־זֶ֨רַע בֵּ֤ית יִשְׂרָאֵל֙ מֵאֶ֣רֶץ צָפ֔וֹנָה וּמִכֹּל֙ הָֽאֲרָצ֔וֹת אֲשֶׁ֥ר הִדַּחְתִּ֖ים שָׁ֑ם וְיָשְׁב֖וּ עַל־אַדְמָתָֽם׃"}},"definableWords":["LORD","house","Israel","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"9":{"text":"Mine heart within me is broken because of the prophets; all my bones shake; I am like a drunken man, and like a man whom wine hath overcome, because of the LORD, and because of the words of his holiness.","ref":"Jeremiah 23:9","synthesized":"As for the prophets:  My heart is broken within me, and all my bones tremble. I have become like a drunkard, like a man overcome by wine, because of the LORD, because of His holy words.","sources":{"KJV":{"text":"Mine heart within me is broken because of the prophets; all my bones shake; I am like a drunken man, and like a man whom wine hath overcome, because of the LORD, and because of the words of his holiness."},"BSB":{"text":"As for the prophets:  My heart is broken within me, and all my bones tremble. I have become like a drunkard, like a man overcome by wine, because of the LORD, because of His holy words."},"TANAKH":{"text":"Concerning the prophets. My heart within me is broken, all my bones shake; I am like a drunken man, and like a man whom wine hath overcome; because of HaShem, and because of His holy words."},"HEBREW":{"text":"לַנְּבִאִ֞ים נִשְׁבַּ֧ר לִבִּ֣י בְקִרְבִּ֗י רָֽחֲפוּ֙ כָּל־עַצְמוֹתַ֔י הָיִ֙יתִי֙ כְּאִ֣ישׁ שִׁכּ֔וֹר וּכְגֶ֖בֶר עֲבָ֣רוֹ יָ֑יִן מִפְּנֵ֣י יְהוָ֔ה וּמִפְּנֵ֖י דִּבְרֵ֥י קָדְשֽׁוֹ׃"}},"definableWords":["heart","bones","man","overcome","LORD","holy"],"peopleInVerse":[]},"10":{"text":"For the land is full of adulterers; for because of swearing the land mourneth; the pleasant places of the wilderness are dried up, and their course is evil, and their force is not right.","ref":"Jeremiah 23:10","synthesized":"For the land is full of adulterers— because of the curse, the land mourns and the pastures of the wilderness have dried up— their course is evil and their power is misused.","sources":{"KJV":{"text":"For the land is full of adulterers; for because of swearing the land mourneth; the pleasant places of the wilderness are dried up, and their course is evil, and their force is not right."},"BSB":{"text":"For the land is full of adulterers— because of the curse, the land mourns and the pastures of the wilderness have dried up— their course is evil and their power is misused."},"TANAKH":{"text":"For the land is full of adulterers; for because of swearing the land mourneth, the pastures of the wilderness are dried up; and their course is evil, and their force is not right."},"HEBREW":{"text":"כִּ֤י מְנָֽאֲפִים֙ מָלְאָ֣ה הָאָ֔רֶץ כִּֽי־מִפְּנֵ֤י אָלָה֙ אָבְלָ֣ה הָאָ֔רֶץ יָבְשׁ֖וּ נְא֣וֹת מִדְבָּ֑ר וַתְּהִ֤י מְרֽוּצָתָם֙ רָעָ֔ה וּגְבוּרָתָ֖ם לֹא־כֵֽן׃"}},"definableWords":["land","curse","evil"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"11":{"text":"For both prophet and priest are profane; yea, in my house have I found their wickedness, saith the LORD.","ref":"Jeremiah 23:11","synthesized":"“For both prophet and priest are ungodly; even in My house I have found their wickedness,” declares the LORD.","sources":{"KJV":{"text":"For both prophet and priest are profane; yea, in my house have I found their wickedness, saith the LORD."},"BSB":{"text":"“For both prophet and priest are ungodly; even in My house I have found their wickedness,” declares the LORD."},"TANAKH":{"text":"For both prophet and priest are ungodly; yea, in My house have I found their wickedness, saith HaShem."},"HEBREW":{"text":"כִּֽי־גַם־נָבִ֥יא גַם־כֹּהֵ֖ן חָנֵ֑פוּ גַּם־בְּבֵיתִ֛י מָצָ֥אתִי רָעָתָ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["prophet","priest","house","LORD"],"peopleInVerse":[],"themesInVerse":["kingdom_priesthood"]},"12":{"text":"Wherefore their way shall be unto them as slippery ways in the darkness: they shall be driven on, and fall therein: for I will bring evil upon them, even the year of their visitation, saith the LORD.","ref":"Jeremiah 23:12","synthesized":"“Therefore their path will become slick; they will be driven away into the darkness and fall into it. For I will bring disaster upon them in the year of their punishment,” declares the LORD.","sources":{"KJV":{"text":"Wherefore their way shall be unto them as slippery ways in the darkness: they shall be driven on, and fall therein: for I will bring evil upon them, even the year of their visitation, saith the LORD."},"BSB":{"text":"“Therefore their path will become slick; they will be driven away into the darkness and fall into it. For I will bring disaster upon them in the year of their punishment,” declares the LORD."},"TANAKH":{"text":"Wherefore their way shall be unto them as slippery places in the darkness, they shall be thrust, and fall therein; for I will bring evil upon them, even the year of their visitation, saith HaShem."},"HEBREW":{"text":"לָכֵן֩ יִֽהְיֶ֨ה דַרְכָּ֜ם לָהֶ֗ם כַּחֲלַקְלַקּוֹת֙ בָּֽאֲפֵלָ֔ה יִדַּ֖חוּ וְנָ֣פְלוּ בָ֑הּ כִּֽי־אָבִ֨יא עֲלֵיהֶ֥ם רָעָ֛ה שְׁנַ֥ת פְּקֻדָּתָ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["darkness","year","LORD"],"peopleInVerse":[],"themesInVerse":["fall_sin","light_darkness"]},"13":{"text":"And I have seen folly in the prophets of Samaria; they prophesied in Baal, and caused my people Israel to err.","ref":"Jeremiah 23:13","synthesized":"“Among the prophets of Samaria I saw an offensive thing: They prophesied by Baal and led My people Israel astray.","sources":{"KJV":{"text":"And I have seen folly in the prophets of Samaria; they prophesied in Baal, and caused my people Israel to err."},"BSB":{"text":"“Among the prophets of Samaria I saw an offensive thing: They prophesied by Baal and led My people Israel astray."},"TANAKH":{"text":"And I have seen unseemliness in the prophets of Samaria: they prophesied by Baal, and caused My people Israel to err."},"HEBREW":{"text":"וּבִנְבִיאֵ֥י שֹׁמְר֖וֹן רָאִ֣יתִי תִפְלָ֑ה הִנַּבְּא֣וּ בַבַּ֔עַל וַיַּתְע֥וּ אֶת־עַמִּ֖י אֶת־יִשְׂרָאֵֽל׃"}},"definableWords":["Samaria","saw","people","Israel"],"peopleInVerse":[],"placesInVerse":["Samaria"]},"14":{"text":"I have seen also in the prophets of Jerusalem an horrible thing: they commit adultery, and walk in lies: they strengthen also the hands of evildoers, that none doth return from his wickedness: they are all of them unto me as Sodom, and the inhabitants thereof as Gomorrah.","ref":"Jeremiah 23:14","synthesized":"And among the prophets of Jerusalem I have seen a horrible thing: They commit adultery and walk in lies. They strengthen the hands of evildoers, so that no one turns his back on wickedness. They are all like Sodom to Me; the people of Jerusalem are like Gomorrah.”","sources":{"KJV":{"text":"I have seen also in the prophets of Jerusalem an horrible thing: they commit adultery, and walk in lies: they strengthen also the hands of evildoers, that none doth return from his wickedness: they are all of them unto me as Sodom, and the inhabitants thereof as Gomorrah."},"BSB":{"text":"And among the prophets of Jerusalem I have seen a horrible thing: They commit adultery and walk in lies. They strengthen the hands of evildoers, so that no one turns his back on wickedness. They are all like Sodom to Me; the people of Jerusalem are like Gomorrah.”"},"TANAKH":{"text":"But in the prophets of Jerusalem I have seen a horrible thing: they commit adultery, and walk in lies, and they strengthen the hands of evil-doers, that none doth return from his wickedness; they are all of them become unto Me as Sodom, and the inhabitants thereof as Gomorrah."},"HEBREW":{"text":"וּבִנְבִאֵ֨י יְרוּשָׁלִַ֜ם רָאִ֣יתִי שַׁעֲרוּרָ֗ה נָא֞וֹף וְהָלֹ֤ךְ בַּשֶּׁ֙קֶר֙ וְחִזְּקוּ֙ יְדֵ֣י מְרֵעִ֔ים לְבִ֨לְתִּי־שָׁ֔בוּ אִ֖ישׁ מֵרָֽעָת֑וֹ הָֽיוּ־לִ֤י כֻלָּם֙ כִּסְדֹ֔ם וְיֹשְׁבֶ֖יהָ כַּעֲמֹרָֽה׃"}},"definableWords":["Jerusalem","walk","one","Sodom","people","Gomorrah"],"peopleInVerse":[],"placesInVerse":["Jerusalem","Sodom","Gomorrah"]},"15":{"text":"Therefore thus saith the LORD of hosts concerning the prophets; Behold, I will feed them with wormwood, and make them drink the water of gall: for from the prophets of Jerusalem is profaneness gone forth into all the land.","ref":"Jeremiah 23:15","synthesized":"Therefore this is what the LORD of Hosts says concerning the prophets:  “I will feed them wormwood and give them poisoned water to drink, for from the prophets of Jerusalem ungodliness has spread throughout the land.”","sources":{"KJV":{"text":"Therefore thus saith the LORD of hosts concerning the prophets; Behold, I will feed them with wormwood, and make them drink the water of gall: for from the prophets of Jerusalem is profaneness gone forth into all the land."},"BSB":{"text":"Therefore this is what the LORD of Hosts says concerning the prophets:  “I will feed them wormwood and give them poisoned water to drink, for from the prophets of Jerusalem ungodliness has spread throughout the land.”"},"TANAKH":{"text":"Therefore thus saith HaShem of hosts concerning the prophets: Behold, I will feed them with wormwood, and make them drink the water of gall; for from the prophets of Jerusalem is ungodliness gone forth into all the land."},"HEBREW":{"text":"לָכֵ֞ן כֹּֽה־אָמַ֨ר יְהוָ֤ה צְבָאוֹת֙ עַל־הַנְּבִאִ֔ים הִנְנִ֨י מַאֲכִ֤יל אוֹתָם֙ לַֽעֲנָ֔ה וְהִשְׁקִתִ֖ים מֵי־רֹ֑אשׁ כִּ֗י מֵאֵת֙ נְבִיאֵ֣י יְרוּשָׁלִַ֔ם יָצְאָ֥ה חֲנֻפָּ֖ה לְכָל־הָאָֽרֶץ׃"}},"definableWords":["LORD","water","Jerusalem","land"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["bread_water_life","land_promise"]},"16":{"text":"Thus saith the LORD of hosts, Hearken not unto the words of the prophets that prophesy unto you: they make you vain: they speak a vision of their own heart, and not out of the mouth of the LORD.","ref":"Jeremiah 23:16","synthesized":"This is what the LORD of Hosts says:  “Do not listen to the words of the prophets who prophesy to you. They are filling you with false hopes. They speak visions from their own minds, not from the mouth of the LORD.","sources":{"KJV":{"text":"Thus saith the LORD of hosts, Hearken not unto the words of the prophets that prophesy unto you: they make you vain: they speak a vision of their own heart, and not out of the mouth of the LORD."},"BSB":{"text":"This is what the LORD of Hosts says:  “Do not listen to the words of the prophets who prophesy to you. They are filling you with false hopes. They speak visions from their own minds, not from the mouth of the LORD."},"TANAKH":{"text":"Thus saith HaShem of hosts: Hearken not unto the words of the prophets that prophesy unto you, they lead you unto vanity; they speak a vision of their own heart, and not out of the mouth of HaShem."},"HEBREW":{"text":"כֹּֽה־אָמַ֞ר יְהוָ֣ה צְבָא֗וֹת אַֽל־תִּשְׁמְע֞וּ עַל־דִּבְרֵ֤י הַנְּבִאִים֙ הַנִּבְּאִ֣ים לָכֶ֔ם מַהְבִּלִ֥ים הֵ֖מָּה אֶתְכֶ֑ם חֲז֤וֹן לִבָּם֙ יְדַבֵּ֔רוּ לֹ֖א מִפִּ֥י יְהוָֽה׃"}},"definableWords":["LORD","Lord"],"peopleInVerse":[]},"17":{"text":"They say still unto them that despise me, The LORD hath said, Ye shall have peace; and they say unto every one that walketh after the imagination of his own heart, No evil shall come upon you.","ref":"Jeremiah 23:17","synthesized":"They keep saying to those who despise Me, ‘The LORD says that you will have peace,’ and to everyone who walks in the stubbornness of his own heart, ‘No harm will come to you.’","sources":{"KJV":{"text":"They say still unto them that despise me, The LORD hath said, Ye shall have peace; and they say unto every one that walketh after the imagination of his own heart, No evil shall come upon you."},"BSB":{"text":"They keep saying to those who despise Me, ‘The LORD says that you will have peace,’ and to everyone who walks in the stubbornness of his own heart, ‘No harm will come to you.’"},"TANAKH":{"text":"They say continually unto them that despise Me: 'The HaShem hath said: Ye shall have peace'; and unto every one that walketh in the stubbornness of his own heart they say: 'No evil shall come upon you';"},"HEBREW":{"text":"אֹמְרִ֤ים אָמוֹר֙ לִֽמְנַאֲצַ֔י דִּבֶּ֣ר יְהוָ֔ה שָׁל֖וֹם יִֽהְיֶ֣ה לָכֶ֑ם וְ֠כֹל הֹלֵ֞ךְ בִּשְׁרִר֤וּת לִבּוֹ֙ אָֽמְר֔וּ לֹֽא־תָב֥וֹא עֲלֵיכֶ֖ם רָעָֽה׃"}},"definableWords":["keep","LORD","peace","heart"],"peopleInVerse":[],"themesInVerse":["peace"]},"18":{"text":"For who hath stood in the counsel of the LORD, and hath perceived and heard his word? who hath marked his word, and heard it?","ref":"Jeremiah 23:18","synthesized":"But which of them has stood in the council of the LORD to see and hear His word? Who has given heed to His word and obeyed it?","sources":{"KJV":{"text":"For who hath stood in the counsel of the LORD, and hath perceived and heard his word? who hath marked his word, and heard it?"},"BSB":{"text":"But which of them has stood in the council of the LORD to see and hear His word? Who has given heed to His word and obeyed it?"},"TANAKH":{"text":"For who hath stood in the council of HaShem, that he should perceive and hear His word? Who hath attended to His word, and heard it?"},"HEBREW":{"text":"כִּ֣י מִ֤י עָמַד֙ בְּס֣וֹד יְהוָ֔ה וְיֵ֖רֶא וְיִשְׁמַ֣ע אֶת־דְּבָר֑וֹ מִֽי־הִקְשִׁ֥יב דברי דְּבָר֖וֹ וַיִּשְׁמָֽע׃"}},"definableWords":["LORD","see","hear","word"],"peopleInVerse":[]},"19":{"text":"Behold, a whirlwind of the LORD is gone forth in fury, even a grievous whirlwind: it shall fall grievously upon the head of the wicked.","ref":"Jeremiah 23:19","synthesized":"Behold, the storm of the LORD has gone out with fury, a whirlwind swirling down upon the heads of the wicked.","sources":{"KJV":{"text":"Behold, a whirlwind of the LORD is gone forth in fury, even a grievous whirlwind: it shall fall grievously upon the head of the wicked."},"BSB":{"text":"Behold, the storm of the LORD has gone out with fury, a whirlwind swirling down upon the heads of the wicked."},"TANAKH":{"text":"Behold, a storm of HaShem is gone forth in fury, yea, a whirling storm; it shall whirl upon the head of the wicked."},"HEBREW":{"text":"הִנֵּ֣ה ׀ סַעֲרַ֣ת יְהוָ֗ה חֵמָה֙ יָֽצְאָ֔ה וְסַ֖עַר מִתְחוֹלֵ֑ל עַ֛ל רֹ֥אשׁ רְשָׁעִ֖ים יָחֽוּל׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"20":{"text":"The anger of the LORD shall not return, until he have executed, and till he have performed the thoughts of his heart: in the latter days ye shall consider it perfectly.","ref":"Jeremiah 23:20","synthesized":"The anger of the LORD will not turn back until He has fully accomplished the purposes of His heart. In the days to come you will understand this clearly.","sources":{"KJV":{"text":"The anger of the LORD shall not return, until he have executed, and till he have performed the thoughts of his heart: in the latter days ye shall consider it perfectly."},"BSB":{"text":"The anger of the LORD will not turn back until He has fully accomplished the purposes of His heart. In the days to come you will understand this clearly."},"TANAKH":{"text":"The anger of HaShem shall not return, until He have executed, and till He have performed the purposes of His heart; in the end of days ye shall consider it perfectly."},"HEBREW":{"text":"לֹ֤א יָשׁוּב֙ אַף־יְהוָ֔ה עַד־עֲשֹׂת֥וֹ וְעַד־הֲקִימ֖וֹ מְזִמּ֣וֹת לִבּ֑וֹ בְּאַֽחֲרִית֙ הַיָּמִ֔ים תִּתְבּ֥וֹנְנוּ בָ֖הּ בִּינָֽה׃"}},"definableWords":["anger","LORD","heart","days"],"peopleInVerse":[]},"21":{"text":"I have not sent these prophets, yet they ran: I have not spoken to them, yet they prophesied.","ref":"Jeremiah 23:21","synthesized":"I did not send these prophets, yet they have run with their message; I did not speak to them, yet they have prophesied.","sources":{"KJV":{"text":"I have not sent these prophets, yet they ran: I have not spoken to them, yet they prophesied."},"BSB":{"text":"I did not send these prophets, yet they have run with their message; I did not speak to them, yet they have prophesied."},"TANAKH":{"text":"I have not sent these prophets, yet they ran; I have not spoken to them, yet they prophesied."},"HEBREW":{"text":"לֹא־שָׁלַ֥חְתִּי אֶת־הַנְּבִאִ֖ים וְהֵ֣ם רָ֑צוּ לֹא־דִבַּ֥רְתִּי אֲלֵיהֶ֖ם וְהֵ֥ם נִבָּֽאוּ׃"}},"definableWords":["run"],"peopleInVerse":[]},"22":{"text":"But if they had stood in my counsel, and had caused my people to hear my words, then they should have turned them from their evil way, and from the evil of their doings.","ref":"Jeremiah 23:22","synthesized":"But if they had stood in My council, they would have proclaimed My words to My people and turned them back from their evil ways and deeds.”","sources":{"KJV":{"text":"But if they had stood in my counsel, and had caused my people to hear my words, then they should have turned them from their evil way, and from the evil of their doings."},"BSB":{"text":"But if they had stood in My council, they would have proclaimed My words to My people and turned them back from their evil ways and deeds.”"},"TANAKH":{"text":"But if they have stood in My council, then let them cause My people to hear My words, and turn them from their evil way, and from the evil of their doings."},"HEBREW":{"text":"וְאִֽם־עָמְד֖וּ בְּסוֹדִ֑י וְיַשְׁמִ֤עוּ דְבָרַי֙ אֶת־עַמִּ֔י וִֽישִׁבוּם֙ מִדַּרְכָּ֣ם הָרָ֔ע וּמֵרֹ֖עַ מַֽעַלְלֵיהֶֽם׃"}},"definableWords":["people","evil"],"peopleInVerse":[]},"23":{"text":"Am I a God at hand, saith the LORD, and not a God afar off?","ref":"Jeremiah 23:23","synthesized":"“Am I only a God nearby,” declares the LORD, “and not a God far away?”","sources":{"KJV":{"text":"Am I a God at hand, saith the LORD, and not a God afar off?"},"BSB":{"text":"“Am I only a God nearby,” declares the LORD, “and not a God far away?”"},"TANAKH":{"text":"Am I a G-d near at hand, saith HaShem, and not a G-d afar off?"},"HEBREW":{"text":"הַאֱלֹהֵ֧י מִקָּרֹ֛ב אָ֖נִי נְאֻם־יְהוָ֑ה וְלֹ֥א אֱלֹהֵ֖י מֵרָחֹֽק׃"}},"definableWords":["God","LORD"],"peopleInVerse":[]},"24":{"text":"Can any hide himself in secret places that I shall not see him? saith the LORD. Do not I fill heaven and earth? saith the LORD.","ref":"Jeremiah 23:24","synthesized":"“Can a man hide in secret places where I cannot see him?” declares the LORD.  “Do I not fill the heavens and the earth?” declares the LORD.","sources":{"KJV":{"text":"Can any hide himself in secret places that I shall not see him? saith the LORD. Do not I fill heaven and earth? saith the LORD."},"BSB":{"text":"“Can a man hide in secret places where I cannot see him?” declares the LORD.  “Do I not fill the heavens and the earth?” declares the LORD."},"TANAKH":{"text":"Can any hide himself in secret places that I shall not see him? saith HaShem. Do not I fill heaven and earth? saith HaShem."},"HEBREW":{"text":"אִם־יִסָּתֵ֨ר אִ֧ישׁ בַּמִּסְתָּרִ֛ים וַאֲנִ֥י לֹֽא־אֶרְאֶ֖נּוּ נְאֻם־יְהוָ֑ה הֲל֨וֹא אֶת־הַשָּׁמַ֧יִם וְאֶת־הָאָ֛רֶץ אֲנִ֥י מָלֵ֖א נְאֻם־יְהוָֽה׃"}},"definableWords":["man","see","LORD","fill","heavens","earth","Lord"],"peopleInVerse":[]},"25":{"text":"I have heard what the prophets said, that prophesy lies in my name, saying, I have dreamed, I have dreamed.","ref":"Jeremiah 23:25","synthesized":"“I have heard the sayings of the prophets who prophesy lies in My name: ‘I had a dream! I had a dream!’","sources":{"KJV":{"text":"I have heard what the prophets said, that prophesy lies in my name, saying, I have dreamed, I have dreamed."},"BSB":{"text":"“I have heard the sayings of the prophets who prophesy lies in My name: ‘I had a dream! I had a dream!’"},"TANAKH":{"text":"I have heard what the prophets have said, that prophesy lies in My name, saying: 'I have dreamed, I have dreamed.'"},"HEBREW":{"text":"שָׁמַ֗עְתִּי אֵ֤ת אֲשֶׁר־אָֽמְרוּ֙ הַנְּבִאִ֔ים הַֽנִּבְּאִ֥ים בִּשְׁמִ֛י שֶׁ֖קֶר לֵאמֹ֑ר חָלַ֖מְתִּי חָלָֽמְתִּי׃"}},"definableWords":["name"],"peopleInVerse":[]},"26":{"text":"How long shall this be in the heart of the prophets that prophesy lies? yea, they are prophets of the deceit of their own heart;","ref":"Jeremiah 23:26","synthesized":"How long will this continue in the hearts of these prophets who prophesy falsehood, these prophets of the delusion of their own minds?","sources":{"KJV":{"text":"How long shall this be in the heart of the prophets that prophesy lies? yea, they are prophets of the deceit of their own heart;"},"BSB":{"text":"How long will this continue in the hearts of these prophets who prophesy falsehood, these prophets of the delusion of their own minds?"},"TANAKH":{"text":"How long shall this be? Is it in the heart of the prophets that prophesy lies, and the prophets of the deceit of their own heart?"},"HEBREW":{"text":"עַד־מָתַ֗י הֲיֵ֛שׁ בְּלֵ֥ב הַנְּבִאִ֖ים נִבְּאֵ֣י הַשָּׁ֑קֶר וּנְבִיאֵ֖י תַּרְמִ֥ת לִבָּֽם׃"}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"Which think to cause my people to forget my name by their dreams which they tell every man to his neighbour, as their fathers have forgotten my name for Baal.","ref":"Jeremiah 23:27","synthesized":"They suppose the dreams that they tell one another will make My people forget My name, just as their fathers forgot My name through the worship of Baal.","sources":{"KJV":{"text":"Which think to cause my people to forget my name by their dreams which they tell every man to his neighbour, as their fathers have forgotten my name for Baal."},"BSB":{"text":"They suppose the dreams that they tell one another will make My people forget My name, just as their fathers forgot My name through the worship of Baal."},"TANAKH":{"text":"That think to cause My people to forget My name by their dreams which they tell every man to his neighbour, as their fathers forgot My name for Baal."},"HEBREW":{"text":"הַחֹשְׁבִ֗ים לְהַשְׁכִּ֤יחַ אֶת־עַמִּי֙ שְׁמִ֔י בַּחֲל֣וֹמֹתָ֔ם אֲשֶׁ֥ר יְסַפְּר֖וּ אִ֣ישׁ לְרֵעֵ֑הוּ כַּאֲשֶׁ֨ר שָׁכְח֧וּ אֲבוֹתָ֛ם אֶת־שְׁמִ֖י בַּבָּֽעַל׃"}},"definableWords":["one","make","people","name","fathers","worship"],"peopleInVerse":[],"themesInVerse":["worship"]},"28":{"text":"The prophet that hath a dream, let him tell a dream; and he that hath my word, let him speak my word faithfully. What is the chaff to the wheat? saith the LORD.","ref":"Jeremiah 23:28","synthesized":"Let the prophet who has a dream retell it, but let him who has My word speak it truthfully. For what is straw compared to grain?” declares the LORD.","sources":{"KJV":{"text":"The prophet that hath a dream, let him tell a dream; and he that hath my word, let him speak my word faithfully. What is the chaff to the wheat? saith the LORD."},"BSB":{"text":"Let the prophet who has a dream retell it, but let him who has My word speak it truthfully. For what is straw compared to grain?” declares the LORD."},"TANAKH":{"text":"The prophet that hath a dream, let him tell a dream; and he that hath My word; let him speak My word faithfully. What hath the straw to do with the wheat? saith HaShem."},"HEBREW":{"text":"הַנָּבִ֞יא אֲשֶׁר־אִתּ֤וֹ חֲלוֹם֙ יְסַפֵּ֣ר חֲל֔וֹם וַאֲשֶׁ֤ר דְּבָרִי֙ אִתּ֔וֹ יְדַבֵּ֥ר דְּבָרִ֖י אֱמֶ֑ת מַה־לַתֶּ֥בֶן אֶת־הַבָּ֖ר נְאֻם־יְהוָֽה׃"}},"definableWords":["prophet","word","LORD"],"peopleInVerse":[]},"29":{"text":"Is not my word like as a fire? saith the LORD; and like a hammer that breaketh the rock in pieces?","ref":"Jeremiah 23:29","synthesized":"“Is not My word like fire,” declares the LORD, “and like a hammer that smashes a rock?”","sources":{"KJV":{"text":"Is not my word like as a fire? saith the LORD; and like a hammer that breaketh the rock in pieces?"},"BSB":{"text":"“Is not My word like fire,” declares the LORD, “and like a hammer that smashes a rock?”"},"TANAKH":{"text":"Is not My word like as fire? saith HaShem; and like a hammer that breaketh the rock in pieces?"},"HEBREW":{"text":"הֲל֨וֹא כֹ֧ה דְבָרִ֛י כָּאֵ֖שׁ נְאֻם־יְהוָ֑ה וּכְפַטִּ֖ישׁ יְפֹ֥צֵֽץ סָֽלַע׃"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"30":{"text":"Therefore, behold, I am against the prophets, saith the LORD, that steal my words every one from his neighbour.","ref":"Jeremiah 23:30","synthesized":"“Therefore behold,” declares the LORD, “I am against the prophets who steal from one another words they attribute to Me.”","sources":{"KJV":{"text":"Therefore, behold, I am against the prophets, saith the LORD, that steal my words every one from his neighbour."},"BSB":{"text":"“Therefore behold,” declares the LORD, “I am against the prophets who steal from one another words they attribute to Me.”"},"TANAKH":{"text":"Therefore, behold, I am against the prophets, saith HaShem, that steal My words every one from his neighbour."},"HEBREW":{"text":"לָכֵ֛ן הִנְנִ֥י עַל־הַנְּבִאִ֖ים נְאֻם־יְהוָ֑ה מְגַנְּבֵ֣י דְבָרַ֔י אִ֖ישׁ מֵאֵ֥ת רֵעֵֽהוּ׃"}},"definableWords":["LORD","one"],"peopleInVerse":[]},"31":{"text":"Behold, I am against the prophets, saith the LORD, that use their tongues, and say, He saith.","ref":"Jeremiah 23:31","synthesized":"“Yes,” declares the LORD, “I am against the prophets who wag their own tongues and proclaim, ‘The LORD declares it.’”","sources":{"KJV":{"text":"Behold, I am against the prophets, saith the LORD, that use their tongues, and say, He saith."},"BSB":{"text":"“Yes,” declares the LORD, “I am against the prophets who wag their own tongues and proclaim, ‘The LORD declares it.’”"},"TANAKH":{"text":"Behold, I am against the prophets, saith HaShem, that use there tongues and say: 'He saith.'"},"HEBREW":{"text":"הִנְנִ֥י עַל־הַנְּבִיאִ֖ם נְאֻם־יְהוָ֑ה הַלֹּקְחִ֣ים לְשׁוֹנָ֔ם וַֽיִּנְאֲמ֖וּ נְאֻֽם׃"}},"definableWords":["LORD","Lord"],"peopleInVerse":[]},"32":{"text":"Behold, I am against them that prophesy false dreams, saith the LORD, and do tell them, and cause my people to err by their lies, and by their lightness; yet I sent them not, nor commanded them: therefore they shall not profit this people at all, saith the LORD.","ref":"Jeremiah 23:32","synthesized":"“Indeed,” declares the LORD, “I am against those who prophesy false dreams and retell them to lead My people astray with their reckless lies. It was not I who sent them or commanded them, and they are of no benefit at all to these people,” declares the LORD.","sources":{"KJV":{"text":"Behold, I am against them that prophesy false dreams, saith the LORD, and do tell them, and cause my people to err by their lies, and by their lightness; yet I sent them not, nor commanded them: therefore they shall not profit this people at all, saith the LORD."},"BSB":{"text":"“Indeed,” declares the LORD, “I am against those who prophesy false dreams and retell them to lead My people astray with their reckless lies. It was not I who sent them or commanded them, and they are of no benefit at all to these people,” declares the LORD."},"TANAKH":{"text":"Behold, I am against them that prophesy lying dreams, saith HaShem, and do tell them, and cause My people to err by their lies, and by their wantonness; yet I sent them not, nor commanded them; neither can they profit this people at all, saith HaShem."},"HEBREW":{"text":"הִ֠נְנִי עַֽל־נִבְּאֵ֞י חֲלֹמ֥וֹת שֶׁ֙קֶר֙ נְאֻם־יְהוָ֔ה וַֽיְסַפְּרוּם֙ וַיַּתְע֣וּ אֶת־עַמִּ֔י בְּשִׁקְרֵיהֶ֖ם וּבְפַחֲזוּתָ֑ם וְאָנֹכִ֨י לֹֽא־שְׁלַחְתִּ֜ים וְלֹ֣א צִוִּיתִ֗ים וְהוֹעֵ֛יל לֹֽא־יוֹעִ֥ילוּ לָֽעָם־הַזֶּ֖ה נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD","people","or","Lord"],"peopleInVerse":[]},"33":{"text":"And when this people, or the prophet, or a priest, shall ask thee, saying, What is the burden of the LORD? thou shalt then say unto them, What burden? I will even forsake you, saith the LORD.","ref":"Jeremiah 23:33","synthesized":"“Now when this people or a prophet or priest asks you, ‘What is the burden of the LORD?’ you are to say to them, ‘What burden? I will forsake you, declares the LORD.’","sources":{"KJV":{"text":"And when this people, or the prophet, or a priest, shall ask thee, saying, What is the burden of the LORD? thou shalt then say unto them, What burden? I will even forsake you, saith the LORD."},"BSB":{"text":"“Now when this people or a prophet or priest asks you, ‘What is the burden of the LORD?’ you are to say to them, ‘What burden? I will forsake you, declares the LORD.’"},"TANAKH":{"text":"And when this people, or the prophet, or a priest, shall ask thee, saying: 'What is the burden of HaShem?' then shalt thou say unto them: 'What burden! I will cast you off, saith HaShem.'"},"HEBREW":{"text":"וְכִי־יִשְׁאָלְךָ֩ הָעָ֨ם הַזֶּ֜ה אֽוֹ־הַנָּבִ֤יא אֽוֹ־כֹהֵן֙ לֵאמֹ֔ר מַה־מַשָּׂ֖א יְהוָ֑ה וְאָמַרְתָּ֤ אֲלֵיהֶם֙ אֶת־מַה־מַשָּׂ֔א וְנָטַשְׁתִּ֥י אֶתְכֶ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["people","or","prophet","priest","LORD","Lord"],"peopleInVerse":[],"themesInVerse":["kingdom_priesthood"]},"34":{"text":"And as for the prophet, and the priest, and the people, that shall say, The burden of the LORD, I will even punish that man and his house.","ref":"Jeremiah 23:34","synthesized":"As for the prophet or priest or anyone who claims, ‘This is the burden of the LORD,’ I will punish that man and his household.","sources":{"KJV":{"text":"And as for the prophet, and the priest, and the people, that shall say, The burden of the LORD, I will even punish that man and his house."},"BSB":{"text":"As for the prophet or priest or anyone who claims, ‘This is the burden of the LORD,’ I will punish that man and his household."},"TANAKH":{"text":"And as for the prophet, and the priest, and the people, that shall say: 'The burden of HaShem', I will even punish that man and his house."},"HEBREW":{"text":"וְהַנָּבִ֤יא וְהַכֹּהֵן֙ וְהָעָ֔ם אֲשֶׁ֥ר יֹאמַ֖ר מַשָּׂ֣א יְהוָ֑ה וּפָקַדְתִּ֛י עַל־הָאִ֥ישׁ הַה֖וּא וְעַל־בֵּיתֽוֹ׃"}},"definableWords":["prophet","or","priest","LORD","man"],"peopleInVerse":[],"themesInVerse":["kingdom_priesthood"]},"35":{"text":"Thus shall ye say every one to his neighbour, and every one to his brother, What hath the LORD answered? and, What hath the LORD spoken?","ref":"Jeremiah 23:35","synthesized":"This is what each man is to say to his friend and to his brother: ‘What has the LORD answered?’ or ‘What has the LORD spoken?’","sources":{"KJV":{"text":"Thus shall ye say every one to his neighbour, and every one to his brother, What hath the LORD answered? and, What hath the LORD spoken?"},"BSB":{"text":"This is what each man is to say to his friend and to his brother: ‘What has the LORD answered?’ or ‘What has the LORD spoken?’"},"TANAKH":{"text":"Thus shall ye say every one to his neighbour, and every one to his brother: 'What hath HaShem answered?' and: 'What hath HaShem spoken?'"},"HEBREW":{"text":"כֹּ֥ה תֹאמְר֛וּ אִ֥ישׁ עַל־רֵעֵ֖הוּ וְאִ֣ישׁ אֶל־אָחִ֑יו מֶה־עָנָ֣ה יְהוָ֔ה וּמַה־דִּבֶּ֖ר יְהוָֽה׃"}},"definableWords":["man","brother","LORD","or","Lord"],"peopleInVerse":[]},"36":{"text":"And the burden of the LORD shall ye mention no more: for every man’s word shall be his burden; for ye have perverted the words of the living God, of the LORD of hosts our God.","ref":"Jeremiah 23:36","synthesized":"But refer no more to the burden of the LORD, for each man’s word becomes the burden, so that you pervert the words of the living God, the LORD of Hosts, our God.","sources":{"KJV":{"text":"And the burden of the LORD shall ye mention no more: for every man’s word shall be his burden; for ye have perverted the words of the living God, of the LORD of hosts our God."},"BSB":{"text":"But refer no more to the burden of the LORD, for each man’s word becomes the burden, so that you pervert the words of the living God, the LORD of Hosts, our God."},"TANAKH":{"text":"And the burden of HaShem shall ye mention no more; for every man's own word shall be his burden; and would ye pervert the words of the living G-d, of HaShem of hosts our G-d?"},"HEBREW":{"text":"וּמַשָּׂ֥א יְהוָ֖ה לֹ֣א תִזְכְּרוּ־ע֑וֹד כִּ֣י הַמַּשָּׂ֗א יִֽהְיֶה֙ לְאִ֣ישׁ דְּבָר֔וֹ וַהֲפַכְתֶּ֗ם אֶת־דִּבְרֵי֙ אֱלֹהִ֣ים חַיִּ֔ים יְהוָ֥ה צְבָא֖וֹת אֱלֹהֵֽינוּ׃"}},"definableWords":["LORD","man","word","living","God","Lord"],"peopleInVerse":[]},"37":{"text":"Thus shalt thou say to the prophet, What hath the LORD answered thee? and, What hath the LORD spoken?","ref":"Jeremiah 23:37","synthesized":"Thus you are to say to the prophet: ‘What has the LORD answered you?’ and ‘What has the LORD spoken?’","sources":{"KJV":{"text":"Thus shalt thou say to the prophet, What hath the LORD answered thee? and, What hath the LORD spoken?"},"BSB":{"text":"Thus you are to say to the prophet: ‘What has the LORD answered you?’ and ‘What has the LORD spoken?’"},"TANAKH":{"text":"Thus shalt thou say to the prophet: 'What hath HaShem answered thee?' and: 'What hath HaShem spoken?'"},"HEBREW":{"text":"כֹּ֥ה תֹאמַ֖ר אֶל־הַנָּבִ֑יא מֶה־עָנָ֣ךְ יְהוָ֔ה וּמַה־דִּבֶּ֖ר יְהוָֽה׃"}},"definableWords":["prophet","LORD","Lord"],"peopleInVerse":[]},"38":{"text":"But since ye say, The burden of the LORD; therefore thus saith the LORD; Because ye say this word, The burden of the LORD, and I have sent unto you, saying, Ye shall not say, The burden of the LORD;","ref":"Jeremiah 23:38","synthesized":"But if you claim, ‘This is the burden of the LORD,’ then this is what the LORD says: Because you have said, ‘This is the burden of the LORD,’ and I specifically told you not to make this claim,","sources":{"KJV":{"text":"But since ye say, The burden of the LORD; therefore thus saith the LORD; Because ye say this word, The burden of the LORD, and I have sent unto you, saying, Ye shall not say, The burden of the LORD;"},"BSB":{"text":"But if you claim, ‘This is the burden of the LORD,’ then this is what the LORD says: Because you have said, ‘This is the burden of the LORD,’ and I specifically told you not to make this claim,"},"TANAKH":{"text":"But if ye say: 'The burden of HaShem'; therefore thus saith HaShem: Because ye say this word: 'The burden of HaShem', and I have sent unto you, saying: 'Ye shall not say: The burden of HaShem';"},"HEBREW":{"text":"וְאִם־מַשָּׂ֣א יְהוָה֮ תֹּאמֵרוּ֒ לָכֵ֗ן כֹּ֚ה אָמַ֣ר יְהוָ֔ה יַ֧עַן אֲמָרְכֶ֛ם אֶת־הַדָּבָ֥ר הַזֶּ֖ה מַשָּׂ֣א יְהוָ֑ה וָאֶשְׁלַ֤ח אֲלֵיכֶם֙ לֵאמֹ֔ר לֹ֥א תֹאמְר֖וּ מַשָּׂ֥א יְהוָֽה׃"}},"definableWords":["LORD","Lord","make"],"peopleInVerse":[]},"39":{"text":"Therefore, behold, I, even I, will utterly forget you, and I will forsake you, and the city that I gave you and your fathers, and cast you out of my presence:","ref":"Jeremiah 23:39","synthesized":"therefore I will surely forget you and will cast you out of My presence, both you and the city that I gave to you and your fathers.","sources":{"KJV":{"text":"Therefore, behold, I, even I, will utterly forget you, and I will forsake you, and the city that I gave you and your fathers, and cast you out of my presence:"},"BSB":{"text":"therefore I will surely forget you and will cast you out of My presence, both you and the city that I gave to you and your fathers."},"TANAKH":{"text":"therefore, behold, I will utterly tear you out, and I will cast you off, and the city that I gave unto you and to your fathers, away from My presence;"},"HEBREW":{"text":"לָכֵ֣ן הִנְנִ֔י וְנָשִׁ֥יתִי אֶתְכֶ֖ם נָשֹׁ֑א וְנָטַשְׁתִּ֣י אֶתְכֶ֗ם וְאֶת־הָעִיר֙ אֲשֶׁ֨ר נָתַ֧תִּי לָכֶ֛ם וְלַאֲבוֹתֵיכֶ֖ם מֵעַ֥ל פָּנָֽי׃"}},"definableWords":["fathers"],"peopleInVerse":[]},"40":{"text":"And I will bring an everlasting reproach upon you, and a perpetual shame, which shall not be forgotten.","ref":"Jeremiah 23:40","synthesized":"And I will bring upon you everlasting shame and perpetual humiliation that will never be forgotten.”","sources":{"KJV":{"text":"And I will bring an everlasting reproach upon you, and a perpetual shame, which shall not be forgotten."},"BSB":{"text":"And I will bring upon you everlasting shame and perpetual humiliation that will never be forgotten.”"},"TANAKH":{"text":"and I will bring an everlasting reproach upon you, and a perpetual shame, which shall not be forgotten"},"HEBREW":{"text":"וְנָתַתִּ֥י עֲלֵיכֶ֖ם חֶרְפַּ֣ת עוֹלָ֑ם וּכְלִמּ֣וּת עוֹלָ֔ם אֲשֶׁ֖ר לֹ֥א תִשָּׁכֵֽחַ׃"}},"definableWords":["everlasting"],"peopleInVerse":[]}}},"24":{"chapter":"24","title":"TWO BASKETS OF FIGS","verses":{"1":{"text":"The LORD shewed me, and, behold, two baskets of figs were set before the temple of the LORD, after that Nebuchadrezzar king of Babylon had carried away captive Jeconiah the son of Jehoiakim king of Judah, and the princes of Judah, with the carpenters and smiths, from Jerusalem, and had brought them to Babylon.","ref":"Jeremiah 24:1","synthesized":"After Nebuchadnezzar king of Babylon had carried away Jeconiah son of Jehoiakim king of Judah, as well as the officials of Judah and the craftsmen and metalsmiths from Jerusalem, and had brought them to Babylon, the LORD showed me two baskets of figs placed in front of the temple of the LORD.","sources":{"KJV":{"text":"The LORD shewed me, and, behold, two baskets of figs were set before the temple of the LORD, after that Nebuchadrezzar king of Babylon had carried away captive Jeconiah the son of Jehoiakim king of Judah, and the princes of Judah, with the carpenters and smiths, from Jerusalem, and had brought them to Babylon."},"BSB":{"text":"After Nebuchadnezzar king of Babylon had carried away Jeconiah son of Jehoiakim king of Judah, as well as the officials of Judah and the craftsmen and metalsmiths from Jerusalem, and had brought them to Babylon, the LORD showed me two baskets of figs placed in front of the temple of the LORD."},"TANAKH":{"text":"HaShem showed me, and behold two baskets of figs set before the temple of HaShem; after that Nebuchadrezzar king of Babylon had carried away captive Jeconiah the son of Jehoiakim, king of Judah, and the princes of Judah, with the craftsmen and smiths, from Jerusalem, and had brought them to Babylon."},"HEBREW":{"text":"הִרְאַנִי֮ יְהוָה֒ וְהִנֵּ֗ה שְׁנֵי֙ דּוּדָאֵ֣י תְאֵנִ֔ים מוּעָדִ֕ים לִפְנֵ֖י הֵיכַ֣ל יְהוָ֑ה אַחֲרֵ֣י הַגְל֣וֹת נְבוּכַדְרֶאצַּ֣ר מֶֽלֶךְ־בָּבֶ֡ל אֶת־יְכָנְיָ֣הוּ בֶן־יְהוֹיָקִ֣ים מֶֽלֶךְ־יְהוּדָה֩ וְאֶת־שָׂרֵ֨י יְהוּדָ֜ה וְאֶת־הֶחָרָ֤שׁ וְאֶת־הַמַּסְגֵּר֙ מִיר֣וּשָׁלִַ֔ם וַיְבִאֵ֖ם בָּבֶֽל׃"}},"definableWords":["king","Babylon","son","King","Judah","Jerusalem","LORD","temple","Lord"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon","Jerusalem"],"themesInVerse":["bread_water_life","kingship","temple"]},"2":{"text":"One basket had very good figs, even like the figs that are first ripe: and the other basket had very naughty figs, which could not be eaten, they were so bad.","ref":"Jeremiah 24:2","synthesized":"One basket had very good figs, like those that ripen early, but the other basket contained very poor figs, so bad they could not be eaten.","sources":{"KJV":{"text":"One basket had very good figs, even like the figs that are first ripe: and the other basket had very naughty figs, which could not be eaten, they were so bad."},"BSB":{"text":"One basket had very good figs, like those that ripen early, but the other basket contained very poor figs, so bad they could not be eaten."},"TANAKH":{"text":"One basket had very good figs, like the figs that are first-ripe; and the other basket had very bad figs, which could not be eaten, they were so bad."},"HEBREW":{"text":"הַדּ֣וּד אֶחָ֗ד תְּאֵנִים֙ טֹב֣וֹת מְאֹ֔ד כִּתְאֵנֵ֖י הַבַּכֻּר֑וֹת וְהַדּ֣וּד אֶחָ֗ד תְּאֵנִים֙ רָע֣וֹת מְאֹ֔ד אֲשֶׁ֥ר לֹא־תֵֽאָכַ֖לְנָה מֵרֹֽעַ׃"}},"definableWords":["one","good"],"peopleInVerse":[]},"3":{"text":"Then said the LORD unto me, What seest thou, Jeremiah? And I said, Figs; the good figs, very good; and the evil, very evil, that cannot be eaten, they are so evil.","ref":"Jeremiah 24:3","synthesized":"“Jeremiah,” the LORD asked, “what do you see?”  “Figs!” I replied. “The good figs are very good, but the bad figs are very bad, so bad they cannot be eaten.”","sources":{"KJV":{"text":"Then said the LORD unto me, What seest thou, Jeremiah? And I said, Figs; the good figs, very good; and the evil, very evil, that cannot be eaten, they are so evil."},"BSB":{"text":"“Jeremiah,” the LORD asked, “what do you see?”  “Figs!” I replied. “The good figs are very good, but the bad figs are very bad, so bad they cannot be eaten.”"},"TANAKH":{"text":"Then said HaShem unto me: 'What seest thou, Jeremiah?' And I said: 'Figs; the good figs, very good; and the bad, very bad, that cannot be eaten, they are so bad.'"},"HEBREW":{"text":"וַיֹּ֨אמֶר יְהוָ֜ה אֵלַ֗י מָֽה־אַתָּ֤ה רֹאֶה֙ יִרְמְיָ֔הוּ וָאֹמַ֖ר תְּאֵנִ֑ים הַתְּאֵנִ֤ים הַטֹּבוֹת֙ טֹב֣וֹת מְאֹ֔ד וְהָֽרָעוֹת֙ רָע֣וֹת מְאֹ֔ד אֲשֶׁ֥ר לֹא־תֵאָכַ֖לְנָה מֵרֹֽעַ׃"}},"definableWords":["LORD","see","good"],"peopleInVerse":["Jeremiah"]},"4":{"text":"Again the word of the LORD came unto me, saying,","ref":"Jeremiah 24:4","synthesized":"Then the word of the LORD came to me, saying,","sources":{"KJV":{"text":"Again the word of the LORD came unto me, saying,"},"BSB":{"text":"Then the word of the LORD came to me, saying,"},"TANAKH":{"text":"And the word of HaShem came unto me, saying:"},"HEBREW":{"text":"וַיְהִ֥י דְבַר־יְהוָ֖ה אֵלַ֥י לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"5":{"text":"Thus saith the LORD, the God of Israel; Like these good figs, so will I acknowledge them that are carried away captive of Judah, whom I have sent out of this place into the land of the Chaldeans for their good.","ref":"Jeremiah 24:5","synthesized":"“This is what the LORD, the God of Israel, says: ‘Like these good figs, so I regard as good the exiles from Judah, whom I have sent away from this place to the land of the Chaldeans.","sources":{"KJV":{"text":"Thus saith the LORD, the God of Israel; Like these good figs, so will I acknowledge them that are carried away captive of Judah, whom I have sent out of this place into the land of the Chaldeans for their good."},"BSB":{"text":"“This is what the LORD, the God of Israel, says: ‘Like these good figs, so I regard as good the exiles from Judah, whom I have sent away from this place to the land of the Chaldeans."},"TANAKH":{"text":"'Thus saith HaShem, the G-d of Israel: Like these good figs, so will I regard the captives of Judah, whom I have sent out of this place into the land of the Chaldeans, for good."},"HEBREW":{"text":"כֹּֽה־אָמַ֤ר יְהוָה֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל כַּתְּאֵנִ֥ים הַטֹּב֖וֹת הָאֵ֑לֶּה כֵּֽן־אַכִּ֞יר אֶת־גָּל֣וּת יְהוּדָ֗ה אֲשֶׁ֨ר שִׁלַּ֜חְתִּי מִן־הַמָּק֥וֹם הַזֶּ֛ה אֶ֥רֶץ כַּשְׂדִּ֖ים לְטוֹבָֽה׃"}},"definableWords":["LORD","God","Israel","good","Judah","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"6":{"text":"For I will set mine eyes upon them for good, and I will bring them again to this land: and I will build them, and not pull them down; and I will plant them, and not pluck them up.","ref":"Jeremiah 24:6","synthesized":"I will keep My eyes on them for good and will return them to this land. I will build them up and not tear them down; I will plant them and not uproot them.","sources":{"KJV":{"text":"For I will set mine eyes upon them for good, and I will bring them again to this land: and I will build them, and not pull them down; and I will plant them, and not pluck them up."},"BSB":{"text":"I will keep My eyes on them for good and will return them to this land. I will build them up and not tear them down; I will plant them and not uproot them."},"TANAKH":{"text":"And I will set Mine eyes upon them for good, and I will bring them back to this land; and I will build them, and not pull them down; and I will plant them, and not pluck them up."},"HEBREW":{"text":"וְשַׂמְתִּ֨י עֵינִ֤י עֲלֵיהֶם֙ לְטוֹבָ֔ה וַהֲשִׁבֹתִ֖ים עַל־הָאָ֣רֶץ הַזֹּ֑את וּבְנִיתִים֙ וְלֹ֣א אֶהֱרֹ֔ס וּנְטַעְתִּ֖ים וְלֹ֥א אֶתּֽוֹשׁ׃"}},"definableWords":["keep","good","land"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise","second_coming"]},"7":{"text":"And I will give them an heart to know me, that I am the LORD: and they shall be my people, and I will be their God: for they shall return unto me with their whole heart.","ref":"Jeremiah 24:7","synthesized":"I will give them a heart to know Me, that I am the LORD. They will be My people, and I will be their God, for they will return to Me with all their heart.","sources":{"KJV":{"text":"And I will give them an heart to know me, that I am the LORD: and they shall be my people, and I will be their God: for they shall return unto me with their whole heart."},"BSB":{"text":"I will give them a heart to know Me, that I am the LORD. They will be My people, and I will be their God, for they will return to Me with all their heart."},"TANAKH":{"text":"And I will give them a heart to know Me, that I am HaShem; and they shall be My people, and I will be their G-d; for they shall return unto Me with their whole heart."},"HEBREW":{"text":"וְנָתַתִּי֩ לָהֶ֨ם לֵ֜ב לָדַ֣עַת אֹתִ֗י כִּ֚י אֲנִ֣י יְהוָ֔ה וְהָיוּ־לִ֣י לְעָ֔ם וְאָ֣נֹכִ֔י אֶהְיֶ֥ה לָהֶ֖ם לֵאלֹהִ֑ים כִּֽי־יָשֻׁ֥בוּ אֵלַ֖י בְּכָל־לִבָּֽם׃"}},"definableWords":["heart","LORD","people","God"],"peopleInVerse":[],"themesInVerse":["exile_return","second_coming"]},"8":{"text":"And as the evil figs, which cannot be eaten, they are so evil; surely thus saith the LORD, So will I give Zedekiah the king of Judah, and his princes, and the residue of Jerusalem, that remain in this land, and them that dwell in the land of Egypt:","ref":"Jeremiah 24:8","synthesized":"But like the bad figs, so bad they cannot be eaten,’ says the LORD, ‘so will I deal with Zedekiah king of Judah, his officials, and the remnant of Jerusalem—those remaining in this land and those living in the land of Egypt.","sources":{"KJV":{"text":"And as the evil figs, which cannot be eaten, they are so evil; surely thus saith the LORD, So will I give Zedekiah the king of Judah, and his princes, and the residue of Jerusalem, that remain in this land, and them that dwell in the land of Egypt:"},"BSB":{"text":"But like the bad figs, so bad they cannot be eaten,’ says the LORD, ‘so will I deal with Zedekiah king of Judah, his officials, and the remnant of Jerusalem—those remaining in this land and those living in the land of Egypt."},"TANAKH":{"text":"And as the bad figs, which cannot be eaten, they are so bad; surely thus saith HaShem: So will I make Zedekiah the king of Judah, and his princes, and the residue of Jerusalem, that remain in this land, and them that dwell in the land of Egypt;"},"HEBREW":{"text":"וְכַתְּאֵנִים֙ הָֽרָע֔וֹת אֲשֶׁ֥ר לֹא־תֵאָכַ֖לְנָה מֵרֹ֑עַ כִּי־כֹ֣ה ׀ אָמַ֣ר יְהוָ֗ה כֵּ֣ן אֶ֠תֵּן אֶת־צִדְקִיָּ֨הוּ מֶֽלֶךְ־יְהוּדָ֤ה וְאֶת־שָׂרָיו֙ וְאֵ֣ת ׀ שְׁאֵרִ֣ית יְרוּשָׁלִַ֗ם הַנִּשְׁאָרִים֙ בָּאָ֣רֶץ הַזֹּ֔את וְהַיֹּשְׁבִ֖ים בְּאֶ֥רֶץ מִצְרָֽיִם׃"}},"definableWords":["LORD","king","Judah","remnant","Jerusalem","land","living","Egypt"],"peopleInVerse":[],"placesInVerse":["Jerusalem","Egypt"],"themesInVerse":["exile_return","exodus_pattern","kingship","land_promise"]},"9":{"text":"And I will deliver them to be removed into all the kingdoms of the earth for their hurt, to be a reproach and a proverb, a taunt and a curse, in all places whither I shall drive them.","ref":"Jeremiah 24:9","synthesized":"I will make them a horror and an offense to all the kingdoms of the earth, a disgrace and an object of scorn, ridicule, and cursing wherever I have banished them.","sources":{"KJV":{"text":"And I will deliver them to be removed into all the kingdoms of the earth for their hurt, to be a reproach and a proverb, a taunt and a curse, in all places whither I shall drive them."},"BSB":{"text":"I will make them a horror and an offense to all the kingdoms of the earth, a disgrace and an object of scorn, ridicule, and cursing wherever I have banished them."},"TANAKH":{"text":"I will even make them a horror among all the kingdoms of the earth for evil; a reproach and a proverb, a taunt and a curse, in all places whither I shall drive them."},"HEBREW":{"text":"וּנְתַתִּים֙ לזועה לְזַעֲוָ֣ה לְרָעָ֔ה לְכֹ֖ל מַמְלְכ֣וֹת הָאָ֑רֶץ לְחֶרְפָּ֤ה וּלְמָשָׁל֙ לִשְׁנִינָ֣ה וְלִקְלָלָ֔ה בְּכָל־הַמְּקֹמ֖וֹת אֲשֶֽׁר־אַדִּיחֵ֥ם שָֽׁם׃"}},"definableWords":["make","earth"],"peopleInVerse":[]},"10":{"text":"And I will send the sword, the famine, and the pestilence, among them, till they be consumed from off the land that I gave unto them and to their fathers.","ref":"Jeremiah 24:10","synthesized":"And I will send against them sword and famine and plague, until they have perished from the land that I gave to them and their fathers.’”","sources":{"KJV":{"text":"And I will send the sword, the famine, and the pestilence, among them, till they be consumed from off the land that I gave unto them and to their fathers."},"BSB":{"text":"And I will send against them sword and famine and plague, until they have perished from the land that I gave to them and their fathers.’”"},"TANAKH":{"text":"And I will send the sword, the famine, and the pestilence, among them, till they be consumed from off the land that I gave unto them and to their fathers.'"},"HEBREW":{"text":"וְשִׁלַּ֣חְתִּי בָ֔ם אֶת־הַחֶ֖רֶב אֶת־הָרָעָ֣ב וְאֶת־הַדָּ֑בֶר עַד־תֻּמָּם֙ מֵעַ֣ל הָאֲדָמָ֔ה אֲשֶׁר־נָתַ֥תִּי לָהֶ֖ם וְלַאֲבוֹתֵיהֶֽם׃"}},"definableWords":["land","fathers"],"peopleInVerse":[],"themesInVerse":["land_promise"]}}},"25":{"chapter":"25","title":"SEVENTY YEARS OF CAPTIVITY FORETOLD","verses":{"1":{"text":"The word that came to Jeremiah concerning all the people of Judah in the fourth year of Jehoiakim the son of Josiah king of Judah, that was the first year of Nebuchadrezzar king of Babylon;","ref":"Jeremiah 25:1","synthesized":"This is the word that came to Jeremiah concerning all the people of Judah in the fourth year of Jehoiakim son of Josiah king of Judah, which was the first year of Nebuchadnezzar king of Babylon.","sources":{"KJV":{"text":"The word that came to Jeremiah concerning all the people of Judah in the fourth year of Jehoiakim the son of Josiah king of Judah, that was the first year of Nebuchadrezzar king of Babylon;"},"BSB":{"text":"This is the word that came to Jeremiah concerning all the people of Judah in the fourth year of Jehoiakim son of Josiah king of Judah, which was the first year of Nebuchadnezzar king of Babylon."},"TANAKH":{"text":"The word that came to Jeremiah concerning all the people of Judah in the fourth year of Jehoiakim the son of Josiah, king of Judah, that was the first year of Nebuchadrezzar king of Babylon;"},"HEBREW":{"text":"הַדָּבָ֞ר אֲשֶׁר־הָיָ֤ה עַֽל־יִרְמְיָ֙הוּ֙ עַל־כָּל־עַ֣ם יְהוּדָ֔ה בַּשָּׁנָה֙ הָֽרְבִעִ֔ית לִיהוֹיָקִ֥ים בֶּן־יֹאשִׁיָּ֖הוּ מֶ֣לֶךְ יְהוּדָ֑ה הִ֗יא הַשָּׁנָה֙ הָרִ֣אשֹׁנִ֔ית לִנְבֽוּכַדְרֶאצַּ֖ר מֶ֥לֶךְ בָּבֶֽל׃"}},"definableWords":["word","people","Judah","year","son","king","King","Babylon"],"peopleInVerse":["Jeremiah","Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"2":{"text":"The which Jeremiah the prophet spake unto all the people of Judah, and to all the inhabitants of Jerusalem, saying,","ref":"Jeremiah 25:2","synthesized":"So the prophet Jeremiah spoke to all the people of Judah and all the residents of Jerusalem as follows:","sources":{"KJV":{"text":"The which Jeremiah the prophet spake unto all the people of Judah, and to all the inhabitants of Jerusalem, saying,"},"BSB":{"text":"So the prophet Jeremiah spoke to all the people of Judah and all the residents of Jerusalem as follows:"},"TANAKH":{"text":"which Jeremiah the prophet spoke unto all the people of Judah, and to all the inhabitants of Jerusalem, saying:"},"HEBREW":{"text":"אֲשֶׁ֨ר דִּבֶּ֜ר יִרְמְיָ֤הוּ הַנָּבִיא֙ עַל־כָּל־עַ֣ם יְהוּדָ֔ה וְאֶ֛ל כָּל־יֹשְׁבֵ֥י יְרוּשָׁלַ֖͏ִם לֵאמֹֽר׃"}},"definableWords":["prophet","people","Judah","Jerusalem"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Jerusalem"]},"3":{"text":"From the thirteenth year of Josiah the son of Amon king of Judah, even unto this day, that is the three and twentieth year, the word of the LORD hath come unto me, and I have spoken unto you, rising early and speaking; but ye have not hearkened.","ref":"Jeremiah 25:3","synthesized":"“From the thirteenth year of Josiah son of Amon king of Judah until this very day—twenty-three years—the word of the LORD has come to me, and I have spoken to you again and again, but you have not listened.","sources":{"KJV":{"text":"From the thirteenth year of Josiah the son of Amon king of Judah, even unto this day, that is the three and twentieth year, the word of the LORD hath come unto me, and I have spoken unto you, rising early and speaking; but ye have not hearkened."},"BSB":{"text":"“From the thirteenth year of Josiah son of Amon king of Judah until this very day—twenty-three years—the word of the LORD has come to me, and I have spoken to you again and again, but you have not listened."},"TANAKH":{"text":"From the thirteenth year of Josiah the son of Amon, king of Judah, even unto this day, these three and twenty years, the word of HaShem hath come unto me, and I have spoken unto you, speaking betimes and often; but ye have not hearkened."},"HEBREW":{"text":"מִן־שְׁלֹ֣שׁ עֶשְׂרֵ֣ה שָׁנָ֡ה לְיֹאשִׁיָּ֣הוּ בֶן־אָמוֹן֩ מֶ֨לֶךְ יְהוּדָ֜ה וְעַ֣ד ׀ הַיּ֣וֹם הַזֶּ֗ה זֶ֚ה שָׁלֹ֤שׁ וְעֶשְׂרִים֙ שָׁנָ֔ה הָיָ֥ה דְבַר־יְהוָ֖ה אֵלָ֑י וָאֲדַבֵּ֧ר אֲלֵיכֶ֛ם אַשְׁכֵּ֥ים וְדַבֵּ֖ר וְלֹ֥א שְׁמַעְתֶּֽם׃"}},"definableWords":["year","son","king","Judah","day","years","word","LORD"],"peopleInVerse":[],"themesInVerse":["kingship"]},"4":{"text":"And the LORD hath sent unto you all his servants the prophets, rising early and sending them; but ye have not hearkened, nor inclined your ear to hear.","ref":"Jeremiah 25:4","synthesized":"And the LORD has sent all His servants the prophets to you again and again, but you have not listened or inclined your ear to hear.","sources":{"KJV":{"text":"And the LORD hath sent unto you all his servants the prophets, rising early and sending them; but ye have not hearkened, nor inclined your ear to hear."},"BSB":{"text":"And the LORD has sent all His servants the prophets to you again and again, but you have not listened or inclined your ear to hear."},"TANAKH":{"text":"And HaShem hath sent unto you all His servants the prophets, sending them betimes and often--but ye have not hearkened, nor inclined your ear to hear--"},"HEBREW":{"text":"וְשָׁלַח֩ יְהוָ֨ה אֲלֵיכֶ֜ם אֶֽת־כָּל־עֲבָדָ֧יו הַנְּבִאִ֛ים הַשְׁכֵּ֥ם וְשָׁלֹ֖חַ וְלֹ֣א שְׁמַעְתֶּ֑ם וְלֹֽא־הִטִּיתֶ֥ם אֶֽת־אָזְנְכֶ֖ם לִשְׁמֹֽעַ׃"}},"definableWords":["LORD","servants","or","hear"],"peopleInVerse":[]},"5":{"text":"They said, Turn ye again now every one from his evil way, and from the evil of your doings, and dwell in the land that the LORD hath given unto you and to your fathers for ever and ever:","ref":"Jeremiah 25:5","synthesized":"The prophets told you, ‘Turn now, each of you, from your evil ways and deeds, and you can dwell in the land that the LORD has given to you and your fathers forever and ever.","sources":{"KJV":{"text":"They said, Turn ye again now every one from his evil way, and from the evil of your doings, and dwell in the land that the LORD hath given unto you and to your fathers for ever and ever:"},"BSB":{"text":"The prophets told you, ‘Turn now, each of you, from your evil ways and deeds, and you can dwell in the land that the LORD has given to you and your fathers forever and ever."},"TANAKH":{"text":"saying: 'Return ye now every one from his evil way, and from the evil of your doings, and dwell in the land that HaShem hath given unto you and to your fathers, for ever and ever;"},"HEBREW":{"text":"לֵאמֹ֗ר שֽׁוּבוּ־נָ֞א אִ֣ישׁ מִדַּרְכּ֤וֹ הָֽרָעָה֙ וּמֵרֹ֣עַ מַעַלְלֵיכֶ֔ם וּשְׁבוּ֙ עַל־הָ֣אֲדָמָ֔ה אֲשֶׁ֨ר נָתַ֧ן יְהוָ֛ה לָכֶ֖ם וְלַאֲבֽוֹתֵיכֶ֑ם לְמִן־עוֹלָ֖ם וְעַד־עוֹלָֽם׃"}},"definableWords":["evil","land","LORD","fathers"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"6":{"text":"And go not after other gods to serve them, and to worship them, and provoke me not to anger with the works of your hands; and I will do you no hurt.","ref":"Jeremiah 25:6","synthesized":"Do not follow other gods to serve and worship them, and do not provoke Me to anger with the works of your hands. Then I will do you no harm.’","sources":{"KJV":{"text":"And go not after other gods to serve them, and to worship them, and provoke me not to anger with the works of your hands; and I will do you no hurt."},"BSB":{"text":"Do not follow other gods to serve and worship them, and do not provoke Me to anger with the works of your hands. Then I will do you no harm.’"},"TANAKH":{"text":"and go not after other gods to serve them, and to worship them, and provoke Me not with the work of your hands, and I will do you no hurt.'"},"HEBREW":{"text":"וְאַל־תֵּלְכ֗וּ אַֽחֲרֵי֙ אֱלֹהִ֣ים אֲחֵרִ֔ים לְעָבְדָ֖ם וּלְהִשְׁתַּחֲוֺ֣ת לָהֶ֑ם וְלֹֽא־תַכְעִ֤יסוּ אוֹתִי֙ בְּמַעֲשֵׂ֣ה יְדֵיכֶ֔ם וְלֹ֥א אָרַ֖ע לָכֶֽם׃"}},"definableWords":["worship","anger","works"],"peopleInVerse":[],"themesInVerse":["worship"]},"7":{"text":"Yet ye have not hearkened unto me, saith the LORD; that ye might provoke me to anger with the works of your hands to your own hurt.","ref":"Jeremiah 25:7","synthesized":"‘But to your own harm, you have not listened to Me,’ declares the LORD, ‘so you have provoked Me to anger with the works of your hands.’","sources":{"KJV":{"text":"Yet ye have not hearkened unto me, saith the LORD; that ye might provoke me to anger with the works of your hands to your own hurt."},"BSB":{"text":"‘But to your own harm, you have not listened to Me,’ declares the LORD, ‘so you have provoked Me to anger with the works of your hands.’"},"TANAKH":{"text":"Yet ye have not hearkened unto Me, saith HaShem; that ye might provoke Me with the work of your hands to your own hurt."},"HEBREW":{"text":"וְלֹֽא־שְׁמַעְתֶּ֥ם אֵלַ֖י נְאֻם־יְהוָ֑ה לְמַ֧עַן הכעסוני הַכְעִיסֵ֛נִי בְּמַעֲשֵׂ֥ה יְדֵיכֶ֖ם לְרַ֥ע לָכֶֽם׃"}},"definableWords":["LORD","anger","works"],"peopleInVerse":[]},"8":{"text":"Therefore thus saith the LORD of hosts; Because ye have not heard my words,","ref":"Jeremiah 25:8","synthesized":"Therefore this is what the LORD of Hosts says: ‘Because you have not obeyed My words,","sources":{"KJV":{"text":"Therefore thus saith the LORD of hosts; Because ye have not heard my words,"},"BSB":{"text":"Therefore this is what the LORD of Hosts says: ‘Because you have not obeyed My words,"},"TANAKH":{"text":"Therefore thus saith HaShem of hosts: Because ye have not heard My words,"},"HEBREW":{"text":"לָכֵ֕ן כֹּ֥ה אָמַ֖ר יְהוָ֣ה צְבָא֑וֹת יַ֕עַן אֲשֶׁ֥ר לֹֽא־שְׁמַעְתֶּ֖ם אֶת־דְּבָרָֽי׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"9":{"text":"Behold, I will send and take all the families of the north, saith the LORD, and Nebuchadrezzar the king of Babylon, my servant, and will bring them against this land, and against the inhabitants thereof, and against all these nations round about, and will utterly destroy them, and make them an astonishment, and an hissing, and perpetual desolations.","ref":"Jeremiah 25:9","synthesized":"behold, I will summon all the families of the north, declares the LORD, and I will send for My servant Nebuchadnezzar king of Babylon, whom I will bring against this land, against its residents, and against all the surrounding nations. So I will devote them to destruction and make them an object of horror and contempt, an everlasting desolation.","sources":{"KJV":{"text":"Behold, I will send and take all the families of the north, saith the LORD, and Nebuchadrezzar the king of Babylon, my servant, and will bring them against this land, and against the inhabitants thereof, and against all these nations round about, and will utterly destroy them, and make them an astonishment, and an hissing, and perpetual desolations."},"BSB":{"text":"behold, I will summon all the families of the north, declares the LORD, and I will send for My servant Nebuchadnezzar king of Babylon, whom I will bring against this land, against its residents, and against all the surrounding nations. So I will devote them to destruction and make them an object of horror and contempt, an everlasting desolation."},"TANAKH":{"text":"behold, I will send and take all the families of the north, saith HaShem, and I will send unto Nebuchadrezzar the king of Babylon, My servant, and will bring them against this land, and against the inhabitants thereof, and against all these nations round about; and I will utterly destroy them, and make them an astonishment, and a hissing, and perpetual desolations."},"HEBREW":{"text":"הִנְנִ֣י שֹׁלֵ֡חַ וְלָקַחְתִּי֩ אֶת־כָּל־מִשְׁפְּח֨וֹת צָפ֜וֹן נְאֻם־יְהוָ֗ה וְאֶל־נְבֽוּכַדְרֶאצַּ֣ר מֶֽלֶךְ־בָּבֶל֮ עַבְדִּי֒ וַהֲבִ֨אֹתִ֜ים עַל־הָאָ֤רֶץ הַזֹּאת֙ וְעַל־יֹ֣שְׁבֶ֔יהָ וְעַ֛ל כָּל־הַגּוֹיִ֥ם הָאֵ֖לֶּה סָבִ֑יב וְהַ֣חֲרַמְתִּ֔ים וְשַׂמְתִּים֙ לְשַׁמָּ֣ה וְלִשְׁרֵקָ֔ה וּלְחָרְב֖וֹת עוֹלָֽם׃"}},"definableWords":["families","LORD","servant","king","Babylon","land","nations","make","everlasting"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship","land_promise"]},"10":{"text":"Moreover I will take from them the voice of mirth, and the voice of gladness, the voice of the bridegroom, and the voice of the bride, the sound of the millstones, and the light of the candle.","ref":"Jeremiah 25:10","synthesized":"Moreover, I will banish from them the sounds of joy and gladness, the voices of the bride and bridegroom, the sound of the millstones, and the light of the lamp.","sources":{"KJV":{"text":"Moreover I will take from them the voice of mirth, and the voice of gladness, the voice of the bridegroom, and the voice of the bride, the sound of the millstones, and the light of the candle."},"BSB":{"text":"Moreover, I will banish from them the sounds of joy and gladness, the voices of the bride and bridegroom, the sound of the millstones, and the light of the lamp."},"TANAKH":{"text":"Moreover I will cause to cease from among them the voice of mirth and the voice of gladness, the voice of the bridegroom and the voice of the bride, the sound of the millstones, and the light of the lamp."},"HEBREW":{"text":"וְהַאֲבַדְתִּ֣י מֵהֶ֗ם ק֤וֹל שָׂשׂוֹן֙ וְק֣וֹל שִׂמְחָ֔ה ק֥וֹל חָתָ֖ן וְק֣וֹל כַּלָּ֑ה ק֥וֹל רֵחַ֖יִם וְא֥וֹר נֵֽר׃"}},"definableWords":["joy","light"],"peopleInVerse":[],"themesInVerse":["joy","light_darkness","marriage_bride"]},"11":{"text":"And this whole land shall be a desolation, and an astonishment; and these nations shall serve the king of Babylon seventy years.","ref":"Jeremiah 25:11","synthesized":"And this whole land will become a desolate wasteland, and these nations will serve the king of Babylon for seventy years.","sources":{"KJV":{"text":"And this whole land shall be a desolation, and an astonishment; and these nations shall serve the king of Babylon seventy years."},"BSB":{"text":"And this whole land will become a desolate wasteland, and these nations will serve the king of Babylon for seventy years."},"TANAKH":{"text":"And this whole land shall be a desolation, and a waste; and these nations shall serve the king of Babylon seventy years."},"HEBREW":{"text":"וְהָֽיְתָה֙ כָּל־הָאָ֣רֶץ הַזֹּ֔את לְחָרְבָּ֖ה לְשַׁמָּ֑ה וְעָ֨בְד֜וּ הַגּוֹיִ֥ם הָאֵ֛לֶּה אֶת־מֶ֥לֶךְ בָּבֶ֖ל שִׁבְעִ֥ים שָׁנָֽה׃"}},"definableWords":["land","nations","king","Babylon","years"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship","land_promise"]},"12":{"text":"And it shall come to pass, when seventy years are accomplished, that I will punish the king of Babylon, and that nation, saith the LORD, for their iniquity, and the land of the Chaldeans, and will make it perpetual desolations.","ref":"Jeremiah 25:12","synthesized":"But when seventy years are complete, I will punish the king of Babylon and that nation, the land of the Chaldeans, for their guilt, declares the LORD, and I will make it an everlasting desolation.","sources":{"KJV":{"text":"And it shall come to pass, when seventy years are accomplished, that I will punish the king of Babylon, and that nation, saith the LORD, for their iniquity, and the land of the Chaldeans, and will make it perpetual desolations."},"BSB":{"text":"But when seventy years are complete, I will punish the king of Babylon and that nation, the land of the Chaldeans, for their guilt, declares the LORD, and I will make it an everlasting desolation."},"TANAKH":{"text":"And it shall come to pass, when seventy years are accomplished, that I will punish the king of Babylon, and that nation, saith HaShem, for their iniquity, and the land of the Chaldeans; and I will make it perpetual desolations."},"HEBREW":{"text":"וְהָיָ֣ה כִמְלֹ֣אות שִׁבְעִ֣ים שָׁנָ֡ה אֶפְקֹ֣ד עַל־מֶֽלֶךְ־בָּבֶל֩ וְעַל־הַגּ֨וֹי הַה֧וּא נְאֻם־יְהוָ֛ה אֶת־עֲוֺנָ֖ם וְעַל־אֶ֣רֶץ כַּשְׂדִּ֑ים וְשַׂמְתִּ֥י אֹת֖וֹ לְשִֽׁמְמ֥וֹת עוֹלָֽם׃"}},"definableWords":["years","king","Babylon","nation","land","LORD","make","everlasting"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship","land_promise"]},"13":{"text":"And I will bring upon that land all my words which I have pronounced against it, even all that is written in this book, which Jeremiah hath prophesied against all the nations.","ref":"Jeremiah 25:13","synthesized":"I will bring upon that land all the words I have pronounced against it, all that is written in this book, which Jeremiah has prophesied against all the nations.","sources":{"KJV":{"text":"And I will bring upon that land all my words which I have pronounced against it, even all that is written in this book, which Jeremiah hath prophesied against all the nations."},"BSB":{"text":"I will bring upon that land all the words I have pronounced against it, all that is written in this book, which Jeremiah has prophesied against all the nations."},"TANAKH":{"text":"And I will bring upon that land all My words which I have pronounced against it, even all that is written in this book, which Jeremiah hath prophesied against all the nations."},"HEBREW":{"text":"והבאיתי וְהֵֽבֵאתִי֙ עַל־הָאָ֣רֶץ הַהִ֔יא אֶת־כָּל־דְּבָרַ֖י אֲשֶׁר־דִּבַּ֣רְתִּי עָלֶ֑יהָ אֵ֤ת כָּל־הַכָּתוּב֙ בַּסֵּ֣פֶר הַזֶּ֔ה אֲשֶׁר־נִבָּ֥א יִרְמְיָ֖הוּ עַל־כָּל־הַגּוֹיִֽם׃"}},"definableWords":["land","nations"],"peopleInVerse":["Jeremiah"],"themesInVerse":["land_promise"]},"14":{"text":"For many nations and great kings shall serve themselves of them also: and I will recompense them according to their deeds, and according to the works of their own hands.","ref":"Jeremiah 25:14","synthesized":"For many nations and great kings will enslave them, and I will repay them according to their deeds and according to the work of their hands.’”","sources":{"KJV":{"text":"For many nations and great kings shall serve themselves of them also: and I will recompense them according to their deeds, and according to the works of their own hands."},"BSB":{"text":"For many nations and great kings will enslave them, and I will repay them according to their deeds and according to the work of their hands.’”"},"TANAKH":{"text":"For many nations and great kings shall make bondmen of them also; and I will recompense them according to their deeds, and according to the work of their own hands."},"HEBREW":{"text":"כִּ֣י עָֽבְדוּ־בָ֤ם גַּם־הֵ֙מָּה֙ גּוֹיִ֣ם רַבִּ֔ים וּמְלָכִ֖ים גְּדוֹלִ֑ים וְשִׁלַּמְתִּ֥י לָהֶ֛ם כְּפָעֳלָ֖ם וּכְמַעֲשֵׂ֥ה יְדֵיהֶֽם׃"}},"definableWords":["nations","great","kings","work"],"peopleInVerse":[]},"15":{"text":"For thus saith the LORD God of Israel unto me; Take the wine cup of this fury at my hand, and cause all the nations, to whom I send thee, to drink it.","ref":"Jeremiah 25:15","synthesized":"This is what the LORD, the God of Israel, said to me: “Take from My hand this cup of the wine of wrath, and make all the nations to whom I send you drink from it.","sources":{"KJV":{"text":"For thus saith the LORD God of Israel unto me; Take the wine cup of this fury at my hand, and cause all the nations, to whom I send thee, to drink it."},"BSB":{"text":"This is what the LORD, the God of Israel, said to me: “Take from My hand this cup of the wine of wrath, and make all the nations to whom I send you drink from it."},"TANAKH":{"text":"For thus saith HaShem, the G-d of Israel, unto me: Take this cup of the wine of fury at My hand, and cause all the nations, to whom I send thee, to drink it."},"HEBREW":{"text":"כִּ֣י כֹה֩ אָמַ֨ר יְהוָ֜ה אֱלֹהֵ֤י יִשְׂרָאֵל֙ אֵלַ֔י קַ֠ח אֶת־כּ֨וֹס הַיַּ֧יִן הַחֵמָ֛ה הַזֹּ֖את מִיָּדִ֑י וְהִשְׁקִיתָ֤ה אֹתוֹ֙ אֶת־כָּל־הַגּוֹיִ֔ם אֲשֶׁ֧ר אָנֹכִ֛י שֹׁלֵ֥חַ אוֹתְךָ֖ אֲלֵיהֶֽם׃"}},"definableWords":["LORD","God","Israel","wrath","make","nations"],"peopleInVerse":[],"themesInVerse":["judgment"]},"16":{"text":"And they shall drink, and be moved, and be mad, because of the sword that I will send among them.","ref":"Jeremiah 25:16","synthesized":"And they will drink and stagger and go out of their minds, because of the sword that I will send among them.”","sources":{"KJV":{"text":"And they shall drink, and be moved, and be mad, because of the sword that I will send among them."},"BSB":{"text":"And they will drink and stagger and go out of their minds, because of the sword that I will send among them.”"},"TANAKH":{"text":"And they shall drink, and reel to and fro, and be like madmen, because of the sword that I will send among them.--"},"HEBREW":{"text":"וְשָׁת֕וּ וְהִֽתְגֹּֽעֲשׁ֖וּ וְהִתְהֹלָ֑לוּ מִפְּנֵ֣י הַחֶ֔רֶב אֲשֶׁ֛ר אָנֹכִ֥י שֹׁלֵ֖חַ בֵּינֹתָֽם׃"}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Then took I the cup at the LORD’s hand, and made all the nations to drink, unto whom the LORD had sent me:","ref":"Jeremiah 25:17","synthesized":"So I took the cup from the LORD’s hand and made all the nations drink from it, each one to whom the LORD had sent me,","sources":{"KJV":{"text":"Then took I the cup at the LORD’s hand, and made all the nations to drink, unto whom the LORD had sent me:"},"BSB":{"text":"So I took the cup from the LORD’s hand and made all the nations drink from it, each one to whom the LORD had sent me,"},"TANAKH":{"text":"Then took I the cup of HaShem'S hand, and made all the nations to drink, unto whom HaShem had sent me:"},"HEBREW":{"text":"וָאֶקַּ֥ח אֶת־הַכּ֖וֹס מִיַּ֣ד יְהוָ֑ה וָֽאַשְׁקֶה֙ אֶת־כָּל־הַגּוֹיִ֔ם אֲשֶׁר־שְׁלָחַ֥נִי יְהוָ֖ה אֲלֵיהֶֽם׃"}},"definableWords":["LORD","made","nations","one","Lord"],"peopleInVerse":[],"themesInVerse":["creation"]},"18":{"text":"To wit, Jerusalem, and the cities of Judah, and the kings thereof, and the princes thereof, to make them a desolation, an astonishment, an hissing, and a curse; as it is this day;","ref":"Jeremiah 25:18","synthesized":"to make them a ruin, an object of horror and contempt and cursing, as they are to this day—Jerusalem and the cities of Judah, its kings and officials;","sources":{"KJV":{"text":"To wit, Jerusalem, and the cities of Judah, and the kings thereof, and the princes thereof, to make them a desolation, an astonishment, an hissing, and a curse; as it is this day;"},"BSB":{"text":"to make them a ruin, an object of horror and contempt and cursing, as they are to this day—Jerusalem and the cities of Judah, its kings and officials;"},"TANAKH":{"text":"Jerusalem, and the cities of Judah, and the kings thereof, and the princes thereof, to make them an appalment, an astonishment, a hissing, and a curse; as it is this day;"},"HEBREW":{"text":"אֶת־יְרוּשָׁלִַ֙ם֙ וְאֶת־עָרֵ֣י יְהוּדָ֔ה וְאֶת־מְלָכֶ֖יהָ אֶת־שָׂרֶ֑יהָ לָתֵ֨ת אֹתָ֜ם לְחָרְבָּ֧ה לְשַׁמָּ֛ה לִשְׁרֵקָ֥ה וְלִקְלָלָ֖ה כַּיּ֥וֹם הַזֶּֽה׃"}},"definableWords":["make","day","Jerusalem","Judah","kings"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"19":{"text":"Pharaoh king of Egypt, and his servants, and his princes, and all his people;","ref":"Jeremiah 25:19","synthesized":"Pharaoh king of Egypt, his officials, his leaders, and all his people;","sources":{"KJV":{"text":"Pharaoh king of Egypt, and his servants, and his princes, and all his people;"},"BSB":{"text":"Pharaoh king of Egypt, his officials, his leaders, and all his people;"},"TANAKH":{"text":"Pharaoh king of Egypt, and his servants, and his princes, and all his people;"},"HEBREW":{"text":"אֶת־פַּרְעֹ֧ה מֶֽלֶךְ־מִצְרַ֛יִם וְאֶת־עֲבָדָ֥יו וְאֶת־שָׂרָ֖יו וְאֶת־כָּל־עַמּֽוֹ׃"}},"definableWords":["Pharaoh","king","Egypt","people"],"peopleInVerse":["Pharaoh"],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","kingship"]},"20":{"text":"And all the mingled people, and all the kings of the land of Uz, and all the kings of the land of the Philistines, and Ashkelon, and Azzah, and Ekron, and the remnant of Ashdod,","ref":"Jeremiah 25:20","synthesized":"all the mixed tribes; all the kings of Uz; all the kings of the Philistines: Ashkelon, Gaza, Ekron, and the remnant of Ashdod;","sources":{"KJV":{"text":"And all the mingled people, and all the kings of the land of Uz, and all the kings of the land of the Philistines, and Ashkelon, and Azzah, and Ekron, and the remnant of Ashdod,"},"BSB":{"text":"all the mixed tribes; all the kings of Uz; all the kings of the Philistines: Ashkelon, Gaza, Ekron, and the remnant of Ashdod;"},"TANAKH":{"text":"and all the mingled people; and all the kings of the land of Uz, and all the kings of the land of the Philistines, and Ashkelon, and Gaza, and Ekron, and the remnant of Ashdod;"},"HEBREW":{"text":"וְאֵת֙ כָּל־הָעֶ֔רֶב וְאֵ֕ת כָּל־מַלְכֵ֖י אֶ֣רֶץ הָע֑וּץ וְאֵ֗ת כָּל־מַלְכֵי֙ אֶ֣רֶץ פְּלִשְׁתִּ֔ים וְאֶת־אַשְׁקְל֤וֹן וְאֶת־עַזָּה֙ וְאֶת־עֶקְר֔וֹן וְאֵ֖ת שְׁאֵרִ֥ית אַשְׁדּֽוֹד׃"}},"definableWords":["kings","remnant"],"peopleInVerse":[],"themesInVerse":["exile_return"]},"21":{"text":"Edom, and Moab, and the children of Ammon,","ref":"Jeremiah 25:21","synthesized":"Edom, Moab, and the Ammonites;","sources":{"KJV":{"text":"Edom, and Moab, and the children of Ammon,"},"BSB":{"text":"Edom, Moab, and the Ammonites;"},"TANAKH":{"text":"Edom, and Moab, and the children of Ammon;"},"HEBREW":{"text":"אֶת־אֱד֥וֹם וְאֶת־מוֹאָ֖ב וְאֶת־בְּנֵ֥י עַמּֽוֹן׃"}},"definableWords":["Edom"],"peopleInVerse":["Ammonites"]},"22":{"text":"And all the kings of Tyrus, and all the kings of Zidon, and the kings of the isles which are beyond the sea,","ref":"Jeremiah 25:22","synthesized":"all the kings of Tyre and Sidon; the kings of the coastlands across the sea;","sources":{"KJV":{"text":"And all the kings of Tyrus, and all the kings of Zidon, and the kings of the isles which are beyond the sea,"},"BSB":{"text":"all the kings of Tyre and Sidon; the kings of the coastlands across the sea;"},"TANAKH":{"text":"and all the kings of Tyre, and all the kings of Zidon, and the kings of the isle which is beyond the sea;"},"HEBREW":{"text":"וְאֵת֙ כָּל־מַלְכֵי־צֹ֔ר וְאֵ֖ת כָּל־מַלְכֵ֣י צִיד֑וֹן וְאֵת֙ מַלְכֵ֣י הָאִ֔י אֲשֶׁ֖ר בְּעֵ֥בֶר הַיָּֽם׃"}},"definableWords":["kings","sea"],"peopleInVerse":[],"placesInVerse":["Tyre","Sidon"]},"23":{"text":"Dedan, and Tema, and Buz, and all that are in the utmost corners,","ref":"Jeremiah 25:23","synthesized":"Dedan, Tema, Buz, and all who cut the corners of their hair;","sources":{"KJV":{"text":"Dedan, and Tema, and Buz, and all that are in the utmost corners,"},"BSB":{"text":"Dedan, Tema, Buz, and all who cut the corners of their hair;"},"TANAKH":{"text":"Dedan, and Tema, and Buz, and all that have the corners of their hair polled;"},"HEBREW":{"text":"וְאֶת־דְּדָ֤ן וְאֶת־תֵּימָא֙ וְאֶת־בּ֔וּז וְאֵ֖ת כָּל־קְצוּצֵ֥י פֵאָֽה׃"}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"And all the kings of Arabia, and all the kings of the mingled people that dwell in the desert,","ref":"Jeremiah 25:24","synthesized":"all the kings of Arabia, and all the kings of the mixed tribes who dwell in the desert;","sources":{"KJV":{"text":"And all the kings of Arabia, and all the kings of the mingled people that dwell in the desert,"},"BSB":{"text":"all the kings of Arabia, and all the kings of the mixed tribes who dwell in the desert;"},"TANAKH":{"text":"and all the kings of Arabia, and all the kings of the mingled people that dwell in the wilderness;"},"HEBREW":{"text":"וְאֵ֖ת כָּל־מַלְכֵ֣י עֲרָ֑ב וְאֵת֙ כָּל־מַלְכֵ֣י הָעֶ֔רֶב הַשֹּׁכְנִ֖ים בַּמִּדְבָּֽר׃"}},"definableWords":["kings"],"peopleInVerse":[]},"25":{"text":"And all the kings of Zimri, and all the kings of Elam, and all the kings of the Medes,","ref":"Jeremiah 25:25","synthesized":"all the kings of Zimri, Elam, and Media;","sources":{"KJV":{"text":"And all the kings of Zimri, and all the kings of Elam, and all the kings of the Medes,"},"BSB":{"text":"all the kings of Zimri, Elam, and Media;"},"TANAKH":{"text":"and all the kings of Zimri, and all the kings of Elam, and all the kings of the Medes;"},"HEBREW":{"text":"וְאֵ֣ת ׀ כָּל־מַלְכֵ֣י זִמְרִ֗י וְאֵת֙ כָּל־מַלְכֵ֣י עֵילָ֔ם וְאֵ֖ת כָּל־מַלְכֵ֥י מָדָֽי׃"}},"definableWords":["kings"],"peopleInVerse":[]},"26":{"text":"And all the kings of the north, far and near, one with another, and all the kingdoms of the world, which are upon the face of the earth: and the king of Sheshach shall drink after them.","ref":"Jeremiah 25:26","synthesized":"all the kings of the north, both near and far, one after another—all the kingdoms on the face of the earth. And after all of them, the king of Sheshach will drink it too.","sources":{"KJV":{"text":"And all the kings of the north, far and near, one with another, and all the kingdoms of the world, which are upon the face of the earth: and the king of Sheshach shall drink after them."},"BSB":{"text":"all the kings of the north, both near and far, one after another—all the kingdoms on the face of the earth. And after all of them, the king of Sheshach will drink it too."},"TANAKH":{"text":"and all the kings of the north, far and near, one with another; and all the kingdoms of the world, which are upon the face of the earth. --And the king of Sheshach shall drink after them."},"HEBREW":{"text":"וְאֵ֣ת ׀ כָּל־מַלְכֵ֣י הַצָּפ֗וֹן הַקְּרֹבִ֤ים וְהָֽרְחֹקִים֙ אִ֣ישׁ אֶל־אָחִ֔יו וְאֵת֙ כָּל־הַמַּמְלְכ֣וֹת הָאָ֔רֶץ אֲשֶׁ֖ר עַל־פְּנֵ֣י הָאֲדָמָ֑ה וּמֶ֥לֶךְ שֵׁשַׁ֖ךְ יִשְׁתֶּ֥ה אַחֲרֵיהֶֽם׃"}},"definableWords":["kings","one","earth","king"],"peopleInVerse":[],"themesInVerse":["kingship"]},"27":{"text":"Therefore thou shalt say unto them, Thus saith the LORD of hosts, the God of Israel; Drink ye, and be drunken, and spue, and fall, and rise no more, because of the sword which I will send among you.","ref":"Jeremiah 25:27","synthesized":"“Then you are to tell them that this is what the LORD of Hosts, the God of Israel, says: ‘Drink, get drunk, and vomit. Fall down and never get up again, because of the sword I will send among you.’","sources":{"KJV":{"text":"Therefore thou shalt say unto them, Thus saith the LORD of hosts, the God of Israel; Drink ye, and be drunken, and spue, and fall, and rise no more, because of the sword which I will send among you."},"BSB":{"text":"“Then you are to tell them that this is what the LORD of Hosts, the God of Israel, says: ‘Drink, get drunk, and vomit. Fall down and never get up again, because of the sword I will send among you.’"},"TANAKH":{"text":"And thou shalt say unto them: Thus saith HaShem of hosts, the G-d of Israel: Drink ye, and be drunken, and spew, and fall, and rise no more, because of the sword which I will send among you."},"HEBREW":{"text":"וְאָמַרְתָּ֣ אֲלֵיהֶ֡ם כֹּֽה־אָמַר֩ יְהוָ֨ה צְבָא֜וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֗ל שְׁת֤וּ וְשִׁכְרוּ֙ וּקְי֔וּ וְנִפְל֖וּ וְלֹ֣א תָק֑וּמוּ מִפְּנֵ֣י הַחֶ֔רֶב אֲשֶׁ֛ר אָנֹכִ֥י שֹׁלֵ֖חַ בֵּינֵיכֶֽם׃"}},"definableWords":["LORD","God","Israel"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"28":{"text":"And it shall be, if they refuse to take the cup at thine hand to drink, then shalt thou say unto them, Thus saith the LORD of hosts; Ye shall certainly drink.","ref":"Jeremiah 25:28","synthesized":"If they refuse to take the cup from your hand and drink it, you are to tell them that this is what the LORD of Hosts says: ‘You most certainly must drink it!","sources":{"KJV":{"text":"And it shall be, if they refuse to take the cup at thine hand to drink, then shalt thou say unto them, Thus saith the LORD of hosts; Ye shall certainly drink."},"BSB":{"text":"If they refuse to take the cup from your hand and drink it, you are to tell them that this is what the LORD of Hosts says: ‘You most certainly must drink it!"},"TANAKH":{"text":"And it shall be, if they refuse to take the cup at thy hand to drink, then shalt thou say unto them: Thus saith HaShem of hosts: Ye shall surely drink."},"HEBREW":{"text":"וְהָיָ֗ה כִּ֧י יְמָאֲנ֛וּ לָקַֽחַת־הַכּ֥וֹס מִיָּדְךָ֖ לִשְׁתּ֑וֹת וְאָמַרְתָּ֣ אֲלֵיהֶ֗ם כֹּ֥ה אָמַ֛ר יְהוָ֥ה צְבָא֖וֹת שָׁת֥וֹ תִשְׁתּֽוּ׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"29":{"text":"For, lo, I begin to bring evil on the city which is called by my name, and should ye be utterly unpunished? Ye shall not be unpunished: for I will call for a sword upon all the inhabitants of the earth, saith the LORD of hosts.","ref":"Jeremiah 25:29","synthesized":"For behold, I am beginning to bring disaster on the city that bears My Name, so how could you possibly go unpunished? You will not go unpunished, for I am calling down a sword upon all the inhabitants of the earth, declares the LORD of Hosts.’","sources":{"KJV":{"text":"For, lo, I begin to bring evil on the city which is called by my name, and should ye be utterly unpunished? Ye shall not be unpunished: for I will call for a sword upon all the inhabitants of the earth, saith the LORD of hosts."},"BSB":{"text":"For behold, I am beginning to bring disaster on the city that bears My Name, so how could you possibly go unpunished? You will not go unpunished, for I am calling down a sword upon all the inhabitants of the earth, declares the LORD of Hosts.’"},"TANAKH":{"text":"For, lo, I begin to bring evil on the city whereupon My name is called, and should ye be utterly unpunished? Ye shall not be unpunished; for I will call for a sword upon all the inhabitants of the earth, saith HaShem of hosts."},"HEBREW":{"text":"כִּי֩ הִנֵּ֨ה בָעִ֜יר אֲשֶׁ֧ר נִֽקְרָא־שְׁמִ֣י עָלֶ֗יהָ אָֽנֹכִי֙ מֵחֵ֣ל לְהָרַ֔ע וְאַתֶּ֖ם הִנָּקֵ֣ה תִנָּק֑וּ לֹ֣א תִנָּק֔וּ כִּ֣י חֶ֗רֶב אֲנִ֤י קֹרֵא֙ עַל־כָּל־יֹשְׁבֵ֣י הָאָ֔רֶץ נְאֻ֖ם יְהוָ֥ה צְבָאֽוֹת׃"}},"definableWords":["beginning","name","earth","LORD"],"peopleInVerse":[],"themesInVerse":["creation"]},"30":{"text":"Therefore prophesy thou against them all these words, and say unto them, The LORD shall roar from on high, and utter his voice from his holy habitation; he shall mightily roar upon his habitation; he shall give a shout, as they that tread the grapes, against all the inhabitants of the earth.","ref":"Jeremiah 25:30","synthesized":"So you are to prophesy all these words against them and say to them:  ‘The LORD will roar from on high; He will raise His voice from His holy habitation. He will roar loudly over His pasture; like those who tread the grapes, He will call out with a shout against all the inhabitants of the earth.","sources":{"KJV":{"text":"Therefore prophesy thou against them all these words, and say unto them, The LORD shall roar from on high, and utter his voice from his holy habitation; he shall mightily roar upon his habitation; he shall give a shout, as they that tread the grapes, against all the inhabitants of the earth."},"BSB":{"text":"So you are to prophesy all these words against them and say to them:  ‘The LORD will roar from on high; He will raise His voice from His holy habitation. He will roar loudly over His pasture; like those who tread the grapes, He will call out with a shout against all the inhabitants of the earth."},"TANAKH":{"text":"Therefore prophesy thou against them all these words, and say unto them: HaShem doth roar from on high, and utter His voice from His holy habitation; He doth mightily roar because of His fold; He giveth a shout, as they that tread the grapes, against all the inhabitants of the earth."},"HEBREW":{"text":"וְאַתָּה֙ תִּנָּבֵ֣א אֲלֵיהֶ֔ם אֵ֥ת כָּל־הַדְּבָרִ֖ים הָאֵ֑לֶּה וְאָמַרְתָּ֣ אֲלֵיהֶ֗ם יְהוָ֞ה מִמָּר֤וֹם יִשְׁאָג֙ וּמִמְּע֤וֹן קָדְשׁוֹ֙ יִתֵּ֣ן קוֹל֔וֹ שָׁאֹ֤ג יִשְׁאַג֙ עַל־נָוֵ֔הוּ הֵידָד֙ כְּדֹרְכִ֣ים יַֽעֲנֶ֔ה אֶ֥ל כָּל־יֹשְׁבֵ֖י הָאָֽרֶץ׃"}},"definableWords":["LORD","voice","holy","earth"],"peopleInVerse":[]},"31":{"text":"A noise shall come even to the ends of the earth; for the LORD hath a controversy with the nations, he will plead with all flesh; he will give them that are wicked to the sword, saith the LORD.","ref":"Jeremiah 25:31","synthesized":"The tumult will resound to the ends of the earth because the LORD brings a charge against the nations. He brings judgment on all mankind and puts the wicked to the sword,’” declares the LORD.","sources":{"KJV":{"text":"A noise shall come even to the ends of the earth; for the LORD hath a controversy with the nations, he will plead with all flesh; he will give them that are wicked to the sword, saith the LORD."},"BSB":{"text":"The tumult will resound to the ends of the earth because the LORD brings a charge against the nations. He brings judgment on all mankind and puts the wicked to the sword,’” declares the LORD."},"TANAKH":{"text":"A noise is come even to the end of the earth; for HaShem hath a controversy with the nations, He doth plead with all flesh; as for the wicked, He hath given them to the sword, saith HaShem."},"HEBREW":{"text":"בָּ֤א שָׁאוֹן֙ עַד־קְצֵ֣ה הָאָ֔רֶץ כִּ֣י רִ֤יב לַֽיהוָה֙ בַּגּוֹיִ֔ם נִשְׁפָּ֥ט ה֖וּא לְכָל־בָּשָׂ֑ר הָרְשָׁעִ֛ים נְתָנָ֥ם לַחֶ֖רֶב נְאֻם־יְהוָֽה׃"}},"definableWords":["earth","LORD","charge","nations","judgment","Lord"],"peopleInVerse":[],"themesInVerse":["judgment"]},"32":{"text":"Thus saith the LORD of hosts, Behold, evil shall go forth from nation to nation, and a great whirlwind shall be raised up from the coasts of the earth.","ref":"Jeremiah 25:32","synthesized":"This is what the LORD of Hosts says:  “Behold! Disaster is spreading from nation to nation; a mighty storm is rising from the ends of the earth.”","sources":{"KJV":{"text":"Thus saith the LORD of hosts, Behold, evil shall go forth from nation to nation, and a great whirlwind shall be raised up from the coasts of the earth."},"BSB":{"text":"This is what the LORD of Hosts says:  “Behold! Disaster is spreading from nation to nation; a mighty storm is rising from the ends of the earth.”"},"TANAKH":{"text":"Thus saith HaShem of hosts: Behold, evil shall go forth from nation to nation, and a great storm shall be raised up from the uttermost parts of the earth."},"HEBREW":{"text":"כֹּ֤ה אָמַר֙ יְהוָ֣ה צְבָא֔וֹת הִנֵּ֥ה רָעָ֛ה יֹצֵ֖את מִגּ֣וֹי אֶל־גּ֑וֹי וְסַ֣עַר גָּד֔וֹל יֵע֖וֹר מִיַּרְכְּתֵי־אָֽרֶץ׃"}},"definableWords":["LORD","nation","mighty","earth"],"peopleInVerse":[]},"33":{"text":"And the slain of the LORD shall be at that day from one end of the earth even unto the other end of the earth: they shall not be lamented, neither gathered, nor buried; they shall be dung upon the ground.","ref":"Jeremiah 25:33","synthesized":"Those slain by the LORD on that day will be spread from one end of the earth to the other. They will not be mourned, gathered, or buried. They will be like dung lying on the ground.","sources":{"KJV":{"text":"And the slain of the LORD shall be at that day from one end of the earth even unto the other end of the earth: they shall not be lamented, neither gathered, nor buried; they shall be dung upon the ground."},"BSB":{"text":"Those slain by the LORD on that day will be spread from one end of the earth to the other. They will not be mourned, gathered, or buried. They will be like dung lying on the ground."},"TANAKH":{"text":"And the slain of HaShem shall be at that day from one end of the earth even unto the other end of the earth; they shall not be lamented, neither gathered, nor buried; they shall be dung upon the face of the ground."},"HEBREW":{"text":"וְהָי֞וּ חַֽלְלֵ֤י יְהוָה֙ בַּיּ֣וֹם הַה֔וּא מִקְצֵ֥ה הָאָ֖רֶץ וְעַד־קְצֵ֣ה הָאָ֑רֶץ לֹ֣א יִסָּפְד֗וּ וְלֹ֤א יֵאָֽסְפוּ֙ וְלֹ֣א יִקָּבֵ֔רוּ לְדֹ֛מֶן עַל־פְּנֵ֥י הָאֲדָמָ֖ה יִֽהְיֽוּ׃"}},"definableWords":["LORD","day","one","earth","or","ground"],"peopleInVerse":[]},"34":{"text":"Howl, ye shepherds, and cry; and wallow yourselves in the ashes, ye principal of the flock: for the days of your slaughter and of your dispersions are accomplished; and ye shall fall like a pleasant vessel.","ref":"Jeremiah 25:34","synthesized":"Wail, you shepherds, and cry out; roll in the dust, you leaders of the flock. For the days of your slaughter have come; you will fall and be shattered like fine pottery.","sources":{"KJV":{"text":"Howl, ye shepherds, and cry; and wallow yourselves in the ashes, ye principal of the flock: for the days of your slaughter and of your dispersions are accomplished; and ye shall fall like a pleasant vessel."},"BSB":{"text":"Wail, you shepherds, and cry out; roll in the dust, you leaders of the flock. For the days of your slaughter have come; you will fall and be shattered like fine pottery."},"TANAKH":{"text":"Wail, ye shepherds, and cry; and wallow yourselves in the dust, ye leaders of the flock; for the days of your slaughter are fully come, and I will break you in pieces, and ye shall fall like a precious vessel."},"HEBREW":{"text":"הֵילִ֨ילוּ הָרֹעִ֜ים וְזַעֲק֗וּ וְהִֽתְפַּלְּשׁוּ֙ אַדִּירֵ֣י הַצֹּ֔אן כִּֽי־מָלְא֥וּ יְמֵיכֶ֖ם לִטְב֑וֹחַ וּתְפוֹצ֣וֹתִיכֶ֔ם וּנְפַלְתֶּ֖ם כִּכְלִ֥י חֶמְדָּֽה׃"}},"definableWords":["days"],"peopleInVerse":[],"themesInVerse":["fall_sin","shepherd_sheep"]},"35":{"text":"And the shepherds shall have no way to flee, nor the principal of the flock to escape.","ref":"Jeremiah 25:35","synthesized":"Flight will evade the shepherds, and escape will elude the leaders of the flock.","sources":{"KJV":{"text":"And the shepherds shall have no way to flee, nor the principal of the flock to escape."},"BSB":{"text":"Flight will evade the shepherds, and escape will elude the leaders of the flock."},"TANAKH":{"text":"And the shepherds shall have no way to flee, nor the leaders of the flock to escape."},"HEBREW":{"text":"וְאָבַ֥ד מָנ֖וֹס מִן־הֽ͏ָרֹעִ֑ים וּפְלֵיטָ֖ה מֵאַדִּירֵ֥י הַצֹּֽאן׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["shepherd_sheep"]},"36":{"text":"A voice of the cry of the shepherds, and an howling of the principal of the flock, shall be heard: for the LORD hath spoiled their pasture.","ref":"Jeremiah 25:36","synthesized":"Hear the cry of the shepherds, the wailing of the leaders of the flock, for the LORD is destroying their pasture.","sources":{"KJV":{"text":"A voice of the cry of the shepherds, and an howling of the principal of the flock, shall be heard: for the LORD hath spoiled their pasture."},"BSB":{"text":"Hear the cry of the shepherds, the wailing of the leaders of the flock, for the LORD is destroying their pasture."},"TANAKH":{"text":"Hark! the cry of the shepherds, and the wailing of the leaders of the flock! For HaShem despoileth their pasture."},"HEBREW":{"text":"ק֚וֹל צַעֲקַ֣ת הָֽרֹעִ֔ים וִֽילְלַ֖ת אַדִּירֵ֣י הַצֹּ֑אן כִּֽי־שֹׁדֵ֥ד יְהוָ֖ה אֶת־מַרְעִיתָֽם׃"}},"definableWords":["hear","LORD"],"peopleInVerse":[],"themesInVerse":["shepherd_sheep"]},"37":{"text":"And the peaceable habitations are cut down because of the fierce anger of the LORD.","ref":"Jeremiah 25:37","synthesized":"The peaceful meadows have been silenced because of the LORD’s burning anger.","sources":{"KJV":{"text":"And the peaceable habitations are cut down because of the fierce anger of the LORD."},"BSB":{"text":"The peaceful meadows have been silenced because of the LORD’s burning anger."},"TANAKH":{"text":"And the peaceable folds are brought to silence because of the fierce anger of HaShem."},"HEBREW":{"text":"וְנָדַ֖מּוּ נְא֣וֹת הַשָּׁל֑וֹם מִפְּנֵ֖י חֲר֥וֹן אַף־יְהוָֽה׃"}},"definableWords":["LORD","anger"],"peopleInVerse":[]},"38":{"text":"He hath forsaken his covert, as the lion: for their land is desolate because of the fierceness of the oppressor, and because of his fierce anger.","ref":"Jeremiah 25:38","synthesized":"He has left His den like a lion, for their land has been made a desolation by the sword of the oppressor, and because of the fierce anger of the LORD.","sources":{"KJV":{"text":"He hath forsaken his covert, as the lion: for their land is desolate because of the fierceness of the oppressor, and because of his fierce anger."},"BSB":{"text":"He has left His den like a lion, for their land has been made a desolation by the sword of the oppressor, and because of the fierce anger of the LORD."},"TANAKH":{"text":"He hath forsaken His covert, as the lion; for their land is become a waste because of the fierceness of the oppressing sword, and because of His fierce anger."},"HEBREW":{"text":"עָזַ֥ב כַּכְּפִ֖יר סֻכּ֑וֹ כִּֽי־הָיְתָ֤ה אַרְצָם֙ לְשַׁמָּ֔ה מִפְּנֵי֙ חֲר֣וֹן הַיּוֹנָ֔ה וּמִפְּנֵ֖י חֲר֥וֹן אַפּֽוֹ׃"}},"definableWords":["lion","land","made","anger","LORD"],"peopleInVerse":[],"themesInVerse":["creation","land_promise"]}}},"26":{"chapter":"26","title":"JEREMIAH PROPHESIES IN THE TEMPLE","verses":{"1":{"text":"In the beginning of the reign of Jehoiakim the son of Josiah king of Judah came this word from the LORD, saying,","ref":"Jeremiah 26:1","synthesized":"At the beginning of the reign of Jehoiakim son of Josiah king of Judah, this word came from the LORD:","sources":{"KJV":{"text":"In the beginning of the reign of Jehoiakim the son of Josiah king of Judah came this word from the LORD, saying,"},"BSB":{"text":"At the beginning of the reign of Jehoiakim son of Josiah king of Judah, this word came from the LORD:"},"TANAKH":{"text":"In the beginning of the reign of Jehoiakim the son of Josiah, king of Judah, came this word from HaShem, saying:"},"HEBREW":{"text":"בְּרֵאשִׁ֗ית מַמְלְכ֛וּת יְהוֹיָקִ֥ים בֶּן־יֹאשִׁיָּ֖הוּ מֶ֣לֶךְ יְהוּדָ֑ה הָיָה֙ הַדָּבָ֣ר הַזֶּ֔ה מֵאֵ֥ת יְהוָ֖ה לֵאמֹֽר׃"}},"definableWords":["beginning","reign","son","king","Judah","word","LORD"],"peopleInVerse":[],"themesInVerse":["creation","kingdom_of_god","kingship"]},"2":{"text":"Thus saith the LORD; Stand in the court of the LORD’s house, and speak unto all the cities of Judah, which come to worship in the LORD’s house, all the words that I command thee to speak unto them; diminish not a word:","ref":"Jeremiah 26:2","synthesized":"“This is what the LORD says: Stand in the courtyard of the house of the LORD and speak all the words I have commanded you to speak to all the cities of Judah who come to worship there. Do not omit a word.","sources":{"KJV":{"text":"Thus saith the LORD; Stand in the court of the LORD’s house, and speak unto all the cities of Judah, which come to worship in the LORD’s house, all the words that I command thee to speak unto them; diminish not a word:"},"BSB":{"text":"“This is what the LORD says: Stand in the courtyard of the house of the LORD and speak all the words I have commanded you to speak to all the cities of Judah who come to worship there. Do not omit a word."},"TANAKH":{"text":"'Thus saith HaShem: Stand in the court of HaShem'S house, and speak unto all the cities of Judah, which come to worship in HaShem'S house, all the words that I command thee to speak unto them; diminish not a word."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה עֲמֹד֮ בַּחֲצַ֣ר בֵּית־יְהוָה֒ וְדִבַּרְתָּ֞ עַל־כָּל־עָרֵ֣י יְהוּדָ֗ה הַבָּאִים֙ לְהִשְׁתַּחֲוֺ֣ת בֵּית־יְהוָ֔ה אֵ֚ת כָּל־הַדְּבָרִ֔ים אֲשֶׁ֥ר צִוִּיתִ֖יךָ לְדַבֵּ֣ר אֲלֵיהֶ֑ם אַל־תִּגְרַ֖ע דָּבָֽר׃"}},"definableWords":["LORD","stand","house","Lord","Judah","worship","word"],"peopleInVerse":[],"themesInVerse":["worship"]},"3":{"text":"If so be they will hearken, and turn every man from his evil way, that I may repent me of the evil, which I purpose to do unto them because of the evil of their doings.","ref":"Jeremiah 26:3","synthesized":"Perhaps they will listen and turn—each from his evil way of life—so that I may relent of the disaster I am planning to bring upon them because of the evil of their deeds.","sources":{"KJV":{"text":"If so be they will hearken, and turn every man from his evil way, that I may repent me of the evil, which I purpose to do unto them because of the evil of their doings."},"BSB":{"text":"Perhaps they will listen and turn—each from his evil way of life—so that I may relent of the disaster I am planning to bring upon them because of the evil of their deeds."},"TANAKH":{"text":"It may be they will hearken, and turn every man from his evil way; that I may repent Me of the evil, which I purpose to do unto them because of the evil of their doings."},"HEBREW":{"text":"אוּלַ֣י יִשְׁמְע֔וּ וְיָשֻׁ֕בוּ אִ֖ישׁ מִדַּרְכּ֣וֹ הָרָעָ֑ה וְנִחַמְתִּ֣י אֶל־הָרָעָ֗ה אֲשֶׁ֨ר אָנֹכִ֤י חֹשֵׁב֙ לַעֲשׂ֣וֹת לָהֶ֔ם מִפְּנֵ֖י רֹ֥עַ מַעַלְלֵיהֶֽם׃"}},"definableWords":["evil","way","life"],"peopleInVerse":[]},"4":{"text":"And thou shalt say unto them, Thus saith the LORD; If ye will not hearken to me, to walk in my law, which I have set before you,","ref":"Jeremiah 26:4","synthesized":"And you are to tell them that this is what the LORD says: ‘If you do not listen to Me and walk in My law, which I have set before you,","sources":{"KJV":{"text":"And thou shalt say unto them, Thus saith the LORD; If ye will not hearken to me, to walk in my law, which I have set before you,"},"BSB":{"text":"And you are to tell them that this is what the LORD says: ‘If you do not listen to Me and walk in My law, which I have set before you,"},"TANAKH":{"text":"And thou shalt say unto them: Thus saith HaShem: If ye will not hearken to Me, to walk in My law, which I have set before you,"},"HEBREW":{"text":"וְאָמַרְתָּ֣ אֲלֵיהֶ֔ם כֹּ֖ה אָמַ֣ר יְהוָ֑ה אִם־לֹ֤א תִשְׁמְעוּ֙ אֵלַ֔י לָלֶ֙כֶת֙ בְּת֣וֹרָתִ֔י אֲשֶׁ֥ר נָתַ֖תִּי לִפְנֵיכֶֽם׃"}},"definableWords":["LORD","walk","law"],"peopleInVerse":[]},"5":{"text":"To hearken to the words of my servants the prophets, whom I sent unto you, both rising up early, and sending them, but ye have not hearkened;","ref":"Jeremiah 26:5","synthesized":"and if you do not listen to the words of My servants the prophets, whom I have sent you again and again even though you did not listen,","sources":{"KJV":{"text":"To hearken to the words of my servants the prophets, whom I sent unto you, both rising up early, and sending them, but ye have not hearkened;"},"BSB":{"text":"and if you do not listen to the words of My servants the prophets, whom I have sent you again and again even though you did not listen,"},"TANAKH":{"text":"to hearken to the words of My servants the prophets, whom I send unto you, even sending them betimes and often, but ye have not hearkened;"},"HEBREW":{"text":"לִשְׁמֹ֗עַ עַל־דִּבְרֵ֨י עֲבָדַ֣י הַנְּבִאִ֔ים אֲשֶׁ֥ר אָנֹכִ֖י שֹׁלֵ֣חַ אֲלֵיכֶ֑ם וְהַשְׁכֵּ֥ם וְשָׁלֹ֖חַ וְלֹ֥א שְׁמַעְתֶּֽם׃"}},"definableWords":["servants"],"peopleInVerse":[]},"6":{"text":"Then will I make this house like Shiloh, and will make this city a curse to all the nations of the earth.","ref":"Jeremiah 26:6","synthesized":"then I will make this house like Shiloh, and I will make this city an object of cursing among all the nations of the earth.’”","sources":{"KJV":{"text":"Then will I make this house like Shiloh, and will make this city a curse to all the nations of the earth."},"BSB":{"text":"then I will make this house like Shiloh, and I will make this city an object of cursing among all the nations of the earth.’”"},"TANAKH":{"text":"then will I make this house like Shiloh, and will make this city a curse to all the nations of the earth.'"},"HEBREW":{"text":"וְנָתַתִּ֛י אֶת־הַבַּ֥יִת הַזֶּ֖ה כְּשִׁלֹ֑ה וְאֶת־הָעִ֤יר הזאתה הַזֹּאת֙ אֶתֵּ֣ן לִקְלָלָ֔ה לְכֹ֖ל גּוֹיֵ֥י הָאָֽרֶץ׃"}},"definableWords":["make","house","nations","earth"],"peopleInVerse":[],"placesInVerse":["Shiloh"]},"7":{"text":"So the priests and the prophets and all the people heard Jeremiah speaking these words in the house of the LORD.","ref":"Jeremiah 26:7","synthesized":"Now the priests and prophets and all the people heard Jeremiah speaking these words in the house of the LORD,","sources":{"KJV":{"text":"So the priests and the prophets and all the people heard Jeremiah speaking these words in the house of the LORD."},"BSB":{"text":"Now the priests and prophets and all the people heard Jeremiah speaking these words in the house of the LORD,"},"TANAKH":{"text":"So the priests and the prophets and all the people heard Jeremiah speaking these words in the house of HaShem."},"HEBREW":{"text":"וַֽיִּשְׁמְע֛וּ הַכֹּהֲנִ֥ים וְהַנְּבִאִ֖ים וְכָל־הָעָ֑ם אֶֽת־יִרְמְיָ֔הוּ מְדַבֵּ֛ר אֶת־הַדְּבָרִ֥ים הָאֵ֖לֶּה בְּבֵ֥ית יְהוָֽה׃"}},"definableWords":["people","house","LORD"],"peopleInVerse":["Jeremiah"]},"8":{"text":"Now it came to pass, when Jeremiah had made an end of speaking all that the LORD had commanded him to speak unto all the people, that the priests and the prophets and all the people took him, saying, Thou shalt surely die.","ref":"Jeremiah 26:8","synthesized":"and as soon as he had finished telling all the people everything the LORD had commanded him to say, the priests and prophets and all the people seized him, shouting, “You must surely die!","sources":{"KJV":{"text":"Now it came to pass, when Jeremiah had made an end of speaking all that the LORD had commanded him to speak unto all the people, that the priests and the prophets and all the people took him, saying, Thou shalt surely die."},"BSB":{"text":"and as soon as he had finished telling all the people everything the LORD had commanded him to say, the priests and prophets and all the people seized him, shouting, “You must surely die!"},"TANAKH":{"text":"Now it came to pass, when Jeremiah had made an end of speaking all that HaShem had commanded him to speak unto all the people, that the priests and the prophets and all the people laid hold on him, saying: 'Thou shalt surely die."},"HEBREW":{"text":"וַיְהִ֣י ׀ כְּכַלּ֣וֹת יִרְמְיָ֗הוּ לְדַבֵּר֙ אֵ֣ת כָּל־אֲשֶׁר־צִוָּ֣ה יְהוָ֔ה לְדַבֵּ֖ר אֶל־כָּל־הָעָ֑ם וַיִּתְפְּשׂ֨וּ אֹת֜וֹ הַכֹּהֲנִ֧ים וְהַנְּבִאִ֛ים וְכָל־הָעָ֥ם לֵאמֹ֖ר מ֥וֹת תָּמֽוּת׃"}},"definableWords":["people","LORD","die"],"peopleInVerse":[]},"9":{"text":"Why hast thou prophesied in the name of the LORD, saying, This house shall be like Shiloh, and this city shall be desolate without an inhabitant? And all the people were gathered against Jeremiah in the house of the LORD.","ref":"Jeremiah 26:9","synthesized":"How dare you prophesy in the name of the LORD that this house will become like Shiloh and this city will be desolate and deserted!”  And all the people assembled against Jeremiah in the house of the LORD.","sources":{"KJV":{"text":"Why hast thou prophesied in the name of the LORD, saying, This house shall be like Shiloh, and this city shall be desolate without an inhabitant? And all the people were gathered against Jeremiah in the house of the LORD."},"BSB":{"text":"How dare you prophesy in the name of the LORD that this house will become like Shiloh and this city will be desolate and deserted!”  And all the people assembled against Jeremiah in the house of the LORD."},"TANAKH":{"text":"Why hast thou prophesied in the name of HaShem, saying: This house shall be like Shiloh, and this city shall be desolate, without an inhabitant?' And all the people were gathered against Jeremiah in the house of HaShem."},"HEBREW":{"text":"מַדּוּעַ֩ נִבֵּ֨יתָ בְשֵׁם־יְהוָ֜ה לֵאמֹ֗ר כְּשִׁלוֹ֙ יִֽהְיֶה֙ הַבַּ֣יִת הַזֶּ֔ה וְהָעִ֥יר הַזֹּ֛את תֶּחֱרַ֖ב מֵאֵ֣ין יוֹשֵׁ֑ב וַיִּקָּהֵ֧ל כָּל־הָעָ֛ם אֶֽל־יִרְמְיָ֖הוּ בְּבֵ֥ית יְהוָֽה׃"}},"definableWords":["name","LORD","house","people","Lord"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Shiloh"]},"10":{"text":"When the princes of Judah heard these things, then they came up from the king’s house unto the house of the LORD, and sat down in the entry of the new gate of the LORD’s house.","ref":"Jeremiah 26:10","synthesized":"When the officials of Judah heard these things, they went up from the king’s palace to the house of the LORD and sat there at the entrance of the New Gate.","sources":{"KJV":{"text":"When the princes of Judah heard these things, then they came up from the king’s house unto the house of the LORD, and sat down in the entry of the new gate of the LORD’s house."},"BSB":{"text":"When the officials of Judah heard these things, they went up from the king’s palace to the house of the LORD and sat there at the entrance of the New Gate."},"TANAKH":{"text":"When the princes of Judah heard these things, they came up from the king's house unto the house of HaShem; and they sat in the entry of the new gate of HaShem'S house."},"HEBREW":{"text":"וַֽיִּשְׁמְע֣וּ ׀ שָׂרֵ֣י יְהוּדָ֗ה אֵ֚ת הַדְּבָרִ֣ים הָאֵ֔לֶּה וַיַּעֲל֥וּ מִבֵּית־הַמֶּ֖לֶךְ בֵּ֣ית יְהוָ֑ה וַיֵּֽשְׁב֛וּ בְּפֶ֥תַח שַֽׁעַר־יְהוָ֖ה הֶחָדָֽשׁ׃"}},"definableWords":["Judah","king","house","LORD"],"peopleInVerse":[],"themesInVerse":["kingship"]},"11":{"text":"Then spake the priests and the prophets unto the princes and to all the people, saying, This man is worthy to die; for he hath prophesied against this city, as ye have heard with your ears.","ref":"Jeremiah 26:11","synthesized":"Then the priests and prophets said to the officials and all the people, “This man is worthy of death, for he has prophesied against this city, as you have heard with your own ears!”","sources":{"KJV":{"text":"Then spake the priests and the prophets unto the princes and to all the people, saying, This man is worthy to die; for he hath prophesied against this city, as ye have heard with your ears."},"BSB":{"text":"Then the priests and prophets said to the officials and all the people, “This man is worthy of death, for he has prophesied against this city, as you have heard with your own ears!”"},"TANAKH":{"text":"Then spoke the priests and the prophets unto the princes and to all the people, saying: 'This man is worthy of death; for he hath prophesied against this city, as ye have heard with your ears.'"},"HEBREW":{"text":"וַיֹּ֨אמְר֜וּ הַכֹּהֲנִ֤ים וְהַנְּבִאִים֙ אֶל־הַשָּׂרִ֔ים וְאֶל־כָּל־הָעָ֖ם לֵאמֹ֑ר מִשְׁפַּט־מָ֙וֶת֙ לָאִ֣ישׁ הַזֶּ֔ה כִּ֤י נִבָּא֙ אֶל־הָעִ֣יר הַזֹּ֔את כַּאֲשֶׁ֥ר שְׁמַעְתֶּ֖ם בְּאָזְנֵיכֶֽם׃"}},"definableWords":["people","man","death"],"peopleInVerse":[]},"12":{"text":"Then spake Jeremiah unto all the princes and to all the people, saying, The LORD sent me to prophesy against this house and against this city all the words that ye have heard.","ref":"Jeremiah 26:12","synthesized":"But Jeremiah said to all the officials and all the people, “The LORD sent me to prophesy against this house and against this city all the words that you have heard.","sources":{"KJV":{"text":"Then spake Jeremiah unto all the princes and to all the people, saying, The LORD sent me to prophesy against this house and against this city all the words that ye have heard."},"BSB":{"text":"But Jeremiah said to all the officials and all the people, “The LORD sent me to prophesy against this house and against this city all the words that you have heard."},"TANAKH":{"text":"Then spoke Jeremiah unto all the princes and to all the people, saying: 'The HaShem sent me to prophesy against this house and against this city all the words that ye have heard."},"HEBREW":{"text":"וַיֹּ֤אמֶר יִרְמְיָ֙הוּ֙ אֶל־כָּל־הַשָּׂרִ֔ים וְאֶל־כָּל־הָעָ֖ם לֵאמֹ֑ר יְהוָ֣ה שְׁלָחַ֗נִי לְהִנָּבֵ֞א אֶל־הַבַּ֤יִת הַזֶּה֙ וְאֶל־הָעִ֣יר הַזֹּ֔את אֵ֥ת כָּל־הַדְּבָרִ֖ים אֲשֶׁ֥ר שְׁמַעְתֶּֽם׃"}},"definableWords":["people","LORD","house"],"peopleInVerse":["Jeremiah"]},"13":{"text":"Therefore now amend your ways and your doings, and obey the voice of the LORD your God; and the LORD will repent him of the evil that he hath pronounced against you.","ref":"Jeremiah 26:13","synthesized":"So now, correct your ways and deeds, and obey the voice of the LORD your God, so that He might relent of the disaster He has pronounced against you.","sources":{"KJV":{"text":"Therefore now amend your ways and your doings, and obey the voice of the LORD your God; and the LORD will repent him of the evil that he hath pronounced against you."},"BSB":{"text":"So now, correct your ways and deeds, and obey the voice of the LORD your God, so that He might relent of the disaster He has pronounced against you."},"TANAKH":{"text":"Therefore now amend your ways and your doings, and hearken to the voice of HaShem your G-d; and HaShem will repent Him of the evil that He hath pronounced against you."},"HEBREW":{"text":"וְעַתָּ֗ה הֵיטִ֤יבוּ דַרְכֵיכֶם֙ וּמַ֣עַלְלֵיכֶ֔ם וְשִׁמְע֕וּ בְּק֖וֹל יְהוָ֣ה אֱלֹהֵיכֶ֑ם וְיִנָּחֵ֣ם יְהוָ֔ה אֶל־הָ֣רָעָ֔ה אֲשֶׁ֥ר דִּבֶּ֖ר עֲלֵיכֶֽם׃"}},"definableWords":["voice","LORD","God"],"peopleInVerse":[]},"14":{"text":"As for me, behold, I am in your hand: do with me as seemeth good and meet unto you.","ref":"Jeremiah 26:14","synthesized":"As for me, here I am in your hands; do to me what you think is good and right.","sources":{"KJV":{"text":"As for me, behold, I am in your hand: do with me as seemeth good and meet unto you."},"BSB":{"text":"As for me, here I am in your hands; do to me what you think is good and right."},"TANAKH":{"text":"But as for me, behold, I am in your hand; do with me as is good and right in your eyes."},"HEBREW":{"text":"וַאֲנִ֖י הִנְנִ֣י בְיֶדְכֶ֑ם עֲשׂוּ־לִ֛י כַּטּ֥וֹב וְכַיָּשָׁ֖ר בְּעֵינֵיכֶֽם׃"}},"definableWords":["good"],"peopleInVerse":[]},"15":{"text":"But know ye for certain, that if ye put me to death, ye shall surely bring innocent blood upon yourselves, and upon this city, and upon the inhabitants thereof: for of a truth the LORD hath sent me unto you to speak all these words in your ears.","ref":"Jeremiah 26:15","synthesized":"But know for certain that if you put me to death, you will bring innocent blood upon yourselves, upon this city, and upon its residents; for truly the LORD has sent me to speak all these words in your hearing.”","sources":{"KJV":{"text":"But know ye for certain, that if ye put me to death, ye shall surely bring innocent blood upon yourselves, and upon this city, and upon the inhabitants thereof: for of a truth the LORD hath sent me unto you to speak all these words in your ears."},"BSB":{"text":"But know for certain that if you put me to death, you will bring innocent blood upon yourselves, upon this city, and upon its residents; for truly the LORD has sent me to speak all these words in your hearing.”"},"TANAKH":{"text":"Only know ye for certain that, if ye put me to death, ye will bring innocent blood upon yourselves, and upon this city, and upon the inhabitants thereof; for of a truth HaShem hath sent me unto you to speak all these words in your ears.'"},"HEBREW":{"text":"אַ֣ךְ ׀ יָדֹ֣עַ תֵּדְע֗וּ כִּ֣י אִם־מְמִתִ֣ים אַתֶּם֮ אֹתִי֒ כִּי־דָ֣ם נָקִ֗י אַתֶּם֙ נֹתְנִ֣ים עֲלֵיכֶ֔ם וְאֶל־הָעִ֥יר הַזֹּ֖את וְאֶל־יֹשְׁבֶ֑יהָ כִּ֣י בֶאֱמֶ֗ת שְׁלָחַ֤נִי יְהוָה֙ עֲלֵיכֶ֔ם לְדַבֵּר֙ בְּאָזְנֵיכֶ֔ם אֵ֥ת כָּל־הַדְּבָרִ֖ים הָאֵֽלֶּה׃"}},"definableWords":["death","blood","LORD"],"peopleInVerse":[],"themesInVerse":["passover","sacrifice"]},"16":{"text":"Then said the princes and all the people unto the priests and to the prophets; This man is not worthy to die: for he hath spoken to us in the name of the LORD our God.","ref":"Jeremiah 26:16","synthesized":"Then the officials and all the people told the priests and prophets, “This man is not worthy of death, for he has spoken to us in the name of the LORD our God!”","sources":{"KJV":{"text":"Then said the princes and all the people unto the priests and to the prophets; This man is not worthy to die: for he hath spoken to us in the name of the LORD our God."},"BSB":{"text":"Then the officials and all the people told the priests and prophets, “This man is not worthy of death, for he has spoken to us in the name of the LORD our God!”"},"TANAKH":{"text":"Then said the princes and all the people unto the priests and to the prophets: 'This man is not worthy of death; for he hath spoken to us in the name of HaShem our G-d.'"},"HEBREW":{"text":"וַיֹּאמְר֤וּ הַשָּׂרִים֙ וְכָל־הָעָ֔ם אֶל־הַכֹּהֲנִ֖ים וְאֶל־הַנְּבִיאִ֑ים אֵין־לָאִ֤ישׁ הַזֶּה֙ מִשְׁפַּט־מָ֔וֶת כִּ֗י בְּשֵׁ֛ם יְהוָ֥ה אֱלֹהֵ֖ינוּ דִּבֶּ֥ר אֵלֵֽינוּ׃"}},"definableWords":["people","man","death","name","LORD","God"],"peopleInVerse":[]},"17":{"text":"Then rose up certain of the elders of the land, and spake to all the assembly of the people, saying,","ref":"Jeremiah 26:17","synthesized":"Some of the elders of the land stood up and said to the whole assembly of the people,","sources":{"KJV":{"text":"Then rose up certain of the elders of the land, and spake to all the assembly of the people, saying,"},"BSB":{"text":"Some of the elders of the land stood up and said to the whole assembly of the people,"},"TANAKH":{"text":"Then rose up certain of the elders of the land, and spoke to all the assembly of the people, saying:"},"HEBREW":{"text":"וַיָּקֻ֣מוּ אֲנָשִׁ֔ים מִזִּקְנֵ֖י הָאָ֑רֶץ וַיֹּ֣אמְר֔וּ אֶל־כָּל־קְהַ֥ל הָעָ֖ם לֵאמֹֽר׃"}},"definableWords":["land","people"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"18":{"text":"Micah the Morasthite prophesied in the days of Hezekiah king of Judah, and spake to all the people of Judah, saying, Thus saith the LORD of hosts; Zion shall be plowed like a field, and Jerusalem shall become heaps, and the mountain of the house as the high places of a forest.","ref":"Jeremiah 26:18","synthesized":"“Micah the Moreshite prophesied in the days of Hezekiah king of Judah and told all the people of Judah that this is what the LORD of Hosts says:  ‘Zion will be plowed like a field, Jerusalem will become a heap of rubble, and the temple mount a wooded ridge.’","sources":{"KJV":{"text":"Micah the Morasthite prophesied in the days of Hezekiah king of Judah, and spake to all the people of Judah, saying, Thus saith the LORD of hosts; Zion shall be plowed like a field, and Jerusalem shall become heaps, and the mountain of the house as the high places of a forest."},"BSB":{"text":"“Micah the Moreshite prophesied in the days of Hezekiah king of Judah and told all the people of Judah that this is what the LORD of Hosts says:  ‘Zion will be plowed like a field, Jerusalem will become a heap of rubble, and the temple mount a wooded ridge.’"},"TANAKH":{"text":"'Micah the Morashtite prophesied in the days of Hezekiah king of Judah; and he spoke to all the people of Judah, saying: Thus saith HaShem of hosts: Zion shall be plowed as a field, and Jerusalem shall become heaps, and the mountain of the house as the high places of a forest."},"HEBREW":{"text":"מיכיה מִיכָה֙ הַמּ֣וֹרַשְׁתִּ֔י הָיָ֣ה נִבָּ֔א בִּימֵ֖י חִזְקִיָּ֣הוּ מֶֽלֶךְ־יְהוּדָ֑ה וַיֹּ֣אמֶר אֶל־כָּל־עַם֩ יְהוּדָ֨ה לֵאמֹ֜ר כֹּֽה־אָמַ֣ר ׀ יְהוָ֣ה צְבָא֗וֹת צִיּ֞וֹן שָׂדֶ֤ה תֵֽחָרֵשׁ֙ וִירוּשָׁלַ֙יִם֙ עִיִּ֣ים תִּֽהְיֶ֔ה וְהַ֥ר הַבַּ֖יִת לְבָמ֥וֹת יָֽעַר׃"}},"definableWords":["days","king","Judah","people","LORD","Zion","field","Jerusalem","temple"],"peopleInVerse":[],"placesInVerse":["Mount Zion","Jerusalem"],"themesInVerse":["kingship","temple"]},"19":{"text":"Did Hezekiah king of Judah and all Judah put him at all to death? did he not fear the LORD, and besought the LORD, and the LORD repented him of the evil which he had pronounced against them? Thus might we procure great evil against our souls.","ref":"Jeremiah 26:19","synthesized":"Did Hezekiah king of Judah or anyone else in Judah put him to death? Did Hezekiah not fear the LORD and seek His favor, and did not the LORD relent of the disaster He had pronounced against them? But we are about to bring great harm on ourselves!”","sources":{"KJV":{"text":"Did Hezekiah king of Judah and all Judah put him at all to death? did he not fear the LORD, and besought the LORD, and the LORD repented him of the evil which he had pronounced against them? Thus might we procure great evil against our souls."},"BSB":{"text":"Did Hezekiah king of Judah or anyone else in Judah put him to death? Did Hezekiah not fear the LORD and seek His favor, and did not the LORD relent of the disaster He had pronounced against them? But we are about to bring great harm on ourselves!”"},"TANAKH":{"text":"Did Hezekiah king of Judah and all Judah put him at all to death? did he not fear HaShem, and entreat the favour of HaShem, and HaShem repented Him of the evil which He had pronounced against them? Thus might we procure great evil against our own souls.'"},"HEBREW":{"text":"הֶהָמֵ֣ת הֱ֠מִתֻהוּ חִזְקִיָּ֨הוּ מֶֽלֶךְ־יְהוּדָ֜ה וְכָל־יְהוּדָ֗ה הֲלֹא֮ יָרֵ֣א אֶת־יְהוָה֒ וַיְחַל֙ אֶת־פְּנֵ֣י יְהוָ֔ה וַיִּנָּ֣חֶם יְהוָ֔ה אֶל־הָרָעָ֖ה אֲשֶׁר־דִּבֶּ֣ר עֲלֵיהֶ֑ם וַאֲנַ֗חְנוּ עֹשִׂ֛ים רָעָ֥ה גְדוֹלָ֖ה עַל־נַפְשׁוֹתֵֽינוּ׃"}},"definableWords":["king","Judah","or","death","fear","LORD","seek","Lord","great"],"peopleInVerse":[],"themesInVerse":["fear_of_lord","grace","kingship"]},"20":{"text":"And there was also a man that prophesied in the name of the LORD, Urijah the son of Shemaiah of Kirjathjearim, who prophesied against this city and against this land according to all the words of Jeremiah:","ref":"Jeremiah 26:20","synthesized":"Now there was another man prophesying in the name of the LORD, Uriah son of Shemaiah from Kiriath-jearim. He prophesied against this city and against this land the same things that Jeremiah did.","sources":{"KJV":{"text":"And there was also a man that prophesied in the name of the LORD, Urijah the son of Shemaiah of Kirjathjearim, who prophesied against this city and against this land according to all the words of Jeremiah:"},"BSB":{"text":"Now there was another man prophesying in the name of the LORD, Uriah son of Shemaiah from Kiriath-jearim. He prophesied against this city and against this land the same things that Jeremiah did."},"TANAKH":{"text":"And there was also a man that prophesied in the name of HaShem, Uriah the son of Shemaiah of Kiriath-jearim; and he prophesied against this city and against this land according to all the words of Jeremiah;"},"HEBREW":{"text":"וְגַם־אִ֗ישׁ הָיָ֤ה מִתְנַבֵּא֙ בְּשֵׁ֣ם יְהוָ֔ה אֽוּרִיָּ֙הוּ֙ בֶּֽן־שְׁמַעְיָ֔הוּ מִקִּרְיַ֖ת הַיְּעָרִ֑ים וַיִּנָּבֵ֞א עַל־הָעִ֤יר הַזֹּאת֙ וְעַל־הָאָ֣רֶץ הַזֹּ֔את כְּכֹ֖ל דִּבְרֵ֥י יִרְמְיָֽהוּ׃"}},"definableWords":["man","name","LORD","son","land"],"peopleInVerse":["Jeremiah"],"themesInVerse":["land_promise"]},"21":{"text":"And when Jehoiakim the king, with all his mighty men, and all the princes, heard his words, the king sought to put him to death: but when Urijah heard it, he was afraid, and fled, and went into Egypt;","ref":"Jeremiah 26:21","synthesized":"King Jehoiakim and all his mighty men and officials heard his words, and the king sought to put him to death. But when Uriah found out about it, he fled in fear and went to Egypt.","sources":{"KJV":{"text":"And when Jehoiakim the king, with all his mighty men, and all the princes, heard his words, the king sought to put him to death: but when Urijah heard it, he was afraid, and fled, and went into Egypt;"},"BSB":{"text":"King Jehoiakim and all his mighty men and officials heard his words, and the king sought to put him to death. But when Uriah found out about it, he fled in fear and went to Egypt."},"TANAKH":{"text":"and when Jehoiakim the king, with all his mighty men, and all the princes, heard his words, the king sought to put him to death; but when Uriah heard it, he was afraid, and fled, and went into Egypt;"},"HEBREW":{"text":"וַיִּשְׁמַ֣ע הַמֶּֽלֶךְ־יְ֠הוֹיָקִים וְכָל־גִּבּוֹרָ֤יו וְכָל־הַשָּׂרִים֙ אֶת־דְּבָרָ֔יו וַיְבַקֵּ֥שׁ הַמֶּ֖לֶךְ הֲמִית֑וֹ וַיִּשְׁמַ֤ע אוּרִיָּ֙הוּ֙ וַיִּרָ֔א וַיִּבְרַ֖ח וַיָּבֹ֥א מִצְרָֽיִם׃"}},"definableWords":["King","mighty","men","king","death","fear","Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","fear_of_lord","kingship"]},"22":{"text":"And Jehoiakim the king sent men into Egypt, namely, Elnathan the son of Achbor, and certain men with him into Egypt.","ref":"Jeremiah 26:22","synthesized":"Then King Jehoiakim sent men to Egypt: Elnathan son of Achbor along with some other men.","sources":{"KJV":{"text":"And Jehoiakim the king sent men into Egypt, namely, Elnathan the son of Achbor, and certain men with him into Egypt."},"BSB":{"text":"Then King Jehoiakim sent men to Egypt: Elnathan son of Achbor along with some other men."},"TANAKH":{"text":"and Jehoiakim the king sent men into Egypt, Elnathan the son of Achbor, and certain men with him, into Egypt;"},"HEBREW":{"text":"וַיִּשְׁלַ֞ח הַמֶּ֧לֶךְ יְהוֹיָקִ֛ים אֲנָשִׁ֖ים מִצְרָ֑יִם אֵ֣ת אֶלְנָתָ֧ן בֶּן־עַכְבּ֛וֹר וַאֲנָשִׁ֥ים אִתּ֖וֹ אֶל־מִצְרָֽיִם׃"}},"definableWords":["King","men","Egypt","son"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","kingship"]},"23":{"text":"And they fetched forth Urijah out of Egypt, and brought him unto Jehoiakim the king; who slew him with the sword, and cast his dead body into the graves of the common people.","ref":"Jeremiah 26:23","synthesized":"They brought Uriah out of Egypt and took him to King Jehoiakim, who had him put to the sword and his body thrown into the burial place of the common people.","sources":{"KJV":{"text":"And they fetched forth Urijah out of Egypt, and brought him unto Jehoiakim the king; who slew him with the sword, and cast his dead body into the graves of the common people."},"BSB":{"text":"They brought Uriah out of Egypt and took him to King Jehoiakim, who had him put to the sword and his body thrown into the burial place of the common people."},"TANAKH":{"text":"and they fetched forth Uriah out of Egypt, and brought him unto Jehoiakim the king; who slew him with the sword, and cast his dead body into the graves of the children of the people."},"HEBREW":{"text":"וַיּוֹצִ֨יאוּ אֶת־אוּרִיָּ֜הוּ מִמִּצְרַ֗יִם וַיְבִאֻ֙הוּ֙ אֶל־הַמֶּ֣לֶךְ יְהוֹיָקִ֔ים וַיַּכֵּ֖הוּ בֶּחָ֑רֶב וַיַּשְׁלֵךְ֙ אֶת־נִבְלָת֔וֹ אֶל־קִבְרֵ֖י בְּנֵ֥י הָעָֽם׃"}},"definableWords":["Egypt","King","people"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","kingship"]},"24":{"text":"Nevertheless the hand of Ahikam the son of Shaphan was with Jeremiah, that they should not give him into the hand of the people to put him to death.","ref":"Jeremiah 26:24","synthesized":"Nevertheless, Ahikam son of Shaphan supported Jeremiah, so he was not handed over to the people to be put to death.","sources":{"KJV":{"text":"Nevertheless the hand of Ahikam the son of Shaphan was with Jeremiah, that they should not give him into the hand of the people to put him to death."},"BSB":{"text":"Nevertheless, Ahikam son of Shaphan supported Jeremiah, so he was not handed over to the people to be put to death."},"TANAKH":{"text":"Nevertheless the hand of Ahikam the son of Shaphan was with Jeremiah, that they should not give him into the hand of the people to put him to death."},"HEBREW":{"text":"אַ֗ךְ יַ֚ד אֲחִיקָ֣ם בֶּן־שָׁפָ֔ן הָיְתָ֖ה אֶֽת־יִרְמְיָ֑הוּ לְבִלְתִּ֛י תֵּת־אֹת֥וֹ בְיַד־הָעָ֖ם לַהֲמִיתֽוֹ׃"}},"definableWords":["son","people","death"],"peopleInVerse":["Jeremiah"]}}},"27":{"chapter":"27","title":"THE YOKES OF SUBMISSION","verses":{"1":{"text":"In the beginning of the reign of Jehoiakim the son of Josiah king of Judah came this word unto Jeremiah from the LORD, saying,","ref":"Jeremiah 27:1","synthesized":"At the beginning of the reign of Zedekiah son of Josiah king of Judah, this word came to Jeremiah from the LORD.","sources":{"KJV":{"text":"In the beginning of the reign of Jehoiakim the son of Josiah king of Judah came this word unto Jeremiah from the LORD, saying,"},"BSB":{"text":"At the beginning of the reign of Zedekiah son of Josiah king of Judah, this word came to Jeremiah from the LORD."},"TANAKH":{"text":"In the beginning of the reign of Jehoiakim the son of Josiah, king of Judah, came this word unto Jeremiah from HaShem, saying:"},"HEBREW":{"text":"בְּרֵאשִׁ֗ית מַמְלֶ֛כֶת יְהוֹיָקִ֥ם בֶּן־יֹאושִׁיָּ֖הוּ מֶ֣לֶךְ יְהוּדָ֑ה הָיָ֞ה הַדָּבָ֤ר הַזֶּה֙ אֶֽל־יִרְמְיָ֔ה מֵאֵ֥ת יְהוָ֖ה לֵאמֹֽר׃"}},"definableWords":["beginning","reign","son","king","Judah","word","LORD"],"peopleInVerse":["Jeremiah"],"themesInVerse":["creation","kingdom_of_god","kingship"]},"2":{"text":"Thus saith the LORD to me; Make thee bonds and yokes, and put them upon thy neck,","ref":"Jeremiah 27:2","synthesized":"This is what the LORD said to me:  “Make for yourself a yoke out of leather straps and put it on your neck.","sources":{"KJV":{"text":"Thus saith the LORD to me; Make thee bonds and yokes, and put them upon thy neck,"},"BSB":{"text":"This is what the LORD said to me:  “Make for yourself a yoke out of leather straps and put it on your neck."},"TANAKH":{"text":"'Thus saith HaShem to me: Make thee bands and bars, and put them upon thy neck;"},"HEBREW":{"text":"כֹּֽה־אָמַ֤ר יְהוָה֙ אֵלַ֔י עֲשֵׂ֣ה לְךָ֔ מוֹסֵר֖וֹת וּמֹט֑וֹת וּנְתַתָּ֖ם עַל־צַוָּארֶֽךָ׃"}},"definableWords":["LORD","make"],"peopleInVerse":[]},"3":{"text":"And send them to the king of Edom, and to the king of Moab, and to the king of the Ammonites, and to the king of Tyrus, and to the king of Zidon, by the hand of the messengers which come to Jerusalem unto Zedekiah king of Judah;","ref":"Jeremiah 27:3","synthesized":"Send word to the kings of Edom, Moab, Ammon, Tyre, and Sidon through the envoys who have come to Jerusalem to Zedekiah king of Judah.","sources":{"KJV":{"text":"And send them to the king of Edom, and to the king of Moab, and to the king of the Ammonites, and to the king of Tyrus, and to the king of Zidon, by the hand of the messengers which come to Jerusalem unto Zedekiah king of Judah;"},"BSB":{"text":"Send word to the kings of Edom, Moab, Ammon, Tyre, and Sidon through the envoys who have come to Jerusalem to Zedekiah king of Judah."},"TANAKH":{"text":"and send them to the king of Edom, and to the king of Moab, and to the king of the children of Ammon, and to the king of Tyre, and to the king of Zidon, by the hand of the messengers that come to Jerusalem unto Zedekiah king of Judah;"},"HEBREW":{"text":"וְשִׁלַּחְתָּם֩ אֶל־מֶ֨לֶךְ אֱד֜וֹם וְאֶל־מֶ֣לֶךְ מוֹאָ֗ב וְאֶל־מֶ֙לֶךְ֙ בְּנֵ֣י עַמּ֔וֹן וְאֶל־מֶ֥לֶךְ צֹ֖ר וְאֶל־מֶ֣לֶךְ צִיד֑וֹן בְּיַ֤ד מַלְאָכִים֙ הַבָּאִ֣ים יְרוּשָׁלִַ֔ם אֶל־צִדְקִיָּ֖הוּ מֶ֥לֶךְ יְהוּדָֽה׃"}},"definableWords":["word","kings","Edom","Jerusalem","king","Judah"],"peopleInVerse":[],"placesInVerse":["Tyre","Sidon","Jerusalem"],"themesInVerse":["kingship"]},"4":{"text":"And command them to say unto their masters, Thus saith the LORD of hosts, the God of Israel; Thus shall ye say unto your masters;","ref":"Jeremiah 27:4","synthesized":"Give them a message from the LORD of Hosts, the God of Israel, to relay to their masters:","sources":{"KJV":{"text":"And command them to say unto their masters, Thus saith the LORD of hosts, the God of Israel; Thus shall ye say unto your masters;"},"BSB":{"text":"Give them a message from the LORD of Hosts, the God of Israel, to relay to their masters:"},"TANAKH":{"text":"and give them a charge unto their masters, saying: Thus saith HaShem of hosts, the G-d of Israel: Thus shall ye say unto your masters:"},"HEBREW":{"text":"וְצִוִּיתָ֣ אֹתָ֔ם אֶל־אֲדֹֽנֵיהֶ֖ם לֵאמֹ֑ר כֹּֽה־אָמַ֞ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל כֹּ֥ה תֹֽאמְר֖וּ אֶל־אֲדֹֽנֵיכֶֽם׃"}},"definableWords":["LORD","God","Israel"],"peopleInVerse":[]},"5":{"text":"I have made the earth, the man and the beast that are upon the ground, by my great power and by my outstretched arm, and have given it unto whom it seemed meet unto me.","ref":"Jeremiah 27:5","synthesized":"By My great power and outstretched arm, I made the earth and the men and beasts on the face of it, and I give it to whom I please.","sources":{"KJV":{"text":"I have made the earth, the man and the beast that are upon the ground, by my great power and by my outstretched arm, and have given it unto whom it seemed meet unto me."},"BSB":{"text":"By My great power and outstretched arm, I made the earth and the men and beasts on the face of it, and I give it to whom I please."},"TANAKH":{"text":"I have made the earth, the man and the beast that are upon the face of the earth, by My great power and by My outstretched arm; and I give it unto whom it seemeth right unto Me."},"HEBREW":{"text":"אָנֹכִ֞י עָשִׂ֣יתִי אֶת־הָאָ֗רֶץ אֶת־הָאָדָ֤ם וְאֶת־הַבְּהֵמָה֙ אֲשֶׁר֙ עַל־פְּנֵ֣י הָאָ֔רֶץ בְּכֹחִי֙ הַגָּד֔וֹל וּבִזְרוֹעִ֖י הַנְּטוּיָ֑ה וּנְתַתִּ֕יהָ לַאֲשֶׁ֖ר יָשַׁ֥ר בְּעֵינָֽי׃"}},"definableWords":["great","made","earth","men"],"peopleInVerse":[],"themesInVerse":["creation"]},"6":{"text":"And now have I given all these lands into the hand of Nebuchadnezzar the king of Babylon, my servant; and the beasts of the field have I given him also to serve him.","ref":"Jeremiah 27:6","synthesized":"So now I have placed all these lands under the authority of My servant Nebuchadnezzar king of Babylon. I have even made the beasts of the field subject to him.","sources":{"KJV":{"text":"And now have I given all these lands into the hand of Nebuchadnezzar the king of Babylon, my servant; and the beasts of the field have I given him also to serve him."},"BSB":{"text":"So now I have placed all these lands under the authority of My servant Nebuchadnezzar king of Babylon. I have even made the beasts of the field subject to him."},"TANAKH":{"text":"And now have I given all these lands into the hand of Nebuchadnezzar the king of Babylon, My servant; and the beasts of the field also have I given him to serve him."},"HEBREW":{"text":"וְעַתָּ֗ה אָֽנֹכִי֙ נָתַ֙תִּי֙ אֶת־כָּל־הָאֲרָצ֣וֹת הָאֵ֔לֶּה בְּיַ֛ד נְבוּכַדְנֶאצַּ֥ר מֶֽלֶךְ־בָּבֶ֖ל עַבְדִּ֑י וְגַם֙ אֶת־חַיַּ֣ת הַשָּׂדֶ֔ה נָתַ֥תִּי ל֖וֹ לְעָבְדֽוֹ׃"}},"definableWords":["servant","king","Babylon","made","field"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["creation","kingship"]},"7":{"text":"And all nations shall serve him, and his son, and his son’s son, until the very time of his land come: and then many nations and great kings shall serve themselves of him.","ref":"Jeremiah 27:7","synthesized":"All nations will serve him and his son and grandson, until the time of his own land comes; then many nations and great kings will enslave him.","sources":{"KJV":{"text":"And all nations shall serve him, and his son, and his son’s son, until the very time of his land come: and then many nations and great kings shall serve themselves of him."},"BSB":{"text":"All nations will serve him and his son and grandson, until the time of his own land comes; then many nations and great kings will enslave him."},"TANAKH":{"text":"And all the nations shall serve him, and his son, and his son's son, until the time of his own land come; and then many nations and great kings shall make him their bondman."},"HEBREW":{"text":"וְעָבְד֤וּ אֹתוֹ֙ כָּל־הַגּוֹיִ֔ם וְאֶת־בְּנ֖וֹ וְאֶֽת־בֶּן־בְּנ֑וֹ עַ֣ד בֹּא־עֵ֤ת אַרְצוֹ֙ גַּם־ה֔וּא וְעָ֤בְדוּ בוֹ֙ גּוֹיִ֣ם רַבִּ֔ים וּמְלָכִ֖ים גְּדֹלִֽים׃"}},"definableWords":["nations","son","land","great","kings"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"8":{"text":"And it shall come to pass, that the nation and kingdom which will not serve the same Nebuchadnezzar the king of Babylon, and that will not put their neck under the yoke of the king of Babylon, that nation will I punish, saith the LORD, with the sword, and with the famine, and with the pestilence, until I have consumed them by his hand.","ref":"Jeremiah 27:8","synthesized":"As for the nation or kingdom that does not serve Nebuchadnezzar king of Babylon and does not place its neck under his yoke, I will punish that nation by sword and famine and plague, declares the LORD, until I have destroyed it by his hand.","sources":{"KJV":{"text":"And it shall come to pass, that the nation and kingdom which will not serve the same Nebuchadnezzar the king of Babylon, and that will not put their neck under the yoke of the king of Babylon, that nation will I punish, saith the LORD, with the sword, and with the famine, and with the pestilence, until I have consumed them by his hand."},"BSB":{"text":"As for the nation or kingdom that does not serve Nebuchadnezzar king of Babylon and does not place its neck under his yoke, I will punish that nation by sword and famine and plague, declares the LORD, until I have destroyed it by his hand."},"TANAKH":{"text":"And it shall come to pass, that the nation and the kingdom which will not serve the same Nebuchadnezzar king of Babylon, and that will not put their neck under the yoke of the king of Babylon, that nation will I visit, saith HaShem, with the sword, and with the famine, and with the pestilence, until I have consumed them by his hand."},"HEBREW":{"text":"וְהָיָ֨ה הַגּ֜וֹי וְהַמַּמְלָכָ֗ה אֲשֶׁ֨ר לֹֽא־יַעַבְד֤וּ אֹתוֹ֙ אֶת־נְבוּכַדְנֶאצַּ֣ר מֶֽלֶךְ־בָּבֶ֔ל וְאֵ֨ת אֲשֶׁ֤ר לֹֽא־יִתֵּן֙ אֶת־צַוָּאר֔וֹ בְּעֹ֖ל מֶ֣לֶךְ בָּבֶ֑ל בַּחֶרֶב֩ וּבָרָעָ֨ב וּבַדֶּ֜בֶר אֶפְקֹ֨ד עַל־הַגּ֤וֹי הַהוּא֙ נְאֻם־יְהוָ֔ה עַד־תֻּמִּ֥י אֹתָ֖ם בְּיָדֽוֹ׃"}},"definableWords":["nation","or","kingdom","king","Babylon","LORD"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingdom_of_god","kingship"]},"9":{"text":"Therefore hearken not ye to your prophets, nor to your diviners, nor to your dreamers, nor to your enchanters, nor to your sorcerers, which speak unto you, saying, Ye shall not serve the king of Babylon:","ref":"Jeremiah 27:9","synthesized":"But as for you, do not listen to your prophets, your diviners, your interpreters of dreams, your mediums, or your sorcerers who declare, ‘You will not serve the king of Babylon.’","sources":{"KJV":{"text":"Therefore hearken not ye to your prophets, nor to your diviners, nor to your dreamers, nor to your enchanters, nor to your sorcerers, which speak unto you, saying, Ye shall not serve the king of Babylon:"},"BSB":{"text":"But as for you, do not listen to your prophets, your diviners, your interpreters of dreams, your mediums, or your sorcerers who declare, ‘You will not serve the king of Babylon.’"},"TANAKH":{"text":"But as for you, hearken ye not to your prophets, nor to your diviners, nor to your dreams, nor to your soothsayers, nor to your sorcerers, that speak unto you, saying: Ye shall not serve the king of Babylon;"},"HEBREW":{"text":"וְ֠אַתֶּם אַל־תִּשְׁמְע֨וּ אֶל־נְבִיאֵיכֶ֜ם וְאֶל־קֹֽסְמֵיכֶ֗ם וְאֶל֙ חֲלֹמֹ֣תֵיכֶ֔ם וְאֶל־עֹֽנְנֵיכֶ֖ם וְאֶל־כַּשָּׁפֵיכֶ֑ם אֲשֶׁר־הֵ֞ם אֹמְרִ֤ים אֲלֵיכֶם֙ לֵאמֹ֔ר לֹ֥א תַעַבְד֖וּ אֶת־מֶ֥לֶךְ בָּבֶֽל׃"}},"definableWords":["or","king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"10":{"text":"For they prophesy a lie unto you, to remove you far from your land; and that I should drive you out, and ye should perish.","ref":"Jeremiah 27:10","synthesized":"For they prophesy to you a lie that will serve to remove you from your land; I will banish you and you will perish.","sources":{"KJV":{"text":"For they prophesy a lie unto you, to remove you far from your land; and that I should drive you out, and ye should perish."},"BSB":{"text":"For they prophesy to you a lie that will serve to remove you from your land; I will banish you and you will perish."},"TANAKH":{"text":"for they prophesy a lie unto you, to remove you far from your land; and that I should drive you out and ye should perish."},"HEBREW":{"text":"כִּ֣י שֶׁ֔קֶר הֵ֖ם נִבְּאִ֣ים לָכֶ֑ם לְמַ֨עַן הַרְחִ֤יק אֶתְכֶם֙ מֵעַ֣ל אַדְמַתְכֶ֔ם וְהִדַּחְתִּ֥י אֶתְכֶ֖ם וַאֲבַדְתֶּֽם׃"}},"definableWords":["land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"11":{"text":"But the nations that bring their neck under the yoke of the king of Babylon, and serve him, those will I let remain still in their own land, saith the LORD; and they shall till it, and dwell therein.","ref":"Jeremiah 27:11","synthesized":"But the nation that will put its neck under the yoke of the king of Babylon and serve him, I will leave in its own land, to cultivate it and reside in it, declares the LORD.”","sources":{"KJV":{"text":"But the nations that bring their neck under the yoke of the king of Babylon, and serve him, those will I let remain still in their own land, saith the LORD; and they shall till it, and dwell therein."},"BSB":{"text":"But the nation that will put its neck under the yoke of the king of Babylon and serve him, I will leave in its own land, to cultivate it and reside in it, declares the LORD.”"},"TANAKH":{"text":"But the nation that shall bring their neck under the yoke of the king of Babylon, and serve him, that nation will I let remain in their own land, saith HaShem; and they shall till it, and dwell therein.'"},"HEBREW":{"text":"וְהַגּ֗וֹי אֲשֶׁ֨ר יָבִ֧יא אֶת־צַוָּאר֛וֹ בְּעֹ֥ל מֶֽלֶךְ־בָּבֶ֖ל וַֽעֲבָד֑וֹ וְהִנַּחְתִּ֤יו עַל־אַדְמָתוֹ֙ נְאֻם־יְהוָ֔ה וַֽעֲבָדָ֖הּ וְיָ֥שַׁב בָּֽהּ׃"}},"definableWords":["nation","king","Babylon","land","LORD"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship","land_promise"]},"12":{"text":"I spake also to Zedekiah king of Judah according to all these words, saying, Bring your necks under the yoke of the king of Babylon, and serve him and his people, and live.","ref":"Jeremiah 27:12","synthesized":"And to Zedekiah king of Judah I spoke the same message: “Put your necks under the yoke of the king of Babylon; serve him and his people, and live!","sources":{"KJV":{"text":"I spake also to Zedekiah king of Judah according to all these words, saying, Bring your necks under the yoke of the king of Babylon, and serve him and his people, and live."},"BSB":{"text":"And to Zedekiah king of Judah I spoke the same message: “Put your necks under the yoke of the king of Babylon; serve him and his people, and live!"},"TANAKH":{"text":"And I spoke to Zedekiah king of Judah according to all these words, saying: 'Bring your necks under the yoke of the king of Babylon, and serve him and his people, and live."},"HEBREW":{"text":"וְאֶל־צִדְקִיָּ֤ה מֶֽלֶךְ־יְהוּדָה֙ דִּבַּ֔רְתִּי כְּכָל־הַדְּבָרִ֥ים הָאֵ֖לֶּה לֵאמֹ֑ר הָבִ֨יאוּ אֶת־צַוְּארֵיכֶ֜ם בְּעֹ֣ל מֶֽלֶךְ־בָּבֶ֗ל וְעִבְד֥וּ אֹת֛וֹ וְעַמּ֖וֹ וִֽחְיֽוּ׃"}},"definableWords":["king","Judah","King","Babylon","people","live"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"13":{"text":"Why will ye die, thou and thy people, by the sword, by the famine, and by the pestilence, as the LORD hath spoken against the nation that will not serve the king of Babylon?","ref":"Jeremiah 27:13","synthesized":"Why should you and your people die by sword and famine and plague, as the LORD has decreed against any nation that does not serve the king of Babylon?","sources":{"KJV":{"text":"Why will ye die, thou and thy people, by the sword, by the famine, and by the pestilence, as the LORD hath spoken against the nation that will not serve the king of Babylon?"},"BSB":{"text":"Why should you and your people die by sword and famine and plague, as the LORD has decreed against any nation that does not serve the king of Babylon?"},"TANAKH":{"text":"Why will ye die, thou and thy people, by the sword, by the famine, and by the pestilence, as HaShem hath spoken concerning the nation that will not serve the king of Babylon?"},"HEBREW":{"text":"לָ֤מָּה תָמ֙וּתוּ֙ אַתָּ֣ה וְעַמֶּ֔ךָ בַּחֶ֖רֶב בָּרָעָ֣ב וּבַדָּ֑בֶר כַּֽאֲשֶׁר֙ דִּבֶּ֣ר יְהוָ֔ה אֶל־הַגּ֕וֹי אֲשֶׁ֥ר לֹֽא־יַעֲבֹ֖ד אֶת־מֶ֥לֶךְ בָּבֶֽל׃"}},"definableWords":["people","die","LORD","nation","king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"14":{"text":"Therefore hearken not unto the words of the prophets that speak unto you, saying, Ye shall not serve the king of Babylon: for they prophesy a lie unto you.","ref":"Jeremiah 27:14","synthesized":"Do not listen to the words of the prophets who say, ‘You must not serve the king of Babylon,’ for they are prophesying to you a lie.","sources":{"KJV":{"text":"Therefore hearken not unto the words of the prophets that speak unto you, saying, Ye shall not serve the king of Babylon: for they prophesy a lie unto you."},"BSB":{"text":"Do not listen to the words of the prophets who say, ‘You must not serve the king of Babylon,’ for they are prophesying to you a lie."},"TANAKH":{"text":"And hearken not unto the words of the prophets that speak unto you, saying: Ye shall not serve the king of Babylon, for they prophesy a lie unto you."},"HEBREW":{"text":"וְאַֽל־תִּשְׁמְע֞וּ אֶל־דִּבְרֵ֣י הַנְּבִאִ֗ים הָאֹמְרִ֤ים אֲלֵיכֶם֙ לֵאמֹ֔ר לֹ֥א תַעַבְד֖וּ אֶת־מֶ֣לֶךְ בָּבֶ֑ל כִּ֣י שֶׁ֔קֶר הֵ֖ם נִבְּאִ֥ים לָכֶֽם׃"}},"definableWords":["king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"15":{"text":"For I have not sent them, saith the LORD, yet they prophesy a lie in my name; that I might drive you out, and that ye might perish, ye, and the prophets that prophesy unto you.","ref":"Jeremiah 27:15","synthesized":"For I have not sent them, declares the LORD, and yet they are prophesying falsely in My name; therefore I will banish you, and you will perish—you and the prophets who prophesy to you.”","sources":{"KJV":{"text":"For I have not sent them, saith the LORD, yet they prophesy a lie in my name; that I might drive you out, and that ye might perish, ye, and the prophets that prophesy unto you."},"BSB":{"text":"For I have not sent them, declares the LORD, and yet they are prophesying falsely in My name; therefore I will banish you, and you will perish—you and the prophets who prophesy to you.”"},"TANAKH":{"text":"For I have not sent them, saith HaShem, and they prophesy falsely in My name; that I might drive you out, and that ye might perish, ye, and the prophets that prophesy unto you.'"},"HEBREW":{"text":"כִּ֣י לֹ֤א שְׁלַחְתִּים֙ נְאֻם־יְהוָ֔ה וְהֵ֛ם נִבְּאִ֥ים בִּשְׁמִ֖י לַשָּׁ֑קֶר לְמַ֨עַן הַדִּיחִ֤י אֶתְכֶם֙ וַאֲבַדְתֶּ֔ם אַתֶּ֕ם וְהַנְּבִאִ֖ים הֽ͏ַנִּבְּאִ֥ים לָכֶֽם׃"}},"definableWords":["LORD","name"],"peopleInVerse":[]},"16":{"text":"Also I spake to the priests and to all this people, saying, Thus saith the LORD; Hearken not to the words of your prophets that prophesy unto you, saying, Behold, the vessels of the LORD’s house shall now shortly be brought again from Babylon: for they prophesy a lie unto you.","ref":"Jeremiah 27:16","synthesized":"Then I said to the priests and to all this people, “This is what the LORD says: Do not listen to the words of your prophets who prophesy to you, saying, ‘Look, very soon now the articles from the house of the LORD will be brought back from Babylon.’ They are prophesying to you a lie.","sources":{"KJV":{"text":"Also I spake to the priests and to all this people, saying, Thus saith the LORD; Hearken not to the words of your prophets that prophesy unto you, saying, Behold, the vessels of the LORD’s house shall now shortly be brought again from Babylon: for they prophesy a lie unto you."},"BSB":{"text":"Then I said to the priests and to all this people, “This is what the LORD says: Do not listen to the words of your prophets who prophesy to you, saying, ‘Look, very soon now the articles from the house of the LORD will be brought back from Babylon.’ They are prophesying to you a lie."},"TANAKH":{"text":"Also I spoke to the priests and to all this people, saying: 'Thus saith HaShem: Hearken not to the words of your prophets that prophesy unto you, saying: Behold, the vessels of HaShem'S house shall now shortly be brought back from Babylon; for they prophesy a lie unto you."},"HEBREW":{"text":"וְאֶל־הַכֹּהֲנִים֩ וְאֶל־כָּל־הָעָ֨ם הַזֶּ֜ה דִּבַּ֣רְתִּי לֵאמֹ֗ר כֹּה֮ אָמַ֣ר יְהוָה֒ אַֽל־תִּשְׁמְע֞וּ אֶל־דִּבְרֵ֣י נְבִֽיאֵיכֶ֗ם הַֽנִבְּאִ֤ים לָכֶם֙ לֵאמֹ֔ר הִנֵּ֨ה כְלֵ֧י בֵית־יְהוָ֛ה מוּשָׁבִ֥ים מִבָּבֶ֖לָה עַתָּ֣ה מְהֵרָ֑ה כִּ֣י שֶׁ֔קֶר הֵ֖מָּה נִבְּאִ֥ים לָכֶֽם׃"}},"definableWords":["people","LORD","house","Lord","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"17":{"text":"Hearken not unto them; serve the king of Babylon, and live: wherefore should this city be laid waste?","ref":"Jeremiah 27:17","synthesized":"Do not listen to them. Serve the king of Babylon and live! Why should this city become a ruin?","sources":{"KJV":{"text":"Hearken not unto them; serve the king of Babylon, and live: wherefore should this city be laid waste?"},"BSB":{"text":"Do not listen to them. Serve the king of Babylon and live! Why should this city become a ruin?"},"TANAKH":{"text":"Hearken not unto them; serve the king of Babylon, and live; wherefore should this city become desolate?"},"HEBREW":{"text":"אַל־תִּשְׁמְע֣וּ אֲלֵיהֶ֔ם עִבְד֥וּ אֶת־מֶֽלֶךְ־בָּבֶ֖ל וִֽחְי֑וּ לָ֧מָּה תִֽהְיֶ֛ה הָעִ֥יר הַזֹּ֖את חָרְבָּֽה׃"}},"definableWords":["king","Babylon","live"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"18":{"text":"But if they be prophets, and if the word of the LORD be with them, let them now make intercession to the LORD of hosts, that the vessels which are left in the house of the LORD, and in the house of the king of Judah, and at Jerusalem, go not to Babylon.","ref":"Jeremiah 27:18","synthesized":"If they are indeed prophets and the word of the LORD is with them, let them now plead with the LORD of Hosts that the articles remaining in the house of the LORD, in the palace of the king of Judah, and in Jerusalem, not be taken to Babylon.","sources":{"KJV":{"text":"But if they be prophets, and if the word of the LORD be with them, let them now make intercession to the LORD of hosts, that the vessels which are left in the house of the LORD, and in the house of the king of Judah, and at Jerusalem, go not to Babylon."},"BSB":{"text":"If they are indeed prophets and the word of the LORD is with them, let them now plead with the LORD of Hosts that the articles remaining in the house of the LORD, in the palace of the king of Judah, and in Jerusalem, not be taken to Babylon."},"TANAKH":{"text":"But if they be prophets, and if the word of HaShem be with them, let them now make intercession to HaShem of hosts, that the vessels which are left in the house of HaShem, and in the house of the king of Judah, and at Jerusalem, go not to Babylon."},"HEBREW":{"text":"וְאִם־נְבִאִ֣ים הֵ֔ם וְאִם־יֵ֥שׁ דְּבַר־יְהוָ֖ה אִתָּ֑ם יִפְגְּעוּ־נָא֙ בַּֽיהוָ֣ה צְבָא֔וֹת לְבִלְתִּי־בֹ֜אוּ הַכֵּלִ֣ים ׀ הַנּוֹתָרִ֣ים בְּבֵית־יְהוָ֗ה וּבֵ֨ית מֶ֧לֶךְ יְהוּדָ֛ה וּבִירוּשָׁלַ֖͏ִם בָּבֶֽלָה׃"}},"definableWords":["word","LORD","Lord","house","king","Judah","Jerusalem","Babylon"],"peopleInVerse":[],"placesInVerse":["Jerusalem","Babylon"],"themesInVerse":["kingship"]},"19":{"text":"For thus saith the LORD of hosts concerning the pillars, and concerning the sea, and concerning the bases, and concerning the residue of the vessels that remain in this city,","ref":"Jeremiah 27:19","synthesized":"For this is what the LORD of Hosts says about the pillars, the sea, the bases, and the rest of the articles that remain in this city,","sources":{"KJV":{"text":"For thus saith the LORD of hosts concerning the pillars, and concerning the sea, and concerning the bases, and concerning the residue of the vessels that remain in this city,"},"BSB":{"text":"For this is what the LORD of Hosts says about the pillars, the sea, the bases, and the rest of the articles that remain in this city,"},"TANAKH":{"text":"For thus saith HaShem of hosts concerning the pillars, and concerning the sea, and concerning the bases, and concerning the residue of the vessels that remain in this city,"},"HEBREW":{"text":"כִּ֣י כֹ֤ה אָמַר֙ יְהוָ֣ה צְבָא֔וֹת אֶל־הָֽעַמֻּדִ֔ים וְעַל־הַיָּ֖ם וְעַל־הַמְּכֹנ֑וֹת וְעַל֙ יֶ֣תֶר הַכֵּלִ֔ים הַנּוֹתָרִ֖ים בָּעִ֥יר הַזֹּֽאת׃"}},"definableWords":["LORD","sea","rest"],"peopleInVerse":[],"themesInVerse":["peace","sabbath_rest"]},"20":{"text":"Which Nebuchadnezzar king of Babylon took not, when he carried away captive Jeconiah the son of Jehoiakim king of Judah from Jerusalem to Babylon, and all the nobles of Judah and Jerusalem;","ref":"Jeremiah 27:20","synthesized":"which Nebuchadnezzar king of Babylon did not take when he carried Jeconiah son of Jehoiakim king of Judah into exile from Jerusalem to Babylon, along with all the nobles of Judah and Jerusalem.","sources":{"KJV":{"text":"Which Nebuchadnezzar king of Babylon took not, when he carried away captive Jeconiah the son of Jehoiakim king of Judah from Jerusalem to Babylon, and all the nobles of Judah and Jerusalem;"},"BSB":{"text":"which Nebuchadnezzar king of Babylon did not take when he carried Jeconiah son of Jehoiakim king of Judah into exile from Jerusalem to Babylon, along with all the nobles of Judah and Jerusalem."},"TANAKH":{"text":"which Nebuchadnezzar king of Babylon took not, when he carried away captive Jeconiah the son of Jehoiakim, king of Judah, from Jerusalem to Babylon, and all the nobles of Judah and Jerusalem;"},"HEBREW":{"text":"אֲשֶׁ֣ר לֹֽא־לְקָחָ֗ם נְבֽוּכַדְנֶאצַּר֙ מֶ֣לֶךְ בָּבֶ֔ל בַּ֠גְלוֹתוֹ אֶת־יְכָונְיָ֨ה בֶן־יְהוֹיָקִ֧ים מֶֽלֶךְ־יְהוּדָ֛ה מִירֽוּשָׁלַ֖͏ִם בָּבֶ֑לָה וְאֵ֛ת כָּל־חֹרֵ֥י יְהוּדָ֖ה וִירוּשָׁלָֽ͏ִם׃"}},"definableWords":["king","Babylon","son","King","Judah","Jerusalem"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon","Jerusalem"],"themesInVerse":["exile_return","kingship"]},"21":{"text":"Yea, thus saith the LORD of hosts, the God of Israel, concerning the vessels that remain in the house of the LORD, and in the house of the king of Judah and of Jerusalem;","ref":"Jeremiah 27:21","synthesized":"Yes, this is what the LORD of Hosts, the God of Israel, says about the articles that remain in the house of the LORD, in the palace of the king of Judah, and in Jerusalem:","sources":{"KJV":{"text":"Yea, thus saith the LORD of hosts, the God of Israel, concerning the vessels that remain in the house of the LORD, and in the house of the king of Judah and of Jerusalem;"},"BSB":{"text":"Yes, this is what the LORD of Hosts, the God of Israel, says about the articles that remain in the house of the LORD, in the palace of the king of Judah, and in Jerusalem:"},"TANAKH":{"text":"yea, thus saith HaShem of hosts, the G-d of Israel, concerning the vessels that remain in the house of HaShem, and in the house of the king of Judah, and at Jerusalem:"},"HEBREW":{"text":"כִּ֣י כֹ֥ה אָמַ֛ר יְהוָ֥ה צְבָא֖וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֑ל עַל־הַכֵּלִ֗ים הַנּֽוֹתָרִים֙ בֵּ֣ית יְהוָ֔ה וּבֵ֥ית מֶֽלֶךְ־יְהוּדָ֖ה וִירוּשָׁלָֽ͏ִם׃"}},"definableWords":["LORD","God","Israel","house","Lord","king","Judah","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["kingship"]},"22":{"text":"They shall be carried to Babylon, and there shall they be until the day that I visit them, saith the LORD; then will I bring them up, and restore them to this place.","ref":"Jeremiah 27:22","synthesized":"‘They will be carried to Babylon and will remain there until the day I attend to them again,’ declares the LORD. ‘Then I will bring them back and restore them to this place.’”","sources":{"KJV":{"text":"They shall be carried to Babylon, and there shall they be until the day that I visit them, saith the LORD; then will I bring them up, and restore them to this place."},"BSB":{"text":"‘They will be carried to Babylon and will remain there until the day I attend to them again,’ declares the LORD. ‘Then I will bring them back and restore them to this place.’”"},"TANAKH":{"text":"They shall be carried to Babylon, and there shall they be, until the day that I remember them, saith HaShem, and bring them up, and restore them to this place.'"},"HEBREW":{"text":"בָּבֶ֥לָה יוּבָ֖אוּ וְשָׁ֣מָּה יִֽהְי֑וּ עַ֠ד י֣וֹם פָּקְדִ֤י אֹתָם֙ נְאֻם־יְהוָ֔ה וְהַֽעֲלִיתִים֙ וַהֲשִׁ֣יבֹתִ֔ים אֶל־הַמָּק֖וֹם הַזֶּֽה׃"}},"definableWords":["Babylon","day","LORD"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["exile_return"]}}},"28":{"chapter":"28","title":"HANANIAH BREAKS THE YOKE","verses":{"1":{"text":"And it came to pass the same year, in the beginning of the reign of Zedekiah king of Judah, in the fourth year, and in the fifth month, that Hananiah the son of Azur the prophet, which was of Gibeon, spake unto me in the house of the LORD, in the presence of the priests and of all the people, saying,","ref":"Jeremiah 28:1","synthesized":"In the fifth month of that same year, the fourth year, near the beginning of the reign of King Zedekiah of Judah, the prophet Hananiah son of Azzur, who was from Gibeon, said to me in the house of the LORD in the presence of the priests and all the people:","sources":{"KJV":{"text":"And it came to pass the same year, in the beginning of the reign of Zedekiah king of Judah, in the fourth year, and in the fifth month, that Hananiah the son of Azur the prophet, which was of Gibeon, spake unto me in the house of the LORD, in the presence of the priests and of all the people, saying,"},"BSB":{"text":"In the fifth month of that same year, the fourth year, near the beginning of the reign of King Zedekiah of Judah, the prophet Hananiah son of Azzur, who was from Gibeon, said to me in the house of the LORD in the presence of the priests and all the people:"},"TANAKH":{"text":"And it came to pass the same year, in the beginning of the reign of Zedekiah king of Judah, in the fourth year, in the fifth month, that Hananiah the son of Azzur the prophet, who was of Gibeon, spoke unto me in the house of HaShem, in the presence of the priests and of all the people, saying:"},"HEBREW":{"text":"וַיְהִ֣י ׀ בַּשָּׁנָ֣ה הַהִ֗יא בְּרֵאשִׁית֙ מַמְלֶ֙כֶת֙ צִדְקִיָּ֣ה מֶֽלֶךְ־יְהוּדָ֔ה בשנת בַּשָּׁנָה֙ הָֽרְבִעִ֔ית בַּחֹ֖דֶשׁ הַחֲמִישִׁ֑י אָמַ֣ר אֵלַ֡י חֲנַנְיָה֩ בֶן־עַזּ֨וּר הַנָּבִ֜יא אֲשֶׁ֤ר מִגִּבְעוֹן֙ בְּבֵ֣ית יְהוָ֔ה לְעֵינֵ֧י הַכֹּהֲנִ֛ים וְכָל־הָעָ֖ם לֵאמֹֽר׃"}},"definableWords":["year","beginning","reign","King","Judah","prophet","son","house","LORD","people"],"peopleInVerse":[],"themesInVerse":["creation","kingdom_of_god","kingship"]},"2":{"text":"Thus speaketh the LORD of hosts, the God of Israel, saying, I have broken the yoke of the king of Babylon.","ref":"Jeremiah 28:2","synthesized":"“This is what the LORD of Hosts, the God of Israel, says: ‘I have broken the yoke of the king of Babylon.","sources":{"KJV":{"text":"Thus speaketh the LORD of hosts, the God of Israel, saying, I have broken the yoke of the king of Babylon."},"BSB":{"text":"“This is what the LORD of Hosts, the God of Israel, says: ‘I have broken the yoke of the king of Babylon."},"TANAKH":{"text":"'Thus speaketh HaShem of hosts, the G-d of Israel, saying: I have broken the yoke of the king of Babylon."},"HEBREW":{"text":"כֹּֽה־אָמַ֞ר יְהוָ֧ה צְבָא֛וֹת אֱלֹהֵ֥י יִשְׂרָאֵ֖ל לֵאמֹ֑ר שָׁבַ֞רְתִּי אֶת־עֹ֖ל מֶ֥לֶךְ בָּבֶֽל׃"}},"definableWords":["LORD","God","Israel","king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"3":{"text":"Within two full years will I bring again into this place all the vessels of the LORD’s house, that Nebuchadnezzar king of Babylon took away from this place, and carried them to Babylon:","ref":"Jeremiah 28:3","synthesized":"Within two years I will restore to this place all the articles of the house of the LORD that Nebuchadnezzar king of Babylon removed from here and carried to Babylon.","sources":{"KJV":{"text":"Within two full years will I bring again into this place all the vessels of the LORD’s house, that Nebuchadnezzar king of Babylon took away from this place, and carried them to Babylon:"},"BSB":{"text":"Within two years I will restore to this place all the articles of the house of the LORD that Nebuchadnezzar king of Babylon removed from here and carried to Babylon."},"TANAKH":{"text":"Within two full years will I bring back into this place all the vessels of HaShem'S house, that Nebuchadnezzar king of Babylon took away from this place, and carried them to Babylon;"},"HEBREW":{"text":"בְּע֣וֹד ׀ שְׁנָתַ֣יִם יָמִ֗ים אֲנִ֤י מֵשִׁיב֙ אֶל־הַמָּק֣וֹם הַזֶּ֔ה אֶֽת־כָּל־כְּלֵ֖י בֵּ֣ית יְהוָ֑ה אֲשֶׁ֨ר לָקַ֜ח נְבוּכַדנֶאצַּ֤ר מֶֽלֶךְ־בָּבֶל֙ מִן־הַמָּק֣וֹם הַזֶּ֔ה וַיְבִיאֵ֖ם בָּבֶֽל׃"}},"definableWords":["years","house","LORD","king","Babylon"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["exile_return","kingship"]},"4":{"text":"And I will bring again to this place Jeconiah the son of Jehoiakim king of Judah, with all the captives of Judah, that went into Babylon, saith the LORD: for I will break the yoke of the king of Babylon.","ref":"Jeremiah 28:4","synthesized":"And I will restore to this place Jeconiah son of Jehoiakim king of Judah, along with all the exiles from Judah who went to Babylon,’ declares the LORD, ‘for I will break the yoke of the king of Babylon.’”","sources":{"KJV":{"text":"And I will bring again to this place Jeconiah the son of Jehoiakim king of Judah, with all the captives of Judah, that went into Babylon, saith the LORD: for I will break the yoke of the king of Babylon."},"BSB":{"text":"And I will restore to this place Jeconiah son of Jehoiakim king of Judah, along with all the exiles from Judah who went to Babylon,’ declares the LORD, ‘for I will break the yoke of the king of Babylon.’”"},"TANAKH":{"text":"and I will bring back to this place Jeconiah the son of Jehoiakim, king of Judah, with all the captives of Judah, that went to Babylon, saith HaShem; for I will break the yoke of the king of Babylon.'"},"HEBREW":{"text":"וְאֶת־יְכָנְיָ֣ה בֶן־יְהוֹיָקִ֣ים מֶֽלֶךְ־יְ֠הוּדָה וְאֶת־כָּל־גָּל֨וּת יְהוּדָ֜ה הַבָּאִ֣ים בָּבֶ֗לָה אֲנִ֥י מֵשִׁ֛יב אֶל־הַמָּק֥וֹם הַזֶּ֖ה נְאֻם־יְהוָ֑ה כִּ֣י אֶשְׁבֹּ֔ר אֶת־עֹ֖ל מֶ֥לֶךְ בָּבֶֽל׃"}},"definableWords":["son","king","Judah","Babylon","LORD","King"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["exile_return","kingship"]},"5":{"text":"Then the prophet Jeremiah said unto the prophet Hananiah in the presence of the priests, and in the presence of all the people that stood in the house of the LORD,","ref":"Jeremiah 28:5","synthesized":"Then the prophet Jeremiah replied to the prophet Hananiah in the presence of the priests and all the people who were standing in the house of the LORD.","sources":{"KJV":{"text":"Then the prophet Jeremiah said unto the prophet Hananiah in the presence of the priests, and in the presence of all the people that stood in the house of the LORD,"},"BSB":{"text":"Then the prophet Jeremiah replied to the prophet Hananiah in the presence of the priests and all the people who were standing in the house of the LORD."},"TANAKH":{"text":"Then the prophet Jeremiah said unto the prophet Hananiah in the presence of the priests, and in the presence of all the people that stood in the house of HaShem,"},"HEBREW":{"text":"וַיֹּ֙אמֶר֙ יִרְמְיָ֣ה הַנָּבִ֔יא אֶל־חֲנַנְיָ֖ה הַנָּבִ֑יא לְעֵינֵ֤י הַכֹּֽהֲנִים֙ וּלְעֵינֵ֣י כָל־הָעָ֔ם הָעֹמְדִ֖ים בְּבֵ֥ית יְהוָֽה׃"}},"definableWords":["prophet","people","house","LORD"],"peopleInVerse":["Jeremiah"]},"6":{"text":"Even the prophet Jeremiah said, Amen: the LORD do so: the LORD perform thy words which thou hast prophesied, to bring again the vessels of the LORD’s house, and all that is carried away captive, from Babylon into this place.","ref":"Jeremiah 28:6","synthesized":"“Amen!” Jeremiah said. “May the LORD do so! May the LORD fulfill the words you have prophesied, and may He restore the articles of His house and all the exiles back to this place from Babylon.","sources":{"KJV":{"text":"Even the prophet Jeremiah said, Amen: the LORD do so: the LORD perform thy words which thou hast prophesied, to bring again the vessels of the LORD’s house, and all that is carried away captive, from Babylon into this place."},"BSB":{"text":"“Amen!” Jeremiah said. “May the LORD do so! May the LORD fulfill the words you have prophesied, and may He restore the articles of His house and all the exiles back to this place from Babylon."},"TANAKH":{"text":"even the prophet Jeremiah said: 'Amen! HaShem do so! HaShem perform thy words which thou hast prophesied, to bring back the vessels of HaShem'S house, and all them that are carried away captive, from Babylon unto this place!"},"HEBREW":{"text":"וַיֹּ֙אמֶר֙ יִרְמְיָ֣ה הַנָּבִ֔יא אָמֵ֕ן כֵּ֖ן יַעֲשֶׂ֣ה יְהוָ֑ה יָקֵ֤ם יְהוָה֙ אֶת־דְּבָרֶ֔יךָ אֲשֶׁ֣ר נִבֵּ֗אתָ לְהָשִׁ֞יב כְּלֵ֤י בֵית־יְהוָה֙ וְכָל־הַגּוֹלָ֔ה מִבָּבֶ֖ל אֶל־הַמָּק֥וֹם הַזֶּֽה׃"}},"definableWords":["LORD","Lord","house","Babylon"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Babylon"],"themesInVerse":["exile_return"]},"7":{"text":"Nevertheless hear thou now this word that I speak in thine ears, and in the ears of all the people;","ref":"Jeremiah 28:7","synthesized":"Nevertheless, listen now to this message I am speaking in your hearing and in the hearing of all the people.","sources":{"KJV":{"text":"Nevertheless hear thou now this word that I speak in thine ears, and in the ears of all the people;"},"BSB":{"text":"Nevertheless, listen now to this message I am speaking in your hearing and in the hearing of all the people."},"TANAKH":{"text":"Nevertheless hear thou now this word that I speak in thine ears, and in the ears of all the people:"},"HEBREW":{"text":"אַךְ־שְׁמַֽע־נָא֙ הַדָּבָ֣ר הַזֶּ֔ה אֲשֶׁ֥ר אָנֹכִ֖י דֹּבֵ֣ר בְּאָזְנֶ֑יךָ וּבְאָזְנֵ֖י כָּל־הָעָֽם׃"}},"definableWords":["people"],"peopleInVerse":[]},"8":{"text":"The prophets that have been before me and before thee of old prophesied both against many countries, and against great kingdoms, of war, and of evil, and of pestilence.","ref":"Jeremiah 28:8","synthesized":"The prophets of old who preceded you and me prophesied war, disaster, and plague against many lands and great kingdoms.","sources":{"KJV":{"text":"The prophets that have been before me and before thee of old prophesied both against many countries, and against great kingdoms, of war, and of evil, and of pestilence."},"BSB":{"text":"The prophets of old who preceded you and me prophesied war, disaster, and plague against many lands and great kingdoms."},"TANAKH":{"text":"The prophets that have been before me and before thee of old prophesied against many countries, and against great kingdoms, of war, and of evil, and of pestilence."},"HEBREW":{"text":"הַנְּבִיאִ֗ים אֲשֶׁ֨ר הָי֧וּ לְפָנַ֛י וּלְפָנֶ֖יךָ מִן־הָֽעוֹלָ֑ם וַיִּנָּ֨בְא֜וּ אֶל־אֲרָצ֤וֹת רַבּוֹת֙ וְעַל־מַמְלָכ֣וֹת גְּדֹל֔וֹת לְמִלְחָמָ֖ה וּלְרָעָ֥ה וּלְדָֽבֶר׃"}},"definableWords":["great"],"peopleInVerse":[]},"9":{"text":"The prophet which prophesieth of peace, when the word of the prophet shall come to pass, then shall the prophet be known, that the LORD hath truly sent him.","ref":"Jeremiah 28:9","synthesized":"As for the prophet who prophesies peace, only if the word of the prophet comes true will the prophet be recognized as one the LORD has truly sent.”","sources":{"KJV":{"text":"The prophet which prophesieth of peace, when the word of the prophet shall come to pass, then shall the prophet be known, that the LORD hath truly sent him."},"BSB":{"text":"As for the prophet who prophesies peace, only if the word of the prophet comes true will the prophet be recognized as one the LORD has truly sent.”"},"TANAKH":{"text":"The prophet that prophesieth of peace, when the word of the prophet shall come to pass, then shall the prophet be known, that HaShem hath truly sent him.'"},"HEBREW":{"text":"הַנָּבִ֕יא אֲשֶׁ֥ר יִנָּבֵ֖א לְשָׁל֑וֹם בְּבֹא֙ דְּבַ֣ר הַנָּבִ֗יא יִוָּדַע֙ הַנָּבִ֔יא אֲשֶׁר־שְׁלָח֥וֹ יְהוָ֖ה בֶּאֱמֶֽת׃"}},"definableWords":["prophet","peace","word","one","LORD"],"peopleInVerse":[],"themesInVerse":["peace"]},"10":{"text":"Then Hananiah the prophet took the yoke from off the prophet Jeremiah’s neck, and brake it.","ref":"Jeremiah 28:10","synthesized":"Then the prophet Hananiah took the yoke off the neck of Jeremiah the prophet and broke it.","sources":{"KJV":{"text":"Then Hananiah the prophet took the yoke from off the prophet Jeremiah’s neck, and brake it."},"BSB":{"text":"Then the prophet Hananiah took the yoke off the neck of Jeremiah the prophet and broke it."},"TANAKH":{"text":"Then Hananiah the prophet took the bar from off the prophet Jeremiah's neck, and broke it."},"HEBREW":{"text":"וַיִּקַּ֞ח חֲנַנְיָ֤ה הַנָּבִיא֙ אֶת־הַמּוֹטָ֔ה מֵעַ֕ל צַוַּ֖אר יִרְמְיָ֣ה הַנָּבִ֑יא וַֽיִּשְׁבְּרֵֽהוּ׃"}},"definableWords":["prophet"],"peopleInVerse":["Jeremiah"]},"11":{"text":"And Hananiah spake in the presence of all the people, saying, Thus saith the LORD; Even so will I break the yoke of Nebuchadnezzar king of Babylon from the neck of all nations within the space of two full years. And the prophet Jeremiah went his way.","ref":"Jeremiah 28:11","synthesized":"And in the presence of all the people Hananiah proclaimed, “This is what the LORD says: ‘In this way, within two years I will break the yoke of Nebuchadnezzar king of Babylon off the neck of all the nations.’”  At this, Jeremiah the prophet went on his way.","sources":{"KJV":{"text":"And Hananiah spake in the presence of all the people, saying, Thus saith the LORD; Even so will I break the yoke of Nebuchadnezzar king of Babylon from the neck of all nations within the space of two full years. And the prophet Jeremiah went his way."},"BSB":{"text":"And in the presence of all the people Hananiah proclaimed, “This is what the LORD says: ‘In this way, within two years I will break the yoke of Nebuchadnezzar king of Babylon off the neck of all the nations.’”  At this, Jeremiah the prophet went on his way."},"TANAKH":{"text":"And Hananiah spoke in the presence of all the people, saying: 'Thus saith HaShem: Even so will I break the yoke of Nebuchadnezzar king of Babylon from off the neck of all the nations within two full years.' And the prophet Jeremiah went his way."},"HEBREW":{"text":"וַיֹּ֣אמֶר חֲנַנְיָה֩ לְעֵינֵ֨י כָל־הָעָ֜ם לֵאמֹ֗ר כֹּה֮ אָמַ֣ר יְהוָה֒ כָּ֣כָה אֶשְׁבֹּ֞ר אֶת־עֹ֣ל ׀ נְבֻֽכַדְנֶאצַּ֣ר מֶֽלֶךְ־בָּבֶ֗ל בְּעוֹד֙ שְׁנָתַ֣יִם יָמִ֔ים מֵעַ֕ל צַוַּ֖אר כָּל־הַגּוֹיִ֑ם וַיֵּ֛לֶךְ יִרְמְיָ֥ה הַנָּבִ֖יא לְדַרְכּֽוֹ׃"}},"definableWords":["people","LORD","way","years","king","Babylon","nations","prophet"],"peopleInVerse":["Nebuchadnezzar","Jeremiah"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"12":{"text":"Then the word of the LORD came unto Jeremiah the prophet, after that Hananiah the prophet had broken the yoke from off the neck of the prophet Jeremiah, saying,","ref":"Jeremiah 28:12","synthesized":"But shortly after Hananiah the prophet had broken the yoke off his neck, the word of the LORD came to Jeremiah:","sources":{"KJV":{"text":"Then the word of the LORD came unto Jeremiah the prophet, after that Hananiah the prophet had broken the yoke from off the neck of the prophet Jeremiah, saying,"},"BSB":{"text":"But shortly after Hananiah the prophet had broken the yoke off his neck, the word of the LORD came to Jeremiah:"},"TANAKH":{"text":"Then the word of HaShem came unto Jeremiah, after that Hananiah the prophet had broken the bar from off the neck of the prophet Jeremiah, saying:"},"HEBREW":{"text":"וַיְהִ֥י דְבַר־יְהוָ֖ה אֶֽל־יִרְמְיָ֑ה אַ֠חֲרֵי שְׁב֞וֹר חֲנַנְיָ֤ה הַנָּבִיא֙ אֶת־הַמּוֹטָ֔ה מֵעַ֗ל צַוַּ֛אר יִרְמְיָ֥ה הַנָּבִ֖יא לֵאמֹֽר׃"}},"definableWords":["prophet","word","LORD"],"peopleInVerse":["Jeremiah"]},"13":{"text":"Go and tell Hananiah, saying, Thus saith the LORD; Thou hast broken the yokes of wood; but thou shalt make for them yokes of iron.","ref":"Jeremiah 28:13","synthesized":"“Go and tell Hananiah that this is what the LORD says: ‘You have broken a yoke of wood, but in its place you have fashioned a yoke of iron.’","sources":{"KJV":{"text":"Go and tell Hananiah, saying, Thus saith the LORD; Thou hast broken the yokes of wood; but thou shalt make for them yokes of iron."},"BSB":{"text":"“Go and tell Hananiah that this is what the LORD says: ‘You have broken a yoke of wood, but in its place you have fashioned a yoke of iron.’"},"TANAKH":{"text":"'Go, and tell Hananiah, saying: Thus saith HaShem: Thou hast broken the bars of wood; but thou shalt make in their stead bars of iron."},"HEBREW":{"text":"הָלוֹךְ֩ וְאָמַרְתָּ֨ אֶל־חֲנַנְיָ֜ה לֵאמֹ֗ר כֹּ֚ה אָמַ֣ר יְהוָ֔ה מוֹטֹ֥ת עֵ֖ץ שָׁבָ֑רְתָּ וְעָשִׂ֥יתָ תַחְתֵּיהֶ֖ן מֹט֥וֹת בַּרְזֶֽל׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"14":{"text":"For thus saith the LORD of hosts, the God of Israel; I have put a yoke of iron upon the neck of all these nations, that they may serve Nebuchadnezzar king of Babylon; and they shall serve him: and I have given him the beasts of the field also.","ref":"Jeremiah 28:14","synthesized":"For this is what the LORD of Hosts, the God of Israel, says: ‘I have put a yoke of iron on the neck of all these nations to make them serve Nebuchadnezzar king of Babylon, and they will serve him. I have even given him control of the beasts of the field.’”","sources":{"KJV":{"text":"For thus saith the LORD of hosts, the God of Israel; I have put a yoke of iron upon the neck of all these nations, that they may serve Nebuchadnezzar king of Babylon; and they shall serve him: and I have given him the beasts of the field also."},"BSB":{"text":"For this is what the LORD of Hosts, the God of Israel, says: ‘I have put a yoke of iron on the neck of all these nations to make them serve Nebuchadnezzar king of Babylon, and they will serve him. I have even given him control of the beasts of the field.’”"},"TANAKH":{"text":"For thus saith HaShem of hosts, the G-d of Israel: I have put a yoke of iron upon the neck of all these nations, that they may serve Nebuchadnezzar king of Babylon; and they shall serve him; and I have given him the beasts of the field also.'"},"HEBREW":{"text":"כִּ֣י כֹֽה־אָמַר֩ יְהוָ֨ה צְבָא֜וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֗ל עֹ֣ל בַּרְזֶ֡ל נָתַ֜תִּי עַל־צַוַּ֣אר ׀ כָּל־הַגּוֹיִ֣ם הָאֵ֗לֶּה לַעֲבֹ֛ד אֶת־נְבֻכַדְנֶאצַּ֥ר מֶֽלֶךְ־בָּבֶ֖ל וַעֲבָדֻ֑הוּ וְגַ֛ם אֶת־חַיַּ֥ת הַשָּׂדֶ֖ה נָתַ֥תִּי לֽוֹ׃"}},"definableWords":["LORD","God","Israel","nations","make","king","Babylon","field"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"15":{"text":"Then said the prophet Jeremiah unto Hananiah the prophet, Hear now, Hananiah; The LORD hath not sent thee; but thou makest this people to trust in a lie.","ref":"Jeremiah 28:15","synthesized":"Then the prophet Jeremiah said to the prophet Hananiah, “Listen, Hananiah! The LORD did not send you, but you have persuaded this people to trust in a lie.","sources":{"KJV":{"text":"Then said the prophet Jeremiah unto Hananiah the prophet, Hear now, Hananiah; The LORD hath not sent thee; but thou makest this people to trust in a lie."},"BSB":{"text":"Then the prophet Jeremiah said to the prophet Hananiah, “Listen, Hananiah! The LORD did not send you, but you have persuaded this people to trust in a lie."},"TANAKH":{"text":"Then said the prophet Jeremiah unto Hananiah the prophet: 'Hear now, Hananiah; HaShem hath not sent thee; but thou makest this people to trust in a lie."},"HEBREW":{"text":"וַיֹּ֨אמֶר יִרְמְיָ֧ה הַנָּבִ֛יא אֶל־חֲנַנְיָ֥ה הַנָּבִ֖יא שְׁמַֽע־נָ֣א חֲנַנְיָ֑ה לֹֽא־שְׁלָחֲךָ֣ יְהוָ֔ה וְאַתָּ֗ה הִבְטַ֛חְתָּ אֶת־הָעָ֥ם הַזֶּ֖ה עַל־שָֽׁקֶר׃"}},"definableWords":["prophet","LORD","people","trust"],"peopleInVerse":["Jeremiah"],"themesInVerse":["faith"]},"16":{"text":"Therefore thus saith the LORD; Behold, I will cast thee from off the face of the earth: this year thou shalt die, because thou hast taught rebellion against the LORD.","ref":"Jeremiah 28:16","synthesized":"Therefore this is what the LORD says: ‘I am about to remove you from the face of the earth. You will die this year because you have preached rebellion against the LORD.’”","sources":{"KJV":{"text":"Therefore thus saith the LORD; Behold, I will cast thee from off the face of the earth: this year thou shalt die, because thou hast taught rebellion against the LORD."},"BSB":{"text":"Therefore this is what the LORD says: ‘I am about to remove you from the face of the earth. You will die this year because you have preached rebellion against the LORD.’”"},"TANAKH":{"text":"'Therefore thus saith HaShem: Behold, I will send thee away from off the face of the earth; this year thou shalt die, because thou hast spoken perversion against HaShem.'"},"HEBREW":{"text":"לָכֵ֗ן כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִנְנִי֙ מְשַֽׁלֵּֽחֲךָ֔ מֵעַ֖ל פְּנֵ֣י הָאֲדָמָ֑ה הַשָּׁנָה֙ אַתָּ֣ה מֵ֔ת כִּֽי־סָרָ֥ה דִבַּ֖רְתָּ אֶל־יְהוָֽה׃"}},"definableWords":["LORD","earth","die","year","Lord"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"17":{"text":"So Hananiah the prophet died the same year in the seventh month.","ref":"Jeremiah 28:17","synthesized":"And in the seventh month of that very year, the prophet Hananiah died.","sources":{"KJV":{"text":"So Hananiah the prophet died the same year in the seventh month."},"BSB":{"text":"And in the seventh month of that very year, the prophet Hananiah died."},"TANAKH":{"text":"So Hananiah the prophet died the same year in the seventh month."},"HEBREW":{"text":"וַיָּ֛מָת חֲנַנְיָ֥ה הַנָּבִ֖יא בַּשָּׁנָ֣ה הַהִ֑יא בַּחֹ֖דֶשׁ הַשְּׁבִיעִֽי׃"}},"definableWords":["year","prophet"],"peopleInVerse":[]}}},"29":{"chapter":"29","title":"PLANS TO PROSPER YOU","verses":{"1":{"text":"Now these are the words of the letter that Jeremiah the prophet sent from Jerusalem unto the residue of the elders which were carried away captives, and to the priests, and to the prophets, and to all the people whom Nebuchadnezzar had carried away captive from Jerusalem to Babylon;","ref":"Jeremiah 29:1","synthesized":"This is the text of the letter that Jeremiah the prophet sent from Jerusalem to the surviving elders among the exiles and to the priests, the prophets, and all the others Nebuchadnezzar had carried into exile from Jerusalem to Babylon.","sources":{"KJV":{"text":"Now these are the words of the letter that Jeremiah the prophet sent from Jerusalem unto the residue of the elders which were carried away captives, and to the priests, and to the prophets, and to all the people whom Nebuchadnezzar had carried away captive from Jerusalem to Babylon;"},"BSB":{"text":"This is the text of the letter that Jeremiah the prophet sent from Jerusalem to the surviving elders among the exiles and to the priests, the prophets, and all the others Nebuchadnezzar had carried into exile from Jerusalem to Babylon."},"TANAKH":{"text":"Now these are the words of the letter that Jeremiah the prophet sent from Jerusalem unto the residue of the elders of the captivity, and to the priests, and to the prophets, and to all the people, whom Nebuchadnezzar had carried away captive from Jerusalem to Babylon,"},"HEBREW":{"text":"וְאֵ֙לֶּה֙ דִּבְרֵ֣י הַסֵּ֔פֶר אֲשֶׁ֥ר שָׁלַ֛ח יִרְמְיָ֥ה הַנָּבִ֖יא מִירוּשָׁלָ֑͏ִם אֶל־יֶ֜תֶר זִקְנֵ֣י הַגּוֹלָ֗ה וְאֶל־הַכֹּהֲנִ֤ים וְאֶל־הַנְּבִיאִים֙ וְאֶל־כָּל־הָעָ֔ם אֲשֶׁ֨ר הֶגְלָ֧ה נְבֽוּכַדְנֶאצַּ֛ר מִירוּשָׁלַ֖͏ִם בָּבֶֽלָה׃"}},"definableWords":["prophet","Jerusalem","Babylon"],"peopleInVerse":["Jeremiah","Nebuchadnezzar"],"placesInVerse":["Jerusalem","Babylon"],"themesInVerse":["exile_return"]},"2":{"text":"(After that Jeconiah the king, and the queen, and the eunuchs, the princes of Judah and Jerusalem, and the carpenters, and the smiths, were departed from Jerusalem;)","ref":"Jeremiah 29:2","synthesized":"(This was after King Jeconiah, the queen mother, the court officials, the officials of Judah and Jerusalem, the craftsmen, and the metalsmiths had been exiled from Jerusalem.)","sources":{"KJV":{"text":"(After that Jeconiah the king, and the queen, and the eunuchs, the princes of Judah and Jerusalem, and the carpenters, and the smiths, were departed from Jerusalem;)"},"BSB":{"text":"(This was after King Jeconiah, the queen mother, the court officials, the officials of Judah and Jerusalem, the craftsmen, and the metalsmiths had been exiled from Jerusalem.)"},"TANAKH":{"text":"after that Jeconiah the king, and the queen-mother, and the officers, and the princes of Judah and Jerusalem, and the craftsmen, and the smiths, were departed from Jerusalem;"},"HEBREW":{"text":"אַחֲרֵ֣י צֵ֣את יְכָנְיָֽה־הַ֠מֶּלֶךְ וְהַגְּבִירָ֨ה וְהַסָּרִיסִ֜ים שָׂרֵ֨י יְהוּדָ֧ה וִירוּשָׁלַ֛͏ִם וְהֶחָרָ֥שׁ וְהַמַּסְגֵּ֖ר מִירוּשָׁלָֽ͏ִם׃"}},"definableWords":["King","mother","Judah","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["kingship"]},"3":{"text":"By the hand of Elasah the son of Shaphan, and Gemariah the son of Hilkiah, (whom Zedekiah king of Judah sent unto Babylon to Nebuchadnezzar king of Babylon) saying,","ref":"Jeremiah 29:3","synthesized":"The letter was entrusted to Elasah son of Shaphan and Gemariah son of Hilkiah, whom Zedekiah king of Judah sent to King Nebuchadnezzar in Babylon. It stated:","sources":{"KJV":{"text":"By the hand of Elasah the son of Shaphan, and Gemariah the son of Hilkiah, (whom Zedekiah king of Judah sent unto Babylon to Nebuchadnezzar king of Babylon) saying,"},"BSB":{"text":"The letter was entrusted to Elasah son of Shaphan and Gemariah son of Hilkiah, whom Zedekiah king of Judah sent to King Nebuchadnezzar in Babylon. It stated:"},"TANAKH":{"text":"by the hand of Elasah the son of Shaphan, and Gemariah the son of Hilkiah, whom Zedekiah king of Judah sent unto Babylon to Nebuchadnezzar king of Babylon, saying:"},"HEBREW":{"text":"בְּיַד֙ אֶלְעָשָׂ֣ה בֶן־שָׁפָ֔ן וּגְמַרְיָ֖ה בֶּן־חִלְקִיָּ֑ה אֲשֶׁ֨ר שָׁלַ֜ח צִדְקִיָּ֣ה מֶֽלֶךְ־יְהוּדָ֗ה אֶל־נְבוּכַדְנֶאצַּ֛ר מֶ֥לֶךְ בָּבֶ֖ל בָּבֶ֥לָה לֵאמֹֽר׃"}},"definableWords":["son","Son","king","Judah","King","Babylon"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"4":{"text":"Thus saith the LORD of hosts, the God of Israel, unto all that are carried away captives, whom I have caused to be carried away from Jerusalem unto Babylon;","ref":"Jeremiah 29:4","synthesized":"This is what the LORD of Hosts, the God of Israel, says to all the exiles who were carried away from Jerusalem to Babylon:","sources":{"KJV":{"text":"Thus saith the LORD of hosts, the God of Israel, unto all that are carried away captives, whom I have caused to be carried away from Jerusalem unto Babylon;"},"BSB":{"text":"This is what the LORD of Hosts, the God of Israel, says to all the exiles who were carried away from Jerusalem to Babylon:"},"TANAKH":{"text":"Thus saith HaShem of hosts, the G-d of Israel, unto all the captivity, whom I have caused to be carried away captive from Jerusalem unto Babylon:"},"HEBREW":{"text":"כֹּ֥ה אָמַ֛ר יְהוָ֥ה צְבָא֖וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֑ל לְכָל־הַ֨גּוֹלָ֔ה אֲשֶׁר־הִגְלֵ֥יתִי מִירוּשָׁלַ֖͏ִם בָּבֶֽלָה׃"}},"definableWords":["LORD","God","Israel","Jerusalem","Babylon"],"peopleInVerse":[],"placesInVerse":["Jerusalem","Babylon"]},"5":{"text":"Build ye houses, and dwell in them; and plant gardens, and eat the fruit of them;","ref":"Jeremiah 29:5","synthesized":"“Build houses and settle down. Plant gardens and eat their produce.","sources":{"KJV":{"text":"Build ye houses, and dwell in them; and plant gardens, and eat the fruit of them;"},"BSB":{"text":"“Build houses and settle down. Plant gardens and eat their produce."},"TANAKH":{"text":"Build ye houses, and dwell in them, and plant gardens, and eat the fruit of them;"},"HEBREW":{"text":"בְּנ֥וּ בָתִּ֖ים וְשֵׁ֑בוּ וְנִטְע֣וּ גַנּ֔וֹת וְאִכְל֖וּ אֶת־פִּרְיָֽן׃"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Take ye wives, and beget sons and daughters; and take wives for your sons, and give your daughters to husbands, that they may bear sons and daughters; that ye may be increased there, and not diminished.","ref":"Jeremiah 29:6","synthesized":"Take wives and have sons and daughters. Take wives for your sons and give your daughters in marriage, so that they too may have sons and daughters. Multiply there; do not decrease.","sources":{"KJV":{"text":"Take ye wives, and beget sons and daughters; and take wives for your sons, and give your daughters to husbands, that they may bear sons and daughters; that ye may be increased there, and not diminished."},"BSB":{"text":"Take wives and have sons and daughters. Take wives for your sons and give your daughters in marriage, so that they too may have sons and daughters. Multiply there; do not decrease."},"TANAKH":{"text":"take ye wives, and beget sons and daughters; and take wives for your sons, and give your daughters to husbands, that they may bear sons and daughters; and multiply ye there, and be not diminished."},"HEBREW":{"text":"קְח֣וּ נָשִׁ֗ים וְהוֹלִידוּ֮ בָּנִ֣ים וּבָנוֹת֒ וּקְח֨וּ לִבְנֵיכֶ֜ם נָשִׁ֗ים וְאֶת־בְּנֽוֹתֵיכֶם֙ תְּנ֣וּ לַֽאֲנָשִׁ֔ים וְתֵלַ֖דְנָה בָּנִ֣ים וּבָנ֑וֹת וּרְבוּ־שָׁ֖ם וְאַל־תִּמְעָֽטוּ׃"}},"definableWords":["sons","daughters","multiply"],"peopleInVerse":[],"themesInVerse":["marriage_bride"]},"7":{"text":"And seek the peace of the city whither I have caused you to be carried away captives, and pray unto the LORD for it: for in the peace thereof shall ye have peace.","ref":"Jeremiah 29:7","synthesized":"Seek the prosperity of the city to which I have sent you as exiles. Pray to the LORD on its behalf, for if it prospers, you too will prosper.”","sources":{"KJV":{"text":"And seek the peace of the city whither I have caused you to be carried away captives, and pray unto the LORD for it: for in the peace thereof shall ye have peace."},"BSB":{"text":"Seek the prosperity of the city to which I have sent you as exiles. Pray to the LORD on its behalf, for if it prospers, you too will prosper.”"},"TANAKH":{"text":"And seek the peace of the city whither I have caused you to be carried away captive, and pray unto HaShem for it; for in the peace thereof shall ye have peace."},"HEBREW":{"text":"וְדִרְשׁ֞וּ אֶת־שְׁל֣וֹם הָעִ֗יר אֲשֶׁ֨ר הִגְלֵ֤יתִי אֶתְכֶם֙ שָׁ֔מָּה וְהִתְפַּֽלְל֥וּ בַעֲדָ֖הּ אֶל־יְהוָ֑ה כִּ֣י בִשְׁלוֹמָ֔הּ יִהְיֶ֥ה לָכֶ֖ם שָׁלֽוֹם׃"}},"definableWords":["seek","LORD"],"peopleInVerse":[],"themesInVerse":["prayer"]},"8":{"text":"For thus saith the LORD of hosts, the God of Israel; Let not your prophets and your diviners, that be in the midst of you, deceive you, neither hearken to your dreams which ye cause to be dreamed.","ref":"Jeremiah 29:8","synthesized":"For this is what the LORD of Hosts, the God of Israel, says: “Do not be deceived by the prophets and diviners among you, and do not listen to the dreams you elicit from them.","sources":{"KJV":{"text":"For thus saith the LORD of hosts, the God of Israel; Let not your prophets and your diviners, that be in the midst of you, deceive you, neither hearken to your dreams which ye cause to be dreamed."},"BSB":{"text":"For this is what the LORD of Hosts, the God of Israel, says: “Do not be deceived by the prophets and diviners among you, and do not listen to the dreams you elicit from them."},"TANAKH":{"text":"For thus saith HaShem of hosts, the G-d of Israel: Let not your prophets that are in the midst of you, and your diviners, beguile you, neither hearken ye to your dreams which ye cause to be dreamed."},"HEBREW":{"text":"כִּי֩ כֹ֨ה אָמַ֜ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל אַל־יַשִּׁ֧יאוּ לָכֶ֛ם נְבִֽיאֵיכֶ֥ם אֲשֶׁר־בְּקִרְבְּכֶ֖ם וְקֹֽסְמֵיכֶ֑ם וְאַֽל־תִּשְׁמְעוּ֙ אֶל־חֲלֹמֹ֣תֵיכֶ֔ם אֲשֶׁ֥ר אַתֶּ֖ם מַחְלְמִֽים׃"}},"definableWords":["LORD","God","Israel"],"peopleInVerse":[]},"9":{"text":"For they prophesy falsely unto you in my name: I have not sent them, saith the LORD.","ref":"Jeremiah 29:9","synthesized":"For they are falsely prophesying to you in My name; I have not sent them, declares the LORD.”","sources":{"KJV":{"text":"For they prophesy falsely unto you in my name: I have not sent them, saith the LORD."},"BSB":{"text":"For they are falsely prophesying to you in My name; I have not sent them, declares the LORD.”"},"TANAKH":{"text":"For they prophesy falsely unto you in My name; I have not sent them, saith HaShem."},"HEBREW":{"text":"כִּ֣י בְשֶׁ֔קֶר הֵ֛ם נִבְּאִ֥ים לָכֶ֖ם בִּשְׁמִ֑י לֹ֥א שְׁלַחְתִּ֖ים נְאֻם־יְהוָֽה׃"}},"definableWords":["name","LORD"],"peopleInVerse":[]},"10":{"text":"For thus saith the LORD, That after seventy years be accomplished at Babylon I will visit you, and perform my good word toward you, in causing you to return to this place.","ref":"Jeremiah 29:10","synthesized":"For this is what the LORD says: “When Babylon’s seventy years are complete, I will attend to you and confirm My promise to restore you to this place.","sources":{"KJV":{"text":"For thus saith the LORD, That after seventy years be accomplished at Babylon I will visit you, and perform my good word toward you, in causing you to return to this place."},"BSB":{"text":"For this is what the LORD says: “When Babylon’s seventy years are complete, I will attend to you and confirm My promise to restore you to this place."},"TANAKH":{"text":"For thus saith HaShem: After seventy years are accomplished for Babylon, I will remember you, and perform My good word toward you, in causing you to return to this place."},"HEBREW":{"text":"כִּֽי־כֹה֙ אָמַ֣ר יְהוָ֔ה כִּ֠י לְפִ֞י מְלֹ֧את לְבָבֶ֛ל שִׁבְעִ֥ים שָׁנָ֖ה אֶפְקֹ֣ד אֶתְכֶ֑ם וַהֲקִמֹתִ֤י עֲלֵיכֶם֙ אֶת־דְּבָרִ֣י הַטּ֔וֹב לְהָשִׁ֣יב אֶתְכֶ֔ם אֶל־הַמָּק֖וֹם הַזֶּֽה׃"}},"definableWords":["LORD","Babylon","years","promise"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["covenant","exile_return"]},"11":{"text":"For I know the thoughts that I think toward you, saith the LORD, thoughts of peace, and not of evil, to give you an expected end.","ref":"Jeremiah 29:11","synthesized":"For I know the plans I have for you, declares the LORD, plans to prosper you and not to harm you, to give you a future and a hope.","sources":{"KJV":{"text":"For I know the thoughts that I think toward you, saith the LORD, thoughts of peace, and not of evil, to give you an expected end."},"BSB":{"text":"For I know the plans I have for you, declares the LORD, plans to prosper you and not to harm you, to give you a future and a hope."},"TANAKH":{"text":"For I know the thoughts that I think toward you, saith HaShem, thoughts of peace, and not of evil, to give you a future and a hope."},"HEBREW":{"text":"כִּי֩ אָנֹכִ֨י יָדַ֜עְתִּי אֶת־הַמַּחֲשָׁבֹ֗ת אֲשֶׁ֧ר אָנֹכִ֛י חֹשֵׁ֥ב עֲלֵיכֶ֖ם נְאֻם־יְהוָ֑ה מַחְשְׁב֤וֹת שָׁלוֹם֙ וְלֹ֣א לְרָעָ֔ה לָתֵ֥ת לָכֶ֖ם אַחֲרִ֥ית וְתִקְוָֽה׃"}},"definableWords":["LORD","hope"],"peopleInVerse":[],"themesInVerse":["hope"]},"12":{"text":"Then shall ye call upon me, and ye shall go and pray unto me, and I will hearken unto you.","ref":"Jeremiah 29:12","synthesized":"Then you will call upon Me and come and pray to Me, and I will listen to you.","sources":{"KJV":{"text":"Then shall ye call upon me, and ye shall go and pray unto me, and I will hearken unto you."},"BSB":{"text":"Then you will call upon Me and come and pray to Me, and I will listen to you."},"TANAKH":{"text":"And ye shall call upon Me, and go, and pray unto Me, and I will hearken unto you."},"HEBREW":{"text":"וּקְרָאתֶ֤ם אֹתִי֙ וַֽהֲלַכְתֶּ֔ם וְהִתְפַּלַּלְתֶּ֖ם אֵלָ֑י וְשָׁמַעְתִּ֖י אֲלֵיכֶֽם׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["prayer"]},"13":{"text":"And ye shall seek me, and find me, when ye shall search for me with all your heart.","ref":"Jeremiah 29:13","synthesized":"You will seek Me and find Me when you search for Me with all your heart.","sources":{"KJV":{"text":"And ye shall seek me, and find me, when ye shall search for me with all your heart."},"BSB":{"text":"You will seek Me and find Me when you search for Me with all your heart."},"TANAKH":{"text":"And ye shall seek Me, and find Me, when ye shall search for Me with all your heart."},"HEBREW":{"text":"וּבִקַּשְׁתֶּ֥ם אֹתִ֖י וּמְצָאתֶ֑ם כִּ֥י תִדְרְשֻׁ֖נִי בְּכָל־לְבַבְכֶֽם׃"}},"definableWords":["seek","heart"],"peopleInVerse":[]},"14":{"text":"And I will be found of you, saith the LORD: and I will turn away your captivity, and I will gather you from all the nations, and from all the places whither I have driven you, saith the LORD; and I will bring you again into the place whence I caused you to be carried away captive.","ref":"Jeremiah 29:14","synthesized":"I will be found by you, declares the LORD, and I will restore you from captivity and gather you from all the nations and places to which I have banished you, declares the LORD. I will restore you to the place from which I sent you into exile.”","sources":{"KJV":{"text":"And I will be found of you, saith the LORD: and I will turn away your captivity, and I will gather you from all the nations, and from all the places whither I have driven you, saith the LORD; and I will bring you again into the place whence I caused you to be carried away captive."},"BSB":{"text":"I will be found by you, declares the LORD, and I will restore you from captivity and gather you from all the nations and places to which I have banished you, declares the LORD. I will restore you to the place from which I sent you into exile.”"},"TANAKH":{"text":"And I will be found of you, saith HaShem, and I will turn your captivity, and gather you from all the nations, and from all the places whither I have driven you, saith HaShem; and I will bring you back unto the place whence I caused you to be carried away captive."},"HEBREW":{"text":"וְנִמְצֵ֣אתִי לָכֶם֮ נְאֻם־יְהוָה֒ וְשַׁבְתִּ֣י אֶת־שביתכם שְׁבוּתְכֶ֗ם וְקִבַּצְתִּ֣י אֶ֠תְכֶם מִֽכָּל־הַגּוֹיִ֞ם וּמִכָּל־הַמְּקוֹמ֗וֹת אֲשֶׁ֨ר הִדַּ֧חְתִּי אֶתְכֶ֛ם שָׁ֖ם נְאֻם־יְהוָ֑ה וַהֲשִׁבֹתִ֣י אֶתְכֶ֔ם אֶל־הַ֨מָּק֔וֹם אֲשֶׁר־הִגְלֵ֥יתִי אֶתְכֶ֖ם מִשָּֽׁם׃"}},"definableWords":["LORD","nations","Lord"],"peopleInVerse":[],"themesInVerse":["exile_return"]},"15":{"text":"Because ye have said, The LORD hath raised us up prophets in Babylon;","ref":"Jeremiah 29:15","synthesized":"Because you may say, “The LORD has raised up for us prophets in Babylon,”","sources":{"KJV":{"text":"Because ye have said, The LORD hath raised us up prophets in Babylon;"},"BSB":{"text":"Because you may say, “The LORD has raised up for us prophets in Babylon,”"},"TANAKH":{"text":"For ye have said: 'The HaShem hath raised us up prophets in Babylon.'"},"HEBREW":{"text":"כִּ֖י אֲמַרְתֶּ֑ם הֵקִ֨ים לָ֧נוּ יְהוָ֛ה נְבִאִ֖ים בָּבֶֽלָה׃"}},"definableWords":["LORD","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["resurrection"]},"16":{"text":"Know that thus saith the LORD of the king that sitteth upon the throne of David, and of all the people that dwelleth in this city, and of your brethren that are not gone forth with you into captivity;","ref":"Jeremiah 29:16","synthesized":"this is what the LORD says about the king who sits on David’s throne and all the people who remain in this city, your brothers who did not go with you into exile—","sources":{"KJV":{"text":"Know that thus saith the LORD of the king that sitteth upon the throne of David, and of all the people that dwelleth in this city, and of your brethren that are not gone forth with you into captivity;"},"BSB":{"text":"this is what the LORD says about the king who sits on David’s throne and all the people who remain in this city, your brothers who did not go with you into exile—"},"TANAKH":{"text":"For thus saith HaShem concerning the king that sitteth upon the throne of David, and concerning all the people that dwell in this city, your brethren that are not gone forth with you into captivity;"},"HEBREW":{"text":"כִּי־כֹ֣ה ׀ אָמַ֣ר יְהוָ֗ה אֶל־הַמֶּ֙לֶךְ֙ הַיּוֹשֵׁב֙ אֶל־כִּסֵּ֣א דָוִ֔ד וְאֶל־כָּל־הָעָ֔ם הַיּוֹשֵׁ֖ב בָּעִ֣יר הַזֹּ֑את אֲחֵיכֶ֕ם אֲשֶׁ֛ר לֹֽא־יָצְא֥וּ אִתְּכֶ֖ם בַּגּוֹלָֽה׃"}},"definableWords":["LORD","king","throne","people"],"peopleInVerse":["David"],"themesInVerse":["exile_return","kingdom_of_god","kingship"]},"17":{"text":"Thus saith the LORD of hosts; Behold, I will send upon them the sword, the famine, and the pestilence, and will make them like vile figs, that cannot be eaten, they are so evil.","ref":"Jeremiah 29:17","synthesized":"this is what the LORD of Hosts says:  “I will send against them sword and famine and plague, and I will make them like rotten figs, so bad they cannot be eaten.","sources":{"KJV":{"text":"Thus saith the LORD of hosts; Behold, I will send upon them the sword, the famine, and the pestilence, and will make them like vile figs, that cannot be eaten, they are so evil."},"BSB":{"text":"this is what the LORD of Hosts says:  “I will send against them sword and famine and plague, and I will make them like rotten figs, so bad they cannot be eaten."},"TANAKH":{"text":"thus saith HaShem of hosts: Behold, I will send upon them the sword, the famine, and the pestilence, and will make them like vile figs, that cannot be eaten, they are so bad."},"HEBREW":{"text":"כֹּ֤ה אָמַר֙ יְהוָ֣ה צְבָא֔וֹת הִנְנִי֙ מְשַׁלֵּ֣חַ בָּ֔ם אֶת־הַחֶ֖רֶב אֶת־הָרָעָ֣ב וְאֶת־הַדָּ֑בֶר וְנָתַתִּ֣י אוֹתָ֗ם כַּתְּאֵנִים֙ הַשֹּׁ֣עָרִ֔ים אֲשֶׁ֥ר לֹא־תֵאָכַ֖לְנָה מֵרֹֽעַ׃"}},"definableWords":["LORD","make"],"peopleInVerse":[]},"18":{"text":"And I will persecute them with the sword, with the famine, and with the pestilence, and will deliver them to be removed to all the kingdoms of the earth, to be a curse, and an astonishment, and an hissing, and a reproach, among all the nations whither I have driven them:","ref":"Jeremiah 29:18","synthesized":"I will pursue them with sword and famine and plague. I will make them a horror to all the kingdoms of the earth—a curse, a desolation, and an object of scorn and reproach among all the nations to which I banish them.","sources":{"KJV":{"text":"And I will persecute them with the sword, with the famine, and with the pestilence, and will deliver them to be removed to all the kingdoms of the earth, to be a curse, and an astonishment, and an hissing, and a reproach, among all the nations whither I have driven them:"},"BSB":{"text":"I will pursue them with sword and famine and plague. I will make them a horror to all the kingdoms of the earth—a curse, a desolation, and an object of scorn and reproach among all the nations to which I banish them."},"TANAKH":{"text":"And I will pursue after them with the sword, with the famine, and with the pestilence, and will make them a horror unto all the kingdoms of the earth, a curse, and an astonishment, and a hissing, and a reproach, among all the nations whither I have driven them;"},"HEBREW":{"text":"וְרָֽדַפְתִּי֙ אַֽחֲרֵיהֶ֔ם בַּחֶ֖רֶב בָּרָעָ֣ב וּבַדָּ֑בֶר וּנְתַתִּ֨ים לזועה לְזַעֲוָ֜ה לְכֹ֣ל ׀ מַמְלְכ֣וֹת הָאָ֗רֶץ לְאָלָ֤ה וּלְשַׁמָּה֙ וְלִשְׁרֵקָ֣ה וּלְחֶרְפָּ֔ה בְּכָל־הַגּוֹיִ֖ם אֲשֶׁר־הִדַּחְתִּ֥ים שָֽׁם׃"}},"definableWords":["make","earth","curse","nations"],"peopleInVerse":[]},"19":{"text":"Because they have not hearkened to my words, saith the LORD, which I sent unto them by my servants the prophets, rising up early and sending them; but ye would not hear, saith the LORD.","ref":"Jeremiah 29:19","synthesized":"I will do this because they have not listened to My words, declares the LORD, which I sent to them again and again through My servants the prophets. And neither have you exiles listened, declares the LORD.”","sources":{"KJV":{"text":"Because they have not hearkened to my words, saith the LORD, which I sent unto them by my servants the prophets, rising up early and sending them; but ye would not hear, saith the LORD."},"BSB":{"text":"I will do this because they have not listened to My words, declares the LORD, which I sent to them again and again through My servants the prophets. And neither have you exiles listened, declares the LORD.”"},"TANAKH":{"text":"because they have not hearkened to My words, saith HaShem, wherewith I sent unto them My servants the prophets, sending them betimes and often; but ye would not hear, saith HaShem."},"HEBREW":{"text":"תַּ֛חַת אֲשֶֽׁר־לֹא־שָׁמְע֥וּ אֶל־דְּבָרַ֖י נְאֻם־יְהוָ֑ה אֲשֶׁר֩ שָׁלַ֨חְתִּי אֲלֵיהֶ֜ם אֶת־עֲבָדַ֤י הַנְּבִאִים֙ הַשְׁכֵּ֣ם וְשָׁלֹ֔חַ וְלֹ֥א שְׁמַעְתֶּ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD","servants","Lord"],"peopleInVerse":[]},"20":{"text":"Hear ye therefore the word of the LORD, all ye of the captivity, whom I have sent from Jerusalem to Babylon:","ref":"Jeremiah 29:20","synthesized":"So hear the word of the LORD, all you exiles I have sent away from Jerusalem to Babylon.","sources":{"KJV":{"text":"Hear ye therefore the word of the LORD, all ye of the captivity, whom I have sent from Jerusalem to Babylon:"},"BSB":{"text":"So hear the word of the LORD, all you exiles I have sent away from Jerusalem to Babylon."},"TANAKH":{"text":"Hear ye therefore the word of HaShem, all ye of the captivity, whom I have sent away from Jerusalem to Babylon:"},"HEBREW":{"text":"וְאַתֶּ֖ם שִׁמְע֣וּ דְבַר־יְהוָ֑ה כָּל־הַ֨גּוֹלָ֔ה אֲשֶׁר־שִׁלַּ֥חְתִּי מִירוּשָׁלַ֖͏ִם בָּבֶֽלָה׃"}},"definableWords":["hear","word","LORD","Jerusalem","Babylon"],"peopleInVerse":[],"placesInVerse":["Jerusalem","Babylon"]},"21":{"text":"Thus saith the LORD of hosts, the God of Israel, of Ahab the son of Kolaiah, and of Zedekiah the son of Maaseiah, which prophesy a lie unto you in my name; Behold, I will deliver them into the hand of Nebuchadrezzar king of Babylon; and he shall slay them before your eyes;","ref":"Jeremiah 29:21","synthesized":"This is what the LORD of Hosts, the God of Israel, says about Ahab son of Kolaiah and Zedekiah son of Maaseiah, who are prophesying to you lies in My name: “I will deliver them to Nebuchadnezzar king of Babylon, and he will kill them before your very eyes.","sources":{"KJV":{"text":"Thus saith the LORD of hosts, the God of Israel, of Ahab the son of Kolaiah, and of Zedekiah the son of Maaseiah, which prophesy a lie unto you in my name; Behold, I will deliver them into the hand of Nebuchadrezzar king of Babylon; and he shall slay them before your eyes;"},"BSB":{"text":"This is what the LORD of Hosts, the God of Israel, says about Ahab son of Kolaiah and Zedekiah son of Maaseiah, who are prophesying to you lies in My name: “I will deliver them to Nebuchadnezzar king of Babylon, and he will kill them before your very eyes."},"TANAKH":{"text":"Thus saith HaShem of hosts, the G-d of Israel, concerning Ahab the son of Kolaiah, and concerning Zedekiah the son of Maaseiah, who prophesy a lie unto you in My name: Behold, I will deliver them into the hand of Nebuchadrezzar king of Babylon; and he shall slay them before your eyes;"},"HEBREW":{"text":"כֹּֽה־אָמַר֩ יְהוָ֨ה צְבָא֜וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֗ל אֶל־אַחְאָ֤ב בֶּן־קֽוֹלָיָה֙ וְאֶל־צִדְקִיָּ֣הוּ בֶן־מַֽעֲשֵׂיָ֔ה הַֽנִּבְּאִ֥ים לָכֶ֛ם בִּשְׁמִ֖י שָׁ֑קֶר הִנְנִ֣י ׀ נֹתֵ֣ן אֹתָ֗ם בְּיַד֙ נְבֽוּכַדְרֶאצַּ֣ר מֶֽלֶךְ־בָּבֶ֔ל וְהִכָּ֖ם לְעֵינֵיכֶֽם׃"}},"definableWords":["LORD","God","Israel","son","Son","name","deliver","king","Babylon"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship","redemption","salvation"]},"22":{"text":"And of them shall be taken up a curse by all the captivity of Judah which are in Babylon, saying, The LORD make thee like Zedekiah and like Ahab, whom the king of Babylon roasted in the fire;","ref":"Jeremiah 29:22","synthesized":"Because of them, all the exiles of Judah who are in Babylon will use this curse: ‘May the LORD make you like Zedekiah and Ahab, whom the king of Babylon roasted in the fire!’","sources":{"KJV":{"text":"And of them shall be taken up a curse by all the captivity of Judah which are in Babylon, saying, The LORD make thee like Zedekiah and like Ahab, whom the king of Babylon roasted in the fire;"},"BSB":{"text":"Because of them, all the exiles of Judah who are in Babylon will use this curse: ‘May the LORD make you like Zedekiah and Ahab, whom the king of Babylon roasted in the fire!’"},"TANAKH":{"text":"and of them shall be taken up a curse by all the captivity of Judah that are in Babylon, saying: 'The HaShem make thee like Zedekiah and like Ahab, whom the king of Babylon roasted in the fire';"},"HEBREW":{"text":"וְלֻקַּ֤ח מֵהֶם֙ קְלָלָ֔ה לְכֹל֙ גָּל֣וּת יְהוּדָ֔ה אֲשֶׁ֥ר בְּבָבֶ֖ל לֵאמֹ֑ר יְשִֽׂמְךָ֤ יְהוָה֙ כְּצִדְקִיָּ֣הוּ וּכְאֶחָ֔ב אֲשֶׁר־קָלָ֥ם מֶֽלֶךְ־בָּבֶ֖ל בָּאֵֽשׁ׃"}},"definableWords":["Judah","Babylon","curse","LORD","make","king"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"23":{"text":"Because they have committed villany in Israel, and have committed adultery with their neighbours’ wives, and have spoken lying words in my name, which I have not commanded them; even I know, and am a witness, saith the LORD.","ref":"Jeremiah 29:23","synthesized":"For they have committed an outrage in Israel by committing adultery with the wives of their neighbors and speaking lies in My name, which I did not command them to do. I am He who knows, and I am a witness, declares the LORD.”","sources":{"KJV":{"text":"Because they have committed villany in Israel, and have committed adultery with their neighbours’ wives, and have spoken lying words in my name, which I have not commanded them; even I know, and am a witness, saith the LORD."},"BSB":{"text":"For they have committed an outrage in Israel by committing adultery with the wives of their neighbors and speaking lies in My name, which I did not command them to do. I am He who knows, and I am a witness, declares the LORD.”"},"TANAKH":{"text":"because they have wrought vile deeds in Israel, and have committed adultery with their neighbours' wives, and have spoken words in My name falsely, which I commanded them not; but I am He that knoweth, and am witness, saith HaShem."},"HEBREW":{"text":"יַ֡עַן אֲשֶׁר֩ עָשׂ֨וּ נְבָלָ֜ה בְּיִשְׂרָאֵ֗ל וַיְנַֽאֲפוּ֙ אֶת־נְשֵׁ֣י רֵֽעֵיהֶ֔ם וַיְדַבְּר֨וּ דָבָ֤ר בִּשְׁמִי֙ שֶׁ֔קֶר אֲשֶׁ֖ר ל֣וֹא צִוִּיתִ֑ם וְאָנֹכִ֛י הוידע הַיּוֹדֵ֥עַ וָעֵ֖ד נְאֻם־יְהוָֽה׃"}},"definableWords":["Israel","name","LORD"],"peopleInVerse":[]},"24":{"text":"Thus shalt thou also speak to Shemaiah the Nehelamite, saying,","ref":"Jeremiah 29:24","synthesized":"You are to tell Shemaiah the Nehelamite that","sources":{"KJV":{"text":"Thus shalt thou also speak to Shemaiah the Nehelamite, saying,"},"BSB":{"text":"You are to tell Shemaiah the Nehelamite that"},"TANAKH":{"text":"And concerning Shemaiah the Nehelamite thou shalt speak, saying:"},"HEBREW":{"text":"וְאֶל־שְׁמַעְיָ֥הוּ הַנֶּחֱלָמִ֖י תֹּאמַ֥ר לֵאמֹֽר׃"}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"Thus speaketh the LORD of hosts, the God of Israel, saying, Because thou hast sent letters in thy name unto all the people that are at Jerusalem, and to Zephaniah the son of Maaseiah the priest, and to all the priests, saying,","ref":"Jeremiah 29:25","synthesized":"this is what the LORD of Hosts, the God of Israel, says: “In your own name you have sent out letters to all the people of Jerusalem, to the priest Zephaniah son of Maaseiah, and to all the priests. You said to Zephaniah:","sources":{"KJV":{"text":"Thus speaketh the LORD of hosts, the God of Israel, saying, Because thou hast sent letters in thy name unto all the people that are at Jerusalem, and to Zephaniah the son of Maaseiah the priest, and to all the priests, saying,"},"BSB":{"text":"this is what the LORD of Hosts, the God of Israel, says: “In your own name you have sent out letters to all the people of Jerusalem, to the priest Zephaniah son of Maaseiah, and to all the priests. You said to Zephaniah:"},"TANAKH":{"text":"Thus speaketh HaShem of hosts, the G-d of Israel, saying: Because thou hast sent letters in thine own name unto all the people that are at Jerusalem, and to Zephaniah the son of Maaseiah the priest, and to all the priests, saying:"},"HEBREW":{"text":"כֹּֽה־אָמַ֞ר יְהוָ֧ה צְבָא֛וֹת אֱלֹהֵ֥י יִשְׂרָאֵ֖ל לֵאמֹ֑ר יַ֡עַן אֲשֶׁ֣ר אַתָּה֩ שָׁלַ֨חְתָּ בְשִׁמְכָ֜ה סְפָרִ֗ים אֶל־כָּל־הָעָם֙ אֲשֶׁ֣ר בִּירוּשָׁלִַ֔ם וְאֶל־צְפַנְיָ֤ה בֶן־מַֽעֲשֵׂיָה֙ הַכֹּהֵ֔ן וְאֶ֥ל כָּל־הַכֹּהֲנִ֖ים לֵאמֹֽר׃"}},"definableWords":["LORD","God","Israel","name","people","Jerusalem","priest","son"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["kingdom_priesthood"]},"26":{"text":"The LORD hath made thee priest in the stead of Jehoiada the priest, that ye should be officers in the house of the LORD, for every man that is mad, and maketh himself a prophet, that thou shouldest put him in prison, and in the stocks.","ref":"Jeremiah 29:26","synthesized":"‘The LORD has appointed you priest in place of Jehoiada, to be the chief officer in the house of the LORD, responsible for any madman who acts like a prophet—you must put him in stocks and neck irons.","sources":{"KJV":{"text":"The LORD hath made thee priest in the stead of Jehoiada the priest, that ye should be officers in the house of the LORD, for every man that is mad, and maketh himself a prophet, that thou shouldest put him in prison, and in the stocks."},"BSB":{"text":"‘The LORD has appointed you priest in place of Jehoiada, to be the chief officer in the house of the LORD, responsible for any madman who acts like a prophet—you must put him in stocks and neck irons."},"TANAKH":{"text":"'The HaShem hath made thee priest in the stead of Jehoiada the priest, that there should be officers in the house of HaShem for every man that is mad, and maketh himself a prophet, that thou shouldest put him in the stocks and in the collar."},"HEBREW":{"text":"יְהוָ֞ה נְתָנְךָ֣ כֹהֵ֗ן תַּ֚חַת יְהוֹיָדָ֣ע הַכֹּהֵ֔ן לִֽהְי֤וֹת פְּקִדִים֙ בֵּ֣ית יְהוָ֔ה לְכָל־אִ֥ישׁ מְשֻׁגָּ֖ע וּמִתְנַבֵּ֑א וְנָתַתָּ֥ה אֹת֛וֹ אֶל־הַמַּהְפֶּ֖כֶת וְאֶל־הַצִּינֹֽק׃"}},"definableWords":["LORD","priest","house","Lord","prophet"],"peopleInVerse":[],"themesInVerse":["kingdom_priesthood"]},"27":{"text":"Now therefore why hast thou not reproved Jeremiah of Anathoth, which maketh himself a prophet to you?","ref":"Jeremiah 29:27","synthesized":"So now, why have you not rebuked Jeremiah of Anathoth, who poses as a prophet among you?","sources":{"KJV":{"text":"Now therefore why hast thou not reproved Jeremiah of Anathoth, which maketh himself a prophet to you?"},"BSB":{"text":"So now, why have you not rebuked Jeremiah of Anathoth, who poses as a prophet among you?"},"TANAKH":{"text":"Now therefore, why hast thou not rebuked Jeremiah of Anathoth, who maketh himself a prophet to you,"},"HEBREW":{"text":"וְעַתָּ֗ה לָ֚מָּה לֹ֣א גָעַ֔רְתָּ בְּיִרְמְיָ֖הוּ הָֽעֲנְּתֹתִ֑י הַמִּתְנַבֵּ֖א לָכֶֽם׃"}},"definableWords":["prophet"],"peopleInVerse":["Jeremiah"]},"28":{"text":"For therefore he sent unto us in Babylon, saying, This captivity is long: build ye houses, and dwell in them; and plant gardens, and eat the fruit of them.","ref":"Jeremiah 29:28","synthesized":"For he has sent to us in Babylon, claiming: Since the exile will be lengthy, build houses and settle down; plant gardens and eat their produce.’”","sources":{"KJV":{"text":"For therefore he sent unto us in Babylon, saying, This captivity is long: build ye houses, and dwell in them; and plant gardens, and eat the fruit of them."},"BSB":{"text":"For he has sent to us in Babylon, claiming: Since the exile will be lengthy, build houses and settle down; plant gardens and eat their produce.’”"},"TANAKH":{"text":"forasmuch as he hath sent unto us in Babylon, saying: The captivity is long; build ye houses, and dwell in them; and plant gardens, and eat the fruit of them?'"},"HEBREW":{"text":"כִּ֣י עַל־כֵּ֞ן שָׁלַ֥ח אֵלֵ֛ינוּ בָּבֶ֥ל לֵאמֹ֖ר אֲרֻכָּ֣ה הִ֑יא בְּנ֤וּ בָתִּים֙ וְשֵׁ֔בוּ וְנִטְע֣וּ גַנּ֔וֹת וְאִכְל֖וּ אֶת־פְּרִיהֶֽן׃"}},"definableWords":["Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["exile_return"]},"29":{"text":"And Zephaniah the priest read this letter in the ears of Jeremiah the prophet.","ref":"Jeremiah 29:29","synthesized":"(Zephaniah the priest, however, had read this letter to Jeremiah the prophet.)","sources":{"KJV":{"text":"And Zephaniah the priest read this letter in the ears of Jeremiah the prophet."},"BSB":{"text":"(Zephaniah the priest, however, had read this letter to Jeremiah the prophet.)"},"TANAKH":{"text":"And Zephaniah the priest read this letter in the ears of Jeremiah the prophet."},"HEBREW":{"text":"וַיִּקְרָ֛א צְפַנְיָ֥ה הַכֹּהֵ֖ן אֶת־הַסֵּ֣פֶר הַזֶּ֑ה בְּאָזְנֵ֖י יִרְמְיָ֥הוּ הַנָּבִֽיא׃"}},"definableWords":["priest","prophet"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingdom_priesthood"]},"30":{"text":"Then came the word of the LORD unto Jeremiah, saying,","ref":"Jeremiah 29:30","synthesized":"Then the word of the LORD came to Jeremiah:","sources":{"KJV":{"text":"Then came the word of the LORD unto Jeremiah, saying,"},"BSB":{"text":"Then the word of the LORD came to Jeremiah:"},"TANAKH":{"text":"Then came the word of HaShem unto Jeremiah, saying:"},"HEBREW":{"text":"וַֽיְהִי֙ דְּבַר־יְהוָ֔ה אֶֽל־יִרְמְיָ֖הוּ לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"31":{"text":"Send to all them of the captivity, saying, Thus saith the LORD concerning Shemaiah the Nehelamite; Because that Shemaiah hath prophesied unto you, and I sent him not, and he caused you to trust in a lie:","ref":"Jeremiah 29:31","synthesized":"“Send a message telling all the exiles what the LORD says concerning Shemaiah the Nehelamite. Because Shemaiah has prophesied to you—though I did not send him—and has made you trust in a lie,","sources":{"KJV":{"text":"Send to all them of the captivity, saying, Thus saith the LORD concerning Shemaiah the Nehelamite; Because that Shemaiah hath prophesied unto you, and I sent him not, and he caused you to trust in a lie:"},"BSB":{"text":"“Send a message telling all the exiles what the LORD says concerning Shemaiah the Nehelamite. Because Shemaiah has prophesied to you—though I did not send him—and has made you trust in a lie,"},"TANAKH":{"text":"Send to all them of the captivity, saying: Thus saith HaShem concerning Shemaiah the Nehelamite: Because that Shemaiah hath prophesied unto you, and I sent him not, and he hath caused you to trust in a lie;"},"HEBREW":{"text":"שְׁלַ֤ח עַל־כָּל־הַגּוֹלָה֙ לֵאמֹ֔ר כֹּ֚ה אָמַ֣ר יְהוָ֔ה אֶל־שְׁמַעְיָ֖ה הַנֶּחֱלָמִ֑י יַ֡עַן אֲשֶׁר֩ נִבָּ֨א לָכֶ֜ם שְׁמַעְיָ֗ה וַֽאֲנִי֙ לֹ֣א שְׁלַחְתִּ֔יו וַיַּבְטַ֥ח אֶתְכֶ֖ם עַל־שָֽׁקֶר׃"}},"definableWords":["LORD","made","trust"],"peopleInVerse":[],"themesInVerse":["creation","faith"]},"32":{"text":"Therefore thus saith the LORD; Behold, I will punish Shemaiah the Nehelamite, and his seed: he shall not have a man to dwell among this people; neither shall he behold the good that I will do for my people, saith the LORD; because he hath taught rebellion against the LORD.","ref":"Jeremiah 29:32","synthesized":"this is what the LORD says: ‘I will surely punish Shemaiah the Nehelamite and his descendants. He will have no one left among this people, nor will he see the good that I will bring to My people, declares the LORD, for he has preached rebellion against the LORD.’”","sources":{"KJV":{"text":"Therefore thus saith the LORD; Behold, I will punish Shemaiah the Nehelamite, and his seed: he shall not have a man to dwell among this people; neither shall he behold the good that I will do for my people, saith the LORD; because he hath taught rebellion against the LORD."},"BSB":{"text":"this is what the LORD says: ‘I will surely punish Shemaiah the Nehelamite and his descendants. He will have no one left among this people, nor will he see the good that I will bring to My people, declares the LORD, for he has preached rebellion against the LORD.’”"},"TANAKH":{"text":"therefore thus saith HaShem: Behold, I will punish Shemaiah the Nehelamite, and his seed; he shall not have a man to dwell among this people, neither shall he behold the good that I will do unto My people, saith HaShem; because he hath spoken perversion against HaShem."},"HEBREW":{"text":"לָכֵ֞ן כֹּֽה־אָמַ֣ר יְהוָ֗ה הִנְנִ֨י פֹקֵ֜ד עַל־שְׁמַעְיָ֣ה הַנֶּחֱלָמִי֮ וְעַל־זַרְעוֹ֒ לֹא־יִהְיֶ֨ה ל֜וֹ אִ֣ישׁ ׀ יוֹשֵׁ֣ב ׀ בְּתוֹךְ־הָעָ֣ם הַזֶּ֗ה וְלֹֽא־יִרְאֶ֥ה בַטּ֛וֹב אֲשֶׁר־אֲנִ֥י עֹשֶֽׂה־לְעַמִּ֖י נְאֻם־יְהוָ֑ה כִּֽי־סָרָ֥ה דִבֶּ֖ר עַל־יְהוָֽה׃"}},"definableWords":["LORD","one","people","see","good","Lord"],"peopleInVerse":[],"themesInVerse":["fall_sin"]}}},"30":{"chapter":"30","title":"JACOB'S TROUBLE — BUT SAVED","verses":{"1":{"text":"The word that came to Jeremiah from the LORD, saying,","ref":"Jeremiah 30:1","synthesized":"This is the word that came to Jeremiah from the LORD:","sources":{"KJV":{"text":"The word that came to Jeremiah from the LORD, saying,"},"BSB":{"text":"This is the word that came to Jeremiah from the LORD:"},"TANAKH":{"text":"The word that came to Jeremiah from HaShem, saying:"},"HEBREW":{"text":"הַדָּבָר֙ אֲשֶׁ֣ר הָיָ֣ה אֶֽל־יִרְמְיָ֔הוּ מֵאֵ֥ת יְהוָ֖ה לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"2":{"text":"Thus speaketh the LORD God of Israel, saying, Write thee all the words that I have spoken unto thee in a book.","ref":"Jeremiah 30:2","synthesized":"“This is what the LORD, the God of Israel, says: ‘Write in a book all the words that I have spoken to you.","sources":{"KJV":{"text":"Thus speaketh the LORD God of Israel, saying, Write thee all the words that I have spoken unto thee in a book."},"BSB":{"text":"“This is what the LORD, the God of Israel, says: ‘Write in a book all the words that I have spoken to you."},"TANAKH":{"text":"'Thus speaketh HaShem, the G-d of Israel, saying: Write thee all the words that I have spoken unto thee in a book."},"HEBREW":{"text":"כֹּֽה־אָמַ֧ר יְהוָ֛ה אֱלֹהֵ֥י יִשְׂרָאֵ֖ל לֵאמֹ֑ר כְּתָב־לְךָ֗ אֵ֧ת כָּל־הַדְּבָרִ֛ים אֲשֶׁר־דִּבַּ֥רְתִּי אֵלֶ֖יךָ אֶל־סֵֽפֶר׃"}},"definableWords":["LORD","God","Israel"],"peopleInVerse":[]},"3":{"text":"For, lo, the days come, saith the LORD, that I will bring again the captivity of my people Israel and Judah, saith the LORD: and I will cause them to return to the land that I gave to their fathers, and they shall possess it.","ref":"Jeremiah 30:3","synthesized":"For behold, the days are coming, declares the LORD, when I will restore from captivity My people Israel and Judah, declares the LORD. I will restore them to the land that I gave to their fathers, and they will possess it.’”","sources":{"KJV":{"text":"For, lo, the days come, saith the LORD, that I will bring again the captivity of my people Israel and Judah, saith the LORD: and I will cause them to return to the land that I gave to their fathers, and they shall possess it."},"BSB":{"text":"For behold, the days are coming, declares the LORD, when I will restore from captivity My people Israel and Judah, declares the LORD. I will restore them to the land that I gave to their fathers, and they will possess it.’”"},"TANAKH":{"text":"For, lo, the days come, saith HaShem, that I will turn the captivity of My people Israel and Judah, saith HaShem; and I will cause them to return to the land that I gave to their fathers, and they shall possess it.'"},"HEBREW":{"text":"כִּ֠י הִנֵּ֨ה יָמִ֤ים בָּאִים֙ נְאֻם־יְהוָ֔ה וְ֠שַׁבְתִּי אֶת־שְׁב֨וּת עַמִּ֧י יִשְׂרָאֵ֛ל וִֽיהוּדָ֖ה אָמַ֣ר יְהוָ֑ה וַהֲשִׁבֹתִ֗ים אֶל־הָאָ֛רֶץ אֲשֶׁר־נָתַ֥תִּי לַאֲבוֹתָ֖ם וִֽירֵשֽׁוּהָ׃"}},"definableWords":["days","LORD","people","Israel","Judah","Lord","land","fathers"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise","second_coming"]},"4":{"text":"And these are the words that the LORD spake concerning Israel and concerning Judah.","ref":"Jeremiah 30:4","synthesized":"These are the words that the LORD spoke concerning Israel and Judah.","sources":{"KJV":{"text":"And these are the words that the LORD spake concerning Israel and concerning Judah."},"BSB":{"text":"These are the words that the LORD spoke concerning Israel and Judah."},"TANAKH":{"text":"And these are the words that HaShem spoke concerning Israel and concerning Judah."},"HEBREW":{"text":"וְאֵ֣לֶּה הַדְּבָרִ֗ים אֲשֶׁ֨ר דִּבֶּ֧ר יְהוָ֛ה אֶל־יִשְׂרָאֵ֖ל וְאֶל־יְהוּדָֽה׃"}},"definableWords":["LORD","Israel","Judah"],"peopleInVerse":[]},"5":{"text":"For thus saith the LORD; We have heard a voice of trembling, of fear, and not of peace.","ref":"Jeremiah 30:5","synthesized":"Yes, this is what the LORD says:  “A cry of panic is heard— a cry of terror, not of peace.","sources":{"KJV":{"text":"For thus saith the LORD; We have heard a voice of trembling, of fear, and not of peace."},"BSB":{"text":"Yes, this is what the LORD says:  “A cry of panic is heard— a cry of terror, not of peace."},"TANAKH":{"text":"For thus saith HaShem: We have heard a voice of trembling, of fear, and not of peace."},"HEBREW":{"text":"כִּי־כֹה֙ אָמַ֣ר יְהוָ֔ה ק֥וֹל חֲרָדָ֖ה שָׁמָ֑עְנוּ פַּ֖חַד וְאֵ֥ין שָׁלֽוֹם׃"}},"definableWords":["LORD","peace"],"peopleInVerse":[],"themesInVerse":["peace"]},"6":{"text":"Ask ye now, and see whether a man doth travail with child? wherefore do I see every man with his hands on his loins, as a woman in travail, and all faces are turned into paleness?","ref":"Jeremiah 30:6","synthesized":"Ask now, and see: Can a male give birth? Why then do I see every man with his hands on his stomach like a woman in labor and every face turned pale?","sources":{"KJV":{"text":"Ask ye now, and see whether a man doth travail with child? wherefore do I see every man with his hands on his loins, as a woman in travail, and all faces are turned into paleness?"},"BSB":{"text":"Ask now, and see: Can a male give birth? Why then do I see every man with his hands on his stomach like a woman in labor and every face turned pale?"},"TANAKH":{"text":"Ask ye now, and see whether a man doth travail with child; wherefore do I see every man with his hands on his loins, as a woman in travail, and all faces are turned into paleness?"},"HEBREW":{"text":"שַׁאֲלוּ־נָ֣א וּרְא֔וּ אִם־יֹלֵ֖ד זָכָ֑ר מַדּוּעַ֩ רָאִ֨יתִי כָל־גֶּ֜בֶר יָדָ֤יו עַל־חֲלָצָיו֙ כַּיּ֣וֹלֵדָ֔ה וְנֶהֶפְכ֥וּ כָל־פָּנִ֖ים לְיֵרָקֽוֹן׃"}},"definableWords":["see","male","man","woman"],"peopleInVerse":[]},"7":{"text":"Alas! for that day is great, so that none is like it: it is even the time of Jacob’s trouble, but he shall be saved out of it.","ref":"Jeremiah 30:7","synthesized":"How awful that day will be! None will be like it! It is the time of Jacob’s distress, but he will be saved out of it.","sources":{"KJV":{"text":"Alas! for that day is great, so that none is like it: it is even the time of Jacob’s trouble, but he shall be saved out of it."},"BSB":{"text":"How awful that day will be! None will be like it! It is the time of Jacob’s distress, but he will be saved out of it."},"TANAKH":{"text":"Alas! for that day is great, so that none is like it; and it is a time of trouble unto Jacob, but out of it shall he be saved."},"HEBREW":{"text":"ה֗וֹי כִּ֥י גָד֛וֹל הַיּ֥וֹם הַה֖וּא מֵאַ֣יִן כָּמֹ֑הוּ וְעֵֽת־צָרָ֥ה הִיא֙ לְיַֽעֲקֹ֔ב וּמִמֶּ֖נָּה יִוָּשֵֽׁעַ׃"}},"definableWords":["day","Jacob"],"peopleInVerse":["Jacob"]},"8":{"text":"For it shall come to pass in that day, saith the LORD of hosts, that I will break his yoke from off thy neck, and will burst thy bonds, and strangers shall no more serve themselves of him:","ref":"Jeremiah 30:8","synthesized":"On that day, declares the LORD of Hosts, I will break the yoke off their necks and tear off their bonds, and no longer will strangers enslave them.","sources":{"KJV":{"text":"For it shall come to pass in that day, saith the LORD of hosts, that I will break his yoke from off thy neck, and will burst thy bonds, and strangers shall no more serve themselves of him:"},"BSB":{"text":"On that day, declares the LORD of Hosts, I will break the yoke off their necks and tear off their bonds, and no longer will strangers enslave them."},"TANAKH":{"text":"And it shall come to pass in that day, saith HaShem of hosts, that I will break his yoke from off thy neck, and will burst thy bands; and strangers shall no more make him their bondman;"},"HEBREW":{"text":"וְהָיָה֩ בַיּ֨וֹם הַה֜וּא נְאֻ֣ם ׀ יְהוָ֣ה צְבָא֗וֹת אֶשְׁבֹּ֤ר עֻלּוֹ֙ מֵעַ֣ל צַוָּארֶ֔ךָ וּמוֹסְרוֹתֶ֖יךָ אֲנַתֵּ֑ק וְלֹא־יַעַבְדוּ־ב֥וֹ ע֖וֹד זָרִֽים׃"}},"definableWords":["day","LORD"],"peopleInVerse":[]},"9":{"text":"But they shall serve the LORD their God, and David their king, whom I will raise up unto them.","ref":"Jeremiah 30:9","synthesized":"Instead, they will serve the LORD their God and David their king, whom I will raise up for them.","sources":{"KJV":{"text":"But they shall serve the LORD their God, and David their king, whom I will raise up unto them."},"BSB":{"text":"Instead, they will serve the LORD their God and David their king, whom I will raise up for them."},"TANAKH":{"text":"But they shall serve HaShem their G-d, and David their king, whom I will raise up unto them."},"HEBREW":{"text":"וְעָ֣בְד֔וּ אֵ֖ת יְהוָ֣ה אֱלֹֽהֵיהֶ֑ם וְאֵת֙ דָּוִ֣ד מַלְכָּ֔ם אֲשֶׁ֥ר אָקִ֖ים לָהֶֽם׃"}},"definableWords":["LORD","God","king"],"peopleInVerse":["David"],"themesInVerse":["kingship"]},"10":{"text":"Therefore fear thou not, O my servant Jacob, saith the LORD; neither be dismayed, O Israel: for, lo, I will save thee from afar, and thy seed from the land of their captivity; and Jacob shall return, and shall be in rest, and be quiet, and none shall make him afraid.","ref":"Jeremiah 30:10","synthesized":"As for you, O Jacob My servant, do not be afraid, declares the LORD, and do not be dismayed, O Israel. For I will surely save you out of a distant place, your descendants from the land of their captivity! Jacob will return to quiet and ease, with no one to make him afraid.","sources":{"KJV":{"text":"Therefore fear thou not, O my servant Jacob, saith the LORD; neither be dismayed, O Israel: for, lo, I will save thee from afar, and thy seed from the land of their captivity; and Jacob shall return, and shall be in rest, and be quiet, and none shall make him afraid."},"BSB":{"text":"As for you, O Jacob My servant, do not be afraid, declares the LORD, and do not be dismayed, O Israel. For I will surely save you out of a distant place, your descendants from the land of their captivity! Jacob will return to quiet and ease, with no one to make him afraid."},"TANAKH":{"text":"Therefore fear thou not, O Jacob My servant, saith HaShem; neither be dismayed, O Israel; for, lo, I will save thee from afar, and thy seed from the land of their captivity; and Jacob shall again be quiet and at ease, and none shall make him afraid."},"HEBREW":{"text":"וְאַתָּ֡ה אַל־תִּירָא֩ עַבְדִּ֨י יַעֲקֹ֤ב נְאֻם־יְהֹוָה֙ וְאַל־תֵּחַ֣ת יִשְׂרָאֵ֔ל כִּ֠י הִנְנִ֤י מוֹשִֽׁיעֲךָ֙ מֵֽרָח֔וֹק וְאֶֽת־זַרְעֲךָ֖ מֵאֶ֣רֶץ שִׁבְיָ֑ם וְשָׁ֧ב יַעֲקֹ֛ב וְשָׁקַ֥ט וְשַׁאֲנַ֖ן וְאֵ֥ין מַחֲרִֽיד׃"}},"definableWords":["Jacob","servant","LORD","Israel","land","one","make"],"peopleInVerse":["Jacob"],"themesInVerse":["exile_return","land_promise","salvation","second_coming"]},"11":{"text":"For I am with thee, saith the LORD, to save thee: though I make a full end of all nations whither I have scattered thee, yet will I not make a full end of thee: but I will correct thee in measure, and will not leave thee altogether unpunished.","ref":"Jeremiah 30:11","synthesized":"For I am with you to save you, declares the LORD. Though I will completely destroy all the nations to which I have scattered you, I will not completely destroy you. Yet I will discipline you justly, and will by no means leave you unpunished.”","sources":{"KJV":{"text":"For I am with thee, saith the LORD, to save thee: though I make a full end of all nations whither I have scattered thee, yet will I not make a full end of thee: but I will correct thee in measure, and will not leave thee altogether unpunished."},"BSB":{"text":"For I am with you to save you, declares the LORD. Though I will completely destroy all the nations to which I have scattered you, I will not completely destroy you. Yet I will discipline you justly, and will by no means leave you unpunished.”"},"TANAKH":{"text":"For I am with thee, saith HaShem, to save thee; for I will make a full end of all the nations whither I have scattered thee, but I will not make a full end of thee; for I will correct thee in measure, and will not utterly destroy thee."},"HEBREW":{"text":"כִּֽי־אִתְּךָ֥ אֲנִ֛י נְאֻם־יְהוָ֖ה לְהֽוֹשִׁיעֶ֑ךָ כִּי֩ אֶעֱשֶׂ֨ה כָלָ֜ה בְּכָֽל־הַגּוֹיִ֣ם ׀ אֲשֶׁ֧ר הֲפִצוֹתִ֣יךָ שָּׁ֗ם אַ֤ךְ אֹֽתְךָ֙ לֹֽא־אֶעֱשֶׂ֣ה כָלָ֔ה וְיִסַּרְתִּ֙יךָ֙ לַמִּשְׁפָּ֔ט וְנַקֵּ֖ה לֹ֥א אֲנַקֶּֽךָּ׃"}},"definableWords":["LORD","nations"],"peopleInVerse":[],"themesInVerse":["salvation"]},"12":{"text":"For thus saith the LORD, Thy bruise is incurable, and thy wound is grievous.","ref":"Jeremiah 30:12","synthesized":"For this is what the LORD says:  “Your injury is incurable; your wound is grievous.","sources":{"KJV":{"text":"For thus saith the LORD, Thy bruise is incurable, and thy wound is grievous."},"BSB":{"text":"For this is what the LORD says:  “Your injury is incurable; your wound is grievous."},"TANAKH":{"text":"For thus saith HaShem: Thy hurt is incurable, and thy wound is grievous."},"HEBREW":{"text":"כִּ֣י כֹ֥ה אָמַ֛ר יְהוָ֖ה אָנ֣וּשׁ לְשִׁבְרֵ֑ךְ נַחְלָ֖ה מַכָּתֵֽךְ׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"13":{"text":"There is none to plead thy cause, that thou mayest be bound up: thou hast no healing medicines.","ref":"Jeremiah 30:13","synthesized":"There is no one to plead your cause, no remedy for your sores, no recovery for you.","sources":{"KJV":{"text":"There is none to plead thy cause, that thou mayest be bound up: thou hast no healing medicines."},"BSB":{"text":"There is no one to plead your cause, no remedy for your sores, no recovery for you."},"TANAKH":{"text":"None deemeth of thy wound that it may be bound up; thou hast no healing medicines."},"HEBREW":{"text":"אֵֽין־דָּ֥ן דִּינֵ֖ךְ לְמָז֑וֹר רְפֻא֥וֹת תְּעָלָ֖ה אֵ֥ין לָֽךְ׃"}},"definableWords":["one"],"peopleInVerse":[]},"14":{"text":"All thy lovers have forgotten thee; they seek thee not; for I have wounded thee with the wound of an enemy, with the chastisement of a cruel one, for the multitude of thine iniquity; because thy sins were increased.","ref":"Jeremiah 30:14","synthesized":"All your lovers have forgotten you; they no longer seek you, for I have struck you as an enemy would, with the discipline of someone cruel, because of your great iniquity and your numerous sins.","sources":{"KJV":{"text":"All thy lovers have forgotten thee; they seek thee not; for I have wounded thee with the wound of an enemy, with the chastisement of a cruel one, for the multitude of thine iniquity; because thy sins were increased."},"BSB":{"text":"All your lovers have forgotten you; they no longer seek you, for I have struck you as an enemy would, with the discipline of someone cruel, because of your great iniquity and your numerous sins."},"TANAKH":{"text":"All thy lovers have forgotten thee, they seek thee not; for I have wounded thee with the wound of an enemy, with the chastisement of a cruel one; for the greatness of thine iniquity, because thy sins were increased."},"HEBREW":{"text":"כָּל־מְאַהֲבַ֣יִךְ שְׁכֵח֔וּךְ אוֹתָ֖ךְ לֹ֣א יִדְרֹ֑שׁוּ כִּי֩ מַכַּ֨ת אוֹיֵ֤ב הִכִּיתִיךְ֙ מוּסַ֣ר אַכְזָרִ֔י עַ֚ל רֹ֣ב עֲוֺנֵ֔ךְ עָצְמ֖וּ חַטֹּאתָֽיִךְ׃"}},"definableWords":["seek","great","iniquity"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"15":{"text":"Why criest thou for thine affliction? thy sorrow is incurable for the multitude of thine iniquity: because thy sins were increased, I have done these things unto thee.","ref":"Jeremiah 30:15","synthesized":"Why do you cry out over your wound? Your pain has no cure! Because of your great iniquity and your numerous sins I have done these things to you.","sources":{"KJV":{"text":"Why criest thou for thine affliction? thy sorrow is incurable for the multitude of thine iniquity: because thy sins were increased, I have done these things unto thee."},"BSB":{"text":"Why do you cry out over your wound? Your pain has no cure! Because of your great iniquity and your numerous sins I have done these things to you."},"TANAKH":{"text":"Why criest thou for thy hurt, that thy pain is incurable? For the greatness of thine iniquity, because thy sins were increased, I have done these things unto thee."},"HEBREW":{"text":"מַה־תִּזְעַק֙ עַל־שִׁבְרֵ֔ךְ אָנ֖וּשׁ מַכְאֹבֵ֑ךְ עַ֣ל ׀ רֹ֣ב עֲוֺנֵ֗ךְ עָֽצְמוּ֙ חַטֹּאתַ֔יִךְ עָשִׂ֥יתִי אֵ֖לֶּה לָֽךְ׃"}},"definableWords":["great","iniquity"],"peopleInVerse":[],"themesInVerse":["fall_sin","suffering"]},"16":{"text":"Therefore all they that devour thee shall be devoured; and all thine adversaries, every one of them, shall go into captivity; and they that spoil thee shall be a spoil, and all that prey upon thee will I give for a prey.","ref":"Jeremiah 30:16","synthesized":"Nevertheless, all who devour you will be devoured, and all your adversaries—every one of them— will go off into exile. Those who plundered you will be plundered, and all who raided you will be raided.","sources":{"KJV":{"text":"Therefore all they that devour thee shall be devoured; and all thine adversaries, every one of them, shall go into captivity; and they that spoil thee shall be a spoil, and all that prey upon thee will I give for a prey."},"BSB":{"text":"Nevertheless, all who devour you will be devoured, and all your adversaries—every one of them— will go off into exile. Those who plundered you will be plundered, and all who raided you will be raided."},"TANAKH":{"text":"Therefore all they that devour thee shall be devoured, and all thine adversaries, every one of them, shall go into captivity; and they that spoil thee shall be a spoil, and all that prey upon thee will I give for a prey."},"HEBREW":{"text":"לָכֵ֞ן כָּל־אֹכְלַ֙יִךְ֙ יֵאָכֵ֔לוּ וְכָל־צָרַ֥יִךְ כֻּלָּ֖ם בַּשְּׁבִ֣י יֵלֵ֑כוּ וְהָי֤וּ שֹׁאסַ֙יִךְ֙ לִמְשִׁסָּ֔ה וְכָל־בֹּזְזַ֖יִךְ אֶתֵּ֥ן לָבַֽז׃"}},"definableWords":["one"],"peopleInVerse":[],"themesInVerse":["exile_return"]},"17":{"text":"For I will restore health unto thee, and I will heal thee of thy wounds, saith the LORD; because they called thee an Outcast, saying, This is Zion, whom no man seeketh after.","ref":"Jeremiah 30:17","synthesized":"But I will restore your health and heal your wounds, declares the LORD, because they call you an outcast, Zion, for whom no one cares.”","sources":{"KJV":{"text":"For I will restore health unto thee, and I will heal thee of thy wounds, saith the LORD; because they called thee an Outcast, saying, This is Zion, whom no man seeketh after."},"BSB":{"text":"But I will restore your health and heal your wounds, declares the LORD, because they call you an outcast, Zion, for whom no one cares.”"},"TANAKH":{"text":"For I will restore health unto thee, and I will heal thee of thy wounds, saith HaShem; because they have called thee an outcast: 'She is Zion, there is none that careth for her.'"},"HEBREW":{"text":"כִּי֩ אַעֲלֶ֨ה אֲרֻכָ֥ה לָ֛ךְ וּמִמַּכּוֹתַ֥יִךְ אֶרְפָּאֵ֖ךְ נְאֻם־יְהוָ֑ה כִּ֤י נִדָּחָה֙ קָ֣רְאוּ לָ֔ךְ צִיּ֣וֹן הִ֔יא דֹּרֵ֖שׁ אֵ֥ין לָֽהּ׃"}},"definableWords":["heal","LORD","Zion","one"],"peopleInVerse":[],"placesInVerse":["Mount Zion"],"themesInVerse":["exile_return"]},"18":{"text":"Thus saith the LORD; Behold, I will bring again the captivity of Jacob’s tents, and have mercy on his dwellingplaces; and the city shall be builded upon her own heap, and the palace shall remain after the manner thereof.","ref":"Jeremiah 30:18","synthesized":"This is what the LORD says:  “I will restore the fortunes of Jacob’s tents and have compassion on his dwellings. And the city will be rebuilt on her own ruins, and the palace will stand in its rightful place.","sources":{"KJV":{"text":"Thus saith the LORD; Behold, I will bring again the captivity of Jacob’s tents, and have mercy on his dwellingplaces; and the city shall be builded upon her own heap, and the palace shall remain after the manner thereof."},"BSB":{"text":"This is what the LORD says:  “I will restore the fortunes of Jacob’s tents and have compassion on his dwellings. And the city will be rebuilt on her own ruins, and the palace will stand in its rightful place."},"TANAKH":{"text":"Thus saith HaShem: Behold, I will turn the captivity of Jacob's tents, and have compassion on his dwelling-places; and the city shall be builded upon her own mound, and the palace shall be inhabited upon its wonted place."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה הִנְנִי־שָׁב֙ שְׁבוּת֙ אָהֳלֵ֣י יַֽעֲק֔וֹב וּמִשְׁכְּנֹתָ֖יו אֲרַחֵ֑ם וְנִבְנְתָ֥ה עִיר֙ עַל־תִּלָּ֔הּ וְאַרְמ֖וֹן עַל־מִשְׁפָּט֥וֹ יֵשֵֽׁב׃"}},"definableWords":["LORD","Jacob","stand"],"peopleInVerse":["Jacob"],"themesInVerse":["exile_return"]},"19":{"text":"And out of them shall proceed thanksgiving and the voice of them that make merry: and I will multiply them, and they shall not be few; I will also glorify them, and they shall not be small.","ref":"Jeremiah 30:19","synthesized":"Thanksgiving will proceed from them, a sound of celebration. I will multiply them, and they will not be decreased; I will honor them, and they will not be belittled.","sources":{"KJV":{"text":"And out of them shall proceed thanksgiving and the voice of them that make merry: and I will multiply them, and they shall not be few; I will also glorify them, and they shall not be small."},"BSB":{"text":"Thanksgiving will proceed from them, a sound of celebration. I will multiply them, and they will not be decreased; I will honor them, and they will not be belittled."},"TANAKH":{"text":"And out of them shall proceed thanksgiving and the voice of them that make merry; and I will multiply them, and they shall not be diminished, I will also increase them, and they shall not dwindle away."},"HEBREW":{"text":"וְיָצָ֥א מֵהֶ֛ם תּוֹדָ֖ה וְק֣וֹל מְשַׂחֲקִ֑ים וְהִרְבִּתִים֙ וְלֹ֣א יִמְעָ֔טוּ וְהִכְבַּדְתִּ֖ים וְלֹ֥א יִצְעָֽרוּ׃"}},"definableWords":["multiply"],"peopleInVerse":[],"themesInVerse":["worship"]},"20":{"text":"Their children also shall be as aforetime, and their congregation shall be established before me, and I will punish all that oppress them.","ref":"Jeremiah 30:20","synthesized":"Their children will be as in days of old, and their congregation will be established before Me; and I will punish all their oppressors.","sources":{"KJV":{"text":"Their children also shall be as aforetime, and their congregation shall be established before me, and I will punish all that oppress them."},"BSB":{"text":"Their children will be as in days of old, and their congregation will be established before Me; and I will punish all their oppressors."},"TANAKH":{"text":"Their children also shall be as aforetime, and their congregation shall be established before Me, and I will punish all that oppress them."},"HEBREW":{"text":"וְהָי֤וּ בָנָיו֙ כְּקֶ֔דֶם וַעֲדָת֖וֹ לְפָנַ֣י תִּכּ֑וֹן וּפָ֣קַדְתִּ֔י עַ֖ל כָּל־לֹחֲצָֽיו׃"}},"definableWords":["days"],"peopleInVerse":[]},"21":{"text":"And their nobles shall be of themselves, and their governor shall proceed from the midst of them; and I will cause him to draw near, and he shall approach unto me: for who is this that engaged his heart to approach unto me? saith the LORD.","ref":"Jeremiah 30:21","synthesized":"Their leader will be one of their own, and their ruler will arise from their midst. And I will bring him near, and he will approach Me, for who would dare on his own to approach Me?” declares the LORD.","sources":{"KJV":{"text":"And their nobles shall be of themselves, and their governor shall proceed from the midst of them; and I will cause him to draw near, and he shall approach unto me: for who is this that engaged his heart to approach unto me? saith the LORD."},"BSB":{"text":"Their leader will be one of their own, and their ruler will arise from their midst. And I will bring him near, and he will approach Me, for who would dare on his own to approach Me?” declares the LORD."},"TANAKH":{"text":"And their prince shall be of themselves, and their ruler shall proceed from the midst of them; and I will cause him to draw near, and he shall approach unto Me; for who is he that hath pledged his heart to approach unto Me? saith HaShem."},"HEBREW":{"text":"וְהָיָ֨ה אַדִּיר֜וֹ מִמֶּ֗נּוּ וּמֹֽשְׁלוֹ֙ מִקִּרְבּ֣וֹ יֵצֵ֔א וְהִקְרַבְתִּ֖יו וְנִגַּ֣שׁ אֵלָ֑י כִּי֩ מִ֨י הוּא־זֶ֜ה עָרַ֧ב אֶת־לִבּ֛וֹ לָגֶ֥שֶׁת אֵלַ֖י נְאֻם־יְהוָֽה׃"}},"definableWords":["one","ruler","LORD"],"peopleInVerse":[]},"22":{"text":"And ye shall be my people, and I will be your God.","ref":"Jeremiah 30:22","synthesized":"“And you will be My people, and I will be your God.”","sources":{"KJV":{"text":"And ye shall be my people, and I will be your God."},"BSB":{"text":"“And you will be My people, and I will be your God.”"},"TANAKH":{"text":"And ye shall be My people, and I will be your G-d."},"HEBREW":{"text":"וִהְיִ֥יתֶם לִ֖י לְעָ֑ם וְאָ֣נֹכִ֔י אֶהְיֶ֥ה לָכֶ֖ם לֵאלֹהִֽים׃"}},"definableWords":["people","God"],"peopleInVerse":[]},"23":{"text":"Behold, the whirlwind of the LORD goeth forth with fury, a continuing whirlwind: it shall fall with pain upon the head of the wicked.","ref":"Jeremiah 30:23","synthesized":"Behold, the storm of the LORD has gone out with fury, a whirlwind swirling down upon the heads of the wicked.","sources":{"KJV":{"text":"Behold, the whirlwind of the LORD goeth forth with fury, a continuing whirlwind: it shall fall with pain upon the head of the wicked."},"BSB":{"text":"Behold, the storm of the LORD has gone out with fury, a whirlwind swirling down upon the heads of the wicked."},"TANAKH":{"text":"Behold, a storm of HaShem is gone forth in fury, a sweeping storm; it shall whirl upon the head of the wicked."},"HEBREW":{"text":"הִנֵּ֣ה ׀ סַעֲרַ֣ת יְהוָ֗ה חֵמָה֙ יָֽצְאָ֔ה סַ֖עַר מִתְגּוֹרֵ֑ר עַ֛ל רֹ֥אשׁ רְשָׁעִ֖ים יָחֽוּל׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"24":{"text":"The fierce anger of the LORD shall not return, until he have done it, and until he have performed the intents of his heart: in the latter days ye shall consider it.","ref":"Jeremiah 30:24","synthesized":"The fierce anger of the LORD will not turn back until He has fully accomplished the purposes of His heart. In the days to come you will understand this.","sources":{"KJV":{"text":"The fierce anger of the LORD shall not return, until he have done it, and until he have performed the intents of his heart: in the latter days ye shall consider it."},"BSB":{"text":"The fierce anger of the LORD will not turn back until He has fully accomplished the purposes of His heart. In the days to come you will understand this."},"TANAKH":{"text":"The fierce anger of HaShem shall not return, until He have executed, and till He have performed the purposes of His heart; in the end of days ye shall consider it."},"HEBREW":{"text":"לֹ֣א יָשׁ֗וּב חֲרוֹן֙ אַף־יְהוָ֔ה עַד־עֲשֹׂת֥וֹ וְעַד־הֲקִימ֖וֹ מְזִמּ֣וֹת לִבּ֑וֹ בְּאַחֲרִ֥ית הַיָּמִ֖ים תִּתְבּ֥וֹנְנוּ בָֽהּ׃"}},"definableWords":["anger","LORD","heart","days"],"peopleInVerse":[]}}},"31":{"chapter":"31","title":"THE NEW COVENANT","verses":{"1":{"text":"At the same time, saith the LORD, will I be the God of all the families of Israel, and they shall be my people.","ref":"Jeremiah 31:1","synthesized":"“At that time,” declares the LORD, “I will be the God of all the families of Israel, and they will be My people.”","sources":{"KJV":{"text":"At the same time, saith the LORD, will I be the God of all the families of Israel, and they shall be my people."},"BSB":{"text":"“At that time,” declares the LORD, “I will be the God of all the families of Israel, and they will be My people.”"},"TANAKH":{"text":"At that time, saith HaShem, will I be the G-d of all the families of Israel, and they shall be My people."},"HEBREW":{"text":"בָּעֵ֤ת הַהִיא֙ נְאֻם־יְהוָ֔ה אֶֽהְיֶה֙ לֵֽאלֹהִ֔ים לְכֹ֖ל מִשְׁפְּח֣וֹת יִשְׂרָאֵ֑ל וְהֵ֖מָּה יִֽהְיוּ־לִ֥י לְעָֽם׃"}},"definableWords":["LORD","God","families","Israel","people"],"peopleInVerse":[],"kingdomLens":"In the darkest hour of Judah's history — with Babylon at the gates — God promises through Jeremiah a new covenant: 'I will put my law in their inward parts, and write it in their hearts... I will forgive their iniquity, and I will remember their sin no more' (Jer 31:33-34). Hebrews 8 quotes this entire passage and applies it directly to Christ.","cultural":{"title":"The New Covenant promised","detail":"The 'new covenant' (Hebrew: brit hadasha) is not new in time only — it is new in kind. The Mosaic covenant was written on stone, external. This one is written on the heart, internal. Jesus said over the cup at the Last Supper: 'this cup is the new testament in my blood' (Luke 22:20).","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"Thus saith the LORD, The people which were left of the sword found grace in the wilderness; even Israel, when I went to cause him to rest.","ref":"Jeremiah 31:2","synthesized":"This is what the LORD says:  “The people who survived the sword found favor in the wilderness when Israel went to find rest.”","sources":{"KJV":{"text":"Thus saith the LORD, The people which were left of the sword found grace in the wilderness; even Israel, when I went to cause him to rest."},"BSB":{"text":"This is what the LORD says:  “The people who survived the sword found favor in the wilderness when Israel went to find rest.”"},"TANAKH":{"text":"Thus saith HaShem: the people that were left of the sword have found grace in the wilderness, even Israel, when I go to cause him to rest."},"HEBREW":{"text":"כֹּ֚ה אָמַ֣ר יְהוָ֔ה מָצָ֥א חֵן֙ בַּמִּדְבָּ֔ר עַ֖ם שְׂרִ֣ידֵי חָ֑רֶב הָל֥וֹךְ לְהַרְגִּיע֖וֹ יִשְׂרָאֵֽל׃"}},"definableWords":["LORD","people","Israel","rest"],"peopleInVerse":[],"themesInVerse":["grace","peace","sabbath_rest"]},"3":{"text":"The LORD hath appeared of old unto me, saying, Yea, I have loved thee with an everlasting love: therefore with lovingkindness have I drawn thee.","ref":"Jeremiah 31:3","synthesized":"The LORD appeared to us in the past, saying:  “I have loved you with an everlasting love; therefore I have drawn you with loving devotion.","sources":{"KJV":{"text":"The LORD hath appeared of old unto me, saying, Yea, I have loved thee with an everlasting love: therefore with lovingkindness have I drawn thee."},"BSB":{"text":"The LORD appeared to us in the past, saying:  “I have loved you with an everlasting love; therefore I have drawn you with loving devotion."},"TANAKH":{"text":"'From afar HaShem appeared unto me.' 'Yea, I have loved thee with an everlasting love; therefore with affection have I drawn thee."},"HEBREW":{"text":"מֵרָח֕וֹק יְהוָ֖ה נִרְאָ֣ה לִ֑י וְאַהֲבַ֤ת עוֹלָם֙ אֲהַבְתִּ֔יךְ עַל־כֵּ֖ן מְשַׁכְתִּ֥יךְ חָֽסֶד׃"}},"definableWords":["LORD","everlasting","love"],"peopleInVerse":[],"themesInVerse":["love"]},"4":{"text":"Again I will build thee, and thou shalt be built, O virgin of Israel: thou shalt again be adorned with thy tabrets, and shalt go forth in the dances of them that make merry.","ref":"Jeremiah 31:4","synthesized":"Again I will build you, and you will be rebuilt, O Virgin Israel. Again you will take up your tambourines and go out in joyful dancing.","sources":{"KJV":{"text":"Again I will build thee, and thou shalt be built, O virgin of Israel: thou shalt again be adorned with thy tabrets, and shalt go forth in the dances of them that make merry."},"BSB":{"text":"Again I will build you, and you will be rebuilt, O Virgin Israel. Again you will take up your tambourines and go out in joyful dancing."},"TANAKH":{"text":"Again will I build thee, and thou shalt be built, O virgin of Israel; again shalt thou be adorned with thy tabrets, and shalt go forth in the dances of them that make merry."},"HEBREW":{"text":"ע֤וֹד אֶבְנֵךְ֙ וְֽנִבְנֵ֔ית בְּתוּלַ֖ת יִשְׂרָאֵ֑ל ע֚וֹד תַּעְדִּ֣י תֻפַּ֔יִךְ וְיָצָ֖את בִּמְח֥וֹל מְשַׂחֲקִֽים׃"}},"definableWords":["Israel"],"peopleInVerse":[]},"5":{"text":"Thou shalt yet plant vines upon the mountains of Samaria: the planters shall plant, and shall eat them as common things.","ref":"Jeremiah 31:5","synthesized":"Again you will plant vineyards on the hills of Samaria; the farmers will plant and enjoy the fruit.","sources":{"KJV":{"text":"Thou shalt yet plant vines upon the mountains of Samaria: the planters shall plant, and shall eat them as common things."},"BSB":{"text":"Again you will plant vineyards on the hills of Samaria; the farmers will plant and enjoy the fruit."},"TANAKH":{"text":"Again shalt thou plant vineyards upon the mountains of Samaria; the planters shall plant, and shall have the use thereof."},"HEBREW":{"text":"ע֚וֹד תִּטְּעִ֣י כְרָמִ֔ים בְּהָרֵ֖י שֹֽׁמְר֑וֹן נָטְע֥וּ נֹטְעִ֖ים וְחִלֵּֽלוּ׃"}},"definableWords":["Samaria"],"peopleInVerse":[],"placesInVerse":["Samaria"],"themesInVerse":["vine_branches"]},"6":{"text":"For there shall be a day, that the watchmen upon the mount Ephraim shall cry, Arise ye, and let us go up to Zion unto the LORD our God.","ref":"Jeremiah 31:6","synthesized":"For there will be a day when watchmen will call out on the hills of Ephraim, ‘Arise, let us go up to Zion, to the LORD our God!’”","sources":{"KJV":{"text":"For there shall be a day, that the watchmen upon the mount Ephraim shall cry, Arise ye, and let us go up to Zion unto the LORD our God."},"BSB":{"text":"For there will be a day when watchmen will call out on the hills of Ephraim, ‘Arise, let us go up to Zion, to the LORD our God!’”"},"TANAKH":{"text":"For there shall be a day, that the watchmen shall call upon the mount Ephraim: arise ye, and let us go up to Zion, unto HaShem our G-d.'"},"HEBREW":{"text":"כִּ֣י יֶשׁ־י֔וֹם קָרְא֥וּ נֹצְרִ֖ים בְּהַ֣ר אֶפְרָ֑יִם ק֚וּמוּ וְנַעֲלֶ֣ה צִיּ֔וֹן אֶל־יְהוָ֖ה אֱלֹהֵֽינוּ׃"}},"definableWords":["day","Zion","LORD","God"],"peopleInVerse":[],"placesInVerse":["Mount Zion"]},"7":{"text":"For thus saith the LORD; Sing with gladness for Jacob, and shout among the chief of the nations: publish ye, praise ye, and say, O LORD, save thy people, the remnant of Israel.","ref":"Jeremiah 31:7","synthesized":"For this is what the LORD says:  “Sing with joy for Jacob; shout for the foremost of the nations! Make your praises heard, and say, ‘O LORD, save Your people, the remnant of Israel!’","sources":{"KJV":{"text":"For thus saith the LORD; Sing with gladness for Jacob, and shout among the chief of the nations: publish ye, praise ye, and say, O LORD, save thy people, the remnant of Israel."},"BSB":{"text":"For this is what the LORD says:  “Sing with joy for Jacob; shout for the foremost of the nations! Make your praises heard, and say, ‘O LORD, save Your people, the remnant of Israel!’"},"TANAKH":{"text":"For thus saith HaShem: sing with gladness for Jacob, and shout at the head of the nations; announce ye, praise ye, and say: 'O HaShem, save Thy people, The remnant of Israel.'"},"HEBREW":{"text":"כִּי־כֹ֣ה ׀ אָמַ֣ר יְהוָ֗ה רָנּ֤וּ לְיַֽעֲקֹב֙ שִׂמְחָ֔ה וְצַהֲל֖וּ בְּרֹ֣אשׁ הַגּוֹיִ֑ם הַשְׁמִ֤יעוּ הַֽלְלוּ֙ וְאִמְר֔וּ הוֹשַׁ֤ע יְהוָה֙ אֶֽת־עַמְּךָ֔ אֵ֖ת שְׁאֵרִ֥ית יִשְׂרָאֵֽל׃"}},"definableWords":["LORD","joy","Jacob","nations","make","Lord","people","remnant","Israel"],"peopleInVerse":["Jacob"],"themesInVerse":["exile_return","joy","salvation"]},"8":{"text":"Behold, I will bring them from the north country, and gather them from the coasts of the earth, and with them the blind and the lame, the woman with child and her that travaileth with child together: a great company shall return thither.","ref":"Jeremiah 31:8","synthesized":"Behold, I will bring them from the land of the north and gather them from the farthest parts of the earth, including the blind and the lame, expectant mothers and women in labor. They will return as a great assembly!","sources":{"KJV":{"text":"Behold, I will bring them from the north country, and gather them from the coasts of the earth, and with them the blind and the lame, the woman with child and her that travaileth with child together: a great company shall return thither."},"BSB":{"text":"Behold, I will bring them from the land of the north and gather them from the farthest parts of the earth, including the blind and the lame, expectant mothers and women in labor. They will return as a great assembly!"},"TANAKH":{"text":"Behold, I will bring them from the north country, and gather them from the uttermost parts of the earth, and with them the blind and the lame, the woman with child and her that travaileth with child together; a great company shall they return hither."},"HEBREW":{"text":"הִנְנִי֩ מֵבִ֨יא אוֹתָ֜ם מֵאֶ֣רֶץ צָפ֗וֹן וְקִבַּצְתִּים֮ מִיַּרְכְּתֵי־אָרֶץ֒ בָּ֚ם עִוֵּ֣ר וּפִסֵּ֔חַ הָרָ֥ה וְיֹלֶ֖דֶת יַחְדָּ֑ו קָהָ֥ל גָּד֖וֹל יָשׁ֥וּבוּ הֵֽנָּה׃"}},"definableWords":["land","earth","women","great"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise","second_coming"]},"9":{"text":"They shall come with weeping, and with supplications will I lead them: I will cause them to walk by the rivers of waters in a straight way, wherein they shall not stumble: for I am a father to Israel, and Ephraim is my firstborn.","ref":"Jeremiah 31:9","synthesized":"They will come with weeping, and by their supplication I will lead them; I will make them walk beside streams of waters, on a level path where they will not stumble. For I am Israel’s Father, and Ephraim is My firstborn.”","sources":{"KJV":{"text":"They shall come with weeping, and with supplications will I lead them: I will cause them to walk by the rivers of waters in a straight way, wherein they shall not stumble: for I am a father to Israel, and Ephraim is my firstborn."},"BSB":{"text":"They will come with weeping, and by their supplication I will lead them; I will make them walk beside streams of waters, on a level path where they will not stumble. For I am Israel’s Father, and Ephraim is My firstborn.”"},"TANAKH":{"text":"They shall come with weeping, and with supplications will I lead them; I will cause them to walk by rivers of waters, in a straight way wherein they shall not stumble; for I am become a father to Israel, and Ephraim is My first-born."},"HEBREW":{"text":"בִּבְכִ֣י יָבֹ֗אוּ וּֽבְתַחֲנוּנִים֮ אֽוֹבִילֵם֒ אֽוֹלִיכֵם֙ אֶל־נַ֣חֲלֵי מַ֔יִם בְּדֶ֣רֶךְ יָשָׁ֔ר לֹ֥א יִכָּשְׁל֖וּ בָּ֑הּ כִּֽי־הָיִ֤יתִי לְיִשְׂרָאֵל֙ לְאָ֔ב וְאֶפְרַ֖יִם בְּכֹ֥רִי הֽוּא׃"}},"definableWords":["make","walk","waters","Israel","Father"],"peopleInVerse":[],"themesInVerse":["prayer"]},"10":{"text":"Hear the word of the LORD, O ye nations, and declare it in the isles afar off, and say, He that scattered Israel will gather him, and keep him, as a shepherd doth his flock.","ref":"Jeremiah 31:10","synthesized":"Hear, O nations, the word of the LORD, and proclaim it in distant coastlands:   “The One who scattered Israel will gather them and keep them as a shepherd keeps his flock.","sources":{"KJV":{"text":"Hear the word of the LORD, O ye nations, and declare it in the isles afar off, and say, He that scattered Israel will gather him, and keep him, as a shepherd doth his flock."},"BSB":{"text":"Hear, O nations, the word of the LORD, and proclaim it in distant coastlands:   “The One who scattered Israel will gather them and keep them as a shepherd keeps his flock."},"TANAKH":{"text":"Hear the word of HaShem, O ye nations, and declare it in the isles afar off, and say: 'He that scattered Israel doth gather him, and keep him, as a shepherd doth his flock.'"},"HEBREW":{"text":"שִׁמְע֤וּ דְבַר־יְהוָה֙ גּוֹיִ֔ם וְהַגִּ֥ידוּ בָאִיִּ֖ים מִמֶּרְחָ֑ק וְאִמְר֗וּ מְזָרֵ֤ה יִשְׂרָאֵל֙ יְקַבְּצֶ֔נּוּ וּשְׁמָר֖וֹ כְּרֹעֶ֥ה עֶדְרֽוֹ׃"}},"definableWords":["hear","nations","word","LORD","one","Israel","keep","shepherd"],"peopleInVerse":[],"themesInVerse":["shepherd_sheep"]},"11":{"text":"For the LORD hath redeemed Jacob, and ransomed him from the hand of him that was stronger than he.","ref":"Jeremiah 31:11","synthesized":"For the LORD has ransomed Jacob and redeemed him from the hand that had overpowered him.","sources":{"KJV":{"text":"For the LORD hath redeemed Jacob, and ransomed him from the hand of him that was stronger than he."},"BSB":{"text":"For the LORD has ransomed Jacob and redeemed him from the hand that had overpowered him."},"TANAKH":{"text":"For HaShem hath ransomed Jacob, and He redeemeth him from the hand of him that is stronger than he."},"HEBREW":{"text":"כִּֽי־פָדָ֥ה יְהוָ֖ה אֶֽת־יַעֲקֹ֑ב וּגְאָל֕וֹ מִיַּ֖ד חָזָ֥ק מִמֶּֽנּוּ׃"}},"definableWords":["LORD","Jacob"],"peopleInVerse":["Jacob"]},"12":{"text":"Therefore they shall come and sing in the height of Zion, and shall flow together to the goodness of the LORD, for wheat, and for wine, and for oil, and for the young of the flock and of the herd: and their soul shall be as a watered garden; and they shall not sorrow any more at all.","ref":"Jeremiah 31:12","synthesized":"They will come and shout for joy on the heights of Zion; they will be radiant over the bounty of the LORD— the grain, new wine, and oil, and the young of the flocks and herds. Their life will be like a well-watered garden, and never again will they languish.","sources":{"KJV":{"text":"Therefore they shall come and sing in the height of Zion, and shall flow together to the goodness of the LORD, for wheat, and for wine, and for oil, and for the young of the flock and of the herd: and their soul shall be as a watered garden; and they shall not sorrow any more at all."},"BSB":{"text":"They will come and shout for joy on the heights of Zion; they will be radiant over the bounty of the LORD— the grain, new wine, and oil, and the young of the flocks and herds. Their life will be like a well-watered garden, and never again will they languish."},"TANAKH":{"text":"And they shall come and sing in the height of Zion, and shall flow unto the goodness of HaShem, to the corn, and to the wine, and to the oil, and to the young of the flock and of the herd; and their soul shall be as a watered garden, and they shall not pine any more at all."},"HEBREW":{"text":"וּבָאוּ֮ וְרִנְּנ֣וּ בִמְרוֹם־צִיּוֹן֒ וְנָהֲר֞וּ אֶל־ט֣וּב יְהוָ֗ה עַל־דָּגָן֙ וְעַל־תִּירֹ֣שׁ וְעַל־יִצְהָ֔ר וְעַל־בְּנֵי־צֹ֖אן וּבָקָ֑ר וְהָיְתָ֤ה נַפְשָׁם֙ כְּגַ֣ן רָוֶ֔ה וְלֹא־יוֹסִ֥יפוּ לְדַאֲבָ֖ה עֽוֹד׃"}},"definableWords":["joy","Zion","LORD","life","garden"],"peopleInVerse":[],"placesInVerse":["Mount Zion"],"themesInVerse":["bread_water_life","joy"]},"13":{"text":"Then shall the virgin rejoice in the dance, both young men and old together: for I will turn their mourning into joy, and will comfort them, and make them rejoice from their sorrow.","ref":"Jeremiah 31:13","synthesized":"Then the maidens will rejoice with dancing, young men and old as well. I will turn their mourning into joy, and give them comfort and joy for their sorrow.","sources":{"KJV":{"text":"Then shall the virgin rejoice in the dance, both young men and old together: for I will turn their mourning into joy, and will comfort them, and make them rejoice from their sorrow."},"BSB":{"text":"Then the maidens will rejoice with dancing, young men and old as well. I will turn their mourning into joy, and give them comfort and joy for their sorrow."},"TANAKH":{"text":"Then shall the virgin rejoice in the dance, and the young men and the old together; for I will turn their mourning into joy, and will comfort them, and make them rejoice from their sorrow."},"HEBREW":{"text":"אָ֣ז תִּשְׂמַ֤ח בְּתוּלָה֙ בְּמָח֔וֹל וּבַחֻרִ֥ים וּזְקֵנִ֖ים יַחְדָּ֑ו וְהָפַכְתִּ֨י אֶבְלָ֤ם לְשָׂשׂוֹן֙ וְנִ֣חַמְתִּ֔ים וְשִׂמַּחְתִּ֖ים מִיגוֹנָֽם׃"}},"definableWords":["men","joy"],"peopleInVerse":[],"themesInVerse":["bread_water_life","joy"]},"14":{"text":"And I will satiate the soul of the priests with fatness, and my people shall be satisfied with my goodness, saith the LORD.","ref":"Jeremiah 31:14","synthesized":"I will fill the souls of the priests abundantly, and will fill My people with My goodness,” declares the LORD.","sources":{"KJV":{"text":"And I will satiate the soul of the priests with fatness, and my people shall be satisfied with my goodness, saith the LORD."},"BSB":{"text":"I will fill the souls of the priests abundantly, and will fill My people with My goodness,” declares the LORD."},"TANAKH":{"text":"And I will satiate the soul of the priests with fatness, and My people shall be satisfied with My goodness, saith HaShem."},"HEBREW":{"text":"וְרִוֵּיתִ֛י נֶ֥פֶשׁ הַכֹּהֲנִ֖ים דָּ֑שֶׁן וְעַמִּ֛י אֶת־טוּבִ֥י יִשְׂבָּ֖עוּ נְאֻם־יְהוָֽה׃"}},"definableWords":["fill","people","LORD"],"peopleInVerse":[]},"15":{"text":"Thus saith the LORD; A voice was heard in Ramah, lamentation, and bitter weeping; Rahel weeping for her children refused to be comforted for her children, because they were not.","ref":"Jeremiah 31:15","synthesized":"This is what the LORD says:  “A voice is heard in Ramah, mourning and great weeping, Rachel weeping for her children, and refusing to be comforted, because they are no more.”","sources":{"KJV":{"text":"Thus saith the LORD; A voice was heard in Ramah, lamentation, and bitter weeping; Rahel weeping for her children refused to be comforted for her children, because they were not."},"BSB":{"text":"This is what the LORD says:  “A voice is heard in Ramah, mourning and great weeping, Rachel weeping for her children, and refusing to be comforted, because they are no more.”"},"TANAKH":{"text":"Thus saith HaShem: A voice is heard in Ramah, lamentation, and bitter weeping, Rachel weeping for her children; she refuseth to be comforted for her children, because they are not."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה ק֣וֹל בְּרָמָ֤ה נִשְׁמָע֙ נְהִי֙ בְּכִ֣י תַמְרוּרִ֔ים רָחֵ֖ל מְבַכָּ֣ה עַל־בָּנֶ֑יהָ מֵאֲנָ֛ה לְהִנָּחֵ֥ם עַל־בָּנֶ֖יהָ כִּ֥י אֵינֶֽנּוּ׃"}},"definableWords":["LORD","voice","great","Rachel"],"peopleInVerse":["Rachel"]},"16":{"text":"Thus saith the LORD; Refrain thy voice from weeping, and thine eyes from tears: for thy work shall be rewarded, saith the LORD; and they shall come again from the land of the enemy.","ref":"Jeremiah 31:16","synthesized":"This is what the LORD says:  “Keep your voice from weeping and your eyes from tears, for the reward for your work will come, declares the LORD. Then your children will return from the land of the enemy.","sources":{"KJV":{"text":"Thus saith the LORD; Refrain thy voice from weeping, and thine eyes from tears: for thy work shall be rewarded, saith the LORD; and they shall come again from the land of the enemy."},"BSB":{"text":"This is what the LORD says:  “Keep your voice from weeping and your eyes from tears, for the reward for your work will come, declares the LORD. Then your children will return from the land of the enemy."},"TANAKH":{"text":"Thus saith HaShem: Refrain thy voice from weeping, and thine eyes from tears; for thy work shall be rewarded, saith HaShem; and they shall come back from the land of the enemy."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה מִנְעִ֤י קוֹלֵךְ֙ מִבֶּ֔כִי וְעֵינַ֖יִךְ מִדִּמְעָ֑ה כִּי֩ יֵ֨שׁ שָׂכָ֤ר לִפְעֻלָּתֵךְ֙ נְאֻם־יְהוָ֔ה וְשָׁ֖בוּ מֵאֶ֥רֶץ אוֹיֵֽב׃"}},"definableWords":["LORD","keep","voice","work","Lord","land"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise","second_coming"]},"17":{"text":"And there is hope in thine end, saith the LORD, that thy children shall come again to their own border.","ref":"Jeremiah 31:17","synthesized":"So there is hope for your future, declares the LORD, and your children will return to their own land.","sources":{"KJV":{"text":"And there is hope in thine end, saith the LORD, that thy children shall come again to their own border."},"BSB":{"text":"So there is hope for your future, declares the LORD, and your children will return to their own land."},"TANAKH":{"text":"And there is hope for thy future, saith HaShem; and thy children shall return to their own border."},"HEBREW":{"text":"וְיֵשׁ־תִּקְוָ֥ה לְאַחֲרִיתֵ֖ךְ נְאֻם־יְהוָ֑ה וְשָׁ֥בוּ בָנִ֖ים לִגְבוּלָֽם׃"}},"definableWords":["hope","LORD","land"],"peopleInVerse":[],"themesInVerse":["exile_return","hope","land_promise","second_coming"]},"18":{"text":"I have surely heard Ephraim bemoaning himself thus; Thou hast chastised me, and I was chastised, as a bullock unaccustomed to the yoke: turn thou me, and I shall be turned; for thou art the LORD my God.","ref":"Jeremiah 31:18","synthesized":"I have surely heard Ephraim’s moaning:   ‘You disciplined me severely, like an untrained calf. Restore me, that I may return, for You are the LORD my God.","sources":{"KJV":{"text":"I have surely heard Ephraim bemoaning himself thus; Thou hast chastised me, and I was chastised, as a bullock unaccustomed to the yoke: turn thou me, and I shall be turned; for thou art the LORD my God."},"BSB":{"text":"I have surely heard Ephraim’s moaning:   ‘You disciplined me severely, like an untrained calf. Restore me, that I may return, for You are the LORD my God."},"TANAKH":{"text":"I have surely heard Ephraim bemoaning himself: 'Thou hast chastised me, and I was chastised, as a calf untrained; turn thou me, and I shall be turned, for Thou art HaShem my G-d."},"HEBREW":{"text":"שָׁמ֣וֹעַ שָׁמַ֗עְתִּי אֶפְרַ֙יִם֙ מִתְנוֹדֵ֔ד יִסַּרְתַּ֙נִי֙ וָֽאִוָּסֵ֔ר כְּעֵ֖גֶל לֹ֣א לֻמָּ֑ד הֲשִׁיבֵ֣נִי וְאָשׁ֔וּבָה כִּ֥י אַתָּ֖ה יְהוָ֥ה אֱלֹהָֽי׃"}},"definableWords":["LORD","God"],"peopleInVerse":[],"themesInVerse":["exile_return","second_coming"]},"19":{"text":"Surely after that I was turned, I repented; and after that I was instructed, I smote upon my thigh: I was ashamed, yea, even confounded, because I did bear the reproach of my youth.","ref":"Jeremiah 31:19","synthesized":"After I returned, I repented; and after I was instructed, I struck my thigh in grief. I was ashamed and humiliated because I bore the disgrace of my youth.’","sources":{"KJV":{"text":"Surely after that I was turned, I repented; and after that I was instructed, I smote upon my thigh: I was ashamed, yea, even confounded, because I did bear the reproach of my youth."},"BSB":{"text":"After I returned, I repented; and after I was instructed, I struck my thigh in grief. I was ashamed and humiliated because I bore the disgrace of my youth.’"},"TANAKH":{"text":"Surely after that I was turned, I repented, and after that I was instructed, I smote upon my thigh; I was ashamed, yea, even confounded, because I did bear the reproach of my youth.'"},"HEBREW":{"text":"כִּֽי־אַחֲרֵ֤י שׁוּבִי֙ נִחַ֔מְתִּי וְאַֽחֲרֵי֙ הִוָּ֣דְעִ֔י סָפַ֖קְתִּי עַל־יָרֵ֑ךְ בֹּ֚שְׁתִּי וְגַם־נִכְלַ֔מְתִּי כִּ֥י נָשָׂ֖אתִי חֶרְפַּ֥ת נְעוּרָֽי׃"}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Is Ephraim my dear son? is he a pleasant child? for since I spake against him, I do earnestly remember him still: therefore my bowels are troubled for him; I will surely have mercy upon him, saith the LORD.","ref":"Jeremiah 31:20","synthesized":"Is not Ephraim a precious son to Me, a delightful child? Though I often speak against him, I still remember him. Therefore My heart yearns for him; I have great compassion for him,” declares the LORD.","sources":{"KJV":{"text":"Is Ephraim my dear son? is he a pleasant child? for since I spake against him, I do earnestly remember him still: therefore my bowels are troubled for him; I will surely have mercy upon him, saith the LORD."},"BSB":{"text":"Is not Ephraim a precious son to Me, a delightful child? Though I often speak against him, I still remember him. Therefore My heart yearns for him; I have great compassion for him,” declares the LORD."},"TANAKH":{"text":"Is Ephraim a darling son unto Me? Is he a child that is dandled? For as often as I speak of him, I do earnestly remember him still; therefore My heart yearneth for him, I will surely have compassion upon him, saith HaShem."},"HEBREW":{"text":"הֲבֵן֩ יַקִּ֨יר לִ֜י אֶפְרַ֗יִם אִ֚ם יֶ֣לֶד שַׁעֲשֻׁעִ֔ים כִּֽי־מִדֵּ֤י דַבְּרִי֙ בּ֔וֹ זָכֹ֥ר אֶזְכְּרֶ֖נּוּ ע֑וֹד עַל־כֵּ֗ן הָמ֤וּ מֵעַי֙ ל֔וֹ רַחֵ֥ם אֲ‍ֽרַחֲמֶ֖נּוּ נְאֻם־יְהוָֽה׃"}},"definableWords":["son","remember","heart","great","LORD"],"peopleInVerse":[]},"21":{"text":"Set thee up waymarks, make thee high heaps: set thine heart toward the highway, even the way which thou wentest: turn again, O virgin of Israel, turn again to these thy cities.","ref":"Jeremiah 31:21","synthesized":"“Set up the roadmarks, establish the signposts. Keep the highway in mind, the road you have traveled. Return, O Virgin Israel, return to these cities of yours.","sources":{"KJV":{"text":"Set thee up waymarks, make thee high heaps: set thine heart toward the highway, even the way which thou wentest: turn again, O virgin of Israel, turn again to these thy cities."},"BSB":{"text":"“Set up the roadmarks, establish the signposts. Keep the highway in mind, the road you have traveled. Return, O Virgin Israel, return to these cities of yours."},"TANAKH":{"text":"Set thee up waymarks, make thee guide-posts; set thy heart toward the high-way, even the way by which thou wentest; return, O virgin of Israel, return to these thy cities."},"HEBREW":{"text":"הַצִּ֧יבִי לָ֣ךְ צִיֻּנִ֗ים שִׂ֤מִי לָךְ֙ תַּמְרוּרִ֔ים שִׁ֣תִי לִבֵּ֔ךְ לַֽמְסִלָּ֖ה דֶּ֣רֶךְ הלכתי הָלָ֑כְתְּ שׁ֚וּבִי בְּתוּלַ֣ת יִשְׂרָאֵ֔ל שֻׁ֖בִי אֶל־עָרַ֥יִךְ אֵֽלֶּה׃"}},"definableWords":["keep","mind","Israel"],"peopleInVerse":[],"themesInVerse":["exile_return","second_coming"]},"22":{"text":"How long wilt thou go about, O thou backsliding daughter? for the LORD hath created a new thing in the earth, A woman shall compass a man.","ref":"Jeremiah 31:22","synthesized":"How long will you wander, O faithless daughter? For the LORD has created a new thing in the land— a woman will shelter a man.”","sources":{"KJV":{"text":"How long wilt thou go about, O thou backsliding daughter? for the LORD hath created a new thing in the earth, A woman shall compass a man."},"BSB":{"text":"How long will you wander, O faithless daughter? For the LORD has created a new thing in the land— a woman will shelter a man.”"},"TANAKH":{"text":"How long wilt thou turn away coyly, O thou backsliding daughter? For HaShem hath created a new thing in the earth: a woman shall court a man."},"HEBREW":{"text":"עַד־מָתַי֙ תִּתְחַמָּקִ֔ין הַבַּ֖ת הַשּֽׁוֹבֵבָ֑ה כִּֽי־בָרָ֨א יְהוָ֤ה חֲדָשָׁה֙ בָּאָ֔רֶץ נְקֵבָ֖ה תְּס֥וֹבֵֽב גָּֽבֶר׃"}},"definableWords":["daughter","LORD","created","land","woman","man"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"23":{"text":"Thus saith the LORD of hosts, the God of Israel; As yet they shall use this speech in the land of Judah and in the cities thereof, when I shall bring again their captivity; The LORD bless thee, O habitation of justice, and mountain of holiness.","ref":"Jeremiah 31:23","synthesized":"This is what the LORD of Hosts, the God of Israel, says: “When I restore them from captivity, they will once again speak this word in the land of Judah and in its cities: ‘May the LORD bless you, O righteous dwelling place, O holy mountain.’","sources":{"KJV":{"text":"Thus saith the LORD of hosts, the God of Israel; As yet they shall use this speech in the land of Judah and in the cities thereof, when I shall bring again their captivity; The LORD bless thee, O habitation of justice, and mountain of holiness."},"BSB":{"text":"This is what the LORD of Hosts, the God of Israel, says: “When I restore them from captivity, they will once again speak this word in the land of Judah and in its cities: ‘May the LORD bless you, O righteous dwelling place, O holy mountain.’"},"TANAKH":{"text":"Thus saith HaShem of hosts, the G-d of Israel: yet again shall they use this speech in the land of Judah and in the cities thereof, when I shall turn their captivity: 'The HaShem bless thee, O habitation of righteousness, O mountain of holiness.'"},"HEBREW":{"text":"כֹּֽה־אָמַ֞ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל ע֣וֹד יֹאמְר֞וּ אֶת־הַדָּבָ֣ר הַזֶּ֗ה בְּאֶ֤רֶץ יְהוּדָה֙ וּבְעָרָ֔יו בְּשׁוּבִ֖י אֶת־שְׁבוּתָ֑ם יְבָרֶכְךָ֧ יְהוָ֛ה נְוֵה־צֶ֖דֶק הַ֥ר הַקֹּֽדֶשׁ׃"}},"definableWords":["LORD","God","Israel","word","land","Judah","Lord","bless","righteous","holy"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise","temple"]},"24":{"text":"And there shall dwell in Judah itself, and in all the cities thereof together, husbandmen, and they that go forth with flocks.","ref":"Jeremiah 31:24","synthesized":"And Judah and all its cities will dwell together in the land, the farmers and those who move with the flocks,","sources":{"KJV":{"text":"And there shall dwell in Judah itself, and in all the cities thereof together, husbandmen, and they that go forth with flocks."},"BSB":{"text":"And Judah and all its cities will dwell together in the land, the farmers and those who move with the flocks,"},"TANAKH":{"text":"And Judah and all the cities thereof shall dwell therein together: the husbandmen, and they that go forth with flocks."},"HEBREW":{"text":"וְיָ֥שְׁבוּ בָ֛הּ יְהוּדָ֥ה וְכָל־עָרָ֖יו יַחְדָּ֑ו אִכָּרִ֕ים וְנָסְע֖וּ בַּעֵֽדֶר׃"}},"definableWords":["Judah","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"25":{"text":"For I have satiated the weary soul, and I have replenished every sorrowful soul.","ref":"Jeremiah 31:25","synthesized":"for I will refresh the weary soul and replenish all who are weak.”","sources":{"KJV":{"text":"For I have satiated the weary soul, and I have replenished every sorrowful soul."},"BSB":{"text":"for I will refresh the weary soul and replenish all who are weak.”"},"TANAKH":{"text":"For I have satiated the weary soul, and every pining soul have I replenished."},"HEBREW":{"text":"כִּ֥י הִרְוֵ֖יתִי נֶ֣פֶשׁ עֲיֵפָ֑ה וְכָל־נֶ֥פֶשׁ דָּאֲבָ֖ה מִלֵּֽאתִי׃"}},"definableWords":["soul"],"peopleInVerse":[]},"26":{"text":"Upon this I awaked, and beheld; and my sleep was sweet unto me.","ref":"Jeremiah 31:26","synthesized":"At this I awoke and looked around. My sleep had been most pleasant to me.","sources":{"KJV":{"text":"Upon this I awaked, and beheld; and my sleep was sweet unto me."},"BSB":{"text":"At this I awoke and looked around. My sleep had been most pleasant to me."},"TANAKH":{"text":"Upon this I awaked, and beheld; and my sleep was sweet unto me."},"HEBREW":{"text":"עַל־זֹ֖את הֱקִיצֹ֣תִי וָאֶרְאֶ֑ה וּשְׁנָתִ֖י עָ֥רְבָה לִּֽי׃"}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"Behold, the days come, saith the LORD, that I will sow the house of Israel and the house of Judah with the seed of man, and with the seed of beast.","ref":"Jeremiah 31:27","synthesized":"“The days are coming,” declares the LORD, “when I will sow the house of Israel and the house of Judah with the seed of man and of beast.","sources":{"KJV":{"text":"Behold, the days come, saith the LORD, that I will sow the house of Israel and the house of Judah with the seed of man, and with the seed of beast."},"BSB":{"text":"“The days are coming,” declares the LORD, “when I will sow the house of Israel and the house of Judah with the seed of man and of beast."},"TANAKH":{"text":"Behold, the days come, saith HaShem, that I will sow the house of Israel and the house of Judah with the seed of man, and with the seed of beast."},"HEBREW":{"text":"הִנֵּ֛ה יָמִ֥ים בָּאִ֖ים נְאֻם־יְהוָ֑ה וְזָרַעְתִּ֗י אֶת־בֵּ֤ית יִשְׂרָאֵל֙ וְאֶת־בֵּ֣ית יְהוּדָ֔ה זֶ֥רַע אָדָ֖ם וְזֶ֥רַע בְּהֵמָֽה׃"}},"definableWords":["days","LORD","house","Israel","Judah","seed","man"],"peopleInVerse":[],"themesInVerse":["messiah","second_coming"]},"28":{"text":"And it shall come to pass, that like as I have watched over them, to pluck up, and to break down, and to throw down, and to destroy, and to afflict; so will I watch over them, to build, and to plant, saith the LORD.","ref":"Jeremiah 31:28","synthesized":"Just as I watched over them to uproot and tear down, to demolish, destroy, and bring disaster, so I will watch over them to build and to plant,” declares the LORD.","sources":{"KJV":{"text":"And it shall come to pass, that like as I have watched over them, to pluck up, and to break down, and to throw down, and to destroy, and to afflict; so will I watch over them, to build, and to plant, saith the LORD."},"BSB":{"text":"Just as I watched over them to uproot and tear down, to demolish, destroy, and bring disaster, so I will watch over them to build and to plant,” declares the LORD."},"TANAKH":{"text":"And it shall come to pass, that like as I have watched over them to pluck up and to break down, and to overthrow and to destroy, and to afflict; so will I watch over them to build and to plant, saith HaShem."},"HEBREW":{"text":"וְהָיָ֞ה כַּאֲשֶׁ֧ר שָׁקַ֣דְתִּי עֲלֵיהֶ֗ם לִנְת֧וֹשׁ וְלִנְת֛וֹץ וְלַהֲרֹ֖ס וּלְהַאֲבִ֣יד וּלְהָרֵ֑עַ כֵּ֣ן אֶשְׁקֹ֧ד עֲלֵיהֶ֛ם לִבְנ֥וֹת וְלִנְט֖וֹעַ נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"29":{"text":"In those days they shall say no more, The fathers have eaten a sour grape, and the children’s teeth are set on edge.","ref":"Jeremiah 31:29","synthesized":"“In those days, it will no longer be said:  ‘The fathers have eaten sour grapes, and the teeth of the children are set on edge.’","sources":{"KJV":{"text":"In those days they shall say no more, The fathers have eaten a sour grape, and the children’s teeth are set on edge."},"BSB":{"text":"“In those days, it will no longer be said:  ‘The fathers have eaten sour grapes, and the teeth of the children are set on edge.’"},"TANAKH":{"text":"In those days they shall say no more: 'The fathers have eaten sour grapes, and the children's teeth are set on edge.'"},"HEBREW":{"text":"בַּיָּמִ֣ים הָהֵ֔ם לֹא־יֹאמְר֣וּ ע֔וֹד אָב֖וֹת אָ֣כְלוּ בֹ֑סֶר וְשִׁנֵּ֥י בָנִ֖ים תִּקְהֶֽינָה׃"}},"definableWords":["days","fathers"],"peopleInVerse":[]},"30":{"text":"But every one shall die for his own iniquity: every man that eateth the sour grape, his teeth shall be set on edge.","ref":"Jeremiah 31:30","synthesized":"Instead, each will die for his own iniquity. If anyone eats the sour grapes, his own teeth will be set on edge.","sources":{"KJV":{"text":"But every one shall die for his own iniquity: every man that eateth the sour grape, his teeth shall be set on edge."},"BSB":{"text":"Instead, each will die for his own iniquity. If anyone eats the sour grapes, his own teeth will be set on edge."},"TANAKH":{"text":"But every one shall die for his own iniquity; every man that eateth the sour grapes, his teeth shall be set on edge."},"HEBREW":{"text":"כִּ֛י אִם־אִ֥ישׁ בַּעֲוֺנ֖וֹ יָמ֑וּת כָּל־הָֽאָדָ֛ם הָאֹכֵ֥ל הַבֹּ֖סֶר תִּקְהֶ֥ינָה שִׁנָּֽיו׃"}},"definableWords":["die","iniquity"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"31":{"text":"Behold, the days come, saith the LORD, that I will make a new covenant with the house of Israel, and with the house of Judah:","ref":"Jeremiah 31:31","synthesized":"Behold, the days are coming, declares the LORD, when I will make a new covenant with the house of Israel and with the house of Judah.","sources":{"KJV":{"text":"Behold, the days come, saith the LORD, that I will make a new covenant with the house of Israel, and with the house of Judah:"},"BSB":{"text":"Behold, the days are coming, declares the LORD, when I will make a new covenant with the house of Israel and with the house of Judah."},"TANAKH":{"text":"Behold, the days come, saith HaShem, that I will make a new covenant with the house of Israel, and with the house of Judah;"},"HEBREW":{"text":"הִנֵּ֛ה יָמִ֥ים בָּאִ֖ים נְאֻם־יְהוָ֑ה וְכָרַתִּ֗י אֶת־בֵּ֧ית יִשְׂרָאֵ֛ל וְאֶת־בֵּ֥ית יְהוּדָ֖ה בְּרִ֥ית חֲדָשָֽׁה׃"}},"definableWords":["days","LORD","make","covenant","house","Israel","Judah"],"peopleInVerse":[],"themesInVerse":["covenant","second_coming"]},"32":{"text":"Not according to the covenant that I made with their fathers in the day that I took them by the hand to bring them out of the land of Egypt; which my covenant they brake, although I was an husband unto them, saith the LORD:","ref":"Jeremiah 31:32","synthesized":"It will not be like the covenant I made with their fathers when I took them by the hand to lead them out of the land of Egypt— a covenant they broke, though I was a husband to them,” declares the LORD.","sources":{"KJV":{"text":"Not according to the covenant that I made with their fathers in the day that I took them by the hand to bring them out of the land of Egypt; which my covenant they brake, although I was an husband unto them, saith the LORD:"},"BSB":{"text":"It will not be like the covenant I made with their fathers when I took them by the hand to lead them out of the land of Egypt— a covenant they broke, though I was a husband to them,” declares the LORD."},"TANAKH":{"text":"not according to the covenant that I made with their fathers in the day that I took them by the hand to bring them out of the land of Egypt; forasmuch as they broke My covenant, although I was a lord over them, saith HaShem."},"HEBREW":{"text":"לֹ֣א כַבְּרִ֗ית אֲשֶׁ֤ר כָּרַ֙תִּי֙ אֶת־אֲבוֹתָ֔ם בְּיוֹם֙ הֶחֱזִיקִ֣י בְיָדָ֔ם לְהוֹצִיאָ֖ם מֵאֶ֖רֶץ מִצְרָ֑יִם אֲשֶׁר־הֵ֜מָּה הֵפֵ֣רוּ אֶת־בְּרִיתִ֗י וְאָנֹכִ֛י בָּעַ֥לְתִּי בָ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["covenant","made","fathers","land","Egypt","husband","LORD"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["covenant","creation","exodus_pattern","land_promise","marriage_bride"]},"33":{"text":"But this shall be the covenant that I will make with the house of Israel; After those days, saith the LORD, I will put my law in their inward parts, and write it in their hearts; and will be their God, and they shall be my people.","ref":"Jeremiah 31:33","synthesized":"“But this is the covenant I will make with the house of Israel after those days, declares the LORD. I will put My law in their minds and inscribe it on their hearts. And I will be their God, and they will be My people.","sources":{"KJV":{"text":"But this shall be the covenant that I will make with the house of Israel; After those days, saith the LORD, I will put my law in their inward parts, and write it in their hearts; and will be their God, and they shall be my people."},"BSB":{"text":"“But this is the covenant I will make with the house of Israel after those days, declares the LORD. I will put My law in their minds and inscribe it on their hearts. And I will be their God, and they will be My people."},"TANAKH":{"text":"But this is the covenant that I will make with the house of Israel after those days, saith HaShem, I will put My law in their inward parts, and in their heart will I write it; and I will be their G-d, and they shall be My people;"},"HEBREW":{"text":"כִּ֣י זֹ֣את הַבְּרִ֡ית אֲשֶׁ֣ר אֶכְרֹת֩ אֶת־בֵּ֨ית יִשְׂרָאֵ֜ל אַחֲרֵ֨י הַיָּמִ֤ים הָהֵם֙ נְאֻם־יְהוָ֔ה נָתַ֤תִּי אֶת־תּֽוֹרָתִי֙ בְּקִרְבָּ֔ם וְעַל־לִבָּ֖ם אֶכְתֲּבֶ֑נָּה וְהָיִ֤יתִי לָהֶם֙ לֵֽאלֹהִ֔ים וְהֵ֖מָּה יִֽהְיוּ־לִ֥י לְעָֽם׃"}},"definableWords":["covenant","make","house","Israel","days","LORD","law","God","people"],"peopleInVerse":[],"themesInVerse":["covenant"]},"34":{"text":"And they shall teach no more every man his neighbour, and every man his brother, saying, Know the LORD: for they shall all know me, from the least of them unto the greatest of them, saith the LORD: for I will forgive their iniquity, and I will remember their sin no more.","ref":"Jeremiah 31:34","synthesized":"No longer will each man teach his neighbor or his brother, saying, ‘Know the LORD,’ because they will all know Me, from the least of them to the greatest, declares the LORD. For I will forgive their iniquities and will remember their sins no more.”","sources":{"KJV":{"text":"And they shall teach no more every man his neighbour, and every man his brother, saying, Know the LORD: for they shall all know me, from the least of them unto the greatest of them, saith the LORD: for I will forgive their iniquity, and I will remember their sin no more."},"BSB":{"text":"No longer will each man teach his neighbor or his brother, saying, ‘Know the LORD,’ because they will all know Me, from the least of them to the greatest, declares the LORD. For I will forgive their iniquities and will remember their sins no more.”"},"TANAKH":{"text":"and they shall teach no more every man his neighbour, and every man his brother, saying: 'Know HaShem'; for they shall all know Me, from the least of them unto the greatest of them, saith HaShem; for I will forgive their iniquity, and their sin will I remember no more."},"HEBREW":{"text":"וְלֹ֧א יְלַמְּד֣וּ ע֗וֹד אִ֣ישׁ אֶת־רֵעֵ֜הוּ וְאִ֤ישׁ אֶת־אָחִיו֙ לֵאמֹ֔ר דְּע֖וּ אֶת־יְהוָ֑ה כִּֽי־כוּלָּם֩ יֵדְע֨וּ אוֹתִ֜י לְמִקְטַנָּ֤ם וְעַד־גְּדוֹלָם֙ נְאֻם־יְהוָ֔ה כִּ֤י אֶסְלַח֙ לַֽעֲוֺנָ֔ם וּלְחַטָּאתָ֖ם לֹ֥א אֶזְכָּר־עֽוֹד׃"}},"definableWords":["man","or","brother","LORD","Lord","forgive","remember"],"peopleInVerse":[]},"35":{"text":"Thus saith the LORD, which giveth the sun for a light by day, and the ordinances of the moon and of the stars for a light by night, which divideth the sea when the waves thereof roar; The LORD of hosts is his name:","ref":"Jeremiah 31:35","synthesized":"Thus says the LORD, who gives the sun for light by day, who sets in order the moon and stars for light by night, who stirs up the sea so that its waves roar—the LORD of Hosts is His name:","sources":{"KJV":{"text":"Thus saith the LORD, which giveth the sun for a light by day, and the ordinances of the moon and of the stars for a light by night, which divideth the sea when the waves thereof roar; The LORD of hosts is his name:"},"BSB":{"text":"Thus says the LORD, who gives the sun for light by day, who sets in order the moon and stars for light by night, who stirs up the sea so that its waves roar—the LORD of Hosts is His name:"},"TANAKH":{"text":"Thus saith HaShem, Who giveth the sun for a light by day, and the ordinances of the moon and of the stars for a light by night, who stirreth up the sea, that the waves thereof roar, HaShem of hosts is His name:"},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה נֹתֵ֥ן שֶׁ֙מֶשׁ֙ לְא֣וֹר יוֹמָ֔ם חֻקֹּ֛ת יָרֵ֥חַ וְכוֹכָבִ֖ים לְא֣וֹר לָ֑יְלָה רֹגַ֤ע הַיָּם֙ וַיֶּהֱמ֣וּ גַלָּ֔יו יְהוָ֥ה צְבָא֖וֹת שְׁמֽוֹ׃"}},"definableWords":["LORD","light","day","night","sea","Lord","name"],"peopleInVerse":[],"themesInVerse":["light_darkness"]},"36":{"text":"If those ordinances depart from before me, saith the LORD, then the seed of Israel also shall cease from being a nation before me for ever.","ref":"Jeremiah 31:36","synthesized":"“Only if this fixed order departed from My presence, declares the LORD, would Israel’s descendants ever cease to be a nation before Me.”","sources":{"KJV":{"text":"If those ordinances depart from before me, saith the LORD, then the seed of Israel also shall cease from being a nation before me for ever."},"BSB":{"text":"“Only if this fixed order departed from My presence, declares the LORD, would Israel’s descendants ever cease to be a nation before Me.”"},"TANAKH":{"text":"If these ordinances depart from before Me, saith HaShem, then the seed of Israel also shall cease from being a nation before Me for ever."},"HEBREW":{"text":"אִם־יָמֻ֜שׁוּ הַחֻקִּ֥ים הָאֵ֛לֶּה מִלְּפָנַ֖י נְאֻם־יְהוָ֑ה גַּם֩ זֶ֨רַע יִשְׂרָאֵ֜ל יִשְׁבְּת֗וּ מִֽהְי֥וֹת גּ֛וֹי לְפָנַ֖י כָּל־הַיָּמִֽים׃"}},"definableWords":["LORD","Israel","nation"],"peopleInVerse":[]},"37":{"text":"Thus saith the LORD; If heaven above can be measured, and the foundations of the earth searched out beneath, I will also cast off all the seed of Israel for all that they have done, saith the LORD.","ref":"Jeremiah 31:37","synthesized":"This is what the LORD says:  “Only if the heavens above could be measured and the foundations of the earth below searched out would I reject all of Israel’s descendants because of all they have done,” declares the LORD.","sources":{"KJV":{"text":"Thus saith the LORD; If heaven above can be measured, and the foundations of the earth searched out beneath, I will also cast off all the seed of Israel for all that they have done, saith the LORD."},"BSB":{"text":"This is what the LORD says:  “Only if the heavens above could be measured and the foundations of the earth below searched out would I reject all of Israel’s descendants because of all they have done,” declares the LORD."},"TANAKH":{"text":"Thus saith HaShem: If heaven above can be measured, and the foundations of the earth searched out beneath, then will I also cast off all the seed of Israel for all that they have done, saith HaShem."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה אִם־יִמַּ֤דּוּ שָׁמַ֙יִם֙ מִלְמַ֔עְלָה וְיֵחָקְר֥וּ מֽוֹסְדֵי־אֶ֖רֶץ לְמָ֑טָּה גַּם־אֲנִ֞י אֶמְאַ֨ס בְּכָל־זֶ֧רַע יִשְׂרָאֵ֛ל עַֽל־כָּל־אֲשֶׁ֥ר עָשׂ֖וּ נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD","heavens","earth","Israel","Lord"],"peopleInVerse":[]},"38":{"text":"Behold, the days come, saith the LORD, that the city shall be built to the LORD from the tower of Hananeel unto the gate of the corner.","ref":"Jeremiah 31:38","synthesized":"“The days are coming,” declares the LORD, “when this city will be rebuilt for Me, from the tower of Hananel to the Corner Gate.","sources":{"KJV":{"text":"Behold, the days come, saith the LORD, that the city shall be built to the LORD from the tower of Hananeel unto the gate of the corner."},"BSB":{"text":"“The days are coming,” declares the LORD, “when this city will be rebuilt for Me, from the tower of Hananel to the Corner Gate."},"TANAKH":{"text":"Behold, the days come, saith HaShem, that the city shall be built to HaShem from the tower of Hananel unto the gate of the corner."},"HEBREW":{"text":"הִנֵּ֛ה יָמִ֥ים בָּאִ֖ים נְאֻם־יְהוָ֑ה וְנִבְנְתָ֤ה הָעִיר֙ לַֽיהוָ֔ה מִמִּגְדַּ֥ל חֲנַנְאֵ֖ל שַׁ֥עַר הַפִּנָּֽה׃"}},"definableWords":["days","LORD"],"peopleInVerse":[],"themesInVerse":["second_coming"]},"39":{"text":"And the measuring line shall yet go forth over against it upon the hill Gareb, and shall compass about to Goath.","ref":"Jeremiah 31:39","synthesized":"The measuring line will once again stretch out straight to the hill of Gareb and then turn toward Goah.","sources":{"KJV":{"text":"And the measuring line shall yet go forth over against it upon the hill Gareb, and shall compass about to Goath."},"BSB":{"text":"The measuring line will once again stretch out straight to the hill of Gareb and then turn toward Goah."},"TANAKH":{"text":"And the measuring line shall yet go out straight forward unto the hill Gareb, and shall turn about unto Goah."},"HEBREW":{"text":"וְיָצָ֨א ע֜וֹד קוה קָ֤ו הַמִּדָּה֙ נֶגְדּ֔וֹ עַ֖ל גִּבְעַ֣ת גָּרֵ֑ב וְנָסַ֖ב גֹּעָֽתָה׃"}},"definableWords":[],"peopleInVerse":[]},"40":{"text":"And the whole valley of the dead bodies, and of the ashes, and all the fields unto the brook of Kidron, unto the corner of the horse gate toward the east, shall be holy unto the LORD; it shall not be plucked up, nor thrown down any more for ever.","ref":"Jeremiah 31:40","synthesized":"The whole valley of the dead bodies and ashes, and all the fields as far as the Kidron Valley, to the corner of the Horse Gate to the east, will be holy to the LORD. It will never again be uprooted or demolished.”","sources":{"KJV":{"text":"And the whole valley of the dead bodies, and of the ashes, and all the fields unto the brook of Kidron, unto the corner of the horse gate toward the east, shall be holy unto the LORD; it shall not be plucked up, nor thrown down any more for ever."},"BSB":{"text":"The whole valley of the dead bodies and ashes, and all the fields as far as the Kidron Valley, to the corner of the Horse Gate to the east, will be holy to the LORD. It will never again be uprooted or demolished.”"},"TANAKH":{"text":"And the whole valley of the dead bodies, and of the ashes, and all the fields unto the brook Kidron, unto the corner of the horse gate toward the east, shall be holy unto HaShem; it shall not be plucked up, nor thrown down any more for ever."},"HEBREW":{"text":"וְכָל־הָעֵ֣מֶק הַפְּגָרִ֣ים ׀ וְהַדֶּ֡שֶׁן וְכָֽל־השרמות הַשְּׁדֵמוֹת֩ עַד־נַ֨חַל קִדְר֜וֹן עַד־פִּנַּ֨ת שַׁ֤עַר הַסּוּסִים֙ מִזְרָ֔חָה קֹ֖דֶשׁ לַֽיהוָ֑ה לֹֽא־יִנָּתֵ֧שׁ וְֽלֹא־יֵהָרֵ֛ס ע֖וֹד לְעוֹלָֽם׃"}},"definableWords":["holy","LORD","or"],"peopleInVerse":[]}}},"32":{"chapter":"32","title":"JEREMIAH BUYS A FIELD IN ANATHOTH","verses":{"1":{"text":"The word that came to Jeremiah from the LORD in the tenth year of Zedekiah king of Judah, which was the eighteenth year of Nebuchadrezzar.","ref":"Jeremiah 32:1","synthesized":"This is the word that came to Jeremiah from the LORD in the tenth year of Zedekiah king of Judah, which was the eighteenth year of Nebuchadnezzar.","sources":{"KJV":{"text":"The word that came to Jeremiah from the LORD in the tenth year of Zedekiah king of Judah, which was the eighteenth year of Nebuchadrezzar."},"BSB":{"text":"This is the word that came to Jeremiah from the LORD in the tenth year of Zedekiah king of Judah, which was the eighteenth year of Nebuchadnezzar."},"TANAKH":{"text":"The word that came to Jeremiah from HaShem in the tenth year of Zedekiah king of Judah, which was the eighteenth year of Nebuchadrezzar."},"HEBREW":{"text":"הַדָּבָ֞ר אֲשֶׁר־הָיָ֤ה אֶֽל־יִרְמְיָ֙הוּ֙ מֵאֵ֣ת יְהוָ֔ה בשנת בַּשָּׁנָה֙ הָעֲשִׂרִ֔ית לְצִדְקִיָּ֖הוּ מֶ֣לֶךְ יְהוּדָ֑ה הִ֧יא הַשָּׁנָ֛ה שְׁמֹנֶֽה־עֶשְׂרֵ֥ה שָׁנָ֖ה לִנְבֽוּכַדְרֶאצַּֽר׃"}},"definableWords":["word","LORD","year","king","Judah"],"peopleInVerse":["Jeremiah","Nebuchadnezzar"],"themesInVerse":["kingship"]},"2":{"text":"For then the king of Babylon’s army besieged Jerusalem: and Jeremiah the prophet was shut up in the court of the prison, which was in the king of Judah’s house.","ref":"Jeremiah 32:2","synthesized":"At that time the army of the king of Babylon was besieging Jerusalem, and Jeremiah the prophet was imprisoned in the courtyard of the guard, which was in the palace of the king of Judah.","sources":{"KJV":{"text":"For then the king of Babylon’s army besieged Jerusalem: and Jeremiah the prophet was shut up in the court of the prison, which was in the king of Judah’s house."},"BSB":{"text":"At that time the army of the king of Babylon was besieging Jerusalem, and Jeremiah the prophet was imprisoned in the courtyard of the guard, which was in the palace of the king of Judah."},"TANAKH":{"text":"Now at that time the king of Babylon's army was besieging Jerusalem; and Jeremiah the prophet was shut up in the court of the guard, which was in the king of Judah's house."},"HEBREW":{"text":"וְאָ֗ז חֵ֚יל מֶ֣לֶךְ בָּבֶ֔ל צָרִ֖ים עַל־יְרוּשָׁלָ֑͏ִם וְיִרְמְיָ֣הוּ הַנָּבִ֗יא הָיָ֤ה כָלוּא֙ בַּחֲצַ֣ר הַמַּטָּרָ֔ה אֲשֶׁ֖ר בֵּֽית־מֶ֥לֶךְ יְהוּדָֽה׃"}},"definableWords":["king","Babylon","Jerusalem","prophet","King","Judah"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Babylon","Jerusalem"],"themesInVerse":["kingship"]},"3":{"text":"For Zedekiah king of Judah had shut him up, saying, Wherefore dost thou prophesy, and say, Thus saith the LORD, Behold, I will give this city into the hand of the king of Babylon, and he shall take it;","ref":"Jeremiah 32:3","synthesized":"For Zedekiah king of Judah had imprisoned him, saying: “Why are you prophesying like this? You claim that the LORD says, ‘Behold, I am about to deliver this city into the hand of the king of Babylon, and he will capture it.","sources":{"KJV":{"text":"For Zedekiah king of Judah had shut him up, saying, Wherefore dost thou prophesy, and say, Thus saith the LORD, Behold, I will give this city into the hand of the king of Babylon, and he shall take it;"},"BSB":{"text":"For Zedekiah king of Judah had imprisoned him, saying: “Why are you prophesying like this? You claim that the LORD says, ‘Behold, I am about to deliver this city into the hand of the king of Babylon, and he will capture it."},"TANAKH":{"text":"For Zedekiah king of Judah had shut him up, saying: 'Wherefore dost thou prophesy, and say: Thus saith HaShem: Behold, I will give this city into the hand of the king of Babylon, and he shall take it;"},"HEBREW":{"text":"אֲשֶׁ֣ר כְּלָא֔וֹ צִדְקִיָּ֥הוּ מֶֽלֶךְ־יְהוּדָ֖ה לֵאמֹ֑ר מַדּוּעַ֩ אַתָּ֨ה נִבָּ֜א לֵאמֹ֗ר כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִנְנִ֨י נֹתֵ֜ן אֶת־הָעִ֥יר הַזֹּ֛את בְּיַ֥ד מֶֽלֶךְ־בָּבֶ֖ל וּלְכָדָֽהּ׃"}},"definableWords":["king","Judah","LORD","deliver","King","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship","redemption","salvation"]},"4":{"text":"And Zedekiah king of Judah shall not escape out of the hand of the Chaldeans, but shall surely be delivered into the hand of the king of Babylon, and shall speak with him mouth to mouth, and his eyes shall behold his eyes;","ref":"Jeremiah 32:4","synthesized":"Zedekiah king of Judah will not escape from the hands of the Chaldeans, but he will surely be delivered into the hand of the king of Babylon, and will speak with him face to face and see him eye to eye.","sources":{"KJV":{"text":"And Zedekiah king of Judah shall not escape out of the hand of the Chaldeans, but shall surely be delivered into the hand of the king of Babylon, and shall speak with him mouth to mouth, and his eyes shall behold his eyes;"},"BSB":{"text":"Zedekiah king of Judah will not escape from the hands of the Chaldeans, but he will surely be delivered into the hand of the king of Babylon, and will speak with him face to face and see him eye to eye."},"TANAKH":{"text":"and Zedekiah king of Judah shall not escape out of the hand of the Chaldeans, but shall surely be delivered into the hand of the king of Babylon, and shall speak with him mouth to mouth, and his eyes shall behold his eyes;"},"HEBREW":{"text":"וְצִדְקִיָּ֙הוּ֙ מֶ֣לֶךְ יְהוּדָ֔ה לֹ֥א יִמָּלֵ֖ט מִיַּ֣ד הַכַּשְׂדִּ֑ים כִּ֣י הִנָּתֹ֤ן יִנָּתֵן֙ בְּיַ֣ד מֶֽלֶךְ־בָּבֶ֔ל וְדִבֶּר־פִּ֣יו עִם־פִּ֔יו וְעֵינָ֖יו אֶת־עינו עֵינָ֥יו תִּרְאֶֽינָה׃"}},"definableWords":["king","Judah","King","Babylon","see"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"5":{"text":"And he shall lead Zedekiah to Babylon, and there shall he be until I visit him, saith the LORD: though ye fight with the Chaldeans, ye shall not prosper.","ref":"Jeremiah 32:5","synthesized":"He will take Zedekiah to Babylon, where he will stay until I attend to him, declares the LORD. If you fight against the Chaldeans, you will not succeed.’”","sources":{"KJV":{"text":"And he shall lead Zedekiah to Babylon, and there shall he be until I visit him, saith the LORD: though ye fight with the Chaldeans, ye shall not prosper."},"BSB":{"text":"He will take Zedekiah to Babylon, where he will stay until I attend to him, declares the LORD. If you fight against the Chaldeans, you will not succeed.’”"},"TANAKH":{"text":"and he shall lead Zedekiah to Babylon, and there shall he be until I remember him, saith HaShem; though ye fight with the Chaldeans, ye shall not prosper?'"},"HEBREW":{"text":"וּבָבֶ֞ל יוֹלִ֤ךְ אֶת־צִדְקִיָּ֙הוּ֙ וְשָׁ֣ם יִֽהְיֶ֔ה עַד־פָּקְדִ֥י אֹת֖וֹ נְאֻם־יְהוָ֑ה כִּ֧י תִֽלָּחֲמ֛וּ אֶת־הַכַּשְׂדִּ֖ים לֹ֥א תַצְלִֽיחוּ׃"}},"definableWords":["Babylon","LORD","fight"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["spiritual_warfare"]},"6":{"text":"And Jeremiah said, The word of the LORD came unto me, saying,","ref":"Jeremiah 32:6","synthesized":"Jeremiah replied, “The word of the LORD came to me, saying:","sources":{"KJV":{"text":"And Jeremiah said, The word of the LORD came unto me, saying,"},"BSB":{"text":"Jeremiah replied, “The word of the LORD came to me, saying:"},"TANAKH":{"text":"And Jeremiah said: 'The word of HaShem came unto me, saying:"},"HEBREW":{"text":"וַיֹּ֖אמֶר יִרְמְיָ֑הוּ הָיָ֥ה דְּבַר־יְהוָ֖ה אֵלַ֥י לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"7":{"text":"Behold, Hanameel the son of Shallum thine uncle shall come unto thee, saying, Buy thee my field that is in Anathoth: for the right of redemption is thine to buy it.","ref":"Jeremiah 32:7","synthesized":"Behold! Hanamel, the son of your uncle Shallum, is coming to you to say, ‘Buy for yourself my field in Anathoth, for you have the right of redemption to buy it.’","sources":{"KJV":{"text":"Behold, Hanameel the son of Shallum thine uncle shall come unto thee, saying, Buy thee my field that is in Anathoth: for the right of redemption is thine to buy it."},"BSB":{"text":"Behold! Hanamel, the son of your uncle Shallum, is coming to you to say, ‘Buy for yourself my field in Anathoth, for you have the right of redemption to buy it.’"},"TANAKH":{"text":"Behold, Hanamel, the son of Shallum thine uncle, shall come unto thee, saying: Buy thee my field that is in Anathoth; for the right of redemption is thine to buy it.'"},"HEBREW":{"text":"הִנֵּ֣ה חֲנַמְאֵ֗ל בֶּן־שַׁלֻּם֙ דֹּֽדְךָ֔ בָּ֥א אֵלֶ֖יךָ לֵאמֹ֑ר קְנֵ֣ה לְךָ֗ אֶת־שָׂדִי֙ אֲשֶׁ֣ר בַּעֲנָת֔וֹת כִּ֥י לְךָ֛ מִשְׁפַּ֥ט הַגְּאֻלָּ֖ה לִקְנֽוֹת׃"}},"definableWords":["son","field","redemption"],"peopleInVerse":[],"themesInVerse":["second_coming"]},"8":{"text":"So Hanameel mine uncle’s son came to me in the court of the prison according to the word of the LORD, and said unto me, Buy my field, I pray thee, that is in Anathoth, which is in the country of Benjamin: for the right of inheritance is thine, and the redemption is thine; buy it for thyself. Then I knew that this was the word of the LORD.","ref":"Jeremiah 32:8","synthesized":"Then, as the LORD had said, my cousin Hanamel came to me in the courtyard of the guard and urged me, ‘Please buy my field in Anathoth in the land of Benjamin, for you own the right of inheritance and redemption. Buy it for yourself.’”  Then I knew that this was the word of the LORD.","sources":{"KJV":{"text":"So Hanameel mine uncle’s son came to me in the court of the prison according to the word of the LORD, and said unto me, Buy my field, I pray thee, that is in Anathoth, which is in the country of Benjamin: for the right of inheritance is thine, and the redemption is thine; buy it for thyself. Then I knew that this was the word of the LORD."},"BSB":{"text":"Then, as the LORD had said, my cousin Hanamel came to me in the courtyard of the guard and urged me, ‘Please buy my field in Anathoth in the land of Benjamin, for you own the right of inheritance and redemption. Buy it for yourself.’”  Then I knew that this was the word of the LORD."},"TANAKH":{"text":"So Hanamel mine uncle's son came to me in the court of the guard according to the word of HaShem, and said unto me: 'Buy my field, I pray thee, that is in Anathoth, which is in the land of Benjamin; for the right of inheritance is thine, and the redemption is thine; buy it for thyself.' Then I knew that this was the word of HaShem."},"HEBREW":{"text":"וַיָּבֹ֣א אֵ֠לַי חֲנַמְאֵ֨ל בֶּן־דֹּדִ֜י כִּדְבַ֣ר יְהוָה֮ אֶל־חֲצַ֣ר הַמַּטָּרָה֒ וַיֹּ֣אמֶר אֵלַ֡י קְנֵ֣ה נָ֠א אֶת־שָׂדִ֨י אֲשֶׁר־בַּעֲנָת֜וֹת אֲשֶׁ֣ר ׀ בְּאֶ֣רֶץ בִּנְיָמִ֗ין כִּֽי־לְךָ֞ מִשְׁפַּ֧ט הַיְרֻשָּׁ֛ה וּלְךָ֥ הַגְּאֻלָּ֖ה קְנֵה־לָ֑ךְ וָאֵדַ֕ע כִּ֥י דְבַר־יְהוָ֖ה הֽוּא׃"}},"definableWords":["LORD","field","land","Benjamin","redemption","word","Lord"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"9":{"text":"And I bought the field of Hanameel my uncle’s son, that was in Anathoth, and weighed him the money, even seventeen shekels of silver.","ref":"Jeremiah 32:9","synthesized":"So I bought the field in Anathoth from my cousin Hanamel, and I weighed out seventeen shekels of silver.","sources":{"KJV":{"text":"And I bought the field of Hanameel my uncle’s son, that was in Anathoth, and weighed him the money, even seventeen shekels of silver."},"BSB":{"text":"So I bought the field in Anathoth from my cousin Hanamel, and I weighed out seventeen shekels of silver."},"TANAKH":{"text":"And I bought the field that was in Anathoth of Hanamel mine uncle's son, and weighed him the money, even seventeen shekels of silver."},"HEBREW":{"text":"וָֽאֶקְנֶה֙ אֶת־הַשָּׂדֶ֔ה מֵאֵ֛ת חֲנַמְאֵ֥ל בֶּן־דֹּדִ֖י אֲשֶׁ֣ר בַּעֲנָת֑וֹת וָֽאֶשְׁקֲלָה־לּוֹ֙ אֶת־הַכֶּ֔סֶף שִׁבְעָ֥ה שְׁקָלִ֖ים וַעֲשָׂרָ֥ה הַכָּֽסֶף׃"}},"definableWords":["field"],"peopleInVerse":[]},"10":{"text":"And I subscribed the evidence, and sealed it, and took witnesses, and weighed him the money in the balances.","ref":"Jeremiah 32:10","synthesized":"I signed and sealed the deed, called in witnesses, and weighed out the silver on the scales.","sources":{"KJV":{"text":"And I subscribed the evidence, and sealed it, and took witnesses, and weighed him the money in the balances."},"BSB":{"text":"I signed and sealed the deed, called in witnesses, and weighed out the silver on the scales."},"TANAKH":{"text":"And I subscribed the deed, and sealed it, and called witnesses, and weighed him the money in the balances."},"HEBREW":{"text":"וָאֶכְתֹּ֤ב בַּסֵּ֙פֶר֙ וָֽאֶחְתֹּ֔ם וָאָעֵ֖ד עֵדִ֑ים וָאֶשְׁקֹ֥ל הַכֶּ֖סֶף בְּמֹאזְנָֽיִם׃"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"So I took the evidence of the purchase, both that which was sealed according to the law and custom, and that which was open:","ref":"Jeremiah 32:11","synthesized":"Then I took the deed of purchase—the sealed copy with its terms and conditions, as well as the open copy—","sources":{"KJV":{"text":"So I took the evidence of the purchase, both that which was sealed according to the law and custom, and that which was open:"},"BSB":{"text":"Then I took the deed of purchase—the sealed copy with its terms and conditions, as well as the open copy—"},"TANAKH":{"text":"So I took the deed of the purchase, both that which was sealed, containing the terms and conditions, and that which was open;"},"HEBREW":{"text":"וָאֶקַּ֖ח אֶת־סֵ֣פֶר הַמִּקְנָ֑ה אֶת־הֶֽחָת֛וּם הַמִּצְוָ֥ה וְהַחֻקִּ֖ים וְאֶת־הַגָּלֽוּי׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["bread_water_life","redemption"]},"12":{"text":"And I gave the evidence of the purchase unto Baruch the son of Neriah, the son of Maaseiah, in the sight of Hanameel mine uncle’s son, and in the presence of the witnesses that subscribed the book of the purchase, before all the Jews that sat in the court of the prison.","ref":"Jeremiah 32:12","synthesized":"and I gave this deed to Baruch son of Neriah, the son of Mahseiah, in the sight of my cousin Hanamel and the witnesses who were signing the purchase agreement and all the Jews sitting in the courtyard of the guard.","sources":{"KJV":{"text":"And I gave the evidence of the purchase unto Baruch the son of Neriah, the son of Maaseiah, in the sight of Hanameel mine uncle’s son, and in the presence of the witnesses that subscribed the book of the purchase, before all the Jews that sat in the court of the prison."},"BSB":{"text":"and I gave this deed to Baruch son of Neriah, the son of Mahseiah, in the sight of my cousin Hanamel and the witnesses who were signing the purchase agreement and all the Jews sitting in the courtyard of the guard."},"TANAKH":{"text":"and I delivered the deed of the purchase unto Baruch the son of Neriah, the son of Mahseiah, in the presence of Hanamel mine uncle 's son, and in the presence of the witnesses that subscribed the deed of the purchase, before all the Jews that sat in the court of the guard."},"HEBREW":{"text":"וָאֶתֵּ֞ן אֶת־הַסֵּ֣פֶר הַמִּקְנָ֗ה אֶל־בָּר֣וּךְ בֶּן־נֵרִיָּה֮ בֶּן־מַחְסֵיָה֒ לְעֵינֵי֙ חֲנַמְאֵ֣ל דֹּדִ֔י וּלְעֵינֵי֙ הָֽעֵדִ֔ים הַכֹּתְבִ֖ים בְּסֵ֣פֶר הַמִּקְנָ֑ה לְעֵינֵי֙ כָּל־הַיְּהוּדִ֔ים הַיֹּשְׁבִ֖ים בַּחֲצַ֥ר הַמַּטָּרָֽה׃"}},"definableWords":["baruch","son","Son"],"peopleInVerse":[],"themesInVerse":["redemption"]},"13":{"text":"And I charged Baruch before them, saying,","ref":"Jeremiah 32:13","synthesized":"In their sight I instructed Baruch,","sources":{"KJV":{"text":"And I charged Baruch before them, saying,"},"BSB":{"text":"In their sight I instructed Baruch,"},"TANAKH":{"text":"And I charged Baruch before them, saying:"},"HEBREW":{"text":"וֽ͏ָאֲצַוֶּה֙ אֶת בָּר֔וּךְ לְעֵינֵיהֶ֖ם לֵאמֹֽר׃"}},"definableWords":["baruch"],"peopleInVerse":[]},"14":{"text":"Thus saith the LORD of hosts, the God of Israel; Take these evidences, this evidence of the purchase, both which is sealed, and this evidence which is open; and put them in an earthen vessel, that they may continue many days.","ref":"Jeremiah 32:14","synthesized":"“This is what the LORD of Hosts, the God of Israel, says: Take these deeds—both the sealed copy and the open copy of the deed of purchase—and put them in a clay jar to preserve them for a long time.","sources":{"KJV":{"text":"Thus saith the LORD of hosts, the God of Israel; Take these evidences, this evidence of the purchase, both which is sealed, and this evidence which is open; and put them in an earthen vessel, that they may continue many days."},"BSB":{"text":"“This is what the LORD of Hosts, the God of Israel, says: Take these deeds—both the sealed copy and the open copy of the deed of purchase—and put them in a clay jar to preserve them for a long time."},"TANAKH":{"text":"'Thus saith HaShem of hosts, the G-d of Israel: Take these deeds, this deed of the purchase, both that which is sealed, and this deed which is open, and put them in an earthen vessel; that they may continue many days."},"HEBREW":{"text":"כֹּֽה־אָמַר֩ יְהוָ֨ה צְבָא֜וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֗ל לָק֣וֹחַ אֶת־הַסְּפָרִ֣ים הָאֵ֡לֶּה אֵ֣ת סֵפֶר֩ הַמִּקְנָ֨ה הַזֶּ֜ה וְאֵ֣ת הֶחָת֗וּם וְאֵ֨ת סֵ֤פֶר הַגָּלוּי֙ הַזֶּ֔ה וּנְתַתָּ֖ם בִּכְלִי־חָ֑רֶשׂ לְמַ֥עַן יַעַמְד֖וּ יָמִ֥ים רַבִּֽים׃"}},"definableWords":["LORD","God","Israel"],"peopleInVerse":[],"themesInVerse":["redemption"]},"15":{"text":"For thus saith the LORD of hosts, the God of Israel; Houses and fields and vineyards shall be possessed again in this land.","ref":"Jeremiah 32:15","synthesized":"For this is what the LORD of Hosts, the God of Israel, says: Houses, fields, and vineyards will again be bought in this land.”","sources":{"KJV":{"text":"For thus saith the LORD of hosts, the God of Israel; Houses and fields and vineyards shall be possessed again in this land."},"BSB":{"text":"For this is what the LORD of Hosts, the God of Israel, says: Houses, fields, and vineyards will again be bought in this land.”"},"TANAKH":{"text":"For thus saith HaShem of hosts, the G-d of Israel: Houses and fields and vineyards shall yet again be bought in this land.'"},"HEBREW":{"text":"כִּ֣י כֹ֥ה אָמַ֛ר יְהוָ֥ה צְבָא֖וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֑ל ע֣וֹד יִקָּנ֥וּ בָתִּ֛ים וְשָׂד֥וֹת וּכְרָמִ֖ים בָּאָ֥רֶץ הַזֹּֽאת׃"}},"definableWords":["LORD","God","Israel","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"16":{"text":"Now when I had delivered the evidence of the purchase unto Baruch the son of Neriah, I prayed unto the LORD, saying,","ref":"Jeremiah 32:16","synthesized":"After I had given the deed of purchase to Baruch son of Neriah, I prayed to the LORD:","sources":{"KJV":{"text":"Now when I had delivered the evidence of the purchase unto Baruch the son of Neriah, I prayed unto the LORD, saying,"},"BSB":{"text":"After I had given the deed of purchase to Baruch son of Neriah, I prayed to the LORD:"},"TANAKH":{"text":"Now after I had delivered the deed of the purchase unto Baruch the son of Neriah, I prayed unto HaShem, saying:"},"HEBREW":{"text":"וָאֶתְפַּלֵּ֖ל אֶל־יְהוָ֑ה אַחֲרֵ֤י תִתִּי֙ אֶת־סֵ֣פֶר הַמִּקְנָ֔ה אֶל־בָּר֥וּךְ בֶּן־נֵרִיָּ֖ה לֵאמֹֽר׃"}},"definableWords":["baruch","son","LORD"],"peopleInVerse":[],"themesInVerse":["redemption"]},"17":{"text":"Ah Lord GOD! behold, thou hast made the heaven and the earth by thy great power and stretched out arm, and there is nothing too hard for thee:","ref":"Jeremiah 32:17","synthesized":"“Oh, Lord GOD! You have made the heavens and the earth by Your great power and outstretched arm. Nothing is too difficult for You!","sources":{"KJV":{"text":"Ah Lord GOD! behold, thou hast made the heaven and the earth by thy great power and stretched out arm, and there is nothing too hard for thee:"},"BSB":{"text":"“Oh, Lord GOD! You have made the heavens and the earth by Your great power and outstretched arm. Nothing is too difficult for You!"},"TANAKH":{"text":"'Ah L-rd GOD! behold, Thou hast made the heaven and the earth by Thy great power and by Thy outstretched arm; there is nothing too hard for Thee;"},"HEBREW":{"text":"אֲהָהּ֮ אֲדֹנָ֣י יְהוִה֒ הִנֵּ֣ה ׀ אַתָּ֣ה עָשִׂ֗יתָ אֶת־הַשָּׁמַ֙יִם֙ וְאֶת־הָאָ֔רֶץ בְּכֹֽחֲךָ֙ הַגָּד֔וֹל וּבִֽזְרֹעֲךָ֖ הַנְּטוּיָ֑ה לֹֽא־יִפָּלֵ֥א מִמְּךָ֖ כָּל־דָּבָֽר׃"}},"definableWords":["Lord","God","made","heavens","earth","great"],"peopleInVerse":[],"themesInVerse":["creation"]},"18":{"text":"Thou shewest lovingkindness unto thousands, and recompensest the iniquity of the fathers into the bosom of their children after them: the Great, the Mighty God, the LORD of hosts, is his name,","ref":"Jeremiah 32:18","synthesized":"You show loving devotion to thousands but lay the iniquity of the fathers into the laps of their children after them, O great and mighty God whose name is the LORD of Hosts,","sources":{"KJV":{"text":"Thou shewest lovingkindness unto thousands, and recompensest the iniquity of the fathers into the bosom of their children after them: the Great, the Mighty God, the LORD of hosts, is his name,"},"BSB":{"text":"You show loving devotion to thousands but lay the iniquity of the fathers into the laps of their children after them, O great and mighty God whose name is the LORD of Hosts,"},"TANAKH":{"text":"who showest mercy unto thousands, and recompensest the iniquity of the fathers into the bosom of their children after them; the great, the mighty G-d, HaShem of hosts is His name;"},"HEBREW":{"text":"עֹ֤שֶׂה חֶ֙סֶד֙ לַֽאֲלָפִ֔ים וּמְשַׁלֵּם֙ עֲוֺ֣ן אָב֔וֹת אֶל־חֵ֥יק בְּנֵיהֶ֖ם אַחֲרֵיהֶ֑ם הָאֵ֤ל הַגָּדוֹל֙ הַגִּבּ֔וֹר יְהוָ֥ה צְבָא֖וֹת שְׁמֽוֹ׃"}},"definableWords":["iniquity","fathers","great","mighty","God","name","LORD"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"19":{"text":"Great in counsel, and mighty in work: for thine eyes are open upon all the ways of the sons of men: to give every one according to his ways, and according to the fruit of his doings:","ref":"Jeremiah 32:19","synthesized":"the One great in counsel and mighty in deed, whose eyes are on all the ways of the sons of men, to reward each one according to his ways and according to the fruit of his deeds.","sources":{"KJV":{"text":"Great in counsel, and mighty in work: for thine eyes are open upon all the ways of the sons of men: to give every one according to his ways, and according to the fruit of his doings:"},"BSB":{"text":"the One great in counsel and mighty in deed, whose eyes are on all the ways of the sons of men, to reward each one according to his ways and according to the fruit of his deeds."},"TANAKH":{"text":"great in counsel, and mighty in work; whose eyes are open upon all the ways of the sons of men, to give every one according to his ways, and according to the fruit of his doings;"},"HEBREW":{"text":"גְּדֹל֙ הָֽעֵצָ֔ה וְרַ֖ב הָעֲלִֽילִיָּ֑ה אֲשֶׁר־עֵינֶ֣יךָ פְקֻח֗וֹת עַל־כָּל־דַּרְכֵי֙ בְּנֵ֣י אָדָ֔ם לָתֵ֤ת לְאִישׁ֙ כִּדְרָכָ֔יו וְכִפְרִ֖י מַעֲלָלָֽיו׃"}},"definableWords":["one","great","mighty","sons","men"],"peopleInVerse":[],"themesInVerse":["vine_branches"]},"20":{"text":"Which hast set signs and wonders in the land of Egypt, even unto this day, and in Israel, and among other men; and hast made thee a name, as at this day;","ref":"Jeremiah 32:20","synthesized":"You performed signs and wonders in the land of Egypt, and You do so to this very day, both in Israel and among all mankind. And You have made a name for Yourself, as is the case to this day.","sources":{"KJV":{"text":"Which hast set signs and wonders in the land of Egypt, even unto this day, and in Israel, and among other men; and hast made thee a name, as at this day;"},"BSB":{"text":"You performed signs and wonders in the land of Egypt, and You do so to this very day, both in Israel and among all mankind. And You have made a name for Yourself, as is the case to this day."},"TANAKH":{"text":"who didst set signs and wonders in the land of Egypt, even unto this day, and in Israel and among other men; and madest Thee a name, as at this day;"},"HEBREW":{"text":"אֲשֶׁר־שַׂ֠מְתָּ אֹת֨וֹת וּמֹפְתִ֤ים בְּאֶֽרֶץ־מִצְרַ֙יִם֙ עַד־הַיּ֣וֹם הַזֶּ֔ה וּבְיִשְׂרָאֵ֖ל וּבָֽאָדָ֑ם וַתַּעֲשֶׂה־לְּךָ֥ שֵׁ֖ם כַּיּ֥וֹם הַזֶּֽה׃"}},"definableWords":["land","Egypt","day","Israel","made","name"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["creation","exodus_pattern","land_promise"]},"21":{"text":"And hast brought forth thy people Israel out of the land of Egypt with signs, and with wonders, and with a strong hand, and with a stretched out arm, and with great terror;","ref":"Jeremiah 32:21","synthesized":"You brought Your people Israel out of the land of Egypt with signs and wonders, with a strong hand and an outstretched arm, and with great terror.","sources":{"KJV":{"text":"And hast brought forth thy people Israel out of the land of Egypt with signs, and with wonders, and with a strong hand, and with a stretched out arm, and with great terror;"},"BSB":{"text":"You brought Your people Israel out of the land of Egypt with signs and wonders, with a strong hand and an outstretched arm, and with great terror."},"TANAKH":{"text":"and didst bring forth Thy people Israel out of the land of Egypt with signs, and with wonders, and with a strong hand, and with an outstretched arm, and with great terror;"},"HEBREW":{"text":"וַתֹּצֵ֛א אֶת־עַמְּךָ֥ אֶת־יִשְׂרָאֵ֖ל מֵאֶ֣רֶץ מִצְרָ֑יִם בְּאֹת֣וֹת וּבְמוֹפְתִ֗ים וּבְיָ֤ד חֲזָקָה֙ וּבְאֶזְר֣וֹעַ נְטוּיָ֔ה וּבְמוֹרָ֖א גָּדֽוֹל׃"}},"definableWords":["people","Israel","land","Egypt","strong","great"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"22":{"text":"And hast given them this land, which thou didst swear to their fathers to give them, a land flowing with milk and honey;","ref":"Jeremiah 32:22","synthesized":"You gave them this land that You had sworn to give their fathers, a land flowing with milk and honey.","sources":{"KJV":{"text":"And hast given them this land, which thou didst swear to their fathers to give them, a land flowing with milk and honey;"},"BSB":{"text":"You gave them this land that You had sworn to give their fathers, a land flowing with milk and honey."},"TANAKH":{"text":"and gavest them this land, which Thou didst swear to their fathers to give them, a land flowing with milk and honey;"},"HEBREW":{"text":"וַתִּתֵּ֤ן לָהֶם֙ אֶת־הָאָ֣רֶץ הַזֹּ֔את אֲשֶׁר־נִשְׁבַּ֥עְתָּ לַאֲבוֹתָ֖ם לָתֵ֣ת לָהֶ֑ם אֶ֛רֶץ זָבַ֥ת חָלָ֖ב וּדְבָֽשׁ׃"}},"definableWords":["land","fathers"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"23":{"text":"And they came in, and possessed it; but they obeyed not thy voice, neither walked in thy law; they have done nothing of all that thou commandedst them to do: therefore thou hast caused all this evil to come upon them:","ref":"Jeremiah 32:23","synthesized":"They came in and possessed it, but they did not obey Your voice or walk in Your law. They failed to perform all that You commanded them to do, and so You have brought upon them all this disaster.","sources":{"KJV":{"text":"And they came in, and possessed it; but they obeyed not thy voice, neither walked in thy law; they have done nothing of all that thou commandedst them to do: therefore thou hast caused all this evil to come upon them:"},"BSB":{"text":"They came in and possessed it, but they did not obey Your voice or walk in Your law. They failed to perform all that You commanded them to do, and so You have brought upon them all this disaster."},"TANAKH":{"text":"and they came in, and possessed it; but they hearkened not to Thy voice, neither walked in Thy law; they have done nothing of all that Thou commandedst them to do; therefore Thou hast caused all this evil to befall them;"},"HEBREW":{"text":"וַיָּבֹ֜אוּ וַיִּֽרְשׁ֣וּ אֹתָ֗הּ וְלֹֽא־שָׁמְע֤וּ בְקוֹלֶ֙ךָ֙ ובתרותך וּבְתוֹרָתְךָ֣ לֹא־הָלָ֔כוּ אֵת֩ כָּל־אֲשֶׁ֨ר צִוִּ֧יתָה לָהֶ֛ם לַעֲשׂ֖וֹת לֹ֣א עָשׂ֑וּ וַתַּקְרֵ֣א אֹתָ֔ם אֵ֥ת כָּל־הָרָעָ֖ה הַזֹּֽאת׃"}},"definableWords":["voice","or","walk","law"],"peopleInVerse":[]},"24":{"text":"Behold the mounts, they are come unto the city to take it; and the city is given into the hand of the Chaldeans, that fight against it, because of the sword, and of the famine, and of the pestilence: and what thou hast spoken is come to pass; and, behold, thou seest it.","ref":"Jeremiah 32:24","synthesized":"See how the siege ramps are mounted against the city to capture it. And by sword and famine and plague, the city has been given into the hands of the Chaldeans who are fighting against it. What You have spoken has happened, as You now see!","sources":{"KJV":{"text":"Behold the mounts, they are come unto the city to take it; and the city is given into the hand of the Chaldeans, that fight against it, because of the sword, and of the famine, and of the pestilence: and what thou hast spoken is come to pass; and, behold, thou seest it."},"BSB":{"text":"See how the siege ramps are mounted against the city to capture it. And by sword and famine and plague, the city has been given into the hands of the Chaldeans who are fighting against it. What You have spoken has happened, as You now see!"},"TANAKH":{"text":"behold the mounds, they are come unto the city to take it; and the city is given into the hand of the Chaldeans that fight against it, because of the sword, and of the famine, and of the pestilence; and what Thou hast spoken is come to pass; and, behold, Thou seest it."},"HEBREW":{"text":"הִנֵּ֣ה הַסֹּלְל֗וֹת בָּ֣אוּ הָעִיר֮ לְלָכְדָהּ֒ וְהָעִ֣יר נִתְּנָ֗ה בְּיַ֤ד הַכַּשְׂדִּים֙ הַנִּלְחָמִ֣ים עָלֶ֔יהָ מִפְּנֵ֛י הַחֶ֥רֶב וְהָרָעָ֖ב וְהַדָּ֑בֶר וַאֲשֶׁ֥ר דִּבַּ֛רְתָּ הָיָ֖ה וְהִנְּךָ֥ רֹאֶֽה׃"}},"definableWords":["see"],"peopleInVerse":[]},"25":{"text":"And thou hast said unto me, O Lord GOD, Buy thee the field for money, and take witnesses; for the city is given into the hand of the Chaldeans.","ref":"Jeremiah 32:25","synthesized":"Yet You, O Lord GOD, have said to me, ‘Buy for yourself the field with silver and call in witnesses, even though the city has been delivered into the hands of the Chaldeans!’”","sources":{"KJV":{"text":"And thou hast said unto me, O Lord GOD, Buy thee the field for money, and take witnesses; for the city is given into the hand of the Chaldeans."},"BSB":{"text":"Yet You, O Lord GOD, have said to me, ‘Buy for yourself the field with silver and call in witnesses, even though the city has been delivered into the hands of the Chaldeans!’”"},"TANAKH":{"text":"Yet Thou hast said unto me, O L-rd GOD: Buy thee the field for money, and call witnesses; whereas the city is given into the hand of the Chaldeans.'"},"HEBREW":{"text":"וְאַתָּ֞ה אָמַ֤רְתָּ אֵלַי֙ אֲדֹנָ֣י יְהוִ֔ה קְנֵֽה־לְךָ֧ הַשָּׂדֶ֛ה בַּכֶּ֖סֶף וְהָעֵ֣ד עֵדִ֑ים וְהָעִ֥יר נִתְּנָ֖ה בְּיַ֥ד הַכַּשְׂדִּֽים׃"}},"definableWords":["Lord","God","field"],"peopleInVerse":[]},"26":{"text":"Then came the word of the LORD unto Jeremiah, saying,","ref":"Jeremiah 32:26","synthesized":"Then the word of the LORD came to Jeremiah:","sources":{"KJV":{"text":"Then came the word of the LORD unto Jeremiah, saying,"},"BSB":{"text":"Then the word of the LORD came to Jeremiah:"},"TANAKH":{"text":"Then came the word of HaShem unto Jeremiah, saying:"},"HEBREW":{"text":"וַיְהִי֙ דְּבַר־יְהוָ֔ה אֶֽל־יִרְמְיָ֖הוּ לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"27":{"text":"Behold, I am the LORD, the God of all flesh: is there any thing too hard for me?","ref":"Jeremiah 32:27","synthesized":"“Behold, I am the LORD, the God of all flesh. Is anything too difficult for Me?","sources":{"KJV":{"text":"Behold, I am the LORD, the God of all flesh: is there any thing too hard for me?"},"BSB":{"text":"“Behold, I am the LORD, the God of all flesh. Is anything too difficult for Me?"},"TANAKH":{"text":"'Behold, I am HaShem, the G-d of all flesh; is there any thing too hard for Me?"},"HEBREW":{"text":"הִנֵּה֙ אֲנִ֣י יְהוָ֔ה אֱלֹהֵ֖י כָּל־בָּשָׂ֑ר הֲ‍ֽמִמֶּ֔נִּי יִפָּלֵ֖א כָּל־דָּבָֽר׃"}},"definableWords":["LORD","God","flesh"],"peopleInVerse":[]},"28":{"text":"Therefore thus saith the LORD; Behold, I will give this city into the hand of the Chaldeans, and into the hand of Nebuchadrezzar king of Babylon, and he shall take it:","ref":"Jeremiah 32:28","synthesized":"Therefore this is what the LORD says: Behold, I am about to deliver this city into the hands of the Chaldeans and of Nebuchadnezzar king of Babylon, who will capture it.","sources":{"KJV":{"text":"Therefore thus saith the LORD; Behold, I will give this city into the hand of the Chaldeans, and into the hand of Nebuchadrezzar king of Babylon, and he shall take it:"},"BSB":{"text":"Therefore this is what the LORD says: Behold, I am about to deliver this city into the hands of the Chaldeans and of Nebuchadnezzar king of Babylon, who will capture it."},"TANAKH":{"text":"Therefore thus saith HaShem: Behold, I will give this city into the hand of the Chaldeans, and into the hand of Nebuchadrezzar king of Babylon, and he shall take it;"},"HEBREW":{"text":"לָכֵ֕ן כֹּ֖ה אָמַ֣ר יְהוָ֑ה הִנְנִ֣י נֹתֵן֩ אֶת־הָעִ֨יר הַזֹּ֜את בְּיַ֣ד הַכַּשְׂדִּ֗ים וּבְיַ֛ד נְבֽוּכַדְרֶאצַּ֥ר מֶֽלֶךְ־בָּבֶ֖ל וּלְכָדָֽהּ׃"}},"definableWords":["LORD","deliver","king","Babylon"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship","redemption","salvation"]},"29":{"text":"And the Chaldeans, that fight against this city, shall come and set fire on this city, and burn it with the houses, upon whose roofs they have offered incense unto Baal, and poured out drink offerings unto other gods, to provoke me to anger.","ref":"Jeremiah 32:29","synthesized":"And the Chaldeans who are fighting against this city will come in, set it on fire, and burn it, along with the houses of those who provoked Me to anger by burning incense to Baal on their rooftops and by pouring out drink offerings to other gods.","sources":{"KJV":{"text":"And the Chaldeans, that fight against this city, shall come and set fire on this city, and burn it with the houses, upon whose roofs they have offered incense unto Baal, and poured out drink offerings unto other gods, to provoke me to anger."},"BSB":{"text":"And the Chaldeans who are fighting against this city will come in, set it on fire, and burn it, along with the houses of those who provoked Me to anger by burning incense to Baal on their rooftops and by pouring out drink offerings to other gods."},"TANAKH":{"text":"and the Chaldeans, that fight against this city, shall come and set this city on fire, and burn it, with the houses, upon whose roofs they have offered unto Baal, and poured out drink-offerings unto other gods, to provoke Me."},"HEBREW":{"text":"וּבָ֣אוּ הַכַּשְׂדִּ֗ים הַנִּלְחָמִים֙ עַל־הָעִ֣יר הַזֹּ֔את וְהִצִּ֜יתוּ אֶת־הָעִ֥יר הַזֹּ֛את בָּאֵ֖שׁ וּשְׂרָפ֑וּהָ וְאֵ֣ת הַבָּתִּ֡ים אֲשֶׁר֩ קִטְּר֨וּ עַל־גַּגּֽוֹתֵיהֶ֜ם לַבַּ֗עַל וְהִסִּ֤כוּ נְסָכִים֙ לֵאלֹהִ֣ים אֲחֵרִ֔ים לְמַ֖עַן הַכְעִסֵֽנִי׃"}},"definableWords":["anger","incense"],"peopleInVerse":[]},"30":{"text":"For the children of Israel and the children of Judah have only done evil before me from their youth: for the children of Israel have only provoked me to anger with the work of their hands, saith the LORD.","ref":"Jeremiah 32:30","synthesized":"For the children of Israel and of Judah have done nothing but evil in My sight from their youth; indeed, they have done nothing but provoke Me to anger by the work of their hands, declares the LORD.","sources":{"KJV":{"text":"For the children of Israel and the children of Judah have only done evil before me from their youth: for the children of Israel have only provoked me to anger with the work of their hands, saith the LORD."},"BSB":{"text":"For the children of Israel and of Judah have done nothing but evil in My sight from their youth; indeed, they have done nothing but provoke Me to anger by the work of their hands, declares the LORD."},"TANAKH":{"text":"For the children of Israel and the children of Judah have only done that which was evil in My sight from their youth; for the children of Israel have only provoked Me with the work of their hands, saith HaShem."},"HEBREW":{"text":"כִּֽי־הָי֨וּ בְנֵֽי־יִשְׂרָאֵ֜ל וּבְנֵ֣י יְהוּדָ֗ה אַ֣ךְ עֹשִׂ֥ים הָרַ֛ע בְּעֵינַ֖י מִנְּעֻרֹֽתֵיהֶ֑ם כִּ֣י בְנֵֽי־יִשְׂרָאֵ֗ל אַ֣ךְ מַכְעִסִ֥ים אֹתִ֛י בְּמַעֲשֵׂ֥ה יְדֵיהֶ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["Israel","Judah","evil","anger","work","LORD"],"peopleInVerse":[]},"31":{"text":"For this city hath been to me as a provocation of mine anger and of my fury from the day that they built it even unto this day; that I should remove it from before my face,","ref":"Jeremiah 32:31","synthesized":"For this city has aroused My wrath and fury from the day it was built until now. Therefore I will remove it from My presence","sources":{"KJV":{"text":"For this city hath been to me as a provocation of mine anger and of my fury from the day that they built it even unto this day; that I should remove it from before my face,"},"BSB":{"text":"For this city has aroused My wrath and fury from the day it was built until now. Therefore I will remove it from My presence"},"TANAKH":{"text":"For this city hath been to Me a provocation of Mine anger and of My fury from the day that they built it even unto this day, that I should remove it from before My face;"},"HEBREW":{"text":"כִּ֧י עַל־אַפִּ֣י וְעַל־חֲמָתִ֗י הָ֤יְתָה לִּי֙ הָעִ֣יר הַזֹּ֔את לְמִן־הַיּוֹם֙ אֲשֶׁ֣ר בָּנ֣וּ אוֹתָ֔הּ וְעַ֖ד הַיּ֣וֹם הַזֶּ֑ה לַהֲסִירָ֖הּ מֵעַ֥ל פָּנָֽי׃"}},"definableWords":["wrath","day"],"peopleInVerse":[],"themesInVerse":["judgment"]},"32":{"text":"Because of all the evil of the children of Israel and of the children of Judah, which they have done to provoke me to anger, they, their kings, their princes, their priests, and their prophets, and the men of Judah, and the inhabitants of Jerusalem.","ref":"Jeremiah 32:32","synthesized":"because of all the evil the children of Israel and of Judah have done to provoke Me to anger—they, their kings, their officials, their priests and prophets, the men of Judah, and the residents of Jerusalem.","sources":{"KJV":{"text":"Because of all the evil of the children of Israel and of the children of Judah, which they have done to provoke me to anger, they, their kings, their princes, their priests, and their prophets, and the men of Judah, and the inhabitants of Jerusalem."},"BSB":{"text":"because of all the evil the children of Israel and of Judah have done to provoke Me to anger—they, their kings, their officials, their priests and prophets, the men of Judah, and the residents of Jerusalem."},"TANAKH":{"text":"because of all the evil of the children of Israel and of the children of Judah, which they have done to provoke Me, they, their kings, their princes, their priests, and their prophets, and the men of Judah, and the inhabitants of Jerusalem."},"HEBREW":{"text":"עַל֩ כָּל־רָעַ֨ת בְּנֵֽי־יִשְׂרָאֵ֜ל וּבְנֵ֣י יְהוּדָ֗ה אֲשֶׁ֤ר עָשׂוּ֙ לְהַכְעִסֵ֔נִי הֵ֤מָּה מַלְכֵיהֶם֙ שָֽׂרֵיהֶ֔ם כֹּהֲנֵיהֶ֖ם וּנְבִֽיאֵיהֶ֑ם וְאִ֣ישׁ יְהוּדָ֔ה וְיֹשְׁבֵ֖י יְרוּשָׁלָֽ͏ִם׃"}},"definableWords":["evil","Israel","Judah","anger","kings","men","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"33":{"text":"And they have turned unto me the back, and not the face: though I taught them, rising up early and teaching them, yet they have not hearkened to receive instruction.","ref":"Jeremiah 32:33","synthesized":"They have turned their backs to Me and not their faces. Though I taught them again and again, they would not listen or respond to discipline.","sources":{"KJV":{"text":"And they have turned unto me the back, and not the face: though I taught them, rising up early and teaching them, yet they have not hearkened to receive instruction."},"BSB":{"text":"They have turned their backs to Me and not their faces. Though I taught them again and again, they would not listen or respond to discipline."},"TANAKH":{"text":"And they have turned unto Me the back, and not the face; and though I taught them, teaching them betimes and often, yet they have not hearkened to receive instruction."},"HEBREW":{"text":"וַיִּפְנ֥וּ אֵלַ֛י עֹ֖רֶף וְלֹ֣א פָנִ֑ים וְלַמֵּ֤ד אֹתָם֙ הַשְׁכֵּ֣ם וְלַמֵּ֔ד וְאֵינָ֥ם שֹׁמְעִ֖ים לָקַ֥חַת מוּסָֽר׃"}},"definableWords":["or"],"peopleInVerse":[]},"34":{"text":"But they set their abominations in the house, which is called by my name, to defile it.","ref":"Jeremiah 32:34","synthesized":"They have placed their abominations in the house that bears My Name, and so have defiled it.","sources":{"KJV":{"text":"But they set their abominations in the house, which is called by my name, to defile it."},"BSB":{"text":"They have placed their abominations in the house that bears My Name, and so have defiled it."},"TANAKH":{"text":"But they set their abominations in the house whereupon My name is called, to defile it."},"HEBREW":{"text":"וַיָּשִׂ֣ימוּ שִׁקּֽוּצֵיהֶ֗ם בַּבַּ֛יִת אֲשֶׁר־נִקְרָֽא־שְׁמִ֥י עָלָ֖יו לְטַמְּאֽוֹ׃"}},"definableWords":["house","name"],"peopleInVerse":[]},"35":{"text":"And they built the high places of Baal, which are in the valley of the son of Hinnom, to cause their sons and their daughters to pass through the fire unto Molech; which I commanded them not, neither came it into my mind, that they should do this abomination, to cause Judah to sin.","ref":"Jeremiah 32:35","synthesized":"They have built the high places of Baal in the Valley of Hinnom to make their sons and daughters pass through the fire to Molech—something I never commanded them, nor had it ever entered My mind, that they should commit such an abomination and cause Judah to sin.","sources":{"KJV":{"text":"And they built the high places of Baal, which are in the valley of the son of Hinnom, to cause their sons and their daughters to pass through the fire unto Molech; which I commanded them not, neither came it into my mind, that they should do this abomination, to cause Judah to sin."},"BSB":{"text":"They have built the high places of Baal in the Valley of Hinnom to make their sons and daughters pass through the fire to Molech—something I never commanded them, nor had it ever entered My mind, that they should commit such an abomination and cause Judah to sin."},"TANAKH":{"text":"And they built the high places of Baal, which are in the valley of the son of Hinnom, to set apart their sons and their daughters unto Molech; which I commanded them not, neither came it into My mind, that they should do this abomination; to cause Judah to sin."},"HEBREW":{"text":"וַיִּבְנוּ֩ אֶת־בָּמ֨וֹת הַבַּ֜עַל אֲשֶׁ֣ר ׀ בְּגֵ֣יא בֶן־הִנֹּ֗ם לְ֠הַעֲבִיר אֶת־בְּנֵיהֶ֣ם וְאֶת־בְּנוֹתֵיהֶם֮ לַמֹּלֶךְ֒ אֲשֶׁ֣ר לֹֽא־צִוִּיתִ֗ים וְלֹ֤א עָֽלְתָה֙ עַל־לִבִּ֔י לַעֲשׂ֖וֹת הַתּוֹעֵבָ֣ה הַזֹּ֑את לְמַ֖עַן החטי הַחֲטִ֥יא אֶת־יְהוּדָֽה׃"}},"definableWords":["make","sons","daughters","mind","Judah","sin"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"36":{"text":"And now therefore thus saith the LORD, the God of Israel, concerning this city, whereof ye say, It shall be delivered into the hand of the king of Babylon by the sword, and by the famine, and by the pestilence;","ref":"Jeremiah 32:36","synthesized":"Now therefore, about this city of which you say, ‘It will be delivered into the hand of the king of Babylon by sword and famine and plague,’ this is what the LORD, the God of Israel, says:","sources":{"KJV":{"text":"And now therefore thus saith the LORD, the God of Israel, concerning this city, whereof ye say, It shall be delivered into the hand of the king of Babylon by the sword, and by the famine, and by the pestilence;"},"BSB":{"text":"Now therefore, about this city of which you say, ‘It will be delivered into the hand of the king of Babylon by sword and famine and plague,’ this is what the LORD, the God of Israel, says:"},"TANAKH":{"text":"And now therefore thus saith HaShem, the G-d of Israel, concerning this city, whereof ye say: It is given into the hand of the king of Babylon by the sword, and by the famine, and by the pestilence:"},"HEBREW":{"text":"וְעַתָּ֕ה לָכֵ֛ן כֹּֽה־אָמַ֥ר יְהוָ֖ה אֱלֹהֵ֣י יִשְׂרָאֵ֑ל אֶל־הָעִ֨יר הַזֹּ֜את אֲשֶׁ֣ר ׀ אַתֶּ֣ם אֹמְרִ֗ים נִתְּנָה֙ בְּיַ֣ד מֶֽלֶךְ־בָּבֶ֔ל בַּחֶ֖רֶב וּבָרָעָ֥ב וּבַדָּֽבֶר׃"}},"definableWords":["king","Babylon","LORD","God","Israel"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"37":{"text":"Behold, I will gather them out of all countries, whither I have driven them in mine anger, and in my fury, and in great wrath; and I will bring them again unto this place, and I will cause them to dwell safely:","ref":"Jeremiah 32:37","synthesized":"I will surely gather My people from all the lands to which I have banished them in My furious anger and great wrath, and I will return them to this place and make them dwell in safety.","sources":{"KJV":{"text":"Behold, I will gather them out of all countries, whither I have driven them in mine anger, and in my fury, and in great wrath; and I will bring them again unto this place, and I will cause them to dwell safely:"},"BSB":{"text":"I will surely gather My people from all the lands to which I have banished them in My furious anger and great wrath, and I will return them to this place and make them dwell in safety."},"TANAKH":{"text":"Behold, I will gather them out of all the countries, whither I have driven them in Mine anger, and in My fury, and in great wrath; and I will bring them back unto this place, and I will cause them to dwell safely;"},"HEBREW":{"text":"הִנְנִ֤י מְקַבְּצָם֙ מִכָּל־הָ֣אֲרָצ֔וֹת אֲשֶׁ֨ר הִדַּחְתִּ֥ים שָׁ֛ם בְּאַפִּ֥י וּבַחֲמָתִ֖י וּבְקֶ֣צֶף גָּד֑וֹל וַהֲשִֽׁבֹתִים֙ אֶל־הַמָּק֣וֹם הַזֶּ֔ה וְהֹשַׁבְתִּ֖ים לָבֶֽטַח׃"}},"definableWords":["people","anger","great","wrath","make"],"peopleInVerse":[],"themesInVerse":["exile_return","judgment","second_coming"]},"38":{"text":"And they shall be my people, and I will be their God:","ref":"Jeremiah 32:38","synthesized":"They will be My people, and I will be their God.","sources":{"KJV":{"text":"And they shall be my people, and I will be their God:"},"BSB":{"text":"They will be My people, and I will be their God."},"TANAKH":{"text":"and they shall be My people, and I will be their G-d;"},"HEBREW":{"text":"וְהָ֥יוּ לִ֖י לְעָ֑ם וַאֲנִ֕י אֶהְיֶ֥ה לָהֶ֖ם לֵאלֹהִֽים׃"}},"definableWords":["people","God"],"peopleInVerse":[]},"39":{"text":"And I will give them one heart, and one way, that they may fear me for ever, for the good of them, and of their children after them:","ref":"Jeremiah 32:39","synthesized":"I will give them one heart and one way, so that they will always fear Me for their own good and for the good of their children after them.","sources":{"KJV":{"text":"And I will give them one heart, and one way, that they may fear me for ever, for the good of them, and of their children after them:"},"BSB":{"text":"I will give them one heart and one way, so that they will always fear Me for their own good and for the good of their children after them."},"TANAKH":{"text":"and I will give them one heart and one way, that they may fear Me for ever; for the good of them, and of their children after them;"},"HEBREW":{"text":"וְנָתַתִּ֨י לָהֶ֜ם לֵ֤ב אֶחָד֙ וְדֶ֣רֶךְ אֶחָ֔ד לְיִרְאָ֥ה אוֹתִ֖י כָּל־הַיָּמִ֑ים לְט֣וֹב לָהֶ֔ם וְלִבְנֵיהֶ֖ם אַחֲרֵיהֶֽם׃"}},"definableWords":["one","heart","way","fear","good"],"peopleInVerse":[],"themesInVerse":["fear_of_lord"]},"40":{"text":"And I will make an everlasting covenant with them, that I will not turn away from them, to do them good; but I will put my fear in their hearts, that they shall not depart from me.","ref":"Jeremiah 32:40","synthesized":"I will make an everlasting covenant with them: I will never turn away from doing good to them, and I will put My fear in their hearts, so that they will never turn away from Me.","sources":{"KJV":{"text":"And I will make an everlasting covenant with them, that I will not turn away from them, to do them good; but I will put my fear in their hearts, that they shall not depart from me."},"BSB":{"text":"I will make an everlasting covenant with them: I will never turn away from doing good to them, and I will put My fear in their hearts, so that they will never turn away from Me."},"TANAKH":{"text":"and I will make an everlasting covenant with them, that I will not turn away from them, to do them good; and I will put My fear in their hearts, that they shall not depart from Me."},"HEBREW":{"text":"וְכָרַתִּ֤י לָהֶם֙ בְּרִ֣ית עוֹלָ֔ם אֲשֶׁ֤ר לֹֽא־אָשׁוּב֙ מֵאַ֣חֲרֵיהֶ֔ם לְהֵיטִיבִ֖י אוֹתָ֑ם וְאֶת־יִרְאָתִי֙ אֶתֵּ֣ן בִּלְבָבָ֔ם לְבִלְתִּ֖י ס֥וּר מֵעָלָֽי׃"}},"definableWords":["make","everlasting","covenant","good","fear"],"peopleInVerse":[],"themesInVerse":["covenant","fear_of_lord"]},"41":{"text":"Yea, I will rejoice over them to do them good, and I will plant them in this land assuredly with my whole heart and with my whole soul.","ref":"Jeremiah 32:41","synthesized":"Yes, I will rejoice in doing them good, and I will faithfully plant them in this land with all My heart and with all My soul.","sources":{"KJV":{"text":"Yea, I will rejoice over them to do them good, and I will plant them in this land assuredly with my whole heart and with my whole soul."},"BSB":{"text":"Yes, I will rejoice in doing them good, and I will faithfully plant them in this land with all My heart and with all My soul."},"TANAKH":{"text":"Yea, I will rejoice over them to do them good, and I will plant them in this land in truth with My whole heart and with My whole soul."},"HEBREW":{"text":"וְשַׂשְׂתִּ֥י עֲלֵיהֶ֖ם לְהֵטִ֣יב אוֹתָ֑ם וּנְטַעְתִּ֞ים בָּאָ֤רֶץ הַזֹּאת֙ בֶּאֱמֶ֔ת בְּכָל־לִבִּ֖י וּבְכָל־נַפְשִֽׁי׃"}},"definableWords":["good","land","heart","soul"],"peopleInVerse":[],"themesInVerse":["joy","land_promise"]},"42":{"text":"For thus saith the LORD; Like as I have brought all this great evil upon this people, so will I bring upon them all the good that I have promised them.","ref":"Jeremiah 32:42","synthesized":"For this is what the LORD says: Just as I have brought all this great disaster on this people, so I will bring on them all the good I have promised them.","sources":{"KJV":{"text":"For thus saith the LORD; Like as I have brought all this great evil upon this people, so will I bring upon them all the good that I have promised them."},"BSB":{"text":"For this is what the LORD says: Just as I have brought all this great disaster on this people, so I will bring on them all the good I have promised them."},"TANAKH":{"text":"For thus saith HaShem: Like as I have brought all this great evil upon this people, so will I bring upon them all the good that I have promised them."},"HEBREW":{"text":"כִּֽי־כֹה֙ אָמַ֣ר יְהוָ֔ה כַּאֲשֶׁ֤ר הֵבֵ֙אתִי֙ אֶל־הָעָ֣ם הַזֶּ֔ה אֵ֛ת כָּל־הָרָעָ֥ה הַגְּדוֹלָ֖ה הַזֹּ֑את כֵּ֣ן אָנֹכִ֞י מֵבִ֤יא עֲלֵיהֶם֙ אֶת־כָּל־הַטּוֹבָ֔ה אֲשֶׁ֥ר אָנֹכִ֖י דֹּבֵ֥ר עֲלֵיהֶֽם׃"}},"definableWords":["LORD","great","people","good"],"peopleInVerse":[]},"43":{"text":"And fields shall be bought in this land, whereof ye say, It is desolate without man or beast; it is given into the hand of the Chaldeans.","ref":"Jeremiah 32:43","synthesized":"And fields will be bought in this land about which you are saying, ‘It is a desolation, without man or beast; it has been delivered into the hands of the Chaldeans.’","sources":{"KJV":{"text":"And fields shall be bought in this land, whereof ye say, It is desolate without man or beast; it is given into the hand of the Chaldeans."},"BSB":{"text":"And fields will be bought in this land about which you are saying, ‘It is a desolation, without man or beast; it has been delivered into the hands of the Chaldeans.’"},"TANAKH":{"text":"And fields shall be bought in this land, whereof ye say: It is desolate, without man or beast; it is given into the hand of the Chaldeans."},"HEBREW":{"text":"וְנִקְנָ֥ה הַשָּׂדֶ֖ה בָּאָ֣רֶץ הַזֹּ֑את אֲשֶׁ֣ר ׀ אַתֶּ֣ם אֹמְרִ֗ים שְׁמָמָ֥ה הִיא֙ מֵאֵ֤ין אָדָם֙ וּבְהֵמָ֔ה נִתְּנָ֖ה בְּיַ֥ד הַכַּשְׂדִּֽים׃"}},"definableWords":["land","man","or"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"44":{"text":"Men shall buy fields for money, and subscribe evidences, and seal them, and take witnesses in the land of Benjamin, and in the places about Jerusalem, and in the cities of Judah, and in the cities of the mountains, and in the cities of the valley, and in the cities of the south: for I will cause their captivity to return, saith the LORD.","ref":"Jeremiah 32:44","synthesized":"Fields will be purchased with silver, and deeds will be signed, sealed, and witnessed in the land of Benjamin, in the areas surrounding Jerusalem, and in the cities of Judah—the cities of the hill country, the foothills, and the Negev—because I will restore them from captivity, declares the LORD.”","sources":{"KJV":{"text":"Men shall buy fields for money, and subscribe evidences, and seal them, and take witnesses in the land of Benjamin, and in the places about Jerusalem, and in the cities of Judah, and in the cities of the mountains, and in the cities of the valley, and in the cities of the south: for I will cause their captivity to return, saith the LORD."},"BSB":{"text":"Fields will be purchased with silver, and deeds will be signed, sealed, and witnessed in the land of Benjamin, in the areas surrounding Jerusalem, and in the cities of Judah—the cities of the hill country, the foothills, and the Negev—because I will restore them from captivity, declares the LORD.”"},"TANAKH":{"text":"Men shall buy fields for money, and subscribe the deeds, and seal them, and call witnesses, in the land of Benjamin, and in the places about Jerusalem, and in the cities of Judah, and in the cities of the hill-country, and in the cities of the Lowland, and in the cities of the South; for I will cause their captivity to return, saith HaShem.'"},"HEBREW":{"text":"שָׂד֞וֹת בַּכֶּ֣סֶף יִקְנ֗וּ וְכָת֨וֹב בַּסֵּ֥פֶר ׀ וְחָתוֹם֮ וְהָעֵ֣ד עֵדִים֒ בְּאֶ֨רֶץ בִּנְיָמִ֜ן וּבִסְבִיבֵ֣י יְרוּשָׁלִַ֗ם וּבְעָרֵ֤י יְהוּדָה֙ וּבְעָרֵ֣י הָהָ֔ר וּבְעָרֵ֥י הַשְּׁפֵלָ֖ה וּבְעָרֵ֣י הַנֶּ֑גֶב כִּֽי־אָשִׁ֥יב אֶת־שְׁבוּתָ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["land","Benjamin","Jerusalem","Judah","LORD"],"peopleInVerse":[],"placesInVerse":["Jerusalem","Negev"],"themesInVerse":["exile_return","land_promise"]}}},"33":{"chapter":"33","title":"GREAT AND MIGHTY THINGS","verses":{"1":{"text":"Moreover the word of the LORD came unto Jeremiah the second time, while he was yet shut up in the court of the prison, saying,","ref":"Jeremiah 33:1","synthesized":"While Jeremiah was still confined in the courtyard of the guard, the word of the LORD came to him a second time:","sources":{"KJV":{"text":"Moreover the word of the LORD came unto Jeremiah the second time, while he was yet shut up in the court of the prison, saying,"},"BSB":{"text":"While Jeremiah was still confined in the courtyard of the guard, the word of the LORD came to him a second time:"},"TANAKH":{"text":"Moreover the word of HaShem came unto Jeremiah the second time, while he was yet shut up in the court of the guard, saying:"},"HEBREW":{"text":"וַיְהִ֧י דְבַר־יְהוָ֛ה אֶֽל־יִרְמְיָ֖הוּ שֵׁנִ֑ית וְהוּא֙ עוֹדֶ֣נּוּ עָצ֔וּר בַּחֲצַ֥ר הַמַּטָּרָ֖ה לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"2":{"text":"Thus saith the LORD the maker thereof, the LORD that formed it, to establish it; the LORD is his name;","ref":"Jeremiah 33:2","synthesized":"“Thus says the LORD who made the earth, the LORD who formed it and established it, the LORD is His name:","sources":{"KJV":{"text":"Thus saith the LORD the maker thereof, the LORD that formed it, to establish it; the LORD is his name;"},"BSB":{"text":"“Thus says the LORD who made the earth, the LORD who formed it and established it, the LORD is His name:"},"TANAKH":{"text":"Thus saith HaShem the Maker thereof, HaShem that formed it to establish it, HaShem is His name:"},"HEBREW":{"text":"כֹּֽה־אָמַ֥ר יְהוָ֖ה עֹשָׂ֑הּ יְהוָ֗ה יוֹצֵ֥ר אוֹתָ֛הּ לַהֲכִינָ֖הּ יְהוָ֥ה שְׁמֽוֹ׃"}},"definableWords":["LORD","made","earth","Lord","formed","name"],"peopleInVerse":[],"themesInVerse":["creation"]},"3":{"text":"Call unto me, and I will answer thee, and shew thee great and mighty things, which thou knowest not.","ref":"Jeremiah 33:3","synthesized":"Call to Me, and I will answer and show you great and unsearchable things you do not know.","sources":{"KJV":{"text":"Call unto me, and I will answer thee, and shew thee great and mighty things, which thou knowest not."},"BSB":{"text":"Call to Me, and I will answer and show you great and unsearchable things you do not know."},"TANAKH":{"text":"Call unto Me, and I will answer thee, and will tell thee great things, and hidden, which thou knowest not."},"HEBREW":{"text":"קְרָ֥א אֵלַ֖י וְאֶעֱנֶ֑ךָּ וְאַגִּ֧ידָה לְּךָ֛ גְּדֹל֥וֹת וּבְצֻר֖וֹת לֹ֥א יְדַעְתָּֽם׃"}},"definableWords":["great"],"peopleInVerse":[]},"4":{"text":"For thus saith the LORD, the God of Israel, concerning the houses of this city, and concerning the houses of the kings of Judah, which are thrown down by the mounts, and by the sword;","ref":"Jeremiah 33:4","synthesized":"For this is what the LORD, the God of Israel, says about the houses of this city and the palaces of the kings of Judah that have been torn down for defense against the siege ramps and the sword:","sources":{"KJV":{"text":"For thus saith the LORD, the God of Israel, concerning the houses of this city, and concerning the houses of the kings of Judah, which are thrown down by the mounts, and by the sword;"},"BSB":{"text":"For this is what the LORD, the God of Israel, says about the houses of this city and the palaces of the kings of Judah that have been torn down for defense against the siege ramps and the sword:"},"TANAKH":{"text":"For thus saith HaShem, the G-d of Israel, concerning the houses of this city, and concerning the houses of the kings of Judah, which are broken down for mounds, and for ramparts;"},"HEBREW":{"text":"כִּי֩ כֹ֨ה אָמַ֤ר יְהוָה֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל עַל־בָּתֵּי֙ הָעִ֣יר הַזֹּ֔את וְעַל־בָּתֵּ֖י מַלְכֵ֣י יְהוּדָ֑ה הַנְּתֻצִ֕ים אֶל־הַסֹּלְל֖וֹת וְאֶל־הֶחָֽרֶב׃"}},"definableWords":["LORD","God","Israel","kings","Judah"],"peopleInVerse":[]},"5":{"text":"They come to fight with the Chaldeans, but it is to fill them with the dead bodies of men, whom I have slain in mine anger and in my fury, and for all whose wickedness I have hid my face from this city.","ref":"Jeremiah 33:5","synthesized":"The Chaldeans are coming to fight and to fill those places with the corpses of the men I will strike down in My anger and in My wrath. I have hidden My face from this city because of all its wickedness.","sources":{"KJV":{"text":"They come to fight with the Chaldeans, but it is to fill them with the dead bodies of men, whom I have slain in mine anger and in my fury, and for all whose wickedness I have hid my face from this city."},"BSB":{"text":"The Chaldeans are coming to fight and to fill those places with the corpses of the men I will strike down in My anger and in My wrath. I have hidden My face from this city because of all its wickedness."},"TANAKH":{"text":"whereon they come to fight with the Chaldeans, even to fill them with the dead bodies of men, whom I have slain in Mine anger and in My fury, and for all whose wickedness I have hid My face from this city:"},"HEBREW":{"text":"בָּאִ֗ים לְהִלָּחֵם֙ אֶת־הַכַּשְׂדִּ֔ים וּלְמַלְאָם֙ אֶת־פִּגְרֵ֣י הָאָדָ֔ם אֲשֶׁר־הִכֵּ֥יתִי בְאַפִּ֖י וּבַחֲמָתִ֑י וַאֲשֶׁ֨ר הִסְתַּ֤רְתִּי פָנַי֙ מֵהָעִ֣יר הַזֹּ֔את עַ֖ל כָּל־רָעָתָֽם׃"}},"definableWords":["fight","fill","men","anger","wrath"],"peopleInVerse":[],"themesInVerse":["judgment","second_coming","spiritual_warfare"]},"6":{"text":"Behold, I will bring it health and cure, and I will cure them, and will reveal unto them the abundance of peace and truth.","ref":"Jeremiah 33:6","synthesized":"Nevertheless, I will bring to it health and healing, and I will heal its people and reveal to them the abundance of peace and truth.","sources":{"KJV":{"text":"Behold, I will bring it health and cure, and I will cure them, and will reveal unto them the abundance of peace and truth."},"BSB":{"text":"Nevertheless, I will bring to it health and healing, and I will heal its people and reveal to them the abundance of peace and truth."},"TANAKH":{"text":"Behold, I will bring it healing and cure, and I will cure them; and I will reveal unto them the abundance of peace and truth."},"HEBREW":{"text":"הִנְנִ֧י מַעֲלֶה־לָּ֛הּ אֲרֻכָ֥ה וּמַרְפֵּ֖א וּרְפָאתִ֑ים וְגִלֵּיתִ֣י לָהֶ֔ם עֲתֶ֥רֶת שָׁל֖וֹם וֶאֱמֶֽת׃"}},"definableWords":["heal","people","peace","truth"],"peopleInVerse":[],"themesInVerse":["peace"]},"7":{"text":"And I will cause the captivity of Judah and the captivity of Israel to return, and will build them, as at the first.","ref":"Jeremiah 33:7","synthesized":"I will restore Judah and Israel from captivity and will rebuild them as in former times.","sources":{"KJV":{"text":"And I will cause the captivity of Judah and the captivity of Israel to return, and will build them, as at the first."},"BSB":{"text":"I will restore Judah and Israel from captivity and will rebuild them as in former times."},"TANAKH":{"text":"And I will cause the captivity of Judah and the captivity of Israel to return, and will build them, as at the first."},"HEBREW":{"text":"וַהֲשִֽׁבֹתִי֙ אֶת־שְׁב֣וּת יְהוּדָ֔ה וְאֵ֖ת שְׁב֣וּת יִשְׂרָאֵ֑ל וּבְנִתִ֖ים כְּבָרִֽאשֹׁנָֽה׃"}},"definableWords":["Judah","Israel"],"peopleInVerse":[],"themesInVerse":["exile_return"]},"8":{"text":"And I will cleanse them from all their iniquity, whereby they have sinned against me; and I will pardon all their iniquities, whereby they have sinned, and whereby they have transgressed against me.","ref":"Jeremiah 33:8","synthesized":"And I will cleanse them from all the iniquity they have committed against Me, and will forgive all their sins of rebellion against Me.","sources":{"KJV":{"text":"And I will cleanse them from all their iniquity, whereby they have sinned against me; and I will pardon all their iniquities, whereby they have sinned, and whereby they have transgressed against me."},"BSB":{"text":"And I will cleanse them from all the iniquity they have committed against Me, and will forgive all their sins of rebellion against Me."},"TANAKH":{"text":"And I will cleanse them from all their iniquity, whereby they have sinned against Me; and I will pardon all their iniquities, whereby they have sinned against Me, and whereby they have transgressed against Me."},"HEBREW":{"text":"וְטִ֣הַרְתִּ֔ים מִכָּל־עֲוֺנָ֖ם אֲשֶׁ֣ר חָֽטְאוּ־לִ֑י וְסָלַחְתִּ֗י לכול־לְכָל־עֲוֺנֽוֹתֵיהֶם֙ אֲשֶׁ֣ר חָֽטְאוּ־לִ֔י וַאֲשֶׁ֖ר פָּ֥שְׁעוּ בִֽי׃"}},"definableWords":["cleanse","iniquity","forgive"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"9":{"text":"And it shall be to me a name of joy, a praise and an honour before all the nations of the earth, which shall hear all the good that I do unto them: and they shall fear and tremble for all the goodness and for all the prosperity that I procure unto it.","ref":"Jeremiah 33:9","synthesized":"So this city will bring Me renown, joy, praise, and glory before all the nations of the earth, who will hear of all the good I do for it. They will tremble in awe because of all the goodness and prosperity that I will provide for it.","sources":{"KJV":{"text":"And it shall be to me a name of joy, a praise and an honour before all the nations of the earth, which shall hear all the good that I do unto them: and they shall fear and tremble for all the goodness and for all the prosperity that I procure unto it."},"BSB":{"text":"So this city will bring Me renown, joy, praise, and glory before all the nations of the earth, who will hear of all the good I do for it. They will tremble in awe because of all the goodness and prosperity that I will provide for it."},"TANAKH":{"text":"And this city shall be to Me for a name of joy, for a praise and for a glory, before all the nations of the earth, which shall hear all the good that I do unto them, and shall fear and tremble for all the good and for all the peace that I procure unto it."},"HEBREW":{"text":"וְהָ֣יְתָה לִּ֗י לְשֵׁ֤ם שָׂשׂוֹן֙ לִתְהִלָּ֣ה וּלְתִפְאֶ֔רֶת לְכֹ֖ל גּוֹיֵ֣י הָאָ֑רֶץ אֲשֶׁ֨ר יִשְׁמְע֜וּ אֶת־כָּל־הַטּוֹבָ֗ה אֲשֶׁ֤ר אָֽנֹכִי֙ עֹשֶׂ֣ה אֹתָ֔ם וּפָחֲד֣וּ וְרָֽגְז֗וּ עַ֤ל כָּל־הַטּוֹבָה֙ וְעַ֣ל כָּל־הַשָּׁל֔וֹם אֲשֶׁ֥ר אָֽנֹכִ֖י עֹ֥שֶׂה לָּֽהּ׃"}},"definableWords":["joy","praise","glory","nations","earth","hear","good"],"peopleInVerse":[],"themesInVerse":["fear_of_lord","joy","worship"]},"10":{"text":"Thus saith the LORD; Again there shall be heard in this place, which ye say shall be desolate without man and without beast, even in the cities of Judah, and in the streets of Jerusalem, that are desolate, without man, and without inhabitant, and without beast,","ref":"Jeremiah 33:10","synthesized":"This is what the LORD says: In this place you say is a wasteland without man or beast, in the cities of Judah and in the streets of Jerusalem that are deserted—inhabited by neither man nor beast—there will be heard again","sources":{"KJV":{"text":"Thus saith the LORD; Again there shall be heard in this place, which ye say shall be desolate without man and without beast, even in the cities of Judah, and in the streets of Jerusalem, that are desolate, without man, and without inhabitant, and without beast,"},"BSB":{"text":"This is what the LORD says: In this place you say is a wasteland without man or beast, in the cities of Judah and in the streets of Jerusalem that are deserted—inhabited by neither man nor beast—there will be heard again"},"TANAKH":{"text":"Thus saith HaShem: Yet again there shall be heard in this place, whereof ye say: It is waste, without man and without beast, even in the cities of Judah, and in the streets of Jerusalem, that are desolate, without man and without inhabitant and without beast,"},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה עוֹד֮ יִשָּׁמַ֣ע בַּמָּקוֹם־הַזֶּה֒ אֲשֶׁר֙ אַתֶּ֣ם אֹֽמְרִ֔ים חָרֵ֣ב ה֔וּא מֵאֵ֥ין אָדָ֖ם וּמֵאֵ֣ין בְּהֵמָ֑ה בְּעָרֵ֤י יְהוּדָה֙ וּבְחֻצ֣וֹת יְרוּשָׁלִַ֔ם הַֽנְשַׁמּ֗וֹת מֵאֵ֥ין אָדָ֛ם וּמֵאֵ֥ין יוֹשֵׁ֖ב וּמֵאֵ֥ין בְּהֵמָֽה׃"}},"definableWords":["LORD","man","or","Judah","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"11":{"text":"The voice of joy, and the voice of gladness, the voice of the bridegroom, and the voice of the bride, the voice of them that shall say, Praise the LORD of hosts: for the LORD is good; for his mercy endureth for ever: and of them that shall bring the sacrifice of praise into the house of the LORD. For I will cause to return the captivity of the land, as at the first, saith the LORD.","ref":"Jeremiah 33:11","synthesized":"the sounds of joy and gladness, the voices of the bride and bridegroom, and the voices of those bringing thank offerings into the house of the LORD, saying:  ‘Give thanks to the LORD of Hosts, for the LORD is good; His loving devotion endures forever.’   For I will restore the land from captivity as in former times, says the LORD.","sources":{"KJV":{"text":"The voice of joy, and the voice of gladness, the voice of the bridegroom, and the voice of the bride, the voice of them that shall say, Praise the LORD of hosts: for the LORD is good; for his mercy endureth for ever: and of them that shall bring the sacrifice of praise into the house of the LORD. For I will cause to return the captivity of the land, as at the first, saith the LORD."},"BSB":{"text":"the sounds of joy and gladness, the voices of the bride and bridegroom, and the voices of those bringing thank offerings into the house of the LORD, saying:  ‘Give thanks to the LORD of Hosts, for the LORD is good; His loving devotion endures forever.’   For I will restore the land from captivity as in former times, says the LORD."},"TANAKH":{"text":"the voice of joy and the voice of gladness, the voice of the bridegroom and the voice of the bride, the voice of them that say: 'Give thanks to HaShem of hosts, for HaShem is good, for His mercy endureth for ever', even of them that bring offerings of thanksgiving into the house of HaShem. For I will cause the captivity of the land to return as at the first, saith HaShem."},"HEBREW":{"text":"ק֣וֹל שָׂשׂ֞וֹן וְק֣וֹל שִׂמְחָ֗ה ק֣וֹל חָתָן֮ וְק֣וֹל כַּלָּה֒ ק֣וֹל אֹמְרִ֡ים הוֹדוּ֩ אֶת־יְהוָ֨ה צְבָא֜וֹת כִּֽי־ט֤וֹב יְהוָה֙ כִּֽי־לְעוֹלָ֣ם חַסְדּ֔וֹ מְבִאִ֥ים תּוֹדָ֖ה בֵּ֣ית יְהוָ֑ה כִּֽי־אָשִׁ֧יב אֶת־שְׁבוּת־הָאָ֛רֶץ כְּבָרִאשֹׁנָ֖ה אָמַ֥ר יְהוָֽה׃"}},"definableWords":["joy","house","LORD","Lord","good","land"],"peopleInVerse":[],"themesInVerse":["exile_return","joy","land_promise","marriage_bride"]},"12":{"text":"Thus saith the LORD of hosts; Again in this place, which is desolate without man and without beast, and in all the cities thereof, shall be an habitation of shepherds causing their flocks to lie down.","ref":"Jeremiah 33:12","synthesized":"This is what the LORD of Hosts says: In this desolate place, without man or beast, and in all its cities, there will once more be pastures for shepherds to rest their flocks.","sources":{"KJV":{"text":"Thus saith the LORD of hosts; Again in this place, which is desolate without man and without beast, and in all the cities thereof, shall be an habitation of shepherds causing their flocks to lie down."},"BSB":{"text":"This is what the LORD of Hosts says: In this desolate place, without man or beast, and in all its cities, there will once more be pastures for shepherds to rest their flocks."},"TANAKH":{"text":"Thus saith HaShem of hosts: Yet again shall there be in this place, which is waste, without man and without beast, and in all the cities thereof, a habitation of shepherds causing their flocks to lie down."},"HEBREW":{"text":"כֹּֽה־אָמַר֮ יְהוָ֣ה צְבָאוֹת֒ ע֞וֹד יִֽהְיֶ֣ה ׀ בַּמָּק֣וֹם הַזֶּ֗ה הֶחָרֵ֛ב מֵֽאֵין־אָדָ֥ם וְעַד־בְּהֵמָ֖ה וּבְכָל־עָרָ֑יו נְוֵ֣ה רֹעִ֔ים מַרְבִּצִ֖ים צֹֽאן׃"}},"definableWords":["LORD","man","or","rest"],"peopleInVerse":[],"themesInVerse":["peace","sabbath_rest"]},"13":{"text":"In the cities of the mountains, in the cities of the vale, and in the cities of the south, and in the land of Benjamin, and in the places about Jerusalem, and in the cities of Judah, shall the flocks pass again under the hands of him that telleth them, saith the LORD.","ref":"Jeremiah 33:13","synthesized":"In the cities of the hill country, the foothills, and the Negev, in the land of Benjamin and the cities surrounding Jerusalem, and in the cities of Judah, the flocks will again pass under the hands of the one who counts them, says the LORD.","sources":{"KJV":{"text":"In the cities of the mountains, in the cities of the vale, and in the cities of the south, and in the land of Benjamin, and in the places about Jerusalem, and in the cities of Judah, shall the flocks pass again under the hands of him that telleth them, saith the LORD."},"BSB":{"text":"In the cities of the hill country, the foothills, and the Negev, in the land of Benjamin and the cities surrounding Jerusalem, and in the cities of Judah, the flocks will again pass under the hands of the one who counts them, says the LORD."},"TANAKH":{"text":"In the cities of the hill-country, in the cities of the Lowland, and in the cities of the South, and in the land of Benjamin, and in the places about Jerusalem, and in the cities of Judah, shall the flocks again pass under the hands of him that counteth them, saith HaShem."},"HEBREW":{"text":"בְּעָרֵ֨י הָהָ֜ר בְּעָרֵ֤י הַשְּׁפֵלָה֙ וּבְעָרֵ֣י הַנֶּ֔גֶב וּבְאֶ֧רֶץ בִּנְיָמִ֛ן וּבִסְבִיבֵ֥י יְרוּשָׁלַ֖͏ִם וּבְעָרֵ֣י יְהוּדָ֑ה עֹ֣ד תַּעֲבֹ֧רְנָה הַצֹּ֛אן עַל־יְדֵ֥י מוֹנֶ֖ה אָמַ֥ר יְהוָֽה׃"}},"definableWords":["land","Benjamin","Jerusalem","Judah","one","LORD"],"peopleInVerse":[],"placesInVerse":["Negev","Jerusalem"],"themesInVerse":["land_promise"]},"14":{"text":"Behold, the days come, saith the LORD, that I will perform that good thing which I have promised unto the house of Israel and to the house of Judah.","ref":"Jeremiah 33:14","synthesized":"Behold, the days are coming, declares the LORD, when I will fulfill the gracious promise that I have spoken to the house of Israel and the house of Judah.","sources":{"KJV":{"text":"Behold, the days come, saith the LORD, that I will perform that good thing which I have promised unto the house of Israel and to the house of Judah."},"BSB":{"text":"Behold, the days are coming, declares the LORD, when I will fulfill the gracious promise that I have spoken to the house of Israel and the house of Judah."},"TANAKH":{"text":"Behold, the days come, saith HaShem, that I will perform that good word which I have spoken concerning the house of Israel and concerning the house of Judah."},"HEBREW":{"text":"הִנֵּ֛ה יָמִ֥ים בָּאִ֖ים נְאֻם־יְהוָ֑ה וַהֲקֽ͏ִמֹתִי֙ אֶת־הַדָּבָ֣ר הַטּ֔וֹב אֲשֶׁ֥ר דִּבַּ֛רְתִּי אֶל־בֵּ֥ית יִשְׂרָאֵ֖ל וְעַל־בֵּ֥ית יְהוּדָֽה׃"}},"definableWords":["days","LORD","promise","house","Israel","Judah"],"peopleInVerse":[],"themesInVerse":["covenant","second_coming"]},"15":{"text":"In those days, and at that time, will I cause the Branch of righteousness to grow up unto David; and he shall execute judgment and righteousness in the land.","ref":"Jeremiah 33:15","synthesized":"In those days and at that time I will cause to sprout for David a righteous Branch, and He will administer justice and righteousness in the land.","sources":{"KJV":{"text":"In those days, and at that time, will I cause the Branch of righteousness to grow up unto David; and he shall execute judgment and righteousness in the land."},"BSB":{"text":"In those days and at that time I will cause to sprout for David a righteous Branch, and He will administer justice and righteousness in the land."},"TANAKH":{"text":"In those days, and at that time, will I cause a shoot of righteousness to grow up unto David; and he shall execute justice and righteousness in the land."},"HEBREW":{"text":"בַּיָּמִ֤ים הָהֵם֙ וּבָעֵ֣ת הַהִ֔יא אַצְמִ֥יחַ לְדָוִ֖ד צֶ֣מַח צְדָקָ֑ה וְעָשָׂ֛ה מִשְׁפָּ֥ט וּצְדָקָ֖ה בָּאָֽרֶץ׃"}},"definableWords":["days","righteous","justice","righteousness","land"],"peopleInVerse":["David"],"themesInVerse":["land_promise","messiah"]},"16":{"text":"In those days shall Judah be saved, and Jerusalem shall dwell safely: and this is the name wherewith she shall be called, The LORD our righteousness.","ref":"Jeremiah 33:16","synthesized":"In those days Judah will be saved, and Jerusalem will dwell securely, and this is the name by which it will be called: The LORD Our Righteousness.","sources":{"KJV":{"text":"In those days shall Judah be saved, and Jerusalem shall dwell safely: and this is the name wherewith she shall be called, The LORD our righteousness."},"BSB":{"text":"In those days Judah will be saved, and Jerusalem will dwell securely, and this is the name by which it will be called: The LORD Our Righteousness."},"TANAKH":{"text":"In those days shall Judah be saved, and Jerusalem shall dwell safely; and this is the name whereby she shall be called, HaShem is our righteousness."},"HEBREW":{"text":"בַּיָּמִ֤ים הָהֵם֙ תִּוָּשַׁ֣ע יְהוּדָ֔ה וִירוּשָׁלַ֖͏ִם תִּשְׁכּ֣וֹן לָבֶ֑טַח וְזֶ֥ה אֲשֶׁר־יִקְרָא־לָ֖הּ יְהוָ֥ה ׀ צִדְקֵֽנוּ׃"}},"definableWords":["days","Judah","Jerusalem","name","LORD","righteousness"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"17":{"text":"For thus saith the LORD; David shall never want a man to sit upon the throne of the house of Israel;","ref":"Jeremiah 33:17","synthesized":"For this is what the LORD says: David will never lack a man to sit on the throne of the house of Israel,","sources":{"KJV":{"text":"For thus saith the LORD; David shall never want a man to sit upon the throne of the house of Israel;"},"BSB":{"text":"For this is what the LORD says: David will never lack a man to sit on the throne of the house of Israel,"},"TANAKH":{"text":"For thus saith HaShem: There shall not be cut off unto David a man to sit upon the throne of the house of Israel;"},"HEBREW":{"text":"כִּי־כֹ֖ה אָמַ֣ר יְהוָ֑ה לֹֽא־יִכָּרֵ֣ת לְדָוִ֔ד אִ֕ישׁ יֹשֵׁ֖ב עַל־כִּסֵּ֥א בֵֽית־יִשְׂרָאֵֽל׃"}},"definableWords":["LORD","man","throne","house","Israel"],"peopleInVerse":["David"],"themesInVerse":["kingdom_of_god","kingship"]},"18":{"text":"Neither shall the priests the Levites want a man before me to offer burnt offerings, and to kindle meat offerings, and to do sacrifice continually.","ref":"Jeremiah 33:18","synthesized":"nor will the priests who are Levites ever fail to have a man before Me to offer burnt offerings, to burn grain offerings, and to present sacrifices.”","sources":{"KJV":{"text":"Neither shall the priests the Levites want a man before me to offer burnt offerings, and to kindle meat offerings, and to do sacrifice continually."},"BSB":{"text":"nor will the priests who are Levites ever fail to have a man before Me to offer burnt offerings, to burn grain offerings, and to present sacrifices.”"},"TANAKH":{"text":"neither shall there be cut off unto the priests the Levites a man before Me to offer burnt-offerings, and to burn meal-offerings, and to do sacrifice continually."},"HEBREW":{"text":"וְלַכֹּהֲנִים֙ הַלְוִיִּ֔ם לֹֽא־יִכָּרֵ֥ת אִ֖ישׁ מִלְּפָנָ֑י מַעֲלֶ֨ה עוֹלָ֜ה וּמַקְטִ֥יר מִנְחָ֛ה וְעֹ֥שֶׂה־זֶּ֖בַח כָּל־הַיָּמִֽים׃"}},"definableWords":["man"],"peopleInVerse":[]},"19":{"text":"And the word of the LORD came unto Jeremiah, saying,","ref":"Jeremiah 33:19","synthesized":"And the word of the LORD came to Jeremiah:","sources":{"KJV":{"text":"And the word of the LORD came unto Jeremiah, saying,"},"BSB":{"text":"And the word of the LORD came to Jeremiah:"},"TANAKH":{"text":"And the word of HaShem came unto Jeremiah, saying:"},"HEBREW":{"text":"וַֽיְהִי֙ דְּבַר־יְהוָ֔ה אֶֽל־יִרְמְיָ֖הוּ לֵאמֽוֹר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"20":{"text":"Thus saith the LORD; If ye can break my covenant of the day, and my covenant of the night, and that there should not be day and night in their season;","ref":"Jeremiah 33:20","synthesized":"“This is what the LORD says: If you can break My covenant with the day and My covenant with the night, so that day and night cease to occupy their appointed time,","sources":{"KJV":{"text":"Thus saith the LORD; If ye can break my covenant of the day, and my covenant of the night, and that there should not be day and night in their season;"},"BSB":{"text":"“This is what the LORD says: If you can break My covenant with the day and My covenant with the night, so that day and night cease to occupy their appointed time,"},"TANAKH":{"text":"Thus saith HaShem: If ye can break My covenant with the day, and My covenant with the night, so that there should not be day and night in their season;"},"HEBREW":{"text":"כֹּ֚ה אָמַ֣ר יְהוָ֔ה אִם־תָּפֵ֙רוּ֙ אֶת־בְּרִיתִ֣י הַיּ֔וֹם וְאֶת־בְּרִיתִ֖י הַלָּ֑יְלָה וּלְבִלְתִּ֛י הֱי֥וֹת יֽוֹמָם־וָלַ֖יְלָה בְּעִתָּֽם׃"}},"definableWords":["LORD","covenant","day","night"],"peopleInVerse":[],"themesInVerse":["covenant"]},"21":{"text":"Then may also my covenant be broken with David my servant, that he should not have a son to reign upon his throne; and with the Levites the priests, my ministers.","ref":"Jeremiah 33:21","synthesized":"then My covenant may also be broken with David My servant and with My ministers the Levites who are priests, so that David will not have a son to reign on his throne.","sources":{"KJV":{"text":"Then may also my covenant be broken with David my servant, that he should not have a son to reign upon his throne; and with the Levites the priests, my ministers."},"BSB":{"text":"then My covenant may also be broken with David My servant and with My ministers the Levites who are priests, so that David will not have a son to reign on his throne."},"TANAKH":{"text":"Then may also My covenant be broken with David My servant, that he should not have a son to reign upon his throne; and with the Levites the priests, My ministers."},"HEBREW":{"text":"גַּם־בְּרִיתִ֤י תֻפַר֙ אֶת־דָּוִ֣ד עַבְדִּ֔י מִהְיֽוֹת־ל֥וֹ בֵ֖ן מֹלֵ֣ךְ עַל־כִּסְא֑וֹ וְאֶת־הַלְוִיִּ֥ם הַכֹּהֲנִ֖ים מְשָׁרְתָֽי׃"}},"definableWords":["covenant","servant","son","reign","throne"],"peopleInVerse":["David"],"themesInVerse":["covenant","kingdom_of_god","kingship"]},"22":{"text":"As the host of heaven cannot be numbered, neither the sand of the sea measured: so will I multiply the seed of David my servant, and the Levites that minister unto me.","ref":"Jeremiah 33:22","synthesized":"As the hosts of heaven cannot be counted and as the sand on the seashore cannot be measured, so too will I multiply the descendants of My servant David and the Levites who minister before Me.”","sources":{"KJV":{"text":"As the host of heaven cannot be numbered, neither the sand of the sea measured: so will I multiply the seed of David my servant, and the Levites that minister unto me."},"BSB":{"text":"As the hosts of heaven cannot be counted and as the sand on the seashore cannot be measured, so too will I multiply the descendants of My servant David and the Levites who minister before Me.”"},"TANAKH":{"text":"As the host of heaven cannot be numbered, neither the sand of the sea measured; so will I multiply the seed of David My servant, and the Levites that minister unto Me."},"HEBREW":{"text":"אֲשֶׁ֤ר לֹֽא־יִסָּפֵר֙ צְבָ֣א הַשָּׁמַ֔יִם וְלֹ֥א יִמַּ֖ד ח֣וֹל הַיָּ֑ם כֵּ֣ן אַרְבֶּ֗ה אֶת־זֶ֙רַע֙ דָּוִ֣ד עַבְדִּ֔י וְאֶת־הַלְוִיִּ֖ם מְשָׁרְתֵ֥י אֹתִֽי׃"}},"definableWords":["heaven","multiply","servant"],"peopleInVerse":["David"]},"23":{"text":"Moreover the word of the LORD came to Jeremiah, saying,","ref":"Jeremiah 33:23","synthesized":"Moreover, the word of the LORD came to Jeremiah:","sources":{"KJV":{"text":"Moreover the word of the LORD came to Jeremiah, saying,"},"BSB":{"text":"Moreover, the word of the LORD came to Jeremiah:"},"TANAKH":{"text":"And the word of HaShem came to Jeremiah, saying:"},"HEBREW":{"text":"וַֽיְהִי֙ דְּבַר־יְהוָ֔ה אֶֽל־יִרְמְיָ֖הוּ לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"24":{"text":"Considerest thou not what this people have spoken, saying, The two families which the LORD hath chosen, he hath even cast them off? thus they have despised my people, that they should be no more a nation before them.","ref":"Jeremiah 33:24","synthesized":"“Have you not noticed what these people are saying: ‘The LORD has rejected the two families He had chosen’? So they despise My people and no longer regard them as a nation.","sources":{"KJV":{"text":"Considerest thou not what this people have spoken, saying, The two families which the LORD hath chosen, he hath even cast them off? thus they have despised my people, that they should be no more a nation before them."},"BSB":{"text":"“Have you not noticed what these people are saying: ‘The LORD has rejected the two families He had chosen’? So they despise My people and no longer regard them as a nation."},"TANAKH":{"text":"'Considerest thou not what this people have spoken, saying: The two families which HaShem did choose, He hath cast them off? and they contemn My people, that they should be no more a nation before them."},"HEBREW":{"text":"הֲל֣וֹא רָאִ֗יתָ מָֽה־הָעָ֤ם הַזֶּה֙ דִּבְּר֣וּ לֵאמֹ֔ר שְׁתֵּ֣י הַמִּשְׁפָּח֗וֹת אֲשֶׁ֨ר בָּחַ֧ר יְהוָ֛ה בָּהֶ֖ם וַיִּמְאָסֵ֑ם וְאֶת־עַמִּי֙ יִנְאָצ֔וּן מִֽהְי֥וֹת ע֖וֹד גּ֥וֹי לִפְנֵיהֶֽם׃"}},"definableWords":["people","LORD","families","nation"],"peopleInVerse":[]},"25":{"text":"Thus saith the LORD; If my covenant be not with day and night, and if I have not appointed the ordinances of heaven and earth;","ref":"Jeremiah 33:25","synthesized":"This is what the LORD says: If I have not established My covenant with the day and the night and the fixed order of heaven and earth,","sources":{"KJV":{"text":"Thus saith the LORD; If my covenant be not with day and night, and if I have not appointed the ordinances of heaven and earth;"},"BSB":{"text":"This is what the LORD says: If I have not established My covenant with the day and the night and the fixed order of heaven and earth,"},"TANAKH":{"text":"Thus saith HaShem: If My covenant be not with day and night, if I have not appointed the ordinances of heaven and earth;"},"HEBREW":{"text":"כֹּ֚ה אָמַ֣ר יְהוָ֔ה אִם־לֹ֥א בְרִיתִ֖י יוֹמָ֣ם וָלָ֑יְלָה חֻקּ֛וֹת שָׁמַ֥יִם וָאָ֖רֶץ לֹא־שָֽׂמְתִּי׃"}},"definableWords":["LORD","covenant","day","night","heaven","earth"],"peopleInVerse":[],"themesInVerse":["covenant"]},"26":{"text":"Then will I cast away the seed of Jacob, and David my servant, so that I will not take any of his seed to be rulers over the seed of Abraham, Isaac, and Jacob: for I will cause their captivity to return, and have mercy on them.","ref":"Jeremiah 33:26","synthesized":"then I would also reject the descendants of Jacob and of My servant David, so as not to take from his descendants rulers over the descendants of Abraham, Isaac, and Jacob. For I will restore them from captivity and will have compassion on them.”","sources":{"KJV":{"text":"Then will I cast away the seed of Jacob, and David my servant, so that I will not take any of his seed to be rulers over the seed of Abraham, Isaac, and Jacob: for I will cause their captivity to return, and have mercy on them."},"BSB":{"text":"then I would also reject the descendants of Jacob and of My servant David, so as not to take from his descendants rulers over the descendants of Abraham, Isaac, and Jacob. For I will restore them from captivity and will have compassion on them.”"},"TANAKH":{"text":"then will I also cast away the seed of Jacob, and of David My servant, so that I will not take of his seed to be rulers over the seed of Abraham, Isaac, and Jacob; for I will cause their captivity to return, and will have compassion on them.'"},"HEBREW":{"text":"גַּם־זֶ֣רַע יַעֲקוֹב֩ וְדָוִ֨ד עַבְדִּ֜י אֶמְאַ֗ס מִקַּ֤חַת מִזַּרְעוֹ֙ מֹֽשְׁלִ֔ים אֶל־זֶ֥רַע אַבְרָהָ֖ם יִשְׂחָ֣ק וְיַעֲקֹ֑ב כִּֽי־אשוב אָשִׁ֥יב אֶת־שְׁבוּתָ֖ם וְרִחַמְתִּֽים׃"}},"definableWords":["Jacob","servant","Abraham","Isaac"],"peopleInVerse":["Jacob","David","Abraham","Isaac"],"themesInVerse":["exile_return"]}}},"34":{"chapter":"34","title":"THE FREEDOM PROCLAMATION REVOKED","verses":{"1":{"text":"The word which came unto Jeremiah from the LORD, when Nebuchadnezzar king of Babylon, and all his army, and all the kingdoms of the earth of his dominion, and all the people, fought against Jerusalem, and against all the cities thereof, saying,","ref":"Jeremiah 34:1","synthesized":"This is the word that came to Jeremiah from the LORD when Nebuchadnezzar king of Babylon, all his army, all the earthly kingdoms under his control, and all the other nations were fighting against Jerusalem and all its surrounding cities.","sources":{"KJV":{"text":"The word which came unto Jeremiah from the LORD, when Nebuchadnezzar king of Babylon, and all his army, and all the kingdoms of the earth of his dominion, and all the people, fought against Jerusalem, and against all the cities thereof, saying,"},"BSB":{"text":"This is the word that came to Jeremiah from the LORD when Nebuchadnezzar king of Babylon, all his army, all the earthly kingdoms under his control, and all the other nations were fighting against Jerusalem and all its surrounding cities."},"TANAKH":{"text":"The word which came unto Jeremiah from HaShem, when Nebuchadrezzar king of Babylon, and all his army, and all the kingdoms of the land of his dominion, and all the peoples, fought against Jerusalem, and against all the cities thereof, saying:"},"HEBREW":{"text":"הַדָּבָ֛ר אֲשֶׁר־הָיָ֥ה אֶֽל־יִרְמְיָ֖הוּ מֵאֵ֣ת יְהוָ֑ה וּנְבוּכַדְרֶאצַּ֣ר מֶֽלֶךְ־בָּבֶ֣ל ׀ וְכָל־חֵיל֡וֹ וְכָל־מַמְלְכ֣וֹת אֶרֶץ֩ מֶמְשֶׁ֨לֶת יָד֜וֹ וְכָל־הָעַמִּ֗ים נִלְחָמִ֧ים עַל־יְרוּשָׁלַ֛͏ִם וְעַל־כָּל־עָרֶ֖יהָ לֵאמֹֽר׃"}},"definableWords":["word","LORD","king","Babylon","nations","Jerusalem"],"peopleInVerse":["Jeremiah","Nebuchadnezzar"],"placesInVerse":["Babylon","Jerusalem"],"themesInVerse":["kingship"]},"2":{"text":"Thus saith the LORD, the God of Israel; Go and speak to Zedekiah king of Judah, and tell him, Thus saith the LORD; Behold, I will give this city into the hand of the king of Babylon, and he shall burn it with fire:","ref":"Jeremiah 34:2","synthesized":"The LORD, the God of Israel, told Jeremiah to go and speak to Zedekiah king of Judah and tell him that this is what the LORD says: “Behold, I am about to deliver this city into the hand of the king of Babylon, and he will burn it down.","sources":{"KJV":{"text":"Thus saith the LORD, the God of Israel; Go and speak to Zedekiah king of Judah, and tell him, Thus saith the LORD; Behold, I will give this city into the hand of the king of Babylon, and he shall burn it with fire:"},"BSB":{"text":"The LORD, the God of Israel, told Jeremiah to go and speak to Zedekiah king of Judah and tell him that this is what the LORD says: “Behold, I am about to deliver this city into the hand of the king of Babylon, and he will burn it down."},"TANAKH":{"text":"Thus saith HaShem, the G-d of Israel: Go, and speak to Zedekiah king of Judah, and tell him: Thus saith HaShem: Behold, I will give this city into the hand of the king of Babylon, and he shall burn it with fire;"},"HEBREW":{"text":"כֹּֽה־אָמַ֤ר יְהוָה֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל הָלֹךְ֙ וְאָ֣מַרְתָּ֔ אֶל־צִדְקִיָּ֖הוּ מֶ֣לֶךְ יְהוּדָ֑ה וְאָמַרְתָּ֣ אֵלָ֗יו כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִנְנִ֨י נֹתֵ֜ן אֶת־הָעִ֤יר הַזֹּאת֙ בְּיַ֣ד מֶֽלֶךְ־בָּבֶ֔ל וּשְׂרָפָ֖הּ בָּאֵֽשׁ׃"}},"definableWords":["LORD","God","Israel","king","Judah","Lord","deliver","King","Babylon"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Babylon"],"themesInVerse":["kingship","redemption","salvation"]},"3":{"text":"And thou shalt not escape out of his hand, but shalt surely be taken, and delivered into his hand; and thine eyes shall behold the eyes of the king of Babylon, and he shall speak with thee mouth to mouth, and thou shalt go to Babylon.","ref":"Jeremiah 34:3","synthesized":"And you yourself will not escape his grasp, but will surely be captured and delivered into his hand. You will see the king of Babylon eye to eye and speak with him face to face; and you will go to Babylon.","sources":{"KJV":{"text":"And thou shalt not escape out of his hand, but shalt surely be taken, and delivered into his hand; and thine eyes shall behold the eyes of the king of Babylon, and he shall speak with thee mouth to mouth, and thou shalt go to Babylon."},"BSB":{"text":"And you yourself will not escape his grasp, but will surely be captured and delivered into his hand. You will see the king of Babylon eye to eye and speak with him face to face; and you will go to Babylon."},"TANAKH":{"text":"and thou shalt not escape out of his hand, but shalt surely be taken, and delivered into his hand; and thine eyes shall behold the eyes of the king of Babylon, and he shall speak with thee mouth to mouth, and thou shalt go to Babylon."},"HEBREW":{"text":"וְאַתָּ֗ה לֹ֚א תִמָּלֵט֙ מִיָּד֔וֹ כִּ֚י תָּפֹ֣שׂ תִּתָּפֵ֔שׂ וּבְיָד֖וֹ תִּנָּתֵ֑ן וְֽ֠עֵינֶיךָ אֶת־עֵינֵ֨י מֶֽלֶךְ־בָּבֶ֜ל תִּרְאֶ֗ינָה וּפִ֛יהוּ אֶת־פִּ֥יךָ יְדַבֵּ֖ר וּבָבֶ֥ל תָּבֽוֹא׃"}},"definableWords":["see","king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"4":{"text":"Yet hear the word of the LORD, O Zedekiah king of Judah; Thus saith the LORD of thee, Thou shalt not die by the sword:","ref":"Jeremiah 34:4","synthesized":"Yet hear the word of the LORD, O Zedekiah king of Judah. This is what the LORD says concerning you: You will not die by the sword;","sources":{"KJV":{"text":"Yet hear the word of the LORD, O Zedekiah king of Judah; Thus saith the LORD of thee, Thou shalt not die by the sword:"},"BSB":{"text":"Yet hear the word of the LORD, O Zedekiah king of Judah. This is what the LORD says concerning you: You will not die by the sword;"},"TANAKH":{"text":"Yet hear the word of HaShem, O Zedekiah king of Judah: Thus saith HaShem concerning thee: Thou shalt not die by the sword;"},"HEBREW":{"text":"אַ֚ךְ שְׁמַ֣ע דְּבַר־יְהוָ֔ה צִדְקִיָּ֖הוּ מֶ֣לֶךְ יְהוּדָ֑ה כֹּֽה־אָמַ֤ר יְהוָה֙ עָלֶ֔יךָ לֹ֥א תָמ֖וּת בֶּחָֽרֶב׃"}},"definableWords":["hear","word","LORD","king","Judah","Lord","die"],"peopleInVerse":[],"themesInVerse":["kingship"]},"5":{"text":"But thou shalt die in peace: and with the burnings of thy fathers, the former kings which were before thee, so shall they burn odours for thee; and they will lament thee, saying, Ah lord! for I have pronounced the word, saith the LORD.","ref":"Jeremiah 34:5","synthesized":"you will die in peace. As spices were burned for your fathers, the former kings who preceded you, so people will burn spices for you and lament, ‘Alas, O master!’ For I Myself have spoken this word, declares the LORD.”","sources":{"KJV":{"text":"But thou shalt die in peace: and with the burnings of thy fathers, the former kings which were before thee, so shall they burn odours for thee; and they will lament thee, saying, Ah lord! for I have pronounced the word, saith the LORD."},"BSB":{"text":"you will die in peace. As spices were burned for your fathers, the former kings who preceded you, so people will burn spices for you and lament, ‘Alas, O master!’ For I Myself have spoken this word, declares the LORD.”"},"TANAKH":{"text":"thou shalt die in peace; and with the burnings of thy fathers, the former kings that were before thee, so shall they make a burning for thee; and they shall lament thee: 'Ah lord!' for I have spoken the word, saith HaShem."},"HEBREW":{"text":"בְּשָׁל֣וֹם תָּמ֗וּת וּֽכְמִשְׂרְפ֣וֹת אֲ֠בוֹתֶיךָ הַמְּלָכִ֨ים הָרִֽאשֹׁנִ֜ים אֲשֶׁר־הָי֣וּ לְפָנֶ֗יךָ כֵּ֚ן יִשְׂרְפוּ־לָ֔ךְ וְה֥וֹי אָד֖וֹן יִסְפְּדוּ־לָ֑ךְ כִּֽי־דָבָ֥ר אֲנִֽי־דִבַּ֖רְתִּי נְאֻם־יְהוָֽה׃"}},"definableWords":["die","peace","fathers","kings","people","word","LORD"],"peopleInVerse":[],"themesInVerse":["peace"]},"6":{"text":"Then Jeremiah the prophet spake all these words unto Zedekiah king of Judah in Jerusalem,","ref":"Jeremiah 34:6","synthesized":"In Jerusalem, then, Jeremiah the prophet relayed all these words to Zedekiah king of Judah","sources":{"KJV":{"text":"Then Jeremiah the prophet spake all these words unto Zedekiah king of Judah in Jerusalem,"},"BSB":{"text":"In Jerusalem, then, Jeremiah the prophet relayed all these words to Zedekiah king of Judah"},"TANAKH":{"text":"Then Jeremiah the prophet spoke all these words unto Zedekiah king of Judah in Jerusalem,"},"HEBREW":{"text":"וַיְדַבֵּר֙ יִרְמְיָ֣הוּ הַנָּבִ֔יא אֶל־צִדְקִיָּ֖הוּ מֶ֣לֶךְ יְהוּדָ֑ה אֵ֛ת כָּל־הַדְּבָרִ֥ים הָאֵ֖לֶּה בִּירוּשָׁלָֽ͏ִם׃"}},"definableWords":["Jerusalem","prophet","king","Judah"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Jerusalem"],"themesInVerse":["kingship"]},"7":{"text":"When the king of Babylon’s army fought against Jerusalem, and against all the cities of Judah that were left, against Lachish, and against Azekah: for these defenced cities remained of the cities of Judah.","ref":"Jeremiah 34:7","synthesized":"as the army of the king of Babylon was fighting against Jerusalem and the remaining cities of Judah—against Lachish and Azekah. For these were the only fortified cities remaining in Judah.","sources":{"KJV":{"text":"When the king of Babylon’s army fought against Jerusalem, and against all the cities of Judah that were left, against Lachish, and against Azekah: for these defenced cities remained of the cities of Judah."},"BSB":{"text":"as the army of the king of Babylon was fighting against Jerusalem and the remaining cities of Judah—against Lachish and Azekah. For these were the only fortified cities remaining in Judah."},"TANAKH":{"text":"when the king of Babylon's army fought against Jerusalem, and against all the cities of Judah that were left, against Lachish and against Azekah; for these alone remained of the cities of Judah as fortified cities."},"HEBREW":{"text":"וְחֵ֣יל מֶֽלֶךְ־בָּבֶ֗ל נִלְחָמִים֙ עַל־יְר֣וּשָׁלִַ֔ם וְעַ֛ל כָּל־עָרֵ֥י יְהוּדָ֖ה הַנּֽוֹתָר֑וֹת אֶל־לָכִישׁ֙ וְאֶל־עֲזֵקָ֔ה כִּ֣י הֵ֗נָּה נִשְׁאֲר֛וּ בְּעָרֵ֥י יְהוּדָ֖ה עָרֵ֥י מִבְצָֽר׃"}},"definableWords":["king","Babylon","Jerusalem","Judah"],"peopleInVerse":[],"placesInVerse":["Babylon","Jerusalem"],"themesInVerse":["kingship"]},"8":{"text":"This is the word that came unto Jeremiah from the LORD, after that the king Zedekiah had made a covenant with all the people which were at Jerusalem, to proclaim liberty unto them;","ref":"Jeremiah 34:8","synthesized":"After King Zedekiah had made a covenant with all the people in Jerusalem to proclaim liberty, the word came to Jeremiah from the LORD","sources":{"KJV":{"text":"This is the word that came unto Jeremiah from the LORD, after that the king Zedekiah had made a covenant with all the people which were at Jerusalem, to proclaim liberty unto them;"},"BSB":{"text":"After King Zedekiah had made a covenant with all the people in Jerusalem to proclaim liberty, the word came to Jeremiah from the LORD"},"TANAKH":{"text":"The word that came unto Jeremiah from HaShem, after that the king Zedekiah had made a covenant with all the people that were at Jerusalem, to proclaim liberty unto them;"},"HEBREW":{"text":"הַדָּבָ֛ר אֲשֶׁר־הָיָ֥ה אֶֽל־יִרְמְיָ֖הוּ מֵאֵ֣ת יְהוָ֑ה אַחֲרֵ֡י כְּרֹת֩ הַמֶּ֨לֶךְ צִדְקִיָּ֜הוּ בְּרִ֗ית אֶת־כָּל־הָעָם֙ אֲשֶׁ֣ר בִּירֽוּשָׁלִַ֔ם לִקְרֹ֥א לָהֶ֖ם דְּרֽוֹר׃"}},"definableWords":["King","made","covenant","people","Jerusalem","word","LORD"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Jerusalem"],"themesInVerse":["covenant","creation","kingship"]},"9":{"text":"That every man should let his manservant, and every man his maidservant, being an Hebrew or an Hebrewess, go free; that none should serve himself of them, to wit, of a Jew his brother.","ref":"Jeremiah 34:9","synthesized":"that each man should free his Hebrew slaves, both male and female, and no one should hold his fellow Jew in bondage.","sources":{"KJV":{"text":"That every man should let his manservant, and every man his maidservant, being an Hebrew or an Hebrewess, go free; that none should serve himself of them, to wit, of a Jew his brother."},"BSB":{"text":"that each man should free his Hebrew slaves, both male and female, and no one should hold his fellow Jew in bondage."},"TANAKH":{"text":"that every man should let his manservant, and every man his maidservant, being a Hebrew man or a Hebrew woman, go free; that none should make bondmen of them, even of a Jew his brother;"},"HEBREW":{"text":"לְ֠שַׁלַּח אִ֣ישׁ אֶת־עַבְדּ֞וֹ וְאִ֧ישׁ אֶת־שִׁפְחָת֛וֹ הָעִבְרִ֥י וְהָעִבְרִיָּ֖ה חָפְשִׁ֑ים לְבִלְתִּ֧י עֲבָד־בָּ֛ם בִּיהוּדִ֥י אָחִ֖יהוּ אִֽישׁ׃"}},"definableWords":["man","male","female","one","Jew"],"peopleInVerse":[]},"10":{"text":"Now when all the princes, and all the people, which had entered into the covenant, heard that every one should let his manservant, and every one his maidservant, go free, that none should serve themselves of them any more, then they obeyed, and let them go.","ref":"Jeremiah 34:10","synthesized":"So all the officials and all the people who entered into this covenant agreed that they would free their menservants and maidservants and no longer hold them in bondage. They obeyed and released them,","sources":{"KJV":{"text":"Now when all the princes, and all the people, which had entered into the covenant, heard that every one should let his manservant, and every one his maidservant, go free, that none should serve themselves of them any more, then they obeyed, and let them go."},"BSB":{"text":"So all the officials and all the people who entered into this covenant agreed that they would free their menservants and maidservants and no longer hold them in bondage. They obeyed and released them,"},"TANAKH":{"text":"and all the princes and all the people hearkened, that had entered into the covenant to let every one his man-servant, and every one his maid-servant, go free, and not to make bondmen of them any more; they hearkened, and let them go;"},"HEBREW":{"text":"וַיִּשְׁמְעוּ֩ כָל־הַשָּׂרִ֨ים וְכָל־הָעָ֜ם אֲשֶׁר־בָּ֣אוּ בַבְּרִ֗ית לְ֠שַׁלַּח אִ֣ישׁ אֶת־עַבְדּ֞וֹ וְאִ֤ישׁ אֶת־שִׁפְחָתוֹ֙ חָפְשִׁ֔ים לְבִלְתִּ֥י עֲבָד־בָּ֖ם ע֑וֹד וַֽיִּשְׁמְע֖וּ וַיְשַׁלֵּֽחוּ׃"}},"definableWords":["people","covenant"],"peopleInVerse":[],"themesInVerse":["covenant"]},"11":{"text":"But afterward they turned, and caused the servants and the handmaids, whom they had let go free, to return, and brought them into subjection for servants and for handmaids.","ref":"Jeremiah 34:11","synthesized":"but later they changed their minds and took back the menservants and maidservants they had freed, and they forced them to become slaves again.","sources":{"KJV":{"text":"But afterward they turned, and caused the servants and the handmaids, whom they had let go free, to return, and brought them into subjection for servants and for handmaids."},"BSB":{"text":"but later they changed their minds and took back the menservants and maidservants they had freed, and they forced them to become slaves again."},"TANAKH":{"text":"but afterwards they turned, and caused the servants and the handmaids, whom they had let go free, to return, and brought them into subjection for servants and for handmaids;"},"HEBREW":{"text":"וַיָּשׁ֙וּבוּ֙ אַחֲרֵי־כֵ֔ן וַיָּשִׁ֗בוּ אֶת־הָֽעֲבָדִים֙ וְאֶת־הַשְּׁפָח֔וֹת אֲשֶׁ֥ר שִׁלְּח֖וּ חָפְשִׁ֑ים ויכבישום וַֽיִּכְבְּשׁ֔וּם לַעֲבָדִ֖ים וְלִשְׁפָחֽוֹת׃"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Therefore the word of the LORD came to Jeremiah from the LORD, saying,","ref":"Jeremiah 34:12","synthesized":"Then the word of the LORD came to Jeremiah from the LORD, saying,","sources":{"KJV":{"text":"Therefore the word of the LORD came to Jeremiah from the LORD, saying,"},"BSB":{"text":"Then the word of the LORD came to Jeremiah from the LORD, saying,"},"TANAKH":{"text":"therefore the word of HaShem came to Jeremiah from HaShem, saying:"},"HEBREW":{"text":"וַיְהִ֤י דְבַר־יְהוָה֙ אֶֽל־יִרְמְיָ֔הוּ מֵאֵ֥ת יְהוָ֖ה לֵאמֹֽר׃"}},"definableWords":["word","LORD","Lord"],"peopleInVerse":["Jeremiah"]},"13":{"text":"Thus saith the LORD, the God of Israel; I made a covenant with your fathers in the day that I brought them forth out of the land of Egypt, out of the house of bondmen, saying,","ref":"Jeremiah 34:13","synthesized":"“This is what the LORD, the God of Israel, says: I made a covenant with your forefathers when I brought them out of the land of Egypt, out of the house of slavery, saying:","sources":{"KJV":{"text":"Thus saith the LORD, the God of Israel; I made a covenant with your fathers in the day that I brought them forth out of the land of Egypt, out of the house of bondmen, saying,"},"BSB":{"text":"“This is what the LORD, the God of Israel, says: I made a covenant with your forefathers when I brought them out of the land of Egypt, out of the house of slavery, saying:"},"TANAKH":{"text":"Thus saith HaShem, the G-d of Israel: I made a covenant with your fathers in the day that I brought them forth out of the land of Egypt, out of the house of bondage, saying:"},"HEBREW":{"text":"כֹּֽה־אָמַ֥ר יְהוָ֖ה אֱלֹהֵ֣י יִשְׂרָאֵ֑ל אָנֹכִ֗י כָּרַ֤תִּֽי בְרִית֙ אֶת־אֲב֣וֹתֵיכֶ֔ם בְּי֨וֹם הוֹצִאִ֤י אוֹתָם֙ מֵאֶ֣רֶץ מִצְרַ֔יִם מִבֵּ֥ית עֲבָדִ֖ים לֵאמֹֽר׃"}},"definableWords":["LORD","God","Israel","made","covenant","land","Egypt","house"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["covenant","creation","exodus_pattern","land_promise"]},"14":{"text":"At the end of seven years let ye go every man his brother an Hebrew, which hath been sold unto thee; and when he hath served thee six years, thou shalt let him go free from thee: but your fathers hearkened not unto me, neither inclined their ear.","ref":"Jeremiah 34:14","synthesized":"Every seventh year, each of you must free his Hebrew brother who has sold himself to you. He may serve you six years, but then you must let him go free. But your fathers did not listen or incline their ear.","sources":{"KJV":{"text":"At the end of seven years let ye go every man his brother an Hebrew, which hath been sold unto thee; and when he hath served thee six years, thou shalt let him go free from thee: but your fathers hearkened not unto me, neither inclined their ear."},"BSB":{"text":"Every seventh year, each of you must free his Hebrew brother who has sold himself to you. He may serve you six years, but then you must let him go free. But your fathers did not listen or incline their ear."},"TANAKH":{"text":"'At the end of seven years ye shall let go every man his brother that is a Hebrew, that hath been sold unto thee, and hath served thee six years, thou shalt let him go free from thee'; but your fathers hearkened not unto Me, neither inclined their ear."},"HEBREW":{"text":"מִקֵּ֣ץ שֶׁ֣בַע שָׁנִ֡ים תְּֽשַׁלְּח֡וּ אִישׁ֩ אֶת־אָחִ֨יו הָעִבְרִ֜י אֲשֶֽׁר־יִמָּכֵ֣ר לְךָ֗ וַעֲבָֽדְךָ֙ שֵׁ֣שׁ שָׁנִ֔ים וְשִׁלַּחְתּ֥וֹ חָפְשִׁ֖י מֵֽעִמָּ֑ךְ וְלֹֽא־שָׁמְע֤וּ אֲבֽוֹתֵיכֶם֙ אֵלַ֔י וְלֹ֥א הִטּ֖וּ אֶת־אָזְנָֽם׃"}},"definableWords":["year","brother","years","fathers","or"],"peopleInVerse":[]},"15":{"text":"And ye were now turned, and had done right in my sight, in proclaiming liberty every man to his neighbour; and ye had made a covenant before me in the house which is called by my name:","ref":"Jeremiah 34:15","synthesized":"Recently you repented and did what pleased Me; each of you proclaimed freedom for his neighbor. You made a covenant before Me in the house that bears My Name.","sources":{"KJV":{"text":"And ye were now turned, and had done right in my sight, in proclaiming liberty every man to his neighbour; and ye had made a covenant before me in the house which is called by my name:"},"BSB":{"text":"Recently you repented and did what pleased Me; each of you proclaimed freedom for his neighbor. You made a covenant before Me in the house that bears My Name."},"TANAKH":{"text":"And ye were now turned, and had done that which is right in Mine eyes, in proclaiming liberty every man to his neighbour; and ye had made a covenant before Me in the house whereon My name is called;"},"HEBREW":{"text":"וַתָּשֻׁ֨בוּ אַתֶּ֜ם הַיּ֗וֹם וַתַּעֲשׂ֤וּ אֶת־הַיָּשָׁר֙ בְּעֵינַ֔י לִקְרֹ֥א דְר֖וֹר אִ֣ישׁ לְרֵעֵ֑הוּ וַתִּכְרְת֤וּ בְרִית֙ לְפָנַ֔י בַּבַּ֕יִת אֲשֶׁר־נִקְרָ֥א שְׁמִ֖י עָלָֽיו׃"}},"definableWords":["made","covenant","house","name"],"peopleInVerse":[],"themesInVerse":["covenant","creation"]},"16":{"text":"But ye turned and polluted my name, and caused every man his servant, and every man his handmaid, whom he had set at liberty at their pleasure, to return, and brought them into subjection, to be unto you for servants and for handmaids.","ref":"Jeremiah 34:16","synthesized":"But now you have changed your minds and profaned My name. Each of you has taken back the menservants and maidservants whom you had set at liberty to go wherever they wanted, and you have again forced them to be your slaves.","sources":{"KJV":{"text":"But ye turned and polluted my name, and caused every man his servant, and every man his handmaid, whom he had set at liberty at their pleasure, to return, and brought them into subjection, to be unto you for servants and for handmaids."},"BSB":{"text":"But now you have changed your minds and profaned My name. Each of you has taken back the menservants and maidservants whom you had set at liberty to go wherever they wanted, and you have again forced them to be your slaves."},"TANAKH":{"text":"but ye turned and profaned My name, and caused every man his servant, and every man his handmaid, whom ye had let go free at their pleasure, to return; and ye brought them into subjection, to be unto you for servants and for handmaids."},"HEBREW":{"text":"וַתָּשֻׁ֙בוּ֙ וַתְּחַלְּל֣וּ אֶת־שְׁמִ֔י וַתָּשִׁ֗בוּ אִ֤ישׁ אֶת־עַבְדּוֹ֙ וְאִ֣ישׁ אֶת־שִׁפְחָת֔וֹ אֲשֶׁר־שִׁלַּחְתֶּ֥ם חָפְשִׁ֖ים לְנַפְשָׁ֑ם וַתִּכְבְּשׁ֣וּ אֹתָ֔ם לִֽהְי֣וֹת לָכֶ֔ם לַעֲבָדִ֖ים וְלִשְׁפָחֽוֹת׃"}},"definableWords":["name"],"peopleInVerse":[]},"17":{"text":"Therefore thus saith the LORD; Ye have not hearkened unto me, in proclaiming liberty, every one to his brother, and every man to his neighbour: behold, I proclaim a liberty for you, saith the LORD, to the sword, to the pestilence, and to the famine; and I will make you to be removed into all the kingdoms of the earth.","ref":"Jeremiah 34:17","synthesized":"Therefore this is what the LORD says: You have not obeyed Me; you have not proclaimed freedom, each man for his brother and for his neighbor. So now I proclaim freedom for you, declares the LORD—freedom to fall by sword, by plague, and by famine! I will make you a horror to all the kingdoms of the earth.","sources":{"KJV":{"text":"Therefore thus saith the LORD; Ye have not hearkened unto me, in proclaiming liberty, every one to his brother, and every man to his neighbour: behold, I proclaim a liberty for you, saith the LORD, to the sword, to the pestilence, and to the famine; and I will make you to be removed into all the kingdoms of the earth."},"BSB":{"text":"Therefore this is what the LORD says: You have not obeyed Me; you have not proclaimed freedom, each man for his brother and for his neighbor. So now I proclaim freedom for you, declares the LORD—freedom to fall by sword, by plague, and by famine! I will make you a horror to all the kingdoms of the earth."},"TANAKH":{"text":"Therefore thus saith HaShem: Ye have not hearkened unto Me, to proclaim liberty, every man to his brother, and every man to his neighbour; behold, I proclaim for you a liberty, saith HaShem, unto the sword, unto the pestilence, and unto the famine; and I will make you a horror unto all the kingdoms of the earth."},"HEBREW":{"text":"לָכֵן֮ כֹּה־אָמַ֣ר יְהוָה֒ אַתֶּם֙ לֹֽא־שְׁמַעְתֶּ֣ם אֵלַ֔י לִקְרֹ֣א דְר֔וֹר אִ֥ישׁ לְאָחִ֖יו וְאִ֣ישׁ לְרֵעֵ֑הוּ הִנְנִ֣י קֹרֵא֩ לָכֶ֨ם דְּר֜וֹר נְאֻם־יְהוָ֗ה אֶל־הַחֶ֙רֶב֙ אֶל־הַדֶּ֣בֶר וְאֶל־הָרָעָ֔ב וְנָתַתִּ֤י אֶתְכֶם֙ לזועה לְזַעֲוָ֔ה לְכֹ֖ל מַמְלְכ֥וֹת הָאָֽרֶץ׃"}},"definableWords":["LORD","man","brother","Lord","make","earth"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"18":{"text":"And I will give the men that have transgressed my covenant, which have not performed the words of the covenant which they had made before me, when they cut the calf in twain, and passed between the parts thereof,","ref":"Jeremiah 34:18","synthesized":"And those who have transgressed My covenant and have not fulfilled the terms of the covenant they made before Me, I will treat like the calf they cut in two in order to pass between its pieces.","sources":{"KJV":{"text":"And I will give the men that have transgressed my covenant, which have not performed the words of the covenant which they had made before me, when they cut the calf in twain, and passed between the parts thereof,"},"BSB":{"text":"And those who have transgressed My covenant and have not fulfilled the terms of the covenant they made before Me, I will treat like the calf they cut in two in order to pass between its pieces."},"TANAKH":{"text":"And I will give the men that have transgressed My covenant, that have not performed the words of the covenant which they made before Me, when they cut the calf in twain and passed between the parts thereof;"},"HEBREW":{"text":"וְנָתַתִּ֣י אֶת־הָאֲנָשִׁ֗ים הָעֹֽבְרִים֙ אֶת־בְּרִתִ֔י אֲשֶׁ֤ר לֹֽא־הֵקִ֙ימוּ֙ אֶת־דִּבְרֵ֣י הַבְּרִ֔ית אֲשֶׁ֥ר כָּרְת֖וּ לְפָנָ֑י הָעֵ֙גֶל֙ אֲשֶׁ֣ר כָּרְת֣וּ לִשְׁנַ֔יִם וַיַּעַבְר֖וּ בֵּ֥ין בְּתָרָֽיו׃"}},"definableWords":["covenant","made"],"peopleInVerse":[],"themesInVerse":["covenant","creation"]},"19":{"text":"The princes of Judah, and the princes of Jerusalem, the eunuchs, and the priests, and all the people of the land, which passed between the parts of the calf;","ref":"Jeremiah 34:19","synthesized":"The officials of Judah and Jerusalem, the court officials, the priests, and all the people of the land who passed between the pieces of the calf,","sources":{"KJV":{"text":"The princes of Judah, and the princes of Jerusalem, the eunuchs, and the priests, and all the people of the land, which passed between the parts of the calf;"},"BSB":{"text":"The officials of Judah and Jerusalem, the court officials, the priests, and all the people of the land who passed between the pieces of the calf,"},"TANAKH":{"text":"the princes of Judah, and the princes of Jerusalem, the officers, and the priests, and all the people of the land, that passed between the parts of the calf;"},"HEBREW":{"text":"שָׂרֵ֨י יְהוּדָ֜ה וְשָׂרֵ֣י יְרוּשָׁלִַ֗ם הַסָּֽרִסִים֙ וְהַכֹּ֣הֲנִ֔ים וְכֹ֖ל עַ֣ם הָאָ֑רֶץ הָעֹ֣בְרִ֔ים בֵּ֖ין בִּתְרֵ֥י הָעֵֽגֶל׃"}},"definableWords":["Judah","Jerusalem","people","land"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["land_promise"]},"20":{"text":"I will even give them into the hand of their enemies, and into the hand of them that seek their life: and their dead bodies shall be for meat unto the fowls of the heaven, and to the beasts of the earth.","ref":"Jeremiah 34:20","synthesized":"I will deliver into the hands of their enemies who seek their lives. Their corpses will become food for the birds of the air and the beasts of the earth.","sources":{"KJV":{"text":"I will even give them into the hand of their enemies, and into the hand of them that seek their life: and their dead bodies shall be for meat unto the fowls of the heaven, and to the beasts of the earth."},"BSB":{"text":"I will deliver into the hands of their enemies who seek their lives. Their corpses will become food for the birds of the air and the beasts of the earth."},"TANAKH":{"text":"I will even give them into the hand of their enemies, and into the hand of them that seek their life; and their dead bodies shall be for food unto the fowls of the heaven, and to the beasts of the earth."},"HEBREW":{"text":"וְנָתַתִּ֤י אוֹתָם֙ בְּיַ֣ד אֹֽיְבֵיהֶ֔ם וּבְיַ֖ד מְבַקְשֵׁ֣י נַפְשָׁ֑ם וְהָיְתָ֤ה נִבְלָתָם֙ לְמַֽאֲכָ֔ל לְע֥וֹף הַשָּׁמַ֖יִם וּלְבֶהֱמַ֥ת הָאָֽרֶץ׃"}},"definableWords":["deliver","seek","birds","earth"],"peopleInVerse":[],"themesInVerse":["redemption","salvation"]},"21":{"text":"And Zedekiah king of Judah and his princes will I give into the hand of their enemies, and into the hand of them that seek their life, and into the hand of the king of Babylon’s army, which are gone up from you.","ref":"Jeremiah 34:21","synthesized":"And I will deliver Zedekiah king of Judah and his officials into the hands of their enemies who seek their lives, to the army of the king of Babylon that had withdrawn from you.","sources":{"KJV":{"text":"And Zedekiah king of Judah and his princes will I give into the hand of their enemies, and into the hand of them that seek their life, and into the hand of the king of Babylon’s army, which are gone up from you."},"BSB":{"text":"And I will deliver Zedekiah king of Judah and his officials into the hands of their enemies who seek their lives, to the army of the king of Babylon that had withdrawn from you."},"TANAKH":{"text":"And Zedekiah king of Judah and his princes will I give into the hand of their enemies, and into the hand of them that seek their life, and into the hand of the king of Babylon's army, that are gone up from you."},"HEBREW":{"text":"וְאֶת־צִדְקִיָּ֨הוּ מֶֽלֶךְ־יְהוּדָ֜ה וְאֶת־שָׂרָ֗יו אֶתֵּן֙ בְּיַ֣ד אֹֽיְבֵיהֶ֔ם וּבְיַ֖ד מְבַקְשֵׁ֣י נַפְשָׁ֑ם וּבְיַד חֵ֚יל מֶ֣לֶךְ בָּבֶ֔ל הָעֹלִ֖ים מֵעֲלֵיכֶֽם׃"}},"definableWords":["deliver","king","Judah","seek","King","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship","redemption","salvation"]},"22":{"text":"Behold, I will command, saith the LORD, and cause them to return to this city; and they shall fight against it, and take it, and burn it with fire: and I will make the cities of Judah a desolation without an inhabitant.","ref":"Jeremiah 34:22","synthesized":"Behold, I am going to give the command, declares the LORD, and I will bring them back to this city. They will fight against it, capture it, and burn it down. And I will make the cities of Judah a desolation, without inhabitant.”","sources":{"KJV":{"text":"Behold, I will command, saith the LORD, and cause them to return to this city; and they shall fight against it, and take it, and burn it with fire: and I will make the cities of Judah a desolation without an inhabitant."},"BSB":{"text":"Behold, I am going to give the command, declares the LORD, and I will bring them back to this city. They will fight against it, capture it, and burn it down. And I will make the cities of Judah a desolation, without inhabitant.”"},"TANAKH":{"text":"Behold, I will command, saith HaShem, and cause them to return to this city; and they shall fight against it, and take it, and burn it with fire; and I will make the cities of Judah a desolation, without inhabitant."},"HEBREW":{"text":"הִנְנִ֨י מְצַוֶּ֜ה נְאֻם־יְהוָ֗ה וַהֲשִׁ֨בֹתִ֜ים אֶל־הָעִ֤יר הַזֹּאת֙ וְנִלְחֲמ֣וּ עָלֶ֔יהָ וּלְכָד֖וּהָ וּשְׂרָפֻ֣הָ בָאֵ֑שׁ וְאֶת־עָרֵ֧י יְהוּדָ֛ה אֶתֵּ֥ן שְׁמָמָ֖ה מֵאֵ֥ין יֹשֵֽׁב׃"}},"definableWords":["LORD","fight","make","Judah"],"peopleInVerse":[],"themesInVerse":["spiritual_warfare"]}}},"35":{"chapter":"35","title":"THE RECHABITES' FAITHFULNESS","verses":{"1":{"text":"The word which came unto Jeremiah from the LORD in the days of Jehoiakim the son of Josiah king of Judah, saying,","ref":"Jeremiah 35:1","synthesized":"This is the word that came to Jeremiah from the LORD in the days of Jehoiakim son of Josiah king of Judah:","sources":{"KJV":{"text":"The word which came unto Jeremiah from the LORD in the days of Jehoiakim the son of Josiah king of Judah, saying,"},"BSB":{"text":"This is the word that came to Jeremiah from the LORD in the days of Jehoiakim son of Josiah king of Judah:"},"TANAKH":{"text":"The word which came unto Jeremiah from HaShem in the days of Jehoiakim the son of Josiah, king of Judah, saying:"},"HEBREW":{"text":"הַדָּבָ֛ר אֲשֶׁר־הָיָ֥ה אֶֽל־יִרְמְיָ֖הוּ מֵאֵ֣ת יְהוָ֑ה בִּימֵ֨י יְהוֹיָקִ֧ים בֶּן־יֹאשִׁיָּ֛הוּ מֶ֥לֶךְ יְהוּדָ֖ה לֵאמֹֽר׃"}},"definableWords":["word","LORD","days","son","king","Judah"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship"]},"2":{"text":"Go unto the house of the Rechabites, and speak unto them, and bring them into the house of the LORD, into one of the chambers, and give them wine to drink.","ref":"Jeremiah 35:2","synthesized":"“Go to the house of the Rechabites, speak to them, and bring them to one of the chambers of the house of the LORD to offer them a drink of wine.”","sources":{"KJV":{"text":"Go unto the house of the Rechabites, and speak unto them, and bring them into the house of the LORD, into one of the chambers, and give them wine to drink."},"BSB":{"text":"“Go to the house of the Rechabites, speak to them, and bring them to one of the chambers of the house of the LORD to offer them a drink of wine.”"},"TANAKH":{"text":"'Go unto the house of the Rechabites, and speak unto them, and bring them into the house of HaShem, into one of the chambers, and give them wine to drink.'"},"HEBREW":{"text":"הָלוֹךְ֮ אֶל־בֵּ֣ית הָרֵכָבִים֒ וְדִבַּרְתָּ֣ אוֹתָ֔ם וַהֲבִֽאוֹתָם֙ בֵּ֣ית יְהוָ֔ה אֶל־אַחַ֖ת הַלְּשָׁכ֑וֹת וְהִשְׁקִיתָ֥ אוֹתָ֖ם יָֽיִן׃"}},"definableWords":["house","one","LORD"],"peopleInVerse":[]},"3":{"text":"Then I took Jaazaniah the son of Jeremiah, the son of Habaziniah, and his brethren, and all his sons, and the whole house of the Rechabites;","ref":"Jeremiah 35:3","synthesized":"So I took Jaazaniah son of Jeremiah, the son of Habazziniah, and his brothers and all his sons—the entire house of the Rechabites—","sources":{"KJV":{"text":"Then I took Jaazaniah the son of Jeremiah, the son of Habaziniah, and his brethren, and all his sons, and the whole house of the Rechabites;"},"BSB":{"text":"So I took Jaazaniah son of Jeremiah, the son of Habazziniah, and his brothers and all his sons—the entire house of the Rechabites—"},"TANAKH":{"text":"Then I took Jaazaniah the son of Jeremiah, the son of Habazziniah, and his brethren, and all his sons, and the whole house of the Rechabites;"},"HEBREW":{"text":"וָאֶקַּ֞ח אֶת־יַאֲזַנְיָ֤ה בֶֽן־יִרְמְיָ֙הוּ֙ בֶּן־חֲבַצִּנְיָ֔ה וְאֶת־אֶחָ֖יו וְאֶת־כָּל־בָּנָ֑יו וְאֵ֖ת כָּל־בֵּ֥ית הָרֵכָבִֽים׃"}},"definableWords":["son","Son","sons","house"],"peopleInVerse":["Jeremiah"]},"4":{"text":"And I brought them into the house of the LORD, into the chamber of the sons of Hanan, the son of Igdaliah, a man of God, which was by the chamber of the princes, which was above the chamber of Maaseiah the son of Shallum, the keeper of the door:","ref":"Jeremiah 35:4","synthesized":"and I brought them into the house of the LORD, to a chamber occupied by the sons of Hanan son of Igdaliah, a man of God. This room was near the chamber of the officials, which was above the chamber of Maaseiah son of Shallum the doorkeeper.","sources":{"KJV":{"text":"And I brought them into the house of the LORD, into the chamber of the sons of Hanan, the son of Igdaliah, a man of God, which was by the chamber of the princes, which was above the chamber of Maaseiah the son of Shallum, the keeper of the door:"},"BSB":{"text":"and I brought them into the house of the LORD, to a chamber occupied by the sons of Hanan son of Igdaliah, a man of God. This room was near the chamber of the officials, which was above the chamber of Maaseiah son of Shallum the doorkeeper."},"TANAKH":{"text":"and I brought them into the house of HaShem, into the chamber of the sons of Hanan the son of Igdaliah, the man of G-d, which was by the chamber of the princes, which was above the chamber of Maaseiah the son of Shallum, the keeper of the door;"},"HEBREW":{"text":"וָאָבִ֤א אֹתָם֙ בֵּ֣ית יְהוָ֔ה אֶל־לִשְׁכַּ֗ת בְּנֵ֛י חָנָ֥ן בֶּן־יִגְדַּלְיָ֖הוּ אִ֣ישׁ הָאֱלֹהִ֑ים אֲשֶׁר־אֵ֙צֶל֙ לִשְׁכַּ֣ת הַשָּׂרִ֔ים אֲשֶׁ֣ר מִמַּ֗עַל לְלִשְׁכַּ֛ת מַעֲשֵׂיָ֥הוּ בֶן־שַׁלֻּ֖ם שֹׁמֵ֥ר הַסַּֽף׃"}},"definableWords":["house","LORD","sons","son","man","God","Son"],"peopleInVerse":[]},"5":{"text":"And I set before the sons of the house of the Rechabites pots full of wine, and cups, and I said unto them, Drink ye wine.","ref":"Jeremiah 35:5","synthesized":"Then I set pitchers full of wine and some cups before the men of the house of the Rechabites, and I said to them, “Drink some wine.”","sources":{"KJV":{"text":"And I set before the sons of the house of the Rechabites pots full of wine, and cups, and I said unto them, Drink ye wine."},"BSB":{"text":"Then I set pitchers full of wine and some cups before the men of the house of the Rechabites, and I said to them, “Drink some wine.”"},"TANAKH":{"text":"and I set before the sons of the house of the Rechabites goblets full of wine, and cups, and I said unto them: 'Drink ye wine.'"},"HEBREW":{"text":"וָאֶתֵּ֞ן לִפְנֵ֣י ׀ בְּנֵ֣י בֵית־הָרֵכָבִ֗ים גְּבִעִ֛ים מְלֵאִ֥ים יַ֖יִן וְכֹס֑וֹת וָאֹמַ֥ר אֲלֵיהֶ֖ם שְׁתוּ־יָֽיִן׃"}},"definableWords":["men","house"],"peopleInVerse":[]},"6":{"text":"But they said, We will drink no wine: for Jonadab the son of Rechab our father commanded us, saying, Ye shall drink no wine, neither ye, nor your sons for ever:","ref":"Jeremiah 35:6","synthesized":"“We do not drink wine,” they replied, “for our forefather Jonadab son of Rechab commanded us, ‘Neither you nor your descendants are ever to drink wine.","sources":{"KJV":{"text":"But they said, We will drink no wine: for Jonadab the son of Rechab our father commanded us, saying, Ye shall drink no wine, neither ye, nor your sons for ever:"},"BSB":{"text":"“We do not drink wine,” they replied, “for our forefather Jonadab son of Rechab commanded us, ‘Neither you nor your descendants are ever to drink wine."},"TANAKH":{"text":"But they said: 'We will drink no wine; for Jonadab the son of Rechab our father commanded us, saying: Ye shall drink no wine, neither ye, nor your sons, for ever;"},"HEBREW":{"text":"וַיֹּאמְר֖וּ לֹ֣א נִשְׁתֶּה־יָּ֑יִן כִּי֩ יוֹנָדָ֨ב בֶּן־רֵכָ֜ב אָבִ֗ינוּ צִוָּ֤ה עָלֵ֙ינוּ֙ לֵאמֹ֔ר לֹ֧א תִשְׁתּוּ־יַ֛יִן אַתֶּ֥ם וּבְנֵיכֶ֖ם עַד־עוֹלָֽם׃"}},"definableWords":["son"],"peopleInVerse":[]},"7":{"text":"Neither shall ye build house, nor sow seed, nor plant vineyard, nor have any: but all your days ye shall dwell in tents; that ye may live many days in the land where ye be strangers.","ref":"Jeremiah 35:7","synthesized":"Nor are you ever to build a house or sow seed or plant a vineyard. Those things are not for you. Instead, you must live in tents all your lives, so that you may live a long time in the land where you wander.’","sources":{"KJV":{"text":"Neither shall ye build house, nor sow seed, nor plant vineyard, nor have any: but all your days ye shall dwell in tents; that ye may live many days in the land where ye be strangers."},"BSB":{"text":"Nor are you ever to build a house or sow seed or plant a vineyard. Those things are not for you. Instead, you must live in tents all your lives, so that you may live a long time in the land where you wander.’"},"TANAKH":{"text":"neither shall ye build house, nor sow seed, nor plant vineyard, nor have any; but all your days ye shall dwell in tents, that ye may live many days in the land wherein ye sojourn."},"HEBREW":{"text":"וּבַ֣יִת לֹֽא־תִבְנ֗וּ וְזֶ֤רַע לֹֽא־תִזְרָ֙עוּ֙ וְכֶ֣רֶם לֹֽא־תִטָּ֔עוּ וְלֹ֥א יִֽהְיֶ֖ה לָכֶ֑ם כִּ֠י בָּאֳהָלִ֤ים תֵּֽשְׁבוּ֙ כָּל־יְמֵיכֶ֔ם לְמַ֨עַן תִּֽחְי֜וּ יָמִ֤ים רַבִּים֙ עַל־פְּנֵ֣י הָאֲדָמָ֔ה אֲשֶׁ֥ר אַתֶּ֖ם גָּרִ֥ים שָֽׁם׃"}},"definableWords":["house","or","seed","live","land"],"peopleInVerse":[],"themesInVerse":["land_promise","messiah","vine_branches"]},"8":{"text":"Thus have we obeyed the voice of Jonadab the son of Rechab our father in all that he hath charged us, to drink no wine all our days, we, our wives, our sons, nor our daughters;","ref":"Jeremiah 35:8","synthesized":"And we have obeyed the voice of our forefather Jonadab son of Rechab in all he commanded us. So we have not drunk wine all our lives—neither we nor our wives nor our sons and daughters.","sources":{"KJV":{"text":"Thus have we obeyed the voice of Jonadab the son of Rechab our father in all that he hath charged us, to drink no wine all our days, we, our wives, our sons, nor our daughters;"},"BSB":{"text":"And we have obeyed the voice of our forefather Jonadab son of Rechab in all he commanded us. So we have not drunk wine all our lives—neither we nor our wives nor our sons and daughters."},"TANAKH":{"text":"And we have hearkened to the voice of Jonadab the son of Rechab our father in all that he charged us, to drink no wine all our days, we, our wives, our sons, nor our daughters;"},"HEBREW":{"text":"וַנִּשְׁמַ֗ע בְּק֨וֹל יְהוֹנָדָ֤ב בֶּן־רֵכָב֙ אָבִ֔ינוּ לְכֹ֖ל אֲשֶׁ֣ר צִוָּ֑נוּ לְבִלְתִּ֤י שְׁתֽוֹת־יַ֙יִן֙ כָּל־יָמֵ֔ינוּ אֲנַ֣חְנוּ נָשֵׁ֔ינוּ בָּנֵ֖ינוּ וּבְנֹתֵֽינוּ׃"}},"definableWords":["voice","son","sons","daughters"],"peopleInVerse":[]},"9":{"text":"Nor to build houses for us to dwell in: neither have we vineyard, nor field, nor seed:","ref":"Jeremiah 35:9","synthesized":"Nor have we built houses in which to live, and we have not owned any vineyards or fields or crops.","sources":{"KJV":{"text":"Nor to build houses for us to dwell in: neither have we vineyard, nor field, nor seed:"},"BSB":{"text":"Nor have we built houses in which to live, and we have not owned any vineyards or fields or crops."},"TANAKH":{"text":"nor to build houses for us to dwell in, neither to have vineyard, or field, or seed;"},"HEBREW":{"text":"וּלְבִלְתִּ֛י בְּנ֥וֹת בָּתִּ֖ים לְשִׁבְתֵּ֑נוּ וְכֶ֧רֶם וְשָׂדֶ֛ה וָזֶ֖רַע לֹ֥א יִֽהְיֶה־לָּֽנוּ׃"}},"definableWords":["live","or"],"peopleInVerse":[]},"10":{"text":"But we have dwelt in tents, and have obeyed, and done according to all that Jonadab our father commanded us.","ref":"Jeremiah 35:10","synthesized":"But we have lived in tents and have obeyed and done exactly as our forefather Jonadab commanded us.","sources":{"KJV":{"text":"But we have dwelt in tents, and have obeyed, and done according to all that Jonadab our father commanded us."},"BSB":{"text":"But we have lived in tents and have obeyed and done exactly as our forefather Jonadab commanded us."},"TANAKH":{"text":"but we have dwelt in tents, and have hearkened, and done according to all that Jonadab our father commanded us."},"HEBREW":{"text":"וַנֵּ֖שֶׁב בָּֽאֳהָלִ֑ים וַנִּשְׁמַ֣ע וַנַּ֔עַשׂ כְּכֹ֥ל אֲשֶׁר־צִוָּ֖נוּ יוֹנָדָ֥ב אָבִֽינוּ׃"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"But it came to pass, when Nebuchadrezzar king of Babylon came up into the land, that we said, Come, and let us go to Jerusalem for fear of the army of the Chaldeans, and for fear of the army of the Syrians: so we dwell at Jerusalem.","ref":"Jeremiah 35:11","synthesized":"So when Nebuchadnezzar king of Babylon marched into the land, we said: ‘Come, let us go into Jerusalem to escape the armies of the Chaldeans and the Arameans.’ So we have remained in Jerusalem.”","sources":{"KJV":{"text":"But it came to pass, when Nebuchadrezzar king of Babylon came up into the land, that we said, Come, and let us go to Jerusalem for fear of the army of the Chaldeans, and for fear of the army of the Syrians: so we dwell at Jerusalem."},"BSB":{"text":"So when Nebuchadnezzar king of Babylon marched into the land, we said: ‘Come, let us go into Jerusalem to escape the armies of the Chaldeans and the Arameans.’ So we have remained in Jerusalem.”"},"TANAKH":{"text":"But it came to pass, when Nebuchadrezzar king of Babylon came up against the land, that we said: Come, and let us go to Jerusalem for fear of the army of the Chaldeans, and for fear of the army of the Arameans; so we dwell at Jerusalem.'"},"HEBREW":{"text":"וַיְהִ֗י בַּעֲל֨וֹת נְבוּכַדְרֶאצַּ֥ר מֶֽלֶךְ־בָּבֶל֮ אֶל־הָאָרֶץ֒ וַנֹּ֗אמֶר בֹּ֚אוּ וְנָב֣וֹא יְרוּשָׁלִַ֔ם מִפְּנֵי֙ חֵ֣יל הַכַּשְׂדִּ֔ים וּמִפְּנֵ֖י חֵ֣יל אֲרָ֑ם וַנֵּ֖שֶׁב בִּירוּשָׁלָֽ͏ִם׃"}},"definableWords":["king","Babylon","land","Jerusalem"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon","Jerusalem"],"themesInVerse":["kingship","land_promise"]},"12":{"text":"Then came the word of the LORD unto Jeremiah, saying,","ref":"Jeremiah 35:12","synthesized":"Then the word of the LORD came to Jeremiah:","sources":{"KJV":{"text":"Then came the word of the LORD unto Jeremiah, saying,"},"BSB":{"text":"Then the word of the LORD came to Jeremiah:"},"TANAKH":{"text":"Then came the word of HaShem unto Jeremiah, saying:"},"HEBREW":{"text":"וַֽיְהִי֙ דְּבַר־יְהוָ֔ה אֶֽל־יִרְמְיָ֖הוּ לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"13":{"text":"Thus saith the LORD of hosts, the God of Israel; Go and tell the men of Judah and the inhabitants of Jerusalem, Will ye not receive instruction to hearken to my words? saith the LORD.","ref":"Jeremiah 35:13","synthesized":"“This is what the LORD of Hosts, the God of Israel, says: Go and tell the men of Judah and the residents of Jerusalem: ‘Will you not accept discipline and obey My words?’ declares the LORD.","sources":{"KJV":{"text":"Thus saith the LORD of hosts, the God of Israel; Go and tell the men of Judah and the inhabitants of Jerusalem, Will ye not receive instruction to hearken to my words? saith the LORD."},"BSB":{"text":"“This is what the LORD of Hosts, the God of Israel, says: Go and tell the men of Judah and the residents of Jerusalem: ‘Will you not accept discipline and obey My words?’ declares the LORD."},"TANAKH":{"text":"'Thus saith HaShem of hosts, the G-d of Israel: Go, and say to the men of Judah and the inhabitants of Jerusalem: Will ye not receive instruction to hearken to My words? saith HaShem."},"HEBREW":{"text":"כֹּֽה־אָמַ֞ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל הָלֹ֤ךְ וְאָֽמַרְתָּ֙ לְאִ֣ישׁ יְהוּדָ֔ה וּלְיֽוֹשְׁבֵ֖י יְרֽוּשָׁלָ֑͏ִם הֲל֨וֹא תִקְח֥וּ מוּסָ֛ר לִשְׁמֹ֥עַ אֶל־דְּבָרַ֖י נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD","God","Israel","men","Judah","Jerusalem","Lord"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"14":{"text":"The words of Jonadab the son of Rechab, that he commanded his sons not to drink wine, are performed; for unto this day they drink none, but obey their father’s commandment: notwithstanding I have spoken unto you, rising early and speaking; but ye hearkened not unto me.","ref":"Jeremiah 35:14","synthesized":"The words of Jonadab son of Rechab have been carried out. He commanded his sons not to drink wine, and they have not drunk it to this very day because they have obeyed the command of their forefather. But I have spoken to you again and again, and you have not obeyed Me!","sources":{"KJV":{"text":"The words of Jonadab the son of Rechab, that he commanded his sons not to drink wine, are performed; for unto this day they drink none, but obey their father’s commandment: notwithstanding I have spoken unto you, rising early and speaking; but ye hearkened not unto me."},"BSB":{"text":"The words of Jonadab son of Rechab have been carried out. He commanded his sons not to drink wine, and they have not drunk it to this very day because they have obeyed the command of their forefather. But I have spoken to you again and again, and you have not obeyed Me!"},"TANAKH":{"text":"The words of Jonadab the son of Rechab, that he commanded his sons, not to drink wine, are performed, and unto this day they drink none, for they hearken to their father's commandment; but I have spoken unto you, speaking betimes and often, and ye have not hearkened unto Me."},"HEBREW":{"text":"הוּקַ֡ם אֶת־דִּבְרֵ֣י יְהוֹנָדָ֣ב בֶּן־רֵ֠כָב אֲשֶׁר־צִוָּ֨ה אֶת־בָּנָ֜יו לְבִלְתִּ֣י שְׁתֽוֹת־יַ֗יִן וְלֹ֤א שָׁתוּ֙ עַד־הַיּ֣וֹם הַזֶּ֔ה כִּ֣י שָֽׁמְע֔וּ אֵ֖ת מִצְוַ֣ת אֲבִיהֶ֑ם וְאָ֨נֹכִ֜י דִּבַּ֤רְתִּי אֲלֵיכֶם֙ הַשְׁכֵּ֣ם וְדַבֵּ֔ר וְלֹ֥א שְׁמַעְתֶּ֖ם אֵלָֽי׃"}},"definableWords":["son","sons","day"],"peopleInVerse":[]},"15":{"text":"I have sent also unto you all my servants the prophets, rising up early and sending them, saying, Return ye now every man from his evil way, and amend your doings, and go not after other gods to serve them, and ye shall dwell in the land which I have given to you and to your fathers: but ye have not inclined your ear, nor hearkened unto me.","ref":"Jeremiah 35:15","synthesized":"Again and again I have sent you all My servants the prophets, proclaiming: ‘Turn now, each of you, from your wicked ways, and correct your actions. Do not go after other gods to serve them. Live in the land that I have given to you and your fathers.’ But you have not inclined your ear or listened to Me.","sources":{"KJV":{"text":"I have sent also unto you all my servants the prophets, rising up early and sending them, saying, Return ye now every man from his evil way, and amend your doings, and go not after other gods to serve them, and ye shall dwell in the land which I have given to you and to your fathers: but ye have not inclined your ear, nor hearkened unto me."},"BSB":{"text":"Again and again I have sent you all My servants the prophets, proclaiming: ‘Turn now, each of you, from your wicked ways, and correct your actions. Do not go after other gods to serve them. Live in the land that I have given to you and your fathers.’ But you have not inclined your ear or listened to Me."},"TANAKH":{"text":"I have sent also unto you all My servants the prophets, sending them betimes and often, saying: Return ye now every man from his evil way, and amend your doings, and go not after other gods to serve them, and ye shall dwell in the land which I have given to you and to your fathers; but ye have not inclined your ear, nor hearkened unto Me."},"HEBREW":{"text":"וָאֶשְׁלַ֣ח אֲלֵיכֶ֣ם אֶת־כָּל־עֲבָדַ֣י הַנְּבִאִ֣ים ׀ הַשְׁכֵּ֣ים וְשָׁלֹ֣חַ ׀ לֵאמֹ֡ר שֻׁבוּ־נָ֡א אִישׁ֩ מִדַּרְכּ֨וֹ הָרָעָ֜ה וְהֵיטִ֣יבוּ מַֽעַלְלֵיכֶ֗ם וְאַל־תֵּ֨לְכ֜וּ אַחֲרֵ֨י אֱלֹהִ֤ים אֲחֵרִים֙ לְעָבְדָ֔ם וּשְׁבוּ֙ אֶל־הָ֣אֲדָמָ֔ה אֲשֶׁר־נָתַ֥תִּי לָכֶ֖ם וְלַאֲבֹֽתֵיכֶ֑ם וְלֹ֤א הִטִּיתֶם֙ אֶֽת־אָזְנְכֶ֔ם וְלֹ֥א שְׁמַעְתֶּ֖ם אֵלָֽי׃"}},"definableWords":["servants","live","land","fathers","or"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"16":{"text":"Because the sons of Jonadab the son of Rechab have performed the commandment of their father, which he commanded them; but this people hath not hearkened unto me:","ref":"Jeremiah 35:16","synthesized":"Yes, the sons of Jonadab son of Rechab carried out the command their forefather gave them, but these people have not listened to Me.","sources":{"KJV":{"text":"Because the sons of Jonadab the son of Rechab have performed the commandment of their father, which he commanded them; but this people hath not hearkened unto me:"},"BSB":{"text":"Yes, the sons of Jonadab son of Rechab carried out the command their forefather gave them, but these people have not listened to Me."},"TANAKH":{"text":"Because the sons of Jonadab the son of Rechab have performed the commandment of their father which he commanded them, but this people hath not hearkened unto Me;"},"HEBREW":{"text":"כִּ֣י הֵקִ֗ימוּ בְּנֵי֙ יְהוֹנָדָ֣ב בֶּן־רֵכָ֔ב אֶת־מִצְוַ֥ת אֲבִיהֶ֖ם אֲשֶׁ֣ר צִוָּ֑ם וְהָעָ֣ם הַזֶּ֔ה לֹ֥א שָׁמְע֖וּ אֵלָֽי׃"}},"definableWords":["sons","son","people"],"peopleInVerse":[]},"17":{"text":"Therefore thus saith the LORD God of hosts, the God of Israel; Behold, I will bring upon Judah and upon all the inhabitants of Jerusalem all the evil that I have pronounced against them: because I have spoken unto them, but they have not heard; and I have called unto them, but they have not answered.","ref":"Jeremiah 35:17","synthesized":"Therefore this is what the LORD God of Hosts, the God of Israel, says: ‘Behold, I will bring to Judah and to all the residents of Jerusalem all the disaster I have pronounced against them, because I have spoken to them but they have not obeyed, and I have called to them but they have not answered.’”","sources":{"KJV":{"text":"Therefore thus saith the LORD God of hosts, the God of Israel; Behold, I will bring upon Judah and upon all the inhabitants of Jerusalem all the evil that I have pronounced against them: because I have spoken unto them, but they have not heard; and I have called unto them, but they have not answered."},"BSB":{"text":"Therefore this is what the LORD God of Hosts, the God of Israel, says: ‘Behold, I will bring to Judah and to all the residents of Jerusalem all the disaster I have pronounced against them, because I have spoken to them but they have not obeyed, and I have called to them but they have not answered.’”"},"TANAKH":{"text":"therefore thus saith HaShem, the G-d of hosts, the G-d of Israel: Behold, I will bring upon Judah and upon all the inhabitants of Jerusalem all the evil that I have pronounced against them; because I have spoken unto them, but they have not heard, and I have called unto them, but they have not answered.'"},"HEBREW":{"text":"לָ֠כֵן כֹּֽה־אָמַ֨ר יְהוָ֜ה אֱלֹהֵ֤י צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל הִנְנִ֧י מֵבִ֣יא אֶל־יְהוּדָ֗ה וְאֶ֤ל כָּל־יֽוֹשְׁבֵי֙ יְר֣וּשָׁלִַ֔ם אֵ֚ת כָּל־הָ֣רָעָ֔ה אֲשֶׁ֥ר דִּבַּ֖רְתִּי עֲלֵיהֶ֑ם יַ֣עַן דִּבַּ֤רְתִּי אֲלֵיהֶם֙ וְלֹ֣א שָׁמֵ֔עוּ וָאֶקְרָ֥א לָהֶ֖ם וְלֹ֥א עָנֽוּ׃"}},"definableWords":["LORD","God","Israel","Judah","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"18":{"text":"And Jeremiah said unto the house of the Rechabites, Thus saith the LORD of hosts, the God of Israel; Because ye have obeyed the commandment of Jonadab your father, and kept all his precepts, and done according unto all that he hath commanded you:","ref":"Jeremiah 35:18","synthesized":"Then Jeremiah said to the house of the Rechabites: “This is what the LORD of Hosts, the God of Israel, says: ‘Because you have obeyed the command of your forefather Jonadab and have kept all his commandments and have done all that he charged you to do,","sources":{"KJV":{"text":"And Jeremiah said unto the house of the Rechabites, Thus saith the LORD of hosts, the God of Israel; Because ye have obeyed the commandment of Jonadab your father, and kept all his precepts, and done according unto all that he hath commanded you:"},"BSB":{"text":"Then Jeremiah said to the house of the Rechabites: “This is what the LORD of Hosts, the God of Israel, says: ‘Because you have obeyed the command of your forefather Jonadab and have kept all his commandments and have done all that he charged you to do,"},"TANAKH":{"text":"And unto the house of the Rechabites Jeremiah said: Thus saith HaShem of hosts, the G-d of Israel: Because ye have hearkened to the commandment of Jonadab your father, and kept all his precepts, and done according unto all that he commanded you;"},"HEBREW":{"text":"וּלְבֵ֨ית הָרֵכָבִ֜ים אָמַ֣ר יִרְמְיָ֗הוּ כֹּֽה־אָמַ֞ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל יַ֚עַן אֲשֶׁ֣ר שְׁמַעְתֶּ֔ם עַל־מִצְוַ֖ת יְהוֹנָדָ֣ב אֲבִיכֶ֑ם וַֽתִּשְׁמְרוּ֙ אֶת־כָּל־מִצְוֺתָ֔יו וַֽתַּעֲשׂ֔וּ כְּכֹ֥ל אֲשֶׁר־צִוָּ֖ה אֶתְכֶֽם׃"}},"definableWords":["house","LORD","God","Israel"],"peopleInVerse":["Jeremiah"]},"19":{"text":"Therefore thus saith the LORD of hosts, the God of Israel; Jonadab the son of Rechab shall not want a man to stand before me for ever.","ref":"Jeremiah 35:19","synthesized":"this is what the LORD of Hosts, the God of Israel, says: Jonadab son of Rechab will never fail to have a man to stand before Me.’”","sources":{"KJV":{"text":"Therefore thus saith the LORD of hosts, the God of Israel; Jonadab the son of Rechab shall not want a man to stand before me for ever."},"BSB":{"text":"this is what the LORD of Hosts, the God of Israel, says: Jonadab son of Rechab will never fail to have a man to stand before Me.’”"},"TANAKH":{"text":"therefore thus saith HaShem of hosts, the G-d of Israel: There shall not be cut off unto Jonadab the son of Rechab a man to stand before Me for ever.'"},"HEBREW":{"text":"לָכֵ֗ן כֹּ֥ה אָמַ֛ר יְהוָ֥ה צְבָא֖וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֑ל לֹֽא־יִכָּרֵ֨ת אִ֜ישׁ לְיוֹנָדָ֧ב בֶּן־רֵכָ֛ב עֹמֵ֥ד לְפָנַ֖י כָּל־הַיָּמִֽים׃"}},"definableWords":["LORD","God","Israel","son","man","stand"],"peopleInVerse":[]}}},"36":{"chapter":"36","title":"JEHOIAKIM BURNS THE SCROLL","verses":{"1":{"text":"And it came to pass in the fourth year of Jehoiakim the son of Josiah king of Judah, that this word came unto Jeremiah from the LORD, saying,","ref":"Jeremiah 36:1","synthesized":"In the fourth year of Jehoiakim son of Josiah king of Judah, this word came to Jeremiah from the LORD:","sources":{"KJV":{"text":"And it came to pass in the fourth year of Jehoiakim the son of Josiah king of Judah, that this word came unto Jeremiah from the LORD, saying,"},"BSB":{"text":"In the fourth year of Jehoiakim son of Josiah king of Judah, this word came to Jeremiah from the LORD:"},"TANAKH":{"text":"And it came to pass in the fourth year of Jehoiakim the son of Josiah, king of Judah, that this word came unto Jeremiah from HaShem, saying:"},"HEBREW":{"text":"וַֽיְהִי֙ בַּשָּׁנָ֣ה הָרְבִיעִ֔ת לִיהוֹיָקִ֥ים בֶּן־יֹאשִׁיָּ֖הוּ מֶ֣לֶךְ יְהוּדָ֑ה הָיָ֞ה הַדָּבָ֤ר הַזֶּה֙ אֶֽל־יִרְמְיָ֔הוּ מֵאֵ֥ת יְהוָ֖ה לֵאמֹֽר׃"}},"definableWords":["year","son","king","Judah","word","LORD"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship"]},"2":{"text":"Take thee a roll of a book, and write therein all the words that I have spoken unto thee against Israel, and against Judah, and against all the nations, from the day I spake unto thee, from the days of Josiah, even unto this day.","ref":"Jeremiah 36:2","synthesized":"“Take a scroll and write on it all the words I have spoken to you concerning Israel, Judah, and all the nations, from the day I first spoke to you during the reign of Josiah until today.","sources":{"KJV":{"text":"Take thee a roll of a book, and write therein all the words that I have spoken unto thee against Israel, and against Judah, and against all the nations, from the day I spake unto thee, from the days of Josiah, even unto this day."},"BSB":{"text":"“Take a scroll and write on it all the words I have spoken to you concerning Israel, Judah, and all the nations, from the day I first spoke to you during the reign of Josiah until today."},"TANAKH":{"text":"'Take thee a roll of a book, and write therein all the words that I have spoken unto thee against Israel, and against Judah, and against all the nations, from the day I spoke unto thee, from the days of Josiah, even unto this day."},"HEBREW":{"text":"קַח־לְךָ֮ מְגִלַּת־סֵפֶר֒ וְכָתַבְתָּ֣ אֵלֶ֗יהָ אֵ֣ת כָּל־הַדְּבָרִ֞ים אֲשֶׁר־דִּבַּ֧רְתִּי אֵלֶ֛יךָ עַל־יִשְׂרָאֵ֥ל וְעַל־יְהוּדָ֖ה וְעַל־כָּל־הַגּוֹיִ֑ם מִיּ֞וֹם דִּבַּ֤רְתִּי אֵלֶ֙יךָ֙ מִימֵ֣י יֹאשִׁיָּ֔הוּ וְעַ֖ד הַיּ֥וֹם הַזֶּֽה׃"}},"definableWords":["Israel","Judah","nations","day","reign"],"peopleInVerse":[],"themesInVerse":["kingdom_of_god","kingship"]},"3":{"text":"It may be that the house of Judah will hear all the evil which I purpose to do unto them; that they may return every man from his evil way; that I may forgive their iniquity and their sin.","ref":"Jeremiah 36:3","synthesized":"Perhaps when the people of Judah hear about all the calamity I plan to bring upon them, each of them will turn from his wicked way. Then I will forgive their iniquity and their sin.”","sources":{"KJV":{"text":"It may be that the house of Judah will hear all the evil which I purpose to do unto them; that they may return every man from his evil way; that I may forgive their iniquity and their sin."},"BSB":{"text":"Perhaps when the people of Judah hear about all the calamity I plan to bring upon them, each of them will turn from his wicked way. Then I will forgive their iniquity and their sin.”"},"TANAKH":{"text":"It may be that the house of Judah will hear all the evil which I purpose to do unto them; that they may return every man from his evil way, and I may forgive their iniquity and their sin.'"},"HEBREW":{"text":"אוּלַ֤י יִשְׁמְעוּ֙ בֵּ֣ית יְהוּדָ֔ה אֵ֚ת כָּל־הָ֣רָעָ֔ה אֲשֶׁ֛ר אָנֹכִ֥י חֹשֵׁ֖ב לַעֲשׂ֣וֹת לָהֶ֑ם לְמַ֣עַן יָשׁ֗וּבוּ אִ֚ישׁ מִדַּרְכּ֣וֹ הָרָעָ֔ה וְסָלַחְתִּ֥י לַעֲוֺנָ֖ם וּלְחַטָּאתָֽם׃"}},"definableWords":["people","Judah","hear","way","forgive","iniquity","sin"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"4":{"text":"Then Jeremiah called Baruch the son of Neriah: and Baruch wrote from the mouth of Jeremiah all the words of the LORD, which he had spoken unto him, upon a roll of a book.","ref":"Jeremiah 36:4","synthesized":"So Jeremiah called Baruch son of Neriah, and at the dictation of Jeremiah, Baruch wrote on a scroll all the words that the LORD had spoken to Jeremiah.","sources":{"KJV":{"text":"Then Jeremiah called Baruch the son of Neriah: and Baruch wrote from the mouth of Jeremiah all the words of the LORD, which he had spoken unto him, upon a roll of a book."},"BSB":{"text":"So Jeremiah called Baruch son of Neriah, and at the dictation of Jeremiah, Baruch wrote on a scroll all the words that the LORD had spoken to Jeremiah."},"TANAKH":{"text":"Then Jeremiah called Baruch the son of Neriah; and Baruch wrote from the mouth of Jeremiah all the words of HaShem, which He had spoken unto him, upon a roll of a book."},"HEBREW":{"text":"וַיִּקְרָ֣א יִרְמְיָ֔הוּ אֶת־בָּר֖וּךְ בֶּן־נֵֽרִיָּ֑ה וַיִּכְתֹּ֨ב בָּר֜וּךְ מִפִּ֣י יִרְמְיָ֗הוּ אֵ֣ת כָּל־דִּבְרֵ֧י יְהוָ֛ה אֲשֶׁר־דִּבֶּ֥ר אֵלָ֖יו עַל־מְגִלַּת־סֵֽפֶר׃"}},"definableWords":["baruch","son","LORD"],"peopleInVerse":["Jeremiah"]},"5":{"text":"And Jeremiah commanded Baruch, saying, I am shut up; I cannot go into the house of the LORD:","ref":"Jeremiah 36:5","synthesized":"Then Jeremiah commanded Baruch, “I am restricted; I cannot enter the house of the LORD;","sources":{"KJV":{"text":"And Jeremiah commanded Baruch, saying, I am shut up; I cannot go into the house of the LORD:"},"BSB":{"text":"Then Jeremiah commanded Baruch, “I am restricted; I cannot enter the house of the LORD;"},"TANAKH":{"text":"And Jeremiah commanded Baruch, saying: 'I am detained, I cannot go into the house of HaShem;"},"HEBREW":{"text":"וַיְצַוֶּ֣ה יִרְמְיָ֔הוּ אֶת־בָּר֖וּךְ לֵאמֹ֑ר אֲנִ֣י עָצ֔וּר לֹ֣א אוּכַ֔ל לָב֖וֹא בֵּ֥ית יְהוָֽה׃"}},"definableWords":["baruch","house","LORD"],"peopleInVerse":["Jeremiah"]},"6":{"text":"Therefore go thou, and read in the roll, which thou hast written from my mouth, the words of the LORD in the ears of the people in the LORD’s house upon the fasting day: and also thou shalt read them in the ears of all Judah that come out of their cities.","ref":"Jeremiah 36:6","synthesized":"so you are to go to the house of the LORD on a day of fasting, and in the hearing of the people you are to read the words of the LORD from the scroll you have written at my dictation. Read them in the hearing of all the people of Judah who are coming from their cities.","sources":{"KJV":{"text":"Therefore go thou, and read in the roll, which thou hast written from my mouth, the words of the LORD in the ears of the people in the LORD’s house upon the fasting day: and also thou shalt read them in the ears of all Judah that come out of their cities."},"BSB":{"text":"so you are to go to the house of the LORD on a day of fasting, and in the hearing of the people you are to read the words of the LORD from the scroll you have written at my dictation. Read them in the hearing of all the people of Judah who are coming from their cities."},"TANAKH":{"text":"therefore go thou, and read in the roll, which thou hast written from my mouth, the words of HaShem in the ears of the people in HaShem'S house upon a fast-day; and also thou shalt read them in the ears of all Judah that come out of their cities."},"HEBREW":{"text":"וּבָאתָ֣ אַתָּ֡ה וְקָרָ֣אתָ בַמְּגִלָּ֣ה אֲשֶׁר־כָּתַֽבְתָּ־מִפִּי֩ אֶת־דִּבְרֵ֨י יְהוָ֜ה בְּאָזְנֵ֥י הָעָ֛ם בֵּ֥ית יְהוָ֖ה בְּי֣וֹם צ֑וֹם וְגַ֨ם בְּאָזְנֵ֧י כָל־יְהוּדָ֛ה הַבָּאִ֥ים מֵעָרֵיהֶ֖ם תִּקְרָאֵֽם׃"}},"definableWords":["house","LORD","day","people","Lord","Judah"],"peopleInVerse":[],"themesInVerse":["second_coming"]},"7":{"text":"It may be they will present their supplication before the LORD, and will return every one from his evil way: for great is the anger and the fury that the LORD hath pronounced against this people.","ref":"Jeremiah 36:7","synthesized":"Perhaps they will bring their petition before the LORD, and each one will turn from his wicked way; for great are the anger and fury that the LORD has pronounced against this people.”","sources":{"KJV":{"text":"It may be they will present their supplication before the LORD, and will return every one from his evil way: for great is the anger and the fury that the LORD hath pronounced against this people."},"BSB":{"text":"Perhaps they will bring their petition before the LORD, and each one will turn from his wicked way; for great are the anger and fury that the LORD has pronounced against this people.”"},"TANAKH":{"text":"It may be they will present their supplication before HaShem, and will return every one from his evil way; for great is the anger and the fury that HaShem hath pronounced against this people.'"},"HEBREW":{"text":"אוּלַ֞י תִּפֹּ֤ל תְּחִנָּתָם֙ לִפְנֵ֣י יְהוָ֔ה וְיָשֻׁ֕בוּ אִ֖ישׁ מִדַּרְכּ֣וֹ הָרָעָ֑ה כִּֽי־גָד֤וֹל הָאַף֙ וְהַ֣חֵמָ֔ה אֲשֶׁר־דִּבֶּ֥ר יְהוָ֖ה אֶל־הָעָ֥ם הַזֶּֽה׃"}},"definableWords":["LORD","one","way","great","anger","Lord","people"],"peopleInVerse":[],"themesInVerse":["prayer"]},"8":{"text":"And Baruch the son of Neriah did according to all that Jeremiah the prophet commanded him, reading in the book the words of the LORD in the LORD’s house.","ref":"Jeremiah 36:8","synthesized":"So Baruch son of Neriah did everything that Jeremiah the prophet had commanded him. In the house of the LORD he read the words of the LORD from the scroll.","sources":{"KJV":{"text":"And Baruch the son of Neriah did according to all that Jeremiah the prophet commanded him, reading in the book the words of the LORD in the LORD’s house."},"BSB":{"text":"So Baruch son of Neriah did everything that Jeremiah the prophet had commanded him. In the house of the LORD he read the words of the LORD from the scroll."},"TANAKH":{"text":"And Baruch the son of Neriah did according to all that Jeremiah the prophet commanded him, reading in the book the words of HaShem in HaShem'S house."},"HEBREW":{"text":"וַיַּ֗עַשׂ בָּרוּךְ֙ בֶּן־נֵ֣רִיָּ֔ה כְּכֹ֥ל אֲשֶׁר־צִוָּ֖הוּ יִרְמְיָ֣הוּ הַנָּבִ֑יא לִקְרֹ֥א בַסֵּ֛פֶר דִּבְרֵ֥י יְהוָ֖ה בֵּ֥ית יְהֹוָֽה׃"}},"definableWords":["baruch","son","prophet","house","LORD","Lord"],"peopleInVerse":["Jeremiah"]},"9":{"text":"And it came to pass in the fifth year of Jehoiakim the son of Josiah king of Judah, in the ninth month, that they proclaimed a fast before the LORD to all the people in Jerusalem, and to all the people that came from the cities of Judah unto Jerusalem.","ref":"Jeremiah 36:9","synthesized":"Now in the ninth month of the fifth year of Jehoiakim son of Josiah king of Judah, a fast before the LORD was proclaimed to all the people of Jerusalem and all who had come there from the cities of Judah.","sources":{"KJV":{"text":"And it came to pass in the fifth year of Jehoiakim the son of Josiah king of Judah, in the ninth month, that they proclaimed a fast before the LORD to all the people in Jerusalem, and to all the people that came from the cities of Judah unto Jerusalem."},"BSB":{"text":"Now in the ninth month of the fifth year of Jehoiakim son of Josiah king of Judah, a fast before the LORD was proclaimed to all the people of Jerusalem and all who had come there from the cities of Judah."},"TANAKH":{"text":"Now it came to pass in the fifth year of Jehoiakim the son of Josiah, king of Judah, in the ninth month, that they proclaimed a fast before HaShem, all the people in Jerusalem, and all the people that came from the cities of Judah unto Jerusalem."},"HEBREW":{"text":"וַיְהִ֣י בַשָּׁנָ֣ה הַ֠חֲמִשִׁית לִיהוֹיָקִ֨ים בֶּן־יֹאשִׁיָּ֤הוּ מֶֽלֶךְ־יְהוּדָה֙ בַּחֹ֣דֶשׁ הַתְּשִׁעִ֔י קָרְא֨וּ צ֜וֹם לִפְנֵ֧י יְהוָ֛ה כָּל־הָעָ֖ם בִּירֽוּשָׁלָ֑͏ִם וְכָל־הָעָ֗ם הַבָּאִ֛ים מֵעָרֵ֥י יְהוּדָ֖ה בִּירוּשָׁלָֽ͏ִם׃"}},"definableWords":["year","son","king","Judah","fast","LORD","people","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["kingship"]},"10":{"text":"Then read Baruch in the book the words of Jeremiah in the house of the LORD, in the chamber of Gemariah the son of Shaphan the scribe, in the higher court, at the entry of the new gate of the LORD’s house, in the ears of all the people.","ref":"Jeremiah 36:10","synthesized":"From the chamber of Gemariah son of Shaphan the scribe, which was in the upper courtyard at the opening of the New Gate of the house of the LORD, Baruch read from the scroll the words of Jeremiah in the hearing of all the people.","sources":{"KJV":{"text":"Then read Baruch in the book the words of Jeremiah in the house of the LORD, in the chamber of Gemariah the son of Shaphan the scribe, in the higher court, at the entry of the new gate of the LORD’s house, in the ears of all the people."},"BSB":{"text":"From the chamber of Gemariah son of Shaphan the scribe, which was in the upper courtyard at the opening of the New Gate of the house of the LORD, Baruch read from the scroll the words of Jeremiah in the hearing of all the people."},"TANAKH":{"text":"Then did Baruch read in the book the words of Jeremiah in the house of HaShem, in the chamber of Gemariah the son of Shaphan the scribe, in the upper court, at the entry of the new gate of HaShem'S house, in the ears of all the people."},"HEBREW":{"text":"וַיִּקְרָ֨א בָר֥וּךְ בַּסֵּ֛פֶר אֶת־דִּבְרֵ֥י יִרְמְיָ֖הוּ בֵּ֣ית יְהוָ֑ה בְּלִשְׁכַּ֡ת גְּמַרְיָהוּ֩ בֶן־שָׁפָ֨ן הַסֹּפֵ֜ר בֶּחָצֵ֣ר הָעֶלְי֗וֹן פֶּ֣תַח שַׁ֤עַר בֵּית־יְהוָה֙ הֶֽחָדָ֔שׁ בְּאָזְנֵ֖י כָּל־הָעָֽם׃"}},"definableWords":["son","Scribe","house","LORD","baruch","people"],"peopleInVerse":["Jeremiah"]},"11":{"text":"When Michaiah the son of Gemariah, the son of Shaphan, had heard out of the book all the words of the LORD,","ref":"Jeremiah 36:11","synthesized":"When Micaiah son of Gemariah, the son of Shaphan, heard all the words of the LORD from the scroll,","sources":{"KJV":{"text":"When Michaiah the son of Gemariah, the son of Shaphan, had heard out of the book all the words of the LORD,"},"BSB":{"text":"When Micaiah son of Gemariah, the son of Shaphan, heard all the words of the LORD from the scroll,"},"TANAKH":{"text":"And when Micaiah the son of Gemariah, the son of Shaphan, had heard out of the book all the words of HaShem,"},"HEBREW":{"text":"וַ֠יִּשְׁמַ֗ע מִכָ֨יְהוּ בֶן־גְּמַרְיָ֧הוּ בֶן־שָׁפָ֛ן אֶת־כָּל־דִּבְרֵ֥י יְהוָ֖ה מֵעַ֥ל הַסֵּֽפֶר׃"}},"definableWords":["son","Son","LORD"],"peopleInVerse":[]},"12":{"text":"Then he went down into the king’s house, into the scribe’s chamber: and, lo, all the princes sat there, even Elishama the scribe, and Delaiah the son of Shemaiah, and Elnathan the son of Achbor, and Gemariah the son of Shaphan, and Zedekiah the son of Hananiah, and all the princes.","ref":"Jeremiah 36:12","synthesized":"he went down to the scribe’s chamber in the king’s palace, where all the officials were sitting: Elishama the scribe, Delaiah son of Shemaiah, Elnathan son of Achbor, Gemariah son of Shaphan, Zedekiah son of Hananiah, and all the other officials.","sources":{"KJV":{"text":"Then he went down into the king’s house, into the scribe’s chamber: and, lo, all the princes sat there, even Elishama the scribe, and Delaiah the son of Shemaiah, and Elnathan the son of Achbor, and Gemariah the son of Shaphan, and Zedekiah the son of Hananiah, and all the princes."},"BSB":{"text":"he went down to the scribe’s chamber in the king’s palace, where all the officials were sitting: Elishama the scribe, Delaiah son of Shemaiah, Elnathan son of Achbor, Gemariah son of Shaphan, Zedekiah son of Hananiah, and all the other officials."},"TANAKH":{"text":"he went down into the king's house, into the scribe's chamber; and, lo, all the princes sat there, even Elishama the scribe, and Delaiah the son of Shemaiah, and Elnathan the son of Achbor, and Gemariah the son of Shaphan, and Zedekiah the son of Hananiah, and all the princes."},"HEBREW":{"text":"וַיֵּ֤רֶד בֵּית־הַמֶּ֙לֶךְ֙ עַל־לִשְׁכַּ֣ת הַסֹּפֵ֔ר וְהִ֨נֵּה־שָׁ֔ם כָּל־הַשָּׂרִ֖ים יֽוֹשְׁבִ֑ים אֱלִישָׁמָ֣ע הַסֹּפֵ֡ר וּדְלָיָ֣הוּ בֶן־שְׁ֠מַעְיָהוּ וְאֶלְנָתָ֨ן בֶּן־עַכְבּ֜וֹר וּגְמַרְיָ֧הוּ בֶן־שָׁפָ֛ן וְצִדְקִיָּ֥הוּ בֶן־חֲנַנְיָ֖הוּ וְכָל־הַשָּׂרִֽים׃"}},"definableWords":["Scribe","king","son","Son"],"peopleInVerse":[],"themesInVerse":["kingship"]},"13":{"text":"Then Michaiah declared unto them all the words that he had heard, when Baruch read the book in the ears of the people.","ref":"Jeremiah 36:13","synthesized":"And Micaiah reported to them all the words he had heard Baruch read from the scroll in the hearing of the people.","sources":{"KJV":{"text":"Then Michaiah declared unto them all the words that he had heard, when Baruch read the book in the ears of the people."},"BSB":{"text":"And Micaiah reported to them all the words he had heard Baruch read from the scroll in the hearing of the people."},"TANAKH":{"text":"Then Micaiah declared unto them all the words that he had heard, when Baruch read the book in the ears of the people."},"HEBREW":{"text":"וַיַּגֵּ֤ד לָהֶם֙ מִכָ֔יְהוּ אֵ֥ת כָּל־הַדְּבָרִ֖ים אֲשֶׁ֣ר שָׁמֵ֑עַ בִּקְרֹ֥א בָר֛וּךְ בַּסֵּ֖פֶר בְּאָזְנֵ֥י הָעָֽם׃"}},"definableWords":["baruch","people"],"peopleInVerse":[]},"14":{"text":"Therefore all the princes sent Jehudi the son of Nethaniah, the son of Shelemiah, the son of Cushi, unto Baruch, saying, Take in thine hand the roll wherein thou hast read in the ears of the people, and come. So Baruch the son of Neriah took the roll in his hand, and came unto them.","ref":"Jeremiah 36:14","synthesized":"Then all the officials sent word to Baruch through Jehudi son of Nethaniah, the son of Shelemiah, the son of Cushi, saying, “Bring the scroll that you read in the hearing of the people, and come here.”  So Baruch son of Neriah took the scroll and went to them.","sources":{"KJV":{"text":"Therefore all the princes sent Jehudi the son of Nethaniah, the son of Shelemiah, the son of Cushi, unto Baruch, saying, Take in thine hand the roll wherein thou hast read in the ears of the people, and come. So Baruch the son of Neriah took the roll in his hand, and came unto them."},"BSB":{"text":"Then all the officials sent word to Baruch through Jehudi son of Nethaniah, the son of Shelemiah, the son of Cushi, saying, “Bring the scroll that you read in the hearing of the people, and come here.”  So Baruch son of Neriah took the scroll and went to them."},"TANAKH":{"text":"Therefore all the princes sent Jehudi the son of Nethaniah, the son of Shelemiah, the son of Cushi, unto Baruch, saying: 'Take in thy hand the roll wherein thou hast read in the ears of the people, and come.' So Baruch the son of Neriah took the roll in his hand, and came unto them."},"HEBREW":{"text":"וַיִּשְׁלְח֨וּ כָל־הַשָּׂרִ֜ים אֶל־בָּר֗וּךְ אֶת־יְהוּדִ֡י בֶּן־נְ֠תַנְיָהוּ בֶּן־שֶׁלֶמְיָ֣הוּ בֶן־כּוּשִׁי֮ לֵאמֹר֒ הַמְּגִלָּ֗ה אֲשֶׁ֨ר קָרָ֤אתָ בָּהּ֙ בְּאָזְנֵ֣י הָעָ֔ם קָחֶ֥נָּה בְיָדְךָ֖ וָלֵ֑ךְ וַ֠יִּקַּח בָּר֨וּךְ בֶּן־נֵרִיָּ֤הוּ אֶת־הַמְּגִלָּה֙ בְּיָד֔וֹ וַיָּבֹ֖א אֲלֵיהֶֽם׃"}},"definableWords":["word","baruch","son","Son","people"],"peopleInVerse":[]},"15":{"text":"And they said unto him, Sit down now, and read it in our ears. So Baruch read it in their ears.","ref":"Jeremiah 36:15","synthesized":"“Please sit down,” they said, “and read it in our hearing.”  So Baruch read it in their hearing.","sources":{"KJV":{"text":"And they said unto him, Sit down now, and read it in our ears. So Baruch read it in their ears."},"BSB":{"text":"“Please sit down,” they said, “and read it in our hearing.”  So Baruch read it in their hearing."},"TANAKH":{"text":"And they said unto him: 'Sit down now, and read it in our ears.' So Baruch read it in their ears."},"HEBREW":{"text":"וַיֹּאמְר֣וּ אֵלָ֔יו שֵׁ֣ב נָ֔א וּקְרָאֶ֖נָּה בְּאָזְנֵ֑ינוּ וַיִּקְרָ֥א בָר֖וּךְ בְּאָזְנֵיהֶֽם׃"}},"definableWords":["baruch"],"peopleInVerse":[]},"16":{"text":"Now it came to pass, when they had heard all the words, they were afraid both one and other, and said unto Baruch, We will surely tell the king of all these words.","ref":"Jeremiah 36:16","synthesized":"When they had heard all these words, they turned to one another in fear and said to Baruch, “Surely we must report all these words to the king.”","sources":{"KJV":{"text":"Now it came to pass, when they had heard all the words, they were afraid both one and other, and said unto Baruch, We will surely tell the king of all these words."},"BSB":{"text":"When they had heard all these words, they turned to one another in fear and said to Baruch, “Surely we must report all these words to the king.”"},"TANAKH":{"text":"Now it came to pass, when they had heard all the words, they turned in fear one toward another, and said unto Baruch: 'We will surely tell the king of all these words.'"},"HEBREW":{"text":"וַיְהִ֗י כְּשָׁמְעָם֙ אֶת־כָּל־הַדְּבָרִ֔ים פָּחֲד֖וּ אִ֣ישׁ אֶל־רֵעֵ֑הוּ וַיֹּֽאמְרוּ֙ אֶל־בָּר֔וּךְ הַגֵּ֤יד נַגִּיד֙ לַמֶּ֔לֶךְ אֵ֥ת כָּל־הַדְּבָרִ֖ים הָאֵֽלֶּה׃"}},"definableWords":["one","fear","baruch","king"],"peopleInVerse":[],"themesInVerse":["fear_of_lord","kingship"]},"17":{"text":"And they asked Baruch, saying, Tell us now, How didst thou write all these words at his mouth?","ref":"Jeremiah 36:17","synthesized":"“Tell us now,” they asked Baruch, “how did you write all these words? Was it at Jeremiah’s dictation?”","sources":{"KJV":{"text":"And they asked Baruch, saying, Tell us now, How didst thou write all these words at his mouth?"},"BSB":{"text":"“Tell us now,” they asked Baruch, “how did you write all these words? Was it at Jeremiah’s dictation?”"},"TANAKH":{"text":"And they asked Baruch, saying: 'Tell us now: How didst thou write all these words at his mouth?'"},"HEBREW":{"text":"וְאֶ֨ת־בָּר֔וּךְ שָׁאֲל֖וּ לֵאמֹ֑ר הַגֶּד־נָ֣א לָ֔נוּ אֵ֗יךְ כָּתַ֛בְתָּ אֶת־כָּל־הַדְּבָרִ֥ים הָאֵ֖לֶּה מִפִּֽיו׃"}},"definableWords":["baruch"],"peopleInVerse":["Jeremiah"]},"18":{"text":"Then Baruch answered them, He pronounced all these words unto me with his mouth, and I wrote them with ink in the book.","ref":"Jeremiah 36:18","synthesized":"“It was at his dictation,” Baruch replied. “He recited all these words to me and I wrote them in ink on the scroll.”","sources":{"KJV":{"text":"Then Baruch answered them, He pronounced all these words unto me with his mouth, and I wrote them with ink in the book."},"BSB":{"text":"“It was at his dictation,” Baruch replied. “He recited all these words to me and I wrote them in ink on the scroll.”"},"TANAKH":{"text":"Then Baruch answered them: 'He pronounced all these words unto me with his mouth, and I wrote them with ink in the book.'"},"HEBREW":{"text":"וַיֹּ֤אמֶר לָהֶם֙ בָּר֔וּךְ מִפִּיו֙ יִקְרָ֣א אֵלַ֔י אֵ֥ת כָּל־הַדְּבָרִ֖ים הָאֵ֑לֶּה וַאֲנִ֛י כֹּתֵ֥ב עַל־הַסֵּ֖פֶר בַּדְּיֽוֹ׃"}},"definableWords":["baruch"],"peopleInVerse":[]},"19":{"text":"Then said the princes unto Baruch, Go, hide thee, thou and Jeremiah; and let no man know where ye be.","ref":"Jeremiah 36:19","synthesized":"Then the officials said to Baruch, “You and Jeremiah must hide yourselves and tell no one where you are.”","sources":{"KJV":{"text":"Then said the princes unto Baruch, Go, hide thee, thou and Jeremiah; and let no man know where ye be."},"BSB":{"text":"Then the officials said to Baruch, “You and Jeremiah must hide yourselves and tell no one where you are.”"},"TANAKH":{"text":"Then said the princes unto Baruch: 'Go, hide thee, thou and Jeremiah, and let no man know where ye are.'"},"HEBREW":{"text":"וַיֹּאמְר֤וּ הַשָּׂרִים֙ אֶל־בָּר֔וּךְ לֵ֥ךְ הִסָּתֵ֖ר אַתָּ֣ה וְיִרְמְיָ֑הוּ וְאִ֥ישׁ אַל־יֵדַ֖ע אֵיפֹ֥ה אַתֶּֽם׃"}},"definableWords":["baruch","one"],"peopleInVerse":["Jeremiah"]},"20":{"text":"And they went in to the king into the court, but they laid up the roll in the chamber of Elishama the scribe, and told all the words in the ears of the king.","ref":"Jeremiah 36:20","synthesized":"So the officials went to the king in the courtyard. And having stored the scroll in the chamber of Elishama the scribe, they reported everything to the king.","sources":{"KJV":{"text":"And they went in to the king into the court, but they laid up the roll in the chamber of Elishama the scribe, and told all the words in the ears of the king."},"BSB":{"text":"So the officials went to the king in the courtyard. And having stored the scroll in the chamber of Elishama the scribe, they reported everything to the king."},"TANAKH":{"text":"And they went in to the king into the court; but they had deposited the roll in the chamber of Elishama the scribe; and they told all the words in the ears of the king."},"HEBREW":{"text":"וַיָּבֹ֤אוּ אֶל־הַמֶּ֙לֶךְ֙ חָצֵ֔רָה וְאֶת־הַמְּגִלָּ֣ה הִפְקִ֔דוּ בְּלִשְׁכַּ֖ת אֱלִישָׁמָ֣ע הַסֹּפֵ֑ר וַיַּגִּ֙ידוּ֙ בְּאָזְנֵ֣י הַמֶּ֔לֶךְ אֵ֖ת כָּל־הַדְּבָרִֽים׃"}},"definableWords":["king","Scribe","King"],"peopleInVerse":[],"themesInVerse":["kingship"]},"21":{"text":"So the king sent Jehudi to fetch the roll: and he took it out of Elishama the scribe’s chamber. And Jehudi read it in the ears of the king, and in the ears of all the princes which stood beside the king.","ref":"Jeremiah 36:21","synthesized":"Then the king sent Jehudi to get the scroll, and he took it from the chamber of Elishama the scribe. And Jehudi read it in the hearing of the king and all the officials who were standing beside him.","sources":{"KJV":{"text":"So the king sent Jehudi to fetch the roll: and he took it out of Elishama the scribe’s chamber. And Jehudi read it in the ears of the king, and in the ears of all the princes which stood beside the king."},"BSB":{"text":"Then the king sent Jehudi to get the scroll, and he took it from the chamber of Elishama the scribe. And Jehudi read it in the hearing of the king and all the officials who were standing beside him."},"TANAKH":{"text":"So the king sent Jehudi to fetch the roll; and he took it out of the chamber of Elishama the scribe. And Jehudi read it in the ears of the king, and in the ears of all the princes that stood beside the king."},"HEBREW":{"text":"וַיִּשְׁלַ֨ח הַמֶּ֜לֶךְ אֶת־יְהוּדִ֗י לָקַ֙חַת֙ אֶת־הַמְּגִלָּ֔ה וַיִּ֨קָּחֶ֔הָ מִלִּשְׁכַּ֖ת אֱלִישָׁמָ֣ע הַסֹּפֵ֑ר וַיִּקְרָאֶ֤הָ יְהוּדִי֙ בְּאָזְנֵ֣י הַמֶּ֔לֶךְ וּבְאָזְנֵי֙ כָּל־הַשָּׂרִ֔ים הָעֹמְדִ֖ים מֵעַ֥ל הַמֶּֽלֶךְ׃"}},"definableWords":["king","Scribe","King"],"peopleInVerse":[],"themesInVerse":["kingship"]},"22":{"text":"Now the king sat in the winterhouse in the ninth month: and there was a fire on the hearth burning before him.","ref":"Jeremiah 36:22","synthesized":"Since it was the ninth month, the king was sitting in his winter quarters with a fire burning before him.","sources":{"KJV":{"text":"Now the king sat in the winterhouse in the ninth month: and there was a fire on the hearth burning before him."},"BSB":{"text":"Since it was the ninth month, the king was sitting in his winter quarters with a fire burning before him."},"TANAKH":{"text":"Now the king was sitting in the winter-house in the ninth month; and the brazier was burning before him."},"HEBREW":{"text":"וְהַמֶּ֗לֶךְ יוֹשֵׁב֙ בֵּ֣ית הַחֹ֔רֶף בַּחֹ֖דֶשׁ הַתְּשִׁיעִ֑י וְאֶת־הָאָ֖ח לְפָנָ֥יו מְבֹעָֽרֶת׃"}},"definableWords":["king"],"peopleInVerse":[],"themesInVerse":["kingship"]},"23":{"text":"And it came to pass, that when Jehudi had read three or four leaves, he cut it with the penknife, and cast it into the fire that was on the hearth, until all the roll was consumed in the fire that was on the hearth.","ref":"Jeremiah 36:23","synthesized":"And as soon as Jehudi had read three or four columns, Jehoiakim would cut them off with a scribe’s knife and throw them into the firepot, until the entire scroll had been consumed by the fire.","sources":{"KJV":{"text":"And it came to pass, that when Jehudi had read three or four leaves, he cut it with the penknife, and cast it into the fire that was on the hearth, until all the roll was consumed in the fire that was on the hearth."},"BSB":{"text":"And as soon as Jehudi had read three or four columns, Jehoiakim would cut them off with a scribe’s knife and throw them into the firepot, until the entire scroll had been consumed by the fire."},"TANAKH":{"text":"And it came to pass, when Jehudi had read three or four columns, that he cut it with the penknife, and cast it into the fire that was in the brazier, until all the roll was consumed in the fire that was in the brazier."},"HEBREW":{"text":"וַיְהִ֣י ׀ כִּקְר֣וֹא יְהוּדִ֗י שָׁלֹ֣שׁ דְּלָתוֹת֮ וְאַרְבָּעָה֒ יִֽקְרָעֶ֙הָ֙ בְּתַ֣עַר הַסֹּפֵ֔ר וְהַשְׁלֵ֕ךְ אֶל־הָאֵ֖שׁ אֲשֶׁ֣ר אֶל־הָאָ֑ח עַד־תֹּם֙ כָּל־הַמְּגִלָּ֔ה עַל־הָאֵ֖שׁ אֲשֶׁ֥ר עַל־הָאָֽח׃"}},"definableWords":["or","Scribe"],"peopleInVerse":[]},"24":{"text":"Yet they were not afraid, nor rent their garments, neither the king, nor any of his servants that heard all these words.","ref":"Jeremiah 36:24","synthesized":"Yet in hearing all these words, the king and his servants did not become frightened or tear their garments.","sources":{"KJV":{"text":"Yet they were not afraid, nor rent their garments, neither the king, nor any of his servants that heard all these words."},"BSB":{"text":"Yet in hearing all these words, the king and his servants did not become frightened or tear their garments."},"TANAKH":{"text":"Yet they were not afraid, nor rent their garments, neither the king, nor any of his servants that heard all these words."},"HEBREW":{"text":"וְלֹ֣א פָחֲד֔וּ וְלֹ֥א קָרְע֖וּ אֶת־בִּגְדֵיהֶ֑ם הַמֶּ֙לֶךְ֙ וְכָל־עֲבָדָ֔יו הַשֹּׁ֣מְעִ֔ים אֵ֥ת כָּל־הַדְּבָרִ֖ים הָאֵֽלֶּה׃"}},"definableWords":["king","servants","or"],"peopleInVerse":[],"themesInVerse":["kingship"]},"25":{"text":"Nevertheless Elnathan and Delaiah and Gemariah had made intercession to the king that he would not burn the roll: but he would not hear them.","ref":"Jeremiah 36:25","synthesized":"Even though Elnathan, Delaiah, and Gemariah urged the king not to burn the scroll, he would not listen to them.","sources":{"KJV":{"text":"Nevertheless Elnathan and Delaiah and Gemariah had made intercession to the king that he would not burn the roll: but he would not hear them."},"BSB":{"text":"Even though Elnathan, Delaiah, and Gemariah urged the king not to burn the scroll, he would not listen to them."},"TANAKH":{"text":"Moreover Elnathan and Delaiah and Gemariah had entreated the king not to burn the roll; but he would not hear them."},"HEBREW":{"text":"וְגַם֩ אֶלְנָתָ֨ן וּדְלָיָ֤הוּ וּגְמַרְיָ֙הוּ֙ הִפְגִּ֣עוּ בַמֶּ֔לֶךְ לְבִלְתִּ֥י שְׂרֹ֖ף אֶת־הַמְּגִלָּ֑ה וְלֹ֥א שָׁמַ֖ע אֲלֵיהֶֽם׃"}},"definableWords":["king"],"peopleInVerse":[],"themesInVerse":["kingship"]},"26":{"text":"But the king commanded Jerahmeel the son of Hammelech, and Seraiah the son of Azriel, and Shelemiah the son of Abdeel, to take Baruch the scribe and Jeremiah the prophet: but the LORD hid them.","ref":"Jeremiah 36:26","synthesized":"Instead, the king commanded Jerahmeel, a son of the king, as well as Seraiah son of Azriel and Shelemiah son of Abdeel, to seize Baruch the scribe and Jeremiah the prophet. But the LORD had hidden them.","sources":{"KJV":{"text":"But the king commanded Jerahmeel the son of Hammelech, and Seraiah the son of Azriel, and Shelemiah the son of Abdeel, to take Baruch the scribe and Jeremiah the prophet: but the LORD hid them."},"BSB":{"text":"Instead, the king commanded Jerahmeel, a son of the king, as well as Seraiah son of Azriel and Shelemiah son of Abdeel, to seize Baruch the scribe and Jeremiah the prophet. But the LORD had hidden them."},"TANAKH":{"text":"And the king commanded Jerahmeel the king's son, and Seraiah the son of Azriel, and Shelemiah the son of Abdeel, to take Baruch the scribe and Jeremiah the prophet; but HaShem hid them."},"HEBREW":{"text":"וַיְצַוֶּ֣ה הַ֠מֶּלֶךְ אֶת־יְרַחְמְאֵ֨ל בֶּן־הַמֶּ֜לֶךְ וְאֶת־שְׂרָיָ֣הוּ בֶן־עַזְרִיאֵ֗ל וְאֶת־שֶֽׁלֶמְיָ֙הוּ֙ בֶּֽן־עַבְדְּאֵ֔ל לָקַ֙חַת֙ אֶת־בָּר֣וּךְ הַסֹּפֵ֔ר וְאֵ֖ת יִרְמְיָ֣הוּ הַנָּבִ֑יא וַיַּסְתִּרֵ֖ם יְהוָֽה׃"}},"definableWords":["king","son","King","Son","baruch","Scribe","prophet","LORD"],"peopleInVerse":["Jeremiah"],"themesInVerse":["bread_water_life","kingship"]},"27":{"text":"Then the word of the LORD came to Jeremiah, after that the king had burned the roll, and the words which Baruch wrote at the mouth of Jeremiah, saying,","ref":"Jeremiah 36:27","synthesized":"After the king had burned the scroll containing the words that Baruch had written at Jeremiah’s dictation, the word of the LORD came to Jeremiah:","sources":{"KJV":{"text":"Then the word of the LORD came to Jeremiah, after that the king had burned the roll, and the words which Baruch wrote at the mouth of Jeremiah, saying,"},"BSB":{"text":"After the king had burned the scroll containing the words that Baruch had written at Jeremiah’s dictation, the word of the LORD came to Jeremiah:"},"TANAKH":{"text":"Then the word of HaShem came to Jeremiah, after that the king had burned the roll, and the words which Baruch wrote at the mouth of Jeremiah, saying:"},"HEBREW":{"text":"וַיְהִ֥י דְבַר־יְהוָ֖ה אֶֽל־יִרְמְיָ֑הוּ אַחֲרֵ֣י ׀ שְׂרֹ֣ף הַמֶּ֗לֶךְ אֶת־הַמְּגִלָּה֙ וְאֶת־הַדְּבָרִ֔ים אֲשֶׁ֨ר כָּתַ֥ב בָּר֛וּךְ מִפִּ֥י יִרְמְיָ֖הוּ לֵאמֹֽר׃"}},"definableWords":["king","baruch","word","LORD"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship"]},"28":{"text":"Take thee again another roll, and write in it all the former words that were in the first roll, which Jehoiakim the king of Judah hath burned.","ref":"Jeremiah 36:28","synthesized":"“Take another scroll and rewrite on it the very words that were on the original scroll, which Jehoiakim king of Judah has burned.","sources":{"KJV":{"text":"Take thee again another roll, and write in it all the former words that were in the first roll, which Jehoiakim the king of Judah hath burned."},"BSB":{"text":"“Take another scroll and rewrite on it the very words that were on the original scroll, which Jehoiakim king of Judah has burned."},"TANAKH":{"text":"'Take thee again another roll, and write in it all the former words that were in the first roll, which Jehoiakim the king of Judah hath burned."},"HEBREW":{"text":"שׁ֥וּב קַח־לְךָ֖ מְגִלָּ֣ה אַחֶ֑רֶת וּכְתֹ֣ב עָלֶ֗יהָ אֵ֤ת כָּל־הַדְּבָרִים֙ הָרִ֣אשֹׁנִ֔ים אֲשֶׁ֣ר הָי֗וּ עַל־הַמְּגִלָּה֙ הָרִ֣אשֹׁנָ֔ה אֲשֶׁ֥ר שָׂרַ֖ף יְהוֹיָקִ֥ים מֶֽלֶךְ־יְהוּדָֽה׃"}},"definableWords":["king","Judah"],"peopleInVerse":[],"themesInVerse":["kingship"]},"29":{"text":"And thou shalt say to Jehoiakim king of Judah, Thus saith the LORD; Thou hast burned this roll, saying, Why hast thou written therein, saying, The king of Babylon shall certainly come and destroy this land, and shall cause to cease from thence man and beast?","ref":"Jeremiah 36:29","synthesized":"You are to proclaim concerning Jehoiakim king of Judah that this is what the LORD says: You have burned the scroll and said, ‘Why have you written on it that the king of Babylon would surely come and destroy this land and deprive it of man and beast?’","sources":{"KJV":{"text":"And thou shalt say to Jehoiakim king of Judah, Thus saith the LORD; Thou hast burned this roll, saying, Why hast thou written therein, saying, The king of Babylon shall certainly come and destroy this land, and shall cause to cease from thence man and beast?"},"BSB":{"text":"You are to proclaim concerning Jehoiakim king of Judah that this is what the LORD says: You have burned the scroll and said, ‘Why have you written on it that the king of Babylon would surely come and destroy this land and deprive it of man and beast?’"},"TANAKH":{"text":"And concerning Jehoiakim king of Judah thou shalt say: Thus saith HaShem: Thou hast burned this roll, saying: Why hast thou written therein, saying: The king of Babylon shall certainly come and destroy this land, and shall cause to cease from thence man and beast?"},"HEBREW":{"text":"וְעַל־יְהוֹיָקִ֤ים מֶֽלֶךְ־יְהוּדָה֙ תֹּאמַ֔ר כֹּ֖ה אָמַ֣ר יְהוָ֑ה אַ֠תָּה שָׂרַ֜פְתָּ אֶת־הַמְּגִלָּ֤ה הַזֹּאת֙ לֵאמֹ֔ר מַדּוּעַ֩ כָּתַ֨בְתָּ עָלֶ֜יהָ לֵאמֹ֗ר בֹּֽא־יָב֤וֹא מֶֽלֶךְ־בָּבֶל֙ וְהִשְׁחִית֙ אֶת־הָאָ֣רֶץ הַזֹּ֔את וְהִשְׁבִּ֥ית מִמֶּ֖נָּה אָדָ֥ם וּבְהֵמָֽה׃"}},"definableWords":["king","Judah","LORD","King","Babylon","land","man"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship","land_promise"]},"30":{"text":"Therefore thus saith the LORD of Jehoiakim king of Judah; He shall have none to sit upon the throne of David: and his dead body shall be cast out in the day to the heat, and in the night to the frost.","ref":"Jeremiah 36:30","synthesized":"Therefore this is what the LORD says about Jehoiakim king of Judah: He will have no one to sit on David’s throne, and his body will be thrown out and exposed to heat by day and frost by night.","sources":{"KJV":{"text":"Therefore thus saith the LORD of Jehoiakim king of Judah; He shall have none to sit upon the throne of David: and his dead body shall be cast out in the day to the heat, and in the night to the frost."},"BSB":{"text":"Therefore this is what the LORD says about Jehoiakim king of Judah: He will have no one to sit on David’s throne, and his body will be thrown out and exposed to heat by day and frost by night."},"TANAKH":{"text":"Therefore thus saith HaShem concerning Jehoiakim king of Judah: He shall have none to sit upon the throne of David; and his dead body shall be cast out in the day to the heat, and in the night to the frost."},"HEBREW":{"text":"לָכֵ֞ן כֹּֽה־אָמַ֣ר יְהוָ֗ה עַל־יְהֽוֹיָקִים֙ מֶ֣לֶךְ יְהוּדָ֔ה לֹא־יִֽהְיֶה־לּ֥וֹ יוֹשֵׁ֖ב עַל־כִּסֵּ֣א דָוִ֑ד וְנִבְלָתוֹ֙ תִּֽהְיֶ֣ה מֻשְׁלֶ֔כֶת לַחֹ֥רֶב בַּיּ֖וֹם וְלַקֶּ֥רַח בַּלָּֽיְלָה׃"}},"definableWords":["LORD","king","Judah","one","throne","day","night"],"peopleInVerse":["David"],"themesInVerse":["kingdom_of_god","kingship"]},"31":{"text":"And I will punish him and his seed and his servants for their iniquity; and I will bring upon them, and upon the inhabitants of Jerusalem, and upon the men of Judah, all the evil that I have pronounced against them; but they hearkened not.","ref":"Jeremiah 36:31","synthesized":"I will punish him and his descendants and servants for their iniquity. I will bring on them, on the residents of Jerusalem, and on the men of Judah, all the calamity about which I warned them but they did not listen.”","sources":{"KJV":{"text":"And I will punish him and his seed and his servants for their iniquity; and I will bring upon them, and upon the inhabitants of Jerusalem, and upon the men of Judah, all the evil that I have pronounced against them; but they hearkened not."},"BSB":{"text":"I will punish him and his descendants and servants for their iniquity. I will bring on them, on the residents of Jerusalem, and on the men of Judah, all the calamity about which I warned them but they did not listen.”"},"TANAKH":{"text":"And I will visit upon him and his seed and his servants their iniquity; and I will bring upon them, and upon the inhabitants of Jerusalem, and upon the men of Judah, all the evil that I have pronounced against them, but they hearkened not.'"},"HEBREW":{"text":"וּפָקַדְתִּ֨י עָלָ֧יו וְעַל־זַרְע֛וֹ וְעַל־עֲבָדָ֖יו אֶת־עֲוֺנָ֑ם וְהֵבֵאתִ֣י עֲ֠לֵיהֶם וְעַל־יֹשְׁבֵ֨י יְרוּשָׁלִַ֜ם וְאֶל־אִ֣ישׁ יְהוּדָ֗ה אֵ֧ת כָּל־הָרָעָ֛ה אֲשֶׁר־דִּבַּ֥רְתִּי אֲלֵיהֶ֖ם וְלֹ֥א שָׁמֵֽעוּ׃"}},"definableWords":["servants","iniquity","Jerusalem","men","Judah"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["fall_sin"]},"32":{"text":"Then took Jeremiah another roll, and gave it to Baruch the scribe, the son of Neriah; who wrote therein from the mouth of Jeremiah all the words of the book which Jehoiakim king of Judah had burned in the fire: and there were added besides unto them many like words.","ref":"Jeremiah 36:32","synthesized":"Then Jeremiah took another scroll and gave it to the scribe Baruch son of Neriah, and at Jeremiah’s dictation he wrote on it all the words of the scroll that Jehoiakim king of Judah had burned in the fire. And many similar words were added to them.","sources":{"KJV":{"text":"Then took Jeremiah another roll, and gave it to Baruch the scribe, the son of Neriah; who wrote therein from the mouth of Jeremiah all the words of the book which Jehoiakim king of Judah had burned in the fire: and there were added besides unto them many like words."},"BSB":{"text":"Then Jeremiah took another scroll and gave it to the scribe Baruch son of Neriah, and at Jeremiah’s dictation he wrote on it all the words of the scroll that Jehoiakim king of Judah had burned in the fire. And many similar words were added to them."},"TANAKH":{"text":"Then took Jeremiah another roll, and gave it to Baruch the scribe, the son of Neriah; who wrote therein from the mouth of Jeremiah all the words of the book which Jehoiakim king of Judah had burned in the fire; and there were added besides unto them many like words."},"HEBREW":{"text":"וְיִרְמְיָ֜הוּ לָקַ֣ח ׀ מְגִלָּ֣ה אַחֶ֗רֶת וַֽיִּתְּנָהּ֮ אֶל־בָּר֣וּךְ בֶּן־נֵרִיָּהוּ֮ הַסֹּפֵר֒ וַיִּכְתֹּ֤ב עָלֶ֙יהָ֙ מִפִּ֣י יִרְמְיָ֔הוּ אֵ֚ת כָּל־דִּבְרֵ֣י הַסֵּ֔פֶר אֲשֶׁ֥ר שָׂרַ֛ף יְהוֹיָקִ֥ים מֶֽלֶךְ־יְהוּדָ֖ה בָּאֵ֑שׁ וְע֨וֹד נוֹסַ֧ף עֲלֵיהֶ֛ם דְּבָרִ֥ים רַבִּ֖ים כָּהֵֽמָּה׃"}},"definableWords":["Scribe","baruch","son","king","Judah"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship"]}}},"37":{"chapter":"37","title":"JEREMIAH IMPRISONED","verses":{"1":{"text":"And king Zedekiah the son of Josiah reigned instead of Coniah the son of Jehoiakim, whom Nebuchadrezzar king of Babylon made king in the land of Judah.","ref":"Jeremiah 37:1","synthesized":"Nebuchadnezzar king of Babylon made Zedekiah son of Josiah the king of Judah, and he reigned in place of Coniah son of Jehoiakim.","sources":{"KJV":{"text":"And king Zedekiah the son of Josiah reigned instead of Coniah the son of Jehoiakim, whom Nebuchadrezzar king of Babylon made king in the land of Judah."},"BSB":{"text":"Nebuchadnezzar king of Babylon made Zedekiah son of Josiah the king of Judah, and he reigned in place of Coniah son of Jehoiakim."},"TANAKH":{"text":"And Zedekiah the son of Josiah reigned as king, instead of Coniah the son of Jehoiakim, whom Nebuchadrezzar king of Babylon made king in the land of Judah."},"HEBREW":{"text":"וַיִּ֨מְלָךְ־מֶ֔לֶךְ צִדְקִיָּ֖הוּ בֶּן־יֹֽאשִׁיָּ֑הוּ תַּ֗חַת כָּנְיָ֙הוּ֙ בֶּן־יְה֣וֹיָקִ֔ים אֲשֶׁ֥ר הִמְלִ֛יךְ נְבוּכַדְרֶאצַּ֥ר מֶֽלֶךְ־בָּבֶ֖ל בְּאֶ֥רֶץ יְהוּדָֽה׃"}},"definableWords":["king","Babylon","made","son","King","Judah","Son"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["creation","kingship"]},"2":{"text":"But neither he, nor his servants, nor the people of the land, did hearken unto the words of the LORD, which he spake by the prophet Jeremiah.","ref":"Jeremiah 37:2","synthesized":"But he and his officers and the people of the land refused to obey the words that the LORD had spoken through Jeremiah the prophet.","sources":{"KJV":{"text":"But neither he, nor his servants, nor the people of the land, did hearken unto the words of the LORD, which he spake by the prophet Jeremiah."},"BSB":{"text":"But he and his officers and the people of the land refused to obey the words that the LORD had spoken through Jeremiah the prophet."},"TANAKH":{"text":"But neither he, nor his servants, nor the people of the land, did hearken unto the words of HaShem, which He spoke by the prophet Jeremiah."},"HEBREW":{"text":"וְלֹ֥א שָׁמַ֛ע ה֥וּא וַעֲבָדָ֖יו וְעַ֣ם הָאָ֑רֶץ אֶל־דִּבְרֵ֣י יְהוָ֔ה אֲשֶׁ֣ר דִּבֶּ֔ר בְּיַ֖ד יִרְמְיָ֥הוּ הַנָּבִֽיא׃"}},"definableWords":["people","land","LORD","prophet"],"peopleInVerse":["Jeremiah"],"themesInVerse":["land_promise"]},"3":{"text":"And Zedekiah the king sent Jehucal the son of Shelemiah and Zephaniah the son of Maaseiah the priest to the prophet Jeremiah, saying, Pray now unto the LORD our God for us.","ref":"Jeremiah 37:3","synthesized":"Yet King Zedekiah sent Jehucal son of Shelemiah and Zephaniah the priest, the son of Maaseiah, to Jeremiah the prophet with the message, “Please pray to the LORD our God for us!”","sources":{"KJV":{"text":"And Zedekiah the king sent Jehucal the son of Shelemiah and Zephaniah the son of Maaseiah the priest to the prophet Jeremiah, saying, Pray now unto the LORD our God for us."},"BSB":{"text":"Yet King Zedekiah sent Jehucal son of Shelemiah and Zephaniah the priest, the son of Maaseiah, to Jeremiah the prophet with the message, “Please pray to the LORD our God for us!”"},"TANAKH":{"text":"And Zedekiah the king sent Jehucal the son of Shelemiah, and Zephaniah the son of Maaseiah the priest, to the prophet Jeremiah, saying: 'Pray now unto HaShem our G-d for us.'"},"HEBREW":{"text":"וַיִּשְׁלַח֩ הַמֶּ֨לֶךְ צִדְקִיָּ֜הוּ אֶת־יְהוּכַ֣ל בֶּן־שֶֽׁלֶמְיָ֗ה וְאֶת־צְפַנְיָ֤הוּ בֶן־מַֽעֲשֵׂיָה֙ הַכֹּהֵ֔ן אֶל־יִרְמְיָ֥הוּ הַנָּבִ֖יא לֵאמֹ֑ר הִתְפַּלֶּל־נָ֣א בַעֲדֵ֔נוּ אֶל־יְהוָ֖ה אֱלֹהֵֽינוּ׃"}},"definableWords":["King","son","priest","Son","prophet","LORD","God"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingdom_priesthood","kingship","prayer"]},"4":{"text":"Now Jeremiah came in and went out among the people: for they had not put him into prison.","ref":"Jeremiah 37:4","synthesized":"Now Jeremiah was free to come and go among the people, for they had not yet put him in prison.","sources":{"KJV":{"text":"Now Jeremiah came in and went out among the people: for they had not put him into prison."},"BSB":{"text":"Now Jeremiah was free to come and go among the people, for they had not yet put him in prison."},"TANAKH":{"text":"Now Jeremiah came in and went out among the people; for they had not put him into prison."},"HEBREW":{"text":"וְיִרְמְיָ֕הוּ בָּ֥א וְיֹצֵ֖א בְּת֣וֹךְ הָעָ֑ם וְלֹֽא־נָתְנ֥וּ אֹת֖וֹ בֵּ֥ית הכליא הַכְּלֽוּא׃"}},"definableWords":["people"],"peopleInVerse":["Jeremiah"]},"5":{"text":"Then Pharaoh’s army was come forth out of Egypt: and when the Chaldeans that besieged Jerusalem heard tidings of them, they departed from Jerusalem.","ref":"Jeremiah 37:5","synthesized":"Pharaoh’s army had left Egypt, and when the Chaldeans who were besieging Jerusalem heard the report, they withdrew from Jerusalem.","sources":{"KJV":{"text":"Then Pharaoh’s army was come forth out of Egypt: and when the Chaldeans that besieged Jerusalem heard tidings of them, they departed from Jerusalem."},"BSB":{"text":"Pharaoh’s army had left Egypt, and when the Chaldeans who were besieging Jerusalem heard the report, they withdrew from Jerusalem."},"TANAKH":{"text":"And Pharaoh's army was come forth out of Egypt; and when the Chaldeans that besieged Jerusalem heard tidings of them, they broke up from Jerusalem."},"HEBREW":{"text":"וְחֵ֥יל פַּרְעֹ֖ה יָצָ֣א מִמִּצְרָ֑יִם וַיִּשְׁמְע֨וּ הַכַּשְׂדִּ֜ים הַצָּרִ֤ים עַל־יְרוּשָׁלִַ֙ם֙ אֶת־שִׁמְעָ֔ם וַיֵּ֣עָל֔וּ מֵעַ֖ל יְרוּשָׁלָֽ͏ִם׃"}},"definableWords":["Pharaoh","Egypt","Jerusalem"],"peopleInVerse":["Pharaoh"],"placesInVerse":["Egypt","Jerusalem"],"themesInVerse":["exodus_pattern"]},"6":{"text":"Then came the word of the LORD unto the prophet Jeremiah, saying,","ref":"Jeremiah 37:6","synthesized":"Then the word of the LORD came to Jeremiah the prophet:","sources":{"KJV":{"text":"Then came the word of the LORD unto the prophet Jeremiah, saying,"},"BSB":{"text":"Then the word of the LORD came to Jeremiah the prophet:"},"TANAKH":{"text":"Then came the word of HaShem unto the prophet Jeremiah, saying:"},"HEBREW":{"text":"וַֽיְהִי֙ דְּבַר־יְהוָ֔ה אֶל־יִרְמְיָ֥הוּ הַנָּבִ֖יא לֵאמֹֽר׃"}},"definableWords":["word","LORD","prophet"],"peopleInVerse":["Jeremiah"]},"7":{"text":"Thus saith the LORD, the God of Israel; Thus shall ye say to the king of Judah, that sent you unto me to enquire of me; Behold, Pharaoh’s army, which is come forth to help you, shall return to Egypt into their own land.","ref":"Jeremiah 37:7","synthesized":"“This is what the LORD, the God of Israel, says that you are to tell the king of Judah, who sent you to Me: Behold, Pharaoh’s army, which has marched out to help you, will go back to its own land of Egypt.","sources":{"KJV":{"text":"Thus saith the LORD, the God of Israel; Thus shall ye say to the king of Judah, that sent you unto me to enquire of me; Behold, Pharaoh’s army, which is come forth to help you, shall return to Egypt into their own land."},"BSB":{"text":"“This is what the LORD, the God of Israel, says that you are to tell the king of Judah, who sent you to Me: Behold, Pharaoh’s army, which has marched out to help you, will go back to its own land of Egypt."},"TANAKH":{"text":"'Thus saith HaShem, the G-d of Israel: Thus shall ye say to the king of Judah, that sent you unto Me to inquire of Me: Behold, Pharaoh's army, which is come forth to help you, shall return to Egypt into their own land."},"HEBREW":{"text":"כֹּֽה־אָמַ֤ר יְהוָה֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל כֹּ֤ה תֹֽאמְרוּ֙ אֶל־מֶ֣לֶךְ יְהוּדָ֔ה הַשֹּׁלֵ֧חַ אֶתְכֶ֛ם אֵלַ֖י לְדָרְשֵׁ֑נִי הִנֵּ֣ה ׀ חֵ֣יל פַּרְעֹ֗ה הַיֹּצֵ֤א לָכֶם֙ לְעֶזְרָ֔ה שָׁ֥ב לְאַרְצ֖וֹ מִצְרָֽיִם׃"}},"definableWords":["LORD","God","Israel","king","Judah","Pharaoh","land","Egypt"],"peopleInVerse":["Pharaoh"],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","kingship","land_promise"]},"8":{"text":"And the Chaldeans shall come again, and fight against this city, and take it, and burn it with fire.","ref":"Jeremiah 37:8","synthesized":"Then the Chaldeans will return and fight against this city. They will capture it and burn it down.","sources":{"KJV":{"text":"And the Chaldeans shall come again, and fight against this city, and take it, and burn it with fire."},"BSB":{"text":"Then the Chaldeans will return and fight against this city. They will capture it and burn it down."},"TANAKH":{"text":"And the Chaldeans shall return, and fight against this city; and they shall take it, and burn it with fire."},"HEBREW":{"text":"וְשָׁ֙בוּ֙ הַכַּשְׂדִּ֔ים וְנִלְחֲמ֖וּ עַל־הָעִ֣יר הַזֹּ֑את וּלְכָדֻ֖הָ וּשְׂרָפֻ֥הָ בָאֵֽשׁ׃"}},"definableWords":["fight"],"peopleInVerse":[],"themesInVerse":["exile_return","second_coming","spiritual_warfare"]},"9":{"text":"Thus saith the LORD; Deceive not yourselves, saying, The Chaldeans shall surely depart from us: for they shall not depart.","ref":"Jeremiah 37:9","synthesized":"This is what the LORD says: Do not deceive yourselves by saying, ‘The Chaldeans will go away for good,’ for they will not!","sources":{"KJV":{"text":"Thus saith the LORD; Deceive not yourselves, saying, The Chaldeans shall surely depart from us: for they shall not depart."},"BSB":{"text":"This is what the LORD says: Do not deceive yourselves by saying, ‘The Chaldeans will go away for good,’ for they will not!"},"TANAKH":{"text":"Thus saith HaShem: Deceive not yourselves, saying: The Chaldeans shall surely depart from us; for they shall not depart."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה אַל־תַּשִּׁ֤אוּ נַפְשֹֽׁתֵיכֶם֙ לֵאמֹ֔ר הָלֹ֛ךְ יֵלְכ֥וּ מֵעָלֵ֖ינוּ הַכַּשְׂדִּ֑ים כִּי־לֹ֖א יֵלֵֽכוּ׃"}},"definableWords":["LORD","good"],"peopleInVerse":[]},"10":{"text":"For though ye had smitten the whole army of the Chaldeans that fight against you, and there remained but wounded men among them, yet should they rise up every man in his tent, and burn this city with fire.","ref":"Jeremiah 37:10","synthesized":"Indeed, if you were to strike down the entire army of the Chaldeans that is fighting against you, and only wounded men remained in their tents, they would still get up and burn this city down.”","sources":{"KJV":{"text":"For though ye had smitten the whole army of the Chaldeans that fight against you, and there remained but wounded men among them, yet should they rise up every man in his tent, and burn this city with fire."},"BSB":{"text":"Indeed, if you were to strike down the entire army of the Chaldeans that is fighting against you, and only wounded men remained in their tents, they would still get up and burn this city down.”"},"TANAKH":{"text":"For though ye had smitten the whole army of the Chaldeans that fight against you, and there remained but wounded men among them, yet would they rise up every man in his tent, and burn this city with fire.'"},"HEBREW":{"text":"כִּ֣י אִם־הִכִּיתֶ֞ם כָּל־חֵ֤יל כַּשְׂדִּים֙ הַנִּלְחָמִ֣ים אִתְּכֶ֔ם וְנִ֨שְׁאֲרוּ בָ֔ם אֲנָשִׁ֖ים מְדֻקָּרִ֑ים אִ֤ישׁ בְּאָהֳלוֹ֙ יָק֔וּמוּ וְשָֽׂרְפ֛וּ אֶת־הָעִ֥יר הַזֹּ֖את בָּאֵֽשׁ׃"}},"definableWords":["men"],"peopleInVerse":[]},"11":{"text":"And it came to pass, that when the army of the Chaldeans was broken up from Jerusalem for fear of Pharaoh’s army,","ref":"Jeremiah 37:11","synthesized":"When the Chaldean army withdrew from Jerusalem for fear of Pharaoh’s army,","sources":{"KJV":{"text":"And it came to pass, that when the army of the Chaldeans was broken up from Jerusalem for fear of Pharaoh’s army,"},"BSB":{"text":"When the Chaldean army withdrew from Jerusalem for fear of Pharaoh’s army,"},"TANAKH":{"text":"And it came to pass, that when the army of the Chaldeans was broken up from Jerusalem for fear of Pharaoh's army,"},"HEBREW":{"text":"וְהָיָ֗ה בְּהֵֽעָלוֹת֙ חֵ֣יל הַכַּשְׂדִּ֔ים מֵעַ֖ל יְרֽוּשָׁלָ֑͏ִם מִפְּנֵ֖י חֵ֥יל פַּרְעֹֽה׃"}},"definableWords":["Jerusalem","fear","Pharaoh"],"peopleInVerse":["Pharaoh"],"placesInVerse":["Jerusalem"],"themesInVerse":["fear_of_lord"]},"12":{"text":"Then Jeremiah went forth out of Jerusalem to go into the land of Benjamin, to separate himself thence in the midst of the people.","ref":"Jeremiah 37:12","synthesized":"Jeremiah started to leave Jerusalem to go to the land of Benjamin to claim his portion there among the people.","sources":{"KJV":{"text":"Then Jeremiah went forth out of Jerusalem to go into the land of Benjamin, to separate himself thence in the midst of the people."},"BSB":{"text":"Jeremiah started to leave Jerusalem to go to the land of Benjamin to claim his portion there among the people."},"TANAKH":{"text":"then Jeremiah went forth out of Jerusalem to go into the land of Benjamin, to receive his portion there, in the midst of the people."},"HEBREW":{"text":"וַיֵּצֵ֤א יִרְמְיָ֙הוּ֙ מִיר֣וּשָׁלִַ֔ם לָלֶ֖כֶת אֶ֣רֶץ בִּנְיָמִ֑ן לַחֲלִ֥ק מִשָּׁ֖ם בְּת֥וֹךְ הָעָֽם׃"}},"definableWords":["Jerusalem","land","Benjamin","people"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Jerusalem"],"themesInVerse":["land_promise"]},"13":{"text":"And when he was in the gate of Benjamin, a captain of the ward was there, whose name was Irijah, the son of Shelemiah, the son of Hananiah; and he took Jeremiah the prophet, saying, Thou fallest away to the Chaldeans.","ref":"Jeremiah 37:13","synthesized":"But when he reached the Gate of Benjamin, the captain of the guard, whose name was Irijah son of Shelemiah, the son of Hananiah, seized him and said, “You are deserting to the Chaldeans!”","sources":{"KJV":{"text":"And when he was in the gate of Benjamin, a captain of the ward was there, whose name was Irijah, the son of Shelemiah, the son of Hananiah; and he took Jeremiah the prophet, saying, Thou fallest away to the Chaldeans."},"BSB":{"text":"But when he reached the Gate of Benjamin, the captain of the guard, whose name was Irijah son of Shelemiah, the son of Hananiah, seized him and said, “You are deserting to the Chaldeans!”"},"TANAKH":{"text":"And when he was in the gate of Benjamin, a captain of the ward was there, whose name was Irijah, the son of Shelemiah, the son of Hananiah; and he laid hold on Jeremiah the prophet, saying: 'Thou fallest away to the Chaldeans.'"},"HEBREW":{"text":"וַיְהִי־ה֞וּא בְּשַׁ֣עַר בִּנְיָמִ֗ן וְשָׁם֙ בַּ֣עַל פְּקִדֻ֔ת וּשְׁמוֹ֙ יִרְאִיָּ֔יה בֶּן־שֶֽׁלֶמְיָ֖ה בֶּן־חֲנַנְיָ֑ה וַיִּתְפֹּ֞שׂ אֶֽת־יִרְמְיָ֤הוּ הַנָּבִיא֙ לֵאמֹ֔ר אֶל־הַכַּשְׂדִּ֖ים אַתָּ֥ה נֹפֵֽל׃"}},"definableWords":["Benjamin","name","son","Son"],"peopleInVerse":[]},"14":{"text":"Then said Jeremiah, It is false; I fall not away to the Chaldeans. But he hearkened not to him: so Irijah took Jeremiah, and brought him to the princes.","ref":"Jeremiah 37:14","synthesized":"“That is a lie,” Jeremiah replied. “I am not deserting to the Chaldeans!”  But Irijah would not listen to him; instead, he arrested Jeremiah and took him to the officials.","sources":{"KJV":{"text":"Then said Jeremiah, It is false; I fall not away to the Chaldeans. But he hearkened not to him: so Irijah took Jeremiah, and brought him to the princes."},"BSB":{"text":"“That is a lie,” Jeremiah replied. “I am not deserting to the Chaldeans!”  But Irijah would not listen to him; instead, he arrested Jeremiah and took him to the officials."},"TANAKH":{"text":"Then said Jeremiah: 'It is false; I fall not away to the Chaldeans'; but he hearkened not to him; so Irijah laid hold on Jeremiah, and brought him to the princes."},"HEBREW":{"text":"וַיֹּ֨אמֶר יִרְמְיָ֜הוּ שֶׁ֗קֶר אֵינֶ֤נִּי נֹפֵל֙ עַל־הַכַּשְׂדִּ֔ים וְלֹ֥א שָׁמַ֖ע אֵלָ֑יו וַיִּתְפֹּ֤שׂ יִרְאִיָּיה֙ בְּיִרְמְיָ֔הוּ וַיְבִאֵ֖הוּ אֶל־הַשָּׂרִֽים׃"}},"definableWords":[],"peopleInVerse":["Jeremiah"]},"15":{"text":"Wherefore the princes were wroth with Jeremiah, and smote him, and put him in prison in the house of Jonathan the scribe: for they had made that the prison.","ref":"Jeremiah 37:15","synthesized":"The officials were angry with Jeremiah, and they beat him and placed him in jail in the house of Jonathan the scribe, for it had been made into a prison.","sources":{"KJV":{"text":"Wherefore the princes were wroth with Jeremiah, and smote him, and put him in prison in the house of Jonathan the scribe: for they had made that the prison."},"BSB":{"text":"The officials were angry with Jeremiah, and they beat him and placed him in jail in the house of Jonathan the scribe, for it had been made into a prison."},"TANAKH":{"text":"And the princes were wroth with Jeremiah, and smote him, and put him in prison in the house of Jonathan the scribe; for they had made that the prison."},"HEBREW":{"text":"וַיִּקְצְפ֧וּ הַשָּׂרִ֛ים עַֽל־יִרְמְיָ֖הוּ וְהִכּ֣וּ אֹת֑וֹ וְנָתְנ֨וּ אוֹת֜וֹ בֵּ֣ית הָאֵס֗וּר בֵּ֚ית יְהוֹנָתָ֣ן הַסֹּפֵ֔ר כִּֽי־אֹת֥וֹ עָשׂ֖וּ לְבֵ֥ית הַכֶּֽלֶא׃"}},"definableWords":["house","Scribe","made"],"peopleInVerse":["Jeremiah","Jonathan"],"themesInVerse":["creation"]},"16":{"text":"When Jeremiah was entered into the dungeon, and into the cabins, and Jeremiah had remained there many days;","ref":"Jeremiah 37:16","synthesized":"So Jeremiah went into a cell in the dungeon and remained there a long time.","sources":{"KJV":{"text":"When Jeremiah was entered into the dungeon, and into the cabins, and Jeremiah had remained there many days;"},"BSB":{"text":"So Jeremiah went into a cell in the dungeon and remained there a long time."},"TANAKH":{"text":"When Jeremiah was come into the dungeon-house, and into the cells, and Jeremiah had remained there many days;"},"HEBREW":{"text":"כִּ֣י בָ֧א יִרְמְיָ֛הוּ אֶל־בֵּ֥ית הַבּ֖וֹר וְאֶל־הַֽחֲנֻ֑יוֹת וַיֵּֽשֶׁב־שָׁ֥ם יִרְמְיָ֖הוּ יָמִ֥ים רַבִּֽים׃"}},"definableWords":[],"peopleInVerse":["Jeremiah"]},"17":{"text":"Then Zedekiah the king sent, and took him out: and the king asked him secretly in his house, and said, Is there any word from the LORD? And Jeremiah said, There is: for, said he, thou shalt be delivered into the hand of the king of Babylon.","ref":"Jeremiah 37:17","synthesized":"Later, King Zedekiah sent for Jeremiah and received him in his palace, where he asked him privately, “Is there a word from the LORD?”  “There is,” Jeremiah replied. “You will be delivered into the hand of the king of Babylon.”","sources":{"KJV":{"text":"Then Zedekiah the king sent, and took him out: and the king asked him secretly in his house, and said, Is there any word from the LORD? And Jeremiah said, There is: for, said he, thou shalt be delivered into the hand of the king of Babylon."},"BSB":{"text":"Later, King Zedekiah sent for Jeremiah and received him in his palace, where he asked him privately, “Is there a word from the LORD?”  “There is,” Jeremiah replied. “You will be delivered into the hand of the king of Babylon.”"},"TANAKH":{"text":"then Zedekiah the king sent, and fetched him; and the king asked him secretly in his house, and said: 'Is there any word from HaShem?' And Jeremiah said: 'There is.' He said also: 'Thou shalt be delivered into the hand of the king of Babylon.'"},"HEBREW":{"text":"וַיִּשְׁלַח֩ הַמֶּ֨לֶךְ צִדְקִיָּ֜הוּ וַיִּקָּחֵ֗הוּ וַיִּשְׁאָלֵ֨הוּ הַמֶּ֤לֶךְ בְּבֵיתוֹ֙ בַּסֵּ֔תֶר וַיֹּ֕אמֶר הֲיֵ֥שׁ דָּבָ֖ר מֵאֵ֣ת יְהוָ֑ה וַיֹּ֤אמֶר יִרְמְיָ֙הוּ֙ יֵ֔שׁ וַיֹּ֕אמֶר בְּיַ֥ד מֶֽלֶךְ־בָּבֶ֖ל תִּנָּתֵֽן׃"}},"definableWords":["King","word","LORD","king","Babylon"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"18":{"text":"Moreover Jeremiah said unto king Zedekiah, What have I offended against thee, or against thy servants, or against this people, that ye have put me in prison?","ref":"Jeremiah 37:18","synthesized":"Then Jeremiah asked King Zedekiah, “How have I sinned against you or your servants or these people, that you have put me in prison?","sources":{"KJV":{"text":"Moreover Jeremiah said unto king Zedekiah, What have I offended against thee, or against thy servants, or against this people, that ye have put me in prison?"},"BSB":{"text":"Then Jeremiah asked King Zedekiah, “How have I sinned against you or your servants or these people, that you have put me in prison?"},"TANAKH":{"text":"Moreover Jeremiah said unto king Zedekiah: 'Wherein have I sinned against thee, or against thy servants, or against this people, that ye have put me in prison?"},"HEBREW":{"text":"וַיֹּ֣אמֶר יִרְמְיָ֔הוּ אֶל־הַמֶּ֖לֶךְ צִדְקִיָּ֑הוּ מֶה֩ חָטָ֨אתִֽי לְךָ֤ וְלַעֲבָדֶ֙יךָ֙ וְלָעָ֣ם הַזֶּ֔ה כִּֽי־נְתַתֶּ֥ם אוֹתִ֖י אֶל־בֵּ֥ית הַכֶּֽלֶא׃"}},"definableWords":["King","or","servants","people"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship"]},"19":{"text":"Where are now your prophets which prophesied unto you, saying, The king of Babylon shall not come against you, nor against this land?","ref":"Jeremiah 37:19","synthesized":"Where are your prophets who prophesied to you, claiming, ‘The king of Babylon will not come against you or this land’?","sources":{"KJV":{"text":"Where are now your prophets which prophesied unto you, saying, The king of Babylon shall not come against you, nor against this land?"},"BSB":{"text":"Where are your prophets who prophesied to you, claiming, ‘The king of Babylon will not come against you or this land’?"},"TANAKH":{"text":"Where now are your prophets that prophesied unto you, saying: The king of Babylon shall not come against you, nor against this land?"},"HEBREW":{"text":"ואיו וְאַיֵּה֙ נְבִ֣יאֵיכֶ֔ם אֲשֶׁר־נִבְּא֥וּ לָכֶ֖ם לֵאמֹ֑ר לֹֽא־יָבֹ֤א מֶֽלֶךְ־בָּבֶל֙ עֲלֵיכֶ֔ם וְעַ֖ל הָאָ֥רֶץ הַזֹּֽאת׃"}},"definableWords":["king","Babylon","or","land"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship","land_promise"]},"20":{"text":"Therefore hear now, I pray thee, O my lord the king: let my supplication, I pray thee, be accepted before thee; that thou cause me not to return to the house of Jonathan the scribe, lest I die there.","ref":"Jeremiah 37:20","synthesized":"But now please listen, O my lord the king. May my petition come before you. Do not send me back to the house of Jonathan the scribe, or I will die there.”","sources":{"KJV":{"text":"Therefore hear now, I pray thee, O my lord the king: let my supplication, I pray thee, be accepted before thee; that thou cause me not to return to the house of Jonathan the scribe, lest I die there."},"BSB":{"text":"But now please listen, O my lord the king. May my petition come before you. Do not send me back to the house of Jonathan the scribe, or I will die there.”"},"TANAKH":{"text":"And now hear, I pray thee, O my lord the king: let my supplication, I pray thee, be presented before thee; that thou cause me not to return to the house of Jonathan the scribe, lest I die there.'"},"HEBREW":{"text":"וְעַתָּ֕ה שְֽׁמַֽע־נָ֖א אֲדֹנִ֣י הַמֶּ֑לֶךְ תִּפָּל־נָ֤א תְחִנָּתִי֙ לְפָנֶ֔יךָ וְאַל־תְּשִׁבֵ֗נִי בֵּ֚ית יְהוֹנָתָ֣ן הַסֹּפֵ֔ר וְלֹ֥א אָמ֖וּת שָֽׁם׃"}},"definableWords":["Lord","king","house","Scribe","or","die"],"peopleInVerse":["Jonathan"],"themesInVerse":["kingship","prayer"]},"21":{"text":"Then Zedekiah the king commanded that they should commit Jeremiah into the court of the prison, and that they should give him daily a piece of bread out of the bakers’ street, until all the bread in the city were spent. Thus Jeremiah remained in the court of the prison.","ref":"Jeremiah 37:21","synthesized":"So King Zedekiah gave orders for Jeremiah to be placed in the courtyard of the guard and given a loaf of bread daily from the street of the bakers, until all the bread in the city was gone. So Jeremiah remained in the courtyard of the guard.","sources":{"KJV":{"text":"Then Zedekiah the king commanded that they should commit Jeremiah into the court of the prison, and that they should give him daily a piece of bread out of the bakers’ street, until all the bread in the city were spent. Thus Jeremiah remained in the court of the prison."},"BSB":{"text":"So King Zedekiah gave orders for Jeremiah to be placed in the courtyard of the guard and given a loaf of bread daily from the street of the bakers, until all the bread in the city was gone. So Jeremiah remained in the courtyard of the guard."},"TANAKH":{"text":"Then Zedekiah the king commanded, and they committed Jeremiah into the court of the guard, and they gave him daily a loaf of bread out of the bakers' street, until all the bread in the city was spent. Thus Jeremiah remained in the court of the guard."},"HEBREW":{"text":"וַיְצַוֶּ֞ה הַמֶּ֣לֶךְ צִדְקִיָּ֗הוּ וַיַּפְקִ֣דוּ אֶֽת־יִרְמְיָהוּ֮ בַּחֲצַ֣ר הַמַּטָּרָה֒ וְנָתֹן֩ ל֨וֹ כִכַּר־לֶ֤חֶם לַיּוֹם֙ מִח֣וּץ הָאֹפִ֔ים עַד־תֹּ֥ם כָּל־הַלֶּ֖חֶם מִן־הָעִ֑יר וַיֵּ֣שֶׁב יִרְמְיָ֔הוּ בַּחֲצַ֖ר הַמַּטָּרָֽה׃"}},"definableWords":["King"],"peopleInVerse":["Jeremiah"],"themesInVerse":["bread_water_life","kingship"]}}},"38":{"chapter":"38","title":"JEREMIAH IN THE CISTERN — EBED-MELECH RESCUES","verses":{"1":{"text":"Then Shephatiah the son of Mattan, and Gedaliah the son of Pashur, and Jucal the son of Shelemiah, and Pashur the son of Malchiah, heard the words that Jeremiah had spoken unto all the people, saying,","ref":"Jeremiah 38:1","synthesized":"Now Shephatiah son of Mattan, Gedaliah son of Pashhur, Jucal son of Shelemiah, and Pashhur son of Malchijah heard that Jeremiah had been telling all the people:","sources":{"KJV":{"text":"Then Shephatiah the son of Mattan, and Gedaliah the son of Pashur, and Jucal the son of Shelemiah, and Pashur the son of Malchiah, heard the words that Jeremiah had spoken unto all the people, saying,"},"BSB":{"text":"Now Shephatiah son of Mattan, Gedaliah son of Pashhur, Jucal son of Shelemiah, and Pashhur son of Malchijah heard that Jeremiah had been telling all the people:"},"TANAKH":{"text":"And Shephatiah the son of Mattan, and Gedaliah the son of Pashhur, and Jucal the son of Shelemiah, and Pashhur the son of Malchiah, heard the words that Jeremiah spoke unto all the people, saying:"},"HEBREW":{"text":"וַיִּשְׁמַ֞ע שְׁפַטְיָ֣ה בֶן־מַתָּ֗ן וּגְדַלְיָ֙הוּ֙ בֶּן־פַּשְׁח֔וּר וְיוּכַל֙ בֶּן־שֶׁ֣לֶמְיָ֔הוּ וּפַשְׁח֖וּר בֶּן־מַלְכִּיָּ֑ה אֶ֨ת־הַדְּבָרִ֔ים אֲשֶׁ֧ר יִרְמְיָ֛הוּ מְדַבֵּ֥ר אֶל־כָּל־הָעָ֖ם לֵאמֹֽר׃"}},"definableWords":["son","Son","people"],"peopleInVerse":["Jeremiah"]},"2":{"text":"Thus saith the LORD, He that remaineth in this city shall die by the sword, by the famine, and by the pestilence: but he that goeth forth to the Chaldeans shall live; for he shall have his life for a prey, and shall live.","ref":"Jeremiah 38:2","synthesized":"“This is what the LORD says: Whoever stays in this city will die by sword and famine and plague, but whoever surrenders to the Chaldeans will live; he will retain his life like a spoil of war, and he will live.","sources":{"KJV":{"text":"Thus saith the LORD, He that remaineth in this city shall die by the sword, by the famine, and by the pestilence: but he that goeth forth to the Chaldeans shall live; for he shall have his life for a prey, and shall live."},"BSB":{"text":"“This is what the LORD says: Whoever stays in this city will die by sword and famine and plague, but whoever surrenders to the Chaldeans will live; he will retain his life like a spoil of war, and he will live."},"TANAKH":{"text":"'Thus saith HaShem: He that remaineth in this city shall die by the sword, by the famine, and by the pestilence; but he that goeth forth to the Chaldeans shall live, and his life shall be unto him for a prey, and he shall live."},"HEBREW":{"text":"כֹּה֮ אָמַ֣ר יְהוָה֒ הַיֹּשֵׁב֙ בָּעִ֣יר הַזֹּ֔את יָמ֕וּת בַּחֶ֖רֶב בָּרָעָ֣ב וּבַדָּ֑בֶר וְהַיֹּצֵ֤א אֶל־הַכַּשְׂדִּים֙ יחיה וְחָיָ֔ה וְהָיְתָה־לּ֥וֹ נַפְשׁ֛וֹ לְשָׁלָ֖ל וָחָֽי׃"}},"definableWords":["LORD","die","live","life"],"peopleInVerse":[]},"3":{"text":"Thus saith the LORD, This city shall surely be given into the hand of the king of Babylon’s army, which shall take it.","ref":"Jeremiah 38:3","synthesized":"This is what the LORD says: This city will surely be delivered into the hands of the army of the king of Babylon, and he will capture it.”","sources":{"KJV":{"text":"Thus saith the LORD, This city shall surely be given into the hand of the king of Babylon’s army, which shall take it."},"BSB":{"text":"This is what the LORD says: This city will surely be delivered into the hands of the army of the king of Babylon, and he will capture it.”"},"TANAKH":{"text":"Thus saith HaShem: This city shall surely be given into the hand of the army of the king of Babylon, and he shall take it.'"},"HEBREW":{"text":"כֹּ֖ה אָמַ֣ר יְהוָ֑ה הִנָּתֹ֨ן תִּנָּתֵ֜ן הָעִ֣יר הַזֹּ֗את בְּיַ֛ד חֵ֥יל מֶֽלֶךְ־בָּבֶ֖ל וּלְכָדָֽהּ׃"}},"definableWords":["LORD","king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"4":{"text":"Therefore the princes said unto the king, We beseech thee, let this man be put to death: for thus he weakeneth the hands of the men of war that remain in this city, and the hands of all the people, in speaking such words unto them: for this man seeketh not the welfare of this people, but the hurt.","ref":"Jeremiah 38:4","synthesized":"Then the officials said to the king, “This man ought to die, for he is discouraging the warriors who remain in this city, as well as all the people, by speaking such words to them; this man is not seeking the well-being of these people, but their ruin.”","sources":{"KJV":{"text":"Therefore the princes said unto the king, We beseech thee, let this man be put to death: for thus he weakeneth the hands of the men of war that remain in this city, and the hands of all the people, in speaking such words unto them: for this man seeketh not the welfare of this people, but the hurt."},"BSB":{"text":"Then the officials said to the king, “This man ought to die, for he is discouraging the warriors who remain in this city, as well as all the people, by speaking such words to them; this man is not seeking the well-being of these people, but their ruin.”"},"TANAKH":{"text":"Then the princes said unto the king: 'Let this man, we pray thee, be put to death; forasmuch as he weakeneth the hands of the men of war that remain in this city, and the hands of all the people, in speaking such words unto them; for this man seeketh not the welfare of this people, but the hurt.'"},"HEBREW":{"text":"וַיֹּאמְר֨וּ הַשָּׂרִ֜ים אֶל־הַמֶּ֗לֶךְ י֣וּמַת נָא֮ אֶת־הָאִ֣ישׁ הַזֶּה֒ כִּֽי־עַל־כֵּ֡ן הֽוּא־מְרַפֵּ֡א אֶת־יְדֵי֩ אַנְשֵׁ֨י הַמִּלְחָמָ֜ה הַֽנִּשְׁאָרִ֣ים ׀ בָּעִ֣יר הַזֹּ֗את וְאֵת֙ יְדֵ֣י כָל־הָעָ֔ם לְדַבֵּ֣ר אֲלֵיהֶ֔ם כַּדְּבָרִ֖ים הָאֵ֑לֶּה כִּ֣י ׀ הָאִ֣ישׁ הַזֶּ֗ה אֵינֶ֨נּוּ דֹרֵ֧שׁ לְשָׁל֛וֹם לָעָ֥ם הַזֶּ֖ה כִּ֥י אִם־לְרָעָֽה׃"}},"definableWords":["king","man","die","people"],"peopleInVerse":[],"themesInVerse":["bread_water_life","kingship"]},"5":{"text":"Then Zedekiah the king said, Behold, he is in your hand: for the king is not he that can do any thing against you.","ref":"Jeremiah 38:5","synthesized":"“Here he is,” replied King Zedekiah. “He is in your hands, since the king can do nothing to stop you.”","sources":{"KJV":{"text":"Then Zedekiah the king said, Behold, he is in your hand: for the king is not he that can do any thing against you."},"BSB":{"text":"“Here he is,” replied King Zedekiah. “He is in your hands, since the king can do nothing to stop you.”"},"TANAKH":{"text":"Then Zedekiah the king said: 'Behold, he is in your hand; for the king is not he that can do any thing against you.'"},"HEBREW":{"text":"וַיֹּ֙אמֶר֙ הַמֶּ֣לֶךְ צִדְקִיָּ֔הוּ הִנֵּה־ה֖וּא בְּיֶדְכֶ֑ם כִּֽי־אֵ֣ין הַמֶּ֔לֶךְ יוּכַ֥ל אֶתְכֶ֖ם דָּבָֽר׃"}},"definableWords":["King","king"],"peopleInVerse":[],"themesInVerse":["kingship"]},"6":{"text":"Then took they Jeremiah, and cast him into the dungeon of Malchiah the son of Hammelech, that was in the court of the prison: and they let down Jeremiah with cords. And in the dungeon there was no water, but mire: so Jeremiah sunk in the mire.","ref":"Jeremiah 38:6","synthesized":"So they took Jeremiah and dropped him into the cistern of Malchiah, the king’s son, which was in the courtyard of the guard. They lowered Jeremiah with ropes into the cistern, which had no water but only mud, and Jeremiah sank down into the mud.","sources":{"KJV":{"text":"Then took they Jeremiah, and cast him into the dungeon of Malchiah the son of Hammelech, that was in the court of the prison: and they let down Jeremiah with cords. And in the dungeon there was no water, but mire: so Jeremiah sunk in the mire."},"BSB":{"text":"So they took Jeremiah and dropped him into the cistern of Malchiah, the king’s son, which was in the courtyard of the guard. They lowered Jeremiah with ropes into the cistern, which had no water but only mud, and Jeremiah sank down into the mud."},"TANAKH":{"text":"Then took they Jeremiah, and cast him into the pit of Malchiah the king's son, that was in the court of the guard; and they let down Jeremiah with cords. And in the pit there was no water, but mire; and Jeremiah sank in the mire."},"HEBREW":{"text":"וַיִּקְח֣וּ אֶֽת־יִרְמְיָ֗הוּ וַיַּשְׁלִ֨כוּ אֹת֜וֹ אֶל־הַבּ֣וֹר ׀ מַלְכִּיָּ֣הוּ בֶן־הַמֶּ֗לֶךְ אֲשֶׁר֙ בַּחֲצַ֣ר הַמַּטָּרָ֔ה וַיְשַׁלְּח֥וּ אֶֽת־יִרְמְיָ֖הוּ בַּחֲבָלִ֑ים וּבַבּ֤וֹר אֵֽין־מַ֙יִם֙ כִּ֣י אִם־טִ֔יט וַיִּטְבַּ֥ע יִרְמְיָ֖הוּ בַּטִּֽיט׃"}},"definableWords":["king","son","water"],"peopleInVerse":["Jeremiah"],"themesInVerse":["bread_water_life","kingship"]},"7":{"text":"Now when Ebedmelech the Ethiopian, one of the eunuchs which was in the king’s house, heard that they had put Jeremiah in the dungeon; the king then sitting in the gate of Benjamin;","ref":"Jeremiah 38:7","synthesized":"Now Ebed-melech the Cushite, a court official in the royal palace, heard that Jeremiah had been put into the cistern. While the king was sitting at the Gate of Benjamin,","sources":{"KJV":{"text":"Now when Ebedmelech the Ethiopian, one of the eunuchs which was in the king’s house, heard that they had put Jeremiah in the dungeon; the king then sitting in the gate of Benjamin;"},"BSB":{"text":"Now Ebed-melech the Cushite, a court official in the royal palace, heard that Jeremiah had been put into the cistern. While the king was sitting at the Gate of Benjamin,"},"TANAKH":{"text":"Now when Ebed-melech the Ethiopian, an officer, who was in the king's house, heard that they had put Jeremiah in the pit; the king then sitting in the gate of Benjamin;"},"HEBREW":{"text":"וַיִּשְׁמַ֡ע עֶֽבֶד־מֶ֨לֶךְ הַכּוּשִׁ֜י אִ֣ישׁ סָרִ֗יס וְהוּא֙ בְּבֵ֣ית הַמֶּ֔לֶךְ כִּֽי־נָתְנ֥וּ אֶֽת־יִרְמְיָ֖הוּ אֶל־הַבּ֑וֹר וְהַמֶּ֥לֶךְ יוֹשֵׁ֖ב בְּשַׁ֥עַר בִּנְיָמִֽן׃"}},"definableWords":["king","Benjamin"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship"]},"8":{"text":"Ebedmelech went forth out of the king’s house, and spake to the king, saying,","ref":"Jeremiah 38:8","synthesized":"Ebed-melech went out from the king’s palace and said to the king,","sources":{"KJV":{"text":"Ebedmelech went forth out of the king’s house, and spake to the king, saying,"},"BSB":{"text":"Ebed-melech went out from the king’s palace and said to the king,"},"TANAKH":{"text":"Ebed-melech went forth out of the king's house, and spoke to the king, saying:"},"HEBREW":{"text":"וַיֵּצֵ֥א עֶֽבֶד־מֶ֖לֶךְ מִבֵּ֣ית הַמֶּ֑לֶךְ וַיְדַבֵּ֥ר אֶל־הַמֶּ֖לֶךְ לֵאמֹֽר׃"}},"definableWords":["king","King"],"peopleInVerse":[],"themesInVerse":["kingship"]},"9":{"text":"My lord the king, these men have done evil in all that they have done to Jeremiah the prophet, whom they have cast into the dungeon; and he is like to die for hunger in the place where he is: for there is no more bread in the city.","ref":"Jeremiah 38:9","synthesized":"“My lord the king, these men have acted wickedly in all that they have done to Jeremiah the prophet. They have dropped him into the cistern, where he will starve to death, for there is no more bread in the city.”","sources":{"KJV":{"text":"My lord the king, these men have done evil in all that they have done to Jeremiah the prophet, whom they have cast into the dungeon; and he is like to die for hunger in the place where he is: for there is no more bread in the city."},"BSB":{"text":"“My lord the king, these men have acted wickedly in all that they have done to Jeremiah the prophet. They have dropped him into the cistern, where he will starve to death, for there is no more bread in the city.”"},"TANAKH":{"text":"'My lord the king, these men have done evil in all that they have done to Jeremiah the prophet, whom they have cast into the pit; and he is like to die in the place where he is because of the famine; for there is no more bread in the city.'"},"HEBREW":{"text":"אֲדֹנִ֣י הַמֶּ֗לֶךְ הֵרֵ֜עוּ הָאֲנָשִׁ֤ים הָאֵ֙לֶּה֙ אֵ֣ת כָּל־אֲשֶׁ֤ר עָשׂוּ֙ לְיִרְמְיָ֣הוּ הַנָּבִ֔יא אֵ֥ת אֲשֶׁר־הִשְׁלִ֖יכוּ אֶל־הַבּ֑וֹר וַיָּ֤מָת תַּחְתָּיו֙ מִפְּנֵ֣י הָֽרָעָ֔ב כִּ֣י אֵ֥ין הַלֶּ֛חֶם ע֖וֹד בָּעִֽיר׃"}},"definableWords":["Lord","king","men","prophet","death"],"peopleInVerse":["Jeremiah"],"themesInVerse":["bread_water_life","kingship"]},"10":{"text":"Then the king commanded Ebedmelech the Ethiopian, saying, Take from hence thirty men with thee, and take up Jeremiah the prophet out of the dungeon, before he die.","ref":"Jeremiah 38:10","synthesized":"So the king commanded Ebed-melech the Cushite, “Take thirty men from here with you and pull Jeremiah the prophet out of the cistern before he dies.”","sources":{"KJV":{"text":"Then the king commanded Ebedmelech the Ethiopian, saying, Take from hence thirty men with thee, and take up Jeremiah the prophet out of the dungeon, before he die."},"BSB":{"text":"So the king commanded Ebed-melech the Cushite, “Take thirty men from here with you and pull Jeremiah the prophet out of the cistern before he dies.”"},"TANAKH":{"text":"Then the king commanded Ebed-melech the Ethiopian, saying: 'Take from hence thirty men with thee, and take up Jeremiah the prophet out of the pit, before he die.'"},"HEBREW":{"text":"וַיְצַוֶּ֣ה הַמֶּ֔לֶךְ אֵ֛ת עֶֽבֶד־מֶ֥לֶךְ הַכּוּשִׁ֖י לֵאמֹ֑ר קַ֣ח בְּיָדְךָ֤ מִזֶּה֙ שְׁלֹשִׁ֣ים אֲנָשִׁ֔ים וְֽהַעֲלִ֜יתָ אֶֽת־יִרְמְיָ֧הוּ הַנָּבִ֛יא מִן־הַבּ֖וֹר בְּטֶ֥רֶם יָמֽוּת׃"}},"definableWords":["king","men","prophet"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship"]},"11":{"text":"So Ebedmelech took the men with him, and went into the house of the king under the treasury, and took thence old cast clouts and old rotten rags, and let them down by cords into the dungeon to Jeremiah.","ref":"Jeremiah 38:11","synthesized":"Then Ebed-melech took the men with him and went to the king’s palace, to a place below the storehouse. From there he took old rags and worn-out clothes and lowered them with ropes to Jeremiah in the cistern.","sources":{"KJV":{"text":"So Ebedmelech took the men with him, and went into the house of the king under the treasury, and took thence old cast clouts and old rotten rags, and let them down by cords into the dungeon to Jeremiah."},"BSB":{"text":"Then Ebed-melech took the men with him and went to the king’s palace, to a place below the storehouse. From there he took old rags and worn-out clothes and lowered them with ropes to Jeremiah in the cistern."},"TANAKH":{"text":"So Ebed-melech took the men with him, and went into the house of the king under the treasury, and took thence worn clouts and worn rags, and let them down by cords into the pit to Jeremiah."},"HEBREW":{"text":"וַיִּקַּ֣ח ׀ עֶֽבֶד־מֶ֨לֶךְ אֶת־הָאֲנָשִׁ֜ים בְּיָד֗וֹ וַיָּבֹ֤א בֵית־הַמֶּ֙לֶךְ֙ אֶל־תַּ֣חַת הָאוֹצָ֔ר וַיִּקַּ֤ח מִשָּׁם֙ בְּלוֹיֵ֣ הסחבות סְחָב֔וֹת וּבְלוֹיֵ֖ מְלָחִ֑ים וַיְשַׁלְּחֵ֧ם אֶֽל־יִרְמְיָ֛הוּ אֶל־הַבּ֖וֹר בַּחֲבָלִֽים׃"}},"definableWords":["men","king"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship"]},"12":{"text":"And Ebedmelech the Ethiopian said unto Jeremiah, Put now these old cast clouts and rotten rags under thine armholes under the cords. And Jeremiah did so.","ref":"Jeremiah 38:12","synthesized":"Ebed-melech the Cushite cried out to Jeremiah, “Put these worn-out rags and clothes under your arms to pad the ropes.” Jeremiah did so,","sources":{"KJV":{"text":"And Ebedmelech the Ethiopian said unto Jeremiah, Put now these old cast clouts and rotten rags under thine armholes under the cords. And Jeremiah did so."},"BSB":{"text":"Ebed-melech the Cushite cried out to Jeremiah, “Put these worn-out rags and clothes under your arms to pad the ropes.” Jeremiah did so,"},"TANAKH":{"text":"And Ebed-melech the Ethiopian said unto Jeremiah: 'Put now these worn clouts and rags under thine armholes under the cords.' And Jeremiah did so."},"HEBREW":{"text":"וַיֹּ֡אמֶר עֶבֶד־מֶ֨לֶךְ הַכּוּשִׁ֜י אֶֽל־יִרְמְיָ֗הוּ שִׂ֣ים נָ֠א בְּלוֹאֵ֨י הַסְּחָב֤וֹת וְהַמְּלָחִים֙ תַּ֚חַת אַצִּל֣וֹת יָדֶ֔יךָ מִתַּ֖חַת לַחֲבָלִ֑ים וַיַּ֥עַשׂ יִרְמְיָ֖הוּ כֵּֽן׃"}},"definableWords":[],"peopleInVerse":["Jeremiah"]},"13":{"text":"So they drew up Jeremiah with cords, and took him up out of the dungeon: and Jeremiah remained in the court of the prison.","ref":"Jeremiah 38:13","synthesized":"and they pulled him up with the ropes and lifted him out of the cistern. And Jeremiah remained in the courtyard of the guard.","sources":{"KJV":{"text":"So they drew up Jeremiah with cords, and took him up out of the dungeon: and Jeremiah remained in the court of the prison."},"BSB":{"text":"and they pulled him up with the ropes and lifted him out of the cistern. And Jeremiah remained in the courtyard of the guard."},"TANAKH":{"text":"So they drew up Jeremiah with the cords, and took him up out of the pit; and Jeremiah remained in the court of the guard."},"HEBREW":{"text":"וַיִּמְשְׁכ֤וּ אֶֽת־יִרְמְיָ֙הוּ֙ בַּֽחֲבָלִ֔ים וַיַּעֲל֥וּ אֹת֖וֹ מִן־הַבּ֑וֹר וַיֵּ֣שֶׁב יִרְמְיָ֔הוּ בַּחֲצַ֖ר הַמַּטָּרָֽה׃"}},"definableWords":[],"peopleInVerse":["Jeremiah"]},"14":{"text":"Then Zedekiah the king sent, and took Jeremiah the prophet unto him into the third entry that is in the house of the LORD: and the king said unto Jeremiah, I will ask thee a thing; hide nothing from me.","ref":"Jeremiah 38:14","synthesized":"Then King Zedekiah sent for Jeremiah the prophet and received him at the third entrance to the house of the LORD. “I am going to ask you something,” said the king to Jeremiah. “Do not hide anything from me.”","sources":{"KJV":{"text":"Then Zedekiah the king sent, and took Jeremiah the prophet unto him into the third entry that is in the house of the LORD: and the king said unto Jeremiah, I will ask thee a thing; hide nothing from me."},"BSB":{"text":"Then King Zedekiah sent for Jeremiah the prophet and received him at the third entrance to the house of the LORD. “I am going to ask you something,” said the king to Jeremiah. “Do not hide anything from me.”"},"TANAKH":{"text":"Then Zedekiah the king sent, and took Jeremiah the prophet unto him into the third entry that was in the house of HaShem; and the king said unto Jeremiah: 'I will ask thee a thing; hide nothing from me.'"},"HEBREW":{"text":"וַיִּשְׁלַ֞ח הַמֶּ֣לֶךְ צִדְקִיָּ֗הוּ וַיִּקַּ֞ח אֶֽת־יִרְמְיָ֤הוּ הַנָּבִיא֙ אֵלָ֔יו אֶל־מָבוֹא֙ הַשְּׁלִישִׁ֔י אֲשֶׁ֖ר בְּבֵ֣ית יְהוָ֑ה וַיֹּ֨אמֶר הַמֶּ֜לֶךְ אֶֽל־יִרְמְיָ֗הוּ שֹׁאֵ֨ל אֲנִ֤י אֹֽתְךָ֙ דָּבָ֔ר אַל־תְּכַחֵ֥ד מִמֶּ֖נִּי דָּבָֽר׃"}},"definableWords":["King","prophet","house","LORD","king"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship"]},"15":{"text":"Then Jeremiah said unto Zedekiah, If I declare it unto thee, wilt thou not surely put me to death? and if I give thee counsel, wilt thou not hearken unto me?","ref":"Jeremiah 38:15","synthesized":"“If I tell you,” Jeremiah replied, “you will surely put me to death. And even if I give you advice, you will not listen to me.”","sources":{"KJV":{"text":"Then Jeremiah said unto Zedekiah, If I declare it unto thee, wilt thou not surely put me to death? and if I give thee counsel, wilt thou not hearken unto me?"},"BSB":{"text":"“If I tell you,” Jeremiah replied, “you will surely put me to death. And even if I give you advice, you will not listen to me.”"},"TANAKH":{"text":"Then Jeremiah said unto Zedekiah: 'If I declare it unto thee, wilt thou not surely put me to death? and if I give thee counsel, thou wilt not hearken unto me.'"},"HEBREW":{"text":"וַיֹּ֤אמֶר יִרְמְיָ֙הוּ֙ אֶל־צִדְקִיָּ֔הוּ כִּ֚י אַגִּ֣יד לְךָ֔ הֲל֖וֹא הָמֵ֣ת תְּמִיתֵ֑נִי וְכִי֙ אִיעָ֣צְךָ֔ לֹ֥א תִשְׁמַ֖ע אֵלָֽי׃"}},"definableWords":["death"],"peopleInVerse":["Jeremiah"]},"16":{"text":"So Zedekiah the king sware secretly unto Jeremiah, saying, As the LORD liveth, that made us this soul, I will not put thee to death, neither will I give thee into the hand of these men that seek thy life.","ref":"Jeremiah 38:16","synthesized":"But King Zedekiah swore secretly to Jeremiah, “As surely as the LORD lives, who has given us this life, I will not kill you, nor will I deliver you into the hands of these men who are seeking your life.”","sources":{"KJV":{"text":"So Zedekiah the king sware secretly unto Jeremiah, saying, As the LORD liveth, that made us this soul, I will not put thee to death, neither will I give thee into the hand of these men that seek thy life."},"BSB":{"text":"But King Zedekiah swore secretly to Jeremiah, “As surely as the LORD lives, who has given us this life, I will not kill you, nor will I deliver you into the hands of these men who are seeking your life.”"},"TANAKH":{"text":"So Zedekiah the king swore secretly unto Jeremiah, saying: 'As HaShem liveth, that made us this soul, I will not put thee to death, neither will I give thee into the hand of these men that seek thy life.'"},"HEBREW":{"text":"וַיִּשָּׁבַ֞ע הַמֶּ֧לֶךְ צִדְקִיָּ֛הוּ אֶֽל־יִרְמְיָ֖הוּ בַּסֵּ֣תֶר לֵאמֹ֑ר חַי־יְהוָ֞ה את אֲשֶׁר֩ עָשָׂה־לָ֨נוּ אֶת־הַנֶּ֤פֶשׁ הַזֹּאת֙ אִם־אֲמִיתֶ֔ךָ וְאִם־אֶתֶּנְךָ֗ בְּיַד֙ הָאֲנָשִׁ֣ים הָאֵ֔לֶּה אֲשֶׁ֥ר מְבַקְשִׁ֖ים אֶת־נַפְשֶֽׁךָ׃"}},"definableWords":["King","LORD","life","deliver","men"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship","redemption","salvation"]},"17":{"text":"Then said Jeremiah unto Zedekiah, Thus saith the LORD, the God of hosts, the God of Israel; If thou wilt assuredly go forth unto the king of Babylon’s princes, then thy soul shall live, and this city shall not be burned with fire; and thou shalt live, and thine house:","ref":"Jeremiah 38:17","synthesized":"Then Jeremiah said to Zedekiah, “This is what the LORD God of Hosts, the God of Israel, says: ‘If you indeed surrender to the officers of the king of Babylon, then you will live, this city will not be burned down, and you and your household will survive.","sources":{"KJV":{"text":"Then said Jeremiah unto Zedekiah, Thus saith the LORD, the God of hosts, the God of Israel; If thou wilt assuredly go forth unto the king of Babylon’s princes, then thy soul shall live, and this city shall not be burned with fire; and thou shalt live, and thine house:"},"BSB":{"text":"Then Jeremiah said to Zedekiah, “This is what the LORD God of Hosts, the God of Israel, says: ‘If you indeed surrender to the officers of the king of Babylon, then you will live, this city will not be burned down, and you and your household will survive."},"TANAKH":{"text":"Then said Jeremiah unto Zedekiah: 'Thus saith HaShem, the G-d of hosts, the G-d of Israel: If thou wilt go forth unto the king of Babylon's princes, then thy soul shall live, and this city shall not be burned with fire; and thou shalt live, thou, and thy house;"},"HEBREW":{"text":"וַיֹּ֣אמֶר יִרְמְיָ֣הוּ אֶל־צִדְקִיָּ֡הוּ כֹּֽה־אָמַ֣ר יְהוָה֩ אֱלֹהֵ֨י צְבָא֜וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֗ל אִם־יָצֹ֨א תֵצֵ֜א אֶל־שָׂרֵ֤י מֶֽלֶךְ־בָּבֶל֙ וְחָיְתָ֣ה נַפְשֶׁ֔ךָ וְהָעִ֣יר הַזֹּ֔את לֹ֥א תִשָּׂרֵ֖ף בָּאֵ֑שׁ וְחָיִ֖תָה אַתָּ֥ה וּבֵיתֶֽךָ׃"}},"definableWords":["LORD","God","Israel","king","Babylon","live"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"18":{"text":"But if thou wilt not go forth to the king of Babylon’s princes, then shall this city be given into the hand of the Chaldeans, and they shall burn it with fire, and thou shalt not escape out of their hand.","ref":"Jeremiah 38:18","synthesized":"But if you do not surrender to the officers of the king of Babylon, then this city will be delivered into the hands of the Chaldeans. They will burn it down, and you yourself will not escape their grasp.’”","sources":{"KJV":{"text":"But if thou wilt not go forth to the king of Babylon’s princes, then shall this city be given into the hand of the Chaldeans, and they shall burn it with fire, and thou shalt not escape out of their hand."},"BSB":{"text":"But if you do not surrender to the officers of the king of Babylon, then this city will be delivered into the hands of the Chaldeans. They will burn it down, and you yourself will not escape their grasp.’”"},"TANAKH":{"text":"but if thou wilt not go forth to the king of Babylon's princes, then shall this city be given into the hand of the Chaldeans, and they shall burn it with fire, and thou shalt not escape out of their hand.'"},"HEBREW":{"text":"וְאִ֣ם לֹֽא־תֵצֵ֗א אֶל־שָׂרֵי֙ מֶ֣לֶךְ בָּבֶ֔ל וְנִתְּנָ֞ה הָעִ֤יר הַזֹּאת֙ בְּיַ֣ד הַכַּשְׂדִּ֔ים וּשְׂרָפ֖וּהָ בָּאֵ֑שׁ וְאַתָּ֖ה לֹֽא־תִמָּלֵ֥ט מִיָּדָֽם׃"}},"definableWords":["king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"19":{"text":"And Zedekiah the king said unto Jeremiah, I am afraid of the Jews that are fallen to the Chaldeans, lest they deliver me into their hand, and they mock me.","ref":"Jeremiah 38:19","synthesized":"But King Zedekiah said to Jeremiah, “I am afraid of the Jews who have deserted to the Chaldeans, for the Chaldeans may deliver me into their hands to abuse me.”","sources":{"KJV":{"text":"And Zedekiah the king said unto Jeremiah, I am afraid of the Jews that are fallen to the Chaldeans, lest they deliver me into their hand, and they mock me."},"BSB":{"text":"But King Zedekiah said to Jeremiah, “I am afraid of the Jews who have deserted to the Chaldeans, for the Chaldeans may deliver me into their hands to abuse me.”"},"TANAKH":{"text":"And Zedekiah the king said unto Jeremiah: 'I am afraid of the Jews that are fallen away to the Chaldeans, lest they deliver me into their hand, and they mock me.'"},"HEBREW":{"text":"וַיֹּ֛אמֶר הַמֶּ֥לֶךְ צִדְקִיָּ֖הוּ אֶֽל־יִרְמְיָ֑הוּ אֲנִ֧י דֹאֵ֣ג אֶת־הַיְּהוּדִ֗ים אֲשֶׁ֤ר נָֽפְלוּ֙ אֶל־הַכַּשְׂדִּ֔ים פֶּֽן־יִתְּנ֥וּ אֹתִ֛י בְּיָדָ֖ם וְהִתְעַלְּלוּ־בִֽי׃"}},"definableWords":["King","deliver"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship","redemption","salvation"]},"20":{"text":"But Jeremiah said, They shall not deliver thee. Obey, I beseech thee, the voice of the LORD, which I speak unto thee: so it shall be well unto thee, and thy soul shall live.","ref":"Jeremiah 38:20","synthesized":"“They will not hand you over,” Jeremiah replied. “Obey the voice of the LORD in what I am telling you, that it may go well with you and you may live.","sources":{"KJV":{"text":"But Jeremiah said, They shall not deliver thee. Obey, I beseech thee, the voice of the LORD, which I speak unto thee: so it shall be well unto thee, and thy soul shall live."},"BSB":{"text":"“They will not hand you over,” Jeremiah replied. “Obey the voice of the LORD in what I am telling you, that it may go well with you and you may live."},"TANAKH":{"text":"But Jeremiah said: 'They shall not deliver thee. Hearken, I beseech thee, to the voice of HaShem, in that which I speak unto thee; so it shall be well with thee, and thy soul shall live."},"HEBREW":{"text":"וַיֹּ֥אמֶר יִרְמְיָ֖הוּ לֹ֣א יִתֵּ֑נוּ שְֽׁמַֽע־נָ֣א ׀ בְּק֣וֹל יְהוָ֗ה לַאֲשֶׁ֤ר אֲנִי֙ דֹּבֵ֣ר אֵלֶ֔יךָ וְיִ֥יטַב לְךָ֖ וּתְחִ֥י נַפְשֶֽׁךָ׃"}},"definableWords":["voice","LORD","live"],"peopleInVerse":["Jeremiah"],"themesInVerse":["bread_water_life"]},"21":{"text":"But if thou refuse to go forth, this is the word that the LORD hath shewed me:","ref":"Jeremiah 38:21","synthesized":"But if you refuse to surrender, this is the word that the LORD has shown me:","sources":{"KJV":{"text":"But if thou refuse to go forth, this is the word that the LORD hath shewed me:"},"BSB":{"text":"But if you refuse to surrender, this is the word that the LORD has shown me:"},"TANAKH":{"text":"But if thou refuse to go forth, this is the word that HaShem hath shown me:"},"HEBREW":{"text":"וְאִם־מָאֵ֥ן אַתָּ֖ה לָצֵ֑את זֶ֣ה הַדָּבָ֔ר אֲשֶׁ֥ר הִרְאַ֖נִי יְהוָֽה׃"}},"definableWords":["word","LORD"],"peopleInVerse":[]},"22":{"text":"And, behold, all the women that are left in the king of Judah’s house shall be brought forth to the king of Babylon’s princes, and those women shall say, Thy friends have set thee on, and have prevailed against thee: thy feet are sunk in the mire, and they are turned away back.","ref":"Jeremiah 38:22","synthesized":"All the women who remain in the palace of the king of Judah will be brought out to the officials of the king of Babylon, and those women will say:  ‘They misled you and overcame you— those trusted friends of yours. Your feet sank into the mire, and they deserted you.’","sources":{"KJV":{"text":"And, behold, all the women that are left in the king of Judah’s house shall be brought forth to the king of Babylon’s princes, and those women shall say, Thy friends have set thee on, and have prevailed against thee: thy feet are sunk in the mire, and they are turned away back."},"BSB":{"text":"All the women who remain in the palace of the king of Judah will be brought out to the officials of the king of Babylon, and those women will say:  ‘They misled you and overcame you— those trusted friends of yours. Your feet sank into the mire, and they deserted you.’"},"TANAKH":{"text":"Behold, all the women that are left in the king of Judah's house shall be brought forth to the king of Babylon's princes, and those women shall say: Thy familiar friends have set thee on, and have prevailed over thee; thy feet are sunk in the mire, and they are turned away back."},"HEBREW":{"text":"וְהִנֵּ֣ה כָל־הַנָּשִׁ֗ים אֲשֶׁ֤ר נִשְׁאֲרוּ֙ בְּבֵ֣ית מֶֽלֶךְ־יְהוּדָ֔ה מוּצָא֕וֹת אֶל־שָׂרֵ֖י מֶ֣לֶךְ בָּבֶ֑ל וְהֵ֣נָּה אֹמְר֗וֹת הִסִּית֜וּךָ וְיָכְל֤וּ לְךָ֙ אַנְשֵׁ֣י שְׁלֹמֶ֔ךָ הָטְבְּע֥וּ בַבֹּ֛ץ רַגְלֶ֖ךָ נָסֹ֥גוּ אָחֽוֹר׃"}},"definableWords":["women","king","Judah","King","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"23":{"text":"So they shall bring out all thy wives and thy children to the Chaldeans: and thou shalt not escape out of their hand, but shalt be taken by the hand of the king of Babylon: and thou shalt cause this city to be burned with fire.","ref":"Jeremiah 38:23","synthesized":"All your wives and children will be brought out to the Chaldeans. And you yourself will not escape their grasp, for you will be seized by the king of Babylon, and this city will be burned down.”","sources":{"KJV":{"text":"So they shall bring out all thy wives and thy children to the Chaldeans: and thou shalt not escape out of their hand, but shalt be taken by the hand of the king of Babylon: and thou shalt cause this city to be burned with fire."},"BSB":{"text":"All your wives and children will be brought out to the Chaldeans. And you yourself will not escape their grasp, for you will be seized by the king of Babylon, and this city will be burned down.”"},"TANAKH":{"text":"And they shall bring out all thy wives and thy children to the Chaldeans; and thou shalt not escape out of their hand, but shalt be taken by the hand of the king of Babylon; and thou shalt cause this city to be burned with fire.'"},"HEBREW":{"text":"וְאֶת־כָּל־נָשֶׁ֣יךָ וְאֶת־בָּנֶ֗יךָ מֽוֹצִאִים֙ אֶל־הַכַּשְׂדִּ֔ים וְאַתָּ֖ה לֹא־תִמָּלֵ֣ט מִיָּדָ֑ם כִּ֣י בְיַ֤ד מֶֽלֶךְ־בָּבֶל֙ תִּתָּפֵ֔שׂ וְאֶת־הָעִ֥יר הַזֹּ֖את תִּשְׂרֹ֥ף בָּאֵֽשׁ׃"}},"definableWords":["king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"24":{"text":"Then said Zedekiah unto Jeremiah, Let no man know of these words, and thou shalt not die.","ref":"Jeremiah 38:24","synthesized":"Then Zedekiah warned Jeremiah, “Do not let anyone know about this conversation, or you will die.","sources":{"KJV":{"text":"Then said Zedekiah unto Jeremiah, Let no man know of these words, and thou shalt not die."},"BSB":{"text":"Then Zedekiah warned Jeremiah, “Do not let anyone know about this conversation, or you will die."},"TANAKH":{"text":"Then said Zedekiah unto Jeremiah: 'Let no man know of these words, and thou shalt not die."},"HEBREW":{"text":"וַיֹּ֨אמֶר צִדְקִיָּ֜הוּ אֶֽל־יִרְמְיָ֗הוּ אִ֛ישׁ אַל־יֵדַ֥ע בַּדְּבָֽרִים־הָאֵ֖לֶּה וְלֹ֥א תָמֽוּת׃"}},"definableWords":["or","die"],"peopleInVerse":["Jeremiah"]},"25":{"text":"But if the princes hear that I have talked with thee, and they come unto thee, and say unto thee, Declare unto us now what thou hast said unto the king, hide it not from us, and we will not put thee to death; also what the king said unto thee:","ref":"Jeremiah 38:25","synthesized":"If the officials hear that I have spoken with you, and they come and demand of you, ‘Tell us what you said to the king and what he said to you; do not hide it from us, or we will kill you,’","sources":{"KJV":{"text":"But if the princes hear that I have talked with thee, and they come unto thee, and say unto thee, Declare unto us now what thou hast said unto the king, hide it not from us, and we will not put thee to death; also what the king said unto thee:"},"BSB":{"text":"If the officials hear that I have spoken with you, and they come and demand of you, ‘Tell us what you said to the king and what he said to you; do not hide it from us, or we will kill you,’"},"TANAKH":{"text":"But if the princes hear that I have talked with thee, and they come unto thee, and say unto thee: Declare unto us now what thou hast said unto the king; hide it not from us, and we will not put thee to death; also what the king said unto thee;"},"HEBREW":{"text":"וְכִֽי־יִשְׁמְע֣וּ הַשָּׂרִים֮ כִּֽי־דִבַּ֣רְתִּי אִתָּךְ֒ וּבָ֣אוּ אֵלֶ֣יךָ וְֽאָמְר֪וּ אֵלֶ֟יךָ הַגִּֽידָה־נָּ֨א לָ֜נוּ מַה־דִּבַּ֧רְתָּ אֶל־הַמֶּ֛לֶךְ אַל־תְּכַחֵ֥ד מִמֶּ֖נּוּ וְלֹ֣א נְמִיתֶ֑ךָ וּמַה־דִּבֶּ֥ר אֵלֶ֖יךָ הַמֶּֽלֶךְ׃"}},"definableWords":["hear","king","or"],"peopleInVerse":[],"themesInVerse":["kingship"]},"26":{"text":"Then thou shalt say unto them, I presented my supplication before the king, that he would not cause me to return to Jonathan’s house, to die there.","ref":"Jeremiah 38:26","synthesized":"then tell them, ‘I was presenting to the king my petition that he not return me to the house of Jonathan to die there.’”","sources":{"KJV":{"text":"Then thou shalt say unto them, I presented my supplication before the king, that he would not cause me to return to Jonathan’s house, to die there."},"BSB":{"text":"then tell them, ‘I was presenting to the king my petition that he not return me to the house of Jonathan to die there.’”"},"TANAKH":{"text":"then thou shalt say unto them: I presented my supplication before the king, that he would not cause me to return to Jonathan's house, to die there.'"},"HEBREW":{"text":"וְאָמַרְתָּ֣ אֲלֵיהֶ֔ם מַפִּיל־אֲנִ֥י תְחִנָּתִ֖י לִפְנֵ֣י הַמֶּ֑לֶךְ לְבִלְתִּ֧י הֲשִׁיבֵ֛נִי בֵּ֥ית יְהוֹנָתָ֖ן לָמ֥וּת שָֽׁם׃"}},"definableWords":["king","house","die"],"peopleInVerse":["Jonathan"],"themesInVerse":["exile_return","kingship","prayer","second_coming"]},"27":{"text":"Then came all the princes unto Jeremiah, and asked him: and he told them according to all these words that the king had commanded. So they left off speaking with him; for the matter was not perceived.","ref":"Jeremiah 38:27","synthesized":"When all the officials came to Jeremiah and questioned him, he relayed to them the exact words the king had commanded him to say. So they said no more to him, for no one had overheard the conversation.","sources":{"KJV":{"text":"Then came all the princes unto Jeremiah, and asked him: and he told them according to all these words that the king had commanded. So they left off speaking with him; for the matter was not perceived."},"BSB":{"text":"When all the officials came to Jeremiah and questioned him, he relayed to them the exact words the king had commanded him to say. So they said no more to him, for no one had overheard the conversation."},"TANAKH":{"text":"Then came all the princes unto Jeremiah, and asked him; and he told them according to all these words that the king had commanded. So they left off speaking with him; for the matter was not reported."},"HEBREW":{"text":"וַיָּבֹ֨אוּ כָל־הַשָּׂרִ֤ים אֶֽל־יִרְמְיָ֙הוּ֙ וַיִּשְׁאֲל֣וּ אֹת֔וֹ וַיַּגֵּ֤ד לָהֶם֙ כְּכָל־הַדְּבָרִ֣ים הָאֵ֔לֶּה אֲשֶׁ֥ר צִוָּ֖ה הַמֶּ֑לֶךְ וַיַּחֲרִ֣שׁוּ מִמֶּ֔נּוּ כִּ֥י לֹֽא־נִשְׁמַ֖ע הַדָּבָֽר׃"}},"definableWords":["king","one"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship"]},"28":{"text":"So Jeremiah abode in the court of the prison until the day that Jerusalem was taken: and he was there when Jerusalem was taken.","ref":"Jeremiah 38:28","synthesized":"And Jeremiah remained in the courtyard of the guard until the day Jerusalem was captured.","sources":{"KJV":{"text":"So Jeremiah abode in the court of the prison until the day that Jerusalem was taken: and he was there when Jerusalem was taken."},"BSB":{"text":"And Jeremiah remained in the courtyard of the guard until the day Jerusalem was captured."},"TANAKH":{"text":"So Jeremiah abode in the court of the guard until the day that Jerusalem was taken. And it came to pass, when Jerusalem was taken--"},"HEBREW":{"text":"וַיֵּ֤שֶׁב יִרְמְיָ֙הוּ֙ בַּחֲצַ֣ר הַמַּטָּרָ֔ה עַד־י֖וֹם אֲשֶׁר־נִלְכְּדָ֣ה יְרוּשָׁלָ֑͏ִם וְהָיָ֕ה כַּאֲשֶׁ֥ר נִלְכְּדָ֖ה יְרוּשָׁלָֽ͏ִם׃"}},"definableWords":["day","Jerusalem"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Jerusalem"]}}},"39":{"chapter":"39","title":"THE FALL OF JERUSALEM","verses":{"1":{"text":"In the ninth year of Zedekiah king of Judah, in the tenth month, came Nebuchadrezzar king of Babylon and all his army against Jerusalem, and they besieged it.","ref":"Jeremiah 39:1","synthesized":"In the ninth year of Zedekiah king of Judah, in the tenth month, Nebuchadnezzar king of Babylon marched against Jerusalem with his entire army and laid siege to the city.","sources":{"KJV":{"text":"In the ninth year of Zedekiah king of Judah, in the tenth month, came Nebuchadrezzar king of Babylon and all his army against Jerusalem, and they besieged it."},"BSB":{"text":"In the ninth year of Zedekiah king of Judah, in the tenth month, Nebuchadnezzar king of Babylon marched against Jerusalem with his entire army and laid siege to the city."},"TANAKH":{"text":"in the ninth year of Zedekiah king of Judah, in the tenth month, came Nebuchadrezzar king of Babylon and all his army against Jerusalem, and besieged it;"},"HEBREW":{"text":"בַּשָּׁנָ֣ה הַ֠תְּשִׁעִית לְצִדְקִיָּ֨הוּ מֶלֶךְ־יְהוּדָ֜ה בַּחֹ֣דֶשׁ הָעֲשִׂרִ֗י בָּ֠א נְבוּכַדְרֶאצַּ֨ר מֶֽלֶךְ־בָּבֶ֤ל וְכָל־חֵילוֹ֙ אֶל־יְר֣וּשָׁלִַ֔ם וַיָּצֻ֖רוּ עָלֶֽיהָ׃"}},"definableWords":["year","king","Judah","King","Babylon","Jerusalem"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon","Jerusalem"],"themesInVerse":["kingship"]},"2":{"text":"And in the eleventh year of Zedekiah, in the fourth month, the ninth day of the month, the city was broken up.","ref":"Jeremiah 39:2","synthesized":"And on the ninth day of the fourth month of Zedekiah’s eleventh year, the city was breached.","sources":{"KJV":{"text":"And in the eleventh year of Zedekiah, in the fourth month, the ninth day of the month, the city was broken up."},"BSB":{"text":"And on the ninth day of the fourth month of Zedekiah’s eleventh year, the city was breached."},"TANAKH":{"text":"in the eleventh year of Zedekiah, in the fourth month, the ninth day of the month, a breach was made in the city--"},"HEBREW":{"text":"בְּעַשְׁתֵּֽי־עֶשְׂרֵ֤ה שָׁנָה֙ לְצִדְקִיָּ֔הוּ בַּחֹ֥דֶשׁ הָרְבִיעִ֖י בְּתִשְׁעָ֣ה לַחֹ֑דֶשׁ הָבְקְעָ֖ה הָעִֽיר׃"}},"definableWords":["day","year"],"peopleInVerse":[]},"3":{"text":"And all the princes of the king of Babylon came in, and sat in the middle gate, even Nergalsharezer, Samgarnebo, Sarsechim, Rabsaris, Nergalsharezer, Rabmag, with all the residue of the princes of the king of Babylon.","ref":"Jeremiah 39:3","synthesized":"Then all the officials of the king of Babylon entered and sat in the Middle Gate: Nergal-sharezer of Samgar, Nebo-sarsekim the Rabsaris, Nergal-sharezer the Rabmag, and all the rest of the officials of the king of Babylon.","sources":{"KJV":{"text":"And all the princes of the king of Babylon came in, and sat in the middle gate, even Nergalsharezer, Samgarnebo, Sarsechim, Rabsaris, Nergalsharezer, Rabmag, with all the residue of the princes of the king of Babylon."},"BSB":{"text":"Then all the officials of the king of Babylon entered and sat in the Middle Gate: Nergal-sharezer of Samgar, Nebo-sarsekim the Rabsaris, Nergal-sharezer the Rabmag, and all the rest of the officials of the king of Babylon."},"TANAKH":{"text":"that all the princes of the king of Babylon came in, and sat in the middle gate, even Nergal-sarezer, Samgar-nebo, Sarsechim Rab-saris, Nergal-sarezer Rab-mag, with all the residue of the princes of the king of Babylon."},"HEBREW":{"text":"וַיָּבֹ֗אוּ כֹּ֚ל שָׂרֵ֣י מֶֽלֶךְ־בָּבֶ֔ל וַיֵּשְׁב֖וּ בְּשַׁ֣עַר הַתָּ֑וֶךְ נֵרְגַ֣ל שַׂר־אֶ֠צֶר סַֽמְגַּר־נְב֞וּ שַׂר־סְכִ֣ים רַב־סָרִ֗יס נֵרְגַ֤ל שַׂר־אֶ֙צֶר֙ רַב־מָ֔ג וְכָל־שְׁאֵרִ֔ית שָׂרֵ֖י מֶ֥לֶךְ בָּבֶֽל׃"}},"definableWords":["king","Babylon","rest","King"],"peopleInVerse":[],"placesInVerse":["Babylon","Mount Nebo"],"themesInVerse":["kingship","peace","sabbath_rest"]},"4":{"text":"And it came to pass, that when Zedekiah the king of Judah saw them, and all the men of war, then they fled, and went forth out of the city by night, by the way of the king’s garden, by the gate betwixt the two walls: and he went out the way of the plain.","ref":"Jeremiah 39:4","synthesized":"When Zedekiah king of Judah and all the soldiers saw them, they fled. They left the city at night by way of the king’s garden, through the gate between the two walls, and they went out along the route to the Arabah.","sources":{"KJV":{"text":"And it came to pass, that when Zedekiah the king of Judah saw them, and all the men of war, then they fled, and went forth out of the city by night, by the way of the king’s garden, by the gate betwixt the two walls: and he went out the way of the plain."},"BSB":{"text":"When Zedekiah king of Judah and all the soldiers saw them, they fled. They left the city at night by way of the king’s garden, through the gate between the two walls, and they went out along the route to the Arabah."},"TANAKH":{"text":"And it came to pass, that when Zedekiah the king of Judah and all the men of war saw them, then they fled, and went forth out of the city by night, by the way of the king's garden, by the gate betwixt the two walls; and he went out the way of the Arabah."},"HEBREW":{"text":"וַיְהִ֡י כַּאֲשֶׁ֣ר רָ֠אָם צִדְקִיָּ֨הוּ מֶֽלֶךְ־יְהוּדָ֜ה וְכֹ֣ל ׀ אַנְשֵׁ֣י הַמִּלְחָמָ֗ה וַֽ֠יִּבְרְחוּ וַיֵּצְא֨וּ לַ֤יְלָה מִן־הָעִיר֙ דֶּ֚רֶךְ גַּ֣ן הַמֶּ֔לֶךְ בְּשַׁ֖עַר בֵּ֣ין הַחֹמֹתָ֑יִם וַיֵּצֵ֖א דֶּ֥רֶךְ הָעֲרָבָֽה׃"}},"definableWords":["king","Judah","saw","night","way","King","garden"],"peopleInVerse":[],"themesInVerse":["kingship"]},"5":{"text":"But the Chaldeans’ army pursued after them, and overtook Zedekiah in the plains of Jericho: and when they had taken him, they brought him up to Nebuchadnezzar king of Babylon to Riblah in the land of Hamath, where he gave judgment upon him.","ref":"Jeremiah 39:5","synthesized":"But the army of the Chaldeans pursued them and overtook Zedekiah in the plains of Jericho. They seized him and brought him up to Nebuchadnezzar king of Babylon at Riblah in the land of Hamath, where he pronounced judgment on him.","sources":{"KJV":{"text":"But the Chaldeans’ army pursued after them, and overtook Zedekiah in the plains of Jericho: and when they had taken him, they brought him up to Nebuchadnezzar king of Babylon to Riblah in the land of Hamath, where he gave judgment upon him."},"BSB":{"text":"But the army of the Chaldeans pursued them and overtook Zedekiah in the plains of Jericho. They seized him and brought him up to Nebuchadnezzar king of Babylon at Riblah in the land of Hamath, where he pronounced judgment on him."},"TANAKH":{"text":"But the army of the Chaldeans pursued after them, and overtook Zedekiah in the plains of Jericho; and when they had taken him, they brought him up to Nebuchadrezzar king of Babylon to Riblah in the land of Hamath, and he gave judgment upon him."},"HEBREW":{"text":"וַיִּרְדְּפ֨וּ חֵיל־כַּשְׂדִּ֜ים אַחֲרֵיהֶ֗ם וַיַּשִּׂ֣גוּ אֶת־צִדְקִיָּהוּ֮ בְּעַֽרְב֣וֹת יְרֵחוֹ֒ וַיִּקְח֣וּ אֹת֗וֹ וַֽ֠יַּעֲלֻהוּ אֶל־נְבוּכַדְרֶאצַּ֧ר מֶֽלֶךְ־בָּבֶ֛ל רִבְלָ֖תָה בְּאֶ֣רֶץ חֲמָ֑ת וַיְדַבֵּ֥ר אִתּ֖וֹ מִשְׁפָּטִֽים׃"}},"definableWords":["king","Babylon","land","judgment"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Jericho","Babylon"],"themesInVerse":["judgment","kingship","land_promise"]},"6":{"text":"Then the king of Babylon slew the sons of Zedekiah in Riblah before his eyes: also the king of Babylon slew all the nobles of Judah.","ref":"Jeremiah 39:6","synthesized":"There at Riblah the king of Babylon slaughtered the sons of Zedekiah before his eyes, and he also killed all the nobles of Judah.","sources":{"KJV":{"text":"Then the king of Babylon slew the sons of Zedekiah in Riblah before his eyes: also the king of Babylon slew all the nobles of Judah."},"BSB":{"text":"There at Riblah the king of Babylon slaughtered the sons of Zedekiah before his eyes, and he also killed all the nobles of Judah."},"TANAKH":{"text":"Then the king of Babylon slew the sons of Zedekiah in Riblah before his eyes; also the king of Babylon slew all the nobles of Judah."},"HEBREW":{"text":"וַיִּשְׁחַט֩ מֶ֨לֶךְ בָּבֶ֜ל אֶת־בְּנֵ֧י צִדְקִיָּ֛הוּ בְּרִבְלָ֖ה לְעֵינָ֑יו וְאֵת֙ כָּל־חֹרֵ֣י יְהוּדָ֔ה שָׁחַ֖ט מֶ֥לֶךְ בָּבֶֽל׃"}},"definableWords":["king","Babylon","sons","Judah"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"7":{"text":"Moreover he put out Zedekiah’s eyes, and bound him with chains, to carry him to Babylon.","ref":"Jeremiah 39:7","synthesized":"Then he put out Zedekiah’s eyes and bound him with bronze chains to take him to Babylon.","sources":{"KJV":{"text":"Moreover he put out Zedekiah’s eyes, and bound him with chains, to carry him to Babylon."},"BSB":{"text":"Then he put out Zedekiah’s eyes and bound him with bronze chains to take him to Babylon."},"TANAKH":{"text":"Moreover he put out Zedekiah's eyes, and bound him in fetters, to carry him to Babylon."},"HEBREW":{"text":"וְאֶת־עֵינֵ֥י צִדְקִיָּ֖הוּ עִוֵּ֑ר וַיַּאַסְרֵ֙הוּ֙ בַּֽנְחֻשְׁתַּ֔יִם לָבִ֥יא אֹת֖וֹ בָּבֶֽלָה׃"}},"definableWords":["Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"8":{"text":"And the Chaldeans burned the king’s house, and the houses of the people, with fire, and brake down the walls of Jerusalem.","ref":"Jeremiah 39:8","synthesized":"The Chaldeans set fire to the palace of the king and to the houses of the people, and they broke down the walls of Jerusalem.","sources":{"KJV":{"text":"And the Chaldeans burned the king’s house, and the houses of the people, with fire, and brake down the walls of Jerusalem."},"BSB":{"text":"The Chaldeans set fire to the palace of the king and to the houses of the people, and they broke down the walls of Jerusalem."},"TANAKH":{"text":"And the Chaldeans burned the king's house, and the house of the people, with fire, and broke down the walls of Jerusalem."},"HEBREW":{"text":"וְאֶת־בֵּ֤ית הַמֶּ֙לֶךְ֙ וְאֶת־בֵּ֣ית הָעָ֔ם שָׂרְפ֥וּ הַכַּשְׂדִּ֖ים בָּאֵ֑שׁ וְאֶת־חֹמ֥וֹת יְרוּשָׁלַ֖͏ִם נָתָֽצוּ׃"}},"definableWords":["king","people","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["kingship"]},"9":{"text":"Then Nebuzaradan the captain of the guard carried away captive into Babylon the remnant of the people that remained in the city, and those that fell away, that fell to him, with the rest of the people that remained.","ref":"Jeremiah 39:9","synthesized":"Then Nebuzaradan captain of the guard carried away to Babylon the remnant of the people who had remained in the city, along with the deserters who had defected to him.","sources":{"KJV":{"text":"Then Nebuzaradan the captain of the guard carried away captive into Babylon the remnant of the people that remained in the city, and those that fell away, that fell to him, with the rest of the people that remained."},"BSB":{"text":"Then Nebuzaradan captain of the guard carried away to Babylon the remnant of the people who had remained in the city, along with the deserters who had defected to him."},"TANAKH":{"text":"Then Nebuzaradan the captain of the guard carried away captive into Babylon the remnant of the people that remained in the city, the deserters also, that fell away to him, with the rest of the people that remained."},"HEBREW":{"text":"וְאֵת֩ יֶ֨תֶר הָעָ֜ם הַנִּשְׁאָרִ֣ים בָּעִ֗יר וְאֶת־הַנֹּֽפְלִים֙ אֲשֶׁ֣ר נָפְל֣וּ עָלָ֔יו וְאֵ֛ת יֶ֥תֶר הָעָ֖ם הַנִּשְׁאָרִ֑ים הֶגְלָ֛ה נְבֽוּזַר־אֲדָ֥ן רַב־טַבָּחִ֖ים בָּבֶֽל׃"}},"definableWords":["Babylon","remnant","people"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["exile_return"]},"10":{"text":"But Nebuzaradan the captain of the guard left of the poor of the people, which had nothing, in the land of Judah, and gave them vineyards and fields at the same time.","ref":"Jeremiah 39:10","synthesized":"But Nebuzaradan left behind in the land of Judah some of the poor people who had no property, and at that time he gave them vineyards and fields.","sources":{"KJV":{"text":"But Nebuzaradan the captain of the guard left of the poor of the people, which had nothing, in the land of Judah, and gave them vineyards and fields at the same time."},"BSB":{"text":"But Nebuzaradan left behind in the land of Judah some of the poor people who had no property, and at that time he gave them vineyards and fields."},"TANAKH":{"text":"But Nebuzaradan the captain of the guard left of the poor of the people, that had nothing, in the land of Judah, and gave them vineyards and fields in that day."},"HEBREW":{"text":"וּמִן־הָעָ֣ם הַדַּלִּ֗ים אֲשֶׁ֤ר אֵין־לָהֶם֙ מְא֔וּמָה הִשְׁאִ֛יר נְבוּזַרְאֲדָ֥ן רַב־טַבָּחִ֖ים בְּאֶ֣רֶץ יְהוּדָ֑ה וַיִּתֵּ֥ן לָהֶ֛ם כְּרָמִ֥ים וִֽיגֵבִ֖ים בַּיּ֥וֹם הַהֽוּא׃"}},"definableWords":["land","Judah","people"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"11":{"text":"Now Nebuchadrezzar king of Babylon gave charge concerning Jeremiah to Nebuzaradan the captain of the guard, saying,","ref":"Jeremiah 39:11","synthesized":"Now Nebuchadnezzar king of Babylon had given orders about Jeremiah through Nebuzaradan captain of the guard, saying,","sources":{"KJV":{"text":"Now Nebuchadrezzar king of Babylon gave charge concerning Jeremiah to Nebuzaradan the captain of the guard, saying,"},"BSB":{"text":"Now Nebuchadnezzar king of Babylon had given orders about Jeremiah through Nebuzaradan captain of the guard, saying,"},"TANAKH":{"text":"Now Nebuchadrezzar king of Babylon gave charge concerning Jeremiah to Nebuzaradan the captain of the guard, saying:"},"HEBREW":{"text":"וַיְצַ֛ו נְבוּכַדְרֶאצַּ֥ר מֶֽלֶךְ־בָּבֶ֖ל עַֽל־יִרְמְיָ֑הוּ בְּיַ֛ד נְבוּזַרְאֲדָ֥ן רַב־טַבָּחִ֖ים לֵאמֹֽר׃"}},"definableWords":["king","Babylon"],"peopleInVerse":["Nebuchadnezzar","Jeremiah"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"12":{"text":"Take him, and look well to him, and do him no harm; but do unto him even as he shall say unto thee.","ref":"Jeremiah 39:12","synthesized":"“Take him, look after him, and do not let any harm come to him; do for him whatever he says.”","sources":{"KJV":{"text":"Take him, and look well to him, and do him no harm; but do unto him even as he shall say unto thee."},"BSB":{"text":"“Take him, look after him, and do not let any harm come to him; do for him whatever he says.”"},"TANAKH":{"text":"'Take him, and look well to him, and do him no harm; but do unto him even as he shall say unto thee.'"},"HEBREW":{"text":"קָחֶ֗נּוּ וְעֵינֶ֙יךָ֙ שִׂ֣ים עָלָ֔יו וְאַל־תַּ֥עַשׂ ל֖וֹ מְא֣וּמָה רָּ֑ע כִּ֗י אם כַּֽאֲשֶׁר֙ יְדַבֵּ֣ר אֵלֶ֔יךָ כֵּ֖ן עֲשֵׂ֥ה עִמּֽוֹ׃"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"So Nebuzaradan the captain of the guard sent, and Nebushasban, Rabsaris, and Nergalsharezer, Rabmag, and all the king of Babylon’s princes;","ref":"Jeremiah 39:13","synthesized":"So Nebuzaradan captain of the guard, Nebushazban the Rabsaris, Nergal-sharezer the Rabmag, and all the captains of the king of Babylon","sources":{"KJV":{"text":"So Nebuzaradan the captain of the guard sent, and Nebushasban, Rabsaris, and Nergalsharezer, Rabmag, and all the king of Babylon’s princes;"},"BSB":{"text":"So Nebuzaradan captain of the guard, Nebushazban the Rabsaris, Nergal-sharezer the Rabmag, and all the captains of the king of Babylon"},"TANAKH":{"text":"So Nebuzaradan the captain of the guard sent, and Nebushazban Rab-saris, and Nergal-sarezer Rab-mag, and all the chief officers of the king of Babylon;"},"HEBREW":{"text":"וַיִּשְׁלַ֞ח נְבֽוּזַרְאֲדָ֣ן רַב־טַבָּחִ֗ים וּנְבֽוּשַׁזְבָּן֙ רַב־סָרִ֔יס וְנֵרְגַ֥ל שַׂר־אֶ֖צֶר רַב־מָ֑ג וְכֹ֖ל רַבֵּ֥י מֶֽלֶךְ־בָּבֶֽל׃"}},"definableWords":["king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"14":{"text":"Even they sent, and took Jeremiah out of the court of the prison, and committed him unto Gedaliah the son of Ahikam the son of Shaphan, that he should carry him home: so he dwelt among the people.","ref":"Jeremiah 39:14","synthesized":"had Jeremiah brought from the courtyard of the guard, and they turned him over to Gedaliah son of Ahikam, the son of Shaphan, to take him home. So Jeremiah remained among his own people.","sources":{"KJV":{"text":"Even they sent, and took Jeremiah out of the court of the prison, and committed him unto Gedaliah the son of Ahikam the son of Shaphan, that he should carry him home: so he dwelt among the people."},"BSB":{"text":"had Jeremiah brought from the courtyard of the guard, and they turned him over to Gedaliah son of Ahikam, the son of Shaphan, to take him home. So Jeremiah remained among his own people."},"TANAKH":{"text":"they sent, and took Jeremiah out of the court of the guard, and committed him unto Gedaliah the son of Ahikam, the son of Shaphan, that he should carry him home; so he dwelt among the people."},"HEBREW":{"text":"וַיִּשְׁלְחוּ֩ וַיִּקְח֨וּ אֶֽת־יִרְמְיָ֜הוּ מֵחֲצַ֣ר הַמַּטָּרָ֗ה וַיִּתְּנ֤וּ אֹתוֹ֙ אֶל־גְּדַלְיָ֙הוּ֙ בֶּן־אֲחִיקָ֣ם בֶּן־שָׁפָ֔ן לְהוֹצִאֵ֖הוּ אֶל־הַבָּ֑יִת וַיֵּ֖שֶׁב בְּת֥וֹךְ הָעָֽם׃"}},"definableWords":["son","Son","people"],"peopleInVerse":["Jeremiah"]},"15":{"text":"Now the word of the LORD came unto Jeremiah, while he was shut up in the court of the prison, saying,","ref":"Jeremiah 39:15","synthesized":"And while Jeremiah had been confined in the courtyard of the guard, the word of the LORD had come to him:","sources":{"KJV":{"text":"Now the word of the LORD came unto Jeremiah, while he was shut up in the court of the prison, saying,"},"BSB":{"text":"And while Jeremiah had been confined in the courtyard of the guard, the word of the LORD had come to him:"},"TANAKH":{"text":"Now the word of HaShem came unto Jeremiah, while he was shut up in the court of the guard, saying:"},"HEBREW":{"text":"וְאֶֽל־יִרְמְיָ֖הוּ הָיָ֣ה דְבַר־יְהוָ֑ה בִּֽהְיֹת֣וֹ עָצ֔וּר בַּחֲצַ֥ר הַמַּטָּרָ֖ה לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"16":{"text":"Go and speak to Ebedmelech the Ethiopian, saying, Thus saith the LORD of hosts, the God of Israel; Behold, I will bring my words upon this city for evil, and not for good; and they shall be accomplished in that day before thee.","ref":"Jeremiah 39:16","synthesized":"“Go and tell Ebed-melech the Cushite that this is what the LORD of Hosts, the God of Israel, says: ‘I am about to fulfill My words against this city for harm and not for good, and on that day they will be fulfilled before your eyes.","sources":{"KJV":{"text":"Go and speak to Ebedmelech the Ethiopian, saying, Thus saith the LORD of hosts, the God of Israel; Behold, I will bring my words upon this city for evil, and not for good; and they shall be accomplished in that day before thee."},"BSB":{"text":"“Go and tell Ebed-melech the Cushite that this is what the LORD of Hosts, the God of Israel, says: ‘I am about to fulfill My words against this city for harm and not for good, and on that day they will be fulfilled before your eyes."},"TANAKH":{"text":"'Go, and speak to Ebed-melech the Ethiopian, saying: Thus saith HaShem of hosts, the G-d of Israel: Behold, I will bring My words upon this city for evil, and not for good; and they shall be accomplished before thee in that day."},"HEBREW":{"text":"הָל֣וֹךְ וְאָמַרְתָּ֡ לְעֶבֶד־מֶ֨לֶךְ הַכּוּשִׁ֜י לֵאמֹ֗ר כֹּֽה־אָמַ֞ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל הִנְנִי֩ מבי מֵבִ֨יא אֶת־דְּבָרַ֜י אֶל־הָעִ֥יר הַזֹּ֛את לְרָעָ֖ה וְלֹ֣א לְטוֹבָ֑ה וְהָי֥וּ לְפָנֶ֖יךָ בַּיּ֥וֹם הַהֽוּא׃"}},"definableWords":["LORD","God","Israel","good","day"],"peopleInVerse":[]},"17":{"text":"But I will deliver thee in that day, saith the LORD: and thou shalt not be given into the hand of the men of whom thou art afraid.","ref":"Jeremiah 39:17","synthesized":"But I will deliver you on that day, declares the LORD, and you will not be delivered into the hands of the men whom you fear.","sources":{"KJV":{"text":"But I will deliver thee in that day, saith the LORD: and thou shalt not be given into the hand of the men of whom thou art afraid."},"BSB":{"text":"But I will deliver you on that day, declares the LORD, and you will not be delivered into the hands of the men whom you fear."},"TANAKH":{"text":"But I will deliver thee in that day, saith HaShem; and thou shalt not be given into the hand of the men of whom thou art afraid."},"HEBREW":{"text":"וְהִצַּלְתִּ֥יךָ בַיּוֹם־הַה֖וּא נְאֻם־יְהוָ֑ה וְלֹ֤א תִנָּתֵן֙ בְּיַ֣ד הָֽאֲנָשִׁ֔ים אֲשֶׁר־אַתָּ֥ה יָג֖וֹר מִפְּנֵיהֶֽם׃"}},"definableWords":["deliver","day","LORD","men","fear"],"peopleInVerse":[],"themesInVerse":["fear_of_lord","redemption","salvation"]},"18":{"text":"For I will surely deliver thee, and thou shalt not fall by the sword, but thy life shall be for a prey unto thee: because thou hast put thy trust in me, saith the LORD.","ref":"Jeremiah 39:18","synthesized":"For I will surely rescue you so that you do not fall by the sword. Because you have trusted in Me, you will escape with your life like a spoil of war, declares the LORD.’”","sources":{"KJV":{"text":"For I will surely deliver thee, and thou shalt not fall by the sword, but thy life shall be for a prey unto thee: because thou hast put thy trust in me, saith the LORD."},"BSB":{"text":"For I will surely rescue you so that you do not fall by the sword. Because you have trusted in Me, you will escape with your life like a spoil of war, declares the LORD.’”"},"TANAKH":{"text":"For I will surely deliver thee, and thou shalt not fall by the sword, but thy life shall be for a prey unto thee; because thou hast put thy trust in Me, saith HaShem.'"},"HEBREW":{"text":"כִּ֤י מַלֵּט֙ אֲמַלֶּטְךָ֔ וּבַחֶ֖רֶב לֹ֣א תִפֹּ֑ל וְהָיְתָ֨ה לְךָ֤ נַפְשְׁךָ֙ לְשָׁלָ֔ל כִּֽי־בָטַ֥חְתָּ בִּ֖י נְאֻם־יְהוָֽה׃"}},"definableWords":["life","LORD"],"peopleInVerse":[],"themesInVerse":["fall_sin","salvation"]}}},"40":{"chapter":"40","title":"GEDALIAH MADE GOVERNOR","verses":{"1":{"text":"The word that came to Jeremiah from the LORD, after that Nebuzaradan the captain of the guard had let him go from Ramah, when he had taken him being bound in chains among all that were carried away captive of Jerusalem and Judah, which were carried away captive unto Babylon.","ref":"Jeremiah 40:1","synthesized":"This is the word that came to Jeremiah from the LORD after Nebuzaradan captain of the guard had released him at Ramah, having found him bound in chains among all the captives of Jerusalem and Judah who were being exiled to Babylon.","sources":{"KJV":{"text":"The word that came to Jeremiah from the LORD, after that Nebuzaradan the captain of the guard had let him go from Ramah, when he had taken him being bound in chains among all that were carried away captive of Jerusalem and Judah, which were carried away captive unto Babylon."},"BSB":{"text":"This is the word that came to Jeremiah from the LORD after Nebuzaradan captain of the guard had released him at Ramah, having found him bound in chains among all the captives of Jerusalem and Judah who were being exiled to Babylon."},"TANAKH":{"text":"The word which came to Jeremiah from HaShem, after that Nebuzaradan the captain of the guard had let him go from Ramah, when he had taken him being bound in chains among all the captives of Jerusalem and Judah, that were carried away captive unto Babylon."},"HEBREW":{"text":"הַדָּבָ֞ר אֲשֶׁר־הָיָ֤ה אֶֽל־יִרְמְיָ֙הוּ֙ מֵאֵ֣ת יְהוָ֔ה אַחַ֣ר ׀ שַׁלַּ֣ח אֹת֗וֹ נְבוּזַרְאֲדָ֛ן רַב־טַבָּחִ֖ים מִן־הָֽרָמָ֑ה בְּקַחְתּ֣וֹ אֹת֗וֹ וְהֽוּא־אָס֤וּר בָּֽאזִקִּים֙ בְּת֨וֹךְ כָּל־גָּל֤וּת יְרוּשָׁלִַ֙ם֙ וִֽיהוּדָ֔ה הַמֻּגְלִ֖ים בָּבֶֽלָה׃"}},"definableWords":["word","LORD","Jerusalem","Judah","Babylon"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Jerusalem","Babylon"]},"2":{"text":"And the captain of the guard took Jeremiah, and said unto him, The LORD thy God hath pronounced this evil upon this place.","ref":"Jeremiah 40:2","synthesized":"The captain of the guard found Jeremiah and said to him, “The LORD your God decreed this disaster on this place,","sources":{"KJV":{"text":"And the captain of the guard took Jeremiah, and said unto him, The LORD thy God hath pronounced this evil upon this place."},"BSB":{"text":"The captain of the guard found Jeremiah and said to him, “The LORD your God decreed this disaster on this place,"},"TANAKH":{"text":"And the captain of the guard took Jeremiah, and said unto him: 'The HaShem thy G-d pronounced this evil upon this place;"},"HEBREW":{"text":"וַיִּקַּ֥ח רַב־טַבָּחִ֖ים לְיִרְמְיָ֑הוּ וַיֹּ֣אמֶר אֵלָ֔יו יְהוָ֣ה אֱלֹהֶ֗יךָ דִּבֶּר֙ אֶת־הָרָעָ֣ה הַזֹּ֔את אֶל־הַמָּק֖וֹם הַזֶּֽה׃"}},"definableWords":["LORD","God"],"peopleInVerse":["Jeremiah"]},"3":{"text":"Now the LORD hath brought it, and done according as he hath said: because ye have sinned against the LORD, and have not obeyed his voice, therefore this thing is come upon you.","ref":"Jeremiah 40:3","synthesized":"and now the LORD has fulfilled it; He has done just as He said. Because you people have sinned against the LORD and have not obeyed His voice, this thing has happened to you.","sources":{"KJV":{"text":"Now the LORD hath brought it, and done according as he hath said: because ye have sinned against the LORD, and have not obeyed his voice, therefore this thing is come upon you."},"BSB":{"text":"and now the LORD has fulfilled it; He has done just as He said. Because you people have sinned against the LORD and have not obeyed His voice, this thing has happened to you."},"TANAKH":{"text":"and HaShem hath brought it, and done according as He spoke; because ye have sinned against HaShem, and have not hearkened to His voice, therefore this thing is come upon you."},"HEBREW":{"text":"וַיָּבֵ֥א וַיַּ֛עַשׂ יְהוָ֖ה כַּאֲשֶׁ֣ר דִּבֵּ֑ר כִּֽי־חֲטָאתֶ֤ם לַֽיהוָה֙ וְלֹֽא־שְׁמַעְתֶּ֣ם בְּקוֹל֔וֹ וְהָיָ֥ה לָכֶ֖ם דבר הַדָּבָ֥ר הַזֶּֽה׃"}},"definableWords":["LORD","people","Lord","voice"],"peopleInVerse":[]},"4":{"text":"And now, behold, I loose thee this day from the chains which were upon thine hand. If it seem good unto thee to come with me into Babylon, come; and I will look well unto thee: but if it seem ill unto thee to come with me into Babylon, forbear: behold, all the land is before thee: whither it seemeth good and convenient for thee to go, thither go.","ref":"Jeremiah 40:4","synthesized":"But now, behold, I am freeing you today from the chains that were on your wrists. If it pleases you to come with me to Babylon, then come, and I will take care of you. But if it seems wrong to you to come with me to Babylon, go no farther. Look, the whole land is before you. Wherever it seems good and right to you, go there.”","sources":{"KJV":{"text":"And now, behold, I loose thee this day from the chains which were upon thine hand. If it seem good unto thee to come with me into Babylon, come; and I will look well unto thee: but if it seem ill unto thee to come with me into Babylon, forbear: behold, all the land is before thee: whither it seemeth good and convenient for thee to go, thither go."},"BSB":{"text":"But now, behold, I am freeing you today from the chains that were on your wrists. If it pleases you to come with me to Babylon, then come, and I will take care of you. But if it seems wrong to you to come with me to Babylon, go no farther. Look, the whole land is before you. Wherever it seems good and right to you, go there.”"},"TANAKH":{"text":"And now, behold, I loose thee this day from the chains which are upon thy hand. If it seem good unto thee to come with me into Babylon, come, and I will look well unto thee; but if it seem ill unto thee to come with me into Babylon, forbear; behold, all the land is before thee; whither it seemeth good and right unto thee to go, thither go.--"},"HEBREW":{"text":"וְעַתָּ֞ה הִנֵּ֧ה פִתַּחְתִּ֣יךָ הַיּ֗וֹם מִֽן־הָאזִקִּים֮ אֲשֶׁ֣ר עַל־יָדֶךָ֒ אִם־ט֨וֹב בְּעֵינֶ֜יךָ לָב֧וֹא אִתִּ֣י בָבֶ֗ל בֹּ֚א וְאָשִׂ֤ים אֶת־עֵינִי֙ עָלֶ֔יךָ וְאִם־רַ֧ע בְּעֵינֶ֛יךָ לָבֽוֹא־אִתִּ֥י בָבֶ֖ל חֲדָ֑ל רְאֵה֙ כָּל־הָאָ֣רֶץ לְפָנֶ֔יךָ אֶל־ט֨וֹב וְאֶל־הַיָּשָׁ֧ר בְּעֵינֶ֛יךָ לָלֶ֥כֶת שָׁ֖מָּה לֵֽךְ׃"}},"definableWords":["Babylon","land","good"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["land_promise"]},"5":{"text":"Now while he was not yet gone back, he said, Go back also to Gedaliah the son of Ahikam the son of Shaphan, whom the king of Babylon hath made governor over the cities of Judah, and dwell with him among the people: or go wheresoever it seemeth convenient unto thee to go. So the captain of the guard gave him victuals and a reward, and let him go.","ref":"Jeremiah 40:5","synthesized":"But before Jeremiah turned to go, Nebuzaradan added, “Return to Gedaliah son of Ahikam, the son of Shaphan, whom the king of Babylon has appointed over the cities of Judah, and stay with him among the people, or go anywhere else that seems right.” Then the captain of the guard gave him a ration and a gift and released him.","sources":{"KJV":{"text":"Now while he was not yet gone back, he said, Go back also to Gedaliah the son of Ahikam the son of Shaphan, whom the king of Babylon hath made governor over the cities of Judah, and dwell with him among the people: or go wheresoever it seemeth convenient unto thee to go. So the captain of the guard gave him victuals and a reward, and let him go."},"BSB":{"text":"But before Jeremiah turned to go, Nebuzaradan added, “Return to Gedaliah son of Ahikam, the son of Shaphan, whom the king of Babylon has appointed over the cities of Judah, and stay with him among the people, or go anywhere else that seems right.” Then the captain of the guard gave him a ration and a gift and released him."},"TANAKH":{"text":"Yet he would not go back. --Go back then to Gedaliah the son of Ahikam, the son of Shaphan, whom the king of Babylon hath made governor over the cities of Judah, and dwell with him among the people; or go wheresoever it seemeth right unto thee to go.' So the captain of the guard gave him an allowance and a present, and let him go."},"HEBREW":{"text":"וְעוֹדֶ֣נּוּ לֹֽא־יָשׁ֗וּב וְשֻׁ֡בָה אֶל־גְּדַלְיָ֣ה בֶן־אֲחִיקָ֣ם בֶּן־שָׁפָ֡ן אֲשֶׁר֩ הִפְקִ֨יד מֶֽלֶךְ־בָּבֶ֜ל בְּעָרֵ֣י יְהוּדָ֗ה וְשֵׁ֤ב אִתּוֹ֙ בְּת֣וֹךְ הָעָ֔ם א֠וֹ אֶל־כָּל־הַיָּשָׁ֧ר בְּעֵינֶ֛יךָ לָלֶ֖כֶת לֵ֑ךְ וַיִּתֶּן־ל֧וֹ רַב־טַבָּחִ֛ים אֲרֻחָ֥ה וּמַשְׂאֵ֖ת וַֽיְשַׁלְּחֵֽהוּ׃"}},"definableWords":["son","Son","king","Babylon","Judah","people","or"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Babylon"],"themesInVerse":["exile_return","kingship","second_coming"]},"6":{"text":"Then went Jeremiah unto Gedaliah the son of Ahikam to Mizpah; and dwelt with him among the people that were left in the land.","ref":"Jeremiah 40:6","synthesized":"So Jeremiah went to Gedaliah son of Ahikam at Mizpah and stayed with him among the people who were left in the land.","sources":{"KJV":{"text":"Then went Jeremiah unto Gedaliah the son of Ahikam to Mizpah; and dwelt with him among the people that were left in the land."},"BSB":{"text":"So Jeremiah went to Gedaliah son of Ahikam at Mizpah and stayed with him among the people who were left in the land."},"TANAKH":{"text":"Then went Jeremiah unto Gedaliah the son of Ahikam to Mizpah, and dwelt with him among the people that were left in the land."},"HEBREW":{"text":"וַיָּבֹ֧א יִרְמְיָ֛הוּ אֶל־גְּדַלְיָ֥ה בֶן־אֲחִיקָ֖ם הַמִּצְפָּ֑תָה וַיֵּ֤שֶׁב אִתּוֹ֙ בְּת֣וֹךְ הָעָ֔ם הַנִּשְׁאָרִ֖ים בָּאָֽרֶץ׃"}},"definableWords":["son","people","land"],"peopleInVerse":["Jeremiah"],"themesInVerse":["land_promise"]},"7":{"text":"Now when all the captains of the forces which were in the fields, even they and their men, heard that the king of Babylon had made Gedaliah the son of Ahikam governor in the land, and had committed unto him men, and women, and children, and of the poor of the land, of them that were not carried away captive to Babylon;","ref":"Jeremiah 40:7","synthesized":"When all the commanders and men of the armies in the field heard that the king of Babylon had appointed Gedaliah son of Ahikam over the land and that he had put him in charge of the men, women, and children who were the poorest of the land and had not been exiled to Babylon,","sources":{"KJV":{"text":"Now when all the captains of the forces which were in the fields, even they and their men, heard that the king of Babylon had made Gedaliah the son of Ahikam governor in the land, and had committed unto him men, and women, and children, and of the poor of the land, of them that were not carried away captive to Babylon;"},"BSB":{"text":"When all the commanders and men of the armies in the field heard that the king of Babylon had appointed Gedaliah son of Ahikam over the land and that he had put him in charge of the men, women, and children who were the poorest of the land and had not been exiled to Babylon,"},"TANAKH":{"text":"Now when all the captains of the forces that were in the fields, even they and their men, heard that the king of Babylon had made Gedaliah the son of Ahikam governor in the land, and had committed unto him men, and women, and children, and of the poorest of the land, of them that were not carried away captive to Babylon;"},"HEBREW":{"text":"וַיִּשְׁמְעוּ֩ כָל־שָׂרֵ֨י הַחֲיָלִ֜ים אֲשֶׁ֣ר בַּשָּׂדֶ֗ה הֵ֚מָּה וְאַנְשֵׁיהֶ֔ם כִּֽי־הִפְקִ֧יד מֶֽלֶךְ־בָּבֶ֛ל אֶת־גְּדַלְיָ֥הוּ בֶן־אֲחִיקָ֖ם בָּאָ֑רֶץ וְכִ֣י ׀ הִפְקִ֣יד אִתּ֗וֹ אֲנָשִׁ֤ים וְנָשִׁים֙ וָטָ֔ף וּמִדַּלַּ֣ת הָאָ֔רֶץ מֵאֲשֶׁ֥ר לֹֽא־הָגְל֖וּ בָּבֶֽלָה׃"}},"definableWords":["men","field","king","Babylon","son","land","charge","women"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship","land_promise"]},"8":{"text":"Then they came to Gedaliah to Mizpah, even Ishmael the son of Nethaniah, and Johanan and Jonathan the sons of Kareah, and Seraiah the son of Tanhumeth, and the sons of Ephai the Netophathite, and Jezaniah the son of a Maachathite, they and their men.","ref":"Jeremiah 40:8","synthesized":"they came to Gedaliah at Mizpah—Ishmael son of Nethaniah, Johanan and Jonathan the sons of Kareah, Seraiah son of Tanhumeth, the sons of Ephai the Netophathite, and Jezaniah son of the Maacathite—they and their men.","sources":{"KJV":{"text":"Then they came to Gedaliah to Mizpah, even Ishmael the son of Nethaniah, and Johanan and Jonathan the sons of Kareah, and Seraiah the son of Tanhumeth, and the sons of Ephai the Netophathite, and Jezaniah the son of a Maachathite, they and their men."},"BSB":{"text":"they came to Gedaliah at Mizpah—Ishmael son of Nethaniah, Johanan and Jonathan the sons of Kareah, Seraiah son of Tanhumeth, the sons of Ephai the Netophathite, and Jezaniah son of the Maacathite—they and their men."},"TANAKH":{"text":"then they came to Gedaliah to Mizpah, even Ishmael the son of Nethaniah, and Johanan and Jonathan the sons of Kareah, and Seraiah the son of Tanhumeth, and the sons of Ephai the Netophathite, and Jezaniah the son of the Maacathite, they and their men."},"HEBREW":{"text":"וַיָּבֹ֥אוּ אֶל־גְּדַלְיָ֖ה הַמִּצְפָּ֑תָה וְיִשְׁמָעֵ֣אל בֶּן־נְתַנְיָ֡הוּ וְיוֹחָנָ֣ן וְיוֹנָתָ֣ן בְּנֵֽי־קָ֠רֵחַ וּשְׂרָיָ֨ה בֶן־תַּנְחֻ֜מֶת וּבְנֵ֣י ׀ עופי עֵיפַ֣י הַנְּטֹפָתִ֗י וִֽיזַנְיָ֙הוּ֙ בֶּן־הַמַּ֣עֲכָתִ֔י הֵ֖מָּה וְאַנְשֵׁיהֶֽם׃"}},"definableWords":["Ishmael","son","sons","Son","men"],"peopleInVerse":["Ishmael","Jonathan"]},"9":{"text":"And Gedaliah the son of Ahikam the son of Shaphan sware unto them and to their men, saying, Fear not to serve the Chaldeans: dwell in the land, and serve the king of Babylon, and it shall be well with you.","ref":"Jeremiah 40:9","synthesized":"Gedaliah son of Ahikam, the son of Shaphan, swore an oath to them and their men, assuring them, “Do not be afraid to serve the Chaldeans. Live in the land and serve the king of Babylon, and it will go well with you.","sources":{"KJV":{"text":"And Gedaliah the son of Ahikam the son of Shaphan sware unto them and to their men, saying, Fear not to serve the Chaldeans: dwell in the land, and serve the king of Babylon, and it shall be well with you."},"BSB":{"text":"Gedaliah son of Ahikam, the son of Shaphan, swore an oath to them and their men, assuring them, “Do not be afraid to serve the Chaldeans. Live in the land and serve the king of Babylon, and it will go well with you."},"TANAKH":{"text":"And Gedaliah the son of Ahikam the son of Shaphan swore unto them and to their men, saying: 'Fear not to serve the Chaldeans; dwell in the land, and serve the king of Babylon, and it shall be well with you."},"HEBREW":{"text":"וַיִּשָּׁבַ֨ע לָהֶ֜ם גְּדַלְיָ֨הוּ בֶן־אֲחִיקָ֤ם בֶּן־שָׁפָן֙ וּלְאַנְשֵׁיהֶ֣ם לֵאמֹ֔ר אַל־תִּֽירְא֖וּ מֵעֲב֣וֹד הַכַּשְׂדִּ֑ים שְׁב֣וּ בָאָ֗רֶץ וְעִבְד֛וּ אֶת־מֶ֥לֶךְ בָּבֶ֖ל וְיִיטַ֥ב לָכֶֽם׃"}},"definableWords":["son","Son","men","live","land","king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["bread_water_life","covenant","kingship","land_promise"]},"10":{"text":"As for me, behold, I will dwell at Mizpah, to serve the Chaldeans, which will come unto us: but ye, gather ye wine, and summer fruits, and oil, and put them in your vessels, and dwell in your cities that ye have taken.","ref":"Jeremiah 40:10","synthesized":"As for me, I will stay in Mizpah to represent you before the Chaldeans who come to us. As for you, gather wine grapes, summer fruit, and oil, place them in your storage jars, and live in the cities you have taken.”","sources":{"KJV":{"text":"As for me, behold, I will dwell at Mizpah, to serve the Chaldeans, which will come unto us: but ye, gather ye wine, and summer fruits, and oil, and put them in your vessels, and dwell in your cities that ye have taken."},"BSB":{"text":"As for me, I will stay in Mizpah to represent you before the Chaldeans who come to us. As for you, gather wine grapes, summer fruit, and oil, place them in your storage jars, and live in the cities you have taken.”"},"TANAKH":{"text":"As for me, behold, I will dwell at Mizpah, to stand before the Chaldeans that may come unto us; but ye, gather ye wine and summer fruits and oil, and put them in your vessels, and dwell in your cities that ye have taken.'"},"HEBREW":{"text":"וַאֲנִ֗י הִנְנִ֤י יֹשֵׁב֙ בַּמִּצְפָּ֔ה לַֽעֲמֹד֙ לִפְנֵ֣י הַכַּשְׂדִּ֔ים אֲשֶׁ֥ר יָבֹ֖אוּ אֵלֵ֑ינוּ וְאַתֶּ֡ם אִסְפוּ֩ יַ֨יִן וְקַ֜יִץ וְשֶׁ֗מֶן וְשִׂ֙מוּ֙ בִּכְלֵיכֶ֔ם וּשְׁב֖וּ בְּעָרֵיכֶ֥ם אֲשֶׁר־תְּפַשְׂתֶּֽם׃"}},"definableWords":["live"],"peopleInVerse":[],"themesInVerse":["vine_branches"]},"11":{"text":"Likewise when all the Jews that were in Moab, and among the Ammonites, and in Edom, and that were in all the countries, heard that the king of Babylon had left a remnant of Judah, and that he had set over them Gedaliah the son of Ahikam the son of Shaphan;","ref":"Jeremiah 40:11","synthesized":"When all the Jews in Moab, Ammon, Edom, and all the other lands heard that the king of Babylon had left a remnant in Judah and had appointed Gedaliah son of Ahikam, the son of Shaphan, over them,","sources":{"KJV":{"text":"Likewise when all the Jews that were in Moab, and among the Ammonites, and in Edom, and that were in all the countries, heard that the king of Babylon had left a remnant of Judah, and that he had set over them Gedaliah the son of Ahikam the son of Shaphan;"},"BSB":{"text":"When all the Jews in Moab, Ammon, Edom, and all the other lands heard that the king of Babylon had left a remnant in Judah and had appointed Gedaliah son of Ahikam, the son of Shaphan, over them,"},"TANAKH":{"text":"Likewise when all the Jews that were in Moab, and among the children of Ammon, and in Edom, and that were in all the countries, heard that the king of Babylon had left a remnant of Judah, and that he had set over them Gedaliah the son of Ahikam, the son of Shaphan;"},"HEBREW":{"text":"וְגַ֣ם כָּֽל־הַיְּהוּדִ֡ים אֲשֶׁר־בְּמוֹאָ֣ב ׀ וּבִבְנֵֽי־עַמּ֨וֹן וּבֶאֱד֜וֹם וַאֲשֶׁ֤ר בְּכָל־הָֽאֲרָצוֹת֙ שָֽׁמְע֔וּ כִּֽי־נָתַ֧ן מֶֽלֶךְ־בָּבֶ֛ל שְׁאֵרִ֖ית לִֽיהוּדָ֑ה וְכִי֙ הִפְקִ֣יד עֲלֵיהֶ֔ם אֶת־גְּדַלְיָ֖הוּ בֶּן־אֲחִיקָ֥ם בֶּן־שָׁפָֽן׃"}},"definableWords":["Edom","king","Babylon","remnant","Judah","son","Son"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["exile_return","kingship"]},"12":{"text":"Even all the Jews returned out of all places whither they were driven, and came to the land of Judah, to Gedaliah, unto Mizpah, and gathered wine and summer fruits very much.","ref":"Jeremiah 40:12","synthesized":"they all returned from all the places to which they had been banished and came to the land of Judah, to Gedaliah at Mizpah. And they gathered an abundance of wine grapes and summer fruit.","sources":{"KJV":{"text":"Even all the Jews returned out of all places whither they were driven, and came to the land of Judah, to Gedaliah, unto Mizpah, and gathered wine and summer fruits very much."},"BSB":{"text":"they all returned from all the places to which they had been banished and came to the land of Judah, to Gedaliah at Mizpah. And they gathered an abundance of wine grapes and summer fruit."},"TANAKH":{"text":"then all the Jews returned out of all places whither they were driven, and came to the land of Judah, to Gedaliah, unto Mizpah, and gathered wine and summer fruits in great abundance."},"HEBREW":{"text":"וַיָּשֻׁ֣בוּ כָל־הַיְּהוּדִ֗ים מִכָּל־הַמְּקֹמוֹת֙ אֲשֶׁ֣ר נִדְּחוּ־שָׁ֔ם וַיָּבֹ֧אוּ אֶֽרֶץ־יְהוּדָ֛ה אֶל־גְּדַלְיָ֖הוּ הַמִּצְפָּ֑תָה וַיַּאַסְפ֛וּ יַ֥יִן וָקַ֖יִץ הַרְבֵּ֥ה מְאֹֽד׃"}},"definableWords":["land","Judah"],"peopleInVerse":[],"themesInVerse":["land_promise","vine_branches"]},"13":{"text":"Moreover Johanan the son of Kareah, and all the captains of the forces that were in the fields, came to Gedaliah to Mizpah,","ref":"Jeremiah 40:13","synthesized":"Meanwhile, Johanan son of Kareah and all the commanders of the armies in the field came to Gedaliah at Mizpah","sources":{"KJV":{"text":"Moreover Johanan the son of Kareah, and all the captains of the forces that were in the fields, came to Gedaliah to Mizpah,"},"BSB":{"text":"Meanwhile, Johanan son of Kareah and all the commanders of the armies in the field came to Gedaliah at Mizpah"},"TANAKH":{"text":"Moreover Johanan the son of Kareah, and all the captains of the forces that were in the fields, came to Gedaliah to Mizpah,"},"HEBREW":{"text":"וְיֽוֹחָנָן֙ בֶּן־קָרֵ֔חַ וְכָל־שָׂרֵ֥י הַחֲיָלִ֖ים אֲשֶׁ֣ר בַּשָּׂדֶ֑ה בָּ֥אוּ אֶל־גְּדַלְיָ֖הוּ הַמִּצְפָּֽתָה׃"}},"definableWords":["son","field"],"peopleInVerse":[]},"14":{"text":"And said unto him, Dost thou certainly know that Baalis the king of the Ammonites hath sent Ishmael the son of Nethaniah to slay thee? But Gedaliah the son of Ahikam believed them not.","ref":"Jeremiah 40:14","synthesized":"and said to him, “Are you aware that Baalis king of the Ammonites has sent Ishmael son of Nethaniah to take your life?”  But Gedaliah son of Ahikam did not believe them.","sources":{"KJV":{"text":"And said unto him, Dost thou certainly know that Baalis the king of the Ammonites hath sent Ishmael the son of Nethaniah to slay thee? But Gedaliah the son of Ahikam believed them not."},"BSB":{"text":"and said to him, “Are you aware that Baalis king of the Ammonites has sent Ishmael son of Nethaniah to take your life?”  But Gedaliah son of Ahikam did not believe them."},"TANAKH":{"text":"and said unto him: 'Dost thou know that Baalis the king of the children of Ammon hath sent Ishmael the son of Nethaniah to take thy life?' But Gedaliah the son of Ahikam believed them not."},"HEBREW":{"text":"וַיֹּאמְר֣וּ אֵלָ֗יו הֲיָדֹ֤עַ תֵּדַע֙ כִּ֞י בַּעֲלִ֣יס ׀ מֶ֣לֶךְ בְּנֵֽי־עַמּ֗וֹן שָׁלַח֙ אֶת־יִשְׁמָעֵ֣אל בֶּן־נְתַנְיָ֔ה לְהַכֹּתְךָ֖ נָ֑פֶשׁ וְלֹא־הֶאֱמִ֣ין לָהֶ֔ם גְּדַלְיָ֖הוּ בֶּן־אֲחִיקָֽם׃"}},"definableWords":["king","Ishmael","son","life","Son"],"peopleInVerse":["Ammonites","Ishmael"],"themesInVerse":["faith","kingship"]},"15":{"text":"Then Johanan the son of Kareah spake to Gedaliah in Mizpah secretly, saying, Let me go, I pray thee, and I will slay Ishmael the son of Nethaniah, and no man shall know it: wherefore should he slay thee, that all the Jews which are gathered unto thee should be scattered, and the remnant in Judah perish?","ref":"Jeremiah 40:15","synthesized":"Then Johanan son of Kareah spoke privately to Gedaliah at Mizpah. “Let me go and kill Ishmael son of Nethaniah,” he said. “No one will know it. Why should he take your life and scatter all the people of Judah who have gathered to you, so that the remnant of Judah would perish?”","sources":{"KJV":{"text":"Then Johanan the son of Kareah spake to Gedaliah in Mizpah secretly, saying, Let me go, I pray thee, and I will slay Ishmael the son of Nethaniah, and no man shall know it: wherefore should he slay thee, that all the Jews which are gathered unto thee should be scattered, and the remnant in Judah perish?"},"BSB":{"text":"Then Johanan son of Kareah spoke privately to Gedaliah at Mizpah. “Let me go and kill Ishmael son of Nethaniah,” he said. “No one will know it. Why should he take your life and scatter all the people of Judah who have gathered to you, so that the remnant of Judah would perish?”"},"TANAKH":{"text":"Then Johanan the son of Kareah spoke to Gedaliah in Mizpah secretly, saying: 'Let me go, I pray thee, and I will slay Ishmael the son of Nethaniah, and no man shall know it; wherefore should he take thy life, that all the Jews that are gathered unto thee should be scattered, and the remnant of Judah perish?'"},"HEBREW":{"text":"וְיוֹחָנָ֣ן בֶּן־קָרֵ֡חַ אָמַ֣ר אֶל־גְּדַלְיָהוּ֩ בַסֵּ֨תֶר בַּמִּצְפָּ֜ה לֵאמֹ֗ר אֵ֤לְכָה נָּא֙ וְאַכֶּה֙ אֶת־יִשְׁמָעֵ֣אל בֶּן־נְתַנְיָ֔ה וְאִ֖ישׁ לֹ֣א יֵדָ֑ע לָ֧מָּה יַכֶּ֣כָּה נֶּ֗פֶשׁ וְנָפֹ֙צוּ֙ כָּל־יְהוּדָ֔ה הַנִּקְבָּצִ֣ים אֵלֶ֔יךָ וְאָבְדָ֖ה שְׁאֵרִ֥ית יְהוּדָֽה׃"}},"definableWords":["son","Ishmael","Son","one","life","people","Judah","remnant"],"peopleInVerse":["Ishmael"],"themesInVerse":["exile_return"]},"16":{"text":"But Gedaliah the son of Ahikam said unto Johanan the son of Kareah, Thou shalt not do this thing: for thou speakest falsely of Ishmael.","ref":"Jeremiah 40:16","synthesized":"But Gedaliah son of Ahikam said to Johanan son of Kareah, “Do not do such a thing! What you are saying about Ishmael is a lie.”","sources":{"KJV":{"text":"But Gedaliah the son of Ahikam said unto Johanan the son of Kareah, Thou shalt not do this thing: for thou speakest falsely of Ishmael."},"BSB":{"text":"But Gedaliah son of Ahikam said to Johanan son of Kareah, “Do not do such a thing! What you are saying about Ishmael is a lie.”"},"TANAKH":{"text":"But Gedaliah the son of Ahikam said unto Johanan the son of Kareah: 'Thou shalt not do this thing; for thou speakest falsely of Ishmael.'"},"HEBREW":{"text":"וַיֹּ֨אמֶר גְּדַלְיָ֤הוּ בֶן־אֲחִיקָם֙ אֶל־יוֹחָנָ֣ן בֶּן־קָרֵ֔חַ אַֽל־תעש תַּעֲשֵׂ֖ה אֶת־הַדָּבָ֣ר הַזֶּ֑ה כִּֽי־שֶׁ֛קֶר אַתָּ֥ה דֹבֵ֖ר אֶל־יִשְׁמָעֵֽאל׃"}},"definableWords":["son","Son","Ishmael"],"peopleInVerse":["Ishmael"]}}},"41":{"chapter":"41","title":"GEDALIAH ASSASSINATED","verses":{"1":{"text":"Now it came to pass in the seventh month, that Ishmael the son of Nethaniah the son of Elishama, of the seed royal, and the princes of the king, even ten men with him, came unto Gedaliah the son of Ahikam to Mizpah; and there they did eat bread together in Mizpah.","ref":"Jeremiah 41:1","synthesized":"In the seventh month, Ishmael son of Nethaniah, the son of Elishama, who was a member of the royal family and one of the king’s chief officers, came with ten men to Gedaliah son of Ahikam at Mizpah, and they ate a meal together there.","sources":{"KJV":{"text":"Now it came to pass in the seventh month, that Ishmael the son of Nethaniah the son of Elishama, of the seed royal, and the princes of the king, even ten men with him, came unto Gedaliah the son of Ahikam to Mizpah; and there they did eat bread together in Mizpah."},"BSB":{"text":"In the seventh month, Ishmael son of Nethaniah, the son of Elishama, who was a member of the royal family and one of the king’s chief officers, came with ten men to Gedaliah son of Ahikam at Mizpah, and they ate a meal together there."},"TANAKH":{"text":"Now it came to pass in the seventh month, that Ishmael the son of Nethaniah, the son of Elishama, of the seed royal, and one of the chief officers of the king, and ten men with him, came unto Gedaliah the son of Ahikam to Mizpah; and there they did eat bread together in Mizpah."},"HEBREW":{"text":"וַיְהִ֣י ׀ בַּחֹ֣דֶשׁ הַשְּׁבִיעִ֗י בָּ֣א יִשְׁמָעֵ֣אל בֶּן־נְתַנְיָ֣ה בֶן־אֱלִישָׁמָ֣ע מִזֶּ֣רַע הַ֠מְּלוּכָה וְרַבֵּ֨י הַמֶּ֜לֶךְ וַעֲשָׂרָ֨ה אֲנָשִׁ֥ים אִתּ֛וֹ אֶל־גְּדַלְיָ֥הוּ בֶן־אֲחִיקָ֖ם הַמִּצְפָּ֑תָה וַיֹּ֨אכְלוּ שָׁ֥ם לֶ֛חֶם יַחְדָּ֖ו בַּמִּצְפָּֽה׃"}},"definableWords":["Ishmael","son","Son","family","one","king","men"],"peopleInVerse":["Ishmael"],"themesInVerse":["kingship"]},"2":{"text":"Then arose Ishmael the son of Nethaniah, and the ten men that were with him, and smote Gedaliah the son of Ahikam the son of Shaphan with the sword, and slew him, whom the king of Babylon had made governor over the land.","ref":"Jeremiah 41:2","synthesized":"Then Ishmael son of Nethaniah and the ten men who were with him got up and struck down Gedaliah son of Ahikam, the son of Shaphan, with the sword, killing the one whom the king of Babylon had appointed to govern the land.","sources":{"KJV":{"text":"Then arose Ishmael the son of Nethaniah, and the ten men that were with him, and smote Gedaliah the son of Ahikam the son of Shaphan with the sword, and slew him, whom the king of Babylon had made governor over the land."},"BSB":{"text":"Then Ishmael son of Nethaniah and the ten men who were with him got up and struck down Gedaliah son of Ahikam, the son of Shaphan, with the sword, killing the one whom the king of Babylon had appointed to govern the land."},"TANAKH":{"text":"Then arose Ishmael the son of Nethaniah, and the ten men that were with him, and smote Gedaliah the son of Ahikam the son of Shaphan with the sword, and slew him, whom the king of Babylon had made governor over the land."},"HEBREW":{"text":"וַיָּקָם֩ יִשְׁמָעֵ֨אל בֶּן־נְתַנְיָ֜ה וַעֲשֶׂ֥רֶת הָאֲנָשִׁ֣ים ׀ אֲשֶׁר־הָי֣וּ אִתּ֗וֹ וַ֠יַּכּוּ אֶת־גְּדַלְיָ֨הוּ בֶן־אֲחִיקָ֧ם בֶּן־שָׁפָ֛ן בַּחֶ֖רֶב וַיָּ֣מֶת אֹת֑וֹ אֲשֶׁר־הִפְקִ֥יד מֶֽלֶךְ־בָּבֶ֖ל בָּאָֽרֶץ׃"}},"definableWords":["Ishmael","son","men","Son","one","king","Babylon","land"],"peopleInVerse":["Ishmael"],"placesInVerse":["Babylon"],"themesInVerse":["kingship","land_promise"]},"3":{"text":"Ishmael also slew all the Jews that were with him, even with Gedaliah, at Mizpah, and the Chaldeans that were found there, and the men of war.","ref":"Jeremiah 41:3","synthesized":"Ishmael also killed all the Jews who were with Gedaliah at Mizpah, as well as the Chaldean soldiers who were there.","sources":{"KJV":{"text":"Ishmael also slew all the Jews that were with him, even with Gedaliah, at Mizpah, and the Chaldeans that were found there, and the men of war."},"BSB":{"text":"Ishmael also killed all the Jews who were with Gedaliah at Mizpah, as well as the Chaldean soldiers who were there."},"TANAKH":{"text":"Ishmael also slew all the Jews that were with him, even with Gedaliah, at Mizpah, and the Chaldeans that were found there, even the men of war."},"HEBREW":{"text":"וְאֵ֣ת כָּל־הַיְּהוּדִ֗ים אֲשֶׁר־הָי֨וּ אִתּ֤וֹ אֶת־גְּדַלְיָ֙הוּ֙ בַּמִּצְפָּ֔ה וְאֶת־הַכַּשְׂדִּ֖ים אֲשֶׁ֣ר נִמְצְאוּ־שָׁ֑ם אֵ֚ת אַנְשֵׁ֣י הַמִּלְחָמָ֔ה הִכָּ֖ה יִשְׁמָעֵֽאל׃"}},"definableWords":["Ishmael"],"peopleInVerse":["Ishmael"],"themesInVerse":["bread_water_life"]},"4":{"text":"And it came to pass the second day after he had slain Gedaliah, and no man knew it,","ref":"Jeremiah 41:4","synthesized":"On the second day after the murder of Gedaliah, when no one yet knew about it,","sources":{"KJV":{"text":"And it came to pass the second day after he had slain Gedaliah, and no man knew it,"},"BSB":{"text":"On the second day after the murder of Gedaliah, when no one yet knew about it,"},"TANAKH":{"text":"And it came to pass the second day after he had slain Gedaliah, and no man knew it,"},"HEBREW":{"text":"וַיְהִ֛י בַּיּ֥וֹם הַשֵּׁנִ֖י לְהָמִ֣ית אֶת־גְּדַלְיָ֑הוּ וְאִ֖ישׁ לֹ֥א יָדָֽע׃"}},"definableWords":["day","one"],"peopleInVerse":[]},"5":{"text":"That there came certain from Shechem, from Shiloh, and from Samaria, even fourscore men, having their beards shaven, and their clothes rent, and having cut themselves, with offerings and incense in their hand, to bring them to the house of the LORD.","ref":"Jeremiah 41:5","synthesized":"eighty men who had shaved off their beards, torn their garments, and cut themselves came from Shechem, Shiloh, and Samaria, carrying grain offerings and frankincense for the house of the LORD.","sources":{"KJV":{"text":"That there came certain from Shechem, from Shiloh, and from Samaria, even fourscore men, having their beards shaven, and their clothes rent, and having cut themselves, with offerings and incense in their hand, to bring them to the house of the LORD."},"BSB":{"text":"eighty men who had shaved off their beards, torn their garments, and cut themselves came from Shechem, Shiloh, and Samaria, carrying grain offerings and frankincense for the house of the LORD."},"TANAKH":{"text":"that there came certain men from Shechem, from Shiloh, and from Samaria, even fourscore men, having their beards shaven and their clothes rent, and having cut themselves, with meal-offerings and frankincense in their hand to bring them to the house of HaShem."},"HEBREW":{"text":"וַיָּבֹ֣אוּ אֲ֠נָשִׁים מִשְּׁכֶ֞ם מִשִּׁל֤וֹ וּמִשֹּֽׁמְרוֹן֙ שְׁמֹנִ֣ים אִ֔ישׁ מְגֻלְּחֵ֥י זָקָ֛ן וּקְרֻעֵ֥י בְגָדִ֖ים וּמִתְגֹּֽדְדִ֑ים וּמִנְחָ֤ה וּלְבוֹנָה֙ בְּיָדָ֔ם לְהָבִ֖יא בֵּ֥ית יְהוָֽה׃"}},"definableWords":["men","Samaria","house","LORD"],"peopleInVerse":[],"placesInVerse":["Shechem","Shiloh","Samaria"]},"6":{"text":"And Ishmael the son of Nethaniah went forth from Mizpah to meet them, weeping all along as he went: and it came to pass, as he met them, he said unto them, Come to Gedaliah the son of Ahikam.","ref":"Jeremiah 41:6","synthesized":"And Ishmael son of Nethaniah went out from Mizpah to meet them, weeping as he went.  When Ishmael encountered the men, he said, “Come to Gedaliah son of Ahikam.”","sources":{"KJV":{"text":"And Ishmael the son of Nethaniah went forth from Mizpah to meet them, weeping all along as he went: and it came to pass, as he met them, he said unto them, Come to Gedaliah the son of Ahikam."},"BSB":{"text":"And Ishmael son of Nethaniah went out from Mizpah to meet them, weeping as he went.  When Ishmael encountered the men, he said, “Come to Gedaliah son of Ahikam.”"},"TANAKH":{"text":"And Ishmael the son of Nethaniah went forth from Mizpah to meet them, weeping all along as he went; and it came to pass, as he met them, he said unto them: 'Come to Gedaliah the son of Ahikam.'"},"HEBREW":{"text":"וַ֠יֵּצֵא יִשְׁמָעֵ֨אל בֶּן־נְתַנְיָ֤ה לִקְרָאתָם֙ מִן־הַמִּצְפָּ֔ה הֹלֵ֥ךְ הָלֹ֖ךְ וּבֹכֶ֑ה וַֽיְהִי֙ כִּפְגֹ֣שׁ אֹתָ֔ם וַיֹּ֣אמֶר אֲלֵיהֶ֔ם בֹּ֖אוּ אֶל־גְּדַלְיָ֥הוּ בֶן־אֲחִיקָֽם׃"}},"definableWords":["Ishmael","son","men","Son"],"peopleInVerse":["Ishmael"]},"7":{"text":"And it was so, when they came into the midst of the city, that Ishmael the son of Nethaniah slew them, and cast them into the midst of the pit, he, and the men that were with him.","ref":"Jeremiah 41:7","synthesized":"And when they came into the city, Ishmael son of Nethaniah and the men with him slaughtered them and threw them into a cistern.","sources":{"KJV":{"text":"And it was so, when they came into the midst of the city, that Ishmael the son of Nethaniah slew them, and cast them into the midst of the pit, he, and the men that were with him."},"BSB":{"text":"And when they came into the city, Ishmael son of Nethaniah and the men with him slaughtered them and threw them into a cistern."},"TANAKH":{"text":"And it was so, when they came into the midst of the city, that Ishmael the son of Nethaniah slew them, and cast them into the midst of the pit, he, and the men that were with him."},"HEBREW":{"text":"וַיְהִ֕י כְּבוֹאָ֖ם אֶל־תּ֣וֹךְ הָעִ֑יר וַיִּשְׁחָטֵ֞ם יִשְׁמָעֵ֤אל בֶּן־נְתַנְיָה֙ אֶל־תּ֣וֹךְ הַבּ֔וֹר ה֖וּא וְהָאֲנָשִׁ֥ים אֲשֶׁר־אִתּֽוֹ׃"}},"definableWords":["Ishmael","son","men"],"peopleInVerse":["Ishmael"]},"8":{"text":"But ten men were found among them that said unto Ishmael, Slay us not: for we have treasures in the field, of wheat, and of barley, and of oil, and of honey. So he forbare, and slew them not among their brethren.","ref":"Jeremiah 41:8","synthesized":"But ten of the men among them said to Ishmael, “Do not kill us, for we have hidden treasure in the field—wheat, barley, oil, and honey!” So he refrained from killing them with the others.","sources":{"KJV":{"text":"But ten men were found among them that said unto Ishmael, Slay us not: for we have treasures in the field, of wheat, and of barley, and of oil, and of honey. So he forbare, and slew them not among their brethren."},"BSB":{"text":"But ten of the men among them said to Ishmael, “Do not kill us, for we have hidden treasure in the field—wheat, barley, oil, and honey!” So he refrained from killing them with the others."},"TANAKH":{"text":"But ten men were found among them that said unto Ishmael: 'Slay us not; for we have stores hidden in the field, of wheat, and of barley, and of oil, and of honey.' So he forbore, and slew them not among their brethren."},"HEBREW":{"text":"וַעֲשָׂרָ֨ה אֲנָשִׁ֜ים נִמְצְאוּ־בָ֗ם וַיֹּאמְר֤וּ אֶל־יִשְׁמָעֵאל֙ אַל־תְּמִתֵ֔נוּ כִּֽי־יֶשׁ־לָ֤נוּ מַטְמֹנִים֙ בַּשָּׂדֶ֔ה חִטִּ֥ים וּשְׂעֹרִ֖ים וְשֶׁ֣מֶן וּדְבָ֑שׁ וַיֶּחְדַּ֕ל וְלֹ֥א הֱמִיתָ֖ם בְּת֥וֹךְ אֲחֵיהֶֽם׃"}},"definableWords":["men","Ishmael","field"],"peopleInVerse":["Ishmael"]},"9":{"text":"Now the pit wherein Ishmael had cast all the dead bodies of the men, whom he had slain because of Gedaliah, was it which Asa the king had made for fear of Baasha king of Israel: and Ishmael the son of Nethaniah filled it with them that were slain.","ref":"Jeremiah 41:9","synthesized":"Now the cistern into which Ishmael had thrown all the bodies of the men he had struck down along with Gedaliah was a large one that King Asa had made for fear of Baasha king of Israel. Ishmael son of Nethaniah filled it with the slain.","sources":{"KJV":{"text":"Now the pit wherein Ishmael had cast all the dead bodies of the men, whom he had slain because of Gedaliah, was it which Asa the king had made for fear of Baasha king of Israel: and Ishmael the son of Nethaniah filled it with them that were slain."},"BSB":{"text":"Now the cistern into which Ishmael had thrown all the bodies of the men he had struck down along with Gedaliah was a large one that King Asa had made for fear of Baasha king of Israel. Ishmael son of Nethaniah filled it with the slain."},"TANAKH":{"text":"Now the pit wherein Ishmael cast all the dead bodies of the men whom he had slain by the side of Gedaliah was that which Asa the king had made for fear of Baasa king of Israel; the same Ishmael the son of Nethaniah filled with them that were slain."},"HEBREW":{"text":"וְהַבּ֗וֹר אֲשֶׁר֩ הִשְׁלִ֨יךְ שָׁ֤ם יִשְׁמָעֵאל֙ אֵ֣ת ׀ כָּל־פִּגְרֵ֣י הָאֲנָשִׁ֗ים אֲשֶׁ֤ר הִכָּה֙ בְּיַד־גְּדַלְיָ֔הוּ ה֗וּא אֲשֶׁ֤ר עָשָׂה֙ הַמֶּ֣לֶךְ אָסָ֔א מִפְּנֵ֖י בַּעְשָׁ֣א מֶֽלֶךְ־יִשְׂרָאֵ֑ל אֹת֗וֹ מִלֵּ֛א יִשְׁמָעֵ֥אל בֶּן־נְתַנְיָ֖הוּ חֲלָלִֽים׃"}},"definableWords":["Ishmael","men","one","King","made","fear","king","Israel","son"],"peopleInVerse":["Ishmael"],"themesInVerse":["creation","fear_of_lord","kingship"]},"10":{"text":"Then Ishmael carried away captive all the residue of the people that were in Mizpah, even the king’s daughters, and all the people that remained in Mizpah, whom Nebuzaradan the captain of the guard had committed to Gedaliah the son of Ahikam: and Ishmael the son of Nethaniah carried them away captive, and departed to go over to the Ammonites.","ref":"Jeremiah 41:10","synthesized":"Then Ishmael took captive all the remnant of the people of Mizpah—the daughters of the king along with all the others who remained in Mizpah—over whom Nebuzaradan captain of the guard had appointed Gedaliah son of Ahikam. Ishmael son of Nethaniah took them captive and set off to cross over to the Ammonites.","sources":{"KJV":{"text":"Then Ishmael carried away captive all the residue of the people that were in Mizpah, even the king’s daughters, and all the people that remained in Mizpah, whom Nebuzaradan the captain of the guard had committed to Gedaliah the son of Ahikam: and Ishmael the son of Nethaniah carried them away captive, and departed to go over to the Ammonites."},"BSB":{"text":"Then Ishmael took captive all the remnant of the people of Mizpah—the daughters of the king along with all the others who remained in Mizpah—over whom Nebuzaradan captain of the guard had appointed Gedaliah son of Ahikam. Ishmael son of Nethaniah took them captive and set off to cross over to the Ammonites."},"TANAKH":{"text":"Then Ishmael carried away captive all the residue of the people that were in Mizpah, even the king's daughters, and all the people that remained in Mizpah, whom Nebuzaradan the captain of the guard had committed to Gedaliah the son of Ahikam; Ishmael the son of Nethaniah carried them away captive, and departed to go over to the children of Ammon."},"HEBREW":{"text":"וַיִּ֣שְׁבְּ ׀ יִ֠שְׁמָעֵאל אֶת־כָּל־שְׁאֵרִ֨ית הָעָ֜ם אֲשֶׁ֣ר בַּמִּצְפָּ֗ה אֶת־בְּנ֤וֹת הַמֶּ֙לֶךְ֙ וְאֶת־כָּל־הָעָם֙ הַנִּשְׁאָרִ֣ים בַּמִּצְפָּ֔ה אֲשֶׁ֣ר הִפְקִ֗יד נְבֽוּזַרְאֲדָן֙ רַב־טַבָּחִ֔ים אֶת־גְּדַלְיָ֖הוּ בֶּן־אֲחִיקָ֑ם וַיִּשְׁבֵּם֙ יִשְׁמָעֵ֣אל בֶּן־נְתַנְיָ֔ה וַיֵּ֕לֶךְ לַעֲבֹ֖ר אֶל־בְּנֵ֥י עַמּֽוֹן׃"}},"definableWords":["Ishmael","remnant","people","daughters","king","son","Son"],"peopleInVerse":["Ishmael","Ammonites"],"themesInVerse":["exile_return","kingship"]},"11":{"text":"But when Johanan the son of Kareah, and all the captains of the forces that were with him, heard of all the evil that Ishmael the son of Nethaniah had done,","ref":"Jeremiah 41:11","synthesized":"When Johanan son of Kareah and all the commanders of the armies with him heard of all the crimes that Ishmael son of Nethaniah had committed,","sources":{"KJV":{"text":"But when Johanan the son of Kareah, and all the captains of the forces that were with him, heard of all the evil that Ishmael the son of Nethaniah had done,"},"BSB":{"text":"When Johanan son of Kareah and all the commanders of the armies with him heard of all the crimes that Ishmael son of Nethaniah had committed,"},"TANAKH":{"text":"But when Johanan the son of Kareah, and all the captains of the forces that were with him, heard of all the evil that Ishmael the son of Nethaniah had done,"},"HEBREW":{"text":"וַיִּשְׁמַע֙ יוֹחָנָ֣ן בֶּן־קָרֵ֔חַ וְכָל־שָׂרֵ֥י הַחֲיָלִ֖ים אֲשֶׁ֣ר אִתּ֑וֹ אֵ֤ת כָּל־הָֽרָעָה֙ אֲשֶׁ֣ר עָשָׂ֔ה יִשְׁמָעֵ֖אל בֶּן־נְתַנְיָֽה׃"}},"definableWords":["son","Ishmael","Son"],"peopleInVerse":["Ishmael"]},"12":{"text":"Then they took all the men, and went to fight with Ishmael the son of Nethaniah, and found him by the great waters that are in Gibeon.","ref":"Jeremiah 41:12","synthesized":"they took all their men and went to fight Ishmael son of Nethaniah. And they found him near the great pool in Gibeon.","sources":{"KJV":{"text":"Then they took all the men, and went to fight with Ishmael the son of Nethaniah, and found him by the great waters that are in Gibeon."},"BSB":{"text":"they took all their men and went to fight Ishmael son of Nethaniah. And they found him near the great pool in Gibeon."},"TANAKH":{"text":"then they took all the men, and went to fight with Ishmael the son of Nethaniah, and found him by the great waters that are in Gibeon."},"HEBREW":{"text":"וַיִּקְחוּ֙ אֶת־כָּל־הָ֣אֲנָשִׁ֔ים וַיֵּ֣לְכ֔וּ לְהִלָּחֵ֖ם עִם־יִשְׁמָעֵ֣אל בֶּן־נְתַנְיָ֑ה וַיִּמְצְא֣וּ אֹת֔וֹ אֶל־מַ֥יִם רַבִּ֖ים אֲשֶׁ֥ר בְּגִבְעֽוֹן׃"}},"definableWords":["men","fight","Ishmael","son","great"],"peopleInVerse":["Ishmael"],"themesInVerse":["spiritual_warfare"]},"13":{"text":"Now it came to pass, that when all the people which were with Ishmael saw Johanan the son of Kareah, and all the captains of the forces that were with him, then they were glad.","ref":"Jeremiah 41:13","synthesized":"When all the people with Ishmael saw Johanan son of Kareah and all the commanders of the army with him, they rejoiced,","sources":{"KJV":{"text":"Now it came to pass, that when all the people which were with Ishmael saw Johanan the son of Kareah, and all the captains of the forces that were with him, then they were glad."},"BSB":{"text":"When all the people with Ishmael saw Johanan son of Kareah and all the commanders of the army with him, they rejoiced,"},"TANAKH":{"text":"Now it came to pass, that when all the people that were with Ishmael saw Johanan the son of Kareah, and all the captains of the forces that were with him, then they were glad."},"HEBREW":{"text":"וַיְהִ֗י כִּרְא֤וֹת כָּל־הָעָם֙ אֲשֶׁ֣ר אֶת־יִשְׁמָעֵ֔אל אֶת־יֽוֹחָנָן֙ בֶּן־קָרֵ֔חַ וְאֵ֛ת כָּל־שָׂרֵ֥י הַחֲיָלִ֖ים אֲשֶׁ֣ר אִתּ֑וֹ וַיִּשְׂמָֽחוּ׃"}},"definableWords":["people","Ishmael","saw","son"],"peopleInVerse":["Ishmael"]},"14":{"text":"So all the people that Ishmael had carried away captive from Mizpah cast about and returned, and went unto Johanan the son of Kareah.","ref":"Jeremiah 41:14","synthesized":"and all the people whom Ishmael had taken captive at Mizpah turned and went over to Johanan son of Kareah.","sources":{"KJV":{"text":"So all the people that Ishmael had carried away captive from Mizpah cast about and returned, and went unto Johanan the son of Kareah."},"BSB":{"text":"and all the people whom Ishmael had taken captive at Mizpah turned and went over to Johanan son of Kareah."},"TANAKH":{"text":"So all the people that Ishmael had carried away captive from Mizpah cast about and returned, and went unto Johanan the son of Kareah."},"HEBREW":{"text":"וַיָּסֹ֙בּוּ֙ כָּל־הָעָ֔ם אֲשֶׁר־שָׁבָ֥ה יִשְׁמָעֵ֖אל מִן־הַמִּצְפָּ֑ה וַיָּשֻׁ֙בוּ֙ וַיֵּ֣לְכ֔וּ אֶל־יֽוֹחָנָ֖ן בֶּן־קָרֵֽחַ׃"}},"definableWords":["people","Ishmael","son"],"peopleInVerse":["Ishmael"]},"15":{"text":"But Ishmael the son of Nethaniah escaped from Johanan with eight men, and went to the Ammonites.","ref":"Jeremiah 41:15","synthesized":"But Ishmael son of Nethaniah and eight of his men escaped from Johanan and went to the Ammonites.","sources":{"KJV":{"text":"But Ishmael the son of Nethaniah escaped from Johanan with eight men, and went to the Ammonites."},"BSB":{"text":"But Ishmael son of Nethaniah and eight of his men escaped from Johanan and went to the Ammonites."},"TANAKH":{"text":"But Ishmael the son of Nethaniah escaped from Johanan with eight men, and went to the children of Ammon."},"HEBREW":{"text":"וְיִשְׁמָעֵ֣אל בֶּן־נְתַנְיָ֗ה נִמְלַט֙ בִּשְׁמֹנָ֣ה אֲנָשִׁ֔ים מִפְּנֵ֖י יֽוֹחָנָ֑ן וַיֵּ֖לֶךְ אֶל־בְּנֵ֥י עַמּֽוֹן׃"}},"definableWords":["Ishmael","son","men"],"peopleInVerse":["Ishmael","Ammonites"]},"16":{"text":"Then took Johanan the son of Kareah, and all the captains of the forces that were with him, all the remnant of the people whom he had recovered from Ishmael the son of Nethaniah, from Mizpah, after that he had slain Gedaliah the son of Ahikam, even mighty men of war, and the women, and the children, and the eunuchs, whom he had brought again from Gibeon:","ref":"Jeremiah 41:16","synthesized":"Then Johanan son of Kareah and all the commanders of the armies with him took the whole remnant of the people from Mizpah whom he had recovered from Ishmael son of Nethaniah after Ishmael had killed Gedaliah son of Ahikam: the soldiers, women, children, and court officials he had brought back from Gibeon.","sources":{"KJV":{"text":"Then took Johanan the son of Kareah, and all the captains of the forces that were with him, all the remnant of the people whom he had recovered from Ishmael the son of Nethaniah, from Mizpah, after that he had slain Gedaliah the son of Ahikam, even mighty men of war, and the women, and the children, and the eunuchs, whom he had brought again from Gibeon:"},"BSB":{"text":"Then Johanan son of Kareah and all the commanders of the armies with him took the whole remnant of the people from Mizpah whom he had recovered from Ishmael son of Nethaniah after Ishmael had killed Gedaliah son of Ahikam: the soldiers, women, children, and court officials he had brought back from Gibeon."},"TANAKH":{"text":"Then took Johanan the son of Kareah, and all the captains of the forces that were with him, all the remnant of the people whom he had recovered from Ishmael the son of Nethaniah, from Mizpah, after that he had slain Gedaliah the son of Ahikam, the men, even the men of war, and the women, and the children, and the officers, whom he had brought back from Gibeon;"},"HEBREW":{"text":"וַיִּקַּח֩ יוֹחָנָ֨ן בֶּן־קָרֵ֜חַ וְכָל־שָׂרֵ֧י הַחֲיָלִ֣ים אֲשֶׁר־אִתּ֗וֹ אֵ֣ת כָּל־שְׁאֵרִ֤ית הָעָם֙ אֲשֶׁ֣ר הֵ֠שִׁיב מֵאֵ֨ת יִשְׁמָעֵ֤אל בֶּן־נְתַנְיָה֙ מִן־הַמִּצְפָּ֔ה אַחַ֣ר הִכָּ֔ה אֶת־גְּדַלְיָ֖ה בֶּן־אֲחִיקָ֑ם גְּבָרִ֞ים אַנְשֵׁ֣י הַמִּלְחָמָ֗ה וְנָשִׁ֤ים וְטַף֙ וְסָ֣רִסִ֔ים אֲשֶׁ֥ר הֵשִׁ֖יב מִגִּבְעֽוֹן׃"}},"definableWords":["son","remnant","people","Ishmael","Son","women"],"peopleInVerse":["Ishmael"],"themesInVerse":["exile_return"]},"17":{"text":"And they departed, and dwelt in the habitation of Chimham, which is by Bethlehem, to go to enter into Egypt,","ref":"Jeremiah 41:17","synthesized":"And they went and stayed in Geruth Chimham, near Bethlehem, in order to proceed into Egypt","sources":{"KJV":{"text":"And they departed, and dwelt in the habitation of Chimham, which is by Bethlehem, to go to enter into Egypt,"},"BSB":{"text":"And they went and stayed in Geruth Chimham, near Bethlehem, in order to proceed into Egypt"},"TANAKH":{"text":"and they departed, and dwelt in Geruth Chimham, which is by Beth-lehem, to go to enter into Egypt,"},"HEBREW":{"text":"וַיֵּלְכ֗וּ וַיֵּֽשְׁבוּ֙ בְּגֵר֣וּת כמוהם כִּמְהָ֔ם אֲשֶׁר־אֵ֖צֶל בֵּ֣ית לָ֑חֶם לָלֶ֖כֶת לָב֥וֹא מִצְרָֽיִם׃"}},"definableWords":["Egypt"],"peopleInVerse":[],"placesInVerse":["Bethlehem","Egypt"],"themesInVerse":["exodus_pattern"]},"18":{"text":"Because of the Chaldeans: for they were afraid of them, because Ishmael the son of Nethaniah had slain Gedaliah the son of Ahikam, whom the king of Babylon made governor in the land.","ref":"Jeremiah 41:18","synthesized":"to escape the Chaldeans. For they were afraid of the Chaldeans because Ishmael son of Nethaniah had struck down Gedaliah son of Ahikam, whom the king of Babylon had appointed over the land.","sources":{"KJV":{"text":"Because of the Chaldeans: for they were afraid of them, because Ishmael the son of Nethaniah had slain Gedaliah the son of Ahikam, whom the king of Babylon made governor in the land."},"BSB":{"text":"to escape the Chaldeans. For they were afraid of the Chaldeans because Ishmael son of Nethaniah had struck down Gedaliah son of Ahikam, whom the king of Babylon had appointed over the land."},"TANAKH":{"text":"because of the Chaldeans; for they were afraid of them, because Ishmael the son of Nethaniah had slain Gedaliah the son of Ahikam, whom the king of Babylon made governor over the land."},"HEBREW":{"text":"מִפְּנֵי֙ הַכַּשְׂדִּ֔ים כִּ֥י יָרְא֖וּ מִפְּנֵיהֶ֑ם כִּֽי־הִכָּ֞ה יִשְׁמָעֵ֣אל בֶּן־נְתַנְיָ֗ה אֶת־גְּדַלְיָ֙הוּ֙ בֶּן־אֲחִיקָ֔ם אֲשֶׁר־הִפְקִ֥יד מֶֽלֶךְ־בָּבֶ֖ל בָּאָֽרֶץ׃"}},"definableWords":["Ishmael","son","Son","king","Babylon","land"],"peopleInVerse":["Ishmael"],"placesInVerse":["Babylon"],"themesInVerse":["kingship","land_promise"]}}},"42":{"chapter":"42","title":"JEREMIAH'S WARNING NOT TO FLEE TO EGYPT","verses":{"1":{"text":"Then all the captains of the forces, and Johanan the son of Kareah, and Jezaniah the son of Hoshaiah, and all the people from the least even unto the greatest, came near,","ref":"Jeremiah 42:1","synthesized":"Then all the commanders of the forces, along with Johanan son of Kareah, Jezaniah son of Hoshaiah, and all the people from the least to the greatest, approached","sources":{"KJV":{"text":"Then all the captains of the forces, and Johanan the son of Kareah, and Jezaniah the son of Hoshaiah, and all the people from the least even unto the greatest, came near,"},"BSB":{"text":"Then all the commanders of the forces, along with Johanan son of Kareah, Jezaniah son of Hoshaiah, and all the people from the least to the greatest, approached"},"TANAKH":{"text":"Then all the captains of the forces, and Johanan the son of Kareah, and Jezaniah the son of Hoshaiah, and all the people from the least even unto the greatest, came near,"},"HEBREW":{"text":"וַֽיִּגְּשׁוּ֙ כָּל־שָׂרֵ֣י הַחֲיָלִ֔ים וְיֽוֹחָנָן֙ בֶּן־קָרֵ֔חַ וִֽיזַנְיָ֖ה בֶּן־הוֹשַֽׁעְיָ֑ה וְכָל־הָעָ֖ם מִקָּטֹ֥ן וְעַד־גָּדֽוֹל׃"}},"definableWords":["son","Son","people"],"peopleInVerse":[]},"2":{"text":"And said unto Jeremiah the prophet, Let, we beseech thee, our supplication be accepted before thee, and pray for us unto the LORD thy God, even for all this remnant; (for we are left but a few of many, as thine eyes do behold us:)","ref":"Jeremiah 42:2","synthesized":"Jeremiah the prophet and said, “May our petition come before you; pray to the LORD your God on behalf of this entire remnant. For few of us remain of the many, as you can see with your own eyes.","sources":{"KJV":{"text":"And said unto Jeremiah the prophet, Let, we beseech thee, our supplication be accepted before thee, and pray for us unto the LORD thy God, even for all this remnant; (for we are left but a few of many, as thine eyes do behold us:)"},"BSB":{"text":"Jeremiah the prophet and said, “May our petition come before you; pray to the LORD your God on behalf of this entire remnant. For few of us remain of the many, as you can see with your own eyes."},"TANAKH":{"text":"and said unto Jeremiah the prophet: 'Let, we pray thee, our supplication be accepted before thee, and pray for us unto HaShem thy G-d, even for all this remnant; for we are left but a few of many, as thine eyes do behold us;"},"HEBREW":{"text":"וַיֹּאמְר֞וּ אֶֽל־יִרְמְיָ֣הוּ הַנָּבִ֗יא תִּפָּל־נָ֤א תְחִנָּתֵ֙נוּ֙ לְפָנֶ֔יךָ וְהִתְפַּלֵּ֤ל בַּעֲדֵ֙נוּ֙ אֶל־יְהוָ֣ה אֱלֹהֶ֔יךָ בְּעַ֖ד כָּל־הַשְּׁאֵרִ֣ית הַזֹּ֑את כִּֽי־נִשְׁאַ֤רְנוּ מְעַט֙ מֵֽהַרְבֵּ֔ה כַּאֲשֶׁ֥ר עֵינֶ֖יךָ רֹא֥וֹת אֹתָֽנוּ׃"}},"definableWords":["prophet","LORD","God","remnant","see"],"peopleInVerse":["Jeremiah"],"themesInVerse":["exile_return","prayer"]},"3":{"text":"That the LORD thy God may shew us the way wherein we may walk, and the thing that we may do.","ref":"Jeremiah 42:3","synthesized":"Pray that the LORD your God will tell us the way we should walk and the thing we should do.”","sources":{"KJV":{"text":"That the LORD thy God may shew us the way wherein we may walk, and the thing that we may do."},"BSB":{"text":"Pray that the LORD your God will tell us the way we should walk and the thing we should do.”"},"TANAKH":{"text":"that HaShem thy G-d may tell us the way wherein we should walk, and the thing that we should do.'"},"HEBREW":{"text":"וְיַגֶּד־לָ֙נוּ֙ יְהוָ֣ה אֱלֹהֶ֔יךָ אֶת־הַדֶּ֖רֶךְ אֲשֶׁ֣ר נֵֽלֶךְ־בָּ֑הּ וְאֶת־הַדָּבָ֖ר אֲשֶׁ֥ר נַעֲשֶֽׂה׃"}},"definableWords":["LORD","God","way","walk"],"peopleInVerse":[],"themesInVerse":["prayer"]},"4":{"text":"Then Jeremiah the prophet said unto them, I have heard you; behold, I will pray unto the LORD your God according to your words; and it shall come to pass, that whatsoever thing the LORD shall answer you, I will declare it unto you; I will keep nothing back from you.","ref":"Jeremiah 42:4","synthesized":"“I have heard you,” replied Jeremiah the prophet. “I will surely pray to the LORD your God as you request, and I will tell you everything that the LORD answers; I will not withhold a word from you.”","sources":{"KJV":{"text":"Then Jeremiah the prophet said unto them, I have heard you; behold, I will pray unto the LORD your God according to your words; and it shall come to pass, that whatsoever thing the LORD shall answer you, I will declare it unto you; I will keep nothing back from you."},"BSB":{"text":"“I have heard you,” replied Jeremiah the prophet. “I will surely pray to the LORD your God as you request, and I will tell you everything that the LORD answers; I will not withhold a word from you.”"},"TANAKH":{"text":"Then Jeremiah the prophet said unto them: 'I have heard you; behold, I will pray unto HaShem your G-d according to your words; and it shall come to pass, that whatsoever thing HaShem shall answer you, I will declare it unto you; I will keep nothing back from you.'"},"HEBREW":{"text":"וַיֹּ֨אמֶר אֲלֵיהֶ֜ם יִרְמְיָ֤הוּ הַנָּבִיא֙ שָׁמַ֔עְתִּי הִנְנִ֧י מִתְפַּלֵּ֛ל אֶל־יְהוָ֥ה אֱלֹהֵיכֶ֖ם כְּדִבְרֵיכֶ֑ם וְֽהָיָ֡ה כָּֽל־הַדָּבָר֩ אֲשֶׁר־יַעֲנֶ֨ה יְהוָ֤ה אֶתְכֶם֙ אַגִּ֣יד לָכֶ֔ם לֹֽא־אֶמְנַ֥ע מִכֶּ֖ם דָּבָֽר׃"}},"definableWords":["prophet","LORD","God","Lord","word"],"peopleInVerse":["Jeremiah"],"themesInVerse":["prayer"]},"5":{"text":"Then they said to Jeremiah, The LORD be a true and faithful witness between us, if we do not even according to all things for the which the LORD thy God shall send thee to us.","ref":"Jeremiah 42:5","synthesized":"Then they said to Jeremiah, “May the LORD be a true and faithful witness against us if we do not act upon every word that the LORD your God sends you to tell us.","sources":{"KJV":{"text":"Then they said to Jeremiah, The LORD be a true and faithful witness between us, if we do not even according to all things for the which the LORD thy God shall send thee to us."},"BSB":{"text":"Then they said to Jeremiah, “May the LORD be a true and faithful witness against us if we do not act upon every word that the LORD your God sends you to tell us."},"TANAKH":{"text":"Then they said to Jeremiah: 'The HaShem be a true and faithful witness against us, if we do not even according to all the word wherewith HaShem thy G-d shall send thee to us."},"HEBREW":{"text":"וְהֵ֙מָּה֙ אָמְר֣וּ אֶֽל־יִרְמְיָ֔הוּ יְהִ֤י יְהוָה֙ בָּ֔נוּ לְעֵ֖ד אֱמֶ֣ת וְנֶאֱמָ֑ן אִם־לֹ֡א כְּֽכָל־הַ֠דָּבָר אֲשֶׁ֨ר יִֽשְׁלָחֲךָ֜ יְהוָ֧ה אֱלֹהֶ֛יךָ אֵלֵ֖ינוּ כֵּ֥ן נַעֲשֶֽׂה׃"}},"definableWords":["LORD","word","Lord","God"],"peopleInVerse":["Jeremiah"]},"6":{"text":"Whether it be good, or whether it be evil, we will obey the voice of the LORD our God, to whom we send thee; that it may be well with us, when we obey the voice of the LORD our God.","ref":"Jeremiah 42:6","synthesized":"Whether it is pleasant or unpleasant, we will obey the voice of the LORD our God to whom we are sending you, so that it may go well with us, for we will obey the voice of the LORD our God!”","sources":{"KJV":{"text":"Whether it be good, or whether it be evil, we will obey the voice of the LORD our God, to whom we send thee; that it may be well with us, when we obey the voice of the LORD our God."},"BSB":{"text":"Whether it is pleasant or unpleasant, we will obey the voice of the LORD our God to whom we are sending you, so that it may go well with us, for we will obey the voice of the LORD our God!”"},"TANAKH":{"text":"Whether it be good, or whether it be evil, we will hearken to the voice of HaShem our G-d, to whom we send thee; that it may be well with us, when we hearken to the voice of HaShem our G-d.'"},"HEBREW":{"text":"אִם־ט֣וֹב וְאִם־רָ֔ע בְּק֣וֹל ׀ יְהוָ֣ה אֱלֹהֵ֗ינוּ אֲשֶׁ֨ר אנו אֲנַ֜חְנוּ שֹׁלְחִ֥ים אֹתְךָ֛ אֵלָ֖יו נִשְׁמָ֑ע לְמַ֙עַן֙ אֲשֶׁ֣ר יִֽיטַב־לָ֔נוּ כִּ֣י נִשְׁמַ֔ע בְּק֖וֹל יְהוָ֥ה אֱלֹהֵֽינוּ׃"}},"definableWords":["or","voice","LORD","God","Lord"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"7":{"text":"And it came to pass after ten days, that the word of the LORD came unto Jeremiah.","ref":"Jeremiah 42:7","synthesized":"After ten days the word of the LORD came to Jeremiah,","sources":{"KJV":{"text":"And it came to pass after ten days, that the word of the LORD came unto Jeremiah."},"BSB":{"text":"After ten days the word of the LORD came to Jeremiah,"},"TANAKH":{"text":"And it came to pass after ten days, that the word of HaShem came unto Jeremiah."},"HEBREW":{"text":"וַיְהִ֕י מִקֵּ֖ץ עֲשֶׂ֣רֶת יָמִ֑ים וַיְהִ֥י דְבַר־יְהוָ֖ה אֶֽל־יִרְמְיָֽהוּ׃"}},"definableWords":["days","word","LORD"],"peopleInVerse":["Jeremiah"]},"8":{"text":"Then called he Johanan the son of Kareah, and all the captains of the forces which were with him, and all the people from the least even to the greatest,","ref":"Jeremiah 42:8","synthesized":"and he summoned Johanan son of Kareah, all the commanders of the forces who were with him, and all the people from the least to the greatest.","sources":{"KJV":{"text":"Then called he Johanan the son of Kareah, and all the captains of the forces which were with him, and all the people from the least even to the greatest,"},"BSB":{"text":"and he summoned Johanan son of Kareah, all the commanders of the forces who were with him, and all the people from the least to the greatest."},"TANAKH":{"text":"Then called he Johanan the son of Kareah, and all the captains of the forces that were with him, and all the people from the least even to the greatest,"},"HEBREW":{"text":"וַיִּקְרָ֗א אֶל־יֽוֹחָנָן֙ בֶּן־קָרֵ֔חַ וְאֶ֛ל כָּל־שָׂרֵ֥י הַחֲיָלִ֖ים אֲשֶׁ֣ר אִתּ֑וֹ וּלְכָ֨ל־הָעָ֔ם לְמִקָּטֹ֥ן וְעַד־גָּדֽוֹל׃"}},"definableWords":["son","people"],"peopleInVerse":[]},"9":{"text":"And said unto them, Thus saith the LORD, the God of Israel, unto whom ye sent me to present your supplication before him;","ref":"Jeremiah 42:9","synthesized":"Jeremiah told them, “Thus says the LORD, the God of Israel, to whom you sent me to present your petition:","sources":{"KJV":{"text":"And said unto them, Thus saith the LORD, the God of Israel, unto whom ye sent me to present your supplication before him;"},"BSB":{"text":"Jeremiah told them, “Thus says the LORD, the God of Israel, to whom you sent me to present your petition:"},"TANAKH":{"text":"and said unto them: 'Thus saith HaShem, the G-d of Israel, unto whom ye sent me to present your supplication before Him:"},"HEBREW":{"text":"וַיֹּ֣אמֶר אֲלֵיהֶ֔ם כֹּֽה־אָמַ֥ר יְהוָ֖ה אֱלֹהֵ֣י יִשְׂרָאֵ֑ל אֲשֶׁ֨ר שְׁלַחְתֶּ֤ם אֹתִי֙ אֵלָ֔יו לְהַפִּ֥יל תְּחִנַּתְכֶ֖ם לְפָנָֽיו׃"}},"definableWords":["LORD","God","Israel"],"peopleInVerse":["Jeremiah"],"themesInVerse":["prayer"]},"10":{"text":"If ye will still abide in this land, then will I build you, and not pull you down, and I will plant you, and not pluck you up: for I repent me of the evil that I have done unto you.","ref":"Jeremiah 42:10","synthesized":"‘If you will indeed stay in this land, then I will build you up and not tear you down; I will plant you and not uproot you, for I will relent of the disaster I have brought upon you.","sources":{"KJV":{"text":"If ye will still abide in this land, then will I build you, and not pull you down, and I will plant you, and not pluck you up: for I repent me of the evil that I have done unto you."},"BSB":{"text":"‘If you will indeed stay in this land, then I will build you up and not tear you down; I will plant you and not uproot you, for I will relent of the disaster I have brought upon you."},"TANAKH":{"text":"If ye will still abide in this land, then will I build you, and not pull you down, and I will plant you, and not pluck you up; for I repent Me of the evil that I have done unto you."},"HEBREW":{"text":"אִם־שׁ֤וֹב תֵּֽשְׁבוּ֙ בָּאָ֣רֶץ הַזֹּ֔את וּבָנִ֤יתִי אֶתְכֶם֙ וְלֹ֣א אֶהֱרֹ֔ס וְנָטַעְתִּ֥י אֶתְכֶ֖ם וְלֹ֣א אֶתּ֑וֹשׁ כִּ֤י נִחַ֙מְתִּי֙ אֶל־הָ֣רָעָ֔ה אֲשֶׁ֥ר עָשִׂ֖יתִי לָכֶֽם׃"}},"definableWords":["land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"11":{"text":"Be not afraid of the king of Babylon, of whom ye are afraid; be not afraid of him, saith the LORD: for I am with you to save you, and to deliver you from his hand.","ref":"Jeremiah 42:11","synthesized":"Do not be afraid of the king of Babylon, whom you now fear; do not be afraid of him, declares the LORD, for I am with you to save you and deliver you from him.","sources":{"KJV":{"text":"Be not afraid of the king of Babylon, of whom ye are afraid; be not afraid of him, saith the LORD: for I am with you to save you, and to deliver you from his hand."},"BSB":{"text":"Do not be afraid of the king of Babylon, whom you now fear; do not be afraid of him, declares the LORD, for I am with you to save you and deliver you from him."},"TANAKH":{"text":"Be not afraid of the king of Babylon, of whom ye are afraid; be not afraid of him, saith HaShem; for I am with you to save you, and to deliver you from his hand."},"HEBREW":{"text":"אַל־תִּֽירְא֗וּ מִפְּנֵי֙ מֶ֣לֶךְ בָּבֶ֔ל אֲשֶׁר־אַתֶּ֥ם יְרֵאִ֖ים מִפָּנָ֑יו אַל־תִּֽירְא֤וּ מִמֶּ֙נּוּ֙ נְאֻם־יְהוָ֔ה כִּֽי־אִתְּכֶ֣ם אָ֔נִי לְהוֹשִׁ֧יעַ אֶתְכֶ֛ם וּלְהַצִּ֥יל אֶתְכֶ֖ם מִיָּדֽוֹ׃"}},"definableWords":["king","Babylon","fear","LORD","deliver"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["fear_of_lord","kingship","redemption","salvation"]},"12":{"text":"And I will shew mercies unto you, that he may have mercy upon you, and cause you to return to your own land.","ref":"Jeremiah 42:12","synthesized":"And I will show you compassion, and he will have compassion on you and restore you to your own land.’","sources":{"KJV":{"text":"And I will shew mercies unto you, that he may have mercy upon you, and cause you to return to your own land."},"BSB":{"text":"And I will show you compassion, and he will have compassion on you and restore you to your own land.’"},"TANAKH":{"text":"And I will grant you compassion, that he may have compassion upon you, and cause you to return to your own land."},"HEBREW":{"text":"וְאֶתֵּ֥ן לָכֶ֛ם רַחֲמִ֖ים וְרִחַ֣ם אֶתְכֶ֑ם וְהֵשִׁ֥יב אֶתְכֶ֖ם אֶל־אַדְמַתְכֶֽם׃"}},"definableWords":["land"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise"]},"13":{"text":"But if ye say, We will not dwell in this land, neither obey the voice of the LORD your God,","ref":"Jeremiah 42:13","synthesized":"But if you say, ‘We will not stay in this land,’ and you thus disobey the voice of the LORD your God,","sources":{"KJV":{"text":"But if ye say, We will not dwell in this land, neither obey the voice of the LORD your God,"},"BSB":{"text":"But if you say, ‘We will not stay in this land,’ and you thus disobey the voice of the LORD your God,"},"TANAKH":{"text":"But if ye say: We will not abide in this land; so that ye hearken not to the voice of HaShem your G-d;"},"HEBREW":{"text":"וְאִם־אֹמְרִ֣ים אַתֶּ֔ם לֹ֥א נֵשֵׁ֖ב בָּאָ֣רֶץ הַזֹּ֑את לְבִלְתִּ֣י שְׁמֹ֔עַ בְּק֖וֹל יְהוָ֥ה אֱלֹהֵיכֶֽם׃"}},"definableWords":["land","voice","LORD","God"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"14":{"text":"Saying, No; but we will go into the land of Egypt, where we shall see no war, nor hear the sound of the trumpet, nor have hunger of bread; and there will we dwell:","ref":"Jeremiah 42:14","synthesized":"and if you say, ‘No, but we will go to the land of Egypt and live there, where we will not see war or hear the sound of the ram’s horn or hunger for bread,’","sources":{"KJV":{"text":"Saying, No; but we will go into the land of Egypt, where we shall see no war, nor hear the sound of the trumpet, nor have hunger of bread; and there will we dwell:"},"BSB":{"text":"and if you say, ‘No, but we will go to the land of Egypt and live there, where we will not see war or hear the sound of the ram’s horn or hunger for bread,’"},"TANAKH":{"text":"saying: No; but we will go into the land of Egypt, where we shall see no war, nor hear the sound of the horn, nor have hunger of bread; and there will we abide;"},"HEBREW":{"text":"לֵאמֹ֗ר לֹ֚א כִּ֣י אֶ֤רֶץ מִצְרַ֙יִם֙ נָב֔וֹא אֲשֶׁ֤ר לֹֽא־נִרְאֶה֙ מִלְחָמָ֔ה וְק֥וֹל שׁוֹפָ֖ר לֹ֣א נִשְׁמָ֑ע וְלַלֶּ֥חֶם לֹֽא־נִרְעָ֖ב וְשָׁ֥ם נֵשֵֽׁב׃"}},"definableWords":["land","Egypt","live","see","or","hear"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["bread_water_life","exodus_pattern","land_promise"]},"15":{"text":"And now therefore hear the word of the LORD, ye remnant of Judah; Thus saith the LORD of hosts, the God of Israel; If ye wholly set your faces to enter into Egypt, and go to sojourn there;","ref":"Jeremiah 42:15","synthesized":"then hear the word of the LORD, O remnant of Judah! This is what the LORD of Hosts, the God of Israel, says: ‘If you are determined to go to Egypt and reside there,","sources":{"KJV":{"text":"And now therefore hear the word of the LORD, ye remnant of Judah; Thus saith the LORD of hosts, the God of Israel; If ye wholly set your faces to enter into Egypt, and go to sojourn there;"},"BSB":{"text":"then hear the word of the LORD, O remnant of Judah! This is what the LORD of Hosts, the God of Israel, says: ‘If you are determined to go to Egypt and reside there,"},"TANAKH":{"text":"now therefore hear ye the word of HaShem, O remnant of Judah: Thus saith HaShem of hosts, the G-d of Israel: If ye wholly set your faces to enter into Egypt, and go to sojourn there;"},"HEBREW":{"text":"וְעַתָּ֕ה לָכֵ֛ן שִׁמְע֥וּ דְבַר־יְהוָ֖ה שְׁאֵרִ֣ית יְהוּדָ֑ה כֹּֽה־אָמַר֩ יְהוָ֨ה צְבָא֜וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֗ל אִם־אַ֠תֶּם שׂ֣וֹם תְּשִׂמ֤וּן פְּנֵיכֶם֙ לָבֹ֣א מִצְרַ֔יִם וּבָאתֶ֖ם לָג֥וּר שָֽׁם׃"}},"definableWords":["hear","word","LORD","remnant","Judah","Lord","God","Israel","Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exile_return","exodus_pattern"]},"16":{"text":"Then it shall come to pass, that the sword, which ye feared, shall overtake you there in the land of Egypt, and the famine, whereof ye were afraid, shall follow close after you there in Egypt; and there ye shall die.","ref":"Jeremiah 42:16","synthesized":"then the sword you fear will overtake you there, and the famine you dread will follow on your heels into Egypt, and you will die there.","sources":{"KJV":{"text":"Then it shall come to pass, that the sword, which ye feared, shall overtake you there in the land of Egypt, and the famine, whereof ye were afraid, shall follow close after you there in Egypt; and there ye shall die."},"BSB":{"text":"then the sword you fear will overtake you there, and the famine you dread will follow on your heels into Egypt, and you will die there."},"TANAKH":{"text":"then it shall come to pass, that the sword, which ye fear, shall overtake you there in the land of Egypt, and the famine, whereof ye are afraid, shall follow hard after you there in Egypt; and there ye shall die."},"HEBREW":{"text":"וְהָיְתָ֣ה הַחֶ֗רֶב אֲשֶׁ֤ר אַתֶּם֙ יְרֵאִ֣ים מִמֶּ֔נָּה שָׁ֛ם תַּשִּׂ֥יג אֶתְכֶ֖ם בְּאֶ֣רֶץ מִצְרָ֑יִם וְהָרָעָ֞ב אֲשֶׁר־אַתֶּ֣ם ׀ דֹּאֲגִ֣ים מִמֶּ֗נּוּ שָׁ֣ם יִדְבַּ֧ק אַחֲרֵיכֶ֛ם מִצְרַ֖יִם וְשָׁ֥ם תָּמֻֽתוּ׃"}},"definableWords":["fear","Egypt","die"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","fear_of_lord"]},"17":{"text":"So shall it be with all the men that set their faces to go into Egypt to sojourn there; they shall die by the sword, by the famine, and by the pestilence: and none of them shall remain or escape from the evil that I will bring upon them.","ref":"Jeremiah 42:17","synthesized":"So all who resolve to go to Egypt to reside there will die by sword and famine and plague. Not one of them will survive or escape the disaster I will bring upon them.’","sources":{"KJV":{"text":"So shall it be with all the men that set their faces to go into Egypt to sojourn there; they shall die by the sword, by the famine, and by the pestilence: and none of them shall remain or escape from the evil that I will bring upon them."},"BSB":{"text":"So all who resolve to go to Egypt to reside there will die by sword and famine and plague. Not one of them will survive or escape the disaster I will bring upon them.’"},"TANAKH":{"text":"So shall it be with all the men that set their faces to go into Egypt to sojourn there; they shall die by the sword, by the famine, and by the pestilence; and none of them shall remain or escape from the evil that I will bring upon them."},"HEBREW":{"text":"וְיִֽהְי֣וּ כָל־הָאֲנָשִׁ֗ים אֲשֶׁר־שָׂ֨מוּ אֶת־פְּנֵיהֶ֜ם לָב֤וֹא מִצְרַ֙יִם֙ לָג֣וּר שָׁ֔ם יָמ֕וּתוּ בַּחֶ֖רֶב בָּרָעָ֣ב וּבַדָּ֑בֶר וְלֹֽא־יִהְיֶ֤ה לָהֶם֙ שָׂרִ֣יד וּפָלִ֔יט מִפְּנֵי֙ הָֽרָעָ֔ה אֲשֶׁ֥ר אֲנִ֖י מֵבִ֥יא עֲלֵיהֶֽם׃"}},"definableWords":["Egypt","die","one","or"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern"]},"18":{"text":"For thus saith the LORD of hosts, the God of Israel; As mine anger and my fury hath been poured forth upon the inhabitants of Jerusalem; so shall my fury be poured forth upon you, when ye shall enter into Egypt: and ye shall be an execration, and an astonishment, and a curse, and a reproach; and ye shall see this place no more.","ref":"Jeremiah 42:18","synthesized":"For this is what the LORD of Hosts, the God of Israel, says: ‘Just as My anger and wrath were poured out on the residents of Jerusalem, so will My wrath be poured out on you if you go to Egypt. You will become an object of cursing and horror, of vilification and disgrace, and you will never see this place again.’","sources":{"KJV":{"text":"For thus saith the LORD of hosts, the God of Israel; As mine anger and my fury hath been poured forth upon the inhabitants of Jerusalem; so shall my fury be poured forth upon you, when ye shall enter into Egypt: and ye shall be an execration, and an astonishment, and a curse, and a reproach; and ye shall see this place no more."},"BSB":{"text":"For this is what the LORD of Hosts, the God of Israel, says: ‘Just as My anger and wrath were poured out on the residents of Jerusalem, so will My wrath be poured out on you if you go to Egypt. You will become an object of cursing and horror, of vilification and disgrace, and you will never see this place again.’"},"TANAKH":{"text":"For thus saith HaShem of hosts, the G-d of Israel: As Mine anger and My fury hath been poured forth upon the inhabitants of Jerusalem, so shall My fury be poured forth upon you, when ye shall enter into Egypt; and ye shall be an execration, and an astonishment, and a curse, and a reproach; and ye shall see this place no more."},"HEBREW":{"text":"כִּי֩ כֹ֨ה אָמַ֜ר יְהוָ֣ה צְבָאוֹת֮ אֱלֹהֵ֣י יִשְׂרָאֵל֒ כַּאֲשֶׁר֩ נִתַּ֨ךְ אַפִּ֜י וַחֲמָתִ֗י עַל־יֹֽשְׁבֵי֙ יְר֣וּשָׁלִַ֔ם כֵּ֣ן תִּתַּ֤ךְ חֲמָתִי֙ עֲלֵיכֶ֔ם בְּבֹאֲכֶ֖ם מִצְרָ֑יִם וִהְיִיתֶ֞ם לְאָלָ֤ה וּלְשַׁמָּה֙ וְלִקְלָלָ֣ה וּלְחֶרְפָּ֔ה וְלֹֽא־תִרְא֣וּ ע֔וֹד אֶת־הַמָּק֖וֹם הַזֶּֽה׃"}},"definableWords":["LORD","God","Israel","anger","wrath","Jerusalem","Egypt","see"],"peopleInVerse":[],"placesInVerse":["Jerusalem","Egypt"],"themesInVerse":["exodus_pattern","judgment"]},"19":{"text":"The LORD hath said concerning you, O ye remnant of Judah; Go ye not into Egypt: know certainly that I have admonished you this day.","ref":"Jeremiah 42:19","synthesized":"The LORD has told you, O remnant of Judah, ‘Do not go to Egypt.’ Know for sure that I have warned you today!","sources":{"KJV":{"text":"The LORD hath said concerning you, O ye remnant of Judah; Go ye not into Egypt: know certainly that I have admonished you this day."},"BSB":{"text":"The LORD has told you, O remnant of Judah, ‘Do not go to Egypt.’ Know for sure that I have warned you today!"},"TANAKH":{"text":"HaShem hath spoken concerning you, O remnant of Judah: Go ye not into Egypt; know certainly that I have forewarned you this day."},"HEBREW":{"text":"דִּבֶּ֨ר יְהוָ֤ה עֲלֵיכֶם֙ שְׁאֵרִ֣ית יְהוּדָ֔ה אַל־תָּבֹ֖אוּ מִצְרָ֑יִם יָדֹ֙עַ֙ תֵּֽדְע֔וּ כִּי־הַעִידֹ֥תִי בָכֶ֖ם הַיּֽוֹם׃"}},"definableWords":["LORD","remnant","Judah","Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exile_return","exodus_pattern"]},"20":{"text":"For ye dissembled in your hearts, when ye sent me unto the LORD your God, saying, Pray for us unto the LORD our God; and according unto all that the LORD our God shall say, so declare unto us, and we will do it.","ref":"Jeremiah 42:20","synthesized":"For you have deceived yourselves by sending me to the LORD your God, saying, ‘Pray to the LORD our God on our behalf, and as for all that the LORD our God says, tell it to us and we will do it.’","sources":{"KJV":{"text":"For ye dissembled in your hearts, when ye sent me unto the LORD your God, saying, Pray for us unto the LORD our God; and according unto all that the LORD our God shall say, so declare unto us, and we will do it."},"BSB":{"text":"For you have deceived yourselves by sending me to the LORD your God, saying, ‘Pray to the LORD our God on our behalf, and as for all that the LORD our God says, tell it to us and we will do it.’"},"TANAKH":{"text":"For ye have dealt deceitfully against your own souls; for ye sent me unto HaShem your G-d, saying: Pray for us unto HaShem our G-d; and according unto all that HaShem our G-d shall say, so declare unto us, and we will do it;"},"HEBREW":{"text":"כִּ֣י התעתים הִתְעֵיתֶם֮ בְּנַפְשֽׁוֹתֵיכֶם֒ כִּֽי־אַתֶּ֞ם שְׁלַחְתֶּ֣ם אֹתִ֗י אֶל־יְהוָ֤ה אֱלֹֽהֵיכֶם֙ לֵאמֹ֔ר הִתְפַּלֵּ֣ל בַּעֲדֵ֔נוּ אֶל־יְהוָ֖ה אֱלֹהֵ֑ינוּ וּכְכֹל֩ אֲשֶׁ֨ר יֹאמַ֜ר יְהוָ֧ה אֱלֹהֵ֛ינוּ כֵּ֥ן הַגֶּד־לָ֖נוּ וְעָשִֽׂינוּ׃"}},"definableWords":["LORD","God","Lord"],"peopleInVerse":[],"themesInVerse":["prayer"]},"21":{"text":"And now I have this day declared it to you; but ye have not obeyed the voice of the LORD your God, nor any thing for the which he hath sent me unto you.","ref":"Jeremiah 42:21","synthesized":"For I have told you today, but you have not obeyed the voice of the LORD your God in all He has sent me to tell you.","sources":{"KJV":{"text":"And now I have this day declared it to you; but ye have not obeyed the voice of the LORD your God, nor any thing for the which he hath sent me unto you."},"BSB":{"text":"For I have told you today, but you have not obeyed the voice of the LORD your God in all He has sent me to tell you."},"TANAKH":{"text":"and I have this day declared it to you; but ye have not hearkened to the voice of HaShem your G-d in any thing for which He hath sent me unto you."},"HEBREW":{"text":"וָאַגִּ֥ד לָכֶ֖ם הַיּ֑וֹם וְלֹ֣א שְׁמַעְתֶּ֗ם בְּקוֹל֙ יְהוָ֣ה אֱלֹֽהֵיכֶ֔ם וּלְכֹ֖ל אֲשֶׁר־שְׁלָחַ֥נִי אֲלֵיכֶֽם׃"}},"definableWords":["voice","LORD","God"],"peopleInVerse":[]},"22":{"text":"Now therefore know certainly that ye shall die by the sword, by the famine, and by the pestilence, in the place whither ye desire to go and to sojourn.","ref":"Jeremiah 42:22","synthesized":"Now therefore, know for sure that by sword and famine and plague you will die in the place where you desire to go to reside.”","sources":{"KJV":{"text":"Now therefore know certainly that ye shall die by the sword, by the famine, and by the pestilence, in the place whither ye desire to go and to sojourn."},"BSB":{"text":"Now therefore, know for sure that by sword and famine and plague you will die in the place where you desire to go to reside.”"},"TANAKH":{"text":"Now therefore know certainly that ye shall die by the sword, by the famine, and by the pestilence, in the place whither ye desire to go to sojourn there.'"},"HEBREW":{"text":"וְעַתָּה֙ יָדֹ֣עַ תֵּֽדְע֔וּ כִּ֗י בַּחֶ֛רֶב בָּרָעָ֥ב וּבַדֶּ֖בֶר תָּמ֑וּתוּ בַּמָּקוֹם֙ אֲשֶׁ֣ר חֲפַצְתֶּ֔ם לָב֖וֹא לָג֥וּר שָֽׁם׃"}},"definableWords":["die"],"peopleInVerse":[]}}},"43":{"chapter":"43","title":"JEREMIAH TAKEN TO EGYPT","verses":{"1":{"text":"And it came to pass, that when Jeremiah had made an end of speaking unto all the people all the words of the LORD their God, for which the LORD their God had sent him to them, even all these words,","ref":"Jeremiah 43:1","synthesized":"When Jeremiah had finished telling all the people all the words of the LORD their God—everything that the LORD had sent him to say—","sources":{"KJV":{"text":"And it came to pass, that when Jeremiah had made an end of speaking unto all the people all the words of the LORD their God, for which the LORD their God had sent him to them, even all these words,"},"BSB":{"text":"When Jeremiah had finished telling all the people all the words of the LORD their God—everything that the LORD had sent him to say—"},"TANAKH":{"text":"And it came to pass, that when Jeremiah had made an end of speaking unto all the people all the words of HaShem their G-d, wherewith HaShem their G-d had sent him to them, even all these words,"},"HEBREW":{"text":"וַיְהִי֩ כְּכַלּ֨וֹת יִרְמְיָ֜הוּ לְדַבֵּ֣ר אֶל־כָּל־הָעָ֗ם אֶת־כָּל־דִּבְרֵי֙ יְהוָ֣ה אֱלֹהֵיהֶ֔ם אֲשֶׁ֧ר שְׁלָח֛וֹ יְהוָ֥ה אֱלֹהֵיהֶ֖ם אֲלֵיהֶ֑ם אֵ֥ת כָּל־הַדְּבָרִ֖ים הָאֵֽלֶּה׃"}},"definableWords":["people","LORD","God","Lord"],"peopleInVerse":["Jeremiah"]},"2":{"text":"Then spake Azariah the son of Hoshaiah, and Johanan the son of Kareah, and all the proud men, saying unto Jeremiah, Thou speakest falsely: the LORD our God hath not sent thee to say, Go not into Egypt to sojourn there:","ref":"Jeremiah 43:2","synthesized":"Azariah son of Hoshaiah, Johanan son of Kareah, and all the arrogant men said to Jeremiah, “You are lying! The LORD our God has not sent you to say, ‘You must not go to Egypt to reside there.’","sources":{"KJV":{"text":"Then spake Azariah the son of Hoshaiah, and Johanan the son of Kareah, and all the proud men, saying unto Jeremiah, Thou speakest falsely: the LORD our God hath not sent thee to say, Go not into Egypt to sojourn there:"},"BSB":{"text":"Azariah son of Hoshaiah, Johanan son of Kareah, and all the arrogant men said to Jeremiah, “You are lying! The LORD our God has not sent you to say, ‘You must not go to Egypt to reside there.’"},"TANAKH":{"text":"then spoke Azariah the son of Hoshaiah, and Johanan the son of Kareah, and all the proud men, saying unto Jeremiah: 'Thou speakest falsely; HaShem our G-d hath not sent thee to say: Ye shall not go into Egypt to sojourn there;"},"HEBREW":{"text":"וַיֹּ֨אמֶר עֲזַרְיָ֤ה בֶן־הוֹשַֽׁעְיָה֙ וְיוֹחָנָ֣ן בֶּן־קָרֵ֔חַ וְכָל־הָאֲנָשִׁ֖ים הַזֵּדִ֑ים אֹמְרִ֣ים אֶֽל־יִרְמְיָ֗הוּ שֶׁ֚קֶר אַתָּ֣ה מְדַבֵּ֔ר לֹ֣א שְׁלָחֲךָ֞ יְהוָ֤ה אֱלֹהֵ֙ינוּ֙ לֵאמֹ֔ר לֹֽא־תָבֹ֥אוּ מִצְרַ֖יִם לָג֥וּר שָֽׁם׃"}},"definableWords":["son","Son","men","LORD","God","Egypt"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern"]},"3":{"text":"But Baruch the son of Neriah setteth thee on against us, for to deliver us into the hand of the Chaldeans, that they might put us to death, and carry us away captives into Babylon.","ref":"Jeremiah 43:3","synthesized":"Rather, Baruch son of Neriah is inciting you against us to deliver us into the hands of the Chaldeans, so that they may put us to death or exile us to Babylon!”","sources":{"KJV":{"text":"But Baruch the son of Neriah setteth thee on against us, for to deliver us into the hand of the Chaldeans, that they might put us to death, and carry us away captives into Babylon."},"BSB":{"text":"Rather, Baruch son of Neriah is inciting you against us to deliver us into the hands of the Chaldeans, so that they may put us to death or exile us to Babylon!”"},"TANAKH":{"text":"but Baruch the son of Neriah setteth thee on against us, to deliver us into the hand of the Chaldeans, that they may put us to death, and carry us away captives to Babylon.'"},"HEBREW":{"text":"כִּ֗י בָּרוּךְ֙ בֶּן־נֵ֣רִיָּ֔ה מַסִּ֥ית אֹתְךָ֖ בָּ֑נוּ לְמַעַן֩ תֵּ֨ת אֹתָ֤נוּ בְיַֽד־הַכַּשְׂדִּים֙ לְהָמִ֣ית אֹתָ֔נוּ וּלְהַגְל֥וֹת אֹתָ֖נוּ בָּבֶֽל׃"}},"definableWords":["baruch","son","deliver","death","or","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["exile_return","redemption","salvation"]},"4":{"text":"So Johanan the son of Kareah, and all the captains of the forces, and all the people, obeyed not the voice of the LORD, to dwell in the land of Judah.","ref":"Jeremiah 43:4","synthesized":"So Johanan son of Kareah and all the commanders of the forces disobeyed the command of the LORD to stay in the land of Judah.","sources":{"KJV":{"text":"So Johanan the son of Kareah, and all the captains of the forces, and all the people, obeyed not the voice of the LORD, to dwell in the land of Judah."},"BSB":{"text":"So Johanan son of Kareah and all the commanders of the forces disobeyed the command of the LORD to stay in the land of Judah."},"TANAKH":{"text":"So Johanan the son of Kareah, and all the captains of the forces, and all the people, hearkened not to the voice of HaShem, to dwell in the land of Judah."},"HEBREW":{"text":"וְלֹֽא־שָׁמַע֩ יוֹחָנָ֨ן בֶּן־קָרֵ֜חַ וְכָל־שָׂרֵ֧י הַחֲיָלִ֛ים וְכָל־הָעָ֖ם בְּק֣וֹל יְהוָ֑ה לָשֶׁ֖בֶת בְּאֶ֥רֶץ יְהוּדָֽה׃"}},"definableWords":["son","LORD","land","Judah"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"5":{"text":"But Johanan the son of Kareah, and all the captains of the forces, took all the remnant of Judah, that were returned from all nations, whither they had been driven, to dwell in the land of Judah;","ref":"Jeremiah 43:5","synthesized":"Instead, Johanan son of Kareah and all the commanders of the forces took the whole remnant of Judah, those who had returned to the land of Judah from all the nations to which they had been scattered,","sources":{"KJV":{"text":"But Johanan the son of Kareah, and all the captains of the forces, took all the remnant of Judah, that were returned from all nations, whither they had been driven, to dwell in the land of Judah;"},"BSB":{"text":"Instead, Johanan son of Kareah and all the commanders of the forces took the whole remnant of Judah, those who had returned to the land of Judah from all the nations to which they had been scattered,"},"TANAKH":{"text":"But Johanan the son of Kareah, and all the captains of the forces, took all the remnant of Judah, that were returned from all the nations whither they had been driven to sojourn in the land of Judah:"},"HEBREW":{"text":"וַיִּקַּ֞ח יוֹחָנָ֤ן בֶּן־קָרֵ֙חַ֙ וְכָל־שָׂרֵ֣י הַחֲיָלִ֔ים אֵ֖ת כָּל־שְׁאֵרִ֣ית יְהוּדָ֑ה אֲשֶׁר־שָׁ֗בוּ מִכָּל־הַגּוֹיִם֙ אֲשֶׁ֣ר נִדְּחוּ־שָׁ֔ם לָג֖וּר בְּאֶ֥רֶץ יְהוּדָֽה׃"}},"definableWords":["son","remnant","Judah","land","nations"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise"]},"6":{"text":"Even men, and women, and children, and the king’s daughters, and every person that Nebuzaradan the captain of the guard had left with Gedaliah the son of Ahikam the son of Shaphan, and Jeremiah the prophet, and Baruch the son of Neriah.","ref":"Jeremiah 43:6","synthesized":"the men, the women, the children, the king’s daughters, and everyone whom Nebuzaradan captain of the guard had allowed to remain with Gedaliah son of Ahikam, the son of Shaphan, as well as Jeremiah the prophet and Baruch son of Neriah.","sources":{"KJV":{"text":"Even men, and women, and children, and the king’s daughters, and every person that Nebuzaradan the captain of the guard had left with Gedaliah the son of Ahikam the son of Shaphan, and Jeremiah the prophet, and Baruch the son of Neriah."},"BSB":{"text":"the men, the women, the children, the king’s daughters, and everyone whom Nebuzaradan captain of the guard had allowed to remain with Gedaliah son of Ahikam, the son of Shaphan, as well as Jeremiah the prophet and Baruch son of Neriah."},"TANAKH":{"text":"the men, and the women, and the children, and the king's daughters, and every person that Nebuzaradan the captain of the guard had left with Gedaliah the son of Ahikam, the son of Shaphan, and Jeremiah the prophet, and Baruch the son of Neriah;"},"HEBREW":{"text":"אֶֽת־הַ֠גְּבָרִים וְאֶת־הַנָּשִׁ֣ים וְאֶת־הַטַּף֮ וְאֶת־בְּנ֣וֹת הַמֶּלֶךְ֒ וְאֵ֣ת כָּל־הַנֶּ֗פֶשׁ אֲשֶׁ֤ר הִנִּ֙יחַ֙ נְבוּזַרְאֲדָ֣ן רַב־טַבָּחִ֔ים אֶת־גְּדַלְיָ֖הוּ בֶּן־אֲחִיקָ֣ם בֶּן־שָׁפָ֑ן וְאֵת֙ יִרְמְיָ֣הוּ הַנָּבִ֔יא וְאֶת־בָּר֖וּךְ בֶּן־נֵרִיָּֽהוּ׃"}},"definableWords":["men","women","king","daughters","son","Son","prophet","baruch"],"peopleInVerse":["Jeremiah"],"themesInVerse":["bread_water_life","kingship"]},"7":{"text":"So they came into the land of Egypt: for they obeyed not the voice of the LORD: thus came they even to Tahpanhes.","ref":"Jeremiah 43:7","synthesized":"So they entered the land of Egypt because they did not obey the voice of the LORD, and they went as far as Tahpanhes.","sources":{"KJV":{"text":"So they came into the land of Egypt: for they obeyed not the voice of the LORD: thus came they even to Tahpanhes."},"BSB":{"text":"So they entered the land of Egypt because they did not obey the voice of the LORD, and they went as far as Tahpanhes."},"TANAKH":{"text":"and they came into the land of Egypt; for they hearkened not to the voice of HaShem; and they came even to Tahpanhes."},"HEBREW":{"text":"וַיָּבֹ֙אוּ֙ אֶ֣רֶץ מִצְרַ֔יִם כִּ֛י לֹ֥א שָׁמְע֖וּ בְּק֣וֹל יְהוָ֑ה וַיָּבֹ֖אוּ עַד־תַּחְפַּנְחֵֽס׃"}},"definableWords":["land","Egypt","voice","LORD"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"8":{"text":"Then came the word of the LORD unto Jeremiah in Tahpanhes, saying,","ref":"Jeremiah 43:8","synthesized":"Then the word of the LORD came to Jeremiah at Tahpanhes:","sources":{"KJV":{"text":"Then came the word of the LORD unto Jeremiah in Tahpanhes, saying,"},"BSB":{"text":"Then the word of the LORD came to Jeremiah at Tahpanhes:"},"TANAKH":{"text":"Then came the word of HaShem unto Jeremiah in Tahpanhes, saying:"},"HEBREW":{"text":"וַיְהִ֤י דְבַר־יְהוָה֙ אֶֽל־יִרְמְיָ֔הוּ בְּתַחְפַּנְחֵ֖ס לֵאמֹֽר׃"}},"definableWords":["word","LORD"],"peopleInVerse":["Jeremiah"]},"9":{"text":"Take great stones in thine hand, and hide them in the clay in the brickkiln, which is at the entry of Pharaoh’s house in Tahpanhes, in the sight of the men of Judah;","ref":"Jeremiah 43:9","synthesized":"“In the sight of the Jews, pick up some large stones and bury them in the clay of the brick pavement at the entrance to Pharaoh’s palace at Tahpanhes.","sources":{"KJV":{"text":"Take great stones in thine hand, and hide them in the clay in the brickkiln, which is at the entry of Pharaoh’s house in Tahpanhes, in the sight of the men of Judah;"},"BSB":{"text":"“In the sight of the Jews, pick up some large stones and bury them in the clay of the brick pavement at the entrance to Pharaoh’s palace at Tahpanhes."},"TANAKH":{"text":"'Take great stones in thy hand, and hide them in the mortar in the framework, which is at the entry of Pharaoh's house in Tahpanhes, in the sight of the men of Judah;"},"HEBREW":{"text":"קַ֣ח בְּיָדְךָ֞ אֲבָנִ֣ים גְּדֹל֗וֹת וּטְמַנְתָּ֤ם בַּמֶּ֙לֶט֙ בַּמַּלְבֵּ֔ן אֲשֶׁ֛ר בְּפֶ֥תַח בֵּית־פַּרְעֹ֖ה בְּתַחְפַּנְחֵ֑ס לְעֵינֵ֖י אֲנָשִׁ֥ים יְהוּדִֽים׃"}},"definableWords":["Pharaoh"],"peopleInVerse":["Pharaoh"]},"10":{"text":"And say unto them, Thus saith the LORD of hosts, the God of Israel; Behold, I will send and take Nebuchadrezzar the king of Babylon, my servant, and will set his throne upon these stones that I have hid; and he shall spread his royal pavilion over them.","ref":"Jeremiah 43:10","synthesized":"Then tell them that this is what the LORD of Hosts, the God of Israel, says: ‘I will send for My servant Nebuchadnezzar king of Babylon, and I will set his throne over these stones that I have embedded, and he will spread his royal pavilion over them.","sources":{"KJV":{"text":"And say unto them, Thus saith the LORD of hosts, the God of Israel; Behold, I will send and take Nebuchadrezzar the king of Babylon, my servant, and will set his throne upon these stones that I have hid; and he shall spread his royal pavilion over them."},"BSB":{"text":"Then tell them that this is what the LORD of Hosts, the God of Israel, says: ‘I will send for My servant Nebuchadnezzar king of Babylon, and I will set his throne over these stones that I have embedded, and he will spread his royal pavilion over them."},"TANAKH":{"text":"and say unto them: Thus saith HaShem of hosts, the G-d of Israel: Behold, I will send and take Nebuchadrezzar the king of Babylon, My servant, and will set his throne upon these stones that I have hid; and he shall spread his royal pavilion over them."},"HEBREW":{"text":"וְאָמַרְתָּ֣ אֲלֵיהֶ֡ם כֹּֽה־אָמַר֩ יְהוָ֨ה צְבָא֜וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֗ל הִנְנִ֤י שֹׁלֵ֙חַ֙ וְ֠לָקַחְתִּי אֶת־נְבוּכַדְרֶאצַּ֤ר מֶֽלֶךְ־בָּבֶל֙ עַבְדִּ֔י וְשַׂמְתִּ֣י כִסְא֔וֹ מִמַּ֛עַל לָאֲבָנִ֥ים הָאֵ֖לֶּה אֲשֶׁ֣ר טָמָ֑נְתִּי וְנָטָ֥ה אֶת־שפרורו שַׁפְרִיר֖וֹ עֲלֵיהֶֽם׃"}},"definableWords":["LORD","God","Israel","servant","king","Babylon","throne"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingdom_of_god","kingship"]},"11":{"text":"And when he cometh, he shall smite the land of Egypt, and deliver such as are for death to death; and such as are for captivity to captivity; and such as are for the sword to the sword.","ref":"Jeremiah 43:11","synthesized":"He will come and strike down the land of Egypt, bringing death to those destined for death, captivity to those destined for captivity, and the sword to those destined for the sword.","sources":{"KJV":{"text":"And when he cometh, he shall smite the land of Egypt, and deliver such as are for death to death; and such as are for captivity to captivity; and such as are for the sword to the sword."},"BSB":{"text":"He will come and strike down the land of Egypt, bringing death to those destined for death, captivity to those destined for captivity, and the sword to those destined for the sword."},"TANAKH":{"text":"And he shall come, and shall smite the land of Egypt; such as are for death to death, and such as are for captivity to captivity, and such as are for the sword to the sword."},"HEBREW":{"text":"ובאה וּבָ֕א וְהִכָּ֖ה אֶת־אֶ֣רֶץ מִצְרָ֑יִם אֲשֶׁ֧ר לַמָּ֣וֶת לַמָּ֗וֶת וַאֲשֶׁ֤ר לַשְּׁבִי֙ לַשֶּׁ֔בִי וַאֲשֶׁ֥ר לַחֶ֖רֶב לֶחָֽרֶב׃"}},"definableWords":["land","Egypt","death"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exile_return","exodus_pattern","land_promise"]},"12":{"text":"And I will kindle a fire in the houses of the gods of Egypt; and he shall burn them, and carry them away captives: and he shall array himself with the land of Egypt, as a shepherd putteth on his garment; and he shall go forth from thence in peace.","ref":"Jeremiah 43:12","synthesized":"I will kindle a fire in the temples of the gods of Egypt, and Nebuchadnezzar will burn those temples and take their gods as captives. So he will wrap himself with the land of Egypt as a shepherd wraps himself in his garment, and he will depart from there unscathed.","sources":{"KJV":{"text":"And I will kindle a fire in the houses of the gods of Egypt; and he shall burn them, and carry them away captives: and he shall array himself with the land of Egypt, as a shepherd putteth on his garment; and he shall go forth from thence in peace."},"BSB":{"text":"I will kindle a fire in the temples of the gods of Egypt, and Nebuchadnezzar will burn those temples and take their gods as captives. So he will wrap himself with the land of Egypt as a shepherd wraps himself in his garment, and he will depart from there unscathed."},"TANAKH":{"text":"And I will kindle a fire in the houses of the gods of Egypt; and he shall burn them, and carry them away captives; and he shall fold up the land of Egypt, as a shepherd foldeth up his garment; and he shall go forth from thence in peace."},"HEBREW":{"text":"וְהִצַּ֣תִּי אֵ֗שׁ בְּבָתֵּי֙ אֱלֹהֵ֣י מִצְרַ֔יִם וּשְׂרָפָ֖ם וְשָׁבָ֑ם וְעָטָה֩ אֶת־אֶ֨רֶץ מִצְרַ֜יִם כַּאֲשֶׁר־יַעְטֶ֤ה הָֽרֹעֶה֙ אֶת־בִּגְד֔וֹ וְיָצָ֥א מִשָּׁ֖ם בְּשָׁלֽוֹם׃"}},"definableWords":["Egypt","land","shepherd"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise","shepherd_sheep"]},"13":{"text":"He shall break also the images of Bethshemesh, that is in the land of Egypt; and the houses of the gods of the Egyptians shall he burn with fire.","ref":"Jeremiah 43:13","synthesized":"He will demolish the sacred pillars of the temple of the sun in the land of Egypt, and he will burn down the temples of the gods of Egypt.’”","sources":{"KJV":{"text":"He shall break also the images of Bethshemesh, that is in the land of Egypt; and the houses of the gods of the Egyptians shall he burn with fire."},"BSB":{"text":"He will demolish the sacred pillars of the temple of the sun in the land of Egypt, and he will burn down the temples of the gods of Egypt.’”"},"TANAKH":{"text":"He shall also break the pillars of Beth-shemesh, that is in the land of Egypt; and the houses of the gods of Egypt shall he burn with fire.'"},"HEBREW":{"text":"וְשִׁבַּ֗ר אֶֽת־מַצְּבוֹת֙ בֵּ֣ית שֶׁ֔מֶשׁ אֲשֶׁ֖ר בְּאֶ֣רֶץ מִצְרָ֑יִם וְאֶת־בָּתֵּ֥י אֱלֹהֵֽי־מִצְרַ֖יִם יִשְׂרֹ֥ף בָּאֵֽשׁ׃"}},"definableWords":["temple","land","Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise","temple"]}}},"44":{"chapter":"44","title":"JUDGMENT ON THE JEWS IN EGYPT","verses":{"1":{"text":"The word that came to Jeremiah concerning all the Jews which dwell in the land of Egypt, which dwell at Migdol, and at Tahpanhes, and at Noph, and in the country of Pathros, saying,","ref":"Jeremiah 44:1","synthesized":"This is the word that came to Jeremiah concerning all the Jews living in the land of Egypt—in Migdol, Tahpanhes, and Memphis—and in the land of Pathros:","sources":{"KJV":{"text":"The word that came to Jeremiah concerning all the Jews which dwell in the land of Egypt, which dwell at Migdol, and at Tahpanhes, and at Noph, and in the country of Pathros, saying,"},"BSB":{"text":"This is the word that came to Jeremiah concerning all the Jews living in the land of Egypt—in Migdol, Tahpanhes, and Memphis—and in the land of Pathros:"},"TANAKH":{"text":"The word that came to Jeremiah concerning all the Jews that dwelt in the land of Egypt, that dwelt at Migdol, and at Tahpanhes, and at Noph, and in the country of Pathros, saying:"},"HEBREW":{"text":"הַדָּבָר֙ אֲשֶׁ֣ר הָיָ֣ה אֶֽל־יִרְמְיָ֔הוּ אֶ֚ל כָּל־הַיְּהוּדִ֔ים הַיֹּשְׁבִ֖ים בְּאֶ֣רֶץ מִצְרָ֑יִם הַיֹּשְׁבִ֤ים בְּמִגְדֹּל֙ וּבְתַחְפַּנְחֵ֣ס וּבְנֹ֔ף וּבְאֶ֥רֶץ פַּתְר֖וֹס לֵאמֹֽר׃"}},"definableWords":["word","living","land","Egypt"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"2":{"text":"Thus saith the LORD of hosts, the God of Israel; Ye have seen all the evil that I have brought upon Jerusalem, and upon all the cities of Judah; and, behold, this day they are a desolation, and no man dwelleth therein,","ref":"Jeremiah 44:2","synthesized":"“This is what the LORD of Hosts, the God of Israel, says: You have seen all the disaster that I brought against Jerusalem and all the cities of Judah; and behold, they lie today in ruins and desolation","sources":{"KJV":{"text":"Thus saith the LORD of hosts, the God of Israel; Ye have seen all the evil that I have brought upon Jerusalem, and upon all the cities of Judah; and, behold, this day they are a desolation, and no man dwelleth therein,"},"BSB":{"text":"“This is what the LORD of Hosts, the God of Israel, says: You have seen all the disaster that I brought against Jerusalem and all the cities of Judah; and behold, they lie today in ruins and desolation"},"TANAKH":{"text":"'Thus saith HaShem of hosts, the G-d of Israel: Ye have seen all the evil that I have brought upon Jerusalem, and upon all the cities of Judah; and, behold, this day they are a desolation, and no man dwelleth therein;"},"HEBREW":{"text":"כֹּה־אָמַ֞ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל אַתֶּ֣ם רְאִיתֶ֗ם אֵ֤ת כָּל־הָֽרָעָה֙ אֲשֶׁ֤ר הֵבֵ֙אתִי֙ עַל־יְר֣וּשָׁלִַ֔ם וְעַ֖ל כָּל־עָרֵ֣י יְהוּדָ֑ה וְהִנָּ֤ם חָרְבָּה֙ הַיּ֣וֹם הַזֶּ֔ה וְאֵ֥ין בָּהֶ֖ם יוֹשֵֽׁב׃"}},"definableWords":["LORD","God","Israel","Jerusalem","Judah"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"3":{"text":"Because of their wickedness which they have committed to provoke me to anger, in that they went to burn incense, and to serve other gods, whom they knew not, neither they, ye, nor your fathers.","ref":"Jeremiah 44:3","synthesized":"because of the evil they have done.  They provoked Me to anger by continuing to burn incense and to serve other gods that neither they nor you nor your fathers ever knew.","sources":{"KJV":{"text":"Because of their wickedness which they have committed to provoke me to anger, in that they went to burn incense, and to serve other gods, whom they knew not, neither they, ye, nor your fathers."},"BSB":{"text":"because of the evil they have done.  They provoked Me to anger by continuing to burn incense and to serve other gods that neither they nor you nor your fathers ever knew."},"TANAKH":{"text":"because of their wickedness which they have committed to provoke Me, in that they went to offer, and to serve other gods, whom they knew not, neither they, nor ye, nor your fathers."},"HEBREW":{"text":"מִפְּנֵ֣י רָעָתָ֗ם אֲשֶׁ֤ר עָשׂוּ֙ לְהַכְעִסֵ֔נִי לָלֶ֣כֶת לְקַטֵּ֔ר לַעֲבֹ֖ד לֵאלֹהִ֣ים אֲחֵרִ֑ים אֲשֶׁר֙ לֹ֣א יְדָע֔וּם הֵ֖מָּה אַתֶּ֥ם וַאֲבֹתֵיכֶֽם׃"}},"definableWords":["evil","anger","incense","fathers"],"peopleInVerse":[]},"4":{"text":"Howbeit I sent unto you all my servants the prophets, rising early and sending them, saying, Oh, do not this abominable thing that I hate.","ref":"Jeremiah 44:4","synthesized":"Yet I sent you all My servants the prophets again and again, saying: ‘Do not do this detestable thing that I hate.’","sources":{"KJV":{"text":"Howbeit I sent unto you all my servants the prophets, rising early and sending them, saying, Oh, do not this abominable thing that I hate."},"BSB":{"text":"Yet I sent you all My servants the prophets again and again, saying: ‘Do not do this detestable thing that I hate.’"},"TANAKH":{"text":"Howbeit I sent unto you all My servants the prophets, sending them betimes and often, saying: Oh, do not this abominable thing that I hate."},"HEBREW":{"text":"וָאֶשְׁלַ֤ח אֲלֵיכֶם֙ אֶת־כָּל־עֲבָדַ֣י הַנְּבִיאִ֔ים הַשְׁכֵּ֥ים וְשָׁלֹ֖חַ לֵאמֹ֑ר אַל־נָ֣א תַעֲשׂ֗וּ אֵ֛ת דְּבַֽר־הַתֹּעֵבָ֥ה הַזֹּ֖את אֲשֶׁ֥ר שָׂנֵֽאתִי׃"}},"definableWords":["servants"],"peopleInVerse":[]},"5":{"text":"But they hearkened not, nor inclined their ear to turn from their wickedness, to burn no incense unto other gods.","ref":"Jeremiah 44:5","synthesized":"But they did not listen or incline their ears; they did not turn from their wickedness or stop burning incense to other gods.","sources":{"KJV":{"text":"But they hearkened not, nor inclined their ear to turn from their wickedness, to burn no incense unto other gods."},"BSB":{"text":"But they did not listen or incline their ears; they did not turn from their wickedness or stop burning incense to other gods."},"TANAKH":{"text":"But they hearkened not, nor inclined their ear to turn from their wickedness, to forbear offering unto other gods."},"HEBREW":{"text":"וְלֹ֤א שָֽׁמְעוּ֙ וְלֹא־הִטּ֣וּ אֶת־אָזְנָ֔ם לָשׁ֖וּב מֵרָֽעָתָ֑ם לְבִלְתִּ֥י קַטֵּ֖ר לֵאלֹהִ֥ים אֲחֵרִֽים׃"}},"definableWords":["or","incense"],"peopleInVerse":[]},"6":{"text":"Wherefore my fury and mine anger was poured forth, and was kindled in the cities of Judah and in the streets of Jerusalem; and they are wasted and desolate, as at this day.","ref":"Jeremiah 44:6","synthesized":"Therefore My wrath and anger poured out and burned in the cities of Judah and in the streets of Jerusalem, so that they have become the desolate ruin they are today.","sources":{"KJV":{"text":"Wherefore my fury and mine anger was poured forth, and was kindled in the cities of Judah and in the streets of Jerusalem; and they are wasted and desolate, as at this day."},"BSB":{"text":"Therefore My wrath and anger poured out and burned in the cities of Judah and in the streets of Jerusalem, so that they have become the desolate ruin they are today."},"TANAKH":{"text":"Wherefore My fury and Mine anger was poured forth, and was kindled in the cities of Judah and in the streets of Jerusalem; and they are wasted and desolate, as at this day."},"HEBREW":{"text":"וַתִּתַּ֤ךְ חֲמָתִי֙ וְאַפִּ֔י וַתִּבְעַר֙ בְּעָרֵ֣י יְהוּדָ֔ה וּבְחֻצ֖וֹת יְרֽוּשָׁלָ֑͏ִם וַתִּהְיֶ֛ינָה לְחָרְבָּ֥ה לִשְׁמָמָ֖ה כַּיּ֥וֹם הַזֶּֽה׃"}},"definableWords":["wrath","anger","Judah","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["judgment"]},"7":{"text":"Therefore now thus saith the LORD, the God of hosts, the God of Israel; Wherefore commit ye this great evil against your souls, to cut off from you man and woman, child and suckling, out of Judah, to leave you none to remain;","ref":"Jeremiah 44:7","synthesized":"So now, this is what the LORD God of Hosts, the God of Israel, says: Why are you doing such great harm to yourselves by cutting off from Judah man and woman, child and infant, leaving yourselves without a remnant?","sources":{"KJV":{"text":"Therefore now thus saith the LORD, the God of hosts, the God of Israel; Wherefore commit ye this great evil against your souls, to cut off from you man and woman, child and suckling, out of Judah, to leave you none to remain;"},"BSB":{"text":"So now, this is what the LORD God of Hosts, the God of Israel, says: Why are you doing such great harm to yourselves by cutting off from Judah man and woman, child and infant, leaving yourselves without a remnant?"},"TANAKH":{"text":"Therefore now thus saith HaShem, the G-d of hosts, the G-d of Israel: Wherefore commit ye this great evil against your own souls, to cut off from you man and woman, infant and suckling, out of the midst of Judah, to leave you none remaining;"},"HEBREW":{"text":"וְעַתָּ֡ה כֹּֽה־אָמַ֣ר יְהוָה֩ אֱלֹהֵ֨י צְבָא֜וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֗ל לָמָה֩ אַתֶּ֨ם עֹשִׂ֜ים רָעָ֤ה גְדוֹלָה֙ אֶל־נַפְשֹׁ֣תֵכֶ֔ם לְהַכְרִ֨ית לָכֶ֧ם אִישׁ־וְאִשָּׁ֛ה עוֹלֵ֥ל וְיוֹנֵ֖ק מִתּ֣וֹךְ יְהוּדָ֑ה לְבִלְתִּ֛י הוֹתִ֥יר לָכֶ֖ם שְׁאֵרִֽית׃"}},"definableWords":["LORD","God","Israel","great","Judah","man","woman","remnant"],"peopleInVerse":[],"themesInVerse":["exile_return"]},"8":{"text":"In that ye provoke me unto wrath with the works of your hands, burning incense unto other gods in the land of Egypt, whither ye be gone to dwell, that ye might cut yourselves off, and that ye might be a curse and a reproach among all the nations of the earth?","ref":"Jeremiah 44:8","synthesized":"Why are you provoking Me to anger by the work of your hands by burning incense to other gods in the land of Egypt, where you have gone to reside?  As a result, you will be cut off and will become an object of cursing and reproach among all the nations of the earth.","sources":{"KJV":{"text":"In that ye provoke me unto wrath with the works of your hands, burning incense unto other gods in the land of Egypt, whither ye be gone to dwell, that ye might cut yourselves off, and that ye might be a curse and a reproach among all the nations of the earth?"},"BSB":{"text":"Why are you provoking Me to anger by the work of your hands by burning incense to other gods in the land of Egypt, where you have gone to reside?  As a result, you will be cut off and will become an object of cursing and reproach among all the nations of the earth."},"TANAKH":{"text":"in that ye provoke Me with the works of your hands, offering unto other gods in the land of Egypt, whither ye are gone to sojourn; that ye may be cut off, and that ye may be a curse and a reproach among all the nations of the earth?"},"HEBREW":{"text":"לְהַכְעִסֵ֙נִי֙ בְּמַעֲשֵׂ֣י יְדֵיכֶ֔ם לְקַטֵּ֞ר לֵאלֹהִ֤ים אֲחֵרִים֙ בְּאֶ֣רֶץ מִצְרַ֔יִם אֲשֶׁר־אַתֶּ֥ם בָּאִ֖ים לָג֣וּר שָׁ֑ם לְמַ֙עַן֙ הַכְרִ֣ית לָכֶ֔ם וּלְמַ֤עַן הֱיֽוֹתְכֶם֙ לִקְלָלָ֣ה וּלְחֶרְפָּ֔ה בְּכֹ֖ל גּוֹיֵ֥י הָאָֽרֶץ׃"}},"definableWords":["anger","work","incense","land","Egypt","nations","earth"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"9":{"text":"Have ye forgotten the wickedness of your fathers, and the wickedness of the kings of Judah, and the wickedness of their wives, and your own wickedness, and the wickedness of your wives, which they have committed in the land of Judah, and in the streets of Jerusalem?","ref":"Jeremiah 44:9","synthesized":"Have you forgotten the wickedness of your fathers and of the kings of Judah and their wives, as well as the wickedness that you and your wives committed in the land of Judah and in the streets of Jerusalem?","sources":{"KJV":{"text":"Have ye forgotten the wickedness of your fathers, and the wickedness of the kings of Judah, and the wickedness of their wives, and your own wickedness, and the wickedness of your wives, which they have committed in the land of Judah, and in the streets of Jerusalem?"},"BSB":{"text":"Have you forgotten the wickedness of your fathers and of the kings of Judah and their wives, as well as the wickedness that you and your wives committed in the land of Judah and in the streets of Jerusalem?"},"TANAKH":{"text":"Have ye forgotten the wicked deeds of your fathers, and the wicked deeds of the kings of Judah, and the wicked deeds of their wives, and your own wicked deeds, and the wicked deeds of your wives, which they committed in the land of Judah, and in the streets of Jerusalem?"},"HEBREW":{"text":"הַֽשְׁכַחְתֶּם֩ אֶת־רָע֨וֹת אֲבוֹתֵיכֶ֜ם וְאֶת־רָע֣וֹת ׀ מַלְכֵ֣י יְהוּדָ֗ה וְאֵת֙ רָע֣וֹת נָשָׁ֔יו וְאֵת֙ רָעֹ֣תֵכֶ֔ם וְאֵ֖ת רָעֹ֣ת נְשֵׁיכֶ֑ם אֲשֶׁ֤ר עָשׂוּ֙ בְּאֶ֣רֶץ יְהוּדָ֔ה וּבְחֻצ֖וֹת יְרוּשָׁלָֽ͏ִם׃"}},"definableWords":["fathers","kings","Judah","land","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["bread_water_life","land_promise"]},"10":{"text":"They are not humbled even unto this day, neither have they feared, nor walked in my law, nor in my statutes, that I set before you and before your fathers.","ref":"Jeremiah 44:10","synthesized":"To this day they have not humbled themselves or shown reverence, nor have they followed My instruction or the statutes that I set before you and your fathers.","sources":{"KJV":{"text":"They are not humbled even unto this day, neither have they feared, nor walked in my law, nor in my statutes, that I set before you and before your fathers."},"BSB":{"text":"To this day they have not humbled themselves or shown reverence, nor have they followed My instruction or the statutes that I set before you and your fathers."},"TANAKH":{"text":"They are not humbled even unto this day, neither have they feared, nor walked in My law, nor in My statutes, that I set before you and before your fathers."},"HEBREW":{"text":"לֹ֣א דֻכְּא֔וּ עַ֖ד הַיּ֣וֹם הַזֶּ֑ה וְלֹ֣א יָרְא֗וּ וְלֹֽא־הָלְכ֤וּ בְתֽוֹרָתִי֙ וּבְחֻקֹּתַ֔י אֲשֶׁר־נָתַ֥תִּי לִפְנֵיכֶ֖ם וְלִפְנֵ֥י אֲבוֹתֵיכֶֽם׃"}},"definableWords":["day","or","fathers"],"peopleInVerse":[],"themesInVerse":["fear_of_lord"]},"11":{"text":"Therefore thus saith the LORD of hosts, the God of Israel; Behold, I will set my face against you for evil, and to cut off all Judah.","ref":"Jeremiah 44:11","synthesized":"Therefore this is what the LORD of Hosts, the God of Israel, says: I will set My face to bring disaster and to cut off all Judah.","sources":{"KJV":{"text":"Therefore thus saith the LORD of hosts, the God of Israel; Behold, I will set my face against you for evil, and to cut off all Judah."},"BSB":{"text":"Therefore this is what the LORD of Hosts, the God of Israel, says: I will set My face to bring disaster and to cut off all Judah."},"TANAKH":{"text":"Therefore thus saith HaShem of hosts, the G-d of Israel: Behold, I will set My face against you for evil, even to cut off all Judah."},"HEBREW":{"text":"לָכֵ֗ן כֹּֽה־אָמַ֞ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל הִנְנִ֨י שָׂ֥ם פָּנַ֛י בָּכֶ֖ם לְרָעָ֑ה וּלְהַכְרִ֖ית אֶת־כָּל־יְהוּדָֽה׃"}},"definableWords":["LORD","God","Israel","Judah"],"peopleInVerse":[]},"12":{"text":"And I will take the remnant of Judah, that have set their faces to go into the land of Egypt to sojourn there, and they shall all be consumed, and fall in the land of Egypt; they shall even be consumed by the sword and by the famine: they shall die, from the least even unto the greatest, by the sword and by the famine: and they shall be an execration, and an astonishment, and a curse, and a reproach.","ref":"Jeremiah 44:12","synthesized":"And I will take away the remnant of Judah who have resolved to go to the land of Egypt to reside there; they will meet their end. They will all fall by the sword or be consumed by famine. From the least to the greatest, they will die by sword or famine; and they will become an object of cursing and horror, of vilification and reproach.","sources":{"KJV":{"text":"And I will take the remnant of Judah, that have set their faces to go into the land of Egypt to sojourn there, and they shall all be consumed, and fall in the land of Egypt; they shall even be consumed by the sword and by the famine: they shall die, from the least even unto the greatest, by the sword and by the famine: and they shall be an execration, and an astonishment, and a curse, and a reproach."},"BSB":{"text":"And I will take away the remnant of Judah who have resolved to go to the land of Egypt to reside there; they will meet their end. They will all fall by the sword or be consumed by famine. From the least to the greatest, they will die by sword or famine; and they will become an object of cursing and horror, of vilification and reproach."},"TANAKH":{"text":"And I will take the remnant of Judah, that have set their faces to go into the land of Egypt to sojourn there, and they shall all be consumed; in the land of Egypt shall they fall; they shall be consumed by the sword and by the famine; they shall die, from the least even unto the greatest, by the sword and by the famine; and they shall be an execration, and an astonishment, and a curse, and a reproach."},"HEBREW":{"text":"וְלָקַחְתִּ֞י אֶת־שְׁאֵרִ֣ית יְהוּדָ֗ה אֲשֶׁר־שָׂ֨מוּ פְנֵיהֶ֜ם לָב֣וֹא אֶֽרֶץ־מִצְרַיִם֮ לָג֣וּר שָׁם֒ וְתַ֨מּוּ כֹ֜ל בְּאֶ֧רֶץ מִצְרַ֣יִם יִפֹּ֗לוּ בַּחֶ֤רֶב בָּֽרָעָב֙ יִתַּ֔מּוּ מִקָּטֹן֙ וְעַד־גָּד֔וֹל בַּחֶ֥רֶב וּבָרָעָ֖ב יָמֻ֑תוּ וְהָיוּ֙ לְאָלָ֣ה לְשַׁמָּ֔ה וְלִקְלָלָ֖ה וּלְחֶרְפָּֽה׃"}},"definableWords":["remnant","Judah","land","Egypt","or","die"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exile_return","exodus_pattern","fall_sin","land_promise"]},"13":{"text":"For I will punish them that dwell in the land of Egypt, as I have punished Jerusalem, by the sword, by the famine, and by the pestilence:","ref":"Jeremiah 44:13","synthesized":"I will punish those who live in the land of Egypt, just as I punished Jerusalem, by sword and famine and plague,","sources":{"KJV":{"text":"For I will punish them that dwell in the land of Egypt, as I have punished Jerusalem, by the sword, by the famine, and by the pestilence:"},"BSB":{"text":"I will punish those who live in the land of Egypt, just as I punished Jerusalem, by sword and famine and plague,"},"TANAKH":{"text":"For I will punish them that dwell in the land of Egypt, as I have punished Jerusalem, by the sword, by the famine, and by the pestilence;"},"HEBREW":{"text":"וּפָקַדְתִּ֗י עַ֤ל הַיּֽוֹשְׁבִים֙ בְּאֶ֣רֶץ מִצְרַ֔יִם כַּאֲשֶׁ֥ר פָּקַ֖דְתִּי עַל־יְרֽוּשָׁלָ֑͏ִם בַּחֶ֥רֶב בָּרָעָ֖ב וּבַדָּֽבֶר׃"}},"definableWords":["live","land","Egypt","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Egypt","Jerusalem"],"themesInVerse":["exodus_pattern","land_promise"]},"14":{"text":"So that none of the remnant of Judah, which are gone into the land of Egypt to sojourn there, shall escape or remain, that they should return into the land of Judah, to the which they have a desire to return to dwell there: for none shall return but such as shall escape.","ref":"Jeremiah 44:14","synthesized":"so that none of the remnant of Judah who have gone to reside in Egypt will escape or survive to return to the land of Judah, where they long to return and live; for none will return except a few fugitives.”","sources":{"KJV":{"text":"So that none of the remnant of Judah, which are gone into the land of Egypt to sojourn there, shall escape or remain, that they should return into the land of Judah, to the which they have a desire to return to dwell there: for none shall return but such as shall escape."},"BSB":{"text":"so that none of the remnant of Judah who have gone to reside in Egypt will escape or survive to return to the land of Judah, where they long to return and live; for none will return except a few fugitives.”"},"TANAKH":{"text":"so that none of the remnant of Judah, that are gone into the land of Egypt to sojourn there, shall escape or remain, that they should return into the land of Judah, to which they have a desire to return to dwell there; for none shall return save such as shall escape.'"},"HEBREW":{"text":"וְלֹ֨א יִהְיֶ֜ה פָּלִ֤יט וְשָׂרִיד֙ לִשְׁאֵרִ֣ית יְהוּדָ֔ה הַבָּאִ֥ים לָגֽוּר־שָׁ֖ם בְּאֶ֣רֶץ מִצְרָ֑יִם וְלָשׁ֣וּב ׀ אֶ֣רֶץ יְהוּדָ֗ה אֲשֶׁר־הֵ֜מָּה מְנַשְּׂאִ֤ים אֶת־נַפְשָׁם֙ לָשׁוּב֙ לָשֶׁ֣בֶת שָׁ֔ם כִּ֥י לֹֽא־יָשׁ֖וּבוּ כִּ֥י אִם־פְּלֵטִֽים׃"}},"definableWords":["remnant","Judah","Egypt","or","land","live"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exile_return","exodus_pattern","land_promise","second_coming"]},"15":{"text":"Then all the men which knew that their wives had burned incense unto other gods, and all the women that stood by, a great multitude, even all the people that dwelt in the land of Egypt, in Pathros, answered Jeremiah, saying,","ref":"Jeremiah 44:15","synthesized":"Then all the men who knew that their wives were burning incense to other gods, and all the women standing by—a great assembly—along with all the people living in the land of Egypt and in Pathros, said to Jeremiah,","sources":{"KJV":{"text":"Then all the men which knew that their wives had burned incense unto other gods, and all the women that stood by, a great multitude, even all the people that dwelt in the land of Egypt, in Pathros, answered Jeremiah, saying,"},"BSB":{"text":"Then all the men who knew that their wives were burning incense to other gods, and all the women standing by—a great assembly—along with all the people living in the land of Egypt and in Pathros, said to Jeremiah,"},"TANAKH":{"text":"Then all the men who knew that their wives offered unto other gods, and all the women that stood by, a great assembly, even all the people that dwelt in the land of Egypt, in Pathros, answered Jeremiah, saying:"},"HEBREW":{"text":"וַיַּעֲנ֣וּ אֶֽת־יִרְמְיָ֗הוּ כָּל־הָאֲנָשִׁ֤ים הַיֹּֽדְעִים֙ כִּֽי־מְקַטְּר֤וֹת נְשֵׁיהֶם֙ לֵאלֹהִ֣ים אֲחֵרִ֔ים וְכָל־הַנָּשִׁ֥ים הָעֹמְד֖וֹת קָהָ֣ל גָּד֑וֹל וְכָל־הָעָ֛ם הַיֹּשְׁבִ֥ים בְּאֶֽרֶץ־מִצְרַ֖יִם בְּפַתְר֥וֹס לֵאמֹֽר׃"}},"definableWords":["men","incense","women","great","people","living","land","Egypt"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"16":{"text":"As for the word that thou hast spoken unto us in the name of the LORD, we will not hearken unto thee.","ref":"Jeremiah 44:16","synthesized":"“As for the word you have spoken to us in the name of the LORD, we will not listen to you!","sources":{"KJV":{"text":"As for the word that thou hast spoken unto us in the name of the LORD, we will not hearken unto thee."},"BSB":{"text":"“As for the word you have spoken to us in the name of the LORD, we will not listen to you!"},"TANAKH":{"text":"'As for the word that thou hast spoken unto us in the name of HaShem, we will not hearken unto thee."},"HEBREW":{"text":"הַדָּבָ֛ר אֲשֶׁר־דִּבַּ֥רְתָּ אֵלֵ֖ינוּ בְּשֵׁ֣ם יְהוָ֑ה אֵינֶ֥נּוּ שֹׁמְעִ֖ים אֵלֶֽיךָ׃"}},"definableWords":["word","name","LORD"],"peopleInVerse":[]},"17":{"text":"But we will certainly do whatsoever thing goeth forth out of our own mouth, to burn incense unto the queen of heaven, and to pour out drink offerings unto her, as we have done, we, and our fathers, our kings, and our princes, in the cities of Judah, and in the streets of Jerusalem: for then had we plenty of victuals, and were well, and saw no evil.","ref":"Jeremiah 44:17","synthesized":"Instead, we will do everything we vowed to do: We will burn incense to the Queen of Heaven and offer drink offerings to her, just as we, our fathers, our kings, and our officials did in the cities of Judah and in the streets of Jerusalem.  At that time we had plenty of food and good things, and we saw no disaster.","sources":{"KJV":{"text":"But we will certainly do whatsoever thing goeth forth out of our own mouth, to burn incense unto the queen of heaven, and to pour out drink offerings unto her, as we have done, we, and our fathers, our kings, and our princes, in the cities of Judah, and in the streets of Jerusalem: for then had we plenty of victuals, and were well, and saw no evil."},"BSB":{"text":"Instead, we will do everything we vowed to do: We will burn incense to the Queen of Heaven and offer drink offerings to her, just as we, our fathers, our kings, and our officials did in the cities of Judah and in the streets of Jerusalem.  At that time we had plenty of food and good things, and we saw no disaster."},"TANAKH":{"text":"But we will certainly perform every word that is gone forth out of our mouth, to offer unto the queen of heaven, and to pour out drink-offerings unto her, as we have done, we and our fathers, our kings and our princes, in the cities of Judah, and in the streets of Jerusalem; for then had we plenty of food, and were well, and saw no evil."},"HEBREW":{"text":"כִּ֩י עָשֹׂ֨ה נַעֲשֶׂ֜ה אֶֽת־כָּל־הַדָּבָ֣ר ׀ אֲשֶׁר־יָצָ֣א מִפִּ֗ינוּ לְקַטֵּ֞ר לִמְלֶ֣כֶת הַשָּׁמַיִם֮ וְהַסֵּֽיךְ־לָ֣הּ נְסָכִים֒ כַּאֲשֶׁ֨ר עָשִׂ֜ינוּ אֲנַ֤חְנוּ וַאֲבֹתֵ֙ינוּ֙ מְלָכֵ֣ינוּ וְשָׂרֵ֔ינוּ בְּעָרֵ֣י יְהוּדָ֔ה וּבְחֻצ֖וֹת יְרוּשָׁלָ֑͏ִם וַנִּֽשְׂבַּֽע־לֶ֙חֶם֙ וַנִּֽהְיֶ֣ה טוֹבִ֔ים וְרָעָ֖ה לֹ֥א רָאִֽינוּ׃"}},"definableWords":["incense","heaven","fathers","kings","Judah","Jerusalem","good","saw"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"18":{"text":"But since we left off to burn incense to the queen of heaven, and to pour out drink offerings unto her, we have wanted all things, and have been consumed by the sword and by the famine.","ref":"Jeremiah 44:18","synthesized":"But from the time we stopped burning incense to the Queen of Heaven and pouring out drink offerings to her, we have lacked everything and have been perishing by sword and famine.”","sources":{"KJV":{"text":"But since we left off to burn incense to the queen of heaven, and to pour out drink offerings unto her, we have wanted all things, and have been consumed by the sword and by the famine."},"BSB":{"text":"But from the time we stopped burning incense to the Queen of Heaven and pouring out drink offerings to her, we have lacked everything and have been perishing by sword and famine.”"},"TANAKH":{"text":"But since we let off to offer to the queen of heaven, and to pour out drink-offerings unto her, we have wanted all things, and have been consumed by the sword and by the famine."},"HEBREW":{"text":"וּמִן־אָ֡ז חָדַ֜לְנוּ לְקַטֵּ֨ר לִמְלֶ֧כֶת הַשָּׁמַ֛יִם וְהַסֵּֽךְ־לָ֥הּ נְסָכִ֖ים חָסַ֣רְנוּ כֹ֑ל וּבַחֶ֥רֶב וּבָרָעָ֖ב תָּֽמְנוּ׃"}},"definableWords":["incense","heaven"],"peopleInVerse":[]},"19":{"text":"And when we burned incense to the queen of heaven, and poured out drink offerings unto her, did we make her cakes to worship her, and pour out drink offerings unto her, without our men?","ref":"Jeremiah 44:19","synthesized":"“Moreover,” said the women, “when we burned incense to the Queen of Heaven and poured out drink offerings to her, was it without our husbands’ knowledge that we made sacrificial cakes in her image and poured out drink offerings to her?”","sources":{"KJV":{"text":"And when we burned incense to the queen of heaven, and poured out drink offerings unto her, did we make her cakes to worship her, and pour out drink offerings unto her, without our men?"},"BSB":{"text":"“Moreover,” said the women, “when we burned incense to the Queen of Heaven and poured out drink offerings to her, was it without our husbands’ knowledge that we made sacrificial cakes in her image and poured out drink offerings to her?”"},"TANAKH":{"text":"And is it we that offer to the queen of heaven, and pour out drink-offerings unto her? did we make her cakes in her image, and pour out drink-offerings unto her, without our husbands?'"},"HEBREW":{"text":"וְכִֽי־אֲנַ֤חְנוּ מְקַטְּרִים֙ לִמְלֶ֣כֶת הַשָּׁמַ֔יִם וּלְהַסֵּ֥ךְ לָ֖הּ נְסָכִ֑ים הֲמִֽבַּלְעֲדֵ֣י אֲנָשֵׁ֗ינוּ עָשִׂ֨ינוּ לָ֤הּ כַּוָּנִים֙ לְהַ֣עֲצִבָ֔הֿ וְהַסֵּ֥ךְ לָ֖הּ נְסָכִֽים׃"}},"definableWords":["women","incense","heaven","knowledge","made","image"],"peopleInVerse":[],"themesInVerse":["creation","image_of_god"]},"20":{"text":"Then Jeremiah said unto all the people, to the men, and to the women, and to all the people which had given him that answer, saying,","ref":"Jeremiah 44:20","synthesized":"Then Jeremiah said to all the people, both men and women, who were answering him,","sources":{"KJV":{"text":"Then Jeremiah said unto all the people, to the men, and to the women, and to all the people which had given him that answer, saying,"},"BSB":{"text":"Then Jeremiah said to all the people, both men and women, who were answering him,"},"TANAKH":{"text":"Then Jeremiah said unto all the people, to the men, and to the women, even to all the people that had given him that answer, saying:"},"HEBREW":{"text":"וַיֹּ֥אמֶר יִרְמְיָ֖הוּ אֶל־כָּל־הָעָ֑ם עַל־הַגְּבָרִ֤ים וְעַל־הַנָּשִׁים֙ וְעַל־כָּל־הָעָ֔ם הָעֹנִ֥ים אֹת֛וֹ דָּבָ֖ר לֵאמֹֽר׃"}},"definableWords":["people","men","women"],"peopleInVerse":["Jeremiah"]},"21":{"text":"The incense that ye burned in the cities of Judah, and in the streets of Jerusalem, ye, and your fathers, your kings, and your princes, and the people of the land, did not the LORD remember them, and came it not into his mind?","ref":"Jeremiah 44:21","synthesized":"“As for the incense you burned in the cities of Judah and in the streets of Jerusalem—you, your fathers, your kings, your officials, and the people of the land—did the LORD not remember and bring this to mind?","sources":{"KJV":{"text":"The incense that ye burned in the cities of Judah, and in the streets of Jerusalem, ye, and your fathers, your kings, and your princes, and the people of the land, did not the LORD remember them, and came it not into his mind?"},"BSB":{"text":"“As for the incense you burned in the cities of Judah and in the streets of Jerusalem—you, your fathers, your kings, your officials, and the people of the land—did the LORD not remember and bring this to mind?"},"TANAKH":{"text":"'The offering that ye offered in the cities of Judah, and in the streets of Jerusalem, ye and your fathers, your kings and your princes, and the people of the land, did not HaShem remember them, and came it not into His mind?"},"HEBREW":{"text":"הֲל֣וֹא אֶת־הַקִּטֵּ֗ר אֲשֶׁ֨ר קִטַּרְתֶּ֜ם בְּעָרֵ֤י יְהוּדָה֙ וּבְחֻצ֣וֹת יְרוּשָׁלִַ֔ם אַתֶּ֧ם וַאֲבֽוֹתֵיכֶ֛ם מַלְכֵיכֶ֥ם וְשָׂרֵיכֶ֖ם וְעַ֣ם הָאָ֑רֶץ אֹתָם֙ זָכַ֣ר יְהוָ֔ה וַֽתַּעֲלֶ֖ה עַל־לִבּֽוֹ׃"}},"definableWords":["incense","Judah","Jerusalem","fathers","kings","people","land","LORD","remember","mind"],"peopleInVerse":[],"placesInVerse":["Jerusalem"],"themesInVerse":["land_promise"]},"22":{"text":"So that the LORD could no longer bear, because of the evil of your doings, and because of the abominations which ye have committed; therefore is your land a desolation, and an astonishment, and a curse, without an inhabitant, as at this day.","ref":"Jeremiah 44:22","synthesized":"So the LORD could no longer endure the evil deeds and detestable acts you committed, and your land became a desolation, a horror, and an object of cursing, without inhabitant, as it is this day.","sources":{"KJV":{"text":"So that the LORD could no longer bear, because of the evil of your doings, and because of the abominations which ye have committed; therefore is your land a desolation, and an astonishment, and a curse, without an inhabitant, as at this day."},"BSB":{"text":"So the LORD could no longer endure the evil deeds and detestable acts you committed, and your land became a desolation, a horror, and an object of cursing, without inhabitant, as it is this day."},"TANAKH":{"text":"So that HaShem could no longer bear, because of the evil of your doings, and because of the abominations which ye have committed; therefore is your land become a desolation, and an astonishment, and a curse, without an inhabitant, as at this day."},"HEBREW":{"text":"וְלֹֽא־יוּכַל֩ יְהוָ֨ה ע֜וֹד לָשֵׂ֗את מִפְּנֵי֙ רֹ֣עַ מַעַלְלֵיכֶ֔ם מִפְּנֵ֥י הַתּוֹעֵבֹ֖ת אֲשֶׁ֣ר עֲשִׂיתֶ֑ם וַתְּהִ֣י אַ֠רְצְכֶם לְחָרְבָּ֨ה וּלְשַׁמָּ֧ה וְלִקְלָלָ֛ה מֵאֵ֥ין יוֹשֵׁ֖ב כְּהַיּ֥וֹם הַזֶּֽה׃"}},"definableWords":["LORD","evil","land","day"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"23":{"text":"Because ye have burned incense, and because ye have sinned against the LORD, and have not obeyed the voice of the LORD, nor walked in his law, nor in his statutes, nor in his testimonies; therefore this evil is happened unto you, as at this day.","ref":"Jeremiah 44:23","synthesized":"Because you burned incense and sinned against the LORD, and did not obey the voice of the LORD or walk in His instruction, His statutes, and His testimonies, this disaster has befallen you, as you see today.”","sources":{"KJV":{"text":"Because ye have burned incense, and because ye have sinned against the LORD, and have not obeyed the voice of the LORD, nor walked in his law, nor in his statutes, nor in his testimonies; therefore this evil is happened unto you, as at this day."},"BSB":{"text":"Because you burned incense and sinned against the LORD, and did not obey the voice of the LORD or walk in His instruction, His statutes, and His testimonies, this disaster has befallen you, as you see today.”"},"TANAKH":{"text":"Because ye have offered, and because ye have sinned against HaShem, and have not hearkened to the voice of HaShem, nor walked in His law, nor in His statutes, nor in His testimonies; therefore this evil is happened unto you, as at this day.'"},"HEBREW":{"text":"מִפְּנֵי֩ אֲשֶׁ֨ר קִטַּרְתֶּ֜ם וַאֲשֶׁ֧ר חֲטָאתֶ֣ם לַיהוָ֗ה וְלֹ֤א שְׁמַעְתֶּם֙ בְּק֣וֹל יְהוָ֔ה וּבְתֹרָת֧וֹ וּבְחֻקֹּתָ֛יו וּבְעֵדְוֺתָ֖יו לֹ֣א הֲלַכְתֶּ֑ם עַל־כֵּ֞ן קָרָ֥את אֶתְכֶ֛ם הָרָעָ֥ה הַזֹּ֖את כַּיּ֥וֹם הַזֶּֽה׃"}},"definableWords":["incense","LORD","voice","Lord","or","walk","see"],"peopleInVerse":[]},"24":{"text":"Moreover Jeremiah said unto all the people, and to all the women, Hear the word of the LORD, all Judah that are in the land of Egypt:","ref":"Jeremiah 44:24","synthesized":"Then Jeremiah said to all the people, including all the women, “Hear the word of the LORD, all those of Judah who are in the land of Egypt.","sources":{"KJV":{"text":"Moreover Jeremiah said unto all the people, and to all the women, Hear the word of the LORD, all Judah that are in the land of Egypt:"},"BSB":{"text":"Then Jeremiah said to all the people, including all the women, “Hear the word of the LORD, all those of Judah who are in the land of Egypt."},"TANAKH":{"text":"Moreover Jeremiah said unto all the people, and to all the women: 'Hear the word of HaShem, all Judah that are in the land of Egypt:"},"HEBREW":{"text":"וַיֹּ֤אמֶר יִרְמְיָ֙הוּ֙ אֶל־כָּל־הָעָ֔ם וְאֶ֖ל כָּל־הַנָּשִׁ֑ים שִׁמְעוּ֙ דְּבַר־יְהוָ֔ה כָּל־יְהוּדָ֕ה אֲשֶׁ֖ר בְּאֶ֥רֶץ מִצְרָֽיִם׃"}},"definableWords":["people","women","hear","word","LORD","Judah","land","Egypt"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"25":{"text":"Thus saith the LORD of hosts, the God of Israel, saying; Ye and your wives have both spoken with your mouths, and fulfilled with your hand, saying, We will surely perform our vows that we have vowed, to burn incense to the queen of heaven, and to pour out drink offerings unto her: ye will surely accomplish your vows, and surely perform your vows.","ref":"Jeremiah 44:25","synthesized":"This is what the LORD of Hosts, the God of Israel, says: As for you and your wives, you have spoken with your mouths and fulfilled with your hands your words: ‘We will surely perform our vows that we have made to burn incense to the Queen of Heaven and to pour out drink offerings to her.’ Go ahead, then, do what you have promised! Keep your vows!","sources":{"KJV":{"text":"Thus saith the LORD of hosts, the God of Israel, saying; Ye and your wives have both spoken with your mouths, and fulfilled with your hand, saying, We will surely perform our vows that we have vowed, to burn incense to the queen of heaven, and to pour out drink offerings unto her: ye will surely accomplish your vows, and surely perform your vows."},"BSB":{"text":"This is what the LORD of Hosts, the God of Israel, says: As for you and your wives, you have spoken with your mouths and fulfilled with your hands your words: ‘We will surely perform our vows that we have made to burn incense to the Queen of Heaven and to pour out drink offerings to her.’ Go ahead, then, do what you have promised! Keep your vows!"},"TANAKH":{"text":"Thus saith HaShem of hosts, the G-d of Israel, saying: Ye and your wives have both spoken with your mouths, and with your hands have fulfilled it, saying: We will surely perform our vows that we have vowed, to offer to the queen of heaven, and to pour out drink-offerings unto her; ye shall surely establish your vows, and surely perform your vows."},"HEBREW":{"text":"כֹּֽה־אָמַ֣ר יְהוָֽה־צְבָאוֹת֩ אֱלֹהֵ֨י יִשְׂרָאֵ֜ל לֵאמֹ֗ר אַתֶּ֨ם וּנְשֵׁיכֶ֜ם וַתְּדַבֵּ֣רְנָה בְּפִיכֶם֮ וּבִידֵיכֶ֣ם מִלֵּאתֶ֣ם ׀ לֵאמֹר֒ עָשֹׂ֨ה נַעֲשֶׂ֜ה אֶת־נְדָרֵ֗ינוּ אֲשֶׁ֤ר נָדַ֙רְנוּ֙ לְקַטֵּר֙ לִמְלֶ֣כֶת הַשָּׁמַ֔יִם וּלְהַסֵּ֥ךְ לָ֖הּ נְסָכִ֑ים הָקֵ֤ים תָּקִ֙ימְנָה֙ אֶת־נִדְרֵיכֶ֔ם וְעָשֹׂ֥ה תַעֲשֶׂ֖ינָה אֶת־נִדְרֵיכֶֽם׃"}},"definableWords":["LORD","God","Israel","made","incense","heaven","keep"],"peopleInVerse":[],"themesInVerse":["creation"]},"26":{"text":"Therefore hear ye the word of the LORD, all Judah that dwell in the land of Egypt; Behold, I have sworn by my great name, saith the LORD, that my name shall no more be named in the mouth of any man of Judah in all the land of Egypt, saying, The Lord GOD liveth.","ref":"Jeremiah 44:26","synthesized":"Nevertheless, hear the word of the LORD, all you people of Judah living in Egypt: Behold, I have sworn by My great name, says the LORD, that never again will any man of Judah living in the land of Egypt invoke My name or say, ‘As surely as the Lord GOD lives.’","sources":{"KJV":{"text":"Therefore hear ye the word of the LORD, all Judah that dwell in the land of Egypt; Behold, I have sworn by my great name, saith the LORD, that my name shall no more be named in the mouth of any man of Judah in all the land of Egypt, saying, The Lord GOD liveth."},"BSB":{"text":"Nevertheless, hear the word of the LORD, all you people of Judah living in Egypt: Behold, I have sworn by My great name, says the LORD, that never again will any man of Judah living in the land of Egypt invoke My name or say, ‘As surely as the Lord GOD lives.’"},"TANAKH":{"text":"Therefore hear ye the word of HaShem, all Judah that dwell in the land of Egypt: Behold, I have sworn by My great name, saith HaShem, that My name shall no more be named in the mouth of any man of Judah in all the land of Egypt saying: As the L-rd GOD liveth."},"HEBREW":{"text":"לָכֵן֙ שִׁמְע֣וּ דְבַר־יְהוָ֔ה כָּל־יְהוּדָ֕ה הַיֹּשְׁבִ֖ים בְּאֶ֣רֶץ מִצְרָ֑יִם הִנְנִ֨י נִשְׁבַּ֜עְתִּי בִּשְׁמִ֤י הַגָּדוֹל֙ אָמַ֣ר יְהוָ֔ה אִם־יִהְיֶה֩ ע֨וֹד שְׁמִ֜י נִקְרָ֣א ׀ בְּפִ֣י ׀ כָּל־אִ֣ישׁ יְהוּדָ֗ה אֹמֵ֛ר חַי־אֲדֹנָ֥י יְהוִ֖ה בְּכָל־אֶ֥רֶץ מִצְרָֽיִם׃"}},"definableWords":["hear","word","LORD","people","Judah","living","Egypt","great","name","Lord","man","land","or","God"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"27":{"text":"Behold, I will watch over them for evil, and not for good: and all the men of Judah that are in the land of Egypt shall be consumed by the sword and by the famine, until there be an end of them.","ref":"Jeremiah 44:27","synthesized":"I am watching over them for harm and not for good, and every man of Judah who is in the land of Egypt will meet his end by sword or famine, until they are finished off.","sources":{"KJV":{"text":"Behold, I will watch over them for evil, and not for good: and all the men of Judah that are in the land of Egypt shall be consumed by the sword and by the famine, until there be an end of them."},"BSB":{"text":"I am watching over them for harm and not for good, and every man of Judah who is in the land of Egypt will meet his end by sword or famine, until they are finished off."},"TANAKH":{"text":"Behold, I watch over them for evil, and not for good; and all the men of Judah that are in the land of Egypt shall be consumed by the sword and by the famine, until there be an end of them."},"HEBREW":{"text":"הִנְנִ֨י שֹׁקֵ֧ד עֲלֵיהֶ֛ם לְרָעָ֖ה וְלֹ֣א לְטוֹבָ֑ה וְתַמּוּ֩ כָל־אִ֨ישׁ יְהוּדָ֜ה אֲשֶׁ֧ר בְּאֶֽרֶץ־מִצְרַ֛יִם בַּחֶ֥רֶב וּבָרָעָ֖ב עַד־כְּלוֹתָֽם׃"}},"definableWords":["good","man","Judah","land","Egypt","or"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","land_promise"]},"28":{"text":"Yet a small number that escape the sword shall return out of the land of Egypt into the land of Judah, and all the remnant of Judah, that are gone into the land of Egypt to sojourn there, shall know whose words shall stand, mine, or theirs.","ref":"Jeremiah 44:28","synthesized":"Those who escape the sword will return from Egypt to Judah, few in number, and the whole remnant of Judah who went to dwell in the land of Egypt will know whose word will stand, Mine or theirs!","sources":{"KJV":{"text":"Yet a small number that escape the sword shall return out of the land of Egypt into the land of Judah, and all the remnant of Judah, that are gone into the land of Egypt to sojourn there, shall know whose words shall stand, mine, or theirs."},"BSB":{"text":"Those who escape the sword will return from Egypt to Judah, few in number, and the whole remnant of Judah who went to dwell in the land of Egypt will know whose word will stand, Mine or theirs!"},"TANAKH":{"text":"And they that escape the sword shall return out of the land of Egypt into the land of Judah, few in number; and all the remnant of Judah, that are gone into the land of Egypt to sojourn there, shall know whose word shall stand, Mine, or theirs."},"HEBREW":{"text":"וּפְלִיטֵ֨י חֶ֜רֶב יְשֻׁב֨וּן מִן־אֶ֧רֶץ מִצְרַ֛יִם אֶ֥רֶץ יְהוּדָ֖ה מְתֵ֣י מִסְפָּ֑ר וְֽיָדְע֞וּ כָּל־שְׁאֵרִ֣ית יְהוּדָ֗ה הַבָּאִ֤ים לְאֶֽרֶץ־מִצְרַ֙יִם֙ לָג֣וּר שָׁ֔ם דְּבַר־מִ֥י יָק֖וּם מִמֶּ֥נִּי וּמֵהֶֽם׃"}},"definableWords":["Egypt","Judah","remnant","land","word","stand","or"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exile_return","exodus_pattern","land_promise","second_coming"]},"29":{"text":"And this shall be a sign unto you, saith the LORD, that I will punish you in this place, that ye may know that my words shall surely stand against you for evil:","ref":"Jeremiah 44:29","synthesized":"This will be a sign to you that I will punish you in this place, declares the LORD, so that you may know that My threats of harm against you will surely stand.","sources":{"KJV":{"text":"And this shall be a sign unto you, saith the LORD, that I will punish you in this place, that ye may know that my words shall surely stand against you for evil:"},"BSB":{"text":"This will be a sign to you that I will punish you in this place, declares the LORD, so that you may know that My threats of harm against you will surely stand."},"TANAKH":{"text":"And this shall be the sign unto you, saith HaShem, that I will punish you in this place, that ye may know that My words shall surely stand against you for evil;"},"HEBREW":{"text":"וְזֹאת־לָכֶ֤ם הָאוֹת֙ נְאֻם־יְהוָ֔ה כִּֽי־פֹקֵ֥ד אֲנִ֛י עֲלֵיכֶ֖ם בַּמָּק֣וֹם הַזֶּ֑ה לְמַ֙עַן֙ תֵּֽדְע֔וּ כִּי֩ ק֨וֹם יָק֧וּמוּ דְבָרַ֛י עֲלֵיכֶ֖ם לְרָעָֽה׃"}},"definableWords":["LORD","stand"],"peopleInVerse":[]},"30":{"text":"Thus saith the LORD; Behold, I will give Pharaohhophra king of Egypt into the hand of his enemies, and into the hand of them that seek his life; as I gave Zedekiah king of Judah into the hand of Nebuchadrezzar king of Babylon, his enemy, and that sought his life.","ref":"Jeremiah 44:30","synthesized":"This is what the LORD says: Behold, I will deliver Pharaoh Hophra king of Egypt into the hands of his enemies who seek his life, just as I delivered Zedekiah king of Judah into the hand of Nebuchadnezzar king of Babylon, the enemy who was seeking his life.”","sources":{"KJV":{"text":"Thus saith the LORD; Behold, I will give Pharaohhophra king of Egypt into the hand of his enemies, and into the hand of them that seek his life; as I gave Zedekiah king of Judah into the hand of Nebuchadrezzar king of Babylon, his enemy, and that sought his life."},"BSB":{"text":"This is what the LORD says: Behold, I will deliver Pharaoh Hophra king of Egypt into the hands of his enemies who seek his life, just as I delivered Zedekiah king of Judah into the hand of Nebuchadnezzar king of Babylon, the enemy who was seeking his life.”"},"TANAKH":{"text":"thus saith HaShem: Behold, I will give Pharaoh Hophra king of Egypt into the hand of his enemies, and into the hand of them that seek his life; as I gave Zedekiah king of Judah into the hand of Nebuchadrezzar king of Babylon, his enemy, and that sought his life.'"},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה הִנְנִ֣י נֹ֠תֵן אֶת־פַּרְעֹ֨ה חָפְרַ֤ע מֶֽלֶךְ־מִצְרַ֙יִם֙ בְּיַ֣ד אֹֽיְבָ֔יו וּבְיַ֖ד מְבַקְשֵׁ֣י נַפְשׁ֑וֹ כַּאֲשֶׁ֨ר נָתַ֜תִּי אֶת־צִדְקִיָּ֣הוּ מֶֽלֶךְ־יְהוּדָ֗ה בְּיַ֨ד נְבוּכַדְרֶאצַּ֧ר מֶֽלֶךְ־בָּבֶ֛ל אֹיְב֖וֹ וּמְבַקֵּ֥שׁ נַפְשֽׁוֹ׃"}},"definableWords":["LORD","deliver","Pharaoh","king","Egypt","seek","life","King","Judah","Babylon"],"peopleInVerse":["Pharaoh","Nebuchadnezzar"],"placesInVerse":["Egypt","Babylon"],"themesInVerse":["exodus_pattern","kingship","redemption","salvation"]}}},"45":{"chapter":"45","title":"WORD TO BARUCH","verses":{"1":{"text":"The word that Jeremiah the prophet spake unto Baruch the son of Neriah, when he had written these words in a book at the mouth of Jeremiah, in the fourth year of Jehoiakim the son of Josiah king of Judah, saying,","ref":"Jeremiah 45:1","synthesized":"This is the word that Jeremiah the prophet spoke to Baruch son of Neriah when he wrote these words on a scroll at the dictation of Jeremiah in the fourth year of Jehoiakim son of Josiah, king of Judah:","sources":{"KJV":{"text":"The word that Jeremiah the prophet spake unto Baruch the son of Neriah, when he had written these words in a book at the mouth of Jeremiah, in the fourth year of Jehoiakim the son of Josiah king of Judah, saying,"},"BSB":{"text":"This is the word that Jeremiah the prophet spoke to Baruch son of Neriah when he wrote these words on a scroll at the dictation of Jeremiah in the fourth year of Jehoiakim son of Josiah, king of Judah:"},"TANAKH":{"text":"The word that Jeremiah the prophet spoke unto Baruch the son of Neriah, when he wrote these words in a book at the mouth of Jeremiah, in the fourth year of Jehoiakim the son of Josiah, king of Judah, saying:"},"HEBREW":{"text":"הַדָּבָ֗ר אֲשֶׁ֤ר דִּבֶּר֙ יִרְמְיָ֣הוּ הַנָּבִ֔יא אֶל־בָּר֖וּךְ בֶּֽן־נֵֽרִיָּ֑ה בְּכָתְבוֹ֩ אֶת־הַדְּבָרִ֨ים הָאֵ֤לֶּה עַל־סֵ֙פֶר֙ מִפִּ֣י יִרְמְיָ֔הוּ בַּשָּׁנָה֙ הָֽרְבִעִ֔ית לִיהוֹיָקִ֧ים בֶּן־יֹאשִׁיָּ֛הוּ מֶ֥לֶךְ יְהוּדָ֖ה לֵאמֹֽר׃"}},"definableWords":["word","prophet","baruch","son","year","Son","king","Judah"],"peopleInVerse":["Jeremiah"],"themesInVerse":["kingship"]},"2":{"text":"Thus saith the LORD, the God of Israel, unto thee, O Baruch:","ref":"Jeremiah 45:2","synthesized":"“This is what the LORD, the God of Israel, says to you, Baruch:","sources":{"KJV":{"text":"Thus saith the LORD, the God of Israel, unto thee, O Baruch:"},"BSB":{"text":"“This is what the LORD, the God of Israel, says to you, Baruch:"},"TANAKH":{"text":"'Thus saith HaShem, the G-d of Israel, concerning thee, O Baruch: Thou didst say:"},"HEBREW":{"text":"כֹּֽה־אָמַ֥ר יְהוָ֖ה אֱלֹהֵ֣י יִשְׂרָאֵ֑ל עָלֶ֖יךָ בָּרֽוּךְ׃"}},"definableWords":["LORD","God","Israel","baruch"],"peopleInVerse":[]},"3":{"text":"Thou didst say, Woe is me now! for the LORD hath added grief to my sorrow; I fainted in my sighing, and I find no rest.","ref":"Jeremiah 45:3","synthesized":"You have said, ‘Woe is me because the LORD has added sorrow to my pain! I am worn out with groaning and have found no rest.’”","sources":{"KJV":{"text":"Thou didst say, Woe is me now! for the LORD hath added grief to my sorrow; I fainted in my sighing, and I find no rest."},"BSB":{"text":"You have said, ‘Woe is me because the LORD has added sorrow to my pain! I am worn out with groaning and have found no rest.’”"},"TANAKH":{"text":"Woe is me now! for HaShem hath added sorrow to my pain; I am weary with my groaning, and I find no rest."},"HEBREW":{"text":"אָמַ֙רְתָּ֙ אֽוֹי־נָ֣א לִ֔י כִּֽי־יָסַ֧ף יְהוָ֛ה יָג֖וֹן עַל־מַכְאֹבִ֑י יָגַ֙עְתִּי֙ בְּאַנְחָתִ֔י וּמְנוּחָ֖ה לֹ֥א מָצָֽאתִי׃"}},"definableWords":["LORD","rest"],"peopleInVerse":[],"themesInVerse":["peace","sabbath_rest","suffering"]},"4":{"text":"Thus shalt thou say unto him, The LORD saith thus; Behold, that which I have built will I break down, and that which I have planted I will pluck up, even this whole land.","ref":"Jeremiah 45:4","synthesized":"Thus Jeremiah was to say to Baruch: “This is what the LORD says: Throughout the land I will demolish what I have built and uproot what I have planted.","sources":{"KJV":{"text":"Thus shalt thou say unto him, The LORD saith thus; Behold, that which I have built will I break down, and that which I have planted I will pluck up, even this whole land."},"BSB":{"text":"Thus Jeremiah was to say to Baruch: “This is what the LORD says: Throughout the land I will demolish what I have built and uproot what I have planted."},"TANAKH":{"text":"Thus shalt thou say unto him: Thus saith HaShem: Behold, that which I have built will I break down, and that which I have planted I will pluck up; and this in the whole land."},"HEBREW":{"text":"כֹּ֣ה ׀ תֹּאמַ֣ר אֵלָ֗יו כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִנֵּ֤ה אֲשֶׁר־בָּנִ֙יתִי֙ אֲנִ֣י הֹרֵ֔ס וְאֵ֥ת אֲשֶׁר־נָטַ֖עְתִּי אֲנִ֣י נֹתֵ֑שׁ וְאֶת־כָּל־הָאָ֖רֶץ הִֽיא׃"}},"definableWords":["baruch","LORD","land"],"peopleInVerse":["Jeremiah"],"themesInVerse":["land_promise"]},"5":{"text":"And seekest thou great things for thyself? seek them not: for, behold, I will bring evil upon all flesh, saith the LORD: but thy life will I give unto thee for a prey in all places whither thou goest.","ref":"Jeremiah 45:5","synthesized":"But as for you, do you seek great things for yourself? Stop seeking! For I will bring disaster on every living creature, declares the LORD, but wherever you go, I will grant your life as a spoil of war.”","sources":{"KJV":{"text":"And seekest thou great things for thyself? seek them not: for, behold, I will bring evil upon all flesh, saith the LORD: but thy life will I give unto thee for a prey in all places whither thou goest."},"BSB":{"text":"But as for you, do you seek great things for yourself? Stop seeking! For I will bring disaster on every living creature, declares the LORD, but wherever you go, I will grant your life as a spoil of war.”"},"TANAKH":{"text":"And seekest thou great things for thyself? seek them not; for, behold, I will bring evil upon all flesh, saith HaShem; but thy life will I give unto thee for a prey in all places whither thou goest.'"},"HEBREW":{"text":"וְאַתָּ֛ה תְּבַקֶּשׁ־לְךָ֥ גְדֹל֖וֹת אַל־תְּבַקֵּ֑שׁ כִּ֡י הִנְנִי֩ מֵבִ֨יא רָעָ֤ה עַל־כָּל־בָּשָׂר֙ נְאֻם־יְהוָ֔ה וְנָתַתִּ֨י לְךָ֤ אֶֽת־נַפְשְׁךָ֙ לְשָׁלָ֔ל עַ֥ל כָּל־הַמְּקֹמ֖וֹת אֲשֶׁ֥ר תֵּֽלֶךְ־שָֽׁם׃"}},"definableWords":["seek","great","living","LORD","life"],"peopleInVerse":[]}}},"46":{"chapter":"46","title":"PROPHECY AGAINST EGYPT","verses":{"1":{"text":"The word of the LORD which came to Jeremiah the prophet against the Gentiles;","ref":"Jeremiah 46:1","synthesized":"This is the word of the LORD about the nations—the word that came to Jeremiah the prophet","sources":{"KJV":{"text":"The word of the LORD which came to Jeremiah the prophet against the Gentiles;"},"BSB":{"text":"This is the word of the LORD about the nations—the word that came to Jeremiah the prophet"},"TANAKH":{"text":"The word of HaShem which came to Jeremiah the prophet concerning the nations."},"HEBREW":{"text":"אֲשֶׁ֨ר הָיָ֧ה דְבַר־יְהוָ֛ה אֶל־יִרְמְיָ֥הוּ הַנָּבִ֖יא עַל־הַגּוֹיִֽם׃"}},"definableWords":["word","LORD","nations","prophet"],"peopleInVerse":["Jeremiah"]},"2":{"text":"Against Egypt, against the army of Pharaohnecho king of Egypt, which was by the river Euphrates in Carchemish, which Nebuchadrezzar king of Babylon smote in the fourth year of Jehoiakim the son of Josiah king of Judah.","ref":"Jeremiah 46:2","synthesized":"concerning Egypt and the army of Pharaoh Neco king of Egypt, which was defeated at Carchemish on the Euphrates River by Nebuchadnezzar king of Babylon in the fourth year of Jehoiakim the son of Josiah king of Judah:","sources":{"KJV":{"text":"Against Egypt, against the army of Pharaohnecho king of Egypt, which was by the river Euphrates in Carchemish, which Nebuchadrezzar king of Babylon smote in the fourth year of Jehoiakim the son of Josiah king of Judah."},"BSB":{"text":"concerning Egypt and the army of Pharaoh Neco king of Egypt, which was defeated at Carchemish on the Euphrates River by Nebuchadnezzar king of Babylon in the fourth year of Jehoiakim the son of Josiah king of Judah:"},"TANAKH":{"text":"Of Egypt: concerning the army of Pharaoh-neco king of Egypt, which was by the river Euphrates in Carchemish, which Nebuchadrezzar king of Babylon smote in the fourth year of Jehoiakim the son of Josiah, king of Judah."},"HEBREW":{"text":"לְמִצְרַ֗יִם עַל־חֵ֨יל פַּרְעֹ֤ה נְכוֹ֙ מֶ֣לֶךְ מִצְרַ֔יִם אֲשֶׁר־הָיָ֥ה עַל־נְהַר־פְּרָ֖ת בְּכַרְכְּמִ֑שׁ אֲשֶׁ֣ר הִכָּ֗ה נְבֽוּכַדְרֶאצַּר֙ מֶ֣לֶךְ בָּבֶ֔ל בִּשְׁנַת֙ הָֽרְבִיעִ֔ית לִיהוֹיָקִ֥ים בֶּן־יֹאשִׁיָּ֖הוּ מֶ֥לֶךְ יְהוּדָֽה׃"}},"definableWords":["Egypt","Pharaoh","king","King","Babylon","year","son","Judah"],"peopleInVerse":["Pharaoh","Nebuchadnezzar"],"placesInVerse":["Egypt","Jordan River","Babylon"],"themesInVerse":["exodus_pattern","kingship"]},"3":{"text":"Order ye the buckler and shield, and draw near to battle.","ref":"Jeremiah 46:3","synthesized":"“Deploy your shields, small and large; advance for battle!","sources":{"KJV":{"text":"Order ye the buckler and shield, and draw near to battle."},"BSB":{"text":"“Deploy your shields, small and large; advance for battle!"},"TANAKH":{"text":"Make ready buckler and shield, and draw near to battle."},"HEBREW":{"text":"עִרְכ֤וּ מָגֵן֙ וְצִנָּ֔ה וּגְשׁ֖וּ לַמִּלְחָמָֽה׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["spiritual_warfare"]},"4":{"text":"Harness the horses; and get up, ye horsemen, and stand forth with your helmets; furbish the spears, and put on the brigandines.","ref":"Jeremiah 46:4","synthesized":"Harness the horses; mount the steeds; take your positions with helmets on! Polish your spears; put on armor!","sources":{"KJV":{"text":"Harness the horses; and get up, ye horsemen, and stand forth with your helmets; furbish the spears, and put on the brigandines."},"BSB":{"text":"Harness the horses; mount the steeds; take your positions with helmets on! Polish your spears; put on armor!"},"TANAKH":{"text":"Harness the horses, and mount, ye horsemen, and stand forth with your helmets; furbish the spears, put on the coats of mail."},"HEBREW":{"text":"אִסְר֣וּ הַסּוּסִ֗ים וַֽעֲלוּ֙ הַפָּ֣רָשִׁ֔ים וְהִֽתְיַצְּב֖וּ בְּכ֥וֹבָעִ֑ים מִרְקוּ֙ הָֽרְמָחִ֔ים לִבְשׁ֖וּ הַסִּרְיֹנֹֽת׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["spiritual_warfare"]},"5":{"text":"Wherefore have I seen them dismayed and turned away back? and their mighty ones are beaten down, and are fled apace, and look not back: for fear was round about, saith the LORD.","ref":"Jeremiah 46:5","synthesized":"Why am I seeing this?   They are terrified, they are retreating; their warriors are defeated, they flee in haste without looking back; terror is on every side!” declares the LORD.","sources":{"KJV":{"text":"Wherefore have I seen them dismayed and turned away back? and their mighty ones are beaten down, and are fled apace, and look not back: for fear was round about, saith the LORD."},"BSB":{"text":"Why am I seeing this?   They are terrified, they are retreating; their warriors are defeated, they flee in haste without looking back; terror is on every side!” declares the LORD."},"TANAKH":{"text":"Wherefore do I see them dismayed and turned backward? and their mighty ones are beaten down, and they are fled apace, and look not back; terror is on every side, saith HaShem."},"HEBREW":{"text":"מַדּ֣וּעַ רָאִ֗יתִי הֵ֣מָּה חַתִּים֮ נְסֹגִ֣ים אָחוֹר֒ וְגִבּוֹרֵיהֶ֣ם יֻכַּ֔תּוּ וּמָנ֥וֹס נָ֖סוּ וְלֹ֣א הִפְנ֑וּ מָג֥וֹר מִסָּבִ֖יב נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"6":{"text":"Let not the swift flee away, nor the mighty man escape; they shall stumble, and fall toward the north by the river Euphrates.","ref":"Jeremiah 46:6","synthesized":"“The swift cannot flee, and the warrior cannot escape! In the north by the River Euphrates they stumble and fall.","sources":{"KJV":{"text":"Let not the swift flee away, nor the mighty man escape; they shall stumble, and fall toward the north by the river Euphrates."},"BSB":{"text":"“The swift cannot flee, and the warrior cannot escape! In the north by the River Euphrates they stumble and fall."},"TANAKH":{"text":"The swift cannot flee away, nor the mighty man escape; in the north by the river Euphrates have they stumbled and fallen."},"HEBREW":{"text":"אַל־יָנ֣וּס הַקַּ֔ל וְאַל־יִמָּלֵ֖ט הַגִּבּ֑וֹר צָפ֙וֹנָה֙ עַל־יַ֣ד נְהַר־פְּרָ֔ת כָּשְׁל֖וּ וְנָפָֽלוּ׃"}},"definableWords":[],"peopleInVerse":[],"placesInVerse":["Jordan River"],"themesInVerse":["fall_sin"]},"7":{"text":"Who is this that cometh up as a flood, whose waters are moved as the rivers?","ref":"Jeremiah 46:7","synthesized":"Who is this, rising like the Nile, like rivers whose waters churn?","sources":{"KJV":{"text":"Who is this that cometh up as a flood, whose waters are moved as the rivers?"},"BSB":{"text":"Who is this, rising like the Nile, like rivers whose waters churn?"},"TANAKH":{"text":"Who is this like the Nile that riseth up, like the rivers whose waters toss themselves?"},"HEBREW":{"text":"מִי־זֶ֖ה כַּיְאֹ֣ר יַֽעֲלֶ֑ה כַּנְּהָר֕וֹת יִֽתְגָּעֲשׁ֖וּ מֵימָֽיו׃"}},"definableWords":["waters"],"peopleInVerse":[]},"8":{"text":"Egypt riseth up like a flood, and his waters are moved like the rivers; and he saith, I will go up, and will cover the earth; I will destroy the city and the inhabitants thereof.","ref":"Jeremiah 46:8","synthesized":"Egypt rises like the Nile, and its waters churn like rivers, boasting, ‘I will rise and cover the earth; I will destroy the cities and their people.’","sources":{"KJV":{"text":"Egypt riseth up like a flood, and his waters are moved like the rivers; and he saith, I will go up, and will cover the earth; I will destroy the city and the inhabitants thereof."},"BSB":{"text":"Egypt rises like the Nile, and its waters churn like rivers, boasting, ‘I will rise and cover the earth; I will destroy the cities and their people.’"},"TANAKH":{"text":"Egypt is like the Nile that riseth up, and like the rivers whose waters toss themselves; and he saith: 'I will rise up, I will cover the earth, I will destroy the city and the inhabitants thereof.'"},"HEBREW":{"text":"מִצְרַ֙יִם֙ כַּיְאֹ֣ר יַֽעֲלֶ֔ה וְכַנְּהָר֖וֹת יִתְגֹּ֣עֲשׁוּ מָ֑יִם וַיֹּ֗אמֶר אַֽעֲלֶה֙ אֲכַסֶּה־אֶ֔רֶץ אֹבִ֥ידָה עִ֖יר וְיֹ֥שְׁבֵי בָֽהּ׃"}},"definableWords":["Egypt","waters","earth","people"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","resurrection"]},"9":{"text":"Come up, ye horses; and rage, ye chariots; and let the mighty men come forth; the Ethiopians and the Libyans, that handle the shield; and the Lydians, that handle and bend the bow.","ref":"Jeremiah 46:9","synthesized":"Advance, O horses! Race furiously, O chariots! Let the warriors come forth— Cush and Put carrying their shields, men of Lydia drawing the bow.","sources":{"KJV":{"text":"Come up, ye horses; and rage, ye chariots; and let the mighty men come forth; the Ethiopians and the Libyans, that handle the shield; and the Lydians, that handle and bend the bow."},"BSB":{"text":"Advance, O horses! Race furiously, O chariots! Let the warriors come forth— Cush and Put carrying their shields, men of Lydia drawing the bow."},"TANAKH":{"text":"Prance, ye horses, and rush madly, ye chariots; and let the mighty men go forth: Cush and Put, that handle the shield, and the Ludim, that handle and bend the bow."},"HEBREW":{"text":"עֲל֤וּ הַסּוּסִים֙ וְהִתְהֹלְל֣וּ הָרֶ֔כֶב וְיֵצְא֖וּ הַגִּבּוֹרִ֑ים כּ֤וּשׁ וּפוּט֙ תֹּפְשֵׂ֣י מָגֵ֔ן וְלוּדִ֕ים תֹּפְשֵׂ֖י דֹּ֥רְכֵי קָֽשֶׁת׃"}},"definableWords":["men"],"peopleInVerse":["Cush"],"themesInVerse":["worship"]},"10":{"text":"For this is the day of the Lord GOD of hosts, a day of vengeance, that he may avenge him of his adversaries: and the sword shall devour, and it shall be satiate and made drunk with their blood: for the Lord GOD of hosts hath a sacrifice in the north country by the river Euphrates.","ref":"Jeremiah 46:10","synthesized":"For that day belongs to the Lord GOD of Hosts, a day of vengeance against His foes. The sword will devour until it is satisfied, until it is quenched with their blood. For the Lord GOD of Hosts will hold a sacrifice in the land of the north by the River Euphrates.","sources":{"KJV":{"text":"For this is the day of the Lord GOD of hosts, a day of vengeance, that he may avenge him of his adversaries: and the sword shall devour, and it shall be satiate and made drunk with their blood: for the Lord GOD of hosts hath a sacrifice in the north country by the river Euphrates."},"BSB":{"text":"For that day belongs to the Lord GOD of Hosts, a day of vengeance against His foes. The sword will devour until it is satisfied, until it is quenched with their blood. For the Lord GOD of Hosts will hold a sacrifice in the land of the north by the River Euphrates."},"TANAKH":{"text":"For the L-rd GOD of hosts shall have on that day a day of vengeance, that He may avenge Him of His adversaries; and the sword shall devour and be satiate, and shall be made drunk with their blood; for the L-rd GOD of hosts hath a sacrifice in the north country by the river Euphrates."},"HEBREW":{"text":"וְֽהַיּ֨וֹם הַה֜וּא לַאדֹנָ֧י יְהוִ֣ה צְבָא֗וֹת י֤וֹם נְקָמָה֙ לְהִנָּקֵ֣ם מִצָּרָ֔יו וְאָכְלָ֥ה חֶ֙רֶב֙ וְשָׂ֣בְעָ֔ה וְרָוְתָ֖ה מִדָּמָ֑ם כִּ֣י זֶ֠בַח לַאדֹנָ֨י יְהוִ֧ה צְבָא֛וֹת בְּאֶ֥רֶץ צָפ֖וֹן אֶל־נְהַר־פְּרָֽת׃"}},"definableWords":["day","Lord","God","blood","sacrifice","land"],"peopleInVerse":[],"placesInVerse":["Jordan River"],"themesInVerse":["land_promise","passover","sacrifice"]},"11":{"text":"Go up into Gilead, and take balm, O virgin, the daughter of Egypt: in vain shalt thou use many medicines; for thou shalt not be cured.","ref":"Jeremiah 46:11","synthesized":"Go up to Gilead for balm, O Virgin Daughter of Egypt! In vain you try many remedies, but for you there is no healing.","sources":{"KJV":{"text":"Go up into Gilead, and take balm, O virgin, the daughter of Egypt: in vain shalt thou use many medicines; for thou shalt not be cured."},"BSB":{"text":"Go up to Gilead for balm, O Virgin Daughter of Egypt! In vain you try many remedies, but for you there is no healing."},"TANAKH":{"text":"Go up into Gilead, and take balm, O virgin daughter of Egypt; in vain dost thou use many medicines; there is no cure for thee."},"HEBREW":{"text":"עֲלִ֤י גִלְעָד֙ וּקְחִ֣י צֳרִ֔י בְּתוּלַ֖ת בַּת־מִצְרָ֑יִם לַשָּׁוְא֙ הרביתי הִרְבֵּ֣ית רְפֻא֔וֹת תְּעָלָ֖ה אֵ֥ין לָֽךְ׃"}},"definableWords":["daughter","Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern"]},"12":{"text":"The nations have heard of thy shame, and thy cry hath filled the land: for the mighty man hath stumbled against the mighty, and they are fallen both together.","ref":"Jeremiah 46:12","synthesized":"The nations have heard of your shame, and your outcry fills the earth, because warrior stumbles over warrior and both of them have fallen together.”","sources":{"KJV":{"text":"The nations have heard of thy shame, and thy cry hath filled the land: for the mighty man hath stumbled against the mighty, and they are fallen both together."},"BSB":{"text":"The nations have heard of your shame, and your outcry fills the earth, because warrior stumbles over warrior and both of them have fallen together.”"},"TANAKH":{"text":"The nations have heard of thy shame, and the earth is full of thy cry; for the mighty man hath stumbled against the mighty, they are fallen both of them together."},"HEBREW":{"text":"שָׁמְע֤וּ גוֹיִם֙ קְלוֹנֵ֔ךְ וְצִוְחָתֵ֖ךְ מָלְאָ֣ה הָאָ֑רֶץ כִּֽי־גִבּ֤וֹר בְּגִבּוֹר֙ כָּשָׁ֔לוּ יַחְדָּ֖יו נָפְל֥וּ שְׁנֵיהֶֽם׃"}},"definableWords":["nations","earth"],"peopleInVerse":[]},"13":{"text":"The word that the LORD spake to Jeremiah the prophet, how Nebuchadrezzar king of Babylon should come and smite the land of Egypt.","ref":"Jeremiah 46:13","synthesized":"This is the word that the LORD spoke to Jeremiah the prophet about the coming of Nebuchadnezzar king of Babylon to strike the land of Egypt:","sources":{"KJV":{"text":"The word that the LORD spake to Jeremiah the prophet, how Nebuchadrezzar king of Babylon should come and smite the land of Egypt."},"BSB":{"text":"This is the word that the LORD spoke to Jeremiah the prophet about the coming of Nebuchadnezzar king of Babylon to strike the land of Egypt:"},"TANAKH":{"text":"The word that HaShem spoke to Jeremiah the prophet, how that Nebuchadrezzar king of Babylon should come and smite the land of Egypt."},"HEBREW":{"text":"הַדָּבָר֙ אֲשֶׁ֣ר דִּבֶּ֣ר יְהוָ֔ה אֶֽל־יִרְמְיָ֖הוּ הַנָּבִ֑יא לָב֗וֹא נְבֽוּכַדְרֶאצַּר֙ מֶ֣לֶךְ בָּבֶ֔ל לְהַכּ֖וֹת אֶת־אֶ֥רֶץ מִצְרָֽיִם׃"}},"definableWords":["word","LORD","prophet","king","Babylon","land","Egypt"],"peopleInVerse":["Jeremiah","Nebuchadnezzar"],"placesInVerse":["Babylon","Egypt"],"themesInVerse":["exodus_pattern","kingship","land_promise","second_coming"]},"14":{"text":"Declare ye in Egypt, and publish in Migdol, and publish in Noph and in Tahpanhes: say ye, Stand fast, and prepare thee; for the sword shall devour round about thee.","ref":"Jeremiah 46:14","synthesized":"“Announce it in Egypt, and proclaim it in Migdol; proclaim it in Memphis and Tahpanhes: ‘Take your positions and prepare yourself, for the sword devours those around you.’","sources":{"KJV":{"text":"Declare ye in Egypt, and publish in Migdol, and publish in Noph and in Tahpanhes: say ye, Stand fast, and prepare thee; for the sword shall devour round about thee."},"BSB":{"text":"“Announce it in Egypt, and proclaim it in Migdol; proclaim it in Memphis and Tahpanhes: ‘Take your positions and prepare yourself, for the sword devours those around you.’"},"TANAKH":{"text":"Declare ye in Egypt, and announce in Migdol, and announce in Noph and in Tahpanhes; say ye: 'Stand forth, and prepare thee, for the sword hath devoured round about thee.'"},"HEBREW":{"text":"הַגִּ֤ידוּ בְמִצְרַ֙יִם֙ וְהַשְׁמִ֣יעוּ בְמִגְדּ֔וֹל וְהַשְׁמִ֥יעוּ בְנֹ֖ף וּבְתַחְפַּנְחֵ֑ס אִמְר֗וּ הִתְיַצֵּב֙ וְהָכֵ֣ן לָ֔ךְ כִּֽי־אָכְלָ֥ה חֶ֖רֶב סְבִיבֶֽיךָ׃"}},"definableWords":["Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern"]},"15":{"text":"Why are thy valiant men swept away? they stood not, because the LORD did drive them.","ref":"Jeremiah 46:15","synthesized":"Why have your warriors been laid low? They cannot stand, for the LORD has thrust them down.","sources":{"KJV":{"text":"Why are thy valiant men swept away? they stood not, because the LORD did drive them."},"BSB":{"text":"Why have your warriors been laid low? They cannot stand, for the LORD has thrust them down."},"TANAKH":{"text":"Why is thy strong one overthrown? He stood not, because HaShem did thrust him down."},"HEBREW":{"text":"מַדּ֖וּעַ נִסְחַ֣ף אַבִּירֶ֑יךָ לֹ֣א עָמַ֔ד כִּ֥י יְהוָ֖ה הֲדָפֽוֹ׃"}},"definableWords":["stand","LORD"],"peopleInVerse":[]},"16":{"text":"He made many to fall, yea, one fell upon another: and they said, Arise, and let us go again to our own people, and to the land of our nativity, from the oppressing sword.","ref":"Jeremiah 46:16","synthesized":"They continue to stumble; indeed, they have fallen over one another. They say, ‘Get up! Let us return to our people and to the land of our birth, away from the sword of the oppressor.’","sources":{"KJV":{"text":"He made many to fall, yea, one fell upon another: and they said, Arise, and let us go again to our own people, and to the land of our nativity, from the oppressing sword."},"BSB":{"text":"They continue to stumble; indeed, they have fallen over one another. They say, ‘Get up! Let us return to our people and to the land of our birth, away from the sword of the oppressor.’"},"TANAKH":{"text":"He made many to stumble; yea, they fell one upon another, and said: 'Arise, and let us return to our own people, and to the land of our birth, from the oppressing sword.'"},"HEBREW":{"text":"הִרְבָּ֖ה כּוֹשֵׁ֑ל גַּם־נָפַ֞ל אִ֣ישׁ אֶל־רֵעֵ֗הוּ וַיֹּֽאמְרוּ֙ ק֣וּמָה ׀ וְנָשֻׁ֣בָה אֶל־עַמֵּ֗נוּ וְאֶל־אֶ֙רֶץ֙ מֽוֹלַדְתֵּ֔נוּ מִפְּנֵ֖י חֶ֥רֶב הַיּוֹנָֽה׃"}},"definableWords":["one","people","land"],"peopleInVerse":[],"themesInVerse":["exile_return","land_promise","second_coming"]},"17":{"text":"They did cry there, Pharaoh king of Egypt is but a noise; he hath passed the time appointed.","ref":"Jeremiah 46:17","synthesized":"There they will cry out: ‘Pharaoh king of Egypt was all noise; he has let the appointed time pass him by.’","sources":{"KJV":{"text":"They did cry there, Pharaoh king of Egypt is but a noise; he hath passed the time appointed."},"BSB":{"text":"There they will cry out: ‘Pharaoh king of Egypt was all noise; he has let the appointed time pass him by.’"},"TANAKH":{"text":"They cried there: 'Pharaoh king of Egypt is but a noise; he hath let the appointed time pass by.'"},"HEBREW":{"text":"קָרְא֖וּ שָׁ֑ם פַּרְעֹ֤ה מֶֽלֶךְ־מִצְרַ֙יִם֙ שָׁא֔וֹן הֶעֱבִ֖יר הַמּוֹעֵֽד׃"}},"definableWords":["Pharaoh","king","Egypt"],"peopleInVerse":["Pharaoh"],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","kingship"]},"18":{"text":"As I live, saith the King, whose name is the LORD of hosts, Surely as Tabor is among the mountains, and as Carmel by the sea, so shall he come.","ref":"Jeremiah 46:18","synthesized":"As surely as I live, declares the King, whose name is the LORD of Hosts, there will come one who is like Tabor among the mountains and like Carmel by the sea.","sources":{"KJV":{"text":"As I live, saith the King, whose name is the LORD of hosts, Surely as Tabor is among the mountains, and as Carmel by the sea, so shall he come."},"BSB":{"text":"As surely as I live, declares the King, whose name is the LORD of Hosts, there will come one who is like Tabor among the mountains and like Carmel by the sea."},"TANAKH":{"text":"As I live, saith the King, whose name is HaShem of hosts, surely like Tabor among the mountains, and like Carmel by the sea, so shall he come."},"HEBREW":{"text":"חַי־אָ֙נִי֙ נְאֻם־הַמֶּ֔לֶךְ יְהוָ֥ה צְבָא֖וֹת שְׁמ֑וֹ כִּ֚י כְּתָב֣וֹר בֶּֽהָרִ֔ים וּכְכַרְמֶ֖ל בַּיָּ֥ם יָבֽוֹא׃"}},"definableWords":["live","King","name","LORD","one","sea"],"peopleInVerse":[],"placesInVerse":["Mount Tabor","Mount Carmel"],"themesInVerse":["kingship"]},"19":{"text":"O thou daughter dwelling in Egypt, furnish thyself to go into captivity: for Noph shall be waste and desolate without an inhabitant.","ref":"Jeremiah 46:19","synthesized":"Pack your bags for exile, O daughter dwelling in Egypt! For Memphis will be laid waste, destroyed and uninhabited.","sources":{"KJV":{"text":"O thou daughter dwelling in Egypt, furnish thyself to go into captivity: for Noph shall be waste and desolate without an inhabitant."},"BSB":{"text":"Pack your bags for exile, O daughter dwelling in Egypt! For Memphis will be laid waste, destroyed and uninhabited."},"TANAKH":{"text":"O thou daughter that dwellest in Egypt, furnish thyself to go into captivity; for Noph shall become a desolation, and shall be laid waste, without inhabitant."},"HEBREW":{"text":"כְּלֵ֤י גוֹלָה֙ עֲשִׂ֣י לָ֔ךְ יוֹשֶׁ֖בֶת בַּת־מִצְרָ֑יִם כִּֽי־נֹף֙ לְשַׁמָּ֣ה תִֽהְיֶ֔ה וְנִצְּתָ֖ה מֵאֵ֥ין יוֹשֵֽׁב׃"}},"definableWords":["daughter","Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exile_return","exodus_pattern","temple"]},"20":{"text":"Egypt is like a very fair heifer, but destruction cometh; it cometh out of the north.","ref":"Jeremiah 46:20","synthesized":"Egypt is a beautiful heifer, but a gadfly from the north is coming against her.","sources":{"KJV":{"text":"Egypt is like a very fair heifer, but destruction cometh; it cometh out of the north."},"BSB":{"text":"Egypt is a beautiful heifer, but a gadfly from the north is coming against her."},"TANAKH":{"text":"Egypt is a very fair heifer; but the gadfly out of the north is come, it is come."},"HEBREW":{"text":"עֶגְלָ֥ה יְפֵֽה־פִיָּ֖ה מִצְרָ֑יִם קֶ֥רֶץ מִצָּפ֖וֹן בָּ֥א בָֽא׃"}},"definableWords":["Egypt"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","second_coming"]},"21":{"text":"Also her hired men are in the midst of her like fatted bullocks; for they also are turned back, and are fled away together: they did not stand, because the day of their calamity was come upon them, and the time of their visitation.","ref":"Jeremiah 46:21","synthesized":"Even the mercenaries among her are like fattened calves. They too will turn back; together they will flee, they will not stand their ground, for the day of calamity is coming upon them— the time of their punishment.","sources":{"KJV":{"text":"Also her hired men are in the midst of her like fatted bullocks; for they also are turned back, and are fled away together: they did not stand, because the day of their calamity was come upon them, and the time of their visitation."},"BSB":{"text":"Even the mercenaries among her are like fattened calves. They too will turn back; together they will flee, they will not stand their ground, for the day of calamity is coming upon them— the time of their punishment."},"TANAKH":{"text":"Also her mercenaries in the midst of her are like calves of the stall, for they also are turned back, they are fled away together, they did not stand; for the day of their calamity is come upon them, the time of their visitation."},"HEBREW":{"text":"גַּם־שְׂכִרֶ֤יהָ בְקִרְבָּהּ֙ כְּעֶגְלֵ֣י מַרְבֵּ֔ק כִּֽי־גַם־הֵ֧מָּה הִפְנ֛וּ נָ֥סוּ יַחְדָּ֖יו לֹ֣א עָמָ֑דוּ כִּ֣י י֥וֹם אֵידָ֛ם בָּ֥א עֲלֵיהֶ֖ם עֵ֥ת פְּקֻדָּתָֽם׃"}},"definableWords":["stand","ground","day"],"peopleInVerse":[],"themesInVerse":["second_coming"]},"22":{"text":"The voice thereof shall go like a serpent; for they shall march with an army, and come against her with axes, as hewers of wood.","ref":"Jeremiah 46:22","synthesized":"Egypt will hiss like a fleeing serpent, for the enemy will advance in force; with axes they will come against her like woodsmen cutting down trees.","sources":{"KJV":{"text":"The voice thereof shall go like a serpent; for they shall march with an army, and come against her with axes, as hewers of wood."},"BSB":{"text":"Egypt will hiss like a fleeing serpent, for the enemy will advance in force; with axes they will come against her like woodsmen cutting down trees."},"TANAKH":{"text":"The sound thereof shall go like the serpent's; for they march with an army, and come against her with axes, as hewers of wood."},"HEBREW":{"text":"קוֹלָ֖הּ כַּנָּחָ֣שׁ יֵלֵ֑ךְ כִּֽי־בְחַ֣יִל יֵלֵ֔כוּ וּבְקַרְדֻּמּוֹת֙ בָּ֣אוּ לָ֔הּ כְּחֹטְבֵ֖י עֵצִֽים׃"}},"definableWords":["Egypt","serpent","trees"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern"]},"23":{"text":"They shall cut down her forest, saith the LORD, though it cannot be searched; because they are more than the grasshoppers, and are innumerable.","ref":"Jeremiah 46:23","synthesized":"They will chop down her forest, declares the LORD, dense though it may be, for they are more numerous than locusts; they cannot be counted.","sources":{"KJV":{"text":"They shall cut down her forest, saith the LORD, though it cannot be searched; because they are more than the grasshoppers, and are innumerable."},"BSB":{"text":"They will chop down her forest, declares the LORD, dense though it may be, for they are more numerous than locusts; they cannot be counted."},"TANAKH":{"text":"They cut down her forest, saith HaShem, though it cannot be searched; because they are more than the locusts, and are innumerable."},"HEBREW":{"text":"כָּרְת֤וּ יַעְרָהּ֙ נְאֻם־יְהוָ֔ה כִּ֖י לֹ֣א יֵֽחָקֵ֑ר כִּ֤י רַבּוּ֙ מֵֽאַרְבֶּ֔ה וְאֵ֥ין לָהֶ֖ם מִסְפָּֽר׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"24":{"text":"The daughter of Egypt shall be confounded; she shall be delivered into the hand of the people of the north.","ref":"Jeremiah 46:24","synthesized":"The Daughter of Egypt will be put to shame; she will be delivered into the hands of the people of the north.”","sources":{"KJV":{"text":"The daughter of Egypt shall be confounded; she shall be delivered into the hand of the people of the north."},"BSB":{"text":"The Daughter of Egypt will be put to shame; she will be delivered into the hands of the people of the north.”"},"TANAKH":{"text":"The daughter of Egypt is put to shame; she is delivered into the hand of the people of the north."},"HEBREW":{"text":"הֹבִ֖ישָׁה בַּת־מִצְרָ֑יִם נִתְּנָ֖ה בְּיַ֥ד עַם־צָפֽוֹן׃"}},"definableWords":["daughter","Egypt","people"],"peopleInVerse":[],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern"]},"25":{"text":"The LORD of hosts, the God of Israel, saith; Behold, I will punish the multitude of No, and Pharaoh, and Egypt, with their gods, and their kings; even Pharaoh, and all them that trust in him:","ref":"Jeremiah 46:25","synthesized":"The LORD of Hosts, the God of Israel, says: “Behold, I am about to punish Amon god of Thebes, along with Pharaoh, Egypt with her gods and kings, and those who trust in Pharaoh.","sources":{"KJV":{"text":"The LORD of hosts, the God of Israel, saith; Behold, I will punish the multitude of No, and Pharaoh, and Egypt, with their gods, and their kings; even Pharaoh, and all them that trust in him:"},"BSB":{"text":"The LORD of Hosts, the God of Israel, says: “Behold, I am about to punish Amon god of Thebes, along with Pharaoh, Egypt with her gods and kings, and those who trust in Pharaoh."},"TANAKH":{"text":"HaShem of hosts, the G-d of Israel, saith: Behold, I will punish Amon of No, and Pharaoh, and Egypt, with her gods, and her kings; even Pharaoh, and them that trust in him;"},"HEBREW":{"text":"אָמַר֩ יְהוָ֨ה צְבָא֜וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֗ל הִנְנִ֤י פוֹקֵד֙ אֶל־אָמ֣וֹן מִנֹּ֔א וְעַל־פַּרְעֹה֙ וְעַל־מִצְרַ֔יִם וְעַל־אֱלֹהֶ֖יהָ וְעַל־מְלָכֶ֑יהָ וְעַ֨ל־פַּרְעֹ֔ה וְעַ֥ל הַבֹּטְחִ֖ים בּֽוֹ׃"}},"definableWords":["LORD","God","Israel","Pharaoh","Egypt","kings","trust"],"peopleInVerse":["Pharaoh"],"placesInVerse":["Egypt"],"themesInVerse":["exodus_pattern","faith"]},"26":{"text":"And I will deliver them into the hand of those that seek their lives, and into the hand of Nebuchadrezzar king of Babylon, and into the hand of his servants: and afterward it shall be inhabited, as in the days of old, saith the LORD.","ref":"Jeremiah 46:26","synthesized":"I will deliver them into the hands of those who seek their lives—of Nebuchadnezzar king of Babylon and his officers. But after this, Egypt will be inhabited as in days of old, declares the LORD.","sources":{"KJV":{"text":"And I will deliver them into the hand of those that seek their lives, and into the hand of Nebuchadrezzar king of Babylon, and into the hand of his servants: and afterward it shall be inhabited, as in the days of old, saith the LORD."},"BSB":{"text":"I will deliver them into the hands of those who seek their lives—of Nebuchadnezzar king of Babylon and his officers. But after this, Egypt will be inhabited as in days of old, declares the LORD."},"TANAKH":{"text":"and I will deliver them into the hand of those that seek their lives, and into the hand of Nebuchadrezzar king of Babylon, and into the hand of his servants; and afterwards it shall be inhabited, as in the days of old, saith HaShem."},"HEBREW":{"text":"וּנְתַתִּ֗ים בְּיַד֙ מְבַקְשֵׁ֣י נַפְשָׁ֔ם וּבְיַ֛ד נְבֽוּכַדְרֶאצַּ֥ר מֶֽלֶךְ־בָּבֶ֖ל וּבְיַד־עֲבָדָ֑יו וְאַחֲרֵי־כֵ֛ן תִּשְׁכֹּ֥ן כִּֽימֵי־קֶ֖דֶם נְאֻם־יְהוָֽה׃"}},"definableWords":["deliver","seek","king","Babylon","Egypt","days","LORD"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon","Egypt"],"themesInVerse":["exodus_pattern","kingship","redemption","salvation"]},"27":{"text":"But fear not thou, O my servant Jacob, and be not dismayed, O Israel: for, behold, I will save thee from afar off, and thy seed from the land of their captivity; and Jacob shall return, and be in rest and at ease, and none shall make him afraid.","ref":"Jeremiah 46:27","synthesized":"But you, O Jacob My servant, do not be afraid, and do not be dismayed, O Israel. For I will surely save you out of a distant place, your descendants from the land of their captivity! Jacob will return to quiet and ease, with no one to make him afraid.","sources":{"KJV":{"text":"But fear not thou, O my servant Jacob, and be not dismayed, O Israel: for, behold, I will save thee from afar off, and thy seed from the land of their captivity; and Jacob shall return, and be in rest and at ease, and none shall make him afraid."},"BSB":{"text":"But you, O Jacob My servant, do not be afraid, and do not be dismayed, O Israel. For I will surely save you out of a distant place, your descendants from the land of their captivity! Jacob will return to quiet and ease, with no one to make him afraid."},"TANAKH":{"text":"But fear not thou, O Jacob My servant, neither be dismayed, O Israel; for, lo, I will save thee from afar, and thy seed from the land of their captivity; and Jacob shall again be quiet and at ease, and none shall make him afraid."},"HEBREW":{"text":"וְ֠אַתָּה אַל־תִּירָ֞א עַבְדִּ֤י יַֽעֲקֹב֙ וְאַל־תֵּחַ֣ת יִשְׂרָאֵ֔ל כִּ֠י הִנְנִ֤י מוֹשִֽׁעֲךָ֙ מֵֽרָח֔וֹק וְאֶֽת־זַרְעֲךָ֖ מֵאֶ֣רֶץ שִׁבְיָ֑ם וְשָׁ֧ב יַעֲק֛וֹב וְשָׁקַ֥ט וְשַׁאֲנַ֖ן וְאֵ֥ין מַחֲרִֽיד׃"}},"definableWords":["Jacob","servant","Israel","land","one","make"],"peopleInVerse":["Jacob"],"themesInVerse":["exile_return","land_promise","salvation","second_coming"]},"28":{"text":"Fear thou not, O Jacob my servant, saith the LORD: for I am with thee; for I will make a full end of all the nations whither I have driven thee: but I will not make a full end of thee, but correct thee in measure; yet will I not leave thee wholly unpunished.","ref":"Jeremiah 46:28","synthesized":"And you, My servant Jacob, do not be afraid, declares the LORD, for I am with you. Though I will completely destroy all the nations to which I have banished you, I will not completely destroy you. Yet I will discipline you justly, and will by no means leave you unpunished.”","sources":{"KJV":{"text":"Fear thou not, O Jacob my servant, saith the LORD: for I am with thee; for I will make a full end of all the nations whither I have driven thee: but I will not make a full end of thee, but correct thee in measure; yet will I not leave thee wholly unpunished."},"BSB":{"text":"And you, My servant Jacob, do not be afraid, declares the LORD, for I am with you. Though I will completely destroy all the nations to which I have banished you, I will not completely destroy you. Yet I will discipline you justly, and will by no means leave you unpunished.”"},"TANAKH":{"text":"Fear not thou, O Jacob My servant, saith HaShem, for I am with thee; for I will make a full end of all the nations whither I have driven thee, but I will not make a full end of thee; and I will correct thee in measure, but will not utterly destroy thee."},"HEBREW":{"text":"אַ֠תָּה אַל־תִּירָ֞א עַבְדִּ֤י יַֽעֲקֹב֙ נְאֻם־יְהוָ֔ה כִּ֥י אִתְּךָ֖ אָ֑נִי כִּי֩ אֶעֱשֶׂ֨ה כָלָ֜ה בְּכָֽל־הַגּוֹיִ֣ם ׀ אֲשֶׁ֧ר הִדַּחְתִּ֣יךָ שָׁ֗מָּה וְאֹֽתְךָ֙ לֹא־אֶעֱשֶׂ֣ה כָלָ֔ה וְיִסַּרְתִּ֙יךָ֙ לַמִּשְׁפָּ֔ט וְנַקֵּ֖ה לֹ֥א אֲנַקֶּֽךָּ׃"}},"definableWords":["servant","Jacob","LORD","nations"],"peopleInVerse":["Jacob"]}}},"47":{"chapter":"47","title":"PROPHECY AGAINST THE PHILISTINES","verses":{"1":{"text":"The word of the LORD that came to Jeremiah the prophet against the Philistines, before that Pharaoh smote Gaza.","ref":"Jeremiah 47:1","synthesized":"This is the word of the LORD that came to Jeremiah the prophet about the Philistines before Pharaoh struck down Gaza.","sources":{"KJV":{"text":"The word of the LORD that came to Jeremiah the prophet against the Philistines, before that Pharaoh smote Gaza."},"BSB":{"text":"This is the word of the LORD that came to Jeremiah the prophet about the Philistines before Pharaoh struck down Gaza."},"TANAKH":{"text":"The word of HaShem that came to Jeremiah the prophet concerning the Philistines, before that Pharaoh smote Gaza."},"HEBREW":{"text":"אֲשֶׁ֨ר הָיָ֧ה דְבַר־יְהוָ֛ה אֶל־יִרְמְיָ֥הוּ הַנָּבִ֖יא אֶל־פְּלִשְׁתִּ֑ים בְּטֶ֛רֶם יַכֶּ֥ה פַרְעֹ֖ה אֶת־עַזָּֽה׃"}},"definableWords":["word","LORD","prophet","Pharaoh"],"peopleInVerse":["Jeremiah","Pharaoh"]},"2":{"text":"Thus saith the LORD; Behold, waters rise up out of the north, and shall be an overflowing flood, and shall overflow the land, and all that is therein; the city, and them that dwell therein: then the men shall cry, and all the inhabitants of the land shall howl.","ref":"Jeremiah 47:2","synthesized":"This is what the LORD says:  “See how the waters are rising from the north and becoming an overflowing torrent. They will overflow the land and its fullness, the cities and their inhabitants. The people will cry out, and all who dwell in the land will wail","sources":{"KJV":{"text":"Thus saith the LORD; Behold, waters rise up out of the north, and shall be an overflowing flood, and shall overflow the land, and all that is therein; the city, and them that dwell therein: then the men shall cry, and all the inhabitants of the land shall howl."},"BSB":{"text":"This is what the LORD says:  “See how the waters are rising from the north and becoming an overflowing torrent. They will overflow the land and its fullness, the cities and their inhabitants. The people will cry out, and all who dwell in the land will wail"},"TANAKH":{"text":"Thus saith HaShem: behold, waters rise up out of the north, and shall become an overflowing stream, and they shall overflow the land and all that is therein, the city and them that dwell therein; and the men shall cry, and all the inhabitants of the land shall wail."},"HEBREW":{"text":"כֹּ֣ה ׀ אָמַ֣ר יְהוָ֗ה הִנֵּה־מַ֜יִם עֹלִ֤ים מִצָּפוֹן֙ וְהָיוּ֙ לְנַ֣חַל שׁוֹטֵ֔ף וְיִשְׁטְפוּ֙ אֶ֣רֶץ וּמְלוֹאָ֔הּ עִ֖יר וְיֹ֣שְׁבֵי בָ֑הּ וְזָֽעֲקוּ֙ הָֽאָדָ֔ם וְהֵילִ֕ל כֹּ֖ל יוֹשֵׁ֥ב הָאָֽרֶץ׃"}},"definableWords":["LORD","see","waters","land","people"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"3":{"text":"At the noise of the stamping of the hoofs of his strong horses, at the rushing of his chariots, and at the rumbling of his wheels, the fathers shall not look back to their children for feebleness of hands;","ref":"Jeremiah 47:3","synthesized":"at the sound of the galloping hooves of stallions, the rumbling of chariots, and the clatter of their wheels. The fathers will not turn back for their sons; their hands will hang limp.","sources":{"KJV":{"text":"At the noise of the stamping of the hoofs of his strong horses, at the rushing of his chariots, and at the rumbling of his wheels, the fathers shall not look back to their children for feebleness of hands;"},"BSB":{"text":"at the sound of the galloping hooves of stallions, the rumbling of chariots, and the clatter of their wheels. The fathers will not turn back for their sons; their hands will hang limp."},"TANAKH":{"text":"At the noise of the stamping of the hoofs of his strong ones, at the rushing of his chariots, at the rumbling of his wheels, the fathers look not back to their children for feebleness of hands;"},"HEBREW":{"text":"מִקּ֗וֹל שַֽׁעֲטַת֙ פַּרְס֣וֹת אַבִּירָ֔יו מֵרַ֣עַשׁ לְרִכְבּ֔וֹ הֲמ֖וֹן גַּלְגִּלָּ֑יו לֹֽא־הִפְנ֤וּ אָבוֹת֙ אֶל־בָּנִ֔ים מֵֽרִפְי֖וֹן יָדָֽיִם׃"}},"definableWords":["fathers","sons"],"peopleInVerse":[]},"4":{"text":"Because of the day that cometh to spoil all the Philistines, and to cut off from Tyrus and Zidon every helper that remaineth: for the LORD will spoil the Philistines, the remnant of the country of Caphtor.","ref":"Jeremiah 47:4","synthesized":"For the day has come to destroy all the Philistines, to cut off from Tyre and Sidon every remaining ally. Indeed, the LORD is about to destroy the Philistines, the remnant from the coasts of Caphtor.","sources":{"KJV":{"text":"Because of the day that cometh to spoil all the Philistines, and to cut off from Tyrus and Zidon every helper that remaineth: for the LORD will spoil the Philistines, the remnant of the country of Caphtor."},"BSB":{"text":"For the day has come to destroy all the Philistines, to cut off from Tyre and Sidon every remaining ally. Indeed, the LORD is about to destroy the Philistines, the remnant from the coasts of Caphtor."},"TANAKH":{"text":"Because of the day that cometh to spoil all the Philistines, to cut off from Tyre and Zidon every helper that remaineth; for HaShem will spoil the Philistines, the remnant of the isle of Caphtor."},"HEBREW":{"text":"עַל־הַיּ֗וֹם הַבָּא֙ לִשְׁד֣וֹד אֶת־כָּל־פְּלִשְׁתִּ֔ים לְהַכְרִ֤ית לְצֹר֙ וּלְצִיד֔וֹן כֹּ֖ל שָׂרִ֣יד עֹזֵ֑ר כִּֽי־שֹׁדֵ֤ד יְהוָה֙ אֶת־פְּלִשְׁתִּ֔ים שְׁאֵרִ֖ית אִ֥י כַפְתּֽוֹר׃"}},"definableWords":["day","LORD","remnant"],"peopleInVerse":[],"placesInVerse":["Tyre","Sidon"],"themesInVerse":["exile_return"]},"5":{"text":"Baldness is come upon Gaza; Ashkelon is cut off with the remnant of their valley: how long wilt thou cut thyself?","ref":"Jeremiah 47:5","synthesized":"The people of Gaza will shave their heads in mourning; Ashkelon will be silenced. O remnant of their valley, how long will you gash yourself?","sources":{"KJV":{"text":"Baldness is come upon Gaza; Ashkelon is cut off with the remnant of their valley: how long wilt thou cut thyself?"},"BSB":{"text":"The people of Gaza will shave their heads in mourning; Ashkelon will be silenced. O remnant of their valley, how long will you gash yourself?"},"TANAKH":{"text":"Baldness is come upon Gaza, Ashkelon is brought to nought, the remnant of their valley; how long wilt thou cut thyself?"},"HEBREW":{"text":"בָּ֤אָה קָרְחָה֙ אֶל־עַזָּ֔ה נִדְמְתָ֥ה אַשְׁקְל֖וֹן שְׁאֵרִ֣ית עִמְקָ֑ם עַד־מָתַ֖י תִּתְגּוֹדָֽדִי׃"}},"definableWords":["people","remnant"],"peopleInVerse":[],"themesInVerse":["exile_return"]},"6":{"text":"O thou sword of the LORD, how long will it be ere thou be quiet? put up thyself into thy scabbard, rest, and be still.","ref":"Jeremiah 47:6","synthesized":"‘Alas, O sword of the LORD, how long until you rest? Return to your sheath; cease and be still!’","sources":{"KJV":{"text":"O thou sword of the LORD, how long will it be ere thou be quiet? put up thyself into thy scabbard, rest, and be still."},"BSB":{"text":"‘Alas, O sword of the LORD, how long until you rest? Return to your sheath; cease and be still!’"},"TANAKH":{"text":"O thou sword of HaShem, how long will it be ere thou be quiet? Put up thyself into thy scabbard, rest, and be still."},"HEBREW":{"text":"ה֗וֹי חֶ֚רֶב לַֽיהוָ֔ה עַד־אָ֖נָה לֹ֣א תִשְׁקֹ֑טִי הֵאָֽסְפִי֙ אַל־תַּעְרֵ֔ךְ הֵרָגְעִ֖י וָדֹֽמִּי׃"}},"definableWords":["LORD","rest"],"peopleInVerse":[],"themesInVerse":["exile_return","peace","sabbath_rest","second_coming"]},"7":{"text":"How can it be quiet, seeing the LORD hath given it a charge against Ashkelon, and against the sea shore? there hath he appointed it.","ref":"Jeremiah 47:7","synthesized":"How can it rest when the LORD has commanded it? He has appointed it against Ashkelon and the shore of its coastland.”","sources":{"KJV":{"text":"How can it be quiet, seeing the LORD hath given it a charge against Ashkelon, and against the sea shore? there hath he appointed it."},"BSB":{"text":"How can it rest when the LORD has commanded it? He has appointed it against Ashkelon and the shore of its coastland.”"},"TANAKH":{"text":"How canst thou be quiet? for HaShem hath given it a charge; against Ashkelon, and against the sea-shore, there hath He appointed it."},"HEBREW":{"text":"אֵ֣יךְ תִּשְׁקֹ֔טִי וַֽיהוָ֖ה צִוָּה־לָ֑הּ אֶֽל־אַשְׁקְל֛וֹן וְאֶל־ח֥וֹף הַיָּ֖ם שָׁ֥ם יְעָדָֽהּ׃"}},"definableWords":["rest","LORD"],"peopleInVerse":[],"themesInVerse":["peace","sabbath_rest"]}}},"48":{"chapter":"48","title":"PROPHECY AGAINST MOAB","verses":{"1":{"text":"Against Moab thus saith the LORD of hosts, the God of Israel; Woe unto Nebo! for it is spoiled: Kiriathaim is confounded and taken: Misgab is confounded and dismayed.","ref":"Jeremiah 48:1","synthesized":"Concerning Moab, this is what the LORD of Hosts, the God of Israel, says:  “Woe to Nebo, for it will be devastated. Kiriathaim will be captured and disgraced; the fortress will be shattered and dismantled.","sources":{"KJV":{"text":"Against Moab thus saith the LORD of hosts, the God of Israel; Woe unto Nebo! for it is spoiled: Kiriathaim is confounded and taken: Misgab is confounded and dismayed."},"BSB":{"text":"Concerning Moab, this is what the LORD of Hosts, the God of Israel, says:  “Woe to Nebo, for it will be devastated. Kiriathaim will be captured and disgraced; the fortress will be shattered and dismantled."},"TANAKH":{"text":"Of Moab. Thus saith HaShem of hosts, the G-d of Israel: Woe unto Nebo! for it is spoiled; Kiriathaim is put to shame, it is taken; Misgab is put to shame and dismayed."},"HEBREW":{"text":"לְמוֹאָ֡ב כֹּֽה־אָמַר֩ יְהוָ֨ה צְבָא֜וֹת אֱלֹהֵ֣י יִשְׂרָאֵ֗ל ה֤וֹי אֶל־נְבוֹ֙ כִּ֣י שֻׁדָּ֔דָה הֹבִ֥ישָׁה נִלְכְּדָ֖ה קִרְיָתָ֑יִם הֹבִ֥ישָׁה הַמִּשְׂגָּ֖ב וָחָֽתָּה׃"}},"definableWords":["LORD","God","Israel"],"peopleInVerse":[],"placesInVerse":["Mount Nebo"]},"2":{"text":"There shall be no more praise of Moab: in Heshbon they have devised evil against it; come, and let us cut it off from being a nation. Also thou shalt be cut down, O Madmen; the sword shall pursue thee.","ref":"Jeremiah 48:2","synthesized":"There is no longer praise for Moab; in Heshbon they devise evil against her: ‘Come, let us cut her off from nationhood.’   You too, O people of Madmen, will be silenced; the sword will pursue you.","sources":{"KJV":{"text":"There shall be no more praise of Moab: in Heshbon they have devised evil against it; come, and let us cut it off from being a nation. Also thou shalt be cut down, O Madmen; the sword shall pursue thee."},"BSB":{"text":"There is no longer praise for Moab; in Heshbon they devise evil against her: ‘Come, let us cut her off from nationhood.’   You too, O people of Madmen, will be silenced; the sword will pursue you."},"TANAKH":{"text":"The praise of Moab is no more; in Heshbon they have devised evil against her: 'Come, and let us cut her off from being a nation.' Thou also, O Madmen, shalt be brought to silence; the sword shall pursue thee."},"HEBREW":{"text":"אֵ֣ין עוֹד֮ תְּהִלַּ֣ת מוֹאָב֒ בְּחֶשְׁבּ֗וֹן חָשְׁב֤וּ עָלֶ֙יהָ֙ רָעָ֔ה לְכ֖וּ וְנַכְרִיתֶ֣נָּה מִגּ֑וֹי גַּם־מַדְמֵ֣ן תִּדֹּ֔מִּי אַחֲרַ֖יִךְ תֵּ֥לֶךְ חָֽרֶב׃"}},"definableWords":["praise","evil","people"],"peopleInVerse":[],"themesInVerse":["worship"]},"3":{"text":"A voice of crying shall be from Horonaim, spoiling and great destruction.","ref":"Jeremiah 48:3","synthesized":"A voice cries out from Horonaim: ‘Devastation and great destruction!’","sources":{"KJV":{"text":"A voice of crying shall be from Horonaim, spoiling and great destruction."},"BSB":{"text":"A voice cries out from Horonaim: ‘Devastation and great destruction!’"},"TANAKH":{"text":"Hark! a cry from Horonaim, spoiling and great destruction!"},"HEBREW":{"text":"ק֥וֹל צְעָקָ֖ה מֵחֹֽרוֹנָ֑יִם שֹׁ֖ד וָשֶׁ֥בֶר גָּדֽוֹל׃"}},"definableWords":["voice","great"],"peopleInVerse":[]},"4":{"text":"Moab is destroyed; her little ones have caused a cry to be heard.","ref":"Jeremiah 48:4","synthesized":"Moab will be shattered; her little ones will cry out.","sources":{"KJV":{"text":"Moab is destroyed; her little ones have caused a cry to be heard."},"BSB":{"text":"Moab will be shattered; her little ones will cry out."},"TANAKH":{"text":"Moab is destroyed; her little ones have caused a cry to be heard."},"HEBREW":{"text":"נִשְׁבְּרָ֖ה מוֹאָ֑ב הִשְׁמִ֥יעוּ זְּעָקָ֖ה צעוריה צְעִירֶֽיהָ׃"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"For in the going up of Luhith continual weeping shall go up; for in the going down of Horonaim the enemies have heard a cry of destruction.","ref":"Jeremiah 48:5","synthesized":"For on the ascent to Luhith they weep bitterly as they go, and on the descent to Horonaim cries of distress resound over the destruction:","sources":{"KJV":{"text":"For in the going up of Luhith continual weeping shall go up; for in the going down of Horonaim the enemies have heard a cry of destruction."},"BSB":{"text":"For on the ascent to Luhith they weep bitterly as they go, and on the descent to Horonaim cries of distress resound over the destruction:"},"TANAKH":{"text":"For by the ascent of Luhith with continual weeping shall they go up; for in the going down of Horonaim they have heard the distressing cry of destruction."},"HEBREW":{"text":"כִּ֚י מַעֲלֵ֣ה הלחות הַלּוּחִ֔ית בִּבְכִ֖י יַֽעֲלֶה־בֶּ֑כִי כִּ֚י בְּמוֹרַ֣ד חוֹרֹנַ֔יִם צָרֵ֥י צַֽעֲקַת־שֶׁ֖בֶר שָׁמֵֽעוּ׃"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Flee, save your lives, and be like the heath in the wilderness.","ref":"Jeremiah 48:6","synthesized":"‘Flee! Run for your lives! Become like a juniper in the desert.’","sources":{"KJV":{"text":"Flee, save your lives, and be like the heath in the wilderness."},"BSB":{"text":"‘Flee! Run for your lives! Become like a juniper in the desert.’"},"TANAKH":{"text":"Flee, save your lives, and be like a tamarisk in the wilderness."},"HEBREW":{"text":"נֻ֖סוּ מַלְּט֣וּ נַפְשְׁכֶ֑ם וְתִֽהְיֶ֕ינָה כַּעֲרוֹעֵ֖ר בַּמִּדְבָּֽר׃"}},"definableWords":["run"],"peopleInVerse":[]},"7":{"text":"For because thou hast trusted in thy works and in thy treasures, thou shalt also be taken: and Chemosh shall go forth into captivity with his priests and his princes together.","ref":"Jeremiah 48:7","synthesized":"Because you trust in your works and treasures, you too will be captured, and Chemosh will go into exile with his priests and officials.","sources":{"KJV":{"text":"For because thou hast trusted in thy works and in thy treasures, thou shalt also be taken: and Chemosh shall go forth into captivity with his priests and his princes together."},"BSB":{"text":"Because you trust in your works and treasures, you too will be captured, and Chemosh will go into exile with his priests and officials."},"TANAKH":{"text":"For, because thou hast trusted in thy works and in thy treasures, thou also shalt be taken; and Chemosh shall go forth into captivity, his priests and his princes together."},"HEBREW":{"text":"כִּ֠י יַ֣עַן בִּטְחֵ֤ךְ בְּמַעֲשַׂ֙יִךְ֙ וּבְא֣וֹצְרוֹתַ֔יִךְ גַּם־אַ֖תְּ תִּלָּכֵ֑דִי וְיָצָ֤א כמיש כְמוֹשׁ֙ בַּגּוֹלָ֔ה כֹּהֲנָ֥יו וְשָׂרָ֖יו יחד יַחְדָּֽיו׃"}},"definableWords":["trust","works"],"peopleInVerse":[],"themesInVerse":["exile_return","faith"]},"8":{"text":"And the spoiler shall come upon every city, and no city shall escape: the valley also shall perish, and the plain shall be destroyed, as the LORD hath spoken.","ref":"Jeremiah 48:8","synthesized":"The destroyer will move against every city, and not one town will escape. The valley will also be ruined, and the high plain will be destroyed, as the LORD has said.","sources":{"KJV":{"text":"And the spoiler shall come upon every city, and no city shall escape: the valley also shall perish, and the plain shall be destroyed, as the LORD hath spoken."},"BSB":{"text":"The destroyer will move against every city, and not one town will escape. The valley will also be ruined, and the high plain will be destroyed, as the LORD has said."},"TANAKH":{"text":"And the spoiler shall come upon every city, and no city shall escape; the valley also shall perish, and the plain shall be destroyed; as HaShem hath spoken."},"HEBREW":{"text":"וְיָבֹ֨א שֹׁדֵ֜ד אֶל־כָּל־עִ֗יר וְעִיר֙ לֹ֣א תִמָּלֵ֔ט וְאָבַ֥ד הָעֵ֖מֶק וְנִשְׁמַ֣ד הַמִּישֹׁ֑ר אֲשֶׁ֖ר אָמַ֥ר יְהוָֽה׃"}},"definableWords":["one","LORD"],"peopleInVerse":[]},"9":{"text":"Give wings unto Moab, that it may flee and get away: for the cities thereof shall be desolate, without any to dwell therein.","ref":"Jeremiah 48:9","synthesized":"Put salt on Moab, for she will be laid waste; her cities will become desolate, with no one to dwell in them.","sources":{"KJV":{"text":"Give wings unto Moab, that it may flee and get away: for the cities thereof shall be desolate, without any to dwell therein."},"BSB":{"text":"Put salt on Moab, for she will be laid waste; her cities will become desolate, with no one to dwell in them."},"TANAKH":{"text":"Give wings unto Moab, for she must fly and get away; and her cities shall become a desolation, without any to dwell therein."},"HEBREW":{"text":"תְּנוּ־צִ֣יץ לְמוֹאָ֔ב כִּ֥י נָצֹ֖א תֵּצֵ֑א וְעָרֶ֙יהָ֙ לְשַׁמָּ֣ה תִֽהְיֶ֔ינָה מֵאֵ֥ין יוֹשֵׁ֖ב בָּהֵֽן׃"}},"definableWords":["one"],"peopleInVerse":[]},"10":{"text":"Cursed be he that doeth the work of the LORD deceitfully, and cursed be he that keepeth back his sword from blood.","ref":"Jeremiah 48:10","synthesized":"Cursed is the one who is remiss in doing the work of the LORD, and cursed is he who withholds his sword from bloodshed.","sources":{"KJV":{"text":"Cursed be he that doeth the work of the LORD deceitfully, and cursed be he that keepeth back his sword from blood."},"BSB":{"text":"Cursed is the one who is remiss in doing the work of the LORD, and cursed is he who withholds his sword from bloodshed."},"TANAKH":{"text":"Cursed be he that doeth the work of HaShem with a slack hand, and cursed be he that keepeth back his sword from blood."},"HEBREW":{"text":"אָר֗וּר עֹשֶׂ֛ה מְלֶ֥אכֶת יְהוָ֖ה רְמִיָּ֑ה וְאָר֕וּר מֹנֵ֥עַ חַרְבּ֖וֹ מִדָּֽם׃"}},"definableWords":["cursed","one","work","LORD"],"peopleInVerse":[]},"11":{"text":"Moab hath been at ease from his youth, and he hath settled on his lees, and hath not been emptied from vessel to vessel, neither hath he gone into captivity: therefore his taste remained in him, and his scent is not changed.","ref":"Jeremiah 48:11","synthesized":"Moab has been at ease from youth, settled like wine on its dregs; he has not been poured from vessel to vessel or gone into exile. So his flavor has remained the same, and his aroma is unchanged.","sources":{"KJV":{"text":"Moab hath been at ease from his youth, and he hath settled on his lees, and hath not been emptied from vessel to vessel, neither hath he gone into captivity: therefore his taste remained in him, and his scent is not changed."},"BSB":{"text":"Moab has been at ease from youth, settled like wine on its dregs; he has not been poured from vessel to vessel or gone into exile. So his flavor has remained the same, and his aroma is unchanged."},"TANAKH":{"text":"Moab hath been at ease from his youth, and he hath settled on his lees, and hath not been emptied from vessel to vessel, neither hath he gone into captivity; therefore his taste remaineth in him, and his scent is not changed."},"HEBREW":{"text":"שַׁאֲנַ֨ן מוֹאָ֜ב מִנְּעוּרָ֗יו וְשֹׁקֵ֥ט הוּא֙ אֶל־שְׁמָרָ֔יו וְלֹֽא־הוּרַ֤ק מִכְּלִי֙ אֶל־כֶּ֔לִי וּבַגּוֹלָ֖ה לֹ֣א הָלָ֑ךְ עַל־כֵּ֗ן עָמַ֤ד טַעְמוֹ֙ בּ֔וֹ וְרֵיח֖וֹ לֹ֥א נָמָֽר׃"}},"definableWords":["or"],"peopleInVerse":[],"themesInVerse":["exile_return"]},"12":{"text":"Therefore, behold, the days come, saith the LORD, that I will send unto him wanderers, that shall cause him to wander, and shall empty his vessels, and break their bottles.","ref":"Jeremiah 48:12","synthesized":"Therefore behold, the days are coming, declares the LORD, when I will send to him wanderers, who will pour him out. They will empty his vessels and shatter his jars.","sources":{"KJV":{"text":"Therefore, behold, the days come, saith the LORD, that I will send unto him wanderers, that shall cause him to wander, and shall empty his vessels, and break their bottles."},"BSB":{"text":"Therefore behold, the days are coming, declares the LORD, when I will send to him wanderers, who will pour him out. They will empty his vessels and shatter his jars."},"TANAKH":{"text":"Therefore, behold, the days come, saith HaShem, that I will send unto him them that tilt up, and they shall tilt him up; and they shall empty his vessels, and break their bottles in pieces."},"HEBREW":{"text":"לָכֵ֞ן הִנֵּ֖ה־יָמִ֤ים בָּאִים֙ נְאֻם־יְהוָ֔ה וְשִׁלַּחְתִּי־ל֥וֹ צֹעִ֖ים וְצֵעֻ֑הוּ וְכֵלָ֣יו יָרִ֔יקוּ וְנִבְלֵיהֶ֖ם יְנַפֵּֽצוּ׃"}},"definableWords":["days","LORD"],"peopleInVerse":[],"themesInVerse":["second_coming"]},"13":{"text":"And Moab shall be ashamed of Chemosh, as the house of Israel was ashamed of Bethel their confidence.","ref":"Jeremiah 48:13","synthesized":"Then Moab will be ashamed of Chemosh, just as the house of Israel was ashamed when they trusted in Bethel.","sources":{"KJV":{"text":"And Moab shall be ashamed of Chemosh, as the house of Israel was ashamed of Bethel their confidence."},"BSB":{"text":"Then Moab will be ashamed of Chemosh, just as the house of Israel was ashamed when they trusted in Bethel."},"TANAKH":{"text":"And Moab shall be ashamed of Chemosh, as the house of Israel was ashamed of Beth-el their confidence."},"HEBREW":{"text":"וּבֹ֥שׁ מוֹאָ֖ב מִכְּמ֑וֹשׁ כַּאֲשֶׁר־בֹּ֙שׁוּ֙ בֵּ֣ית יִשְׂרָאֵ֔ל מִבֵּ֥ית אֵ֖ל מִבְטֶחָֽם׃"}},"definableWords":["house","Israel","Bethel"],"peopleInVerse":[],"placesInVerse":["Bethel"]},"14":{"text":"How say ye, We are mighty and strong men for the war?","ref":"Jeremiah 48:14","synthesized":"How can you say, ‘We are warriors, mighty men ready for battle’?","sources":{"KJV":{"text":"How say ye, We are mighty and strong men for the war?"},"BSB":{"text":"How can you say, ‘We are warriors, mighty men ready for battle’?"},"TANAKH":{"text":"How say ye: 'We are mighty men, and valiant men for the war'?"},"HEBREW":{"text":"אֵ֚יךְ תֹּֽאמְר֔וּ גִּבּוֹרִ֖ים אֲנָ֑חְנוּ וְאַנְשֵׁי־חַ֖יִל לַמִּלְחָמָֽה׃"}},"definableWords":["mighty","men"],"peopleInVerse":[],"themesInVerse":["spiritual_warfare"]},"15":{"text":"Moab is spoiled, and gone up out of her cities, and his chosen young men are gone down to the slaughter, saith the King, whose name is the LORD of hosts.","ref":"Jeremiah 48:15","synthesized":"Moab has been destroyed and its towns have been invaded; the best of its young men have gone down in the slaughter, declares the King, whose name is the LORD of Hosts.","sources":{"KJV":{"text":"Moab is spoiled, and gone up out of her cities, and his chosen young men are gone down to the slaughter, saith the King, whose name is the LORD of hosts."},"BSB":{"text":"Moab has been destroyed and its towns have been invaded; the best of its young men have gone down in the slaughter, declares the King, whose name is the LORD of Hosts."},"TANAKH":{"text":"Moab is spoiled, and they are gone up into her cities, and his chosen young men are gone down to the slaughter, saith the King, whose name is HaShem of hosts."},"HEBREW":{"text":"שֻׁדַּ֤ד מוֹאָב֙ וְעָרֶ֣יהָ עָלָ֔ה וּמִבְחַ֥ר בַּֽחוּרָ֖יו יָרְד֣וּ לַטָּ֑בַח נְאֻ֨ם־הַמֶּ֔לֶךְ יְהוָ֥ה צְבָא֖וֹת שְׁמֽוֹ׃"}},"definableWords":["men","King","name","LORD"],"peopleInVerse":[],"themesInVerse":["kingship"]},"16":{"text":"The calamity of Moab is near to come, and his affliction hasteth fast.","ref":"Jeremiah 48:16","synthesized":"Moab’s calamity is at hand, and his affliction is rushing swiftly.","sources":{"KJV":{"text":"The calamity of Moab is near to come, and his affliction hasteth fast."},"BSB":{"text":"Moab’s calamity is at hand, and his affliction is rushing swiftly."},"TANAKH":{"text":"The calamity of Moab is near to come, and his affliction hasteth fast."},"HEBREW":{"text":"קָר֥וֹב אֵיד־מוֹאָ֖ב לָב֑וֹא וְרָ֣עָת֔וֹ מִהֲרָ֖ה מְאֹֽד׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["suffering"]},"17":{"text":"All ye that are about him, bemoan him; and all ye that know his name, say, How is the strong staff broken, and the beautiful rod!","ref":"Jeremiah 48:17","synthesized":"Mourn for him, all you who surround him, everyone who knows his name; tell how the mighty scepter is shattered— the glorious staff!","sources":{"KJV":{"text":"All ye that are about him, bemoan him; and all ye that know his name, say, How is the strong staff broken, and the beautiful rod!"},"BSB":{"text":"Mourn for him, all you who surround him, everyone who knows his name; tell how the mighty scepter is shattered— the glorious staff!"},"TANAKH":{"text":"Bemoan him, all ye that are round about him, and all ye that know his name; say: 'How is the strong staff broken, the beautiful rod!'"},"HEBREW":{"text":"נֻ֤דוּ לוֹ֙ כָּל־סְבִיבָ֔יו וְכֹ֖ל יֹדְעֵ֣י שְׁמ֑וֹ אִמְר֗וּ אֵיכָ֤ה נִשְׁבַּר֙ מַטֵּה־עֹ֔ז מַקֵּ֖ל תִּפְאָרָֽה׃"}},"definableWords":["name","mighty","scepter"],"peopleInVerse":[],"themesInVerse":["kingship"]},"18":{"text":"Thou daughter that dost inhabit Dibon, come down from thy glory, and sit in thirst; for the spoiler of Moab shall come upon thee, and he shall destroy thy strong holds.","ref":"Jeremiah 48:18","synthesized":"Come down from your glory; sit on parched ground, O daughter dwelling in Dibon, for the destroyer of Moab has come against you; he has destroyed your fortresses.","sources":{"KJV":{"text":"Thou daughter that dost inhabit Dibon, come down from thy glory, and sit in thirst; for the spoiler of Moab shall come upon thee, and he shall destroy thy strong holds."},"BSB":{"text":"Come down from your glory; sit on parched ground, O daughter dwelling in Dibon, for the destroyer of Moab has come against you; he has destroyed your fortresses."},"TANAKH":{"text":"O thou daughter that dwellest in Dibon, come down from thy glory, and sit in thirst; for the spoiler of Moab is come up against thee, he hath destroyed thy strongholds."},"HEBREW":{"text":"רְדִ֤י מִכָּבוֹד֙ ישבי וּשְׁבִ֣י בַצָּמָ֔א יֹשֶׁ֖בֶת בַּת־דִּיב֑וֹן כִּֽי־שֹׁדֵ֤ד מוֹאָב֙ עָ֣לָה בָ֔ךְ שִׁחֵ֖ת מִבְצָרָֽיִךְ׃"}},"definableWords":["glory","ground","daughter"],"peopleInVerse":[],"themesInVerse":["temple","worship"]},"19":{"text":"O inhabitant of Aroer, stand by the way, and espy; ask him that fleeth, and her that escapeth, and say, What is done?","ref":"Jeremiah 48:19","synthesized":"Stand by the road and watch, O dweller of Aroer! Ask the man fleeing or the woman escaping, ‘What has happened?’","sources":{"KJV":{"text":"O inhabitant of Aroer, stand by the way, and espy; ask him that fleeth, and her that escapeth, and say, What is done?"},"BSB":{"text":"Stand by the road and watch, O dweller of Aroer! Ask the man fleeing or the woman escaping, ‘What has happened?’"},"TANAKH":{"text":"O inhabitant of Aroer, stand by the way, and watch; ask him that fleeth, and her that escapeth; say: 'What hath been done?'"},"HEBREW":{"text":"אֶל־דֶּ֛רֶךְ עִמְדִ֥י וְצַפִּ֖י יוֹשֶׁ֣בֶת עֲרוֹעֵ֑ר שַׁאֲלִי־נָ֣ס וְנִמְלָ֔טָה אִמְרִ֖י מַה־נִּֽהְיָֽתָה׃"}},"definableWords":["stand","man","or","woman"],"peopleInVerse":[]},"20":{"text":"Moab is confounded; for it is broken down: howl and cry; tell ye it in Arnon, that Moab is spoiled,","ref":"Jeremiah 48:20","synthesized":"Moab is put to shame, for it has been shattered. Wail and cry out! Declare by the Arnon that Moab is destroyed.","sources":{"KJV":{"text":"Moab is confounded; for it is broken down: howl and cry; tell ye it in Arnon, that Moab is spoiled,"},"BSB":{"text":"Moab is put to shame, for it has been shattered. Wail and cry out! Declare by the Arnon that Moab is destroyed."},"TANAKH":{"text":"Moab is put to shame, for it is dismayed; wail and cry; tell ye it in Arnon, that Moab is spoiled."},"HEBREW":{"text":"הֹבִ֥ישׁ מוֹאָ֛ב כִּֽי־חַ֖תָּה הילילי הֵילִ֣ילוּ ׀ וזעקי וּֽזְעָ֑קוּ הַגִּ֣ידוּ בְאַרְנ֔וֹן כִּ֥י שֻׁדַּ֖ד מוֹאָֽב׃"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"And judgment is come upon the plain country; upon Holon, and upon Jahazah, and upon Mephaath,","ref":"Jeremiah 48:21","synthesized":"Judgment has come upon the high plain— upon Holon, Jahzah, and Mephaath,","sources":{"KJV":{"text":"And judgment is come upon the plain country; upon Holon, and upon Jahazah, and upon Mephaath,"},"BSB":{"text":"Judgment has come upon the high plain— upon Holon, Jahzah, and Mephaath,"},"TANAKH":{"text":"And judgment is come upon the country of the Plain; upon Holon, and upon Jahzah, and upon Mephaath;"},"HEBREW":{"text":"וּמִשְׁפָּ֥ט בָּ֖א אֶל־אֶ֣רֶץ הַמִּישֹׁ֑ר אֶל־חֹל֥וֹן וְאֶל־יַ֖הְצָה וְעַל־מופעת מֵיפָֽעַת׃"}},"definableWords":["judgment"],"peopleInVerse":[],"themesInVerse":["judgment"]},"22":{"text":"And upon Dibon, and upon Nebo, and upon Bethdiblathaim,","ref":"Jeremiah 48:22","synthesized":"upon Dibon, Nebo, and Beth-diblathaim,","sources":{"KJV":{"text":"And upon Dibon, and upon Nebo, and upon Bethdiblathaim,"},"BSB":{"text":"upon Dibon, Nebo, and Beth-diblathaim,"},"TANAKH":{"text":"and upon Dibon, and upon Nebo, and upon Beth-diblathaim;"},"HEBREW":{"text":"וְעַל־דִּיב֣וֹן וְעַל־נְב֔וֹ וְעַל־בֵּ֖ית דִּבְלָתָֽיִם׃"}},"definableWords":[],"peopleInVerse":[],"placesInVerse":["Mount Nebo"]},"23":{"text":"And upon Kiriathaim, and upon Bethgamul, and upon Bethmeon,","ref":"Jeremiah 48:23","synthesized":"upon Kiriathaim, Beth-gamul, and Beth-meon,","sources":{"KJV":{"text":"And upon Kiriathaim, and upon Bethgamul, and upon Bethmeon,"},"BSB":{"text":"upon Kiriathaim, Beth-gamul, and Beth-meon,"},"TANAKH":{"text":"and upon Kiriathaim, and upon Beth-gamul, and upon Beth-meon;"},"HEBREW":{"text":"וְעַ֧ל קִרְיָתַ֛יִם וְעַל־בֵּ֥ית גָּמ֖וּל וְעַל־בֵּ֥ית מְעֽוֹן׃"}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"And upon Kerioth, and upon Bozrah, and upon all the cities of the land of Moab, far or near.","ref":"Jeremiah 48:24","synthesized":"upon Kerioth, Bozrah, and all the towns of Moab, those far and near.","sources":{"KJV":{"text":"And upon Kerioth, and upon Bozrah, and upon all the cities of the land of Moab, far or near."},"BSB":{"text":"upon Kerioth, Bozrah, and all the towns of Moab, those far and near."},"TANAKH":{"text":"and upon Kerioth, and upon Bozrah, and upon all the cities of the land of Moab, far or near."},"HEBREW":{"text":"וְעַל־קְרִיּ֖וֹת וְעַל־בָּצְרָ֑ה וְעַ֗ל כָּל־עָרֵי֙ אֶ֣רֶץ מוֹאָ֔ב הָרְחֹק֖וֹת וְהַקְּרֹבֽוֹת׃"}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"The horn of Moab is cut off, and his arm is broken, saith the LORD.","ref":"Jeremiah 48:25","synthesized":"The horn of Moab has been cut off, and his arm is broken,” declares the LORD.","sources":{"KJV":{"text":"The horn of Moab is cut off, and his arm is broken, saith the LORD."},"BSB":{"text":"The horn of Moab has been cut off, and his arm is broken,” declares the LORD."},"TANAKH":{"text":"The horn of Moab is cut off, and his arm is broken, saith HaShem."},"HEBREW":{"text":"נִגְדְּעָה֙ קֶ֣רֶן מוֹאָ֔ב וּזְרֹע֖וֹ נִשְׁבָּ֑רָה נְאֻ֖ם יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"26":{"text":"Make ye him drunken: for he magnified himself against the LORD: Moab also shall wallow in his vomit, and he also shall be in derision.","ref":"Jeremiah 48:26","synthesized":"“Make him drunk, because he has magnified himself against the LORD; so Moab will wallow in his own vomit, and he will also become a laughingstock.","sources":{"KJV":{"text":"Make ye him drunken: for he magnified himself against the LORD: Moab also shall wallow in his vomit, and he also shall be in derision."},"BSB":{"text":"“Make him drunk, because he has magnified himself against the LORD; so Moab will wallow in his own vomit, and he will also become a laughingstock."},"TANAKH":{"text":"Make ye him drunken, for he magnified himself against HaShem; and Moab shall wallow in his vomit, and he also shall be in derision."},"HEBREW":{"text":"הַשְׁכִּירֻ֕הוּ כִּ֥י עַל־יְהוָ֖ה הִגְדִּ֑יל וְסָפַ֤ק מוֹאָב֙ בְּקִיא֔וֹ וְהָיָ֥ה לִשְׂחֹ֖ק גַּם־הֽוּא׃"}},"definableWords":["make","LORD"],"peopleInVerse":[]},"27":{"text":"For was not Israel a derision unto thee? was he found among thieves? for since thou spakest of him, thou skippedst for joy.","ref":"Jeremiah 48:27","synthesized":"Was not Israel your object of ridicule? Was he ever found among thieves? For whenever you speak of him you shake your head.","sources":{"KJV":{"text":"For was not Israel a derision unto thee? was he found among thieves? for since thou spakest of him, thou skippedst for joy."},"BSB":{"text":"Was not Israel your object of ridicule? Was he ever found among thieves? For whenever you speak of him you shake your head."},"TANAKH":{"text":"For was not Israel a derision unto thee? Was he found among thieves? For as often as thou speakest of him, thou waggest the head."},"HEBREW":{"text":"וְאִ֣ם ׀ ל֣וֹא הַשְּׂחֹ֗ק הָיָ֤ה לְךָ֙ יִשְׂרָאֵ֔ל אִם־בְּגַנָּבִ֖ים נמצאה נִמְצָ֑א כִּֽי־מִדֵּ֧י דְבָרֶ֛יךָ בּ֖וֹ תִּתְנוֹדָֽד׃"}},"definableWords":["Israel"],"peopleInVerse":[]},"28":{"text":"O ye that dwell in Moab, leave the cities, and dwell in the rock, and be like the dove that maketh her nest in the sides of the hole’s mouth.","ref":"Jeremiah 48:28","synthesized":"Abandon the towns and settle among the rocks, O dwellers of Moab! Be like a dove that nests at the mouth of a cave.","sources":{"KJV":{"text":"O ye that dwell in Moab, leave the cities, and dwell in the rock, and be like the dove that maketh her nest in the sides of the hole’s mouth."},"BSB":{"text":"Abandon the towns and settle among the rocks, O dwellers of Moab! Be like a dove that nests at the mouth of a cave."},"TANAKH":{"text":"O ye that dwell in Moab, leave the cities, and dwell in the rock; and be like the dove that maketh her nest in the sides of the pit's mouth."},"HEBREW":{"text":"עִזְב֤וּ עָרִים֙ וְשִׁכְנ֣וּ בַּסֶּ֔לַע יֹשְׁבֵ֖י מוֹאָ֑ב וִֽהְי֣וּ כְיוֹנָ֔ה תְּקַנֵּ֖ן בְּעֶבְרֵ֥י פִי־פָֽחַת׃"}},"definableWords":[],"peopleInVerse":[]},"29":{"text":"We have heard the pride of Moab, (he is exceeding proud) his loftiness, and his arrogancy, and his pride, and the haughtiness of his heart.","ref":"Jeremiah 48:29","synthesized":"We have heard of Moab’s pomposity, his exceeding pride and conceit, his proud arrogance and haughtiness of heart.","sources":{"KJV":{"text":"We have heard the pride of Moab, (he is exceeding proud) his loftiness, and his arrogancy, and his pride, and the haughtiness of his heart."},"BSB":{"text":"We have heard of Moab’s pomposity, his exceeding pride and conceit, his proud arrogance and haughtiness of heart."},"TANAKH":{"text":"We have heard of the pride of Moab; he is very proud; his loftiness, and his pride, and his haughtiness, and the assumption of his heart."},"HEBREW":{"text":"שָׁמַ֥עְנוּ גְאוֹן־מוֹאָ֖ב גֵּאֶ֣ה מְאֹ֑ד גָּבְה֧וֹ וּגְאוֹנ֛וֹ וְגַאֲוָת֖וֹ וְרֻ֥ם לִבּֽוֹ׃"}},"definableWords":["heart"],"peopleInVerse":[]},"30":{"text":"I know his wrath, saith the LORD; but it shall not be so; his lies shall not so effect it.","ref":"Jeremiah 48:30","synthesized":"I know his insolence,” declares the LORD, “but it is futile. His boasting is as empty as his deeds.","sources":{"KJV":{"text":"I know his wrath, saith the LORD; but it shall not be so; his lies shall not so effect it."},"BSB":{"text":"I know his insolence,” declares the LORD, “but it is futile. His boasting is as empty as his deeds."},"TANAKH":{"text":"I know his arrogancy, saith HaShem, that it is ill-founded; his boastings have wrought nothing well-founded."},"HEBREW":{"text":"אֲנִ֤י יָדַ֙עְתִּי֙ נְאֻם־יְהוָ֔ה עֶבְרָת֖וֹ וְלֹא־כֵ֑ן בַּדָּ֖יו לֹא־כֵ֥ן עָשֽׂוּ׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"31":{"text":"Therefore will I howl for Moab, and I will cry out for all Moab; mine heart shall mourn for the men of Kirheres.","ref":"Jeremiah 48:31","synthesized":"Therefore I will wail for Moab; I will cry out for all of Moab; I will moan for the men of Kir-heres.","sources":{"KJV":{"text":"Therefore will I howl for Moab, and I will cry out for all Moab; mine heart shall mourn for the men of Kirheres."},"BSB":{"text":"Therefore I will wail for Moab; I will cry out for all of Moab; I will moan for the men of Kir-heres."},"TANAKH":{"text":"Therefore will I wail for Moab; yea, I will cry out for all Moab; for the men of Kir-heres shall my heart moan."},"HEBREW":{"text":"עַל־כֵּן֙ עַל־מוֹאָ֣ב אֲיֵלִ֔יל וּלְמוֹאָ֥ב כֻּלֹּ֖ה אֶזְעָ֑ק אֶל־אַנְשֵׁ֥י קִֽיר־חֶ֖רֶשׂ יֶהְגֶּֽה׃"}},"definableWords":["men"],"peopleInVerse":[]},"32":{"text":"O vine of Sibmah, I will weep for thee with the weeping of Jazer: thy plants are gone over the sea, they reach even to the sea of Jazer: the spoiler is fallen upon thy summer fruits and upon thy vintage.","ref":"Jeremiah 48:32","synthesized":"I will weep for you, O vine of Sibmah, more than I weep for Jazer. Your tendrils have extended to the sea; they reach even to Jazer. The destroyer has descended on your summer fruit and grape harvest.","sources":{"KJV":{"text":"O vine of Sibmah, I will weep for thee with the weeping of Jazer: thy plants are gone over the sea, they reach even to the sea of Jazer: the spoiler is fallen upon thy summer fruits and upon thy vintage."},"BSB":{"text":"I will weep for you, O vine of Sibmah, more than I weep for Jazer. Your tendrils have extended to the sea; they reach even to Jazer. The destroyer has descended on your summer fruit and grape harvest."},"TANAKH":{"text":"With more than the weeping of Jazer will I weep for thee, O vine of Sibmah; thy branches passed over the sea, they reached even to the sea of Jazer; upon thy summer fruits and upon thy vintage the spoiler is fallen."},"HEBREW":{"text":"מִבְּכִ֨י יַעְזֵ֤ר אֶבְכֶּה־לָּךְ֙ הַגֶּ֣פֶן שִׂבְמָ֔ה נְטִֽישֹׁתַ֙יִךְ֙ עָ֣בְרוּ יָ֔ם עַ֛ד יָ֥ם יַעְזֵ֖ר נָגָ֑עוּ עַל־קֵיצֵ֥ךְ וְעַל־בְּצִירֵ֖ךְ שֹׁדֵ֥ד נָפָֽל׃"}},"definableWords":["sea"],"peopleInVerse":[],"themesInVerse":["vine_branches"]},"33":{"text":"And joy and gladness is taken from the plentiful field, and from the land of Moab; and I have caused wine to fail from the winepresses: none shall tread with shouting; their shouting shall be no shouting.","ref":"Jeremiah 48:33","synthesized":"Joy and gladness are removed from the orchard and from the fields of Moab. I have stopped the flow of wine from the presses; no one treads them with shouts of joy; their shouts are not for joy.","sources":{"KJV":{"text":"And joy and gladness is taken from the plentiful field, and from the land of Moab; and I have caused wine to fail from the winepresses: none shall tread with shouting; their shouting shall be no shouting."},"BSB":{"text":"Joy and gladness are removed from the orchard and from the fields of Moab. I have stopped the flow of wine from the presses; no one treads them with shouts of joy; their shouts are not for joy."},"TANAKH":{"text":"And gladness and joy is taken away from the fruitful field, and from the land of Moab; and I have caused wine to cease from the winepresses; none shall tread with shouting; the shouting shall be no shouting."},"HEBREW":{"text":"וְנֶאֶסְפָ֨ה שִׂמְחָ֥ה וָגִ֛יל מִכַּרְמֶ֖ל וּמֵאֶ֣רֶץ מוֹאָ֑ב וְיַ֙יִן֙ מִיקָבִ֣ים הִשְׁבַּ֔תִּי לֹֽא־יִדְרֹ֣ךְ הֵידָ֔ד הֵידָ֖ד לֹ֥א הֵידָֽד׃"}},"definableWords":["joy","one"],"peopleInVerse":[],"themesInVerse":["joy"]},"34":{"text":"From the cry of Heshbon even unto Elealeh, and even unto Jahaz, have they uttered their voice, from Zoar even unto Horonaim, as an heifer of three years old: for the waters also of Nimrim shall be desolate.","ref":"Jeremiah 48:34","synthesized":"There is a cry from Heshbon to Elealeh; they raise their voices to Jahaz, from Zoar to Horonaim and Eglath-shelishiyah; for even the waters of Nimrim have dried up.","sources":{"KJV":{"text":"From the cry of Heshbon even unto Elealeh, and even unto Jahaz, have they uttered their voice, from Zoar even unto Horonaim, as an heifer of three years old: for the waters also of Nimrim shall be desolate."},"BSB":{"text":"There is a cry from Heshbon to Elealeh; they raise their voices to Jahaz, from Zoar to Horonaim and Eglath-shelishiyah; for even the waters of Nimrim have dried up."},"TANAKH":{"text":"From the cry of Heshbon even unto Elealeh, even unto Jahaz have they uttered their voice, from Zoar even unto Horonaim, a heifer of three years old; for the Waters of Nimrim also shall be desolate."},"HEBREW":{"text":"מִזַּעֲקַ֨ת חֶשְׁבּ֜וֹן עַד־אֶלְעָלֵ֗ה עַד־יַ֙הַץ֙ נָתְנ֣וּ קוֹלָ֔ם מִצֹּ֙עַר֙ עַד־חֹ֣רֹנַ֔יִם עֶגְלַ֖ת שְׁלִֽשִׁיָּ֑ה כִּ֚י גַּם־מֵ֣י נִמְרִ֔ים לִמְשַׁמּ֖וֹת יִהְיֽוּ׃"}},"definableWords":["waters"],"peopleInVerse":[]},"35":{"text":"Moreover I will cause to cease in Moab, saith the LORD, him that offereth in the high places, and him that burneth incense to his gods.","ref":"Jeremiah 48:35","synthesized":"In Moab, declares the LORD, I will bring an end to those who make offerings on the high places and burn incense to their gods.","sources":{"KJV":{"text":"Moreover I will cause to cease in Moab, saith the LORD, him that offereth in the high places, and him that burneth incense to his gods."},"BSB":{"text":"In Moab, declares the LORD, I will bring an end to those who make offerings on the high places and burn incense to their gods."},"TANAKH":{"text":"Moreover I will cause to cease in Moab, saith HaShem, him that offereth in the high place, and him that offereth to his gods."},"HEBREW":{"text":"וְהִשְׁבַּתִּ֥י לְמוֹאָ֖ב נְאֻם־יְהוָ֑ה מַעֲלֶ֣ה בָמָ֔ה וּמַקְטִ֖יר לֵאלֹהָֽיו׃"}},"definableWords":["LORD","make","incense"],"peopleInVerse":[]},"36":{"text":"Therefore mine heart shall sound for Moab like pipes, and mine heart shall sound like pipes for the men of Kirheres: because the riches that he hath gotten are perished.","ref":"Jeremiah 48:36","synthesized":"Therefore My heart laments like a flute for Moab; it laments like a flute for the men of Kir-heres, because the wealth they acquired has perished.","sources":{"KJV":{"text":"Therefore mine heart shall sound for Moab like pipes, and mine heart shall sound like pipes for the men of Kirheres: because the riches that he hath gotten are perished."},"BSB":{"text":"Therefore My heart laments like a flute for Moab; it laments like a flute for the men of Kir-heres, because the wealth they acquired has perished."},"TANAKH":{"text":"Therefore my heart moaneth for Moab like pipes, and my heart moaneth like pipes for the men of Kir-heres; therefore the abundance that he hath gotten is perished."},"HEBREW":{"text":"עַל־כֵּ֞ן לִבִּ֤י לְמוֹאָב֙ כַּחֲלִלִ֣ים יֶהֱמֶ֔ה וְלִבִּי֙ אֶל־אַנְשֵׁ֣י קִֽיר־חֶ֔רֶשׂ כַּחֲלִילִ֖ים יֶהֱמֶ֑ה עַל־כֵּ֛ן יִתְרַ֥ת עָשָׂ֖ה אָבָֽדוּ׃"}},"definableWords":["heart","men"],"peopleInVerse":[]},"37":{"text":"For every head shall be bald, and every beard clipped: upon all the hands shall be cuttings, and upon the loins sackcloth.","ref":"Jeremiah 48:37","synthesized":"For every head is shaved and every beard is clipped; on every hand is a gash, and around every waist is sackcloth.","sources":{"KJV":{"text":"For every head shall be bald, and every beard clipped: upon all the hands shall be cuttings, and upon the loins sackcloth."},"BSB":{"text":"For every head is shaved and every beard is clipped; on every hand is a gash, and around every waist is sackcloth."},"TANAKH":{"text":"For every head is bald, and every beard clipped; upon all the hands are cuttings, and upon the loins sackcloth."},"HEBREW":{"text":"כִּ֤י כָל־רֹאשׁ֙ קָרְחָ֔ה וְכָל־זָקָ֖ן גְּרֻעָ֑ה עַ֤ל כָּל־יָדַ֙יִם֙ גְּדֻדֹ֔ת וְעַל־מָתְנַ֖יִם שָֽׂק׃"}},"definableWords":[],"peopleInVerse":[]},"38":{"text":"There shall be lamentation generally upon all the housetops of Moab, and in the streets thereof: for I have broken Moab like a vessel wherein is no pleasure, saith the LORD.","ref":"Jeremiah 48:38","synthesized":"On all the rooftops of Moab and in the public squares, everyone is mourning; for I have shattered Moab like an unwanted jar,” declares the LORD.","sources":{"KJV":{"text":"There shall be lamentation generally upon all the housetops of Moab, and in the streets thereof: for I have broken Moab like a vessel wherein is no pleasure, saith the LORD."},"BSB":{"text":"On all the rooftops of Moab and in the public squares, everyone is mourning; for I have shattered Moab like an unwanted jar,” declares the LORD."},"TANAKH":{"text":"On all the housetops of Moab and in the broad places thereof there is lamentation every where; for I have broken Moab like a vessel wherein is no pleasure, saith HaShem."},"HEBREW":{"text":"עַ֣ל כָּל־גַּגּ֥וֹת מוֹאָ֛ב וּבִרְחֹבֹתֶ֖יהָ כֻּלֹּ֣ה מִסְפֵּ֑ד כִּֽי־שָׁבַ֣רְתִּי אֶת־מוֹאָ֗ב כִּכְלִ֛י אֵֽין־חֵ֥פֶץ בּ֖וֹ נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"39":{"text":"They shall howl, saying, How is it broken down! how hath Moab turned the back with shame! so shall Moab be a derision and a dismaying to all them about him.","ref":"Jeremiah 48:39","synthesized":"“How shattered it is! How they wail! How Moab has turned his back in shame! Moab has become an object of ridicule and horror to all those around him.”","sources":{"KJV":{"text":"They shall howl, saying, How is it broken down! how hath Moab turned the back with shame! so shall Moab be a derision and a dismaying to all them about him."},"BSB":{"text":"“How shattered it is! How they wail! How Moab has turned his back in shame! Moab has become an object of ridicule and horror to all those around him.”"},"TANAKH":{"text":"'How is it broken down!' wail ye! 'How hath Moab turned the back with shame!' so shall Moab become a derision and a dismay to all that are round about him."},"HEBREW":{"text":"אֵ֥יךְ חַ֙תָּה֙ הֵילִ֔ילוּ אֵ֛יךְ הִפְנָה־עֹ֥רֶף מוֹאָ֖ב בּ֑וֹשׁ וְהָיָ֥ה מוֹאָ֛ב לִשְׂחֹ֥ק וְלִמְחִתָּ֖ה לְכָל־סְבִיבָֽיו׃"}},"definableWords":[],"peopleInVerse":[]},"40":{"text":"For thus saith the LORD; Behold, he shall fly as an eagle, and shall spread his wings over Moab.","ref":"Jeremiah 48:40","synthesized":"For this is what the LORD says:  “Behold, an eagle swoops down and spreads his wings against Moab.","sources":{"KJV":{"text":"For thus saith the LORD; Behold, he shall fly as an eagle, and shall spread his wings over Moab."},"BSB":{"text":"For this is what the LORD says:  “Behold, an eagle swoops down and spreads his wings against Moab."},"TANAKH":{"text":"For thus saith HaShem: Behold, he shall swoop as a vulture, and shall spread out his wings against Moab."},"HEBREW":{"text":"כִּי־כֹה֙ אָמַ֣ר יְהוָ֔ה הִנֵּ֥ה כַנֶּ֖שֶׁר יִדְאֶ֑ה וּפָרַ֥שׂ כְּנָפָ֖יו אֶל־מוֹאָֽב׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"41":{"text":"Kerioth is taken, and the strong holds are surprised, and the mighty men’s hearts in Moab at that day shall be as the heart of a woman in her pangs.","ref":"Jeremiah 48:41","synthesized":"Kirioth has been taken, and the strongholds seized. In that day the heart of Moab’s warriors will be like the heart of a woman in labor.","sources":{"KJV":{"text":"Kerioth is taken, and the strong holds are surprised, and the mighty men’s hearts in Moab at that day shall be as the heart of a woman in her pangs."},"BSB":{"text":"Kirioth has been taken, and the strongholds seized. In that day the heart of Moab’s warriors will be like the heart of a woman in labor."},"TANAKH":{"text":"The cities are taken, and the strongholds are seized, and the heart of the mighty men of Moab at that day shall be as the heart of a woman in her pangs."},"HEBREW":{"text":"נִלְכְּדָה֙ הַקְּרִיּ֔וֹת וְהַמְּצָד֖וֹת נִתְפָּ֑שָׂה וְֽ֠הָיָה לֵ֞ב גִּבּוֹרֵ֤י מוֹאָב֙ בַּיּ֣וֹם הַה֔וּא כְּלֵ֖ב אִשָּׁ֥ה מְצֵרָֽה׃"}},"definableWords":["day","heart","woman"],"peopleInVerse":[]},"42":{"text":"And Moab shall be destroyed from being a people, because he hath magnified himself against the LORD.","ref":"Jeremiah 48:42","synthesized":"Moab will be destroyed as a nation because he vaunted himself against the LORD.","sources":{"KJV":{"text":"And Moab shall be destroyed from being a people, because he hath magnified himself against the LORD."},"BSB":{"text":"Moab will be destroyed as a nation because he vaunted himself against the LORD."},"TANAKH":{"text":"And Moab shall be destroyed from being a people, because he hath magnified himself against HaShem."},"HEBREW":{"text":"וְנִשְׁמַ֥ד מוֹאָ֖ב מֵעָ֑ם כִּ֥י עַל־יְהוָ֖ה הִגְדִּֽיל׃"}},"definableWords":["nation","LORD"],"peopleInVerse":[]},"43":{"text":"Fear, and the pit, and the snare, shall be upon thee, O inhabitant of Moab, saith the LORD.","ref":"Jeremiah 48:43","synthesized":"Terror and pit and snare await you, O dweller of Moab,” declares the LORD.","sources":{"KJV":{"text":"Fear, and the pit, and the snare, shall be upon thee, O inhabitant of Moab, saith the LORD."},"BSB":{"text":"Terror and pit and snare await you, O dweller of Moab,” declares the LORD."},"TANAKH":{"text":"Terror, and the pit, and the trap, are upon thee, O inhabitant of Moab, saith HaShem."},"HEBREW":{"text":"פַּ֥חַד וָפַ֖חַת וָפָ֑ח עָלֶ֛יךָ יוֹשֵׁ֥ב מוֹאָ֖ב נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"44":{"text":"He that fleeth from the fear shall fall into the pit; and he that getteth up out of the pit shall be taken in the snare: for I will bring upon it, even upon Moab, the year of their visitation, saith the LORD.","ref":"Jeremiah 48:44","synthesized":"“Whoever flees the panic will fall into the pit, and whoever climbs from the pit will be caught in the snare. For I will bring upon Moab the year of their punishment,” declares the LORD.","sources":{"KJV":{"text":"He that fleeth from the fear shall fall into the pit; and he that getteth up out of the pit shall be taken in the snare: for I will bring upon it, even upon Moab, the year of their visitation, saith the LORD."},"BSB":{"text":"“Whoever flees the panic will fall into the pit, and whoever climbs from the pit will be caught in the snare. For I will bring upon Moab the year of their punishment,” declares the LORD."},"TANAKH":{"text":"He that fleeth from the terror shall fall into the pit; and he that getteth up out of the pit shall be taken in the trap; for I will bring upon her, even upon Moab, the year of their visitation, saith HaShem."},"HEBREW":{"text":"הניס הַנָּ֞ס מִפְּנֵ֤י הַפַּ֙חַד֙ יִפֹּ֣ל אֶל־הַפַּ֔חַת וְהָֽעֹלֶה֙ מִן־הַפַּ֔חַת יִלָּכֵ֖ד בַּפָּ֑ח כִּֽי־אָבִ֨יא אֵלֶ֧יהָ אֶל־מוֹאָ֛ב שְׁנַ֥ת פְּקֻדָּתָ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["year","LORD"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"45":{"text":"They that fled stood under the shadow of Heshbon because of the force: but a fire shall come forth out of Heshbon, and a flame from the midst of Sihon, and shall devour the corner of Moab, and the crown of the head of the tumultuous ones.","ref":"Jeremiah 48:45","synthesized":"“Those who flee will stand helpless in Heshbon’s shadow, because fire has gone forth from Heshbon and a flame from within Sihon. It devours the foreheads of Moab and the skulls of the sons of tumult.","sources":{"KJV":{"text":"They that fled stood under the shadow of Heshbon because of the force: but a fire shall come forth out of Heshbon, and a flame from the midst of Sihon, and shall devour the corner of Moab, and the crown of the head of the tumultuous ones."},"BSB":{"text":"“Those who flee will stand helpless in Heshbon’s shadow, because fire has gone forth from Heshbon and a flame from within Sihon. It devours the foreheads of Moab and the skulls of the sons of tumult."},"TANAKH":{"text":"In the shadow of Heshbon the fugitives stand without strength; for a fire is gone forth out of Heshbon, and a flame from the midst of Sihon, and it devoureth the corner of Moab, and the crown of the head of the tumultuous ones."},"HEBREW":{"text":"בְּצֵ֥ל חֶשְׁבּ֛וֹן עָמְד֖וּ מִכֹּ֣חַ נָסִ֑ים כִּֽי־אֵ֞שׁ יָצָ֣א מֵחֶשְׁבּ֗וֹן וְלֶֽהָבָה֙ מִבֵּ֣ין סִיח֔וֹן וַתֹּ֙אכַל֙ פְּאַ֣ת מוֹאָ֔ב וְקָדְקֹ֖ד בְּנֵ֥י שָׁאֽוֹן׃"}},"definableWords":["stand","sons"],"peopleInVerse":[]},"46":{"text":"Woe be unto thee, O Moab! the people of Chemosh perisheth: for thy sons are taken captives, and thy daughters captives.","ref":"Jeremiah 48:46","synthesized":"Woe to you, O Moab! The people of Chemosh have perished; for your sons have been taken into exile and your daughters have gone into captivity.","sources":{"KJV":{"text":"Woe be unto thee, O Moab! the people of Chemosh perisheth: for thy sons are taken captives, and thy daughters captives."},"BSB":{"text":"Woe to you, O Moab! The people of Chemosh have perished; for your sons have been taken into exile and your daughters have gone into captivity."},"TANAKH":{"text":"Woe unto thee, O Moab! The people of Chemosh is undone; for thy sons are taken away captive, and thy daughters into captivity."},"HEBREW":{"text":"אוֹי־לְךָ֣ מוֹאָ֔ב אָבַ֖ד עַם־כְּמ֑וֹשׁ כִּֽי־לֻקְּח֤וּ בָנֶ֙יךָ֙ בַּשֶּׁ֔בִי וּבְנֹתֶ֖יךָ בַּשִּׁבְיָֽה׃"}},"definableWords":["people","sons","daughters"],"peopleInVerse":[],"themesInVerse":["exile_return"]},"47":{"text":"Yet will I bring again the captivity of Moab in the latter days, saith the LORD. Thus far is the judgment of Moab.","ref":"Jeremiah 48:47","synthesized":"Yet in the latter days I will restore Moab from captivity,” declares the LORD.   Here ends the judgment on Moab.","sources":{"KJV":{"text":"Yet will I bring again the captivity of Moab in the latter days, saith the LORD. Thus far is the judgment of Moab."},"BSB":{"text":"Yet in the latter days I will restore Moab from captivity,” declares the LORD.   Here ends the judgment on Moab."},"TANAKH":{"text":"Yet will I turn the captivity of Moab in the end of days, saith HaShem. Thus far is the judgment of Moab."},"HEBREW":{"text":"וְשַׁבְתִּ֧י שְׁבוּת־מוֹאָ֛ב בְּאַחֲרִ֥ית הַיָּמִ֖ים נְאֻם־יְהוָ֑ה עַד־הֵ֖נָּה מִשְׁפַּ֥ט מוֹאָֽב׃"}},"definableWords":["days","LORD","judgment"],"peopleInVerse":[],"themesInVerse":["exile_return","judgment"]}}},"49":{"chapter":"49","title":"PROPHECY AGAINST AMMON, EDOM, DAMASCUS","verses":{"1":{"text":"Concerning the Ammonites, thus saith the LORD; Hath Israel no sons? hath he no heir? why then doth their king inherit Gad, and his people dwell in his cities?","ref":"Jeremiah 49:1","synthesized":"Concerning the Ammonites, this is what the LORD says:  “Has Israel no sons? Is he without heir? Why then has Milcom taken possession of Gad? Why have his people settled in their cities?","sources":{"KJV":{"text":"Concerning the Ammonites, thus saith the LORD; Hath Israel no sons? hath he no heir? why then doth their king inherit Gad, and his people dwell in his cities?"},"BSB":{"text":"Concerning the Ammonites, this is what the LORD says:  “Has Israel no sons? Is he without heir? Why then has Milcom taken possession of Gad? Why have his people settled in their cities?"},"TANAKH":{"text":"Of the children of Ammon. Thus saith HaShem: Hath Israel no sons? Hath he no heir? Why then doth Malcam take possession of Gad, and his people dwell in the cities thereof?"},"HEBREW":{"text":"לִבְנֵ֣י עַמּ֗וֹן כֹּ֚ה אָמַ֣ר יְהוָ֔ה הֲבָנִ֥ים אֵין֙ לְיִשְׂרָאֵ֔ל אִם־יוֹרֵ֖שׁ אֵ֣ין ל֑וֹ מַדּ֗וּעַ יָרַ֤שׁ מַלְכָּם֙ אֶת־גָּ֔ד וְעַמּ֖וֹ בְּעָרָ֥יו יָשָֽׁב׃"}},"definableWords":["LORD","Israel","sons","people"],"peopleInVerse":["Ammonites"],"themesInVerse":["land_promise"]},"2":{"text":"Therefore, behold, the days come, saith the LORD, that I will cause an alarm of war to be heard in Rabbah of the Ammonites; and it shall be a desolate heap, and her daughters shall be burned with fire: then shall Israel be heir unto them that were his heirs, saith the LORD.","ref":"Jeremiah 49:2","synthesized":"Therefore, behold, the days are coming, declares the LORD, when I will sound the battle cry against Rabbah of the Ammonites. It will become a heap of ruins, and its villages will be burned. Then Israel will drive out their dispossessors, says the LORD.","sources":{"KJV":{"text":"Therefore, behold, the days come, saith the LORD, that I will cause an alarm of war to be heard in Rabbah of the Ammonites; and it shall be a desolate heap, and her daughters shall be burned with fire: then shall Israel be heir unto them that were his heirs, saith the LORD."},"BSB":{"text":"Therefore, behold, the days are coming, declares the LORD, when I will sound the battle cry against Rabbah of the Ammonites. It will become a heap of ruins, and its villages will be burned. Then Israel will drive out their dispossessors, says the LORD."},"TANAKH":{"text":"Therefore, behold, the days come, saith HaShem, that I will cause an alarm of war to be heard against Rabbah of the children of Ammon; and it shall become a desolate mound, and her daughters shall be burned with fire; then shall Israel dispossess them that did dispossess him, saith HaShem."},"HEBREW":{"text":"לָכֵ֡ן הִנֵּה֩ יָמִ֨ים בָּאִ֜ים נְאֻם־יְהוָ֗ה וְ֠הִשְׁמַעְתִּי אֶל־רַבַּ֨ת בְּנֵי־עַמּ֜וֹן תְּרוּעַ֣ת מִלְחָמָ֗ה וְהָֽיְתָה֙ לְתֵ֣ל שְׁמָמָ֔ה וּבְנֹתֶ֖יהָ בָּאֵ֣שׁ תִּצַּ֑תְנָה וְיָרַ֧שׁ יִשְׂרָאֵ֛ל אֶת־יֹרְשָׁ֖יו אָמַ֥ר יְהוָֽה׃"}},"definableWords":["days","LORD","Israel","Lord"],"peopleInVerse":["Ammonites"],"themesInVerse":["second_coming","spiritual_warfare"]},"3":{"text":"Howl, O Heshbon, for Ai is spoiled: cry, ye daughters of Rabbah, gird you with sackcloth; lament, and run to and fro by the hedges; for their king shall go into captivity, and his priests and his princes together.","ref":"Jeremiah 49:3","synthesized":"Wail, O Heshbon, for Ai has been destroyed; cry out, O daughters of Rabbah! Put on sackcloth and mourn; run back and forth within your walls, for Milcom will go into exile together with his priests and officials.","sources":{"KJV":{"text":"Howl, O Heshbon, for Ai is spoiled: cry, ye daughters of Rabbah, gird you with sackcloth; lament, and run to and fro by the hedges; for their king shall go into captivity, and his priests and his princes together."},"BSB":{"text":"Wail, O Heshbon, for Ai has been destroyed; cry out, O daughters of Rabbah! Put on sackcloth and mourn; run back and forth within your walls, for Milcom will go into exile together with his priests and officials."},"TANAKH":{"text":"Wail, O Heshbon, for Ai is undone; cry, ye daughters of Rabbah, gird you with sackcloth; lament, and run to and fro among the folds; for Malcam shall go into captivity, his priests and his princes together."},"HEBREW":{"text":"הֵילִ֨ילִי חֶשְׁבּ֜וֹן כִּ֣י שֻׁדְּדָה־עַ֗י צְעַקְנָה֮ בְּנ֣וֹת רַבָּה֒ חֲגֹ֣רְנָה שַׂקִּ֔ים סְפֹ֕דְנָה וְהִתְשׁוֹטַ֖טְנָה בַּגְּדֵר֑וֹת כִּ֤י מַלְכָּם֙ בַּגּוֹלָ֣ה יֵלֵ֔ךְ כֹּהֲנָ֥יו וְשָׂרָ֖יו יַחְדָּֽיו׃"}},"definableWords":["daughters","run"],"peopleInVerse":[],"themesInVerse":["exile_return"]},"4":{"text":"Wherefore gloriest thou in the valleys, thy flowing valley, O backsliding daughter? that trusted in her treasures, saying, Who shall come unto me?","ref":"Jeremiah 49:4","synthesized":"Why do you boast of your valleys— your valleys so fruitful, O faithless daughter? You trust in your riches and say, ‘Who can come against me?’","sources":{"KJV":{"text":"Wherefore gloriest thou in the valleys, thy flowing valley, O backsliding daughter? that trusted in her treasures, saying, Who shall come unto me?"},"BSB":{"text":"Why do you boast of your valleys— your valleys so fruitful, O faithless daughter? You trust in your riches and say, ‘Who can come against me?’"},"TANAKH":{"text":"Wherefore gloriest thou in the valleys, thy flowing valley, O backsliding daughter? that didst trust in thy treasures: 'Who shall come unto me?'"},"HEBREW":{"text":"מַה־תִּתְהַֽלְלִי֙ בָּֽעֲמָקִ֔ים זָ֣ב עִמְקֵ֔ךְ הַבַּ֖ת הַשּֽׁוֹבֵבָ֑ה הַבֹּֽטְחָה֙ בְּאֹ֣צְרֹתֶ֔יהָ מִ֖י יָב֥וֹא אֵלָֽי׃"}},"definableWords":["fruitful","daughter","trust"],"peopleInVerse":[],"themesInVerse":["faith"]},"5":{"text":"Behold, I will bring a fear upon thee, saith the Lord GOD of hosts, from all those that be about thee; and ye shall be driven out every man right forth; and none shall gather up him that wandereth.","ref":"Jeremiah 49:5","synthesized":"Behold, I am about to bring terror upon you, declares the Lord GOD of Hosts, from all those around you. You will each be driven headlong, with no one to regather the fugitives.","sources":{"KJV":{"text":"Behold, I will bring a fear upon thee, saith the Lord GOD of hosts, from all those that be about thee; and ye shall be driven out every man right forth; and none shall gather up him that wandereth."},"BSB":{"text":"Behold, I am about to bring terror upon you, declares the Lord GOD of Hosts, from all those around you. You will each be driven headlong, with no one to regather the fugitives."},"TANAKH":{"text":"Behold, I will bring a terror upon thee, saith the L-rd GOD of hosts, from all that are round about thee; and ye shall be driven out every man right forth, and there shall be none to gather up him that wandereth."},"HEBREW":{"text":"הִנְנִי֩ מֵבִ֨יא עָלַ֜יִךְ פַּ֗חַד נְאֻם־אֲדֹנָ֧י יְהוִ֛ה צְבָא֖וֹת מִכָּל־סְבִיבָ֑יִךְ וְנִדַּחְתֶּם֙ אִ֣ישׁ לְפָנָ֔יו וְאֵ֥ין מְקַבֵּ֖ץ לַנֹּדֵֽד׃"}},"definableWords":["Lord","God","one"],"peopleInVerse":[]},"6":{"text":"And afterward I will bring again the captivity of the children of Ammon, saith the LORD.","ref":"Jeremiah 49:6","synthesized":"Yet afterward I will restore the Ammonites from captivity,” declares the LORD.","sources":{"KJV":{"text":"And afterward I will bring again the captivity of the children of Ammon, saith the LORD."},"BSB":{"text":"Yet afterward I will restore the Ammonites from captivity,” declares the LORD."},"TANAKH":{"text":"But afterward I will bring back the captivity of the children of Ammon, saith HaShem."},"HEBREW":{"text":"וְאַחֲרֵי־כֵ֗ן אָשִׁ֛יב אֶת־שְׁב֥וּת בְּנֵֽי־עַמּ֖וֹן נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":["Ammonites"],"themesInVerse":["exile_return"]},"7":{"text":"Concerning Edom, thus saith the LORD of hosts; Is wisdom no more in Teman? is counsel perished from the prudent? is their wisdom vanished?","ref":"Jeremiah 49:7","synthesized":"Concerning Edom, this is what the LORD of Hosts says:  “Is there no longer wisdom in Teman? Has counsel perished from the prudent? Has their wisdom decayed?","sources":{"KJV":{"text":"Concerning Edom, thus saith the LORD of hosts; Is wisdom no more in Teman? is counsel perished from the prudent? is their wisdom vanished?"},"BSB":{"text":"Concerning Edom, this is what the LORD of Hosts says:  “Is there no longer wisdom in Teman? Has counsel perished from the prudent? Has their wisdom decayed?"},"TANAKH":{"text":"Of Edom. Thus saith HaShem of hosts: Is wisdom no more in Teman? Is counsel perished from the prudent? Is their wisdom vanished?"},"HEBREW":{"text":"לֶאֱד֗וֹם כֹּ֤ה אָמַר֙ יְהוָ֣ה צְבָא֔וֹת הַאֵ֥ין ע֛וֹד חָכְמָ֖ה בְּתֵימָ֑ן אָבְדָ֤ה עֵצָה֙ מִבָּנִ֔ים נִסְרְחָ֖ה חָכְמָתָֽם׃"}},"definableWords":["Edom","LORD","wisdom"],"peopleInVerse":[],"themesInVerse":["wisdom"]},"8":{"text":"Flee ye, turn back, dwell deep, O inhabitants of Dedan; for I will bring the calamity of Esau upon him, the time that I will visit him.","ref":"Jeremiah 49:8","synthesized":"Turn and run! Lie low, O dwellers of Dedan, for I will bring disaster on Esau at the time I punish him.","sources":{"KJV":{"text":"Flee ye, turn back, dwell deep, O inhabitants of Dedan; for I will bring the calamity of Esau upon him, the time that I will visit him."},"BSB":{"text":"Turn and run! Lie low, O dwellers of Dedan, for I will bring disaster on Esau at the time I punish him."},"TANAKH":{"text":"Flee ye, turn back, dwell deep, O inhabitants of Dedan; for I do bring the calamity of Esau upon him, the time that I shall punish him."},"HEBREW":{"text":"נֻ֤סוּ הָפְנוּ֙ הֶעְמִ֣יקוּ לָשֶׁ֔בֶת יֹשְׁבֵ֖י דְּדָ֑ן כִּ֣י אֵ֥יד עֵשָׂ֛ו הֵבֵ֥אתִי עָלָ֖יו עֵ֥ת פְּקַדְתִּֽיו׃"}},"definableWords":["run","Esau"],"peopleInVerse":["Esau"]},"9":{"text":"If grapegatherers come to thee, would they not leave some gleaning grapes? if thieves by night, they will destroy till they have enough.","ref":"Jeremiah 49:9","synthesized":"If grape gatherers came to you, would they not leave some gleanings? Were thieves to come in the night, would they not steal only what they wanted?","sources":{"KJV":{"text":"If grapegatherers come to thee, would they not leave some gleaning grapes? if thieves by night, they will destroy till they have enough."},"BSB":{"text":"If grape gatherers came to you, would they not leave some gleanings? Were thieves to come in the night, would they not steal only what they wanted?"},"TANAKH":{"text":"If grape-gatherers came to thee, would they not leave some gleaning grapes? if thieves by night, would they not destroy till they had enough?"},"HEBREW":{"text":"אִם־בֹּֽצְרִים֙ בָּ֣אוּ לָ֔ךְ לֹ֥א יַשְׁאִ֖רוּ עֽוֹלֵל֑וֹת אִם־גַּנָּבִ֥ים בַּלַּ֖יְלָה הִשְׁחִ֥יתוּ דַיָּֽם׃"}},"definableWords":["night"],"peopleInVerse":[],"themesInVerse":["vine_branches"]},"10":{"text":"But I have made Esau bare, I have uncovered his secret places, and he shall not be able to hide himself: his seed is spoiled, and his brethren, and his neighbours, and he is not.","ref":"Jeremiah 49:10","synthesized":"But I will strip Esau bare; I will uncover his hiding places, and he will be unable to conceal himself. His descendants will be destroyed along with his relatives and neighbors, and he will be no more.","sources":{"KJV":{"text":"But I have made Esau bare, I have uncovered his secret places, and he shall not be able to hide himself: his seed is spoiled, and his brethren, and his neighbours, and he is not."},"BSB":{"text":"But I will strip Esau bare; I will uncover his hiding places, and he will be unable to conceal himself. His descendants will be destroyed along with his relatives and neighbors, and he will be no more."},"TANAKH":{"text":"But I have made Esau bare, I have uncovered his secret places, and he shall not be able to hide himself; his seed is spoiled, and his brethren, and his neighbours, and he is not."},"HEBREW":{"text":"כִּֽי־אֲנִ֞י חָשַׂ֣פְתִּי אֶת־עֵשָׂ֗ו גִּלֵּ֙יתִי֙ אֶת־מִסְתָּרָ֔יו וְנֶחְבָּ֖ה לֹ֣א יוּכָ֑ל שֻׁדַּ֥ד זַרְע֛וֹ וְאֶחָ֥יו וּשְׁכֵנָ֖יו וְאֵינֶֽנּוּ׃"}},"definableWords":["Esau"],"peopleInVerse":["Esau"]},"11":{"text":"Leave thy fatherless children, I will preserve them alive; and let thy widows trust in me.","ref":"Jeremiah 49:11","synthesized":"Abandon your orphans; I will preserve their lives. Let your widows trust in Me.”","sources":{"KJV":{"text":"Leave thy fatherless children, I will preserve them alive; and let thy widows trust in me."},"BSB":{"text":"Abandon your orphans; I will preserve their lives. Let your widows trust in Me.”"},"TANAKH":{"text":"Leave thy fatherless children, I will rear them, and let thy widows trust in Me."},"HEBREW":{"text":"עָזְבָ֥ה יְתֹמֶ֖יךָ אֲנִ֣י אֲחַיֶּ֑ה וְאַלְמְנֹתֶ֖יךָ עָלַ֥י תִּבְטָֽחוּ׃"}},"definableWords":["trust"],"peopleInVerse":[],"themesInVerse":["faith"]},"12":{"text":"For thus saith the LORD; Behold, they whose judgment was not to drink of the cup have assuredly drunken; and art thou he that shall altogether go unpunished? thou shalt not go unpunished, but thou shalt surely drink of it.","ref":"Jeremiah 49:12","synthesized":"For this is what the LORD says: “If those who do not deserve to drink the cup must drink it, can you possibly remain unpunished? You will not go unpunished, for you must drink it too.","sources":{"KJV":{"text":"For thus saith the LORD; Behold, they whose judgment was not to drink of the cup have assuredly drunken; and art thou he that shall altogether go unpunished? thou shalt not go unpunished, but thou shalt surely drink of it."},"BSB":{"text":"For this is what the LORD says: “If those who do not deserve to drink the cup must drink it, can you possibly remain unpunished? You will not go unpunished, for you must drink it too."},"TANAKH":{"text":"For thus saith HaShem: Behold, they to whom it pertained not to drink of the cup shall assuredly drink; and art thou he that shall altogether go unpunished? thou shalt not go unpunished, but thou shalt surely drink."},"HEBREW":{"text":"כִּי־כֹ֣ה ׀ אָמַ֣ר יְהוָ֗ה הִ֠נֵּה אֲשֶׁר־אֵ֨ין מִשְׁפָּטָ֜ם לִשְׁתּ֤וֹת הַכּוֹס֙ שָׁת֣וֹ יִשְׁתּ֔וּ וְאַתָּ֣ה ה֔וּא נָקֹ֖ה תִּנָּקֶ֑ה לֹ֣א תִנָּקֶ֔ה כִּ֥י שָׁתֹ֖ה תִּשְׁתֶּֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"13":{"text":"For I have sworn by myself, saith the LORD, that Bozrah shall become a desolation, a reproach, a waste, and a curse; and all the cities thereof shall be perpetual wastes.","ref":"Jeremiah 49:13","synthesized":"For by Myself I have sworn, declares the LORD, that Bozrah will become a desolation, a disgrace, a ruin, and a curse, and all her cities will be in ruins forever.”","sources":{"KJV":{"text":"For I have sworn by myself, saith the LORD, that Bozrah shall become a desolation, a reproach, a waste, and a curse; and all the cities thereof shall be perpetual wastes."},"BSB":{"text":"For by Myself I have sworn, declares the LORD, that Bozrah will become a desolation, a disgrace, a ruin, and a curse, and all her cities will be in ruins forever.”"},"TANAKH":{"text":"For I have sworn by Myself, saith HaShem, that Bozrah shall become an astonishment, a reproach, a waste, and a curse; and all the cities thereof shall be perpetual wastes."},"HEBREW":{"text":"כִּ֣י בִ֤י נִשְׁבַּ֙עְתִּי֙ נְאֻם־יְהוָ֔ה כִּֽי־לְשַׁמָּ֧ה לְחֶרְפָּ֛ה לְחֹ֥רֶב וְלִקְלָלָ֖ה תִּֽהְיֶ֣ה בָצְרָ֑ה וְכָל־עָרֶ֥יהָ תִהְיֶ֖ינָה לְחָרְב֥וֹת עוֹלָֽם׃"}},"definableWords":["LORD","curse"],"peopleInVerse":[]},"14":{"text":"I have heard a rumour from the LORD, and an ambassador is sent unto the heathen, saying, Gather ye together, and come against her, and rise up to the battle.","ref":"Jeremiah 49:14","synthesized":"I have heard a message from the LORD; an envoy has been sent to the nations: “Assemble yourselves to march against her! Rise up for battle!”","sources":{"KJV":{"text":"I have heard a rumour from the LORD, and an ambassador is sent unto the heathen, saying, Gather ye together, and come against her, and rise up to the battle."},"BSB":{"text":"I have heard a message from the LORD; an envoy has been sent to the nations: “Assemble yourselves to march against her! Rise up for battle!”"},"TANAKH":{"text":"I have heard a message from HaShem, and an ambassador is sent among the nations: 'Gather yourselves together, and come against her, and rise up to the battle.'"},"HEBREW":{"text":"שְׁמוּעָ֤ה שָׁמַ֙עְתִּי֙ מֵאֵ֣ת יְהוָ֔ה וְצִ֖יר בַּגּוֹיִ֣ם שָׁל֑וּחַ הִֽתְקַבְּצוּ֙ וּבֹ֣אוּ עָלֶ֔יהָ וְק֖וּמוּ לַמִּלְחָמָֽה׃"}},"definableWords":["LORD","nations"],"peopleInVerse":[],"themesInVerse":["resurrection","spiritual_warfare"]},"15":{"text":"For, lo, I will make thee small among the heathen, and despised among men.","ref":"Jeremiah 49:15","synthesized":"“For behold, I will make you small among nations, despised among men.","sources":{"KJV":{"text":"For, lo, I will make thee small among the heathen, and despised among men."},"BSB":{"text":"“For behold, I will make you small among nations, despised among men."},"TANAKH":{"text":"For, behold, I make thee small among the nations, and despised among men."},"HEBREW":{"text":"כִּֽי־הִנֵּ֥ה קָטֹ֛ן נְתַתִּ֖יךָ בַּגּוֹיִ֑ם בָּז֖וּי בָּאָדָֽם׃"}},"definableWords":["make","nations","men"],"peopleInVerse":[]},"16":{"text":"Thy terribleness hath deceived thee, and the pride of thine heart, O thou that dwellest in the clefts of the rock, that holdest the height of the hill: though thou shouldest make thy nest as high as the eagle, I will bring thee down from thence, saith the LORD.","ref":"Jeremiah 49:16","synthesized":"The terror you cause and the pride of your heart have deceived you, O dwellers in the clefts of the rocks, O occupiers of the mountain summit. Though you elevate your nest like the eagle, even from there I will bring you down,” declares the LORD.","sources":{"KJV":{"text":"Thy terribleness hath deceived thee, and the pride of thine heart, O thou that dwellest in the clefts of the rock, that holdest the height of the hill: though thou shouldest make thy nest as high as the eagle, I will bring thee down from thence, saith the LORD."},"BSB":{"text":"The terror you cause and the pride of your heart have deceived you, O dwellers in the clefts of the rocks, O occupiers of the mountain summit. Though you elevate your nest like the eagle, even from there I will bring you down,” declares the LORD."},"TANAKH":{"text":"Thy terribleness hath deceived thee, even the pride of thy heart, O thou that dwellest in the clefts of the rock, that holdest the height of the hill; though thou shouldest make thy nest as high as the eagle, I will bring thee down from thence, saith HaShem."},"HEBREW":{"text":"תִּֽפְלַצְתְּךָ֞ הִשִּׁ֤יא אֹתָךְ֙ זְד֣וֹן לִבֶּ֔ךָ שֹֽׁכְנִי֙ בְּחַגְוֵ֣י הַסֶּ֔לַע תֹּפְשִׂ֖י מְר֣וֹם גִּבְעָ֑ה כִּֽי־תַגְבִּ֤יהַ כַּנֶּ֙שֶׁר֙ קִנֶּ֔ךָ מִשָּׁ֥ם אֽוֹרִידְךָ֖ נְאֻם־יְהוָֽה׃"}},"definableWords":["heart","LORD"],"peopleInVerse":[]},"17":{"text":"Also Edom shall be a desolation: every one that goeth by it shall be astonished, and shall hiss at all the plagues thereof.","ref":"Jeremiah 49:17","synthesized":"“Edom will become an object of horror. All who pass by will be appalled and will scoff at all her wounds.","sources":{"KJV":{"text":"Also Edom shall be a desolation: every one that goeth by it shall be astonished, and shall hiss at all the plagues thereof."},"BSB":{"text":"“Edom will become an object of horror. All who pass by will be appalled and will scoff at all her wounds."},"TANAKH":{"text":"And Edom shall become an astonishment; every one that passeth by it shall be astonished and shall hiss at all the plagues thereof."},"HEBREW":{"text":"וְהָיְתָ֥ה אֱד֖וֹם לְשַׁמָּ֑ה כֹּ֚ל עֹבֵ֣ר עָלֶ֔יהָ יִשֹּׁ֥ם וְיִשְׁרֹ֖ק עַל־כָּל־מַכּוֹתֶֽהָ׃"}},"definableWords":["Edom"],"peopleInVerse":[]},"18":{"text":"As in the overthrow of Sodom and Gomorrah and the neighbour cities thereof, saith the LORD, no man shall abide there, neither shall a son of man dwell in it.","ref":"Jeremiah 49:18","synthesized":"As Sodom and Gomorrah were overthrown along with their neighbors,” says the LORD, “no one will dwell there; no man will abide there.","sources":{"KJV":{"text":"As in the overthrow of Sodom and Gomorrah and the neighbour cities thereof, saith the LORD, no man shall abide there, neither shall a son of man dwell in it."},"BSB":{"text":"As Sodom and Gomorrah were overthrown along with their neighbors,” says the LORD, “no one will dwell there; no man will abide there."},"TANAKH":{"text":"As in the overthrow of Sodom and Gomorrah and the neighbour cities thereof, saith HaShem, no man shall abide there, neither shall any son of man dwell therein."},"HEBREW":{"text":"כְּֽמַהְפֵּכַ֞ת סְדֹ֧ם וַעֲמֹרָ֛ה וּשְׁכֵנֶ֖יהָ אָמַ֣ר יְהוָ֑ה לֹֽא־יֵשֵׁ֥ב שָׁם֙ אִ֔ישׁ וְלֹֽא־יָג֥וּר בָּ֖הּ בֶּן־אָדָֽם׃"}},"definableWords":["Sodom","Gomorrah","LORD","one","man","abide"],"peopleInVerse":[],"placesInVerse":["Sodom","Gomorrah"]},"19":{"text":"Behold, he shall come up like a lion from the swelling of Jordan against the habitation of the strong: but I will suddenly make him run away from her: and who is a chosen man, that I may appoint over her? for who is like me? and who will appoint me the time? and who is that shepherd that will stand before me?","ref":"Jeremiah 49:19","synthesized":"Behold, one will come up like a lion from the thickets of the Jordan to the watered pasture. For in an instant I will chase Edom from her land. Who is the chosen one I will appoint for this? For who is like Me, and who can challenge Me? What shepherd can stand against Me?”","sources":{"KJV":{"text":"Behold, he shall come up like a lion from the swelling of Jordan against the habitation of the strong: but I will suddenly make him run away from her: and who is a chosen man, that I may appoint over her? for who is like me? and who will appoint me the time? and who is that shepherd that will stand before me?"},"BSB":{"text":"Behold, one will come up like a lion from the thickets of the Jordan to the watered pasture. For in an instant I will chase Edom from her land. Who is the chosen one I will appoint for this? For who is like Me, and who can challenge Me? What shepherd can stand against Me?”"},"TANAKH":{"text":"Behold, he shall come up like a lion from the thickets of the Jordan against the strong habitation; for I will suddenly make him run away from it, and whoso is chosen, him will I appoint over it; for who is like Me? and who will appoint Me a time? and who is that shepherd that will stand before Me?"},"HEBREW":{"text":"הִ֠נֵּה כְּאַרְיֵ֞ה יַעֲלֶ֨ה מִגְּא֣וֹן הַיַּרְדֵּן֮ אֶל־נְוֵ֣ה אֵיתָן֒ כִּֽי־אַרְגִּ֤יעָה אֲרִיצֶ֨נּוּ מֵֽעָלֶ֔יהָ וּמִ֥י בָח֖וּר אֵלֶ֣יהָ אֶפְקֹ֑ד כִּ֣י מִ֤י כָמ֙וֹנִי֙ וּמִ֣י יֹעִידֶ֔נִּי וּמִי־זֶ֣ה רֹעֶ֔ה אֲשֶׁ֥ר יַעֲמֹ֖ד לְפָנָֽי׃"}},"definableWords":["one","lion","Edom","land","shepherd","stand"],"peopleInVerse":[],"placesInVerse":["Jordan River"],"themesInVerse":["land_promise","shepherd_sheep"]},"20":{"text":"Therefore hear the counsel of the LORD, that he hath taken against Edom; and his purposes, that he hath purposed against the inhabitants of Teman: Surely the least of the flock shall draw them out: surely he shall make their habitations desolate with them.","ref":"Jeremiah 49:20","synthesized":"Therefore hear the plans that the LORD has drawn up against Edom and the strategies He has devised against the people of Teman: Surely the little ones of the flock will be dragged away; certainly their pasture will be made desolate because of them.","sources":{"KJV":{"text":"Therefore hear the counsel of the LORD, that he hath taken against Edom; and his purposes, that he hath purposed against the inhabitants of Teman: Surely the least of the flock shall draw them out: surely he shall make their habitations desolate with them."},"BSB":{"text":"Therefore hear the plans that the LORD has drawn up against Edom and the strategies He has devised against the people of Teman: Surely the little ones of the flock will be dragged away; certainly their pasture will be made desolate because of them."},"TANAKH":{"text":"Therefore hear ye the counsel of HaShem, that He hath taken against Edom; and His purposes, that He hath purposed against the inhabitants of Teman: surely the least of the flock shall drag them away, surely their habitation shall be appalled at them."},"HEBREW":{"text":"לָכֵ֞ן שִׁמְע֣וּ עֲצַת־יְהוָ֗ה אֲשֶׁ֤ר יָעַץ֙ אֶל־אֱד֔וֹם וּמַ֨חְשְׁבוֹתָ֔יו אֲשֶׁ֥ר חָשַׁ֖ב אֶל־יֹשְׁבֵ֣י תֵימָ֑ן אִם־לֹ֤א יִסְחָבוּם֙ צְעִירֵ֣י הַצֹּ֔אן אִם־לֹ֥א יַשִּׁ֛ים עֲלֵיהֶ֖ם נְוֵהֶֽם׃"}},"definableWords":["hear","LORD","Edom","people","made"],"peopleInVerse":[],"themesInVerse":["creation","shepherd_sheep"]},"21":{"text":"The earth is moved at the noise of their fall, at the cry the noise thereof was heard in the Red sea.","ref":"Jeremiah 49:21","synthesized":"At the sound of their fall the earth will quake; their cry will resound to the Red Sea.","sources":{"KJV":{"text":"The earth is moved at the noise of their fall, at the cry the noise thereof was heard in the Red sea."},"BSB":{"text":"At the sound of their fall the earth will quake; their cry will resound to the Red Sea."},"TANAKH":{"text":"The earth quaketh at the noise of their fall; there is a cry, the noise whereof is heard in the Red Sea."},"HEBREW":{"text":"מִקּ֣וֹל נִפְלָ֔ם רָעֲשָׁ֖ה הָאָ֑רֶץ צְעָקָ֕ה בְּיַם־ס֖וּף נִשְׁמַ֥ע קוֹלָֽהּ׃"}},"definableWords":["earth","sea"],"peopleInVerse":[],"placesInVerse":["Dead Sea"],"themesInVerse":["fall_sin"]},"22":{"text":"Behold, he shall come up and fly as the eagle, and spread his wings over Bozrah: and at that day shall the heart of the mighty men of Edom be as the heart of a woman in her pangs.","ref":"Jeremiah 49:22","synthesized":"Look! An eagle will soar and swoop down, spreading its wings over Bozrah. In that day the hearts of Edom’s mighty men will be like the heart of a woman in labor.","sources":{"KJV":{"text":"Behold, he shall come up and fly as the eagle, and spread his wings over Bozrah: and at that day shall the heart of the mighty men of Edom be as the heart of a woman in her pangs."},"BSB":{"text":"Look! An eagle will soar and swoop down, spreading its wings over Bozrah. In that day the hearts of Edom’s mighty men will be like the heart of a woman in labor."},"TANAKH":{"text":"Behold, he shall come up and swoop down as the vulture, and spread out his wings against Bozrah; and the heart of the mighty men of Edom at that day shall be as the heart of a woman in her pangs."},"HEBREW":{"text":"הִנֵּ֤ה כַנֶּ֙שֶׁר֙ יַעֲלֶ֣ה וְיִדְאֶ֔ה וְיִפְרֹ֥שׂ כְּנָפָ֖יו עַל־בָּצְרָ֑ה וְֽ֠הָיָה לֵ֞ב גִּבּוֹרֵ֤י אֱדוֹם֙ בַּיּ֣וֹם הַה֔וּא כְּלֵ֖ב אִשָּׁ֥ה מְצֵרָֽה׃"}},"definableWords":["day","Edom","mighty","men","heart","woman"],"peopleInVerse":[]},"23":{"text":"Concerning Damascus. Hamath is confounded, and Arpad: for they have heard evil tidings: they are fainthearted; there is sorrow on the sea; it cannot be quiet.","ref":"Jeremiah 49:23","synthesized":"Concerning Damascus:  “Hamath and Arpad are put to shame, for they have heard a bad report; they are agitated like the sea; their anxiety cannot be calmed.","sources":{"KJV":{"text":"Concerning Damascus. Hamath is confounded, and Arpad: for they have heard evil tidings: they are fainthearted; there is sorrow on the sea; it cannot be quiet."},"BSB":{"text":"Concerning Damascus:  “Hamath and Arpad are put to shame, for they have heard a bad report; they are agitated like the sea; their anxiety cannot be calmed."},"TANAKH":{"text":"Of Damascus. Hamath is ashamed, and Arpad; for they have heard evil tidings, they are melted away; there is trouble in the sea; it cannot be quiet."},"HEBREW":{"text":"לְדַמֶּ֗שֶׂק בּ֤וֹשָֽׁה חֲמָת֙ וְאַרְפָּ֔ד כִּי־שְׁמֻעָ֥ה רָעָ֛ה שָׁמְע֖וּ נָמֹ֑גוּ בַּיָּ֣ם דְּאָגָ֔ה הַשְׁקֵ֖ט לֹ֥א יוּכָֽל׃"}},"definableWords":["sea"],"peopleInVerse":[],"placesInVerse":["Damascus"]},"24":{"text":"Damascus is waxed feeble, and turneth herself to flee, and fear hath seized on her: anguish and sorrows have taken her, as a woman in travail.","ref":"Jeremiah 49:24","synthesized":"Damascus has become feeble; she has turned to flee. Panic has gripped her; anguish and pain have seized her like a woman in labor.","sources":{"KJV":{"text":"Damascus is waxed feeble, and turneth herself to flee, and fear hath seized on her: anguish and sorrows have taken her, as a woman in travail."},"BSB":{"text":"Damascus has become feeble; she has turned to flee. Panic has gripped her; anguish and pain have seized her like a woman in labor."},"TANAKH":{"text":"Damascus is waxed feeble, she turneth herself to flee, and trembling hath seized on her; anguish and pangs have taken hold of her, as of a woman in travail."},"HEBREW":{"text":"רָפְתָ֥ה דַמֶּ֛שֶׂק הִפְנְתָ֥ה לָנ֖וּס וְרֶ֣טֶט ׀ הֶחֱזִ֑יקָה צָרָ֧ה וַחֲבָלִ֛ים אֲחָזַ֖תָּה כַּיּוֹלֵדָֽה׃"}},"definableWords":["woman"],"peopleInVerse":[],"placesInVerse":["Damascus"],"themesInVerse":["suffering"]},"25":{"text":"How is the city of praise not left, the city of my joy!","ref":"Jeremiah 49:25","synthesized":"How is the city of praise not forsaken, the town that brings Me joy?","sources":{"KJV":{"text":"How is the city of praise not left, the city of my joy!"},"BSB":{"text":"How is the city of praise not forsaken, the town that brings Me joy?"},"TANAKH":{"text":"'How is the city of praise left unrepaired, the city of my joy?'"},"HEBREW":{"text":"אֵ֥יךְ לֹֽא־עֻזְּבָ֖ה עִ֣יר תהלה תְּהִלָּ֑ת קִרְיַ֖ת מְשׂוֹשִֽׂי׃"}},"definableWords":["praise","joy"],"peopleInVerse":[],"themesInVerse":["joy","worship"]},"26":{"text":"Therefore her young men shall fall in her streets, and all the men of war shall be cut off in that day, saith the LORD of hosts.","ref":"Jeremiah 49:26","synthesized":"For her young men will fall in the streets, and all her warriors will be silenced in that day,” declares the LORD of Hosts.","sources":{"KJV":{"text":"Therefore her young men shall fall in her streets, and all the men of war shall be cut off in that day, saith the LORD of hosts."},"BSB":{"text":"For her young men will fall in the streets, and all her warriors will be silenced in that day,” declares the LORD of Hosts."},"TANAKH":{"text":"Therefore her young men shall fall in her broad places, and all the men of war shall be brought to silence in that day, saith HaShem of hosts."},"HEBREW":{"text":"לָכֵ֛ן יִפְּל֥וּ בַחוּרֶ֖יהָ בִּרְחֹבֹתֶ֑יהָ וְכָל־אַנְשֵׁ֨י הַמִּלְחָמָ֤ה יִדַּ֙מּוּ֙ בַּיּ֣וֹם הַה֔וּא נְאֻ֖ם יְהוָ֥ה צְבָאֽוֹת׃"}},"definableWords":["men","day","LORD"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"27":{"text":"And I will kindle a fire in the wall of Damascus, and it shall consume the palaces of Benhadad.","ref":"Jeremiah 49:27","synthesized":"“I will set fire to the walls of Damascus; it will consume the fortresses of Ben-hadad.”","sources":{"KJV":{"text":"And I will kindle a fire in the wall of Damascus, and it shall consume the palaces of Benhadad."},"BSB":{"text":"“I will set fire to the walls of Damascus; it will consume the fortresses of Ben-hadad.”"},"TANAKH":{"text":"And I will kindle a fire in the wall of Damascus, and it shall devour the palaces of Ben-hadad."},"HEBREW":{"text":"וְהִצַּ֥תִּי אֵ֖שׁ בְּחוֹמַ֣ת דַּמָּ֑שֶׂק וְאָכְלָ֖ה אַרְמְנ֥וֹת בֶּן־הֲדָֽד׃"}},"definableWords":[],"peopleInVerse":[],"placesInVerse":["Damascus"]},"28":{"text":"Concerning Kedar, and concerning the kingdoms of Hazor, which Nebuchadrezzar king of Babylon shall smite, thus saith the LORD; Arise ye, go up to Kedar, and spoil the men of the east.","ref":"Jeremiah 49:28","synthesized":"Concerning Kedar and the kingdoms of Hazor, which Nebuchadnezzar king of Babylon defeated, this is what the LORD says:  “Rise up, advance against Kedar, and destroy the people of the east!","sources":{"KJV":{"text":"Concerning Kedar, and concerning the kingdoms of Hazor, which Nebuchadrezzar king of Babylon shall smite, thus saith the LORD; Arise ye, go up to Kedar, and spoil the men of the east."},"BSB":{"text":"Concerning Kedar and the kingdoms of Hazor, which Nebuchadnezzar king of Babylon defeated, this is what the LORD says:  “Rise up, advance against Kedar, and destroy the people of the east!"},"TANAKH":{"text":"Of Kedar, and of the kingdoms of Hazor, which Nebuchadrezzar king of Babylon smote. Thus saith HaShem: Arise ye, go up against Kedar, and spoil the children of the east."},"HEBREW":{"text":"לְקֵדָ֣ר ׀ וּֽלְמַמְלְכ֣וֹת חָצ֗וֹר אֲשֶׁ֤ר הִכָּה֙ נבוכדראצור נְבֽוּכַדְרֶאצַּ֣ר מֶֽלֶךְ־בָּבֶ֔ל כֹּ֖ה אָמַ֣ר יְהוָ֑ה ק֚וּמוּ עֲל֣וּ אֶל־קֵדָ֔ר וְשָׁדְד֖וּ אֶת־בְּנֵי־קֶֽדֶם׃"}},"definableWords":["king","Babylon","LORD","people"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship","resurrection"]},"29":{"text":"Their tents and their flocks shall they take away: they shall take to themselves their curtains, and all their vessels, and their camels; and they shall cry unto them, Fear is on every side.","ref":"Jeremiah 49:29","synthesized":"They will take their tents and flocks, their tent curtains and all their goods. They will take their camels for themselves. They will shout to them: ‘Terror is on every side!’","sources":{"KJV":{"text":"Their tents and their flocks shall they take away: they shall take to themselves their curtains, and all their vessels, and their camels; and they shall cry unto them, Fear is on every side."},"BSB":{"text":"They will take their tents and flocks, their tent curtains and all their goods. They will take their camels for themselves. They will shout to them: ‘Terror is on every side!’"},"TANAKH":{"text":"Their tents and their flocks shall they take, they shall carry away for themselves their curtains, and all their vessels, and their camels; and they shall proclaim against them a terror on every side."},"HEBREW":{"text":"אָהֳלֵיהֶ֤ם וְצֹאנָם֙ יִקָּ֔חוּ יְרִיעוֹתֵיהֶ֧ם וְכָל־כְּלֵיהֶ֛ם וּגְמַלֵּיהֶ֖ם יִשְׂא֣וּ לָהֶ֑ם וְקָרְא֧וּ עֲלֵיהֶ֛ם מָג֖וֹר מִסָּבִֽיב׃"}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"Flee, get you far off, dwell deep, O ye inhabitants of Hazor, saith the LORD; for Nebuchadrezzar king of Babylon hath taken counsel against you, and hath conceived a purpose against you.","ref":"Jeremiah 49:30","synthesized":"Run! Escape quickly! Lie low, O residents of Hazor,” declares the LORD, “for Nebuchadnezzar king of Babylon has drawn up a plan against you; he has devised a strategy against you.","sources":{"KJV":{"text":"Flee, get you far off, dwell deep, O ye inhabitants of Hazor, saith the LORD; for Nebuchadrezzar king of Babylon hath taken counsel against you, and hath conceived a purpose against you."},"BSB":{"text":"Run! Escape quickly! Lie low, O residents of Hazor,” declares the LORD, “for Nebuchadnezzar king of Babylon has drawn up a plan against you; he has devised a strategy against you."},"TANAKH":{"text":"Flee ye, flit far off, dwell deep, O ye inhabitants of Hazor, saith HaShem; for Nebuchadrezzar king of Babylon hath taken counsel against you, and hath conceived a purpose against you."},"HEBREW":{"text":"נֻסוּ֩ נֻּ֨דוּ מְאֹ֜ד הֶעְמִ֧יקוּ לָשֶׁ֛בֶת יֹשְׁבֵ֥י חָצ֖וֹר נְאֻם־יְהוָ֑ה כִּֽי־יָעַ֨ץ עֲלֵיכֶ֜ם נְבוּכַדְרֶאצַּ֤ר מֶֽלֶךְ־בָּבֶל֙ עֵצָ֔ה וְחָשַׁ֥ב עליהם עֲלֵיכֶ֖ם מַחֲשָׁבָֽה׃"}},"definableWords":["run","LORD","king","Babylon"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"31":{"text":"Arise, get you up unto the wealthy nation, that dwelleth without care, saith the LORD, which have neither gates nor bars, which dwell alone.","ref":"Jeremiah 49:31","synthesized":"Rise up, advance against a nation at ease, one that dwells securely,” declares the LORD. “They have no gates or bars; they live alone.","sources":{"KJV":{"text":"Arise, get you up unto the wealthy nation, that dwelleth without care, saith the LORD, which have neither gates nor bars, which dwell alone."},"BSB":{"text":"Rise up, advance against a nation at ease, one that dwells securely,” declares the LORD. “They have no gates or bars; they live alone."},"TANAKH":{"text":"Arise, get you up against a nation that is at ease, that dwelleth without care, saith HaShem; that have neither gates nor bars, that dwell alone."},"HEBREW":{"text":"ק֣וּמוּ עֲל֗וּ אֶל־גּ֥וֹי שְׁלֵ֛יו יוֹשֵׁ֥ב לָבֶ֖טַח נְאֻם־יְהוָ֑ה לֹא־דְלָתַ֧יִם וְלֹֽא־בְרִ֛יחַ ל֖וֹ בָּדָ֥ד יִשְׁכֹּֽנוּ׃"}},"definableWords":["nation","one","LORD","or","live"],"peopleInVerse":[],"themesInVerse":["resurrection"]},"32":{"text":"And their camels shall be a booty, and the multitude of their cattle a spoil: and I will scatter into all winds them that are in the utmost corners; and I will bring their calamity from all sides thereof, saith the LORD.","ref":"Jeremiah 49:32","synthesized":"Their camels will become plunder, and their large herds will be spoil. I will scatter to the wind in every direction those who shave their temples; I will bring calamity on them from all sides,” declares the LORD.","sources":{"KJV":{"text":"And their camels shall be a booty, and the multitude of their cattle a spoil: and I will scatter into all winds them that are in the utmost corners; and I will bring their calamity from all sides thereof, saith the LORD."},"BSB":{"text":"Their camels will become plunder, and their large herds will be spoil. I will scatter to the wind in every direction those who shave their temples; I will bring calamity on them from all sides,” declares the LORD."},"TANAKH":{"text":"And their camels shall be a booty, and the multitude of their cattle a spoil; and I will scatter unto all winds them that have the corners polled; and I will bring their calamity from every side of them, saith HaShem."},"HEBREW":{"text":"וְהָי֨וּ גְמַלֵּיהֶ֜ם לָבַ֗ז וַהֲמ֤וֹן מִקְנֵיהֶם֙ לְשָׁלָ֔ל וְזֵרִתִ֥ים לְכָל־ר֖וּחַ קְצוּצֵ֣י פֵאָ֑ה וּמִכָּל־עֲבָרָ֛יו אָבִ֥יא אֶת־אֵידָ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"33":{"text":"And Hazor shall be a dwelling for dragons, and a desolation for ever: there shall no man abide there, nor any son of man dwell in it.","ref":"Jeremiah 49:33","synthesized":"“Hazor will become a haunt for jackals, a desolation forever. No one will dwell there; no man will abide there.”","sources":{"KJV":{"text":"And Hazor shall be a dwelling for dragons, and a desolation for ever: there shall no man abide there, nor any son of man dwell in it."},"BSB":{"text":"“Hazor will become a haunt for jackals, a desolation forever. No one will dwell there; no man will abide there.”"},"TANAKH":{"text":"And Hazor shall be a dwelling-place of jackals, a desolation for ever; no man shall abide there, neither shall any son of man dwell therein."},"HEBREW":{"text":"וְהָיְתָ֨ה חָצ֜וֹר לִמְע֥וֹן תַּנִּ֛ים שְׁמָמָ֖ה עַד־עוֹלָ֑ם לֹֽא־יֵשֵׁ֥ב שָׁם֙ אִ֔ישׁ וְלֹֽא־יָג֥וּר בָּ֖הּ בֶּן־אָדָֽם׃"}},"definableWords":["one","man","abide"],"peopleInVerse":[]},"34":{"text":"The word of the LORD that came to Jeremiah the prophet against Elam in the beginning of the reign of Zedekiah king of Judah, saying,","ref":"Jeremiah 49:34","synthesized":"This is the word of the LORD that came to Jeremiah the prophet concerning Elam at the beginning of the reign of Zedekiah king of Judah.","sources":{"KJV":{"text":"The word of the LORD that came to Jeremiah the prophet against Elam in the beginning of the reign of Zedekiah king of Judah, saying,"},"BSB":{"text":"This is the word of the LORD that came to Jeremiah the prophet concerning Elam at the beginning of the reign of Zedekiah king of Judah."},"TANAKH":{"text":"The word of HaShem that came to Jeremiah the prophet concerning Elam in the beginning of the reign of Zedekiah king of Judah, saying:"},"HEBREW":{"text":"אֲשֶׁ֨ר הָיָ֧ה דְבַר־יְהוָ֛ה אֶל־יִרְמְיָ֥הוּ הַנָּבִ֖יא אֶל־עֵילָ֑ם בְּרֵאשִׁ֗ית מַלְכ֛וּת צִדְקִיָּ֥ה מֶֽלֶךְ־יְהוּדָ֖ה לֵאמֹֽר׃"}},"definableWords":["word","LORD","prophet","beginning","reign","king","Judah"],"peopleInVerse":["Jeremiah"],"themesInVerse":["creation","kingdom_of_god","kingship"]},"35":{"text":"Thus saith the LORD of hosts; Behold, I will break the bow of Elam, the chief of their might.","ref":"Jeremiah 49:35","synthesized":"This is what the LORD of Hosts says:  “Behold, I will shatter Elam’s bow, the mainstay of their might.","sources":{"KJV":{"text":"Thus saith the LORD of hosts; Behold, I will break the bow of Elam, the chief of their might."},"BSB":{"text":"This is what the LORD of Hosts says:  “Behold, I will shatter Elam’s bow, the mainstay of their might."},"TANAKH":{"text":"Thus saith HaShem of hosts: behold, I will break the bow of Elam the chief of their might."},"HEBREW":{"text":"כֹּ֤ה אָמַר֙ יְהוָ֣ה צְבָא֔וֹת הִנְנִ֥י שֹׁבֵ֖ר אֶת־קֶ֣שֶׁת עֵילָ֑ם רֵאשִׁ֖ית גְּבוּרָתָֽם׃"}},"definableWords":["LORD"],"peopleInVerse":[],"themesInVerse":["worship"]},"36":{"text":"And upon Elam will I bring the four winds from the four quarters of heaven, and will scatter them toward all those winds; and there shall be no nation whither the outcasts of Elam shall not come.","ref":"Jeremiah 49:36","synthesized":"I will bring the four winds against Elam from the four corners of the heavens, and I will scatter them to all these winds. There will not be a nation to which Elam’s exiles will not go.","sources":{"KJV":{"text":"And upon Elam will I bring the four winds from the four quarters of heaven, and will scatter them toward all those winds; and there shall be no nation whither the outcasts of Elam shall not come."},"BSB":{"text":"I will bring the four winds against Elam from the four corners of the heavens, and I will scatter them to all these winds. There will not be a nation to which Elam’s exiles will not go."},"TANAKH":{"text":"And I will bring against Elam the four winds from the four quarters of heaven, and will scatter them toward all those winds; and there shall be no nation whither the dispersed of Elam shall not come."},"HEBREW":{"text":"וְהֵבֵאתִ֨י אֶל־עֵילָ֜ם אַרְבַּ֣ע רוּח֗וֹת מֵֽאַרְבַּע֙ קְצ֣וֹת הַשָּׁמַ֔יִם וְזֵ֣רִתִ֔ים לְכֹ֖ל הָרֻח֣וֹת הָאֵ֑לֶּה וְלֹֽא־יִהְיֶ֣ה הַגּ֔וֹי אֲשֶׁ֛ר לֹֽא־יָב֥וֹא שָׁ֖ם נִדְּחֵ֥י עולם עֵילָֽם׃"}},"definableWords":["heavens","nation"],"peopleInVerse":[]},"37":{"text":"For I will cause Elam to be dismayed before their enemies, and before them that seek their life: and I will bring evil upon them, even my fierce anger, saith the LORD; and I will send the sword after them, till I have consumed them:","ref":"Jeremiah 49:37","synthesized":"So I will shatter Elam before their foes, before those who seek their lives. I will bring disaster upon them, even My fierce anger,” declares the LORD. “I will send out the sword after them until I finish them off.","sources":{"KJV":{"text":"For I will cause Elam to be dismayed before their enemies, and before them that seek their life: and I will bring evil upon them, even my fierce anger, saith the LORD; and I will send the sword after them, till I have consumed them:"},"BSB":{"text":"So I will shatter Elam before their foes, before those who seek their lives. I will bring disaster upon them, even My fierce anger,” declares the LORD. “I will send out the sword after them until I finish them off."},"TANAKH":{"text":"And I will cause Elam to be dismayed before their enemies, and before them that seek their life; and I will bring evil upon them, even My fierce anger, saith HaShem; and I will send the sword after them, till I have consumed them;"},"HEBREW":{"text":"וְהַחְתַּתִּ֣י אֶת־עֵ֠ילָם לִפְנֵ֨י אֹיְבֵיהֶ֜ם וְלִפְנֵ֣י ׀ מְבַקְשֵׁ֣י נַפְשָׁ֗ם וְהֵבֵאתִ֨י עֲלֵיהֶ֧ם ׀ רָעָ֛ה אֶת־חֲר֥וֹן אַפִּ֖י נְאֻם־יְהוָ֑ה וְשִׁלַּחְתִּ֤י אַֽחֲרֵיהֶם֙ אֶת־הַחֶ֔רֶב עַ֥ד כַּלּוֹתִ֖י אוֹתָֽם׃"}},"definableWords":["seek","anger","LORD"],"peopleInVerse":[]},"38":{"text":"And I will set my throne in Elam, and will destroy from thence the king and the princes, saith the LORD.","ref":"Jeremiah 49:38","synthesized":"I will set My throne in Elam, and destroy its king and officials,” declares the LORD.","sources":{"KJV":{"text":"And I will set my throne in Elam, and will destroy from thence the king and the princes, saith the LORD."},"BSB":{"text":"I will set My throne in Elam, and destroy its king and officials,” declares the LORD."},"TANAKH":{"text":"And I will set My throne in Elam, and will destroy from thence king and princes, saith HaShem."},"HEBREW":{"text":"וְשַׂמְתִּ֥י כִסְאִ֖י בְּעֵילָ֑ם וְהַאֲבַדְתִּ֥י מִשָּׁ֛ם מֶ֥לֶךְ וְשָׂרִ֖ים נְאֻם־יְהוָֽה׃"}},"definableWords":["throne","king","LORD"],"peopleInVerse":[],"themesInVerse":["kingdom_of_god","kingship"]},"39":{"text":"But it shall come to pass in the latter days, that I will bring again the captivity of Elam, saith the LORD.","ref":"Jeremiah 49:39","synthesized":"“Yet in the last days, I will restore Elam from captivity,” declares the LORD.","sources":{"KJV":{"text":"But it shall come to pass in the latter days, that I will bring again the captivity of Elam, saith the LORD."},"BSB":{"text":"“Yet in the last days, I will restore Elam from captivity,” declares the LORD."},"TANAKH":{"text":"But it shall come to pass in the end of days, that I will bring back the captivity of Elam, saith HaShem."},"HEBREW":{"text":"וְהָיָ֣ה ׀ בְּאַחֲרִ֣ית הַיָּמִ֗ים אשוב אָשִׁ֛יב אֶת־שבית שְׁב֥וּת עֵילָ֖ם נְאֻם־יְהוָֽה׃"}},"definableWords":["days","LORD"],"peopleInVerse":[],"themesInVerse":["exile_return"]}}},"50":{"chapter":"50","title":"JUDGMENT AGAINST BABYLON","verses":{"1":{"text":"The word that the LORD spake against Babylon and against the land of the Chaldeans by Jeremiah the prophet.","ref":"Jeremiah 50:1","synthesized":"This is the word that the LORD spoke through Jeremiah the prophet concerning Babylon and the land of the Chaldeans:","sources":{"KJV":{"text":"The word that the LORD spake against Babylon and against the land of the Chaldeans by Jeremiah the prophet."},"BSB":{"text":"This is the word that the LORD spoke through Jeremiah the prophet concerning Babylon and the land of the Chaldeans:"},"TANAKH":{"text":"The word that HaShem spoke concerning Babylon, concerning the land of the Chaldeans, by Jeremiah the prophet."},"HEBREW":{"text":"הַדָּבָ֗ר אֲשֶׁ֨ר דִּבֶּ֧ר יְהוָ֛ה אֶל־בָּבֶ֖ל אֶל־אֶ֣רֶץ כַּשְׂדִּ֑ים בְּיַ֖ד יִרְמְיָ֥הוּ הַנָּבִֽיא׃"}},"definableWords":["word","LORD","prophet","Babylon","land"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Babylon"],"themesInVerse":["land_promise"]},"2":{"text":"Declare ye among the nations, and publish, and set up a standard; publish, and conceal not: say, Babylon is taken, Bel is confounded, Merodach is broken in pieces; her idols are confounded, her images are broken in pieces.","ref":"Jeremiah 50:2","synthesized":"“Announce and declare to the nations; lift up a banner and proclaim it; hold nothing back when you say, ‘Babylon is captured; Bel is put to shame; Marduk is shattered, her images are disgraced, her idols are broken in pieces.’","sources":{"KJV":{"text":"Declare ye among the nations, and publish, and set up a standard; publish, and conceal not: say, Babylon is taken, Bel is confounded, Merodach is broken in pieces; her idols are confounded, her images are broken in pieces."},"BSB":{"text":"“Announce and declare to the nations; lift up a banner and proclaim it; hold nothing back when you say, ‘Babylon is captured; Bel is put to shame; Marduk is shattered, her images are disgraced, her idols are broken in pieces.’"},"TANAKH":{"text":"Declare ye among the nations and announce, and set up a standard; announce, and conceal not; say: 'Babylon is taken, Bel is put to shame, Merodach is dismayed; her images are put to shame, her idols are dismayed.'"},"HEBREW":{"text":"הַגִּ֨ידוּ בַגּוֹיִ֤ם וְהַשְׁמִ֙יעוּ֙ וּֽשְׂאוּ־נֵ֔ס הַשְׁמִ֖יעוּ אַל־תְּכַחֵ֑דוּ אִמְרוּ֩ נִלְכְּדָ֨ה בָבֶ֜ל הֹבִ֥ישׁ בֵּל֙ חַ֣ת מְרֹדָ֔ךְ הֹבִ֣ישׁוּ עֲצַבֶּ֔יהָ חַ֖תּוּ גִּלּוּלֶֽיהָ׃"}},"definableWords":["nations","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"3":{"text":"For out of the north there cometh up a nation against her, which shall make her land desolate, and none shall dwell therein: they shall remove, they shall depart, both man and beast.","ref":"Jeremiah 50:3","synthesized":"For a nation from the north will come against her; it will make her land a desolation. No one will live in it; both man and beast will flee.”","sources":{"KJV":{"text":"For out of the north there cometh up a nation against her, which shall make her land desolate, and none shall dwell therein: they shall remove, they shall depart, both man and beast."},"BSB":{"text":"For a nation from the north will come against her; it will make her land a desolation. No one will live in it; both man and beast will flee.”"},"TANAKH":{"text":"For out of the north there cometh up a nation against her, which shall make her land desolate, and none shall dwell therein; they are fled, they are gone, both man and beast."},"HEBREW":{"text":"כִּ֣י עָלָה֩ עָלֶ֨יהָ גּ֜וֹי מִצָּפ֗וֹן הֽוּא־יָשִׁ֤ית אֶת־אַרְצָהּ֙ לְשַׁמָּ֔ה וְלֹֽא־יִהְיֶ֥ה יוֹשֵׁ֖ב בָּ֑הּ מֵאָדָ֥ם וְעַד־בְּהֵמָ֖ה נָ֥דוּ הָלָֽכוּ׃"}},"definableWords":["nation","make","land","one","live","man"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"4":{"text":"In those days, and in that time, saith the LORD, the children of Israel shall come, they and the children of Judah together, going and weeping: they shall go, and seek the LORD their God.","ref":"Jeremiah 50:4","synthesized":"“In those days and at that time, declares the LORD, the children of Israel and the children of Judah will come together, weeping as they come, and will seek the LORD their God.","sources":{"KJV":{"text":"In those days, and in that time, saith the LORD, the children of Israel shall come, they and the children of Judah together, going and weeping: they shall go, and seek the LORD their God."},"BSB":{"text":"“In those days and at that time, declares the LORD, the children of Israel and the children of Judah will come together, weeping as they come, and will seek the LORD their God."},"TANAKH":{"text":"In those days, and in that time, saith HaShem, the children of Israel shall come, they and the children of Judah together; they shall go on their way weeping, and shall seek HaShem their G-d."},"HEBREW":{"text":"בַּיָּמִ֨ים הָהֵ֜מָּה וּבָעֵ֤ת הַהִיא֙ נְאֻם־יְהוָ֔ה יָבֹ֧אוּ בְנֵֽי־יִשְׂרָאֵ֛ל הֵ֥מָּה וּבְנֵֽי־יְהוּדָ֖ה יַחְדָּ֑ו הָל֤וֹךְ וּבָכוֹ֙ יֵלֵ֔כוּ וְאֶת־יְהוָ֥ה אֱלֹהֵיהֶ֖ם יְבַקֵּֽשׁוּ׃"}},"definableWords":["days","LORD","Israel","Judah","seek","Lord","God"],"peopleInVerse":[]},"5":{"text":"They shall ask the way to Zion with their faces thitherward, saying, Come, and let us join ourselves to the LORD in a perpetual covenant that shall not be forgotten.","ref":"Jeremiah 50:5","synthesized":"They will ask the way to Zion and turn their faces toward it. They will come and join themselves to the LORD in an everlasting covenant that will never be forgotten.","sources":{"KJV":{"text":"They shall ask the way to Zion with their faces thitherward, saying, Come, and let us join ourselves to the LORD in a perpetual covenant that shall not be forgotten."},"BSB":{"text":"They will ask the way to Zion and turn their faces toward it. They will come and join themselves to the LORD in an everlasting covenant that will never be forgotten."},"TANAKH":{"text":"They shall inquire concerning Zion with their faces hitherward: 'Come ye, and join yourselves to HaShem in an everlasting covenant that shall not be forgotten.'"},"HEBREW":{"text":"צִיּ֣וֹן יִשְׁאָ֔לוּ דֶּ֖רֶךְ הֵ֣נָּה פְנֵיהֶ֑ם בֹּ֚אוּ וְנִלְו֣וּ אֶל־יְהוָ֔ה בְּרִ֥ית עוֹלָ֖ם לֹ֥א תִשָּׁכֵֽחַ׃"}},"definableWords":["way","Zion","LORD","everlasting","covenant"],"peopleInVerse":[],"placesInVerse":["Mount Zion"],"themesInVerse":["covenant"]},"6":{"text":"My people hath been lost sheep: their shepherds have caused them to go astray, they have turned them away on the mountains: they have gone from mountain to hill, they have forgotten their restingplace.","ref":"Jeremiah 50:6","synthesized":"My people are lost sheep; their shepherds have led them astray, causing them to roam the mountains. They have wandered from mountain to hill; they have forgotten their resting place.","sources":{"KJV":{"text":"My people hath been lost sheep: their shepherds have caused them to go astray, they have turned them away on the mountains: they have gone from mountain to hill, they have forgotten their restingplace."},"BSB":{"text":"My people are lost sheep; their shepherds have led them astray, causing them to roam the mountains. They have wandered from mountain to hill; they have forgotten their resting place."},"TANAKH":{"text":"My people hath been lost sheep; their shepherds have caused them to go astray, they have turned them away on the mountains; they have gone from mountain to hill, they have forgotten their resting-place."},"HEBREW":{"text":"צֹ֤אן אֹֽבְדוֹת֙ היה הָי֣וּ עַמִּ֔י רֹעֵיהֶ֣ם הִתְע֔וּם הָרִ֖ים שובבים שֽׁוֹבְב֑וּם מֵהַ֤ר אֶל־גִּבְעָה֙ הָלָ֔כוּ שָׁכְח֖וּ רִבְצָֽם׃"}},"definableWords":["people"],"peopleInVerse":[],"themesInVerse":["shepherd_sheep"]},"7":{"text":"All that found them have devoured them: and their adversaries said, We offend not, because they have sinned against the LORD, the habitation of justice, even the LORD, the hope of their fathers.","ref":"Jeremiah 50:7","synthesized":"All who found them devoured them, and their enemies said, ‘We are not guilty, for they have sinned against the LORD, their true pasture, the LORD, the hope of their fathers.’","sources":{"KJV":{"text":"All that found them have devoured them: and their adversaries said, We offend not, because they have sinned against the LORD, the habitation of justice, even the LORD, the hope of their fathers."},"BSB":{"text":"All who found them devoured them, and their enemies said, ‘We are not guilty, for they have sinned against the LORD, their true pasture, the LORD, the hope of their fathers.’"},"TANAKH":{"text":"All that found them have devoured them; and their adversaries said: 'We are not guilty'; because they have sinned against HaShem, the habitation of justice, even HaShem, the hope of their fathers."},"HEBREW":{"text":"כָּל־מוֹצְאֵיהֶ֣ם אֲכָל֔וּם וְצָרֵיהֶ֥ם אָמְר֖וּ לֹ֣א נֶאְשָׁ֑ם תַּ֗חַת אֲשֶׁ֨ר חָטְא֤וּ לַֽיהוָה֙ נְוֵה־צֶ֔דֶק וּמִקְוֵ֥ה אֲבֽוֹתֵיהֶ֖ם יְהוָֽה׃"}},"definableWords":["LORD","Lord","hope","fathers"],"peopleInVerse":[],"themesInVerse":["hope"]},"8":{"text":"Remove out of the midst of Babylon, and go forth out of the land of the Chaldeans, and be as the he goats before the flocks.","ref":"Jeremiah 50:8","synthesized":"Flee from the midst of Babylon; depart from the land of the Chaldeans; be like the he-goats that lead the flock.","sources":{"KJV":{"text":"Remove out of the midst of Babylon, and go forth out of the land of the Chaldeans, and be as the he goats before the flocks."},"BSB":{"text":"Flee from the midst of Babylon; depart from the land of the Chaldeans; be like the he-goats that lead the flock."},"TANAKH":{"text":"Flee out of the midst of Babylon, and go forth out of the land of the Chaldeans, and be as the he-goats before the flocks."},"HEBREW":{"text":"נֻ֚דוּ מִתּ֣וֹךְ בָּבֶ֔ל וּמֵאֶ֥רֶץ כַּשְׂדִּ֖ים יצאו צֵ֑אוּ וִהְי֕וּ כְּעַתּוּדִ֖ים לִפְנֵי־צֹֽאן׃"}},"definableWords":["Babylon","land"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["land_promise","shepherd_sheep"]},"9":{"text":"For, lo, I will raise and cause to come up against Babylon an assembly of great nations from the north country: and they shall set themselves in array against her; from thence she shall be taken: their arrows shall be as of a mighty expert man; none shall return in vain.","ref":"Jeremiah 50:9","synthesized":"For behold, I stir up and bring against Babylon an assembly of great nations from the land of the north. They will line up against her; from the north she will be captured. Their arrows will be like skilled warriors who do not return empty-handed.","sources":{"KJV":{"text":"For, lo, I will raise and cause to come up against Babylon an assembly of great nations from the north country: and they shall set themselves in array against her; from thence she shall be taken: their arrows shall be as of a mighty expert man; none shall return in vain."},"BSB":{"text":"For behold, I stir up and bring against Babylon an assembly of great nations from the land of the north. They will line up against her; from the north she will be captured. Their arrows will be like skilled warriors who do not return empty-handed."},"TANAKH":{"text":"For, lo, I will stir up and cause to come up against Babylon an assembly of great nations from the north country; and they shall set themselves in array against her, from thence she shall be taken; their arrows shall be as of a mighty man that maketh childless; none shall return in vain."},"HEBREW":{"text":"כִּ֣י הִנֵּ֣ה אָנֹכִ֡י מֵעִיר֩ וּמַעֲלֶ֨ה עַל־בָּבֶ֜ל קְהַל־גּוֹיִ֤ם גְּדֹלִים֙ מֵאֶ֣רֶץ צָפ֔וֹן וְעָ֣רְכוּ לָ֔הּ מִשָּׁ֖ם תִּלָּכֵ֑ד חִצָּיו֙ כְּגִבּ֣וֹר מַשְׁכִּ֔יל לֹ֥א יָשׁ֖וּב רֵיקָֽם׃"}},"definableWords":["Babylon","great","nations","land"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["exile_return","land_promise","second_coming"]},"10":{"text":"And Chaldea shall be a spoil: all that spoil her shall be satisfied, saith the LORD.","ref":"Jeremiah 50:10","synthesized":"Chaldea will be plundered; all who plunder her will have their fill,” declares the LORD.","sources":{"KJV":{"text":"And Chaldea shall be a spoil: all that spoil her shall be satisfied, saith the LORD."},"BSB":{"text":"Chaldea will be plundered; all who plunder her will have their fill,” declares the LORD."},"TANAKH":{"text":"And Chaldea shall be a spoil; all that spoil her shall be satisfied, saith HaShem."},"HEBREW":{"text":"וְהָיְתָ֥ה כַשְׂדִּ֖ים לְשָׁלָ֑ל כָּל־שֹׁלְלֶ֥יהָ יִשְׂבָּ֖עוּ נְאֻם־יְהוָֽה׃"}},"definableWords":["fill","LORD"],"peopleInVerse":[]},"11":{"text":"Because ye were glad, because ye rejoiced, O ye destroyers of mine heritage, because ye are grown fat as the heifer at grass, and bellow as bulls;","ref":"Jeremiah 50:11","synthesized":"“Because you rejoice, because you sing in triumph— you who plunder My inheritance— because you frolic like a heifer treading grain and neigh like stallions,","sources":{"KJV":{"text":"Because ye were glad, because ye rejoiced, O ye destroyers of mine heritage, because ye are grown fat as the heifer at grass, and bellow as bulls;"},"BSB":{"text":"“Because you rejoice, because you sing in triumph— you who plunder My inheritance— because you frolic like a heifer treading grain and neigh like stallions,"},"TANAKH":{"text":"Because ye are glad, because ye rejoice, O ye that plunder My heritage, because ye gambol as a heifer at grass, and neigh as strong horses;"},"HEBREW":{"text":"כִּ֤י תשמחי תִשְׂמְחוּ֙ כִּ֣י תעלזי תַֽעֲלְז֔וּ שֹׁסֵ֖י נַחֲלָתִ֑י כִּ֤י תפושי תָפ֙וּשׁוּ֙ כְּעֶגְלָ֣ה דָשָׁ֔ה ותצהלי וְתִצְהֲל֖וּ כָּאֲבִּרִֽים׃"}},"definableWords":[],"peopleInVerse":[],"themesInVerse":["joy","land_promise"]},"12":{"text":"Your mother shall be sore confounded; she that bare you shall be ashamed: behold, the hindermost of the nations shall be a wilderness, a dry land, and a desert.","ref":"Jeremiah 50:12","synthesized":"your mother will be greatly ashamed; she who bore you will be disgraced. Behold, she will be the least of the nations, a wilderness, a dry land, and a desert.","sources":{"KJV":{"text":"Your mother shall be sore confounded; she that bare you shall be ashamed: behold, the hindermost of the nations shall be a wilderness, a dry land, and a desert."},"BSB":{"text":"your mother will be greatly ashamed; she who bore you will be disgraced. Behold, she will be the least of the nations, a wilderness, a dry land, and a desert."},"TANAKH":{"text":"Your mother shall be sore ashamed, she that bore you shall be confounded; behold, the hindermost of the nations shall be a wilderness, a dry land, and a desert."},"HEBREW":{"text":"בּ֤וֹשָׁה אִמְּכֶם֙ מְאֹ֔ד חָפְרָ֖ה יֽוֹלַדְתְּכֶ֑ם הִנֵּה֙ אַחֲרִ֣ית גּוֹיִ֔ם מִדְבָּ֖ר צִיָּ֥ה וַעֲרָבָֽה׃"}},"definableWords":["mother","nations","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"13":{"text":"Because of the wrath of the LORD it shall not be inhabited, but it shall be wholly desolate: every one that goeth by Babylon shall be astonished, and hiss at all her plagues.","ref":"Jeremiah 50:13","synthesized":"Because of the wrath of the LORD, she will not be inhabited; she will become completely desolate. All who pass through Babylon will be horrified and will hiss at all her wounds.","sources":{"KJV":{"text":"Because of the wrath of the LORD it shall not be inhabited, but it shall be wholly desolate: every one that goeth by Babylon shall be astonished, and hiss at all her plagues."},"BSB":{"text":"Because of the wrath of the LORD, she will not be inhabited; she will become completely desolate. All who pass through Babylon will be horrified and will hiss at all her wounds."},"TANAKH":{"text":"Because of the wrath of HaShem it shall not be inhabited, but it shall be wholly desolate; every one that goeth by Babylon shall be appalled and hiss at all her plagues."},"HEBREW":{"text":"מִקֶּ֤צֶף יְהוָה֙ לֹ֣א תֵשֵׁ֔ב וְהָיְתָ֥ה שְׁמָמָ֖ה כֻּלָּ֑הּ כֹּ֚ל עֹבֵ֣ר עַל־בָּבֶ֔ל יִשֹּׁ֥ם וְיִשְׁרֹ֖ק עַל־כָּל־מַכּוֹתֶֽיהָ׃"}},"definableWords":["wrath","LORD","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["judgment"]},"14":{"text":"Put yourselves in array against Babylon round about: all ye that bend the bow, shoot at her, spare no arrows: for she hath sinned against the LORD.","ref":"Jeremiah 50:14","synthesized":"Line up in formation around Babylon, all you who draw the bow! Shoot at her! Spare no arrows! For she has sinned against the LORD.","sources":{"KJV":{"text":"Put yourselves in array against Babylon round about: all ye that bend the bow, shoot at her, spare no arrows: for she hath sinned against the LORD."},"BSB":{"text":"Line up in formation around Babylon, all you who draw the bow! Shoot at her! Spare no arrows! For she has sinned against the LORD."},"TANAKH":{"text":"Set yourselves in array against Babylon round about, all ye that bend the bow, shoot at her, spare no arrows; for she hath sinned against HaShem."},"HEBREW":{"text":"עִרְכ֨וּ עַל־בָּבֶ֤ל ׀ סָבִיב֙ כָּל־דֹּ֣רְכֵי קֶ֔שֶׁת יְד֣וּ אֵלֶ֔יהָ אַֽל־תַּחְמְל֖וּ אֶל־חֵ֑ץ כִּ֥י לַֽיהוָ֖ה חָטָֽאָה׃"}},"definableWords":["Babylon","LORD"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["worship"]},"15":{"text":"Shout against her round about: she hath given her hand: her foundations are fallen, her walls are thrown down: for it is the vengeance of the LORD: take vengeance upon her; as she hath done, do unto her.","ref":"Jeremiah 50:15","synthesized":"Raise a war cry against her on every side! She has thrown up her hands in surrender; her towers have fallen; her walls are torn down.   Since this is the vengeance of the LORD, take out your vengeance upon her; as she has done, do the same to her.","sources":{"KJV":{"text":"Shout against her round about: she hath given her hand: her foundations are fallen, her walls are thrown down: for it is the vengeance of the LORD: take vengeance upon her; as she hath done, do unto her."},"BSB":{"text":"Raise a war cry against her on every side! She has thrown up her hands in surrender; her towers have fallen; her walls are torn down.   Since this is the vengeance of the LORD, take out your vengeance upon her; as she has done, do the same to her."},"TANAKH":{"text":"Shout against her round about, she hath submitted herself; her buttresses are fallen, her walls are thrown down; for it is the vengeance of HaShem, take vengeance upon her; as she hath done, do unto her."},"HEBREW":{"text":"הָרִ֨יעוּ עָלֶ֤יהָ סָבִיב֙ נָתְנָ֣ה יָדָ֔הּ נָֽפְלוּ֙ אשויתיה אָשְׁיוֹתֶ֔יהָ נֶהֶרְס֖וּ חֽוֹמוֹתֶ֑יהָ כִּי֩ נִקְמַ֨ת יְהוָ֥ה הִיא֙ הִנָּ֣קְמוּ בָ֔הּ כַּאֲשֶׁ֥ר עָשְׂתָ֖ה עֲשׂוּ־לָֽהּ׃"}},"definableWords":["LORD"],"peopleInVerse":[]},"16":{"text":"Cut off the sower from Babylon, and him that handleth the sickle in the time of harvest: for fear of the oppressing sword they shall turn every one to his people, and they shall flee every one to his own land.","ref":"Jeremiah 50:16","synthesized":"Cut off the sower from Babylon, and the one who wields the sickle at harvest time. In the face of the oppressor’s sword, each will turn to his own people, each will flee to his own land.","sources":{"KJV":{"text":"Cut off the sower from Babylon, and him that handleth the sickle in the time of harvest: for fear of the oppressing sword they shall turn every one to his people, and they shall flee every one to his own land."},"BSB":{"text":"Cut off the sower from Babylon, and the one who wields the sickle at harvest time. In the face of the oppressor’s sword, each will turn to his own people, each will flee to his own land."},"TANAKH":{"text":"Cut off the sower from Babylon, and him that handleth the sickle in the time of harvest; for fear of the oppressing sword they shall turn every one to his people, and they shall flee every one to his own land."},"HEBREW":{"text":"כִּרְת֤וּ זוֹרֵ֙עַ֙ מִבָּבֶ֔ל וְתֹפֵ֥שׂ מַגָּ֖ל בְּעֵ֣ת קָצִ֑יר מִפְּנֵי֙ חֶ֣רֶב הַיּוֹנָ֔ה אִ֤ישׁ אֶל־עַמּוֹ֙ יִפְנ֔וּ וְאִ֥ישׁ לְאַרְצ֖וֹ יָנֻֽסוּ׃"}},"definableWords":["Babylon","one","people","land"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["land_promise"]},"17":{"text":"Israel is a scattered sheep; the lions have driven him away: first the king of Assyria hath devoured him; and last this Nebuchadrezzar king of Babylon hath broken his bones.","ref":"Jeremiah 50:17","synthesized":"Israel is a scattered flock, chased away by lions. The first to devour him was the king of Assyria; the last to crush his bones was Nebuchadnezzar king of Babylon.”","sources":{"KJV":{"text":"Israel is a scattered sheep; the lions have driven him away: first the king of Assyria hath devoured him; and last this Nebuchadrezzar king of Babylon hath broken his bones."},"BSB":{"text":"Israel is a scattered flock, chased away by lions. The first to devour him was the king of Assyria; the last to crush his bones was Nebuchadnezzar king of Babylon.”"},"TANAKH":{"text":"Israel is a scattered sheep, the lions have driven him away; first the king of Assyria hath devoured him, and last this Nebuchadrezzar king of Babylon hath broken his bones."},"HEBREW":{"text":"שֶׂ֧ה פְזוּרָ֛ה יִשְׂרָאֵ֖ל אֲרָי֣וֹת הִדִּ֑יחוּ הָרִאשׁ֤וֹן אֲכָלוֹ֙ מֶ֣לֶךְ אַשּׁ֔וּר וְזֶ֤ה הָאַחֲרוֹן֙ עִצְּמ֔וֹ נְבוּכַדְרֶאצַּ֖ר מֶ֥לֶךְ בָּבֶֽל׃"}},"definableWords":["Israel","king","bones","King","Babylon"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship","shepherd_sheep"]},"18":{"text":"Therefore thus saith the LORD of hosts, the God of Israel; Behold, I will punish the king of Babylon and his land, as I have punished the king of Assyria.","ref":"Jeremiah 50:18","synthesized":"Therefore this is what the LORD of Hosts, the God of Israel, says:  “I will punish the king of Babylon and his land as I punished the king of Assyria.","sources":{"KJV":{"text":"Therefore thus saith the LORD of hosts, the God of Israel; Behold, I will punish the king of Babylon and his land, as I have punished the king of Assyria."},"BSB":{"text":"Therefore this is what the LORD of Hosts, the God of Israel, says:  “I will punish the king of Babylon and his land as I punished the king of Assyria."},"TANAKH":{"text":"Therefore thus saith HaShem of hosts, the G-d of Israel: behold, I will punish the king of Babylon and his land, as I have punished the king of Assyria."},"HEBREW":{"text":"לָכֵ֗ן כֹּֽה־אָמַ֞ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל הִנְנִ֥י פֹקֵ֛ד אֶל־מֶ֥לֶךְ בָּבֶ֖ל וְאֶל־אַרְצ֑וֹ כַּאֲשֶׁ֥ר פָּקַ֖דְתִּי אֶל־מֶ֥לֶךְ אַשּֽׁוּר׃"}},"definableWords":["LORD","God","Israel","king","Babylon","land","King"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship","land_promise"]},"19":{"text":"And I will bring Israel again to his habitation, and he shall feed on Carmel and Bashan, and his soul shall be satisfied upon mount Ephraim and Gilead.","ref":"Jeremiah 50:19","synthesized":"I will return Israel to his pasture, and he will graze on Carmel and Bashan; his soul will be satisfied on the hills of Ephraim and Gilead.","sources":{"KJV":{"text":"And I will bring Israel again to his habitation, and he shall feed on Carmel and Bashan, and his soul shall be satisfied upon mount Ephraim and Gilead."},"BSB":{"text":"I will return Israel to his pasture, and he will graze on Carmel and Bashan; his soul will be satisfied on the hills of Ephraim and Gilead."},"TANAKH":{"text":"And I will bring Israel back to his pasture, and he shall feed on Carmel and Bashan, and his soul shall be satisfied upon the hills of Ephraim and in Gilead."},"HEBREW":{"text":"וְשֹׁבַבְתִּ֤י אֶת־יִשְׂרָאֵל֙ אֶל־נָוֵ֔הוּ וְרָעָ֥ה הַכַּרְמֶ֖ל וְהַבָּשָׁ֑ן וּבְהַ֥ר אֶפְרַ֛יִם וְהַגִּלְעָ֖ד תִּשְׂבַּ֥ע נַפְשֽׁוֹ׃"}},"definableWords":["Israel","soul"],"peopleInVerse":[],"placesInVerse":["Mount Carmel"],"themesInVerse":["exile_return","second_coming"]},"20":{"text":"In those days, and in that time, saith the LORD, the iniquity of Israel shall be sought for, and there shall be none; and the sins of Judah, and they shall not be found: for I will pardon them whom I reserve.","ref":"Jeremiah 50:20","synthesized":"In those days and at that time, declares the LORD, a search will be made for Israel’s guilt, but there will be none, and for Judah’s sins, but they will not be found; for I will forgive the remnant I preserve.","sources":{"KJV":{"text":"In those days, and in that time, saith the LORD, the iniquity of Israel shall be sought for, and there shall be none; and the sins of Judah, and they shall not be found: for I will pardon them whom I reserve."},"BSB":{"text":"In those days and at that time, declares the LORD, a search will be made for Israel’s guilt, but there will be none, and for Judah’s sins, but they will not be found; for I will forgive the remnant I preserve."},"TANAKH":{"text":"In those days, and in that time, saith HaShem, the iniquity of Israel shall be sought for, and there shall be none, and the sins of Judah, and they shall not be found; for I will pardon them whom I leave as a remnant."},"HEBREW":{"text":"בַּיָּמִ֣ים הָהֵם֩ וּבָעֵ֨ת הַהִ֜יא נְאֻם־יְהוָ֗ה יְבֻקַּ֞שׁ אֶת־עֲוֺ֤ן יִשְׂרָאֵל֙ וְאֵינֶ֔נּוּ וְאֶת־חַטֹּ֥את יְהוּדָ֖ה וְלֹ֣א תִמָּצֶ֑אינָה כִּ֥י אֶסְלַ֖ח לַאֲשֶׁ֥ר אַשְׁאִֽיר׃"}},"definableWords":["days","LORD","made","Israel","Judah","forgive","remnant"],"peopleInVerse":[],"themesInVerse":["creation","exile_return"]},"21":{"text":"Go up against the land of Merathaim, even against it, and against the inhabitants of Pekod: waste and utterly destroy after them, saith the LORD, and do according to all that I have commanded thee.","ref":"Jeremiah 50:21","synthesized":"Go up against the land of Merathaim, and against the residents of Pekod. Kill them and devote them to destruction. Do all that I have commanded you,” declares the LORD.","sources":{"KJV":{"text":"Go up against the land of Merathaim, even against it, and against the inhabitants of Pekod: waste and utterly destroy after them, saith the LORD, and do according to all that I have commanded thee."},"BSB":{"text":"Go up against the land of Merathaim, and against the residents of Pekod. Kill them and devote them to destruction. Do all that I have commanded you,” declares the LORD."},"TANAKH":{"text":"Go up against the land of Merathaim, even against it, and against the inhabitants of Pekod; waste and utterly destroy after them, saith HaShem, and do according to all that I have commanded thee."},"HEBREW":{"text":"עַל־הָאָ֤רֶץ מְרָתַ֙יִם֙ עֲלֵ֣ה עָלֶ֔יהָ וְאֶל־יוֹשְׁבֵ֖י פְּק֑וֹד חֲרֹ֨ב וְהַחֲרֵ֤ם אַֽחֲרֵיהֶם֙ נְאֻם־יְהוָ֔ה וַעֲשֵׂ֕ה כְּכֹ֖ל אֲשֶׁ֥ר צִוִּיתִֽיךָ׃"}},"definableWords":["land","LORD"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"22":{"text":"A sound of battle is in the land, and of great destruction.","ref":"Jeremiah 50:22","synthesized":"“The noise of battle is in the land— the noise of great destruction.","sources":{"KJV":{"text":"A sound of battle is in the land, and of great destruction."},"BSB":{"text":"“The noise of battle is in the land— the noise of great destruction."},"TANAKH":{"text":"Hark! battle is in the land, and great destruction."},"HEBREW":{"text":"ק֥וֹל מִלְחָמָ֖ה בָּאָ֑רֶץ וְשֶׁ֖בֶר גָּדֽוֹל׃"}},"definableWords":["land","great"],"peopleInVerse":[],"themesInVerse":["land_promise","spiritual_warfare"]},"23":{"text":"How is the hammer of the whole earth cut asunder and broken! how is Babylon become a desolation among the nations!","ref":"Jeremiah 50:23","synthesized":"How the hammer of the whole earth lies broken and shattered! What a horror Babylon has become among the nations!","sources":{"KJV":{"text":"How is the hammer of the whole earth cut asunder and broken! how is Babylon become a desolation among the nations!"},"BSB":{"text":"How the hammer of the whole earth lies broken and shattered! What a horror Babylon has become among the nations!"},"TANAKH":{"text":"How is the hammer of the whole earth cut asunder and broken! How is Babylon become a desolation among the nations!"},"HEBREW":{"text":"אֵ֤יךְ נִגְדַּע֙ וַיִּשָּׁבֵ֔ר פַּטִּ֖ישׁ כָּל־הָאָ֑רֶץ אֵ֣יךְ הָיְתָ֧ה לְשַׁמָּ֛ה בָּבֶ֖ל בַּגּוֹיִֽם׃"}},"definableWords":["earth","Babylon","nations"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"24":{"text":"I have laid a snare for thee, and thou art also taken, O Babylon, and thou wast not aware: thou art found, and also caught, because thou hast striven against the LORD.","ref":"Jeremiah 50:24","synthesized":"I laid a snare for you, O Babylon, and you were caught before you knew it. You were found and captured because you challenged the LORD.","sources":{"KJV":{"text":"I have laid a snare for thee, and thou art also taken, O Babylon, and thou wast not aware: thou art found, and also caught, because thou hast striven against the LORD."},"BSB":{"text":"I laid a snare for you, O Babylon, and you were caught before you knew it. You were found and captured because you challenged the LORD."},"TANAKH":{"text":"I have laid a snare for thee, and thou art also taken, O Babylon, and thou wast not aware; thou art found, and also caught, because thou hast striven against HaShem."},"HEBREW":{"text":"יָקֹ֨שְׁתִּי לָ֤ךְ וְגַם־נִלְכַּדְתְּ֙ בָּבֶ֔ל וְאַ֖תְּ לֹ֣א יָדָ֑עַתְּ נִמְצֵאת֙ וְגַם־נִתְפַּ֔שְׂתְּ כִּ֥י בַֽיהוָ֖ה הִתְגָּרִֽית׃"}},"definableWords":["Babylon","LORD"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"25":{"text":"The LORD hath opened his armoury, and hath brought forth the weapons of his indignation: for this is the work of the Lord GOD of hosts in the land of the Chaldeans.","ref":"Jeremiah 50:25","synthesized":"The LORD has opened His armory and brought out His weapons of wrath, for this is the work of the Lord GOD of Hosts in the land of the Chaldeans.","sources":{"KJV":{"text":"The LORD hath opened his armoury, and hath brought forth the weapons of his indignation: for this is the work of the Lord GOD of hosts in the land of the Chaldeans."},"BSB":{"text":"The LORD has opened His armory and brought out His weapons of wrath, for this is the work of the Lord GOD of Hosts in the land of the Chaldeans."},"TANAKH":{"text":"HaShem hath opened His armoury, and hath brought forth the weapons of His indignation; for it is a work that the L-rd GOD of hosts hath to do in the land of the Chaldeans."},"HEBREW":{"text":"פָּתַ֤ח יְהוָה֙ אֶת־א֣וֹצָר֔וֹ וַיּוֹצֵ֖א אֶת־כְּלֵ֣י זַעְמ֑וֹ כִּי־מְלָאכָ֣ה הִ֗יא לַֽאדֹנָ֧י יְהוִ֛ה צְבָא֖וֹת בְּאֶ֥רֶץ כַּשְׂדִּֽים׃"}},"definableWords":["LORD","wrath","work","Lord","God","land"],"peopleInVerse":[],"themesInVerse":["judgment","land_promise"]},"26":{"text":"Come against her from the utmost border, open her storehouses: cast her up as heaps, and destroy her utterly: let nothing of her be left.","ref":"Jeremiah 50:26","synthesized":"Come against her from the farthest border. Break open her granaries; pile her up like mounds of grain. Devote her to destruction; leave her no survivors.","sources":{"KJV":{"text":"Come against her from the utmost border, open her storehouses: cast her up as heaps, and destroy her utterly: let nothing of her be left."},"BSB":{"text":"Come against her from the farthest border. Break open her granaries; pile her up like mounds of grain. Devote her to destruction; leave her no survivors."},"TANAKH":{"text":"Come against her from every quarter, open her granaries, cast her up as heaps, and destroy her utterly; let nothing of her be left."},"HEBREW":{"text":"בֹּֽאוּ־לָ֤הּ מִקֵּץ֙ פִּתְח֣וּ מַאֲבֻסֶ֔יהָ סָלּ֥וּהָ כְמוֹ־עֲרֵמִ֖ים וְהַחֲרִימ֑וּהָ אַל־תְּהִי־לָ֖הּ שְׁאֵרִֽית׃"}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"Slay all her bullocks; let them go down to the slaughter: woe unto them! for their day is come, the time of their visitation.","ref":"Jeremiah 50:27","synthesized":"Kill all her young bulls; let them go down to the slaughter. Woe to them, for their day has come— the time of their punishment.","sources":{"KJV":{"text":"Slay all her bullocks; let them go down to the slaughter: woe unto them! for their day is come, the time of their visitation."},"BSB":{"text":"Kill all her young bulls; let them go down to the slaughter. Woe to them, for their day has come— the time of their punishment."},"TANAKH":{"text":"Slay all her bullocks, let them go down to the slaughter; woe unto them! for their day is come, the time of their visitation."},"HEBREW":{"text":"חִרְבוּ֙ כָּל־פָּרֶ֔יהָ יֵרְד֖וּ לַטָּ֑בַח ה֣וֹי עֲלֵיהֶ֔ם כִּֽי־בָ֥א יוֹמָ֖ם עֵ֥ת פְּקֻדָּתָֽם׃"}},"definableWords":["day"],"peopleInVerse":[]},"28":{"text":"The voice of them that flee and escape out of the land of Babylon, to declare in Zion the vengeance of the LORD our God, the vengeance of his temple.","ref":"Jeremiah 50:28","synthesized":"Listen to the fugitives and refugees from the land of Babylon, declaring in Zion the vengeance of the LORD our God, the vengeance for His temple.","sources":{"KJV":{"text":"The voice of them that flee and escape out of the land of Babylon, to declare in Zion the vengeance of the LORD our God, the vengeance of his temple."},"BSB":{"text":"Listen to the fugitives and refugees from the land of Babylon, declaring in Zion the vengeance of the LORD our God, the vengeance for His temple."},"TANAKH":{"text":"Hark! they flee and escape out of the land of Babylon, to declare in Zion the vengeance of HaShem our G-d, the vengeance of His temple."},"HEBREW":{"text":"ק֥וֹל נָסִ֛ים וּפְלֵטִ֖ים מֵאֶ֣רֶץ בָּבֶ֑ל לְהַגִּ֣יד בְּצִיּ֗וֹן אֶת־נִקְמַת֙ יְהוָ֣ה אֱלֹהֵ֔ינוּ נִקְמַ֖ת הֵיכָלֽוֹ׃"}},"definableWords":["land","Babylon","Zion","LORD","God","temple"],"peopleInVerse":[],"placesInVerse":["Babylon","Mount Zion"],"themesInVerse":["land_promise","temple"]},"29":{"text":"Call together the archers against Babylon: all ye that bend the bow, camp against it round about; let none thereof escape: recompense her according to her work; according to all that she hath done, do unto her: for she hath been proud against the LORD, against the Holy One of Israel.","ref":"Jeremiah 50:29","synthesized":"Summon the archers against Babylon, all who string the bow. Encamp all around her; let no one escape. Repay her according to her deeds; do to her as she has done. For she has defied the LORD, the Holy One of Israel.","sources":{"KJV":{"text":"Call together the archers against Babylon: all ye that bend the bow, camp against it round about; let none thereof escape: recompense her according to her work; according to all that she hath done, do unto her: for she hath been proud against the LORD, against the Holy One of Israel."},"BSB":{"text":"Summon the archers against Babylon, all who string the bow. Encamp all around her; let no one escape. Repay her according to her deeds; do to her as she has done. For she has defied the LORD, the Holy One of Israel."},"TANAKH":{"text":"Call together the archers against Babylon, all them that bend the bow; encamp against her round about, let none thereof escape; recompense her according to her work, according to all that she hath done, do unto her: for she hath been arrogant against HaShem, against the Holy One of Israel."},"HEBREW":{"text":"הַשְׁמִ֣יעוּ אֶל־בָּבֶ֣ל ׀ רַ֠בִּים כָּל־דֹּ֨רְכֵי קֶ֜שֶׁת חֲנ֧וּ עָלֶ֣יהָ סָבִ֗יב אַל־יְהִי־לָהּ֙ פְּלֵטָ֔ה שַׁלְּמוּ־לָ֣הּ כְּפָעֳלָ֔הּ כְּכֹ֛ל אֲשֶׁ֥ר עָשְׂתָ֖ה עֲשׂוּ־לָ֑הּ כִּ֧י אֶל־יְהוָ֛ה זָ֖דָה אֶל־קְד֥וֹשׁ יִשְׂרָאֵֽל׃"}},"definableWords":["Babylon","one","LORD","holy","Israel"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["worship"]},"30":{"text":"Therefore shall her young men fall in the streets, and all her men of war shall be cut off in that day, saith the LORD.","ref":"Jeremiah 50:30","synthesized":"Therefore, her young men will fall in the streets, and all her warriors will be silenced in that day,” declares the LORD.","sources":{"KJV":{"text":"Therefore shall her young men fall in the streets, and all her men of war shall be cut off in that day, saith the LORD."},"BSB":{"text":"Therefore, her young men will fall in the streets, and all her warriors will be silenced in that day,” declares the LORD."},"TANAKH":{"text":"Therefore shall her young men fall in her broad places, and all her men of war shall be brought to silence in that day, saith HaShem."},"HEBREW":{"text":"לָכֵ֛ן יִפְּל֥וּ בַחוּרֶ֖יהָ בִּרְחֹבֹתֶ֑יהָ וְכָל־אַנְשֵׁ֨י מִלְחַמְתָּ֥הּ יִדַּ֛מּוּ בַּיּ֥וֹם הַה֖וּא נְאֻם־יְהוָֽה׃"}},"definableWords":["men","day","LORD"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"31":{"text":"Behold, I am against thee, O thou most proud, saith the Lord GOD of hosts: for thy day is come, the time that I will visit thee.","ref":"Jeremiah 50:31","synthesized":"“Behold, I am against you, O arrogant one,” declares the Lord GOD of Hosts, “for your day has come, the time when I will punish you.","sources":{"KJV":{"text":"Behold, I am against thee, O thou most proud, saith the Lord GOD of hosts: for thy day is come, the time that I will visit thee."},"BSB":{"text":"“Behold, I am against you, O arrogant one,” declares the Lord GOD of Hosts, “for your day has come, the time when I will punish you."},"TANAKH":{"text":"Behold, I am against thee, O thou most arrogant, saith the L-rd GOD of hosts; for thy day is come, the time that I will punish thee."},"HEBREW":{"text":"הִנְנִ֤י אֵלֶ֙יךָ֙ זָד֔וֹן נְאֻם־אֲדֹנָ֥י יְהוִ֖ה צְבָא֑וֹת כִּ֛י בָּ֥א יוֹמְךָ֖ עֵ֥ת פְּקַדְתִּֽיךָ׃"}},"definableWords":["one","Lord","God","day"],"peopleInVerse":[]},"32":{"text":"And the most proud shall stumble and fall, and none shall raise him up: and I will kindle a fire in his cities, and it shall devour all round about him.","ref":"Jeremiah 50:32","synthesized":"The arrogant one will stumble and fall with no one to pick him up. And I will kindle a fire in his cities to consume all those around him.”","sources":{"KJV":{"text":"And the most proud shall stumble and fall, and none shall raise him up: and I will kindle a fire in his cities, and it shall devour all round about him."},"BSB":{"text":"The arrogant one will stumble and fall with no one to pick him up. And I will kindle a fire in his cities to consume all those around him.”"},"TANAKH":{"text":"And the most arrogant shall stumble and fall, and none shall raise him up; and I will kindle a fire in his cities, and it shall devour all that are round about him."},"HEBREW":{"text":"וְכָשַׁ֤ל זָדוֹן֙ וְנָפַ֔ל וְאֵ֥ין ל֖וֹ מֵקִ֑ים וְהִצַּ֤תִּי אֵשׁ֙ בְּעָרָ֔יו וְאָכְלָ֖ה כָּל־סְבִיבֹתָֽיו׃"}},"definableWords":["one"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"33":{"text":"Thus saith the LORD of hosts; The children of Israel and the children of Judah were oppressed together: and all that took them captives held them fast; they refused to let them go.","ref":"Jeremiah 50:33","synthesized":"This is what the LORD of Hosts says:  “The sons of Israel are oppressed, and the sons of Judah as well. All their captors hold them fast, refusing to release them.","sources":{"KJV":{"text":"Thus saith the LORD of hosts; The children of Israel and the children of Judah were oppressed together: and all that took them captives held them fast; they refused to let them go."},"BSB":{"text":"This is what the LORD of Hosts says:  “The sons of Israel are oppressed, and the sons of Judah as well. All their captors hold them fast, refusing to release them."},"TANAKH":{"text":"Thus saith HaShem of hosts: The children of Israel and the children of Judah are oppressed together; and all that took them captives hold them fast; they refuse to let them go."},"HEBREW":{"text":"כֹּ֤ה אָמַר֙ יְהוָ֣ה צְבָא֔וֹת עֲשׁוּקִ֛ים בְּנֵי־יִשְׂרָאֵ֥ל וּבְנֵי־יְהוּדָ֖ה יַחְדָּ֑ו וְכָל־שֹֽׁבֵיהֶם֙ הֶחֱזִ֣יקוּ בָ֔ם מֵאֲנ֖וּ שַׁלְּחָֽם׃"}},"definableWords":["LORD","sons","Israel","Judah","fast"],"peopleInVerse":[],"themesInVerse":["bread_water_life"]},"34":{"text":"Their Redeemer is strong; the LORD of hosts is his name: he shall throughly plead their cause, that he may give rest to the land, and disquiet the inhabitants of Babylon.","ref":"Jeremiah 50:34","synthesized":"Their Redeemer is strong; the LORD of Hosts is His name. He will fervently plead their case so that He may bring rest to the earth, but turmoil to those who live in Babylon.","sources":{"KJV":{"text":"Their Redeemer is strong; the LORD of hosts is his name: he shall throughly plead their cause, that he may give rest to the land, and disquiet the inhabitants of Babylon."},"BSB":{"text":"Their Redeemer is strong; the LORD of Hosts is His name. He will fervently plead their case so that He may bring rest to the earth, but turmoil to those who live in Babylon."},"TANAKH":{"text":"Their Redeemer is strong, HaShem of hosts is His name; He will thoroughly plead their cause, that He may give rest to the earth, and disquiet the inhabitants of Babylon."},"HEBREW":{"text":"גֹּאֲלָ֣ם ׀ חָזָ֗ק יְהוָ֤ה צְבָאוֹת֙ שְׁמ֔וֹ רִ֥יב יָרִ֖יב אֶת־רִיבָ֑ם לְמַ֙עַן֙ הִרְגִּ֣יעַ אֶת־הָאָ֔רֶץ וְהִרְגִּ֖יז לְיֹשְׁבֵ֥י בָבֶֽל׃"}},"definableWords":["Redeemer","strong","LORD","name","rest","earth","live","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["peace","sabbath_rest"]},"35":{"text":"A sword is upon the Chaldeans, saith the LORD, and upon the inhabitants of Babylon, and upon her princes, and upon her wise men.","ref":"Jeremiah 50:35","synthesized":"A sword is against the Chaldeans, declares the LORD, against those who live in Babylon, and against her officials and wise men.","sources":{"KJV":{"text":"A sword is upon the Chaldeans, saith the LORD, and upon the inhabitants of Babylon, and upon her princes, and upon her wise men."},"BSB":{"text":"A sword is against the Chaldeans, declares the LORD, against those who live in Babylon, and against her officials and wise men."},"TANAKH":{"text":"A sword is upon the Chaldeans, saith HaShem, and upon the inhabitants of Babylon, and upon her princes, and upon her wise men."},"HEBREW":{"text":"חֶ֥רֶב עַל־כַּשְׂדִּ֖ים נְאֻם־יְהוָ֑ה וְאֶל־יֹשְׁבֵ֣י בָבֶ֔ל וְאֶל־שָׂרֶ֖יהָ וְאֶל־חֲכָמֶֽיהָ׃"}},"definableWords":["LORD","live","Babylon","men"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["wisdom"]},"36":{"text":"A sword is upon the liars; and they shall dote: a sword is upon her mighty men; and they shall be dismayed.","ref":"Jeremiah 50:36","synthesized":"A sword is against her false prophets, and they will become fools. A sword is against her warriors, and they will be filled with terror.","sources":{"KJV":{"text":"A sword is upon the liars; and they shall dote: a sword is upon her mighty men; and they shall be dismayed."},"BSB":{"text":"A sword is against her false prophets, and they will become fools. A sword is against her warriors, and they will be filled with terror."},"TANAKH":{"text":"A sword is upon the boasters, and they shall become fools; a sword is upon her mighty men, and they shall be dismayed."},"HEBREW":{"text":"חֶ֥רֶב אֶל־הַבַּדִּ֖ים וְנֹאָ֑לוּ חֶ֥רֶב אֶל־גִּבּוֹרֶ֖יהָ וָחָֽתּוּ׃"}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"A sword is upon their horses, and upon their chariots, and upon all the mingled people that are in the midst of her; and they shall become as women: a sword is upon her treasures; and they shall be robbed.","ref":"Jeremiah 50:37","synthesized":"A sword is against her horses and chariots and against all the foreigners in her midst, and they will become like women. A sword is against her treasuries, and they will be plundered.","sources":{"KJV":{"text":"A sword is upon their horses, and upon their chariots, and upon all the mingled people that are in the midst of her; and they shall become as women: a sword is upon her treasures; and they shall be robbed."},"BSB":{"text":"A sword is against her horses and chariots and against all the foreigners in her midst, and they will become like women. A sword is against her treasuries, and they will be plundered."},"TANAKH":{"text":"A sword is upon their horses, and upon their chariots, and upon all the mingled people that are in the midst of her, and they shall become as women; a sword is upon her treasures, and they shall be robbed."},"HEBREW":{"text":"חֶ֜רֶב אֶל־סוּסָ֣יו וְאֶל־רִכְבּ֗וֹ וְאֶל־כָּל־הָעֶ֛רֶב אֲשֶׁ֥ר בְּתוֹכָ֖הּ וְהָי֣וּ לְנָשִׁ֑ים חֶ֥רֶב אֶל־אוֹצְרֹתֶ֖יהָ וּבֻזָּֽזוּ׃"}},"definableWords":["women"],"peopleInVerse":[]},"38":{"text":"A drought is upon her waters; and they shall be dried up: for it is the land of graven images, and they are mad upon their idols.","ref":"Jeremiah 50:38","synthesized":"A drought is upon her waters, and they will be dried up. For it is a land of graven images, and the people go mad over idols.","sources":{"KJV":{"text":"A drought is upon her waters; and they shall be dried up: for it is the land of graven images, and they are mad upon their idols."},"BSB":{"text":"A drought is upon her waters, and they will be dried up. For it is a land of graven images, and the people go mad over idols."},"TANAKH":{"text":"A drought is upon her waters, and they shall be dried up; for it is a land of graven images, and they are mad upon things of horror."},"HEBREW":{"text":"חֹ֥רֶב אֶל־מֵימֶ֖יהָ וְיָבֵ֑שׁוּ כִּ֣י אֶ֤רֶץ פְּסִלִים֙ הִ֔יא וּבָאֵימִ֖ים יִתְהֹלָֽלוּ׃"}},"definableWords":["waters","land","people"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"39":{"text":"Therefore the wild beasts of the desert with the wild beasts of the islands shall dwell there, and the owls shall dwell therein: and it shall be no more inhabited for ever; neither shall it be dwelt in from generation to generation.","ref":"Jeremiah 50:39","synthesized":"So the desert creatures and hyenas will live there and ostriches will dwell there. It will never again be inhabited or lived in from generation to generation.","sources":{"KJV":{"text":"Therefore the wild beasts of the desert with the wild beasts of the islands shall dwell there, and the owls shall dwell therein: and it shall be no more inhabited for ever; neither shall it be dwelt in from generation to generation."},"BSB":{"text":"So the desert creatures and hyenas will live there and ostriches will dwell there. It will never again be inhabited or lived in from generation to generation."},"TANAKH":{"text":"Therefore the wild-cats with the jackals shall dwell there, and the ostriches shall dwell therein; and it shall be no more inhabited for ever, neither shall it be dwelt in from generation to generation."},"HEBREW":{"text":"לָכֵ֗ן יֵשְׁב֤וּ צִיִּים֙ אֶת־אִיִּ֔ים וְיָ֥שְׁבוּ בָ֖הּ בְּנ֣וֹת יַֽעֲנָ֑ה וְלֹֽא־תֵשֵׁ֥ב עוֹד֙ לָנֶ֔צַח וְלֹ֥א תִשְׁכּ֖וֹן עַד־דּ֥וֹר וָדֽוֹר׃"}},"definableWords":["live","or"],"peopleInVerse":[]},"40":{"text":"As God overthrew Sodom and Gomorrah and the neighbour cities thereof, saith the LORD; so shall no man abide there, neither shall any son of man dwell therein.","ref":"Jeremiah 50:40","synthesized":"As God overthrew Sodom and Gomorrah along with their neighbors,” declares the LORD, “no one will dwell there; no man will abide there.","sources":{"KJV":{"text":"As God overthrew Sodom and Gomorrah and the neighbour cities thereof, saith the LORD; so shall no man abide there, neither shall any son of man dwell therein."},"BSB":{"text":"As God overthrew Sodom and Gomorrah along with their neighbors,” declares the LORD, “no one will dwell there; no man will abide there."},"TANAKH":{"text":"As when G-d overthrew Sodom and Gomorrah and the neighbour cities thereof, saith HaShem; so shall no man abide there, neither shall any son of man dwell therein."},"HEBREW":{"text":"כְּמַהְפֵּכַ֨ת אֱלֹהִ֜ים אֶת־סְדֹ֧ם וְאֶת־עֲמֹרָ֛ה וְאֶת־שְׁכֵנֶ֖יהָ נְאֻם־יְהוָ֑ה לֹֽא־יֵשֵׁ֥ב שָׁם֙ אִ֔ישׁ וְלֹֽא־יָג֥וּר בָּ֖הּ בֶּן־אָדָֽם׃"}},"definableWords":["God","Sodom","Gomorrah","LORD","one","man","abide"],"peopleInVerse":[],"placesInVerse":["Sodom","Gomorrah"]},"41":{"text":"Behold, a people shall come from the north, and a great nation, and many kings shall be raised up from the coasts of the earth.","ref":"Jeremiah 50:41","synthesized":"Behold, an army is coming from the north; a great nation and many kings are stirred up from the ends of the earth.","sources":{"KJV":{"text":"Behold, a people shall come from the north, and a great nation, and many kings shall be raised up from the coasts of the earth."},"BSB":{"text":"Behold, an army is coming from the north; a great nation and many kings are stirred up from the ends of the earth."},"TANAKH":{"text":"Behold, a people cometh from the north, and a great nation, and many kings shall be roused from the uttermost parts of the earth."},"HEBREW":{"text":"הִנֵּ֛ה עַ֥ם בָּ֖א מִצָּפ֑וֹן וְג֤וֹי גָּדוֹל֙ וּמְלָכִ֣ים רַבִּ֔ים יֵעֹ֖רוּ מִיַּרְכְּתֵי־אָֽרֶץ׃"}},"definableWords":["great","nation","kings","earth"],"peopleInVerse":[],"themesInVerse":["second_coming"]},"42":{"text":"They shall hold the bow and the lance: they are cruel, and will not shew mercy: their voice shall roar like the sea, and they shall ride upon horses, every one put in array, like a man to the battle, against thee, O daughter of Babylon.","ref":"Jeremiah 50:42","synthesized":"They grasp the bow and spear; they are cruel and merciless. Their voice roars like the sea, and they ride upon horses, lined up like men in formation against you, O Daughter of Babylon.","sources":{"KJV":{"text":"They shall hold the bow and the lance: they are cruel, and will not shew mercy: their voice shall roar like the sea, and they shall ride upon horses, every one put in array, like a man to the battle, against thee, O daughter of Babylon."},"BSB":{"text":"They grasp the bow and spear; they are cruel and merciless. Their voice roars like the sea, and they ride upon horses, lined up like men in formation against you, O Daughter of Babylon."},"TANAKH":{"text":"They lay hold on bow and spear, they are cruel, and have no compassion; their voice is like the roaring sea, and they ride upon horses; set in array, as a man for war, against thee, O daughter of Babylon."},"HEBREW":{"text":"קֶ֣שֶׁת וְכִידֹ֞ן יַחֲזִ֗יקוּ אַכְזָרִ֥י הֵ֙מָּה֙ וְלֹ֣א יְרַחֵ֔מוּ קוֹלָם֙ כַּיָּ֣ם יֶהֱמֶ֔ה וְעַל־סוּסִ֖ים יִרְכָּ֑בוּ עָר֗וּךְ כְּאִישׁ֙ לַמִּלְחָמָ֔ה עָלַ֖יִךְ בַּת־בָּבֶֽל׃"}},"definableWords":["voice","sea","men","daughter","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["worship"]},"43":{"text":"The king of Babylon hath heard the report of them, and his hands waxed feeble: anguish took hold of him, and pangs as of a woman in travail.","ref":"Jeremiah 50:43","synthesized":"The king of Babylon has heard the report, and his hands hang limp. Anguish has gripped him, pain like that of a woman in labor.","sources":{"KJV":{"text":"The king of Babylon hath heard the report of them, and his hands waxed feeble: anguish took hold of him, and pangs as of a woman in travail."},"BSB":{"text":"The king of Babylon has heard the report, and his hands hang limp. Anguish has gripped him, pain like that of a woman in labor."},"TANAKH":{"text":"The king of Babylon hath heard the fame of them, and his hands wax feeble; anguish hath taken hold of him, and pain, as of a woman in travail."},"HEBREW":{"text":"שָׁמַ֧ע מֶֽלֶךְ־בָּבֶ֛ל אֶת־שִׁמְעָ֖ם וְרָפ֣וּ יָדָ֑יו צָרָה֙ הֶחֱזִיקַ֔תְהוּ חִ֖יל כַּיּוֹלֵדָֽה׃"}},"definableWords":["king","Babylon","woman"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship","suffering"]},"44":{"text":"Behold, he shall come up like a lion from the swelling of Jordan unto the habitation of the strong: but I will make them suddenly run away from her: and who is a chosen man, that I may appoint over her? for who is like me? and who will appoint me the time? and who is that shepherd that will stand before me?","ref":"Jeremiah 50:44","synthesized":"Behold, one will come up like a lion from the thickets of the Jordan to the watered pasture. For in an instant I will chase Babylon from her land. Who is the chosen one I will appoint for this? For who is like Me, and who can challenge Me? What shepherd can stand against Me?”","sources":{"KJV":{"text":"Behold, he shall come up like a lion from the swelling of Jordan unto the habitation of the strong: but I will make them suddenly run away from her: and who is a chosen man, that I may appoint over her? for who is like me? and who will appoint me the time? and who is that shepherd that will stand before me?"},"BSB":{"text":"Behold, one will come up like a lion from the thickets of the Jordan to the watered pasture. For in an instant I will chase Babylon from her land. Who is the chosen one I will appoint for this? For who is like Me, and who can challenge Me? What shepherd can stand against Me?”"},"TANAKH":{"text":"Behold, he shall come up like a lion from the thickets of the Jordan against the strong habitation; for I will suddenly make them run away from it, and whoso is chosen, him will I appoint over it; for who is like Me? and who will appoint Me a time? and who is that shepherd that will stand before Me?"},"HEBREW":{"text":"הִ֠נֵּה כְּאַרְיֵ֞ה יַעֲלֶ֨ה מִגְּא֣וֹן הַיַּרְדֵּן֮ אֶל־נְוֵ֣ה אֵיתָן֒ כִּֽי־אַרְגִּ֤עָה ארוצם אֲרִיצֵם֙ מֵֽעָלֶ֔יהָ וּמִ֥י בָח֖וּר אֵלֶ֣יהָ אֶפְקֹ֑ד כִּ֣י מִ֤י כָמ֙וֹנִי֙ וּמִ֣י יוֹעִדֶ֔נִּי וּמִֽי־זֶ֣ה רֹעֶ֔ה אֲשֶׁ֥ר יַעֲמֹ֖ד לְפָנָֽי׃"}},"definableWords":["one","lion","Babylon","land","shepherd","stand"],"peopleInVerse":[],"placesInVerse":["Jordan River","Babylon"],"themesInVerse":["land_promise","shepherd_sheep"]},"45":{"text":"Therefore hear ye the counsel of the LORD, that he hath taken against Babylon; and his purposes, that he hath purposed against the land of the Chaldeans: Surely the least of the flock shall draw them out: surely he shall make their habitation desolate with them.","ref":"Jeremiah 50:45","synthesized":"Therefore hear the plans that the LORD has drawn up against Babylon and the strategies He has devised against the land of the Chaldeans: Surely the little ones of the flock will be dragged away; certainly their pasture will be made desolate because of them.","sources":{"KJV":{"text":"Therefore hear ye the counsel of the LORD, that he hath taken against Babylon; and his purposes, that he hath purposed against the land of the Chaldeans: Surely the least of the flock shall draw them out: surely he shall make their habitation desolate with them."},"BSB":{"text":"Therefore hear the plans that the LORD has drawn up against Babylon and the strategies He has devised against the land of the Chaldeans: Surely the little ones of the flock will be dragged away; certainly their pasture will be made desolate because of them."},"TANAKH":{"text":"Therefore hear ye the counsel of HaShem, that He hath taken against Babylon, and His purposes, that He hath purposed against the land of the Chaldeans: surely the least of the flock shall drag them away, surely their habitation shall be appalled at them."},"HEBREW":{"text":"לָכֵ֞ן שִׁמְע֣וּ עֲצַת־יְהוָ֗ה אֲשֶׁ֤ר יָעַץ֙ אֶל־בָּבֶ֔ל וּמַ֨חְשְׁבוֹתָ֔יו אֲשֶׁ֥ר חָשַׁ֖ב אֶל־אֶ֣רֶץ כַּשְׂדִּ֑ים אִם־לֹ֤א יִסְחָבוּם֙ צְעִירֵ֣י הַצֹּ֔אן אִם־לֹ֥א יַשִּׁ֛ים עֲלֵיהֶ֖ם נָוֶֽה׃"}},"definableWords":["hear","LORD","Babylon","land","made"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["creation","land_promise","shepherd_sheep"]},"46":{"text":"At the noise of the taking of Babylon the earth is moved, and the cry is heard among the nations.","ref":"Jeremiah 50:46","synthesized":"At the sound of Babylon’s capture the earth will quake; a cry will be heard among the nations.","sources":{"KJV":{"text":"At the noise of the taking of Babylon the earth is moved, and the cry is heard among the nations."},"BSB":{"text":"At the sound of Babylon’s capture the earth will quake; a cry will be heard among the nations."},"TANAKH":{"text":"At the noise of the taking of Babylon the earth quaketh, and the cry is heard among the nations."},"HEBREW":{"text":"מִקּוֹל֙ נִתְפְּשָׂ֣ה בָבֶ֔ל נִרְעֲשָׁ֖ה הָאָ֑רֶץ וּזְעָקָ֖ה בַּגּוֹיִ֥ם נִשְׁמָֽע׃"}},"definableWords":["Babylon","earth","nations"],"peopleInVerse":[],"placesInVerse":["Babylon"]}}},"51":{"chapter":"51","title":"BABYLON'S DOOM","verses":{"1":{"text":"Thus saith the LORD; Behold, I will raise up against Babylon, and against them that dwell in the midst of them that rise up against me, a destroying wind;","ref":"Jeremiah 51:1","synthesized":"This is what the LORD says:  “Behold, I will stir up against Babylon and against the people of Leb-kamai the spirit of a destroyer.","sources":{"KJV":{"text":"Thus saith the LORD; Behold, I will raise up against Babylon, and against them that dwell in the midst of them that rise up against me, a destroying wind;"},"BSB":{"text":"This is what the LORD says:  “Behold, I will stir up against Babylon and against the people of Leb-kamai the spirit of a destroyer."},"TANAKH":{"text":"Thus saith HaShem: Behold, I will raise up against Babylon, and against them that dwell in Leb-kamai, a destroying wind."},"HEBREW":{"text":"כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִנְנִי֙ מֵעִ֣יר עַל־בָּבֶ֔ל וְאֶל־יֹשְׁבֵ֖י לֵ֣ב קָמָ֑י ר֖וּחַ מַשְׁחִֽית׃"}},"definableWords":["LORD","Babylon","people","spirit"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["angels_demons","holy_spirit"]},"2":{"text":"And will send unto Babylon fanners, that shall fan her, and shall empty her land: for in the day of trouble they shall be against her round about.","ref":"Jeremiah 51:2","synthesized":"I will send strangers to Babylon to winnow her and empty her land; for they will come against her from every side in her day of disaster.","sources":{"KJV":{"text":"And will send unto Babylon fanners, that shall fan her, and shall empty her land: for in the day of trouble they shall be against her round about."},"BSB":{"text":"I will send strangers to Babylon to winnow her and empty her land; for they will come against her from every side in her day of disaster."},"TANAKH":{"text":"And I will send unto Babylon strangers, that shall fan her, and they shall empty her land; for in the day of trouble they shall be against her round about."},"HEBREW":{"text":"וְשִׁלַּחְתִּ֨י לְבָבֶ֤ל ׀ זָרִים֙ וְזֵר֔וּהָ וִיבֹקְק֖וּ אֶת־אַרְצָ֑הּ כִּֽי־הָי֥וּ עָלֶ֛יהָ מִסָּבִ֖יב בְּי֥וֹם רָעָֽה׃"}},"definableWords":["Babylon","land","day"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["land_promise"]},"3":{"text":"Against him that bendeth let the archer bend his bow, and against him that lifteth himself up in his brigandine: and spare ye not her young men; destroy ye utterly all her host.","ref":"Jeremiah 51:3","synthesized":"Do not let the archer bend his bow or put on his armor. Do not spare her young men; devote all her army to destruction!","sources":{"KJV":{"text":"Against him that bendeth let the archer bend his bow, and against him that lifteth himself up in his brigandine: and spare ye not her young men; destroy ye utterly all her host."},"BSB":{"text":"Do not let the archer bend his bow or put on his armor. Do not spare her young men; devote all her army to destruction!"},"TANAKH":{"text":"Let the archer bend his bow against her, and let him lift himself up against her in his coat of mail; and spare ye not her young men, destroy ye utterly all her host."},"HEBREW":{"text":"אֶֽל־יִדְרֹ֤ךְ ידרך הַדֹּרֵךְ֙ קַשְׁתּ֔וֹ וְאֶל־יִתְעַ֖ל בְּסִרְיֹנ֑וֹ וְאַֽל־תַּחְמְלוּ֙ אֶל־בַּ֣חֻרֶ֔יהָ הַחֲרִ֖ימוּ כָּל־צְבָאָֽהּ׃"}},"definableWords":["or","men"],"peopleInVerse":[],"themesInVerse":["spiritual_warfare","worship"]},"4":{"text":"Thus the slain shall fall in the land of the Chaldeans, and they that are thrust through in her streets.","ref":"Jeremiah 51:4","synthesized":"And they will fall slain in the land of the Chaldeans, and pierced through in her streets.","sources":{"KJV":{"text":"Thus the slain shall fall in the land of the Chaldeans, and they that are thrust through in her streets."},"BSB":{"text":"And they will fall slain in the land of the Chaldeans, and pierced through in her streets."},"TANAKH":{"text":"And they shall fall down slain in the land of the Chaldeans, and thrust through in her streets."},"HEBREW":{"text":"וְנָפְל֥וּ חֲלָלִ֖ים בְּאֶ֣רֶץ כַּשְׂדִּ֑ים וּמְדֻקָּרִ֖ים בְּחוּצוֹתֶֽיהָ׃"}},"definableWords":["land"],"peopleInVerse":[],"themesInVerse":["fall_sin","land_promise"]},"5":{"text":"For Israel hath not been forsaken, nor Judah of his God, of the LORD of hosts; though their land was filled with sin against the Holy One of Israel.","ref":"Jeremiah 51:5","synthesized":"For Israel and Judah have not been abandoned by their God, the LORD of Hosts, though their land is full of guilt before the Holy One of Israel.”","sources":{"KJV":{"text":"For Israel hath not been forsaken, nor Judah of his God, of the LORD of hosts; though their land was filled with sin against the Holy One of Israel."},"BSB":{"text":"For Israel and Judah have not been abandoned by their God, the LORD of Hosts, though their land is full of guilt before the Holy One of Israel.”"},"TANAKH":{"text":"For Israel is not widowed, nor Judah, of his G-d, of HaShem of hosts; for their land is full of guilt against the Holy One of Israel."},"HEBREW":{"text":"כִּ֠י לֹֽא־אַלְמָ֨ן יִשְׂרָאֵ֤ל וִֽיהוּדָה֙ מֵֽאֱלֹהָ֔יו מֵֽיְהוָ֖ה צְבָא֑וֹת כִּ֤י אַרְצָם֙ מָלְאָ֣ה אָשָׁ֔ם מִקְּד֖וֹשׁ יִשְׂרָאֵֽל׃"}},"definableWords":["Israel","Judah","God","LORD","land","holy","one"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"6":{"text":"Flee out of the midst of Babylon, and deliver every man his soul: be not cut off in her iniquity; for this is the time of the LORD’s vengeance; he will render unto her a recompence.","ref":"Jeremiah 51:6","synthesized":"Flee from Babylon! Escape with your lives! Do not be destroyed in her punishment. For this is the time of the LORD’s vengeance; He will pay her what she deserves.","sources":{"KJV":{"text":"Flee out of the midst of Babylon, and deliver every man his soul: be not cut off in her iniquity; for this is the time of the LORD’s vengeance; he will render unto her a recompence."},"BSB":{"text":"Flee from Babylon! Escape with your lives! Do not be destroyed in her punishment. For this is the time of the LORD’s vengeance; He will pay her what she deserves."},"TANAKH":{"text":"Flee out of the midst of Babylon, and save every man his life, be not cut off in her iniquity; for it is the time of HaShem'S vengeance; He will render unto her a recompense."},"HEBREW":{"text":"נֻ֣סוּ ׀ מִתּ֣וֹךְ בָּבֶ֗ל וּמַלְּטוּ֙ אִ֣ישׁ נַפְשׁ֔וֹ אַל־תִּדַּ֖מּוּ בַּעֲוֺנָ֑הּ כִּי֩ עֵ֨ת נְקָמָ֥ה הִיא֙ לַֽיהוָ֔ה גְּמ֕וּל ה֥וּא מְשַׁלֵּ֖ם לָֽהּ׃"}},"definableWords":["Babylon","LORD"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"7":{"text":"Babylon hath been a golden cup in the LORD’s hand, that made all the earth drunken: the nations have drunken of her wine; therefore the nations are mad.","ref":"Jeremiah 51:7","synthesized":"Babylon was a gold cup in the hand of the LORD, making the whole earth drunk. The nations drank her wine; therefore the nations have gone mad.","sources":{"KJV":{"text":"Babylon hath been a golden cup in the LORD’s hand, that made all the earth drunken: the nations have drunken of her wine; therefore the nations are mad."},"BSB":{"text":"Babylon was a gold cup in the hand of the LORD, making the whole earth drunk. The nations drank her wine; therefore the nations have gone mad."},"TANAKH":{"text":"Babylon hath been a golden cup in HaShem'S hand, that made all the earth drunken; the nations have drunk of her wine, therefore the nations are mad."},"HEBREW":{"text":"כּוֹס־זָהָ֤ב בָּבֶל֙ בְּיַד־יְהוָ֔ה מְשַׁכֶּ֖רֶת כָּל־הָאָ֑רֶץ מִיֵּינָהּ֙ שָׁת֣וּ גוֹיִ֔ם עַל־כֵּ֖ן יִתְהֹלְל֥וּ גוֹיִֽם׃"}},"definableWords":["Babylon","LORD","earth","nations"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"8":{"text":"Babylon is suddenly fallen and destroyed: howl for her; take balm for her pain, if so be she may be healed.","ref":"Jeremiah 51:8","synthesized":"Suddenly Babylon has fallen and been shattered. Wail for her; get her balm for her pain; perhaps she can be healed.","sources":{"KJV":{"text":"Babylon is suddenly fallen and destroyed: howl for her; take balm for her pain, if so be she may be healed."},"BSB":{"text":"Suddenly Babylon has fallen and been shattered. Wail for her; get her balm for her pain; perhaps she can be healed."},"TANAKH":{"text":"Babylon is suddenly fallen and destroyed, wail for her; take balm for her pain, if so be she may be healed."},"HEBREW":{"text":"פִּתְאֹ֛ם נָפְלָ֥ה בָבֶ֖ל וַתִּשָּׁבֵ֑ר הֵילִ֣ילוּ עָלֶ֗יהָ קְח֤וּ צֳרִי֙ לְמַכְאוֹבָ֔הּ אוּלַ֖י תֵּרָפֵֽא׃"}},"definableWords":["Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["suffering"]},"9":{"text":"We would have healed Babylon, but she is not healed: forsake her, and let us go every one into his own country: for her judgment reacheth unto heaven, and is lifted up even to the skies.","ref":"Jeremiah 51:9","synthesized":"“We tried to heal Babylon, but she could not be healed. Abandon her! Let each of us go to his own land, for her judgment extends to the sky and reaches to the clouds.”","sources":{"KJV":{"text":"We would have healed Babylon, but she is not healed: forsake her, and let us go every one into his own country: for her judgment reacheth unto heaven, and is lifted up even to the skies."},"BSB":{"text":"“We tried to heal Babylon, but she could not be healed. Abandon her! Let each of us go to his own land, for her judgment extends to the sky and reaches to the clouds.”"},"TANAKH":{"text":"We would have healed Babylon, but she is not healed; forsake her, and let us go every one into his own country; for her judgment reacheth unto heaven, and is lifted up even to the skies."},"HEBREW":{"text":"רפאנו רִפִּ֣ינוּ אֶת־בָּבֶל֙ וְלֹ֣א נִרְפָּ֔תָה עִזְב֕וּהָ וְנֵלֵ֖ךְ אִ֣ישׁ לְאַרְצ֑וֹ כִּֽי־נָגַ֤ע אֶל־הַשָּׁמַ֙יִם֙ מִשְׁפָּטָ֔הּ וְנִשָּׂ֖א עַד־שְׁחָקִֽים׃"}},"definableWords":["heal","Babylon","land","judgment"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["judgment","land_promise"]},"10":{"text":"The LORD hath brought forth our righteousness: come, and let us declare in Zion the work of the LORD our God.","ref":"Jeremiah 51:10","synthesized":"“The LORD has brought forth our vindication; come, let us tell in Zion what the LORD our God has accomplished.”","sources":{"KJV":{"text":"The LORD hath brought forth our righteousness: come, and let us declare in Zion the work of the LORD our God."},"BSB":{"text":"“The LORD has brought forth our vindication; come, let us tell in Zion what the LORD our God has accomplished.”"},"TANAKH":{"text":"HaShem hath brought forth our victory; come, and let us declare in Zion the work of HaShem our G-d."},"HEBREW":{"text":"הוֹצִ֥יא יְהוָ֖ה אֶת־צִדְקֹתֵ֑ינוּ בֹּ֚אוּ וּנְסַפְּרָ֣ה בְצִיּ֔וֹן אֶֽת־מַעֲשֵׂ֖ה יְהוָ֥ה אֱלֹהֵֽינוּ׃"}},"definableWords":["LORD","Zion","Lord","God"],"peopleInVerse":[],"placesInVerse":["Mount Zion"]},"11":{"text":"Make bright the arrows; gather the shields: the LORD hath raised up the spirit of the kings of the Medes: for his device is against Babylon, to destroy it; because it is the vengeance of the LORD, the vengeance of his temple.","ref":"Jeremiah 51:11","synthesized":"Sharpen the arrows! Fill the quivers! The LORD has aroused the spirit of the kings of the Medes, because His plan is aimed at Babylon to destroy her, for it is the vengeance of the LORD— vengeance for His temple.","sources":{"KJV":{"text":"Make bright the arrows; gather the shields: the LORD hath raised up the spirit of the kings of the Medes: for his device is against Babylon, to destroy it; because it is the vengeance of the LORD, the vengeance of his temple."},"BSB":{"text":"Sharpen the arrows! Fill the quivers! The LORD has aroused the spirit of the kings of the Medes, because His plan is aimed at Babylon to destroy her, for it is the vengeance of the LORD— vengeance for His temple."},"TANAKH":{"text":"Make bright the arrows, fill the quivers, HaShem hath roused the spirit of the kings of the Medes; because His device is against Babylon, to destroy it; for it is the vengeance of HaShem, the vengeance of His temple."},"HEBREW":{"text":"הָבֵ֣רוּ הַחִצִּים֮ מִלְא֣וּ הַשְּׁלָטִים֒ הֵעִ֣יר יְהוָ֗ה אֶת־ר֙וּחַ֙ מַלְכֵ֣י מָדַ֔י כִּֽי־עַל־בָּבֶ֥ל מְזִמָּת֖וֹ לְהַשְׁחִיתָ֑הּ כִּֽי־נִקְמַ֤ת יְהוָה֙ הִ֔יא נִקְמַ֖ת הֵיכָלֽוֹ׃"}},"definableWords":["fill","LORD","spirit","kings","Babylon","Lord","temple"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["angels_demons","holy_spirit","temple"]},"12":{"text":"Set up the standard upon the walls of Babylon, make the watch strong, set up the watchmen, prepare the ambushes: for the LORD hath both devised and done that which he spake against the inhabitants of Babylon.","ref":"Jeremiah 51:12","synthesized":"Raise a banner against the walls of Babylon; post the guard; station the watchmen; prepare the ambush. For the LORD has both devised and accomplished what He spoke against the people of Babylon.","sources":{"KJV":{"text":"Set up the standard upon the walls of Babylon, make the watch strong, set up the watchmen, prepare the ambushes: for the LORD hath both devised and done that which he spake against the inhabitants of Babylon."},"BSB":{"text":"Raise a banner against the walls of Babylon; post the guard; station the watchmen; prepare the ambush. For the LORD has both devised and accomplished what He spoke against the people of Babylon."},"TANAKH":{"text":"Set up a standard against the walls of Babylon, make the watch strong, set the watchmen, prepare the ambushes; for HaShem hath both devised and done that which He spoke concerning the inhabitants of Babylon."},"HEBREW":{"text":"אֶל־חוֹמֹ֨ת בָּבֶ֜ל שְׂאוּ־נֵ֗ס הַחֲזִ֙יקוּ֙ הַמִּשְׁמָ֔ר הָקִ֙ימוּ֙ שֹֽׁמְרִ֔ים הָכִ֖ינוּ הָאֹֽרְבִ֑ים כִּ֚י גַּם־זָמַ֣ם יְהוָ֔ה גַּם־עָשָׂ֕ה אֵ֥ת אֲשֶׁר־דִּבֶּ֖ר אֶל־יֹשְׁבֵ֥י בָבֶֽל׃"}},"definableWords":["Babylon","LORD","people"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"13":{"text":"O thou that dwellest upon many waters, abundant in treasures, thine end is come, and the measure of thy covetousness.","ref":"Jeremiah 51:13","synthesized":"You who dwell by many waters, rich in treasures, your end has come; the thread of your life is cut.","sources":{"KJV":{"text":"O thou that dwellest upon many waters, abundant in treasures, thine end is come, and the measure of thy covetousness."},"BSB":{"text":"You who dwell by many waters, rich in treasures, your end has come; the thread of your life is cut."},"TANAKH":{"text":"O thou that dwellest upon many waters, abundant in treasures, thine end is come, the measure of thy covetousness."},"HEBREW":{"text":"שכנתי שֹׁכַנְתְּ֙ עַל־מַ֣יִם רַבִּ֔ים רַבַּ֖ת אֽוֹצָרֹ֑ת בָּ֥א קִצֵּ֖ךְ אַמַּ֥ת בִּצְעֵֽךְ׃"}},"definableWords":["waters","life"],"peopleInVerse":[]},"14":{"text":"The LORD of hosts hath sworn by himself, saying, Surely I will fill thee with men, as with caterpillers; and they shall lift up a shout against thee.","ref":"Jeremiah 51:14","synthesized":"The LORD of Hosts has sworn by Himself:  “Surely I will fill you up with men as with locusts, and they will shout in triumph over you.”","sources":{"KJV":{"text":"The LORD of hosts hath sworn by himself, saying, Surely I will fill thee with men, as with caterpillers; and they shall lift up a shout against thee."},"BSB":{"text":"The LORD of Hosts has sworn by Himself:  “Surely I will fill you up with men as with locusts, and they will shout in triumph over you.”"},"TANAKH":{"text":"HaShem of hosts hath sworn by Himself: Surely I will fill thee with men, as with the canker-worm, and they shall lift up a shout against thee."},"HEBREW":{"text":"נִשְׁבַּ֛ע יְהוָ֥ה צְבָא֖וֹת בְּנַפְשׁ֑וֹ כִּ֣י אִם־מִלֵּאתִ֤יךְ אָדָם֙ כַּיֶּ֔לֶק וְעָנ֥וּ עָלַ֖יִךְ הֵידָֽד׃"}},"definableWords":["LORD","fill","men"],"peopleInVerse":[]},"15":{"text":"He hath made the earth by his power, he hath established the world by his wisdom, and hath stretched out the heaven by his understanding.","ref":"Jeremiah 51:15","synthesized":"The LORD made the earth by His power; He established the world by His wisdom and stretched out the heavens by His understanding.","sources":{"KJV":{"text":"He hath made the earth by his power, he hath established the world by his wisdom, and hath stretched out the heaven by his understanding."},"BSB":{"text":"The LORD made the earth by His power; He established the world by His wisdom and stretched out the heavens by His understanding."},"TANAKH":{"text":"He that hath made the earth by His power, that hath established the world by His wisdom, and hath stretched out the heavens by His discernment;"},"HEBREW":{"text":"עֹשֵׂ֥ה אֶ֙רֶץ֙ בְּכֹח֔וֹ מֵכִ֥ין תֵּבֵ֖ל בְּחָכְמָת֑וֹ וּבִתְבוּנָת֖וֹ נָטָ֥ה שָׁמָֽיִם׃"}},"definableWords":["LORD","made","earth","wisdom","heavens"],"peopleInVerse":[],"themesInVerse":["creation","wisdom"]},"16":{"text":"When he uttereth his voice, there is a multitude of waters in the heavens; and he causeth the vapours to ascend from the ends of the earth: he maketh lightnings with rain, and bringeth forth the wind out of his treasures.","ref":"Jeremiah 51:16","synthesized":"When He thunders, the waters in the heavens roar; He causes the clouds to rise from the ends of the earth. He generates the lightning with the rain and brings forth the wind from His storehouses.","sources":{"KJV":{"text":"When he uttereth his voice, there is a multitude of waters in the heavens; and he causeth the vapours to ascend from the ends of the earth: he maketh lightnings with rain, and bringeth forth the wind out of his treasures."},"BSB":{"text":"When He thunders, the waters in the heavens roar; He causes the clouds to rise from the ends of the earth. He generates the lightning with the rain and brings forth the wind from His storehouses."},"TANAKH":{"text":"At the sound of His giving a multitude of waters in the heavens, He causeth the vapours to ascend from the ends of the earth; He maketh lightnings at the time of the rain, and bringeth forth the wind out of His treasuries;"},"HEBREW":{"text":"לְק֨וֹל תִּתּ֜וֹ הֲמ֥וֹן מַ֙יִם֙ בַּשָּׁמַ֔יִם וַיַּ֥עַל נְשִׂאִ֖ים מִקְצֵה־אָ֑רֶץ בְּרָקִ֤ים לַמָּטָר֙ עָשָׂ֔ה וַיֹּ֥צֵא ר֖וּחַ מֵאֹצְרֹתָֽיו׃"}},"definableWords":["waters","heavens","earth"],"peopleInVerse":[],"themesInVerse":["resurrection"]},"17":{"text":"Every man is brutish by his knowledge; every founder is confounded by the graven image: for his molten image is falsehood, and there is no breath in them.","ref":"Jeremiah 51:17","synthesized":"Every man is senseless and devoid of knowledge; every goldsmith is put to shame by his idols. For his molten images are a fraud, and there is no breath in them.","sources":{"KJV":{"text":"Every man is brutish by his knowledge; every founder is confounded by the graven image: for his molten image is falsehood, and there is no breath in them."},"BSB":{"text":"Every man is senseless and devoid of knowledge; every goldsmith is put to shame by his idols. For his molten images are a fraud, and there is no breath in them."},"TANAKH":{"text":"Every man is proved to be brutish, for the knowledge--every goldsmith is put to shame by the graven image--that his molten image is falsehood, and there is no breath in them."},"HEBREW":{"text":"נִבְעַ֤ר כָּל־אָדָם֙ מִדַּ֔עַת הֹבִ֥ישׁ כָּל־צֹרֵ֖ף מִפָּ֑סֶל כִּ֛י שֶׁ֥קֶר נִסְכּ֖וֹ וְלֹא־ר֥וּחַ בָּֽם׃"}},"definableWords":["man","knowledge","breath"],"peopleInVerse":[]},"18":{"text":"They are vanity, the work of errors: in the time of their visitation they shall perish.","ref":"Jeremiah 51:18","synthesized":"They are worthless, a work to be mocked. In the time of their punishment they will perish.","sources":{"KJV":{"text":"They are vanity, the work of errors: in the time of their visitation they shall perish."},"BSB":{"text":"They are worthless, a work to be mocked. In the time of their punishment they will perish."},"TANAKH":{"text":"They are vanity, a work of delusion; in the time of their visitation they shall perish,"},"HEBREW":{"text":"הֶ֣בֶל הֵ֔מָּה מַעֲשֵׂ֖ה תַּעְתֻּעִ֑ים בְּעֵ֥ת פְּקֻדָּתָ֖ם יֹאבֵֽדוּ׃"}},"definableWords":["work"],"peopleInVerse":[]},"19":{"text":"The portion of Jacob is not like them; for he is the former of all things: and Israel is the rod of his inheritance: the LORD of hosts is his name.","ref":"Jeremiah 51:19","synthesized":"The Portion of Jacob is not like these, for He is the Maker of all things, and of the tribe of His inheritance— the LORD of Hosts is His name.","sources":{"KJV":{"text":"The portion of Jacob is not like them; for he is the former of all things: and Israel is the rod of his inheritance: the LORD of hosts is his name."},"BSB":{"text":"The Portion of Jacob is not like these, for He is the Maker of all things, and of the tribe of His inheritance— the LORD of Hosts is His name."},"TANAKH":{"text":"The portion of Jacob is not like these; for He is the former of all things, and Israel is the tribe of His inheritance; HaShem of hosts is His name."},"HEBREW":{"text":"לֹֽא־כְאֵ֜לֶּה חֵ֣לֶק יַעֲק֗וֹב כִּֽי־יוֹצֵ֤ר הַכֹּל֙ ה֔וּא וְשֵׁ֖בֶט נַחֲלָת֑וֹ יְהוָ֥ה צְבָא֖וֹת שְׁמֽוֹ׃"}},"definableWords":["Jacob","tribe","LORD","name"],"peopleInVerse":["Jacob"],"themesInVerse":["land_promise"]},"20":{"text":"Thou art my battle axe and weapons of war: for with thee will I break in pieces the nations, and with thee will I destroy kingdoms;","ref":"Jeremiah 51:20","synthesized":"“You are My war club, My weapon for battle. With you I shatter nations; with you I bring kingdoms to ruin.","sources":{"KJV":{"text":"Thou art my battle axe and weapons of war: for with thee will I break in pieces the nations, and with thee will I destroy kingdoms;"},"BSB":{"text":"“You are My war club, My weapon for battle. With you I shatter nations; with you I bring kingdoms to ruin."},"TANAKH":{"text":"Thou art My maul and weapons of war, and with thee will I shatter the nations, and with thee will I destroy kingdoms;"},"HEBREW":{"text":"מַפֵּץ־אַתָּ֣ה לִ֔י כְּלֵ֖י מִלְחָמָ֑ה וְנִפַּצְתִּ֤י בְךָ֙ גּוֹיִ֔ם וְהִשְׁחַתִּ֥י בְךָ֖ מַמְלָכֽוֹת׃"}},"definableWords":["nations"],"peopleInVerse":[],"themesInVerse":["spiritual_warfare"]},"21":{"text":"And with thee will I break in pieces the horse and his rider; and with thee will I break in pieces the chariot and his rider;","ref":"Jeremiah 51:21","synthesized":"With you I shatter the horse and rider; with you I shatter the chariot and driver.","sources":{"KJV":{"text":"And with thee will I break in pieces the horse and his rider; and with thee will I break in pieces the chariot and his rider;"},"BSB":{"text":"With you I shatter the horse and rider; with you I shatter the chariot and driver."},"TANAKH":{"text":"And with thee will I shatter the horse and his rider, and with thee will I shatter the chariot and him that rideth therein;"},"HEBREW":{"text":"וְנִפַּצְתִּ֣י בְךָ֔ ס֖וּס וְרֹֽכְב֑וֹ וְנִפַּצְתִּ֣י בְךָ֔ רֶ֖כֶב וְרֹכְבֽוֹ׃"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"With thee also will I break in pieces man and woman; and with thee will I break in pieces old and young; and with thee will I break in pieces the young man and the maid;","ref":"Jeremiah 51:22","synthesized":"With you I shatter man and woman; with you I shatter the old man and the youth; with you I shatter the young man and the maiden.","sources":{"KJV":{"text":"With thee also will I break in pieces man and woman; and with thee will I break in pieces old and young; and with thee will I break in pieces the young man and the maid;"},"BSB":{"text":"With you I shatter man and woman; with you I shatter the old man and the youth; with you I shatter the young man and the maiden."},"TANAKH":{"text":"And with thee will I shatter man and woman, and with thee will I shatter the old man and the youth, and with thee will I shatter the young man and the maid;"},"HEBREW":{"text":"וְנִפַּצְתִּ֤י בְךָ֙ אִ֣ישׁ וְאִשָּׁ֔ה וְנִפַּצְתִּ֥י בְךָ֖ זָקֵ֣ן וָנָ֑עַר וְנִפַּצְתִּ֣י בְךָ֔ בָּח֖וּר וּבְתוּלָֽה׃"}},"definableWords":["man","woman"],"peopleInVerse":[]},"23":{"text":"I will also break in pieces with thee the shepherd and his flock; and with thee will I break in pieces the husbandman and his yoke of oxen; and with thee will I break in pieces captains and rulers.","ref":"Jeremiah 51:23","synthesized":"With you I shatter the shepherd and his flock; with you I shatter the farmer and his oxen; with you I shatter the governors and officials.","sources":{"KJV":{"text":"I will also break in pieces with thee the shepherd and his flock; and with thee will I break in pieces the husbandman and his yoke of oxen; and with thee will I break in pieces captains and rulers."},"BSB":{"text":"With you I shatter the shepherd and his flock; with you I shatter the farmer and his oxen; with you I shatter the governors and officials."},"TANAKH":{"text":"And with thee will I shatter the shepherd and his flock, and with thee will I shatter the husbandman and his yoke of oxen, and with thee will I shatter governors and deputies."},"HEBREW":{"text":"וְנִפַּצְתִּ֤י בְךָ֙ רֹעֶ֣ה וְעֶדְר֔וֹ וְנִפַּצְתִּ֥י בְךָ֖ אִכָּ֣ר וְצִמְדּ֑וֹ וְנִפַּצְתִּ֣י בְךָ֔ פַּח֖וֹת וּסְגָנִֽים׃"}},"definableWords":["shepherd"],"peopleInVerse":[],"themesInVerse":["shepherd_sheep"]},"24":{"text":"And I will render unto Babylon and to all the inhabitants of Chaldea all their evil that they have done in Zion in your sight, saith the LORD.","ref":"Jeremiah 51:24","synthesized":"Before your very eyes I will repay Babylon and all the dwellers of Chaldea for all the evil they have done in Zion,” declares the LORD.","sources":{"KJV":{"text":"And I will render unto Babylon and to all the inhabitants of Chaldea all their evil that they have done in Zion in your sight, saith the LORD."},"BSB":{"text":"Before your very eyes I will repay Babylon and all the dwellers of Chaldea for all the evil they have done in Zion,” declares the LORD."},"TANAKH":{"text":"And I will render unto Babylon and to all the inhabitants of Chaldea all their evil that they have done in Zion, in your sight; saith HaShem."},"HEBREW":{"text":"וְשִׁלַּמְתִּ֨י לְבָבֶ֜ל וּלְכֹ֣ל ׀ יוֹשְׁבֵ֣י כַשְׂדִּ֗ים אֵ֧ת כָּל־רָעָתָ֛ם אֲשֶׁר־עָשׂ֥וּ בְצִיּ֖וֹן לְעֵֽינֵיכֶ֑ם נְאֻ֖ם יְהוָֽה׃"}},"definableWords":["Babylon","evil","Zion","LORD"],"peopleInVerse":[],"placesInVerse":["Babylon","Mount Zion"]},"25":{"text":"Behold, I am against thee, O destroying mountain, saith the LORD, which destroyest all the earth: and I will stretch out mine hand upon thee, and roll thee down from the rocks, and will make thee a burnt mountain.","ref":"Jeremiah 51:25","synthesized":"“Behold, I am against you, O destroying mountain, you who devastate the whole earth, declares the LORD. I will stretch out My hand against you; I will roll you over the cliffs and turn you into a charred mountain.","sources":{"KJV":{"text":"Behold, I am against thee, O destroying mountain, saith the LORD, which destroyest all the earth: and I will stretch out mine hand upon thee, and roll thee down from the rocks, and will make thee a burnt mountain."},"BSB":{"text":"“Behold, I am against you, O destroying mountain, you who devastate the whole earth, declares the LORD. I will stretch out My hand against you; I will roll you over the cliffs and turn you into a charred mountain."},"TANAKH":{"text":"Behold, I am against thee, O destroying mountain, saith HaShem, which destroyest all the earth; and I will stretch out My hand upon thee, and roll thee down from the rocks, and will make thee a burnt mountain."},"HEBREW":{"text":"הִנְנִ֨י אֵלֶ֜יךָ הַ֤ר הַמַּשְׁחִית֙ נְאֻם־יְהוָ֔ה הַמַּשְׁחִ֖ית אֶת־כָּל־הָאָ֑רֶץ וְנָטִ֨יתִי אֶת־יָדִ֜י עָלֶ֗יךָ וְגִלְגַּלְתִּ֙יךָ֙ מִן־הַסְּלָעִ֔ים וּנְתַתִּ֖יךָ לְהַ֥ר שְׂרֵפָֽה׃"}},"definableWords":["earth","LORD"],"peopleInVerse":[]},"26":{"text":"And they shall not take of thee a stone for a corner, nor a stone for foundations; but thou shalt be desolate for ever, saith the LORD.","ref":"Jeremiah 51:26","synthesized":"No one shall retrieve from you a cornerstone or a foundation stone, because you will become desolate forever,” declares the LORD.","sources":{"KJV":{"text":"And they shall not take of thee a stone for a corner, nor a stone for foundations; but thou shalt be desolate for ever, saith the LORD."},"BSB":{"text":"No one shall retrieve from you a cornerstone or a foundation stone, because you will become desolate forever,” declares the LORD."},"TANAKH":{"text":"And they shall not take of thee a stone for a corner, nor a stone for foundations; but thou shalt be desolate for ever, saith HaShem."},"HEBREW":{"text":"וְלֹֽא־יִקְח֤וּ מִמְּךָ֙ אֶ֣בֶן לְפִנָּ֔ה וְאֶ֖בֶן לְמֽוֹסָד֑וֹת כִּֽי־שִׁמְמ֥וֹת עוֹלָ֛ם תִּֽהְיֶ֖ה נְאֻם־יְהוָֽה׃"}},"definableWords":["one","or","stone","LORD"],"peopleInVerse":[]},"27":{"text":"Set ye up a standard in the land, blow the trumpet among the nations, prepare the nations against her, call together against her the kingdoms of Ararat, Minni, and Ashchenaz; appoint a captain against her; cause the horses to come up as the rough caterpillers.","ref":"Jeremiah 51:27","synthesized":"“Raise a banner in the land! Blow the ram’s horn among the nations! Prepare the nations against her. Summon the kingdoms against her— Ararat, Minni, and Ashkenaz. Appoint a captain against her; bring up horses like swarming locusts.","sources":{"KJV":{"text":"Set ye up a standard in the land, blow the trumpet among the nations, prepare the nations against her, call together against her the kingdoms of Ararat, Minni, and Ashchenaz; appoint a captain against her; cause the horses to come up as the rough caterpillers."},"BSB":{"text":"“Raise a banner in the land! Blow the ram’s horn among the nations! Prepare the nations against her. Summon the kingdoms against her— Ararat, Minni, and Ashkenaz. Appoint a captain against her; bring up horses like swarming locusts."},"TANAKH":{"text":"Set ye up a standard in the land, blow the horn among the nations, prepare the nations against her, call together against her the kingdoms of Ararat, Minni, and Ashkenaz; appoint a marshal against her; cause the horses to come up as the rough canker-worm."},"HEBREW":{"text":"שְׂאוּ־נֵ֣ס בָּאָ֗רֶץ תִּקְע֨וּ שׁוֹפָ֤ר בַּגּוֹיִם֙ קַדְּשׁ֤וּ עָלֶ֙יהָ֙ גּוֹיִ֔ם הַשְׁמִ֧יעוּ עָלֶ֛יהָ מַמְלְכ֥וֹת אֲרָרַ֖ט מִנִּ֣י וְאַשְׁכְּנָ֑ז פִּקְד֤וּ עָלֶ֙יהָ֙ טִפְסָ֔ר הַֽעֲלוּ־ס֖וּס כְּיֶ֥לֶק סָמָֽר׃"}},"definableWords":["land","nations","Ararat"],"peopleInVerse":[],"placesInVerse":["Ararat"],"themesInVerse":["land_promise"]},"28":{"text":"Prepare against her the nations with the kings of the Medes, the captains thereof, and all the rulers thereof, and all the land of his dominion.","ref":"Jeremiah 51:28","synthesized":"Prepare the nations for battle against her— the kings of the Medes, their governors and all their officials, and all the lands they rule.","sources":{"KJV":{"text":"Prepare against her the nations with the kings of the Medes, the captains thereof, and all the rulers thereof, and all the land of his dominion."},"BSB":{"text":"Prepare the nations for battle against her— the kings of the Medes, their governors and all their officials, and all the lands they rule."},"TANAKH":{"text":"Prepare against her the nations, the kings of the Medes, the governors thereof, and all the deputies thereof, and all the land of his dominion."},"HEBREW":{"text":"קַדְּשׁ֨וּ עָלֶ֤יהָ גוֹיִם֙ אֶת־מַלְכֵ֣י מָדַ֔י אֶת־פַּחוֹתֶ֖יהָ וְאֶת־כָּל־סְגָנֶ֑יהָ וְאֵ֖ת כָּל־אֶ֥רֶץ מֶמְשַׁלְתּֽוֹ׃"}},"definableWords":["nations","kings","rule"],"peopleInVerse":[],"themesInVerse":["kingdom_of_god","spiritual_warfare"]},"29":{"text":"And the land shall tremble and sorrow: for every purpose of the LORD shall be performed against Babylon, to make the land of Babylon a desolation without an inhabitant.","ref":"Jeremiah 51:29","synthesized":"The earth quakes and writhes because the LORD’s intentions against Babylon stand: to make the land of Babylon a desolation, without inhabitant.","sources":{"KJV":{"text":"And the land shall tremble and sorrow: for every purpose of the LORD shall be performed against Babylon, to make the land of Babylon a desolation without an inhabitant."},"BSB":{"text":"The earth quakes and writhes because the LORD’s intentions against Babylon stand: to make the land of Babylon a desolation, without inhabitant."},"TANAKH":{"text":"And the land quaketh and is in pain; for the purposes of HaShem are performed against Babylon, to make the land of Babylon a desolation, without inhabitant."},"HEBREW":{"text":"וַתִּרְעַ֥שׁ הָאָ֖רֶץ וַתָּחֹ֑ל כִּ֣י קָ֤מָה עַל־בָּבֶל֙ מַחְשְׁב֣וֹת יְהוָ֔ה לָשׂ֞וּם אֶת־אֶ֧רֶץ בָּבֶ֛ל לְשַׁמָּ֖ה מֵאֵ֥ין יוֹשֵֽׁב׃"}},"definableWords":["earth","LORD","Babylon","stand","make","land"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["land_promise"]},"30":{"text":"The mighty men of Babylon have forborn to fight, they have remained in their holds: their might hath failed; they became as women: they have burned her dwellingplaces; her bars are broken.","ref":"Jeremiah 51:30","synthesized":"The warriors of Babylon have stopped fighting; they sit in their strongholds. Their strength is exhausted; they have become like women. Babylon’s homes have been set ablaze, the bars of her gates are broken.","sources":{"KJV":{"text":"The mighty men of Babylon have forborn to fight, they have remained in their holds: their might hath failed; they became as women: they have burned her dwellingplaces; her bars are broken."},"BSB":{"text":"The warriors of Babylon have stopped fighting; they sit in their strongholds. Their strength is exhausted; they have become like women. Babylon’s homes have been set ablaze, the bars of her gates are broken."},"TANAKH":{"text":"The mighty men of Babylon have forborne to fight, they remain in their strongholds; their might hath failed, they are become as women; her dwelling-places are set on fire; her bars are broken."},"HEBREW":{"text":"חָדְלוּ֩ גִבּוֹרֵ֨י בָבֶ֜ל לְהִלָּחֵ֗ם יָֽשְׁבוּ֙ בַּמְּצָד֔וֹת נָשְׁתָ֥ה גְבוּרָתָ֖ם הָי֣וּ לְנָשִׁ֑ים הִצִּ֥יתוּ מִשְׁכְּנֹתֶ֖יהָ נִשְׁבְּר֥וּ בְרִיחֶֽיהָ׃"}},"definableWords":["Babylon","women"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"31":{"text":"One post shall run to meet another, and one messenger to meet another, to shew the king of Babylon that his city is taken at one end,","ref":"Jeremiah 51:31","synthesized":"One courier races to meet another, and messenger follows messenger, to announce to the king of Babylon that his city has been captured from end to end.","sources":{"KJV":{"text":"One post shall run to meet another, and one messenger to meet another, to shew the king of Babylon that his city is taken at one end,"},"BSB":{"text":"One courier races to meet another, and messenger follows messenger, to announce to the king of Babylon that his city has been captured from end to end."},"TANAKH":{"text":"One post runneth to meet another, and one messenger to meet an other, to tell the king of Babylon that his city is taken on every quarter;"},"HEBREW":{"text":"רָ֤ץ לִקְרַאת־רָץ֙ יָר֔וּץ וּמַגִּ֖יד לִקְרַ֣את מַגִּ֑יד לְהַגִּיד֙ לְמֶ֣לֶךְ בָּבֶ֔ל כִּֽי־נִלְכְּדָ֥ה עִיר֖וֹ מִקָּצֶֽה׃"}},"definableWords":["one","king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"32":{"text":"And that the passages are stopped, and the reeds they have burned with fire, and the men of war are affrighted.","ref":"Jeremiah 51:32","synthesized":"The fords have been seized, the marshes set on fire, and the soldiers are terrified.”","sources":{"KJV":{"text":"And that the passages are stopped, and the reeds they have burned with fire, and the men of war are affrighted."},"BSB":{"text":"The fords have been seized, the marshes set on fire, and the soldiers are terrified.”"},"TANAKH":{"text":"And the fords are seized, and the castles they have burned with fire, and the men of war are affrighted."},"HEBREW":{"text":"וְהַמַּעְבָּר֣וֹת נִתְפָּ֔שׂוּ וְאֶת־הָאֲגַמִּ֖ים שָׂרְפ֣וּ בָאֵ֑שׁ וְאַנְשֵׁ֥י הַמִּלְחָמָ֖ה נִבְהָֽלוּ׃"}},"definableWords":[],"peopleInVerse":[]},"33":{"text":"For thus saith the LORD of hosts, the God of Israel; The daughter of Babylon is like a threshingfloor, it is time to thresh her: yet a little while, and the time of her harvest shall come.","ref":"Jeremiah 51:33","synthesized":"For this is what the LORD of Hosts, the God of Israel, says:  “The Daughter of Babylon is like a threshing floor at the time it is trampled. In just a little while her harvest time will come.”","sources":{"KJV":{"text":"For thus saith the LORD of hosts, the God of Israel; The daughter of Babylon is like a threshingfloor, it is time to thresh her: yet a little while, and the time of her harvest shall come."},"BSB":{"text":"For this is what the LORD of Hosts, the God of Israel, says:  “The Daughter of Babylon is like a threshing floor at the time it is trampled. In just a little while her harvest time will come.”"},"TANAKH":{"text":"For thus saith HaShem of hosts, the G-d of Israel: The daughter of Babylon is like a threshing-floor at the time when it is trodden; yet a little while, and the time of harvest shall come for her."},"HEBREW":{"text":"כִּי֩ כֹ֨ה אָמַ֜ר יְהוָ֤ה צְבָאוֹת֙ אֱלֹהֵ֣י יִשְׂרָאֵ֔ל בַּת־בָּבֶ֕ל כְּגֹ֖רֶן עֵ֣ת הִדְרִיכָ֑הּ ע֣וֹד מְעַ֔ט וּבָ֥אָה עֵֽת־הַקָּצִ֖יר לָֽהּ׃"}},"definableWords":["LORD","God","Israel","daughter","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"34":{"text":"Nebuchadrezzar the king of Babylon hath devoured me, he hath crushed me, he hath made me an empty vessel, he hath swallowed me up like a dragon, he hath filled his belly with my delicates, he hath cast me out.","ref":"Jeremiah 51:34","synthesized":"“Nebuchadnezzar king of Babylon has devoured me; he has crushed me. He has set me aside like an empty vessel; he has swallowed me like a monster; he filled his belly with my delicacies and vomited me out.","sources":{"KJV":{"text":"Nebuchadrezzar the king of Babylon hath devoured me, he hath crushed me, he hath made me an empty vessel, he hath swallowed me up like a dragon, he hath filled his belly with my delicates, he hath cast me out."},"BSB":{"text":"“Nebuchadnezzar king of Babylon has devoured me; he has crushed me. He has set me aside like an empty vessel; he has swallowed me like a monster; he filled his belly with my delicacies and vomited me out."},"TANAKH":{"text":"Nebuchadrezzar the king of Babylon hath devoured me, he hath crushed me, he hath set me down as an empty vessel, he hath swallowed me up like a dragon, he hath filled his maw with my delicacies; he hath washed me clean."},"HEBREW":{"text":"אכלנו אֲכָלַ֣נִי הממנו הֲמָמַ֗נִי נְבוּכַדְרֶאצַּר֮ מֶ֣לֶךְ בָּבֶל֒ הציגנו הִצִּיגַ֙נִי֙ כְּלִ֣י רִ֔יק בלענו בְּלָעַ֙נִי֙ כַּתַּנִּ֔ין מִלָּ֥א כְרֵשׂ֖וֹ מֵֽעֲדָנָ֑י הדיחנו הֱדִיחָֽנִי׃"}},"definableWords":["king","Babylon"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"35":{"text":"The violence done to me and to my flesh be upon Babylon, shall the inhabitant of Zion say; and my blood upon the inhabitants of Chaldea, shall Jerusalem say.","ref":"Jeremiah 51:35","synthesized":"May the violence done to me and to my flesh be upon Babylon,” says the dweller of Zion.   “May my blood be on the dwellers of Chaldea,” says Jerusalem.","sources":{"KJV":{"text":"The violence done to me and to my flesh be upon Babylon, shall the inhabitant of Zion say; and my blood upon the inhabitants of Chaldea, shall Jerusalem say."},"BSB":{"text":"May the violence done to me and to my flesh be upon Babylon,” says the dweller of Zion.   “May my blood be on the dwellers of Chaldea,” says Jerusalem."},"TANAKH":{"text":"'The violence done to me and to my flesh be upon Babylon', shall the inhabitant of Zion say; and: 'My blood be upon the inhabitants of Chaldea', shall Jerusalem say."},"HEBREW":{"text":"חֲמָסִ֤י וּשְׁאֵרִי֙ עַל־בָּבֶ֔ל תֹּאמַ֖ר יֹשֶׁ֣בֶת צִיּ֑וֹן וְדָמִי֙ אֶל־יֹשְׁבֵ֣י כַשְׂדִּ֔ים תֹּאמַ֖ר יְרוּשָׁלָֽ͏ִם׃"}},"definableWords":["flesh","Babylon","Zion","blood","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Babylon","Mount Zion","Jerusalem"],"themesInVerse":["passover","sacrifice"]},"36":{"text":"Therefore thus saith the LORD; Behold, I will plead thy cause, and take vengeance for thee; and I will dry up her sea, and make her springs dry.","ref":"Jeremiah 51:36","synthesized":"Therefore this is what the LORD says:  “Behold, I will plead your case and take vengeance on your behalf; I will dry up her sea and make her springs run dry.","sources":{"KJV":{"text":"Therefore thus saith the LORD; Behold, I will plead thy cause, and take vengeance for thee; and I will dry up her sea, and make her springs dry."},"BSB":{"text":"Therefore this is what the LORD says:  “Behold, I will plead your case and take vengeance on your behalf; I will dry up her sea and make her springs run dry."},"TANAKH":{"text":"Therefore thus saith HaShem: Behold, I will plead thy cause, and take vengeance for thee; and I will dry up her sea, and make her fountain dry."},"HEBREW":{"text":"לָכֵ֗ן כֹּ֚ה אָמַ֣ר יְהוָ֔ה הִנְנִי־רָב֙ אֶת־רִיבֵ֔ךְ וְנִקַּמְתִּ֖י אֶת־נִקְמָתֵ֑ךְ וְהַחֲרַבְתִּי֙ אֶת־יַמָּ֔הּ וְהֹבַשְׁתִּ֖י אֶת־מְקוֹרָֽהּ׃"}},"definableWords":["LORD","sea","make","run"],"peopleInVerse":[]},"37":{"text":"And Babylon shall become heaps, a dwellingplace for dragons, an astonishment, and an hissing, without an inhabitant.","ref":"Jeremiah 51:37","synthesized":"Babylon will become a heap of rubble, a haunt for jackals, an object of horror and scorn, without inhabitant.","sources":{"KJV":{"text":"And Babylon shall become heaps, a dwellingplace for dragons, an astonishment, and an hissing, without an inhabitant."},"BSB":{"text":"Babylon will become a heap of rubble, a haunt for jackals, an object of horror and scorn, without inhabitant."},"TANAKH":{"text":"And Babylon shall become heaps, a dwelling-place for jackals, an astonishment, and a hissing, without inhabitant."},"HEBREW":{"text":"וְהָיְתָה֩ בָבֶ֨ל ׀ לְגַלִּ֧ים ׀ מְעוֹן־תַּנִּ֛ים שַׁמָּ֥ה וּשְׁרֵקָ֖ה מֵאֵ֥ין יוֹשֵֽׁב׃"}},"definableWords":["Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"38":{"text":"They shall roar together like lions: they shall yell as lions’ whelps.","ref":"Jeremiah 51:38","synthesized":"They will roar together like young lions; they will growl like lion cubs.","sources":{"KJV":{"text":"They shall roar together like lions: they shall yell as lions’ whelps."},"BSB":{"text":"They will roar together like young lions; they will growl like lion cubs."},"TANAKH":{"text":"They shall roar together like young lions; they shall growl as lions' whelps."},"HEBREW":{"text":"יַחְדָּ֖ו כַּכְּפִרִ֣ים יִשְׁאָ֑גוּ נָעֲר֖וּ כְּגוֹרֵ֥י אֲרָיֽוֹת׃"}},"definableWords":["lion"],"peopleInVerse":[]},"39":{"text":"In their heat I will make their feasts, and I will make them drunken, that they may rejoice, and sleep a perpetual sleep, and not wake, saith the LORD.","ref":"Jeremiah 51:39","synthesized":"While they are flushed with heat, I will serve them a feast, and I will make them drunk so that they may revel; then they will fall asleep forever and never wake up, declares the LORD.","sources":{"KJV":{"text":"In their heat I will make their feasts, and I will make them drunken, that they may rejoice, and sleep a perpetual sleep, and not wake, saith the LORD."},"BSB":{"text":"While they are flushed with heat, I will serve them a feast, and I will make them drunk so that they may revel; then they will fall asleep forever and never wake up, declares the LORD."},"TANAKH":{"text":"With their poison I will prepare their feast, and I will make them drunken, that they may be convulsed, and sleep a perpetual sleep, and not wake, saith HaShem."},"HEBREW":{"text":"בְּחֻמָּ֞ם אָשִׁ֣ית אֶת־מִשְׁתֵּיהֶ֗ם וְהִשְׁכַּרְתִּים֙ לְמַ֣עַן יַעֲלֹ֔זוּ וְיָשְׁנ֥וּ שְׁנַת־עוֹלָ֖ם וְלֹ֣א יָקִ֑יצוּ נְאֻ֖ם יְהוָֽה׃"}},"definableWords":["make","LORD"],"peopleInVerse":[],"themesInVerse":["fall_sin"]},"40":{"text":"I will bring them down like lambs to the slaughter, like rams with he goats.","ref":"Jeremiah 51:40","synthesized":"I will bring them down like lambs to the slaughter, like rams with male goats.","sources":{"KJV":{"text":"I will bring them down like lambs to the slaughter, like rams with he goats."},"BSB":{"text":"I will bring them down like lambs to the slaughter, like rams with male goats."},"TANAKH":{"text":"I will bring them down like lambs to the slaughter, like rams with he-goats."},"HEBREW":{"text":"אֽוֹרִידֵ֖ם כְּכָרִ֣ים לִטְב֑וֹחַ כְּאֵילִ֖ים עִם־עַתּוּדִֽים׃"}},"definableWords":["male"],"peopleInVerse":[]},"41":{"text":"How is Sheshach taken! and how is the praise of the whole earth surprised! how is Babylon become an astonishment among the nations!","ref":"Jeremiah 51:41","synthesized":"How Sheshach has been captured! The praise of all the earth has been seized. What a horror Babylon has become among the nations!","sources":{"KJV":{"text":"How is Sheshach taken! and how is the praise of the whole earth surprised! how is Babylon become an astonishment among the nations!"},"BSB":{"text":"How Sheshach has been captured! The praise of all the earth has been seized. What a horror Babylon has become among the nations!"},"TANAKH":{"text":"How is Sheshach taken! and the praise of the whole earth seized! How is Babylon become an astonishment among the nations!"},"HEBREW":{"text":"אֵ֚יךְ נִלְכְּדָ֣ה שֵׁשַׁ֔ךְ וַתִּתָּפֵ֖שׂ תְּהִלַּ֣ת כָּל־הָאָ֑רֶץ אֵ֣יךְ הָיְתָ֧ה לְשַׁמָּ֛ה בָּבֶ֖ל בַּגּוֹיִֽם׃"}},"definableWords":["praise","earth","Babylon","nations"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["worship"]},"42":{"text":"The sea is come up upon Babylon: she is covered with the multitude of the waves thereof.","ref":"Jeremiah 51:42","synthesized":"The sea has come up over Babylon; she is covered in turbulent waves.","sources":{"KJV":{"text":"The sea is come up upon Babylon: she is covered with the multitude of the waves thereof."},"BSB":{"text":"The sea has come up over Babylon; she is covered in turbulent waves."},"TANAKH":{"text":"The sea is come up upon Babylon; she is covered with the multitude of the waves thereof."},"HEBREW":{"text":"עָלָ֥ה עַל־בָּבֶ֖ל הַיָּ֑ם בַּהֲמ֥וֹן גַּלָּ֖יו נִכְסָֽתָה׃"}},"definableWords":["sea","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"43":{"text":"Her cities are a desolation, a dry land, and a wilderness, a land wherein no man dwelleth, neither doth any son of man pass thereby.","ref":"Jeremiah 51:43","synthesized":"Her cities have become a desolation, a dry and arid land, a land where no one lives, where no son of man passes through.","sources":{"KJV":{"text":"Her cities are a desolation, a dry land, and a wilderness, a land wherein no man dwelleth, neither doth any son of man pass thereby."},"BSB":{"text":"Her cities have become a desolation, a dry and arid land, a land where no one lives, where no son of man passes through."},"TANAKH":{"text":"Her cities are become a desolation, a dry land, and a desert, a land wherein no man dwelleth, neither doth any son of man pass thereby."},"HEBREW":{"text":"הָי֤וּ עָרֶ֙יהָ֙ לְשַׁמָּ֔ה אֶ֖רֶץ צִיָּ֣ה וַעֲרָבָ֑ה אֶ֗רֶץ לֹֽא־יֵשֵׁ֤ב בָּהֵן֙ כָּל־אִ֔ישׁ וְלֹֽא־יַעֲבֹ֥ר בָּהֵ֖ן בֶּן־אָדָֽם׃"}},"definableWords":["land","one","son","man"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"44":{"text":"And I will punish Bel in Babylon, and I will bring forth out of his mouth that which he hath swallowed up: and the nations shall not flow together any more unto him: yea, the wall of Babylon shall fall.","ref":"Jeremiah 51:44","synthesized":"I will punish Bel in Babylon. I will make him spew out what he swallowed. The nations will no longer stream to him; even the wall of Babylon will fall.","sources":{"KJV":{"text":"And I will punish Bel in Babylon, and I will bring forth out of his mouth that which he hath swallowed up: and the nations shall not flow together any more unto him: yea, the wall of Babylon shall fall."},"BSB":{"text":"I will punish Bel in Babylon. I will make him spew out what he swallowed. The nations will no longer stream to him; even the wall of Babylon will fall."},"TANAKH":{"text":"And I will punish Bel in Babylon, and I will bring forth out of his mouth that which he hath swallowed up, and the nations shall not flow any more unto him; yea, the wall of Babylon shall fall."},"HEBREW":{"text":"וּפָקַדְתִּ֨י עַל־בֵּ֜ל בְּבָבֶ֗ל וְהֹצֵאתִ֤י אֶת־בִּלְעוֹ֙ מִפִּ֔יו וְלֹֽא־יִנְהֲר֥וּ אֵלָ֛יו ע֖וֹד גּוֹיִ֑ם גַּם־חוֹמַ֥ת בָּבֶ֖ל נָפָֽלָה׃"}},"definableWords":["Babylon","make","nations"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["fall_sin"]},"45":{"text":"My people, go ye out of the midst of her, and deliver ye every man his soul from the fierce anger of the LORD.","ref":"Jeremiah 51:45","synthesized":"Come out of her, My people! Save your lives, each of you, from the fierce anger of the LORD.","sources":{"KJV":{"text":"My people, go ye out of the midst of her, and deliver ye every man his soul from the fierce anger of the LORD."},"BSB":{"text":"Come out of her, My people! Save your lives, each of you, from the fierce anger of the LORD."},"TANAKH":{"text":"My people, go ye out of the midst of her, and save yourselves every man from the fierce anger of HaShem."},"HEBREW":{"text":"צְא֤וּ מִתּוֹכָהּ֙ עַמִּ֔י וּמַלְּט֖וּ אִ֣ישׁ אֶת־נַפְשׁ֑וֹ מֵחֲר֖וֹן אַף־יְהוָֽה׃"}},"definableWords":["people","anger","LORD"],"peopleInVerse":[],"themesInVerse":["salvation"]},"46":{"text":"And lest your heart faint, and ye fear for the rumour that shall be heard in the land; a rumour shall both come one year, and after that in another year shall come a rumour, and violence in the land, ruler against ruler.","ref":"Jeremiah 51:46","synthesized":"Do not let your heart grow faint, and do not be afraid when the rumor is heard in the land; for a rumor will come one year— and then another the next year— of violence in the land and of ruler against ruler.","sources":{"KJV":{"text":"And lest your heart faint, and ye fear for the rumour that shall be heard in the land; a rumour shall both come one year, and after that in another year shall come a rumour, and violence in the land, ruler against ruler."},"BSB":{"text":"Do not let your heart grow faint, and do not be afraid when the rumor is heard in the land; for a rumor will come one year— and then another the next year— of violence in the land and of ruler against ruler."},"TANAKH":{"text":"And let not your heart faint, neither fear ye, for the rumour that shall be heard in the land; for a rumour shall come one year, and after that in another year a rumour, and violence in the land, ruler against ruler."},"HEBREW":{"text":"וּפֶן־יֵרַ֤ךְ לְבַבְכֶם֙ וְתִֽירְא֔וּ בַּשְּׁמוּעָ֖ה הַנִּשְׁמַ֣עַת בָּאָ֑רֶץ וּבָ֧א בַשָּׁנָ֣ה הַשְּׁמוּעָ֗ה וְאַחֲרָ֤יו בַּשָּׁנָה֙ הַשְּׁמוּעָ֔ה וְחָמָ֣ס בָּאָ֔רֶץ וּמֹשֵׁ֖ל עַל־מֹשֵֽׁל׃"}},"definableWords":["heart","land","one","year","ruler"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"47":{"text":"Therefore, behold, the days come, that I will do judgment upon the graven images of Babylon: and her whole land shall be confounded, and all her slain shall fall in the midst of her.","ref":"Jeremiah 51:47","synthesized":"Therefore, behold, the days are coming when I will punish the idols of Babylon. Her entire land will suffer shame, and all her slain will lie fallen within her.","sources":{"KJV":{"text":"Therefore, behold, the days come, that I will do judgment upon the graven images of Babylon: and her whole land shall be confounded, and all her slain shall fall in the midst of her."},"BSB":{"text":"Therefore, behold, the days are coming when I will punish the idols of Babylon. Her entire land will suffer shame, and all her slain will lie fallen within her."},"TANAKH":{"text":"Therefore behold, the days come, that I will do judgment upon the graven images of Babylon, and her whole land shall be ashamed; and all her slain shall fall in the midst of her."},"HEBREW":{"text":"לָכֵן֙ הִנֵּ֣ה יָמִ֣ים בָּאִ֔ים וּפָקַדְתִּי֙ עַל־פְּסִילֵ֣י בָבֶ֔ל וְכָל־אַרְצָ֖הּ תֵּב֑וֹשׁ וְכָל־חֲלָלֶ֖יהָ יִפְּל֥וּ בְתוֹכָֽהּ׃"}},"definableWords":["days","Babylon","land"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["land_promise","second_coming","suffering"]},"48":{"text":"Then the heaven and the earth, and all that is therein, shall sing for Babylon: for the spoilers shall come unto her from the north, saith the LORD.","ref":"Jeremiah 51:48","synthesized":"Then heaven and earth and all that is in them will shout for joy over Babylon because the destroyers from the north will come against her,” declares the LORD.","sources":{"KJV":{"text":"Then the heaven and the earth, and all that is therein, shall sing for Babylon: for the spoilers shall come unto her from the north, saith the LORD."},"BSB":{"text":"Then heaven and earth and all that is in them will shout for joy over Babylon because the destroyers from the north will come against her,” declares the LORD."},"TANAKH":{"text":"Then the heaven and the earth, and all that is therein, shall sing for joy over Babylon; for the spoilers shall come unto her from the north, saith HaShem."},"HEBREW":{"text":"וְרִנְּנ֤וּ עַל־בָּבֶל֙ שָׁמַ֣יִם וָאָ֔רֶץ וְכֹ֖ל אֲשֶׁ֣ר בָּהֶ֑ם כִּ֧י מִצָּפ֛וֹן יָבוֹא־לָ֥הּ הַשּׁוֹדְדִ֖ים נְאֻם־יְהוָֽה׃"}},"definableWords":["heaven","earth","joy","Babylon","LORD"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["joy"]},"49":{"text":"As Babylon hath caused the slain of Israel to fall, so at Babylon shall fall the slain of all the earth.","ref":"Jeremiah 51:49","synthesized":"“Babylon must fall on account of the slain of Israel, just as the slain of all the earth have fallen because of Babylon.","sources":{"KJV":{"text":"As Babylon hath caused the slain of Israel to fall, so at Babylon shall fall the slain of all the earth."},"BSB":{"text":"“Babylon must fall on account of the slain of Israel, just as the slain of all the earth have fallen because of Babylon."},"TANAKH":{"text":"As Babylon hath caused the slain of Israel to fall, so at Babylon shall fall the slain of all the land."},"HEBREW":{"text":"גַּם־בָּבֶ֕ל לִנְפֹּ֖ל חַֽלְלֵ֣י יִשְׂרָאֵ֑ל גַּם־לְבָבֶ֥ל נָפְל֖וּ חַֽלְלֵ֥י כָל־הָאָֽרֶץ׃"}},"definableWords":["Babylon","Israel","earth"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["fall_sin"]},"50":{"text":"Ye that have escaped the sword, go away, stand not still: remember the LORD afar off, and let Jerusalem come into your mind.","ref":"Jeremiah 51:50","synthesized":"You who have escaped the sword, depart and do not linger! Remember the LORD from far away, and let Jerusalem come to mind.”","sources":{"KJV":{"text":"Ye that have escaped the sword, go away, stand not still: remember the LORD afar off, and let Jerusalem come into your mind."},"BSB":{"text":"You who have escaped the sword, depart and do not linger! Remember the LORD from far away, and let Jerusalem come to mind.”"},"TANAKH":{"text":"Ye that have escaped the sword, go ye, stand not still; remember HaShem from afar, and let Jerusalem come into your mind."},"HEBREW":{"text":"פְּלֵטִ֣ים מֵחֶ֔רֶב הִלְכ֖וּ אַֽל־תַּעֲמֹ֑דוּ זִכְר֤וּ מֵֽרָחוֹק֙ אֶת־יְהוָ֔ה וִירֽוּשָׁלַ֖͏ִם תַּעֲלֶ֥ה עַל־לְבַבְכֶֽם׃"}},"definableWords":["remember","LORD","Jerusalem","mind"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"51":{"text":"We are confounded, because we have heard reproach: shame hath covered our faces: for strangers are come into the sanctuaries of the LORD’s house.","ref":"Jeremiah 51:51","synthesized":"“We are ashamed because we have heard reproach; disgrace has covered our faces, because foreigners have entered the holy places of the LORD’s house.”","sources":{"KJV":{"text":"We are confounded, because we have heard reproach: shame hath covered our faces: for strangers are come into the sanctuaries of the LORD’s house."},"BSB":{"text":"“We are ashamed because we have heard reproach; disgrace has covered our faces, because foreigners have entered the holy places of the LORD’s house.”"},"TANAKH":{"text":"'We are ashamed, because we have heard reproach, confusion hath covered our faces; for strangers are come into the sanctuaries of HaShem'S house.'"},"HEBREW":{"text":"בֹּ֚שְׁנוּ כִּֽי־שָׁמַ֣עְנוּ חֶרְפָּ֔ה כִּסְּתָ֥ה כְלִמָּ֖ה פָּנֵ֑ינוּ כִּ֚י בָּ֣אוּ זָרִ֔ים עַֽל־מִקְדְּשֵׁ֖י בֵּ֥ית יְהוָֽה׃"}},"definableWords":["holy","LORD","house"],"peopleInVerse":[]},"52":{"text":"Wherefore, behold, the days come, saith the LORD, that I will do judgment upon her graven images: and through all her land the wounded shall groan.","ref":"Jeremiah 51:52","synthesized":"“Therefore, behold, the days are coming,” declares the LORD, “when I will punish her idols, and throughout her land the wounded will groan.","sources":{"KJV":{"text":"Wherefore, behold, the days come, saith the LORD, that I will do judgment upon her graven images: and through all her land the wounded shall groan."},"BSB":{"text":"“Therefore, behold, the days are coming,” declares the LORD, “when I will punish her idols, and throughout her land the wounded will groan."},"TANAKH":{"text":"Wherefore, behold, the days come, saith HaShem, that I will do judgment upon her graven images; and through all her land the wounded shall groan."},"HEBREW":{"text":"לָכֵ֞ן הִנֵּֽה־יָמִ֤ים בָּאִים֙ נְאֻם־יְהוָ֔ה וּפָקַדְתִּ֖י עַל־פְּסִילֶ֑יהָ וּבְכָל־אַרְצָ֖הּ יֶאֱנֹ֥ק חָלָֽל׃"}},"definableWords":["days","LORD","land"],"peopleInVerse":[],"themesInVerse":["land_promise","second_coming"]},"53":{"text":"Though Babylon should mount up to heaven, and though she should fortify the height of her strength, yet from me shall spoilers come unto her, saith the LORD.","ref":"Jeremiah 51:53","synthesized":"Even if Babylon ascends to the heavens and fortifies her lofty stronghold, the destroyers I send will come against her,” declares the LORD.","sources":{"KJV":{"text":"Though Babylon should mount up to heaven, and though she should fortify the height of her strength, yet from me shall spoilers come unto her, saith the LORD."},"BSB":{"text":"Even if Babylon ascends to the heavens and fortifies her lofty stronghold, the destroyers I send will come against her,” declares the LORD."},"TANAKH":{"text":"Though Babylon should mount up to heaven, and though she should fortify the height of her strength, yet from Me shall spoilers come unto her, saith HaShem."},"HEBREW":{"text":"כִּֽי־תַעֲלֶ֤ה בָבֶל֙ הַשָּׁמַ֔יִם וְכִ֥י תְבַצֵּ֖ר מְר֣וֹם עֻזָּ֑הּ מֵאִתִּ֗י יָבֹ֧אוּ שֹׁדְדִ֛ים לָ֖הּ נְאֻם־יְהוָֽה׃"}},"definableWords":["Babylon","heavens","LORD"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"54":{"text":"A sound of a cry cometh from Babylon, and great destruction from the land of the Chaldeans:","ref":"Jeremiah 51:54","synthesized":"“The sound of a cry comes from Babylon, the sound of great destruction from the land of the Chaldeans!","sources":{"KJV":{"text":"A sound of a cry cometh from Babylon, and great destruction from the land of the Chaldeans:"},"BSB":{"text":"“The sound of a cry comes from Babylon, the sound of great destruction from the land of the Chaldeans!"},"TANAKH":{"text":"Hark! a cry from Babylon, and great destruction from the land of the Chaldeans!"},"HEBREW":{"text":"ק֥וֹל זְעָקָ֖ה מִבָּבֶ֑ל וְשֶׁ֥בֶר גָּד֖וֹל מֵאֶ֥רֶץ כַּשְׂדִּֽים׃"}},"definableWords":["Babylon","great","land"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["land_promise"]},"55":{"text":"Because the LORD hath spoiled Babylon, and destroyed out of her the great voice; when her waves do roar like great waters, a noise of their voice is uttered:","ref":"Jeremiah 51:55","synthesized":"For the LORD will destroy Babylon; He will silence her mighty voice. The waves will roar like great waters; the tumult of their voices will resound.","sources":{"KJV":{"text":"Because the LORD hath spoiled Babylon, and destroyed out of her the great voice; when her waves do roar like great waters, a noise of their voice is uttered:"},"BSB":{"text":"For the LORD will destroy Babylon; He will silence her mighty voice. The waves will roar like great waters; the tumult of their voices will resound."},"TANAKH":{"text":"For HaShem spoileth Babylon, and destroyeth out of her the great voice; and their waves roar like many waters, the noise of their voice is uttered;"},"HEBREW":{"text":"כִּֽי־שֹׁדֵ֤ד יְהוָה֙ אֶת־בָּבֶ֔ל וְאִבַּ֥ד מִמֶּ֖נָּה ק֣וֹל גָּד֑וֹל וְהָמ֤וּ גַלֵּיהֶם֙ כְּמַ֣יִם רַבִּ֔ים נִתַּ֥ן שְׁא֖וֹן קוֹלָֽם׃"}},"definableWords":["LORD","Babylon","mighty","voice","great","waters"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"56":{"text":"Because the spoiler is come upon her, even upon Babylon, and her mighty men are taken, every one of their bows is broken: for the LORD God of recompences shall surely requite.","ref":"Jeremiah 51:56","synthesized":"For a destroyer is coming against her— against Babylon. Her warriors will be captured, and their bows will be broken, for the LORD is a God of retribution; He will repay in full.","sources":{"KJV":{"text":"Because the spoiler is come upon her, even upon Babylon, and her mighty men are taken, every one of their bows is broken: for the LORD God of recompences shall surely requite."},"BSB":{"text":"For a destroyer is coming against her— against Babylon. Her warriors will be captured, and their bows will be broken, for the LORD is a God of retribution; He will repay in full."},"TANAKH":{"text":"For the spoiler is come upon her, even upon Babylon, and her mighty men are taken, their bows are shattered; for HaShem is a G-d of recompenses, He will surely requite."},"HEBREW":{"text":"כִּי֩ בָ֨א עָלֶ֤יהָ עַל־בָּבֶל֙ שׁוֹדֵ֔ד וְנִלְכְּדוּ֙ גִּבּוֹרֶ֔יהָ חִתְּתָ֖ה קַשְּׁתוֹתָ֑ם כִּ֣י אֵ֧ל גְּמֻל֛וֹת יְהוָ֖ה שַׁלֵּ֥ם יְשַׁלֵּֽם׃"}},"definableWords":["Babylon","LORD","God"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["second_coming"]},"57":{"text":"And I will make drunk her princes, and her wise men, her captains, and her rulers, and her mighty men: and they shall sleep a perpetual sleep, and not wake, saith the King, whose name is the LORD of hosts.","ref":"Jeremiah 51:57","synthesized":"I will make her princes and wise men drunk, along with her governors, officials, and warriors. Then they will fall asleep forever and not wake up,” declares the King, whose name is the LORD of Hosts.","sources":{"KJV":{"text":"And I will make drunk her princes, and her wise men, her captains, and her rulers, and her mighty men: and they shall sleep a perpetual sleep, and not wake, saith the King, whose name is the LORD of hosts."},"BSB":{"text":"I will make her princes and wise men drunk, along with her governors, officials, and warriors. Then they will fall asleep forever and not wake up,” declares the King, whose name is the LORD of Hosts."},"TANAKH":{"text":"And I will make drunk her princes and her wise men, her governors and her deputies, and her mighty men; and they shall sleep a perpetual sleep, and not wake, saith the King, whose name is HaShem of hosts."},"HEBREW":{"text":"וְ֠הִשְׁכַּרְתִּי שָׂרֶ֨יהָ וַחֲכָמֶ֜יהָ פַּחוֹתֶ֤יהָ וּסְגָנֶ֙יהָ֙ וְגִבּוֹרֶ֔יהָ וְיָשְׁנ֥וּ שְׁנַת־עוֹלָ֖ם וְלֹ֣א יָקִ֑יצוּ נְאֻ֨ם־הַמֶּ֔לֶךְ יְהוָ֥ה צְבָא֖וֹת שְׁמֽוֹ׃"}},"definableWords":["make","men","King","name","LORD"],"peopleInVerse":[],"themesInVerse":["fall_sin","kingship","wisdom"]},"58":{"text":"Thus saith the LORD of hosts; The broad walls of Babylon shall be utterly broken, and her high gates shall be burned with fire; and the people shall labour in vain, and the folk in the fire, and they shall be weary.","ref":"Jeremiah 51:58","synthesized":"This is what the LORD of Hosts says:  “Babylon’s thick walls will be leveled, and her high gates consumed by fire. So the labor of the people will be for nothing; the nations will exhaust themselves to fuel the flames.”","sources":{"KJV":{"text":"Thus saith the LORD of hosts; The broad walls of Babylon shall be utterly broken, and her high gates shall be burned with fire; and the people shall labour in vain, and the folk in the fire, and they shall be weary."},"BSB":{"text":"This is what the LORD of Hosts says:  “Babylon’s thick walls will be leveled, and her high gates consumed by fire. So the labor of the people will be for nothing; the nations will exhaust themselves to fuel the flames.”"},"TANAKH":{"text":"Thus saith HaShem of hosts: the broad walls of Babylon shall be utterly overthrown, and her high gates shall be burned with fire; and the peoples shall labour for vanity, and the nations for the fire; and they shall be weary."},"HEBREW":{"text":"כֹּֽה־אָמַ֞ר יְהוָ֣ה צְבָא֗וֹת חֹ֠מוֹת בָּבֶ֤ל הָֽרְחָבָה֙ עַרְעֵ֣ר תִּתְעַרְעָ֔ר וּשְׁעָרֶ֥יהָ הַגְּבֹהִ֖ים בָּאֵ֣שׁ יִצַּ֑תּוּ וְיִֽגְע֨וּ עַמִּ֧ים בְּדֵי־רִ֛יק וּלְאֻמִּ֥ים בְּדֵי־אֵ֖שׁ וְיָעֵֽפוּ׃"}},"definableWords":["LORD","Babylon","people","nations"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"59":{"text":"The word which Jeremiah the prophet commanded Seraiah the son of Neriah, the son of Maaseiah, when he went with Zedekiah the king of Judah into Babylon in the fourth year of his reign. And this Seraiah was a quiet prince.","ref":"Jeremiah 51:59","synthesized":"This is the message that Jeremiah the prophet gave to the quartermaster Seraiah son of Neriah, the son of Mahseiah, when he went to Babylon with King Zedekiah of Judah in the fourth year of Zedekiah’s reign.","sources":{"KJV":{"text":"The word which Jeremiah the prophet commanded Seraiah the son of Neriah, the son of Maaseiah, when he went with Zedekiah the king of Judah into Babylon in the fourth year of his reign. And this Seraiah was a quiet prince."},"BSB":{"text":"This is the message that Jeremiah the prophet gave to the quartermaster Seraiah son of Neriah, the son of Mahseiah, when he went to Babylon with King Zedekiah of Judah in the fourth year of Zedekiah’s reign."},"TANAKH":{"text":"The word which Jeremiah the prophet commanded Seraiah the son of Neriah, the son of Mahseiah, when he went with Zedekiah the king of Judah to Babylon in the fourth year of his reign. Now Seraiah was quartermaster."},"HEBREW":{"text":"הַדָּבָ֞ר אֲשֶׁר־צִוָּ֣ה ׀ יִרְמְיָ֣הוּ הַנָּבִ֗יא אֶת־שְׂרָיָ֣ה בֶן־נֵרִיָּה֮ בֶּן־מַחְסֵיָה֒ בְּלֶכְתּ֞וֹ אֶת־צִדְקִיָּ֤הוּ מֶֽלֶךְ־יְהוּדָה֙ בָּבֶ֔ל בִּשְׁנַ֥ת הָרְבִעִ֖ית לְמָלְכ֑וֹ וּשְׂרָיָ֖ה שַׂ֥ר מְנוּחָֽה׃"}},"definableWords":["prophet","son","Son","Babylon","King","Judah","year","reign"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Babylon"],"themesInVerse":["kingdom_of_god","kingship"]},"60":{"text":"So Jeremiah wrote in a book all the evil that should come upon Babylon, even all these words that are written against Babylon.","ref":"Jeremiah 51:60","synthesized":"Jeremiah had written on a single scroll about all the disaster that would come upon Babylon—all these words that had been written concerning Babylon.","sources":{"KJV":{"text":"So Jeremiah wrote in a book all the evil that should come upon Babylon, even all these words that are written against Babylon."},"BSB":{"text":"Jeremiah had written on a single scroll about all the disaster that would come upon Babylon—all these words that had been written concerning Babylon."},"TANAKH":{"text":"And Jeremiah wrote in one book all the evil that should come upon Babylon, even all these words that are written concerning Babylon."},"HEBREW":{"text":"וַיִּכְתֹּ֣ב יִרְמְיָ֗הוּ אֵ֧ת כָּל־הָרָעָ֛ה אֲשֶׁר־תָּב֥וֹא אֶל־בָּבֶ֖ל אֶל־סֵ֣פֶר אֶחָ֑ד אֵ֚ת כָּל־הַדְּבָרִ֣ים הָאֵ֔לֶּה הַכְּתֻבִ֖ים אֶל־בָּבֶֽל׃"}},"definableWords":["Babylon"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Babylon"]},"61":{"text":"And Jeremiah said to Seraiah, When thou comest to Babylon, and shalt see, and shalt read all these words;","ref":"Jeremiah 51:61","synthesized":"And Jeremiah said to Seraiah, “When you get to Babylon, see that you read all these words aloud,","sources":{"KJV":{"text":"And Jeremiah said to Seraiah, When thou comest to Babylon, and shalt see, and shalt read all these words;"},"BSB":{"text":"And Jeremiah said to Seraiah, “When you get to Babylon, see that you read all these words aloud,"},"TANAKH":{"text":"And Jeremiah said to Seraiah: 'When thou comest to Babylon, then see that thou read all these words,"},"HEBREW":{"text":"וַיֹּ֥אמֶר יִרְמְיָ֖הוּ אֶל־שְׂרָיָ֑ה כְּבֹאֲךָ֣ בָבֶ֔ל וְֽרָאִ֔יתָ וְֽקָרָ֔אתָ אֵ֥ת כָּל־הַדְּבָרִ֖ים הָאֵֽלֶּה׃"}},"definableWords":["Babylon","see"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Babylon"]},"62":{"text":"Then shalt thou say, O LORD, thou hast spoken against this place, to cut it off, that none shall remain in it, neither man nor beast, but that it shall be desolate for ever.","ref":"Jeremiah 51:62","synthesized":"and say, ‘O LORD, You have promised to cut off this place so that no one will remain—neither man nor beast. Indeed, it will be desolate forever.’","sources":{"KJV":{"text":"Then shalt thou say, O LORD, thou hast spoken against this place, to cut it off, that none shall remain in it, neither man nor beast, but that it shall be desolate for ever."},"BSB":{"text":"and say, ‘O LORD, You have promised to cut off this place so that no one will remain—neither man nor beast. Indeed, it will be desolate forever.’"},"TANAKH":{"text":"and say: O HaShem, Thou hast spoken concerning this place, to cut it off, that none shall dwell therein, neither man nor beast, but that it shall be desolate for ever."},"HEBREW":{"text":"וְאָמַרְתָּ֗ יְהוָה֙ אַתָּ֨ה דִבַּ֜רְתָּ אֶל־הַמָּק֤וֹם הַזֶּה֙ לְהַכְרִית֔וֹ לְבִלְתִּ֤י הֱיֽוֹת־בּוֹ֙ יוֹשֵׁ֔ב לְמֵאָדָ֖ם וְעַד־בְּהֵמָ֑ה כִּֽי־שִׁמְמ֥וֹת עוֹלָ֖ם תִּֽהְיֶֽה׃"}},"definableWords":["LORD","one","man"],"peopleInVerse":[]},"63":{"text":"And it shall be, when thou hast made an end of reading this book, that thou shalt bind a stone to it, and cast it into the midst of Euphrates:","ref":"Jeremiah 51:63","synthesized":"When you finish reading this scroll, tie a stone to it and cast it into the Euphrates.","sources":{"KJV":{"text":"And it shall be, when thou hast made an end of reading this book, that thou shalt bind a stone to it, and cast it into the midst of Euphrates:"},"BSB":{"text":"When you finish reading this scroll, tie a stone to it and cast it into the Euphrates."},"TANAKH":{"text":"And it shall be, when thou hast made an end of reading this book, that thou shalt bind a stone to it, and cast it into the midst of the Euphrates;"},"HEBREW":{"text":"וְהָיָה֙ כְּכַלֹּ֣תְךָ֔ לִקְרֹ֖א אֶת־הַסֵּ֣פֶר הַזֶּ֑ה תִּקְשֹׁ֤ר עָלָיו֙ אֶ֔בֶן וְהִשְׁלַכְתּ֖וֹ אֶל־תּ֥וֹךְ פְּרָֽת׃"}},"definableWords":["stone"],"peopleInVerse":[]},"64":{"text":"And thou shalt say, Thus shall Babylon sink, and shall not rise from the evil that I will bring upon her: and they shall be weary. Thus far are the words of Jeremiah.","ref":"Jeremiah 51:64","synthesized":"Then you are to say, ‘In the same way Babylon will sink and never rise again, because of the disaster I will bring upon her. And her people will grow weary.’”  Here end the words of Jeremiah.","sources":{"KJV":{"text":"And thou shalt say, Thus shall Babylon sink, and shall not rise from the evil that I will bring upon her: and they shall be weary. Thus far are the words of Jeremiah."},"BSB":{"text":"Then you are to say, ‘In the same way Babylon will sink and never rise again, because of the disaster I will bring upon her. And her people will grow weary.’”  Here end the words of Jeremiah."},"TANAKH":{"text":"and thou shalt say: Thus shall Babylon sink, and shall not rise again because of the evil that I will bring upon her; and they shall be weary.' Thus far are the words of Jeremiah."},"HEBREW":{"text":"וְאָמַרְתָּ֗ כָּ֠כָה תִּשְׁקַ֨ע בָּבֶ֤ל וְלֹֽא־תָקוּם֙ מִפְּנֵ֣י הָרָעָ֗ה אֲשֶׁ֧ר אָנֹכִ֛י מֵבִ֥יא עָלֶ֖יהָ וְיָעֵ֑פוּ עַד־הֵ֖נָּה דִּבְרֵ֥י יִרְמְיָֽהוּ׃"}},"definableWords":["way","Babylon","people"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Babylon"],"themesInVerse":["resurrection"]}}},"52":{"chapter":"52","title":"FALL OF JERUSALEM AGAIN — THE FINAL CHAPTER","verses":{"1":{"text":"Zedekiah was one and twenty years old when he began to reign, and he reigned eleven years in Jerusalem. And his mother’s name was Hamutal the daughter of Jeremiah of Libnah.","ref":"Jeremiah 52:1","synthesized":"Zedekiah was twenty-one years old when he became king, and he reigned in Jerusalem eleven years. His mother’s name was Hamutal daughter of Jeremiah; she was from Libnah.","sources":{"KJV":{"text":"Zedekiah was one and twenty years old when he began to reign, and he reigned eleven years in Jerusalem. And his mother’s name was Hamutal the daughter of Jeremiah of Libnah."},"BSB":{"text":"Zedekiah was twenty-one years old when he became king, and he reigned in Jerusalem eleven years. His mother’s name was Hamutal daughter of Jeremiah; she was from Libnah."},"TANAKH":{"text":"Zedekiah was one and twenty years old when he began to reign; and he reigned eleven years in Jerusalem; and his mother's name was Hamutal the daughter of Jeremiah of Libnah."},"HEBREW":{"text":"בֶּן־עֶשְׂרִ֨ים וְאַחַ֤ת שָׁנָה֙ צִדְקִיָּ֣הוּ בְמָלְכ֔וֹ וְאַחַ֤ת עֶשְׂרֵה֙ שָׁנָ֔ה מָלַ֖ךְ בִּירֽוּשָׁלָ֑͏ִם וְשֵׁ֣ם אִמּ֔וֹ חמיטל חֲמוּטַ֥ל בַּֽת־יִרְמְיָ֖הוּ מִלִּבְנָֽה׃"}},"definableWords":["one","years","king","Jerusalem","mother","name","daughter"],"peopleInVerse":["Jeremiah"],"placesInVerse":["Jerusalem"],"themesInVerse":["kingship"]},"2":{"text":"And he did that which was evil in the eyes of the LORD, according to all that Jehoiakim had done.","ref":"Jeremiah 52:2","synthesized":"And Zedekiah did evil in the sight of the LORD, just as Jehoiakim had done.","sources":{"KJV":{"text":"And he did that which was evil in the eyes of the LORD, according to all that Jehoiakim had done."},"BSB":{"text":"And Zedekiah did evil in the sight of the LORD, just as Jehoiakim had done."},"TANAKH":{"text":"And he did that which was evil in the sight of HaShem, according to all that Jehoiakim had done."},"HEBREW":{"text":"וַיַּ֥עַשׂ הָרַ֖ע בְּעֵינֵ֣י יְהוָ֑ה כְּכֹ֥ל אֲשֶׁר־עָשָׂ֖ה יְהוֹיָקִֽים׃"}},"definableWords":["evil","LORD"],"peopleInVerse":[]},"3":{"text":"For through the anger of the LORD it came to pass in Jerusalem and Judah, till he had cast them out from his presence, that Zedekiah rebelled against the king of Babylon.","ref":"Jeremiah 52:3","synthesized":"For because of the anger of the LORD, all this happened in Jerusalem and Judah, until He finally banished them from His presence.  And Zedekiah also rebelled against the king of Babylon.","sources":{"KJV":{"text":"For through the anger of the LORD it came to pass in Jerusalem and Judah, till he had cast them out from his presence, that Zedekiah rebelled against the king of Babylon."},"BSB":{"text":"For because of the anger of the LORD, all this happened in Jerusalem and Judah, until He finally banished them from His presence.  And Zedekiah also rebelled against the king of Babylon."},"TANAKH":{"text":"For through the anger of HaShem did it come to pass in Jerusalem and Judah, until He had cast them out from His presence. And Zedekiah rebelled against the king of Babylon."},"HEBREW":{"text":"כִּ֣י ׀ עַל־אַ֣ף יְהוָ֗ה הָֽיְתָה֙ בִּירוּשָׁלַ֣͏ִם וִֽיהוּדָ֔ה עַד־הִשְׁלִיכ֥וֹ אוֹתָ֖ם מֵעַ֣ל פָּנָ֑יו וַיִּמְרֹ֥ד צִדְקִיָּ֖הוּ בְּמֶ֥לֶךְ בָּבֶֽל׃"}},"definableWords":["anger","LORD","Jerusalem","Judah","king","Babylon"],"peopleInVerse":[],"placesInVerse":["Jerusalem","Babylon"],"themesInVerse":["kingship"]},"4":{"text":"And it came to pass in the ninth year of his reign, in the tenth month, in the tenth day of the month, that Nebuchadrezzar king of Babylon came, he and all his army, against Jerusalem, and pitched against it, and built forts against it round about.","ref":"Jeremiah 52:4","synthesized":"So in the ninth year of Zedekiah’s reign, on the tenth day of the tenth month, Nebuchadnezzar king of Babylon marched against Jerusalem with his entire army. They encamped outside the city and built a siege wall all around it.","sources":{"KJV":{"text":"And it came to pass in the ninth year of his reign, in the tenth month, in the tenth day of the month, that Nebuchadrezzar king of Babylon came, he and all his army, against Jerusalem, and pitched against it, and built forts against it round about."},"BSB":{"text":"So in the ninth year of Zedekiah’s reign, on the tenth day of the tenth month, Nebuchadnezzar king of Babylon marched against Jerusalem with his entire army. They encamped outside the city and built a siege wall all around it."},"TANAKH":{"text":"And it came to pass in the ninth year of his reign, in the tenth month, in the tenth day of the month, that Nebuchadrezzar king of Babylon came, he and all his army, against Jerusalem, and encamped against it; and they built forts against it round about."},"HEBREW":{"text":"וַיְהִי֩ בַשָּׁנָ֨ה הַתְּשִׁעִ֜ית לְמָלְכ֗וֹ בַּחֹ֣דֶשׁ הָעֲשִׂירִי֮ בֶּעָשׂ֣וֹר לַחֹדֶשׁ֒ בָּ֠א נְבוּכַדְרֶאצַּ֨ר מֶֽלֶךְ־בָּבֶ֜ל ה֤וּא וְכָל־חֵילוֹ֙ עַל־יְר֣וּשָׁלִַ֔ם וַֽיַּחֲנ֖וּ עָלֶ֑יהָ וַיִּבְנ֥וּ עָלֶ֛יהָ דָּיֵ֖ק סָבִֽיב׃"}},"definableWords":["year","reign","day","king","Babylon","Jerusalem"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon","Jerusalem"],"themesInVerse":["kingdom_of_god","kingship"]},"5":{"text":"So the city was besieged unto the eleventh year of king Zedekiah.","ref":"Jeremiah 52:5","synthesized":"And the city was kept under siege until King Zedekiah’s eleventh year.","sources":{"KJV":{"text":"So the city was besieged unto the eleventh year of king Zedekiah."},"BSB":{"text":"And the city was kept under siege until King Zedekiah’s eleventh year."},"TANAKH":{"text":"So the city was besieged unto the eleventh year of king Zedekiah."},"HEBREW":{"text":"וַתָּבֹ֥א הָעִ֖יר בַּמָּצ֑וֹר עַ֚ד עַשְׁתֵּ֣י עֶשְׂרֵ֣ה שָׁנָ֔ה לַמֶּ֖לֶךְ צִדְקִיָּֽהוּ׃"}},"definableWords":["King","year"],"peopleInVerse":[],"themesInVerse":["kingship"]},"6":{"text":"And in the fourth month, in the ninth day of the month, the famine was sore in the city, so that there was no bread for the people of the land.","ref":"Jeremiah 52:6","synthesized":"By the ninth day of the fourth month, the famine in the city was so severe that the people of the land had no food.","sources":{"KJV":{"text":"And in the fourth month, in the ninth day of the month, the famine was sore in the city, so that there was no bread for the people of the land."},"BSB":{"text":"By the ninth day of the fourth month, the famine in the city was so severe that the people of the land had no food."},"TANAKH":{"text":"In the fourth month, in the ninth day of the month, the famine was sore in the city, so that there was no bread for the people of the land."},"HEBREW":{"text":"בַּחֹ֤דֶשׁ הָֽרְבִיעִי֙ בְּתִשְׁעָ֣ה לַחֹ֔דֶשׁ וַיֶּחֱזַ֥ק הָרָעָ֖ב בָּעִ֑יר וְלֹא־הָיָ֥ה לֶ֖חֶם לְעַ֥ם הָאָֽרֶץ׃"}},"definableWords":["day","people","land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"7":{"text":"Then the city was broken up, and all the men of war fled, and went forth out of the city by night by the way of the gate between the two walls, which was by the king’s garden; (now the Chaldeans were by the city round about:) and they went by the way of the plain.","ref":"Jeremiah 52:7","synthesized":"Then the city was breached; and though the Chaldeans had surrounded the city, all the men of war fled the city by night by way of the gate between the two walls near the king’s garden.  They headed toward the Arabah,","sources":{"KJV":{"text":"Then the city was broken up, and all the men of war fled, and went forth out of the city by night by the way of the gate between the two walls, which was by the king’s garden; (now the Chaldeans were by the city round about:) and they went by the way of the plain."},"BSB":{"text":"Then the city was breached; and though the Chaldeans had surrounded the city, all the men of war fled the city by night by way of the gate between the two walls near the king’s garden.  They headed toward the Arabah,"},"TANAKH":{"text":"Then a breach was made in the city, and all the men of war fled, and went forth out of the city by night by the way of the gate between the two walls, which was by the king's garden--now the Chaldeans were against the city round about--and they went by the way of the Arabah."},"HEBREW":{"text":"וַתִּבָּקַ֣ע הָעִ֗יר וְכָל־אַנְשֵׁ֣י הַמִּלְחָמָ֡ה יִבְרְחוּ֩ וַיֵּצְא֨וּ מֵהָעִ֜יר לַ֗יְלָה דֶּ֜רֶךְ שַׁ֤עַר בֵּין־הַחֹמֹתַ֙יִם֙ אֲשֶׁר֙ עַל־גַּ֣ן הַמֶּ֔לֶךְ וְכַשְׂדִּ֥ים עַל־הָעִ֖יר סָבִ֑יב וַיֵּלְכ֖וּ דֶּ֥רֶךְ הָעֲרָבָֽה׃"}},"definableWords":["men","night","way","king","garden"],"peopleInVerse":[],"themesInVerse":["kingship"]},"8":{"text":"But the army of the Chaldeans pursued after the king, and overtook Zedekiah in the plains of Jericho; and all his army was scattered from him.","ref":"Jeremiah 52:8","synthesized":"but the army of the Chaldeans pursued the king and overtook Zedekiah in the plains of Jericho, and all his army was separated from him.","sources":{"KJV":{"text":"But the army of the Chaldeans pursued after the king, and overtook Zedekiah in the plains of Jericho; and all his army was scattered from him."},"BSB":{"text":"but the army of the Chaldeans pursued the king and overtook Zedekiah in the plains of Jericho, and all his army was separated from him."},"TANAKH":{"text":"But the army of the Chaldeans pursued after the king, and overtook Zedekiah in the plains of Jericho; and all his army was scattered from him."},"HEBREW":{"text":"וַיִּרְדְּפ֤וּ חֵיל־כַּשְׂדִּים֙ אַחֲרֵ֣י הַמֶּ֔לֶךְ וַיַּשִּׂ֥יגוּ אֶת־צִדְקִיָּ֖הוּ בְּעַֽרְבֹ֣ת יְרֵח֑וֹ וְכָל־חֵיל֔וֹ נָפֹ֖צוּ מֵעָלָֽיו׃"}},"definableWords":["king"],"peopleInVerse":[],"placesInVerse":["Jericho"],"themesInVerse":["kingship"]},"9":{"text":"Then they took the king, and carried him up unto the king of Babylon to Riblah in the land of Hamath; where he gave judgment upon him.","ref":"Jeremiah 52:9","synthesized":"The Chaldeans seized the king and brought him up to the king of Babylon at Riblah in the land of Hamath, where he pronounced judgment on Zedekiah.","sources":{"KJV":{"text":"Then they took the king, and carried him up unto the king of Babylon to Riblah in the land of Hamath; where he gave judgment upon him."},"BSB":{"text":"The Chaldeans seized the king and brought him up to the king of Babylon at Riblah in the land of Hamath, where he pronounced judgment on Zedekiah."},"TANAKH":{"text":"Then they took the king, and carried him up unto the king of Babylon to Riblah in the land of Hamath; and he gave judgment upon him."},"HEBREW":{"text":"וַֽיִּתְפְּשׂוּ֙ אֶת־הַמֶּ֔לֶךְ וַיַּעֲל֨וּ אֹת֜וֹ אֶל־מֶ֧לֶךְ בָּבֶ֛ל רִבְלָ֖תָה בְּאֶ֣רֶץ חֲמָ֑ת וַיְדַבֵּ֥ר אִתּ֖וֹ מִשְׁפָּטִֽים׃"}},"definableWords":["king","King","Babylon","land","judgment"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["judgment","kingship","land_promise"]},"10":{"text":"And the king of Babylon slew the sons of Zedekiah before his eyes: he slew also all the princes of Judah in Riblah.","ref":"Jeremiah 52:10","synthesized":"There at Riblah the king of Babylon slaughtered the sons of Zedekiah before his eyes, and he also killed all the officials of Judah.","sources":{"KJV":{"text":"And the king of Babylon slew the sons of Zedekiah before his eyes: he slew also all the princes of Judah in Riblah."},"BSB":{"text":"There at Riblah the king of Babylon slaughtered the sons of Zedekiah before his eyes, and he also killed all the officials of Judah."},"TANAKH":{"text":"And the king of Babylon slew the sons of Zedekiah before his eyes; he slew also all the princes of Judah in Riblah."},"HEBREW":{"text":"וַיִּשְׁחַ֧ט מֶֽלֶךְ־בָּבֶ֛ל אֶת־בְּנֵ֥י צִדְקִיָּ֖הוּ לְעֵינָ֑יו וְגַ֛ם אֶת־כָּל־שָׂרֵ֥י יְהוּדָ֖ה שָׁחַ֥ט בְּרִבְלָֽתָה׃"}},"definableWords":["king","Babylon","sons","Judah"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"11":{"text":"Then he put out the eyes of Zedekiah; and the king of Babylon bound him in chains, and carried him to Babylon, and put him in prison till the day of his death.","ref":"Jeremiah 52:11","synthesized":"Then he put out Zedekiah’s eyes, bound him with bronze shackles, and took him to Babylon, where he kept him in custody until his dying day.","sources":{"KJV":{"text":"Then he put out the eyes of Zedekiah; and the king of Babylon bound him in chains, and carried him to Babylon, and put him in prison till the day of his death."},"BSB":{"text":"Then he put out Zedekiah’s eyes, bound him with bronze shackles, and took him to Babylon, where he kept him in custody until his dying day."},"TANAKH":{"text":"And he put out the eyes of Zedekiah; and the king of Babylon bound him in fetters, and carried him to Babylon, and put him in prison till the day of his death."},"HEBREW":{"text":"וְאֶת־עֵינֵ֥י צִדְקִיָּ֖הוּ עִוֵּ֑ר וַיַּאַסְרֵ֣הוּ בַֽנְחֻשְׁתַּ֗יִם וַיְבִאֵ֤הוּ מֶֽלֶךְ־בָּבֶל֙ בָּבֶ֔לָה וַיִּתְּנֵ֥הוּ בבית־בֵֽית־הַפְּקֻדֹּ֖ת עַד־י֥וֹם מוֹתֽוֹ׃"}},"definableWords":["Babylon","day"],"peopleInVerse":[],"placesInVerse":["Babylon"]},"12":{"text":"Now in the fifth month, in the tenth day of the month, which was the nineteenth year of Nebuchadrezzar king of Babylon, came Nebuzaradan, captain of the guard, which served the king of Babylon, into Jerusalem,","ref":"Jeremiah 52:12","synthesized":"On the tenth day of the fifth month, in the nineteenth year of Nebuchadnezzar’s reign over Babylon, Nebuzaradan captain of the guard, a servant of the king of Babylon, entered Jerusalem.","sources":{"KJV":{"text":"Now in the fifth month, in the tenth day of the month, which was the nineteenth year of Nebuchadrezzar king of Babylon, came Nebuzaradan, captain of the guard, which served the king of Babylon, into Jerusalem,"},"BSB":{"text":"On the tenth day of the fifth month, in the nineteenth year of Nebuchadnezzar’s reign over Babylon, Nebuzaradan captain of the guard, a servant of the king of Babylon, entered Jerusalem."},"TANAKH":{"text":"Now in the fifth month, in the tenth day of the month, which was the nineteenth year of king Nebuchadrezzar, king of Babylon, came Nebuzaradan the captain of the guard, who stood before the king of Babylon, into Jerusalem;"},"HEBREW":{"text":"וּבַחֹ֤דֶשׁ הֽ͏ַחֲמִישִׁי֙ בֶּעָשׂ֣וֹר לַחֹ֔דֶשׁ הִ֗יא שְׁנַת֙ תְּשַֽׁע־עֶשְׂרֵ֣ה שָׁנָ֔ה לַמֶּ֖לֶךְ נְבוּכַדְרֶאצַּ֣ר מֶֽלֶךְ־בָּבֶ֑ל בָּ֗א נְבֽוּזַרְאֲדָן֙ רַב־טַבָּחִ֔ים עָמַ֛ד לִפְנֵ֥י מֶֽלֶךְ־בָּבֶ֖ל בִּירוּשָׁלָֽ͏ִם׃"}},"definableWords":["day","year","reign","Babylon","servant","king","Jerusalem"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Babylon","Jerusalem"],"themesInVerse":["kingdom_of_god","kingship"]},"13":{"text":"And burned the house of the LORD, and the king’s house; and all the houses of Jerusalem, and all the houses of the great men, burned he with fire:","ref":"Jeremiah 52:13","synthesized":"He burned down the house of the LORD, the royal palace, and all the houses of Jerusalem—every significant building.","sources":{"KJV":{"text":"And burned the house of the LORD, and the king’s house; and all the houses of Jerusalem, and all the houses of the great men, burned he with fire:"},"BSB":{"text":"He burned down the house of the LORD, the royal palace, and all the houses of Jerusalem—every significant building."},"TANAKH":{"text":"and he burned the house of HaShem, and the king's house; and all the houses of Jerusalem, even every great man's house, burned he with fire."},"HEBREW":{"text":"וַיִּשְׂרֹ֥ף אֶת־בֵּית־יְהוָ֖ה וְאֶת־בֵּ֣ית הַמֶּ֑לֶךְ וְאֵ֨ת כָּל־בָּתֵּ֧י יְרוּשָׁלַ֛͏ִם וְאֶת־כָּל־בֵּ֥ית הַגָּד֖וֹל שָׂרַ֥ף בָּאֵֽשׁ׃"}},"definableWords":["house","LORD","Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"14":{"text":"And all the army of the Chaldeans, that were with the captain of the guard, brake down all the walls of Jerusalem round about.","ref":"Jeremiah 52:14","synthesized":"And the whole army of the Chaldeans under the captain of the guard broke down all the walls around Jerusalem.","sources":{"KJV":{"text":"And all the army of the Chaldeans, that were with the captain of the guard, brake down all the walls of Jerusalem round about."},"BSB":{"text":"And the whole army of the Chaldeans under the captain of the guard broke down all the walls around Jerusalem."},"TANAKH":{"text":"And all the army of the Chaldeans, that were with the captain of the guard, broke down all the walls of Jerusalem round about."},"HEBREW":{"text":"וְאֶת־כָּל־חֹמ֥וֹת יְרוּשָׁלַ֖͏ִם סָבִ֑יב נָֽתְצוּ֙ כָּל־חֵ֣יל כַּשְׂדִּ֔ים אֲשֶׁ֖ר אֶת־רַב־טַבָּחִֽים׃"}},"definableWords":["Jerusalem"],"peopleInVerse":[],"placesInVerse":["Jerusalem"]},"15":{"text":"Then Nebuzaradan the captain of the guard carried away captive certain of the poor of the people, and the residue of the people that remained in the city, and those that fell away, that fell to the king of Babylon, and the rest of the multitude.","ref":"Jeremiah 52:15","synthesized":"Then Nebuzaradan captain of the guard carried into exile some of the poorest people and those who remained in the city, along with the deserters who had defected to the king of Babylon and the rest of the craftsmen.","sources":{"KJV":{"text":"Then Nebuzaradan the captain of the guard carried away captive certain of the poor of the people, and the residue of the people that remained in the city, and those that fell away, that fell to the king of Babylon, and the rest of the multitude."},"BSB":{"text":"Then Nebuzaradan captain of the guard carried into exile some of the poorest people and those who remained in the city, along with the deserters who had defected to the king of Babylon and the rest of the craftsmen."},"TANAKH":{"text":"Then Nebuzaradan the captain of the guard carried away captive of the poorest sort of the people, and the residue of the people that remained in the city, and those that fell away, that fell to the king of Babylon, and the residue of the multitude."},"HEBREW":{"text":"וּמִדַּלּ֨וֹת הָעָ֜ם וְֽאֶת־יֶ֥תֶר הָעָ֣ם ׀ הַנִּשְׁאָרִ֣ים בָּעִ֗יר וְאֶת־הַנֹּֽפְלִים֙ אֲשֶׁ֤ר נָֽפְלוּ֙ אֶל־מֶ֣לֶךְ בָּבֶ֔ל וְאֵ֖ת יֶ֣תֶר הָֽאָמ֑וֹן הֶגְלָ֕ה נְבוּזַרְאֲדָ֖ן רַב־טַבָּחִֽים׃"}},"definableWords":["people","king","Babylon","rest"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["exile_return","kingship","peace","sabbath_rest"]},"16":{"text":"But Nebuzaradan the captain of the guard left certain of the poor of the land for vinedressers and for husbandmen.","ref":"Jeremiah 52:16","synthesized":"But Nebuzaradan captain of the guard left behind some of the poorest of the land to tend the vineyards and fields.","sources":{"KJV":{"text":"But Nebuzaradan the captain of the guard left certain of the poor of the land for vinedressers and for husbandmen."},"BSB":{"text":"But Nebuzaradan captain of the guard left behind some of the poorest of the land to tend the vineyards and fields."},"TANAKH":{"text":"But Nebuzaradan the captain of the guard left of the poorest of the land to be vinedressers and husbandmen."},"HEBREW":{"text":"וּמִדַּלּ֣וֹת הָאָ֔רֶץ הִשְׁאִ֕יר נְבוּזַרְאֲדָ֖ן רַב־טַבָּחִ֑ים לְכֹרְמִ֖ים וּלְיֹגְבִֽים׃"}},"definableWords":["land"],"peopleInVerse":[],"themesInVerse":["land_promise"]},"17":{"text":"Also the pillars of brass that were in the house of the LORD, and the bases, and the brasen sea that was in the house of the LORD, the Chaldeans brake, and carried all the brass of them to Babylon.","ref":"Jeremiah 52:17","synthesized":"Moreover, the Chaldeans broke up the bronze pillars and stands and the bronze Sea in the house of the LORD, and they carried all the bronze to Babylon.","sources":{"KJV":{"text":"Also the pillars of brass that were in the house of the LORD, and the bases, and the brasen sea that was in the house of the LORD, the Chaldeans brake, and carried all the brass of them to Babylon."},"BSB":{"text":"Moreover, the Chaldeans broke up the bronze pillars and stands and the bronze Sea in the house of the LORD, and they carried all the bronze to Babylon."},"TANAKH":{"text":"And the pillars of brass that were in the house of HaShem, and the bases and the brazen sea that were in the house of HaShem, did the Chaldeans break in pieces, and carried all the brass of them to Babylon."},"HEBREW":{"text":"וְאֶת־עַמּוּדֵ֨י הַנְּחֹ֜שֶׁת אֲשֶׁ֣ר לְבֵית־יְהוָ֗ה וְֽאֶת־הַמְּכֹנ֞וֹת וְאֶת־יָ֧ם הַנְּחֹ֛שֶׁת אֲשֶׁ֥ר בְּבֵית־יְהוָ֖ה שִׁבְּר֣וּ כַשְׂדִּ֑ים וַיִּשְׂא֥וּ אֶת־כָּל־נְחֻשְׁתָּ֖ם בָּבֶֽלָה׃"}},"definableWords":["sea","house","LORD","Babylon"],"peopleInVerse":[],"placesInVerse":["Dead Sea","Babylon"]},"18":{"text":"The caldrons also, and the shovels, and the snuffers, and the bowls, and the spoons, and all the vessels of brass wherewith they ministered, took they away.","ref":"Jeremiah 52:18","synthesized":"They also took away the pots, shovels, wick trimmers, sprinkling bowls, dishes, and all the articles of bronze used in the temple service.","sources":{"KJV":{"text":"The caldrons also, and the shovels, and the snuffers, and the bowls, and the spoons, and all the vessels of brass wherewith they ministered, took they away."},"BSB":{"text":"They also took away the pots, shovels, wick trimmers, sprinkling bowls, dishes, and all the articles of bronze used in the temple service."},"TANAKH":{"text":"The pots also, and the shovels, and the snuffers, and the basins, and the pans, and all the vessels of brass wherewith they ministered, took they away."},"HEBREW":{"text":"וְאֶת־הַ֠סִּרוֹת וְאֶת־הַיָּעִ֨ים וְאֶת־הַֽמְזַמְּר֜וֹת וְאֶת־הַמִּזְרָקֹ֣ת וְאֶת־הַכַּפּ֗וֹת וְאֵ֨ת כָּל־כְּלֵ֧י הַנְּחֹ֛שֶׁת אֲשֶׁר־יְשָׁרְת֥וּ בָהֶ֖ם לָקָֽחוּ׃"}},"definableWords":["temple"],"peopleInVerse":[],"themesInVerse":["temple"]},"19":{"text":"And the basons, and the firepans, and the bowls, and the caldrons, and the candlesticks, and the spoons, and the cups; that which was of gold in gold, and that which was of silver in silver, took the captain of the guard away.","ref":"Jeremiah 52:19","synthesized":"The captain of the guard also took away the basins, censers, sprinkling bowls, pots, lampstands, pans, and drink offering bowls—anything made of pure gold or fine silver.","sources":{"KJV":{"text":"And the basons, and the firepans, and the bowls, and the caldrons, and the candlesticks, and the spoons, and the cups; that which was of gold in gold, and that which was of silver in silver, took the captain of the guard away."},"BSB":{"text":"The captain of the guard also took away the basins, censers, sprinkling bowls, pots, lampstands, pans, and drink offering bowls—anything made of pure gold or fine silver."},"TANAKH":{"text":"And the cups, and the fire-pans, and the basins, and the pots, and the candlesticks, and the pans, and the bowls--that which was of gold, in gold, and that which was of silver, in silver--the captain of the guard took away."},"HEBREW":{"text":"וְאֶת־הַ֠סִּפִּים וְאֶת־הַמַּחְתּ֨וֹת וְאֶת־הַמִּזְרָק֜וֹת וְאֶת־הַסִּיר֣וֹת וְאֶת־הַמְּנֹר֗וֹת וְאֶת־הַכַּפּוֹת֙ וְאֶת־הַמְּנַקִי֔וֹת אֲשֶׁ֤ר זָהָב֙ זָהָ֔ב וַאֲשֶׁר־כֶּ֖סֶף כָּ֑סֶף לָקַ֖ח רַב־טַבָּחִֽים׃"}},"definableWords":["offering","made","or"],"peopleInVerse":[],"themesInVerse":["creation","sacrifice"]},"20":{"text":"The two pillars, one sea, and twelve brasen bulls that were under the bases, which king Solomon had made in the house of the LORD: the brass of all these vessels was without weight.","ref":"Jeremiah 52:20","synthesized":"As for the two pillars, the Sea, the twelve bronze bulls under it, and the movable stands that King Solomon had made for the house of the LORD, the weight of the bronze from all these articles was beyond measure.","sources":{"KJV":{"text":"The two pillars, one sea, and twelve brasen bulls that were under the bases, which king Solomon had made in the house of the LORD: the brass of all these vessels was without weight."},"BSB":{"text":"As for the two pillars, the Sea, the twelve bronze bulls under it, and the movable stands that King Solomon had made for the house of the LORD, the weight of the bronze from all these articles was beyond measure."},"TANAKH":{"text":"The two pillars, the one sea, and the twelve brazen bulls that were under the bases, which king Solomon had made for the house of HaShem--the brass of all these vessels was without weight."},"HEBREW":{"text":"הָעַמּוּדִ֣ים ׀ שְׁנַ֗יִם הַיָּ֤ם אֶחָד֙ וְהַבָּקָ֞ר שְׁנֵים־עָשָׂ֤ר נְחֹ֙שֶׁת֙ אֲשֶׁר־תַּ֣חַת הַמְּכֹנ֔וֹת אֲשֶׁ֥ר עָשָׂ֛ה הַמֶּ֥לֶךְ שְׁלֹמֹ֖ה לְבֵ֣ית יְהוָ֑ה לֹא־הָיָ֣ה מִשְׁקָ֔ל לִנְחֻשְׁתָּ֖ם כָּל־הַכֵּלִ֥ים הָאֵֽלֶּה׃"}},"definableWords":["sea","King","made","house","LORD"],"peopleInVerse":["Solomon"],"placesInVerse":["Dead Sea"],"themesInVerse":["creation","kingship"]},"21":{"text":"And concerning the pillars, the height of one pillar was eighteen cubits; and a fillet of twelve cubits did compass it; and the thickness thereof was four fingers: it was hollow.","ref":"Jeremiah 52:21","synthesized":"Each pillar was eighteen cubits tall and twelve cubits in circumference; each was hollow, four fingers thick.","sources":{"KJV":{"text":"And concerning the pillars, the height of one pillar was eighteen cubits; and a fillet of twelve cubits did compass it; and the thickness thereof was four fingers: it was hollow."},"BSB":{"text":"Each pillar was eighteen cubits tall and twelve cubits in circumference; each was hollow, four fingers thick."},"TANAKH":{"text":"And as for the pillars, the height of the one pillar was eighteen cubits; and a line of twelve cubits did compass it; and the thickness thereof was four fingers; it was hollow."},"HEBREW":{"text":"וְהָעַמּוּדִ֗ים שְׁמֹנֶ֨ה עֶשְׂרֵ֤ה אַמָּה֙ קומה קוֹמַת֙ הָעַמֻּ֣ד הָאֶחָ֔ד וְח֛וּט שְׁתֵּים־עֶשְׂרֵ֥ה אַמָּ֖ה יְסֻבֶּ֑נּוּ וְעָבְי֛וֹ אַרְבַּ֥ע אַצְבָּע֖וֹת נָבֽוּב׃"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"And a chapiter of brass was upon it; and the height of one chapiter was five cubits, with network and pomegranates upon the chapiters round about, all of brass. The second pillar also and the pomegranates were like unto these.","ref":"Jeremiah 52:22","synthesized":"The bronze capital atop one pillar was five cubits high, with a network of bronze pomegranates all around. The second pillar, with its pomegranates, was similar.","sources":{"KJV":{"text":"And a chapiter of brass was upon it; and the height of one chapiter was five cubits, with network and pomegranates upon the chapiters round about, all of brass. The second pillar also and the pomegranates were like unto these."},"BSB":{"text":"The bronze capital atop one pillar was five cubits high, with a network of bronze pomegranates all around. The second pillar, with its pomegranates, was similar."},"TANAKH":{"text":"And a capital of brass was upon it; and the height of the one capital was five cubits, with network and pomegranates upon the capital round about, all of brass; and the second pillar also had like unto these, and pomegranates."},"HEBREW":{"text":"וְכֹתֶ֨רֶת עָלָ֜יו נְחֹ֗שֶׁת וְקוֹמַ֨ת הַכֹּתֶ֥רֶת הָאַחַת֮ חָמֵ֣שׁ אַמּוֹת֒ וּשְׂבָכָ֨ה וְרִמּוֹנִ֧ים עַֽל־הַכּוֹתֶ֛רֶת סָבִ֖יב הַכֹּ֣ל נְחֹ֑שֶׁת וְכָאֵ֛לֶּה לַֽעַמּ֥וּד הַשֵּׁנִ֖י וְרִמּוֹנִֽים׃"}},"definableWords":["one"],"peopleInVerse":[]},"23":{"text":"And there were ninety and six pomegranates on a side; and all the pomegranates upon the network were an hundred round about.","ref":"Jeremiah 52:23","synthesized":"Each capital had ninety-six pomegranates on the sides, and a total of a hundred pomegranates were above the surrounding network.","sources":{"KJV":{"text":"And there were ninety and six pomegranates on a side; and all the pomegranates upon the network were an hundred round about."},"BSB":{"text":"Each capital had ninety-six pomegranates on the sides, and a total of a hundred pomegranates were above the surrounding network."},"TANAKH":{"text":"And there were ninety and six pomegranates on the outside; all the pomegranates were a hundred upon the network round about."},"HEBREW":{"text":"וַיִּֽהְיוּ֙ הָֽרִמֹּנִ֔ים תִּשְׁעִ֥ים וְשִׁשָּׁ֖ה ר֑וּחָה כָּל־הָרִמּוֹנִ֥ים מֵאָ֛ה עַל־הַשְּׂבָכָ֖ה סָבִֽיב׃"}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"And the captain of the guard took Seraiah the chief priest, and Zephaniah the second priest, and the three keepers of the door:","ref":"Jeremiah 52:24","synthesized":"The captain of the guard also took away Seraiah the chief priest, Zephaniah the priest of second rank, and the three doorkeepers.","sources":{"KJV":{"text":"And the captain of the guard took Seraiah the chief priest, and Zephaniah the second priest, and the three keepers of the door:"},"BSB":{"text":"The captain of the guard also took away Seraiah the chief priest, Zephaniah the priest of second rank, and the three doorkeepers."},"TANAKH":{"text":"And the captain of the guard took Seraiah the chief priest, and Zephaniah the second priest, and the three keepers of the door;"},"HEBREW":{"text":"וַיִּקַּ֣ח רַב־טַבָּחִ֗ים אֶת־שְׂרָיָה֙ כֹּהֵ֣ן הָרֹ֔אשׁ וְאֶת־צְפַנְיָ֖ה כֹּהֵ֣ן הַמִּשְׁנֶ֑ה וְאֶת־שְׁלֹ֖שֶׁת שֹׁמְרֵ֥י הַסַּֽף׃"}},"definableWords":["priest"],"peopleInVerse":[],"themesInVerse":["kingdom_priesthood"]},"25":{"text":"He took also out of the city an eunuch, which had the charge of the men of war; and seven men of them that were near the king’s person, which were found in the city; and the principal scribe of the host, who mustered the people of the land; and threescore men of the people of the land, that were found in the midst of the city.","ref":"Jeremiah 52:25","synthesized":"Of those still in the city, he took a court official who had been appointed over the men of war, as well as seven trusted royal advisers. He also took the scribe of the captain of the army, who had enlisted the people of the land, and sixty men who were found in the city.","sources":{"KJV":{"text":"He took also out of the city an eunuch, which had the charge of the men of war; and seven men of them that were near the king’s person, which were found in the city; and the principal scribe of the host, who mustered the people of the land; and threescore men of the people of the land, that were found in the midst of the city."},"BSB":{"text":"Of those still in the city, he took a court official who had been appointed over the men of war, as well as seven trusted royal advisers. He also took the scribe of the captain of the army, who had enlisted the people of the land, and sixty men who were found in the city."},"TANAKH":{"text":"and out of the city he took an officer that was set over the men of war; and seven men of them that saw the king's face, who were found in the city; and the scribe of the captain of the host, who mustered the people of the land; and threescore men of the people of the land, that were found in the midst of the city."},"HEBREW":{"text":"וּמִן־הָעִ֡יר לָקַח֩ סָרִ֨יס אֶחָ֜ד אֲ‍ֽשֶׁר־הָיָ֥ה פָקִ֣יד ׀ עַל־אַנְשֵׁ֣י הַמִּלְחָמָ֗ה וְשִׁבְעָ֨ה אֲנָשִׁ֜ים מֵרֹאֵ֤י פְנֵי־הַמֶּ֙לֶךְ֙ אֲשֶׁ֣ר נִמְצְא֣וּ בָעִ֔יר וְאֵ֗ת סֹפֵר֙ שַׂ֣ר הַצָּבָ֔א הַמַּצְבִּ֖א אֶת־עַ֣ם הָאָ֑רֶץ וְשִׁשִּׁ֥ים אִישׁ֙ מֵעַ֣ם הָאָ֔רֶץ הַֽנִּמְצְאִ֖ים בְּת֥וֹךְ הָעִֽיר׃"}},"definableWords":["men","Scribe","people","land"],"peopleInVerse":[],"themesInVerse":["bread_water_life","land_promise"]},"26":{"text":"So Nebuzaradan the captain of the guard took them, and brought them to the king of Babylon to Riblah.","ref":"Jeremiah 52:26","synthesized":"Nebuzaradan captain of the guard took them and brought them to the king of Babylon at Riblah.","sources":{"KJV":{"text":"So Nebuzaradan the captain of the guard took them, and brought them to the king of Babylon to Riblah."},"BSB":{"text":"Nebuzaradan captain of the guard took them and brought them to the king of Babylon at Riblah."},"TANAKH":{"text":"And Nebuzaradan the captain of the guard took them, and brought them to the king of Babylon to Riblah."},"HEBREW":{"text":"וַיִּקַּ֣ח אוֹתָ֔ם נְבוּזַרְאֲדָ֖ן רַב־טַבָּחִ֑ים וַיֹּ֧לֶךְ אוֹתָ֛ם אֶל־מֶ֥לֶךְ בָּבֶ֖ל רִבְלָֽתָה׃"}},"definableWords":["king","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship"]},"27":{"text":"And the king of Babylon smote them, and put them to death in Riblah in the land of Hamath. Thus Judah was carried away captive out of his own land.","ref":"Jeremiah 52:27","synthesized":"There at Riblah in the land of Hamath, the king of Babylon struck them down and put them to death. So Judah was taken into exile, away from its own land.","sources":{"KJV":{"text":"And the king of Babylon smote them, and put them to death in Riblah in the land of Hamath. Thus Judah was carried away captive out of his own land."},"BSB":{"text":"There at Riblah in the land of Hamath, the king of Babylon struck them down and put them to death. So Judah was taken into exile, away from its own land."},"TANAKH":{"text":"And the king of Babylon smote them, and put them to death at Riblah in the land of Hamath. So Judah was carried away captive out of his land."},"HEBREW":{"text":"וַיַּכֶּ֣ה אוֹתָם֩ מֶ֨לֶךְ בָּבֶ֧ל וַיְמִתֵ֛ם בְּרִבְלָ֖ה בְּאֶ֣רֶץ חֲמָ֑ת וַיִּ֥גֶל יְהוּדָ֖ה מֵעַ֥ל אַדְמָתֽוֹ׃"}},"definableWords":["land","king","Babylon","death","Judah"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["exile_return","kingship","land_promise"]},"28":{"text":"This is the people whom Nebuchadrezzar carried away captive: in the seventh year three thousand Jews and three and twenty:","ref":"Jeremiah 52:28","synthesized":"These are the people Nebuchadnezzar carried away:  in the seventh year, 3,023 Jews;","sources":{"KJV":{"text":"This is the people whom Nebuchadrezzar carried away captive: in the seventh year three thousand Jews and three and twenty:"},"BSB":{"text":"These are the people Nebuchadnezzar carried away:  in the seventh year, 3,023 Jews;"},"TANAKH":{"text":"This is the people whom Nebuchadrezzar carried away captive: in the seventh year three thousand Jews and three and twenty;"},"HEBREW":{"text":"זֶ֣ה הָעָ֔ם אֲשֶׁ֥ר הֶגְלָ֖ה נְבֽוּכַדְרֶאצַּ֑ר בִּשְׁנַת־שֶׁ֕בַע יְהוּדִ֕ים שְׁלֹ֥שֶׁת אֲלָפִ֖ים וְעֶשְׂרִ֥ים וּשְׁלֹשָֽׁה׃"}},"definableWords":["people","year"],"peopleInVerse":["Nebuchadnezzar"]},"29":{"text":"In the eighteenth year of Nebuchadrezzar he carried away captive from Jerusalem eight hundred thirty and two persons:","ref":"Jeremiah 52:29","synthesized":"in Nebuchadnezzar’s eighteenth year, 832 people from Jerusalem;","sources":{"KJV":{"text":"In the eighteenth year of Nebuchadrezzar he carried away captive from Jerusalem eight hundred thirty and two persons:"},"BSB":{"text":"in Nebuchadnezzar’s eighteenth year, 832 people from Jerusalem;"},"TANAKH":{"text":"in the eighteenth year of Nebuchadrezzar, from Jerusalem, eight hundred thirty and two persons;"},"HEBREW":{"text":"בִּשְׁנַ֛ת שְׁמוֹנֶ֥ה עֶשְׂרֵ֖ה לִנְבֽוּכַדְרֶאצַּ֑ר מִיר֣וּשָׁלִַ֔ם נֶ֕פֶשׁ שְׁמֹנֶ֥ה מֵא֖וֹת שְׁלֹשִׁ֥ים וּשְׁנָֽיִם׃"}},"definableWords":["year","people","Jerusalem"],"peopleInVerse":["Nebuchadnezzar"],"placesInVerse":["Jerusalem"]},"30":{"text":"In the three and twentieth year of Nebuchadrezzar Nebuzaradan the captain of the guard carried away captive of the Jews seven hundred forty and five persons: all the persons were four thousand and six hundred.","ref":"Jeremiah 52:30","synthesized":"in Nebuchadnezzar’s twenty-third year, Nebuzaradan captain of the guard carried away 745 Jews.   So in all, 4,600 people were taken away.","sources":{"KJV":{"text":"In the three and twentieth year of Nebuchadrezzar Nebuzaradan the captain of the guard carried away captive of the Jews seven hundred forty and five persons: all the persons were four thousand and six hundred."},"BSB":{"text":"in Nebuchadnezzar’s twenty-third year, Nebuzaradan captain of the guard carried away 745 Jews.   So in all, 4,600 people were taken away."},"TANAKH":{"text":"in the three and twentieth year of Nebuchadrezzar Nebuzaradan the captain of the guard carried away captive of the Jews seven hundred forty and five persons; all the persons were four thousand and six hundred."},"HEBREW":{"text":"בִּשְׁנַ֨ת שָׁלֹ֣שׁ וְעֶשְׂרִים֮ לִנְבֽוּכַדְרֶאצַּר֒ הֶגְלָ֗ה נְבֽוּזַרְאֲדָן֙ רַב־טַבָּחִ֔ים יְהוּדִ֕ים נֶ֕פֶשׁ שְׁבַ֥ע מֵא֖וֹת אַרְבָּעִ֣ים וַחֲמִשָּׁ֑ה כָּל־נֶ֕פֶשׁ אַרְבַּ֥עַת אֲלָפִ֖ים וְשֵׁ֥שׁ מֵאֽוֹת׃"}},"definableWords":["year","people"],"peopleInVerse":["Nebuchadnezzar"]},"31":{"text":"And it came to pass in the seven and thirtieth year of the captivity of Jehoiachin king of Judah, in the twelfth month, in the five and twentieth day of the month, that Evilmerodach king of Babylon in the first year of his reign lifted up the head of Jehoiachin king of Judah, and brought him forth out of prison,","ref":"Jeremiah 52:31","synthesized":"On the twenty-fifth day of the twelfth month of the thirty-seventh year of the exile of Jehoiachin king of Judah, in the first year of the reign of Evil-merodach king of Babylon, he pardoned Jehoiachin king of Judah and released him from prison.","sources":{"KJV":{"text":"And it came to pass in the seven and thirtieth year of the captivity of Jehoiachin king of Judah, in the twelfth month, in the five and twentieth day of the month, that Evilmerodach king of Babylon in the first year of his reign lifted up the head of Jehoiachin king of Judah, and brought him forth out of prison,"},"BSB":{"text":"On the twenty-fifth day of the twelfth month of the thirty-seventh year of the exile of Jehoiachin king of Judah, in the first year of the reign of Evil-merodach king of Babylon, he pardoned Jehoiachin king of Judah and released him from prison."},"TANAKH":{"text":"And it came to pass in the seven and thirtieth year of the captivity of Jehoiachin king of Judah, in the twelfth month, in the five and twentieth day of the month, that Evil-merodach king of Babylon, in the first year of his reign, lifted up the head of Jehoiachin king of Judah, and brought him forth out of prison."},"HEBREW":{"text":"וַיְהִי֩ בִשְׁלֹשִׁ֨ים וָשֶׁ֜בַע שָׁנָ֗ה לְגָלוּת֙ יְהוֹיָכִ֣ן מֶֽלֶךְ־יְהוּדָ֔ה בִּשְׁנֵ֤ים עָשָׂר֙ חֹ֔דֶשׁ בְּעֶשְׂרִ֥ים וַחֲמִשָּׁ֖ה לַחֹ֑דֶשׁ נָשָׂ֡א אֱוִ֣יל מְרֹדַךְ֩ מֶ֨לֶךְ בָּבֶ֜ל בִּשְׁנַ֣ת מַלְכֻת֗וֹ אֶת־רֹאשׁ֙ יְהוֹיָכִ֣ין מֶֽלֶךְ־יְהוּדָ֔ה וַיֹּצֵ֥א אוֹת֖וֹ מִבֵּ֥ית הכליא הַכְּלֽוּא׃"}},"definableWords":["day","year","king","Judah","reign","evil","King","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["exile_return","kingdom_of_god","kingship"]},"32":{"text":"And spake kindly unto him, and set his throne above the throne of the kings that were with him in Babylon,","ref":"Jeremiah 52:32","synthesized":"And he spoke kindly to Jehoiachin and set his throne above the thrones of the other kings who were with him in Babylon.","sources":{"KJV":{"text":"And spake kindly unto him, and set his throne above the throne of the kings that were with him in Babylon,"},"BSB":{"text":"And he spoke kindly to Jehoiachin and set his throne above the thrones of the other kings who were with him in Babylon."},"TANAKH":{"text":"And he spoke kindly to him, and set his throne above the throne of the kings that were with him in Babylon."},"HEBREW":{"text":"וַיְדַבֵּ֥ר אִתּ֖וֹ טֹב֑וֹת וַיִּתֵּן֙ אֶת־כִּסְא֔וֹ מִמַּ֗עַל לְכִסֵּ֧א מלכים הַמְּלָכִ֛ים אֲשֶׁ֥ר אִתּ֖וֹ בְּבָבֶֽל׃"}},"definableWords":["throne","kings","Babylon"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingdom_of_god","kingship"]},"33":{"text":"And changed his prison garments: and he did continually eat bread before him all the days of his life.","ref":"Jeremiah 52:33","synthesized":"So Jehoiachin changed out of his prison clothes, and he dined regularly at the king’s table for the rest of his life.","sources":{"KJV":{"text":"And changed his prison garments: and he did continually eat bread before him all the days of his life."},"BSB":{"text":"So Jehoiachin changed out of his prison clothes, and he dined regularly at the king’s table for the rest of his life."},"TANAKH":{"text":"And he changed his prison garments, and did eat bread before him continually all the days of his life."},"HEBREW":{"text":"וְשִׁנָּ֕ה אֵ֖ת בִּגְדֵ֣י כִלְא֑וֹ וְאָכַ֨ל לֶ֧חֶם לְפָנָ֛יו תָּמִ֖יד כָּל־יְמֵ֥י חַיָּֽו׃"}},"definableWords":["king","rest","life"],"peopleInVerse":[],"themesInVerse":["kingship","peace","sabbath_rest"]},"34":{"text":"And for his diet, there was a continual diet given him of the king of Babylon, every day a portion until the day of his death, all the days of his life.","ref":"Jeremiah 52:34","synthesized":"And the king of Babylon provided Jehoiachin a daily portion for the rest of his life, until the day of his death.","sources":{"KJV":{"text":"And for his diet, there was a continual diet given him of the king of Babylon, every day a portion until the day of his death, all the days of his life."},"BSB":{"text":"And the king of Babylon provided Jehoiachin a daily portion for the rest of his life, until the day of his death."},"TANAKH":{"text":"And for his allowance, there was a continual allowance given him of the king of Babylon, every day a portion until the day of his death, all the days of his life."},"HEBREW":{"text":"וַאֲרֻחָת֗וֹ אֲרֻחַת֩ תָּמִ֨יד נִתְּנָה־לּ֜וֹ מֵאֵ֧ת מֶֽלֶךְ־בָּבֶ֛ל דְּבַר־י֥וֹם בְּיוֹמ֖וֹ עַד־י֣וֹם מוֹת֑וֹ כֹּ֖ל יְמֵ֥י חַיָּֽיו׃ 1364 52 4 4"}},"definableWords":["king","Babylon","rest","life","day","death"],"peopleInVerse":[],"placesInVerse":["Babylon"],"themesInVerse":["kingship","peace","sabbath_rest"]}}}};